window.QUIZ_DATA = [{"id": "set1", "title": "ชุดที่ 1 — Cardiology + Pulmonology", "questions": [{"topic": "Cardiology", "q": "A 58-year-old man has crushing central chest pain radiating to the jaw for 40 minutes with diaphoresis. ECG shows ST elevation in V2–V4. He is at a hospital capable of primary PCI. What is the most appropriate reperfusion strategy?", "choices": ["Primary PCI within 90 minutes", "Immediate fibrinolytic (thrombolytic) therapy", "Wait for a positive troponin before deciding", "Start warfarin for anticoagulation", "Observe on telemetry for 24 hours"], "ans": 0, "exp": "นี่คือ anterior STEMI (LAD). เมื่อทำ primary PCI ได้ในเวลา ควรเลือก PCI ภายใน 90 นาที (door-to-balloon) ซึ่งเป็น reperfusion ที่ดีที่สุด. Fibrinolytic ใช้เมื่อ PCI ไม่ทัน (คาดว่าเกิน 120 นาที). ไม่ต้องรอ troponin เพราะ ST elevation วินิจฉัย STEMI ได้แล้ว.", "id": "set1-1"}, {"topic": "Cardiology", "q": "A patient with inferior STEMI (II, III, aVF) has BP 88/60. After sublingual nitroglycerin the BP drops markedly. What is the most likely mechanism?", "choices": ["Acute aortic dissection extension", "Right ventricular infarction", "Pericardial tamponade physiology", "Tension pneumothorax reducing preload", "Vasovagal reaction to the nitrate"], "ans": 1, "exp": "Inferior MI มักมี RV infarction ร่วม ซึ่ง preload-dependent การให้ nitrate จะลด preload ทำให้ BP ตก. รักษาด้วย IV fluid และหลีกเลี่ยง nitrate. ควรตรวจ right-sided lead (V4R).", "id": "set1-2"}, {"topic": "Cardiology", "q": "A 65-year-old woman with DM and HT has exertional dyspnea, orthopnea, leg edema, elevated JVP, bibasal crepitations, and S3. Echo shows EF 30%. Which drug does NOT reduce mortality in HFrEF?", "choices": ["ARNI (sacubitril/valsartan)", "Beta-blocker (e.g., carvedilol)", "Amlodipine (a dihydropyridine CCB)", "SGLT2 inhibitor (e.g., dapagliflozin)", "MRA (spironolactone/eplerenone)"], "ans": 2, "exp": "HFrEF ใช้ 4 เสาหลัก: ARNI/ACEI/ARB + beta-blocker + MRA + SGLT2i. Amlodipine (DHP-CCB) ไม่ลด mortality ใน HFrEF ใช้เฉพาะคุมความดัน/angina; non-DHP CCB (verapamil/diltiazem) เป็นข้อห้ามใน HFrEF.", "id": "set1-3"}, {"topic": "Cardiology", "q": "A 70-year-old man has palpitations and an irregularly irregular pulse. ECG shows absent P waves. CHA2DS2-VASc = 4. Which intervention most reduces his stroke risk?", "choices": ["Aspirin monotherapy alone", "Rate control with digoxin", "Immediate cardioversion without work-up", "Anticoagulation with a DOAC", "High-intensity statin therapy"], "ans": 3, "exp": "AF ที่ CHA2DS2-VASc ≥ 2 (ชาย) ควรได้ anticoagulant โดย DOAC เป็นตัวเลือกแรก (เหนือ warfarin ยกเว้น mechanical valve/moderate-severe MS). Aspirin ไม่พอ; cardioversion โดยไม่ประเมิน thrombus เสี่ยง embolic stroke.", "id": "set1-4"}, {"topic": "Cardiology", "q": "A patient with AF for more than 48 hours who has NOT been anticoagulated is scheduled for cardioversion. What is the most important risk?", "choices": ["Torsades de pointes arrhythmia", "Life-threatening hyperkalemia", "Malignant hyperthermia crisis", "Acute aortic dissection", "Embolic (thromboembolic) stroke"], "ans": 4, "exp": "AF > 48 ชม. อาจมี thrombus ใน left atrial appendage การ cardiovert อาจทำให้ลิ่มหลุดเกิด embolic stroke. ต้อง anticoagulate ≥ 3 สัปดาห์ก่อน หรือทำ TEE ตัด thrombus ก่อน แล้ว anticoagulate ต่อ ≥ 4 สัปดาห์.", "id": "set1-5"}, {"topic": "Cardiology", "q": "A patient develops polymorphic VT that twists around the baseline; ECG before the event showed a prolonged QT. What is the most appropriate immediate treatment?", "choices": ["IV magnesium sulfate", "IV amiodarone bolus", "IV digoxin loading", "IV verapamil push", "IV adenosine rapid push"], "ans": 0, "exp": "นี่คือ Torsades de pointes (polymorphic VT บน long QT). รักษาด้วย IV magnesium sulfate + แก้สาเหตุ QT ยาว (ยา, hypoK/Mg/Ca), overdrive pacing ถ้าจำเป็น. Amiodarone/ยาที่ยืด QT อาจทำให้แย่ลง.", "id": "set1-6"}, {"topic": "Cardiology", "q": "A 60-year-old man has predictable chest pain on exertion that resolves within 5 minutes of rest, with no dynamic troponin change. What is the most appropriate diagnosis and next step?", "choices": ["Unstable angina; give immediate fibrinolytic therapy", "Stable angina; exercise stress test or CT coronary angiography", "STEMI; activate the cath lab for primary PCI", "Acute pericarditis; treat with high-dose NSAIDs", "Aortic dissection; obtain urgent CT of the aorta"], "ans": 1, "exp": "อาการ predictable เจ็บเวลาออกแรงและหายเมื่อพัก = stable angina. ประเมินด้วย non-invasive test (exercise stress test/CTCA) และให้ ASA + statin + anti-anginal + คุมปัจจัยเสี่ยง.", "id": "set1-7"}, {"topic": "Cardiology", "q": "According to current guidelines, the LDL-C target for a very-high-risk patient after ACS is:", "choices": ["< 130 mg/dL with no time limit", "< 100 mg/dL as the sole target", "< 55 mg/dL and ≥ 50% reduction", "< 70 mg/dL without a reduction goal", "No specific LDL-C target needed"], "ans": 2, "exp": "แนวทางปัจจุบัน (ESC 2023 ACS / ACC-AHA 2025) เป้า LDL-C < 55 mg/dL และลดลง ≥ 50% จาก baseline. ถ้าไม่ถึงเป้าด้วย high-intensity statin เต็มขนาด เพิ่ม ezetimibe แล้ว PCSK9 inhibitor. (สไลด์เดิมมักระบุ < 70).", "id": "set1-8"}, {"topic": "Cardiology", "q": "A 55-year-old asymptomatic woman has office BP averaging 150/95 on two visits. What is the most appropriate step before confirming a diagnosis of hypertension?", "choices": ["Start two antihypertensive drugs immediately", "Refer directly for adrenalectomy surgery", "Give an empiric trial of a diuretic", "Confirm with home or ambulatory BP monitoring", "Diagnose a hypertensive emergency now"], "ans": 3, "exp": "ควรยืนยันด้วยการวัดนอกคลินิก (HBPM เฉลี่ย ≥135/85 หรือ ABPM) เพื่อตัด white-coat hypertension ก่อนวินิจฉัยและเริ่มยา (ยกเว้น BP สูงมาก/มี target organ damage).", "id": "set1-9"}, {"topic": "Cardiology", "q": "A 30-year-old man has hypertension resistant to three drugs and is found to have hypokalemia. Which screening test is most appropriate for a secondary cause?", "choices": ["24-hour urine free cortisol", "Renal artery Doppler ultrasound", "Plasma free metanephrines", "Serum TSH measurement", "Aldosterone-to-renin ratio"], "ans": 4, "exp": "HT + hypokalemia (โดยเฉพาะ resistant/อายุน้อย) นึกถึง primary aldosteronism (Conn) คัดกรองด้วย aldosterone-to-renin ratio ที่สูง. Pheochromocytoma (metanephrine) มี HT เป็นพักๆ + ปวดหัว/เหงื่อ/ใจสั่น.", "id": "set1-10"}, {"topic": "Cardiology", "q": "A 45-year-old man has BP 230/130 with severe headache, blurred vision, papilledema, and rising creatinine. What is the appropriate management?", "choices": ["Controlled IV BP reduction (~10–20% in the first hour)", "Oral antihypertensive then discharge home", "Normalize the BP within 15 minutes", "No acute BP reduction is needed", "Sublingual nifedipine to drop BP fast"], "ans": 0, "exp": "นี่คือ hypertensive emergency (encephalopathy + retinopathy + AKI) ต้องลด BP แบบควบคุมด้วยยา IV ~10–20% ใน 1 ชม.แรก (dissection ลดเร็วกว่า) เพื่อเลี่ยง hypoperfusion. Sublingual nifedipine เสี่ยง ischemia.", "id": "set1-11"}, {"topic": "Cardiology", "q": "ECG shows the PR interval progressively lengthening until a QRS is dropped, then the cycle repeats. What is the diagnosis?", "choices": ["First-degree AV block only", "Mobitz type I (Wenckebach)", "Mobitz type II AV block", "Complete (third-degree) heart block", "Atrial flutter with variable block"], "ans": 1, "exp": "PR ยาวขึ้นเรื่อยๆ จน drop beat = Mobitz I (Wenckebach) มักไม่รุนแรง ไม่ต้อง pacemaker ถ้าไม่มีอาการ. ต่างจาก Mobitz II (PR คงที่แล้ว drop ทันที) ที่เสี่ยงและต้อง pacemaker.", "id": "set1-12"}, {"topic": "Cardiology", "q": "A patient with complete (third-degree) AV block, heart rate 35, has recurrent presyncope. What is the definitive long-term treatment?", "choices": ["Atropine infusion indefinitely", "Oral beta-blocker therapy", "Permanent pacemaker implantation", "Digoxin for rate control", "Observation without intervention"], "ans": 2, "exp": "Complete heart block ที่มีอาการเสี่ยง asystole รักษาชั่วคราวด้วย atropine/transcutaneous pacing และรักษาถาวรด้วย permanent pacemaker. Beta-blocker/digoxin จะยิ่งกด conduction.", "id": "set1-13"}, {"topic": "Cardiology", "q": "A 68-year-old woman has exertional syncope, an ejection systolic murmur at the base radiating to the carotids, and pulsus parvus et tardus. What is the diagnosis?", "choices": ["Mitral regurgitation", "Mitral stenosis", "Aortic regurgitation", "Aortic stenosis", "Ventricular septal defect"], "ans": 3, "exp": "Ejection systolic murmur ร้าวคอ + pulsus parvus et tardus = aortic stenosis. Triad: angina/syncope/HF; symptomatic severe AS ควรทำ AVR/TAVI. Syncope เวลาออกแรงเป็นลักษณะเด่น.", "id": "set1-14"}, {"topic": "Cardiology", "q": "A patient has fever, a new murmur, splinter hemorrhages, and blood cultures growing Staphylococcus aureus. What is the diagnosis and the key confirmatory investigation?", "choices": ["Rheumatic fever; ASO antibody titer", "Acute pericarditis; ECG changes", "Acute myocarditis; cardiac MRI", "Pulmonary embolism; CT pulmonary angiogram", "Infective endocarditis; echocardiography"], "ans": 4, "exp": "ไข้ + murmur ใหม่ + peripheral emboli + positive blood culture เข้า Duke criteria ของ infective endocarditis. ทำ echocardiography หา vegetation และให้ IV antibiotics ตามเชื้อ 4–6 สัปดาห์.", "id": "set1-15"}, {"topic": "Cardiology", "q": "In a diabetic patient with albuminuria, which antihypertensive class is first-line?", "choices": ["ACE inhibitor or ARB", "Beta-blocker (e.g., atenolol)", "Alpha-blocker (e.g., doxazosin)", "Direct vasodilator hydralazine", "Loop diuretic (e.g., furosemide)"], "ans": 0, "exp": "เบาหวาน + albuminuria/CKD ควรใช้ ACEI หรือ ARB เป็นแนวหน้าเพราะลด proteinuria และชะลอไตเสื่อม. ห้ามใช้ ACEI ร่วม ARB. อาจเพิ่ม SGLT2i เพื่อป้องกันไต/หัวใจ.", "id": "set1-16"}, {"topic": "Cardiology", "q": "A patient with stable, narrow-complex regular SVT is hemodynamically stable. What is the first step?", "choices": ["Immediate synchronized cardioversion", "Vagal maneuver then adenosine", "Amiodarone infusion drip", "Unsynchronized defibrillation", "IV verapamil push immediately"], "ans": 1, "exp": "SVT ที่ stable เริ่มด้วย vagal maneuver (Valsalva/carotid massage) ถ้าไม่ได้ผลให้ adenosine IV push. ถ้า unstable จึงทำ synchronized cardioversion. Defibrillation ใช้กับ pulseless VT/VF.", "id": "set1-17"}, {"topic": "Cardiology", "q": "A CKD patient has ECG showing peaked T waves, prolonged PR, and widening QRS. Which drug should be given FIRST to protect the heart?", "choices": ["Insulin plus glucose infusion", "Nebulized salbutamol therapy", "IV calcium gluconate", "IV sodium bicarbonate", "Oral Kayexalate (resin)"], "ans": 2, "exp": "ECG เข้าได้กับ hyperkalemia รุนแรง. ลำดับแรกคือ IV calcium gluconate เพื่อ stabilize cardiac membrane (แม้ไม่ลดระดับ K). จากนั้นจึง shift K (insulin+glucose, beta-agonist) และกำจัด K (diuretic/resin/dialysis).", "id": "set1-18"}, {"topic": "Cardiology", "q": "Which murmur is characteristic of mitral stenosis?", "choices": ["Holosystolic murmur radiating to the axilla", "Ejection systolic radiating to the carotids", "Early diastolic at the left sternal border", "Mid-diastolic rumble with opening snap at the apex", "Continuous machinery murmur"], "ans": 3, "exp": "Mitral stenosis: mid-diastolic rumble ที่ apex + opening snap. สาเหตุหลัก rheumatic heart disease มักสัมพันธ์ AF และ hemoptysis. Holosystolic ร้าวรักแร้ = MR; early diastolic = AR.", "id": "set1-19"}, {"topic": "Cardiology", "q": "A patient in acute decompensated heart failure with pulmonary edema has BP 150/90. What is the appropriate initial management?", "choices": ["Give an IV beta-blocker bolus", "Give a rapid IV fluid bolus", "Start a calcium channel blocker", "Give immediate IV digoxin", "Sit upright, O2/NIV, IV loop diuretic ± nitrate"], "ans": 4, "exp": "Acute pulmonary edema: นั่งตัวตรง, O2/NIV, IV loop diuretic (furosemide) ลด preload, nitrate ถ้า BP พอ, หา precipitant. IV fluid และ beta-blocker bolus เป็นข้อห้ามในภาวะ decompensated.", "id": "set1-20"}, {"topic": "Cardiology", "q": "Which complication is the most common cause of sudden death in the first hour of an acute MI?", "choices": ["Ventricular arrhythmia (VT/VF)", "Ventricular free wall rupture", "Dressler (post-MI) syndrome", "Papillary muscle rupture", "Left ventricular aneurysm"], "ans": 0, "exp": "สาเหตุตายเฉียบพลันที่พบบ่อยสุดในช่วงแรกของ MI คือ ventricular arrhythmia (VT/VF). Free wall/papillary muscle rupture มักเกิดวันถัดมา; Dressler syndrome เกิดเป็นสัปดาห์-เดือนหลัง MI.", "id": "set1-21"}, {"topic": "Cardiology", "q": "How long should standard dual antiplatelet therapy (DAPT) be given after ACS in a patient not at high bleeding risk?", "choices": ["About 1 month only", "At least 12 months", "About 3 months only", "About 1 week only", "Not necessary at all"], "ans": 1, "exp": "DAPT (aspirin + P2Y12 inhibitor) มาตรฐานหลัง ACS คืออย่างน้อย 12 เดือนในผู้ที่ไม่เสี่ยงเลือดออกสูง. ถ้าเสี่ยงเลือดออกอาจสั้นลง; ถ้าเสี่ยง ischemic สูงอาจยาวขึ้น.", "id": "set1-22"}, {"topic": "Cardiology", "q": "Which ECG leads localize an inferior wall myocardial infarction?", "choices": ["Leads V1–V2", "Leads V3–V4", "Leads II, III, aVF", "Leads I and aVL", "Leads V5–V6"], "ans": 2, "exp": "Inferior wall MI แสดง ST changes ที่ II, III, aVF (มัก RCA). V1–V2 = septal, V3–V4 = anterior (LAD), I/aVL/V5–V6 = lateral (LCx).", "id": "set1-23"}, {"topic": "Cardiology", "q": "Which pulse finding is characteristic of chronic aortic regurgitation?", "choices": ["Pulsus parvus et tardus", "Pulsus paradoxus", "Pulsus alternans", "Water-hammer (Corrigan) pulse", "Bisferiens pulse only"], "ans": 3, "exp": "AR เรื้อรังมี wide pulse pressure ทำให้เกิด water-hammer (Corrigan) pulse + early diastolic murmur. Pulsus parvus et tardus = AS; pulsus paradoxus = tamponade.", "id": "set1-24"}, {"topic": "Cardiology", "q": "A patient with AF and rheumatic moderate-to-severe mitral stenosis needs anticoagulation. Which agent should be used?", "choices": ["DOAC such as apixaban", "Aspirin monotherapy", "Clopidogrel monotherapy", "No anticoagulation needed", "Warfarin (vitamin K antagonist)"], "ans": 4, "exp": "AF ที่มี moderate-severe mitral stenosis (rheumatic) หรือ mechanical valve ต้องใช้ warfarin เท่านั้น ไม่ใช้ DOAC เพราะ DOAC ด้อยกว่าและยังไม่รับรองในกลุ่มนี้.", "id": "set1-25"}, {"topic": "Cardiology", "q": "Under the 2024 ESC classification, the new category of 'Elevated BP' corresponds to which range?", "choices": ["120–139/70–89 mmHg", "Below 120/70 mmHg", "140–159/90–99 mmHg", "At least 160/100 mmHg", "At least 180/110 mmHg"], "ans": 0, "exp": "ESC 2024 เพิ่มหมวด Elevated BP = 120–139/70–89 (พิจารณาให้ยาตามความเสี่ยง CV); Non-elevated < 120/70; Hypertension ≥ 140/90. เป้าการรักษา default SBP 120–129 ถ้าทนได้.", "id": "set1-26"}, {"topic": "Cardiology", "q": "A patient with stable angina cannot take a beta-blocker due to severe asthma. Which anti-anginal is appropriate?", "choices": ["Digoxin for rate control", "A calcium channel blocker and/or long-acting nitrate", "Warfarin anticoagulation", "Furosemide diuresis", "Spironolactone therapy"], "ans": 1, "exp": "เมื่อ beta-blocker มีข้อห้าม ใช้ CCB (non-DHP diltiazem หรือ DHP amlodipine) และ/หรือ long-acting nitrate เป็น anti-anginal ร่วมกับ ASA + statin.", "id": "set1-27"}, {"topic": "Cardiology", "q": "A patient with chest pain has diffuse concave ST elevation with PR depression and an audible friction rub. What is the diagnosis?", "choices": ["Acute STEMI", "Aortic dissection", "Acute pericarditis", "Pulmonary embolism", "Benign early repolarization"], "ans": 2, "exp": "Diffuse concave ST elevation + PR depression + friction rub = acute pericarditis. รักษาด้วย NSAID + colchicine. ต่างจาก STEMI ที่ ST elevation จำกัด territory + reciprocal change.", "id": "set1-28"}, {"topic": "Cardiology", "q": "Which bedside test best confirms pericardial tamponade?", "choices": ["A 12-lead ECG", "Portable chest X-ray", "Serum troponin level", "Bedside echocardiography", "Serum BNP level"], "ans": 3, "exp": "Tamponade วินิจฉัยด้วย echocardiography (pericardial effusion + RA/RV diastolic collapse). อาการ Beck triad + pulsus paradoxus. รักษา pericardiocentesis.", "id": "set1-29"}, {"topic": "Cardiology", "q": "Which ECG feature characterizes Wolff-Parkinson-White syndrome?", "choices": ["Peaked (tented) T waves", "A prolonged QT interval", "An epsilon wave", "An Osborn (J) wave", "Delta wave with a short PR interval"], "ans": 4, "exp": "WPW มี accessory pathway → short PR + delta wave + wide QRS. ระวัง AF ใน WPW ห้ามใช้ AV nodal blocker (digoxin/verapamil/adenosine) เพราะอาจ conduct เร็วผ่าน accessory pathway.", "id": "set1-30"}, {"topic": "Cardiology", "q": "In a young athlete with hypertrophic cardiomyopathy, strenuous exercise most increases the risk of which event?", "choices": ["Sudden cardiac death", "Acute aortic dissection", "Acute pulmonary embolism", "Stroke from AF only", "Myxoma embolization"], "ans": 0, "exp": "HCM (โดยเฉพาะในนักกีฬาอายุน้อย) เป็นสาเหตุ sudden cardiac death ขณะออกกำลังหักโหม จาก outflow obstruction/arrhythmia. ควรจำกัดกิจกรรมหักโหมและประเมิน ICD ในผู้เสี่ยงสูง.", "id": "set1-31"}, {"topic": "Cardiology", "q": "Which agent, beyond its benefit in HFrEF, also reduces heart-failure hospitalization in HFpEF based on recent evidence?", "choices": ["Digoxin therapy", "An SGLT2 inhibitor", "Ivabradine therapy", "Hydralazine therapy", "Amlodipine therapy"], "ans": 1, "exp": "SGLT2 inhibitor (dapagliflozin/empagliflozin) ลด HF hospitalization ทั้งใน HFrEF และ HFpEF จึงเป็นเสาหลักที่ใช้ได้กว้าง. Ivabradine/hydralazine ใช้เฉพาะ HFrEF บางกลุ่ม.", "id": "set1-32"}, {"topic": "Cardiology", "q": "A 50-year-old man develops sudden dyspnea after major surgery, with a swollen left leg. ECG shows sinus tachycardia and an S1Q3T3 pattern. What should be suspected first?", "choices": ["Acute myocardial infarction", "Acute pericarditis", "Acute pulmonary embolism", "Acute aortic dissection", "Spontaneous pneumothorax"], "ans": 2, "exp": "หลังผ่าตัด + ขาบวมข้างเดียว + เหนื่อยเฉียบพลัน + S1Q3T3/RV strain ชี้ pulmonary embolism (VTE). ยืนยันด้วย CTPA; รักษา anticoagulation, massive PE + shock พิจารณา thrombolysis.", "id": "set1-33"}, {"topic": "Cardiology", "q": "What is the immediate treatment of pulseless ventricular tachycardia or ventricular fibrillation?", "choices": ["Synchronized cardioversion", "IV adenosine push", "IV magnesium sulfate only", "Immediate defibrillation with CPR", "A vagal maneuver"], "ans": 3, "exp": "Pulseless VT/VF เป็น cardiac arrest ต้อง defibrillation (unsynchronized) ทันที + CPR คุณภาพสูง + epinephrine ตาม ACLS. Synchronized cardioversion ใช้กับ tachyarrhythmia ที่ยังมีชีพจรแต่ unstable.", "id": "set1-34"}, {"topic": "Cardiology", "q": "Three weeks after an MI, a patient develops low-grade fever, pleuritic chest pain, a friction rub, and a pericardial effusion. What is the diagnosis?", "choices": ["Reinfarction of the myocardium", "Infective endocarditis", "Acute pulmonary embolism", "Acute viral myocarditis", "Dressler syndrome (post-MI pericarditis)"], "ans": 4, "exp": "Dressler syndrome = post-MI autoimmune pericarditis เกิดหลายสัปดาห์หลัง MI. รักษาด้วย NSAID/colchicine (หลีกเลี่ยง steroid ระยะแรกหลัง MI).", "id": "set1-35"}, {"topic": "Cardiology", "q": "A patient with symptomatic bradycardia (HR 38, BP 80/50) does not respond to atropine. What is the next step?", "choices": ["Transcutaneous pacing (± dopamine/epinephrine)", "IV beta-blocker therapy", "IV adenosine push", "IV digoxin loading", "IV verapamil push"], "ans": 0, "exp": "Symptomatic bradycardia ที่ไม่ตอบสนอง atropine ให้ transcutaneous pacing และ/หรือ chronotropic infusion (dopamine/epinephrine) แล้วเตรียม pacemaker. ยา AV nodal blocker เป็นข้อห้าม.", "id": "set1-36"}, {"topic": "Cardiology", "q": "In a diabetic patient screened for lipids, what is the first-line drug class to reduce ASCVD risk?", "choices": ["Fibrate as the primary agent", "Statin according to risk level", "Omega-3 fatty acids alone", "Niacin as the main therapy", "No lipid-lowering drug needed"], "ans": 1, "exp": "ยาแนวหน้าลด ASCVD คือ statin ตามระดับความเสี่ยง (high-intensity ในผู้เสี่ยงสูง/มี ASCVD). Fibrate ใช้เมื่อ TG สูงมากเพื่อลด pancreatitis. เป้า LDL ต่ำลงตามความเสี่ยง.", "id": "set1-37"}, {"topic": "Cardiology", "q": "Which adverse effect of NSAIDs is most concerning in a patient with heart failure?", "choices": ["Marked hypokalemia and arrhythmia", "Drug-induced hyperthyroidism", "Fluid retention worsening HF and reduced diuretic effect", "Symptomatic bradycardia", "QT-interval prolongation"], "ans": 2, "exp": "NSAID ทำให้ Na/น้ำคั่ง ลดประสิทธิภาพ diuretic และ ACEI/ARB ทำให้ HF กำเริบและเสี่ยง AKI จึงควรหลีกเลี่ยงใน HF/CKD.", "id": "set1-38"}, {"topic": "Cardiology", "q": "Which auscultatory finding is characteristic of mitral valve prolapse?", "choices": ["Opening snap after S2", "Continuous machinery murmur", "Early diastolic decrescendo murmur", "Mid-systolic click and late systolic murmur", "Fixed splitting of S2"], "ans": 3, "exp": "MVP มี mid-systolic click ตามด้วย late systolic murmur; ท่าที่ลด preload (standing/Valsalva) ทำให้ click มาเร็วขึ้น. MVP เป็นสาเหตุ chronic MR ที่พบบ่อย.", "id": "set1-39"}, {"topic": "Cardiology", "q": "After successful fibrinolysis for STEMI, what should be done next?", "choices": ["Observation without further action", "Start long-term warfarin immediately", "Stop all antiplatelet therapy", "Give a calcium channel blocker", "Refer for coronary angiography ± PCI"], "ans": 4, "exp": "หลัง fibrinolytic ควรส่งต่อทำ coronary angiography ± PCI (routine early หรือ rescue PCI ถ้า reperfusion ล้มเหลว) ตาม pharmaco-invasive strategy. ยังคง DAPT + anticoagulant ตามข้อบ่งชี้.", "id": "set1-40"}, {"topic": "Cardiology", "q": "A woman at 30 weeks gestation has BP 160/110 with proteinuria and headache. What is the diagnosis and appropriate drug?", "choices": ["Preeclampsia; labetalol/hydralazine/nifedipine", "Chronic hypertension; an ACE inhibitor", "Gestational hypertension; atenolol", "Pheochromocytoma; phenoxybenzamine", "White-coat hypertension; no drug"], "ans": 0, "exp": "BP สูง + proteinuria หลัง 20 สัปดาห์ = preeclampsia. ยาปลอดภัย: labetalol, hydralazine, nifedipine + MgSO4 ป้องกัน/รักษา eclampsia. ACEI/ARB เป็นข้อห้ามในการตั้งครรภ์.", "id": "set1-41"}, {"topic": "Cardiology", "q": "Which drug reduces mortality in HFrEF via neprilysin inhibition combined with an ARB?", "choices": ["Ivabradine therapy", "Sacubitril/valsartan (ARNI)", "Digoxin therapy", "Amlodipine therapy", "Hydrochlorothiazide therapy"], "ans": 1, "exp": "Sacubitril/valsartan (ARNI) ยับยั้ง neprilysin + block AT1 receptor ลด mortality เหนือ ACEI ใน HFrEF. ห้ามใช้ร่วม/ใกล้ ACEI (เสี่ยง angioedema) ต้องเว้น 36 ชม.", "id": "set1-42"}, {"topic": "Cardiology", "q": "ECG shows a wide QRS with an rSR' pattern in V1 and a slurred S wave in leads I and V6. What is it?", "choices": ["Left bundle branch block", "Left ventricular hypertrophy", "Right bundle branch block", "Wolff-Parkinson-White pattern", "Hyperkalemia changes"], "ans": 2, "exp": "rSR' (rabbit ear) ที่ V1 + wide QRS + slurred S ที่ lateral leads = RBBB. LBBB จะมี broad monophasic R ที่ I/V6 และอาจ mask MI.", "id": "set1-43"}, {"topic": "Cardiology", "q": "In symptomatic severe aortic stenosis, which intervention improves survival?", "choices": ["Vasodilator therapy", "Beta-blocker therapy", "Balloon valvuloplasty as permanent therapy", "Aortic valve replacement (SAVR/TAVI)", "Diuretic therapy alone"], "ans": 3, "exp": "Symptomatic severe AS มี prognosis แย่หากไม่ผ่าตัด การรักษาที่ปรับ prognosis คือ aortic valve replacement (surgical/TAVI). Vasodilator ต้องระวังเพราะ preload/afterload sensitive.", "id": "set1-44"}, {"topic": "Cardiology", "q": "Which antihypertensive class should be avoided in a patient with gout?", "choices": ["ACE inhibitor therapy", "ARB therapy", "Calcium channel blocker", "An ARB plus a CCB", "High-dose thiazide diuretic"], "ans": 4, "exp": "Thiazide เพิ่มกรดยูริกและกระตุ้น gout จึงควรหลีกเลี่ยง. ทางเลือกที่ดีกว่าเช่น CCB/ACEI/ARB (losartan มีฤทธิ์ลด uric เล็กน้อย).", "id": "set1-45"}, {"topic": "Cardiology", "q": "Using the rapid '300 rule', if the R-R interval spans 4 large boxes, the heart rate is approximately:", "choices": ["About 75 /min", "About 150 /min", "About 100 /min", "About 60 /min", "About 50 /min"], "ans": 0, "exp": "300 หารด้วยจำนวนช่องใหญ่ระหว่าง R-R: 300/4 = 75 ครั้ง/นาที (1 ช่อง=300, 2=150, 3=100, 4=75, 5=60, 6=50).", "id": "set1-46"}, {"topic": "Cardiology", "q": "Which is first-line rate control for AF in a patient with normal EF and no heart failure?", "choices": ["Digoxin monotherapy", "Beta-blocker or non-DHP calcium channel blocker", "Amiodarone infusion", "IV adenosine push", "Ivabradine therapy"], "ans": 1, "exp": "Rate control ใน AF ที่ EF ปกติ เริ่มด้วย beta-blocker หรือ non-DHP CCB (diltiazem/verapamil). Digoxin ใช้เสริมเมื่อมี HF/ความดันต่ำ. ใน HFrEF ห้าม non-DHP CCB.", "id": "set1-47"}, {"topic": "Cardiology", "q": "A 55-year-old man with prior MI has LDL-C 60 mg/dL on maximally tolerated statin. His residual risk is high. What is the reasonable next step to lower LDL further?", "choices": ["Stop the statin entirely", "Switch the statin to a fibrate", "Add ezetimibe ± PCSK9 inhibitor", "Add niacin to the statin", "No change is needed"], "ans": 2, "exp": "เป้า LDL หลัง ACS < 55; ที่ 60 ยังไม่ถึงเป้า ควรเพิ่ม ezetimibe และ/หรือ PCSK9 inhibitor ตามแนวทาง 2025 ACS lipid. Fibrate/niacin ไม่ใช่ตัวเลือกหลักลด LDL.", "id": "set1-48"}, {"topic": "Cardiology", "q": "A patient with new AF is planned for rhythm control. According to the 2023 AF guideline, in which group is early rhythm control/catheter ablation particularly favored as first-line?", "choices": ["Asymptomatic elderly with permanent AF", "AF with a mechanical valve only", "Isolated first episode that self-resolved", "Symptomatic AF, especially with HFrEF", "AF with active major bleeding"], "ans": 3, "exp": "2023 ACC/AHA/ACCP/HRS เน้น early rhythm control และ catheter ablation เป็น first-line ในบางกลุ่ม เช่น symptomatic AF และผู้ป่วย HFrEF (ablation ลด mortality/HF hospitalization). และเน้น modify ปัจจัยเสี่ยง.", "id": "set1-49"}, {"topic": "Cardiology", "q": "A 65-year-old man has sudden severe 'tearing' chest pain radiating to the back, BP 180/100 in the right arm but 140/80 in the left arm, and a widened mediastinum on CXR. What is the most likely diagnosis?", "choices": ["Acute myocardial infarction", "Acute pulmonary embolism", "Acute pericarditis", "Spontaneous pneumothorax", "Acute aortic dissection"], "ans": 4, "exp": "เจ็บอกแบบ tearing ร้าวหลัง + ความดันสองแขนต่างกัน + mediastinum กว้าง = aortic dissection. Type A (ascending) ต้องผ่าตัดฉุกเฉิน; Type B คุมด้วยยา (beta-blocker ลด HR/BP ก่อน). ยืนยันด้วย CT angiography.", "id": "set1-50"}, {"topic": "Pulmonology", "q": "A 25-year-old with episodic wheeze and nocturnal cough has spirometry showing an obstructive pattern that improves after a bronchodilator (FEV1 rises 15% and 300 mL). What is the diagnosis?", "choices": ["Bronchial asthma", "COPD", "Bronchiectasis", "Interstitial lung disease", "Vocal cord dysfunction"], "ans": 0, "exp": "Reversible airflow obstruction (FEV1 เพิ่ม ≥12% และ ≥200 mL หลัง bronchodilator) + อาการเป็นๆ หายๆ = asthma. ต่างจาก COPD ที่ obstruction ไม่ reversible เต็มที่.", "id": "set1-51"}, {"topic": "Pulmonology", "q": "According to GINA 2025, what is the preferred reliever/controller strategy even in mild asthma?", "choices": ["SABA alone as needed", "ICS-formoterol as reliever (and maintenance)", "Oral steroid as needed", "LABA alone as needed", "Theophylline as needed"], "ans": 1, "exp": "GINA 2025 ห้ามใช้ SABA เดี่ยว; ทุกคนต้องได้ ICS-containing reliever โดยแนะนำ ICS-formoterol เป็นทั้ง reliever และ maintenance (AIR/MART) เพราะลดการกำเริบรุนแรงและการเสียชีวิต.", "id": "set1-52"}, {"topic": "Pulmonology", "q": "A patient with acute severe asthma is tiring; ABG shows a 'normal' PaCO2. How should this be interpreted?", "choices": ["Reassuring, patient improving", "Compensated metabolic alkalosis", "Impending respiratory failure", "A normal, expected finding", "Chronic compensation only"], "ans": 2, "exp": "ในหอบรุนแรง ผู้ป่วยควร hyperventilate ทำให้ PaCO2 ต่ำ. PaCO2 ที่ 'ปกติ' หรือสูงขึ้นบ่งชี้กล้ามเนื้อหายใจล้า = impending respiratory failure ต้องเฝ้าใกล้ชิด/เตรียมช่วยหายใจ.", "id": "set1-53"}, {"topic": "Pulmonology", "q": "A 65-year-old smoker has chronic productive cough and dyspnea; post-bronchodilator FEV1/FVC is 0.60. What is the single most effective intervention to slow disease progression?", "choices": ["Inhaled corticosteroid", "Oral theophylline", "Long-term antibiotics", "Smoking cessation", "Mucolytic agents"], "ans": 3, "exp": "COPD (FEV1/FVC < 0.70 post-BD). การหยุดบุหรี่เป็นสิ่งเดียวที่ชะลอการเสื่อมของ lung function และลด mortality ได้ชัดเจนที่สุด. ยาสูดช่วยอาการ/ลด exacerbation แต่ไม่ชะลอ decline เท่า.", "id": "set1-54"}, {"topic": "Pulmonology", "q": "Under GOLD 2025, a COPD patient in Group B or Group E should be started on which initial inhaled therapy?", "choices": ["SABA as needed only", "ICS monotherapy", "Oral corticosteroid", "Theophylline therapy", "LABA + LAMA combination"], "ans": 4, "exp": "GOLD 2025 แนะนำเริ่ม LABA + LAMA (คู่) ในทั้ง Group B และ Group E. Group A ใช้ bronchodilator เดี่ยว. เพิ่ม ICS (triple) เมื่อ eosinophil > 300 หรือ Group E ที่ eos สูง.", "id": "set1-55"}, {"topic": "Pulmonology", "q": "A COPD patient presents with increased dyspnea, sputum volume, and purulence. Besides bronchodilators and systemic steroids, what else is indicated?", "choices": ["Add antibiotics", "Immediate intubation", "IV magnesium sulfate", "Diuretic therapy", "Long-term home oxygen"], "ans": 0, "exp": "AECOPD ที่มี cardinal symptoms ครบ (เหนื่อยเพิ่ม + เสมหะเพิ่ม + เสมหะเป็นหนอง) หรือเสมหะเป็นหนอง+อีก 1 ข้อ หรือต้องใช้ ventilator → ให้ antibiotics ร่วมกับ SABA±SAMA และ systemic corticosteroid 5 วัน.", "id": "set1-56"}, {"topic": "Pulmonology", "q": "A COPD patient in exacerbation has pH 7.28, PaCO2 68. What is the most appropriate respiratory support?", "choices": ["High-flow O2 to reach SpO2 100%", "Non-invasive ventilation (BiPAP)", "Immediate tracheostomy", "Nasal cannula oxygen only", "Sedation and observation"], "ans": 1, "exp": "Hypercapnic respiratory acidosis (pH < 7.35, PaCO2 สูง) ใน AECOPD ตอบสนองดีต่อ NIV (BiPAP) ซึ่งลดการใส่ท่อและ mortality. ให้ O2 แบบควบคุม (เป้า SpO2 88–92%) ไม่ใช่ให้จนถึง 100%.", "id": "set1-57"}, {"topic": "Pulmonology", "q": "A previously healthy adult with CAP has CURB-65 = 0 and no comorbidities. What is appropriate first-line outpatient therapy?", "choices": ["IV ceftriaxone plus azithromycin", "IV respiratory fluoroquinolone", "High-dose amoxicillin (or a macrolide/doxycycline)", "IV vancomycin therapy", "No antibiotic needed"], "ans": 2, "exp": "CAP ที่ CURB-65 ต่ำและไม่มีโรคร่วม รักษาแบบผู้ป่วยนอกด้วย amoxicillin ขนาดสูง หรือ macrolide/doxycycline. ผู้มีโรคร่วมใช้ β-lactam + macrolide หรือ respiratory FQ; admit ใช้ ceftriaxone + azithromycin.", "id": "set1-58"}, {"topic": "Pulmonology", "q": "A 32-year-old man with HIV (CD4 120) has 3 weeks of exertional dyspnea, dry cough, SpO2 88%, and bilateral perihilar interstitial infiltrates. Which test best confirms the diagnosis?", "choices": ["Sputum AFB smear and culture", "PCR of sputum for Mycoplasma", "Blood culture for pneumococcus", "Immunofluorescence of induced sputum for Pneumocystis jirovecii", "Urine antigen for Legionella"], "ans": 3, "exp": "ภาพเข้าได้กับ PCP (Pneumocystis jirovecii) ใน HIV ที่ CD4 < 200. ยืนยันด้วย immunofluorescence/stain ของ induced sputum หรือ BAL. รักษาด้วย high-dose co-trimoxazole + steroid ถ้า PaO2 ต่ำ/A-a gradient กว้าง. (แนวข้อสอบ NLE2)", "id": "set1-59"}, {"topic": "Pulmonology", "q": "A 50-year-old with 2 weeks of productive cough, hemoptysis, night sweats, and a right-upper-lobe cavity on CXR most likely has:", "choices": ["Community-acquired pneumonia", "Aspiration lung abscess", "Acute pulmonary embolism", "Pulmonary sarcoidosis", "Pulmonary tuberculosis"], "ans": 4, "exp": "ไอเรื้อรัง + ไอเป็นเลือด + เหงื่อกลางคืน + upper-lobe cavity เข้าได้กับ pulmonary TB. ยืนยันด้วย sputum AFB/Xpert MTB/RIF (บอกดื้อ rifampicin) + culture.", "id": "set1-60"}, {"topic": "Pulmonology", "q": "According to WHO 2022, which regimen is now an option for drug-susceptible pulmonary TB?", "choices": ["A 4-month rifapentine–moxifloxacin regimen", "A 24-month injectable regimen", "Isoniazid monotherapy", "Rifampicin alone for 2 months", "The BPaL regimen for all cases"], "ans": 0, "exp": "WHO 2022 มีสูตร 4 เดือนสำหรับ DS-TB (2 เดือน HPZM + 2 เดือน HPM, rifapentine+moxifloxacin) เป็นทางเลือกนอกเหนือสูตร 6 เดือน 2HRZE/4HR. BPaL/BPaLM ใช้กับ DR-TB.", "id": "set1-61"}, {"topic": "Pulmonology", "q": "Which anti-TB drug most classically causes optic neuritis (reduced visual acuity and color vision)?", "choices": ["Isoniazid", "Ethambutol", "Rifampicin", "Pyrazinamide", "Streptomycin"], "ans": 1, "exp": "Ethambutol ทำให้เกิด optic neuritis (visual acuity/color vision ลด). INH → peripheral neuropathy (ให้ pyridoxine); Rifampicin → orange secretions; PZA → hyperuricemia; ทั้งกลุ่มเสี่ยง hepatitis.", "id": "set1-62"}, {"topic": "Pulmonology", "q": "A pleural effusion has pleural/serum protein ratio 0.7 and pleural/serum LDH ratio 0.8. How is it classified and what does it suggest?", "choices": ["Transudate; from heart failure", "Transudate; from cirrhosis", "Exudate; infection/malignancy/TB", "Chylothorax from lymphatics", "Hemothorax from bleeding"], "ans": 2, "exp": "เข้าเกณฑ์ Light's criteria เป็น exudate (protein ratio > 0.5 หรือ LDH ratio > 0.6). สาเหตุ exudate = infection (parapneumonic/empyema), malignancy, TB. Transudate = HF, cirrhosis, nephrotic.", "id": "set1-63"}, {"topic": "Pulmonology", "q": "A parapneumonic effusion has pH 7.10, low glucose, and frank pus. What is the appropriate management?", "choices": ["Antibiotics alone without drainage", "Observation without drainage", "Diuretic therapy", "Chest tube drainage plus antibiotics", "Repeat tap in 1 week"], "ans": 3, "exp": "Complicated parapneumonic effusion/empyema (pH < 7.2, glucose ต่ำ, หนอง) ต้องระบายด้วย chest tube (ICD) ร่วมกับ antibiotics; อาจต้อง fibrinolytic/VATS ถ้า loculated.", "id": "set1-64"}, {"topic": "Pulmonology", "q": "A tall thin young man has sudden pleuritic chest pain and dyspnea; exam shows hyperresonance and absent breath sounds on one side with tracheal deviation and hypotension. What is the immediate action?", "choices": ["Obtain a chest X-ray first", "Obtain a CT of the chest first", "Observation with oxygen only", "Endotracheal intubation only", "Needle/finger decompression then chest tube"], "ans": 4, "exp": "อาการเข้ากับ tension pneumothorax (hypotension + tracheal deviation) เป็นการวินิจฉัยทางคลินิก อย่ารอ CXR ต้อง decompress ทันที (needle/finger) แล้วใส่ ICD.", "id": "set1-65"}, {"topic": "Pulmonology", "q": "Which describes type 2 (hypercapnic) respiratory failure?", "choices": ["PaCO2 > 45 with respiratory acidosis", "PaO2 < 60 with normal/low PaCO2", "A completely normal ABG", "Metabolic acidosis only", "Isolated hypoxemia from shunt"], "ans": 0, "exp": "Type 2 respiratory failure = hypoventilation → PaCO2 > 45 + respiratory acidosis (COPD, neuromuscular, CNS depression). Type 1 = hypoxemic (PaO2 < 60, PaCO2 ปกติ/ต่ำ) จาก V/Q mismatch/shunt.", "id": "set1-66"}, {"topic": "Pulmonology", "q": "ABG: pH 7.30, HCO3 14, PaCO2 30, Na 140, Cl 100. What is the primary disorder?", "choices": ["Primary respiratory acidosis", "High anion gap metabolic acidosis", "Primary metabolic alkalosis", "Primary respiratory alkalosis", "A normal acid-base state"], "ans": 1, "exp": "pH ต่ำ + HCO3 ต่ำ = metabolic acidosis; anion gap = 140 − 100 − 14 = 26 (สูง) → high anion gap metabolic acidosis. PaCO2 30 = respiratory compensation (Winter: 1.5×14+8=29 ≈ เหมาะสม). สาเหตุ MUDPILES.", "id": "set1-67"}, {"topic": "Pulmonology", "q": "Which condition causes a NORMAL anion gap (hyperchloremic) metabolic acidosis?", "choices": ["Diabetic ketoacidosis", "Lactic acidosis", "Severe diarrhea", "Methanol poisoning", "Uremia from renal failure"], "ans": 2, "exp": "Severe diarrhea เสีย HCO3 ทาง GI ทำให้ normal anion gap (hyperchloremic) metabolic acidosis. DKA, lactic acidosis, methanol, uremia ล้วนเป็น high anion gap (MUDPILES).", "id": "set1-68"}, {"topic": "Pulmonology", "q": "A patient with sepsis-related ARDS has bilateral infiltrates and PaO2/FiO2 = 150 with no cardiac cause. Which ventilator strategy is recommended?", "choices": ["High tidal volume around 12 mL/kg", "High FiO2 with high PEEP only", "A permissive hyperoxia strategy", "Lung-protective ventilation (Vt ~6 mL/kg, plateau < 30) + consider prone", "Ventilation while avoiding PEEP"], "ans": 3, "exp": "ARDS ใช้ lung-protective ventilation (Vt 6 mL/kg predicted BW, plateau pressure < 30) + prone positioning ในราย moderate-severe + จัดการสาเหตุ. High tidal volume เพิ่ม ventilator-induced lung injury.", "id": "set1-69"}, {"topic": "Pulmonology", "q": "A post-operative patient develops sudden dyspnea and pleuritic chest pain; Wells score is high. What is the best confirmatory test?", "choices": ["Serum D-dimer assay", "Plain chest X-ray", "Bedside echocardiography", "Sputum culture", "CT pulmonary angiography"], "ans": 4, "exp": "เมื่อ pretest probability สูง (Wells สูง) ควรทำ CT pulmonary angiography (gold standard) เลย ไม่ใช้ D-dimer (มีประโยชน์เฉพาะ low/intermediate เพื่อ rule out). V/Q scan ใช้เมื่อทำ CT ไม่ได้.", "id": "set1-70"}, {"topic": "Pulmonology", "q": "A hemodynamically unstable patient with massive PE and shock should receive:", "choices": ["Systemic thrombolysis (or embolectomy)", "Anticoagulation with a DOAC only", "IVC filter placement alone", "Aspirin monotherapy", "Observation without treatment"], "ans": 0, "exp": "Massive PE (hypotension/shock) มี indication สำหรับ systemic thrombolysis (หรือ catheter/surgical embolectomy ถ้ามีข้อห้าม) นอกเหนือจาก anticoagulation. Submassive/stable ใช้ anticoagulation เป็นหลัก.", "id": "set1-71"}, {"topic": "Pulmonology", "q": "A 55-year-old heavy smoker has a spiculated 2 cm lung nodule that grew compared to a prior film. What is the most appropriate next step?", "choices": ["Repeat the chest X-ray in 1 year", "Tissue diagnosis (biopsy) ± PET/CT staging", "Reassure with no further follow-up", "Start empiric antibiotics", "Start empiric anti-TB drugs"], "ans": 1, "exp": "Nodule ที่ spiculated, โตขึ้น, ในผู้สูบจัด = เสี่ยงมะเร็งสูง ควร characterize ด้วย CT/PET และ tissue diagnosis (biopsy) เพื่อวินิจฉัยและ staging. การรอเฉยเหมาะกับ nodule เสี่ยงต่ำเท่านั้น.", "id": "set1-72"}, {"topic": "Pulmonology", "q": "Which lung cancer is most strongly associated with SIADH and Cushing (ectopic ACTH) paraneoplastic syndromes?", "choices": ["Pulmonary adenocarcinoma", "Squamous cell carcinoma", "Small cell lung cancer", "Large cell carcinoma", "Pulmonary carcinoid tumor"], "ans": 2, "exp": "Small cell lung cancer (SCLC) สัมพันธ์ paraneoplastic ที่เป็น neuroendocrine เช่น SIADH และ ectopic ACTH (Cushing), Lambert-Eaton. Squamous cell → hypercalcemia (PTHrP).", "id": "set1-73"}, {"topic": "Pulmonology", "q": "A squamous cell lung cancer patient presents with confusion, constipation, and a calcium of 13 mg/dL. What is the mechanism?", "choices": ["SIADH-mediated effect", "Ectopic ACTH secretion", "Bone metastasis alone", "PTHrP secretion (humoral hypercalcemia)", "Primary hypoparathyroidism"], "ans": 3, "exp": "Squamous cell carcinoma หลั่ง PTHrP ทำให้เกิด humoral hypercalcemia of malignancy (hyperCa → stones/bones/groans/moans). รักษา IV fluid + bisphosphonate/calcitonin + รักษามะเร็ง.", "id": "set1-74"}, {"topic": "Pulmonology", "q": "Which oxygen delivery device most precisely controls FiO2, useful in COPD patients at risk of CO2 retention?", "choices": ["Simple nasal cannula", "Simple face mask", "Non-rebreather mask", "Bag-valve mask", "Venturi (air-entrainment) mask"], "ans": 4, "exp": "Venturi mask ให้ FiO2 ที่แม่นยำ (24–60%) จึงเหมาะกับ COPD ที่ต้องคุม O2 (เป้า SpO2 88–92%) เพื่อเลี่ยง CO2 retention. Non-rebreather ให้ FiO2 สูงแต่ควบคุมไม่แม่น.", "id": "set1-75"}, {"topic": "Pulmonology", "q": "A patient with stable COPD has resting PaO2 54 mmHg (SpO2 87%). Which intervention improves survival?", "choices": ["Long-term oxygen therapy (>15 h/day)", "Inhaled corticosteroid", "Oral theophylline", "Prophylactic antibiotics", "Mucolytic agents"], "ans": 0, "exp": "Long-term oxygen therapy (LTOT) ในผู้ป่วย COPD ที่ PaO2 ≤ 55 หรือ SpO2 ≤ 88% (หรือ ≤ 59/89% ที่มี cor pulmonale/polycythemia) ช่วยเพิ่มอัตราการรอดชีวิตเมื่อใช้ > 15 ชม./วัน.", "id": "set1-76"}, {"topic": "Pulmonology", "q": "A young non-smoker with recurrent pneumonia, chronic cough with copious purulent sputum, and 'tram-track' opacities most likely has:", "choices": ["Bronchial asthma", "Bronchiectasis", "Simple chronic bronchitis", "Pulmonary fibrosis", "Pulmonary sarcoidosis"], "ans": 1, "exp": "อาการไอเสมหะมากเรื้อรัง + ปอดอักเสบซ้ำ + tram-track/ring shadow เข้าได้กับ bronchiectasis (ยืนยันด้วย HRCT). หาสาเหตุ (post-infection, CF, immunodeficiency) + airway clearance + ATB เวลากำเริบ.", "id": "set1-77"}, {"topic": "Pulmonology", "q": "Which finding on examination suggests consolidation (e.g., lobar pneumonia)?", "choices": ["Hyperresonance with absent breath sounds", "Tracheal deviation to the opposite side", "Bronchial breath sounds, increased vocal fremitus, egophony", "Isolated expiratory wheeze", "A pleural friction rub only"], "ans": 2, "exp": "Consolidation ทำให้เสียงส่งผ่านดีขึ้น: bronchial breath sound, increased tactile/vocal fremitus, egophony (E→A), dullness to percussion. Hyperresonance + absent breath sound = pneumothorax.", "id": "set1-78"}, {"topic": "Pulmonology", "q": "A patient has an exudative lymphocyte-predominant pleural effusion with high adenosine deaminase (ADA). What is the most likely cause in an endemic area?", "choices": ["Heart failure effusion", "Rheumatoid pleural effusion", "Chylothorax", "Tuberculous pleuritis", "Empyema (frank pus)"], "ans": 3, "exp": "Exudate ที่ lymphocyte เด่น + ADA สูง ในพื้นที่ระบาด เข้าได้กับ tuberculous pleuritis. ยืนยันด้วย pleural biopsy (granuloma)/culture; ตอบสนองดีต่อ anti-TB.", "id": "set1-79"}, {"topic": "Pulmonology", "q": "What is the classic ECG finding sometimes seen in acute pulmonary embolism (though sinus tachycardia is most common)?", "choices": ["A delta wave", "Peaked T waves", "Prominent U waves", "An Osborn wave", "An S1Q3T3 pattern"], "ans": 4, "exp": "S1Q3T3 (S ใน I, Q และ T inversion ใน III) เป็น classic แต่พบไม่บ่อยใน PE; สิ่งที่พบบ่อยสุดคือ sinus tachycardia. อาจเห็น RV strain (T inversion V1–V4).", "id": "set1-80"}, {"topic": "Pulmonology", "q": "A patient on long-term home oxygen for COPD suddenly becomes drowsy after oxygen was turned up to high flow. What happened?", "choices": ["CO2 retention/hypercapnia worsened by uncontrolled high-flow O2", "An oxygen-toxicity seizure", "Acute hypoglycemia", "Acute pulmonary embolism", "Spontaneous pneumothorax"], "ans": 0, "exp": "ในบาง COPD ที่เป็น chronic CO2 retainer การให้ O2 สูงเกินไปอาจทำให้ CO2 คั่งมากขึ้น (ลด hypoxic drive + V/Q + Haldane effect) → ซึม. ควรให้ O2 แบบควบคุมเป้า SpO2 88–92% และตรวจ ABG.", "id": "set1-81"}, {"topic": "Pulmonology", "q": "Which is the initial diagnostic test of choice to confirm airflow obstruction in suspected COPD?", "choices": ["High-resolution chest CT", "Spirometry (post-bronchodilator FEV1/FVC)", "Peak flow measurement only", "Arterial blood gas", "Serum D-dimer"], "ans": 1, "exp": "COPD ยืนยันด้วย spirometry ที่ post-bronchodilator FEV1/FVC < 0.70. CXR/CT ช่วยดู complication/ตัดสาเหตุอื่น แต่ไม่ใช้วินิจฉัยหลัก.", "id": "set1-82"}, {"topic": "Pulmonology", "q": "A patient with asthma has frequent night symptoms despite low-dose ICS-formoterol maintenance. According to GINA, what is the appropriate step-up?", "choices": ["Add a SABA reliever only", "Stop the inhaled corticosteroid", "Increase to medium-dose ICS-formoterol", "Long-term oral corticosteroid", "Add empiric antibiotics"], "ans": 2, "exp": "เมื่อคุมไม่ได้ด้วย low-dose ICS-formoterol maintenance (step 3) ให้ step up เป็น medium-dose ICS-formoterol (step 4) ก่อนพิจารณา LAMA/biologic (step 5). ตรวจ adherence/inhaler technique/trigger ก่อนเสมอ.", "id": "set1-83"}, {"topic": "Pulmonology", "q": "A patient develops an anaphylactic reaction with wheeze, hypotension, and angioedema after a bee sting. What is the first-line drug?", "choices": ["IV hydrocortisone", "IV antihistamine", "Nebulized salbutamol", "Intramuscular adrenaline (epinephrine)", "IV fluids alone"], "ans": 3, "exp": "Anaphylaxis รักษาลำดับแรกด้วย IM adrenaline (epinephrine) ที่ต้นขาด้านนอก ทันที + วางราบ/ยกขา + O2 + IV fluid; steroid/antihistamine เป็น adjunct ไม่ใช่ตัวหลัก.", "id": "set1-84"}, {"topic": "Pulmonology", "q": "A patient with idiopathic pulmonary fibrosis has fine bibasal 'velcro' crackles and reticular changes with honeycombing at the bases on HRCT. Which is true about management?", "choices": ["High-dose steroids are curative", "Antibiotics are curative", "Bronchodilators reverse it", "No treatment affects progression", "Antifibrotics (pirfenidone/nintedanib) slow decline"], "ans": 4, "exp": "IPF (UIP pattern: subpleural basal reticulation + honeycombing) รักษาด้วย antifibrotic (pirfenidone/nintedanib) ชะลอการเสื่อมของ FVC; steroid ไม่ช่วยและอาจอันตรายใน IPF. พิจารณา lung transplant.", "id": "set1-85"}, {"topic": "Pulmonology", "q": "A diabetic patient has fever, right-sided chest pain, and CXR shows a cavity with an air-fluid level following an aspiration event. What is the likely diagnosis?", "choices": ["Lung abscess", "Pulmonary tuberculosis", "Pulmonary embolism", "Pulmonary sarcoidosis", "Cavitating lung cancer"], "ans": 0, "exp": "หลัง aspiration + cavity ที่มี air-fluid level = lung abscess (มัก anaerobe/mixed oral flora, บริเวณ dependent เช่น RLL/posterior segment). รักษาด้วย antibiotics คลุม anaerobe (clindamycin/β-lactam-β-lactamase inhibitor) นาน.", "id": "set1-86"}, {"topic": "Pulmonology", "q": "A young woman has dyspnea, bilateral hilar lymphadenopathy on CXR, erythema nodosum, and elevated serum ACE. What is the most likely diagnosis?", "choices": ["Pulmonary tuberculosis", "Sarcoidosis", "Mediastinal lymphoma", "Silicosis", "Histoplasmosis"], "ans": 1, "exp": "Bilateral hilar lymphadenopathy + erythema nodosum + ACE สูง เข้าได้กับ sarcoidosis (non-caseating granuloma). Löfgren syndrome (arthritis + BHL + erythema nodosum) พยากรณ์ดี มักหายเอง.", "id": "set1-87"}, {"topic": "Pulmonology", "q": "In interpreting a chest X-ray, Kerley B lines and cephalization of vessels suggest:", "choices": ["Lobar pneumonia", "Pneumothorax", "Pulmonary edema (cardiogenic congestion)", "Emphysema", "Pleural effusion only"], "ans": 2, "exp": "Kerley B lines + cephalization + perihilar (bat-wing) opacities + cardiomegaly เข้าได้กับ cardiogenic pulmonary edema. ช่วยแยกจาก ARDS ที่หัวใจปกติและ infiltrate กระจายทั่ว.", "id": "set1-88"}, {"topic": "Pulmonology", "q": "A patient with severe CAP requiring ICU admission should receive which empiric regimen?", "choices": ["Oral amoxicillin alone", "Oral doxycycline alone", "IV vancomycin alone", "IV beta-lactam (e.g., ceftriaxone) plus a macrolide or respiratory fluoroquinolone", "No antibiotics until culture"], "ans": 3, "exp": "Severe CAP (ICU) ใช้ IV β-lactam (ceftriaxone) + macrolide (azithromycin) หรือ respiratory fluoroquinolone. พิจารณาคลุม MRSA/Pseudomonas ตามความเสี่ยง.", "id": "set1-89"}, {"topic": "Pulmonology", "q": "A patient with obstructive sleep apnea has daytime somnolence and witnessed apneas. What is the first-line treatment for moderate-to-severe OSA?", "choices": ["Weight loss measures only", "Nocturnal oxygen alone", "Sedative medication", "Surgical tracheostomy", "Continuous positive airway pressure (CPAP)"], "ans": 4, "exp": "OSA ระดับปานกลาง-รุนแรง first-line คือ CPAP (ร่วมกับลดน้ำหนัก/เลี่ยงแอลกอฮอล์-ยานอนหลับ). O2 เดี่ยวไม่แก้ obstruction; sedative จะทำให้แย่ลง.", "id": "set1-90"}, {"topic": "Pulmonology", "q": "A patient with massive hemoptysis (>200 mL/day). What is the priority in initial management?", "choices": ["Airway protection and positioning bleeding side down", "Immediate emergency lobectomy", "Give systemic thrombolytics", "Start therapeutic anticoagulation", "Discharge with a cough suppressant"], "ans": 0, "exp": "Massive hemoptysis เสี่ยง asphyxiation มากกว่า exsanguination — จัดการ airway ก่อน (ป้องกันเลือดท่วมปอดดี, จัดท่าให้ข้างที่เลือดออกอยู่ล่าง), resuscitate, แล้ว localize (bronchoscopy/CT) + bronchial artery embolization; หลีกเลี่ยง anticoagulant.", "id": "set1-91"}, {"topic": "Pulmonology", "q": "Which criterion is part of CURB-65 for pneumonia severity?", "choices": ["Age ≥ 50 years alone", "Confusion, Urea > 19 mg/dL, RR ≥ 30, BP < 90/60, Age ≥ 65", "WBC greater than 12,000", "CRP greater than 100", "SpO2 below 95%"], "ans": 1, "exp": "CURB-65 = Confusion, Urea > 7 mmol/L (~19 mg/dL BUN), RR ≥ 30, BP (SBP<90 หรือ DBP≤60), Age ≥ 65. คะแนนสูงขึ้น = พิจารณา admit/ICU.", "id": "set1-92"}, {"topic": "Pulmonology", "q": "A febrile neutropenic oncology patient develops cough and a new lung infiltrate. Empiric antibiotics should be started within what time frame?", "choices": ["Within about 24 hours", "Within about 72 hours", "Within 1 hour", "Only after culture results", "Only if the patient is unstable"], "ans": 2, "exp": "Febrile neutropenia เป็นภาวะฉุกเฉิน ต้องให้ empiric broad-spectrum antibiotic (คลุม Pseudomonas เช่น piperacillin-tazobactam/cefepime/carbapenem) ภายใน 1 ชม.หลังเจาะ culture.", "id": "set1-93"}, {"topic": "Pulmonology", "q": "A patient with COPD is assessed for exacerbation risk. Which parameter guides the addition of inhaled corticosteroid to LABA/LAMA?", "choices": ["Serum CRP level", "Serum D-dimer", "Serum BNP level", "Blood eosinophil count", "Serum IgE level only"], "ans": 3, "exp": "GOLD ใช้ blood eosinophil count นำการเพิ่ม ICS: เพิ่ม ICS (triple therapy) เมื่อ eos ≥ 300 หรือใน Group E ที่ eos สูง/ประวัติ exacerbation บ่อย; หลีกเลี่ยง ICS ถ้า eos < 100 (ประโยชน์น้อย เสี่ยงปอดอักเสบ).", "id": "set1-94"}, {"topic": "Pulmonology", "q": "A 40-year-old presents with acute hypersensitivity: fever, cough, and dyspnea hours after exposure to moldy hay, with diffuse ground-glass on CT. What is the diagnosis?", "choices": ["Acute bronchial asthma", "Bacterial pneumonia", "Pulmonary embolism", "COPD exacerbation", "Hypersensitivity pneumonitis"], "ans": 4, "exp": "อาการหลังสัมผัส antigen (moldy hay = Farmer's lung) + ไข้/ไอ/เหนื่อย + ground-glass เข้าได้กับ hypersensitivity pneumonitis. การรักษาสำคัญคือหลีกเลี่ยง antigen ± corticosteroid.", "id": "set1-95"}, {"topic": "Pulmonology", "q": "Which best differentiates cardiogenic pulmonary edema (type of respiratory failure) from ARDS?", "choices": ["Elevated BNP and cardiac cause supports cardiogenic edema", "Bilateral infiltrates are present in both", "The PaO2/FiO2 ratio value", "The presence of dyspnea", "The need for supplemental oxygen"], "ans": 0, "exp": "ทั้งคู่มี bilateral infiltrate + hypoxemia. สิ่งที่แยกคือหลักฐานของ cardiac cause (BNP สูง, EF ต่ำ, cardiomegaly, response to diuretic) ใน cardiogenic edema; ARDS ไม่ได้เกิดจาก hydrostatic/cardiac เพียงอย่างเดียว.", "id": "set1-96"}, {"topic": "Pulmonology", "q": "A patient develops stridor and drooling with rapid-onset severe sore throat and high fever; he is sitting forward (tripod). What is the immediate concern?", "choices": ["Simple viral pharyngitis", "Acute epiglottitis (airway emergency)", "The common cold", "Allergic rhinitis", "A tonsillar stone (tonsillolith)"], "ans": 1, "exp": "Stridor + drooling + tripod position + toxic เข้าได้กับ acute epiglottitis เป็นภาวะฉุกเฉินทางเดินหายใจ — ห้ามตรวจคอโดยไม่พร้อม, ให้ secure airway โดยผู้เชี่ยวชาญ + IV antibiotics (ceftriaxone).", "id": "set1-97"}, {"topic": "Pulmonology", "q": "A patient recovering from viral illness develops a normal-anion-gap picture with rapid deep breathing (Kussmaul) — actually found to have DKA. Kussmaul breathing represents what compensation?", "choices": ["Primary respiratory acidosis", "Primary metabolic alkalosis", "Respiratory compensation for metabolic acidosis", "Primary respiratory alkalosis", "No compensation occurring"], "ans": 2, "exp": "Kussmaul breathing (หายใจลึกเร็ว) เป็น respiratory compensation ต่อ metabolic acidosis (เช่น DKA) เพื่อขับ CO2 ลด acidemia. คำนวณด้วย Winter's formula เพื่อดูว่า compensation เหมาะสม.", "id": "set1-98"}, {"topic": "Pulmonology", "q": "Which patient with a solitary pulmonary nodule can be safely followed with serial imaging rather than immediate biopsy?", "choices": ["Spiculated, growing nodule in a heavy smoker", "A nodule with high PET avidity", "Cavitating nodule with weight loss", "Small (<6 mm) smooth nodule with benign calcification in a low-risk patient", "A nodule enlarging over 3 months"], "ans": 3, "exp": "Nodule ที่เล็ก, ขอบเรียบ, มี benign calcification (popcorn = hamartoma, central/laminated), ในคนเสี่ยงต่ำ มีโอกาสมะเร็งต่ำ ติดตามด้วย imaging ได้. ลักษณะเสี่ยง (spiculated, โตเร็ว, PET avid, สูบจัด) → biopsy.", "id": "set1-99"}, {"topic": "Pulmonology", "q": "A patient presents with acute dyspnea and wheeze. Which single feature most strongly indicates a life-threatening asthma attack requiring immediate escalation?", "choices": ["Peak flow at 70% of predicted", "Only mild expiratory wheeze", "A respiratory rate of 18", "An SpO2 of 97%", "Silent chest with inability to speak in full sentences"], "ans": 4, "exp": "Silent chest (airflow น้อยจนไม่ได้ยิน wheeze) + พูดไม่จบประโยค + ใช้กล้ามเนื้อช่วยหายใจ = life-threatening asthma. ต้อง O2, nebulized SABA+ipratropium ซ้ำ, systemic steroid, IV magnesium และเตรียมช่วยหายใจ.", "id": "set1-100"}]}, {"id": "set2", "title": "ชุดที่ 2 — Nephrology + Endocrine", "questions": [{"topic": "Nephrology", "q": "A hypotensive patient after GI bleeding has oliguria, BUN/Cr ratio 25, FeNa 0.5%, and concentrated urine. What type of AKI is this?", "choices": ["Prerenal azotemia", "Acute tubular necrosis", "Acute interstitial nephritis", "Postrenal obstruction", "Acute glomerulonephritis"], "ans": 0, "exp": "BUN/Cr > 20, FeNa < 1%, urine เข้มข้น + ประวัติ hypovolemia = prerenal AKI (ไตยัง reabsorb Na/น้ำได้ดี). รักษาโดยแก้ volume; ถ้าปล่อยไว้อาจกลายเป็น ATN.", "id": "set2-1"}, {"topic": "Nephrology", "q": "A patient develops AKI after prolonged hypotension; urine shows muddy brown granular casts and FeNa 3%. What is the diagnosis?", "choices": ["Prerenal azotemia", "Acute tubular necrosis", "Postrenal obstruction", "Minimal change disease", "Prerenal azotemia from CHF"], "ans": 1, "exp": "Muddy brown granular cast + FeNa > 2% (ไตเสียความสามารถ reabsorb Na) หลัง ischemia/hypotension = acute tubular necrosis. รักษาแบบประคับประคอง หลีกเลี่ยง nephrotoxin, รอ recovery.", "id": "set2-2"}, {"topic": "Nephrology", "q": "Which is an absolute indication for urgent dialysis in AKI?", "choices": ["A blood urea nitrogen of 40 mg/dL without other complications", "A serum creatinine of 2.5 mg/dL without other complications", "Refractory hyperkalemia, pulmonary edema, severe acidosis, or uremia", "A mild metabolic acidosis that responds to bicarbonate", "Isolated proteinuria without any electrolyte disturbance"], "ans": 2, "exp": "ข้อบ่งชี้ dialysis (AEIOU): Acidosis รุนแรงดื้อยา, Electrolyte (hyperK ดื้อยา), Intoxication, Overload (pulmonary edema ดื้อยา), Uremia (encephalopathy/pericarditis/bleeding). ค่า BUN/Cr เดี่ยวไม่ใช่ข้อบ่งชี้.", "id": "set2-3"}, {"topic": "Nephrology", "q": "A patient started on an ACE inhibitor for hypertension has a creatinine rise of 40% within a week and a bruit is heard over the abdomen. What is the likely cause?", "choices": ["Diabetic nephropathy", "Acute glomerulonephritis", "Simple dehydration only", "Bilateral renal artery stenosis", "Expected normal ACEI effect"], "ans": 3, "exp": "Cr เพิ่มมาก (> 30%) หลังเริ่ม ACEI + abdominal bruit นึกถึง bilateral renal artery stenosis ซึ่ง efferent arteriole พึ่ง angiotensin II เพื่อคง GFR. หยุด ACEI และประเมิน renal artery.", "id": "set2-4"}, {"topic": "Nephrology", "q": "A CKD patient has Hb 8.5, low iron studies corrected, and no bleeding. What is the main mechanism of the anemia?", "choices": ["Iron deficiency alone", "Chronic hemolysis", "Vitamin B12 deficiency", "Underlying thalassemia", "Reduced erythropoietin production"], "ans": 4, "exp": "Anemia of CKD เกิดจากไตผลิต erythropoietin ลดลง (normocytic normochromic). รักษาด้วย ESA (erythropoiesis-stimulating agent) หลังแก้ iron ให้พอ; เป้า Hb ไม่สูงเกิน (~10–11.5).", "id": "set2-5"}, {"topic": "Nephrology", "q": "Which medication class is now recommended to slow CKD progression in a patient with eGFR 30 and albuminuria (per KDIGO 2024)?", "choices": ["An SGLT2 inhibitor", "A loop diuretic", "A calcium channel blocker", "A beta-blocker", "An NSAID"], "ans": 0, "exp": "KDIGO 2024 แนะนำ SGLT2 inhibitor ใน CKD (eGFR ≥ 20) ที่มี albuminuria (ACR ≥ 200) หรือ HF เพื่อชะลอการเสื่อมของไต ร่วมกับ ACEI/ARB. Finerenone เพิ่มเติมใน T2D + albuminuria.", "id": "set2-6"}, {"topic": "Nephrology", "q": "A patient with type 2 diabetes, eGFR 40, albuminuria persists despite maximal ARB and an SGLT2i, K+ normal. What can be added to further reduce albuminuria?", "choices": ["Spironolactone (steroidal MRA)", "Finerenone (nonsteroidal MRA)", "A second added ARB", "Amlodipine therapy", "Hydralazine therapy"], "ans": 1, "exp": "KDIGO/ADA แนะนำ finerenone (nonsteroidal MRA) ใน T2D + albuminuria, eGFR > 25, K+ ปกติ ที่ยังมี albuminuria แม้ใช้ RASi เต็มที่ — ลด CV/renal events. ไม่ใช้ ACEI+ARB ร่วมกัน.", "id": "set2-7"}, {"topic": "Nephrology", "q": "A patient has serum Na 118 mmol/L, is euvolemic, with high urine osmolality and urine Na > 40. Which is the most likely cause?", "choices": ["Diarrheal fluid loss", "Heart failure", "SIADH", "Diabetes insipidus", "Adrenal hormone excess"], "ans": 2, "exp": "Euvolemic hyponatremia + urine osmolality สูง + urine Na สูง = SIADH (หลัง exclude hypothyroid/adrenal insufficiency). สาเหตุ: CNS, ปอด (SCLC), ยา, ปวด/คลื่นไส้. รักษาจำกัดน้ำ + แก้สาเหตุ.", "id": "set2-8"}, {"topic": "Nephrology", "q": "When correcting severe chronic hyponatremia, what complication results from correcting too rapidly?", "choices": ["Cerebral edema from overcorrection", "Seizure from hypocalcemia", "Rhabdomyolysis", "Osmotic demyelination syndrome (central pontine myelinolysis)", "Severe hyperkalemia"], "ans": 3, "exp": "แก้ Na เร็วเกิน (> 8–10 mEq/L/24 ชม.) ใน chronic hyponatremia เสี่ยง osmotic demyelination (central pontine myelinolysis). แก้ hypernatremia เร็วเกินต่างหากที่เสี่ยง cerebral edema.", "id": "set2-9"}, {"topic": "Nephrology", "q": "A patient with CKD has ECG showing peaked T waves and K+ 7.2. After IV calcium, which combination best shifts potassium into cells?", "choices": ["Furosemide diuresis", "Kayexalate (resin)", "Sodium bicarbonate alone", "Normal saline infusion", "Insulin with glucose (± nebulized salbutamol)"], "ans": 4, "exp": "หลัง calcium gluconate (stabilize membrane) ให้ insulin + glucose (± beta-agonist) เพื่อ shift K เข้าเซลล์อย่างรวดเร็ว. Furosemide/resin/dialysis กำจัด K ออกจากร่างกาย (ช้ากว่า).", "id": "set2-10"}, {"topic": "Nephrology", "q": "A patient with hypokalemia does not improve despite potassium replacement. What should be checked and corrected?", "choices": ["Serum magnesium level", "Serum calcium level", "Serum phosphate level", "Serum albumin level", "Serum TSH level"], "ans": 0, "exp": "Hypokalemia ที่ดื้อต่อการเติม K มักมี hypomagnesemia ร่วม (Mg ต่ำทำให้ renal K wasting) ต้องแก้ Mg ก่อน K จึงจะขึ้น.", "id": "set2-11"}, {"topic": "Nephrology", "q": "A patient has hypercalcemia with 'stones, bones, groans, and psychiatric moans'. PTH is elevated and phosphate is low. What is the diagnosis?", "choices": ["Malignancy-related hypercalcemia", "Primary hyperparathyroidism", "Vitamin D toxicity", "Sarcoidosis", "Milk-alkali syndrome"], "ans": 1, "exp": "Hypercalcemia + PTH สูง + phosphate ต่ำ = primary hyperparathyroidism (มัก parathyroid adenoma). ต่างจาก malignancy ที่ PTH ต่ำ (PTHrP). รักษา parathyroidectomy ถ้าเข้าเกณฑ์.", "id": "set2-12"}, {"topic": "Nephrology", "q": "Immediate management of severe symptomatic hypercalcemia (Ca 14) includes:", "choices": ["Restrict fluids strictly to avoid worsening fluid overload", "Start a thiazide diuretic to promote calcium excretion", "IV isotonic saline hydration + calcitonin ± bisphosphonate", "Give oral calcium supplements to correct the imbalance", "Give high-dose vitamin D to improve calcium handling"], "ans": 2, "exp": "Severe hypercalcemia รักษาด้วย IV isotonic saline (rehydrate + promote calciuresis) + calcitonin (ออกเร็ว) + bisphosphonate (ออกช้าแต่ยาว). หลีกเลี่ยง thiazide (เพิ่ม Ca reabsorption).", "id": "set2-13"}, {"topic": "Nephrology", "q": "A patient presents with tetany, perioral numbness, positive Chvostek sign, and a prolonged QT after thyroid surgery. What is the cause?", "choices": ["Severe hyperkalemia", "Acute hypernatremia", "Isolated hypomagnesemia", "Hypocalcemia from hypoparathyroidism", "Isolated hyperphosphatemia"], "ans": 3, "exp": "หลังผ่าตัด thyroid/parathyroid เสี่ยง hypoparathyroidism → hypocalcemia (ชา เกร็ง Chvostek/Trousseau, QT ยาว). รักษาด้วย IV/oral calcium + calcitriol.", "id": "set2-14"}, {"topic": "Nephrology", "q": "A child has periorbital edema, proteinuria > 3.5 g/day, hypoalbuminemia, and hyperlipidemia. What is the most likely histology?", "choices": ["IgA nephropathy", "Post-streptococcal GN", "Rapidly progressive GN", "Thin basement membrane disease", "Minimal change disease"], "ans": 4, "exp": "Nephrotic syndrome ในเด็กส่วนใหญ่คือ minimal change disease (ตอบสนองดีต่อ steroid). Nephrotic = proteinuria > 3.5 g/day, hypoalbuminemia, edema, hyperlipidemia; เสี่ยง infection และ VTE.", "id": "set2-15"}, {"topic": "Nephrology", "q": "A 10-year-old develops hematuria, hypertension, and periorbital edema 2 weeks after a sore throat; C3 is low and ASO is elevated. What is the diagnosis?", "choices": ["Post-streptococcal glomerulonephritis", "Minimal change disease", "IgA nephropathy", "Alport syndrome", "Membranous nephropathy"], "ans": 0, "exp": "Nephritic syndrome หลัง strep 1–3 สัปดาห์ + C3 ต่ำ + ASO สูง = post-streptococcal GN. รักษาประคับประคอง (คุมความดัน/บวม); ส่วนใหญ่หายเองในเด็ก.", "id": "set2-16"}, {"topic": "Nephrology", "q": "A patient with gross hematuria occurring 1–2 days after an upper respiratory infection (synpharyngitic) most likely has:", "choices": ["Post-streptococcal GN", "IgA nephropathy", "Minimal change disease", "Diabetic nephropathy", "Membranous nephropathy"], "ans": 1, "exp": "Hematuria พร้อม/หลัง URI ทันที (1–2 วัน, synpharyngitic) ต่างจาก PSGN (ล่าช้า 1–3 สัปดาห์) = IgA nephropathy (Berger). วินิจฉัยด้วย renal biopsy (mesangial IgA).", "id": "set2-17"}, {"topic": "Nephrology", "q": "A nephrotic syndrome patient develops sudden flank pain and worsening renal function. Which complication should be suspected?", "choices": ["Acute pyelonephritis", "An obstructing renal stone", "Renal vein thrombosis", "Renal artery stenosis", "Renal papillary necrosis"], "ans": 2, "exp": "Nephrotic syndrome ทำให้ hypercoagulable (เสีย antithrombin III ทางปัสสาวะ) เสี่ยง renal vein thrombosis (โดยเฉพาะ membranous) → flank pain + hematuria + ไตแย่ลง. ยืนยันด้วย imaging; รักษา anticoagulation.", "id": "set2-18"}, {"topic": "Nephrology", "q": "A woman has dysuria, frequency, and suprapubic discomfort but no fever or flank pain. What is the appropriate management of uncomplicated cystitis?", "choices": ["IV ceftriaxone therapy", "No treatment needed", "Long-term antibiotics", "Short course nitrofurantoin/fosfomycin/co-trimoxazole", "Renal ultrasound first"], "ans": 3, "exp": "Uncomplicated cystitis (ไม่มีไข้/ปวดสีข้าง) รักษาด้วยยา oral สั้น: nitrofurantoin, fosfomycin, หรือ co-trimoxazole (ตาม local resistance). ไม่ต้อง imaging ในรายไม่ซับซ้อน.", "id": "set2-19"}, {"topic": "Nephrology", "q": "A woman has high fever, chills, and costovertebral angle tenderness with pyuria. What is the diagnosis and management?", "choices": ["Cystitis; oral nitrofurantoin", "Asymptomatic bacteriuria; observe", "Interstitial cystitis; analgesia", "Renal stone; lithotripsy", "Acute pyelonephritis; ceftriaxone or fluoroquinolone"], "ans": 4, "exp": "ไข้สูง + CVA tenderness + pyuria = acute pyelonephritis. เก็บ urine + hemoculture, ให้ ceftriaxone/fluoroquinolone, admit ถ้ารุนแรง/อาเจียน/ตั้งครรภ์. Nitrofurantoin ไม่เหมาะกับ pyelonephritis (tissue level ต่ำ).", "id": "set2-20"}, {"topic": "Nephrology", "q": "In which situation should asymptomatic bacteriuria be treated?", "choices": ["Pregnancy or before a urologic procedure", "All elderly patients routinely", "All diabetic patients routinely", "Any patient with an indwelling catheter", "It should never be treated"], "ans": 0, "exp": "Asymptomatic bacteriuria รักษาเฉพาะหญิงตั้งครรภ์ (ลด pyelonephritis/preterm) และก่อนหัตถการทางเดินปัสสาวะที่เสี่ยงเลือดออก. กลุ่มอื่น (สูงอายุ, เบาหวาน, คาสาย) ไม่ต้องรักษาเพราะเพิ่ม resistance.", "id": "set2-21"}, {"topic": "Nephrology", "q": "Urinalysis shows RBC casts. Which condition does this most specifically indicate?", "choices": ["Urinary tract infection", "Glomerulonephritis", "Acute tubular necrosis", "Prerenal azotemia", "Bladder carcinoma"], "ans": 1, "exp": "RBC cast จำเพาะต่อ glomerular bleeding = glomerulonephritis. WBC cast = pyelonephritis/AIN; muddy brown cast = ATN; hyaline cast = ปกติ/dehydration.", "id": "set2-22"}, {"topic": "Nephrology", "q": "A patient with diabetes has microalbuminuria. Besides glycemic control, which drug slows progression of diabetic nephropathy?", "choices": ["A beta-blocker", "A calcium channel blocker", "ACE inhibitor or ARB (plus SGLT2i)", "An alpha-blocker", "A loop diuretic"], "ans": 2, "exp": "Diabetic nephropathy ที่มี albuminuria ใช้ ACEI/ARB ลด intraglomerular pressure/proteinuria + SGLT2i ชะลอไตเสื่อม. คุมน้ำตาล/ความดัน/lipid ร่วมด้วย.", "id": "set2-23"}, {"topic": "Nephrology", "q": "A patient on chronic NSAIDs presents with AKI, sterile pyuria, eosinophiluria, and a maculopapular rash. What is the diagnosis?", "choices": ["Acute tubular necrosis", "Prerenal azotemia", "Post-streptococcal GN", "Acute interstitial nephritis", "An obstructing renal stone"], "ans": 3, "exp": "AKI + rash + eosinophilia/eosinophiluria + ประวัติยา (NSAID, antibiotic, PPI) = acute interstitial nephritis (allergic). รักษาโดยหยุดยาต้นเหตุ ± corticosteroid.", "id": "set2-24"}, {"topic": "Nephrology", "q": "ABG in a patient with prolonged vomiting shows pH 7.50, HCO3 34, PaCO2 46. What is the primary acid-base disorder?", "choices": ["Metabolic acidosis", "Respiratory acidosis", "Respiratory alkalosis", "A normal acid-base state", "Metabolic alkalosis"], "ans": 4, "exp": "pH สูง + HCO3 สูง = metabolic alkalosis; อาเจียนเสีย HCl + volume contraction. PaCO2 สูงเล็กน้อยเป็น respiratory compensation. รักษาด้วย isotonic saline (chloride-responsive).", "id": "set2-25"}, {"topic": "Nephrology", "q": "A patient with distal (type 1) renal tubular acidosis typically has which electrolyte/stone pattern?", "choices": ["Hypokalemia, normal anion gap acidosis, and calcium phosphate stones", "Hyperkalemia with a high anion gap acidosis and no stones", "A primary metabolic alkalosis with a low serum potassium", "Hyperphosphatemia with a high anion gap and uric acid stones", "Hypernatremia with a normal anion gap and no renal stones"], "ans": 0, "exp": "Distal (type 1) RTA: ไม่สามารถขับ H+ ที่ distal tubule → normal anion gap metabolic acidosis + hypokalemia + urine pH สูง (> 5.5) + เสี่ยง calcium phosphate stones/nephrocalcinosis.", "id": "set2-26"}, {"topic": "Nephrology", "q": "A patient develops rapidly rising creatinine over days with hematuria, RBC casts, and crescents on biopsy. What is the diagnosis?", "choices": ["Minimal change disease", "Rapidly progressive (crescentic) glomerulonephritis", "Established chronic kidney disease", "Prerenal azotemia", "Acute tubular necrosis"], "ans": 1, "exp": "ไตวายเร็ว + nephritic (RBC cast) + crescents = rapidly progressive GN (RPGN). สาเหตุ: ANCA-associated vasculitis, anti-GBM (Goodpasture), immune complex (lupus). ต้องรีบวินิจฉัย + immunosuppression.", "id": "set2-27"}, {"topic": "Nephrology", "q": "Which finding best distinguishes chronic kidney disease from acute kidney injury on imaging/labs?", "choices": ["An isolated elevation of serum creatinine on a single test", "Reduced urine output over the preceding twenty-four hours", "Small echogenic kidneys, anemia, and CKD-MBD (high PTH, low Ca)", "An elevated serum potassium without any other abnormality", "Isolated proteinuria detected on a routine dipstick test"], "ans": 2, "exp": "CKD มักมีไตเล็ก echogenic, anemia (EPO ต่ำ), และ CKD-MBD (PTH สูง, Ca ต่ำ, PO4 สูง) ที่ค่อยเป็นค่อยไป — ต่างจาก AKI ที่ไตขนาดปกติและ acute. ช่วยแยกเมื่อไม่มี baseline.", "id": "set2-28"}, {"topic": "Nephrology", "q": "A patient with CKD stage 4 has high phosphate. What is the first-line dietary/pharmacologic management?", "choices": ["A high-phosphate diet", "Calcium supplement alone", "A vitamin D megadose", "Dietary phosphate restriction + phosphate binders", "Loop diuretic therapy"], "ans": 3, "exp": "Hyperphosphatemia ใน CKD จัดการด้วยจำกัดฟอสเฟตในอาหาร + phosphate binder (calcium-based หรือ non-calcium เช่น sevelamer) เพื่อคุม CKD-MBD และลด vascular calcification.", "id": "set2-29"}, {"topic": "Nephrology", "q": "A patient with rhabdomyolysis (CK very high) after crush injury is at risk of AKI. What is the key initial treatment?", "choices": ["Strict fluid restriction", "Immediate dialysis for all", "Diuretic therapy alone", "Bicarbonate is contraindicated", "Aggressive IV fluid to maintain urine output"], "ans": 4, "exp": "Rhabdomyolysis → myoglobin cast + AKI; รักษาด้วย aggressive IV fluid รักษา urine output สูง (± urine alkalinization ในบางราย). ระวัง hyperkalemia และ hypocalcemia. Dialysis เมื่อมีข้อบ่งชี้.", "id": "set2-30"}, {"topic": "Nephrology", "q": "An elderly patient with poor water intake has Na 158, lethargy, and concentrated urine. How should hypernatremia be corrected?", "choices": ["Slowly replace the free water deficit (≤ 10 mEq/L/day)", "A rapid bolus of hypotonic fluid", "Give hypertonic saline", "Strict fluid restriction", "Loop diuretic alone"], "ans": 0, "exp": "Hypernatremia แก้โดยค่อยๆ ทดแทน free water deficit ช้าๆ (ลด Na ไม่เกิน ~10 mEq/L/วัน) เพื่อป้องกัน cerebral edema. หาสาเหตุ (ขาดน้ำ, DI). การแก้เร็วเกินอันตราย.", "id": "set2-31"}, {"topic": "Nephrology", "q": "A patient with polyuria and dilute urine does not concentrate urine after water deprivation but responds to desmopressin. What is the diagnosis?", "choices": ["Nephrogenic diabetes insipidus", "Central diabetes insipidus", "Primary polydipsia", "SIADH", "Osmotic diuresis"], "ans": 1, "exp": "ตอบสนองต่อ desmopressin (urine osmolality เพิ่ม) = central DI (ขาด ADH). Nephrogenic DI จะไม่ตอบสนอง desmopressin (ไตดื้อ ADH). Primary polydipsia จะ concentrate ได้เมื่อ deprive.", "id": "set2-32"}, {"topic": "Nephrology", "q": "A patient with severe flank pain radiating to the groin and microscopic hematuria most likely has:", "choices": ["Acute pyelonephritis", "Acute cystitis", "Ureteric (renal) colic from a stone", "Acute glomerulonephritis", "Bladder carcinoma"], "ans": 2, "exp": "ปวดสีข้าวร้าวลงขาหนีบ (colicky) + hematuria = ureteric stone (renal colic). ยืนยันด้วย non-contrast CT KUB; รักษา analgesia, hydration, medical expulsive therapy (alpha-blocker) สำหรับนิ่วเล็ก; intervention ถ้านิ่วใหญ่/อุดตัน/ติดเชื้อ.", "id": "set2-33"}, {"topic": "Nephrology", "q": "A diabetic patient is scheduled for contrast CT. What is the best strategy to reduce contrast-associated AKI?", "choices": ["Give NSAIDs beforehand", "Give a diuretic before contrast", "Withhold all fluids", "Ensure adequate IV hydration and hold nephrotoxins", "Give high-dose vitamin C"], "ans": 3, "exp": "ลดเสี่ยง contrast-associated nephropathy ด้วยการให้ isotonic IV hydration รอบการฉีด contrast + หยุด nephrotoxin (NSAID) + ใช้ contrast ปริมาณน้อย. Diuretic/NSAID ทำให้แย่ลง.", "id": "set2-34"}, {"topic": "Nephrology", "q": "A cirrhotic patient with tense ascites develops AKI unresponsive to volume, with bland urine and no other cause. What is the diagnosis?", "choices": ["Prerenal azotemia", "Acute tubular necrosis", "Acute glomerulonephritis", "Postrenal obstruction", "Hepatorenal syndrome"], "ans": 4, "exp": "AKI ใน cirrhosis ที่ตัดสาเหตุอื่นและไม่ตอบสนอง volume (bland urine, FeNa ต่ำ) = hepatorenal syndrome. รักษาด้วย terlipressin (หรือ noradrenaline) + albumin; แก้ precipitant; ปลูกถ่ายตับ.", "id": "set2-35"}, {"topic": "Nephrology", "q": "An adult with flank masses, hypertension, hematuria, and a family history of kidney failure has multiple bilateral renal cysts. What is the diagnosis?", "choices": ["Autosomal dominant polycystic kidney disease", "Simple renal cysts", "Medullary sponge kidney", "Renal cell carcinoma", "Acquired cystic kidney disease"], "ans": 0, "exp": "Multiple bilateral cysts + HT + ประวัติครอบครัว = ADPKD (PKD1/2). สัมพันธ์ berry aneurysm (SAH), hepatic cysts, MVP. คุมความดัน (ACEI/ARB); tolvaptan ชะลอในรายเสี่ยงสูง.", "id": "set2-36"}, {"topic": "Nephrology", "q": "A patient has nephrotic syndrome; biopsy shows subepithelial deposits and thickened GBM (membranous nephropathy). Which underlying condition should be excluded, especially in older adults?", "choices": ["Underlying diabetes mellitus", "Underlying malignancy (with anti-PLA2R testing)", "Viral hepatitis alone", "Amyloidosis alone", "Thyroid disease"], "ans": 1, "exp": "Membranous nephropathy อาจ secondary ต่อ malignancy (โดยเฉพาะผู้สูงอายุ), infection (HBV), SLE, ยา. ควรคัดกรองมะเร็งตามอายุ + ตรวจ anti-PLA2R (primary). เสี่ยง renal vein thrombosis สูง.", "id": "set2-37"}, {"topic": "Nephrology", "q": "A young woman with SLE has proteinuria, hematuria, red cell casts, and rising creatinine. What is essential for guiding treatment?", "choices": ["Empiric antibiotic therapy", "Observation without action", "Renal biopsy to classify lupus nephritis", "Loop diuretic only", "Immediate dialysis"], "ans": 2, "exp": "Lupus nephritis ต้อง renal biopsy จำแนก class (I–VI) เพราะกำหนดการรักษา (class III/IV → induction ด้วย steroid + mycophenolate/cyclophosphamide). Complement ต่ำ + anti-dsDNA สูงช่วยประเมิน activity.", "id": "set2-38"}, {"topic": "Nephrology", "q": "A patient presents with hemoptysis and rapidly progressive glomerulonephritis; anti-GBM antibody is positive. What is the diagnosis?", "choices": ["Granulomatosis with polyangiitis", "Microscopic polyangiitis", "IgA nephropathy", "Goodpasture syndrome (anti-GBM disease)", "Post-streptococcal GN"], "ans": 3, "exp": "RPGN + pulmonary hemorrhage + anti-GBM positive = Goodpasture syndrome. รักษาด้วย plasmapheresis + steroid + cyclophosphamide. ต่างจาก ANCA-vasculitis ที่ ANCA positive.", "id": "set2-39"}, {"topic": "Nephrology", "q": "A patient with fatigue, weight loss, sinusitis, hemoptysis, and RPGN has c-ANCA (anti-PR3) positive. What is the diagnosis?", "choices": ["Goodpasture syndrome", "Minimal change disease", "Diabetic nephropathy", "Renal amyloidosis", "Granulomatosis with polyangiitis (GPA)"], "ans": 4, "exp": "Upper+lower respiratory (sinusitis, hemoptysis) + RPGN + c-ANCA/PR3 = granulomatosis with polyangiitis. รักษา induction ด้วย steroid + rituximab/cyclophosphamide.", "id": "set2-40"}, {"topic": "Nephrology", "q": "ABG shows pH 7.34, PaCO2 60, HCO3 32 in a COPD patient. What is the interpretation?", "choices": ["Chronic (compensated) respiratory acidosis", "Acute respiratory acidosis", "Primary metabolic acidosis", "Respiratory alkalosis", "Mixed metabolic alkalosis"], "ans": 0, "exp": "PaCO2 สูง + HCO3 สูงชดเชย + pH เกือบปกติ (แค่ต่ำเล็กน้อย) = chronic respiratory acidosis with metabolic compensation (พบใน COPD). Acute จะมี pH ต่ำชัดโดย HCO3 ยังไม่ขึ้น.", "id": "set2-41"}, {"topic": "Nephrology", "q": "A patient with type 4 (hyporeninemic hypoaldosteronism) RTA, common in diabetics, typically shows:", "choices": ["Hypokalemia with alkalosis", "Hyperkalemia with normal anion gap acidosis", "High anion gap acidosis", "Metabolic alkalosis", "Hypernatremia"], "ans": 1, "exp": "Type 4 RTA (hypoaldosteronism, พบในเบาหวาน) มี hyperkalemia + normal anion gap metabolic acidosis. รักษาแก้ hyperkalemia (จำกัด K, diuretic, fludrocortisone ในบางราย).", "id": "set2-42"}, {"topic": "Nephrology", "q": "A patient develops thrombocytopenia, microangiopathic hemolytic anemia, and AKI after bloody diarrhea (E. coli O157:H7). What is the diagnosis?", "choices": ["Thrombotic thrombocytopenic purpura", "Disseminated intravascular coagulation", "Hemolytic uremic syndrome (HUS)", "Immune thrombocytopenic purpura", "Evans syndrome"], "ans": 2, "exp": "เด็ก/หลัง bloody diarrhea (Shiga toxin E. coli) + MAHA + thrombocytopenia + AKI = HUS. รักษาประคับประคอง (มัก supportive, dialysis ถ้าจำเป็น); หลีกเลี่ยง antibiotics/antimotility ที่อาจเพิ่ม toxin.", "id": "set2-43"}, {"topic": "Nephrology", "q": "An older man has difficulty voiding, weak stream, nocturia, and a distended bladder with AKI. What is the mechanism of his kidney injury?", "choices": ["Prerenal azotemia", "Intrinsic acute tubular necrosis", "Acute glomerulonephritis", "Postrenal obstruction from BPH", "Acute interstitial nephritis"], "ans": 3, "exp": "BPH ทำให้ bladder outlet obstruction → postrenal AKI (hydronephrosis 2 ข้าง). ระบายปัสสาวะด้วย catheter จะทำให้ไตดีขึ้น; ระวัง post-obstructive diuresis.", "id": "set2-44"}, {"topic": "Nephrology", "q": "A patient on hemodialysis develops hypotension, muscle cramps during the session. What is the most likely cause?", "choices": ["Air embolism", "Acute hemolysis", "Anaphylactic reaction", "Severe hyperkalemia", "Excess fluid removal (intradialytic hypotension)"], "ans": 4, "exp": "Intradialytic hypotension มักจากการดึงน้ำเร็ว/มากเกิน (ultrafiltration) → hypotension + cramps. จัดการโดยลด ultrafiltration rate, ให้ saline, ประเมิน dry weight.", "id": "set2-45"}, {"topic": "Nephrology", "q": "Which is the recommended blood pressure target for most CKD patients with albuminuria (KDIGO), if tolerated?", "choices": ["Systolic below 120 mmHg", "Below 160/100 mmHg", "Below 150/90 mmHg", "Below 140/90 only", "No specific target"], "ans": 0, "exp": "KDIGO แนะนำเป้า systolic < 120 mmHg (วัดแบบมาตรฐาน) ในผู้ป่วย CKD ส่วนใหญ่ถ้าทนได้ เพื่อลด CV events. ใช้ ACEI/ARB เป็นยาหลักเมื่อมี albuminuria.", "id": "set2-46"}, {"topic": "Nephrology", "q": "A patient has persistent proteinuria on dipstick. What is the best test to quantify and characterize it?", "choices": ["Serum albumin level only", "Spot urine albumin/protein-to-creatinine ratio", "Renal ultrasound", "Serum creatinine only", "A complete blood count"], "ans": 1, "exp": "Quantify proteinuria ด้วย spot urine protein/creatinine ratio หรือ albumin/creatinine ratio (สะดวกกว่า 24-hr และสัมพันธ์กันดี). ช่วยประเมิน glomerular disease และ CKD progression.", "id": "set2-47"}, {"topic": "Nephrology", "q": "A patient with recurrent calcium oxalate stones should be advised to:", "choices": ["Severely restrict all dietary calcium to prevent stone growth", "Increase dietary protein intake to acidify the urine further", "Increase fluids, reduce sodium/oxalate, keep normal dietary calcium", "Take high-dose vitamin C supplements to reduce recurrence", "Restrict total fluid intake to concentrate the urine output"], "ans": 2, "exp": "ป้องกันนิ่ว calcium oxalate: ดื่มน้ำมาก (urine > 2 L/วัน), ลดเกลือและ oxalate, กิน calcium ปกติ (ไม่จำกัดเข้ม เพราะการจำกัด Ca เพิ่ม oxalate absorption), thiazide ในราย hypercalciuria.", "id": "set2-48"}, {"topic": "Nephrology", "q": "A patient presents with painless gross hematuria and no infection. In an older smoker, which diagnosis must be excluded?", "choices": ["A simple urinary tract infection", "Prerenal azotemia", "Minimal change disease", "Urothelial (bladder) carcinoma", "Renal (ureteric) colic"], "ans": 3, "exp": "Painless gross hematuria ในผู้สูงอายุ/สูบบุหรี่ ต้องตัด urothelial (bladder) carcinoma ด้วย cystoscopy + CT urography. อย่าเหมาว่าเป็น UTI ถ้าไม่มีหลักฐานติดเชื้อ.", "id": "set2-49"}, {"topic": "Endocrinology", "q": "Which of the following meets the diagnostic criteria for diabetes mellitus?", "choices": ["A fasting glucose of 110 mg/dL", "Random glucose 160 mg/dL, no symptoms", "A 2-hr OGTT of 150 mg/dL", "An HbA1c of 6.0%", "HbA1c ≥ 6.5% or fasting glucose ≥ 126 mg/dL"], "ans": 4, "exp": "เกณฑ์เบาหวาน: FPG ≥ 126, 2-hr OGTT ≥ 200, HbA1c ≥ 6.5% (ยืนยันซ้ำถ้าไม่มีอาการ), หรือ random ≥ 200 + อาการ. FPG 100–125 = IFG (prediabetes); A1c 5.7–6.4 = prediabetes.", "id": "set2-50"}, {"topic": "Endocrinology", "q": "A patient with T2DM and established ASCVD needs glucose-lowering therapy. Which agents should be included irrespective of A1c?", "choices": ["A GLP-1 RA and/or SGLT2 inhibitor with CV benefit", "A sulfonylurea agent", "Basal insulin therapy", "A thiazolidinedione", "Acarbose therapy"], "ans": 0, "exp": "ADA 2025/26: ในผู้ป่วย T2DM + ASCVD/ความเสี่ยงสูง ให้ GLP-1 RA และ/หรือ SGLT2i ที่มีหลักฐานลด CV events โดยไม่ขึ้นกับ A1c หรือการใช้ metformin. HF → SGLT2i; CKD → SGLT2i first-line.", "id": "set2-51"}, {"topic": "Endocrinology", "q": "A T2DM patient with heart failure needs additional therapy. Which class both lowers glucose and reduces HF hospitalization?", "choices": ["A sulfonylurea", "An SGLT2 inhibitor", "A DPP-4 inhibitor", "A thiazolidinedione", "Insulin therapy"], "ans": 1, "exp": "SGLT2 inhibitor ลด HF hospitalization (ทั้ง HFrEF/HFpEF) และชะลอ CKD จึงเป็นตัวเลือกใน T2DM + HF. TZD (pioglitazone) ทำให้ fluid retention/HF แย่ลง.", "id": "set2-52"}, {"topic": "Endocrinology", "q": "A patient with T1DM presents with vomiting, Kussmaul breathing, glucose 450, pH 7.15, HCO3 10, and ketonuria. What is the first step in management?", "choices": ["An IV insulin bolus before fluids", "Oral hydration alone", "IV isotonic fluid resuscitation, then insulin with K+ monitoring", "Routine sodium bicarbonate", "Give glucose"], "ans": 2, "exp": "DKA รักษาลำดับ: IV fluid resuscitation ก่อน → insulin drip → เติม K (ถ้า K < 3.3 ต้องเติม K ก่อนเริ่ม insulin) → หา precipitant. Bicarbonate ให้เฉพาะ pH ต่ำมาก (< 6.9). อย่าเริ่ม insulin ก่อน fluid/ตรวจ K.", "id": "set2-53"}, {"topic": "Endocrinology", "q": "An elderly T2DM patient has glucose 900, serum osmolality 350, profound dehydration, and minimal ketones. What is the diagnosis?", "choices": ["Diabetic ketoacidosis", "Lactic acidosis", "Hypoglycemia", "Hyperosmolar hyperglycemic state (HHS)", "Diabetes insipidus"], "ans": 3, "exp": "น้ำตาลสูงมาก (>600) + osmolality สูง + ไม่มี ketoacidosis เด่น + ซึม/ขาดน้ำ = HHS. เน้น aggressive fluid resuscitation เป็นหลัก + insulin + แก้ electrolyte + หาสาเหตุ (ติดเชื้อ).", "id": "set2-54"}, {"topic": "Endocrinology", "q": "A diabetic on insulin becomes confused and diaphoretic with glucose 45 mg/dL. What is the immediate treatment if conscious and able to swallow?", "choices": ["IV insulin infusion", "IM glucagon only", "Observation only", "IV normal saline", "Oral fast-acting carbohydrate (glucose)"], "ans": 4, "exp": "Hypoglycemia (< 70) ที่รู้ตัวและกลืนได้ → ให้ oral carbohydrate/glucose 15 g ทันที (rule of 15). ถ้าไม่รู้ตัว/กลืนไม่ได้ → IV glucose หรือ IM glucagon. Whipple triad ยืนยันภาวะน้ำตาลต่ำ.", "id": "set2-55"}, {"topic": "Endocrinology", "q": "A T2DM patient is screened for diabetic complications. How often should retinal examination be performed?", "choices": ["Annually (once a year)", "Every 5 years", "Only if symptomatic", "Every month", "Never needed"], "ans": 0, "exp": "ควรตรวจตา (dilated retinal exam) อย่างน้อยปีละครั้งเพื่อคัดกรอง diabetic retinopathy; ตรวจเท้า (monofilament) และ urine ACR + eGFR ปีละครั้งเช่นกัน.", "id": "set2-56"}, {"topic": "Endocrinology", "q": "A patient with diabetic neuropathy has painful burning feet. Which is an appropriate first-line agent for neuropathic pain?", "choices": ["Paracetamol alone", "Pregabalin/gabapentin or duloxetine/amitriptyline", "Ibuprofen (an NSAID)", "An opioid as first-line", "Topical corticosteroid"], "ans": 1, "exp": "Painful diabetic neuropathy ใช้ pregabalin/gabapentin, duloxetine, หรือ TCA (amitriptyline) เป็น first-line. NSAID/paracetamol ได้ผลน้อย; opioid ไม่ใช่ตัวแรก.", "id": "set2-57"}, {"topic": "Endocrinology", "q": "A patient has palpitations, weight loss, heat intolerance, tremor, exophthalmos, and pretibial myxedema. TSH is low. What is the diagnosis?", "choices": ["Toxic multinodular goiter", "Subacute thyroiditis", "Graves disease", "Hashimoto thyroiditis", "Iodine deficiency"], "ans": 2, "exp": "Hyperthyroid + exophthalmos + pretibial myxedema (จำเพาะ) + TRAb = Graves disease (autoimmune). รักษาด้วย antithyroid drug (methimazole), RAI, หรือผ่าตัด + beta-blocker คุมอาการ.", "id": "set2-58"}, {"topic": "Endocrinology", "q": "A pregnant woman in the first trimester needs antithyroid drug for hyperthyroidism. Which is preferred?", "choices": ["Methimazole", "Radioactive iodine", "Carbimazole", "Propylthiouracil (PTU)", "Levothyroxine"], "ans": 3, "exp": "Trimester 1 เลือก PTU (methimazole เสี่ยง teratogenic – aplasia cutis, choanal atresia ในช่วงต้น). หลัง trimester 1 มักเปลี่ยนเป็น methimazole (PTU เสี่ยง hepatotoxicity). RAI เป็นข้อห้ามในการตั้งครรภ์.", "id": "set2-59"}, {"topic": "Endocrinology", "q": "A patient with fever, tachycardia/AF, agitation, and heart failure after infection has severe thyrotoxicosis. What is the treatment sequence for thyroid storm?", "choices": ["Give iodine first and then start PTU one hour afterwards", "Start levothyroxine to replace the depleted thyroid hormone", "Give radioactive iodine immediately as the definitive therapy", "Use methimazole alone without any adjunctive treatment", "PTU first, then iodine (>1 h later), beta-blocker, hydrocortisone"], "ans": 4, "exp": "Thyroid storm: ให้ PTU (block synthesis + peripheral T4→T3 conversion) ก่อน แล้วให้ iodine (Lugol) หลัง ≥ 1 ชม. (ให้ก่อนจะเป็นสารตั้งต้น hormone) + beta-blocker (propranolol) + hydrocortisone + ลดไข้ + รักษา precipitant.", "id": "set2-60"}, {"topic": "Endocrinology", "q": "A patient has fatigue, cold intolerance, weight gain, constipation, and bradycardia. TSH is high and free T4 low. What is the treatment?", "choices": ["Levothyroxine", "Methimazole", "Radioactive iodine", "Propranolol", "Prednisolone"], "ans": 0, "exp": "Primary hypothyroidism (TSH สูง, FT4 ต่ำ; มัก Hashimoto) รักษาด้วย levothyroxine แล้วปรับตาม TSH. เริ่มขนาดต่ำในผู้สูงอายุ/โรคหัวใจ.", "id": "set2-61"}, {"topic": "Endocrinology", "q": "A patient presents with hypothermia, bradycardia, hyponatremia, and depressed consciousness with a history of untreated hypothyroidism. What is the management of myxedema coma?", "choices": ["Oral levothyroxine then discharge", "IV levothyroxine (± T3) plus IV hydrocortisone and support", "Methimazole therapy", "Active rewarming only", "Observation only"], "ans": 1, "exp": "Myxedema coma เป็นภาวะฉุกเฉิน: IV levothyroxine (± T3) + IV hydrocortisone (กัน adrenal crisis) + supportive (warming, ventilation, แก้ hyponatremia/hypoglycemia) + รักษา precipitant.", "id": "set2-62"}, {"topic": "Endocrinology", "q": "A patient has a thyroid nodule. What is the appropriate initial investigation?", "choices": ["Immediate surgery", "CT of the neck", "Serum TSH, then thyroid ultrasound and FNA by risk", "Thyroid scan for all", "Start levothyroxine"], "ans": 2, "exp": "Thyroid nodule เริ่มด้วย TSH → ถ้าต่ำทำ thyroid scan (hot nodule มักไม่ร้าย); ทำ ultrasound (TIRADS) แล้ว FNA ตามขนาด/ลักษณะเสี่ยง (Bethesda). ไม่ผ่าตัดทุกราย.", "id": "set2-63"}, {"topic": "Endocrinology", "q": "Which thyroid cancer is the most common and generally has the best prognosis?", "choices": ["Follicular carcinoma", "Medullary carcinoma", "Anaplastic carcinoma", "Papillary carcinoma", "Thyroid lymphoma"], "ans": 3, "exp": "Papillary thyroid carcinoma พบบ่อยสุดและพยากรณ์ดี (แพร่ทาง lymphatic). Follicular แพร่ทาง hematogenous; medullary จาก C-cell (calcitonin, MEN2); anaplastic ดุ พยากรณ์แย่.", "id": "set2-64"}, {"topic": "Endocrinology", "q": "A patient with medullary thyroid carcinoma should be screened for which associated condition?", "choices": ["MEN 1 syndrome only", "Addison disease", "Graves disease", "Cushing disease", "MEN 2 (pheochromocytoma, hyperparathyroidism)"], "ans": 4, "exp": "Medullary thyroid carcinoma สัมพันธ์กับ MEN 2 (pheochromocytoma, primary hyperparathyroidism, RET mutation). ต้องคัดกรอง pheochromocytoma ก่อนผ่าตัด thyroid.", "id": "set2-65"}, {"topic": "Endocrinology", "q": "A patient has central obesity, moon face, purple striae, proximal weakness, hypertension, and hyperglycemia. Which test screens for Cushing syndrome?", "choices": ["Late-night salivary cortisol, 1-mg dexamethasone, or 24-h urinary cortisol", "A single random serum cortisol level drawn at any time of day", "An ACTH stimulation (Synacthen) test to assess the response", "Serum TSH and free thyroxine to exclude thyroid dysfunction", "Plasma renin and aldosterone measured together in the morning"], "ans": 0, "exp": "คัดกรอง Cushing ด้วย 1 ใน 3: overnight low-dose dexamethasone suppression test, 24-hr urinary free cortisol, หรือ late-night salivary cortisol. จากนั้นหาสาเหตุด้วย ACTH + high-dose dexamethasone/imaging.", "id": "set2-66"}, {"topic": "Endocrinology", "q": "A patient has fatigue, weight loss, hyperpigmentation, hypotension, hyponatremia, and hyperkalemia. What is the diagnosis?", "choices": ["Cushing syndrome", "Primary adrenal insufficiency (Addison disease)", "Hyperthyroidism", "Conn syndrome", "SIADH"], "ans": 1, "exp": "Hyperpigmentation (ACTH สูง) + hypotension + hypoNa + hyperK = primary adrenal insufficiency (Addison). ยืนยันด้วย morning cortisol ต่ำ + ACTH stimulation test. รักษา hydrocortisone + fludrocortisone.", "id": "set2-67"}, {"topic": "Endocrinology", "q": "A patient in shock refractory to fluids and vasopressors, with a history of chronic steroid use recently stopped, should receive:", "choices": ["Give more intravenous crystalloid fluids and nothing else", "Start broad-spectrum antibiotics and await culture results", "IV hydrocortisone immediately (treat adrenal crisis)", "Give an insulin infusion to control the blood glucose", "Start thyroxine replacement to correct the hypotension"], "ans": 2, "exp": "Shock ดื้อ fluid/vasopressor + ประวัติหยุด steroid = adrenal crisis. ให้ IV hydrocortisone ทันทีโดยไม่ต้องรอผลตรวจ + fluid resuscitation + หา/แก้ precipitant.", "id": "set2-68"}, {"topic": "Endocrinology", "q": "A patient has episodic severe hypertension with headache, palpitations, and diaphoresis. Which test and treatment order are correct?", "choices": ["Metanephrines; give beta-blocker first", "TSH; give levothyroxine", "Aldosterone; give spironolactone", "Plasma/urine metanephrines; alpha- then beta-blockade, then surgery", "Cortisol; proceed to surgery"], "ans": 3, "exp": "Pheochromocytoma: HT เป็นพักๆ + triad (ปวดหัว/ใจสั่น/เหงื่อ). ตรวจ plasma/urine metanephrines. ผ่าตัดหลังเตรียมด้วย alpha-blockade (phenoxybenzamine) ก่อน beta-block (ถ้าให้ beta ก่อนจะเกิด unopposed alpha → HT crisis).", "id": "set2-69"}, {"topic": "Endocrinology", "q": "A hypertensive patient with hypokalemia and a high aldosterone-to-renin ratio most likely has:", "choices": ["Pheochromocytoma", "Cushing syndrome", "Addison disease", "Renal artery stenosis", "Primary aldosteronism (Conn syndrome)"], "ans": 4, "exp": "HT + hypokalemia + aldosterone/renin ratio สูง = primary aldosteronism (Conn). ยืนยันด้วย confirmatory test + adrenal imaging/AVS; รักษา MRA (spironolactone/eplerenone) หรือผ่าตัดถ้า adenoma ข้างเดียว.", "id": "set2-70"}, {"topic": "Endocrinology", "q": "A young woman has amenorrhea, galactorrhea, and reduced libido; prolactin is markedly elevated with a pituitary mass. What is first-line treatment?", "choices": ["Dopamine agonist (cabergoline)", "Transsphenoidal surgery first", "Radiotherapy", "Estrogen therapy", "Observation only"], "ans": 0, "exp": "Prolactinoma รักษาลำดับแรกด้วย dopamine agonist (cabergoline/bromocriptine) ซึ่งลด prolactin และขนาด tumor ได้ดีแม้ macroadenoma. ผ่าตัดสงวนไว้เมื่อดื้อยา/ทน side effect ไม่ได้.", "id": "set2-71"}, {"topic": "Endocrinology", "q": "An adult with enlarging hands/feet, coarse facial features, and headache has elevated IGF-1. What confirms acromegaly?", "choices": ["A random GH level", "OGTT showing failure to suppress GH", "Serum prolactin", "Serum TSH", "Serum cortisol"], "ans": 1, "exp": "Acromegaly (GH เกินในผู้ใหญ่): คัดกรองด้วย IGF-1 สูง ยืนยันด้วย OGTT ที่ GH ไม่ suppress. หา pituitary adenoma ด้วย MRI; รักษาผ่าตัด ± somatostatin analog.", "id": "set2-72"}, {"topic": "Endocrinology", "q": "A patient with head trauma develops polyuria with dilute urine and rising sodium; urine osmolality is inappropriately low. What is the diagnosis?", "choices": ["SIADH", "Primary polydipsia", "Central diabetes insipidus", "Osmotic diuresis", "Nephrogenic DI"], "ans": 2, "exp": "หลัง head trauma/ผ่าตัด pituitary + polyuria เจือจาง + hypernatremia + urine osmolality ต่ำ = central diabetes insipidus (ขาด ADH). รักษาด้วย desmopressin.", "id": "set2-73"}, {"topic": "Endocrinology", "q": "A patient with lung small cell carcinoma has euvolemic hyponatremia, high urine osmolality, and high urine sodium. What is the diagnosis and initial management?", "choices": ["Addison; give steroid", "DI; give desmopressin", "Diuretic effect; stop diuretic", "SIADH; fluid restriction", "Cushing; surgery"], "ans": 3, "exp": "Euvolemic hyponatremia + urine osmolality/Na สูง + มะเร็งปอด = SIADH (ectopic ADH). รักษาเริ่มด้วยจำกัดน้ำ; รายรุนแรง/ชักใช้ hypertonic saline (แก้ช้าๆ), รักษาสาเหตุ.", "id": "set2-74"}, {"topic": "Endocrinology", "q": "A postmenopausal woman has a fragility fracture. A DEXA scan shows a T-score of -2.8. What is the diagnosis and a first-line treatment?", "choices": ["Osteomalacia; vitamin D only", "Paget disease; calcitonin", "Normal scan; no treatment", "Hyperparathyroidism; surgery", "Osteoporosis; bisphosphonate + calcium/vitamin D"], "ans": 4, "exp": "T-score ≤ -2.5 = osteoporosis (fragility fracture ยิ่งยืนยัน). รักษาด้วย bisphosphonate (alendronate) + calcium/vitamin D + ออกกำลัง/ป้องกันล้ม. ประเมิน secondary causes.", "id": "set2-75"}, {"topic": "Endocrinology", "q": "A patient with subclinical hypothyroidism has TSH 8 and normal free T4, is asymptomatic and not pregnant. What is the general recommendation?", "choices": ["Treat if TSH > 10, symptomatic, pregnant, or antibody-positive; else monitor", "Always start levothyroxine immediately in every such patient", "Start methimazole and reassess thyroid function in six weeks", "Give radioactive iodine ablation to prevent any progression", "Refer for thyroid surgery once the diagnosis is confirmed"], "ans": 0, "exp": "Subclinical hypothyroidism (TSH สูงเล็กน้อย, FT4 ปกติ) พิจารณา levothyroxine เมื่อ TSH > 10, มีอาการ, ตั้งครรภ์/วางแผนตั้งครรภ์, หรือ anti-TPO บวก; ที่เหลือมักติดตาม.", "id": "set2-76"}, {"topic": "Endocrinology", "q": "A patient recently started metformin. Which is a key contraindication/precaution to remember?", "choices": ["It is absolutely contraindicated in any patient who is obese", "Caution if eGFR > 30; stop if eGFR < 30 or acute illness (lactic acidosis)", "It very commonly causes significant weight gain over time", "It frequently causes hypoglycemia even used as monotherapy", "It cannot be combined with an SGLT2 inhibitor at all"], "ans": 1, "exp": "Metformin หลีกเลี่ยงเมื่อ eGFR < 30 (เสี่ยง lactic acidosis) และหยุดชั่วคราวช่วงเจ็บป่วยเฉียบพลัน/ก่อนฉีด contrast ในราย eGFR ต่ำ. ข้อดี: ไม่ทำให้น้ำตาลต่ำ/น้ำหนักเป็นกลาง.", "id": "set2-77"}, {"topic": "Endocrinology", "q": "Which diabetes drug class is associated with euglycemic diabetic ketoacidosis, especially perioperatively?", "choices": ["A sulfonylurea", "Metformin", "An SGLT2 inhibitor", "A DPP-4 inhibitor", "Insulin"], "ans": 2, "exp": "SGLT2 inhibitor อาจทำให้เกิด euglycemic DKA (โดยเฉพาะช่วงผ่าตัด/อดอาหาร/เจ็บป่วย) จึงแนะนำหยุด 3–4 วันก่อนผ่าตัดใหญ่. ต้องนึกถึงแม้ระดับน้ำตาลไม่สูงมาก.", "id": "set2-78"}, {"topic": "Endocrinology", "q": "A patient with type 1 diabetes should receive which insulin regimen as the physiologic standard?", "choices": ["Sliding scale insulin only", "Premixed insulin twice daily only", "Metformin therapy", "Basal-bolus (basal + rapid-acting with meals)", "A GLP-1 agonist alone"], "ans": 3, "exp": "T1DM ต้องใช้ insulin เสมอ; basal-bolus (basal long-acting + rapid-acting ก่อนอาหาร) เลียนแบบสรีรวิทยาได้ดีสุด. Sliding scale เดี่ยวไม่พอ; oral agents ไม่ใช้เป็นหลักใน T1DM.", "id": "set2-79"}, {"topic": "Endocrinology", "q": "A woman has secondary amenorrhea; workup shows high FSH/LH and low estrogen before age 40. What is the diagnosis?", "choices": ["Pregnancy", "Hypothalamic amenorrhea", "Polycystic ovary syndrome", "Prolactinoma", "Primary ovarian insufficiency (premature)"], "ans": 4, "exp": "High FSH/LH + low estrogen (hypergonadotropic hypogonadism) ก่อนอายุ 40 = primary ovarian insufficiency. ต่างจาก hypothalamic (FSH/LH ต่ำ). พิจารณา estrogen replacement + หา autoimmune/genetic cause.", "id": "set2-80"}, {"topic": "Endocrinology", "q": "A patient has a low serum cortisol; ACTH stimulation shows an appropriate cortisol rise. This suggests:", "choices": ["Secondary (central) adrenal insufficiency", "Primary adrenal insufficiency", "Cushing syndrome", "Pheochromocytoma", "Conn syndrome"], "ans": 0, "exp": "Cortisol ต่ำแต่ตอบสนองต่อ ACTH stimulation ดี ชี้ secondary/central adrenal insufficiency (pituitary ACTH ขาด, ต่อมหมวกไตยังทำงานได้) — มัก no hyperpigmentation, K ปกติ. Primary จะไม่ตอบสนอง ACTH.", "id": "set2-81"}, {"topic": "Endocrinology", "q": "A young woman with hirsutism, acne, oligomenorrhea, and polycystic ovaries on ultrasound has which condition, and what is first-line for menstrual regulation?", "choices": ["Cushing syndrome; surgery", "PCOS; combined oral contraceptive (± metformin)", "Prolactinoma; cabergoline", "Congenital adrenal hyperplasia; steroid", "Ovarian tumor; surgery"], "ans": 1, "exp": "PCOS (Rotterdam: 2/3 ของ oligo-ovulation, hyperandrogenism, polycystic ovaries) รักษา menstrual/hirsutism ด้วย combined OCP; metformin ช่วย insulin resistance; ลดน้ำหนัก; letrozole สำหรับ ovulation induction.", "id": "set2-82"}, {"topic": "Endocrinology", "q": "A patient with primary hyperparathyroidism has asymptomatic hypercalcemia. Which is an indication for parathyroidectomy?", "choices": ["Any measurable elevation of parathyroid hormone whatsoever", "A completely normal serum calcium with no other findings", "Age < 50, Ca > 1 above normal, eGFR < 60, osteoporosis, or stones", "Coexisting vitamin D deficiency that has not been corrected", "Only mild non-specific fatigue without any other feature"], "ans": 2, "exp": "Indication ผ่าตัดใน primary hyperparathyroidism: อายุ < 50, Ca สูงกว่าปกติ > 1 mg/dL, eGFR < 60, osteoporosis (T ≤ -2.5)/fracture, หรือนิ่วไต/hypercalciuria. Asymptomatic ที่ไม่เข้าเกณฑ์ ติดตามได้.", "id": "set2-83"}, {"topic": "Endocrinology", "q": "A patient with hypocalcemia, high phosphate, and LOW PTH after neck surgery has:", "choices": ["Primary hyperparathyroidism", "Secondary hyperparathyroidism", "Vitamin D deficiency", "Hypoparathyroidism", "Pseudohypoparathyroidism"], "ans": 3, "exp": "หลังผ่าตัดคอ + Ca ต่ำ + PO4 สูง + PTH ต่ำ = hypoparathyroidism (มัก iatrogenic). รักษาด้วย calcium + calcitriol. Secondary hyperparathyroidism (CKD/vit D ต่ำ) จะมี PTH สูง.", "id": "set2-84"}, {"topic": "Endocrinology", "q": "A patient has fasting triglycerides of 1200 mg/dL. What is the main acute risk and treatment?", "choices": ["Ischemic stroke; start a high-intensity statin urgently", "Myocardial infarction; give aspirin and dual antiplatelets", "Acute gout flare; start allopurinol with colchicine cover", "No significant acute risk; simply observe and reassure", "Acute pancreatitis; fibrate/omega-3 + control DM/alcohol"], "ans": 4, "exp": "TG สูงมาก (> 500–1000) เสี่ยง acute pancreatitis. รักษาด้วย fibrate/omega-3, คุมเบาหวาน/งดแอลกอฮอล์/ลดน้ำตาล/ลดน้ำหนัก. Statin ลด LDL แต่ไม่ใช่ตัวหลักลด TG สูงมาก.", "id": "set2-85"}, {"topic": "Endocrinology", "q": "A patient with newly diagnosed T2DM and A1c 11% with symptoms (polyuria, weight loss). What is appropriate initial therapy?", "choices": ["Insulin (± metformin) for marked hyperglycemia/symptoms", "Lifestyle alone for 3 months", "A sulfonylurea only", "Acarbose", "Observation only"], "ans": 0, "exp": "A1c สูงมาก (> 10%) + อาการ/catabolic (น้ำหนักลด) ควรเริ่ม insulin (± metformin) เพื่อคุมน้ำตาลเร็ว แล้วค่อยปรับลดเมื่อดีขึ้น. Lifestyle เดี่ยวไม่พอในภาวะน้ำตาลสูงมีอาการ.", "id": "set2-86"}, {"topic": "Endocrinology", "q": "A patient develops flushing, diarrhea, and right-sided heart valve disease; urine 5-HIAA is elevated. What is the diagnosis?", "choices": ["Pheochromocytoma", "Carcinoid syndrome", "Cushing syndrome", "Medullary thyroid cancer", "VIPoma"], "ans": 1, "exp": "Flushing + diarrhea + right-heart valvular disease + urine 5-HIAA สูง = carcinoid syndrome (serotonin จาก neuroendocrine tumor, มัก GI + liver metastasis). รักษาด้วย somatostatin analog (octreotide).", "id": "set2-87"}, {"topic": "Endocrinology", "q": "A patient with poorly controlled diabetes has bilateral lower-limb sensory loss in a 'stocking' distribution. What is the pattern of neuropathy?", "choices": ["Focal mononeuropathy", "Lumbar radiculopathy", "Distal symmetric polyneuropathy", "Autonomic neuropathy only", "Plexopathy"], "ans": 2, "exp": "Diabetic peripheral neuropathy ที่พบบ่อยสุดคือ distal symmetric (length-dependent) polyneuropathy แบบ stocking-glove. เสี่ยงแผลที่เท้า จึงต้องตรวจเท้า/สอนดูแลเท้า.", "id": "set2-88"}, {"topic": "Endocrinology", "q": "A patient on long-term glucocorticoids is at risk of which complications requiring monitoring?", "choices": ["Hypoglycemia, weight loss, hyperkalemia, and bradycardia over time", "Hypercalcemia, polyuria, renal stones, and a shortened QT interval", "Hyponatremia, hyperpigmentation, and marked postural hypotension", "Hyperglycemia, osteoporosis, hypertension, infection, adrenal suppression", "Hypertension with hypokalemia and a metabolic alkalosis only"], "ans": 3, "exp": "Long-term corticosteroid เสี่ยง hyperglycemia, osteoporosis, HT, น้ำหนักขึ้น/central obesity, ติดเชื้อ, cataract, และ HPA axis suppression (ห้ามหยุดกะทันหัน → adrenal crisis). ต้อง taper และให้ stress dose.", "id": "set2-89"}, {"topic": "Endocrinology", "q": "A patient with type 2 diabetes and obesity would benefit most (for weight and glycemia) from which class?", "choices": ["A sulfonylurea", "Insulin therapy", "A thiazolidinedione", "A DPP-4 inhibitor", "GLP-1 RA (or dual GIP/GLP-1, e.g., tirzepatide)"], "ans": 4, "exp": "GLP-1 RA (semaglutide/liraglutide) และ dual GIP/GLP-1 (tirzepatide) ลดทั้งน้ำตาลและน้ำหนักเด่นชัด เหมาะกับ T2DM + obesity. Sulfonylurea/insulin/TZD ทำให้น้ำหนักขึ้น.", "id": "set2-90"}, {"topic": "Endocrinology", "q": "A diabetic patient has an A1c goal individualized. Which patient is appropriate for a LESS stringent target (e.g., < 8%)?", "choices": ["Elderly with multiple comorbidities and hypoglycemia risk", "Young, newly diagnosed, no complications", "A pregnant patient", "A patient wanting tight control", "A young athlete"], "ans": 0, "exp": "เป้า A1c ปรับตามผู้ป่วย: ผ่อนเป้า (< 8%) ในผู้สูงอายุ/โรคร่วมมาก/เสี่ยง hypoglycemia/ life expectancy สั้น. เข้มขึ้น (< 6.5%) ในคนอายุน้อย สุขภาพดี ไม่มีภาวะแทรกซ้อน.", "id": "set2-91"}, {"topic": "Endocrinology", "q": "A patient has weight gain, proximal myopathy, easy bruising, and hyperglycemia; ACTH is elevated and high-dose dexamethasone suppresses cortisol. Where is the lesion?", "choices": ["An adrenal adenoma", "Pituitary source (Cushing disease)", "Ectopic ACTH from lung cancer", "Exogenous steroid use", "Adrenal carcinoma"], "ans": 1, "exp": "ACTH-dependent Cushing ที่ high-dose dexamethasone suppress ได้ = pituitary source (Cushing disease). Ectopic ACTH (เช่น SCLC) มักไม่ suppress และ ACTH สูงมาก.", "id": "set2-92"}, {"topic": "Endocrinology", "q": "A patient with hypothyroidism on levothyroxine still has high TSH despite adherence. What common issue should be checked?", "choices": ["An overdose of levothyroxine causing suppressed TSH levels", "Coexisting hyperthyroidism from an autonomous thyroid nodule", "Taking it with food/calcium/iron (poor absorption) or underdosing", "An unrecognized adrenal crisis complicating the picture", "A completely normal and expected laboratory finding here"], "ans": 2, "exp": "TSH ยังสูงทั้งที่กินยา — ตรวจการดูดซึม: levothyroxine ควรกินตอนท้องว่าง ห่างจากอาหาร/calcium/iron/PPI; หรือขนาดยาไม่พอ. ปรับขนาดตาม TSH ทุก 6–8 สัปดาห์.", "id": "set2-93"}, {"topic": "Endocrinology", "q": "A patient presents with tetany and carpopedal spasm; ionized calcium is low. Which acute treatment is appropriate for symptomatic hypocalcemia?", "choices": ["Oral calcium only", "Vitamin D alone", "Phosphate supplement", "IV calcium gluconate", "A bisphosphonate"], "ans": 3, "exp": "Symptomatic hypocalcemia (tetany, Trousseau/Chvostek, seizure, QT ยาว) รักษาด้วย IV calcium gluconate + แก้ Mg ถ้าต่ำ + ตามด้วย oral calcium/calcitriol. หาสาเหตุ (hypoparathyroid, vit D).", "id": "set2-94"}, {"topic": "Endocrinology", "q": "A patient with Graves disease is treated with radioactive iodine. What is the most common long-term outcome to counsel about?", "choices": ["Permanent hyperthyroidism", "Thyroid cancer", "No change at all", "Adrenal failure", "Hypothyroidism requiring levothyroxine"], "ans": 4, "exp": "RAI สำหรับ Graves มักทำให้เกิด hypothyroidism ในระยะยาว ต้องได้ levothyroxine. RAI เป็นข้อห้ามในการตั้งครรภ์/ให้นม และอาจทำให้ Graves ophthalmopathy แย่ลงชั่วคราว (พิจารณา steroid คลุม).", "id": "set2-95"}, {"topic": "Endocrinology", "q": "A patient with an incidental adrenal mass (incidentaloma) requires evaluation for which functional problems?", "choices": ["Hormone hypersecretion (cortisol, catecholamines, aldosterone) and malignancy", "Thyroid function tests with an iodine uptake scan only", "Serum prolactin and growth hormone dynamic testing only", "Bone density scanning and vitamin D level assessment only", "Serial imaging of nodule size without any hormonal testing"], "ans": 0, "exp": "Adrenal incidentaloma ต้องประเมิน functional: cortisol excess (dexamethasone suppression), pheochromocytoma (metanephrines), และ aldosterone (ARR ถ้ามี HT/hypoK) + ลักษณะ malignant (size > 4 cm, imaging phenotype).", "id": "set2-96"}, {"topic": "Endocrinology", "q": "A malnourished alcoholic patient is started on IV dextrose and develops confusion; you should also give which vitamin to prevent Wernicke encephalopathy?", "choices": ["Vitamin C", "Thiamine (B1) before or with glucose", "Folate only", "Vitamin D", "Vitamin K"], "ans": 1, "exp": "ผู้ป่วยขาดสารอาหาร/แอลกอฮอล์ ต้องให้ thiamine (B1) ก่อนหรือพร้อมกับ glucose เพื่อป้องกัน/รักษา Wernicke encephalopathy (การให้ glucose ก่อนอาจกระตุ้นอาการ). Triad: confusion, ophthalmoplegia, ataxia.", "id": "set2-97"}, {"topic": "Endocrinology", "q": "A patient with a large non-functioning pituitary macroadenoma presents with bitemporal hemianopia. What is the mechanism?", "choices": ["Cavernous sinus invasion", "Raised intracranial pressure", "Compression of the optic chiasm", "Retinal detachment", "Occipital lobe stroke"], "ans": 2, "exp": "Pituitary macroadenoma กด optic chiasm ทำให้เกิด bitemporal hemianopia (เสียลานสายตาด้านนอกทั้งสองข้าง). ประเมิน visual field + MRI + hormone panel; ผ่าตัด transsphenoidal ถ้ากดเส้นประสาท.", "id": "set2-98"}, {"topic": "Endocrinology", "q": "A patient with hypothyroidism and coexisting untreated adrenal insufficiency is given levothyroxine first. What can occur?", "choices": ["Nothing happens", "A thyroid storm", "Hyperkalemia resolves", "Precipitation of an adrenal crisis", "Only hypoglycemia"], "ans": 3, "exp": "ถ้ามี adrenal insufficiency ร่วม การเริ่ม levothyroxine ก่อนให้ steroid จะเพิ่ม metabolic demand และ cortisol clearance → กระตุ้น adrenal crisis. ต้องให้ glucocorticoid ก่อน/พร้อมกับ thyroid replacement.", "id": "set2-99"}, {"topic": "Endocrinology", "q": "A patient with diabetes has an A1c that seems discordantly low despite high glucose readings. Which condition can falsely lower A1c?", "choices": ["Iron deficiency anemia", "Post-splenectomy state", "Vitamin B12 deficiency", "Renal failure (raises it)", "Hemolytic anemia or blood loss (short RBC lifespan)"], "ans": 4, "exp": "A1c ต่ำผิดปกติเมื่อ RBC lifespan สั้นลง (hemolysis, เสียเลือด, ตั้งครรภ์). ในทางกลับกัน iron deficiency/asplenia ทำให้ A1c สูงลวง. ในกรณีเหล่านี้ใช้ fructosamine หรือ glucose monitoring แทน.", "id": "set2-100"}]}, {"id": "set3", "title": "ชุดที่ 3 — GI/Hepatology + Hematology", "questions": [{"topic": "GI/Hepatology", "q": "A 48-year-old obese man has retrosternal burning after large meals, worse when lying down, with no alarm features. What is the most appropriate initial step?", "choices": ["Lifestyle modification and an empiric PPI trial", "Immediate upper endoscopy for everyone", "24-hour esophageal pH monitoring first", "A barium swallow study as first step", "Early Nissen fundoplication surgery"], "ans": 0, "exp": "GERD ที่ไม่มี alarm features รักษาเริ่มด้วย lifestyle modification + empiric PPI. Endoscopy เมื่อมี alarm (กลืนลำบาก/น้ำหนักลด/เลือดออก/ซีด/อายุมาก). (แนวข้อสอบ NLE2)", "id": "set3-1"}, {"topic": "GI/Hepatology", "q": "Which alarm feature in a patient with dyspepsia mandates upper endoscopy?", "choices": ["Being younger than thirty years of age", "Weight loss, dysphagia, GI bleeding, or anemia", "Occasional mild bloating after meals", "Symptoms appearing after drinking coffee", "A family history of simple GERD"], "ans": 1, "exp": "Alarm features ที่ต้อง endoscopy: น้ำหนักลด, กลืนลำบาก/เจ็บ, เลือดออก (melena/hematemesis)/ซีด, อาเจียนเรื้อรัง, คลำก้อน, อายุ ≥ 50 เริ่มใหม่, ประวัติมะเร็งในครอบครัว.", "id": "set3-2"}, {"topic": "GI/Hepatology", "q": "A patient with a duodenal ulcer tests positive for H. pylori. What is the appropriate treatment?", "choices": ["A proton pump inhibitor alone without antibiotics", "Antacids alone for symptom control only", "Triple/quadruple therapy (PPI + antibiotics) to eradicate H. pylori", "Surgical management with a partial gastrectomy", "An H2-receptor blocker alone without antibiotics"], "ans": 2, "exp": "PUD จาก H. pylori รักษาด้วย eradication therapy (PPI + amoxicillin + clarithromycin หรือ bismuth quadruple 14 วัน) + PPI. ยืนยันการกำจัดด้วย urea breath test/stool antigen หลังหยุดยา.", "id": "set3-3"}, {"topic": "GI/Hepatology", "q": "Which is the most appropriate non-invasive test to confirm H. pylori eradication after treatment?", "choices": ["Serology for H. pylori antibodies", "Rapid urease test during endoscopy", "Bacterial culture of a gastric biopsy", "Urea breath test or stool antigen test", "A random serum antibody titre check"], "ans": 3, "exp": "ยืนยันการกำจัด H. pylori ด้วย urea breath test หรือ stool antigen (non-invasive, สะท้อน active infection). Serology ยังบวกได้แม้หายแล้วจึงไม่เหมาะยืนยันการกำจัด. หยุด PPI ≥ 2 สัปดาห์ก่อนตรวจ.", "id": "set3-4"}, {"topic": "GI/Hepatology", "q": "A patient presents with sudden severe epigastric pain, a rigid abdomen, and free air under the diaphragm on upright CXR. What is the diagnosis?", "choices": ["Acute pancreatitis", "Acute cholecystitis", "Acute appendicitis", "Acute gastroenteritis", "Perforated peptic ulcer"], "ans": 4, "exp": "ปวดท้องเฉียบพลันรุนแรง + peritonitis + free air ใต้ diaphragm = perforated peptic ulcer. รักษาผ่าตัด (simple closure + omental/Graham patch) + resuscitation + IV PPI/antibiotics.", "id": "set3-5"}, {"topic": "GI/Hepatology", "q": "A patient with cirrhosis presents with hematemesis. Besides resuscitation, which combination is appropriate for suspected variceal bleeding?", "choices": ["Vasoactive drug + prophylactic antibiotic + endoscopic band ligation", "A proton pump inhibitor infusion alone", "A beta-blocker infusion to lower portal pressure", "Tranexamic acid alone to stop the bleeding", "Observation with close monitoring only"], "ans": 0, "exp": "Variceal bleeding: vasoactive (octreotide/terlipressin) + prophylactic antibiotic (ceftriaxone — ลด SBP/mortality) + endoscopic variceal ligation. ป้องกันซ้ำด้วย NSBB + EVL.", "id": "set3-6"}, {"topic": "GI/Hepatology", "q": "In an actively bleeding cirrhotic patient, why are prophylactic antibiotics given?", "choices": ["They are given only to treat established SBP", "They reduce bacterial infection, rebleeding, and mortality", "They directly prevent hepatic encephalopathy", "They are given to treat the varices themselves", "They have no proven benefit in this setting"], "ans": 1, "exp": "ผู้ป่วย cirrhosis ที่มี GI bleeding ให้ prophylactic antibiotic (ceftriaxone) ลดการติดเชื้อ (รวม SBP), ลด rebleeding และลด mortality — เป็นมาตรฐานการดูแล.", "id": "set3-7"}, {"topic": "GI/Hepatology", "q": "A patient with an upper GI bleed is stable with Hb 8. What transfusion strategy is preferred?", "choices": ["A liberal strategy keeping Hb above 10", "Transfuse only when Hb falls below 5", "Restrictive strategy (transfuse to a target Hb ~7)", "Never transfuse regardless of the level", "Use only fresh whole blood transfusions"], "ans": 2, "exp": "UGIB ใช้ restrictive transfusion strategy (เป้า Hb ~7, หรือ ~8 ในโรคหัวใจ) ให้ผลลัพธ์ดีกว่า liberal (โดยเฉพาะ variceal — การให้เลือดเกินเพิ่ม portal pressure/rebleeding).", "id": "set3-8"}, {"topic": "GI/Hepatology", "q": "A cirrhotic patient with ascites develops fever and abdominal pain; ascitic fluid PMN is 320/mm³. What is the diagnosis and treatment?", "choices": ["Secondary peritonitis; proceed to surgery", "Tuberculous peritonitis; start anti-TB drugs", "Malignant ascites; begin chemotherapy", "Spontaneous bacterial peritonitis; give cefotaxime", "Pancreatic ascites; give octreotide"], "ans": 3, "exp": "Ascitic fluid PMN ≥ 250 = spontaneous bacterial peritonitis (SBP). รักษาด้วย cefotaxime + IV albumin (ลด hepatorenal). ป้องกันซ้ำด้วย norfloxacin ในกลุ่มเสี่ยง.", "id": "set3-9"}, {"topic": "GI/Hepatology", "q": "A cirrhotic patient becomes confused with asterixis after constipation. What is the first-line treatment for hepatic encephalopathy?", "choices": ["Long-term dietary protein restriction", "Sedation to calm the confused patient", "A benzodiazepine to settle the patient", "A diuretic to reduce the ascites", "Lactulose (± rifaximin) and treat precipitants"], "ans": 4, "exp": "Hepatic encephalopathy รักษาด้วย lactulose (เป้าถ่าย 2–3 ครั้ง/วัน ลด ammonia) ± rifaximin + หา/แก้ precipitant (ท้องผูก, เลือดออก, ติดเชื้อ, electrolyte, ยา sedative). ไม่จำกัดโปรตีนระยะยาว.", "id": "set3-10"}, {"topic": "GI/Hepatology", "q": "How is the serum-ascites albumin gradient (SAAG) used?", "choices": ["SAAG ≥ 1.1 g/dL indicates portal hypertension", "SAAG < 1.1 g/dL indicates portal hypertension", "The SAAG value measures ascitic infection", "The SAAG value measures underlying malignancy", "The SAAG is not a clinically useful test"], "ans": 0, "exp": "SAAG = serum albumin − ascites albumin. ≥ 1.1 g/dL บ่งชี้ portal hypertension (cirrhosis, HF, Budd-Chiari); < 1.1 บ่งชี้สาเหตุอื่น (malignancy, TB, nephrotic, pancreatic).", "id": "set3-11"}, {"topic": "GI/Hepatology", "q": "A patient with chronic hepatitis B and cirrhosis needs HCC surveillance. What is the recommended approach?", "choices": ["CT of the abdomen once every year", "Ultrasound ± AFP every 6 months", "Upper endoscopy once every year", "No surveillance is needed at all", "MRI of the liver every single month"], "ans": 1, "exp": "ผู้ป่วย cirrhosis หรือ HBV เสี่ยง HCC ควร surveillance ด้วย ultrasound ± AFP ทุก 6 เดือน. รอยโรคสงสัยยืนยันด้วย triple-phase CT/MRI (arterial enhancement + washout).", "id": "set3-12"}, {"topic": "GI/Hepatology", "q": "A patient has HBsAg positive, anti-HBc IgG positive, HBeAg positive, and high HBV DNA. What does this indicate?", "choices": ["Immunity acquired from prior vaccination", "A fully resolved past HBV infection", "Chronic active hepatitis B with high infectivity", "Acute hepatitis A virus infection", "The serologic window period"], "ans": 2, "exp": "HBsAg + high HBV DNA + HBeAg = chronic active HBV ที่ติดต่อง่าย. Anti-HBs เดี่ยว = ภูมิจากวัคซีน; anti-HBc IgM = acute; anti-HBs + anti-HBc = หายและมีภูมิ. รักษา antiviral (tenofovir/entecavir) เมื่อเข้าเกณฑ์.", "id": "set3-13"}, {"topic": "GI/Hepatology", "q": "A person has anti-HBs positive but anti-HBc negative. What does this indicate?", "choices": ["Chronic hepatitis B infection", "Acute hepatitis B infection", "Resolved natural HBV infection", "Immunity acquired from vaccination", "The serologic window period"], "ans": 3, "exp": "Anti-HBs positive + anti-HBc negative = ภูมิจากวัคซีน (ไม่เคยติดเชื้อธรรมชาติ). ถ้าเคยติดเชื้อแล้วหาย จะมีทั้ง anti-HBs + anti-HBc positive. (แนวข้อสอบ NLE2)", "id": "set3-14"}, {"topic": "GI/Hepatology", "q": "A patient with chronic hepatitis C (genotype-agnostic) should be offered which treatment with >95% cure?", "choices": ["Interferon plus ribavirin therapy", "Lifelong lamivudine monotherapy", "No treatment is needed at all", "Systemic corticosteroid therapy", "Direct-acting antivirals (DAA)"], "ans": 4, "exp": "Chronic HCV รักษาด้วย direct-acting antivirals (DAA) ระยะสั้น 8–12 สัปดาห์ หายกว่า 95% (SVR). Interferon เป็นของเดิมที่เลิกใช้แล้ว.", "id": "set3-15"}, {"topic": "GI/Hepatology", "q": "A patient develops jaundice, dark urine, and RUQ pain 3 weeks after starting a herbal weight-loss supplement; viral panel negative. Which test is most critical initially?", "choices": ["Liver function tests", "A fasting lipid profile", "Serum creatinine level", "Serum TSH level", "A complete blood count only"], "ans": 0, "exp": "สงสัย drug/herb-induced liver injury — ตรวจ liver function tests (AST/ALT/bilirubin/ALP) เพื่อประเมินอวัยวะที่ถูกกระทบและรูปแบบ (hepatocellular vs cholestatic). หยุด agent ต้นเหตุ. (แนวข้อสอบ NLE2)", "id": "set3-16"}, {"topic": "GI/Hepatology", "q": "A patient meets 2 of 3 criteria for acute pancreatitis. What is the cornerstone of early management?", "choices": ["Prophylactic antibiotics for every patient", "Aggressive IV fluid resuscitation, analgesia, and early enteral feeding", "Immediate surgery to remove the pancreas", "Keeping the patient NPO for two weeks", "Immediate ERCP for every patient"], "ans": 1, "exp": "Acute pancreatitis รักษาด้วย aggressive IV fluid (goal-directed), analgesia, early enteral feeding. ไม่ให้ prophylactic antibiotic (ให้เมื่อ infected necrosis); ERCP เฉพาะเมื่อมี cholangitis/นิ่วอุดตัน.", "id": "set3-17"}, {"topic": "GI/Hepatology", "q": "Which are the two most common causes of acute pancreatitis?", "choices": ["Abdominal trauma and drugs", "Hyperlipidemia and mumps", "Gallstones and alcohol", "Scorpion sting and post-ERCP", "Autoimmune and idiopathic causes"], "ans": 2, "exp": "สาเหตุที่พบบ่อยที่สุดของ acute pancreatitis คือ gallstones และ alcohol. อื่นๆ (GET SMASHED): hyperTG, ERCP, drugs, trauma, mumps, autoimmune, scorpion. ตรวจ lipase > 3 เท่า + imaging.", "id": "set3-18"}, {"topic": "GI/Hepatology", "q": "A patient has painless obstructive jaundice with a palpable non-tender gallbladder (Courvoisier sign). What is the most concerning diagnosis?", "choices": ["A gallstone impacted in the cystic duct", "Acute viral hepatitis", "Gilbert syndrome", "Pancreatic head / periampullary carcinoma", "Hemolysis of red cells"], "ans": 3, "exp": "Courvoisier sign (ถุงน้ำดีโตคลำได้ ไม่เจ็บ + jaundice) บ่งชี้ malignant obstruction (pancreatic head/periampullary CA) มากกว่านิ่ว. ประเมินด้วย imaging (CT/MRCP/EUS); Whipple ถ้า resectable.", "id": "set3-19"}, {"topic": "GI/Hepatology", "q": "A patient with progressive dysphagia to solids then liquids, weight loss, and a history of smoking/alcohol most likely has:", "choices": ["Achalasia of the esophagus", "Gastroesophageal reflux disease", "A congenital esophageal web", "Diffuse esophageal spasm", "Esophageal carcinoma"], "ans": 4, "exp": "Progressive dysphagia (solids → liquids) + น้ำหนักลด + สูบบุหรี่/เหล้า = esophageal carcinoma (upper/mid = SCC). Achalasia มัก dysphagia ต่อทั้ง solid+liquid ตั้งแต่ต้นและไม่ค่อยน้ำหนักลดเร็ว.", "id": "set3-20"}, {"topic": "GI/Hepatology", "q": "A patient has dysphagia to both solids and liquids; barium shows a dilated esophagus with a 'bird's beak' narrowing at the GE junction. What is the diagnosis?", "choices": ["Achalasia", "Esophageal carcinoma", "A GERD-related stricture", "A Schatzki ring", "Zenker diverticulum"], "ans": 0, "exp": "Dysphagia ต่อทั้ง solid+liquid + bird's beak (dilated esophagus, narrow GE junction) = achalasia (LES ไม่คลาย + aperistalsis). ยืนยันด้วย manometry; รักษา pneumatic dilatation/Heller myotomy/POEM. (แนวข้อสอบ NLE2)", "id": "set3-21"}, {"topic": "GI/Hepatology", "q": "A young patient has chronic bloody diarrhea, tenesmus, and continuous inflammation from the rectum proximally limited to the mucosa on colonoscopy. What is the diagnosis?", "choices": ["Crohn disease", "Ulcerative colitis", "Ischemic colitis", "Amoebic colitis", "Celiac disease"], "ans": 1, "exp": "Continuous inflammation จาก rectum ขึ้นไป, จำกัดที่ mucosa, bloody diarrhea = ulcerative colitis. Crohn = skip lesions, transmural, ทุกส่วนของ GI, fistula/granuloma.", "id": "set3-22"}, {"topic": "GI/Hepatology", "q": "Which feature is characteristic of Crohn disease rather than ulcerative colitis?", "choices": ["Continuous colonic mucosal involvement", "Disease limited to the rectum and colon", "Transmural skip lesions with fistulas and granulomas", "Bloody diarrhea present in every case", "No small bowel involvement at all"], "ans": 2, "exp": "Crohn: transmural, skip lesions, ได้ทุกส่วน (mouth-anus), fistula/stricture/perianal disease, non-caseating granuloma. UC: continuous, mucosal, จำกัด colon เริ่มจาก rectum.", "id": "set3-23"}, {"topic": "GI/Hepatology", "q": "A 35-year-old returning traveler has bloody, foul diarrhea; stool shows motile trophozoites with ingested RBCs. What is the treatment?", "choices": ["Ciprofloxacin monotherapy", "Ceftriaxone monotherapy", "Albendazole therapy", "Metronidazole, then a luminal agent", "Oral vancomycin therapy"], "ans": 3, "exp": "Trophozoite ที่กิน RBC = Entamoeba histolytica (amoebic dysentery/liver abscess). รักษาด้วย metronidazole/tinidazole ตามด้วย luminal agent (paromomycin/diloxanide) กำจัด cyst. (แนวข้อสอบ NLE2)", "id": "set3-24"}, {"topic": "GI/Hepatology", "q": "A patient develops profuse watery diarrhea after recent antibiotic use; stool tests positive for C. difficile toxin. What is the first-line treatment?", "choices": ["Intravenous metronidazole alone", "Loperamide to stop the diarrhea", "Ciprofloxacin therapy", "Probiotics alone without antibiotics", "Oral vancomycin or fidaxomicin"], "ans": 4, "exp": "C. difficile infection รักษา first-line ด้วย oral vancomycin หรือ fidaxomicin (metronidazole เป็นทางเลือกรองในรายไม่รุนแรงที่เข้าถึงยาหลักไม่ได้). หยุด antibiotic ต้นเหตุ; หลีกเลี่ยง antimotility.", "id": "set3-25"}, {"topic": "GI/Hepatology", "q": "A patient has chronic diarrhea, weight loss, iron deficiency, and a rash (dermatitis herpetiformis); anti-tissue transglutaminase is positive. What is the diagnosis?", "choices": ["Celiac disease", "Crohn disease", "Tropical sprue", "Lactose intolerance", "Whipple disease"], "ans": 0, "exp": "Malabsorption + anti-tTG positive + dermatitis herpetiformis = celiac disease. ยืนยันด้วย duodenal biopsy (villous atrophy); รักษาด้วย gluten-free diet.", "id": "set3-26"}, {"topic": "GI/Hepatology", "q": "A patient has right lower quadrant pain migrating from the periumbilical area, anorexia, and low-grade fever with McBurney tenderness. What is the diagnosis?", "choices": ["Acute gastroenteritis", "Acute appendicitis", "Acute diverticulitis", "Acute cholecystitis", "Mesenteric adenitis"], "ans": 1, "exp": "ปวด periumbilical แล้วย้ายมา RLQ (McBurney) + anorexia + ไข้ต่ำ = acute appendicitis. ยืนยัน US/CT; รักษา appendectomy (uncomplicated ที่ยืนยันด้วย CT อาจใช้ antibiotics-first ในบางราย).", "id": "set3-27"}, {"topic": "GI/Hepatology", "q": "An elderly patient has left lower quadrant pain, fever, and a CT showing sigmoid diverticula with pericolic inflammation. What is the diagnosis?", "choices": ["Acute appendicitis", "Ulcerative colitis", "Acute diverticulitis", "Ischemic colitis", "Colorectal cancer"], "ans": 2, "exp": "LLQ pain + ไข้ + sigmoid diverticula + pericolic fat stranding = acute diverticulitis. Uncomplicated รักษา bowel rest ± antibiotics; complicated (abscess/perforation) → drainage/surgery.", "id": "set3-28"}, {"topic": "GI/Hepatology", "q": "A 55-year-old has iron-deficiency anemia and change in bowel habits. What is the essential investigation?", "choices": ["Upper endoscopy alone as the work-up", "CT of the abdomen alone", "A stool culture for pathogens", "Colonoscopy to exclude colorectal cancer", "Reassurance without investigation"], "ans": 3, "exp": "IDA + เปลี่ยนแปลงการขับถ่ายในผู้ใหญ่ ≥ 45–50 ปี ต้อง colonoscopy เพื่อตัด colorectal cancer (เลือดออกเรื้อรัง). Right-sided CA มัก present ด้วย anemia/occult bleeding.", "id": "set3-29"}, {"topic": "GI/Hepatology", "q": "At what age should average-risk adults begin colorectal cancer screening according to current recommendations?", "choices": ["At age 40 years", "At age 50 years", "At age 60 years", "At age 65 years", "At age 45 years"], "ans": 4, "exp": "USPSTF 2021 ลดอายุเริ่มคัดกรอง colorectal cancer เป็น 45 ปี (จากเดิม 50) ในคนความเสี่ยงปกติ — colonoscopy ทุก 10 ปี หรือ FIT ทุกปี.", "id": "set3-30"}, {"topic": "GI/Hepatology", "q": "A patient with cirrhosis has AKI unresponsive to volume with bland urine sediment. Which is a key treatment for hepatorenal syndrome?", "choices": ["Terlipressin (or noradrenaline) plus albumin", "A loop diuretic to increase urine output", "A dopamine infusion for renal perfusion", "An NSAID for symptomatic relief", "A nephrotoxic aminoglycoside antibiotic"], "ans": 0, "exp": "Hepatorenal syndrome รักษาด้วย vasoconstrictor (terlipressin หรือ noradrenaline) + albumin เพื่อเพิ่ม effective circulating volume; แก้ precipitant; ปลูกถ่ายตับเป็น definitive.", "id": "set3-31"}, {"topic": "GI/Hepatology", "q": "A patient has episodic upper abdominal pain after fatty meals with a positive Murphy sign and fever. Ultrasound shows a thickened gallbladder wall with stones. What is the diagnosis?", "choices": ["Biliary colic", "Acute cholecystitis", "Ascending cholangitis", "Acute pancreatitis", "Acute hepatitis"], "ans": 1, "exp": "RUQ pain + Murphy sign + ไข้ + gallstone + wall thickening = acute cholecystitis. รักษา NPO, IV fluid/antibiotics, analgesia + laparoscopic cholecystectomy (early). Biliary colic ไม่มีไข้/อักเสบ.", "id": "set3-32"}, {"topic": "GI/Hepatology", "q": "A patient has fever, jaundice, and RUQ pain (Charcot triad). What is the diagnosis and key intervention?", "choices": ["Cholecystitis; perform cholecystectomy", "Viral hepatitis; supportive care only", "Ascending cholangitis; ERCP decompression + antibiotics", "Acute pancreatitis; give IV fluids", "Liver abscess; percutaneous drainage"], "ans": 2, "exp": "Charcot triad (fever + jaundice + RUQ pain) = ascending cholangitis (มัก choledocholithiasis). ต้อง IV antibiotics + biliary decompression (ERCP) ด่วน. Reynolds pentad (+ hypotension + confusion) = รุนแรง.", "id": "set3-33"}, {"topic": "GI/Hepatology", "q": "A patient with alcoholic liver disease has an AST:ALT ratio of about 2:1 and both are moderately elevated (< 300). What does this suggest?", "choices": ["Acute viral hepatitis", "Ischemic hepatitis", "Autoimmune hepatitis", "Alcoholic hepatitis", "Biliary obstruction"], "ans": 3, "exp": "AST:ALT > 2:1 กับ transaminase สูงปานกลาง (มัก < 300) เข้าได้กับ alcoholic liver disease/hepatitis. Viral hepatitis มัก ALT > AST และสูงมากได้.", "id": "set3-34"}, {"topic": "GI/Hepatology", "q": "A young woman has amenorrhea, high transaminases, positive ANA/anti-smooth muscle antibody, and high IgG. What is the diagnosis?", "choices": ["Acute viral hepatitis", "Wilson disease", "Hereditary hemochromatosis", "Primary biliary cholangitis", "Autoimmune hepatitis"], "ans": 4, "exp": "Autoimmune hepatitis: หญิงสาว, transaminase สูง, ANA/anti-smooth muscle Ab positive, IgG สูง. ยืนยันด้วย biopsy (interface hepatitis); รักษาด้วย corticosteroid ± azathioprine.", "id": "set3-35"}, {"topic": "GI/Hepatology", "q": "A young patient has liver disease, neuropsychiatric symptoms, and Kayser-Fleischer rings. What is the diagnosis?", "choices": ["Wilson disease", "Hereditary hemochromatosis", "Alpha-1 antitrypsin deficiency", "Autoimmune hepatitis", "Chronic hepatitis B"], "ans": 0, "exp": "Wilson disease (copper สะสม): liver disease + neuropsychiatric + Kayser-Fleischer rings; ceruloplasmin ต่ำ, urinary copper สูง. รักษาด้วย chelator (penicillamine/trientine) + zinc.", "id": "set3-36"}, {"topic": "GI/Hepatology", "q": "A patient has bronze skin, diabetes, arthralgia, and elevated ferritin/transferrin saturation. What is the diagnosis?", "choices": ["Wilson disease", "Hereditary hemochromatosis", "Acute porphyria", "Alcoholic liver disease", "Chronic hepatitis C"], "ans": 1, "exp": "Hereditary hemochromatosis (iron overload, HFE mutation): bronze diabetes + arthralgia + hepatomegaly/HCC risk; ferritin + transferrin saturation สูง. รักษาด้วย phlebotomy.", "id": "set3-37"}, {"topic": "GI/Hepatology", "q": "A patient has watery diarrhea, and stool osmotic gap is high, improving with fasting. What type of diarrhea is this?", "choices": ["Secretory diarrhea", "Inflammatory diarrhea", "Osmotic diarrhea", "Infectious diarrhea", "Fatty (malabsorptive) diarrhea"], "ans": 2, "exp": "Osmotic diarrhea (เช่น lactose intolerance, laxative) มี stool osmotic gap สูง และดีขึ้นเมื่ออดอาหาร. Secretory diarrhea (เช่น cholera, VIPoma) ไม่หยุดเมื่ออดอาหารและ gap ต่ำ.", "id": "set3-38"}, {"topic": "GI/Hepatology", "q": "A patient has recurrent peptic ulcers in unusual locations with diarrhea and very high gastrin. What is the diagnosis?", "choices": ["Common peptic ulcer disease", "H. pylori-related ulceration", "Gastroesophageal reflux disease", "Zollinger-Ellison syndrome (gastrinoma)", "Menetrier disease"], "ans": 3, "exp": "แผลหลายตำแหน่ง/ตำแหน่งผิดปกติ + diarrhea + gastrin สูงมาก = Zollinger-Ellison syndrome (gastrinoma) มักสัมพันธ์ MEN1. ยืนยันด้วย secretin stimulation test.", "id": "set3-39"}, {"topic": "GI/Hepatology", "q": "A patient with severe acute pancreatitis develops persistent fever and clinical deterioration at 2 weeks; CT shows gas in a necrotic collection. What does this indicate?", "choices": ["A pancreatic pseudocyst", "Splenic vein thrombosis", "Resolving pancreatitis", "Pancreatic ascites", "Infected pancreatic necrosis"], "ans": 4, "exp": "ไข้ต่อเนื่อง + gas ใน necrotic collection = infected pancreatic necrosis → ให้ antibiotics + drainage/necrosectomy (step-up). Prophylactic antibiotic ไม่แนะนำ แต่ให้เมื่อมีการติดเชื้อยืนยัน.", "id": "set3-40"}, {"topic": "GI/Hepatology", "q": "A patient presents with hematochezia; after resuscitation, which is the most common cause of significant lower GI bleeding in older adults?", "choices": ["Diverticulosis", "Bleeding hemorrhoids", "An anal fissure", "Ischemic colitis", "Infectious colitis"], "ans": 0, "exp": "สาเหตุ LGIB ที่มีนัยสำคัญในผู้สูงอายุที่พบบ่อยคือ diverticulosis (และ angiodysplasia). ประเมินด้วย colonoscopy หลัง resuscitation; หา malignancy ด้วย.", "id": "set3-41"}, {"topic": "GI/Hepatology", "q": "A patient with cirrhosis has no prior variceal bleeding but endoscopy shows large esophageal varices. What is appropriate primary prophylaxis?", "choices": ["No treatment until the first bleed", "Non-selective beta-blocker (or endoscopic band ligation)", "A proton pump inhibitor", "Prophylactic antibiotics", "A TIPS procedure upfront"], "ans": 1, "exp": "Primary prophylaxis ของ variceal bleeding ใน large varices = non-selective beta-blocker (propranolol/carvedilol) หรือ endoscopic variceal ligation. TIPS ใช้ในรายเลือดออกซ้ำ/ดื้อ.", "id": "set3-42"}, {"topic": "GI/Hepatology", "q": "A patient has chronic epigastric pain, steatorrhea, and new diabetes with pancreatic calcifications. What is the diagnosis?", "choices": ["Acute pancreatitis", "Pancreatic carcinoma", "Chronic pancreatitis", "Gallstone disease", "Celiac disease"], "ans": 2, "exp": "ปวดเรื้อรัง + steatorrhea (exocrine insufficiency) + DM (endocrine) + pancreatic calcification = chronic pancreatitis (มักจากแอลกอฮอล์). รักษาด้วย pancreatic enzyme replacement, คุมปวด, งดเหล้า.", "id": "set3-43"}, {"topic": "GI/Hepatology", "q": "A patient with a right-lobe liver abscess and recent travel/dysentery, positive amoebic serology. What is the treatment?", "choices": ["Surgical resection of the abscess", "Ceftriaxone monotherapy", "Percutaneous drainage first-line always", "Metronidazole, then a luminal agent", "Albendazole therapy"], "ans": 3, "exp": "Amoebic liver abscess (Entamoeba histolytica, มัก lobe ขวา) รักษาด้วย metronidazole ตามด้วย luminal agent. Drainage สงวนไว้เมื่อใหญ่มาก/ไม่ตอบสนอง/สงสัย pyogenic.", "id": "set3-44"}, {"topic": "GI/Hepatology", "q": "A patient with obstructive jaundice has a dilated common bile duct with a stone on MRCP. What is the appropriate intervention?", "choices": ["Cholecystectomy performed first", "Observation without intervention", "Antibiotics alone without drainage", "A Whipple procedure", "ERCP with stone extraction"], "ans": 4, "exp": "Choledocholithiasis (นิ่วใน CBD) รักษาด้วย ERCP + sphincterotomy/stone extraction; ตามด้วย cholecystectomy ถ้ามี gallstone. ถ้ามี cholangitis ต้อง decompress ด่วน.", "id": "set3-45"}, {"topic": "GI/Hepatology", "q": "A patient develops acute severe abdominal pain out of proportion to exam findings, with a history of AF; lactate is rising. What is the diagnosis?", "choices": ["Acute mesenteric ischemia", "A perforated peptic ulcer", "Acute diverticulitis", "Acute pancreatitis", "Acute gastroenteritis"], "ans": 0, "exp": "ปวดท้องรุนแรงเกินกว่าตรวจพบ (pain out of proportion) + AF (embolic source) + lactate สูง = acute mesenteric ischemia (มัก SMA embolism). ต้อง CT angiography + revascularization ด่วน; delay = bowel necrosis.", "id": "set3-46"}, {"topic": "GI/Hepatology", "q": "A patient with Barrett esophagus is at increased risk of which malignancy?", "choices": ["Esophageal squamous cell carcinoma", "Esophageal adenocarcinoma", "Gastric lymphoma", "Small bowel carcinoid", "Pancreatic carcinoma"], "ans": 1, "exp": "Barrett esophagus (intestinal metaplasia จาก chronic GERD) เพิ่มเสี่ยง esophageal adenocarcinoma (lower third). เฝ้าระวังด้วย endoscopy + biopsy หา dysplasia.", "id": "set3-47"}, {"topic": "GI/Hepatology", "q": "A patient with jaundice has predominantly elevated unconjugated (indirect) bilirubin with normal LFTs and no hemolysis, worse with fasting/stress. What is the likely diagnosis?", "choices": ["Acute viral hepatitis", "Biliary obstruction", "Gilbert syndrome", "Established cirrhosis", "Pancreatic carcinoma"], "ans": 2, "exp": "Indirect hyperbilirubinemia ที่ LFT ปกติ ไม่มี hemolysis, เป็นมากเวลาอด/เครียด = Gilbert syndrome (UGT1A1 ลดลง) — benign ไม่ต้องรักษา.", "id": "set3-48"}, {"topic": "GI/Hepatology", "q": "A patient with alcohol use disorder takes paracetamol 8 tabs/day for a week and presents with markedly elevated transaminases (AST/ALT in thousands). What is the mechanism of injury?", "choices": ["Cholestatic injury from bile duct blockage", "A viral cytopathic effect on hepatocytes", "An autoimmune attack on the liver", "Hepatotoxic NAPQI accumulation with glutathione depletion", "Ischemic injury from hypoperfusion only"], "ans": 3, "exp": "Paracetamol เกินขนาด (ยิ่งในผู้ดื่มสุรา/อดอาหาร) สร้าง NAPQI มากขึ้นและ glutathione พร่อง → centrilobular hepatic necrosis (transaminase สูงเป็นพัน). รักษาด้วย N-acetylcysteine ตาม nomogram/เร็วที่สุด. (แนวข้อสอบ NLE2)", "id": "set3-49"}, {"topic": "GI/Hepatology", "q": "A patient presents with acute liver failure from paracetamol overdose. What is the specific antidote?", "choices": ["Naloxone", "Flumazenil", "Vitamin K", "Fomepizole", "N-acetylcysteine"], "ans": 4, "exp": "Paracetamol toxicity รักษาด้วย N-acetylcysteine (เติม glutathione precursor) ยิ่งให้เร็วยิ่งดี (ภายใน 8 ชม.). ประเมินด้วย paracetamol level + Rumack-Matthew nomogram; ดู King's College criteria สำหรับ transplant.", "id": "set3-50"}, {"topic": "GI/Hepatology", "q": "A patient has chronic constipation alternating with diarrhea, abdominal pain relieved by defecation, and normal investigations with no alarm features. What is the diagnosis?", "choices": ["Irritable bowel syndrome", "Colorectal cancer", "Ulcerative colitis", "Celiac disease", "Diverticulitis"], "ans": 0, "exp": "ปวดท้องเรื้อรังสัมพันธ์การขับถ่าย + เปลี่ยนความถี่/ลักษณะอุจจาระ โดยไม่มี alarm feature และตรวจปกติ = irritable bowel syndrome (Rome criteria). รักษาตามอาการ + diet (low-FODMAP) + ให้ความมั่นใจ.", "id": "set3-51"}, {"topic": "Hematology", "q": "A patient has microcytic hypochromic anemia with low ferritin and high RDW. What is the diagnosis and next step?", "choices": ["Thalassemia trait; do hemoglobin typing", "Iron deficiency anemia; find the source of blood loss", "Anemia of chronic disease; treat inflammation", "Sideroblastic anemia; give pyridoxine (B6)", "Lead poisoning; start chelation therapy"], "ans": 1, "exp": "Microcytic + ferritin ต่ำ = iron deficiency anemia. ในผู้ใหญ่ต้องหาสาเหตุเสียเลือด (GI → endoscopy; menorrhagia ในหญิง). รักษาด้วย ferrous + แก้สาเหตุ.", "id": "set3-52"}, {"topic": "Hematology", "q": "A Southeast Asian woman has microcytic anemia with NORMAL ferritin, target cells, basophilic stippling, and 'golf ball' inclusions on brilliant cresyl blue stain. What is the diagnosis?", "choices": ["Iron deficiency anemia", "Hereditary spherocytosis", "Hemoglobin H disease", "Megaloblastic anemia", "Autoimmune hemolytic anemia"], "ans": 2, "exp": "Microcytic ที่ ferritin ปกติ + target cell + HbH inclusion (golf ball ด้วย supravital stain) = Hemoglobin H disease (alpha-thalassemia, 3-gene deletion). ห้ามให้ธาตุเหล็กพร่ำเพรื่อ. (แนวข้อสอบ NLE2)", "id": "set3-53"}, {"topic": "Hematology", "q": "How can iron deficiency anemia be distinguished from thalassemia trait when both are microcytic?", "choices": ["The MCV value on its own", "The reticulocyte count on its own", "The total white cell count", "RDW and ferritin (low in IDA, normal/high in thalassemia)", "The platelet count"], "ans": 3, "exp": "IDA: ferritin ต่ำ, RDW กว้าง, Mentzer index (MCV/RBC) > 13. Thalassemia trait: ferritin ปกติ/สูง, RDW ปกติ, RBC count สูง, Mentzer < 13, ยืนยันด้วย Hb typing.", "id": "set3-54"}, {"topic": "Hematology", "q": "A patient with rheumatoid arthritis has normocytic anemia, low serum iron, low TIBC, and high ferritin. What is the diagnosis?", "choices": ["Iron deficiency anemia", "Thalassemia trait", "Hemolytic anemia", "Vitamin B12 deficiency", "Anemia of chronic disease"], "ans": 4, "exp": "Anemia of chronic disease/inflammation: iron ต่ำ, TIBC ต่ำ, ferritin สูง (acute phase, hepcidin สูง). ต่างจาก IDA ที่ TIBC สูง ferritin ต่ำ. รักษาที่โรคต้นเหตุ.", "id": "set3-55"}, {"topic": "Hematology", "q": "A patient has macrocytic anemia with hypersegmented neutrophils and neurological symptoms (paresthesia, ataxia). What is the deficiency?", "choices": ["Vitamin B12 (cobalamin)", "Folate (vitamin B9)", "Iron", "Vitamin C", "Vitamin K"], "ans": 0, "exp": "Macrocytic + hypersegmented neutrophils + neuro (subacute combined degeneration) = B12 deficiency. Folate deficiency ให้ภาพ megaloblastic เหมือนกันแต่ไม่มี neuro. ให้ B12 ก่อน folate เพื่อไม่บดบัง neuro.", "id": "set3-56"}, {"topic": "Hematology", "q": "A patient of Thai descent develops acute hemolysis after taking an antimalarial or eating fava beans; blood smear shows bite cells and Heinz bodies. What is the diagnosis?", "choices": ["Hereditary spherocytosis", "G6PD deficiency", "Autoimmune hemolytic anemia", "Thalassemia", "Sickle cell disease"], "ans": 1, "exp": "Hemolysis หลังยา/ถั่วปากอ้า/ติดเชื้อ + bite cells + Heinz bodies (X-linked) = G6PD deficiency (พบบ่อยในไทย). หลีกเลี่ยง oxidative triggers; ตรวจ G6PD level หลัง acute episode (อาจปกติลวงช่วง hemolysis).", "id": "set3-57"}, {"topic": "Hematology", "q": "A patient has anemia with high reticulocytes, high LDH, high indirect bilirubin, low haptoglobin, and a positive direct Coombs test. What is the diagnosis?", "choices": ["Iron deficiency anemia", "Thalassemia trait", "Autoimmune hemolytic anemia", "Aplastic anemia", "Anemia of chronic disease"], "ans": 2, "exp": "Hemolysis markers (retic สูง, LDH สูง, indirect bili สูง, haptoglobin ต่ำ) + direct Coombs positive = autoimmune hemolytic anemia. Warm (IgG) vs cold (IgM). รักษา warm AIHA ด้วย corticosteroid. (แนวข้อสอบ NLE2)", "id": "set3-58"}, {"topic": "Hematology", "q": "A patient with anemia has spherocytes on smear, a negative Coombs test, splenomegaly, and a family history; osmotic fragility is increased. What is the diagnosis?", "choices": ["Autoimmune hemolytic anemia", "G6PD deficiency", "Thalassemia", "Hereditary spherocytosis", "Sickle cell disease"], "ans": 3, "exp": "Spherocytes + Coombs negative + ประวัติครอบครัว + osmotic fragility เพิ่ม = hereditary spherocytosis (membrane defect). ต่างจาก AIHA (Coombs positive). รักษา folate ± splenectomy ในรายรุนแรง.", "id": "set3-59"}, {"topic": "Hematology", "q": "A patient receiving packed red cells develops fever, chills, back pain, hypotension, and dark urine 15 minutes into transfusion. What is the diagnosis and immediate action?", "choices": ["Febrile non-hemolytic reaction; slow the rate", "TACO fluid overload; give a diuretic", "Allergic reaction; give an antihistamine", "TRALI; support with ventilation", "Acute hemolytic reaction (ABO mismatch); stop transfusion now"], "ans": 4, "exp": "อาการเฉียบพลัน (ไข้ ปวดหลัง hypotension hemoglobinuria) = acute hemolytic transfusion reaction (ABO incompatibility). หยุดให้เลือดทันที, IV fluid รักษาไต, ตรวจซ้ำ. (แนวข้อสอบ NLE2)", "id": "set3-60"}, {"topic": "Hematology", "q": "A patient develops dyspnea and bilateral pulmonary infiltrates within 6 hours of transfusion, with normal cardiac filling. What is the diagnosis?", "choices": ["Transfusion-related acute lung injury (TRALI)", "Transfusion-associated circulatory overload", "Anaphylactic reaction", "Acute hemolytic reaction", "Febrile non-hemolytic reaction"], "ans": 0, "exp": "Non-cardiogenic pulmonary edema ภายใน 6 ชม.หลังให้เลือด (donor antibody ต่อ leukocyte) = TRALI. ต่างจาก TACO (volume overload, cardiogenic). รักษาแบบ supportive/ventilation; TACO ใช้ diuretic.", "id": "set3-61"}, {"topic": "Hematology", "q": "A stable patient needs platelet transfusion prophylaxis. At what platelet count is prophylactic transfusion generally indicated?", "choices": ["Below 100,000 platelets", "Below 10,000 (or < 50,000 if bleeding/procedure)", "Below 50,000 platelets", "Below 150,000 platelets", "Never given prophylactically"], "ans": 1, "exp": "Platelet transfusion เชิงป้องกันเมื่อ < 10,000 (เสี่ยงเลือดออกเอง); ให้ที่ < 50,000 ถ้ามีเลือดออก/ก่อนหัตถการ; < 100,000 สำหรับ neurosurgery/ตา.", "id": "set3-62"}, {"topic": "Hematology", "q": "A patient has isolated thrombocytopenia with mucocutaneous bleeding, normal WBC/Hb, and a normal-sized spleen; other causes excluded. What is the diagnosis?", "choices": ["Thrombotic thrombocytopenic purpura", "Disseminated intravascular coagulation", "Immune thrombocytopenic purpura (ITP)", "Aplastic anemia", "Acute leukemia"], "ans": 2, "exp": "Isolated thrombocytopenia (line อื่นปกติ) + mucocutaneous bleeding + exclude สาเหตุอื่น = ITP (autoimmune). รักษาเมื่อเลือดออก/นับต่ำมากด้วย corticosteroid/IVIG.", "id": "set3-63"}, {"topic": "Hematology", "q": "A patient with sepsis has bleeding from venipuncture sites; labs show prolonged PT/aPTT, low fibrinogen, high D-dimer, low platelets, and schistocytes. What is the diagnosis?", "choices": ["Immune thrombocytopenic purpura", "Thrombotic thrombocytopenic purpura", "Hemophilia", "Disseminated intravascular coagulation (DIC)", "Vitamin K deficiency"], "ans": 3, "exp": "Consumptive coagulopathy (PT/aPTT ยาว, fibrinogen ต่ำ, D-dimer สูง, platelet ต่ำ, schistocyte) ในภาวะ sepsis = DIC. รักษาที่สาเหตุ + component (FFP/cryo/platelet) ตามการเลือดออก.", "id": "set3-64"}, {"topic": "Hematology", "q": "A patient has microangiopathic hemolytic anemia, thrombocytopenia, fever, neurologic changes, and renal involvement with very low ADAMTS13. What is the treatment?", "choices": ["Platelet transfusion", "Corticosteroids alone", "Heparin anticoagulation", "Observation only", "Plasma exchange (plasmapheresis)"], "ans": 4, "exp": "TTP (pentad: MAHA + thrombocytopenia + fever + neuro + renal; ADAMTS13 ต่ำ) รักษาด้วย plasma exchange ด่วน ± steroid/rituximab. ห้ามให้ platelet transfusion (ยกเว้นเลือดออกคุกคามชีวิต) เพราะเพิ่ม thrombosis.", "id": "set3-65"}, {"topic": "Hematology", "q": "A boy has recurrent hemarthrosis and deep muscle bleeds; aPTT is prolonged, PT normal, and factor VIII is low. What is the diagnosis?", "choices": ["Hemophilia A", "von Willebrand disease", "Vitamin K deficiency", "Immune thrombocytopenia", "Hemophilia B"], "ans": 0, "exp": "Hemarthrosis/deep bleeding + isolated prolonged aPTT + factor VIII ต่ำ (X-linked) = hemophilia A. Factor IX ต่ำ = hemophilia B. รักษาด้วย factor replacement.", "id": "set3-66"}, {"topic": "Hematology", "q": "A patient has mucosal/skin bleeding, prolonged bleeding time, prolonged aPTT, and low ristocetin cofactor activity. What is the diagnosis?", "choices": ["Hemophilia A", "von Willebrand disease", "Immune thrombocytopenia", "Disseminated intravascular coagulation", "Glanzmann thrombasthenia"], "ans": 1, "exp": "vWD (โรคเลือดออกทางพันธุกรรมที่พบบ่อยสุด): mucocutaneous bleeding + platelet-type + aPTT อาจยาว (vWF พา factor VIII) + ristocetin cofactor ต่ำ. รักษา desmopressin/vWF concentrate.", "id": "set3-67"}, {"topic": "Hematology", "q": "A patient on heparin develops a drop in platelets 5–10 days after starting, with new thrombosis. What is the diagnosis and action?", "choices": ["DIC; give more heparin", "ITP; start corticosteroids", "HIT; stop heparin and start a non-heparin anticoagulant", "TTP; begin plasma exchange", "Normal finding; continue heparin"], "ans": 2, "exp": "HIT (platelet ลด > 50% วันที่ 5–10 + thrombosis, anti-PF4 antibody) — หยุด heparin ทุกชนิดทันที และเปลี่ยนเป็น non-heparin anticoagulant (argatroban/fondaparinux/DOAC). ห้ามให้ platelet/warfarin เดี่ยวช่วงเฉียบพลัน.", "id": "set3-68"}, {"topic": "Hematology", "q": "A patient has prolonged PT with normal aPTT and bleeding; this improves with vitamin K. Which factor is affected earliest?", "choices": ["Factor VIII", "Factor IX", "Fibrinogen", "Factor VII (extrinsic pathway)", "Factor XIII"], "ans": 3, "exp": "Isolated prolonged PT = extrinsic pathway (factor VII มี half-life สั้นสุด จึงเสียก่อนใน vitamin K deficiency/warfarin/liver disease). aPTT = intrinsic (VIII, IX).", "id": "set3-69"}, {"topic": "Hematology", "q": "An elderly patient has fatigue, bone pain, anemia, hypercalcemia, renal failure, and lytic bone lesions. Serum protein electrophoresis shows an M-spike. What is the diagnosis?", "choices": ["Chronic lymphocytic leukemia", "Lymphoma", "Metastatic carcinoma", "MGUS", "Multiple myeloma"], "ans": 4, "exp": "CRAB (hyperCalcemia, Renal failure, Anemia, Bone lytic lesions) + M-protein + plasma cells = multiple myeloma. ตรวจ serum/urine electrophoresis, free light chain, bone marrow. (แนวข้อสอบ NLE2)", "id": "set3-70"}, {"topic": "Hematology", "q": "In multiple myeloma, urine testing classically reveals which protein?", "choices": ["Bence Jones protein (free light chains)", "Albumin", "Myoglobin", "Hemoglobin", "Transferrin"], "ans": 0, "exp": "Multiple myeloma หลั่ง free light chains ที่ตรวจพบในปัสสาวะเป็น Bence Jones protein (urine dipstick มัก negative เพราะจับ albumin เป็นหลัก → ต้อง electrophoresis). (แนวข้อสอบ NLE2)", "id": "set3-71"}, {"topic": "Hematology", "q": "A young adult has painless cervical lymphadenopathy, fever, night sweats, weight loss, and Reed-Sternberg cells on biopsy. What is the diagnosis?", "choices": ["Non-Hodgkin lymphoma", "Hodgkin lymphoma", "Tuberculous lymphadenitis", "Chronic lymphocytic leukemia", "Reactive lymphadenopathy"], "ans": 1, "exp": "Painless lymphadenopathy + B symptoms + Reed-Sternberg cells = Hodgkin lymphoma (แพร่แบบต่อเนื่อง, พยากรณ์ดี). Staging ด้วย PET/CT; รักษา chemo (ABVD) ± RT.", "id": "set3-72"}, {"topic": "Hematology", "q": "A child presents with pallor, bruising, fever, and bone pain; blood shows > 20% lymphoblasts. What is the most likely diagnosis?", "choices": ["Acute myeloid leukemia", "Chronic myeloid leukemia", "Acute lymphoblastic leukemia", "Aplastic anemia", "Immune thrombocytopenia"], "ans": 2, "exp": "เด็ก + bone marrow failure (ซีด/เลือดออก/ติดเชื้อ) + lymphoblasts > 20% = acute lymphoblastic leukemia (ALL, พบบ่อยในเด็ก). AML พบผู้ใหญ่ (Auer rods). เป็นภาวะเร่งด่วน.", "id": "set3-73"}, {"topic": "Hematology", "q": "An adult with fatigue and gum infiltration has a bone marrow with myeloblasts containing Auer rods. What is the diagnosis?", "choices": ["Acute lymphoblastic leukemia", "Chronic myeloid leukemia", "Chronic lymphocytic leukemia", "Acute myeloid leukemia", "Myelofibrosis"], "ans": 3, "exp": "Auer rods ใน myeloblasts = acute myeloid leukemia. APL (AML-M3, t(15;17)) เสี่ยง DIC รักษาด้วย ATRA. เป็นภาวะเร่งด่วน.", "id": "set3-74"}, {"topic": "Hematology", "q": "A middle-aged patient has marked leukocytosis with all granulocyte stages and a Philadelphia chromosome (BCR-ABL). What is the treatment?", "choices": ["Cytotoxic chemotherapy alone", "Splenectomy", "Observation only", "Corticosteroids", "Tyrosine kinase inhibitor (imatinib)"], "ans": 4, "exp": "CML (Philadelphia chromosome, BCR-ABL, leukocytosis + all maturation stages, basophilia, splenomegaly) รักษาด้วย tyrosine kinase inhibitor (imatinib/dasatinib) — เปลี่ยน prognosis อย่างมาก.", "id": "set3-75"}, {"topic": "Hematology", "q": "An elderly patient has lymphocytosis with smudge cells on smear and mature-appearing lymphocytes. What is the diagnosis?", "choices": ["Chronic lymphocytic leukemia", "Acute lymphoblastic leukemia", "Chronic myeloid leukemia", "Hodgkin lymphoma", "Reactive lymphocytosis"], "ans": 0, "exp": "ผู้สูงอายุ + mature lymphocytosis + smudge cells = chronic lymphocytic leukemia (CLL). มักดำเนินโรคช้า; รักษาเมื่อมีอาการ/cytopenia/rapid progression.", "id": "set3-76"}, {"topic": "Hematology", "q": "A patient with polycythemia has elevated hematocrit, low erythropoietin, splenomegaly, and a JAK2 mutation. What is the diagnosis and a key treatment?", "choices": ["Secondary polycythemia; give oxygen", "Polycythemia vera; phlebotomy plus aspirin", "Relative polycythemia; rehydrate", "Dehydration; give IV fluids", "CML; start imatinib"], "ans": 1, "exp": "Polycythemia vera (JAK2 V617F, EPO ต่ำ, splenomegaly) รักษาด้วย phlebotomy (เป้า Hct < 45%) + low-dose aspirin ± hydroxyurea ในรายเสี่ยงสูง. เสี่ยง thrombosis.", "id": "set3-77"}, {"topic": "Hematology", "q": "A patient with cancer on chemotherapy develops fever and an absolute neutrophil count < 500. What is the immediate management?", "choices": ["Oral antibiotics the next day", "G-CSF alone without antibiotics", "Empiric broad-spectrum IV antibiotics within 1 hour", "Antifungal therapy alone", "Observation without treatment"], "ans": 2, "exp": "Febrile neutropenia เป็นภาวะฉุกเฉิน — ให้ empiric broad-spectrum IV antibiotic (คลุม Pseudomonas เช่น piperacillin-tazobactam/cefepime/carbapenem) ภายใน 1 ชม.หลังเจาะ culture.", "id": "set3-78"}, {"topic": "Hematology", "q": "A patient starting chemotherapy for a bulky lymphoma develops hyperkalemia, hyperphosphatemia, hyperuricemia, and hypocalcemia. What is the diagnosis and prevention?", "choices": ["DIC; give heparin", "SIADH; restrict fluids", "Hypercalcemia; give a bisphosphonate", "Tumor lysis syndrome; hydration + allopurinol/rasburicase", "Sepsis; give antibiotics"], "ans": 3, "exp": "Tumor lysis syndrome (high K/PO4/uric acid, low Ca) หลัง chemo tumor ใหญ่. ป้องกัน/รักษาด้วย aggressive hydration + allopurinol (หรือ rasburicase ในรายเสี่ยงสูง) + แก้ electrolyte.", "id": "set3-79"}, {"topic": "Hematology", "q": "A patient with pancytopenia has a hypocellular bone marrow with no abnormal cells or fibrosis. What is the diagnosis?", "choices": ["Acute leukemia", "Myelodysplastic syndrome", "Myelofibrosis", "Megaloblastic anemia", "Aplastic anemia"], "ans": 4, "exp": "Pancytopenia + hypocellular marrow (ไม่มี blast/fibrosis) = aplastic anemia (idiopathic/ยา/ไวรัส/toxin). รักษาด้วย immunosuppression (ATG+ciclosporin) หรือ stem cell transplant; supportive transfusion.", "id": "set3-80"}, {"topic": "Hematology", "q": "An older patient has macrocytic anemia and cytopenias with dysplastic cells and ring sideroblasts in marrow. What is the diagnosis?", "choices": ["Myelodysplastic syndrome", "Aplastic anemia", "Acute myeloid leukemia", "Vitamin B12 deficiency", "Thalassemia"], "ans": 0, "exp": "Cytopenia + dysplasia (± ring sideroblasts) ในผู้สูงอายุ = myelodysplastic syndrome (clonal, เสี่ยงเปลี่ยนเป็น AML). รักษาตามความเสี่ยง (supportive, ESA, hypomethylating agent, transplant).", "id": "set3-81"}, {"topic": "Hematology", "q": "A pregnant woman with unprovoked DVT needs anticoagulation. Which agent is preferred?", "choices": ["Warfarin", "Low-molecular-weight heparin", "A direct oral anticoagulant", "Aspirin", "No treatment"], "ans": 1, "exp": "ในการตั้งครรภ์ใช้ LMWH (ไม่ผ่านรก, ปลอดภัย). Warfarin เป็น teratogen; DOAC หลีกเลี่ยงในการตั้งครรภ์/ให้นม (ข้อมูลจำกัด).", "id": "set3-82"}, {"topic": "Hematology", "q": "A patient with a first provoked DVT (after surgery, now resolved) should receive anticoagulation for how long?", "choices": ["For about 6 weeks", "Indefinitely", "For about 3 months", "For 1 year in all cases", "No treatment needed"], "ans": 2, "exp": "VTE ที่ provoked จากปัจจัยชั่วคราว (ผ่าตัด) รักษา 3 เดือน. Unprovoked หรือ persistent risk (มะเร็ง/thrombophilia) พิจารณา anticoagulation ต่อเนื่องระยะยาว.", "id": "set3-83"}, {"topic": "Hematology", "q": "A patient with active cancer develops VTE. Which anticoagulant class has strong evidence and is commonly preferred?", "choices": ["Warfarin", "Aspirin", "No treatment", "LMWH or a DOAC (edoxaban/apixaban/rivaroxaban)", "An IVC filter alone"], "ans": 3, "exp": "Cancer-associated VTE ใช้ LMWH หรือ DOAC (edoxaban/apixaban/rivaroxaban) ได้ผลดีกว่า warfarin. ระวัง DOAC ใน GI/GU malignancy (เลือดออก) — เลือกตามผู้ป่วย.", "id": "set3-84"}, {"topic": "Hematology", "q": "A patient with recurrent unprovoked thromboses and miscarriages has prolonged aPTT that does not correct with mixing, plus positive anticardiolipin antibodies. What is the diagnosis?", "choices": ["Hemophilia", "von Willebrand disease", "Disseminated intravascular coagulation", "Protein C deficiency", "Antiphospholipid syndrome"], "ans": 4, "exp": "Recurrent thrombosis + pregnancy loss + lupus anticoagulant (aPTT ไม่ correct เมื่อ mix) + anticardiolipin/anti-β2GP1 = antiphospholipid syndrome. รักษาด้วย anticoagulation (warfarin) ระยะยาว.", "id": "set3-85"}, {"topic": "Hematology", "q": "A patient has anemia, jaundice, splenomegaly, and a peripheral smear with sickle-shaped cells during a painful crisis. What is the mainstay of acute management?", "choices": ["Analgesia, hydration, oxygen, and treat the precipitant", "Iron supplementation", "Immediate splenectomy", "Exchange transfusion for all pain", "Iron chelation therapy"], "ans": 0, "exp": "Sickle cell vaso-occlusive crisis: analgesia (มัก opioid), hydration, oxygen, รักษา infection/precipitant. Hydroxyurea ลดความถี่ crisis; exchange transfusion ในภาวะรุนแรง (stroke, acute chest, priapism).", "id": "set3-86"}, {"topic": "Hematology", "q": "A blood smear shows target cells, and Hb electrophoresis shows increased HbA2 in a mildly microcytic patient. What is the diagnosis?", "choices": ["Iron deficiency anemia", "Beta-thalassemia trait", "Alpha-thalassemia", "Sideroblastic anemia", "Lead poisoning"], "ans": 1, "exp": "Microcytosis เล็กน้อย + target cells + HbA2 สูง (> 3.5%) = beta-thalassemia trait. RBC count มักสูง, ferritin ปกติ. ให้คำปรึกษาพันธุกรรม; ห้ามให้ธาตุเหล็กถ้าไม่ขาดจริง.", "id": "set3-87"}, {"topic": "Hematology", "q": "A patient needs urgent warfarin reversal due to major bleeding. What is appropriate?", "choices": ["Vitamin K alone", "Fresh frozen plasma alone, slowly", "Prothrombin complex concentrate (PCC) + IV vitamin K", "Protamine sulfate", "Platelet transfusion"], "ans": 2, "exp": "Major bleeding on warfarin: ให้ 4-factor prothrombin complex concentrate (PCC) + IV vitamin K (FFP ถ้าไม่มี PCC). Protamine ใช้ reverse heparin; idarucizumab reverse dabigatran; andexanet reverse anti-Xa DOAC.", "id": "set3-88"}, {"topic": "Hematology", "q": "A patient has anemia with a low reticulocyte count and normal MCV. What does the low reticulocyte indicate?", "choices": ["An adequate marrow response", "Active ongoing hemolysis", "Recent acute blood loss", "Inadequate marrow production (hypoproliferative)", "Iron overload"], "ans": 3, "exp": "Reticulocyte count ต่ำในภาวะ anemia = marrow ตอบสนองไม่พอ (hypoproliferative: CKD/EPO ต่ำ, ACD, aplastic, marrow infiltration). Reticulocyte สูง = hemolysis/blood loss (marrow ตอบสนองดี).", "id": "set3-89"}, {"topic": "Hematology", "q": "A patient develops warm autoimmune hemolytic anemia. What is the first-line treatment?", "choices": ["Splenectomy", "Rituximab first-line", "Plasma exchange", "Iron supplementation", "Corticosteroids"], "ans": 4, "exp": "Warm AIHA (IgG, spherocytes, direct Coombs positive) รักษา first-line ด้วย corticosteroid; rituximab/splenectomy เป็น second-line. หา secondary cause (lymphoma, SLE, ยา).", "id": "set3-90"}, {"topic": "Hematology", "q": "A patient has cold agglutinin disease with hemolysis worse in cold. Which antibody type mediates this?", "choices": ["IgM (cold antibody)", "IgG (warm antibody)", "IgA antibody", "IgE antibody", "IgD antibody"], "ans": 0, "exp": "Cold agglutinin disease เกิดจาก IgM ที่จับ RBC ในอุณหภูมิเย็น → complement-mediated hemolysis. สัมพันธ์ Mycoplasma/EBV/lymphoma. รักษาหลีกเลี่ยงความเย็น + รักษาสาเหตุ (steroid ได้ผลน้อยกว่า warm).", "id": "set3-91"}, {"topic": "Hematology", "q": "A patient has a normocytic anemia, rouleaux formation, elevated ESR, and back pain. Which malignancy should be suspected?", "choices": ["Acute leukemia", "Multiple myeloma", "Lymphoma", "Polycythemia vera", "Chronic myeloid leukemia"], "ans": 1, "exp": "Rouleaux (จาก M-protein) + ESR สูง + back/bone pain + anemia = multiple myeloma. ตรวจ serum/urine protein electrophoresis + free light chains + skeletal survey/MRI.", "id": "set3-92"}, {"topic": "Hematology", "q": "A patient with splenomegaly and a 'dry tap' on bone marrow aspiration with teardrop cells on smear likely has:", "choices": ["Chronic lymphocytic leukemia", "Immune thrombocytopenia", "Primary myelofibrosis", "Iron deficiency anemia", "Aplastic anemia"], "ans": 2, "exp": "Dry tap (marrow fibrosis) + teardrop (dacrocytes) + splenomegaly (extramedullary hematopoiesis) = primary myelofibrosis (JAK2). รักษา JAK inhibitor (ruxolitinib), supportive, transplant ในรายเหมาะสม.", "id": "set3-93"}, {"topic": "Hematology", "q": "A patient develops petechiae and thrombocytopenia after starting a new drug; counts recover after stopping it. What is the mechanism?", "choices": ["Aplastic anemia", "Disseminated intravascular coagulation", "Thrombotic thrombocytopenic purpura", "Drug-induced immune thrombocytopenia", "Splenic sequestration"], "ans": 3, "exp": "Thrombocytopenia ที่ฟื้นหลังหยุดยา = drug-induced immune thrombocytopenia (เช่น quinine, sulfa, vancomycin, heparin). จัดการโดยหยุดยาต้นเหตุ.", "id": "set3-94"}, {"topic": "Hematology", "q": "A patient with iron deficiency anemia is treated with oral iron. When should the reticulocyte count begin to rise if therapy is effective?", "choices": ["Within a few hours", "Only after 3 months", "It never rises at all", "Only with IV iron", "Within about 5–7 days"], "ans": 4, "exp": "หลังเริ่ม iron ที่ได้ผล reticulocyte จะเริ่มขึ้นภายใน ~5–7 วัน และ Hb ค่อยขึ้นในสัปดาห์ถัดไป; ให้ต่อ 3–6 เดือนเพื่อเติม iron store. ถ้าไม่ตอบสนองให้ทบทวนการวินิจฉัย/การดูดซึม/เลือดออกต่อเนื่อง.", "id": "set3-95"}, {"topic": "Hematology", "q": "Which vaccination timing is critical for a patient scheduled for elective splenectomy?", "choices": ["Encapsulated-organism vaccines ≥ 2 weeks before surgery", "Give the vaccines only after surgery", "No vaccines are needed at all", "Only the influenza vaccine is needed", "Only after a subsequent infection"], "ans": 0, "exp": "ก่อน splenectomy ควรให้วัคซีนต่อ encapsulated organisms (pneumococcus, Hib, meningococcus) อย่างน้อย 2 สัปดาห์ก่อนผ่าตัด เพื่อลดเสี่ยง overwhelming post-splenectomy infection; ให้ prophylactic antibiotic ในบางราย.", "id": "set3-96"}, {"topic": "Hematology", "q": "A patient has a hemoglobin of 6 g/dL with active bleeding and hemodynamic instability. What is the most appropriate transfusion decision?", "choices": ["Withhold transfusion despite instability", "Transfuse packed red cells to restore oxygen delivery", "Give platelets only, not red cells", "Give fresh frozen plasma only", "Give crystalloid fluids only"], "ans": 1, "exp": "Anemia รุนแรงที่มีเลือดออก + hemodynamic instability = ให้ PRC เพื่อเพิ่ม oxygen-carrying capacity (พร้อม resuscitation + หยุดเลือด). เกณฑ์ restrictive (Hb 7) ใช้กับผู้ป่วยคงที่.", "id": "set3-97"}, {"topic": "Hematology", "q": "A patient has isolated prolonged aPTT that fully corrects on a 1:1 mixing study. What does this suggest?", "choices": ["A factor inhibitor is present", "A lupus anticoagulant is present", "A factor deficiency (e.g., VIII, IX, XI)", "Disseminated intravascular coagulation", "A normal laboratory variant"], "ans": 2, "exp": "aPTT ยาวที่ correct เมื่อ mix 1:1 = factor deficiency (เติม factor จาก normal plasma แล้วปกติ). ถ้าไม่ correct = inhibitor (เช่น lupus anticoagulant หรือ factor inhibitor).", "id": "set3-98"}, {"topic": "Hematology", "q": "A patient with beta-thalassemia major on chronic transfusions is at risk of which complication requiring monitoring?", "choices": ["Iron deficiency anemia", "Vitamin B12 excess", "A bleeding tendency", "Iron overload (hemosiderosis) requiring chelation", "Polycythemia"], "ans": 3, "exp": "Thalassemia major ที่รับเลือดเรื้อรังเสี่ยง iron overload (หัวใจ/ตับ/ต่อมไร้ท่อ) — ต้องติดตาม ferritin/MRI T2* และให้ iron chelation (deferasirox/deferoxamine).", "id": "set3-99"}, {"topic": "Hematology", "q": "A patient has anemia and is found to have colon cancer as the bleeding source. Which anemia morphology is most expected?", "choices": ["A macrocytic pattern", "Normocytic with high reticulocytes", "A megaloblastic pattern", "A hemolytic pattern", "Microcytic hypochromic (iron deficiency)"], "ans": 4, "exp": "เลือดออกเรื้อรังจาก colon cancer → chronic blood loss → iron deficiency anemia (microcytic hypochromic). IDA ในผู้ใหญ่ต้องหาสาเหตุ GI เสมอ.", "id": "set3-100"}]}, {"id": "set4", "title": "ชุดที่ 4 — Infectious Disease + Rheumatology", "questions": [{"topic": "Infectious disease", "q": "A patient with suspected sepsis is being managed. According to current bundles, which should be done first alongside cultures?", "choices": ["Blood cultures then early antibiotics and fluids", "Delay all antibiotics until cultures have resulted", "Give only antipyretics and reassess later", "Start vasopressors before any fluid resuscitation", "Give corticosteroids to every septic patient"], "ans": 0, "exp": "Sepsis: เจาะ hemoculture ก่อน แล้วให้ empiric broad-spectrum antibiotic เร็ว (ภายใน 1 ชม.ใน septic shock) + IV crystalloid + วัด lactate + source control. SSC 2026 เน้น balanced crystalloid และประเมิน fluid responsiveness.", "id": "set4-1"}, {"topic": "Infectious disease", "q": "A febrile patient in septic shock remains hypotensive after adequate fluid resuscitation. What is the first-line vasopressor?", "choices": ["Dopamine", "Norepinephrine", "Epinephrine", "Phenylephrine", "Vasopressin alone"], "ans": 1, "exp": "Septic shock ที่ยัง hypotensive หลัง fluid ให้ norepinephrine เป็น first-line vasopressor (เป้า MAP ≥ 65). เพิ่ม vasopressin/epinephrine เป็นตัวที่สอง; SSC 2026 อนุญาตเริ่ม norepinephrine ทาง peripheral ได้.", "id": "set4-2"}, {"topic": "Infectious disease", "q": "A patient with fever, headache, neck stiffness, and photophobia has CSF with high neutrophils, high protein, and low glucose. What is the diagnosis and immediate treatment?", "choices": ["Viral meningitis; supportive care only", "Tuberculous meningitis; start anti-TB drugs", "Bacterial meningitis; ceftriaxone + vancomycin", "Fungal meningitis; give amphotericin B", "Migraine headache; give simple analgesia"], "ans": 2, "exp": "CSF neutrophil สูง + protein สูง + glucose ต่ำ = bacterial meningitis. ให้ empiric ceftriaxone + vancomycin (± ampicillin ถ้าเสี่ยง Listeria) + dexamethasone ก่อน/พร้อม ATB. อย่ารอผลถ้าต้องเลื่อน CT.", "id": "set4-3"}, {"topic": "Infectious disease", "q": "When should a CT head be performed before lumbar puncture in suspected meningitis?", "choices": ["In every case before a lumbar puncture", "It is never needed before a lumbar puncture", "Only when the patient is febrile", "Focal deficit, papilledema, or reduced GCS", "Only in pediatric patients"], "ans": 3, "exp": "ทำ CT ก่อน LP เมื่อมี focal deficit, papilledema, immunocompromised, seizure ใหม่, หรือ GCS ลด (เสี่ยง herniation). ในกรณีนี้อย่า delay antibiotic — ให้ ATB + dexamethasone ก่อนแล้วค่อย LP.", "id": "set4-4"}, {"topic": "Infectious disease", "q": "An HIV patient with CD4 count 120 should receive prophylaxis against which opportunistic infection?", "choices": ["Cryptococcus neoformans", "Mycobacterium avium complex", "Cytomegalovirus", "Toxoplasma gondii only", "Pneumocystis jirovecii (co-trimoxazole)"], "ans": 4, "exp": "CD4 < 200 → ให้ co-trimoxazole prophylaxis กัน PCP (และ toxoplasma เมื่อ < 100 + IgG positive). CD4 < 50 พิจารณา MAC prophylaxis (แนวทางปัจจุบันเน้นเริ่ม ART เร็วมากกว่า).", "id": "set4-5"}, {"topic": "Infectious disease", "q": "What is the recommended first-line antiretroviral regimen for most treatment-naive adults with HIV?", "choices": ["A dolutegravir-based regimen", "A zidovudine-based regimen", "Efavirenz plus two NRTIs only", "Protease inhibitor monotherapy", "No treatment until CD4 < 200"], "ans": 0, "exp": "First-line ART = dolutegravir (INSTI)-based เช่น TDF/3TC/DTG; เริ่มเร็ว (rapid start) โดยไม่รอ CD4. แนวคิด U=U. ระวัง DTG กับ antacid/Ca/Fe/Zn (เว้นระยะ).", "id": "set4-6"}, {"topic": "Infectious disease", "q": "A patient with HIV (CD4 50) has headache, fever, and a positive serum cryptococcal antigen with high opening pressure on LP. What is the treatment?", "choices": ["Fluconazole monotherapy alone", "Amphotericin B + flucytosine, then fluconazole", "Ceftriaxone as for bacterial meningitis", "Acyclovir as for viral meningitis", "Empiric anti-tuberculous therapy"], "ans": 1, "exp": "Cryptococcal meningitis ใน HIV: induction ด้วย amphotericin B + flucytosine แล้ว consolidation/maintenance fluconazole + จัดการ raised intracranial pressure (serial LP). เริ่ม ART หลังไปสักระยะเพื่อลด IRIS.", "id": "set4-7"}, {"topic": "Infectious disease", "q": "A returning traveler from an endemic area has cyclical fever, chills, and anemia; thick and thin blood films are ordered. What is the purpose of each film?", "choices": ["Both films give identical information", "The thick film is used only to speciate", "Thick film to detect, thin film to speciate", "The thin film is used only for detection", "Neither film is clinically useful"], "ans": 2, "exp": "Malaria: thick film (sensitive, ตรวจหาเชื้อ) + thin film (speciate + quantify parasitemia). P. falciparum รุนแรง (cerebral, ไตวาย, hypoglycemia) → artesunate IV. (แนวข้อสอบ NLE2)", "id": "set4-8"}, {"topic": "Infectious disease", "q": "A patient has severe P. falciparum malaria with impaired consciousness and high parasitemia. What is the treatment of choice?", "choices": ["Oral chloroquine", "Oral doxycycline", "Primaquine alone", "IV artesunate", "Supportive care only"], "ans": 3, "exp": "Severe falciparum malaria รักษาด้วย IV artesunate (ดีกว่า quinine) + supportive; ตามด้วย full oral ACT course. Primaquine ใช้กำจัด hypnozoite ใน vivax/ovale (ตรวจ G6PD ก่อน).", "id": "set4-9"}, {"topic": "Infectious disease", "q": "A rice-farmer presents with fever, severe calf myalgia, conjunctival suffusion, jaundice, and acute kidney injury after wading in floodwater. What is the diagnosis?", "choices": ["Dengue fever", "Scrub typhus", "Melioidosis", "Malaria", "Leptospirosis"], "ans": 4, "exp": "ประวัติลุยน้ำ/นา + ไข้ + ปวดน่อง + conjunctival suffusion + ตัวเหลือง + ไตวาย (Weil disease) = leptospirosis. รักษาด้วย penicillin/doxycycline/ceftriaxone; ระวัง Jarisch-Herxheimer.", "id": "set4-10"}, {"topic": "Infectious disease", "q": "A febrile patient from a rural area has an eschar (painless ulcer with black crust) and regional lymphadenopathy. What is the diagnosis and treatment?", "choices": ["Scrub typhus; give doxycycline", "Dengue; supportive care", "Leptospirosis; give penicillin", "Malaria; give artesunate", "Typhoid; give ceftriaxone"], "ans": 0, "exp": "ไข้ + eschar (แผลบุหรี่จี้) + lymphadenopathy = scrub typhus (Orientia tsutsugamushi). ตอบสนองเร็วต่อ doxycycline (azithromycin เป็นทางเลือก). Eschar เป็น clue สำคัญ.", "id": "set4-11"}, {"topic": "Infectious disease", "q": "A diabetic farmer from northeastern Thailand has community-acquired sepsis with multiple abscesses; culture grows a bipolar 'safety pin' gram-negative bacillus. What is the diagnosis?", "choices": ["Disseminated tuberculosis", "Melioidosis (Burkholderia pseudomallei)", "Leptospirosis", "Typhoid fever", "Systemic anthrax"], "ans": 1, "exp": "Melioidosis (Burkholderia pseudomallei, ดิน/น้ำอีสาน, เบาหวานเสี่ยง): sepsis + abscess หลายอวัยวะ, bipolar staining. รักษา intensive ด้วย ceftazidime/meropenem แล้ว eradication ด้วย co-trimoxazole นาน.", "id": "set4-12"}, {"topic": "Infectious disease", "q": "A patient has high fever for 5 days, retro-orbital pain, myalgia, and a positive tourniquet test with low WBC and platelets. During defervescence, what is the key concern?", "choices": ["Secondary bacterial superinfection", "A guaranteed uneventful recovery", "Plasma leakage, shock, and bleeding", "New-onset hyperglycemia", "An obstructing renal stone"], "ans": 2, "exp": "Dengue: ช่วงไข้ลด (defervescence, วันที่ 4–6) เป็น critical phase — เสี่ยง plasma leakage/shock และเลือดออก. เฝ้าระวัง warning signs, ให้ isotonic fluid ระวัง over/under, ห้าม NSAID/ASA.", "id": "set4-13"}, {"topic": "Infectious disease", "q": "Which are recognized dengue warning signs indicating risk of progression to severe disease?", "choices": ["An isolated skin rash only", "A high fever on its own", "A headache on its own", "Warning signs of severe dengue", "Muscle aches on their own"], "ans": 3, "exp": "Dengue warning signs (WHO): ปวดท้อง/กดเจ็บ, อาเจียนต่อเนื่อง, มีน้ำรั่ว, เลือดออกเยื่อบุ, ซึม/กระสับกระส่าย, ตับโต > 2 ซม., Hct เพิ่ม + platelet ลดเร็ว → ต้อง admit/เฝ้าใกล้ชิด.", "id": "set4-14"}, {"topic": "Infectious disease", "q": "A patient has sustained high fever, relative bradycardia, abdominal pain, and rose spots after travel; blood culture grows Salmonella Typhi. What is the treatment?", "choices": ["Metronidazole", "Vancomycin", "Doxycycline", "Penicillin", "Ceftriaxone or azithromycin"], "ans": 4, "exp": "Enteric (typhoid) fever: ไข้สูงต่อเนื่อง + relative bradycardia + rose spots; hemoculture ยืนยัน. รักษาด้วย ceftriaxone หรือ azithromycin (ระวัง fluoroquinolone resistance).", "id": "set4-15"}, {"topic": "Infectious disease", "q": "A young adult has fever, severe joint pain in the hands/wrists, maculopapular rash after mosquito exposure; the arthralgia is debilitating and prolonged. What is the most likely diagnosis?", "choices": ["Chikungunya", "Dengue fever", "Malaria", "Zika virus", "Typhoid fever"], "ans": 0, "exp": "ไข้ + ปวดข้อรุนแรง (โดยเฉพาะข้อเล็ก) เด่นและยืดเยื้อ + ผื่น หลังยุงกัด = chikungunya. Dengue ปวดกล้ามเนื้อ/กระบอกตาเด่นกว่า; Zika มักอาการน้อย + ผื่น/เยื่อบุตาแดง. (แนวข้อสอบ NLE2)", "id": "set4-16"}, {"topic": "Infectious disease", "q": "A patient develops a seizure and CT shows multiple small calcified brain lesions without edema; he is from a pork-consuming rural area. What is the etiology?", "choices": ["Cerebral toxoplasmosis", "Neurocysticercosis (Taenia solium)", "Primary CNS lymphoma", "A tuberculous granuloma", "A cerebral metastasis"], "ans": 1, "exp": "Calcified brain lesions หลายจุด + seizure ในพื้นที่ระบาด/กินหมูดิบ = neurocysticercosis (Taenia solium). รักษาตาม stage: albendazole/praziquantel + steroid + antiseizure (ระวังในระยะ active/มี edema). (แนวข้อสอบ NLE2)", "id": "set4-17"}, {"topic": "Infectious disease", "q": "An HIV patient (CD4 80) has ring-enhancing brain lesions and positive Toxoplasma serology. What is the initial treatment?", "choices": ["Acyclovir", "Amphotericin B", "Pyrimethamine plus sulfadiazine", "Ceftriaxone", "Anti-tuberculous therapy"], "ans": 2, "exp": "Ring-enhancing lesions ใน HIV (CD4 < 100) + Toxoplasma IgG positive → รักษา empiric toxoplasmic encephalitis ด้วย pyrimethamine + sulfadiazine + leucovorin. ถ้าไม่ตอบสนอง คิดถึง CNS lymphoma (biopsy).", "id": "set4-18"}, {"topic": "Infectious disease", "q": "A patient has cellulitis with rapidly spreading erythema, pain out of proportion, bullae, crepitus, and systemic toxicity. What is the diagnosis and treatment?", "choices": ["Simple cellulitis; give oral antibiotics", "Erysipelas; give penicillin", "A simple abscess; drainage only", "Necrotizing fasciitis; urgent debridement", "Contact dermatitis; give a steroid"], "ans": 3, "exp": "Necrotizing fasciitis: ปวดเกินกว่าที่เห็น + bullae/crepitus + systemic toxicity เป็นภาวะฉุกเฉิน — surgical debridement ด่วน + broad-spectrum antibiotic (คลุม anaerobe/GAS) + clindamycin (ลด toxin). LRINEC score ช่วยประเมิน.", "id": "set4-19"}, {"topic": "Infectious disease", "q": "A patient has a localized skin abscess with fluctuance. What is the primary treatment?", "choices": ["Antibiotics alone without drainage", "A warm compress only", "A topical corticosteroid", "An antifungal agent", "Incision and drainage (± antibiotics)"], "ans": 4, "exp": "Skin abscess รักษาหลักด้วย incision and drainage; ให้ antibiotic เพิ่มเมื่อมี cellulitis รอบข้าง, systemic sign, immunocompromised, หรือหลายตำแหน่ง (คลุม MRSA ตามความเสี่ยง).", "id": "set4-20"}, {"topic": "Infectious disease", "q": "A patient with fever, new murmur, and Janeway lesions has infective endocarditis. Which empiric consideration is important for IV drug users?", "choices": ["Cover Staphylococcus aureus", "Cover only viridans streptococci", "Cover only enterococci", "No antibiotics are required", "Cover only fungal organisms"], "ans": 0, "exp": "IV drug users มัก right-sided endocarditis จาก Staphylococcus aureus (tricuspid, septic pulmonary emboli). Empiric ต้องคลุม S. aureus (รวม MRSA). Viridans strep พบใน native valve subacute; enterococci ใน GI/GU.", "id": "set4-21"}, {"topic": "Infectious disease", "q": "A patient with prolonged fever > 3 weeks and no diagnosis after initial work-up has FUO. Which categories should be systematically considered?", "choices": ["Only underlying malignancy", "Infection, malignancy, or autoimmune disease", "Only an underlying infection", "Only drug-induced fever", "A purely psychogenic cause"], "ans": 1, "exp": "FUO (> 38.3°C, > 3 สัปดาห์, หาไม่พบหลังตรวจเบื้องต้น) — พิจารณา 4 กลุ่ม: infection (TB, abscess, IE), malignancy (lymphoma), autoimmune/CTD (SLE, adult Still, GCA), และ miscellaneous (drug fever, DVT). ประวัติ+ตรวจซ้ำสำคัญ.", "id": "set4-22"}, {"topic": "Infectious disease", "q": "A patient steps on a nail and later develops lockjaw, risus sardonicus, and muscle spasms. What is the diagnosis?", "choices": ["Rabies", "Botulism", "Tetanus", "Meningitis", "Strychnine poisoning"], "ans": 2, "exp": "Puncture wound + trismus (lockjaw) + risus sardonicus + spasm = tetanus (Clostridium tetani, tetanospasmin). รักษา wound care + metronidazole + tetanus immunoglobulin + ควบคุม spasm (benzodiazepine) + vaccine.", "id": "set4-23"}, {"topic": "Infectious disease", "q": "A patient bitten by a stray dog with an unknown vaccination status. What is the appropriate post-exposure management for rabies (category III)?", "choices": ["Wound care alone with no vaccine", "Antibiotics alone without vaccine", "Observe the patient without action", "Wound wash + rabies vaccine + immunoglobulin", "Vaccine only if symptoms appear"], "ans": 3, "exp": "Rabies category III (bite/แผลเลือดออก/เยื่อบุ): ล้างแผลด้วยน้ำสบู่ทันที + rabies vaccine + rabies immunoglobulin (infiltrate รอบแผล) + พิจารณา tetanus/antibiotic. Rabies เมื่อมีอาการแล้วเสียชีวิตเกือบ 100%.", "id": "set4-24"}, {"topic": "Infectious disease", "q": "A young sexually active woman has dysuria, purulent cervical discharge; NAAT is positive for Neisseria gonorrhoeae. What is recommended treatment (also covering common co-infection)?", "choices": ["Penicillin", "Metronidazole", "Ciprofloxacin alone", "Acyclovir", "Ceftriaxone plus doxycycline/azithromycin"], "ans": 4, "exp": "Gonorrhea รักษาด้วย ceftriaxone IM + คลุม Chlamydia (doxycycline หรือ azithromycin) เพราะ co-infection บ่อย. รักษาคู่นอน + คัดกรอง STI อื่น (HIV/syphilis).", "id": "set4-25"}, {"topic": "Infectious disease", "q": "A patient has a painless genital ulcer (chancre) with a positive dark-field/serology. What is the treatment for primary syphilis?", "choices": ["Benzathine penicillin G", "Ceftriaxone", "Doxycycline for everyone", "Routine azithromycin", "Metronidazole"], "ans": 0, "exp": "Primary syphilis (painless chancre, Treponema pallidum): รักษาด้วย benzathine penicillin G IM single dose; doxycycline เป็นทางเลือกในผู้แพ้ penicillin (ยกเว้นตั้งครรภ์/neurosyphilis ต้อง desensitize).", "id": "set4-26"}, {"topic": "Infectious disease", "q": "A patient with genital vesicles and painful ulcers on an erythematous base has recurrent episodes; Tzanck smear shows multinucleated giant cells. What is the diagnosis and treatment?", "choices": ["Syphilis; give penicillin", "Genital herpes (HSV); give acyclovir", "Chancroid; give azithromycin", "Granuloma inguinale; give doxycycline", "LGV; give doxycycline"], "ans": 1, "exp": "Painful grouped vesicles/ulcers + recurrence + multinucleated giant cells = genital herpes (HSV). รักษาด้วย acyclovir/valacyclovir (episodic หรือ suppressive). Syphilis ให้ ulcer ไม่เจ็บ.", "id": "set4-27"}, {"topic": "Infectious disease", "q": "A patient develops watery diarrhea and vomiting after a buffet; symptoms began within hours and resolve within a day. What is the most likely mechanism?", "choices": ["An invasive bacterial infection", "Acute viral hepatitis", "A preformed bacterial toxin", "A parasitic infection", "C. difficile colitis"], "ans": 2, "exp": "อาการเร็ว (1–6 ชม.) หลังกินอาหาร + อาเจียนเด่น + หายไว = preformed toxin (S. aureus, B. cereus). รักษาแบบ supportive (rehydration); ไม่ต้อง antibiotic.", "id": "set4-28"}, {"topic": "Infectious disease", "q": "A patient develops descending flaccid paralysis, diplopia, dysphagia, and dry mouth after eating home-canned food. What is the diagnosis?", "choices": ["Guillain-Barré syndrome", "Myasthenia gravis", "Tetanus", "Botulism", "Acute stroke"], "ans": 3, "exp": "Descending symmetric flaccid paralysis + bulbar/autonomic (diplopia, dry mouth) หลังอาหารกระป๋อง/หมักเอง = botulism (Clostridium botulinum toxin). รักษาด้วย antitoxin + supportive/ventilation.", "id": "set4-29"}, {"topic": "Infectious disease", "q": "A patient with prosthetic material or endocarditis risk needs antibiotic prophylaxis before which procedure (per current guidelines)?", "choices": ["All dental cleanings for everyone", "Before every colonoscopy", "Before every catheterization", "It is never indicated", "High-risk cardiac lesions before dental work"], "ans": 4, "exp": "Antibiotic prophylaxis ก่อนหัตถการทันตกรรม (ที่ manipulate gingiva/mucosa) ให้เฉพาะกลุ่มเสี่ยงสูง (prosthetic valve, ประวัติ IE, congenital heart บางชนิด, transplant valvulopathy) เท่านั้น.", "id": "set4-30"}, {"topic": "Infectious disease", "q": "A patient with cough > 2 weeks, weight loss, and night sweats has a positive sputum Xpert MTB/RIF showing rifampicin resistance. What does this indicate?", "choices": ["Rifampicin-resistant (MDR) tuberculosis", "Ordinary drug-susceptible TB", "Latent TB infection", "Non-tuberculous mycobacteria", "Laboratory contamination"], "ans": 0, "exp": "Xpert MTB/RIF ที่พบ rifampicin resistance บ่งชี้ RR/MDR-TB — ต้องส่ง DST เพิ่มและเริ่มสูตร second-line (เช่น BPaLM 6 เดือน: bedaquiline, pretomanid, linezolid, moxifloxacin) ตามแนวทาง.", "id": "set4-31"}, {"topic": "Infectious disease", "q": "A patient starting anti-TB therapy develops tingling in the feet. Which drug is responsible and how is it prevented?", "choices": ["Rifampicin; give a steroid", "Isoniazid; give pyridoxine (vitamin B6)", "Ethambutol; give vitamin A", "Pyrazinamide; give allopurinol", "Streptomycin; give magnesium"], "ans": 1, "exp": "Isoniazid ทำให้ peripheral neuropathy จากการรบกวน pyridoxine metabolism — ป้องกัน/รักษาด้วย pyridoxine (vitamin B6) โดยเฉพาะในกลุ่มเสี่ยง (DM, สุรา, ตั้งครรภ์, CKD, HIV).", "id": "set4-32"}, {"topic": "Infectious disease", "q": "A close contact of an active pulmonary TB case has a positive tuberculin skin test but a normal CXR and no symptoms. What is the management?", "choices": ["Give full four-drug TB treatment", "Give no treatment at all", "Treat latent TB infection", "Repeat the test in five years", "Give antibiotics for five days"], "ans": 2, "exp": "Latent TB infection (positive test, ไม่มีอาการ, CXR ปกติ) — หลังตัด active disease ให้ latent TB treatment (isoniazid 6–9 เดือน หรือ 3HP rifapentine+isoniazid รายสัปดาห์ 3 เดือน) ลดการกลายเป็น active.", "id": "set4-33"}, {"topic": "Infectious disease", "q": "A hospitalized patient develops a central-line-associated bloodstream infection. Besides antibiotics, what is a key management step?", "choices": ["Increase intravenous fluids only", "Add systemic corticosteroids", "Give antipyretics only", "Source control: remove the infected catheter", "Keep the line and continue it"], "ans": 3, "exp": "CLABSI: source control สำคัญ — remove infected catheter (โดยเฉพาะ S. aureus/Candida/Pseudomonas) + antibiotic ตามเชื้อ. Source control เป็นหลักการสำคัญของการรักษาการติดเชื้อทุกชนิด.", "id": "set4-34"}, {"topic": "Infectious disease", "q": "A young adult has sore throat, posterior cervical lymphadenopathy, splenomegaly, and atypical lymphocytes; a heterophile (Monospot) test is positive. What is the diagnosis?", "choices": ["Streptococcal pharyngitis", "Diphtheria", "Acute HIV seroconversion", "CMV infection only", "Infectious mononucleosis (EBV)"], "ans": 4, "exp": "Sore throat + posterior cervical nodes + splenomegaly + atypical lymphocytes + Monospot positive = infectious mononucleosis (EBV). หลีกเลี่ยง contact sport (เสี่ยง splenic rupture); เลี่ยง amoxicillin (ผื่น).", "id": "set4-35"}, {"topic": "Infectious disease", "q": "A patient with animal (dog/cat) bite wound needs antibiotic prophylaxis. Which agent covers Pasteurella and oral flora?", "choices": ["Amoxicillin-clavulanate", "Azithromycin", "Ciprofloxacin alone", "Metronidazole alone", "Vancomycin"], "ans": 0, "exp": "Bite wounds (Pasteurella multocida, anaerobe, oral flora) → amoxicillin-clavulanate เป็น first-line prophylaxis/treatment + wound care + ประเมิน tetanus/rabies.", "id": "set4-36"}, {"topic": "Infectious disease", "q": "A patient presents with fever and a petechial/purpuric rash that is rapidly spreading with hypotension. Which diagnosis must be treated immediately?", "choices": ["A benign viral exanthem", "Meningococcemia (N. meningitidis)", "Dengue fever only", "Contact dermatitis", "A simple drug rash"], "ans": 1, "exp": "ไข้ + petechial/purpuric rash แพร่เร็ว + hypotension = meningococcemia (fulminant) — ให้ ceftriaxone ทันที + resuscitation; แจ้ง infection control + prophylaxis ผู้สัมผัสใกล้ชิด.", "id": "set4-37"}, {"topic": "Infectious disease", "q": "A patient with community-acquired pneumonia is found to have Legionella. Which clue and treatment are relevant?", "choices": ["Rusty sputum; give penicillin", "Currant-jelly sputum; give ceftriaxone", "Bradycardia, hyponatremia; give a macrolide", "No specific clinical clue exists", "Treat with metronidazole"], "ans": 2, "exp": "Legionella: pneumonia + hyponatremia + diarrhea + relative bradycardia + สัมผัสน้ำ/แอร์; ตรวจ urine antigen. รักษาด้วย macrolide (azithromycin) หรือ respiratory fluoroquinolone.", "id": "set4-38"}, {"topic": "Infectious disease", "q": "A pregnant woman is found to have asymptomatic bacteriuria. Why should it be treated?", "choices": ["It is never treated in pregnancy", "Only to relieve urinary symptoms", "To prevent gestational diabetes", "To prevent pyelonephritis and preterm birth", "There is no clear reason to treat"], "ans": 3, "exp": "Asymptomatic bacteriuria ในหญิงตั้งครรภ์ต้องรักษา (ตามผล culture, ยาที่ปลอดภัย) เพื่อลด pyelonephritis และผลลัพธ์การตั้งครรภ์ไม่ดี (preterm/low birth weight).", "id": "set4-39"}, {"topic": "Infectious disease", "q": "A patient with fever and right upper quadrant pain has a single large liver abscess; aspiration grows Klebsiella pneumoniae. What is appropriate management?", "choices": ["Observation without treatment", "Metronidazole alone in all cases", "Surgical resection only", "An antifungal agent", "Antibiotics plus percutaneous drainage"], "ans": 4, "exp": "Pyogenic liver abscess (มัก Klebsiella/enteric, biliary source) รักษาด้วย antibiotics + percutaneous drainage (โดยเฉพาะ abscess ใหญ่). ต่างจาก amoebic ที่ตอบสนอง metronidazole โดยมัก drainage เมื่อจำเป็น.", "id": "set4-40"}, {"topic": "Infectious disease", "q": "A patient develops an IRIS reaction after starting ART. What is IRIS?", "choices": ["Worsening infection as immunity recovers", "A drug allergy to antiretrovirals", "Treatment failure of the ART regimen", "A brand-new HIV infection", "A completely normal response"], "ans": 0, "exp": "IRIS = อาการของการติดเชื้อฉวยโอกาสแย่ลง/ปรากฏชัดหลังเริ่ม ART เพราะภูมิฟื้น (พบใน TB, cryptococcus). จัดการรักษาการติดเชื้อต่อ + ต้าน inflammation (steroid ในบางราย); มัก ไม่หยุด ART.", "id": "set4-41"}, {"topic": "Infectious disease", "q": "A healthcare worker sustains a needlestick from an HIV-positive source. What is the appropriate action?", "choices": ["Observe the worker without action", "Start HIV post-exposure prophylaxis now", "Give a hepatitis vaccine only", "Give immunoglobulin alone", "No action is needed at all"], "ans": 1, "exp": "Needlestick จากแหล่ง HIV+: เริ่ม PEP (3-drug ART) เร็วที่สุด (ภายในชั่วโมง-72 ชม.) นาน 28 วัน + baseline/follow-up testing (HIV/HBV/HCV) + ประเมิน HBV prophylaxis.", "id": "set4-42"}, {"topic": "Infectious disease", "q": "A patient with severe sepsis of unclear source. Which principle is essential besides antibiotics and fluids?", "choices": ["Deliberately delay all imaging", "Avoid taking any cultures", "Source control of the infection", "Give corticosteroids to everyone", "Give antipyretics only"], "ans": 2, "exp": "Source control (ระบายหนอง, เอาอุปกรณ์ติดเชื้อออก, แก้ obstruction เช่น obstructed biliary/urinary) เป็นหัวใจของการรักษา sepsis ควบคู่ antibiotic + resuscitation; ถ้าไม่ควบคุมแหล่ง ยาจะไม่ได้ผล.", "id": "set4-43"}, {"topic": "Infectious disease", "q": "A patient has recurrent oral thrush and esophageal candidiasis without another cause. What underlying condition should be tested for?", "choices": ["Diabetes mellitus only", "Iron deficiency anemia", "Hypothyroidism", "HIV infection", "Vitamin C deficiency"], "ans": 3, "exp": "Esophageal candidiasis / recurrent thrush เป็น AIDS-defining/immunocompromise clue — ควรตรวจ HIV (และประเมิน DM, corticosteroid, ยากดภูมิ). รักษา candidiasis ด้วย fluconazole.", "id": "set4-44"}, {"topic": "Infectious disease", "q": "A patient develops fever and a diffuse erythematous rash with desquamation, hypotension, and multiorgan involvement associated with tampon use. What is the diagnosis?", "choices": ["Anaphylactic reaction", "Dengue fever", "Scarlet fever", "Kawasaki disease", "Staphylococcal toxic shock syndrome"], "ans": 4, "exp": "Toxic shock syndrome (S. aureus superantigen TSST-1): ไข้ + diffuse rash + desquamation (ฝ่ามือ/เท้า) + hypotension + multiorgan + สัมพันธ์ tampon/wound. รักษา remove source + fluids + antibiotic (clindamycin ลด toxin + anti-staph).", "id": "set4-45"}, {"topic": "Infectious disease", "q": "A patient from an area with poor sanitation has acute watery 'rice-water' stools with rapid dehydration. What is the priority treatment?", "choices": ["Aggressive fluid/electrolyte replacement", "Give antibiotics before rehydration", "Give an antimotility agent", "Observation without rehydration", "An antifungal agent"], "ans": 0, "exp": "Cholera (rice-water stool, dehydration เร็ว): หัวใจคือ rapid fluid/electrolyte replacement (ORS หรือ IV) ป้องกันช็อก; antibiotic (doxycycline/azithromycin) ลดระยะเวลา/ปริมาณอุจจาระเป็นตัวเสริม.", "id": "set4-46"}, {"topic": "Infectious disease", "q": "A patient with HIV has CD4 30 and painless progressive visual loss; funduscopy shows hemorrhages and exudates ('pizza pie'). What is the diagnosis?", "choices": ["Toxoplasma retinitis", "CMV retinitis", "Cryptococcal eye disease", "HSV keratitis", "Diabetic retinopathy"], "ans": 1, "exp": "CD4 < 50 + retinitis (hemorrhage + exudate, pizza-pie) = CMV retinitis. รักษาด้วย ganciclovir/valganciclovir + เริ่ม/optimize ART. ต้องรีบเพื่อรักษาการมองเห็น.", "id": "set4-47"}, {"topic": "Infectious disease", "q": "Which patient should receive influenza antiviral (oseltamivir) treatment even beyond 48 hours ideally as early as possible?", "choices": ["A healthy adult with mild symptoms", "Anyone who has a common cold", "A hospitalized or high-risk patient", "Only pediatric patients", "No one at all"], "ans": 2, "exp": "Oseltamivir ให้ประโยชน์สูงสุดภายใน 48 ชม. แต่ยังแนะนำในผู้ป่วยที่ admit/รุนแรง/กลุ่มเสี่ยงสูง (ตั้งครรภ์, โรคเรื้อรัง, สูงอายุ) แม้เกิน 48 ชม. Healthy mild case มักไม่จำเป็น.", "id": "set4-48"}, {"topic": "Infectious disease", "q": "A patient with pyelonephritis and an obstructing ureteric stone with pus remains septic despite antibiotics. What is the essential intervention?", "choices": ["Increase the antibiotic dose only", "Give more IV fluids only", "Observation without intervention", "Urgent urinary decompression + antibiotics", "An antifungal agent"], "ans": 3, "exp": "Obstructed infected urinary system (pyonephrosis) เป็น urologic emergency — ต้อง decompress ด่วน (ureteric stent หรือ percutaneous nephrostomy) ควบคู่ antibiotic. Antibiotic เดี่ยวไม่พอถ้าไม่ระบายแหล่งติดเชื้อ.", "id": "set4-49"}, {"topic": "Infectious disease", "q": "A patient has a chronic non-healing ulcer with 'sulfur granules' draining from a jaw/neck sinus tract. What is the diagnosis?", "choices": ["Tuberculosis", "Nocardiosis", "Melioidosis", "Sporotrichosis", "Actinomycosis"], "ans": 4, "exp": "Sulfur granules + chronic draining sinus (มัก cervicofacial หลังทำฟัน) = actinomycosis (Actinomyces israelii). รักษาด้วย penicillin ขนาดสูงระยะยาว ± surgical drainage.", "id": "set4-50"}, {"topic": "Infectious disease", "q": "A patient with fever, headache, and altered mental status has CSF lymphocytic pleocytosis with normal glucose; MRI shows temporal lobe involvement. What is the likely diagnosis and treatment?", "choices": ["Herpes simplex encephalitis; give IV acyclovir", "Bacterial meningitis; give ceftriaxone", "Tuberculous meningitis; start anti-TB drugs", "Cryptococcal meningitis; give amphotericin B", "Migraine headache; give analgesia"], "ans": 0, "exp": "Encephalitis + temporal lobe involvement + lymphocytic CSF (glucose ปกติ) = HSV encephalitis. เริ่ม IV acyclovir ทันที (อย่ารอผล PCR) เพราะการรักษาเร็วลดการตาย/พิการ.", "id": "set4-51"}, {"topic": "Infectious disease", "q": "A patient traveling develops profuse watery diarrhea without blood or high fever ('traveler's diarrhea'). What is the most common cause and management?", "choices": ["Entamoeba histolytica; give metronidazole", "ETEC; oral rehydration ± antibiotic", "C. difficile colitis; give vancomycin", "Rotavirus; prevent with vaccine", "Cholera; give IV fluids only"], "ans": 1, "exp": "Traveler's diarrhea ส่วนใหญ่จาก enterotoxigenic E. coli (ETEC). หลักคือ oral rehydration; antibiotic (azithromycin/fluoroquinolone) เมื่อปานกลาง-รุนแรง; loperamide เสริมได้ถ้าไม่มีเลือด/ไข้สูง.", "id": "set4-52"}, {"topic": "Rheumatology", "q": "A young woman has a malar rash, photosensitivity, oral ulcers, arthritis, and proteinuria. Which antibodies are most specific for the diagnosis?", "choices": ["ANA alone", "Rheumatoid factor", "Anti-dsDNA and anti-Smith", "Anti-CCP antibody", "Anti-histone antibody"], "ans": 2, "exp": "อาการหลายระบบ = SLE. ANA sensitive (คัดกรอง) แต่ anti-dsDNA และ anti-Smith จำเพาะสุด. Anti-dsDNA สัมพันธ์ lupus nephritis/activity; complement ต่ำเวลากำเริบ.", "id": "set4-53"}, {"topic": "Rheumatology", "q": "Which medication should essentially all SLE patients receive unless contraindicated?", "choices": ["Cyclophosphamide", "Methotrexate", "Rituximab", "Hydroxychloroquine", "Azathioprine"], "ans": 3, "exp": "Hydroxychloroquine เป็นยาพื้นฐานสำหรับ SLE ทุกราย (ลดกำเริบ, ปกป้องอวัยวะ, ปรับ prognosis). เพิ่ม steroid/immunosuppressant ตามความรุนแรง/nephritis. ต้องตรวจตาเป็นระยะ.", "id": "set4-54"}, {"topic": "Rheumatology", "q": "A patient develops a lupus-like syndrome (arthralgia, serositis) after long-term hydralazine or procainamide; anti-histone antibody is positive. What is the diagnosis?", "choices": ["Systemic lupus erythematosus", "Rheumatoid arthritis", "Sjogren syndrome", "Systemic sclerosis", "Drug-induced lupus"], "ans": 4, "exp": "Drug-induced lupus (hydralazine, procainamide, isoniazid): arthralgia/serositis, anti-histone positive, มัก spares kidney/CNS, หายเมื่อหยุดยา. ต่าง SLE ที่ anti-dsDNA/Smith positive.", "id": "set4-55"}, {"topic": "Rheumatology", "q": "A patient has symmetric small-joint polyarthritis (MCP, PIP, wrists) with > 1 hour of morning stiffness. Which antibody is most specific?", "choices": ["Anti-CCP antibody", "Antinuclear antibody", "Rheumatoid factor", "Anti-dsDNA antibody", "Anti-Ro antibody"], "ans": 0, "exp": "RA: symmetric small-joint arthritis + morning stiffness > 1 ชม. Anti-CCP จำเพาะกว่า RF (RF พบได้ในโรคอื่น). ESR/CRP ประเมิน activity; X-ray = erosion/joint space narrowing.", "id": "set4-56"}, {"topic": "Rheumatology", "q": "What is the first-line disease-modifying agent for rheumatoid arthritis?", "choices": ["NSAIDs", "Methotrexate", "Long-term prednisolone", "Rituximab", "Paracetamol"], "ans": 1, "exp": "RA ควรเริ่ม DMARD เร็ว โดย methotrexate เป็น first-line (± bridging steroid). ถ้าไม่ตอบสนอง เพิ่ม/เปลี่ยนเป็น biologic (anti-TNF) หรือ JAK inhibitor. NSAID/steroid คุมอาการเท่านั้น.", "id": "set4-57"}, {"topic": "Rheumatology", "q": "A patient has acute monoarthritis of the first MTP joint that is red, hot, and exquisitely tender. Synovial fluid shows needle-shaped negatively birefringent crystals. What is the diagnosis?", "choices": ["Pseudogout", "Septic arthritis", "Gout", "Rheumatoid arthritis", "Reactive arthritis"], "ans": 2, "exp": "Podagra (MTP1) + needle-shaped negatively birefringent MSU crystals = gout. รักษาเฉียบพลันด้วย NSAID/colchicine/steroid. ไม่เริ่ม/หยุด urate-lowering ระหว่างกำเริบ.", "id": "set4-58"}, {"topic": "Rheumatology", "q": "What is the goal serum urate when starting urate-lowering therapy (allopurinol) for recurrent gout?", "choices": ["Below 8 mg/dL", "Below 10 mg/dL", "No specific target", "Below 6 mg/dL", "Below 2 mg/dL"], "ans": 3, "exp": "Urate-lowering therapy (allopurinol/febuxostat) เป้า serum urate < 6 mg/dL (< 5 ถ้ามี tophi). เริ่มขนาดต่ำค่อยเพิ่ม + prophylaxis (colchicine/NSAID) ช่วงเริ่มเพื่อกัน flare.", "id": "set4-59"}, {"topic": "Rheumatology", "q": "A patient's synovial fluid shows rhomboid-shaped positively birefringent crystals with chondrocalcinosis on X-ray. What is the diagnosis?", "choices": ["Gout", "Septic arthritis", "Osteoarthritis", "Reactive arthritis", "Pseudogout (CPPD disease)"], "ans": 4, "exp": "Rhomboid, positively birefringent crystals + chondrocalcinosis = CPPD (pseudogout). มักโดนข้อใหญ่ (knee, wrist); สัมพันธ์ hyperparathyroidism, hemochromatosis, hypomagnesemia.", "id": "set4-60"}, {"topic": "Rheumatology", "q": "A patient has an acutely hot, swollen, painful single joint with fever. What is the most important immediate step?", "choices": ["Aspiration for culture, then antibiotics", "Start allopurinol immediately", "NSAIDs and discharge home", "Obtain an MRI first", "Refer for physiotherapy"], "ans": 0, "exp": "Acute monoarthritis + ไข้ = ต้องตัด septic arthritis เสมอ — ทำ arthrocentesis (cell count, Gram stain, culture, crystals) ด่วน แล้วเริ่ม empiric antibiotic + joint drainage. Septic arthritis เป็นภาวะฉุกเฉิน (ทำลายข้อ).", "id": "set4-61"}, {"topic": "Rheumatology", "q": "The most common organism causing septic arthritis in adults is:", "choices": ["Neisseria gonorrhoeae", "Staphylococcus aureus", "Streptococcus pneumoniae", "Escherichia coli", "Pseudomonas aeruginosa"], "ans": 1, "exp": "Septic arthritis ในผู้ใหญ่ส่วนใหญ่เกิดจาก Staphylococcus aureus. ในผู้ใหญ่วัยเจริญพันธุ์ที่ active ทางเพศ ให้คิดถึง Neisseria gonorrhoeae (มักหลายข้อ + tenosynovitis + ผื่น).", "id": "set4-62"}, {"topic": "Rheumatology", "q": "An older woman has bilateral knee pain worse with activity, relieved by rest, with bony enlargement (Heberden/Bouchard nodes) and no systemic symptoms. What is the diagnosis?", "choices": ["Rheumatoid arthritis", "Gout", "Osteoarthritis", "Systemic lupus erythematosus", "Septic arthritis"], "ans": 2, "exp": "Osteoarthritis: ปวดข้อเมื่อใช้งาน ดีขึ้นเมื่อพัก, ข้อฝืดเช้าสั้น (< 30 นาที), Heberden (DIP)/Bouchard (PIP) nodes, ไม่มี systemic inflammation. รักษา exercise, ลดน้ำหนัก, paracetamol/NSAID, ข้อเทียมเมื่อรุนแรง.", "id": "set4-63"}, {"topic": "Rheumatology", "q": "A young man has chronic inflammatory low back pain (better with exercise, worse with rest), reduced spinal mobility, and sacroiliitis; HLA-B27 positive. What is the diagnosis?", "choices": ["Mechanical low back pain", "Osteoarthritis of the spine", "A herniated disc", "Ankylosing spondylitis", "Osteoporosis"], "ans": 3, "exp": "Inflammatory back pain (ดีขึ้นเมื่อขยับ, ตอนเช้าฝืด) + sacroiliitis + HLA-B27 = ankylosing spondylitis (bamboo spine). รักษา NSAID + exercise; anti-TNF/IL-17 ในรายดื้อ.", "id": "set4-64"}, {"topic": "Rheumatology", "q": "A patient develops arthritis, urethritis, and conjunctivitis after a GI/GU infection. What is the diagnosis?", "choices": ["Rheumatoid arthritis", "Gout", "Psoriatic arthritis", "Septic arthritis", "Reactive arthritis"], "ans": 4, "exp": "Reactive arthritis (asymmetric oligoarthritis + urethritis + conjunctivitis) หลังติดเชื้อ GI (Salmonella/Shigella/Campylobacter) หรือ GU (Chlamydia); HLA-B27 สัมพันธ์. รักษา NSAID; รักษาเชื้อต้นเหตุ.", "id": "set4-65"}, {"topic": "Rheumatology", "q": "A patient with psoriasis develops asymmetric arthritis with dactylitis ('sausage digit') and nail pitting. What is the diagnosis?", "choices": ["Psoriatic arthritis", "Rheumatoid arthritis", "Gout", "Osteoarthritis", "Reactive arthritis"], "ans": 0, "exp": "Psoriatic arthritis: arthritis + psoriasis + dactylitis + nail changes (pitting, onycholysis), อาจโดน DIP; X-ray pencil-in-cup. รักษา NSAID, DMARD (methotrexate), biologic (anti-TNF/IL-17).", "id": "set4-66"}, {"topic": "Rheumatology", "q": "A woman has Raynaud phenomenon, skin thickening, dysphagia, and pulmonary involvement; anti-Scl-70 is positive. What is the diagnosis?", "choices": ["Systemic lupus erythematosus", "Systemic sclerosis (scleroderma)", "Rheumatoid arthritis", "Dermatomyositis", "Sjogren syndrome"], "ans": 1, "exp": "Systemic sclerosis: skin thickening + Raynaud + GERD/dysphagia + ILD/PAH. Diffuse (anti-Scl-70) vs limited/CREST (anti-centromere). ระวัง scleroderma renal crisis (รักษา ACEI).", "id": "set4-67"}, {"topic": "Rheumatology", "q": "A scleroderma patient develops malignant hypertension and acute kidney injury (renal crisis). What is the treatment of choice?", "choices": ["A beta-blocker", "A calcium channel blocker", "An ACE inhibitor", "A diuretic", "A corticosteroid"], "ans": 2, "exp": "Scleroderma renal crisis (HT รุนแรง + AKI + MAHA) รักษาด้วย ACE inhibitor (captopril) เป็นตัวเลือกหลัก แม้ Cr สูง. หลีกเลี่ยง high-dose steroid ซึ่งกระตุ้น renal crisis.", "id": "set4-68"}, {"topic": "Rheumatology", "q": "A patient has dry eyes and dry mouth (sicca) with positive anti-Ro (SSA)/anti-La (SSB). What is the diagnosis?", "choices": ["Systemic lupus erythematosus", "Rheumatoid arthritis", "Systemic sclerosis", "Sjogren syndrome", "Sarcoidosis"], "ans": 3, "exp": "Sjogren syndrome: keratoconjunctivitis sicca + xerostomia + anti-Ro/La; ยืนยันด้วย Schirmer test/lip biopsy. เสี่ยง lymphoma (MALT). รักษาตามอาการ (น้ำตาเทียม, pilocarpine).", "id": "set4-69"}, {"topic": "Rheumatology", "q": "A patient has proximal muscle weakness, elevated CK, and a heliotrope rash with Gottron papules. What is the diagnosis?", "choices": ["Polymyositis", "Polymyalgia rheumatica", "Myasthenia gravis", "Fibromyalgia", "Dermatomyositis"], "ans": 4, "exp": "Proximal muscle weakness + CK สูง + heliotrope rash + Gottron papules = dermatomyositis. สัมพันธ์ malignancy (ควรคัดกรองมะเร็ง). รักษาด้วย corticosteroid ± immunosuppressant.", "id": "set4-70"}, {"topic": "Rheumatology", "q": "An older patient has new bilateral temporal headache, jaw claudication, scalp tenderness, and a markedly elevated ESR. What is the immediate treatment to prevent blindness?", "choices": ["Immediate high-dose corticosteroid", "NSAIDs", "Methotrexate", "Observation only", "Antibiotics"], "ans": 0, "exp": "Giant cell (temporal) arteritis: ปวดขมับ + jaw claudication + ESR สูง เสี่ยงตาบอด (anterior ischemic optic neuropathy) — ให้ high-dose corticosteroid ทันทีโดยไม่รอ temporal artery biopsy. สัมพันธ์ polymyalgia rheumatica.", "id": "set4-71"}, {"topic": "Rheumatology", "q": "An older patient has bilateral shoulder and hip girdle pain and stiffness with a high ESR but normal CK and no true weakness. What is the diagnosis?", "choices": ["Polymyositis", "Polymyalgia rheumatica", "Fibromyalgia", "Rheumatoid arthritis", "Hypothyroid myopathy"], "ans": 1, "exp": "Polymyalgia rheumatica: ปวด/ฝืด shoulder+hip girdle, ESR สูง, CK ปกติ, ไม่มี weakness จริง. ตอบสนองดีต่อ low-dose prednisolone. สัมพันธ์ GCA (เฝ้าระวังอาการตา).", "id": "set4-72"}, {"topic": "Rheumatology", "q": "A young Asian/Middle-Eastern patient has recurrent painful oral and genital ulcers with uveitis. What is the diagnosis?", "choices": ["Systemic lupus erythematosus", "Reactive arthritis", "Behcet disease", "Crohn disease", "Herpes infection"], "ans": 2, "exp": "Behcet disease: recurrent oral + genital ulcers + uveitis (± skin lesions, pathergy). รักษาตามอวัยวะที่โดน (colchicine, steroid, immunosuppressant/biologic).", "id": "set4-73"}, {"topic": "Rheumatology", "q": "A patient has palpable purpura, abdominal pain, arthralgia, and hematuria after a URI; biopsy shows IgA deposition. What is the diagnosis?", "choices": ["Immune thrombocytopenic purpura", "Meningococcemia", "Systemic lupus erythematosus", "IgA vasculitis (Henoch-Schonlein purpura)", "Cryoglobulinemia"], "ans": 3, "exp": "IgA vasculitis (HSP, พบในเด็ก): palpable purpura (ขาส่วนล่าง) + abdominal pain + arthritis + IgA nephropathy. มัก self-limited; supportive ± steroid ในรายรุนแรง.", "id": "set4-74"}, {"topic": "Rheumatology", "q": "A patient has asthma, eosinophilia, and vasculitis with mononeuritis multiplex; p-ANCA may be positive. What is the diagnosis?", "choices": ["Granulomatosis with polyangiitis", "Polyarteritis nodosa", "Giant cell arteritis", "Takayasu arteritis", "Eosinophilic granulomatosis (Churg-Strauss)"], "ans": 4, "exp": "Asthma + eosinophilia + vasculitis (mononeuritis multiplex) = eosinophilic granulomatosis with polyangiitis (Churg-Strauss), p-ANCA/MPO. รักษาด้วย corticosteroid ± immunosuppressant.", "id": "set4-75"}, {"topic": "Rheumatology", "q": "A middle-aged man has systemic vasculitis with renal and GI involvement, hypertension, and is hepatitis B associated; ANCA is typically negative and there is no glomerulonephritis with pulmonary hemorrhage. What is the diagnosis?", "choices": ["Polyarteritis nodosa", "Granulomatosis with polyangiitis", "Microscopic polyangiitis", "Giant cell arteritis", "Behcet disease"], "ans": 0, "exp": "Polyarteritis nodosa (PAN): medium-vessel vasculitis, สัมพันธ์ HBV, โดนไต (renal artery, ไม่ใช่ GN)/GI/ผิวหนัง/เส้นประสาท, ANCA negative, spares ปอด. รักษา steroid ± cyclophosphamide (+ antiviral ถ้า HBV).", "id": "set4-76"}, {"topic": "Rheumatology", "q": "A young Asian woman has arm claudication, unequal pulses/blood pressures, and bruits over large arteries. What is the diagnosis?", "choices": ["Giant cell arteritis", "Takayasu arteritis", "Polyarteritis nodosa", "Buerger disease", "Kawasaki disease"], "ans": 1, "exp": "Takayasu arteritis ('pulseless disease'): large-vessel vasculitis ในหญิงเอเชียอายุน้อย — ชีพจร/ความดันไม่เท่ากัน, bruit, claudication แขน. รักษาด้วย corticosteroid ± immunosuppressant.", "id": "set4-77"}, {"topic": "Rheumatology", "q": "A patient has widespread chronic musculoskeletal pain, fatigue, poor sleep, and multiple tender points but normal inflammatory markers and imaging. What is the diagnosis?", "choices": ["Polymyalgia rheumatica", "Rheumatoid arthritis", "Fibromyalgia", "Systemic lupus erythematosus", "Hypothyroidism"], "ans": 2, "exp": "Fibromyalgia: ปวดกล้ามเนื้อทั่วตัวเรื้อรัง + เหนื่อยล้า + นอนไม่ดี + tender points โดย inflammatory markers/imaging ปกติ. รักษาด้วยออกกำลัง, ปรับการนอน, ยา (duloxetine, pregabalin, amitriptyline).", "id": "set4-78"}, {"topic": "Rheumatology", "q": "A patient with SLE has recurrent arterial/venous thrombosis and pregnancy losses with positive lupus anticoagulant. What is the diagnosis and long-term treatment?", "choices": ["Simple DVT; short-course anticoagulation", "Immune thrombocytopenia; corticosteroids", "TTP; plasma exchange", "Antiphospholipid syndrome; long-term anticoagulation", "Factor V Leiden; aspirin"], "ans": 3, "exp": "Antiphospholipid syndrome (thrombosis + pregnancy loss + antiphospholipid antibody, อาจ secondary ต่อ SLE) รักษาด้วย long-term anticoagulation (warfarin) หลัง thrombosis; ในตั้งครรภ์ใช้ heparin + aspirin.", "id": "set4-79"}, {"topic": "Rheumatology", "q": "A patient has Raynaud phenomenon alone with no other features; nailfold capillaroscopy is normal and antibodies negative. What is the classification and management?", "choices": ["Secondary Raynaud; treat the underlying cause", "Systemic sclerosis; give immunosuppression", "Buerger disease; stop smoking", "Vasculitis; give corticosteroids", "Primary Raynaud; calcium channel blocker"], "ans": 4, "exp": "Primary Raynaud (ไม่มีโรคพื้นฐาน, capillaroscopy/serology ปกติ) รักษาด้วยหลีกเลี่ยงความเย็น/บุหรี่ ± dihydropyridine CCB (nifedipine). Secondary (systemic sclerosis, SLE) ต้องหาและรักษาโรคพื้นฐาน.", "id": "set4-80"}, {"topic": "Rheumatology", "q": "A patient with rheumatoid arthritis, splenomegaly, and neutropenia has which syndrome?", "choices": ["Felty syndrome", "Sjogren syndrome", "Caplan syndrome", "Still disease", "Sweet syndrome"], "ans": 0, "exp": "Felty syndrome = RA + splenomegaly + neutropenia (เสี่ยงติดเชื้อ). Caplan = RA + pneumoconiosis; adult Still = ไข้สูง + ผื่นสีแซลมอน + arthritis + ferritin สูงมาก.", "id": "set4-81"}, {"topic": "Rheumatology", "q": "A young adult has daily high spiking fevers, an evanescent salmon-colored rash, arthritis, and a very high ferritin with negative RF/ANA. What is the diagnosis?", "choices": ["Systemic lupus erythematosus", "Adult-onset Still disease", "Rheumatoid arthritis", "Reactive arthritis", "Systemic sepsis"], "ans": 1, "exp": "Adult-onset Still disease: quotidian fever + salmon rash + arthritis + leukocytosis + ferritin สูงมาก, RF/ANA negative. เป็น diagnosis of exclusion; รักษาด้วย NSAID/steroid ± IL-1/IL-6 inhibitor.", "id": "set4-82"}, {"topic": "Rheumatology", "q": "A patient on long-term corticosteroids for a rheumatic disease needs prophylaxis against which complication?", "choices": ["Hyperkalemia", "Hypoglycemia", "Osteoporosis and peptic ulcer risk", "Bradycardia", "Hyperthyroidism"], "ans": 2, "exp": "Long-term steroid เสี่ยง glucocorticoid-induced osteoporosis — ให้ calcium/vitamin D ± bisphosphonate; ระวัง hyperglycemia, HT, infection, PUD (โดยเฉพาะร่วม NSAID), adrenal suppression (ห้ามหยุดกะทันหัน).", "id": "set4-83"}, {"topic": "Rheumatology", "q": "A patient starting methotrexate for RA should also receive which supplement to reduce side effects?", "choices": ["Vitamin D", "Iron", "Vitamin B12", "Folic acid", "Calcium"], "ans": 3, "exp": "Methotrexate ให้ folic acid ร่วมเพื่อลด mucositis/GI/hepatotoxicity/cytopenia. ติดตาม CBC/LFT; หลีกเลี่ยงในตั้งครรภ์ (teratogen) และระวังใน renal impairment.", "id": "set4-84"}, {"topic": "Rheumatology", "q": "Before starting a biologic anti-TNF agent, screening for which latent infection is essential?", "choices": ["HIV infection only", "Malaria", "Dengue", "Syphilis", "Latent TB and hepatitis B"], "ans": 4, "exp": "ก่อนเริ่ม anti-TNF ต้องคัดกรอง latent TB (TST/IGRA + CXR) และ hepatitis B (เสี่ยง reactivation) เพราะ anti-TNF เพิ่มความเสี่ยงติดเชื้อฉวยโอกาส/reactivation.", "id": "set4-85"}, {"topic": "Rheumatology", "q": "A patient with gout has a flare while on stable allopurinol. What should be done with the allopurinol?", "choices": ["Continue it and treat the flare separately", "Stop the allopurinol", "Double the dose immediately", "Switch to colchicine only", "Stop urate-lowering therapy forever"], "ans": 0, "exp": "ระหว่าง gout flare ไม่ควรหยุด (หรือเริ่ม) urate-lowering therapy ที่ใช้อยู่เดิม — ให้คงยาไว้และรักษา flare แยก (NSAID/colchicine/steroid) เพราะการเปลี่ยนระดับ urate กระตุ้น flare.", "id": "set4-86"}, {"topic": "Rheumatology", "q": "A patient with lupus nephritis class IV needs induction therapy. Which regimen is appropriate?", "choices": ["Hydroxychloroquine alone", "Steroid plus mycophenolate/cyclophosphamide", "An NSAID", "Methotrexate", "Antibiotics"], "ans": 1, "exp": "Proliferative lupus nephritis (class III/IV) induction ด้วย high-dose corticosteroid + mycophenolate mofetil หรือ cyclophosphamide (± belimumab/voclosporin). ทุกรายให้ hydroxychloroquine + คุมความดัน/proteinuria.", "id": "set4-87"}, {"topic": "Rheumatology", "q": "A patient has osteoarthritis of the knee. What is the recommended first-line management?", "choices": ["Opioid analgesics", "Immediate joint replacement", "Exercise, weight loss, and an NSAID", "Long-term corticosteroids", "Colchicine"], "ans": 2, "exp": "OA เข่า first-line = exercise/strengthening, ลดน้ำหนัก, และ analgesia (topical NSAID, paracetamol/oral NSAID). Intra-articular steroid ช่วงกำเริบ; joint replacement เมื่อรุนแรง/ล้มเหลวจากการรักษาอนุรักษ์.", "id": "set4-88"}, {"topic": "Rheumatology", "q": "A patient with an acute gout flare has CKD and cannot take NSAIDs. What is an appropriate alternative?", "choices": ["A high-dose NSAID anyway", "Allopurinol to abort the flare", "Aspirin", "Colchicine or a corticosteroid", "Febuxostat to abort the flare"], "ans": 3, "exp": "ใน gout flare ที่มี CKD/ห้าม NSAID ใช้ colchicine (ปรับขนาดตาม renal) หรือ corticosteroid (oral/intra-articular). Urate-lowering (allopurinol/febuxostat) ไม่ใช้ abort flare.", "id": "set4-89"}, {"topic": "Rheumatology", "q": "A patient has a positive ANA at low titer but no symptoms. How should this be interpreted?", "choices": ["The patient definitely has lupus", "Start immunosuppression at once", "Ignore all future symptoms", "Repeat the test every week", "A low-titer ANA is nonspecific"], "ans": 4, "exp": "ANA titer ต่ำพบได้ในคนปกติและโรคอื่น — ไม่จำเพาะ; ต้องแปลผลร่วมอาการทางคลินิก. ตรวจ specific antibody (anti-dsDNA/Smith) เมื่อสงสัย SLE. ไม่เริ่มรักษาเพียงเพราะ ANA บวก.", "id": "set4-90"}, {"topic": "Rheumatology", "q": "A patient with granulomatosis with polyangiitis (GPA) has upper airway, lung, and kidney disease with c-ANCA. What is induction treatment?", "choices": ["Steroid plus rituximab/cyclophosphamide", "NSAIDs", "Antibiotics only", "Colchicine", "Methotrexate alone"], "ans": 0, "exp": "GPA (ANCA-associated vasculitis) รุนแรง (ไต/ปอด) induction ด้วย corticosteroid + rituximab หรือ cyclophosphamide; maintenance ด้วย rituximab/azathioprine. คัดกรอง infection ก่อน immunosuppress.", "id": "set4-91"}, {"topic": "Rheumatology", "q": "A patient with rheumatoid arthritis is at increased risk of which extra-articular/systemic complication?", "choices": ["A reduced cardiovascular risk", "Cardiovascular disease and neck instability", "Hyperthyroidism", "Polycythemia", "Hypercalcemia"], "ans": 1, "exp": "RA เพิ่มความเสี่ยง cardiovascular disease (inflammation เร่ง atherosclerosis) และ atlantoaxial subluxation (ระวังตอน intubation/ผ่าตัด). ควบคุมโรค + ประเมิน CV risk.", "id": "set4-92"}, {"topic": "Rheumatology", "q": "A patient has an acute swollen knee; aspiration shows WBC 80,000 with neutrophil predominance and no crystals. What is the most likely diagnosis?", "choices": ["Osteoarthritis", "Gout", "Septic arthritis", "Reactive arthritis", "Hemarthrosis"], "ans": 2, "exp": "Synovial WBC สูงมาก (> 50,000, มัก > 50–100k) neutrophil เด่น ไม่มี crystal = septic arthritis จนกว่าจะพิสูจน์เป็นอื่น — ต้อง culture + antibiotic + drainage ด่วน. Crystal disease อาจ WBC สูงได้แต่มี crystal.", "id": "set4-93"}, {"topic": "Rheumatology", "q": "A patient with dermatomyositis is diagnosed. What additional evaluation is important, especially in adults?", "choices": ["Bone density testing only", "An echocardiogram only", "No further work-up needed", "Age-appropriate malignancy screening", "Thyroid testing only"], "ans": 3, "exp": "Dermatomyositis (และ polymyositis) ในผู้ใหญ่สัมพันธ์ occult malignancy — ต้องทำ age-appropriate cancer screening (และตามอาการ) เพราะอาจเป็น paraneoplastic.", "id": "set4-94"}, {"topic": "Rheumatology", "q": "A patient develops gout tophi and chronic arthropathy. What long-term strategy prevents joint damage?", "choices": ["NSAIDs only during flares", "Colchicine only", "Dietary change alone", "Surgery for all patients", "Urate-lowering to target with prophylaxis"], "ans": 4, "exp": "Chronic tophaceous gout ต้องใช้ urate-lowering therapy ต่อเนื่องจนถึงเป้า (< 5–6 mg/dL เพื่อละลาย tophi) + prophylaxis ช่วงเริ่ม + ปรับ lifestyle. การรักษาเฉพาะ flare ไม่ป้องกันความเสียหายข้อ.", "id": "set4-95"}, {"topic": "Rheumatology", "q": "A patient with SLE plans pregnancy. Which drug is safe to continue and which is contraindicated?", "choices": ["Continue HCQ; stop teratogenic agents", "Continue methotrexate", "Stop all medications", "Continue mycophenolate", "Start warfarin routinely"], "ans": 0, "exp": "ในตั้งครรภ์ SLE: hydroxychloroquine ปลอดภัยและควรใช้ต่อ (ลด flare); methotrexate/mycophenolate/cyclophosphamide เป็น teratogen ต้องหยุด/เปลี่ยน (azathioprine ใช้ได้). วางแผนช่วงโรคสงบ.", "id": "set4-96"}, {"topic": "Rheumatology", "q": "A patient with reactive arthritis or spondyloarthritis has which associated genetic marker?", "choices": ["HLA-DR4", "HLA-B27", "HLA-DQ2", "HLA-B51", "HLA-DR3"], "ans": 1, "exp": "Spondyloarthritis group (ankylosing spondylitis, reactive, psoriatic, IBD-associated) สัมพันธ์ HLA-B27. (HLA-DR4 → RA; HLA-B51 → Behcet; HLA-DQ2 → celiac).", "id": "set4-97"}, {"topic": "Rheumatology", "q": "A patient presents with acute anterior uveitis (painful red eye, photophobia). Which systemic association should be considered?", "choices": ["Osteoarthritis", "Fibromyalgia", "HLA-B27 spondyloarthritis", "Gout", "Osteoporosis"], "ans": 2, "exp": "Acute anterior uveitis สัมพันธ์ HLA-B27 spondyloarthritis (ankylosing spondylitis, IBD, reactive, psoriatic) รวมถึง sarcoidosis/Behcet. ต้องส่งจักษุแพทย์ด่วน + ประเมินโรคระบบ.", "id": "set4-98"}, {"topic": "Rheumatology", "q": "A patient with long-standing RA develops amyloidosis. Which type and consequence should be considered?", "choices": ["AL amyloid with cardiac involvement", "No amyloid risk at all", "Beta-2 microglobulin amyloid only", "AA amyloid; nephrotic syndrome, renal failure", "Purely localized amyloid"], "ans": 3, "exp": "Chronic inflammatory disease (RA, IBD, chronic infection) เสี่ยง AA (secondary) amyloidosis จาก serum amyloid A → มัก renal involvement (proteinuria/nephrotic). ควบคุม inflammation เป็นการป้องกัน.", "id": "set4-99"}, {"topic": "Rheumatology", "q": "A patient with vasculitis affecting the kidneys and lungs (pulmonary-renal syndrome) has p-ANCA/MPO without granulomas. What is the diagnosis?", "choices": ["Granulomatosis with polyangiitis", "Goodpasture syndrome", "Polyarteritis nodosa", "Behcet disease", "Microscopic polyangiitis"], "ans": 4, "exp": "Microscopic polyangiitis: small-vessel vasculitis, pulmonary-renal syndrome (RPGN + alveolar hemorrhage), p-ANCA/MPO positive, ไม่มี granuloma (ต่าง GPA). รักษา steroid + rituximab/cyclophosphamide.", "id": "set4-100"}]}, {"id": "set5", "title": "ชุดที่ 5 — Neurology + Integrated", "questions": [{"topic": "Neurology", "q": "A 26-year-old woman has recurrent unilateral throbbing headaches lasting 12–24 hours with nausea, photophobia, and phonophobia; the neurological exam is normal. What is the most likely diagnosis?", "choices": ["Migraine", "Tension-type headache", "Cluster headache", "Trigeminal neuralgia", "Giant cell arteritis"], "ans": 0, "exp": "ปวดศีรษะข้างเดียว ตุบๆ + คลื่นไส้ + กลัวแสง/เสียง + exam ปกติ = migraine. รักษาเฉียบพลันด้วย NSAID/triptan; ป้องกันด้วย propranolol/topiramate/amitriptyline เมื่อบ่อย. (แนวข้อสอบ NLE2)", "id": "set5-1"}, {"topic": "Neurology", "q": "A patient has the sudden 'worst headache of my life' (thunderclap); CT may be negative early. What is the next step if CT is non-diagnostic?", "choices": ["Discharge the patient home", "Lumbar puncture for xanthochromia", "MRI of the spine", "Reassurance without work-up", "Empiric antibiotics"], "ans": 1, "exp": "Thunderclap headache = สงสัย subarachnoid hemorrhage. ถ้า CT ปกติ (โดยเฉพาะหลัง 6 ชม.) ทำ LP หา xanthochromia/RBC. ยืนยัน aneurysm ด้วย CT/DSA angiography.", "id": "set5-2"}, {"topic": "Neurology", "q": "A patient presents within 2 hours of acute left-sided weakness and facial droop; CT shows no hemorrhage and BP is 170/90. What is the appropriate treatment?", "choices": ["Aspirin alone as treatment", "Immediate full anticoagulation", "IV thrombolysis if no contraindication", "Observation without treatment", "Rapid BP lowering with nifedipine"], "ans": 2, "exp": "Acute ischemic stroke ภายใน 4.5 ชม. + CT ไม่มีเลือดออก + ไม่มีข้อห้าม → IV thrombolysis (alteplase 0.9 หรือ tenecteplase 0.25 mg/kg — class I). ถ้า BP > 185/110 ต้องลดก่อน. พิจารณา thrombectomy ถ้า LVO.", "id": "set5-3"}, {"topic": "Neurology", "q": "A stroke patient with a large-vessel occlusion presents at 8 hours with salvageable tissue on perfusion imaging. What is appropriate?", "choices": ["No further treatment is offered", "Thrombolysis alone without thrombectomy", "Immediate full anticoagulation", "Mechanical thrombectomy (extended window up to 24 h)", "Decompressive craniectomy"], "ans": 3, "exp": "AHA/ASA 2026: mechanical thrombectomy ขยายถึง 24 ชม.ในผู้ป่วย LVO ที่ advanced imaging (CTP/MRI) แสดง salvageable tissue (DAWN/DEFUSE-3). เป็นการเปลี่ยนแปลงสำคัญจากเดิม ~6 ชม.", "id": "set5-4"}, {"topic": "Neurology", "q": "A patient with acute ischemic stroke who is NOT eligible for thrombolysis should receive which within 48 hours?", "choices": ["Warfarin anticoagulation", "A heparin infusion", "No treatment at all", "Thrombolysis anyway", "Aspirin (an antiplatelet)"], "ans": 4, "exp": "Stroke ที่ไม่ได้ยาละลายลิ่ม ให้ aspirin ภายใน 24–48 ชม. Early anticoagulation ไม่แนะนำ routine (เสี่ยง hemorrhagic transformation) แม้มี AF (เริ่มภายหลังตามขนาด infarct).", "id": "set5-5"}, {"topic": "Neurology", "q": "A seizing patient has been convulsing for more than 5 minutes. What is the first-line drug?", "choices": ["An IV/IM benzodiazepine", "IV phenytoin", "IV valproate", "IV propofol", "IV levetiracetam"], "ans": 0, "exp": "Status epilepticus (ชัก > 5 นาที/ไม่ฟื้นระหว่างชัก): first-line = benzodiazepine (lorazepam IV, midazolam IM). จากนั้น load ด้วย levetiracetam/phenytoin/valproate; หา/แก้สาเหตุ (น้ำตาล, Na, ติดเชื้อ). ดูแล ABC.", "id": "set5-6"}, {"topic": "Neurology", "q": "A patient develops ascending symmetric weakness and areflexia days after a diarrheal illness; CSF shows high protein with normal cells. What is the diagnosis and treatment?", "choices": ["Myasthenia gravis; give pyridostigmine", "Guillain-Barre syndrome; IVIG or plasma exchange", "Acute stroke; give thrombolysis", "Botulism; give the antitoxin", "Multiple sclerosis; give steroids"], "ans": 1, "exp": "Ascending symmetric weakness + areflexia + albuminocytologic dissociation หลังติดเชื้อ (Campylobacter) = Guillain-Barre. รักษาด้วย IVIG หรือ plasma exchange; เฝ้าระวังการหายใจ (FVC) + autonomic instability. ไม่ใช้ steroid.", "id": "set5-7"}, {"topic": "Neurology", "q": "A patient has fatigable weakness with ptosis and diplopia worsening through the day; anti-AChR antibodies are positive. What is the diagnosis?", "choices": ["Guillain-Barre syndrome", "Lambert-Eaton syndrome", "Myasthenia gravis", "Multiple sclerosis", "Motor neuron disease"], "ans": 2, "exp": "Fatigable weakness (ptosis, diplopia แย่ตอนเย็น/ใช้งาน) + anti-AChR = myasthenia gravis. รักษาด้วย pyridostigmine + immunosuppression; ตรวจ thymoma (CT chest). ระวัง myasthenic crisis (หายใจล้มเหลว).", "id": "set5-8"}, {"topic": "Neurology", "q": "A patient with myasthenia gravis develops respiratory distress and severe weakness (myasthenic crisis). What is the treatment?", "choices": ["Increase pyridostigmine only", "Corticosteroids alone", "Antibiotics only", "Airway support plus IVIG or plasma exchange", "Observation only"], "ans": 3, "exp": "Myasthenic crisis (หายใจล้มเหลว) ต้อง secure airway/ventilate + IVIG หรือ plasma exchange + รักษา precipitant (ติดเชื้อ/ยา). ระวังยาที่กระตุ้น (aminoglycoside, beta-blocker).", "id": "set5-9"}, {"topic": "Neurology", "q": "A young woman has episodes of optic neuritis and limb weakness separated in time and space; MRI shows white-matter lesions. What is the diagnosis?", "choices": ["Acute stroke", "Guillain-Barre syndrome", "Myasthenia gravis", "Migraine", "Multiple sclerosis"], "ans": 4, "exp": "MS: CNS demyelination หลายตำแหน่ง หลายช่วงเวลา (optic neuritis, weakness, sensory, INO); MRI = periventricular white-matter lesions; CSF oligoclonal bands. รักษา acute relapse ด้วย steroid; disease-modifying therapy ระยะยาว.", "id": "set5-10"}, {"topic": "Neurology", "q": "An elderly patient has a resting tremor, bradykinesia, rigidity, and postural instability. What is the diagnosis?", "choices": ["Parkinson disease", "Essential tremor", "Cerebellar disease", "Huntington disease", "Wilson disease"], "ans": 0, "exp": "Parkinson disease: resting tremor (pill-rolling) + bradykinesia + rigidity (cogwheel) + postural instability, asymmetric onset. รักษาด้วย levodopa/carbidopa, dopamine agonist. Essential tremor เป็น action tremor (ดีขึ้นด้วยแอลกอฮอล์/propranolol).", "id": "set5-11"}, {"topic": "Neurology", "q": "A patient has trigeminal neuralgia with brief electric-shock-like facial pain triggered by touch. What is the first-line medication?", "choices": ["Paracetamol", "Carbamazepine", "Opioid analgesics", "Gabapentin alone", "Amitriptyline"], "ans": 1, "exp": "Trigeminal neuralgia (paroxysmal electric-shock facial pain ตาม trigeminal) first-line = carbamazepine (หรือ oxcarbazepine). ผ่าตัด microvascular decompression ในรายดื้อยา.", "id": "set5-12"}, {"topic": "Neurology", "q": "A patient with a cluster headache has severe unilateral periorbital pain with ipsilateral lacrimation and rhinorrhea in bouts. What is the acute treatment?", "choices": ["An oral triptan tablet", "Paracetamol", "High-flow oxygen or SC sumatriptan", "Carbamazepine", "Antibiotics"], "ans": 2, "exp": "Cluster headache: ปวดรอบตาข้างเดียวรุนแรง + autonomic (น้ำตา/คัดจมูก) เป็นชุด. รักษาเฉียบพลันด้วย high-flow oxygen 100% และ/หรือ SC sumatriptan; ป้องกันด้วย verapamil.", "id": "set5-13"}, {"topic": "Neurology", "q": "A patient has a peripheral facial (Bell) palsy affecting the forehead. What distinguishes it from a central (stroke) facial palsy?", "choices": ["There is no clinical difference", "Peripheral spares the forehead", "Both types spare the forehead", "Central palsy spares the forehead", "Both involve the forehead equally"], "ans": 3, "exp": "Peripheral (LMN, Bell) palsy โดนทั้งใบหน้ารวมหน้าผาก; central (UMN, stroke) spares forehead (เพราะ bilateral cortical innervation ส่วนบน). Bell palsy รักษาด้วย corticosteroid (± antiviral) เร็ว + eye care.", "id": "set5-14"}, {"topic": "Neurology", "q": "A patient with new headache, papilledema, and focal deficit should be evaluated for what before lumbar puncture?", "choices": ["No investigation is needed", "Blood glucose only", "An ECG only", "A chest X-ray only", "Raised ICP lesion; obtain CT or MRI"], "ans": 4, "exp": "Headache + papilledema + focal deficit = สงสัย raised ICP/mass — ต้อง neuroimaging (CT/MRI) ก่อน LP เพื่อเลี่ยง herniation. หาสาเหตุ (tumor, abscess, hemorrhage).", "id": "set5-15"}, {"topic": "Neurology", "q": "A patient develops a sudden severe headache with neck stiffness and photophobia but no fever; CT confirms blood in the subarachnoid space. What is the most common underlying cause?", "choices": ["Ruptured berry (saccular) aneurysm", "A hypertensive intracerebral bleed", "An AV malformation only", "Head trauma only", "A brain tumor"], "ans": 0, "exp": "Non-traumatic subarachnoid hemorrhage ส่วนใหญ่จาก ruptured saccular (berry) aneurysm. ต้อง CT/DSA angiography หา aneurysm + secure (coiling/clipping) + ป้องกัน vasospasm (nimodipine).", "id": "set5-16"}, {"topic": "Neurology", "q": "A diabetic patient has burning, tingling, and numbness in a stocking distribution. What is the pattern and a first-line drug?", "choices": ["A radiculopathy; refer for surgery", "Diabetic polyneuropathy; give pregabalin", "Mononeuritis multiplex; give a steroid", "A myopathy; caused by a statin", "A plexopathy; observation only"], "ans": 1, "exp": "Diabetic distal symmetric polyneuropathy (stocking-glove) รักษา neuropathic pain ด้วย pregabalin/gabapentin, duloxetine, หรือ TCA. คุมน้ำตาล + ดูแลเท้าเพื่อป้องกันแผล.", "id": "set5-17"}, {"topic": "Neurology", "q": "A patient has an acute ischemic stroke with atrial fibrillation. When is anticoagulation typically started?", "choices": ["Immediately, within the first few hours", "It should never be given at all", "Delayed anticoagulation by infarct size", "Only same-day warfarin", "Only if the patient is bleeding"], "ans": 2, "exp": "ใน cardioembolic stroke (AF) การเริ่ม anticoagulation ล่าช้าตามขนาด infarct (เช่น '1-3-6-12 day rule') เพื่อลด hemorrhagic transformation. ระยะเฉียบพลันให้ aspirin ก่อน.", "id": "set5-18"}, {"topic": "Neurology", "q": "A patient has a lacunar stroke presenting as pure motor hemiparesis. Which vessels/mechanism are typically involved?", "choices": ["A large-artery embolism", "Cerebral venous thrombosis", "A cardioembolic source", "Small-vessel lacunar occlusion", "An underlying vasculitis"], "ans": 3, "exp": "Lacunar infarcts (pure motor, pure sensory, ataxic hemiparesis) เกิดจาก small-vessel disease (lipohyalinosis) สัมพันธ์ chronic HT/DM. ป้องกันด้วยคุมปัจจัยเสี่ยง + antiplatelet.", "id": "set5-19"}, {"topic": "Neurology", "q": "A comatose patient with pinpoint pupils, slow shallow breathing (RR 6), and evidence of IV drug use should receive which antidote?", "choices": ["Flumazenil", "Atropine", "Glucose alone", "Thiamine alone", "Naloxone"], "ans": 4, "exp": "Pinpoint pupils + respiratory depression + IVDU = opioid overdose → naloxone (opioid antagonist) + airway/ventilation support. (แนวข้อสอบ NLE2)", "id": "set5-20"}, {"topic": "Neurology", "q": "A patient presents with vertigo, and you need to distinguish peripheral from central causes. Which finding suggests a central (dangerous) cause?", "choices": ["Vertical/direction-changing nystagmus", "Fatigable horizontal nystagmus", "Positive Dix-Hallpike with brief vertigo", "Improvement with the Epley maneuver", "Tinnitus with hearing loss"], "ans": 0, "exp": "Central vertigo: nystagmus เปลี่ยนทิศ/แนวตั้ง, ไม่ fatigable, มี neuro signs อื่น (dysarthria, ataxia, diplopia), HINTS exam abnormal → นึกถึง posterior stroke. Peripheral (BPPV/vestibular neuritis) มัก fatigable + Epley ช่วย.", "id": "set5-21"}, {"topic": "Neurology", "q": "A patient with a brain abscess (ring-enhancing lesion with edema) and fever. Besides antibiotics, what is often required?", "choices": ["No further intervention is needed", "Neurosurgical drainage and aspiration", "Give thrombolysis", "Start anticoagulation", "Give chemotherapy"], "ans": 1, "exp": "Brain abscess (ring-enhancing + edema + fever + source เช่น หูชั้นกลาง/ฟัน/endocarditis) มักต้อง neurosurgical aspiration + prolonged antibiotics ตามเชื้อ + จัดการ raised ICP.", "id": "set5-22"}, {"topic": "Neurology", "q": "A patient with wrist drop after prolonged pressure on the arm has which nerve palsy?", "choices": ["The median nerve", "The ulnar nerve", "The radial nerve", "The axillary nerve", "The musculocutaneous nerve"], "ans": 2, "exp": "Wrist drop (extensor weakness) จากการกดทับที่ spiral groove (Saturday night palsy) = radial nerve palsy. Median → carpal tunnel; ulnar → claw hand/clumsy grip.", "id": "set5-23"}, {"topic": "Neurology", "q": "A patient with delirium is acutely confused with fluctuating attention. What is the most important first step?", "choices": ["Sedate the patient immediately", "Start a long-term antipsychotic", "Use physical restraints first-line", "Identify and treat the underlying cause", "Discharge the patient home"], "ans": 3, "exp": "Delirium (acute, fluctuating attention/consciousness) เป็นภาวะเฉียบพลันจากสาเหตุกาย — หาและแก้สาเหตุ (UTI/pneumonia, electrolyte, ยา, hypoxia, ถอนสุรา). จัดการสิ่งแวดล้อม; ยาเป็นทางเลือกสุดท้ายเมื่อจำเป็น.", "id": "set5-24"}, {"topic": "Neurology", "q": "An alcoholic patient develops confusion, ophthalmoplegia, and ataxia. What is the diagnosis and treatment?", "choices": ["Acute stroke; give thrombolysis", "Delirium tremens; give a benzodiazepine", "Hepatic encephalopathy; give lactulose", "Hypoglycemia; give glucose only", "Wernicke encephalopathy; give IV thiamine"], "ans": 4, "exp": "Wernicke encephalopathy (confusion + ophthalmoplegia + ataxia) จาก thiamine deficiency — ให้ IV thiamine ทันที (ก่อน glucose). ถ้าไม่รักษาอาจเป็น Korsakoff (memory ถาวร).", "id": "set5-25"}, {"topic": "Misc", "q": "A patient in shock has cold clammy extremities, JVP elevated, and pulmonary edema after an MI. What type of shock is this?", "choices": ["Cardiogenic shock", "Hypovolemic shock", "Distributive (septic) shock", "Obstructive shock", "Anaphylactic shock"], "ans": 0, "exp": "หลัง MI + pump failure (JVP สูง, pulmonary edema, cold extremities) = cardiogenic shock. รักษาด้วย inotrope/vasopressor + แก้สาเหตุ (revascularization); mechanical support ในรายรุนแรง.", "id": "set5-26"}, {"topic": "Misc", "q": "A patient with fever and hypotension has warm extremities and a wide pulse pressure with a high cardiac output. What type of shock is this?", "choices": ["Cardiogenic shock", "Distributive (septic) shock", "Hypovolemic shock", "Obstructive shock", "Neurogenic shock only"], "ans": 1, "exp": "Distributive (septic) shock: vasodilation → warm extremities, wide pulse pressure, high/normal CO, low SVR. รักษาด้วย fluid + norepinephrine + antibiotics + source control.", "id": "set5-27"}, {"topic": "Misc", "q": "A trauma patient has distended neck veins, hypotension, and muffled heart sounds. What is the diagnosis and treatment?", "choices": ["Tension pneumothorax; needle decompression", "Hemorrhagic shock; give transfusion", "Cardiac tamponade; do pericardiocentesis", "Septic shock; give antibiotics", "Neurogenic shock; give a vasopressor"], "ans": 2, "exp": "Beck triad (hypotension + distended neck veins + muffled heart sounds) = cardiac tamponade (obstructive shock). รักษาด้วย pericardiocentesis/pericardial window. Tension pneumothorax ก็ทำให้ neck vein distend แต่มี absent breath sound + tracheal deviation.", "id": "set5-28"}, {"topic": "Misc", "q": "A patient develops urticaria, wheeze, and hypotension minutes after a drug. What is the first-line treatment?", "choices": ["IV hydrocortisone", "IV antihistamine", "Nebulized salbutamol only", "Intramuscular adrenaline (epinephrine)", "IV fluids only"], "ans": 3, "exp": "Anaphylaxis รักษาลำดับแรกด้วย IM adrenaline ที่ต้นขาด้านนอกทันที + จัดท่า + O2 + IV fluid; antihistamine/steroid เป็น adjunct. หยุด trigger; สังเกตอาการ biphasic.", "id": "set5-29"}, {"topic": "Misc", "q": "At what age should average-risk adults begin colorectal cancer screening (a commonly tested prevention point)?", "choices": ["At age 40 years", "At age 50 years", "At age 55 years", "At age 60 years", "At age 45 years"], "ans": 4, "exp": "USPSTF 2021 แนะนำเริ่มคัดกรอง colorectal cancer อายุ 45 ปีในคนความเสี่ยงปกติ (colonoscopy ทุก 10 ปี หรือ FIT ทุกปี).", "id": "set5-30"}, {"topic": "Misc", "q": "Which cancer screening is recommended for a woman in her 30s (cervical cancer)?", "choices": ["Pap smear with HPV co-testing", "No screening is needed", "A mammogram only", "A colonoscopy", "A CA-125 blood test"], "ans": 0, "exp": "Cervical cancer screening: Pap smear ± HPV testing ตามช่วงอายุ (มักเริ่ม 25–30, HPV-based เป็นหลักในช่วง 30–65). วัคซีน HPV เป็นการป้องกันปฐมภูมิ.", "id": "set5-31"}, {"topic": "Misc", "q": "A terminally ill patient has severe cancer pain. According to the WHO analgesic ladder and modern practice, how should opioids be used?", "choices": ["Avoid opioids entirely", "Titrate opioids; add a laxative", "Use only paracetamol", "Only when death is imminent", "A fixed low dose regardless of pain"], "ans": 1, "exp": "Cancer pain ปานกลาง-รุนแรง ใช้ opioid titrate ตามอาการ (ไม่มี ceiling สำหรับ pure agonist) + ให้ laxative ป้องกันท้องผูก + จัดการ breakthrough pain. เป้าคือคุณภาพชีวิต ไม่ใช่เร่ง/ชะลอความตาย.", "id": "set5-32"}, {"topic": "Misc", "q": "Which framework is used for delivering bad news to patients?", "choices": ["The ABCDE approach", "The FAST tool", "The SPIKES protocol", "The SAMPLE history", "The AMPLE history"], "ans": 2, "exp": "SPIKES: Setting, Perception, Invitation, Knowledge, Emotion (empathy), Strategy/Summary — ใช้สื่อสารข่าวร้ายอย่างเป็นระบบและเห็นอกเห็นใจ.", "id": "set5-33"}, {"topic": "Misc", "q": "A patient presents with a pearly, telangiectatic papule on the face that occasionally bleeds. What is the most likely diagnosis?", "choices": ["Squamous cell carcinoma", "Malignant melanoma", "Seborrheic keratosis", "Basal cell carcinoma", "Actinic keratosis"], "ans": 3, "exp": "Pearly papule + telangiectasia + occasional bleeding บนใบหน้า (sun-exposed) = basal cell carcinoma (พบบ่อยสุด, โตช้า, metastasis น้อย). รักษาด้วย excision. (แนวข้อสอบ NLE2)", "id": "set5-34"}, {"topic": "Misc", "q": "A pigmented skin lesion shows Asymmetry, irregular Border, Color variation, Diameter > 6 mm, and Evolution. What should be done?", "choices": ["Reassure without biopsy", "Blind cryotherapy", "A topical corticosteroid", "Observe for one year", "Excisional biopsy to exclude melanoma"], "ans": 4, "exp": "ABCDE ที่ผิดปกติ = สงสัย melanoma → excisional biopsy (full thickness) เพื่อวินิจฉัยและวัด Breslow thickness (กำหนด prognosis/wide excision margin + SLNB).", "id": "set5-35"}, {"topic": "Misc", "q": "A 20-year-old has a single 'herald patch' followed by a 'Christmas tree' distribution of scaly oval plaques on the trunk. What is the diagnosis?", "choices": ["Pityriasis rosea", "Tinea corporis", "Secondary syphilis", "Psoriasis", "Atopic dermatitis"], "ans": 0, "exp": "Herald patch ตามด้วยผื่นรูปไข่เรียงตาม cleavage lines (Christmas tree) = pityriasis rosea (self-limited). ควรตัด secondary syphilis ออกถ้ามีปัจจัยเสี่ยง (โดนฝ่ามือ/เท้า). (แนวข้อสอบ NLE2)", "id": "set5-36"}, {"topic": "Misc", "q": "A patient develops a target-shaped (iris) lesions and mucosal involvement after a drug or infection. What is the diagnosis?", "choices": ["Acute urticaria", "Erythema multiforme", "Pityriasis rosea", "Psoriasis", "Eczema"], "ans": 1, "exp": "Target/iris lesions = erythema multiforme (มัก HSV/ยา); ถ้ามี mucosal + skin detachment มากขึ้น → Stevens-Johnson syndrome/TEN (หยุดยาต้นเหตุ + supportive/burn-unit care).", "id": "set5-37"}, {"topic": "Misc", "q": "A patient on a new drug (e.g., allopurinol, sulfa, anticonvulsant) develops fever, rash, and skin sloughing with positive Nikolsky sign. What is the diagnosis and first step?", "choices": ["Cellulitis; give antibiotics", "Psoriasis; give a steroid", "Stevens-Johnson/TEN; stop the drug", "Eczema; apply an emollient", "Urticaria; give an antihistamine"], "ans": 2, "exp": "SJS/TEN (fever + mucocutaneous + epidermal detachment, Nikolsky positive) เป็นภาวะฉุกเฉิน — หยุดยาต้นเหตุทันที + supportive care (fluid, wound, temperature) ใน burn/ICU; ประเมิน SCORTEN.", "id": "set5-38"}, {"topic": "Misc", "q": "Which ECG/electrolyte pattern is seen in hyperkalemia?", "choices": ["U waves with flattened T waves", "A prolonged QT interval", "A delta wave", "Peaked T waves, wide QRS, sine wave", "An Osborn wave"], "ans": 3, "exp": "Hyperkalemia: peaked T → PR ยาว/P หาย → wide QRS → sine wave → arrest. Hypokalemia: U wave, flat T, ST depression. รักษา hyperK: calcium → insulin/glucose/salbutamol → removal.", "id": "set5-39"}, {"topic": "Misc", "q": "A patient with vomiting and nasogastric suction develops which acid-base disorder?", "choices": ["Metabolic acidosis", "Respiratory acidosis", "Respiratory alkalosis", "No acid-base change", "Hypochloremic, hypokalemic alkalosis"], "ans": 4, "exp": "เสีย HCl จากการอาเจียน/NG suction → hypochloremic hypokalemic metabolic alkalosis (chloride-responsive). รักษาด้วย isotonic saline + KCl.", "id": "set5-40"}, {"topic": "Misc", "q": "A patient with a suspected drug overdose is unconscious. Which is part of the initial 'coma cocktail'/approach for reversible causes?", "choices": ["Check glucose, thiamine, and naloxone", "Give empiric antibiotics", "Immediate CT scan only", "Give corticosteroids", "Give diuretics"], "ans": 0, "exp": "ผู้ป่วยหมดสติไม่ทราบสาเหตุ: ABC + ตรวจ/แก้ hypoglycemia (dextrose + thiamine), พิจารณา naloxone ถ้าสงสัย opioid, ประเมิน toxidrome + neuroimaging ตามข้อบ่งชี้.", "id": "set5-41"}, {"topic": "Misc", "q": "A patient with a high fever, muscle rigidity, altered mental status, and autonomic instability after starting an antipsychotic has which condition?", "choices": ["Serotonin syndrome", "Neuroleptic malignant syndrome", "Malignant hyperthermia", "Thyroid storm", "Heat stroke"], "ans": 1, "exp": "Neuroleptic malignant syndrome (หลัง antipsychotic/dopamine blocker): hyperthermia + lead-pipe rigidity + altered mental status + autonomic instability + CK สูง. หยุดยา + cooling + supportive ± dantrolene/bromocriptine.", "id": "set5-42"}, {"topic": "Misc", "q": "A patient on an SSRI plus another serotonergic drug develops agitation, hyperreflexia, clonus, and hyperthermia. What is the diagnosis?", "choices": ["Neuroleptic malignant syndrome", "Malignant hyperthermia", "Serotonin syndrome", "Anticholinergic toxicity", "Systemic sepsis"], "ans": 2, "exp": "Serotonin syndrome: agitation + neuromuscular hyperactivity (clonus, hyperreflexia — เด่นที่ขา) + autonomic + hyperthermia, onset เร็วหลังเพิ่ม serotonergic. หยุดยา + supportive ± cyproheptadine. ต่าง NMS ที่ rigidity/bradyreflexia และ onset ช้า.", "id": "set5-43"}, {"topic": "Misc", "q": "A patient with organophosphate poisoning has salivation, lacrimation, urination, defecation, miosis, and bradycardia. What is the antidote?", "choices": ["Naloxone", "Flumazenil", "Physostigmine", "Atropine (± pralidoxime)", "Glucagon"], "ans": 3, "exp": "Organophosphate (cholinergic/SLUDGE + miosis + bronchorrhea/bradycardia) รักษาด้วย atropine (block muscarinic) + pralidoxime (reactivate acetylcholinesterase) + decontamination + airway.", "id": "set5-44"}, {"topic": "Misc", "q": "A previously healthy young adult collapses; ECG shows a shockable rhythm. What is the immediate priority?", "choices": ["Obtain IV access first", "Intubate the patient first", "Give amiodarone first", "Take a full history first", "High-quality CPR, early defibrillation"], "ans": 4, "exp": "Cardiac arrest ด้วย shockable rhythm (VF/pVT): หัวใจของการรักษาคือ high-quality CPR + early defibrillation (ยิ่งเร็วยิ่งรอด) + epinephrine/amiodarone ตาม ACLS; หา reversible causes (H's & T's).", "id": "set5-45"}, {"topic": "Misc", "q": "A patient with chronic anticholinergic overdose is 'hot as a hare, dry as a bone, red as a beet, mad as a hatter, blind as a bat'. Which finding fits?", "choices": ["Dilated pupils, dry skin, retention", "Miosis with excess salivation", "Bradycardia with sweating", "Pinpoint pupils", "Marked bronchorrhea"], "ans": 0, "exp": "Anticholinergic toxidrome: mydriasis, dry/flushed skin, hyperthermia, urinary retention, delirium, tachycardia (ตรงข้าม cholinergic). รักษา supportive ± physostigmine ในบางราย.", "id": "set5-46"}, {"topic": "Misc", "q": "A palliative patient near end of life has distressing dyspnea. Which is appropriate for symptom relief?", "choices": ["Withhold all medication", "Low-dose opioids titrated for dyspnea", "Only oxygen regardless of cause", "Aggressive diuresis for all", "Antibiotics for all"], "ans": 1, "exp": "Dyspnea ในผู้ป่วยระยะท้ายบรรเทาด้วย low-dose opioid (titrate) ± anxiolytic + จัดท่า/พัดลม/oxygen ตามอาการ. เป้าหมายคือความสบาย (comfort) ตาม goals of care.", "id": "set5-47"}, {"topic": "Misc", "q": "A patient has a decision-making capacity question. Which four elements are assessed for capacity?", "choices": ["Age, education, wealth, and family", "Only the patient's understanding", "Understanding, appreciation, reasoning, choice", "Only the physician's own opinion", "The diagnosis alone"], "ans": 2, "exp": "Decision-making capacity ประเมิน 4 องค์ประกอบ: understanding, appreciation, reasoning, และ ability to communicate a choice. Capacity เป็นเรื่องเฉพาะการตัดสินใจและอาจเปลี่ยนตามเวลา.", "id": "set5-48"}, {"topic": "Mixed/Integrated", "q": "A patient with COPD presents drowsy after receiving high-flow oxygen; ABG shows pH 7.25, PaCO2 80, HCO3 34. What is the best intervention?", "choices": ["Increase the oxygen further", "Give IV bicarbonate", "Sedate the patient", "NIV with controlled oxygen", "Give diuretics"], "ans": 3, "exp": "Acute-on-chronic hypercapnic respiratory failure ใน COPD → NIV (BiPAP) + O2 แบบควบคุม (เป้า SpO2 88–92%). O2 สูงเกินลด hypoxic drive/เพิ่ม V/Q mismatch ทำให้ CO2 คั่ง.", "id": "set5-49"}, {"topic": "Mixed/Integrated", "q": "A patient with diabetes has an A1c of 9%, BP 150/90, and albuminuria. Which single drug addresses both renal protection and could be added for cardiovascular/renal benefit?", "choices": ["Amlodipine", "A beta-blocker", "Hydralazine", "A thiazide alone", "An ACE inhibitor/ARB plus an SGLT2i"], "ans": 4, "exp": "เบาหวาน + HT + albuminuria: ACEI/ARB เป็นแกน (ลด proteinuria/ชะลอไต + คุมความดัน) และเพิ่ม SGLT2i เพื่อ CV/renal protection. คุม A1c/lipid ร่วม.", "id": "set5-50"}, {"topic": "Mixed/Integrated", "q": "A patient presents with confusion, Na 110, and seizures. What is the most appropriate immediate treatment?", "choices": ["Careful 3% hypertonic saline", "Rapid full correction with normal saline", "Fluid restriction alone", "Give desmopressin", "Urgent dialysis"], "ans": 0, "exp": "Severe symptomatic hyponatremia (seizure) ให้ 3% hypertonic saline อย่างระมัดระวัง (เพิ่ม Na ~4–6 mEq/L เพื่อหยุดชัก, ไม่เกิน 8–10/24 ชม.) กัน osmotic demyelination. หาสาเหตุร่วม.", "id": "set5-51"}, {"topic": "Mixed/Integrated", "q": "A young woman has fatigue, weight gain, cold intolerance, and menorrhagia; TSH is elevated. Which anemia pattern may coexist?", "choices": ["Microcytic anemia from thalassemia", "Macrocytic anemia of hypothyroidism", "A hemolytic anemia", "A sideroblastic anemia", "An aplastic anemia"], "ans": 1, "exp": "Hypothyroidism อาจทำให้เกิด macrocytic/normocytic anemia (และ menorrhagia อาจเพิ่ม IDA). รักษา hypothyroidism ด้วย levothyroxine + ประเมิน iron/B12 ถ้ามี.", "id": "set5-52"}, {"topic": "Mixed/Integrated", "q": "A patient on warfarin for AF presents with an INR of 8 but no bleeding. What is appropriate management?", "choices": ["Continue the same warfarin dose", "Give fresh frozen plasma", "Hold warfarin ± oral vitamin K", "Give prothrombin complex concentrate", "Increase the warfarin dose"], "ans": 2, "exp": "INR สูงมาก (> 4.5–10) โดยไม่มีเลือดออก: หยุด warfarin ชั่วคราว ± vitamin K ขนาดต่ำ (oral) แล้วตรวจ INR ซ้ำ. PCC/FFP สงวนไว้เมื่อมี major bleeding.", "id": "set5-53"}, {"topic": "Mixed/Integrated", "q": "A patient with cirrhosis has new confusion, asterixis, and constipation. Besides lactulose, what is essential?", "choices": ["Sedate the patient", "A high-protein diet", "Escalate the diuretic dose", "Identify and treat the precipitant", "Paracentesis for all patients"], "ans": 3, "exp": "Hepatic encephalopathy: lactulose + หา/แก้ precipitant (เลือดออก GI, ติดเชื้อ/SBP, electrolyte, ท้องผูก, ยา sedative). rifaximin เสริม; หลีกเลี่ยง sedative.", "id": "set5-54"}, {"topic": "Mixed/Integrated", "q": "A patient with acute chest pain has a normal ECG and a normal high-sensitivity troponin at 0 and 3 hours. What does this suggest?", "choices": ["A definite STEMI", "Proceed to immediate PCI", "Pericarditis is confirmed", "Aortic dissection is confirmed", "Low likelihood of MI; seek other causes"], "ans": 4, "exp": "ECG ปกติ + hs-troponin ไม่เปลี่ยนแปลงที่ 0/3 ชม. ช่วย rule out acute MI (โอกาสต่ำ). ประเมินสาเหตุอื่นของ chest pain (GERD, MSK, PE, dissection ตามบริบท) + risk stratify.", "id": "set5-55"}, {"topic": "Mixed/Integrated", "q": "A patient with newly diagnosed HIV has a CD4 of 350. When should antiretroviral therapy be started?", "choices": ["As soon as possible, regardless of CD4 count", "Only when the CD4 falls below 200", "Only if the patient is symptomatic", "After a six-month delay", "Never while asymptomatic"], "ans": 0, "exp": "แนวทางปัจจุบันแนะนำเริ่ม ART ทันที (rapid start) ในผู้ติดเชื้อ HIV ทุกรายโดยไม่ขึ้นกับ CD4 เพื่อสุขภาพและลดการแพร่ (U=U).", "id": "set5-56"}, {"topic": "Mixed/Integrated", "q": "A patient with severe community-acquired pneumonia has hyponatremia, diarrhea, and confusion. Which pathogen is suggested?", "choices": ["Streptococcus pneumoniae", "Legionella pneumophila", "Mycoplasma pneumoniae", "Klebsiella pneumoniae", "Staphylococcus aureus"], "ans": 1, "exp": "Pneumonia + hyponatremia + diarrhea + confusion/relative bradycardia = Legionella (urine antigen). รักษาด้วย macrolide/respiratory fluoroquinolone.", "id": "set5-57"}, {"topic": "Mixed/Integrated", "q": "A diabetic patient has foot ulcer with surrounding cellulitis and probing to bone. What complication should be evaluated?", "choices": ["An acute gout flare", "A deep vein thrombosis", "Osteomyelitis (MRI, bone culture)", "Cellulitis only", "A Charcot joint only"], "ans": 2, "exp": "Diabetic foot ulcer ที่ probe-to-bone positive/ไม่หาย → สงสัย osteomyelitis (MRI ไวสุด; bone biopsy/culture นำการรักษา) + revascularization ถ้ามี PAD + prolonged antibiotics ± debridement.", "id": "set5-58"}, {"topic": "Mixed/Integrated", "q": "A patient with atrial fibrillation and mechanical heart valve requires anticoagulation. Which is appropriate?", "choices": ["Apixaban", "Aspirin only", "Dabigatran", "Warfarin (not a DOAC)", "No anticoagulation"], "ans": 3, "exp": "Mechanical heart valve ต้องใช้ warfarin เท่านั้น; DOAC เป็นข้อห้าม (RE-ALIGN trial แสดง dabigatran แย่กว่า). เป้า INR ตามชนิด/ตำแหน่งลิ้น.", "id": "set5-59"}, {"topic": "Mixed/Integrated", "q": "A patient presents with painless jaundice, weight loss, and a dilated bile duct with a pancreatic head mass. What is the next step?", "choices": ["Reassurance without work-up", "Empiric antibiotics", "ERCP for stones only", "Observation only", "Staging CT and EUS-guided biopsy"], "ans": 4, "exp": "Painless obstructive jaundice + pancreatic head mass = สงสัย pancreatic adenocarcinoma → contrast CT (staging/resectability) + tissue diagnosis (EUS-FNA); Whipple ถ้า resectable. Courvoisier sign สนับสนุน malignancy.", "id": "set5-60"}, {"topic": "Mixed/Integrated", "q": "A patient with heart failure on furosemide develops muscle weakness and ECG U waves. What is the electrolyte problem and risk?", "choices": ["Hypokalemia (worsened by digoxin)", "Hyperkalemia", "Hypernatremia", "Hypercalcemia", "Hypomagnesemia only"], "ans": 0, "exp": "Loop diuretic ทำให้ hypokalemia (U wave, weakness) เพิ่มเสี่ยง arrhythmia และ digoxin toxicity. แก้ K + Mg; พิจารณา K-sparing (MRA) ที่เป็นเสาหลักใน HFrEF อยู่แล้ว.", "id": "set5-61"}, {"topic": "Mixed/Integrated", "q": "A patient with chronic kidney disease has fatigue and pallor; Hb 8.5, iron studies adequate. What is appropriate treatment?", "choices": ["Blood transfusion for all patients", "An ESA after ensuring iron stores", "High-dose IV iron only", "Vitamin B12 supplementation", "Observation only"], "ans": 1, "exp": "Anemia of CKD (EPO ต่ำ) รักษาด้วย ESA เมื่อ iron เพียงพอ, เป้า Hb ~10–11.5 (ไม่สูงเกิน — เสี่ยง CV/stroke). Transfusion เฉพาะเมื่อจำเป็น.", "id": "set5-62"}, {"topic": "Mixed/Integrated", "q": "A patient with rheumatoid arthritis on methotrexate develops a dry cough and dyspnea with new infiltrates. What must be considered?", "choices": ["Simple acute bronchitis", "Bronchial asthma", "Methotrexate pneumonitis or infection", "Gastroesophageal reflux", "An anxiety disorder"], "ans": 2, "exp": "Methotrexate อาจทำให้เกิด pneumonitis (hypersensitivity) และเพิ่มเสี่ยงการติดเชื้อ (รวม PCP/atypical) — ผู้ป่วย immunosuppressed ที่มีอาการทางเดินหายใจต้องประเมินทั้งสอง (หยุดยา, imaging, work-up).", "id": "set5-63"}, {"topic": "Mixed/Integrated", "q": "A patient presents with acute severe hypertension, headache, and pulmonary edema. Which is a hypertensive emergency requiring IV therapy?", "choices": ["Asymptomatic BP of 160/100", "White-coat hypertension", "Isolated systolic HT, no symptoms", "Hypertension with acute organ damage", "Masked hypertension"], "ans": 3, "exp": "Hypertensive emergency = BP สูง + acute target-organ damage → IV antihypertensive แบบควบคุม. Asymptomatic BP สูง (urgency) ใช้ยากินและติดตาม ไม่ต้องลดเร็ว.", "id": "set5-64"}, {"topic": "Mixed/Integrated", "q": "A patient with type 2 diabetes and a recent MI needs a glucose-lowering agent with cardiovascular benefit. Which is appropriate?", "choices": ["A sulfonylurea", "Basal insulin only", "A thiazolidinedione", "Acarbose", "A GLP-1 agonist or SGLT2 inhibitor"], "ans": 4, "exp": "T2DM + ASCVD/หลัง MI: เลือก GLP-1 RA หรือ SGLT2i ที่มีหลักฐานลด CV events โดยไม่ขึ้นกับ A1c. หลีกเลี่ยง TZD (HF), ระวัง hypoglycemia จาก sulfonylurea/insulin.", "id": "set5-65"}, {"topic": "Mixed/Integrated", "q": "A patient with fever and a heart murmur has multiple septic emboli and blood cultures positive for Staph aureus. What is the diagnosis and key imaging?", "choices": ["Infective endocarditis; echocardiography", "Rheumatic fever; ASO titer", "Acute myocarditis; cardiac MRI", "Acute pericarditis; ECG", "Pulmonary embolism; CTPA"], "ans": 0, "exp": "IE (ไข้ + murmur + emboli + positive blood culture) — ทำ echocardiography หา vegetation (TEE ไวกว่า TTE) + ให้ IV antibiotics ตามเชื้อ 4–6 สัปดาห์; ผ่าตัดตามข้อบ่งชี้ (HF, abscess, large vegetation, resistant infection).", "id": "set5-66"}, {"topic": "Mixed/Integrated", "q": "A patient with cirrhosis develops rapidly worsening renal function with a bland urinalysis and no response to volume expansion. What is the diagnosis?", "choices": ["Acute tubular necrosis", "Hepatorenal syndrome", "Acute glomerulonephritis", "Prerenal from dehydration", "Postrenal obstruction"], "ans": 1, "exp": "AKI ใน cirrhosis ที่ bland urine + ไม่ตอบสนอง albumin/volume + ตัดสาเหตุอื่น = hepatorenal syndrome. รักษาด้วย terlipressin/noradrenaline + albumin; liver transplant เป็น definitive.", "id": "set5-67"}, {"topic": "Mixed/Integrated", "q": "A patient with sepsis has lactate 5 mmol/L. What does an elevated lactate indicate and guide?", "choices": ["A completely normal finding", "Liver failure alone", "Tissue hypoperfusion guiding resuscitation", "Renal failure alone", "It can be ignored"], "ans": 2, "exp": "Lactate สูงใน sepsis สะท้อน tissue hypoperfusion/ความรุนแรง ใช้เป็นเป้า resuscitation (lactate clearance). ให้ fluid + norepinephrine + antibiotics + source control และติดตาม lactate ซ้ำ.", "id": "set5-68"}, {"topic": "Mixed/Integrated", "q": "A patient with a swollen, painful calf after a long flight has a positive D-dimer and compression ultrasound confirms DVT. What is the treatment?", "choices": ["Aspirin", "An IVC filter for all", "Thrombolysis for all", "Anticoagulation (a DOAC first-line)", "Observation only"], "ans": 3, "exp": "DVT รักษาด้วย anticoagulation (DOAC เป็น first-line ในรายไม่มีข้อห้าม); LMHW ในมะเร็ง/ตั้งครรภ์. IVC filter เฉพาะเมื่อมีข้อห้ามต่อ anticoagulation.", "id": "set5-69"}, {"topic": "Mixed/Integrated", "q": "A patient with an anaphylactic reaction has been given IM adrenaline but remains hypotensive. What is the next step?", "choices": ["Only observe the patient", "Give an oral antihistamine", "Discharge the patient", "Give a beta-blocker", "Repeat IM adrenaline plus IV fluids"], "ans": 4, "exp": "Anaphylaxis ที่ยัง hypotensive: ให้ IM adrenaline ซ้ำทุก 5–15 นาที + IV fluid bolus + พิจารณา adrenaline infusion; airway/O2. Adjunct: antihistamine, steroid. สังเกต biphasic reaction.", "id": "set5-70"}, {"topic": "Mixed/Integrated", "q": "A patient with type 1 diabetes presents with DKA. During treatment, potassium is 3.2 mEq/L. What should be done before continuing insulin?", "choices": ["Replace potassium before insulin", "Give even more insulin", "Give sodium bicarbonate", "Stop all IV fluids", "Give calcium gluconate"], "ans": 0, "exp": "ใน DKA ถ้า K < 3.3 ต้องเติม K ก่อน/ระหว่างก่อนให้ insulin เต็มที่ เพราะ insulin จะดัน K เข้าเซลล์ทำให้ hypokalemia รุนแรง (arrhythmia). ให้ fluid + monitor K ทุก 2–4 ชม.", "id": "set5-71"}, {"topic": "Mixed/Integrated", "q": "A patient develops sudden monocular vision loss ('curtain coming down') that resolves in minutes. What is this and what does it warrant?", "choices": ["A migraine aura", "Amaurosis fugax; assess carotids", "Retinal detachment", "Optic neuritis", "A cataract"], "ans": 1, "exp": "Amaurosis fugax (transient monocular blindness) = retinal TIA — ประเมิน carotid stenosis + stroke risk factors + antiplatelet/statin; carotid endarterectomy ถ้า stenosis รุนแรงมีอาการ.", "id": "set5-72"}, {"topic": "Mixed/Integrated", "q": "A patient with fever, productive cough, and consolidation has CURB-65 of 3. What is the appropriate disposition?", "choices": ["Discharge with oral antibiotics", "No treatment needed", "Admit (± ICU) for IV antibiotics", "Outpatient follow-up in a week", "Antivirals only"], "ans": 2, "exp": "CURB-65 = 3 บ่งชี้ pneumonia รุนแรง → admit (พิจารณา ICU) + IV antibiotic (β-lactam + macrolide หรือ respiratory FQ). CURB-65 0–1 มัก OPD.", "id": "set5-73"}, {"topic": "Mixed/Integrated", "q": "A patient on ACE inhibitor develops a persistent dry cough. What is the appropriate change?", "choices": ["Stop all antihypertensives", "Add a beta-blocker", "Increase the ACE inhibitor", "Switch to an ARB", "Add a long-term antitussive"], "ans": 3, "exp": "ACE inhibitor cough (จาก bradykinin) → เปลี่ยนเป็น ARB (ไม่ทำให้ไอ) โดยยังคงประโยชน์ต่อไต/หัวใจ. ระวัง angioedema (ต้องหยุดและไม่ใช้ ACEI อีก).", "id": "set5-74"}, {"topic": "Mixed/Integrated", "q": "A patient with a first unprovoked seizure has a normal exam, normal labs, and normal imaging/EEG. What is the general approach?", "choices": ["Start a lifelong drug immediately for all", "No follow-up is needed", "Proceed to immediate surgery", "Sedate the patient", "Individualized decision to start therapy"], "ans": 4, "exp": "First unprovoked seizure: ประเมินหาสาเหตุ (imaging, EEG, labs). การเริ่มยาขึ้นกับความเสี่ยงกลับเป็นซ้ำ (EEG/MRI abnormal เพิ่มเสี่ยง) — มักเริ่มหลัง seizure ที่สอง หรือรายที่เสี่ยงสูง; ให้คำแนะนำเรื่องขับรถ/ความปลอดภัย.", "id": "set5-75"}, {"topic": "Mixed/Integrated", "q": "A patient with hypertension, hypokalemia, and metabolic alkalosis has an elevated aldosterone and suppressed renin. What is the diagnosis?", "choices": ["Primary aldosteronism", "Pheochromocytoma", "Cushing syndrome", "Renal artery stenosis", "Bartter syndrome"], "ans": 0, "exp": "HT + hypokalemia + metabolic alkalosis + aldosterone สูง/renin ต่ำ = primary aldosteronism. ยืนยัน confirmatory + adrenal imaging/AVS; รักษา MRA หรือผ่าตัด (unilateral adenoma).", "id": "set5-76"}, {"topic": "Mixed/Integrated", "q": "A patient develops acute flank pain, hematuria, and imaging shows a 4 mm ureteric stone without obstruction/infection. What is appropriate management?", "choices": ["Immediate surgery", "Analgesia, hydration, and an alpha-blocker", "Antibiotics for all", "Urgent dialysis", "Chemotherapy"], "ans": 1, "exp": "นิ่วท่อไตขนาดเล็ก (< 5–10 mm) ไม่มี obstruction/ติดเชื้อ: analgesia (NSAID), hydration, medical expulsive therapy (tamsulosin) รอนิ่วหลุด + ติดตาม. Intervention ถ้านิ่วใหญ่/อุดตัน/ติดเชื้อ/ปวดคุมไม่ได้.", "id": "set5-77"}, {"topic": "Mixed/Integrated", "q": "A patient with a suspected pulmonary embolism is hemodynamically stable with a high pretest probability. What is the best test?", "choices": ["Serum D-dimer", "Chest X-ray", "CT pulmonary angiography", "Bedside echocardiography", "Sputum culture"], "ans": 2, "exp": "High pretest probability PE → CT pulmonary angiography (gold standard) โดยไม่ต้องรอ D-dimer. D-dimer มีประโยชน์เฉพาะ low/intermediate probability เพื่อ rule out.", "id": "set5-78"}, {"topic": "Mixed/Integrated", "q": "A patient with fever, jaundice, RUQ pain, hypotension, and confusion (Reynolds pentad) needs which urgent intervention?", "choices": ["Cholecystectomy first", "Observation only", "A Whipple procedure", "ERCP decompression plus antibiotics", "Paracentesis"], "ans": 3, "exp": "Reynolds pentad (Charcot triad + hypotension + confusion) = suppurative ascending cholangitis รุนแรง → resuscitate + IV antibiotics + urgent biliary decompression (ERCP). Source control สำคัญ.", "id": "set5-79"}, {"topic": "Mixed/Integrated", "q": "A patient with hyperthyroidism and new AF should receive which for rate control (and consideration for stroke prevention)?", "choices": ["Digoxin only", "Amiodarone first-line", "Adenosine", "No treatment", "Beta-blocker for rate control"], "ans": 4, "exp": "Hyperthyroid + AF: beta-blocker คุม rate/อาการ + รักษา hyperthyroid (ATD). ประเมิน anticoagulation ตาม CHA2DS2-VASc. AF มักกลับเป็น sinus เมื่อ euthyroid.", "id": "set5-80"}, {"topic": "Mixed/Integrated", "q": "A patient with severe anemia (Hb 5) from chronic GI bleeding is hemodynamically stable. What is the appropriate transfusion approach?", "choices": ["Restrictive transfusion; treat the source", "Withhold transfusion", "Transfuse up to Hb 12", "Give platelets", "Give iron only"], "ans": 0, "exp": "Chronic GI bleeding + anemia รุนแรง: ให้ PRC ตาม restrictive target (~7, หรือ 8 ในโรคหัวใจ) + iron + endoscopic investigation/treatment ของแหล่งเลือดออก (colonoscopy/EGD).", "id": "set5-81"}, {"topic": "Mixed/Integrated", "q": "A patient with newly diagnosed hypertension is young (<40) with resistant BP and an abdominal bruit. What secondary cause should be evaluated?", "choices": ["Primary aldosteronism only", "Renal artery stenosis (fibromuscular)", "Cushing syndrome only", "Pheochromocytoma only", "White-coat hypertension"], "ans": 1, "exp": "HT อายุน้อย + resistant + abdominal bruit → renal artery stenosis (young women: fibromuscular dysplasia; older: atherosclerotic). ประเมินด้วย duplex/CTA/MRA; ระวัง Cr เพิ่มหลัง ACEI.", "id": "set5-82"}, {"topic": "Mixed/Integrated", "q": "A patient with community-acquired pneumonia fails to improve after 3 days of appropriate antibiotics and develops a loculated effusion with low pH. What is needed?", "choices": ["Continue the same antibiotics only", "Observation only", "Chest tube drainage of the empyema", "Diuretic therapy", "Corticosteroids"], "ans": 2, "exp": "Complicated parapneumonic effusion/empyema (pH < 7.2, loculated, หนอง) ที่ไม่ตอบสนอง antibiotic ต้อง chest tube drainage (± intrapleural fibrinolytic/VATS). Source control สำคัญ.", "id": "set5-83"}, {"topic": "Mixed/Integrated", "q": "A patient with fatigue and pallor has a macrocytic anemia; further testing shows low B12 and anti-intrinsic factor antibodies. What is the diagnosis?", "choices": ["Folate deficiency", "Iron deficiency", "Thalassemia trait", "Pernicious anemia (B12 deficiency)", "Hemolytic anemia"], "ans": 3, "exp": "Macrocytic anemia + B12 ต่ำ + anti-intrinsic factor/parietal cell antibody = pernicious anemia (autoimmune gastritis). รักษาด้วย B12 (IM/oral high-dose); สัมพันธ์ autoimmune อื่นและ gastric cancer risk.", "id": "set5-84"}, {"topic": "Mixed/Integrated", "q": "A patient develops acute pancreatitis with a calcium of 6.5 mg/dL and tetany. What does hypocalcemia here indicate?", "choices": ["A sign of mild disease", "Underlying hyperparathyroidism", "A completely normal finding", "Vitamin D excess", "A marker of severity (fat saponification)"], "ans": 4, "exp": "Hypocalcemia ใน acute pancreatitis (จาก fat saponification/calcium sequestration) เป็นตัวบ่งชี้ความรุนแรง (Ranson criterion). แก้ symptomatic hypocalcemia + จัดการ pancreatitis.", "id": "set5-85"}, {"topic": "Mixed/Integrated", "q": "A patient with a chronic cough, weight loss, and hemoptysis has a lung mass; biopsy shows small cell carcinoma with SIADH. What is the paraneoplastic electrolyte finding?", "choices": ["Hyponatremia", "Hypercalcemia", "Hyperkalemia", "Hypernatremia", "Hypophosphatemia"], "ans": 0, "exp": "Small cell lung cancer หลั่ง ADH ectopic → SIADH → euvolemic hyponatremia. (Squamous cell → hypercalcemia จาก PTHrP). รักษา SIADH ด้วยจำกัดน้ำ + รักษามะเร็ง.", "id": "set5-86"}, {"topic": "Mixed/Integrated", "q": "A patient with acute kidney injury has hyperkalemia with ECG changes and pulmonary edema unresponsive to medical therapy. What is indicated?", "choices": ["More diuretics only", "Urgent hemodialysis", "More IV fluids", "Observation only", "Corticosteroids"], "ans": 1, "exp": "AKI ที่มี refractory hyperkalemia + pulmonary edema (overload) ที่ไม่ตอบสนองยา = ข้อบ่งชี้ urgent dialysis (AEIOU). ให้ calcium/insulin-glucose ระหว่างเตรียม dialysis.", "id": "set5-87"}, {"topic": "Mixed/Integrated", "q": "A patient with fever and neck stiffness has a petechial rash and rapid deterioration. What empiric treatment should not be delayed?", "choices": ["Antiviral therapy", "Antifungal therapy", "Immediate ceftriaxone + dexamethasone", "Observation only", "An antihistamine"], "ans": 2, "exp": "Meningococcal meningitis/septicemia (fever + neck stiffness + petechiae) — ให้ ceftriaxone ทันที (± dexamethasone) โดยไม่รอผล LP ถ้าจะ delay; แจ้ง prophylaxis ผู้สัมผัส.", "id": "set5-88"}, {"topic": "Mixed/Integrated", "q": "A patient develops warfarin-associated major GI bleeding with INR 6. What is the appropriate reversal?", "choices": ["Oral vitamin K only", "Protamine sulfate", "Fresh frozen plasma slowly only", "Prothrombin complex + vitamin K", "Platelet transfusion"], "ans": 3, "exp": "Major bleeding on warfarin: 4-factor PCC (rapid reversal) + IV vitamin K (sustained). FFP ถ้าไม่มี PCC. Protamine ใช้กับ heparin; DOAC มี specific reversal (idarucizumab/andexanet).", "id": "set5-89"}, {"topic": "Mixed/Integrated", "q": "A patient with chronic alcohol use is admitted and develops tremor, agitation, hallucinations, and autonomic instability 2–3 days after stopping. What is the diagnosis and treatment?", "choices": ["Wernicke; give thiamine only", "Sepsis; give antibiotics", "Hepatic encephalopathy; give lactulose", "Serotonin syndrome; give cyproheptadine", "Delirium tremens; benzodiazepine + thiamine"], "ans": 4, "exp": "Delirium tremens (2–3 วันหลังหยุดสุรา): agitation, hallucination, autonomic instability, seizure — รักษาด้วย benzodiazepine (symptom-triggered) + thiamine + fluids/electrolyte. เป็นภาวะที่เสียชีวิตได้.", "id": "set5-90"}, {"topic": "Mixed/Integrated", "q": "A patient with metabolic acidosis has a high anion gap; history reveals antifreeze ingestion and calcium oxalate crystals in urine. What is the diagnosis and antidote?", "choices": ["Ethylene glycol; give fomepizole", "Methanol; give ethanol", "Salicylate; give bicarbonate", "Isoniazid; give pyridoxine", "Uremia; give dialysis"], "ans": 0, "exp": "Ethylene glycol (antifreeze) → high anion gap metabolic acidosis + calcium oxalate crystals + AKI. รักษาด้วย fomepizole (block alcohol dehydrogenase) ± hemodialysis. Methanol ให้ตาบอด + fomepizole เช่นกัน.", "id": "set5-91"}, {"topic": "Mixed/Integrated", "q": "A patient with fever and right-sided flank pain, pyuria, and an obstructing stone is septic. What is the priority?", "choices": ["Antibiotics alone", "Urgent decompression plus antibiotics", "Immediate lithotripsy", "Observation only", "Diuretic therapy"], "ans": 1, "exp": "Obstructing stone + infection (infected obstructed system) เป็น urologic emergency → decompress ด่วน (ureteric stent/percutaneous nephrostomy) + antibiotic + resuscitation. Definitive stone treatment ทำภายหลัง.", "id": "set5-92"}, {"topic": "Mixed/Integrated", "q": "A patient develops acute onset dyspnea, hypoxia, and clear lungs after major long-bone fracture, with petechiae and confusion. What is the diagnosis?", "choices": ["Thrombotic pulmonary embolism", "Bacterial pneumonia", "Fat embolism syndrome", "ARDS from sepsis", "Anaphylaxis"], "ans": 2, "exp": "Fat embolism syndrome (24–72 ชม.หลัง long-bone/pelvic fracture): triad = hypoxemia + neurologic (confusion) + petechial rash. รักษาแบบ supportive (oxygen/ventilation) + early fracture fixation เพื่อป้องกัน.", "id": "set5-93"}, {"topic": "Mixed/Integrated", "q": "A patient with a large anterior STEMI develops a new harsh holosystolic murmur and acute pulmonary edema 4 days later. What mechanical complication is likely?", "choices": ["Acute pericarditis", "Reinfarction only", "Aortic dissection", "Papillary muscle or septal rupture", "Pulmonary embolism"], "ans": 3, "exp": "หลัง MI 3–7 วัน + murmur holosystolic ใหม่ + acute decompensation = mechanical complication (ventricular septal rupture หรือ acute mitral regurgitation จาก papillary muscle rupture) — emergency echo + surgical/hemodynamic support.", "id": "set5-94"}, {"topic": "Mixed/Integrated", "q": "A patient with obesity, snoring, and daytime sleepiness has resistant hypertension. Which condition should be screened for?", "choices": ["Hypothyroidism only", "Pheochromocytoma only", "Diabetes insipidus", "Addison disease", "Obstructive sleep apnea"], "ans": 4, "exp": "Resistant HT + obesity + snoring + daytime somnolence → obstructive sleep apnea (secondary/contributing cause of HT). ยืนยันด้วย sleep study; รักษาด้วย CPAP + ลดน้ำหนัก.", "id": "set5-95"}, {"topic": "Mixed/Integrated", "q": "A patient with a positive fecal occult blood test and iron deficiency anemia is 55 years old. What is the essential next investigation?", "choices": ["Colonoscopy", "Reassurance only", "Upper endoscopy only", "CT abdomen only", "Repeat FIT in a year"], "ans": 0, "exp": "FOBT/FIT บวก + IDA ในผู้ใหญ่ ≥ 45–50 ปี ต้อง colonoscopy เพื่อประเมิน colorectal cancer/polyp (± EGD ถ้า colonoscopy ปกติ). อย่าเหมาเป็น hemorrhoid โดยไม่ตรวจ.", "id": "set5-96"}, {"topic": "Mixed/Integrated", "q": "A patient with hypertension is found to have a potassium of 6.8 with peaked T waves while on an ACE inhibitor and spironolactone. What is the immediate priority?", "choices": ["Give more spironolactone", "IV calcium, then shift/remove potassium", "Increase the ACE inhibitor", "Observation only", "Give potassium"], "ans": 1, "exp": "Severe hyperkalemia (ECG changes) จากยา RAAS + K-sparing: ให้ calcium gluconate stabilize membrane → insulin/glucose + salbutamol shift → diuretic/resin/dialysis removal + หยุด ACEI/spironolactone.", "id": "set5-97"}, {"topic": "Mixed/Integrated", "q": "A patient with severe asthma exacerbation has a rising PaCO2 and is tiring despite maximal therapy. What does this indicate?", "choices": ["The patient is improving", "This is a mild attack", "Impending respiratory failure; ICU care", "This is anxiety only", "A metabolic alkalosis"], "ans": 2, "exp": "ใน severe asthma การที่ PaCO2 สูงขึ้น (แทนที่จะต่ำ) + ผู้ป่วยเหนื่อยล้า/silent chest = impending respiratory failure → ICU, เตรียม intubation, ให้ IV magnesium, systemic steroid, continuous nebulizer.", "id": "set5-98"}, {"topic": "Mixed/Integrated", "q": "A patient presents with jaundice; labs show elevated ALP and GGT with mild transaminase rise and pruritus. What pattern is this?", "choices": ["A hepatocellular pattern", "A hemolytic pattern", "Isolated indirect hyperbilirubinemia", "Cholestatic pattern; image biliary tree", "A completely normal pattern"], "ans": 3, "exp": "ALP + GGT สูงเด่น + pruritus = cholestatic pattern (obstruction/biliary disease) → imaging (US/MRCP) หา obstruction (stone, stricture, mass). ต่างจาก hepatocellular (AST/ALT สูงเด่น).", "id": "set5-99"}, {"topic": "Mixed/Integrated", "q": "A patient with type 2 diabetes presents for a routine visit. Which vaccination is particularly important to offer?", "choices": ["No vaccines are needed", "Only the rabies vaccine", "Only the tetanus vaccine", "Only the HPV vaccine", "Influenza, pneumococcal, HBV, COVID-19"], "ans": 4, "exp": "ผู้ป่วยเบาหวาน/โรคเรื้อรังควรได้วัคซีนป้องกัน influenza (ทุกปี), pneumococcal, hepatitis B, และ COVID-19 เพื่อลดภาวะแทรกซ้อนจากการติดเชื้อ. เป็นส่วนหนึ่งของ preventive care.", "id": "set5-100"}]}, {"id": "obgyn1", "title": "Ob-gyne ชุดที่ 1 — Obstetrics I (Physiology, ANC, Fetal Assessment, Labor & EFM)", "subject": "obgyn", "questions": [{"topic": "Obstetrics", "q": "A 30-year-old G2P1 woman at 32 weeks of gestation attends a routine prenatal visit and feels well. Her CBC shows hemoglobin 10.8 g/dL with a normal MCV and normal serum ferritin. Which physiological change best explains this hemoglobin value?", "choices": ["Plasma volume expansion exceeds red cell mass", "Increased red cell destruction", "Severe iron deficiency", "Suppressed bone marrow production", "Chronic occult blood loss"], "ans": 0, "exp": "Physiologic anemia of pregnancy: plasma volume เพิ่ม ~40-50% มากกว่า red cell mass (~20-30%) → hemodilution ทำให้ Hb ลดลงโดย ferritin/MCV ปกติ. เกณฑ์ anemia: Hb <11 (T1,3), <10.5 (T2)."}, {"topic": "Obstetrics", "q": "A healthy 28-year-old primigravida at 30 weeks of gestation asks how her heart has adapted to pregnancy. Compared with her pre-pregnancy state, which change in cardiac output is expected?", "choices": ["Decreased by 20 percent", "Increased by 30-50 percent", "Unchanged from baseline", "Decreased then normalized", "Increased by 5 percent only"], "ans": 1, "exp": "Cardiac output เพิ่ม 30-50% (จาก stroke volume + heart rate ~15-20 bpm) สูงสุด GA 28-32 wk และเพิ่มอีกตอนคลอด/หลังคลอด (autotransfusion). SVR ลดลง. เป็นช่วงเสี่ยงในโรคหัวใจ."}, {"topic": "Obstetrics", "q": "A 26-year-old woman at 12 weeks of gestation with mild dyspnea has an arterial blood gas showing pH 7.44, PaCO2 30 mmHg, and HCO3 19 mEq/L. Which acid-base state is this in a normal pregnancy?", "choices": ["Primary metabolic acidosis", "Primary metabolic alkalosis", "Compensated respiratory alkalosis", "Primary respiratory acidosis", "A mixed acid-base disorder"], "ans": 2, "exp": "Progesterone กระตุ้นศูนย์หายใจ → minute ventilation เพิ่ม → ขับ CO2 เกิด chronic respiratory alkalosis (PaCO2 ~30) ไตชดเชยด้วย HCO3 ต่ำ (~18-20). ค่าปกติในครรภ์."}, {"topic": "Obstetrics", "q": "A 25-year-old G1P0 at 34 weeks of gestation has routine labs showing a serum creatinine of 1.0 mg/dL. How should this be interpreted?", "choices": ["Completely normal for pregnancy", "Diagnostic of preeclampsia", "Consistent with dehydration", "Abnormally elevated for pregnancy", "Expected in third trimester"], "ans": 3, "exp": "GFR เพิ่ม ~50% ในครรภ์ → Cr ปกติ <0.8 mg/dL. Cr 1.0 ที่ปกติในคนทั่วไป จึงบ่งชี้การทำงานของไตที่แย่กว่าที่ควรในหญิงตั้งครรภ์ → ต้องประเมินเพิ่มเติม."}, {"topic": "Obstetrics", "q": "A 24-year-old primigravida with a pre-pregnancy BMI of 22 kg/m2 asks how much weight she should gain. Per Institute of Medicine guidance, what is the recommended total gestational weight gain?", "choices": ["5-9 kg", "7-11.5 kg", "18-20 kg", "12.5-18 kg", "11.5-16 kg"], "ans": 4, "exp": "น้ำหนักเพิ่มตาม BMI: ผอม 12.5-18, ปกติ (18.5-24.9) 11.5-16, น้ำหนักเกิน 7-11.5, อ้วน 5-9 kg. BMI 22 = ปกติ → 11.5-16 kg."}, {"topic": "Obstetrics", "q": "A 29-year-old G2P1 at 36 weeks develops near-syncope whenever she lies supine, relieved by turning onto her side. Her supine BP is 88/54 mmHg. What is the most appropriate immediate step?", "choices": ["Left lateral positioning", "High-flow oxygen only", "Intravenous vasopressor", "Large fluid bolus first", "Elevate legs while supine"], "ans": 0, "exp": "Supine hypotensive syndrome: มดลูกกด IVC ในท่านอนหงาย → venous return ลด → BP ตก. แก้ทันทีด้วยการตะแคงซ้าย (เลื่อนมดลูกออกจาก IVC)."}, {"topic": "Obstetrics", "q": "A 27-year-old woman with irregular cycles is unsure of her last menstrual period and presents at about 9 weeks. Which method most accurately estimates gestational age?", "choices": ["Biparietal diameter", "Crown-rump length", "Abdominal circumference", "Femur length", "Amniotic fluid index"], "ans": 1, "exp": "Crown-rump length ไตรมาสแรก (ถึง ~13+6 wk) แม่นสุด (±5-7 วัน). เมื่อ LMP ไม่แน่นอน/ต่างจาก US เกินเกณฑ์ ให้ยึด US ไตรมาสแรก."}, {"topic": "Obstetrics", "q": "A 23-year-old primigravida presents for her first prenatal visit at 8 weeks. Per the WHO 2016 model, what is the recommended minimum number of antenatal care contacts?", "choices": ["Six contacts", "Ten contacts", "Eight contacts", "Four contacts", "Twelve contacts"], "ans": 2, "exp": "[อัปเดต] WHO 2016 เปลี่ยนจาก 4 เป็น ≥8 contacts เพื่อลดการตายปริกำเนิด: ครั้งแรก <12 wk ตามด้วย 20,26,30,34,36,38,40 wk."}, {"topic": "Obstetrics", "q": "A 22-year-old woman at her first prenatal visit is screened for syphilis. Which test is used for this screening?", "choices": ["HBsAg", "Anti-HIV antibody", "Hemoglobin typing", "VDRL or RPR", "Urine culture"], "ans": 3, "exp": "VDRL/RPR (non-treponemal) คัดกรองซิฟิลิสทุกราย. Congenital syphilis รักษาด้วย penicillin (แพ้ต้อง desensitize)."}, {"topic": "Obstetrics", "q": "A 26-year-old G2P1 at 30 weeks receives vaccination counseling. What is the optimal gestational window for the Tdap vaccine in each pregnancy?", "choices": ["Before 12 weeks", "16-20 weeks", "Contraindicated in pregnancy", "After delivery only", "27-36 weeks"], "ans": 4, "exp": "Tdap ทุกครรภ์ที่ GA 27-36 wk เพื่อให้แม่สร้างแอนติบอดีผ่านรกป้องกันไอกรนในทารก. วัคซีนเชื้อเป็น (MMR, VZV) ห้ามในครรภ์."}, {"topic": "Obstetrics", "q": "A 33-year-old woman at 12 weeks undergoes first-trimester combined aneuploidy screening. Which combination of markers is used?", "choices": ["NT, PAPP-A, free beta-hCG", "AFP, hCG, estriol", "BPD, FL, AC", "Inhibin A and AFP", "NST and BPP"], "ans": 0, "exp": "First-trimester combined (11-13+6 wk) = NT + PAPP-A + free β-hCG (จับ Down ~85%). Down: PAPP-A ต่ำ, β-hCG สูง, NT หนา. Quad test ทำไตรมาส 2."}, {"topic": "Obstetrics", "q": "A 30-year-old G1P0 at 17 weeks has quadruple screening showing a markedly elevated maternal serum AFP. This most suggests which fetal condition?", "choices": ["Trisomy 21", "Open neural tube defect", "Trisomy 18", "Trisomy 13", "Turner syndrome"], "ans": 1, "exp": "MSAFP สูงใน open neural tube defect (spina bifida, anencephaly) และ abdominal wall defect. Down: AFP/estriol ต่ำ, hCG/inhibin A สูง; trisomy 18 ต่ำทุกตัว."}, {"topic": "Obstetrics", "q": "A 38-year-old G3P2 at 11 weeks asks about cell-free fetal DNA testing (NIPT). Which statement is correct?", "choices": ["It is diagnostic and definitive", "It only determines fetal sex", "It is a highly sensitive screening test", "It requires amniocentesis", "It replaces the anomaly scan"], "ans": 2, "exp": "[อัปเดต] NIPT sensitivity สูงมาก (>99% สำหรับ T21) แต่เป็น screening — ผลบวกต้องยืนยันด้วย diagnostic (amniocentesis/CVS). ACOG เสนอได้ทุกระดับความเสี่ยง."}, {"topic": "Obstetrics", "q": "A 36-year-old G2P1 chooses diagnostic karyotyping by amniocentesis. What is the earliest gestational age at which amniocentesis is typically performed?", "choices": ["6-9 weeks", "At or after 28 weeks", "10-13 weeks", "At or after 15 weeks", "After delivery only"], "ans": 3, "exp": "Amniocentesis ทำเมื่อ GA ≥15 wk (early amnio <15 เพิ่มความเสี่ยง). CVS ทำได้ 10-13 wk. ทั้งคู่เป็น diagnostic เสี่ยงแท้ง ~0.1-0.3%."}, {"topic": "Obstetrics", "q": "A 34-year-old G1P0 at 33 weeks undergoes an NST. Over 20 minutes there are two accelerations of at least 15 bpm lasting at least 15 seconds each. How is this interpreted?", "choices": ["Nonreactive tracing", "Positive contraction stress test", "Sinusoidal pattern", "Absent variability", "Reactive tracing"], "ans": 4, "exp": "NST reactive (≥32 wk) = acceleration ≥2 ครั้ง เพิ่ม ≥15 bpm นาน ≥15 วินาที ใน 20 นาที → fetal wellbeing. <32 wk ใช้เกณฑ์ 10×10."}, {"topic": "Obstetrics", "q": "A 32-year-old G2P1 at 36 weeks with gestational hypertension has a biophysical profile of 4/10 with oligohydramnios. What does this indicate?", "choices": ["Concerning for fetal compromise", "Normal fetus", "Fetal sleep cycle only", "Maternal dehydration only", "Reassuring result"], "ans": 0, "exp": "BPP 8-10 ปกติ, 6 equivocal, ≤4 ผิดปกติ เสี่ยง fetal asphyxia → พิจารณาคลอดตามอายุครรภ์. Oligohydramnios เพิ่มความน่ากังวลเสมอ."}, {"topic": "Obstetrics", "q": "A 31-year-old G3P2 at 38 weeks has an ultrasound reporting an amniotic fluid index of 4 cm. This is consistent with which condition?", "choices": ["Normal fluid", "Oligohydramnios", "Polyhydramnios", "Fetal macrosomia", "Twin gestation"], "ans": 1, "exp": "Oligohydramnios: AFI <5 cm หรือ single deepest pocket <2 cm. สาเหตุ: uteroplacental insufficiency (FGR), PROM, renal agenesis, post-term. AFI >25 = polyhydramnios."}, {"topic": "Obstetrics", "q": "A laboring woman's care team reviews the cardinal movements of labor. Which sequence is correct?", "choices": ["Descent, engagement, flexion, extension", "Flexion, engagement, extension, rotation", "Engagement, descent, flexion, internal rotation, extension", "Internal rotation, engagement, flexion, descent", "Engagement, extension, flexion, descent"], "ans": 2, "exp": "กลไกการคลอด: Engagement → Descent → Flexion → Internal rotation → Extension → External rotation → Expulsion. Flexion ทำให้ diameter เล็กสุด (suboccipitobregmatic) ผ่านเชิงกราน."}, {"topic": "Obstetrics", "q": "A 28-year-old G1P0 is in labor. Per current ACOG/Consortium definitions, the active phase of the first stage begins at what cervical dilation?", "choices": ["Two centimeters", "Three centimeters", "Four centimeters", "Six centimeters", "Eight centimeters"], "ans": 3, "exp": "[อัปเดต] active phase เริ่มที่ 6 cm (เดิม 4 cm) เพราะ latent phase อาจยาวได้ปกติ → ลดการวินิจฉัย arrest ผิดและลดผ่าคลอดเกินจำเป็น."}, {"topic": "Obstetrics", "q": "A 29-year-old G2P1 in labor reaches 6 cm with ruptured membranes, then shows no cervical change over 4 hours despite adequate contractions (over 200 Montevideo units). What is the diagnosis?", "choices": ["Prolonged latent phase", "Precipitous labor", "Second stage arrest", "Normal progress", "Active phase arrest"], "ans": 4, "exp": "Active phase arrest: ≥6 cm, ถุงน้ำแตก, ไม่มี cervical change ≥4 ชม.ทั้งที่ contraction เพียงพอ (≥200 MVU) → ข้อบ่งชี้พิจารณาผ่าคลอด."}, {"topic": "Obstetrics", "q": "A 24-year-old nulliparous woman without epidural has been pushing in the second stage. Beyond approximately what duration is the second stage considered prolonged (per ACOG)?", "choices": ["Three hours", "Four hours", "Thirty minutes", "One hour", "Two hours"], "ans": 0, "exp": "Stage 2: ครรภ์แรกยอมได้ ~3 ชม. (มี epidural +1), ครรภ์หลัง ~2 ชม. (มี epidural +1) ตราบใดที่มี progress และ FHR ปกติ."}, {"topic": "Obstetrics", "q": "Immediately after delivery of the infant, the team performs active management of the third stage to reduce hemorrhage. Which component is most important?", "choices": ["Waiting 60 minutes for the placenta", "Oxytocin administration", "Ergometrine before infant delivery", "Immediate vigorous cord traction", "Fundal massage before placenta"], "ans": 1, "exp": "Active management: (1) oxytocin หลังคลอดไหล่หน้า/ทารก, (2) controlled cord traction, (3) uterine massage. องค์ประกอบสำคัญสุดคือ oxytocin."}, {"topic": "Obstetrics", "q": "During the third stage, the physician notes cord lengthening, a firm globular uterus, and a sudden gush of blood. What do these signs indicate?", "choices": ["Uterine inversion", "Uterine atony", "Placental separation", "Cord prolapse", "Retained placenta"], "ans": 2, "exp": "สัญญาณรกลอกตัว: สายสะดือยาวขึ้น, มดลูกกลมแข็งลอยสูง, เลือดออกกะทันหัน. เมื่อพบจึงทำ controlled cord traction."}, {"topic": "Obstetrics", "q": "A 28-year-old G1P0 at 40 weeks on oxytocin has an EFM baseline of 140 bpm with moderate variability and recurrent gradual decelerations beginning after each contraction peak and returning to baseline after the contraction ends. What is the most likely cause?", "choices": ["Fetal head compression", "Normal sleep cycle", "Umbilical cord compression", "Uteroplacental insufficiency", "Maternal fever"], "ans": 3, "exp": "Late deceleration = FHR ลดค่อยเป็นค่อยไป จุดต่ำสุดหลัง peak → uteroplacental insufficiency. Early = head compression; Variable รูปตัว V = cord compression."}, {"topic": "Obstetrics", "q": "A term fetus on EFM shows absent baseline variability with recurrent late decelerations. By the NICHD 3-tier system, this is which category?", "choices": ["Category II", "Reactive", "Category I", "Indeterminate", "Category III"], "ans": 4, "exp": "Category III = absent variability + recurrent late/variable decel หรือ bradycardia; หรือ sinusoidal → แก้ไขทันทีและเตรียมคลอดเร่งด่วน. Category I ปกติ, II พบบ่อยสุด."}, {"topic": "Obstetrics", "q": "A laboring woman develops recurrent variable decelerations. Which intrauterine resuscitation measure is INAPPROPRIATE?", "choices": ["Increase the oxytocin rate", "Left lateral positioning", "Maternal oxygen", "Intravenous fluid bolus", "Exclude cord prolapse"], "ans": 0, "exp": "Intrauterine resuscitation: ตะแคงซ้าย, O2, IV fluid, 'หยุด/ลด oxytocin', ตรวจแยก cord prolapse, พิจารณา tocolytic. การเพิ่ม oxytocin ทำให้ tachysystole → ทารกแย่ลง."}, {"topic": "Obstetrics", "q": "An EFM tracing shows moderate baseline variability of 6-25 bpm. What does moderate variability most reliably indicate?", "choices": ["Fetal sleep state present", "Normal fetal oxygenation status", "Maternal fever developing", "Rapid cervical dilation", "Early placental separation"], "ans": 1, "exp": "Moderate variability (6-25 bpm) เป็นตัวบ่งชี้ดีที่สุดว่าทารกมี oxygenation/acid-base ปกติ (ไม่มี metabolic acidosis ขณะนั้น). Absent/minimal + deceleration จึงน่ากังวล."}, {"topic": "Obstetrics", "q": "To monitor labor progress and guide intervention, the team plots cervical dilation, descent, fetal heart rate, and contractions over time. Which tool is this?", "choices": ["Bishop score", "Apgar score", "Partograph", "Ballard score", "Silverman score"], "ans": 2, "exp": "Partograph (WHO Labour Care Guide 2020) บันทึกการเปิดปากมดลูก การเคลื่อนต่ำ FHR contraction ช่วยตรวจจับ labor ผิดปกติแต่เนิ่นๆ. Bishop ประเมินความพร้อมชักนำคลอด."}, {"topic": "Obstetrics", "q": "When evaluating labor dystocia, the physician considers the '3 Ps.' Which option lists them correctly?", "choices": ["Pain, Position, Pressure", "Progress, Passage, Pain", "Placenta, Presentation, Pelvis", "Power, Passage, Passenger", "Parity, Position, Power"], "ans": 3, "exp": "3P: Power (contraction), Passage (ช่องเชิงกราน/CPD), Passenger (ทารก - ขนาด/ท่า). ช่วยหาสาเหตุ dystocia และวางแผน."}, {"topic": "Obstetrics", "q": "A couple attends preconception counseling and both are found to be carriers of alpha-thalassemia-1 trait. For which condition is their fetus at risk?", "choices": ["Beta-thalassemia major alone", "Hemoglobin E trait", "Hemoglobin H disease", "G6PD deficiency", "Hemoglobin Bart's hydrops fetalis"], "ans": 4, "exp": "α-thal 1 ทั้งคู่: โอกาส 1/4 ลูกเป็น homozygous (--/--) = Hb Bart's hydrops fetalis (บวมน้ำ เสียชีวิต, แม่เสี่ยง preeclampsia). เป็นข้อบ่งชี้ prenatal diagnosis."}, {"topic": "Obstetrics", "q": "A 25-year-old woman planning pregnancy with no prior affected child asks about supplementation. What is the recommended daily dose of folic acid?", "choices": ["400-600 micrograms", "4 milligrams", "1 milligram weekly", "10 milligrams", "No supplement needed"], "ans": 0, "exp": "หญิงทั่วไป โฟเลต 400-600 µg/วัน เริ่ม ≥1 เดือนก่อนตั้งครรภ์. ผู้เคยมีลูก NTD/ใช้ยากันชักบางชนิดใช้ 4 mg/วัน. ลด neural tube defect."}, {"topic": "Obstetrics", "q": "A 27-year-old woman at 9 weeks has a mildly suppressed TSH without symptoms. Which mechanism best explains this early-pregnancy finding?", "choices": ["Graves disease in all cases", "hCG stimulation of the TSH receptor", "Pituitary failure", "Iodine deficiency", "Decreased thyroid-binding globulin"], "ans": 1, "exp": "hCG มี α-subunit คล้าย TSH กระตุ้น TSH receptor อ่อนๆ ในไตรมาสแรก → free T4 เพิ่มเล็กน้อย → กด TSH ชั่วคราว มักหายเอง. TBG เพิ่ม (total T4/T3 สูง แต่ free ปกติ)."}, {"topic": "Obstetrics", "q": "A 28-year-old G2P1 without high-risk features is scheduled for gestational diabetes screening. At what gestational age is routine screening performed?", "choices": ["8-12 weeks", "16-20 weeks", "24-28 weeks", "32-36 weeks", "After delivery"], "ans": 2, "exp": "คัดกรอง GDM ที่ GA 24-28 wk (ช่วง insulin resistance เด่น). ความเสี่ยงสูงคัดกรองตั้งแต่ฝากครรภ์ครั้งแรกและตรวจซ้ำ 24-28 ถ้าครั้งแรกปกติ."}, {"topic": "Obstetrics", "q": "A 26-year-old Rh(D)-negative woman with no anti-D antibodies is at 28 weeks. When should routine antenatal anti-D immunoglobulin be given?", "choices": ["During labor only", "After delivery only", "At 12 weeks only", "At 28 weeks", "Never without antibodies"], "ans": 3, "exp": "Anti-D routine ที่ GA 28 wk และภายใน 72 ชม.หลังคลอดถ้าทารก Rh positive. ให้เพิ่มหลังเหตุการณ์เสี่ยง FMH (แท้ง, ectopic, เจาะน้ำคร่ำ, trauma, ECV)."}, {"topic": "Obstetrics", "q": "A 24-year-old G1P0 at 32 weeks has a symphysis-fundal height of 27 cm. What is the most appropriate first consideration?", "choices": ["Fetal macrosomia", "Polyhydramnios alone", "Molar pregnancy alone", "Twin gestation alone", "Fetal growth restriction"], "ans": 4, "exp": "SFH(cm) ≈ อายุครรภ์ ±2-3 (20-36 wk). SFH น้อยกว่า >3 cm บ่งชี้ FGR/oligohydramnios/dating ผิด → ทำ US ประเมิน EFW และน้ำคร่ำ."}, {"topic": "Obstetrics", "q": "A 30-year-old G2P1 at 40 weeks is considered for induction, and a Bishop score is calculated. A high Bishop score indicates which of the following?", "choices": ["Favorable cervix for induction", "A healthy neonate", "The level of labor pain", "Severe preeclampsia", "Fetal lung maturity"], "ans": 0, "exp": "Bishop score ประเมินปากมดลูก 5 องค์ประกอบ. ≥8 = favorable โอกาสชักนำคลอดสำเร็จสูง. <6 อาจต้อง cervical ripening ก่อน."}, {"topic": "Obstetrics", "q": "A 29-year-old G1P0 at 41 weeks with an unfavorable cervix (Bishop score 3) requires induction. Which agent is appropriate for cervical ripening?", "choices": ["Terbutaline tocolysis", "Prostaglandin (misoprostol)", "Oxytocin infusion", "Indomethacin", "Magnesium sulfate"], "ans": 1, "exp": "Cervical ripening ใช้ prostaglandin (misoprostol/dinoprostone) หรือ Foley balloon. Oxytocin ใช้เมื่อปากมดลูกพร้อม. ห้าม misoprostol ในผู้เคยผ่าคลอด (เสี่ยง rupture)."}, {"topic": "Obstetrics", "q": "A 28-year-old G2P1 is evaluated for induction of labor. Which of the following is a valid indication?", "choices": ["Every nulliparous patient", "Breech presentation", "Post-term pregnancy", "Complete placenta previa", "Prior classical cesarean"], "ans": 2, "exp": "ข้อบ่งชี้ induction: post-term ≥41 wk, PROM, HT/preeclampsia, GDM คุมไม่ดี, IUGR, IUFD, chorioamnionitis. Previa totalis/ท่าขวาง/แผล classical = ข้อห้าม."}, {"topic": "Obstetrics", "q": "Immediately after birth, a neonate is assessed with the Apgar score. Which five components make up the score?", "choices": ["Alertness, Pulse, Grip, Activity, Rate", "Airway, Pulse, Growth, Activity, Reflex", "Apnea, Pulse, Grimace, Airway, Reflex", "Appearance, Pulse, Grimace, Activity, Respiration", "Appearance, Pressure, Grimace, Age, Rate"], "ans": 3, "exp": "Apgar = Appearance, Pulse, Grimace, Activity, Respiration ประเมินที่ 1 และ 5 นาที แต่ละอย่าง 0-2 คะแนน. ใช้ประเมินสภาพและการตอบสนองต่อการกู้ชีพ."}, {"topic": "Obstetrics", "q": "A 24-year-old G1P0 at 39 weeks is in labor with the cervix dilated 4 cm, unchanged over 3 hours. How should this be classified?", "choices": ["Second stage arrest", "Active phase arrest", "Prolonged third stage", "Precipitous labor", "Latent phase"], "ans": 4, "exp": "active phase เริ่มที่ 6 cm ดังนั้น 4 cm ยังเป็น latent phase. Prolonged latent phase ไม่ใช่ arrest และไม่ควรผ่าคลอดด้วยเหตุนี้เพียงอย่างเดียว — รอ, oxytocin/amniotomy ได้."}, {"topic": "Obstetrics", "q": "A laboring woman receives epidural analgesia. Which side effect should the physician anticipate?", "choices": ["Maternal hypotension", "Fetal malformation", "Permanent loss of contractions", "Marked rise in cesarean rate", "Uterine rupture"], "ans": 0, "exp": "Epidural อาจทำให้ maternal hypotension (sympathetic block) → ให้ IV fluid, เฝ้า BP/FHR. อาจทำให้ stage 2 ยาวขึ้นเล็กน้อย แต่ไม่เพิ่มผ่าคลอดอย่างมีนัยสำคัญ และไม่ทำให้ทารกพิการ."}, {"topic": "Obstetrics", "q": "During a vaginal delivery, the physician considers episiotomy. Per current evidence, when is episiotomy indicated?", "choices": ["Routinely in all deliveries", "Only when specifically indicated", "To reduce labor pain", "To always prevent laceration", "For cosmetic reasons"], "ans": 1, "exp": "ไม่แนะนำ routine episiotomy (restrictive use). ทำเมื่อมีข้อบ่งชี้: เร่งคลอด (fetal distress), shoulder dystocia, operative delivery. Mediolateral ลด severe tear เทียบ midline."}, {"topic": "Obstetrics", "q": "After delivery, a perineal laceration extends into the anal sphincter but not through the rectal mucosa. What degree is this?", "choices": ["First degree", "Second degree", "Third degree", "Cervical laceration", "Fourth degree"], "ans": 2, "exp": "1st = ผิวหนัง/mucosa, 2nd = ถึง muscle (ไม่ถึงหูรูด), 3rd = ถึง anal sphincter, 4th = ทะลุ rectal mucosa. 3rd/4th (OASIS) ต้องซ่อมพิถีพิถัน เฝ้าระวัง fecal incontinence."}, {"topic": "Obstetrics", "q": "One hour after an uncomplicated delivery, the physician palpates the uterus. Which finding indicates good uterine tone?", "choices": ["Soft and above the umbilicus", "Boggy and deviated right", "Not palpable at all", "Firm at or below the umbilicus", "Below the symphysis pubis"], "ans": 3, "exp": "หลังคลอดมดลูกควรกลมแข็งอยู่ระดับสะดือหรือต่ำกว่า. ถ้านุ่ม (boggy) และสูงขึ้น = uterine atony (สาเหตุ PPH บ่อยสุด) → นวดมดลูก + uterotonic."}, {"topic": "Obstetrics", "q": "In the mechanism of labor, engagement of the fetal head is defined as which event?", "choices": ["The head passes the pelvic outlet", "Complete cervical dilation", "Internal rotation of the fetal head", "Rupture of the membranes", "Biparietal diameter passes the pelvic inlet"], "ans": 4, "exp": "Engagement = biparietal diameter ผ่านระดับ pelvic inlet (leading part ที่ ischial spine = station 0). ครรภ์แรกมักเกิดก่อนเจ็บครรภ์; ครรภ์หลังตอนเจ็บครรภ์."}, {"topic": "Obstetrics", "q": "During a vaginal examination, the fetal presenting bony part is at the level of the ischial spines. What station is this?", "choices": ["Station zero", "At the pelvic inlet", "At the pelvic outlet", "Floating high", "Dilated zero centimeters"], "ans": 0, "exp": "Station เทียบกับ ischial spines: 0 = ระดับ spines (engaged), ลบ = อยู่เหนือ, บวก = ต่ำกว่า (+5 = crowning). ใช้ติดตาม descent ในระยะที่ 2."}, {"topic": "Obstetrics", "q": "A woman with regular 28-day cycles reports her last menstrual period began January 1. Using Naegele's rule, what is her estimated date of delivery?", "choices": ["September 8", "October 8", "October 1", "September 24", "November 1"], "ans": 1, "exp": "Naegele: EDD = LMP + 7 วัน - 3 เดือน. 1 ม.ค. +7 = 8 ม.ค. -3 เดือน = 8 ต.ค. → EDD 8 ตุลาคม. ใช้เมื่อรอบสม่ำเสมอ 28 วัน; ไม่แน่นอนยึด US."}, {"topic": "Obstetrics", "q": "A woman with a twin pregnancy is counseled about chorionicity. When and how is chorionicity best determined?", "choices": ["Third trimester by palpation", "By serum beta-hCG", "First trimester by ultrasound", "After delivery by placenta", "By amniocentesis always"], "ans": 2, "exp": "ประเมิน chorionicity ในไตรมาสแรก (แม่นสุด 11-14 wk): lambda/twin-peak = dichorionic, T-sign = monochorionic. สำคัญสุดเพราะ monochorionic เสี่ยง TTTS."}, {"topic": "Obstetrics", "q": "A healthy 26-year-old at 34 weeks has a white cell count of 14,000/mm3 with neutrophil predominance and no symptoms of infection. How is this interpreted?", "choices": ["Requires antibiotics now", "Always indicates infection", "Indicates leukemia", "A normal physiologic change", "Lymphocyte elevation only"], "ans": 3, "exp": "WBC เพิ่มได้ปกติในครรภ์ (มัก 9,000-15,000, คลอดถึง 25,000) เป็น neutrophilia โดยไม่ติดเชื้อ. แปลผลต้องใช้ร่วมกับอาการทางคลินิก."}, {"topic": "Obstetrics", "q": "A 29-year-old G1P0 at 41 weeks with a reactive NST and AFI of 6 cm is counseled. What is the most appropriate recommendation?", "choices": ["Wait until 43 weeks", "Immediate cesarean delivery", "Discontinue prenatal care", "Administer tocolytics", "Induction of labor"], "ans": 4, "exp": "ที่ GA 41 wk แนะนำ induction เพื่อลด stillbirth, meconium aspiration, macrosomia ที่เพิ่มหลัง 41 wk. หลักฐานสนับสนุน induction ที่ 41 wk ดีกว่ารอ."}, {"topic": "Obstetrics", "q": "A 30-year-old at 36 weeks is at increased risk of venous thromboembolism. Which physiological change accounts for this hypercoagulable state?", "choices": ["Increased clotting factors and stasis", "Increased protein S levels", "Increased fibrinolysis", "Very high platelet count", "Increased antithrombin"], "ans": 0, "exp": "ครรภ์เป็น hypercoagulable state: เพิ่ม fibrinogen, factor VII/VIII/X/vWF; ลด protein S/fibrinolysis; venous stasis. เสี่ยง VTE เพิ่ม 4-5 เท่า สูงสุดหลังคลอด."}, {"topic": "Obstetrics", "q": "A 32-year-old at 34 weeks reports decreased fetal movements, counting only 5 movements over 2 hours. What is the most appropriate action?", "choices": ["Observe at home 1 week", "Evaluation with NST/BPP", "Reassure as normal", "Deliver immediately", "Give hematinics"], "ans": 1, "exp": "Fetal movement count ผิดปกติ (<10 ครั้ง/2 ชม.) เป็นสัญญาณเตือน ควรมาประเมิน NST/BPP เพื่อค้นหา fetal compromise ไม่ควรรอสังเกตนานที่บ้าน."}, {"topic": "Obstetrics", "q": "A growth-restricted fetus undergoes umbilical artery Doppler, which shows absent end-diastolic flow. What does this indicate?", "choices": ["A normal healthy fetus", "Twin pregnancy", "Severe placental insufficiency", "Excess amniotic fluid", "Intrauterine infection"], "ans": 2, "exp": "Absent/reversed end-diastolic flow บ่งชี้ placental resistance สูงมาก = severe placental insufficiency สัมพันธ์ perinatal mortality สูง → ข้อบ่งชี้พิจารณาคลอด."}, {"topic": "Obstetrics", "q": "A pregnant woman is scheduled for GBS screening by vaginal-rectal culture. Per current ACOG guidance, at what gestational age is this performed?", "choices": ["28-30 weeks", "32-34 weeks", "During labor only", "36 0/7 to 37 6/7 weeks", "At delivery only"], "ans": 3, "exp": "[อัปเดต] ACOG 2020 เลื่อน GBS screening เป็น 36 0/7 - 37 6/7 wk (เดิม 35-37) ให้ culture ครอบคลุมนานขึ้น. ผลบวก → intrapartum penicillin."}, {"topic": "Obstetrics", "q": "A GBS-colonized woman is in labor. Which antibiotic is preferred for intrapartum prophylaxis?", "choices": ["Vancomycin", "Metronidazole", "Doxycycline", "Gentamicin", "Penicillin G"], "ans": 4, "exp": "Penicillin G IV เป็นตัวแรก (ampicillin ทางเลือก). แพ้ penicillin: cefazolin, clindamycin (เชื้อไว), vancomycin (ดื้อ). ให้ ≥4 ชม.ก่อนคลอด."}, {"topic": "Obstetrics", "q": "A 32-year-old multipara delivers within 2 hours of the onset of regular contractions. What is this called?", "choices": ["Precipitous labor", "Prolonged labor", "Arrest of labor", "Protracted labor", "Latent labor"], "ans": 0, "exp": "Precipitous labor = คลอดภายใน <3 ชม.นับจากเริ่มเจ็บครรภ์ พบบ่อยในครรภ์หลัง. เสี่ยง laceration, PPH (atony), amniotic fluid embolism."}, {"topic": "Obstetrics", "q": "A 30-year-old G2P1 with a breech fetus at 37 weeks is offered external cephalic version. At what gestational age is ECV typically performed?", "choices": ["28 weeks", "About 37 weeks", "32 weeks", "41 weeks", "During active labor"], "ans": 1, "exp": "ECV มักทำที่ ~37 wk (term): ถ้าเร็วไปทารกอาจกลับท่าก้น, ถ้าเกิดภาวะแทรกซ้อนก็คลอดทารกครบกำหนดได้. ทำภายใต้ US เตรียมผ่าคลอดฉุกเฉิน; anti-D ถ้า Rh negative."}, {"topic": "Obstetrics", "q": "In a vigorous term newborn, the physician delays cord clamping for 30-60 seconds. What is the main benefit?", "choices": ["Reduced jaundice", "Reduced birth weight", "Increased iron stores", "Prevention of GBS", "Less respiratory effort"], "ans": 2, "exp": "Delayed cord clamping เพิ่ม blood volume, hemoglobin, iron store (ลด anemia); ในทารกก่อนกำหนดลด IVH/NEC. ข้อเสียเล็กน้อยคือ jaundice ที่ต้อง phototherapy เพิ่มเล็กน้อย."}, {"topic": "Obstetrics", "q": "A postpartum woman is followed. What is the correct sequence of lochia color change?", "choices": ["Alba, serosa, rubra", "Serosa, alba, rubra", "Rubra, alba, serosa", "Rubra, serosa, alba", "No color change"], "ans": 3, "exp": "Lochia: rubra (แดง, 1-4 วัน) → serosa (ชมพู-น้ำตาล, 4-10 วัน) → alba (ขาว-เหลือง, 2-6 สัปดาห์). กลับเป็นแดงสด/มีกลิ่นบ่งชี้ปัญหา (retained products, endometritis)."}, {"topic": "Obstetrics", "q": "A healthy pregnant woman has trace glucosuria on urine dipstick. What is the most common explanation?", "choices": ["Diabetes in all cases", "Excessive sugar intake", "Renal failure", "Urinary tract infection", "Lowered renal glucose threshold"], "ans": 4, "exp": "GFR เพิ่มในครรภ์ → renal glucose threshold ลด เกิด glucosuria ได้แม้น้ำตาลในเลือดปกติ. อย่างไรก็ตามควรคัดกรอง GDM ตามปกติ."}, {"topic": "Obstetrics", "q": "A woman in the transverse lie at 39 weeks presents in labor. What is the appropriate mode of delivery?", "choices": ["Cesarean section", "Vaginal delivery", "Forceps delivery", "Vacuum extraction", "Await spontaneous rotation"], "ans": 0, "exp": "Transverse lie คลอดทางช่องคลอดไม่ได้ (ไม่มีส่วนนำเหมาะ) → ผ่าคลอด. เสี่ยง cord prolapse/uterine rupture ถ้าปล่อยไว้."}, {"topic": "Obstetrics", "q": "A term newborn of a mother with poorly controlled gestational diabetes is at greatest risk of which early complication?", "choices": ["Hyperbilirubinemia only", "Neonatal hypoglycemia", "Cataract", "Necrotizing enterocolitis", "Congenital heart block"], "ans": 1, "exp": "ทารกจากแม่ GDM มี fetal hyperinsulinemia → เสี่ยง neonatal hypoglycemia (ต้องตรวจน้ำตาลหลังเกิด), macrosomia, shoulder dystocia, RDS, hyperbilirubinemia, polyhydramnios."}, {"topic": "Obstetrics", "q": "A 25-year-old G1P0 at 38 weeks in labor has an EFM showing early decelerations that mirror the contractions. What is the underlying cause?", "choices": ["Uteroplacental insufficiency", "Umbilical cord compression", "Fetal head compression", "Fetal anemia", "Maternal fever"], "ans": 2, "exp": "Early deceleration = FHR ลดพร้อม contraction แบบ mirror image เกิดจาก fetal head compression (vagal reflex) เป็นภาวะปกติ ไม่ต้องแทรกแซง. ต่างจาก late (uteroplacental) และ variable (cord)."}, {"topic": "Obstetrics", "q": "A 27-year-old at 39 weeks has ruptured membranes with clear fluid but no contractions after 18 hours. She is GBS positive. What is the most appropriate management?", "choices": ["Expectant care for 1 week", "Tocolysis", "Immediate cesarean delivery", "Induction with GBS prophylaxis", "Corticosteroids"], "ans": 3, "exp": "Term PROM ที่ไม่เข้าสู่ระยะคลอดเอง → induction (ลด chorioamnionitis/neonatal infection) พร้อม GBS intrapartum prophylaxis. ไม่ต้อง steroid/tocolytic เพราะครบกำหนด."}, {"topic": "Obstetrics", "q": "A 26-year-old at 8 weeks by LMP has a transvaginal ultrasound showing a gestational sac with a fetal pole but no cardiac activity; measurements correspond to 8 weeks. What best describes this finding requiring confirmation?", "choices": ["Definite viable pregnancy", "Complete spontaneous abortion", "Tubal ectopic pregnancy", "Complete molar pregnancy", "Early pregnancy loss likely"], "ans": 4, "exp": "CRL ที่วัดได้สอดคล้อง 8 wk แต่ไม่มี cardiac activity บ่งชี้ early pregnancy loss (missed abortion) — ควรยืนยันตามเกณฑ์ (CRL ≥7 mm ไม่มี cardiac activity) หรือ US ซ้ำก่อนจัดการ."}, {"topic": "Obstetrics", "q": "A woman at 39 weeks with a fetus in breech presentation and adequate pelvis is counseled on delivery. What is the most widely recommended approach for a term breech today?", "choices": ["Planned cesarean delivery", "Vaginal breech delivery always", "Await spontaneous version", "Forceps-assisted delivery", "Oxytocin augmentation"], "ans": 0, "exp": "ตาม Term Breech Trial การผ่าคลอดในทารกท่าก้นครบกำหนดลด perinatal morbidity → เป็นแนวทางที่นิยม. ทางเลือกป้องกันคือ ECV ที่ ~37 wk."}, {"topic": "Obstetrics", "q": "A 28-year-old at 30 weeks reports worsening heartburn and constipation. Which hormone primarily accounts for these gastrointestinal changes?", "choices": ["Estrogen", "Progesterone", "Human chorionic gonadotropin", "Prolactin", "Oxytocin"], "ans": 1, "exp": "Progesterone คลายกล้ามเนื้อเรียบ → ลด LES tone (GERD) และลด motility (ท้องผูก, gallstone). มดลูกที่โตยังดันกระเพาะอาหารร่วมด้วย."}, {"topic": "Obstetrics", "q": "A pregnant woman asks how her blood pressure changes across pregnancy. Which pattern is expected in a normal pregnancy?", "choices": ["Rises steadily throughout", "Lowest at term", "Lowest in the second trimester", "Highest in the second trimester", "Unchanged throughout"], "ans": 2, "exp": "SVR ลดลง → BP ค่อยๆ ลด ต่ำสุดกลางไตรมาส 2 (~24 wk) แล้วกลับสู่ระดับเดิมใกล้ครบกำหนด. BP สูงหลัง 20 wk ต้องระวัง gestational hypertension/preeclampsia."}, {"topic": "Obstetrics", "q": "A woman with mitral stenosis is at highest risk of pulmonary edema at which point?", "choices": ["First trimester", "Before pregnancy", "At 12 weeks", "Immediately postpartum", "Six months postpartum"], "ans": 3, "exp": "ช่วงเสี่ยง: GA 28-32 wk (CO สูงสุด) และหลังคลอดทันที (autotransfusion จากมดลูกหดตัว + IVC decompression → preload เพิ่มฉับพลัน) อาจกระตุ้น pulmonary edema."}, {"topic": "Obstetrics", "q": "After delivery of the placenta, the uterus contracts and shifts blood back into the circulation, transiently increasing preload. What is this phenomenon called?", "choices": ["External transfusion", "Hemodilution", "Fetal transfusion", "Reverse shunt", "Autotransfusion"], "ans": 4, "exp": "Autotransfusion: มดลูกหดบีบเลือด ~500 mL กลับเข้าระบบไหลเวียน + IVC decompression → venous return/CO เพิ่มชั่วคราว. เสี่ยงในผู้ป่วยโรคหัวใจ."}, {"topic": "Obstetrics", "q": "A woman at 30 weeks is counseled about respiratory physiology. Which combination of changes is expected in normal pregnancy?", "choices": ["Tidal volume up, FRC down", "Both increased", "Tidal volume down, FRC up", "Both decreased", "No change"], "ans": 0, "exp": "ในครรภ์ tidal volume เพิ่ม 30-40% (progesterone) แต่ FRC ลด ~20% (มดลูกดันกะบังลม). FRC ที่ลดทำให้ hypoxia เร็วขณะ apnea (สำคัญตอน intubation)."}, {"topic": "Obstetrics", "q": "A fetus is evaluated with a contraction stress test that shows late decelerations after 50% of contractions. How is this test interpreted?", "choices": ["Negative, reassuring", "Positive, concerning", "Equivocal only", "Reactive", "Invalid"], "ans": 1, "exp": "CST positive = มี late deceleration ตามหลัง ≥50% ของ contraction บ่งชี้ uteroplacental insufficiency. CST negative (ไม่มี late) = ผลดี. ปัจจุบันใช้ NST/BPP มากกว่า."}, {"topic": "Obstetrics", "q": "A 24-year-old primigravida at 39 weeks is fully dilated and has been pushing for 2.5 hours with epidural; the head is at station +1 and the FHR is category I. What is the most appropriate management?", "choices": ["Immediate cesarean for arrest", "Stop labor efforts", "Allow continued pushing", "Administer tocolytics", "Apply forceps immediately"], "ans": 2, "exp": "ครรภ์แรกที่มี epidural ยอมให้ stage 2 นานถึง ~4 ชม.ตราบใดที่มี progress และ FHR ปกติ. 2.5 ชม. + FHR category I → ให้เบ่งต่อได้พร้อมติดตาม descent."}, {"topic": "Obstetrics", "q": "A woman receiving oxytocin augmentation develops contractions every 90 seconds with recurrent decelerations. What is the most important complication of oxytocin to monitor?", "choices": ["Hypoglycemia", "Rash", "Hypertension", "Uterine tachysystole", "Diarrhea"], "ans": 3, "exp": "Oxytocin overstimulation → tachysystole (>5 ครั้ง/10 นาที) → ลด placental perfusion → FHR decel/distress และเสี่ยง uterine rupture. ปรับ/หยุดยาตาม contraction และ FHR."}, {"topic": "Obstetrics", "q": "A woman asks which vaccine is safe during pregnancy. Which of the following can be given during pregnancy?", "choices": ["Live attenuated influenza (nasal)", "Measles-mumps-rubella", "Varicella vaccine", "Oral polio vaccine", "Inactivated influenza vaccine"], "ans": 4, "exp": "Inactivated influenza vaccine ให้ได้ทุกไตรมาส. ห้ามวัคซีนเชื้อเป็น (LAIV, MMR, VZV) ในครรภ์ → ให้หลังคลอด."}, {"topic": "Obstetrics", "q": "At what gestational age is a detailed fetal anomaly scan optimally performed?", "choices": ["18-22 weeks", "11-13 weeks", "8-10 weeks", "28-30 weeks", "36-38 weeks"], "ans": 0, "exp": "Anomaly scan ทำที่ GA 18-22 wk (อวัยวะพัฒนาพอตรวจได้ครบ, น้ำคร่ำเพียงพอ). ช่วง 11-13 wk ทำ NT scan (คัดกรองโครโมโซม)."}, {"topic": "Obstetrics", "q": "A woman is taught to count fetal movements starting in the third trimester. At approximately what gestational age is this typically begun?", "choices": ["24 weeks", "28 weeks", "20 weeks", "34 weeks", "36 weeks"], "ans": 1, "exp": "แนะนำเริ่มนับลูกดิ้นตั้งแต่ ~GA 28 wk เป็นวิธีเฝ้าระวังที่มารดาทำเอง. ถ้าลูกดิ้นน้อยควรมาประเมิน NST/BPP."}, {"topic": "Obstetrics", "q": "Which milk-related reflex is primarily mediated by oxytocin during breastfeeding?", "choices": ["Milk production", "Colostrum synthesis", "Milk ejection (let-down)", "Prolactin release", "Suppression of lactation"], "ans": 2, "exp": "Prolactin สร้างน้ำนม; Oxytocin กระตุ้น milk ejection/let-down (myoepithelial cells หดตัว) เมื่อทารกดูดนม และช่วยมดลูกหดรัดตัว (ปวดมดลูกขณะให้นม)."}, {"topic": "Obstetrics", "q": "After delivery of the placenta, the rapid fall in estrogen and progesterone allows which process to begin?", "choices": ["Suppression of lactation", "Uterine atony", "Increased VTE risk", "Onset of lactogenesis", "Immediate menstruation"], "ans": 3, "exp": "ระหว่างครรภ์ estrogen/progesterone สูงยับยั้งผล prolactin. หลังคลอดรกฮอร์โมนลดเร็ว → ปลดการยับยั้ง → prolactin กระตุ้น lactogenesis II (น้ำนมมาเต็มที่ ~วันที่ 3-4)."}, {"topic": "Obstetrics", "q": "How long does WHO recommend exclusive breastfeeding?", "choices": ["Three months", "Twelve months", "Nine months", "Two years", "Six months"], "ans": 4, "exp": "WHO แนะนำ exclusive breastfeeding 6 เดือน แล้วเสริมอาหารตามวัยควบคู่นมแม่ถึง 2 ปีขึ้นไป. นมแม่ให้ภูมิคุ้มกัน (IgA), ลด infection/NEC, เป็น natural contraception (LAM)."}, {"topic": "Obstetrics", "q": "A postpartum woman relies on the lactational amenorrhea method (LAM). Which set of conditions must be met for it to be effective?", "choices": ["Exclusive breastfeeding with amenorrhea under 6 months", "Any breastfeeding at any infant age", "Mixed feeding with formula supplements", "Breastfeeding beyond twelve months postpartum", "Breastfeeding with resumed menstruation"], "ans": 0, "exp": "LAM ได้ผล (~98%) เมื่อครบ 3 เงื่อนไข: exclusive breastfeeding, amenorrhea (ประจำเดือนยังไม่มา), ทารก <6 เดือน. เมื่อเงื่อนไขใดหายไปต้องเริ่มวิธีอื่น."}, {"topic": "Obstetrics", "q": "An 18-year-old primigravida at 8 weeks by LMP denies bleeding or pain. TVS shows an intrauterine sac of 15 mm mean diameter with no yolk sac or fetal pole. What is the most appropriate next step?", "choices": ["Immediate dilation and curettage", "Repeat ultrasound in 7-14 days", "Misoprostol to complete the loss", "Methotrexate for ectopic pregnancy", "Pelvic MRI for confirmation"], "ans": 1, "exp": "Sac 15 mm ยังไม่ถึงเกณฑ์วินิจฉัย pregnancy loss แน่นอน (empty sac ต้อง MSD ≥25 mm) → reassure และ repeat US ใน 7-14 วันเพื่อประเมิน interval growth/cardiac activity ก่อนจัดการ."}, {"topic": "Obstetrics", "q": "A 40-year-old at 38 weeks with gestational diabetes has an NST with baseline 140 bpm and no accelerations over 40 minutes. What is the most appropriate next step?", "choices": ["Repeat NST in 1 week", "Immediate cesarean delivery", "Perform a biophysical profile", "Discharge home", "Start tocolysis"], "ans": 2, "exp": "NST non-reactive ต้องประเมินต่อด้วย biophysical profile (หรือ CST) เพื่อยืนยัน fetal wellbeing ก่อนตัดสินใจ ไม่ใช่ผ่าคลอดทันทีหรือส่งกลับบ้าน. Non-reactive อาจเป็นเพียง sleep cycle."}, {"topic": "Obstetrics", "q": "A 32-year-old G3P2 delivers and the physician documents the placenta to check completeness. Why is this important?", "choices": ["To determine fetal sex", "To assess Apgar", "To confirm gestational age", "To detect retained fragments", "To measure fluid"], "ans": 3, "exp": "ตรวจความสมบูรณ์ของรก/เยื่อหุ้มและจำนวนหลอดเลือดสายสะดือ (2A+1V). รกไม่ครบ (retained fragment) เสี่ยง PPH/infection → อาจต้องสำรวจโพรงมดลูก."}, {"topic": "Obstetrics", "q": "A twin pregnancy is dichorionic-diamniotic and uncomplicated. At approximately what gestational age is delivery recommended?", "choices": ["34 weeks", "36 weeks", "42 weeks", "40 weeks", "38 weeks"], "ans": 4, "exp": "DCDA ปกติแนะนำคลอด ~38 wk (ไม่เกิน 38-39 เพราะเสี่ยง stillbirth). MCDA ~34-37, MCMA ~32-34 (ผ่าคลอด เพราะ cord entanglement)."}, {"topic": "Obstetrics", "q": "During the fourth stage of labor (first hour postpartum), what is the most important complication to monitor for?", "choices": ["Postpartum hemorrhage", "Depression", "Urinary infection", "Delayed lactation", "Epidural hypotension"], "ans": 0, "exp": "Stage 4 (1-2 ชม.แรก) เสี่ยงสูงสุดต่อ early PPH โดยเฉพาะ uterine atony. ต้องตรวจ fundus (กลมแข็ง), ปริมาณเลือด, vital signs, perineum เป็นระยะ."}, {"topic": "Obstetrics", "q": "A 26-year-old at 12 weeks presents with dysuria, frequency, and urgency; urinalysis shows nitrites and leukocytes, without fever or flank pain. Which antibiotic is most appropriate?", "choices": ["Ciprofloxacin", "Amoxicillin", "Doxycycline", "Gentamicin", "Trimethoprim-sulfamethoxazole"], "ans": 1, "exp": "Cystitis ในครรภ์รักษาด้วยยาปลอดภัย: amoxicillin, cephalexin, nitrofurantoin (เลี่ยงใกล้คลอด/G6PD), fosfomycin. หลีกเลี่ยง fluoroquinolone, doxycycline, และ TMP-SMX (ระวังไตรมาสแรก/ใกล้คลอด)."}, {"topic": "Obstetrics", "q": "A pregnant woman with hyperthyroidism from Graves disease needs an antithyroid drug in the first trimester. Which is preferred?", "choices": ["Methimazole", "Propranolol alone", "Propylthiouracil", "Radioactive iodine", "Levothyroxine"], "ans": 2, "exp": "ไตรมาสแรกใช้ PTU (methimazole เสี่ยง aplasia cutis/embryopathy), แล้วเปลี่ยนเป็น methimazole ไตรมาส 2-3 (PTU เสี่ยง hepatotoxicity). ห้าม radioactive iodine (ทำลายต่อมทารก)."}, {"topic": "Obstetrics", "q": "A woman with hypothyroidism becomes pregnant. How should her levothyroxine dose be adjusted?", "choices": ["Decrease the dose by half", "Stop levothyroxine entirely", "Switch to propylthiouracil", "Increase by about 30 percent", "Keep the dose unchanged"], "ans": 3, "exp": "ความต้องการ thyroid hormone เพิ่มในครรภ์ → เพิ่ม levothyroxine ~25-30% ทันทีที่ทราบว่าตั้งครรภ์ และตรวจ TSH ทุก 4-6 สัปดาห์. Maternal hypothyroidism สัมพันธ์กับ pregnancy loss/พัฒนาการสมอง."}, {"topic": "Obstetrics", "q": "A woman at 41 weeks with meconium-stained amniotic fluid delivers. What neonatal complication is of greatest concern?", "choices": ["Hyperbilirubinemia", "Hypoglycemia", "Polycythemia", "Necrotizing enterocolitis", "Meconium aspiration syndrome"], "ans": 4, "exp": "Meconium-stained fluid (พบบ่อยใน post-term) เสี่ยง meconium aspiration syndrome (respiratory distress, chemical pneumonitis, pulmonary hypertension) ถ้าทารกสำลัก. ดูแลตาม NRP ในทารก non-vigorous."}, {"topic": "Obstetrics", "q": "A woman with epilepsy on valproate is counseled before pregnancy. Which fetal risk is greatest with valproate?", "choices": ["Neural tube defect", "Cardiac defect only", "Limb defect", "Cataract", "Deafness"], "ans": 0, "exp": "Valproate เสี่ยงสูงสุดต่อ neural tube defect และ neurodevelopmental impairment → เลี่ยงในหญิงวัยเจริญพันธุ์ (เปลี่ยนเป็น lamotrigine/levetiracetam), ให้ folate สูง, ใช้ monotherapy ขนาดต่ำสุด."}, {"topic": "Obstetrics", "q": "A pregnant woman with asthma asks about her medications. What is the guiding principle for asthma management in pregnancy?", "choices": ["Stop all medications", "Continue inhaled controllers", "Use only oral steroids", "Give oxygen alone", "Switch to herbal therapy"], "ans": 1, "exp": "คุมโรคหืดให้ดีสำคัญกว่าความเสี่ยงจากยา (หืดกำเริบ → ทารกขาดออกซิเจน). ยาสูดพ่น (inhaled corticosteroid, SABA) ปลอดภัยและควรใช้ต่อ เป้าหมายควบคุมอาการเหมือนคนทั่วไป."}, {"topic": "Obstetrics", "q": "A woman with a monochorionic twin pregnancy requires close monitoring for which specific complication?", "choices": ["Rh isoimmunization", "Placenta previa", "Twin-twin transfusion syndrome", "Gestational diabetes only", "No special risk"], "ans": 2, "exp": "Monochorionic (แชร์รก + vascular anastomoses) เสี่ยง TTTS (donor ซีด/oligohydramnios/โตช้า, recipient เลือดข้น/polyhydramnios). ต้อง US ทุก 2 สัปดาห์ตั้งแต่ 16 wk; severe TTTS รักษาด้วย fetoscopic laser."}, {"topic": "Obstetrics", "q": "A 30-year-old with a persistent occiput posterior position has a prolonged second stage. What is a reasonable option in a suitable candidate?", "choices": ["Immediate cesarean in all cases", "Tocolysis to slow labor", "Maximal-dose oxytocin infusion", "Manual rotation or operative delivery", "Vigorous fundal pressure applied"], "ans": 3, "exp": "Persistent OP ทำให้ prolonged 2nd stage. หลายรายหมุนเป็น OA เอง; ถ้าไม่ก้าวหน้าพิจารณา manual rotation หรือ operative vaginal delivery โดยผู้เชี่ยวชาญ, หรือ cesarean ถ้ามี CPD/ล้มเหลว. ห้ามกด fundus."}, {"topic": "Obstetrics", "q": "A 34-year-old at 39 weeks in labor develops a fetal baseline of 175 bpm; the mother's temperature is 38.5°C. What is the most likely explanation?", "choices": ["Fetal heart block", "Fetal anemia", "Normal variant", "Cord prolapse", "Chorioamnionitis"], "ans": 4, "exp": "Fetal tachycardia (>160) + ไข้มารดา บ่งชี้ chorioamnionitis (พบบ่อยหลังถุงน้ำแตกนาน). รักษาด้วยยาปฏิชีวนะ + เร่งคลอด (คลอดทางช่องคลอดได้)."}, {"topic": "Obstetrics", "q": "A fetal heart rate baseline is documented as 105 bpm. How should this be classified?", "choices": ["Fetal bradycardia", "Normal baseline", "Marked variability", "Fetal tachycardia", "Sinusoidal pattern"], "ans": 0, "exp": "FHR baseline ปกติ 110-160 bpm. <110 = bradycardia (สาเหตุ: hypoxia, heart block, hypothermia). >160 = tachycardia. ประเมินร่วมกับ variability และ deceleration."}, {"topic": "Obstetrics", "q": "A 29-year-old G1P0 at 41+3 weeks declines induction. What antenatal surveillance is most appropriate while awaiting labor?", "choices": ["No further monitoring needed", "NST with amniotic fluid assessment", "Oral hematinic supplements", "Immediate cesarean delivery", "Prophylactic tocolytic therapy"], "ans": 1, "exp": "เมื่อ expectant เกิน 41 wk ต้องทำ antenatal surveillance (NST + AFI หรือ BPP) 1-2 ครั้ง/สัปดาห์ เพื่อเฝ้าระวัง fetal compromise เพราะความเสี่ยง stillbirth เพิ่มเมื่อครรภ์เกินกำหนด."}, {"topic": "Obstetrics", "q": "A 30-year-old at 37 weeks is counseled that antenatal corticosteroids are given when preterm delivery is anticipated before which gestational age?", "choices": ["24 weeks", "37 weeks", "34 weeks", "40 weeks", "42 weeks"], "ans": 2, "exp": "Antenatal corticosteroid (betamethasone/dexamethasone) ให้เมื่อเสี่ยงคลอดก่อน GA 34 wk (ช่วง 24-34) เพื่อลด RDS/IVH/NEC/การตาย; อาจพิจารณาถึง late preterm ในบางราย. ประสิทธิผลสูงสุดเมื่อคลอดใน 7 วัน."}, {"topic": "Obstetrics", "q": "A 27-year-old G1P0 at 39 weeks is fully dilated. As the head descends onto the perineum and begins to distend it, the presenting part is at which station?", "choices": ["Station minus five", "Station zero", "At the pelvic inlet", "Station plus five", "Above the ischial spines"], "ans": 3, "exp": "Station +5 = ส่วนนำโผล่พ้น perineum (crowning) ใกล้คลอด. 0 = ระดับ ischial spines (engaged), -5 = อยู่สูงที่ pelvic inlet. ใช้ติดตาม fetal descent."}, {"topic": "Obstetrics", "q": "A 30-year-old G2P1 delivers vaginally. Which uterotonic is used first-line for routine active management of the third stage?", "choices": ["Carboprost", "Misoprostol", "Methylergonovine", "Tranexamic acid", "Oxytocin"], "ans": 4, "exp": "Oxytocin 10 U IM เป็น uterotonic ตัวแรกใน active management of third stage เพื่อป้องกัน PPH. Methylergonovine (ห้ามในความดันสูง) และ carboprost (ห้ามในหืด) เป็นทางเลือกเมื่อ atony ดื้อ."}]}, {"id": "obgyn2", "title": "Ob-gyne ชุดที่ 2 — Obstetrics II (Bleeding, Hypertension, Diabetes, Preterm, Infections, Emergencies & Postpartum)", "subject": "obgyn", "questions": [{"topic": "Obstetrics", "q": "A 24-year-old G2P1 at 8 weeks of gestation reports mild vaginal spotting. On speculum exam the cervical os is closed, and transvaginal ultrasound shows a live intrauterine pregnancy. What is the diagnosis?", "choices": ["Threatened abortion", "Inevitable abortion", "Incomplete abortion", "Missed abortion", "Complete abortion"], "ans": 0, "exp": "Threatened abortion = เลือดออก <20 wk โดยปากมดลูกปิดและทารกยังมีชีวิต. ดูแลแบบ expectant. ~50% ตั้งครรภ์ต่อได้. ต่างจาก inevitable (os เปิด) และ missed (ทารกเสียชีวิต os ปิด)."}, {"topic": "Obstetrics", "q": "A 27-year-old woman at 10 weeks presents with heavy bleeding and cramping; the cervical os is open, some tissue has passed, and ultrasound shows retained products. What is the diagnosis?", "choices": ["Threatened abortion", "Incomplete abortion", "Complete abortion", "Missed abortion", "Septic abortion"], "ans": 1, "exp": "Incomplete abortion = os เปิด ขับเนื้อเยื่อบางส่วน แต่มีเศษค้าง ทำให้เลือดออกต่อเนื่อง. รักษาด้วย expectant, misoprostol, หรือ surgical evacuation (MVA/D&C) โดยเฉพาะถ้าเลือดออกมาก."}, {"topic": "Obstetrics", "q": "A 30-year-old woman with three consecutive first-trimester losses is evaluated. Which is the most common treatable cause of recurrent pregnancy loss?", "choices": ["Diabetes mellitus", "Thyrotoxicosis", "Antiphospholipid syndrome", "Uterine fibroids", "Cervical insufficiency"], "ans": 2, "exp": "Antiphospholipid syndrome (APS) เป็นสาเหตุ recurrent pregnancy loss ที่รักษาได้และพบบ่อย. รักษาด้วย aspirin + heparin เพิ่มอัตราคลอดมีชีพ. สาเหตุอื่น: septate uterus, parental translocation, DM/thyroid."}, {"topic": "Obstetrics", "q": "In an ectopic pregnancy, which anatomical site is most commonly involved?", "choices": ["The uterine cervix", "The ovarian surface", "The uterine cornua", "Ampulla of the fallopian tube", "The abdominal cavity"], "ans": 3, "exp": "Ectopic พบบ่อยสุดที่ท่อนำไข่ (~95%) โดยเฉพาะ ampulla (~70%). ปัจจัยเสี่ยง: PID/STI, เคยผ่าตัดท่อ, เคย ectopic, IUD, ART, สูบบุหรี่."}, {"topic": "Obstetrics", "q": "A 25-year-old woman with 6 weeks of amenorrhea has right lower quadrant pain; beta-hCG is 2,500 mIU/mL and transvaginal ultrasound shows no intrauterine gestational sac. What is the most likely diagnosis?", "choices": ["Normal early pregnancy", "Complete molar pregnancy", "Threatened abortion", "Missed abortion", "Ectopic pregnancy"], "ans": 4, "exp": "β-hCG เกิน discriminatory zone (~1,500-2,000) แต่ไม่พบ intrauterine sac → ectopic จนกว่าจะพิสูจน์เป็นอื่น. ประเมินเสถียรภาพ: คงที่ → methotrexate; แตก/ไม่คงที่ → ผ่าตัดฉุกเฉิน."}, {"topic": "Obstetrics", "q": "A hemodynamically stable woman has an unruptured ectopic pregnancy. Which finding makes her a suitable candidate for methotrexate?", "choices": ["Beta-hCG below 5,000 mIU/mL", "Mass over six centimeters", "Fetal cardiac activity present", "Large hemoperitoneum", "Unstable vital signs"], "ans": 0, "exp": "เกณฑ์ MTX: stable, ท่อยังไม่แตก, mass <3.5-4 cm, β-hCG <5,000, ไม่มี cardiac activity, ติดตามได้. ติดตาม hCG วันที่ 4 และ 7 (ต้องลด ≥15%). แตก/ไม่คงที่ต้องผ่าตัด."}, {"topic": "Obstetrics", "q": "In a normal early intrauterine pregnancy, what is the expected rise in beta-hCG over 48 hours?", "choices": ["Remains unchanged", "At least 49-66 percent", "Halves every 48 hours", "Increases tenfold in 24 hours", "No predictable pattern"], "ans": 1, "exp": "ครรภ์ในมดลูกปกติช่วงต้น β-hCG เพิ่ม ≥49-66% ใน 48 ชม. การเพิ่มช้าผิดปกติหรือ plateau บ่งชี้ ectopic/nonviable; การลดลงบ่งชี้ failing pregnancy."}, {"topic": "Obstetrics", "q": "A complete hydatidiform mole has which genetic and clinical profile?", "choices": ["Triploid with fetal tissue", "Normal 46,XY karyotype", "Paternal-only 46,XX with no fetus", "Trisomy 21 present", "Monosomy X present"], "ans": 2, "exp": "Complete mole: มัก 46,XX จากพ่อทั้งหมด (androgenesis) ไม่มีเนื้อเยื่อทารก. hCG สูงมาก, มดลูกโตกว่าอายุครรภ์, snowstorm, theca lutein cysts, เสี่ยงกลายเป็น GTN สูง. Partial mole = triploid (69,XXX) มีเนื้อเยื่อทารก."}, {"topic": "Obstetrics", "q": "What is the initial treatment of a hydatidiform mole?", "choices": ["Hysterectomy in all cases", "Await spontaneous expulsion", "Immediate chemotherapy", "Suction curettage with hCG follow-up", "Pelvic radiotherapy"], "ans": 3, "exp": "รักษา molar pregnancy ด้วย suction curettage แล้วติดตาม serial β-hCG จนเป็นลบต่อเนื่อง. คุมกำเนิดระหว่างติดตาม. ถ้า hCG plateau/สูงขึ้น = GTN → เคมีบำบัด."}, {"topic": "Obstetrics", "q": "A 32-year-old woman at 32 weeks has painless, bright-red vaginal bleeding; the uterus is soft and nontender. What should be avoided until the placental location is confirmed?", "choices": ["Ultrasound examination", "Blood typing", "Fetal heart monitoring", "Intravenous access", "Digital vaginal examination"], "ans": 4, "exp": "เลือดออกแดงสด ไม่ปวด มดลูกนุ่ม = placenta previa. ห้าม digital/speculum PV เพราะอาจกระตุ้นเลือดออกรุนแรง — ใช้ ultrasound วินิจฉัยตำแหน่งรกก่อน. รกคลุมปากมดลูกต้องผ่าคลอด."}, {"topic": "Obstetrics", "q": "Which is the most important risk factor for placenta accreta spectrum?", "choices": ["Previa with prior cesarean", "First pregnancy alone", "Young maternal age", "Nulliparity", "Twin gestation"], "ans": 0, "exp": "[อัปเดต] Placenta accreta spectrum เพิ่มตามอัตราผ่าคลอด. ปัจจัยเสี่ยงหลักคือ placenta previa + ประวัติ cesarean. วางแผนคลอดโดยทีมสหสาขา, เตรียมเลือด, มักต้อง cesarean hysterectomy."}, {"topic": "Obstetrics", "q": "A 34-year-old woman at 34 weeks with hypertension presents with painful vaginal bleeding, a tense tender uterus, and an abnormal fetal heart rate. What is the diagnosis?", "choices": ["Placenta previa", "Placental abruption", "Chorioamnionitis", "Vasa previa", "Uterine rupture"], "ans": 1, "exp": "Placental abruption: ปวดท้อง มดลูก tense/tender เลือดออก (อาจ concealed) + fetal distress. เสี่ยง: HT/preeclampsia, trauma, สูบบุหรี่/โคเคน, PPROM. แทรกซ้อน: DIC, Couvelaire uterus, fetal death."}, {"topic": "Obstetrics", "q": "What is the most important hematologic complication of severe placental abruption?", "choices": ["Reactive polycythemia", "Acute leukemia", "Disseminated intravascular coagulation", "Hemophilia A", "Thrombocytosis"], "ans": 2, "exp": "Abruption รุนแรงปล่อย thromboplastin → กระตุ้น coagulation → DIC (fibrinogen ลด, PT/PTT ยาว, เกล็ดต่ำ). เป็นสาเหตุ obstetric DIC ที่พบบ่อย. รักษาโดยคลอดและให้ blood products."}, {"topic": "Obstetrics", "q": "A 25-year-old at 24 weeks has BP 150/95 confirmed 4 hours apart with a urine protein/creatinine ratio of 0.4. What is the diagnosis?", "choices": ["Chronic hypertension", "Gestational hypertension", "Normal pregnancy", "Preeclampsia", "Eclampsia"], "ans": 3, "exp": "BP ≥140/90 หลัง 20 wk + proteinuria (protein/Cr ≥0.3) = preeclampsia. ถ้าไม่มี proteinuria แต่มี severe features/end-organ damage ก็วินิจฉัย preeclampsia ได้."}, {"topic": "Obstetrics", "q": "Which finding qualifies as a severe feature of preeclampsia?", "choices": ["Blood pressure 145/92", "Platelets of 250,000", "Proteinuria 300 mg/day", "Weight gain of 1 kg weekly", "Platelet count below 100,000"], "ans": 4, "exp": "Severe features: BP ≥160/110, platelet <100,000, Cr >1.1, transaminase สูง ≥2 เท่า, pulmonary edema, อาการทางสมอง/ตา, ปวด RUQ. เปลี่ยนแนวทางเป็นให้ MgSO4 และพิจารณาคลอดที่ 34 wk."}, {"topic": "Obstetrics", "q": "Which agent is the drug of choice for both prevention and treatment of eclamptic seizures?", "choices": ["Magnesium sulfate", "Diazepam", "Phenytoin", "Levetiracetam", "Labetalol"], "ans": 0, "exp": "Magnesium sulfate เป็นตัวเลือกแรกในการป้องกัน (severe features) และรักษา eclamptic seizure — เหนือกว่า diazepam/phenytoin. Loading 4-6 g IV แล้ว 1-2 g/hr. เฝ้าระวัง toxicity."}, {"topic": "Obstetrics", "q": "A woman on magnesium sulfate for preeclampsia is being monitored. What is the earliest sign of magnesium toxicity?", "choices": ["Cardiac arrest", "Loss of deep tendon reflexes", "Respiratory failure", "Increased urine output", "Rising blood pressure"], "ans": 1, "exp": "ลำดับ Mg toxicity: loss of DTR (~8-10) เป็นสัญญาณเตือนแรก → respiratory depression (~12) → cardiac arrest (>15). Antidote = calcium gluconate. ตรวจ reflex, RR, urine output เป็นระยะ."}, {"topic": "Obstetrics", "q": "What does HELLP syndrome comprise?", "choices": ["Hypertension, edema, low platelets", "Hyperglycemia, edema, low platelets", "Hemolysis, elevated liver enzymes, low platelets", "High lipids, elevated lactate, leukopenia", "Hemorrhage, encephalopathy, liver lesion"], "ans": 2, "exp": "HELLP = Hemolysis (schistocytes, LDH สูง), Elevated Liver enzymes (AST/ALT), Low Platelets (<100,000). รูปแบบรุนแรงของ preeclampsia (บางรายไม่มีความดันสูง). เสี่ยง liver rupture, DIC, abruption. รักษา: MgSO4, คุมความดัน, คลอด."}, {"topic": "Obstetrics", "q": "What is the only definitive treatment of preeclampsia?", "choices": ["Magnesium sulfate", "Antihypertensive drugs", "Intravenous fluids", "Delivery of the placenta", "Strict bed rest"], "ans": 3, "exp": "Preeclampsia เกิดจากพยาธิสภาพของรก จึงรักษาหายด้วยการคลอด. MgSO4/ยาลดความดันเป็นการควบคุมชั่วคราว. Timing: ไม่มี severe features → 37 wk; มี severe features → 34 wk (หรือเร็วกว่าถ้าไม่คงที่)."}, {"topic": "Obstetrics", "q": "A woman at high risk of preeclampsia is counseled on prophylaxis. What is the recommended aspirin regimen?", "choices": ["300 mg starting at 28 weeks", "500 mg in the third trimester", "81 mg after delivery", "162 mg at term only", "81 mg starting at 12-28 weeks"], "ans": 4, "exp": "[อัปเดต] Low-dose aspirin 81 mg/วัน เริ่ม GA 12-28 wk (ดีที่สุดก่อน 16) ต่อจนคลอด ในผู้มี high-risk factor ≥1 หรือ moderate-risk ≥2. ลดความเสี่ยง preeclampsia และภาวะแทรกซ้อน."}, {"topic": "Obstetrics", "q": "A woman with preeclampsia has a BP of 165/112. Which antihypertensive is appropriate for acute control in pregnancy?", "choices": ["Labetalol", "Enalapril", "Losartan", "Long-term nitroprusside", "Atenolol"], "ans": 0, "exp": "ยาลดความดันเฉียบพลัน (≥160/110): IV labetalol, IV hydralazine, oral nifedipine. หลีกเลี่ยง ACEI/ARB (teratogen, fetal renal), nitroprusside (cyanide). ลด BP แต่คง placental perfusion."}, {"topic": "Obstetrics", "q": "A 26-year-old at 26 weeks has a 50 g glucose challenge test result of 155 mg/dL. What is the next step?", "choices": ["Diagnose GDM, start insulin now", "Perform a 100 g tolerance test", "Check the HbA1c level only", "No further action needed", "Proceed directly to cesarean"], "ans": 1, "exp": "Two-step: 50 g GCT ≥140 (บางที่ 130/135) → ทำ 100 g OGTT ยืนยัน. GCT อย่างเดียวไม่วินิจฉัย GDM. วินิจฉัยเมื่อ 100 g OGTT ผิดปกติ ≥2 ค่า (Carpenter-Coustan)."}, {"topic": "Obstetrics", "q": "How many abnormal values on a 100 g oral glucose tolerance test are required to diagnose gestational diabetes (Carpenter-Coustan)?", "choices": ["One value", "Three values", "Two or more values", "All four values", "This test is not used"], "ans": 2, "exp": "100 g OGTT (Carpenter-Coustan): FBS ≥95, 1hr ≥180, 2hr ≥155, 3hr ≥140. วินิจฉัยเมื่อผิดปกติ ≥2 ค่า. ต่างจาก one-step 75 g OGTT ที่วินิจฉัยเมื่อ ≥1 ค่า (92/180/153)."}, {"topic": "Obstetrics", "q": "A woman is newly diagnosed with gestational diabetes. What is the first-line management?", "choices": ["Start insulin therapy immediately", "Start metformin therapy first", "Start glyburide therapy first", "Medical nutrition therapy, exercise", "Proceed directly to cesarean"], "ans": 3, "exp": "GDM เริ่มด้วยควบคุมอาหาร + ออกกำลังกาย + ตรวจน้ำตาลปลายนิ้ว (เป้า FBS <95, 1hr <140, 2hr <120). คุมไม่ได้จึงเริ่มยา insulin เป็นตัวแรก. คุมน้ำตาลลด macrosomia, shoulder dystocia, neonatal hypoglycemia."}, {"topic": "Obstetrics", "q": "A neonate born to a mother with gestational diabetes is at risk of all the following EXCEPT which?", "choices": ["Macrosomia", "Neonatal hypoglycemia", "Polyhydramnios", "Shoulder dystocia", "Neural tube defect"], "ans": 4, "exp": "GDM (เริ่มหลังไตรมาสแรก) → macrosomia, shoulder dystocia, neonatal hypoglycemia, polyhydramnios, RDS. ส่วน neural tube/cardiac/caudal regression พบใน pregestational DM (น้ำตาลสูงตั้งแต่ organogenesis) ไม่ใช่ GDM ทั่วไป."}, {"topic": "Obstetrics", "q": "A woman had gestational diabetes. What postpartum follow-up is recommended?", "choices": ["75 g OGTT at 4-12 weeks postpartum", "No further testing is needed", "Weekly HbA1c measurement", "Daily urine glucose testing", "Lifelong insulin therapy"], "ans": 0, "exp": "หญิง GDM ควรตรวจ 75 g OGTT ที่ 4-12 สัปดาห์หลังคลอดเพื่อคัดกรอง type 2 DM/prediabetes (เสี่ยงเป็น DM2 สูง). แนะนำคุมน้ำหนัก ออกกำลังกาย และตรวจน้ำตาลเป็นระยะ."}, {"topic": "Obstetrics", "q": "A 32-year-old woman in preterm labor at 30 weeks is at risk of imminent delivery. Which agent is given specifically for fetal neuroprotection?", "choices": ["Terbutaline", "Magnesium sulfate", "Indomethacin", "Betamethasone", "Nifedipine"], "ans": 1, "exp": "[อัปเดต] คลอดก่อน 32 wk ให้ magnesium sulfate เพื่อ fetal neuroprotection (ลด cerebral palsy). ควบคู่ betamethasone (lung maturity), tocolytic, GBS prophylaxis. Betamethasone เป็น steroid ลด RDS ไม่ใช่ neuroprotection."}, {"topic": "Obstetrics", "q": "A woman in preterm labor at 28 weeks receives corticosteroids. What is their main purpose?", "choices": ["Reduce infection", "Stop contractions", "Accelerate fetal lung maturity", "Lower blood pressure", "Control electrolytes"], "ans": 2, "exp": "Antenatal corticosteroid (betamethasone/dexamethasone) ให้ GA 24-34 wk เร่ง surfactant (lung maturity) ลด RDS, IVH, NEC, การตาย. ประสิทธิผลสูงสุดเมื่อคลอดใน 2-7 วัน."}, {"topic": "Obstetrics", "q": "Which tocolytic should be avoided at 32 weeks or beyond due to the risk of premature ductus arteriosus closure?", "choices": ["Nifedipine", "Terbutaline", "Atosiban", "Indomethacin", "Magnesium sulfate"], "ans": 3, "exp": "Indomethacin (NSAID) ใช้ tocolysis ได้ผลดีแต่จำกัดที่ <32 wk และใช้สั้น เพราะเสี่ยง premature closure of ductus arteriosus และ oligohydramnios. Nifedipine/atosiban เป็นทางเลือกที่นิยม."}, {"topic": "Obstetrics", "q": "A woman at 30 weeks has preterm premature rupture of membranes without infection and a reassuring fetus. What is the appropriate management?", "choices": ["Immediate delivery of the fetus", "Long-term tocolysis for one month", "Emergency cervical cerclage placement", "Aggressive antihypertensive therapy", "Expectant care with steroids/antibiotics"], "ans": 4, "exp": "PPROM <34 wk ไม่มีข้อบ่งชี้คลอด → expectant: corticosteroid, latency antibiotics (ampicillin + erythromycin/azithromycin), MgSO4 (<32 wk), เฝ้าระวัง chorioamnionitis/abruption/cord prolapse. คลอด ~34 wk หรือมีภาวะแทรกซ้อน."}, {"topic": "Obstetrics", "q": "A woman with painless second-trimester cervical dilation and recurrent mid-trimester losses is diagnosed with which condition?", "choices": ["Cervical insufficiency", "Preeclampsia", "Post-term pregnancy", "Placenta previa", "Gestational diabetes"], "ans": 0, "exp": "Cervical insufficiency = ปากมดลูกเปิด/สั้นโดยไม่เจ็บครรภ์ในไตรมาส 2 → แท้ง/คลอดก่อนกำหนดซ้ำ. รักษาด้วย cervical cerclage (history/US/exam-indicated), มักถอดที่ ~37 wk."}, {"topic": "Obstetrics", "q": "When is vaginal progesterone used to prevent preterm birth?", "choices": ["In every pregnancy routinely", "When the cervix is short", "Always in twin pregnancies", "Only after delivery occurs", "Only in preeclampsia cases"], "ans": 1, "exp": "Vaginal progesterone ป้องกัน preterm birth ในผู้ที่ cervix สั้น (<25 mm) จาก US ไตรมาส 2. 17-OHPC เคยใช้ในผู้มีประวัติคลอดก่อนกำหนด (หลักฐานลดลง). ไม่ได้ผลชัดในครรภ์แฝด."}, {"topic": "Obstetrics", "q": "An Rh(D)-negative unsensitized woman delivers an Rh-positive infant. When should anti-D immunoglobulin be given?", "choices": ["No dose needed", "Only if the infant is anemic", "Within 72 hours of delivery", "One month postpartum", "Before delivery only"], "ans": 2, "exp": "หญิง Rh negative ที่ไม่ sensitized คลอดทารก Rh positive ต้องได้ anti-D ภายใน 72 ชม.หลังคลอด (+ dose ที่ 28 wk และหลังเหตุการณ์เสี่ยง). ตรวจ Kleihauer-Betke ถ้าสงสัย FMH ปริมาณมาก."}, {"topic": "Obstetrics", "q": "In a sensitized pregnancy, which method is used to assess for fetal anemia?", "choices": ["The amniotic fluid index", "A nonstress test", "The biophysical profile", "Middle cerebral artery peak systolic velocity", "Symphysis-fundal height"], "ans": 3, "exp": "ในครรภ์ alloimmunized ใช้ MCA peak systolic velocity Doppler — ทารกซีด เลือดไหลเร็วขึ้น → MCA-PSV สูง (>1.5 MoM = ซีดปานกลาง-รุนแรง) → intrauterine transfusion. ทดแทนการเจาะน้ำคร่ำวัด bilirubin เดิม."}, {"topic": "Obstetrics", "q": "Which congenital infection is the most common and a frequent cause of congenital sensorineural hearing loss?", "choices": ["Rubella", "Syphilis", "Toxoplasmosis", "Parvovirus B19", "Cytomegalovirus"], "ans": 4, "exp": "CMV เป็น congenital infection ที่พบบ่อยสุด และเป็นสาเหตุ sensorineural hearing loss แต่กำเนิดบ่อย. อาจมี microcephaly, periventricular calcification, IUGR, petechiae. Rubella → cataract/PDA/หูหนวก."}, {"topic": "Obstetrics", "q": "Which classic triad is associated with congenital toxoplasmosis?", "choices": ["Hydrocephalus, intracranial calcification, chorioretinitis", "Cataract, PDA, and deafness (rubella)", "Limb defects, cardiac lesions, cleft lip", "Microcephaly, petechiae, hepatomegaly (CMV)", "Sacral agenesis and clubfoot"], "ans": 0, "exp": "Classic triad ของ congenital toxoplasmosis: hydrocephalus, intracranial calcification (แบบกระจาย), chorioretinitis. ป้องกันโดยเลี่ยงเนื้อดิบ, ล้างผัก, เลี่ยงอุจจาระแมว."}, {"topic": "Obstetrics", "q": "A pregnant woman is HIV-positive. What management best reduces vertical transmission?", "choices": ["No treatment needed", "Antiretroviral therapy for all patients", "Treatment of the neonate only", "ART only in the third trimester", "Cesarean for all patients"], "ans": 1, "exp": "หญิงตั้งครรภ์ HIV ทุกรายควรได้ ART ลด vertical transmission เหลือ <1-2%. viral load >1,000 ใกล้คลอด → scheduled C/S + IV zidovudine. ทารกได้ ARV prophylaxis; หลีกเลี่ยงให้นม (ในไทย)."}, {"topic": "Obstetrics", "q": "An infant is born to a mother who is HBsAg-positive. What should the infant receive within 12 hours of birth?", "choices": ["Broad-spectrum antibiotics", "Magnesium sulfate infusion", "Hepatitis B immunoglobulin and vaccine", "Anti-D immunoglobulin dose", "MMR vaccine given at birth"], "ans": 2, "exp": "ทารกจากแม่ HBsAg positive ต้องได้ทั้ง HBIG และ hepatitis B vaccine ภายใน 12 ชม. เพื่อป้องกัน perinatal transmission (>90%). แม่ที่ HBV DNA สูงควรได้ tenofovir ไตรมาส 3."}, {"topic": "Obstetrics", "q": "A pregnant woman with confirmed syphilis is allergic to penicillin. What is the appropriate management?", "choices": ["Use doxycycline instead", "Give erythromycin", "Withhold treatment", "Desensitize and give penicillin", "Wait until after delivery"], "ans": 3, "exp": "Penicillin เป็นยาเดียวที่รักษาซิฟิลิสในครรภ์และป้องกัน congenital syphilis ได้ผล. แพ้ penicillin ต้อง desensitize แล้วให้ penicillin (ไม่ใช้ doxycycline ในครรภ์ หรือ erythromycin ที่ผ่านรกไม่ดีพอ)."}, {"topic": "Obstetrics", "q": "A pregnant woman at 39 weeks with a transverse lie presents in labor. What is the appropriate mode of delivery?", "choices": ["Vaginal delivery", "Vacuum extraction", "Forceps delivery", "Await spontaneous rotation", "Cesarean section"], "ans": 4, "exp": "Transverse lie คลอดทางช่องคลอดไม่ได้ — เมื่อเจ็บครรภ์/ครบกำหนดต้องผ่าคลอด. เสี่ยง cord prolapse/uterine rupture. บางรายอาจ ECV ก่อนเจ็บครรภ์."}, {"topic": "Obstetrics", "q": "After delivery of the head, the anterior shoulder becomes impacted (turtle sign). What is the appropriate first maneuver?", "choices": ["McRoberts with suprapubic pressure", "Strong downward traction on head", "Wait quietly for five minutes", "Firm fundal pressure downward", "Immediate cesarean delivery"], "ans": 0, "exp": "Shoulder dystocia (HELPERR): ขั้นแรกที่ได้ผลและทำง่ายคือ McRoberts maneuver + suprapubic pressure. ห้าม fundal pressure (ยิ่งติดแน่น/rupture) และห้ามดึงศีรษะแรง (brachial plexus injury)."}, {"topic": "Obstetrics", "q": "Which is the most common fetal complication of shoulder dystocia?", "choices": ["Cephalhematoma", "Brachial plexus injury", "Cataract", "Cleft palate alone", "Hydrocephalus alone"], "ans": 1, "exp": "Shoulder dystocia เสี่ยง brachial plexus injury (Erb palsy - C5-6, 'waiter's tip'), กระดูกไหปลาร้า/แขนหัก, hypoxic injury ถ้าคลอดช้า. การจัดการที่ถูกต้อง (ไม่ดึงแรง/ไม่กด fundus) ลดการบาดเจ็บ. ส่วนใหญ่หายได้เอง."}, {"topic": "Obstetrics", "q": "After membrane rupture, sudden fetal bradycardia occurs and the umbilical cord is palpable in the vagina. What is the most appropriate first action?", "choices": ["Administer an oxytocin infusion", "Observe expectantly for now", "Elevate presenting part, urgent cesarean", "Push the cord back inside", "Give analgesia for the pain"], "ans": 2, "exp": "Umbilical cord prolapse: ส่วนนำกดสายสะดือ → ยกส่วนนำขึ้นด้วยมือ (ไม่ดันสายสะดือกลับ), จัดท่า knee-chest/Trendelenburg, ให้ O2, tocolytic ถ้าจำเป็น, และผ่าคลอดฉุกเฉิน."}, {"topic": "Obstetrics", "q": "A woman with a prior classical cesarean in labor develops sudden severe abdominal pain, an abnormal FHR, and loss of station. What is the diagnosis?", "choices": ["Placental abruption", "Cord prolapse", "Amniotic fluid embolism", "Uterine rupture", "Chorioamnionitis"], "ans": 3, "exp": "Uterine rupture: เสี่ยงในแผล classical/VBAC. อาการ: ปวดฉับพลันรุนแรง, FHR bradycardia (ไวสุด), ส่วนนำลอยขึ้น (loss of station), เลือดออก, ช็อก → ผ่าตัดเปิดหน้าท้องฉุกเฉิน."}, {"topic": "Obstetrics", "q": "During delivery a woman suddenly develops respiratory failure, cardiovascular collapse, and disseminated intravascular coagulation. What is the most likely diagnosis?", "choices": ["Thrombotic pulmonary embolism", "Eclampsia", "Myocardial infarction", "Drug anaphylaxis", "Amniotic fluid embolism"], "ans": 4, "exp": "Amniotic fluid embolism (AFE): เกิดเฉียบพลันระหว่าง/หลังคลอด — hypoxia/respiratory failure, cardiovascular collapse, DIC. เป็น clinical diagnosis, พยากรณ์แย่, รักษาประคับประคอง. เป็นสาเหตุ maternal mortality สำคัญ."}, {"topic": "Obstetrics", "q": "What is the most common cause of postpartum hemorrhage?", "choices": ["Uterine atony", "Retained placenta", "Uterine inversion", "Laceration", "Coagulopathy"], "ans": 0, "exp": "สาเหตุ PPH (4T): Tone (atony), Trauma, Tissue (retained placenta), Thrombin (coagulopathy). Uterine atony พบบ่อยสุด (~70-80%). ปัจจัยเสี่ยง: มดลูกยืดมาก, คลอดนาน/เร็ว, chorioamnionitis, MgSO4."}, {"topic": "Obstetrics", "q": "A postpartum woman has a soft, boggy uterus and heavy bleeding. Which uterotonic is given first?", "choices": ["Methylergonovine", "Oxytocin", "Carboprost", "Misoprostol", "Tranexamic acid"], "ans": 1, "exp": "Uterine atony: นวดมดลูก + oxytocin เป็น uterotonic ตัวแรก. ถ้าไม่ได้ผลเพิ่ม methylergonovine (ห้ามความดันสูง), carboprost (ห้ามหืด), misoprostol. ให้ TXA ร่วม; ดื้อ → balloon, B-Lynch, ligation, hysterectomy."}, {"topic": "Obstetrics", "q": "A postpartum woman with uterine atony has a history of asthma. Which uterotonic should be avoided?", "choices": ["Oxytocin", "Tranexamic acid", "Carboprost", "Misoprostol", "Methylergonovine"], "ans": 2, "exp": "Carboprost (15-methyl PGF2α) ทำให้ bronchospasm → ห้ามในหืด. Methylergonovine ห้ามในความดันสูง/preeclampsia. Oxytocin ปลอดภัยที่สุดเป็นตัวแรก. ต้องจำ contraindication ของแต่ละ uterotonic."}, {"topic": "Obstetrics", "q": "When should tranexamic acid be given for postpartum hemorrhage to gain the most benefit?", "choices": ["After 24 hours", "Before delivery", "Only during cesarean", "Within 3 hours of birth", "After 4 units of blood"], "ans": 3, "exp": "[อัปเดต WHO/FIGO - WOMAN trial] TXA 1 g IV ให้เร็วภายใน 3 ชม.หลังคลอดในผู้วินิจฉัย PPH ลด maternal mortality. ให้ซ้ำอีก 1 g ถ้ายังเลือดออกหลัง 30 นาที. ให้หลัง 3 ชม.ประโยชน์ลดลง."}, {"topic": "Obstetrics", "q": "Which surgical procedure is the last resort for postpartum hemorrhage unresponsive to other measures?", "choices": ["B-Lynch suture", "Uterine artery ligation", "Balloon tamponade", "Uterine massage", "Hysterectomy"], "ans": 4, "exp": "ลำดับ PPH ดื้อ: uterotonics → TXA → balloon/embolization → surgical (B-Lynch, uterine/internal iliac ligation) → peripartum hysterectomy เป็นทางเลือกสุดท้ายเพื่อช่วยชีวิต (โดยเฉพาะ accreta, atony คุมไม่ได้)."}, {"topic": "Obstetrics", "q": "What is the preferred initial fluid for resuscitation of postpartum hemorrhage?", "choices": ["Isotonic crystalloid", "Colloid", "5% dextrose", "Albumin", "Hypertonic saline"], "ans": 0, "exp": "[อัปเดต WHO/FIGO] แนะนำ isotonic crystalloid (NSS, Ringer's lactate) เป็นสารน้ำเริ่มต้น มากกว่า colloid. ควบคู่การให้เลือด/blood products และแก้ coagulopathy (massive transfusion protocol)."}, {"topic": "Obstetrics", "q": "Which condition must be met to perform operative vaginal delivery (forceps or vacuum)?", "choices": ["Cervix dilated to only 6 cm", "Fully dilated cervix with engaged head", "No maternal or fetal indication", "A presenting part still floating", "A breech presentation"], "ans": 1, "exp": "เงื่อนไข operative vaginal delivery: ปากมดลูกเปิดหมด, ถุงน้ำแตก, ทราบตำแหน่ง/station (engaged), ไม่มี CPD, กระเพาะปัสสาวะว่าง, มี anesthesia, มี indication, พร้อมผ่าคลอดถ้าล้มเหลว."}, {"topic": "Obstetrics", "q": "A woman with one prior low-transverse cesarean desires VBAC. What is the most important risk to counsel her about?", "choices": ["Placenta previa", "Gestational diabetes", "Uterine rupture", "Preeclampsia", "Cord prolapse"], "ans": 2, "exp": "VBAC พิจารณาได้ในผู้เคยผ่า low transverse 1 ครั้ง. ความเสี่ยงสำคัญคือ uterine rupture ~0.5-1% (สูงขึ้นถ้า prostaglandin induction, หลายแผล, classical). ต้องคลอดในที่ที่ผ่าคลอดฉุกเฉินได้ทันที."}, {"topic": "Obstetrics", "q": "Which is a clear indication for cesarean delivery?", "choices": ["First pregnancy", "Maternal age of 35", "Well-controlled GDM", "Complete placenta previa", "Twin DCDA pregnancy"], "ans": 3, "exp": "ข้อบ่งชี้ absolute cesarean: complete placenta previa, transverse lie, cord prolapse (มีชีวิต), fetal distress ที่คลอดไม่ทัน, prior classical incision, active genital herpes, CPD ชัดเจน. อายุ/GDM/แฝด DCDA ไม่ใช่ข้อบ่งชี้เสมอไป."}, {"topic": "Obstetrics", "q": "A woman on postpartum day 3 has a fever of 38.5°C, uterine tenderness, and foul-smelling lochia. What is the treatment?", "choices": ["Nitrofurantoin for UTI", "Incision and drainage", "Dicloxacillin for mastitis", "Heparin for DVT", "Clindamycin plus gentamicin"], "ans": 4, "exp": "Postpartum endometritis เป็นสาเหตุไข้หลังคลอดที่พบบ่อยสุด (เสี่ยงหลังผ่าคลอด, ถุงน้ำแตกนาน). อาการ: ไข้ มดลูกกดเจ็บ น้ำคาวปลามีกลิ่น. เป็น polymicrobial → clindamycin + gentamicin IV จนไม่มีไข้ 24-48 ชม."}, {"topic": "Obstetrics", "q": "A breastfeeding woman has a red, warm, tender area on one breast with fever. What is the appropriate management?", "choices": ["Dicloxacillin, continue breastfeeding", "Radical mastectomy of the breast", "Stop breastfeeding completely", "Immediate surgery in all cases", "Observation without any treatment"], "ans": 0, "exp": "Lactational mastitis (มัก S. aureus): รักษาด้วย dicloxacillin/cephalexin + ประคบ + ระบายน้ำนม และ 'ให้นมต่อ'/ปั๊มออก (ไม่หยุด เพราะ stasis แย่ลง). คลำได้ก้อน fluctuant/ไม่ดีขึ้น = abscess → I&D/aspiration."}, {"topic": "Obstetrics", "q": "A woman 2 weeks postpartum has a depressed mood, tearfulness, and insomnia persisting over 2 weeks that impair infant care. What is the diagnosis?", "choices": ["Baby blues", "Postpartum depression", "Normal adjustment", "Postpartum psychosis", "Hypothyroidism only"], "ans": 1, "exp": "Postpartum depression: อาการซึมเศร้าเข้าเกณฑ์ major depression เกิดหลังคลอดถึง 12 เดือน นาน >2 สัปดาห์ กระทบการทำหน้าที่. ต่างจาก baby blues (หายใน ~2 สัปดาห์) และ psychosis (หลงผิด/ประสาทหลอน - ฉุกเฉิน). คัดกรอง EPDS; รักษา psychotherapy ± SSRI."}, {"topic": "Obstetrics", "q": "An intrauterine fetal death has been retained for several weeks. What complication should be monitored?", "choices": ["Polycythemia", "Hypertension", "Consumptive coagulopathy", "Diabetes", "Twin gestation alone"], "ans": 2, "exp": "IUFD ที่ค้างนาน (>4 สัปดาห์) เสี่ยง consumptive coagulopathy/DIC จาก thromboplastin ที่ปล่อยจากทารกที่เสียชีวิต → fibrinogen ลด. ควรตรวจ coagulation และวางแผนคลอด (induction). ยืนยัน IUFD ด้วย US."}, {"topic": "Obstetrics", "q": "A pregnant woman with heart disease is at greatest risk of heart failure at which time?", "choices": ["During the first trimester", "Only before pregnancy begins", "Around 12 weeks gestation", "At 28-32 weeks and postpartum", "At six months postpartum"], "ans": 3, "exp": "ช่วงเสี่ยงสูงในหญิงตั้งครรภ์โรคหัวใจ: GA 28-32 wk (CO/blood volume สูงสุด) และหลังคลอดทันที (autotransfusion). โรคที่เป็นข้อห้ามตั้งครรภ์: Eisenmenger, severe pulmonary HT, severe symptomatic stenosis."}, {"topic": "Obstetrics", "q": "A pregnant woman is switched from her seizure medication because of high teratogenic risk. Which drug has the greatest risk of neural tube defects?", "choices": ["Lamotrigine", "Levetiracetam", "Carbamazepine", "Phenobarbital", "Valproate"], "ans": 4, "exp": "Valproate เสี่ยงสูงสุดต่อ neural tube defect และ neurodevelopmental impairment → เลี่ยงในหญิงวัยเจริญพันธุ์ (เปลี่ยนเป็น lamotrigine/levetiracetam), ให้ folate สูง, ใช้ monotherapy."}, {"topic": "Obstetrics", "q": "A woman with persistent occiput posterior position has a prolonged second stage. Which is a reasonable option in a suitable candidate?", "choices": ["Manual rotation or operative delivery", "Immediate cesarean in all cases", "Maximal-dose oxytocin infusion", "Vigorous fundal pressure", "Tocolysis to slow labor"], "ans": 0, "exp": "Persistent OP → prolonged 2nd stage. หลายรายหมุนเป็น OA เอง; ถ้าไม่ก้าวหน้าพิจารณา manual rotation หรือ operative vaginal delivery, หรือ cesarean ถ้ามี CPD/ล้มเหลว. ห้ามกด fundus."}, {"topic": "Obstetrics", "q": "A woman at 30 weeks sustains blunt abdominal trauma in a motor vehicle collision. Besides fetal monitoring, what should be given if she is Rh-negative?", "choices": ["Nothing is needed", "Anti-D immunoglobulin", "Antibiotics only", "Insulin", "Magnesium sulfate"], "ans": 1, "exp": "Trauma เสี่ยง placental abruption (แม้ไม่มีบาดเจ็บภายนอกชัด) → monitor FHR/contraction ≥4-6 ชม., ตรวจ Kleihauer-Betke, และให้ anti-D ถ้ามารดา Rh negative (FMH). ประเมินมารดาตามหลัก trauma."}, {"topic": "Obstetrics", "q": "A woman 1 week postpartum has persistent high fever unresponsive to antibiotics with no identifiable source. What is the likely diagnosis?", "choices": ["Simple endometritis", "Urinary tract infection", "Septic pelvic thrombophlebitis", "Mastitis", "Normal puerperium"], "ans": 2, "exp": "Septic pelvic thrombophlebitis: ไข้ที่ไม่ตอบสนองต่อยาปฏิชีวนะหลังคลอด/ผ่าตัดโดยไม่พบแหล่งติดเชื้อ (diagnosis of exclusion). จากลิ่มเลือดติดเชื้อในหลอดเลือดดำอุ้งเชิงกราน. รักษาด้วยยาปฏิชีวนะ + anticoagulation."}, {"topic": "Obstetrics", "q": "A woman 2 weeks postpartum has unilateral leg swelling, calf pain, and tenderness. What test should be performed?", "choices": ["Skin swab and culture", "Breast ultrasound", "Endometrial biopsy", "Compression ultrasound of the leg", "No investigation needed"], "ans": 3, "exp": "หลังคลอดเสี่ยง VTE สูงสุด. ขาบวมข้างเดียว ปวดน่อง กดเจ็บ = DVT → compression/Doppler ultrasound. ยืนยันแล้วให้ anticoagulation. ระวัง pulmonary embolism (เหนื่อย เจ็บอก) ซึ่งเป็นสาเหตุ maternal death สำคัญ."}, {"topic": "Obstetrics", "q": "After delivery of the placenta the fundus is not palpable and the mother is in shock with hemorrhage; a mass is seen at the introitus. What is the first step?", "choices": ["Give a uterotonic immediately", "Apply firm cord traction", "Perform immediate hysterectomy", "Observe expectantly for now", "Stop uterotonics, replace the uterus"], "ans": 4, "exp": "Uterine inversion เป็นภาวะฉุกเฉิน. ขั้นแรก: เรียกช่วยเหลือ, หยุด uterotonic (ให้มดลูกคลาย), ดันมดลูกกลับด้วยมือ (Johnson maneuver) อาจใช้ tocolytic/ยาสลบช่วย, กู้ชีพด้วยสารน้ำ/เลือด. กลับเข้าที่แล้วจึงให้ uterotonic."}, {"topic": "Obstetrics", "q": "A woman with prolonged rupture of membranes has maternal fever, maternal and fetal tachycardia, and uterine tenderness. What is the diagnosis and appropriate management?", "choices": ["Chorioamnionitis, antibiotics and delivery", "Normal labor, observe", "Preeclampsia, magnesium sulfate", "Abruption, immediate cesarean", "UTI, oral antibiotics"], "ans": 0, "exp": "Intraamniotic infection (chorioamnionitis): ไข้มารดา + fetal/maternal tachycardia, มดลูกกดเจ็บ, น้ำคร่ำมีกลิ่น. รักษาด้วย ampicillin + gentamicin และเร่งคลอด (คลอดทางช่องคลอดได้ ไม่ใช่ข้อบ่งชี้ผ่าคลอด). เสี่ยง PPH, neonatal sepsis."}, {"topic": "Obstetrics", "q": "An Rh-negative unsensitized woman has a first-trimester miscarriage. What should she receive?", "choices": ["Nothing is required", "Anti-D immunoglobulin", "Oxytocin only", "Antibiotics only", "Iron supplements only"], "ans": 1, "exp": "เหตุการณ์ที่ทำให้ FMH และต้องให้ anti-D (Rh negative unsensitized): แท้ง/ectopic/molar, เจาะน้ำคร่ำ/CVS, เลือดออก (abruption/previa), trauma, ECV, IUFD. + dose ประจำที่ 28 wk และหลังคลอด."}, {"topic": "Obstetrics", "q": "A woman at 37 weeks has term PROM with clear fluid and is GBS-positive but not in labor. What is the appropriate management?", "choices": ["Expectant care for 1 week", "Immediate cesarean", "Induction with GBS prophylaxis", "Tocolysis", "Corticosteroids"], "ans": 2, "exp": "Term PROM ที่ไม่เข้าสู่ระยะคลอดเอง → induction (ลด chorioamnionitis/neonatal infection) + GBS intrapartum prophylaxis. ไม่ต้อง steroid/tocolytic เพราะครบกำหนด."}, {"topic": "Obstetrics", "q": "Which drug is a known teratogen that should be avoided in pregnancy?", "choices": ["Insulin", "Methyldopa", "Penicillin", "Isotretinoin", "Paracetamol"], "ans": 3, "exp": "Isotretinoin (retinoid) เป็น teratogen รุนแรง (craniofacial/cardiac/CNS anomalies) → ห้ามในครรภ์ ต้องคุมกำเนิดเข้มงวด. teratogen อื่น: warfarin, ACEI/ARB, valproate, tetracycline, methotrexate. Insulin/methyldopa/paracetamol/penicillin ปลอดภัย."}, {"topic": "Obstetrics", "q": "A woman with GDM controlled on insulin is at 38 weeks. What is the recommended timing of delivery?", "choices": ["Wait until 42 weeks", "Await spontaneous labor indefinitely", "Immediate cesarean at 38 weeks", "At 34 weeks", "About 39 weeks"], "ans": 4, "exp": "GDM ที่ใช้ยา (insulin)/คุมไม่ดี แนะนำคลอด ~GA 39 wk (สมดุลระหว่าง stillbirth/macrosomia กับ prematurity). GDM คุมได้ดีด้วยอาหารรอได้ถึง 40-41 wk. ประเมิน EFW พิจารณา C/S ถ้า macrosomia มาก."}, {"topic": "Obstetrics", "q": "In a diabetic mother, cesarean delivery is offered to prevent shoulder dystocia when the estimated fetal weight reaches what threshold?", "choices": ["4,500 grams or more", "4,000 grams or more", "3,500 grams or more", "3,000 grams or more", "No threshold exists"], "ans": 0, "exp": "ACOG แนะนำพิจารณา cesarean เพื่อป้องกัน shoulder dystocia เมื่อ EFW ≥4,500 g ในมารดาเบาหวาน และ ≥5,000 g ในมารดาไม่เบาหวาน (US ทำนาย macrosomia คลาดเคลื่อน). วินิจฉัย macrosomia = EFW >4,000-4,500 g."}, {"topic": "Obstetrics", "q": "A woman with isolated gestational hypertension without severe features should be delivered at what gestational age?", "choices": ["34 weeks", "37 weeks", "40 weeks", "42 weeks", "Await spontaneous labor"], "ans": 1, "exp": "Gestational hypertension/preeclampsia without severe features แนะนำคลอดที่ GA 37 wk. Preeclampsia with severe features คลอดที่ 34 wk (หรือเร็วกว่าถ้าไม่คงที่). ก่อนถึงกำหนดต้องเฝ้าระวังการดำเนินโรค."}, {"topic": "Obstetrics", "q": "A woman at 12 weeks has severe nausea and vomiting with 6% weight loss and ketonuria. Besides supportive care, what should be done?", "choices": ["Discharge home without workup", "Empiric broad-spectrum antibiotics", "Ultrasound to exclude molar/multiple", "Immediate exploratory surgery", "Upper GI endoscopy now"], "ans": 2, "exp": "Hyperemesis gravidarum: คลื่นไส้อาเจียนรุนแรง น้ำหนักลด >5%, ketonuria. สัมพันธ์ hCG สูง → ควร US แยก molar/แฝด. รักษา: สารน้ำ, B6 ± doxylamine, antiemetic, thiamine (ป้องกัน Wernicke)."}, {"topic": "Obstetrics", "q": "A woman at 36 weeks has severe pruritus of the palms and soles worst at night with elevated bile acids. What is the diagnosis and its main risk?", "choices": ["PUPPP with no fetal risk", "Eczema needing topical cream", "Scabies needing a scabicide", "Intrahepatic cholestasis, stillbirth risk", "Normal pregnancy-related itch"], "ans": 3, "exp": "Intrahepatic cholestasis of pregnancy: คันรุนแรง (ฝ่ามือ/ฝ่าเท้า เด่นกลางคืน) ไม่มีผื่น, bile acid สูง. เสี่ยง sudden fetal death/stillbirth, meconium, preterm. รักษา ursodeoxycholic acid, คลอด ~37 wk (เร็วกว่าถ้า bile acid สูงมาก)."}, {"topic": "Obstetrics", "q": "A woman on magnesium sulfate becomes drowsy with absent reflexes and a respiratory rate of 10. What is the immediate management?", "choices": ["Increase the magnesium dose", "Administer furosemide now", "Administer naloxone now", "Administer flumazenil now", "Stop magnesium, give calcium"], "ans": 4, "exp": "ซึม, loss of DTR, RR ต่ำ = magnesium toxicity → หยุด MgSO4 ทันที และให้ calcium gluconate IV (antidote). ประเมิน airway/breathing, ตรวจ serum Mg และ renal function."}, {"topic": "Obstetrics", "q": "A woman with chronic hypertension presents for care. Which antihypertensive is safe and commonly used in pregnancy?", "choices": ["Labetalol", "Enalapril", "Losartan", "Atenolol", "Spironolactone"], "ans": 0, "exp": "ยาลดความดันปลอดภัยในครรภ์: methyldopa, labetalol, nifedipine. ห้าม ACEI/ARB (teratogen, fetal renal/oligohydramnios) และ atenolol (สัมพันธ์ FGR). Chronic HT ควรได้ aspirin ป้องกัน superimposed preeclampsia."}, {"topic": "Obstetrics", "q": "A woman with two prior low-transverse cesareans presents in labor at 39 weeks and desires vaginal delivery. What is the most appropriate recommendation?", "choices": ["Fully support VBAC", "Recommend repeat cesarean", "Prostaglandin induction", "Vacuum delivery", "Await spontaneous labor"], "ans": 1, "exp": "การเคยผ่าคลอด ≥2 ครั้งเพิ่มความเสี่ยง uterine rupture → ส่วนใหญ่แนะนำ repeat elective cesarean. ห้าม induction ด้วย prostaglandin ในผู้มีแผลผ่าคลอด (เพิ่ม rupture)."}, {"topic": "Obstetrics", "q": "A pregnant woman with SLE is anti-Ro/SSA positive. Which fetal complication is of particular concern?", "choices": ["Macrosomia", "Cleft palate alone", "Congenital heart block", "Hydrocephalus alone", "Erb palsy"], "ans": 2, "exp": "Anti-Ro/SSA ผ่านรกทำลาย fetal cardiac conduction → congenital complete heart block (neonatal lupus). เฝ้าระวัง fetal heart rate/echo ช่วง 16-26 wk. SLE ที่ active เสี่ยง preeclampsia, FGR, pregnancy loss (โดยเฉพาะมี APS)."}, {"topic": "Obstetrics", "q": "A woman at 40 weeks in labor has an active genital herpes lesion. What is the appropriate mode of delivery?", "choices": ["Normal vaginal delivery", "Antibiotics then vaginal delivery", "Vacuum extraction", "Cesarean section", "Await lesion healing"], "ans": 3, "exp": "Active genital HSV lesion/prodrome ขณะเจ็บครรภ์ = ข้อบ่งชี้ผ่าคลอด ลดความเสี่ยง neonatal herpes (รุนแรง). ผู้มีประวัติ HSV ควรได้ acyclovir suppression ตั้งแต่ ~36 wk เพื่อลดการกำเริบ."}, {"topic": "Obstetrics", "q": "A 39-week frank breech with an estimated fetal weight of 3,000 g and adequate pelvis presents in labor. What is the most widely recommended approach today?", "choices": ["Vaginal breech delivery always", "Oxytocin augmentation", "Forceps-assisted delivery", "Await spontaneous version", "Planned cesarean delivery"], "ans": 4, "exp": "ตาม Term Breech Trial การผ่าคลอดในทารกท่าก้นครบกำหนดลด perinatal morbidity → นิยม. ทางเลือกป้องกันคือ ECV ที่ ~37 wk. การคลอดท่าก้นทางช่องคลอดยังทำได้ในเงื่อนไขจำกัดโดยผู้เชี่ยวชาญ."}, {"topic": "Obstetrics", "q": "A woman at 8 weeks has asymptomatic bacteriuria on screening urine culture. What is the appropriate management?", "choices": ["Treat with a pregnancy-safe antibiotic", "No treatment since asymptomatic", "Give a diuretic", "Wait for symptoms", "Refer for surgery"], "ans": 0, "exp": "Asymptomatic bacteriuria ในครรภ์ต้องรักษา (ต่างจากคนทั่วไป) เพราะเสี่ยง pyelonephritis และ preterm/LBW. คัดกรองด้วย urine culture ไตรมาสแรก, เลือกยาปลอดภัย, และ test of cure."}, {"topic": "Obstetrics", "q": "A pregnant woman with microcytic anemia (Hb 8), a family history of thalassemia, and normal iron studies should undergo which next step?", "choices": ["Give oral iron and stop", "Hemoglobin typing, test partner", "Proceed to cesarean delivery", "Immediate blood transfusion", "Check thyroid function only"], "ans": 1, "exp": "Microcytic anemia + ประวัติครอบครัว ต้องแยกธาลัสซีเมียจากขาดเหล็ก → Hb typing (± DNA) และประเมินคู่สมรส. คู่เสี่ยง → prenatal diagnosis (ทารกเสี่ยง Bart's hydrops/β-thal major). หัวใจของโครงการควบคุมธาลัสซีเมียไทย."}, {"topic": "Obstetrics", "q": "In which condition does blood infiltrate the myometrium, giving the uterus a purplish appearance (Couvelaire uterus)?", "choices": ["Placenta previa alone", "Uterine atony", "Severe placental abruption", "Molar pregnancy alone", "Ectopic pregnancy alone"], "ans": 2, "exp": "Couvelaire uterus (uteroplacental apoplexy) เกิดใน severe abruption — เลือดแทรกชั้นกล้ามเนื้อและ serosa ทำให้มดลูกม่วงคล้ำ. อาจสัมพันธ์ atony/PPH. ส่วนใหญ่มดลูกยังหดตัวได้ ไม่จำเป็นต้องตัดมดลูกเสมอ."}, {"topic": "Obstetrics", "q": "A pregnant woman with a history of VTE or thrombophilia needs prophylaxis. Which agent is appropriate?", "choices": ["Warfarin throughout pregnancy", "No treatment needed", "High-dose aspirin", "Low-molecular-weight heparin", "Vitamin K"], "ans": 3, "exp": "เสี่ยง VTE สูง → thromboprophylaxis ด้วย LMWH/heparin (ไม่ผ่านรก ปลอดภัยในครรภ์). หลีกเลี่ยง warfarin (teratogen, fetal bleeding) ยกเว้นบางกรณี (mechanical valve). ปรับแผนช่วงคลอดเรื่อง neuraxial anesthesia."}, {"topic": "Obstetrics", "q": "A woman at 30 weeks in preterm labor is started on nifedipine as a tocolytic. What side effect should be monitored?", "choices": ["Increased urine output", "Ductus arteriosus closure", "Palpitations from beta-agonism", "Respiratory depression", "Hypotension and headache"], "ans": 4, "exp": "Nifedipine (calcium channel blocker) ยับยั้งการหดตัวมดลูก (นิยมเพราะให้ทางปาก ผลข้างเคียงน้อย). ผลข้างเคียง: hypotension, ปวดศีรษะ, หน้าแดง, ใจสั่น. เลี่ยงใช้ร่วม MgSO4 ขนาดสูงพร้อมกัน."}, {"topic": "Obstetrics", "q": "A GBS-positive woman is in labor. What should she receive?", "choices": ["Intrapartum penicillin prophylaxis", "No specific intervention", "Elective cesarean section", "Antiviral therapy", "Magnesium sulfate infusion"], "ans": 0, "exp": "GBS positive → intrapartum antibiotic prophylaxis (penicillin G IV เป็นตัวแรก) เมื่อเข้าสู่ระยะคลอด/ถุงน้ำแตก เพื่อป้องกัน early-onset GBS disease. ให้ ≥4 ชม.ก่อนคลอด. ยกเว้นผ่าคลอดก่อนเจ็บครรภ์และถุงน้ำยังไม่แตก."}, {"topic": "Obstetrics", "q": "A woman had a prior infant with invasive GBS disease. What is the appropriate approach in this pregnancy?", "choices": ["Culture first always", "Intrapartum prophylaxis without culture", "No antibiotics", "Cesarean section", "Treatment from the first trimester"], "ans": 1, "exp": "ข้อบ่งชี้ให้ GBS prophylaxis โดยไม่ต้องรอ culture: เคยมีบุตร invasive GBS, GBS bacteriuria ครรภ์นี้, ผลคัดกรอง positive, หรือสถานะไม่ทราบ + ปัจจัยเสี่ยง (<37 wk, ถุงน้ำแตก ≥18 ชม., ไข้)."}, {"topic": "Obstetrics", "q": "A woman at 28 weeks with severe early-onset FGR has absent umbilical artery end-diastolic flow. What is the most appropriate management?", "choices": ["Routine follow-up in 4 weeks", "Give hematinic supplements", "Admit for close fetal surveillance", "Immediate cesarean in all cases", "Discontinue all prenatal care"], "ans": 2, "exp": "Severe early-onset FGR + absent EDF บ่งชี้ placental insufficiency รุนแรง เสี่ยง fetal demise → admit, surveillance ใกล้ชิด (Doppler, BPP), ให้ steroid และ MgSO4 (<32 wk) เตรียมคลอด. Timing สมดุลระหว่าง prematurity กับความเสี่ยง fetal death."}, {"topic": "Obstetrics", "q": "A woman received a full course of betamethasone at 29 weeks and is now at risk of delivery again at 33 weeks. What should be considered?", "choices": ["Repeat multiple full courses", "No further steroids at all", "Switch to hydrocortisone instead", "A single rescue steroid course", "Give magnesium instead of steroid"], "ans": 3, "exp": "หากให้ course แรก >14 วันก่อน และยังเสี่ยงคลอดใน 7 วันที่ GA <34 wk พิจารณา single rescue course ได้ — แต่ไม่แนะนำหลายรอบ (multiple courses) เพราะสัมพันธ์กับ FGR/ปัญหาพัฒนาการ."}, {"topic": "Obstetrics", "q": "A woman at 41 weeks has a non-reactive NST followed by a BPP of 4/10 with oligohydramnios. What is the appropriate management?", "choices": ["Repeat testing next week", "Give hematinics", "Wait until 43 weeks", "Give tocolytics", "Proceed with delivery"], "ans": 4, "exp": "BPP ≤4/10 + oligohydramnios ในครรภ์เกินกำหนด บ่งชี้ fetal compromise → พิจารณาให้คลอด (induction/cesarean ตามสภาพปากมดลูก/FHR). การรอเพิ่มความเสี่ยง stillbirth. ทารกครบกำหนดแล้วจึงคลอดได้."}, {"topic": "Obstetrics", "q": "A woman at 34 weeks presents with BP 160/110, a severe headache, blurred vision, and brisk reflexes. What is the appropriate urgent management?", "choices": ["Admit, magnesium, plan delivery", "Discharge with follow-up next week", "Analgesia and simple observation", "Give low-dose aspirin only", "Reassurance and ultrasound only"], "ans": 0, "exp": "Preeclampsia with severe features (BP ≥160/110 + อาการทางสมอง/ตา = เสี่ยง eclampsia) → admit, MgSO4, ยาลดความดัน (labetalol/hydralazine/nifedipine), steroid ถ้า <34 wk, และวางแผนคลอด (severe features ที่ ≥34 wk → คลอด)."}, {"topic": "Obstetrics", "q": "A woman at 33 weeks with preterm labor is a candidate for magnesium sulfate neuroprotection. This is recommended when delivery is anticipated before which gestational age?", "choices": ["37 weeks", "32 weeks", "34 weeks", "28 weeks", "24 weeks"], "ans": 1, "exp": "[อัปเดต] MgSO4 ให้เพื่อ fetal neuroprotection (ลด cerebral palsy) เมื่อคาดว่าจะคลอดก่อน GA 32 wk — คนละบทบาทกับ MgSO4 ใน preeclampsia (ป้องกันชัก ทุกอายุครรภ์ที่ severe)."}, {"topic": "Obstetrics", "q": "A neonate born to a mother with poorly controlled gestational diabetes is at risk of which early complication?", "choices": ["Hyperbilirubinemia only", "Necrotizing enterocolitis", "Neonatal hypoglycemia", "Cataract", "Congenital heart block"], "ans": 2, "exp": "ทารกจากแม่ GDM มี fetal hyperinsulinemia → neonatal hypoglycemia (ตรวจน้ำตาลหลังเกิด), macrosomia, shoulder dystocia, RDS, hyperbilirubinemia, polyhydramnios."}, {"topic": "Obstetrics", "q": "A woman at 26 weeks presents for routine care. Which screening is due at 24-28 weeks?", "choices": ["The fetal anomaly scan", "Group B streptococcus culture", "Nuchal translucency scan", "Gestational diabetes screening", "The quadruple serum test"], "ans": 3, "exp": "ช่วง GA 24-28 wk เป็นกำหนดคัดกรอง GDM และตรวจ Hb ซ้ำ. Anomaly scan 18-22 wk, NT 11-14 wk, GBS 36-37+6 wk."}, {"topic": "Obstetrics", "q": "A woman at 28 weeks has a fundal height of 34 cm; ultrasound shows an amniotic fluid index of 28 cm. What condition should be considered?", "choices": ["Oligohydramnios", "Growth restriction", "Fetal demise", "Normal fluid volume", "Polyhydramnios"], "ans": 4, "exp": "AFI >25 cm = polyhydramnios ทำให้ SFH มากกว่าอายุครรภ์. สาเหตุ: เบาหวาน, ความผิดปกติทารกที่รบกวนการกลืน (esophageal/duodenal atresia, anencephaly), hydrops, แฝด/TTTS. ตรวจ anomaly scan + คัดกรองเบาหวาน."}, {"topic": "Obstetrics", "q": "A woman with severe preeclampsia at 30 weeks has stable vital signs after magnesium and antihypertensives. What is the next appropriate step before delivery?", "choices": ["Administer antenatal corticosteroids", "Immediate delivery regardless", "Start oral iron therapy", "Discharge home on medication", "Give prophylactic antibiotics"], "ans": 0, "exp": "Preeclampsia with severe features <34 wk ที่เสถียร → ให้ antenatal corticosteroid (lung maturity) ก่อนคลอด และคลอดที่ ~34 wk (หรือเร็วกว่าถ้าไม่คงที่/มีภาวะแทรกซ้อน). MgSO4 ป้องกันชักต่อเนื่อง."}, {"topic": "Obstetrics", "q": "A woman with a molar pregnancy is being followed after evacuation. What is essential during follow-up?", "choices": ["Immediate next pregnancy", "Serial beta-hCG with contraception", "Prophylactic chemotherapy", "Annual ultrasound only", "No specific follow-up"], "ans": 1, "exp": "หลัง evacuation ต้องติดตาม serial β-hCG จนเป็นลบต่อเนื่อง เพื่อตรวจจับ GTN. คุมกำเนิดระหว่างติดตาม (ห้ามตั้งครรภ์ เพราะทำให้แปลผล hCG ไม่ได้). hCG plateau/สูงขึ้น = GTN → เคมีบำบัด."}, {"topic": "Obstetrics", "q": "A woman at 34 weeks with twins is counseled on the most important factor determining monitoring intensity. What is it?", "choices": ["Maternal age", "Fetal sex", "Chorionicity", "Maternal weight", "Parity"], "ans": 2, "exp": "Chorionicity สำคัญที่สุดในการดูแลครรภ์แฝด: monochorionic เสี่ยง TTTS/sFGR/TAPS ต้อง US ถี่กว่า. ประเมินในไตรมาสแรก (lambda = dichorionic, T-sign = monochorionic)."}, {"topic": "Obstetrics", "q": "A woman with type 1 diabetes had poor glycemic control in early pregnancy. Which fetal anomaly is characteristically associated?", "choices": ["Meconium aspiration", "Erb palsy", "Cataract", "Caudal regression syndrome", "Congenital heart block"], "ans": 3, "exp": "Pregestational DM ที่น้ำตาลสูงช่วง organogenesis เพิ่ม cardiac defects (บ่อยสุด), neural tube defects, และ caudal regression syndrome (จำเพาะกับเบาหวาน). เน้น preconception glycemic control + folate. ต่างจาก GDM (macrosomia/hypoglycemia)."}, {"topic": "Obstetrics", "q": "A woman with hyperthyroidism from Graves disease is pregnant in the first trimester. Which antithyroid drug is preferred at this stage?", "choices": ["Methimazole", "Radioactive iodine", "Levothyroxine", "Propranolol alone", "Propylthiouracil"], "ans": 4, "exp": "ไตรมาสแรกใช้ PTU (methimazole เสี่ยง aplasia cutis/embryopathy), แล้วเปลี่ยนเป็น methimazole ไตรมาส 2-3 (PTU เสี่ยง hepatotoxicity). ห้าม radioactive iodine (ทำลายต่อมทารก). เฝ้าระวัง neonatal thyrotoxicosis จาก TSI ผ่านรก."}]}, {"id": "obgyn3", "title": "Ob-gyne ชุดที่ 3 — Gynecology I (Menstrual Cycle, Amenorrhea & PCOS, AUB, Endometriosis, Menopause)", "subject": "obgyn", "questions": [{"topic": "Gynecology", "q": "During embryologic development, the Müllerian (paramesonephric) ducts give rise to which structures?", "choices": ["Tubes, uterus, cervix, upper vagina", "The ovaries and gonads", "The male genital structures", "The lower two-thirds of vagina", "The bladder and urethra"], "ans": 0, "exp": "Müllerian ducts พัฒนาเป็นท่อนำไข่ มดลูก ปากมดลูก และช่องคลอดส่วนบน 1/3. ช่องคลอดส่วนล่างมาจาก urogenital sinus. รังไข่มาจาก gonadal ridge. ในชาย AMH ทำให้ Müllerian ฝ่อ."}, {"topic": "Gynecology", "q": "A 16-year-old with normal breasts and pubic hair has never menstruated. She has an absent uterus and upper vagina but a 46,XX karyotype with normal ovaries. What is the diagnosis?", "choices": ["Androgen insensitivity syndrome", "Müllerian agenesis (MRKH)", "Turner syndrome", "Polycystic ovary syndrome", "Imperforate hymen"], "ans": 1, "exp": "Müllerian agenesis (MRKH): 46,XX, รังไข่/ฮอร์โมนปกติ (ลักษณะทางเพศปกติ) แต่ไม่มีมดลูก/ช่องคลอดส่วนบน → primary amenorrhea. ต่างจาก AIS (46,XY, ไม่มีขนหัวหน่าว, มี testis)."}, {"topic": "Gynecology", "q": "A 17-year-old with normal breasts but absent pubic and axillary hair has intra-abdominal testes and a 46,XY karyotype. What is the diagnosis?", "choices": ["Müllerian agenesis (MRKH)", "Turner syndrome", "Complete androgen insensitivity", "5-alpha reductase deficiency", "Kallmann syndrome"], "ans": 2, "exp": "Complete AIS: 46,XY มี testis สร้าง testosterone/AMH ปกติ แต่ receptor ไม่ทำงาน → external genitalia เป็นหญิง, มีเต้านม (aromatization) แต่ไม่มีขน (androgen-dependent) และไม่มีมดลูก (AMH). แนะนำ gonadectomy หลัง puberty."}, {"topic": "Gynecology", "q": "Which Müllerian anomaly is most associated with recurrent pregnancy loss and treated by hysteroscopic resection?", "choices": ["Bicornuate uterus", "Uterine didelphys", "Unicornuate uterus", "Septate uterus", "Arcuate uterus"], "ans": 3, "exp": "Septate uterus (ผนังกั้นในโพรงมดลูก) สัมพันธ์ recurrent pregnancy loss มากที่สุด (septum เลือดเลี้ยงน้อย ฝังตัวไม่ดี). รักษาด้วย hysteroscopic septum resection. เกิดจากความล้มเหลวของ resorption (ต่างจาก bicornuate = fusion defect)."}, {"topic": "Gynecology", "q": "What is the correct sequence of pubertal development in girls?", "choices": ["Menarche, thelarche, pubarche", "Pubarche, menarche, thelarche", "Growth spurt, menarche, thelarche", "Menarche, growth spurt, thelarche", "Thelarche, pubarche, growth spurt, menarche"], "ans": 4, "exp": "ลำดับ puberty หญิง: thelarche (เต้านม-แรก) → pubarche/adrenarche (ขน) → growth spurt → menarche (สุดท้าย). Menarche เกิดหลัง thelarche ~2-3 ปี. ลำดับผิดปกติบ่งชี้พยาธิสภาพ."}, {"topic": "Gynecology", "q": "Precocious puberty in a girl is defined as development of secondary sexual characteristics before what age?", "choices": ["Eight years", "Six years", "Fourteen years", "Ten years", "Twelve years"], "ans": 0, "exp": "Precocious puberty หญิง = ลักษณะทางเพศทุติยภูมิก่อนอายุ 8 ปี (หรือ menarche ก่อน 9-10). แบ่ง central (GnRH-dependent, มัก idiopathic) และ peripheral (cyst, McCune-Albright, CAH). ประเมิน bone age, GnRH stimulation, imaging."}, {"topic": "Gynecology", "q": "In the menstrual cycle, which event triggers ovulation?", "choices": ["An isolated FSH surge", "An LH surge from rising estrogen", "A mid-cycle progesterone surge", "A rise in hCG", "A sudden fall in estrogen"], "ans": 1, "exp": "Estrogen สูงจาก dominant follicle ปลาย follicular phase มี positive feedback → LH surge → ovulation (~36 ชม.หลัง surge). หลัง ovulation corpus luteum สร้าง progesterone (luteal phase คงที่ 14 วัน)."}, {"topic": "Gynecology", "q": "What is the approximately fixed length of the luteal phase of the menstrual cycle?", "choices": ["Seven days", "Ten days", "Fourteen days", "Highly variable", "Twenty-one days"], "ans": 2, "exp": "Luteal phase (หลัง ovulation ถึงก่อนประจำเดือน) คงที่ ~14 วัน (อายุขัย corpus luteum). ความแปรผันของรอบเดือนมาจาก follicular phase. รอบ 35 วัน → ovulation ~วันที่ 21."}, {"topic": "Gynecology", "q": "During the secretory phase of the endometrium, which hormone is the main driver?", "choices": ["Estrogen", "hCG", "FSH", "Progesterone", "LH"], "ans": 3, "exp": "หลัง ovulation corpus luteum สร้าง progesterone เปลี่ยน endometrium เป็น secretory (ต่อมขดตัว หลั่ง glycogen เตรียม implantation). ไม่ตั้งครรภ์ → corpus luteum ฝ่อ → progesterone ลด → ประจำเดือน."}, {"topic": "Gynecology", "q": "How is primary amenorrhea defined?", "choices": ["Absence of menses for three months", "No menses following a delivery", "Absence of menses for six months", "Scanty, infrequent menstrual flow", "No menses by 15 with normal development"], "ans": 4, "exp": "Primary amenorrhea = ไม่เคยมีประจำเดือนเมื่ออายุ 15 ปี (มีลักษณะทางเพศ) หรือ 13 ปี (ไม่มีลักษณะทางเพศ). Secondary = เคยมีแล้วขาด ≥3 เดือน (รอบสม่ำเสมอ) หรือ ≥6 เดือน. แยกการตั้งครรภ์ก่อนเสมอ."}, {"topic": "Gynecology", "q": "In evaluating a woman with secondary amenorrhea, which test should always be done first?", "choices": ["A pregnancy test (beta-hCG)", "Serum prolactin", "Serum FSH", "Serum TSH", "Pelvic ultrasound alone"], "ans": 0, "exp": "การตั้งครรภ์เป็นสาเหตุ secondary amenorrhea ที่พบบ่อยที่สุด จึงตรวจ β-hCG ก่อนเสมอ. จากนั้น TSH และ prolactin แล้วประเมิน estrogen status ด้วย progestin challenge."}, {"topic": "Gynecology", "q": "A woman with secondary amenorrhea has withdrawal bleeding after a progestin challenge test. What does this indicate?", "choices": ["Significant estrogen deficiency", "Adequate estrogen with anovulation", "Primary ovarian failure", "An outflow tract obstruction", "An early pregnancy"], "ans": 1, "exp": "Withdrawal bleeding หลัง progestin = มี endometrium ที่ถูก prime ด้วย estrogen เพียงพอ และ outflow tract เปิด → anovulation (มี estrogen แต่ไม่มี ovulation/progesterone) เช่น PCOS. ไม่ออก → estrogen ต่ำ หรือ outflow obstruction."}, {"topic": "Gynecology", "q": "How many of the three Rotterdam criteria are required to diagnose polycystic ovary syndrome?", "choices": ["One of three", "Three of three", "Two of three", "Not based on count", "Hyperandrogenism alone"], "ans": 2, "exp": "Rotterdam: ต้องมี 2 ใน 3 — oligo/anovulation, hyperandrogenism (คลินิก/ชีวเคมี), polycystic ovaries (US ≥12 follicles/volume >10 mL). [อัปเดต] 2023 ยอมใช้ AMH สูงแทน US ในผู้ใหญ่. ต้องแยกสาเหตุอื่นก่อน."}, {"topic": "Gynecology", "q": "Which long-term risk is associated with polycystic ovary syndrome?", "choices": ["Cervical cancer", "Ovarian germ cell tumor", "Thalassemia", "Endometrial hyperplasia and cancer", "Congenital heart disease"], "ans": 3, "exp": "PCOS สัมพันธ์ insulin resistance → DM2, metabolic syndrome. Chronic anovulation → unopposed estrogen → endometrial hyperplasia/มะเร็งเยื่อบุโพรงมดลูก. จึงควรคุมรอบเดือน (progestin/OC) ป้องกัน."}, {"topic": "Gynecology", "q": "What is the first-line ovulation induction agent for a woman with PCOS who desires pregnancy?", "choices": ["Clomiphene citrate", "Metformin", "Gonadotropin", "GnRH agonist", "Letrozole"], "ans": 4, "exp": "[อัปเดต] Letrozole (aromatase inhibitor) เป็นตัวเลือกแรกใน ovulation induction ใน PCOS (อัตราคลอดมีชีพสูงกว่า clomiphene). ลดน้ำหนักเป็นการรักษาพื้นฐานสำคัญ."}, {"topic": "Gynecology", "q": "In the PALM-COEIN classification of abnormal uterine bleeding, what does 'PALM' represent?", "choices": ["Structural causes", "Non-structural causes", "Coagulation disorders", "Malignancy only", "Ovulatory dysfunction"], "ans": 0, "exp": "PALM = structural causes (Polyp, Adenomyosis, Leiomyoma, Malignancy/hyperplasia) ตรวจด้วย imaging/histology. COEIN = non-structural (Coagulopathy, Ovulatory dysfunction, Endometrial, Iatrogenic, Not classified)."}, {"topic": "Gynecology", "q": "A 14-year-old has had heavy menstrual bleeding since menarche. What are the most likely causes?", "choices": ["Endometrial carcinoma", "Anovulation or coagulopathy", "Endometrial polyp", "Uterine fibroids", "Pregnancy"], "ans": 1, "exp": "AUB วัยรุ่นมักจาก anovulatory cycle (HPO axis ยังไม่สมบูรณ์) → unopposed estrogen → heavy/irregular bleeding. เลือดออกมากตั้งแต่ menarche ควรคัดกรอง bleeding disorder (von Willebrand พบบ่อยสุด)."}, {"topic": "Gynecology", "q": "A 58-year-old postmenopausal woman has vaginal bleeding. What must be excluded first, and how?", "choices": ["Atrophic vaginitis by cream trial", "Fibroid by surgery", "Endometrial cancer by biopsy/TVS", "Pregnancy by hCG", "UTI by urinalysis"], "ans": 2, "exp": "Postmenopausal bleeding ต้องแยกมะเร็งเยื่อบุโพรงมดลูกก่อนเสมอ (แม้สาเหตุบ่อยสุดจริงคือ atrophy). ประเมินด้วย TVS (endometrial thickness >4 mm → ตรวจต่อ) และ/หรือ endometrial biopsy (gold standard)."}, {"topic": "Gynecology", "q": "In a postmenopausal woman with bleeding, what endometrial thickness on ultrasound warrants further evaluation?", "choices": ["Over 10 mm", "Over 15 mm", "Over 20 mm", "Over 4 mm", "Any thickness"], "ans": 3, "exp": "Postmenopausal bleeding + endometrial thickness (TVS) >4 mm → ควรตรวจเพิ่ม (biopsy/hysteroscopy) เพราะเสี่ยงมะเร็ง/hyperplasia. ≤4 mm ความเสี่ยงต่ำมาก. ถ้าเลือดออกซ้ำแม้ endometrium บางก็ควรตรวจชิ้นเนื้อ."}, {"topic": "Gynecology", "q": "What is the mechanism and first-line treatment of primary dysmenorrhea?", "choices": ["Endometriosis, treated surgically", "Infection, treated with antibiotics", "Fibroid, treated by myomectomy", "Adenomyosis, treated by hysterectomy", "Excess prostaglandins, treated with NSAIDs"], "ans": 4, "exp": "Primary dysmenorrhea (ไม่มีพยาธิสภาพ) เกิดจาก prostaglandin สูง → uterine hypercontractility/ischemia. รักษาด้วย NSAIDs (ยับยั้ง prostaglandin) และ/หรือ combined OC. ต่างจาก secondary (มีพยาธิสภาพ)."}, {"topic": "Gynecology", "q": "A woman has dysmenorrhea, dyspareunia, dyschezia, and infertility. What is the most likely diagnosis?", "choices": ["Endometriosis", "Polycystic ovary syndrome", "Uterine fibroids", "Pelvic inflammatory disease", "Adenomyosis"], "ans": 0, "exp": "Endometriosis มีอาการ '3D': Dysmenorrhea, Dyspareunia, Dyschezia + infertility. ตำแหน่งพบบ่อย: รังไข่ (endometrioma/chocolate cyst), cul-de-sac, uterosacral ligament."}, {"topic": "Gynecology", "q": "What is the gold standard for diagnosing endometriosis?", "choices": ["Ultrasound", "Laparoscopy", "Serum CA-125", "MRI", "Pelvic examination"], "ans": 1, "exp": "Laparoscopy เป็น gold standard (เห็นรอยโรค: powder-burn lesions, endometrioma, adhesions ± histology). US พบ endometrioma แต่ไม่เห็น peritoneal implants. CA-125 ไม่จำเพาะ. ปัจจุบันเริ่มรักษา empirically ได้."}, {"topic": "Gynecology", "q": "What is the goal of medical therapy for endometriosis?", "choices": ["Increase estrogen levels", "Increase ovulation", "Create a hypoestrogenic state", "Give antibiotics", "Increase prostaglandins"], "ans": 2, "exp": "Endometriosis เป็น estrogen-dependent → รักษาด้วยยาที่ลด estrogen: OC, progestin (dienogest, LNG-IUS), GnRH agonist/antagonist (hypoestrogenic - ระวังกระดูก, ใช้ add-back), NSAIDs. ดื้อยา/มีบุตรยาก → ผ่าตัด."}, {"topic": "Gynecology", "q": "A 42-year-old multipara has a symmetrically enlarged, soft, tender uterus with menorrhagia and worsening dysmenorrhea. What is the diagnosis?", "choices": ["Uterine fibroid", "Endometrial polyp", "Ovarian cyst", "Adenomyosis", "Cervical cancer"], "ans": 3, "exp": "Adenomyosis = เยื่อบุโพรงมดลูกในชั้นกล้ามเนื้อ → มดลูกโตสมมาตร นุ่ม กดเจ็บ (globular/boggy), menorrhagia + dysmenorrhea. วินิจฉัย US/MRI (junctional zone หนา). รักษาชัดเจน = hysterectomy."}, {"topic": "Gynecology", "q": "A woman has severe premenstrual mood symptoms confined to the luteal phase. Which treatment is effective?", "choices": ["Antibiotics", "Analgesics alone", "Thyroid hormone alone", "Sleeping pills alone", "SSRIs and/or combined OC"], "ans": 4, "exp": "PMDD (อาการทางอารมณ์รุนแรงในระยะ luteal) รักษาด้วย SSRIs (fluoxetine/sertraline - ต่อเนื่องหรือเฉพาะ luteal) และ combined OC (โดยเฉพาะ drospirenone). ร่วมกับปรับพฤติกรรม."}, {"topic": "Gynecology", "q": "How is menopause defined?", "choices": ["Amenorrhea for 12 months", "Irregular menstrual cycles", "Age 45 or older", "Low FSH", "Reduced menstrual flow"], "ans": 0, "exp": "Menopause = ขาดประจำเดือนต่อเนื่อง ≥12 เดือน (วินิจฉัยย้อนหลัง) จากรังไข่หยุดทำงาน (estrogen ต่ำ, FSH สูง). อายุเฉลี่ย ~51 ปี. ก่อน 40 ปี = premature ovarian insufficiency."}, {"topic": "Gynecology", "q": "Which symptoms comprise the genitourinary syndrome of menopause?", "choices": ["Hot flashes and night sweats", "Vaginal dryness, dyspareunia, dysuria", "Headache and dizziness", "Heavy menstrual bleeding", "Acne and hirsutism"], "ans": 1, "exp": "GSM (เดิม vulvovaginal atrophy) จาก estrogen ต่ำ: ช่องคลอดแห้ง แสบ คัน, dyspareunia, ปัสสาวะบ่อย/แสบขัด/ติดเชื้อซ้ำ. รักษาดีด้วย low-dose vaginal estrogen หรือ moisturizer/lubricant."}, {"topic": "Gynecology", "q": "According to the NAMS 2022 position statement, hormone therapy has a favorable benefit-risk ratio in which group?", "choices": ["Any age regardless of health", "A history of breast cancer", "Under 60 or within 10 years of menopause", "Over 65 years of age", "A history of prior VTE"], "ans": 2, "exp": "[อัปเดต NAMS 2022] HT มี benefit-risk ดีในหญิงอายุ <60 ปี หรือภายใน 10 ปีหลัง menopause ที่ไม่มีข้อห้าม ('timing hypothesis'). เริ่มช้า (>60/>10 ปี) เสี่ยง CHD, stroke, VTE, dementia เพิ่ม."}, {"topic": "Gynecology", "q": "A woman with an intact uterus receives estrogen therapy. What must be added to prevent endometrial cancer?", "choices": ["Nothing additional", "Testosterone", "Calcium only", "A progestogen", "Aspirin"], "ans": 3, "exp": "หญิงมีมดลูกใช้ systemic estrogen ต้องได้ progestogen ร่วม (combined HT) เพราะ unopposed estrogen → endometrial hyperplasia/มะเร็ง. ตัดมดลูกแล้วใช้ estrogen เดี่ยวได้. LNG-IUS เป็นทางเลือกให้ progestin."}, {"topic": "Gynecology", "q": "A postmenopausal woman has only genitourinary symptoms (vaginal dryness, dyspareunia). What is the most appropriate treatment?", "choices": ["High-dose systemic estrogen", "Pelvic surgery", "SSRIs", "Bisphosphonate", "Low-dose vaginal estrogen"], "ans": 4, "exp": "GSM อย่างเดียว (ไม่มี vasomotor) → low-dose vaginal estrogen (ออกฤทธิ์เฉพาะที่ ดูดซึมน้อย ปลอดภัย ไม่ต้องเพิ่ม progestogen). ไม่ต้องใช้ systemic HT. ทางเลือก: vaginal moisturizer/lubricant."}, {"topic": "Gynecology", "q": "Which is a contraindication to menopausal hormone therapy?", "choices": ["History of breast cancer", "Age of 52 years alone", "Hot flashes", "Osteoporosis", "Vaginal dryness alone"], "ans": 0, "exp": "ข้อห้าม HT: มะเร็งเต้านม/estrogen-dependent cancer, VTE/PE, stroke/CHD, เลือดออกทางช่องคลอดไม่ทราบสาเหตุ, active liver disease, ตั้งครรภ์. ประเมิน benefit-risk รายบุคคล ใช้ขนาดต่ำสุดระยะสั้นสุด."}, {"topic": "Gynecology", "q": "Which newer non-hormonal agent (2023) treats vasomotor symptoms of menopause?", "choices": ["Bisphosphonate", "Fezolinetant", "Metformin", "Raloxifene", "Calcium supplement"], "ans": 1, "exp": "[อัปเดต] Fezolinetant (NK3 receptor antagonist, FDA 2023) รักษา moderate-severe vasomotor symptoms โดยไม่ใช้ฮอร์โมน — ออกฤทธิ์ที่ hypothalamic thermoregulatory center (KNDy neurons). เหมาะกับผู้มีข้อห้าม HT. ทางเลือกอื่น: SSRI/SNRI, gabapentin."}, {"topic": "Gynecology", "q": "A 35-year-old with amenorrhea for 8 months has high FSH, low estrogen, and hot flashes. What is the diagnosis?", "choices": ["Polycystic ovary syndrome", "Hyperprolactinemia", "Premature ovarian insufficiency", "Hypothalamic amenorrhea", "Asherman syndrome"], "ans": 2, "exp": "Premature ovarian insufficiency (POI) = รังไข่หยุดทำงานก่อน 40 ปี: amenorrhea + FSH สูง (hypergonadotropic) + estrogen ต่ำ + อาการขาด estrogen. สาเหตุ: idiopathic, Turner, fragile X, autoimmune, เคมี/รังสี. ให้ HT จนถึงวัยหมดประจำเดือนปกติ."}, {"topic": "Gynecology", "q": "A thin athlete training intensely has amenorrhea with low FSH, low LH, and low estrogen. What is the diagnosis?", "choices": ["Polycystic ovary syndrome", "Premature ovarian insufficiency", "Prolactinoma", "Functional hypothalamic amenorrhea", "Turner syndrome"], "ans": 3, "exp": "Functional hypothalamic amenorrhea (FHA): พลังงานไม่พอ (น้ำหนักลด/ออกกำลังหนัก/เครียด) → กด GnRH → LH/FSH ต่ำ (hypogonadotropic) → estrogen ต่ำ, anovulation. ส่วนหนึ่งของ female athlete triad. รักษาโดยแก้พลังงาน/พฤติกรรม."}, {"topic": "Gynecology", "q": "A woman with galactorrhea and amenorrhea has a high prolactin level. What is the next investigation?", "choices": ["Serum testosterone level", "Hysteroscopy", "Serum FSH level", "Pelvic ultrasound", "Pituitary MRI"], "ans": 4, "exp": "Hyperprolactinemia → galactorrhea + amenorrhea (prolactin กด GnRH). แยกสาเหตุ: prolactinoma (MRI pituitary), ยา, hypothyroidism (TSH), การตั้งครรภ์. รักษา prolactinoma ด้วย dopamine agonist (cabergoline/bromocriptine)."}, {"topic": "Gynecology", "q": "A woman develops amenorrhea and light menses after a postpartum dilation and curettage. Progestin challenge yields no bleeding despite normal estrogen. What is the diagnosis?", "choices": ["Asherman syndrome", "Premature ovarian insufficiency", "Prolactinoma", "Polycystic ovary syndrome", "Hypothalamic amenorrhea"], "ans": 0, "exp": "Asherman syndrome = พังผืดในโพรงมดลูก (intrauterine adhesions) มักหลังขูดมดลูก/ติดเชื้อ → endometrium ถูกทำลาย ประจำเดือนน้อย/ขาด (outflow/endometrial), มีบุตรยาก, แท้งซ้ำ. วินิจฉัย/รักษาด้วย hysteroscopy. Progestin challenge จะไม่มีเลือดออก."}, {"topic": "Gynecology", "q": "A woman develops rapid, severe hirsutism with a deepening voice and clitoromegaly. What should be suspected?", "choices": ["Simple PCOS", "Androgen-secreting tumor", "Idiopathic hirsutism", "Hypothyroidism", "Menopause"], "ans": 1, "exp": "Virilization เกิดเร็วและรุนแรง (hirsutism + clitoromegaly + เสียงห้าว + amenorrhea) บ่งชี้ androgen สูงมากจาก androgen-secreting tumor (ovarian - Sertoli-Leydig, adrenal). ตรวจ testosterone (>150-200), DHEAS, imaging. ต่างจาก PCOS ที่ค่อยเป็นค่อยไป."}, {"topic": "Gynecology", "q": "A 45-year-old with chronic menorrhagia has an enlarged, irregular uterus and fibroids on ultrasound. What is the definitive treatment?", "choices": ["Iron supplementation alone", "Antibiotic therapy", "Hysterectomy", "Watchful waiting", "Chemotherapy"], "ans": 2, "exp": "Leiomyoma ที่มีอาการ: definitive treatment คือ hysterectomy (ผู้ไม่ต้องการมีบุตร) หรือ myomectomy (เก็บมดลูก). ทางเลือก medical: LNG-IUS, tranexamic acid, GnRH agonist, UAE. เลือกตามอาการ/ขนาด/ความต้องการมีบุตร."}, {"topic": "Gynecology", "q": "Which type of fibroid causes the most bleeding and is most associated with infertility?", "choices": ["Subserosal", "Intramural", "Cervical", "Submucosal", "Pedunculated subserosal"], "ans": 3, "exp": "Submucosal fibroid (ยื่นเข้าโพรงมดลูก) รบกวน endometrium มากสุด → menorrhagia รุนแรงและรบกวนการฝังตัว (infertility/แท้ง). รักษาด้วย hysteroscopic myomectomy. Intramural พบบ่อยสุด; subserosal ทำให้อาการกดเบียด."}, {"topic": "Gynecology", "q": "A 28-year-old with a 4 cm simple ovarian cyst and no symptoms is evaluated. What is the appropriate management?", "choices": ["Immediate surgery", "Chemotherapy", "CA-125 then surgery", "Hysterectomy", "Follow-up ultrasound"], "ans": 4, "exp": "Simple cyst เล็ก (<5-7 cm) ในวัยเจริญพันธุ์ที่ไม่มีอาการ มักเป็น functional cyst (หายเอง) → ติดตามด้วย US ซ้ำใน 6-12 สัปดาห์. ลักษณะน่ากังวล (solid, septation, ascites, ใหญ่, CA-125 สูงในวัยหมดประจำเดือน) จึงผ่าตัด."}, {"topic": "Gynecology", "q": "A benign ovarian tumor containing hair, teeth, and sebaceous material describes which lesion?", "choices": ["Mature cystic teratoma", "Serous cystadenoma", "Endometrioma", "Corpus luteum cyst", "Ovarian fibroma"], "ans": 0, "exp": "Mature cystic teratoma (dermoid cyst) = germ cell tumor ไม่ร้ายที่พบบ่อยในวัยเจริญพันธุ์ ประกอบด้วยเนื้อเยื่อจาก 3 germ layers (ผม ฟัน ไขมัน). เสี่ยง torsion. รักษา cystectomy. ต่างจาก immature teratoma (มะเร็ง)."}, {"topic": "Gynecology", "q": "A 25-year-old has acute severe pelvic pain, nausea, an adnexal mass, and reduced ovarian Doppler flow. What is the diagnosis and management?", "choices": ["PID, give antibiotics", "Ovarian torsion, urgent surgery", "Ectopic, give methotrexate", "Ruptured cyst, observe", "Appendicitis, appendectomy"], "ans": 1, "exp": "Ovarian torsion (รังไข่บิดขั้ว): ปวดเฉียบพลันรุนแรงเป็นพักๆ + คลื่นไส้ + adnexal mass, Doppler ลดลง (ปกติไม่ตัดออก). ฉุกเฉิน → ผ่าตัดด่วน (laparoscopy) คลายการบิด (detorsion) + cystectomy. ยิ่งช้ารังไข่ยิ่งตาย."}, {"topic": "Gynecology", "q": "How is the risk of malignancy in an adnexal mass assessed?", "choices": ["Patient age alone", "Blood pressure readings alone", "Age, ultrasound features, CA-125", "Body weight and BMI", "Serum FSH level only"], "ans": 2, "exp": "ประเมิน adnexal mass ด้วยหลายปัจจัย: อายุ/สถานะประจำเดือน, ลักษณะ US (solid, thick septation, papillary, ascites), และ CA-125. เครื่องมือช่วย RMI, IOTA rules เพื่อตัดสินใจส่งต่อ gyn-oncologist."}, {"topic": "Gynecology", "q": "A 15-year-old with cyclic lower abdominal pain has never menstruated; exam shows a bulging bluish membrane at the introitus. What is the diagnosis?", "choices": ["Müllerian agenesis", "Polycystic ovary syndrome", "Ovarian tumor", "Imperforate hymen", "Ectopic pregnancy"], "ans": 3, "exp": "Imperforate hymen: เยื่อพรหมจารีปิดสนิท → เลือดประจำเดือนคั่ง (hematocolpos) → ปวดเป็นรอบ (cyclic) โดยไม่มีประจำเดือนออก, เยื่อโป่งสีน้ำเงิน. รักษาด้วย hymenotomy. เป็น outflow obstruction ที่ลักษณะทางเพศปกติ."}, {"topic": "Gynecology", "q": "A 14-year-old with short stature, a webbed neck, and no secondary sexual characteristics has a 45,X karyotype. What is the diagnosis?", "choices": ["Klinefelter syndrome", "Down syndrome", "Müllerian agenesis", "Androgen insensitivity", "Turner syndrome"], "ans": 4, "exp": "Turner syndrome (45,X): ตัวเตี้ย, webbed neck, streak gonads (gonadal dysgenesis) → primary amenorrhea + ไม่มีลักษณะทางเพศ (FSH สูง). สัมพันธ์ coarctation, bicuspid aortic valve, horseshoe kidney. รักษา: GH + estrogen replacement."}, {"topic": "Gynecology", "q": "Delayed puberty in a girl is defined as the absence of breast development by what age?", "choices": ["Thirteen years", "Eleven years", "Fifteen years", "Sixteen years", "Eighteen years"], "ans": 0, "exp": "Delayed puberty หญิง = ไม่มี thelarche เมื่ออายุ 13 ปี หรือไม่มี menarche เมื่อ 15 ปี. ประเมิน FSH/LH: สูง = gonadal (Turner, POI); ต่ำ = hypothalamic-pituitary (constitutional delay, Kallmann, eating disorder)."}, {"topic": "Gynecology", "q": "Which condition combines hypogonadotropic hypogonadism with an impaired sense of smell?", "choices": ["Cushing syndrome", "Kallmann syndrome", "Turner syndrome", "Polycystic ovary syndrome", "Sheehan syndrome"], "ans": 1, "exp": "Kallmann syndrome = isolated GnRH deficiency (hypogonadotropic hypogonadism, LH/FSH ต่ำ) + anosmia/hyposmia (ความล้มเหลวของการเคลื่อน GnRH/olfactory neurons) → delayed puberty/primary amenorrhea. รักษาด้วยฮอร์โมนทดแทน/gonadotropin."}, {"topic": "Gynecology", "q": "A 30-year-old with acute heavy uterine bleeding causing anemia, no pregnancy, and no structural lesion is treated with which first-line therapy?", "choices": ["Immediate hysterectomy", "Iron supplements alone", "High-dose estrogen or combined OC", "Watchful waiting", "Long-term GnRH agonist"], "ans": 2, "exp": "Acute AUB (ovulatory dysfunction) ไม่มี structural cause → hormonal: high-dose estrogen หรือ combined OC (taper) + tranexamic acid. ประเมิน hemodynamic/ให้เลือดถ้าจำเป็น. ผ่าตัด (D&C) เมื่อไม่ตอบสนองยา."}, {"topic": "Gynecology", "q": "Which option best manages chronic heavy menstrual bleeding while also providing contraception?", "choices": ["Tranexamic acid during menses", "Lifelong GnRH agonist", "NSAIDs", "Levonorgestrel intrauterine system", "Hysterectomy only"], "ans": 3, "exp": "LNG-IUS เป็นทางเลือกแรกที่ดีสำหรับ chronic heavy menstrual bleeding — ลดเลือด >80-90%, คุมกำเนิด, ป้องกัน endometrial hyperplasia. ทางเลือกอื่น: combined OC, progestin, TXA, NSAIDs, ablation, hysterectomy."}, {"topic": "Gynecology", "q": "A postmenopausal woman is assessed for osteoporosis prevention. Which approach is recommended?", "choices": ["No evaluation needed", "Antibiotics", "High-dose estrogen for all", "Surgery", "DXA, calcium/vitamin D, exercise"], "ans": 4, "exp": "Estrogen ที่ลดหลังหมดประจำเดือนเร่งการสูญเสียมวลกระดูก. แนะนำ: ตรวจ BMD (DXA), calcium/vitamin D, weight-bearing exercise, เลิกบุหรี่. ยา: bisphosphonate (first-line), denosumab, SERM, และ HT ในกลุ่มที่มีข้อบ่งชี้."}, {"topic": "Gynecology", "q": "A woman has gradual hirsutism, oligomenorrhea, and an elevated 17-hydroxyprogesterone. What is the diagnosis?", "choices": ["Non-classic congenital adrenal hyperplasia", "Polycystic ovary syndrome", "Idiopathic hirsutism", "An androgen-secreting tumor", "Cushing syndrome"], "ans": 0, "exp": "Non-classic CAH (21-hydroxylase deficiency) เลียนแบบ PCOS แต่แยกด้วย 17-OHP สูง (โดยเฉพาะหลัง ACTH stimulation). ขาดเอนไซม์บางส่วน → สร้าง androgen เกิน. รักษา glucocorticoid ± OC/antiandrogen. ควรตรวจ 17-OHP เมื่อประเมิน hyperandrogenism."}, {"topic": "Gynecology", "q": "Which antiandrogen is used adjunctively to treat hirsutism?", "choices": ["Progesterone", "Spironolactone", "Metformin", "Levothyroxine", "Clomiphene"], "ans": 1, "exp": "Spironolactone (antiandrogen - บล็อก androgen receptor และลดการสร้าง androgen) ใช้รักษา hirsutism ร่วมกับ combined OC. ต้องคุมกำเนิดร่วม (teratogenic). ผลเห็นช้า ~6 เดือน. combined OC เพิ่ม SHBG ลด free androgen."}, {"topic": "Gynecology", "q": "A 48-year-old has increasingly spaced menses, hot flashes, insomnia, and mood swings. What stage is she in?", "choices": ["Menopause", "Premature ovarian insufficiency", "Perimenopause", "Reproductive age", "Postmenopause"], "ans": 2, "exp": "Perimenopause (menopausal transition): รอบเดือนแปรปรวน (ห่างขึ้น/ข้ามรอบ), FSH ผันผวน, เริ่มมีอาการ vasomotor. ยังตกไข่/ตั้งครรภ์ได้ (ต้องคุมกำเนิด). Menopause = หลังขาดประจำเดือน 12 เดือนเต็ม."}, {"topic": "Gynecology", "q": "Menstruation occurs due to a fall in which hormone?", "choices": ["Estrogen rising", "FSH falling", "LH surging", "Progesterone falling", "hCG rising"], "ans": 3, "exp": "ไม่ตั้งครรภ์ → corpus luteum ฝ่อ (luteolysis) → progesterone และ estrogen ลดลง → spiral arteries หดตัว, endometrium ขาดเลือดหลุดลอกเป็นประจำเดือน. การลด progesterone ยังปลด negative feedback → FSH เพิ่มเริ่มรอบใหม่."}, {"topic": "Gynecology", "q": "The follicular phase of the menstrual cycle is dominated by which hormone?", "choices": ["Progesterone", "Testosterone", "hCG", "Inhibin A", "Estrogen"], "ans": 4, "exp": "Follicular phase: FSH กระตุ้น follicle สร้าง estrogen (estradiol) เพิ่ม → กระตุ้น endometrium proliferate. Estrogen สูงปลาย follicular กระตุ้น LH surge. Dominant follicle ถูกเลือกจากมี FSH receptor มากสุด."}, {"topic": "Gynecology", "q": "How can ovulation be confirmed in a woman being evaluated for infertility?", "choices": ["Mid-luteal serum progesterone", "Early-cycle serum FSH", "Early-cycle serum LH", "Day-3 serum estradiol", "Serum TSH level"], "ans": 0, "exp": "Mid-luteal (วันที่ ~21 ในรอบ 28 วัน) serum progesterone สูง (>3 ng/mL) ยืนยันการตกไข่. วิธีอื่น: LH surge (OPK), BBT เพิ่ม, US ติดตาม follicle. ใช้ประเมิน ovulatory function."}, {"topic": "Gynecology", "q": "A 25-year-old has an ovarian mass with a homogeneous 'ground-glass' appearance and severe dysmenorrhea. What is the likely diagnosis?", "choices": ["Dermoid cyst", "Endometrioma", "Serous cystadenoma", "Corpus luteum cyst", "Hydrosalpinx"], "ans": 1, "exp": "Endometrioma (chocolate cyst) มี US เป็น cyst ที่มี homogeneous low-level internal echoes ('ground-glass') จากเลือดเก่า. สัมพันธ์ endometriosis (dysmenorrhea, dyspareunia, infertility). ต่างจาก dermoid (echogenic) และ simple cyst (anechoic)."}, {"topic": "Gynecology", "q": "What is a key limitation of CA-125 in reproductive-age women?", "choices": ["It is 100% specific", "It is always low in cancer", "It rises in many benign conditions", "It is never elevated in benign disease", "It screens the general population"], "ans": 2, "exp": "CA-125 ไม่จำเพาะ — สูงได้ในภาวะไม่ร้าย (endometriosis, PID, fibroid, adenomyosis, ประจำเดือน, ตั้งครรภ์). จึงไม่เหมาะคัดกรองมะเร็งรังไข่ในคนทั่วไป. มีประโยชน์มากกว่าในวัยหมดประจำเดือนและติดตามการรักษามะเร็งรังไข่."}, {"topic": "Gynecology", "q": "What is Mittelschmerz?", "choices": ["Menstrual cramping", "Postcoital bleeding", "Postmenopausal pain", "Mid-cycle ovulation pain", "Premenstrual symptoms"], "ans": 3, "exp": "Mittelschmerz = ปวดท้องน้อยข้างเดียวช่วงกลางรอบเดือน (ตกไข่) จาก follicle แตกและมีของเหลว/เลือดระคายเยื่อบุช่องท้อง. ไม่อันตราย หายเองใน 1-2 วัน. แยกจากสาเหตุปวดเฉียบพลันอื่น (torsion, appendicitis, ectopic)."}, {"topic": "Gynecology", "q": "How does adenomyosis differ from leiomyoma on physical examination?", "choices": ["Adenomyosis gives an irregular hard uterus", "They are identical", "Fibroids give a soft uterus", "Adenomyosis does not enlarge the uterus", "Adenomyosis gives a symmetric, soft, tender uterus"], "ans": 4, "exp": "Adenomyosis: มดลูกโตสมมาตร (globular) นุ่ม (boggy) กดเจ็บ (โดยเฉพาะช่วงมีประจำเดือน). Leiomyoma: มดลูกโตไม่สมมาตร เป็นก้อนแข็ง (nodular). ทั้งคู่ menorrhagia แต่ adenomyosis dysmenorrhea เด่นกว่า."}, {"topic": "Gynecology", "q": "A 22-year-old with irregular menses, acne, hirsutism, and overweight has polycystic ovaries. What is the most important baseline management?", "choices": ["Lifestyle modification", "Antibiotics", "GnRH agonist", "Ovarian surgery", "Hysterectomy"], "ans": 0, "exp": "การรักษาพื้นฐานของ PCOS คือ lifestyle modification (ลดน้ำหนัก 5-10%, อาหาร, ออกกำลังกาย) ช่วยฟื้นการตกไข่ ลด androgen ปรับ insulin resistance. เสริมด้วย combined OC, metformin, letrozole (มีบุตร)."}, {"topic": "Gynecology", "q": "A woman with recurrent pregnancy loss should be evaluated for which of the following?", "choices": ["Serum CA-125 level", "Antiphospholipid antibodies and uterine cavity", "Serum prolactin level", "Fetal karyotype alone", "No evaluation is needed"], "ans": 1, "exp": "ประเมิน recurrent pregnancy loss: antiphospholipid antibodies (รักษาได้), TSH/prolactin, ควบคุมเบาหวาน, ประเมินโพรงมดลูก (septate - US 3D/hysteroscopy/HSG), parental karyotype. ~50% ไม่พบสาเหตุ."}, {"topic": "Gynecology", "q": "A woman has dysmenorrhea beginning after age 25 that progressively worsens with dyspareunia. What should be suspected?", "choices": ["Primary dysmenorrhea", "Normal menstruation", "Secondary dysmenorrhea", "Pregnancy", "Polycystic ovary syndrome"], "ans": 2, "exp": "Dysmenorrhea ที่เริ่มช้า (หลังวัยรุ่น) รุนแรงขึ้นเรื่อยๆ + อาการอื่น (dyspareunia, dyschezia, menorrhagia) บ่งชี้ secondary dysmenorrhea จากพยาธิสภาพ (endometriosis, adenomyosis, fibroid, PID). ต่างจาก primary (เริ่มตั้งแต่ menarche)."}, {"topic": "Gynecology", "q": "A 30-year-old with a prolactinoma causing amenorrhea is treated with which first-line therapy?", "choices": ["Immediate surgery", "Radiation therapy", "Estrogen therapy", "Dopamine agonist", "Observation"], "ans": 3, "exp": "Prolactinoma (แม้ macroadenoma) รักษาด้วย dopamine agonist (cabergoline ตัวแรก) — ลดขนาดก้อนและ prolactin, ฟื้นการตกไข่/ประจำเดือน. ผ่าตัด (transsphenoidal) เมื่อดื้อยา, ทนยาไม่ได้, หรือมีการกดเบียด (visual field defect)."}, {"topic": "Gynecology", "q": "What is the mechanism of hot flashes (vasomotor symptoms) in menopause?", "choices": ["An excess of circulating estrogen", "Underlying thyrotoxicosis", "An elevated prolactin level", "Recurrent hypoglycemia", "Estrogen deficiency affecting thermoregulation"], "ans": 4, "exp": "Hot flashes เกิดจากการขาด estrogen กระทบ hypothalamic thermoregulatory center (KNDy neurons/NK3) → thermoneutral zone แคบลง → vasodilation/เหงื่อออก. HT ได้ผลดีสุด; fezolinetant ออกฤทธิ์ที่ NK3 pathway."}, {"topic": "Gynecology", "q": "A woman has chronic intermenstrual bleeding. What should be specifically evaluated?", "choices": ["Endometrial/cervical polyp, cervix", "No evaluation is needed alone", "Serum TSH level only", "Pregnancy test only", "Bone mineral density"], "ans": 0, "exp": "Intermenstrual bleeding เรื้อรังควรประเมิน structural: endometrial/cervical polyp, พยาธิสภาพปากมดลูก (คัดกรองมะเร็ง/HPV), การติดเชื้อ (cervicitis-chlamydia). Postcoital bleeding เน้นปากมดลูก. ตรวจ β-hCG เสมอในวัยเจริญพันธุ์."}, {"topic": "Gynecology", "q": "A 40-year-old with menorrhagia is found to have an endometrial polyp. What is the appropriate treatment?", "choices": ["Hysterectomy", "Hysteroscopic polypectomy", "Antibiotics", "Observation always", "Chemotherapy"], "ans": 1, "exp": "Endometrial polyp ที่มีอาการ (AUB) รักษาด้วย hysteroscopic polypectomy (วินิจฉัยและรักษา + ส่งชิ้นเนื้อแยก atypia/มะเร็ง โดยเฉพาะวัยหมดประจำเดือน). Polyp เล็กไม่มีอาการอาจติดตามได้."}, {"topic": "Gynecology", "q": "What are the components of the female athlete triad?", "choices": ["Obesity, hypertension, diabetes", "Hirsutism, acne, obesity", "Amenorrhea, osteoporosis, low energy", "Anemia, fatigue, infection", "Galactorrhea, amenorrhea, headache"], "ans": 2, "exp": "Female athlete triad: (1) low energy availability (± eating disorder), (2) menstrual dysfunction (FHA), (3) low bone density/osteoporosis. พลังงานไม่พอ → กด GnRH → hypoestrogenism → กระดูกบาง. รักษาโดยเพิ่มพลังงาน/ลดออกกำลังหนักเกิน."}, {"topic": "Gynecology", "q": "Which test best reflects ovarian reserve in a woman planning pregnancy?", "choices": ["CA-125", "TSH only", "Serum prolactin", "Anti-Müllerian hormone", "Hysterosalpingography"], "ans": 3, "exp": "AMH สร้างจาก granulosa cells ของ small antral follicles สะท้อน ovarian reserve — ลดลงเมื่อเข้าใกล้ menopause. ใช้ประเมินใน infertility/IVF และทำนายเวลาเข้าสู่ menopause. [อัปเดต] ใช้แทน US ในการวินิจฉัย PCOS ในผู้ใหญ่ได้."}, {"topic": "Gynecology", "q": "A 35-year-old with a large fibroid wants to preserve her uterus and shrink it before surgery. Which drug helps?", "choices": ["Clomiphene", "Metformin", "Estrogen", "Antibiotics", "GnRH agonist"], "ans": 4, "exp": "GnRH agonist (leuprolide) สร้างภาวะ hypoestrogenic ชั่วคราว → ลดขนาด fibroid และแก้ anemia ก่อนผ่าตัด. ใช้ระยะสั้น (menopausal symptoms/กระดูกบาง; fibroid โตกลับหลังหยุด). ทางเลือกใหม่: GnRH antagonist, SPRM."}, {"topic": "Gynecology", "q": "A woman has mild premenstrual symptoms that are not disabling. What is the initial management?", "choices": ["Lifestyle modification, monitoring", "SSRIs started immediately", "Total abdominal hysterectomy", "A GnRH agonist course", "Broad-spectrum antibiotics"], "ans": 0, "exp": "PMS เล็กน้อยจัดการด้วย lifestyle: ออกกำลังกาย, ลดคาเฟอีน/เกลือ/แอลกอฮอล์, จัดการความเครียด, calcium/B6. อาการรุนแรง (PMDD) จึงพิจารณา SSRIs หรือ combined OC. บันทึกอาการยืนยันความสัมพันธ์กับ luteal phase."}, {"topic": "Gynecology", "q": "A postmenopausal woman with an intact uterus needs HT for vasomotor symptoms. Which regimen is appropriate?", "choices": ["Estrogen alone", "Estrogen plus progestogen", "Testosterone", "Progestogen alone", "No hormone therapy"], "ans": 1, "exp": "หญิงมีมดลูกต้องใช้ combined (estrogen + progestogen) เพื่อป้องกัน endometrial hyperplasia/cancer. ตัดมดลูกแล้วใช้ estrogen เดี่ยว. Continuous combined ให้ amenorrhea; sequential ให้ withdrawal bleeding (เหมาะ perimenopause)."}, {"topic": "Gynecology", "q": "A woman with prolonged unopposed estrogen exposure is at risk of which endometrial condition?", "choices": ["Simple endometrial atrophy", "Chronic pelvic infection", "Endometrial hyperplasia and cancer", "Endometrial polyp formation", "No increased cancer risk"], "ans": 2, "exp": "Unopposed estrogen → endometrial proliferation ต่อเนื่อง → hyperplasia (โดยเฉพาะ atypical/EIN) → มะเร็งเยื่อบุโพรงมดลูก. กลุ่มเสี่ยง: PCOS/anovulation, obesity, estrogen-only HT (มีมดลูก), tamoxifen, granulosa cell tumor."}, {"topic": "Gynecology", "q": "A woman not desiring future fertility has atypical endometrial hyperplasia (EIN). What is the recommended treatment?", "choices": ["Observation", "Radiation", "Antibiotics", "Total hysterectomy", "Combined OC"], "ans": 3, "exp": "Atypical hyperplasia/EIN เสี่ยงมะเร็งร่วมสูง (~40%) → ผู้ไม่ต้องการเก็บมดลูก แนะนำ total hysterectomy. ต้องการเก็บมดลูก/มีบุตร → high-dose progestin (LNG-IUS/oral) + ติดตามชิ้นเนื้อ. Hyperplasia without atypia รักษาด้วย progestin."}, {"topic": "Gynecology", "q": "How is endometrial hyperplasia without atypia treated?", "choices": ["Immediate hysterectomy in all", "A course of antibiotics", "Adjuvant chemotherapy", "Observation with no treatment", "Progestin therapy and follow-up"], "ans": 4, "exp": "Hyperplasia without atypia เสี่ยงมะเร็งต่ำ (~1-3%) → progestin (oral หรือ LNG-IUS) + แก้ปัจจัยเสี่ยง (ลดน้ำหนัก, หยุด unopposed estrogen) + ติดตามชิ้นเนื้อ. ต่างจาก atypical ที่แนะนำ hysterectomy."}, {"topic": "Gynecology", "q": "A woman has amenorrhea for over 6 months after stopping oral contraceptives. What should be done?", "choices": ["Evaluate as secondary amenorrhea", "Wait indefinitely", "No action needed", "Restart the pill", "Perform surgery"], "ans": 0, "exp": "ประจำเดือนมักกลับใน 3 เดือนหลังหยุดยาคุม. ขาด >3-6 เดือนต้องประเมิน secondary amenorrhea ตามปกติ (แยกการตั้งครรภ์, thyroid, hyperprolactinemia, PCOS ที่ถูกบดบัง, POI). ยาคุมไม่ทำให้มีบุตรยากถาวร."}, {"topic": "Gynecology", "q": "Central (GnRH-dependent) precocious puberty is treated with which agent?", "choices": ["Dopamine agonist", "GnRH agonist", "Estrogen", "Testosterone", "Metformin"], "ans": 1, "exp": "Central precocious puberty รักษาด้วย GnRH agonist (leuprolide) — การให้ต่อเนื่องกด pituitary (downregulation) → หยุดการดำเนินของ puberty และคงความสูงตอนโต. หาสาเหตุด้วย MRI สมอง (แยก CNS lesion โดยเฉพาะเด็กเล็ก/ชาย)."}, {"topic": "Gynecology", "q": "Follicular and corpus luteum cysts are classified as which type of ovarian cyst?", "choices": ["Neoplastic", "Endometriotic alone", "Functional (physiologic)", "Malignant", "Infectious"], "ans": 2, "exp": "Follicular cyst (follicle ไม่แตก) และ corpus luteum cyst (corpus luteum ไม่ฝ่อ) เป็น functional/physiologic cyst — พบบ่อยในวัยเจริญพันธุ์ มักหายเองใน 1-2 รอบเดือน. Corpus luteum cyst อาจแตกทำให้ปวด/เลือดออก. Combined OC ลดการเกิดใหม่."}, {"topic": "Gynecology", "q": "A woman with regular, predictable monthly cycles most likely has which of the following?", "choices": ["Anovulation", "Pregnancy", "Polycystic ovary syndrome", "Ovulatory cycles", "Menopause"], "ans": 3, "exp": "รอบเดือนสม่ำเสมอและคาดเดาได้ มักบ่งชี้ ovulatory cycles (luteal phase คงที่). รอบไม่สม่ำเสมอ/ห่างมาก มักเป็น anovulatory (PCOS). Molimina (อาการก่อนประจำเดือน) สนับสนุนว่ามีการตกไข่."}, {"topic": "Gynecology", "q": "A woman with an endometrioma and infertility is counseled. Which is a reasonable option depending on age and reserve?", "choices": ["Hysterectomy", "Chemotherapy", "Antibiotics", "Observation only", "Cystectomy and/or IVF"], "ans": 4, "exp": "Endometrioma สัมพันธ์ infertility. การจัดการขึ้นกับอาการ/ขนาด/อายุ/ovarian reserve: laparoscopic cystectomy (บรรเทาปวด/ยืนยัน แต่เสี่ยงลด reserve), หรือมุ่งสู่ IVF โดยตรง (โดยเฉพาะ reserve ต่ำ/เคยผ่าตัด). ชั่งน้ำหนักเป็นรายบุคคล."}, {"topic": "Gynecology", "q": "A woman with very high testosterone (>200 ng/dL) and rapid virilization needs which investigation?", "choices": ["Imaging of the ovaries and adrenals", "No further investigation", "Serum TSH alone", "A trial of combined pills", "Diagnostic hysterectomy"], "ans": 0, "exp": "Testosterone สูงมาก + virilization เริ่มเร็ว บ่งชี้ androgen-secreting tumor → imaging: TVS/MRI รังไข่ (Sertoli-Leydig, hilus cell) และ CT/MRI ต่อมหมวกไต (DHEAS สูงมาก = ต่อมหมวกไต). ต่างจาก PCOS."}, {"topic": "Gynecology", "q": "A woman has had heavy menses since her teens with easy bruising and epistaxis. What should be tested?", "choices": ["Serum CA-125 level", "Coagulation and von Willebrand panel", "Serum prolactin level", "Serum TSH alone", "Pelvic ultrasound alone"], "ans": 1, "exp": "Heavy menstrual bleeding ตั้งแต่ menarche + อาการเลือดออกง่ายอื่น (epistaxis, ช้ำง่าย) บ่งชี้ coagulopathy (C ใน PALM-COEIN) โดย von Willebrand disease พบบ่อยสุด → ตรวจ vWF, CBC, PT/aPTT. รักษา: TXA, desmopressin, hormonal."}, {"topic": "Gynecology", "q": "Long-term use of combined oral contraceptives reduces the risk of which cancers?", "choices": ["Breast cancer", "Cervical cancer", "Ovarian and endometrial cancer", "Liver cancer", "Colon cancer"], "ans": 2, "exp": "Combined OC ลดความเสี่ยงมะเร็งรังไข่ (ยับยั้งการตกไข่) และเยื่อบุโพรงมดลูก (progestin ปกป้อง) อย่างมีนัยสำคัญ คงอยู่หลายปีหลังหยุด. (เพิ่ม VTE เล็กน้อย, สัมพันธ์มะเร็งปากมดลูก/เต้านมเล็กน้อยระหว่างใช้ ซึ่งลดหลังหยุด)."}, {"topic": "Gynecology", "q": "A woman needs both contraception and treatment of heavy menses with dysmenorrhea. Which single method addresses both?", "choices": ["A copper intrauterine device", "Partner vasectomy", "Barrier condoms", "Levonorgestrel intrauterine system", "The calendar rhythm method"], "ans": 3, "exp": "LNG-IUS คุมกำเนิดประสิทธิภาพสูง (LARC) + ลดปริมาณประจำเดือน (รักษา HMB) + บรรเทา dysmenorrhea/endometriosis จึงตอบทั้งคุมกำเนิดและรักษา. ต่างจาก copper IUD ที่อาจทำให้ประจำเดือนมากขึ้น."}, {"topic": "Gynecology", "q": "Isolated premature breast development in a young child without other pubertal signs is best described as which condition?", "choices": ["Always precocious puberty alone", "Sign of malignancy", "Cause of early menses", "Requiring surgery", "Usually benign premature thelarche"], "ans": 4, "exp": "Premature thelarche = เต้านมโตเดี่ยวๆ (มัก <2-3 ปี) โดยไม่มีสัญญาณ puberty อื่น (bone age ปกติ) มักไม่อันตราย (self-limited) ติดตามได้. ต่างจาก true precocious puberty (หลายสัญญาณ + bone age เร่ง) ที่ต้องประเมิน/รักษา."}, {"topic": "Gynecology", "q": "A woman under 40 has amenorrhea with FSH confirmed elevated on two occasions. What is the diagnosis?", "choices": ["Premature ovarian insufficiency", "Polycystic ovary syndrome", "Pregnancy", "Hypothalamic amenorrhea", "Prolactinoma"], "ans": 0, "exp": "FSH สูง (menopausal range) ซ้ำ 2 ครั้งห่าง ≥1 เดือน ในหญิง <40 ปีที่ขาดประจำเดือน = POI. หาสาเหตุ (karyotype-Turner, FMR1 premutation, autoimmune) และให้ estrogen replacement จนถึงวัยหมดประจำเดือนปกติ (ป้องกันกระดูก/หัวใจ)."}, {"topic": "Gynecology", "q": "A 48-year-old with abnormal bleeding in perimenopause requires which key assessment?", "choices": ["No assessment is needed", "Endometrial evaluation for cancer", "Immediate hormone therapy", "Immediate surgical treatment", "Serum CA-125 testing"], "ans": 1, "exp": "AUB ในหญิง ≥45 ปี (หรือน้อยกว่าที่มีปัจจัยเสี่ยง: obesity, PCOS, unopposed estrogen, tamoxifen) ต้องประเมิน endometrium (biopsy/TVS) แยก hyperplasia/มะเร็ง — ไม่ควรถือว่าเป็นเพียง perimenopausal change."}, {"topic": "Gynecology", "q": "On pelvic exam, uterosacral nodularity and a fixed, retroverted uterus suggest which condition?", "choices": ["Fibroid", "Polycystic ovary syndrome", "Deep infiltrating endometriosis", "Pregnancy", "Ovarian cyst only"], "ans": 2, "exp": "Uterosacral nodularity/tenderness + fixed retroverted uterus (จากพังผืด) บ่งชี้ deep infiltrating endometriosis ร่วมกับอาการ 3D. Endometrioma อาจคลำได้ที่ปีกมดลูก. ยืนยันด้วย imaging/laparoscopy."}, {"topic": "Gynecology", "q": "A woman with only mild galactorrhea, normal menses, and a normal prolactin level should receive what management?", "choices": ["Transsphenoidal pituitary surgery", "Systemic chemotherapy course", "Total abdominal hysterectomy", "Reassurance after excluding red flags", "A dopamine agonist now"], "ans": 3, "exp": "Galactorrhea ที่ prolactin ปกติ + ประจำเดือนปกติ มักเป็น physiologic/idiopathic ไม่จำเป็นต้องรักษาถ้าไม่มีก้อน/อาการ. แยกน้ำจากเต้าที่มีเลือด/ข้างเดียว (สงสัยพยาธิสภาพเต้านม → imaging). Reassure + ตรวจ TSH."}, {"topic": "Gynecology", "q": "A woman has superficial (entry) dyspareunia. Which cause is common?", "choices": ["Deep pelvic endometriosis", "A uterine fibroid", "Ovarian carcinoma", "Polycystic ovary syndrome", "Vulvovaginal atrophy or vaginismus"], "ans": 4, "exp": "Superficial (entry) dyspareunia มักจากปากช่องคลอด/ช่องคลอดส่วนต้น: vulvovaginal atrophy (GSM), vaginismus, vulvodynia, การติดเชื้อ. ส่วน deep dyspareunia มักจาก endometriosis, PID, adnexal pathology. ซักประวัติแยกตำแหน่ง/timing."}, {"topic": "Gynecology", "q": "A woman wants a reversible, highly effective method to space births. What should be recommended?", "choices": ["A LARC method (implant/IUD)", "Permanent tubal ligation", "Condoms used alone", "Calendar-based awareness", "DMPA injections only"], "ans": 0, "exp": "ผู้ต้องการเว้นระยะและเก็บโอกาสมีบุตร แนะนำ LARC (implant/IUD) — ประสิทธิภาพสูงเทียบเท่าทำหมันแต่กลับคืนได้ (fertility กลับเร็วหลังถอด). ไม่ควรแนะนำ tubal ligation (ถาวร). shared decision-making."}, {"topic": "Gynecology", "q": "A woman with only genitourinary atrophic symptoms in menopause is treated with which agent?", "choices": ["Metronidazole", "Low-dose vaginal estrogen", "Acyclovir", "Fluconazole", "Systemic antibiotics"], "ans": 1, "exp": "Atrophic vaginitis (GSM) จากขาด estrogen — ช่องคลอดแห้ง บาง แดง เจ็บ pH สูง. รักษาด้วย vaginal estrogen ขนาดต่ำ (ได้ผลดีสุด) หรือ moisturizer/lubricant. ไม่ใช่การติดเชื้อจึงไม่ใช้ยาปฏิชีวนะ/ยาต้านเชื้อรา (แต่แยกการติดเชื้อร่วม)."}, {"topic": "Gynecology", "q": "A woman on estrogen-progestogen continuous combined HT experiences which intended effect?", "choices": ["Regular scheduled menses", "No need for progestogen", "No withdrawal bleeding (amenorrhea)", "Increased cancer risk", "Reduced estrogen level"], "ans": 2, "exp": "Continuous combined HT (estrogen + progestogen ทุกวัน) เหมาะกับผู้หมดประจำเดือนแล้ว — เป้าหมายให้ amenorrhea (ไม่มี scheduled bleeding) และปกป้อง endometrium. อาจมี unscheduled spotting ช่วงแรก. Sequential regimen มี withdrawal bleeding (เหมาะ perimenopause)."}, {"topic": "Gynecology", "q": "A 45-year-old wants to know whether she has reached menopause. Which test may help when unclear?", "choices": ["Serum CA-125 level", "Serum TSH level", "Serum prolactin level", "Elevated FSH with low estradiol", "A serum hCG level"], "ans": 3, "exp": "การวินิจฉัย menopause เป็น clinical (ขาดประจำเดือน 12 เดือน). กรณีไม่ชัด (อายุน้อย/ตัดมดลูก) การพบ FSH สูง + estradiol ต่ำสนับสนุน ovarian failure. FSH ในช่วง perimenopause ผันผวนจึงแปลผลระวัง. สงสัย POI (<40) ต้องตรวจ FSH ยืนยัน 2 ครั้ง."}, {"topic": "Gynecology", "q": "A woman with granulosa cell tumor producing estrogen should have which additional assessment?", "choices": ["No assessment is needed", "Routine cervical screening", "HPV testing of cervix", "Serum pregnancy testing", "Endometrial evaluation for hyperplasia"], "ans": 4, "exp": "Granulosa cell tumor สร้าง estrogen → unopposed estrogen เสี่ยง endometrial hyperplasia/มะเร็งร่วม (~5-25%). เมื่อวินิจฉัย (โดยเฉพาะมี abnormal bleeding) ต้องประเมิน endometrium (biopsy). Marker: inhibin/AMH. มักโตช้าและกลับเป็นซ้ำได้."}, {"topic": "Gynecology", "q": "A woman has postcoital bleeding. Which structure should be specifically evaluated?", "choices": ["The cervix", "The ovary", "The thyroid", "The fallopian tube", "The breast"], "ans": 0, "exp": "Postcoital bleeding เน้นประเมินปากมดลูก: มะเร็งปากมดลูก (แยกเสมอ - speculum, Pap/HPV, biopsy), cervicitis (chlamydia/gonorrhea), cervical polyp, ectropion. ควรตรวจภายในและคัดกรองมะเร็งปากมดลูก."}, {"topic": "Gynecology", "q": "A 30-year-old woman has amenorrhea; the pregnancy test is negative, and TSH and prolactin are normal. A progestin challenge gives no bleeding, but an estrogen-progestin challenge produces bleeding. What does this indicate?", "choices": ["An outflow tract obstruction", "A hypothalamic-pituitary-ovarian problem", "Polycystic ovary syndrome", "An ongoing pregnancy", "Asherman syndrome"], "ans": 1, "exp": "Progestin challenge ไม่มีเลือดออก (estrogen ต่ำ หรือ outflow obstruction) แต่ estrogen-progestin challenge มีเลือดออก → outflow/endometrium ปกติ แต่ขาด endogenous estrogen → ปัญหาที่ HPO axis. ตรวจ FSH: สูง = ovarian (POI); ต่ำ/ปกติ = hypothalamic-pituitary."}, {"topic": "Gynecology", "q": "A young woman has isolated Tanner stage IV breast and pubic hair development, cyclic pain, and no menses with a bluish bulging introital membrane. What is the definitive management?", "choices": ["Combined oral contraceptives", "Total abdominal hysterectomy", "Cruciate incision of the hymen", "Dilation and curettage", "Simple needle aspiration"], "ans": 2, "exp": "Imperforate hymen ที่มี hematocolpos รักษาด้วยการผ่าเปิดเยื่อพรหมจารี (hymenotomy/cruciate incision) เพื่อระบายเลือดที่คั่ง — ไม่ใช่การเจาะดูด (aspiration) ซึ่งเสี่ยงติดเชื้อและกลับเป็นซ้ำ. ลักษณะทางเพศปกติ (ต่างจาก MRKH)."}, {"topic": "Gynecology", "q": "A woman has vaginal dryness and dyspareunia in menopause without vasomotor symptoms. Besides vaginal estrogen, what is a non-hormonal option?", "choices": ["Systemic hormone therapy", "Oral antibiotics", "Bisphosphonate therapy", "Vaginal moisturizer or lubricant", "Combined oral contraceptive"], "ans": 3, "exp": "GSM อย่างเดียว ทางเลือก non-hormonal คือ vaginal moisturizer (ใช้สม่ำเสมอ) และ lubricant (ตอนมีเพศสัมพันธ์). ถ้าอาการมากใช้ low-dose vaginal estrogen (ได้ผลดีสุด). ไม่จำเป็นต้อง systemic HT ถ้าไม่มีอาการทั่วร่างกาย."}, {"topic": "Gynecology", "q": "A woman with polycystic ovaries, oligomenorrhea, and hirsutism is being worked up. Before diagnosing PCOS, which conditions must be excluded?", "choices": ["No exclusion is necessary", "Only pregnancy", "Only anemia", "Only osteoporosis", "Thyroid disease, hyperprolactinemia, CAH"], "ans": 4, "exp": "PCOS เป็น diagnosis of exclusion — ต้องแยก thyroid dysfunction (TSH), hyperprolactinemia (prolactin), non-classic CAH (17-OHP), Cushing, androgen-secreting tumor (testosterone/DHEAS สูงมาก + virilization) ก่อนใช้ Rotterdam criteria."}]}, {"id": "obgyn4", "title": "Ob-gyne ชุดที่ 4 — Gynecology II (Infertility, Contraception, STI & PID, Benign Tumors, Prolapse, Breast)", "subject": "obgyn", "questions": [{"topic": "Gynecology", "q": "A 28-year-old woman has not conceived after 12 months of regular unprotected intercourse. How is infertility defined in a woman under 35?", "choices": ["No conception after 12 months", "No conception after 3 months", "One miscarriage", "No conception after 6 months", "Lifelong subfertility"], "ans": 0, "exp": "Infertility = ไม่ตั้งครรภ์หลังมีเพศสัมพันธ์สม่ำเสมอไม่คุมกำเนิด 12 เดือน (อายุ <35) หรือ 6 เดือน (≥35). ควรประเมินเร็วขึ้นถ้ามีปัจจัยเสี่ยง (ประจำเดือนผิดปกติ, PID, endometriosis)."}, {"topic": "Gynecology", "q": "A couple presents for infertility evaluation. Which three domains should be assessed initially?", "choices": ["CBC, LFT, renal panel", "Semen, ovulation, tubal patency", "TSH, prolactin, FSH only", "CA-125, ultrasound, MRI", "Karyotype of both partners"], "ans": 1, "exp": "ประเมิน infertility 3 ด้าน: (1) male factor - semen analysis, (2) ovulation - mid-luteal progesterone, (3) tubal/uterine - HSG. เสริม ovarian reserve (AMH/FSH). Male และ ovulatory เป็นสาเหตุที่พบบ่อย."}, {"topic": "Gynecology", "q": "Which infertility factor is common and should be evaluated early because the test is simple and inexpensive?", "choices": ["Uterine factor", "Cervical factor", "Male factor (semen analysis)", "Immunologic factor", "Psychologic factor"], "ans": 2, "exp": "Male factor เป็นสาเหตุ ~30-40% และตรวจง่าย non-invasive ด้วย semen analysis จึงควรตรวจตั้งแต่ต้น (ก่อนหัตถการ invasive ในฝ่ายหญิง). ประเมิน volume, concentration, motility, morphology."}, {"topic": "Gynecology", "q": "A woman with PCOS and anovulatory infertility desires pregnancy. What is the current first-line ovulation induction agent?", "choices": ["Clomiphene citrate", "Gonadotropin injection", "In vitro fertilization", "Letrozole", "Metformin alone"], "ans": 3, "exp": "[อัปเดต] Letrozole เป็น first-line ovulation induction ใน PCOS (อัตราคลอดมีชีพสูงกว่า clomiphene). ไม่ตอบสนอง → gonadotropin หรือ ovarian drilling หรือ IVF. ลดน้ำหนักเป็นพื้นฐาน."}, {"topic": "Gynecology", "q": "Which assisted reproductive technique is used for severe male factor infertility?", "choices": ["Intrauterine insemination", "Standard in vitro fertilization", "Ovulation induction", "Timed intercourse", "Intracytoplasmic sperm injection"], "ans": 4, "exp": "ICSI (ฉีดอสุจิตัวเดียวเข้าไข่โดยตรง) ใช้ใน severe male factor (oligo/astheno/teratozoospermia รุนแรง, azoospermia ที่ได้อสุจิจาก TESE) หรือ IVF ล้มเหลว fertilization. IUI เหมาะ mild male factor/unexplained."}, {"topic": "Gynecology", "q": "Which contraceptive methods are the most effective (long-acting reversible contraception)?", "choices": ["IUD and contraceptive implant", "Condoms", "Oral contraceptive pills", "Calendar method", "DMPA injection"], "ans": 0, "exp": "LARC = IUD (copper/LNG-IUS) และ implant (etonogestrel) มีประสิทธิภาพสูงสุด (failure <1%) เพราะ user-independent. แนะนำเป็นทางเลือกแรก. Implant มีประสิทธิภาพสูงสุด."}, {"topic": "Gynecology", "q": "Which is a contraindication (MEC category 4) to combined oral contraceptives?", "choices": ["Age of 25 years", "Migraine with aura", "Acne", "Heavy menstrual bleeding", "Polycystic ovary syndrome"], "ans": 1, "exp": "ข้อห้าม combined OC (estrogen): migraine with aura (เสี่ยง stroke), อายุ ≥35 + สูบบุหรี่ ≥15 มวน, ประวัติ VTE/stroke/CHD, มะเร็งเต้านม, ความดันสูงคุมไม่ได้, <21 วันหลังคลอด, โรคตับรุนแรง."}, {"topic": "Gynecology", "q": "A breastfeeding woman wants contraception. Which option is safe and appropriate early postpartum?", "choices": ["Combined OC immediately", "High-dose estrogen", "Progestin-only pill or LARC", "No available options", "Calendar method"], "ans": 2, "exp": "หญิงให้นมควรเลี่ยง estrogen ช่วงแรก (อาจลดน้ำนม + เสี่ยง VTE) → progestin-only pill, DMPA, implant, IUD ปลอดภัย. Combined OC ใช้ได้หลัง ~6 สัปดาห์เมื่อ VTE risk ลดและน้ำนมมั่นคง."}, {"topic": "Gynecology", "q": "Which is the most effective method of emergency contraception?", "choices": ["Levonorgestrel 1.5 mg", "Condom afterward", "Ulipristal acetate", "Copper IUD", "Yuzpe combined pills"], "ans": 3, "exp": "Copper IUD เป็น emergency contraception ที่ได้ผลดีที่สุด (failure <0.1%) ภายใน 5 วัน + คุมกำเนิดต่อระยะยาว. รองลงมา: ulipristal acetate (>levonorgestrel โดยเฉพาะ BMI สูง/ใกล้ตกไข่), levonorgestrel 1.5 mg."}, {"topic": "Gynecology", "q": "By which primary mechanism does the copper IUD prevent pregnancy?", "choices": ["Suppressing ovulation", "Closing the cervix", "Causing uterine contractions", "Lowering estrogen", "A spermicidal inflammatory reaction"], "ans": 4, "exp": "Copper IUD ปล่อยทองแดงสร้าง sterile inflammatory reaction ที่เป็นพิษต่ออสุจิ/ไข่ → ป้องกันการปฏิสนธิ. ไม่ใช้ฮอร์โมน (ไม่ยับยั้งการตกไข่). คุมได้ 10 ปี. ผลข้างเคียง: ประจำเดือนมาก/ปวดมากขึ้น."}, {"topic": "Gynecology", "q": "A woman using DMPA should be counseled about which side effect?", "choices": ["Amenorrhea and delayed fertility return", "Immediate return of fertility", "Increased ovarian cancer risk", "Low blood pressure", "Permanent hair loss"], "ans": 0, "exp": "DMPA (ฉีดทุก 3 เดือน): amenorrhea/irregular bleeding, น้ำหนักเพิ่ม, การกลับมาของ fertility ล่าช้า (~6-12 เดือน), มวลกระดูกลดชั่วคราว (กลับคืนได้). ข้อดี: ไม่มี estrogen, ลด menorrhagia, ป้องกัน endometrial cancer."}, {"topic": "Gynecology", "q": "Which is a method of permanent contraception in a woman?", "choices": ["Vasectomy (male sterilization)", "Tubal ligation or salpingectomy", "DMPA injection", "An intrauterine device", "A contraceptive implant"], "ans": 1, "exp": "การทำหมันถาวรในหญิง = tubal ligation หรือ bilateral salpingectomy (นิยม salpingectomy เพราะลดความเสี่ยงมะเร็งรังไข่ serous). Vasectomy เป็นการทำหมันชาย. ต้องให้คำปรึกษาว่าเป็นวิธีถาวร."}, {"topic": "Gynecology", "q": "A woman has thin, gray, malodorous discharge with a pH above 4.5, a positive whiff test, and clue cells. What is the diagnosis and treatment?", "choices": ["Candidiasis, give fluconazole", "Trichomoniasis, treat the partner", "Bacterial vaginosis, give metronidazole", "Gonorrhea, give ceftriaxone", "Normal discharge, no treatment"], "ans": 2, "exp": "Bacterial vaginosis (Gardnerella): ตกขาวเทา บาง กลิ่นคาว, pH >4.5, whiff test +, clue cells (Amsel ≥3/4). รักษา metronidazole (หรือ clindamycin). ไม่ต้องรักษาคู่. BV ในครรภ์สัมพันธ์ preterm."}, {"topic": "Gynecology", "q": "A woman has thick, white, curd-like discharge with intense itching, normal pH, and pseudohyphae on KOH. What is the diagnosis and treatment?", "choices": ["Bacterial vaginosis, give metronidazole", "Atrophic vaginitis, give estrogen", "Trichomoniasis, give metronidazole", "Vulvovaginal candidiasis, give azole", "Chlamydia, give doxycycline"], "ans": 3, "exp": "Vulvovaginal candidiasis (Candida albicans): ตกขาวขาวข้นคล้าย cottage cheese, คันแดง, pH ปกติ (<4.5), KOH พบ pseudohyphae. รักษา azole (fluconazole oral single dose หรือ topical). ไม่ใช่ STI. เสี่ยง: เบาหวาน, ยาปฏิชีวนะ, ครรภ์."}, {"topic": "Gynecology", "q": "A woman has yellow-green frothy discharge with a pH above 4.5, motile trichomonads, and a strawberry cervix. What is the diagnosis and treatment?", "choices": ["Candidiasis, give fluconazole", "Bacterial vaginosis, give clindamycin", "Gonorrhea, give ceftriaxone", "Normal discharge, no treatment", "Trichomoniasis, treat the partner"], "ans": 4, "exp": "Trichomoniasis (T. vaginalis, STI): ตกขาวเหลืองเขียวเป็นฟอง, pH >4.5, motile flagellates, strawberry cervix. รักษา metronidazole (หรือ tinidazole) + 'รักษาคู่นอน' + งดเพศสัมพันธ์จนหาย. สัมพันธ์ preterm และเพิ่มความเสี่ยง HIV."}, {"topic": "Gynecology", "q": "A 22-year-old has lower abdominal pain, fever, discharge, and cervical motion tenderness. What is the diagnosis and the most common pathogens?", "choices": ["PID from gonorrhea and chlamydia", "UTI from E. coli", "Appendicitis, mixed flora", "Endometriosis, no organism", "Ectopic, no organism"], "ans": 0, "exp": "PID: cervical motion tenderness (chandelier sign) + ปวดท้องน้อย/ไข้/ตกขาว. เชื้อหลัก: N. gonorrhoeae และ C. trachomatis (± anaerobes). รักษา empiric: ceftriaxone + doxycycline + metronidazole. รักษาเร็วป้องกันภาวะแทรกซ้อน (infertility, ectopic)."}, {"topic": "Gynecology", "q": "Which is a long-term complication of pelvic inflammatory disease?", "choices": ["Cervical carcinoma", "Tubal infertility and ectopic pregnancy", "Osteoporosis", "Gestational diabetes", "Preeclampsia"], "ans": 1, "exp": "PID ทำลายท่อนำไข่ (scarring) → tubal factor infertility, ectopic pregnancy, chronic pelvic pain, tubo-ovarian abscess. Fitz-Hugh-Curtis (perihepatitis) เป็นภาวะแทรกซ้อนจากการลามขึ้นตับ."}, {"topic": "Gynecology", "q": "What is Fitz-Hugh-Curtis syndrome?", "choices": ["An ovarian cyst", "Gallstones", "Perihepatitis from PID", "Liver cancer", "Appendicitis"], "ans": 2, "exp": "Fitz-Hugh-Curtis syndrome = perihepatitis จากการลุกลามของเชื้อ PID (chlamydia/gonorrhea) ไปที่แคปซูลตับ → ปวด RUQ + 'violin-string' adhesions. อาการเลียนแบบ cholecystitis. รักษาเหมือน PID."}, {"topic": "Gynecology", "q": "A painless genital ulcer with a firm, indurated base (chancre) is caused by which organism?", "choices": ["Herpes simplex virus", "Human papillomavirus", "Haemophilus ducreyi", "Treponema pallidum", "Candida albicans"], "ans": 3, "exp": "แผล chancre — ไม่เจ็บ ขอบแข็ง ก้นสะอาด ในซิฟิลิสระยะแรก (Treponema pallidum). ต่างจาก HSV (แผลเจ็บเป็นกลุ่ม) และ chancroid (H. ducreyi - เจ็บ ก้นสกปรก). ตรวจ dark-field/serology. รักษา penicillin."}, {"topic": "Gynecology", "q": "Painful grouped vesicles that ulcerate and recur on the genitalia are caused by which organism?", "choices": ["Treponema pallidum", "Human papillomavirus", "Chlamydia trachomatis", "Candida albicans", "Herpes simplex virus"], "ans": 4, "exp": "Genital herpes (HSV-2 ส่วนใหญ่): ตุ่มน้ำเป็นกลุ่มบนฐานแดง แตกเป็นแผลตื้นเจ็บ, ต่อมน้ำเหลืองโต, ไข้ในการติดเชื้อครั้งแรก, และกลับเป็นซ้ำ (latency). รักษา acyclovir/valacyclovir (ไม่หายขาด). Active lesion ตอนคลอด → C/S."}, {"topic": "Gynecology", "q": "Condyloma acuminata (genital warts) are caused by which HPV types?", "choices": ["HPV 6 and 11", "HPV 16 and 18", "HPV 31 and 33", "HPV 45 only", "Herpes simplex virus"], "ans": 0, "exp": "Condyloma acuminata เกิดจาก HPV ความเสี่ยงต่ำ 6 และ 11 (~90%). HPV 16, 18 เป็นชนิดความเสี่ยงสูงก่อมะเร็ง. วัคซีน quadrivalent/9-valent ครอบคลุม 6, 11. รักษาหูด: imiquimod, podophyllin, cryotherapy, ผ่าตัด."}, {"topic": "Gynecology", "q": "A 45-year-old with menorrhagia has multiple fibroids and wants to preserve her uterus. Which option is appropriate?", "choices": ["Total hysterectomy", "Myomectomy or medical therapy", "Pelvic radiotherapy", "Systemic chemotherapy", "No treatment at all"], "ans": 1, "exp": "หญิงต้องการเก็บมดลูก: myomectomy หรือ medical therapy (LNG-IUS, TXA, NSAIDs, GnRH agonist, UAE). Hysterectomy เป็น definitive สำหรับผู้ไม่ต้องการเก็บมดลูก. เลือกตามอาการ/ขนาด/ความต้องการมีบุตร."}, {"topic": "Gynecology", "q": "A young woman has a smooth, well-circumscribed, mobile, non-tender breast lump. What is the most likely diagnosis?", "choices": ["Breast cancer", "Breast abscess", "Fibroadenoma", "Fibrocystic change", "Fat necrosis"], "ans": 2, "exp": "Fibroadenoma — เนื้องอกเต้านมไม่ร้ายที่พบบ่อยในหญิงสาว: ก้อนเรียบ ขอบชัด เคลื่อนที่ได้ ('breast mouse') ไม่เจ็บ. วินิจฉัยด้วย triple assessment. ก้อนเล็กที่ยืนยันแล้วอาจติดตามได้."}, {"topic": "Gynecology", "q": "A woman has cyclical breast pain with lumpiness that varies with her menstrual cycle. What is the most likely diagnosis?", "choices": ["Breast cancer", "Paget disease", "Fibroadenoma", "Fibrocystic change", "Breast abscess"], "ans": 3, "exp": "Fibrocystic change: เจ็บเต้านมเป็นๆ หายๆ สัมพันธ์รอบเดือน, คลำได้ก้อน/ปุ่มหลายจุดสองข้าง, อาจมี cyst. เป็น benign. จัดการ supportive. ก้อน dominant/น่าสงสัยควรประเมินด้วย imaging/biopsy."}, {"topic": "Gynecology", "q": "Which finding is a red flag for breast cancer?", "choices": ["A soft, mobile lump", "Symmetrical breasts", "Cyclical breast pain", "A small lump that resolves alone", "A hard, fixed lump with skin dimpling"], "ans": 4, "exp": "Red flags มะเร็งเต้านม: ก้อนแข็ง ขอบไม่ชัด ติดแน่น (fixed) ไม่เจ็บ, ผิวบุ๋ม/เปลือกส้ม (peau d'orange), หัวนมบุ๋ม/มีน้ำเลือด, ผื่นหัวนม (Paget), ต่อมน้ำเหลืองรักแร้โต. ประเมินด้วย triple assessment."}, {"topic": "Gynecology", "q": "A 55-year-old with uterine prolapse who is not a surgical candidate is best managed with which non-surgical option?", "choices": ["Pessary and pelvic floor exercise", "Vaginal hysterectomy", "Systemic chemotherapy", "A course of antibiotics", "Pelvic radiotherapy"], "ans": 0, "exp": "Pelvic organ prolapse ที่ไม่ผ่าตัด: vaginal pessary + pelvic floor exercise (Kegel), ลดน้ำหนัก, รักษาท้องผูก/ไอเรื้อรัง. ผ่าตัด (colporrhaphy, sacrocolpopexy, hysterectomy) สำหรับรายมีอาการมากและต้องการแก้ถาวร."}, {"topic": "Gynecology", "q": "A woman leaks urine with coughing, sneezing, and lifting, without urgency. What is the diagnosis and initial treatment?", "choices": ["Urge incontinence; an antimuscarinic", "Stress incontinence; pelvic floor exercise", "Overflow incontinence; catheterization", "A UTI; a course of antibiotics", "A fistula; surgical repair"], "ans": 1, "exp": "Stress urinary incontinence — ปัสสาวะเล็ดเมื่อความดันในช่องท้องเพิ่ม (ไอ จาม) จาก urethral hypermobility/sphincter weakness. รักษาเบื้องต้น: Kegel, ลดน้ำหนัก, pessary; ไม่ดีขึ้น → midurethral sling. ต่างจาก urge (OAB)."}, {"topic": "Gynecology", "q": "A woman has urgency, frequency, and inability to hold urine (overactive bladder). What is the treatment?", "choices": ["A midurethral sling procedure", "A course of antibiotics", "Bladder training and an antimuscarinic", "Intermittent catheterization", "A hysterectomy"], "ans": 2, "exp": "Urge incontinence/overactive bladder: รักษาด้วย bladder training, ลดคาเฟอีน, Kegel, และยา antimuscarinic (oxybutynin, solifenacin) หรือ β3-agonist (mirabegron). ดื้อยา → botulinum toxin/neuromodulation. ต่างจาก SUI ที่รักษาด้วย sling."}, {"topic": "Gynecology", "q": "A 30-year-old with a tubo-ovarian abscess unresponsive to antibiotics requires which additional management?", "choices": ["Observation", "Analgesics alone", "Chemotherapy", "Drainage plus antibiotics", "Hormone therapy alone"], "ans": 3, "exp": "Tubo-ovarian abscess (TOA): เริ่มด้วยยาปฏิชีวนะ IV. ถ้าใหญ่ (>7-9 cm), ไม่ตอบสนองใน 48-72 ชม., หรือสงสัยแตก → drainage (image-guided/ผ่าตัด). TOA ที่แตกเป็นฉุกเฉินต้องผ่าตัด."}, {"topic": "Gynecology", "q": "Which organism should be routinely screened for in sexually active women under 25?", "choices": ["HIV only", "Syphilis only", "No screening needed", "HPV only", "Chlamydia and gonorrhea"], "ans": 4, "exp": "แนะนำคัดกรอง Chlamydia (± gonorrhea) เป็นประจำในหญิง <25 ปีที่มีเพศสัมพันธ์ (มักไม่มีอาการแต่นำสู่ PID/infertility). ร่วมคัดกรอง HIV, syphilis ตามความเสี่ยง. รักษา chlamydia: doxycycline, รักษาคู่."}, {"topic": "Gynecology", "q": "A 30-year-old with chlamydial cervicitis should receive which current first-line treatment?", "choices": ["Doxycycline and treat the partner", "Metronidazole", "Penicillin", "Fluconazole", "Acyclovir"], "ans": 0, "exp": "[อัปเดต] Chlamydia รักษาด้วย doxycycline 100 mg วันละ 2 ครั้ง 7 วัน (CDC first-line, azithromycin single dose ยังใช้ได้เช่นในครรภ์). รักษาคู่นอน, งดเพศสัมพันธ์ 7 วัน, ตรวจ/รักษา gonorrhea ร่วม (co-infection บ่อย)."}, {"topic": "Gynecology", "q": "A pregnant woman is diagnosed with gonorrhea. What is the treatment?", "choices": ["Doxycycline", "Ceftriaxone intramuscularly", "Ciprofloxacin", "Metronidazole", "No treatment needed"], "ans": 1, "exp": "Gonorrhea รักษาด้วย ceftriaxone IM single dose. ในครรภ์ห้าม doxycycline/fluoroquinolone. เพิ่ม azithromycin/amoxicillin ถ้าสงสัย chlamydia co-infection. รักษาคู่นอน. Neonatal gonococcal conjunctivitis ป้องกันด้วย erythromycin eye ointment."}, {"topic": "Gynecology", "q": "Which contraceptive method also protects against sexually transmitted infections?", "choices": ["IUD", "Oral contraceptive pills", "Condom", "DMPA", "Implant"], "ans": 2, "exp": "ถุงยางอนามัย (condom) เป็นวิธีเดียวที่ทั้งคุมกำเนิดและป้องกัน STI/HIV (barrier). วิธีฮอร์โมน/IUD ไม่ป้องกัน STI. แนะนำ 'dual protection' (ถุงยาง + วิธีประสิทธิภาพสูง) โดยเฉพาะผู้เสี่ยง STI."}, {"topic": "Gynecology", "q": "A woman requests medical abortion in the first trimester. Which drug regimen is most effective?", "choices": ["Methotrexate alone", "Tranexamic acid", "Oxytocin infusion", "Mifepristone then misoprostol", "Magnesium sulfate"], "ans": 3, "exp": "Medical abortion ไตรมาสแรกที่ได้ผลดีที่สุด: mifepristone (antiprogestin) ตามด้วย misoprostol (prostaglandin). ถ้าไม่มี mifepristone ใช้ misoprostol เดี่ยว (ประสิทธิภาพต่ำกว่า). ติดตามให้ complete + คุมกำเนิดต่อ."}, {"topic": "Gynecology", "q": "Before inserting an IUD, which condition must be excluded?", "choices": ["Underlying heart disease", "Diabetes mellitus", "Thyroid disease", "Renal disease", "Pregnancy and active pelvic infection"], "ans": 4, "exp": "ก่อนใส่ IUD ต้องแยกการตั้งครรภ์และ active pelvic infection (PID/purulent cervicitis) เพราะเพิ่มความเสี่ยง PID. ไม่จำเป็นต้องคัดกรอง STI ทุกรายก่อนใส่ แต่ตามความเสี่ยง. Distorted cavity (fibroid) เป็นข้อพิจารณา."}, {"topic": "Gynecology", "q": "A woman conceives with an IUD in place and the strings are visible. What is the recommended management?", "choices": ["Remove the IUD if strings are visible", "Always leave it in place", "Immediate surgery", "Long-term antibiotics", "Terminate the pregnancy always"], "ans": 0, "exp": "ตั้งครรภ์ทั้งที่มี IUD และเห็นสาย → ถอด IUD (ถ้าทำได้ง่ายและอายุครรภ์น้อย) ลดความเสี่ยง แท้ง/preterm/chorioamnionitis/septic abortion. ไม่เห็นสาย/ถอดยาก → ประเมิน US. แยก ectopic เสมอ."}, {"topic": "Gynecology", "q": "A woman had unprotected intercourse 3 days ago and wants effective emergency contraception plus ongoing contraception. What should be recommended?", "choices": ["Levonorgestrel pill", "Copper IUD", "No action needed", "Calendar method", "Condom next time"], "ans": 1, "exp": "Copper IUD เป็น EC ที่ได้ผลดีที่สุด (ภายใน 5 วัน) และให้การคุมกำเนิดต่อระยะยาว จึงเหมาะกับผู้ต้องการคุมต่อ. ทางเลือกยา: ulipristal acetate (ดีกว่า levonorgestrel โดยเฉพาะ BMI สูง). ยิ่งเร็วยิ่งได้ผล."}, {"topic": "Gynecology", "q": "A woman with hydrosalpinx plans to undergo IVF. What should be done to improve success?", "choices": ["Proceed directly with IVF", "Long-term antibiotic therapy", "Salpingectomy or tubal occlusion before IVF", "A hysterectomy first", "Observation without action"], "ans": 2, "exp": "Hydrosalpinx ลดอัตราสำเร็จ IVF (ของเหลวเป็นพิษต่อ embryo/รบกวน implantation, ไหลย้อนเข้าโพรงมดลูก). แนะนำ laparoscopic salpingectomy หรือ proximal tubal occlusion ก่อน IVF เพื่อเพิ่มอัตราตั้งครรภ์."}, {"topic": "Gynecology", "q": "A woman has recurrent vulvovaginal candidiasis (four or more episodes per year). What is the management?", "choices": ["No treatment is needed", "Surgical intervention", "A course of antibiotics", "Induction then maintenance antifungal", "Estrogen therapy"], "ans": 3, "exp": "Recurrent VVC (≥4 ครั้ง/ปี): รักษา induction (azole นานขึ้น) แล้ว maintenance (fluconazole 150 mg สัปดาห์ละครั้ง ~6 เดือน). หาปัจจัยส่งเสริม: เบาหวานคุมไม่ดี, ภูมิคุ้มกันต่ำ, non-albicans (เพาะเชื้อ)."}, {"topic": "Gynecology", "q": "A woman has a painful, fluctuant mass at the posterior vaginal introitus that has recurred. What is the appropriate surgical management?", "choices": ["Antibiotics alone in all cases", "A hysterectomy", "Observation without drainage", "Systemic chemotherapy", "Marsupialization or a Word catheter"], "ans": 4, "exp": "Bartholin gland abscess/cyst ที่มีอาการ: incision & drainage + Word catheter (คา ~4 สัปดาห์ให้เกิดทางระบายถาวร) หรือ marsupialization (สำหรับที่เป็นซ้ำ). ให้ยาปฏิชีวนะถ้ามี cellulitis/เสี่ยง STI. หญิง >40 ปีที่เป็นก้อนแข็งควร biopsy แยกมะเร็ง."}, {"topic": "Gynecology", "q": "A woman on combined oral contraceptives misses one pill. What should she do?", "choices": ["Take it immediately and continue as usual", "Stop all pills for the cycle", "Start an entirely new pack", "Seek urgent medical care", "Take emergency contraception"], "ans": 0, "exp": "ลืมยาคุมรวม 1 เม็ด (<48 ชม.): กินเม็ดที่ลืมทันทีที่นึกได้ แล้วกินต่อตามปกติ ไม่ต้องใช้วิธีสำรอง. ถ้าลืม ≥2 เม็ด: กินเม็ดล่าสุด, ทิ้งเม็ดอื่นที่ลืม, ใช้ถุงยางสำรอง 7 วัน, พิจารณา EC ถ้ามีเพศสัมพันธ์เสี่ยง."}, {"topic": "Gynecology", "q": "A 35-year-old woman who smokes 20 cigarettes daily wants contraception. Which method should be avoided?", "choices": ["A copper intrauterine device", "Combined oral contraceptives", "A contraceptive implant", "The progestin-only pill", "Barrier condoms"], "ans": 1, "exp": "หญิงอายุ ≥35 + สูบบุหรี่ ≥15 มวน/วัน = ข้อห้าม (MEC 4) ของ combined OC เพราะเพิ่มความเสี่ยง cardiovascular/VTE/MI. ทางเลือกปลอดภัย: progestin-only, DMPA, implant, IUD, ถุงยาง (ไม่มี estrogen)."}, {"topic": "Gynecology", "q": "A 60-year-old woman has a chronic itchy vulval lesion with white, thinned, parchment-like skin. What is the treatment?", "choices": ["Topical vaginal estrogen", "A course of antibiotics", "High-potency topical corticosteroid", "Radical vulvectomy", "Systemic chemotherapy"], "ans": 2, "exp": "Lichen sclerosus — ผิวขาวบางคล้ายกระดาษที่ vulva, คันมาก. รักษาด้วย high-potency topical corticosteroid (clobetasol), ติดตามระยะยาว. สำคัญเพราะเพิ่มความเสี่ยง vulvar SCC (~4-5%) → เฝ้าระวังและ biopsy บริเวณน่าสงสัย."}, {"topic": "Gynecology", "q": "A 60-year-old has a chronic vulvar ulcer, biopsy showing squamous cell carcinoma. In older women, which is a common risk factor?", "choices": ["HPV only", "Fibroadenoma", "Endometriosis", "Lichen sclerosus", "Polycystic ovary syndrome"], "ans": 3, "exp": "Vulvar cancer (ส่วนใหญ่ SCC) มี 2 pathway: HPV-related (อายุน้อย) และ non-HPV related สัมพันธ์กับ lichen sclerosus/chronic inflammation ในผู้สูงอายุ. แผลเรื้อรังที่ vulva ควร biopsy เสมอ."}, {"topic": "Gynecology", "q": "A daughter exposed to DES in utero is at increased risk of which malignancy?", "choices": ["Squamous cervical carcinoma", "Ovarian carcinoma", "Endometrial carcinoma", "Breast carcinoma", "Clear cell adenocarcinoma of the vagina"], "ans": 4, "exp": "In utero DES exposure สัมพันธ์กับ clear cell adenocarcinoma ของช่องคลอด/ปากมดลูก (DES daughters), รวมถึงความผิดปกติของอวัยวะสืบพันธุ์ (T-shaped uterus). DES เลิกใช้แล้วแต่เป็นความรู้คลาสสิก."}, {"topic": "Gynecology", "q": "A 25-year-old with a confirmed 1.5 cm fibroadenoma that is stable is best managed how?", "choices": ["Observation, or excision if it grows", "A total mastectomy", "Systemic chemotherapy", "Radiotherapy", "Anti-hormonal therapy"], "ans": 0, "exp": "Fibroadenoma ที่ยืนยัน triple assessment ในหญิงสาว ขนาดเล็กและคงที่ ติดตามได้ (มักคงที่/ฝ่อ). Excision ถ้าโต, ใหญ่ (>2-3 cm), มีอาการ, ผลไม่สอดคล้อง หรือผู้ป่วยต้องการ. ไม่ใช่มะเร็ง."}, {"topic": "Gynecology", "q": "A breastfeeding woman has a fluctuant breast mass consistent with abscess. What is the management?", "choices": ["Continue breastfeeding only", "Drainage plus antibiotics", "Observation only", "Stop breastfeeding permanently", "Mastectomy"], "ans": 1, "exp": "Breast abscess (ภาวะแทรกซ้อนของ mastitis): drainage (needle aspiration/incision & drainage) + ยาปฏิชีวนะครอบคลุม S. aureus (รวม MRSA ถ้าเสี่ยง) และให้นม/ปั๊มออกต่อ. หญิงไม่ให้นมที่เป็นซ้ำ ระวัง underlying malignancy."}, {"topic": "Gynecology", "q": "How is neonatal gonococcal ophthalmia prevented?", "choices": ["Maternal antibiotics after delivery", "A saline eye rinse", "Erythromycin eye ointment to the newborn", "Neonatal vaccination", "Elective cesarean delivery"], "ans": 2, "exp": "Neonatal gonococcal conjunctivitis ป้องกันด้วยการป้ายตาทารกแรกเกิดด้วย erythromycin ophthalmic ointment ทุกราย. แม่ที่ติด gonorrhea ควรรักษาก่อนคลอด. ทารกติดเชื้อต้องรักษา ceftriaxone systemic."}, {"topic": "Gynecology", "q": "A menopausal woman has atrophic vaginitis. What is the treatment?", "choices": ["Metronidazole", "Systemic antibiotics", "Fluconazole", "Vaginal estrogen or a moisturizer", "Acyclovir"], "ans": 3, "exp": "Atrophic vaginitis (GSM) จากขาด estrogen — ช่องคลอดแห้ง บาง แดง เจ็บ pH สูง. รักษาด้วย vaginal estrogen ขนาดต่ำ หรือ moisturizer/lubricant. ไม่ใช่การติดเชื้อจึงไม่ใช้ยาปฏิชีวนะ/ยาต้านเชื้อรา (แต่แยกการติดเชื้อร่วม)."}, {"topic": "Gynecology", "q": "A woman wants to track ovulation at home for conception. Which method is used?", "choices": ["A home progesterone test", "A home prolactin test", "A home FSH test", "Daily pelvic ultrasound", "Ovulation predictor kit and basal body temperature"], "ans": 4, "exp": "วิธีติดตามการตกไข่ที่บ้าน: ovulation predictor kit (ตรวจ LH surge ในปัสสาวะ - ตกไข่ ~24-36 ชม.หลัง surge) และ basal body temperature (เพิ่มขึ้นหลังตกไข่จาก progesterone). ช่วยกำหนด fertile window."}, {"topic": "Gynecology", "q": "A 28-year-old pregnant woman has a 5 cm simple ovarian cyst without symptoms in the first trimester. What is the most likely diagnosis?", "choices": ["Corpus luteum cyst of pregnancy", "Ovarian carcinoma", "A dermoid cyst", "An endometrioma", "A hydrosalpinx"], "ans": 0, "exp": "ในไตรมาสแรก simple cyst มักเป็น corpus luteum cyst (สร้าง progesterone พยุงการตั้งครรภ์จนรกทำงาน ~10-12 wk) มักหายเองไตรมาส 2. ติดตามด้วย US. ก้อนใหญ่ >5-6 cm/มี solid component/มีอาการจึงผ่าตัด (เลี่ยงไตรมาสแรก)."}, {"topic": "Gynecology", "q": "A woman with hirsutism wants a cosmetic (non-medication) option. Which is appropriate?", "choices": ["A hysterectomy", "Laser hair removal or electrolysis", "Systemic chemotherapy", "Pelvic radiotherapy", "Bilateral oophorectomy"], "ans": 1, "exp": "การจัดการ hirsutism แบบ cosmetic: laser hair removal, electrolysis (ถาวรกว่า), การโกน/ถอน/แว็กซ์, eflornithine cream. ใช้ร่วมการรักษาต้นเหตุ (combined OC ± spironolactone). Medical therapy เห็นผลช้า ~6 เดือน."}, {"topic": "Gynecology", "q": "A pregnant woman with a history of recurrent genital herpes should receive which intervention to reduce recurrence at delivery?", "choices": ["No intervention needed", "Cesarean for all such patients", "Acyclovir suppression from about 36 weeks", "Herpes vaccination", "A course of antibiotics"], "ans": 2, "exp": "หญิงตั้งครรภ์ที่มีประวัติ genital HSV ควรได้ antiviral suppression (acyclovir/valacyclovir) ตั้งแต่ ~36 wk เพื่อลดการกำเริบและ viral shedding → ลดการต้องผ่าคลอดและ neonatal herpes. Active lesion/prodrome ตอนเจ็บครรภ์จึงผ่าคลอด."}, {"topic": "Gynecology", "q": "A woman has superficial (entry) dyspareunia. Which cause is most common?", "choices": ["Deep pelvic endometriosis", "A uterine fibroid", "Ovarian carcinoma", "Vulvovaginal atrophy or vaginismus", "Adenomyosis"], "ans": 3, "exp": "Superficial (entry) dyspareunia มักจากปากช่องคลอด/ช่องคลอดส่วนต้น: vulvovaginal atrophy (GSM), vaginismus, vulvodynia, การติดเชื้อ (candida/herpes). Deep dyspareunia มักจาก endometriosis, PID, adnexal pathology."}, {"topic": "Gynecology", "q": "A woman wants a reversible, highly effective method to space births. What should be recommended?", "choices": ["Tubal ligation", "DMPA only", "Calendar method", "Condoms alone", "A LARC method (implant/IUD)"], "ans": 4, "exp": "ผู้ต้องการเว้นระยะและเก็บโอกาสมีบุตร แนะนำ LARC (implant/IUD) — ประสิทธิภาพสูงเทียบเท่าทำหมันแต่กลับคืนได้. ไม่ควรแนะนำ tubal ligation (ถาวร). shared decision-making."}, {"topic": "Gynecology", "q": "A 45-year-old with a fibroid compressing the bladder wants to avoid major surgery. Which option is appropriate?", "choices": ["Uterine artery embolization or myomectomy", "Observation without treatment", "Systemic chemotherapy", "Pelvic radiotherapy", "A course of antibiotics"], "ans": 0, "exp": "Fibroid ที่มีอาการกดเบียด (bulk symptoms) ในผู้ต้องการเลี่ยง hysterectomy: uterine artery embolization (เก็บมดลูก แต่ไม่แนะนำถ้าต้องการมีบุตร), myomectomy, หรือ MRI-guided focused ultrasound. Medical (GnRH agonist) ลดขนาดชั่วคราว."}, {"topic": "Gynecology", "q": "A woman has a single-duct, spontaneous, bloody nipple discharge. What is the appropriate approach?", "choices": ["Reassurance without work-up", "Imaging and evaluation for papilloma/cancer", "Expressing the discharge manually", "A dopamine agonist", "A course of antibiotics"], "ans": 1, "exp": "น้ำจากหัวนม 'ข้างเดียว, ท่อเดียว, เป็นเลือด, spontaneous' เป็น pathologic discharge — สาเหตุบ่อยคือ intraductal papilloma (benign) แต่ต้องแยกมะเร็ง → mammogram/US ± ductography/biopsy. ต่างจาก galactorrhea (bilateral, milky, prolactin)."}, {"topic": "Gynecology", "q": "At approximately what age is screening mammography generally started in the average-risk population?", "choices": ["Age 20", "Age 30", "Age 40-50, every 1-2 years", "Age 65", "No screening needed"], "ans": 2, "exp": "การคัดกรองมะเร็งเต้านมด้วย mammography เริ่มช่วงอายุ 40-50 ปี ทุก 1-2 ปี (แนวทางต่างกันเล็กน้อย: USPSTF ล่าสุด 40, ACS 45). ผู้เสี่ยงสูง (BRCA, ประวัติครอบครัว) เริ่มเร็วกว่าและอาจเสริม MRI."}, {"topic": "Gynecology", "q": "After a spontaneous or induced abortion, when can contraception be started?", "choices": ["One must wait three months first", "Only condoms may be used", "Contraception is contraindicated", "IUD or hormonal method can start immediately", "Only the calendar method is allowed"], "ans": 3, "exp": "หลังแท้ง การตกไข่กลับมาเร็ว (~2-3 สัปดาห์) จึงควรเริ่มคุมกำเนิดทันที. IUD ใส่ได้ทันทีหลัง evacuation, implant/ยาฮอร์โมนเริ่มได้เลย — ป้องกันการตั้งครรภ์ที่ไม่พึงประสงค์ซ้ำ."}, {"topic": "Gynecology", "q": "A woman with complete uterine procidentia who is a surgical candidate is best managed with which option?", "choices": ["A course of antibiotics", "Systemic chemotherapy", "Estrogen therapy alone", "Observation without treatment", "Vaginal hysterectomy and repair"], "ans": 4, "exp": "Complete procidentia มีอาการมาก — ผ่าตัด (vaginal hysterectomy + apical suspension/colporrhaphy หรือ colpocleisis ในผู้สูงอายุที่ไม่มีเพศสัมพันธ์). ผู้ที่ผ่าตัดไม่ได้ใช้ pessary. Vaginal estrogen ช่วยสภาพเนื้อเยื่อ."}, {"topic": "Gynecology", "q": "What is the benefit of pelvic floor muscle exercise (Kegel)?", "choices": ["Helps stress incontinence and mild prolapse", "Treats ovarian carcinoma", "Treats polycystic ovary syndrome", "Shrinks uterine fibroids", "Reduces menopausal hot flashes"], "ans": 0, "exp": "Kegel exercise เสริมความแข็งแรงของ pelvic floor → ช่วย stress urinary incontinence, mild-moderate prolapse, หลังคลอด. เป็น first-line conservative treatment. ทำถูกวิธีสม่ำเสมอ (อาจใช้ biofeedback/physical therapy ช่วย)."}, {"topic": "Gynecology", "q": "A woman with mixed urinary incontinence (both stress and urge) should receive which initial management?", "choices": ["Immediate surgical repair", "Lifestyle and pelvic floor training", "A course of antibiotics", "A permanent indwelling catheter", "A hysterectomy"], "ans": 1, "exp": "Mixed urinary incontinence — จัดการเบื้องต้นด้วย conservative: lifestyle (ลดน้ำหนัก/คาเฟอีน), Kegel, bladder training และรักษาส่วนที่รำคาญมากสุดก่อน (antimuscarinic ถ้า urge เด่น; sling ถ้า stress เด่นและดื้อ). ประเมิน urodynamics ในรายซับซ้อน."}, {"topic": "Gynecology", "q": "A woman with stress incontinence unresponsive to conservative treatment is best managed with which surgery?", "choices": ["Hysterectomy", "Antimuscarinic drugs", "Midurethral sling", "Catheterization", "Estrogen therapy"], "ans": 2, "exp": "SUI ที่ดื้อ conservative → ผ่าตัดมาตรฐานคือ midurethral sling (TVT/TOT) พยุงท่อปัสสาวะ. ทางเลือกอื่น: Burch colposuspension, urethral bulking agents. เลือกตามผู้ป่วยและความเชี่ยวชาญ."}, {"topic": "Gynecology", "q": "A pregnant woman is non-immune to rubella. What is the appropriate management?", "choices": ["Give the MMR vaccine now in pregnancy", "Give antiviral therapy", "Terminate the pregnancy", "Avoid exposure and give MMR postpartum", "No action is needed"], "ans": 3, "exp": "MMR เป็นวัคซีนเชื้อเป็น ห้ามในครรภ์. หญิงที่ไม่มีภูมิ rubella ควรหลีกเลี่ยงผู้ติดเชื้อ และรับ MMR หลังคลอด (ให้นมได้) เพื่อป้องกันครรภ์ถัดไป. Rubella ไตรมาสแรก → congenital rubella (cataract, PDA, หูหนวก)."}, {"topic": "Gynecology", "q": "A woman with anovulation due to hypogonadotropic (hypothalamic) causes needs ovulation induction. Which is appropriate?", "choices": ["Letrozole alone", "Metformin therapy", "IVF in every case", "No treatment option exists", "Pulsatile GnRH or gonadotropins"], "ans": 4, "exp": "Hypogonadotropic hypogonadism (hypothalamic, LH/FSH ต่ำ) — clomiphene/letrozole มักไม่ได้ผล. ใช้ pulsatile GnRH หรือ gonadotropins (FSH+LH) กระตุ้น follicle โดยตรง. ใน FHA ควรแก้ต้นเหตุ (เพิ่มพลังงาน) ก่อน."}, {"topic": "Gynecology", "q": "A woman with mild PID and stable vital signs is treated as an outpatient with which regimen?", "choices": ["Ceftriaxone plus doxycycline", "Metronidazole alone", "Penicillin alone", "Fluconazole", "Acyclovir"], "ans": 0, "exp": "PID ไม่รุนแรง (ผู้ป่วยนอก): ceftriaxone IM + doxycycline oral 14 วัน + metronidazole (anaerobes) 14 วัน. ข้อบ่งชี้ admit/IV: ตั้งครรภ์, อาการรุนแรง/ไข้สูง/อาเจียน, TOA, ไม่ตอบสนอง oral, สงสัยต้องผ่าตัด. ติดตามดีขึ้นใน 72 ชม."}, {"topic": "Gynecology", "q": "A pregnant woman is diagnosed with PID (rare). What is the appropriate management?", "choices": ["Outpatient oral therapy", "Admission with IV antibiotics", "Immediate surgery", "No treatment needed", "Antiviral therapy"], "ans": 1, "exp": "PID ในครรภ์พบน้อยแต่ถ้าเป็นถือว่ารุนแรง เสี่ยงทั้งแม่และทารก (preterm, pregnancy loss) → admit ให้ยาปฏิชีวนะ IV, หลีกเลี่ยง doxycycline (สูตรปลอดภัยในครรภ์). แยกภาวะอื่น (appendicitis, ectopic)."}, {"topic": "Gynecology", "q": "A woman has recurrent bacterial vaginosis. Besides retreatment, what is helpful?", "choices": ["No further action needed", "Antifungal therapy", "Suppressive therapy and avoid douching", "Estrogen therapy", "Surgical management"], "ans": 2, "exp": "Recurrent BV: extended/suppressive therapy (metronidazole gel 2 ครั้ง/สัปดาห์ หลายเดือน), หลีกเลี่ยงการสวนล้างช่องคลอด (douching) ที่รบกวนสมดุลแบคทีเรีย. การรักษาคู่นอนไม่ช่วยลดการเป็นซ้ำ."}, {"topic": "Gynecology", "q": "A submucosal fibroid causing infertility and recurrent loss is best treated with which procedure?", "choices": ["Observation", "Uterine artery embolization", "Hysterectomy", "Hysteroscopic myomectomy", "Chemotherapy"], "ans": 3, "exp": "Submucosal fibroid (ยื่นเข้าโพรงมดลูก) รบกวนการฝังตัว/เพิ่มการแท้ง → ในผู้ต้องการมีบุตร รักษาด้วย hysteroscopic myomectomy เพิ่มโอกาสตั้งครรภ์. UAE ไม่แนะนำในผู้ต้องการมีบุตร."}, {"topic": "Gynecology", "q": "How should a man prepare for semen analysis?", "choices": ["Abstain for only 24 hours", "No preparation is needed", "Abstain for a full month", "Ejaculate one hour beforehand", "Abstain for 2-5 days before collection"], "ans": 4, "exp": "Semen analysis: งดการหลั่ง 2-5 วันก่อนเก็บ (สั้นเกิน → count ต่ำ; ยาวเกิน → motility ลด), เก็บครบถ้วนส่งภายใน ~1 ชม. (เก็บอุ่น). ประเมิน volume, concentration, motility, morphology (WHO). ผิดปกติควรตรวจซ้ำ."}, {"topic": "Gynecology", "q": "A woman on systemic hormone therapy should be monitored for which of the following?", "choices": ["Symptoms, bleeding, breast/CV risk", "Body weight alone", "Serum prolactin alone", "Serum TSH alone", "No monitoring is needed"], "ans": 0, "exp": "ผู้ใช้ systemic HT ควรประเมินซ้ำเป็นระยะ: ความจำเป็นในการใช้ต่อ (ขนาดต่ำสุด/สั้นสุด), unscheduled vaginal bleeding (ต้องประเมิน endometrium), benefit-risk (เต้านม, cardiovascular, VTE). คัดกรองมะเร็งเต้านมตามปกติ. shared decision-making."}, {"topic": "Gynecology", "q": "A woman has deep dyspareunia with dysmenorrhea and infertility. What is suspected, and how is it confirmed?", "choices": ["Vaginismus, by exam", "Endometriosis, by laparoscopy", "UTI, by urine culture", "Candida, by KOH", "Atrophy, by estrogen trial"], "ans": 1, "exp": "Deep dyspareunia + dysmenorrhea + infertility เป็นภาพคลาสสิกของ endometriosis (โดยเฉพาะ deep infiltrating). ยืนยันด้วย laparoscopy (gold standard) ± imaging (TVS/MRI). สามารถเริ่มรักษา empirically ในหลายกรณี."}, {"topic": "Gynecology", "q": "A woman with a symptomatic 6 cm ovarian dermoid cyst is best treated with which procedure?", "choices": ["Observation", "Hysterectomy with BSO", "Ovarian cystectomy", "Chemotherapy", "Radiation"], "ans": 2, "exp": "Mature cystic teratoma (dermoid) เป็น benign. ขนาดใหญ่ (>5-6 cm)/มีอาการ/เสี่ยง torsion → ovarian cystectomy (laparoscopic ถ้าได้ เก็บรังไข่ในวัยเจริญพันธุ์ ระวัง spillage - chemical peritonitis). อาจ bilateral (~10-15%)."}, {"topic": "Gynecology", "q": "A pregnant woman has a suspicious breast mass. What is the appropriate safe evaluation?", "choices": ["Defer until after delivery", "Hormone therapy", "A CT scan", "Ultrasound primarily, with core biopsy", "Terminate the pregnancy"], "ans": 3, "exp": "ก้อนเต้านมในครรภ์ต้องประเมินเหมือนคนทั่วไป (อย่าเลื่อน — pregnancy-associated breast cancer พยากรณ์แย่). Ultrasound เป็นการตรวจเริ่มต้นที่ปลอดภัย; mammogram ทำได้ (กำบังหน้าท้อง); core biopsy ยืนยัน. Triple assessment ใช้ได้ในครรภ์."}, {"topic": "Gynecology", "q": "A woman stopping contraception to conceive should be counseled about which point?", "choices": ["Wait 6 months to conceive", "Pills cause permanent infertility", "Detox is needed first", "Avoid pregnancy for 1 year", "Fertility returns quickly; start folate"], "ans": 4, "exp": "หลังหยุดยาคุม fertility กลับมาเร็ว (1-3 เดือน) ยกเว้น DMPA (อาจช้าถึง 6-12 เดือน). ยาคุมไม่ทำให้มีบุตรยากถาวร. ควรเริ่ม folic acid 400-600 µg/วันก่อนตั้งครรภ์และ preconception counseling."}, {"topic": "Gynecology", "q": "Drug-induced hyperprolactinemia with galactorrhea is most commonly caused by which drug class?", "choices": ["Antipsychotics and metoclopramide", "NSAIDs", "Statins", "Antihistamines", "Antibiotics"], "ans": 0, "exp": "Drug-induced hyperprolactinemia พบบ่อยจากยาต้าน dopamine: antipsychotics (risperidone, haloperidol), metoclopramide/domperidone, บางส่วน TCA/SSRI, opioids, estrogen. ตรวจประวัติยาก่อนคิดถึง prolactinoma. หยุด/เปลี่ยนยาถ้าทำได้แล้วประเมินซ้ำ."}, {"topic": "Gynecology", "q": "A woman needs non-hormonal contraception without an intrauterine device. Which is appropriate?", "choices": ["A contraceptive implant", "Condom, diaphragm, or fertility awareness", "Combined oral contraceptives", "DMPA injection", "The levonorgestrel IUS"], "ans": 1, "exp": "ทางเลือก non-hormonal (ไม่ใช่ device ในโพรงมดลูก): barrier (ถุงยาง, diaphragm + spermicide), fertility awareness-based methods (การนับวัน/มูก/BBT). ถุงยางยังป้องกัน STI. Copper IUD เป็น non-hormonal แต่เป็น device."}, {"topic": "Gynecology", "q": "A pregnant woman with large genital warts is best treated with which method?", "choices": ["Cesarean delivery for all", "Radiotherapy", "Pregnancy-safe methods (TCA, cryotherapy, surgery)", "No treatment ever", "Oral antiviral therapy"], "ans": 2, "exp": "Genital warts ในครรภ์อาจโตขึ้น. รักษาด้วยวิธีปลอดภัยในครรภ์: TCA, cryotherapy, surgical removal/laser. หลีกเลี่ยง podophyllin/imiquimod. ผ่าคลอดพิจารณาเฉพาะเมื่อหูดใหญ่มากอุดกั้นช่องคลอด/เสี่ยงเลือดออก (ไม่ใช่เพื่อป้องกัน transmission)."}, {"topic": "Gynecology", "q": "A woman with a cervical polyp causing intermenstrual bleeding is best managed with which procedure?", "choices": ["Observation only", "Antibiotics", "Hysterectomy", "Polypectomy with histology", "Chemotherapy"], "ans": 3, "exp": "Cervical polyp ที่มีอาการ (เลือดออก/postcoital) ควรตัดออก (polypectomy) และส่งชิ้นเนื้อตรวจพยาธิ (ส่วนใหญ่ benign แต่แยก malignancy/dysplasia). ประเมิน endometrium/ปากมดลูกร่วมถ้ามีเลือดออกผิดปกติ."}, {"topic": "Gynecology", "q": "A 30-year-old couple with 2 years of unexplained infertility is best managed with which first step?", "choices": ["IVF immediately", "Hysterectomy", "Observation only", "Tubal surgery", "Ovulation induction with IUI"], "ans": 4, "exp": "Unexplained infertility (ตรวจครบปกติ) — รักษาเป็นขั้นบันได: เริ่ม ovulation induction (letrozole/clomiphene) + IUI หลายรอบ; ไม่สำเร็จจึง IVF. อายุมารดา/ระยะเวลามีผลต่อการก้าวไป IVF เร็วขึ้น (≥35-38 ปี)."}, {"topic": "Gynecology", "q": "A woman worried about bone loss from DMPA should be counseled that which is true?", "choices": ["Bone loss is reversible after stopping", "It is absolutely contraindicated", "DXA is needed monthly", "Only the elderly can use it", "Switch to high-dose estrogen"], "ans": 0, "exp": "DMPA ทำให้ BMD ลดชั่วคราว (reversible) กลับคืนหลังหยุด — ไม่ควรจำกัดระยะเวลาการใช้เพียงเพราะเรื่องกระดูก (WHO/ACOG). แนะนำ calcium/vitamin D, ออกกำลังกาย, เลิกบุหรี่. ประโยชน์คุมกำเนิดมีมากกว่าความเสี่ยง."}, {"topic": "Gynecology", "q": "A woman postpartum wants an IUD. When can it be inserted?", "choices": ["Never in the postpartum period", "Immediately after placenta or at 4-6 weeks", "Only during menstruation", "Only after one year", "Only after weaning"], "ans": 1, "exp": "IUD ใส่ได้ทั้ง immediate postpartum (ภายใน 10 นาที-48 ชม.หลังคลอดรก — สะดวก แต่ expulsion สูงกว่าเล็กน้อย) หรือ interval (หลัง 4-6 สัปดาห์). ปลอดภัยในหญิงให้นม. เป็น LARC ที่ดีสำหรับ postpartum contraception."}, {"topic": "Gynecology", "q": "A pelvic mass with ascites and a very high CA-125 in a postmenopausal woman should be referred to whom?", "choices": ["General internist", "General surgeon", "Gynecologic oncologist", "Dermatologist", "No referral needed"], "ans": 2, "exp": "Pelvic/adnexal mass ที่น่าสงสัยมะเร็ง (solid, ascites, CA-125 สูงในวัยหมดประจำเดือน, RMI สูง) ควรส่ง gynecologic oncologist เพื่อวางแผน surgical staging/cytoreduction (เพิ่ม survival). อย่าเจาะ/ผ่าก้อนแบบไม่วางแผน (เสี่ยง spillage)."}, {"topic": "Gynecology", "q": "A woman with an ovarian cyst aspirated to clear fluid with complete resolution is managed how?", "choices": ["Mastectomy", "Chemotherapy", "Hormone therapy", "Reassure and follow up", "Radiation"], "ans": 3, "exp": "Simple cyst ที่เจาะดูดได้ของเหลวใส (ไม่มีเลือด) และก้อนยุบหมด เป็น benign → reassure และติดตาม. ถ้าของเหลวเป็นเลือด/ก้อนไม่ยุบ/กลับเป็นซ้ำ ต้องประเมินต่อ (imaging/biopsy) แยก intracystic pathology/มะเร็ง."}, {"topic": "Gynecology", "q": "A pregnant woman treated for syphilis develops fever, chills, and myalgia hours after penicillin. What is this reaction?", "choices": ["Drug anaphylaxis alone", "A new infection", "Preeclampsia", "Chorioamnionitis alone", "Jarisch-Herxheimer reaction"], "ans": 4, "exp": "Jarisch-Herxheimer reaction — ไข้ หนาวสั่น ปวดเมื่อย ภายในไม่กี่ชั่วโมงหลังเริ่มรักษาซิฟิลิสด้วย penicillin (จาก endotoxin เมื่อ spirochete ตาย). ในครรภ์อาจกระตุ้น contraction/fetal distress ชั่วคราว → เฝ้าระวัง. รักษาประคับประคอง ไม่ต้องหยุด penicillin."}, {"topic": "Gynecology", "q": "For the lactational amenorrhea method (LAM) to be effective, which conditions must be met?", "choices": ["Exclusive breastfeeding, amenorrhea, under 6 months", "Any breastfeeding at any time", "No specific conditions required", "Mixed feeding is acceptable", "Concurrent pills are required"], "ans": 0, "exp": "LAM ได้ผลดี (~98%) เมื่อครบ 3 เงื่อนไข: exclusive breastfeeding, amenorrhea (ประจำเดือนยังไม่มา), ทารก <6 เดือน. เมื่อเงื่อนไขใดหายไปต้องเริ่มวิธีอื่น. การให้นมบ่อยกด GnRH → ยับยั้งการตกไข่."}, {"topic": "Gynecology", "q": "A 38-year-old wants to assess ovarian reserve before planning pregnancy. Which test is used?", "choices": ["Serum CA-125 level", "AMH and antral follicle count", "Serum prolactin level", "Serum TSH alone", "Hysterosalpingography"], "ans": 1, "exp": "Ovarian reserve testing: AMH (จำนวน follicle ที่เหลือ - ตรวจได้ทุกวัน), antral follicle count (US), day-3 FSH/estradiol. ช่วยทำนายการตอบสนอง IVF และให้คำปรึกษาเรื่องอายุ. AMH ต่ำ = diminished reserve."}, {"topic": "Gynecology", "q": "A woman with bilateral tubal blockage on HSG who desires pregnancy is best managed with which option?", "choices": ["Timed intercourse", "Ovulation drugs alone", "IVF, bypassing the tubes", "IUI", "No option available"], "ans": 2, "exp": "Bilateral tubal blockage (tubal factor) — ไข่กับอสุจิพบกันไม่ได้ในท่อ → IVF เหมาะสม (ผสมนอกร่างกายแล้วย้ายตัวอ่อนกลับ ไม่ต้องพึ่งท่อ). Tubal surgery ในบางรายที่ท่อเสียหายน้อย. IUI ต้องการท่อเปิดอย่างน้อยข้างหนึ่ง."}, {"topic": "Gynecology", "q": "A woman with a simple ovarian cyst 8 cm and pain is best managed how?", "choices": ["Follow up only", "Antibiotics", "Chemotherapy", "Consider surgery (cystectomy)", "Hysterectomy"], "ans": 3, "exp": "Simple cyst ที่ใหญ่ (>7-10 cm)/มีอาการ/ไม่หายตามการติดตาม เสี่ยง torsion → พิจารณาผ่าตัด (laparoscopic cystectomy - เก็บรังไข่). Cyst เล็ก (<5 cm) ไม่มีอาการมักติดตามได้. ประเมินลักษณะน่ากังวลและ CA-125 ตามเหมาะสม."}, {"topic": "Gynecology", "q": "A woman with recurrent Bartholin abscess after simple I&D is best managed with which procedure?", "choices": ["Repeat simple I&D", "Antibiotics alone", "Hysterectomy", "Observation", "Marsupialization"], "ans": 4, "exp": "Bartholin abscess ที่เป็นซ้ำหลัง simple I&D → marsupialization (เย็บเปิดผนัง cyst สร้างทางระบายถาวร) หรือ Word catheter. หญิง >40 ปีที่เป็นก้อนแข็งควร biopsy แยกมะเร็ง Bartholin gland."}, {"topic": "Gynecology", "q": "A woman with combined OC who wants help for acne and hirsutism benefits from which type of progestin?", "choices": ["Anti-androgenic progestin", "Androgenic progestin", "Progestin-only method", "Copper IUD", "DMPA"], "ans": 0, "exp": "Combined OC ที่มี anti-androgenic progestin (drospirenone, cyproterone) ช่วยสิว/hirsutism (เพิ่ม SHBG ลด free androgen + ต้าน androgen receptor). เหมาะกับ PCOS ที่มี hyperandrogenism. Copper IUD/progestin-only บางชนิดไม่ช่วย/อาจแย่ลง."}, {"topic": "Gynecology", "q": "An HIV-positive pregnant woman with a viral load over 1,000 copies near term should deliver by which route?", "choices": ["Normal vaginal delivery", "Scheduled cesarean with IV zidovudine", "Await spontaneous labor", "Vacuum extraction", "Emergency cesarean only in labor"], "ans": 1, "exp": "หญิง HIV ที่ viral load >1,000 copies/mL ใกล้คลอด → scheduled cesarean ที่ ~38 wk (ก่อนเจ็บครรภ์/ถุงน้ำแตก) + IV zidovudine ลด vertical transmission. viral load <1,000 คุมได้ดี คลอดทางช่องคลอดได้. ทารกได้ ARV prophylaxis, หลีกเลี่ยงให้นม (ในไทย)."}, {"topic": "Gynecology", "q": "A woman has bilateral milky nipple discharge with a high prolactin level. What should be evaluated?", "choices": ["Underlying breast cancer", "A normal physiologic finding", "Causes of hyperprolactinemia", "A breast infection", "A fibroadenoma"], "ans": 2, "exp": "Bilateral galactorrhea + prolactin สูง = hyperprolactinemia. หาสาเหตุ: prolactinoma (MRI), ยา (antipsychotics, metoclopramide), hypothyroidism (TSH), การตั้งครรภ์. ต่างจากน้ำหัวนมข้างเดียว/มีเลือด (ประเมินพยาธิสภาพเต้านม)."}, {"topic": "Gynecology", "q": "A woman with PCOS on combined OC gains which benefit for the endometrium?", "choices": ["An increased cancer risk", "Permanent amenorrhea", "Increased androgen levels", "Protection from endometrial hyperplasia", "No effect at all"], "ans": 3, "exp": "ใน PCOS ที่ chronic anovulation ทำให้ endometrium ได้รับ unopposed estrogen เสี่ยง hyperplasia/มะเร็ง. Combined OC (หรือ cyclic progestin/LNG-IUS) ให้ progestin ปกป้อง endometrium, คุมรอบเดือน, ลด androgen."}, {"topic": "Gynecology", "q": "A woman with an ovarian cyst in menopause, 3 cm, simple, with a normal CA-125, is best managed how?", "choices": ["Immediate surgery", "A hysterectomy", "Systemic chemotherapy", "No follow-up needed", "Ultrasound and CA-125 follow-up"], "ans": 4, "exp": "Simple unilocular cyst เล็ก (<5-10 cm) ในวัยหมดประจำเดือนที่ CA-125 ปกติ ความเสี่ยงมะเร็งต่ำ → ติดตามด้วย US + CA-125. ลักษณะน่ากังวล (solid, septation, ascites, ใหญ่, CA-125 สูง) จึงส่ง gyn-oncology. ใช้ IOTA/RMI ช่วย."}, {"topic": "Gynecology", "q": "A woman has chronic pelvic pain for more than 6 months. Which gynecologic cause is most common?", "choices": ["Endometriosis or adhesions", "Ovarian cancer", "Fibroadenoma", "Osteoporosis", "Gestational diabetes"], "ans": 0, "exp": "Chronic pelvic pain (>6 เดือน) — สาเหตุทางนรีเวชบ่อยสุด: endometriosis, pelvic adhesions (หลัง PID/ผ่าตัด), adenomyosis, chronic PID. ต้องประเมินสาเหตุนอกนรีเวชด้วย (IBS, interstitial cystitis, musculoskeletal). แนวทางสหสาขา."}, {"topic": "Gynecology", "q": "A woman with a breast cyst aspirated to bloody fluid, with the mass not fully resolving, requires which next step?", "choices": ["Reassurance only", "Imaging and biopsy", "Hormone therapy", "Repeat aspiration only", "Antibiotics"], "ans": 1, "exp": "Cyst ที่เจาะได้ของเหลว 'เป็นเลือด' หรือก้อนไม่ยุบหมด/กลับเป็นซ้ำ ต้องประเมินต่อ (imaging + biopsy) แยก intracystic pathology/มะเร็ง. ต่างจาก simple cyst ที่ของเหลวใสและยุบหมด (benign, reassure)."}, {"topic": "Gynecology", "q": "A woman using a combined pill misses two consecutive pills at midcycle. What should she do?", "choices": ["Continue as if nothing happened", "Start a completely new pack", "Take the most recent missed pill and use backup", "Stop the pill permanently", "Nothing needs to be done"], "ans": 2, "exp": "ลืมยาคุมรวม ≥2 เม็ด (≥48 ชม.): กินเม็ดล่าสุดที่ลืมทันที, ทิ้งเม็ดอื่นที่ลืม, กินต่อตามปกติ, ใช้ถุงยางสำรอง 7 วัน, และพิจารณา emergency contraception ถ้ามีเพศสัมพันธ์ในช่วงเสี่ยง."}, {"topic": "Gynecology", "q": "A woman with lichen sclerosus should be monitored for which long-term risk?", "choices": ["Ovarian cancer", "Endometrial cancer", "Cervical cancer", "Vulvar squamous cell carcinoma", "Breast cancer"], "ans": 3, "exp": "Lichen sclerosus เพิ่มความเสี่ยง vulvar SCC (~4-5%) → ต้องเฝ้าระวังระยะยาว และ biopsy บริเวณที่หนา/แผล/เปลี่ยนแปลง. รักษาด้วย high-potency topical corticosteroid ช่วยลดอาการและความเสี่ยง."}, {"topic": "Gynecology", "q": "A woman has recurrent painful genital ulcers that are grouped vesicles. What is the recommended treatment?", "choices": ["Penicillin injection", "Metronidazole", "Fluconazole", "Doxycycline", "Acyclovir or valacyclovir"], "ans": 4, "exp": "Genital herpes (HSV) รักษาด้วย antiviral (acyclovir/valacyclovir/famciclovir) — ลดความรุนแรง/ระยะเวลาและใช้ suppressive therapy ลดการกำเริบ (ไม่หายขาด เพราะ latency ใน ganglia). ในครรภ์ที่มี active lesion ตอนคลอด → C/S."}]}, {"id": "obgyn5", "title": "Ob-gyne ชุดที่ 5 — Gynecologic Oncology & Guideline Updates (Cervix, Endometrium, Ovary, GTD)", "subject": "obgyn", "questions": [{"topic": "Gynecologic Oncology", "q": "A 45-year-old woman is diagnosed with cervical cancer. What is the main underlying cause?", "choices": ["High-risk HPV, especially 16 and 18", "Long-term cigarette smoking", "Oral contraceptive use", "A BRCA gene mutation", "Herpes simplex virus infection"], "ans": 0, "exp": "HPV ความเสี่ยงสูง โดยเฉพาะ HPV 16 และ 18 เป็นสาเหตุหลัก (~70%). persistent infection → precancer (CIN) → มะเร็ง. ปัจจัยเสริม: สูบบุหรี่, HIV, เพศสัมพันธ์อายุน้อย/หลายคู่, ไม่คัดกรอง."}, {"topic": "Gynecologic Oncology", "q": "Which is the most common histologic type of cervical cancer?", "choices": ["Adenocarcinoma", "Squamous cell carcinoma", "Small cell carcinoma", "Clear cell carcinoma", "Sarcoma"], "ans": 1, "exp": "Squamous cell carcinoma พบบ่อยสุด (~70%) เกิดที่ transformation zone. Adenocarcinoma (~25%) จาก glandular cells, คัดกรองด้วย cytology ยากกว่า, สัมพันธ์ HPV 18. ทั้งคู่สัมพันธ์ HPV."}, {"topic": "Gynecologic Oncology", "q": "At what age is the HPV vaccine most effective when given?", "choices": ["After age 45", "Age 20-30", "Age 9-14, before sexual debut", "Only after sexual debut", "Only in infected persons"], "ans": 2, "exp": "วัคซีน HPV มีประสิทธิภาพสูงสุดเมื่อฉีดอายุ 9-14 ปี ก่อนเริ่มมีเพศสัมพันธ์ (ก่อนสัมผัส HPV). ให้ประโยชน์ถึง 26 ปี (พิจารณาถึง 45). เป็น primary prevention ตามเป้า WHO 90-70-90."}, {"topic": "Gynecologic Oncology", "q": "According to the WHO 2022 (SAGE) update, what is the new recommendation on HPV vaccine dosing?", "choices": ["Three doses are always required", "Five doses are now needed", "The vaccine is no longer recommended", "A single dose protects like two doses", "It is only for adults"], "ans": 3, "exp": "[อัปเดต] WHO SAGE 2022: single-dose schedule ให้การป้องกันเทียบเท่า 2 เข็มในอายุ 9-20 ปี — ประเทศเลือกใช้ 1 หรือ 2 เข็มได้ (การศึกษาในไทยสนับสนุน). เพิ่มความครอบคลุม/ลดต้นทุน. (ภูมิคุ้มกันบกพร่อง/HIV ยังแนะนำหลายเข็ม)."}, {"topic": "Gynecologic Oncology", "q": "Per RTCOG/Thai guidance, which is the preferred primary screening method for women aged 30 and over?", "choices": ["A yearly Pap smear", "No screening at all", "Monthly VIA inspection", "Serum CA-125 testing", "Primary HPV testing every 5 years"], "ans": 4, "exp": "[อัปเดต] RTCOG/ไทย: คัดกรองอายุ 25-65 ปี ด้วย cytology ทุก 2 ปี หรือ HPV testing ทุก 5 ปี หรือ co-testing ทุก 5 ปี; อายุ ≥30 ปีเน้น HPV testing ทุก 5 ปี (ไวกว่า). สปสช.บรรจุ HPV DNA test + self-collection."}, {"topic": "Gynecologic Oncology", "q": "Which approach has the NHSO (สปสช.) adopted to expand cervical cancer screening coverage?", "choices": ["HPV DNA testing with self-collection", "A blood-based screening test", "No change from before", "MRI-based screening", "Surgical screening"], "ans": 0, "exp": "[อัปเดต] ตั้งแต่ปี 2563 สปสช.บรรจุ HPV DNA test และรองรับ self-collected HPV sampling (เก็บตัวอย่างเอง) เพื่อเพิ่มการเข้าถึง/ความครอบคลุม โดยเฉพาะผู้ไม่สะดวกตรวจภายใน. เป็นกลยุทธ์สู่การกำจัดมะเร็งปากมดลูก."}, {"topic": "Gynecologic Oncology", "q": "A woman has an HSIL Pap smear result. What is the next step?", "choices": ["Repeat Pap in 5 years", "Colposcopy and biopsy", "Immediate hysterectomy", "Antibiotic therapy", "Radiotherapy"], "ans": 1, "exp": "ผลคัดกรองความเสี่ยงสูง (HSIL, HPV 16/18, หรือ high-risk HPV + abnormal cytology) → colposcopy + biopsy. พบ CIN2/3 → รักษาด้วย excision (LEEP/conization) หรือ ablation. ไม่ผ่าตัดใหญ่ก่อนยืนยันชิ้นเนื้อ."}, {"topic": "Gynecologic Oncology", "q": "How is CIN 2/3 (high-grade cervical precancer) treated?", "choices": ["Antiviral therapy", "Chemotherapy", "LEEP or conization", "Hysterectomy always", "Observation for 5 years"], "ans": 2, "exp": "CIN 2/3 (precancer) รักษาด้วย excisional (LEEP/conization - ได้ margin) หรือ ablative (cryotherapy/laser). ไม่จำเป็นต้อง hysterectomy (สงวนมดลูก). CIN 1 มักติดตาม (regress เอง). รักษา precancer ป้องกันมะเร็ง."}, {"topic": "Gynecologic Oncology", "q": "What is a key change in the FIGO 2018 cervical cancer staging system?", "choices": ["Uses clinical examination only", "Abolishes staging entirely", "Uses serum CA-125", "Adds imaging and nodal status (IIIC)", "Uses tumor size only"], "ans": 3, "exp": "[อัปเดต FIGO 2018] อนุญาตให้ใช้ imaging (MRI/CT/PET) และผลพยาธิร่วมประเมิน, เพิ่ม lymph node involvement เป็น stage IIIC (IIIC1 pelvic, IIIC2 para-aortic), และปรับเกณฑ์ขนาดใน stage IB (IB1<2, IB2 2-4, IB3 ≥4 cm)."}, {"topic": "Gynecologic Oncology", "q": "How is locally advanced cervical cancer (stage IIB-IVA) treated?", "choices": ["Radical surgery alone", "Chemotherapy alone", "Observation only", "Hormone therapy alone", "Concurrent chemoradiation with brachytherapy"], "ans": 4, "exp": "มะเร็งปากมดลูก locally advanced รักษาด้วย concurrent chemoradiation (external beam RT + cisplatin) ตามด้วย brachytherapy. Early stage (IA, IB1-IB2, IIA1) รักษาด้วยผ่าตัด (radical hysterectomy + pelvic node) หรือ RT ได้ผลเทียบเท่า."}, {"topic": "Gynecologic Oncology", "q": "Which gynecologic cancer characteristically presents as postmenopausal bleeding?", "choices": ["Endometrial cancer", "Ovarian cancer", "Vulvar cancer", "Fallopian tube cancer", "Early cervical cancer"], "ans": 0, "exp": "มะเร็งเยื่อบุโพรงมดลูก (endometrial cancer) มีอาการเด่นเป็น postmenopausal bleeding (~90%) จึงมักวินิจฉัยระยะแรก. Postmenopausal bleeding ทุกรายต้องประเมิน endometrium. พบบ่อยในประเทศพัฒนาแล้ว."}, {"topic": "Gynecologic Oncology", "q": "Which is a risk factor for type I endometrial cancer?", "choices": ["Oral contraceptive use", "Unopposed estrogen exposure", "Breastfeeding", "Cigarette smoking", "Regular exercise"], "ans": 1, "exp": "Endometrial cancer type I (endometrioid, estrogen-dependent) เสี่ยงจาก unopposed estrogen: obesity, PCOS/anovulation, nulliparity, tamoxifen, estrogen-only HT, DM, Lynch syndrome. Combined OC/multiparity/ให้นมเป็นปัจจัยป้องกัน."}, {"topic": "Gynecologic Oncology", "q": "What is the gold standard for diagnosing endometrial cancer?", "choices": ["Transvaginal ultrasound", "Pap smear", "Endometrial biopsy", "Serum CA-125", "MRI"], "ans": 2, "exp": "Endometrial biopsy (histology) เป็น gold standard — office sampling หรือ D&C/hysteroscopy. TVS (endometrial thickness) ใช้คัดกรองเบื้องต้น แต่ยืนยันด้วยชิ้นเนื้อ. Pap ไม่ใช้วินิจฉัย endometrial cancer."}, {"topic": "Gynecologic Oncology", "q": "What is a key change in the FIGO 2023 endometrial cancer staging system?", "choices": ["Uses anatomy only", "Abolishes staging entirely", "Uses serum CA-125", "Adds grade, LVSI, molecular class", "Uses uterine size only"], "ans": 3, "exp": "[อัปเดต FIGO 2023] ผนวก histologic type, grade, substantial LVSI, และ molecular classification (POLEmut/MMRd/NSMP/p53abn). POLEmut = พยากรณ์ดีสุด, p53abn = แย่สุด. สะท้อนพยากรณ์/การรักษาแม่นยำขึ้น."}, {"topic": "Gynecologic Oncology", "q": "What is the standard treatment of early-stage endometrial cancer?", "choices": ["Chemotherapy alone", "Radiotherapy alone", "Hormone therapy alone", "Observation only", "Hysterectomy, BSO, and surgical staging"], "ans": 4, "exp": "การรักษาหลักคือผ่าตัด: total hysterectomy + bilateral salpingo-oophorectomy + surgical staging (± node/sentinel node). เสริม adjuvant RT/chemo ตามระยะ/ความเสี่ยง/molecular. ผู้ต้องการมีบุตรระยะต้น grade ต่ำ อาจ high-dose progestin ชั่วคราว."}, {"topic": "Gynecologic Oncology", "q": "Which gynecologic cancer has the highest mortality, often diagnosed at a late stage?", "choices": ["Ovarian cancer", "Cervical cancer", "Vaginal cancer", "Endometrial cancer", "Vulvar cancer"], "ans": 0, "exp": "Ovarian cancer มีอัตราตายสูงสุด เพราะมักวินิจฉัยระยะท้าย — อาการไม่จำเพาะ ('silent killer': ท้องอืด อิ่มเร็ว ปัสสาวะบ่อย) และไม่มีวิธีคัดกรองที่ได้ผลในคนทั่วไป. Epithelial (high-grade serous) พบบ่อยสุด."}, {"topic": "Gynecologic Oncology", "q": "Which genetic mutation most increases the risk of epithelial ovarian cancer?", "choices": ["HPV integration", "BRCA1/BRCA2 mutation", "Cigarette exposure", "Thalassemia trait", "GDM"], "ans": 1, "exp": "BRCA1/BRCA2 mutation เพิ่มความเสี่ยงมะเร็งรังไข่ (และเต้านม) มาก — เป็นข้อบ่งชี้ risk-reducing salpingo-oophorectomy. Lynch syndrome ก็เพิ่มความเสี่ยง. ปัจจัยป้องกัน: combined OC, ตั้งครรภ์/ให้นม, ทำหมัน/salpingectomy."}, {"topic": "Gynecologic Oncology", "q": "Which tumor marker is used to monitor epithelial ovarian cancer?", "choices": ["AFP", "hCG", "CA-125", "LDH", "CEA only"], "ans": 2, "exp": "CA-125 ใช้ติดตามการรักษา/กลับเป็นซ้ำของ epithelial ovarian cancer (โดยเฉพาะ serous). ไม่จำเพาะ จึงไม่ใช้คัดกรองคนทั่วไป. Germ cell: dysgerminoma-LDH, yolk sac-AFP, choriocarcinoma-hCG. HE4+CA-125 (ROMA) ช่วยประเมิน."}, {"topic": "Gynecologic Oncology", "q": "An 18-year-old has a rapidly enlarging ovarian mass with a high AFP. Which tumor is likely?", "choices": ["Serous cystadenocarcinoma", "A Brenner tumor", "A granulosa cell tumor", "Yolk sac (endodermal sinus) tumor", "Mucinous cystadenoma"], "ans": 3, "exp": "หญิงสาว + ก้อนรังไข่โตเร็ว + AFP สูง = yolk sac (endodermal sinus) tumor (germ cell). Germ cell markers: dysgerminoma-LDH, choriocarcinoma-hCG, immature teratoma. Germ cell tumors ตอบสนองเคมี (BEP) ดี, ผ่าตัดเก็บ fertility ได้."}, {"topic": "Gynecologic Oncology", "q": "An ovarian tumor producing estrogen causing precocious puberty or postmenopausal bleeding, with elevated inhibin, is which type?", "choices": ["Dysgerminoma", "Yolk sac tumor", "Serous cystadenoma", "Krukenberg tumor", "Granulosa cell tumor"], "ans": 4, "exp": "Granulosa cell tumor (sex cord-stromal) สร้าง estrogen → precocious puberty (เด็ก), menorrhagia/hyperplasia (ผู้ใหญ่), postmenopausal bleeding. Marker: inhibin, AMH. Call-Exner bodies. โตช้าและกลับเป็นซ้ำได้."}, {"topic": "Gynecologic Oncology", "q": "An ovarian tumor producing androgens causing virilization is which type?", "choices": ["Sertoli-Leydig cell tumor", "Granulosa cell tumor", "Serous cystadenoma", "Dysgerminoma", "Dermoid cyst"], "ans": 0, "exp": "Sertoli-Leydig cell tumor (sex cord-stromal) สร้าง androgen → virilization: hirsutism, เสียงห้าว, clitoromegaly, amenorrhea. พบในหญิงสาว. ต่างจาก granulosa (estrogen). รักษาด้วยผ่าตัด (มัก unilateral, prognosis ดีระยะต้น)."}, {"topic": "Gynecologic Oncology", "q": "What is a Krukenberg tumor?", "choices": ["A primary ovarian carcinoma", "Metastasis to the ovary with signet-ring cells", "A benign ovarian tumor", "A functional ovarian cyst", "A germ cell tumor"], "ans": 1, "exp": "Krukenberg tumor = มะเร็งแพร่กระจายมารังไข่ทั้งสองข้าง (metastatic) จาก primary GI (โดยเฉพาะกระเพาะอาหาร) มี mucin-producing signet-ring cells. เมื่อพบก้อนรังไข่ที่สงสัย metastasis ต้องหา primary GI."}, {"topic": "Gynecologic Oncology", "q": "How is advanced ovarian cancer treated?", "choices": ["Radiotherapy alone", "Hormone therapy alone", "Debulking plus platinum chemotherapy", "Observation only", "A course of antibiotics"], "ans": 2, "exp": "Epithelial ovarian cancer ระยะลุกลาม: cytoreductive surgery (debulking optimal <1 cm) + platinum-based chemo (carboplatin+paclitaxel). [อัปเดต] PARP inhibitor maintenance ใน BRCA/HRD. Neoadjuvant chemo ก่อนผ่าตัดในบางราย."}, {"topic": "Gynecologic Oncology", "q": "Which drug class is used as maintenance in ovarian cancer with BRCA mutation/HRD?", "choices": ["Aromatase inhibitor", "Cisplatin alone", "Metformin", "PARP inhibitor", "Tamoxifen"], "ans": 3, "exp": "[อัปเดต] PARP inhibitor (olaparib, niraparib) เป็น maintenance หลัง platinum chemo ในมะเร็งรังไข่ BRCA mutation/HRD — อาศัย synthetic lethality (เซลล์ซ่อม DNA บกพร่องตายเมื่อยับยั้ง PARP). เพิ่ม progression-free survival."}, {"topic": "Gynecologic Oncology", "q": "What is the genetic profile of a complete hydatidiform mole?", "choices": ["Triploid with fetal tissue", "Trisomy 21", "Normal 46,XY", "Monosomy X", "Paternal-only 46,XX with no fetus"], "ans": 4, "exp": "Complete mole: มัก 46,XX จากพ่อทั้งหมด (androgenesis) ไม่มีเนื้อเยื่อทารก. hCG สูงมาก, snowstorm, theca lutein cysts, เสี่ยงกลายเป็น GTN สูงกว่า partial mole (triploid 69,XXX มีเนื้อเยื่อทารก)."}, {"topic": "Gynecologic Oncology", "q": "Which finding may be seen in a molar pregnancy?", "choices": ["Uterus larger than dates with very high hCG", "Persistent low blood pressure", "A high spiking fever", "Recurrent hypoglycemia", "Profuse watery diarrhea"], "ans": 0, "exp": "Molar pregnancy: เลือดออก, มดลูกโตกว่าอายุครรภ์, hCG สูงมาก, hyperemesis รุนแรง, theca lutein cysts, และภาวะจาก hCG สูง (hyperthyroidism, preeclampsia ก่อน 20 wk). US: snowstorm/ไม่พบทารก (complete)."}, {"topic": "Gynecologic Oncology", "q": "What is the initial treatment and follow-up of a hydatidiform mole?", "choices": ["Hysterectomy always", "Suction curettage with serial hCG", "Radiotherapy", "Immediate chemotherapy", "Await spontaneous abortion"], "ans": 1, "exp": "รักษา molar ด้วย suction curettage แล้วติดตาม serial β-hCG จนเป็นลบต่อเนื่อง (ตรวจต่อ ~6 เดือน) เพื่อจับ GTN. คุมกำเนิดระหว่างติดตาม (การตั้งครรภ์ใหม่ทำให้แปลผล hCG ไม่ได้). Rh negative ให้ anti-D."}, {"topic": "Gynecologic Oncology", "q": "After molar evacuation, beta-hCG plateaus or rises. What does this indicate?", "choices": ["Normal expected recovery", "A new intrauterine pregnancy", "GTN needing chemotherapy", "Developing preeclampsia", "An intrauterine infection"], "ans": 2, "exp": "β-hCG plateau (คงที่ ≥3 ค่า/3 สัปดาห์) หรือ rising หลัง evacuation บ่งชี้ persistent GTN (invasive mole/choriocarcinoma) → ประเมินระยะ (FIGO/WHO score) และรักษาด้วยเคมีบำบัด. แยกการตั้งครรภ์ใหม่ก่อน. GTN ตอบสนองเคมีดีมาก."}, {"topic": "Gynecologic Oncology", "q": "How does choriocarcinoma respond to treatment?", "choices": ["Resistant to all treatment", "It cannot be treated at all", "Responds only to hormone therapy", "Very responsive to chemotherapy, even if metastatic", "Requires radiotherapy only"], "ans": 3, "exp": "Choriocarcinoma ตอบสนองเคมีบำบัดดีมาก — low-risk GTN: single-agent (methotrexate/actinomycin D); high-risk: multi-agent (EMA-CO). อัตราหายสูงแม้แพร่กระจาย (ปอด สมอง) โดยติดตาม hCG. เป็นตัวอย่างมะเร็งที่รักษาหายด้วยเคมีบำบัดแม้ระยะแพร่กระจาย."}, {"topic": "Gynecologic Oncology", "q": "A 60-year-old has a chronic vulvar ulcer with squamous cell carcinoma on biopsy. In older women, which is a risk factor?", "choices": ["HPV only", "The oral contraceptive pill", "Pregnancy", "PCOS", "Lichen sclerosus"], "ans": 4, "exp": "Vulvar cancer (ส่วนใหญ่ SCC) 2 pathway: HPV-related (อายุน้อย) และ non-HPV related สัมพันธ์กับ lichen sclerosus/chronic inflammation ในผู้สูงอายุ. แผลเรื้อรังที่ vulva ต้อง biopsy. รักษาด้วยผ่าตัด (wide excision/vulvectomy + node) ± RT."}, {"topic": "Gynecologic Oncology", "q": "An ovarian fibroma with ascites and a pleural effusion that resolve after tumor removal describes which syndrome?", "choices": ["Meigs syndrome", "Sheehan syndrome", "Krukenberg syndrome", "Fitz-Hugh-Curtis syndrome", "Asherman syndrome"], "ans": 0, "exp": "Meigs syndrome = triad ของ ovarian fibroma (benign) + ascites + pleural effusion ซึ่งหายหมดหลังผ่าตัด. สำคัญเพราะเลียนแบบมะเร็งรังไข่ระยะลุกลาม (ก้อน + ascites + effusion + CA-125 สูงเล็กน้อย) แต่เป็น benign."}, {"topic": "Gynecologic Oncology", "q": "Primary and secondary prevention of cervical cancer are best represented by which pair?", "choices": ["Screening, then treatment", "HPV vaccine, then screening", "Treatment, then vaccine", "Surgery, then radiation", "No prevention available"], "ans": 1, "exp": "Primary prevention = วัคซีน HPV (ป้องกันการติดเชื้อ). Secondary = การคัดกรอง (Pap/HPV) ตรวจจับและรักษา precancer (CIN) ก่อนเป็นมะเร็ง. Tertiary = การรักษามะเร็ง. เป้า WHO 90-70-90."}, {"topic": "Gynecologic Oncology", "q": "A woman with Lynch syndrome (HNPCC) has an increased risk of which gynecologic cancers?", "choices": ["Cervical cancer", "Breast cancer", "Endometrial and ovarian cancer", "Vaginal cancer", "No increased risk"], "ans": 2, "exp": "Lynch syndrome (MMR gene mutation) เพิ่มความเสี่ยงมะเร็งลำไส้ใหญ่, เยื่อบุโพรงมดลูก ('sentinel cancer'), และรังไข่. แนะนำเฝ้าระวัง (endometrial sampling) และพิจารณา risk-reducing hysterectomy + BSO หลังมีบุตรครบ. ตรวจ MMR/MSI ในชิ้นเนื้อ."}, {"topic": "Gynecologic Oncology", "q": "A woman with a BRCA1 mutation wants to reduce ovarian cancer risk. What should be considered?", "choices": ["No intervention needed", "Hysterectomy alone", "Preventive chemotherapy", "Risk-reducing salpingo-oophorectomy after childbearing", "Preventive radiotherapy"], "ans": 3, "exp": "[อัปเดต] ผู้มี BRCA1/2 แนะนำ risk-reducing bilateral salpingo-oophorectomy หลังมีบุตรครบ (BRCA1 ~35-40 ปี) ลดความเสี่ยงมะเร็งรังไข่/ท่อนำไข่ ~80% และลดมะเร็งเต้านม. ทางเลือกใหม่: salpingectomy ก่อนแล้ว oophorectomy ทีหลัง กำลังศึกษา."}, {"topic": "Gynecologic Oncology", "q": "Which HPV types does the 9-valent vaccine add beyond the quadrivalent vaccine?", "choices": ["None additional", "Only 6 and 11", "Herpes types", "Only 16 and 18", "31, 33, 45, 52, 58"], "ans": 4, "exp": "9-valent ครอบคลุม HPV 6, 11 (หูด) + 16, 18 (มะเร็ง) เหมือน quadrivalent และเพิ่ม high-risk 31, 33, 45, 52, 58 → ป้องกันมะเร็งปากมดลูกครอบคลุมขึ้น (~90%). Bivalent ครอบคลุม 16, 18."}, {"topic": "Gynecologic Oncology", "q": "Which malignant ovarian germ cell tumor is the most common and radiosensitive?", "choices": ["Dysgerminoma", "Yolk sac tumor", "Choriocarcinoma", "Immature teratoma", "Embryonal carcinoma"], "ans": 0, "exp": "Dysgerminoma เป็น malignant germ cell tumor ที่พบบ่อยสุด พบในหญิงสาว, marker LDH (± hCG เล็กน้อย), ไวต่อทั้งเคมี (BEP) และรังสี. เทียบเท่า seminoma. มัก unilateral ระยะต้น, ผ่าตัดเก็บ fertility + เคมี, พยากรณ์ดี."}, {"topic": "Gynecologic Oncology", "q": "Which epithelial ovarian cancer is the most common and most aggressive?", "choices": ["Mucinous carcinoma", "High-grade serous carcinoma", "Endometrioid carcinoma", "Clear cell carcinoma", "Brenner tumor"], "ans": 1, "exp": "High-grade serous carcinoma พบบ่อยสุด (~70% ของ epithelial) และร้ายแรง — วินิจฉัยระยะลุกลาม, สัมพันธ์ BRCA/TP53, หลายรายเริ่มจาก fallopian tube (STIC). ตอบสนอง platinum. ชนิดอื่น: mucinous, endometrioid/clear cell (สัมพันธ์ endometriosis)."}, {"topic": "Gynecologic Oncology", "q": "Many high-grade serous 'ovarian' cancers are now thought to originate where?", "choices": ["Endometrium alone", "Vagina", "Fallopian tube (STIC)", "Cervix", "Breast tissue"], "ans": 2, "exp": "หลักฐานปัจจุบันชี้ว่า high-grade serous 'ovarian' cancer จำนวนมากเริ่มจาก fimbrial end ของ fallopian tube (serous tubal intraepithelial carcinoma - STIC) แล้วลุกลามมารังไข่/เยื่อบุช่องท้อง. จึง opportunistic/risk-reducing salpingectomy ช่วยลดความเสี่ยง."}, {"topic": "Gynecologic Oncology", "q": "How is high-grade vulvar intraepithelial neoplasia (VIN) treated?", "choices": ["No treatment needed", "A total hysterectomy", "Systemic chemotherapy", "Wide local excision or laser", "Pelvic radiotherapy"], "ans": 3, "exp": "VIN high-grade เป็น precancer ของ vulva. รักษาด้วย wide local excision (โดยเฉพาะ differentiated VIN เสี่ยงมะเร็งสูง), laser ablation, หรือ topical imiquimod (usual type). ติดตามใกล้ชิดเพราะเสี่ยง vulvar SCC. เลิกบุหรี่/รักษา lichen sclerosus ช่วยลดความเสี่ยง."}, {"topic": "Gynecologic Oncology", "q": "What is the classic triad of fallopian tube carcinoma (hydrops tubae profluens)?", "choices": ["Pain, fever, and vaginal bleeding", "Back pain, leg swelling, fatigue", "Nausea, vomiting, and diarrhea", "No classic triad exists", "Watery/bloody discharge, pain, adnexal mass"], "ans": 4, "exp": "มะเร็งท่อนำไข่ (พบน้อย, ส่วนใหญ่ serous, สัมพันธ์ BRCA) — triad 'hydrops tubae profluens': ตกขาว/เลือดออกเป็นน้ำเป็นระยะ + ปวดท้องน้อย + ก้อนที่ปีกมดลูก (ยุบหลังของเหลวระบาย). ปัจจุบันจัดรวมกับมะเร็งรังไข่/peritoneal."}, {"topic": "Gynecologic Oncology", "q": "Which landmark trial supports tranexamic acid use in postpartum hemorrhage?", "choices": ["WOMAN trial", "Term Breech Trial", "ARRIVE trial", "Hypitat trial", "MAGPIE trial"], "ans": 0, "exp": "[อัปเดต] WOMAN trial แสดงว่า TXA (1 g IV ภายใน 3 ชม.) ลดการตายจากเลือดออกใน PPH → WHO/FIGO แนะนำเป็นการรักษามาตรฐาน. (MAGPIE = MgSO4 ใน preeclampsia; ARRIVE = induction 39 wk; Term Breech Trial = ผ่าคลอดท่าก้น)."}, {"topic": "Gynecologic Oncology", "q": "Which trial supports the use of magnesium sulfate to prevent eclampsia in preeclampsia?", "choices": ["Aspirin in GDM", "MAGPIE trial", "Insulin in GDM", "WOMAN trial", "Steroid in preterm"], "ans": 1, "exp": "MAGPIE trial แสดงว่า magnesium sulfate ลดความเสี่ยง eclamptic seizure ในหญิง preeclampsia อย่างมีนัยสำคัญ → หลักฐานสนับสนุน MgSO4 เป็นยาป้องกัน/รักษาชักมาตรฐาน (เหนือกว่า diazepam/phenytoin)."}, {"topic": "Gynecologic Oncology", "q": "A woman has biopsy-confirmed CIN 1 (low-grade). What is the appropriate management for most patients?", "choices": ["Immediate LEEP", "Radiation", "Observation (surveillance)", "Hysterectomy", "Chemotherapy"], "ans": 2, "exp": "CIN 1 ส่วนใหญ่ (~60%) regress เองใน 1-2 ปี (สะท้อนการติดเชื้อ HPV ชั่วคราว) → ติดตาม (surveillance ด้วย co-testing). รักษา (excision/ablation) ถ้า CIN 1 คงอยู่นาน (≥2 ปี) หรือมี high-grade cytology นำมาก่อน. ต่างจาก CIN 2/3."}, {"topic": "Gynecologic Oncology", "q": "Using the one-step 75 g OGTT, how many abnormal values are needed to diagnose gestational diabetes?", "choices": ["One value at 200", "Two abnormal values", "All three values", "One abnormal value", "This test is not used"], "ans": 3, "exp": "One-step 75 g OGTT (IADPSG/WHO): วินิจฉัย GDM เมื่อผิดปกติเพียง ≥1 ค่า — FBS ≥92, 1hr ≥180, 2hr ≥153. ให้อัตราวินิจฉัยสูงกว่า two-step (100 g ต้อง ≥2 ค่า). เป็นประเด็นที่ ACOG ทบทวน."}, {"topic": "Gynecologic Oncology", "q": "A Brenner tumor of the ovary is usually of which nature?", "choices": ["Always malignant", "A germ cell tumor", "Androgen-secreting", "A metastasis", "Mostly benign"], "ans": 4, "exp": "Brenner tumor เป็น surface epithelial-stromal tumor ที่มี transitional-type epithelium ('coffee-bean' nuclei) — ส่วนใหญ่ benign, มักพบโดยบังเอิญ, solid, เล็ก. Borderline/malignant Brenner พบน้อย."}, {"topic": "Gynecologic Oncology", "q": "What is a recognized complication of radical hysterectomy for cervical cancer?", "choices": ["Bladder dysfunction and ureteral injury", "No complications occur", "Sensorineural deafness", "Sudden blindness", "Diffuse hair loss"], "ans": 0, "exp": "Radical hysterectomy (มดลูก + parametrium + upper vagina + pelvic node) มีภาวะแทรกซ้อน: bladder dysfunction (จากการเลาะ autonomic nerve), ureteral injury/fistula, lymphedema/lymphocyst, เลือดออก. Nerve-sparing ลดภาวะกระเพาะปัสสาวะ."}, {"topic": "Gynecologic Oncology", "q": "What is the advantage of sentinel lymph node biopsy in gynecologic cancers?", "choices": ["It has no real benefit", "Reduces full node dissection and lymphedema", "It increases metastasis", "It replaces surgery entirely", "It replaces chemotherapy"], "ans": 1, "exp": "Sentinel lymph node mapping (dye/tracer หา node แรก) ใช้ในมะเร็งเยื่อบุมดลูก, ปากมดลูกระยะต้น, vulva — ประเมิน node status แม่นยำโดยไม่ต้องเลาะทั้งหมด จึงลด lymphedema. SLN บวก → full lymphadenectomy/adjuvant."}, {"topic": "Gynecologic Oncology", "q": "How is an immature teratoma of the ovary (malignant germ cell) treated?", "choices": ["Observation only", "Radiotherapy alone", "Surgery (fertility-sparing) plus chemotherapy", "Hormone therapy alone", "A course of antibiotics"], "ans": 2, "exp": "Immature teratoma เป็น malignant germ cell tumor. รักษาด้วยผ่าตัด — มัก fertility-sparing (unilateral salpingo-oophorectomy + staging) เพราะพบในหญิงสาวและมัก unilateral — ตามด้วย BEP chemotherapy ในรายที่ grade สูง/ระยะลุกลาม. พยากรณ์ดี."}, {"topic": "Gynecologic Oncology", "q": "An MMR-deficient endometrial cancer prompts which additional consideration?", "choices": ["No further action needed", "Hormone therapy", "Prophylactic radiotherapy", "Genetic counseling for Lynch syndrome", "Prophylactic mastectomy"], "ans": 3, "exp": "Endometrial cancer ที่ MMR-deficient (โดยเฉพาะไม่ได้เกิดจาก MLH1 methylation) ควรประเมิน Lynch syndrome (genetic counseling/germline testing) — endometrial มักเป็น sentinel cancer ของ Lynch. [อัปเดต] MMRd/MSI-high ยังทำนายการตอบสนองต่อ immunotherapy."}, {"topic": "Gynecologic Oncology", "q": "Which new therapy is effective in MMR-deficient/MSI-high endometrial cancer?", "choices": ["Hormone therapy", "Aspirin therapy", "A course of antibiotics", "A bisphosphonate", "An immune checkpoint inhibitor"], "ans": 4, "exp": "[อัปเดต] เนื้องอก MMR-deficient/MSI-high (รวม endometrial cancer จำนวนมาก) มี tumor mutational burden สูงและตอบสนองต่อ immune checkpoint inhibitor (anti-PD-1 เช่น pembrolizumab/dostarlimab) — ทางเลือกในระยะลุกลาม/กลับเป็นซ้ำ. การตรวจ MMR/MSI สำคัญทั้ง Lynch และเลือก immunotherapy."}, {"topic": "Gynecologic Oncology", "q": "According to Thai (RTCOG) guidance, at what age should cervical cancer screening begin?", "choices": ["Age 25", "Age 18", "Age 35", "Age 30", "Age 40"], "ans": 0, "exp": "[อัปเดต] RTCOG/ไทย แนะนำเริ่มคัดกรองมะเร็งปากมดลูกที่อายุ 25 ปี (สอดคล้องแนวโน้มสากลที่เลื่อนจาก 21 เป็น 25). วิธี: cytology ทุก 2 ปี หรือ HPV/co-testing ทุก 5 ปี (≥30 ปีเน้น HPV)."}, {"topic": "Gynecologic Oncology", "q": "A woman is HPV-positive (non-16/18) with normal cytology. What is the appropriate management?", "choices": ["Immediate colposcopy", "Repeat co-testing in 1 year", "LEEP", "Hysterectomy", "No follow-up"], "ans": 1, "exp": "HPV positive (non-16/18) + cytology ปกติ → ความเสี่ยงทันทีต่ำ, repeat testing ใน ~1 ปี (surveillance). HPV 16/18 positive → colposcopy แม้ cytology ปกติ. cytology ผิดปกติร่วม → colposcopy. จัดการแบบ risk-based (ASCCP)."}, {"topic": "Gynecologic Oncology", "q": "Cervical cancer screening can generally be stopped after age 65 under which condition?", "choices": ["Screening should never stop", "Only after a hysterectomy", "Adequate prior negative screening with no CIN history", "Only if never sexually active", "Only after menopause"], "ans": 2, "exp": "หยุดคัดกรองเมื่ออายุ >65 ปี ในผู้ที่มีผลก่อนหน้าปกติเพียงพอและไม่มีประวัติ CIN2+ ใน 25 ปี. ผู้ตัดมดลูก (รวมปากมดลูก) จาก benign และไม่มีประวัติ high-grade ก็ไม่ต้องคัดกรองต่อ. ผู้ไม่เคยคัดกรอง/ประวัติผิดปกติยังต้องตรวจ."}, {"topic": "Gynecologic Oncology", "q": "A woman with stage IA1 cervical cancer who desires fertility is best managed with which option?", "choices": ["Radical hysterectomy always", "No treatment", "Chemotherapy", "Cone biopsy with negative margins", "Radiotherapy"], "ans": 3, "exp": "มะเร็งปากมดลูกระยะ IA1 (invasion <3 mm, ไม่มี LVSI) ในผู้ต้องการมีบุตร รักษาแบบ fertility-sparing ด้วย cervical conization (cone biopsy) ถ้า margin ปลอดภัย. ระยะสูงขึ้น (IA2-IB1) อาจใช้ radical trachelectomy + node. ไม่ต้องการมีบุตร: simple/radical hysterectomy."}, {"topic": "Gynecologic Oncology", "q": "A postmenopausal woman with bleeding and endometrial carcinoma on biopsy needs which next step?", "choices": ["Observation without treatment", "Hormone therapy alone", "A course of antibiotics", "Serum CA-125 alone", "Staging and surgical planning by a specialist"], "ans": 4, "exp": "เมื่อยืนยัน endometrial carcinoma → ประเมินการแพร่กระจาย (imaging ตามข้อบ่งชี้) และวางแผนผ่าตัด staging: hysterectomy + BSO + surgical staging (± node/sentinel) โดยผู้เชี่ยวชาญ. adjuvant ตามระยะ/grade/molecular. ส่งต่อ gyn-oncologist ในรายเสี่ยงสูง."}, {"topic": "Gynecologic Oncology", "q": "What characterizes type II endometrial cancer (serous/clear cell)?", "choices": ["Non-estrogen-dependent, worse prognosis", "Estrogen-dependent, good prognosis", "Associated with HPV", "Occurs in adolescents", "Is benign"], "ans": 0, "exp": "Type II (serous, clear cell, carcinosarcoma) — ไม่ขึ้นกับ estrogen, พบในผู้สูงอายุ/ผอมกว่า, มัก high-grade, p53-abnormal, พยากรณ์แย่กว่า type I, แพร่กระจายเร็ว (คล้ายมะเร็งรังไข่ serous). ต้องการการรักษาเข้มข้นกว่า (staging เต็ม + chemo)."}, {"topic": "Gynecologic Oncology", "q": "In a molar pregnancy, what causes large bilateral theca lutein cysts?", "choices": ["A concurrent pelvic infection", "Stimulation by very high hCG", "Coexisting ovarian cancer", "Underlying endometriosis", "An unrecognized twin gestation"], "ans": 1, "exp": "Theca lutein cysts (มัก bilateral, multicystic) เกิดจากการกระตุ้นรังไข่ด้วย hCG ที่สูงมากใน molar (หรือ multiple gestation, OHSS). มักหายเองหลัง hCG ลดลง — conservative (ไม่ต้องผ่าตัดยกเว้นแตก/torsion)."}, {"topic": "Gynecologic Oncology", "q": "A 55-year-old has a solid ovarian mass with CA-125 of 500 and ascites. What preoperative step is appropriate?", "choices": ["No assessment", "Immediate chemotherapy without diagnosis", "Imaging and referral to gyn-oncologist", "Drain ascites only", "Hormone therapy"], "ans": 2, "exp": "ก้อนรังไข่สงสัยมะเร็งในวัยหมดประจำเดือน (solid, CA-125 สูง, ascites) — ประเมินก่อนผ่าตัดด้วย imaging (CT/MRI ประเมิน extent, แยก primary GI) และส่ง gyn-oncologist เพื่อวางแผน cytoreduction + staging หรือ neoadjuvant chemo. การผ่าตัดโดยผู้เชี่ยวชาญเพิ่ม survival."}, {"topic": "Gynecologic Oncology", "q": "How should ovarian cancer screening be approached in average-risk women?", "choices": ["Yearly CA-125 and ultrasound", "Yearly Pap smear", "Yearly MRI", "Screening is not recommended", "Prophylactic surgery"], "ans": 3, "exp": "ไม่แนะนำคัดกรองมะเร็งรังไข่ในหญิงความเสี่ยงปกติ (CA-125/TVS ไม่ลด mortality และ false positive สูง → ผ่าตัดโดยไม่จำเป็น). ผู้เสี่ยงสูง (BRCA/Lynch) พิจารณา RRSO มากกว่าคัดกรอง. ต่างจากมะเร็งปากมดลูก/เต้านมที่มีการคัดกรองที่ได้ผล."}, {"topic": "Gynecologic Oncology", "q": "How is low-risk GTN (WHO score below 7) treated?", "choices": ["Multi-agent EMA-CO chemotherapy", "Pelvic radiotherapy", "Hysterectomy alone", "Hormone therapy", "Single-agent methotrexate or actinomycin D"], "ans": 4, "exp": "Low-risk GTN (FIGO/WHO score ≤6): single-agent chemotherapy — methotrexate (± folinic acid) หรือ actinomycin D — อัตราหายเกือบ 100%. High-risk (≥7) ใช้ multi-agent (EMA-CO). ติดตาม β-hCG จนเป็นลบและคุมกำเนิด ~1 ปี."}, {"topic": "Gynecologic Oncology", "q": "What does the WHO '90-70-90' strategy for cervical cancer elimination represent?", "choices": ["Vaccinate 90%, screen 70%, treat 90%", "Three stages of cervical cancer", "Expected survival rates", "The number of vaccine doses", "Vaccine drug pricing tiers"], "ans": 0, "exp": "WHO 90-70-90 (ภายในปี 2030): เด็กหญิงได้วัคซีน HPV ครบก่อน 15 ปี 90%, ผู้หญิงได้รับการคัดกรองด้วยวิธีประสิทธิภาพสูง (HPV test) ที่ 35 และ 45 ปี 70%, และผู้พบความผิดปกติ/มะเร็งได้รับการรักษา 90%."}, {"topic": "Gynecologic Oncology", "q": "A pregnant woman is found to have advanced cervical cancer in the first trimester. What must guide management?", "choices": ["Normal vaginal delivery in all cases", "Multidisciplinary care weighing maternal vs fetal needs", "Wait until term in every case", "Immediate chemotherapy for all", "No treatment at all"], "ans": 1, "exp": "มะเร็งปากมดลูกในครรภ์ซับซ้อน ต้องดูแลโดยทีมสหสาขา (gyn-onc, MFM, neonatology) และให้คำปรึกษาผู้ป่วย. ตัดสินใจตามระยะโรค/อายุครรภ์/ความต้องการ — อาจต้องเลือกระหว่างรักษาทันที (อาจยุติการตั้งครรภ์) หรือเลื่อนเพื่อให้ทารกโตพอ."}, {"topic": "Gynecologic Oncology", "q": "A woman with a granulosa cell tumor producing estrogen needs which additional evaluation?", "choices": ["No further evaluation needed", "Routine cervical screening", "Endometrial assessment for hyperplasia", "HPV testing", "A pregnancy test"], "ans": 2, "exp": "Granulosa cell tumor สร้าง estrogen → unopposed estrogen เสี่ยง endometrial hyperplasia/มะเร็งร่วม (~5-25%). เมื่อวินิจฉัย (โดยเฉพาะมี abnormal bleeding) ต้องประเมิน endometrium (biopsy). Marker: inhibin/AMH. โตช้าและกลับเป็นซ้ำได้."}, {"topic": "Gynecologic Oncology", "q": "Vaginal clear cell adenocarcinoma is associated with which factor?", "choices": ["HPV", "Smoking", "BRCA mutation", "In-utero DES exposure", "Oral contraceptives"], "ans": 3, "exp": "Vaginal clear cell adenocarcinoma สัมพันธ์กับ in utero DES exposure (มารดาได้ DES ขณะตั้งครรภ์). พบในหญิงสาว. มะเร็งช่องคลอด SCC (พบบ่อยกว่า) สัมพันธ์ HPV. DES เลิกใช้แล้วแต่เป็นความรู้คลาสสิก."}, {"topic": "Gynecologic Oncology", "q": "Which symptoms should raise suspicion for ovarian cancer, even though nonspecific?", "choices": ["A persistent headache", "A widespread skin rash", "Pleuritic chest pain", "Diffuse joint pain", "Bloating and early satiety"], "ans": 4, "exp": "อาการมะเร็งรังไข่มักคลุมเครือ ('silent'): ท้องอืด/ท้องโต, แน่นท้อง/อิ่มเร็ว (early satiety), ปวดท้องน้อย, ปัสสาวะบ่อย/รีบ ที่เป็นเรื้อรังและใหม่ในหญิง >50 ปี ควรประเมิน (US + CA-125). Ascites/ก้อนบ่งชี้ระยะลุกลาม."}, {"topic": "Gynecologic Oncology", "q": "In FIGO 2023 endometrial molecular classification, which subtype has the best prognosis?", "choices": ["POLE-mutated", "p53-abnormal", "MMR-deficient", "NSMP", "All are equal"], "ans": 0, "exp": "[อัปเดต FIGO 2023] Molecular 4 กลุ่ม: POLEmut = พยากรณ์ดีสุด (แม้ grade สูง, อาจ de-escalate การรักษา); MMRd/NSMP = ปานกลาง; p53abn = แย่สุด (มัก serous, รักษาเข้มข้น). ช่วยวางแผนการรักษาแม่นยำขึ้น."}, {"topic": "Gynecologic Oncology", "q": "A 32-year-old with early grade 1 endometrial cancer wants to preserve fertility. What is an option?", "choices": ["Hysterectomy alone", "High-dose progestin with close monitoring", "Systemic chemotherapy", "Pelvic radiotherapy", "No treatment option exists"], "ans": 1, "exp": "หญิงสาว endometrial cancer ระยะต้น (grade 1, endometrioid, ไม่มี myometrial invasion/แพร่กระจาย) ที่ต้องการ fertility อาจ fertility-sparing ด้วย high-dose progestin (megestrol/medroxyprogesterone หรือ LNG-IUS) + endometrial sampling ทุก 3-6 เดือน. มีบุตรครบ → hysterectomy. คัดเลือกผู้ป่วยเข้มงวด."}, {"topic": "Gynecologic Oncology", "q": "A suspicious ovarian mass (solid, papillary, ascites) is best managed by which approach?", "choices": ["Simple cyst aspiration", "Routine follow-up in one year", "Refer to a gyn-oncologist for staging", "A course of antibiotics", "Hormone therapy"], "ans": 2, "exp": "ก้อนรังไข่สงสัยมะเร็งควรส่ง gyn-oncologist เพื่อ surgical staging/cytoreduction (เพิ่ม survival). ไม่ควรเจาะดูด/ผ่าก้อนแบบไม่วางแผน (เสี่ยง spillage → upstage). ประเมินก่อนผ่าด้วย imaging + tumor markers (CA-125 ± HE4/ROMA, germ cell markers ตามอายุ)."}, {"topic": "Gynecologic Oncology", "q": "A large mucinous ovarian tumor ruptures, leaving gelatinous mucin in the abdomen. What is this called?", "choices": ["Meigs syndrome", "Krukenberg tumor", "Simple ascites", "Pseudomyxoma peritonei", "Endometriosis"], "ans": 3, "exp": "Pseudomyxoma peritonei = การสะสม mucinous material ('jelly belly') ในช่องท้อง — ปัจจุบันเชื่อว่าส่วนใหญ่มาจาก appendiceal mucinous neoplasm มากกว่ารังไข่. รักษาด้วย cytoreductive surgery + HIPEC. โตช้าแต่กลับเป็นซ้ำ."}, {"topic": "Gynecologic Oncology", "q": "How is high-grade or serous endometrial cancer managed compared with type I?", "choices": ["Managed identically to type I", "Observation without treatment", "Hormone therapy alone", "No surgery at all", "Full staging plus chemotherapy"], "ans": 4, "exp": "Type II (serous/clear cell/carcinosarcoma, p53abn) แพร่กระจายเร็วคล้ายมะเร็งรังไข่ — ต้อง comprehensive staging (hysterectomy + BSO + node + omentectomy + washing) และมัก adjuvant chemotherapy (± RT) แม้ระยะดูต้น. ต่างจาก type I grade ต่ำ. FIGO 2023 molecular guiding treatment."}, {"topic": "Gynecologic Oncology", "q": "What is the aim of the WHO 2016 antenatal care model?", "choices": ["Improve ANC to reduce perinatal death", "To reduce healthcare cost", "To reduce the number of visits", "To abolish antenatal care", "Only for high-risk women"], "ans": 0, "exp": "[อัปเดต] WHO 2016 ANC เพิ่มเป็น ≥8 contacts (จาก 4) โดยเน้นทั้งการดูแลทางการแพทย์และ positive pregnancy experience → ลด perinatal mortality และเพิ่มการเข้าถึง. ไทยปรับใช้แนวทางฝากครรภ์คุณภาพตามหลักนี้."}, {"topic": "Gynecologic Oncology", "q": "A borderline ovarian tumor (low malignant potential) has which characteristic?", "choices": ["Rapid spread with poor prognosis", "Atypia without stromal invasion, good prognosis", "A distant metastatic deposit", "A completely benign lesion", "A malignant germ cell tumor"], "ans": 1, "exp": "Borderline ovarian tumor: มี epithelial atypia แต่ 'ไม่มี stromal invasion' (destructive). พบในหญิงอายุน้อยกว่า, มักระยะต้น, พยากรณ์ดีมาก. รักษาด้วยผ่าตัด (fertility-sparing ระยะต้น); โดยทั่วไปไม่ต้องเคมี. ติดตามระยะยาว."}, {"topic": "Gynecologic Oncology", "q": "A woman previously treated for GTN is now pregnant again. What follow-up is appropriate?", "choices": ["No special care", "Terminate the pregnancy", "Early ultrasound and postpartum hCG", "Prophylactic chemotherapy", "Cesarean for all"], "ans": 2, "exp": "ผู้เคยเป็น GTN/molar เสี่ยง molar/GTN ซ้ำเพิ่ม — ครรภ์ถัดไปควรทำ early US (ไตรมาสแรก) ยืนยันครรภ์ปกติ, ตรวจ placental pathology, และตรวจ β-hCG ~6 สัปดาห์หลังสิ้นสุดครรภ์เพื่อเฝ้าระวังการกลับเป็นซ้ำ."}, {"topic": "Gynecologic Oncology", "q": "Vaginal intraepithelial neoplasia (VAIN) is related to which factor and managed how?", "choices": ["Not HPV-related; always surgery", "Hormonal; treat with estrogen", "Bacterial; treat with antibiotics", "HPV-related; laser/topical/excision with follow-up", "It is never treated"], "ans": 3, "exp": "VAIN เป็น precancer ของช่องคลอด สัมพันธ์ HPV (คล้าย CIN/VIN), มักพบร่วม/หลัง cervical neoplasia. รักษาตามระดับ: observation (low-grade), laser/topical (5-FU, imiquimod)/excision (high-grade). ติดตามเพราะเสี่ยง vaginal cancer. ตัดมดลูกแล้วยังเฝ้าระวัง vaginal cuff."}, {"topic": "Gynecologic Oncology", "q": "Advanced ovarian cancer not amenable to optimal primary debulking is best managed with which approach?", "choices": ["No treatment at all", "Observation without treatment", "Radiotherapy alone", "Hormone therapy", "Neoadjuvant chemo, interval debulking"], "ans": 4, "exp": "เมื่อผ่าตัด optimal cytoreduction ตั้งแต่แรกไม่ได้ (หรือผู้ป่วยไม่พร้อม) → neoadjuvant chemotherapy (carboplatin+paclitaxel 3 cycles) ลดขนาดก้อน แล้ว interval debulking surgery + เคมีต่อ. ผลเทียบเท่า primary debulking ในกลุ่มเหมาะสม, ลด surgical morbidity. ยืนยันวินิจฉัยด้วย biopsy ก่อน."}, {"topic": "Gynecologic Oncology", "q": "When transvaginal ultrasound is inconclusive in postmenopausal bleeding, which test best clarifies the diagnosis?", "choices": ["Hysteroscopy with biopsy", "CA-125", "MRI for all", "Pap smear", "Urinalysis"], "ans": 0, "exp": "เมื่อ TVS ไม่ชัด/endometrium ประเมินยาก หรือ office biopsy ไม่พอ/เลือดออกซ้ำ → hysteroscopy + biopsy/D&C ช่วยวินิจฉัยรอยโรคเฉพาะที่ (polyp, focal lesion, มะเร็ง) ได้ดีกว่า blind sampling. Postmenopausal bleeding ต้องได้ข้อวินิจฉัยทางเนื้อเยื่อ."}, {"topic": "Gynecologic Oncology", "q": "How is stage IB2 cervical cancer (tumor 2-4 cm) treated?", "choices": ["Conization alone", "Radical surgery or chemoradiation", "Observation without treatment", "Hormone therapy", "A course of antibiotics"], "ans": 1, "exp": "มะเร็งปากมดลูกระยะต้น (IB1-IB2, IIA1) รักษาด้วย radical hysterectomy + pelvic lymphadenectomy หรือ definitive chemoradiation — ผลเทียบเท่ากัน. ระยะก้อนใหญ่ (IB3 ≥4 cm) หรือลุกลามกว่านิยม chemoradiation เพื่อเลี่ยงการรักษาซ้ำซ้อน."}, {"topic": "Gynecologic Oncology", "q": "According to the LACC trial, minimally invasive radical hysterectomy for early cervical cancer showed what?", "choices": ["Better than open surgery", "Surgery is contraindicated", "Worse survival than open surgery", "No difference", "Not relevant"], "ans": 2, "exp": "[อัปเดต LACC trial] minimally invasive radical hysterectomy ให้ disease-free/overall survival 'แย่กว่า' open (abdominal) radical hysterectomy ในมะเร็งปากมดลูกระยะต้น → แนวทางปัจจุบันแนะนำ open approach เป็นมาตรฐาน. เป็นการเปลี่ยน practice สำคัญ."}, {"topic": "Gynecologic Oncology", "q": "A young woman with a suspected germ cell ovarian tumor should have which tumor markers checked?", "choices": ["Serum CA-125 alone", "Serum CEA", "Serum PSA", "AFP, beta-hCG, and LDH", "Serum CA 19-9"], "ans": 3, "exp": "หญิงสาวที่สงสัย germ cell tumor: AFP (yolk sac, embryonal), β-hCG (choriocarcinoma, dysgerminoma บางส่วน), LDH (dysgerminoma). อาจเพิ่ม inhibin/AMH (sex cord-stromal). CA-125 เหมาะ epithelial (สูงอายุ). เลือก marker ตามอายุ/ลักษณะก้อน."}, {"topic": "Gynecologic Oncology", "q": "Endometrioid ovarian carcinoma is most associated with which condition?", "choices": ["HPV", "Thalassemia", "GDM", "Smoking", "Endometriosis"], "ans": 4, "exp": "Endometrioid (และ clear cell) ovarian carcinoma สัมพันธ์กับ endometriosis (malignant transformation). Endometrioid ยังพบร่วม synchronous endometrial cancer ได้ (~15-20%) — ควรประเมิน endometrium. สะท้อนความเชื่อมโยง endometriosis กับมะเร็งบางชนิด."}, {"topic": "Gynecologic Oncology", "q": "Magnesium sulfate for fetal neuroprotection is recommended when delivery is anticipated before which gestational age?", "choices": ["32 weeks", "37 weeks", "34 weeks", "28 weeks", "24 weeks"], "ans": 0, "exp": "[อัปเดต] MgSO4 เพื่อ fetal neuroprotection (ลด cerebral palsy) เมื่อคาดว่าจะคลอดก่อน GA 32 wk — คนละบทบาทกับ MgSO4 ใน preeclampsia (ป้องกันชัก ทุกอายุครรภ์ที่ severe). ร่วมกับ steroid และ GBS prophylaxis/tocolytic."}, {"topic": "Gynecologic Oncology", "q": "A 54-year-old with bothersome hot flashes and no contraindications is best treated with which option (NAMS 2022)?", "choices": ["No treatment", "Systemic hormone therapy", "Antibiotics", "Bisphosphonate alone", "Surgery"], "ans": 1, "exp": "[อัปเดต NAMS 2022] หญิงอายุ 54 ปี (<60, <10 ปีหลังหมดประจำเดือน) ที่มี bothersome VMS และไม่มีข้อห้าม → systemic hormone therapy ได้ผลดีสุด, benefit-risk ดี (มีมดลูกใช้ estrogen+progestogen). ทางเลือก non-hormonal (SSRI/SNRI, gabapentin, fezolinetant) สำหรับผู้มีข้อห้าม."}, {"topic": "Gynecologic Oncology", "q": "How is stage IVB cervical cancer (distant metastasis) treated?", "choices": ["Radical surgical resection", "Hormone therapy", "Systemic therapy with palliative intent", "Observation only", "Conization alone"], "ans": 2, "exp": "มะเร็งปากมดลูกระยะ IVB (แพร่กระจายไกล) รักษาด้วย systemic therapy: platinum chemo + bevacizumab และ [อัปเดต] immunotherapy (pembrolizumab สำหรับ PD-L1 positive) — palliative เพื่อยืดชีวิต/คุมอาการ. RT ประคับประคอง (เลือดออก/ปวด). พยากรณ์ไม่ดี."}, {"topic": "Gynecologic Oncology", "q": "GTN with lung metastasis has which prognosis and treatment?", "choices": ["Very poor and untreatable", "Radiotherapy alone", "Requires lung resection", "Still very chemosensitive with good prognosis", "Hormone therapy"], "ans": 3, "exp": "GTN (โดยเฉพาะ choriocarcinoma) แม้แพร่กระจาย (ปอดพบบ่อยสุด) ยังตอบสนองเคมีบำบัดดีมากและรักษาหายได้สูง. ใช้ FIGO/WHO risk score แบ่ง low-risk (single-agent) vs high-risk (EMA-CO). ติดตามด้วย β-hCG. ตัวอย่างมะเร็งแพร่กระจายที่พยากรณ์ดี."}, {"topic": "Gynecologic Oncology", "q": "A woman on tamoxifen for breast cancer should be monitored for which gynecologic cancer?", "choices": ["Cervical cancer", "Ovarian cancer", "Vaginal cancer", "No increased risk", "Endometrial cancer"], "ans": 4, "exp": "Tamoxifen (SERM) ต้าน estrogen ที่เต้านมแต่ 'กระตุ้น' estrogen ที่ endometrium → เพิ่มความเสี่ยง endometrial hyperplasia/polyp/มะเร็ง. ผู้ใช้ tamoxifen ที่มี abnormal bleeding ต้องประเมิน endometrium. ไม่แนะนำ routine screening ในผู้ไม่มีอาการ แต่ให้ความรู้เรื่องสัญญาณเตือน."}, {"topic": "Gynecologic Oncology", "q": "What is the principle of 'synthetic lethality' underlying PARP inhibitors in BRCA-mutated ovarian cancer?", "choices": ["BRCA-mutant cells die when PARP is also inhibited", "It kills all cells indiscriminately", "It enhances DNA repair", "It stimulates the immune system", "It blocks hormone receptors"], "ans": 0, "exp": "Synthetic lethality: เซลล์มะเร็ง BRCA-mutant ซ่อม double-strand break (homologous recombination) ไม่ได้ — เมื่อให้ PARP inhibitor (ยับยั้งการซ่อม single-strand break) เซลล์สะสมความเสียหาย DNA จนตาย ขณะที่เซลล์ปกติ (BRCA wild-type) รอด. จำเพาะต่อเซลล์มะเร็ง BRCA/HRD."}, {"topic": "Gynecologic Oncology", "q": "After fertility-sparing treatment (conization for stage IA1 cervical cancer), what follow-up is needed?", "choices": ["No follow-up needed", "Cytology/HPV and colposcopy periodically", "Adjuvant radiotherapy", "Immediate hysterectomy", "Preventive chemotherapy"], "ans": 1, "exp": "หลัง fertility-sparing (conization IA1, margin negative) ต้องติดตามใกล้ชิดด้วย co-testing (cytology + HPV) และ colposcopy เป็นระยะ เพื่อจับการกลับเป็นซ้ำ/persistent disease. มีบุตรครบ/พบผิดปกติ → definitive treatment. ให้คำปรึกษาความเสี่ยง preterm จาก conization."}, {"topic": "Gynecologic Oncology", "q": "Which finding indicates cervical cancer has extended to the pelvic sidewall (stage IIIB)?", "choices": ["A small confined cervical lesion", "A watery vaginal discharge", "Hydronephrosis from ureteral obstruction", "Minor intermenstrual spotting", "Menstrual cramping pain"], "ans": 2, "exp": "มะเร็งปากมดลูก stage III: IIIA (1/3 ล่างช่องคลอด), IIIB (pelvic sidewall และ/หรือ hydronephrosis/non-functioning kidney จากกด ureter), IIIC (node). Hydronephrosis จากการอุดกั้นเป็นเกณฑ์ stage IIIB. รักษาด้วย concurrent chemoradiation."}, {"topic": "Gynecologic Oncology", "q": "A woman with ovarian cancer stage IA, grade 1, who desires fertility is best managed with which option?", "choices": ["Hysterectomy and BSO in all", "No treatment at all", "Chemotherapy alone", "Fertility-sparing surgery with staging", "Radiotherapy alone"], "ans": 3, "exp": "มะเร็งรังไข่ระยะ IA, grade ต่ำ (โดยเฉพาะ germ cell, sex cord-stromal, low-grade epithelial/borderline) ที่ต้องการมีบุตร อาจ fertility-sparing: unilateral salpingo-oophorectomy + comprehensive staging (เก็บมดลูก/รังไข่อีกข้าง). คัดเลือกผู้ป่วย/ให้คำปรึกษา. ระยะสูง/grade สูงต้องผ่าตัดครบ + เคมี."}, {"topic": "Gynecologic Oncology", "q": "A woman not desiring fertility has atypical endometrial hyperplasia (EIN). What is recommended?", "choices": ["No treatment", "Chemotherapy", "Radiation", "Antibiotics", "Total hysterectomy"], "ans": 4, "exp": "Atypical hyperplasia/EIN เสี่ยงมะเร็งร่วม/ลุกลามสูง (~40%) → ผู้ไม่ต้องการเก็บมดลูก แนะนำ total hysterectomy. ต้องการเก็บมดลูก/มีบุตร → high-dose progestin (LNG-IUS/oral) + ติดตามชิ้นเนื้อ. ให้คำปรึกษาความเสี่ยงชัดเจน."}, {"topic": "Gynecologic Oncology", "q": "A 40-year-old pregnant woman wants aneuploidy screening with the highest detection rate. What is recommended?", "choices": ["Cell-free fetal DNA (NIPT)", "Quadruple test", "AFP alone", "Ultrasound alone", "No screening"], "ans": 0, "exp": "NIPT (cfDNA) มี detection rate สูงสุดสำหรับ trisomy 21 (>99%) และ 18/13 ในกลุ่มเสี่ยงสูง (อายุมาก) — screening ที่ดีที่สุด. ผลบวกต้องยืนยันด้วย diagnostic (amniocentesis/CVS). อายุ ≥35-40 ปีอาจพิจารณา diagnostic โดยตรง."}, {"topic": "Gynecologic Oncology", "q": "What is the primary prevention level represented by low-dose aspirin for preeclampsia and the WHO 90-70-90 vaccination component?", "choices": ["Tertiary prevention", "Primary prevention", "Not prevention", "End-stage treatment", "Diagnosis"], "ans": 1, "exp": "Aspirin ป้องกัน preeclampsia = primary prevention (ให้กลุ่มเสี่ยงก่อนเกิดโรค). WHO 90-70-90 วัคซีน = primary prevention มะเร็งปากมดลูก; คัดกรอง+รักษา precancer = secondary. แนวคิดการป้องกันเชิงรุกเป็นหัวใจของเวชศาสตร์ป้องกันทางสูติ-นรีเวช."}, {"topic": "Gynecologic Oncology", "q": "A GBS-colonized woman should receive prophylaxis to prevent which neonatal condition?", "choices": ["Congenital rubella syndrome", "A neural tube defect", "Early-onset neonatal GBS sepsis", "Neonatal hyperbilirubinemia", "Fetal macrosomia"], "ans": 2, "exp": "[อัปเดต] คัดกรอง GBS (36-37+6 wk) และให้ intrapartum penicillin prophylaxis ในผู้ positive เพื่อป้องกัน early-onset neonatal GBS disease (sepsis, pneumonia, meningitis ในสัปดาห์แรก) ซึ่งรุนแรง. ลด early-onset GBS ได้มาก."}, {"topic": "Gynecologic Oncology", "q": "A woman with a very high testosterone level and rapid virilization should be evaluated with which investigation?", "choices": ["No evaluation is needed", "A trial of combined pills", "Serum TSH alone", "Imaging of the ovaries and adrenals", "Diagnostic hysterectomy"], "ans": 3, "exp": "Testosterone สูงมาก (>150-200) + virilization เริ่มเร็ว บ่งชี้ androgen-secreting tumor → imaging: TVS/MRI รังไข่ (Sertoli-Leydig, hilus cell) และ CT/MRI ต่อมหมวกไต (DHEAS สูงมาก = ต่อมหมวกไต). ต่างจาก PCOS."}, {"topic": "Gynecologic Oncology", "q": "CA-125 elevation in a reproductive-age woman with an ovarian mass should be interpreted how?", "choices": ["It always indicates cancer", "It has no clinical meaning", "It reliably excludes cancer", "It is used for general screening", "May rise in benign conditions too"], "ans": 4, "exp": "CA-125 ในวัยเจริญพันธุ์แปลผลต้องระวัง — สูงได้ในภาวะ benign (endometriosis, PID, fibroid, ประจำเดือน, ตั้งครรภ์). จึงมีประโยชน์จำกัดในการแยกมะเร็งในกลุ่มนี้ — ใช้ร่วมกับลักษณะ US, อายุ, และเครื่องมือ (IOTA/RMI). จำเพาะขึ้นในวัยหมดประจำเดือน."}, {"topic": "Gynecologic Oncology", "q": "Why does primary HPV testing allow a longer (5-year) screening interval than cytology?", "choices": ["Higher sensitivity for high-grade precancer", "It is substantially cheaper", "It is usable at any age", "It is entirely painless", "No sample is required"], "ans": 0, "exp": "[อัปเดต] Primary HPV testing มี sensitivity สูงกว่า cytology ในการตรวจจับ high-grade precancer (CIN2+) และ negative predictive value สูง จึงยืดช่วงคัดกรองเป็นทุก 5 ปีได้อย่างปลอดภัย (เทียบ Pap ทุก 2-3 ปี). รองรับ self-collection เพิ่มการเข้าถึง."}, {"topic": "Gynecologic Oncology", "q": "A woman on postpartum GTN follow-up should use which measure during monitoring?", "choices": ["Attempt pregnancy soon", "Reliable contraception during follow-up", "Await natural conception", "Prophylactic chemotherapy", "No contraception needed"], "ans": 1, "exp": "ระหว่างติดตาม β-hCG ต้องคุมกำเนิด (หลีกเลี่ยงตั้งครรภ์) เพราะการตั้งครรภ์ใหม่ทำให้แปลผล hCG ไม่ได้ และแยก GTN ที่กลับเป็นซ้ำไม่ได้. คุมกำเนิด ~1 ปีหลัง hCG เป็นลบ (นิยม combined OC/LARC)."}, {"topic": "Gynecologic Oncology", "q": "A woman with a pelvic mass and ascites plus a very high CA-125 in menopause should be referred to whom?", "choices": ["General internist", "General surgeon", "Gynecologic oncologist", "Dermatologist", "No referral needed"], "ans": 2, "exp": "Pelvic/adnexal mass ที่น่าสงสัยมะเร็ง (solid, ascites, CA-125 สูงในวัยหมดประจำเดือน, RMI สูง) ควรส่ง gynecologic oncologist เพื่อวางแผน surgical staging/cytoreduction (การผ่าตัดโดยผู้เชี่ยวชาญเพิ่ม survival). อย่าเจาะ/ผ่าก้อนแบบไม่วางแผน."}, {"topic": "Gynecologic Oncology", "q": "Which histologic feature characterizes a Krukenberg tumor?", "choices": ["Call-Exner bodies", "Psammoma bodies", "Schiller-Duval bodies", "Signet-ring cells", "Coffee-bean nuclei"], "ans": 3, "exp": "Krukenberg tumor (metastasis to ovary จาก GI, มักกระเพาะอาหาร) มี mucin-producing 'signet-ring cells'. (Call-Exner bodies = granulosa cell; Schiller-Duval bodies = yolk sac; psammoma bodies = serous; coffee-bean nuclei = Brenner)."}, {"topic": "Gynecologic Oncology", "q": "A woman with endometrial cancer that is MMR-deficient due to MLH1 promoter methylation most likely has which situation?", "choices": ["Definite Lynch syndrome", "p53 abnormality", "BRCA mutation", "POLE mutation", "Sporadic (non-hereditary) tumor"], "ans": 4, "exp": "MMR-deficient จาก MLH1 promoter hypermethylation มักเป็น sporadic (ไม่ใช่ Lynch). MMRd ที่ไม่ได้เกิดจาก methylation จึงต้องประเมิน Lynch (germline testing). ทั้งสองกรณี MMRd/MSI-high ตอบสนอง immunotherapy (checkpoint inhibitor)."}]}, {"id": "surg1", "title": "Surgery ชุดที่ 1 — General & GI Surgery (Acute Abdomen, HPB, Bowel, Hernia, Anorectal, Pediatric GI)", "subject": "surg", "questions": [{"topic": "General/GI Surgery", "q": "A 22-year-old man presents with 18 hours of periumbilical pain that migrated to the right lower quadrant, with anorexia and low-grade fever. He has tenderness at McBurney point with guarding. What is the most likely diagnosis?", "choices": ["Acute appendicitis", "Mesenteric adenitis", "Acute cholecystitis", "Ureteric colic", "Meckel diverticulitis"], "ans": 0, "exp": "อาการคลาสสิกของ acute appendicitis: ปวดรอบสะดือย้ายมา RLQ, เบื่ออาหาร, ไข้ต่ำๆ, กดเจ็บที่ McBurney point + guarding. เกิดจากการอุดตันของ appendiceal lumen. การวินิจฉัยส่วนใหญ่เป็นทางคลินิก (± US/CT). รักษาด้วย appendectomy."}, {"topic": "General/GI Surgery", "q": "A 40-year-old obese woman has 6 hours of severe right upper quadrant pain radiating to the scapula after a fatty meal, with fever and a positive Murphy sign. Ultrasound shows gallstones and a thickened gallbladder wall. What is the diagnosis?", "choices": ["Biliary colic", "Acute cholecystitis", "Perforated ulcer", "Acute pancreatitis", "Ascending cholangitis"], "ans": 1, "exp": "Acute cholecystitis: ปวด RUQ ต่อเนื่อง >6 ชม. หลังอาหารมัน, ไข้, Murphy sign บวก, US พบ gallstone + ผนังถุงน้ำดีหนา/pericholecystic fluid. รักษา: ยาปฏิชีวนะ + early laparoscopic cholecystectomy. ต่างจาก biliary colic (ปวดเป็นพักๆ ไม่มีไข้/อักเสบ)."}, {"topic": "General/GI Surgery", "q": "A 55-year-old man with gallstones presents with right upper quadrant pain, high fever with rigors, and jaundice. What triad does this represent, and what is the diagnosis?", "choices": ["Cushing triad, raised ICP", "Beck triad, tamponade", "Charcot triad, ascending cholangitis", "Virchow triad, thrombosis", "Reynolds pentad, sepsis"], "ans": 2, "exp": "Charcot triad (ปวด RUQ + ไข้หนาวสั่น + ดีซ่าน) = ascending cholangitis จากการอุดตันและติดเชื้อของท่อน้ำดี. เพิ่ม hypotension + confusion = Reynolds pentad (suppurative cholangitis รุนแรง). รักษา: ยาปฏิชีวนะ + biliary drainage (ERCP)."}, {"topic": "General/GI Surgery", "q": "A 45-year-old man with a history of heavy alcohol use has severe epigastric pain radiating to the back with vomiting. Serum lipase is five times the upper limit of normal. What is the diagnosis?", "choices": ["Myocardial infarction", "Perforated peptic ulcer", "Acute cholecystitis", "Acute pancreatitis", "Ruptured aortic aneurysm"], "ans": 3, "exp": "Acute pancreatitis: ปวด epigastric ทะลุหลัง + อาเจียน + lipase/amylase สูง ≥3 เท่า. สาเหตุบ่อย: gallstone, alcohol. ประเมินความรุนแรง (Ranson/APACHE), รักษาประคับประคอง (IV fluid, งดอาหาร, ยาแก้ปวด). ระวัง necrotizing pancreatitis, pseudocyst."}, {"topic": "General/GI Surgery", "q": "A 68-year-old man has colicky abdominal pain, distension, vomiting, and no passage of flatus or stool. Abdominal X-ray shows dilated small bowel loops with air-fluid levels. What is the diagnosis?", "choices": ["Acute pancreatitis", "Large bowel obstruction", "Paralytic ileus", "Mesenteric ischemia", "Small bowel obstruction"], "ans": 4, "exp": "Small bowel obstruction: ปวดบิดเป็นพักๆ, ท้องอืด, อาเจียน (เร็ว/มาก), ไม่ผายลม/ถ่าย. X-ray: dilated small bowel + air-fluid levels, ไม่มีลมในลำไส้ใหญ่. สาเหตุบ่อยสุด: adhesion (เคยผ่าตัด), hernia. รักษา: NPO, NG tube, IV fluid; ผ่าตัดถ้า strangulation/ไม่ดีขึ้น."}, {"topic": "General/GI Surgery", "q": "A 60-year-old man presents with a painful, irreducible groin lump, vomiting, and signs of bowel obstruction. The lump is tender with overlying skin erythema. What is the diagnosis?", "choices": ["Incarcerated/strangulated hernia", "Reducible inguinal hernia", "Hydrocele", "Femoral lymphadenopathy", "Saphena varix"], "ans": 0, "exp": "Strangulated hernia: ก้อนที่ขาหนีบ ดันกลับไม่ได้ (irreducible), เจ็บ, ผิวแดง + อาการลำไส้อุดตัน/ขาดเลือด → ต้องผ่าตัดฉุกเฉิน (เสี่ยง bowel necrosis). Incarcerated = ดันกลับไม่ได้แต่ยังไม่ขาดเลือด. Reducible = ดันกลับได้."}, {"topic": "General/GI Surgery", "q": "A 3-month-old boy has a soft, reducible bulge in the inguinal canal that appears when he cries. The testis is normally descended. What is the most appropriate management?", "choices": ["Manual reduction and a truss", "Elective surgical repair (herniorrhaphy)", "Immediate emergency repair", "Observation until age 5", "Aspiration of the sac"], "ans": 1, "exp": "Pediatric indirect inguinal hernia (จาก patent processus vaginalis) — ไม่หายเอง เสี่ยง incarceration (สูงในทารก) → แนะนำ elective herniorrhaphy โดยเร็ว. ถ้า incarcerated ที่ reduce ได้ → ผ่าตัดกึ่งเร่งด่วน; reduce ไม่ได้ → ผ่าตัดฉุกเฉิน."}, {"topic": "General/GI Surgery", "q": "A 65-year-old man presents with hematemesis and melena. He takes NSAIDs daily. He is tachycardic with a blood pressure of 90/60 mmHg. What is the most appropriate initial management?", "choices": ["Immediate endoscopy first for this patient", "Barium meal study for this patient", "Resuscitate with IV fluids/blood, then endoscopy", "Oral antacids only", "Emergency laparotomy for this patient"], "ans": 2, "exp": "Upper GI bleeding (peptic ulcer จาก NSAID): จัดการเบื้องต้นคือ 'resuscitation' ก่อน — IV access 2 เส้น, สารน้ำ/เลือด, ประเมิน ABC, ให้ PPI. เมื่อ hemodynamic เสถียรจึงทำ endoscopy (วินิจฉัย + ห้ามเลือด). ไม่ทำ barium (รบกวน scope)."}, {"topic": "General/GI Surgery", "q": "A 50-year-old man has sudden severe epigastric pain and a rigid, board-like abdomen. Upright chest X-ray shows free air under the diaphragm. What is the diagnosis?", "choices": ["Acute pancreatitis", "Acute cholecystitis", "Small bowel obstruction", "Perforated peptic ulcer", "Ruptured spleen"], "ans": 3, "exp": "Perforated peptic ulcer: ปวด epigastric เฉียบพลันรุนแรง + peritonitis (board-like rigidity) + free air under diaphragm (pneumoperitoneum) จาก upright CXR. เป็น surgical emergency → resuscitation + IV antibiotic/PPI + ผ่าตัดซ่อม (omental patch)."}, {"topic": "General/GI Surgery", "q": "A 70-year-old man has a change in bowel habit, weight loss, and iron-deficiency anemia. Colonoscopy shows an obstructing mass in the sigmoid colon. What is the most likely diagnosis?", "choices": ["Diverticulitis", "Ulcerative colitis", "Ischemic colitis", "Colonic volvulus", "Colorectal carcinoma"], "ans": 4, "exp": "Colorectal carcinoma: การเปลี่ยนแปลงการขับถ่าย + น้ำหนักลด + iron-deficiency anemia (จากเลือดออกเรื้อรัง) ในผู้สูงอายุ. Left-sided (sigmoid) มัก obstruct/เปลี่ยน bowel habit; right-sided มัก anemia/ก้อน. วินิจฉัยด้วย colonoscopy + biopsy; staging CT. รักษา: ผ่าตัด ± chemo."}, {"topic": "General/GI Surgery", "q": "A 25-year-old man has bright red rectal bleeding on the toilet paper and severe pain during defecation. Examination shows a tear at the posterior midline of the anal canal. What is the diagnosis?", "choices": ["Anal fissure", "Rectal cancer", "Internal hemorrhoids", "Perianal abscess", "Anal fistula"], "ans": 0, "exp": "Anal fissure: แผลฉีกที่ anal canal (posterior midline บ่อยสุด) → เจ็บมากขณะถ่าย + เลือดแดงสด. สัมพันธ์ท้องผูก/อุจจาระแข็ง. รักษา: เพิ่มไฟเบอร์/น้ำ, sitz bath, topical GTN/CCB (คลาย internal sphincter); เรื้อรัง → lateral internal sphincterotomy."}, {"topic": "General/GI Surgery", "q": "A 40-year-old man has a painful, fluctuant, erythematous swelling next to the anus with fever. What is the most appropriate management?", "choices": ["Oral antibiotics alone", "Incision and drainage", "Sitz baths only", "Topical steroid", "High-fiber diet only"], "ans": 1, "exp": "Perianal abscess: ก้อนบวมแดงเจ็บข้างทวารหนัก + ไข้. รักษาด้วย incision & drainage ทันที (ยาปฏิชีวนะอย่างเดียวไม่พอ). ~30-50% กลายเป็น anal fistula ตามมา. ในเบาหวาน/ภูมิคุ้มกันต่ำระวัง necrotizing infection (Fournier gangrene)."}, {"topic": "General/GI Surgery", "q": "A 55-year-old woman has painless, intermittent bright red rectal bleeding coating the stool, with prolapsing lumps that reduce spontaneously. What is the most likely diagnosis?", "choices": ["Anal fissure", "Rectal prolapse", "Internal hemorrhoids", "Colorectal cancer", "Diverticular bleed"], "ans": 2, "exp": "Internal hemorrhoids: เลือดแดงสดเคลือบอุจจาระ 'ไม่เจ็บ' + ก้อนยื่นที่ reduce เองได้ (grade II). รักษาตาม grade: เพิ่มไฟเบอร์/น้ำ (I-II), rubber band ligation (II-III), hemorrhoidectomy (III-IV). ต้องแยกมะเร็ง (colonoscopy ถ้าเสี่ยง/อายุมาก)."}, {"topic": "General/GI Surgery", "q": "A 30-year-old woman is diagnosed with acute appendicitis. What is the definitive treatment?", "choices": ["Intravenous antibiotics only", "Interval colonoscopy", "Bowel rest and observation", "Appendectomy", "Percutaneous drainage"], "ans": 3, "exp": "การรักษามาตรฐานของ acute appendicitis คือ appendectomy (laparoscopic หรือ open). ยาปฏิชีวนะให้ perioperative. กรณี appendiceal mass/abscess ที่มาช้า อาจให้ยาปฏิชีวนะ ± drainage แล้วพิจารณา interval appendectomy. Uncomplicated บางรายรักษาด้วยยาปฏิชีวนะได้แต่ recurrence สูง."}, {"topic": "General/GI Surgery", "q": "A 60-year-old man has sudden severe abdominal pain out of proportion to exam findings; he has atrial fibrillation. Lactate is markedly elevated. What is the most likely diagnosis?", "choices": ["Diverticulitis", "Acute pancreatitis", "Small bowel obstruction", "Peptic ulcer", "Acute mesenteric ischemia"], "ans": 4, "exp": "Acute mesenteric ischemia (มัก SMA embolism ในผู้มี AF): 'ปวดท้องรุนแรงเกินกว่าที่ตรวจพบ' (pain out of proportion) + lactate สูง (metabolic acidosis). เป็น surgical emergency — CT angiography, resuscitation, revascularization/resection. ล่าช้าทำให้ bowel necrosis และตายสูง."}, {"topic": "General/GI Surgery", "q": "A 75-year-old man presents with abdominal distension, and abdominal X-ray shows a massively dilated loop in a 'coffee bean' shape arising from the pelvis. What is the diagnosis?", "choices": ["Sigmoid volvulus", "Paralytic ileus", "Cecal volvulus", "Small bowel obstruction", "Toxic megacolon"], "ans": 0, "exp": "Sigmoid volvulus: พบในผู้สูงอายุ/ท้องผูกเรื้อรัง — X-ray เห็น 'coffee bean/omega sign' ชี้จากอุ้งเชิงกราน. รักษาเบื้องต้น: sigmoidoscopic detorsion + rectal tube (ถ้าไม่มี ischemia); เป็นซ้ำบ่อย → sigmoid colectomy. ถ้ามี peritonitis/gangrene → ผ่าตัดฉุกเฉิน."}, {"topic": "General/GI Surgery", "q": "A 45-year-old woman has recurrent left lower quadrant pain, fever, and altered bowel habits. CT shows sigmoid diverticula with pericolic fat stranding. What is the diagnosis?", "choices": ["Ischemic colitis", "Acute diverticulitis", "Colorectal cancer", "Ulcerative colitis", "Appendicitis"], "ans": 1, "exp": "Acute diverticulitis (มัก sigmoid): ปวด LLQ + ไข้ + เปลี่ยน bowel habit; CT พบ diverticula + fat stranding ± abscess. Uncomplicated รักษาด้วยยาปฏิชีวนะ ± NPO. Complicated (abscess → drainage; perforation/peritonitis → ผ่าตัด Hartmann). Colonoscopy หลังหายเพื่อแยกมะเร็ง."}, {"topic": "General/GI Surgery", "q": "A 58-year-old man with cirrhosis and a history of alcohol use has massive hematemesis. Endoscopy reveals bleeding esophageal varices. What is the definitive endoscopic treatment?", "choices": ["Emergency laparotomy", "Balloon tamponade only", "Endoscopic band ligation", "Beta-blocker only", "Barium swallow"], "ans": 2, "exp": "Bleeding esophageal varices (portal hypertension จาก cirrhosis): รักษา resuscitation + vasoactive drug (octreotide/terlipressin) + antibiotic prophylaxis + 'endoscopic band ligation' (definitive endoscopic). Balloon tamponade (Sengstaken) เป็น bridge ชั่วคราว. ดื้อ → TIPS. ป้องกันซ้ำด้วย band + beta-blocker."}, {"topic": "General/GI Surgery", "q": "A 62-year-old man has progressive dysphagia to solids then liquids, with significant weight loss. He has a long history of GERD. What is the most likely diagnosis?", "choices": ["Esophageal web", "Achalasia", "Diffuse esophageal spasm", "Esophageal carcinoma", "Peptic stricture"], "ans": 3, "exp": "Esophageal carcinoma: dysphagia ที่ลุกลามจาก solid → liquid (mechanical obstruction ที่แย่ลงเรื่อยๆ) + น้ำหนักลด. Adenocarcinoma สัมพันธ์ GERD/Barrett; SCC สัมพันธ์บุหรี่/เหล้า. วินิจฉัย endoscopy + biopsy, staging. ต่างจาก achalasia (dysphagia ทั้ง solid/liquid พร้อมกัน, ไม่ลุกลาม)."}, {"topic": "General/GI Surgery", "q": "A 50-year-old man has epigastric pain relieved by eating and antacids, worse at night. Endoscopy shows a duodenal ulcer, and biopsy is positive for Helicobacter pylori. What is the appropriate treatment?", "choices": ["Surgery (vagotomy) for this patient", "Antacids alone", "Long-term steroids for this patient", "H2 blocker only", "Triple therapy (PPI plus two antibiotics)"], "ans": 4, "exp": "Duodenal ulcer + H. pylori: รักษาด้วย eradication triple therapy (PPI + clarithromycin + amoxicillin, หรือสูตร bismuth-based) 14 วัน แล้ว test of cure. ผ่าตัด (vagotomy) ปัจจุบันแทบไม่ใช้ ยกเว้นภาวะแทรกซ้อน (perforation, bleeding, obstruction) ที่ไม่ตอบสนอง."}, {"topic": "General/GI Surgery", "q": "A 55-year-old man is found to have a gastric ulcer on endoscopy. What must be done because of the risk of malignancy?", "choices": ["Biopsy the ulcer edges", "Repeat endoscopy in 1 year", "Immediate gastrectomy", "Start antacids and discharge", "Barium meal only"], "ans": 0, "exp": "Gastric ulcer (ต่างจาก duodenal) มีความเสี่ยงเป็นมะเร็ง → ต้อง biopsy ขอบแผลหลายจุดเสมอ และ 'repeat endoscopy' หลังรักษา 6-8 สัปดาห์เพื่อยืนยันการหายและแยกมะเร็ง. รักษา H. pylori + PPI. Duodenal ulcer ไม่จำเป็นต้อง biopsy routine."}, {"topic": "General/GI Surgery", "q": "A 20-year-old man is stabbed in the left upper abdomen and presents with hypotension, left shoulder pain (Kehr sign), and peritonitis. What organ is most likely injured?", "choices": ["Liver", "Spleen", "Stomach", "Pancreas", "Left kidney"], "ans": 1, "exp": "Splenic injury: บาดเจ็บ LUQ + hypotension + Kehr sign (ปวดร้าวไหล่ซ้ายจากเลือดระคายกะบังลม). ม้ามเป็นอวัยวะที่บาดเจ็บบ่อยใน blunt/penetrating LUQ trauma. Unstable → laparotomy; stable blunt → non-operative ± angioembolization. หลังตัดม้ามต้องให้วัคซีน encapsulated organisms."}, {"topic": "General/GI Surgery", "q": "A 48-year-old woman has intermittent right upper quadrant pain and ultrasound shows gallstones but no wall thickening or fever. She is otherwise well. What is the diagnosis?", "choices": ["Gallbladder cancer", "Acute cholecystitis", "Biliary colic", "Choledocholithiasis", "Cholangitis"], "ans": 2, "exp": "Biliary colic: ปวด RUQ/epigastric เป็นพักๆ หลังอาหารมัน หายเองใน <6 ชม., ไม่มีไข้/อักเสบ, US พบ gallstone ผนังปกติ. เกิดจากนิ่วอุดชั่วคราวที่ cystic duct. รักษา: elective laparoscopic cholecystectomy (มีอาการ). ต่างจาก cholecystitis (อักเสบต่อเนื่อง + ไข้ + Murphy)."}, {"topic": "General/GI Surgery", "q": "A 30-year-old woman presents with a firm, non-tender, mobile breast lump. Which feature is most reassuring for a benign fibroadenoma?", "choices": ["Fixed to chest wall", "Bloody nipple discharge", "Skin dimpling present", "Well-circumscribed and mobile", "Axillary lymphadenopathy"], "ans": 3, "exp": "Fibroadenoma: ก้อนเรียบ ขอบชัด เคลื่อนที่ได้ ไม่เจ็บ ในหญิงสาว — ลักษณะ benign. ประเมินด้วย triple assessment. Red flags มะเร็ง: ติดแน่น (fixed), ผิวบุ๋ม, หัวนมมีเลือด, ต่อมน้ำเหลืองรักแร้โต. (หมวดนี้ทับกับ breast surgery — เน้น surgical evaluation)."}, {"topic": "General/GI Surgery", "q": "A 65-year-old man has painless obstructive jaundice with a palpable, non-tender gallbladder (Courvoisier sign). What is the most likely underlying cause?", "choices": ["Gallstone in the cystic duct", "Gilbert syndrome", "Acute cholecystitis", "Viral hepatitis", "Pancreatic head carcinoma"], "ans": 4, "exp": "Courvoisier's law: ดีซ่านแบบอุดกั้นที่ 'ไม่เจ็บ' + คลำถุงน้ำดีโตไม่เจ็บ → ไม่น่าเกิดจากนิ่ว (ถุงน้ำดีมักหดจากการอักเสบเรื้อรัง) แต่บ่งชี้การอุดกั้นจาก malignancy โดยเฉพาะ pancreatic head carcinoma (หรือ cholangiocarcinoma). วินิจฉัยด้วย CT/MRCP + CA 19-9."}, {"topic": "General/GI Surgery", "q": "A 5-year-old boy has intermittent painless rectal bleeding. A technetium-99m scan is positive. What is the most likely diagnosis?", "choices": ["Meckel diverticulum", "Anal fissure", "Intussusception", "Juvenile polyp", "Hirschsprung disease"], "ans": 0, "exp": "Meckel diverticulum: 'rule of 2s' (2% ประชากร, 2 ฟุตจาก ileocecal, 2 นิ้ว, มัก <2 ปี). มี ectopic gastric mucosa → painless rectal bleeding ในเด็ก. วินิจฉัยด้วย Meckel (technetium-99m pertechnetate) scan. รักษา: surgical resection ถ้ามีอาการ."}, {"topic": "General/GI Surgery", "q": "A 6-month-old infant has episodic colicky pain, drawing up of the legs, and 'currant jelly' stools. A sausage-shaped mass is palpable. What is the diagnosis?", "choices": ["Meckel diverticulum", "Intussusception", "Pyloric stenosis", "Hirschsprung disease", "Volvulus"], "ans": 1, "exp": "Intussusception (ileocolic บ่อยสุด, ~3-12 เดือน): ปวดบิดเป็นพักๆ, งอขา, 'currant jelly stool' (เลือด+เมือก), คลำได้ก้อน sausage-shaped. วินิจฉัย/รักษาด้วย air/contrast enema reduction; ล้มเหลว/peritonitis → ผ่าตัด. เป็นสาเหตุลำไส้อุดตันที่พบบ่อยในวัยทารก."}, {"topic": "General/GI Surgery", "q": "A 3-week-old firstborn boy has projectile non-bilious vomiting after feeds and a palpable 'olive' mass in the epigastrium. What metabolic abnormality is expected?", "choices": ["Hyponatremic metabolic acidosis initially", "Respiratory acidosis for this patient", "Hypochloremic hypokalemic metabolic alkalosis", "Anion-gap metabolic acidosis as first step", "Normal electrolytes for this patient"], "ans": 2, "exp": "Hypertrophic pyloric stenosis (~3-6 สัปดาห์, first-born ชาย): projectile non-bilious vomiting + คลำ 'olive' mass. การอาเจียนกรด (HCl) → hypochloremic hypokalemic metabolic alkalosis. รักษา: แก้ไขเกลือแร่/สารน้ำก่อน แล้ว pyloromyotomy (ไม่ใช่ฉุกเฉิน)."}, {"topic": "General/GI Surgery", "q": "A 45-year-old man has a reducible bulge in the groin located above and medial to the pubic tubercle. What type of hernia is this?", "choices": ["Femoral hernia", "Umbilical hernia", "Incisional hernia", "Inguinal hernia", "Obturator hernia"], "ans": 3, "exp": "Inguinal hernia อยู่ 'เหนือและด้านใน' ต่อ pubic tubercle. Femoral hernia อยู่ 'ใต้และด้านนอก' ต่อ pubic tubercle (พบในหญิงมากกว่า, เสี่ยง strangulation สูง). การแยกตำแหน่งเทียบ pubic tubercle เป็นจุดสำคัญทางคลินิก."}, {"topic": "General/GI Surgery", "q": "A 70-year-old woman has a tender, irreducible lump below and lateral to the pubic tubercle with bowel obstruction. Which hernia has the highest risk of strangulation?", "choices": ["Direct inguinal hernia", "Spigelian hernia", "Umbilical hernia", "Epigastric hernia", "Femoral hernia"], "ans": 4, "exp": "Femoral hernia (ใต้/ด้านนอกต่อ pubic tubercle, พบในหญิงสูงอายุ) มีคอแคบ (rigid femoral ring) → เสี่ยง incarceration/strangulation สูงสุด → แนะนำผ่าตัดซ่อมแม้ไม่มีอาการ. กรณีนี้มีลำไส้อุดตัน → ผ่าตัดฉุกเฉิน."}, {"topic": "General/GI Surgery", "q": "A 35-year-old man has severe epigastric pain and vomiting; CT shows peripancreatic fluid collections 3 weeks after an episode of acute pancreatitis. He now has a well-defined encapsulated collection. What is the diagnosis?", "choices": ["Pancreatic pseudocyst", "Pancreatic carcinoma", "Pancreatic abscess", "Splenic cyst", "Mesenteric cyst"], "ans": 0, "exp": "Pancreatic pseudocyst: เกิดหลัง acute pancreatitis ~4 สัปดาห์ — collection ที่มีผนัง (ไม่มี epithelium จริง). ส่วนใหญ่หายเอง; ถ้าใหญ่/มีอาการ/ติดเชื้อ → drainage (endoscopic cystogastrostomy ที่นิยม). ต่างจาก abscess (มีการติดเชื้อ/หนอง)."}, {"topic": "General/GI Surgery", "q": "A 40-year-old woman has recurrent episodes of RUQ pain; ultrasound shows a dilated common bile duct with a stone. What is the appropriate management to relieve the obstruction?", "choices": ["Laparoscopic cholecystectomy alone", "ERCP with stone extraction", "Observation", "Oral ursodeoxycholic acid", "Percutaneous drainage only"], "ans": 1, "exp": "Choledocholithiasis (นิ่วใน common bile duct): ปวด RUQ + CBD dilated + นิ่ว, เสี่ยง cholangitis/pancreatitis. รักษาด้วย ERCP + stone extraction (± sphincterotomy) เพื่อเอานิ่วออก, ตามด้วย cholecystectomy (จัดการต้นตอ). US/MRCP ช่วยวินิจฉัย."}, {"topic": "General/GI Surgery", "q": "A 65-year-old man has epigastric pain, early satiety, and weight loss. Endoscopy shows an ulcerated mass in the gastric antrum; biopsy confirms adenocarcinoma. Which risk factor is most associated?", "choices": ["Lactose intolerance alone", "Gilbert syndrome initially", "Helicobacter pylori infection", "Hemochromatosis initially", "Wilson disease in this case"], "ans": 2, "exp": "Gastric adenocarcinoma: ปวด epigastric + อิ่มเร็ว + น้ำหนักลด. ปัจจัยเสี่ยงหลัก: H. pylori (chronic gastritis → intestinal metaplasia), อาหารเค็ม/ปลาเค็ม, บุหรี่, pernicious anemia. อาจมี Virchow node (ต่อมน้ำเหลือง supraclavicular ซ้าย). วินิจฉัย endoscopy + biopsy; รักษา gastrectomy ± chemo."}, {"topic": "General/GI Surgery", "q": "A 60-year-old man with chronic hepatitis B has a new liver mass and an alpha-fetoprotein of 800 ng/mL. What is the most likely diagnosis?", "choices": ["Liver hemangioma", "Focal nodular hyperplasia", "Hepatic adenoma", "Hepatocellular carcinoma", "Pyogenic liver abscess"], "ans": 3, "exp": "Hepatocellular carcinoma (HCC): เกิดบน chronic liver disease (HBV/HCV, cirrhosis) + AFP สูง + mass ที่มี arterial enhancement/washout ทาง CT/MRI (LI-RADS). รักษาตามระยะ/liver function: resection, transplant, ablation, TACE, systemic. คัดกรองด้วย US ± AFP ทุก 6 เดือนในกลุ่มเสี่ยง."}, {"topic": "General/GI Surgery", "q": "A 45-year-old man from a rural area has fever and RUQ pain; ultrasound shows a solitary liver abscess. He recently had bloody diarrhea. Serology for Entamoeba is positive. What is the treatment?", "choices": ["Surgical resection", "Albendazole", "Percutaneous drainage first", "Broad-spectrum antibiotics only", "Metronidazole"], "ans": 4, "exp": "Amoebic liver abscess (Entamoeba histolytica, มักกลีบขวา, หลัง amoebic colitis): รักษาด้วย metronidazole (+ luminal agent เช่น diloxanide เพื่อกำจัด cyst). ส่วนใหญ่ไม่ต้อง drain; drain เมื่อใหญ่มาก/ไม่ตอบสนอง/เสี่ยงแตก. ต่างจาก pyogenic abscess (polymicrobial → antibiotic + drainage)."}, {"topic": "General/GI Surgery", "q": "A 68-year-old man has painless jaundice, weight loss, and a pancreatic head mass on CT. Which tumor marker is most associated?", "choices": ["CA 19-9", "AFP", "CEA", "Beta-hCG", "PSA"], "ans": 0, "exp": "Pancreatic head adenocarcinoma: painless obstructive jaundice + น้ำหนักลด + Courvoisier sign. Tumor marker: CA 19-9 (ใช้ติดตาม ไม่ใช่คัดกรอง). วินิจฉัย CT pancreas protocol ± EUS-guided biopsy. รักษา: Whipple (pancreaticoduodenectomy) ถ้า resectable; ส่วนใหญ่วินิจฉัยระยะท้าย พยากรณ์แย่."}, {"topic": "General/GI Surgery", "q": "A 25-year-old woman has a chronic discharging sinus in the natal cleft with a tuft of hair. What is the diagnosis?", "choices": ["Hidradenitis suppurativa", "Pilonidal disease", "Anal fistula", "Perianal abscess", "Sacral dermoid"], "ans": 1, "exp": "Pilonidal disease: sinus/ฝีบริเวณร่องก้น (natal cleft) มีขนฝังใน, พบในชายหนุ่มขนดก/นั่งนาน. Acute abscess → I&D; chronic sinus → excision (± flap) + สุขอนามัย/กำจัดขน. ต่างจาก anal fistula (เชื่อมกับ anal canal)."}, {"topic": "General/GI Surgery", "q": "A 50-year-old man has a chronic discharging opening near the anus connecting to the anal canal. What is the diagnosis and definitive treatment?", "choices": ["Anal fissure, sphincterotomy", "Hemorrhoids, banding", "Anal fistula, fistulotomy", "Pilonidal sinus, excision", "Perianal abscess, drainage"], "ans": 2, "exp": "Anal fistula (fistula-in-ano): ทางเชื่อมระหว่าง anal canal กับผิวหนัง มักตามหลัง perianal abscess. Goodsall's rule ทำนายทิศทาง. รักษา: fistulotomy (low fistula) หรือ seton/LIFT (high/complex เพื่อรักษา sphincter). ประเมิน IBD (Crohn) ในรายซับซ้อน/เป็นซ้ำ."}, {"topic": "General/GI Surgery", "q": "A 55-year-old man with severe vomiting develops sudden severe chest and epigastric pain with subcutaneous emphysema. Chest imaging shows a left pleural effusion and mediastinal air. What is the diagnosis?", "choices": ["Mallory-Weiss tear", "Peptic perforation", "Myocardial infarction", "Boerhaave syndrome", "Aortic dissection"], "ans": 3, "exp": "Boerhaave syndrome: esophageal rupture เต็มความหนา (transmural) หลังอาเจียนรุนแรง → ปวดอก/epigastric รุนแรง, subcutaneous emphysema, pleural effusion (ซ้าย), mediastinal air. Mackler triad (อาเจียน + เจ็บอก + emphysema). เป็น surgical emergency — resuscitation + antibiotic + ผ่าตัดซ่อม/drainage. ต่างจาก Mallory-Weiss (แผลเยื่อบุ ไม่ทะลุ, เลือดออก)."}, {"topic": "General/GI Surgery", "q": "A 40-year-old alcoholic man has hematemesis after repeated forceful retching. Endoscopy shows a longitudinal mucosal tear at the gastroesophageal junction. What is the diagnosis?", "choices": ["Boerhaave syndrome", "Peptic ulcer", "Esophageal varices", "Esophageal cancer", "Mallory-Weiss tear"], "ans": 4, "exp": "Mallory-Weiss tear: แผลฉีก 'เยื่อบุ' (mucosal, ไม่ทะลุ) ที่ GE junction หลังอาเจียน/retching ซ้ำ → hematemesis. ส่วนใหญ่หยุดเองได้; เลือดออกมากใช้ endoscopic hemostasis. ต่างจาก Boerhaave (transmural rupture, รุนแรง)."}, {"topic": "General/GI Surgery", "q": "A 30-year-old woman has dysphagia to both solids and liquids, regurgitation, and a 'bird-beak' tapering of the distal esophagus on barium swallow. What is the diagnosis?", "choices": ["Achalasia", "Esophageal carcinoma", "Esophageal web", "Peptic stricture", "Zenker diverticulum"], "ans": 0, "exp": "Achalasia: dysphagia ต่อทั้ง solid และ liquid 'พร้อมกัน' + regurgitation; barium เห็น 'bird-beak' (LES ไม่คลาย + esophagus ขยาย). ยืนยันด้วย manometry (aperistalsis + LES ไม่คลาย). รักษา: pneumatic dilation, Heller myotomy, หรือ POEM. ต่างจากมะเร็ง (dysphagia solid→liquid ลุกลาม + น้ำหนักลด)."}, {"topic": "General/GI Surgery", "q": "A 2-day-old neonate has bilious vomiting and abdominal distension and has not passed meconium. Contrast enema shows a transition zone in the rectosigmoid. What is the diagnosis?", "choices": ["Duodenal atresia", "Hirschsprung disease", "Meconium ileus", "Necrotizing enterocolitis", "Anorectal malformation"], "ans": 1, "exp": "Hirschsprung disease: ไม่มี ganglion cells (aganglionosis) เริ่มจาก rectum ขึ้นไป → ไม่ถ่ายขี้เทาใน 48 ชม., ท้องอืด, bilious vomiting. Contrast เห็น transition zone; ยืนยันด้วย rectal biopsy (ไม่มี ganglion cells). รักษา: ผ่าตัด pull-through. เสี่ยง enterocolitis (อันตราย)."}, {"topic": "General/GI Surgery", "q": "A newborn has bilious vomiting on the first day; abdominal X-ray shows a 'double bubble' sign. What is the most likely diagnosis?", "choices": ["Malrotation with volvulus", "Pyloric stenosis", "Duodenal atresia", "Hirschsprung disease", "Jejunal atresia"], "ans": 2, "exp": "Duodenal atresia: bilious vomiting วันแรก + 'double bubble' (ลมในกระเพาะ + duodenum ส่วนต้น). สัมพันธ์กับ Down syndrome (~30%). รักษา: duodenoduodenostomy. ต้องแยก malrotation with midgut volvulus (bilious vomiting + surgical emergency — ต้อง upper GI contrast ด่วน)."}, {"topic": "General/GI Surgery", "q": "A newborn has bilious vomiting and an upper GI study shows the duodenojejunal junction on the right side with a 'corkscrew' appearance. What is the diagnosis requiring emergency surgery?", "choices": ["Duodenal atresia in this case", "Meconium ileus as first step", "Hirschsprung disease initially", "Malrotation with midgut volvulus", "Pyloric stenosis in this case"], "ans": 3, "exp": "Malrotation with midgut volvulus: bilious vomiting ในทารก + upper GI พบ DJ junction ผิดตำแหน่ง (ขวา) + 'corkscrew' → เป็น surgical emergency (bowel ischemia ได้เร็ว) → Ladd procedure ด่วน. Bilious vomiting ในทารกทุกรายต้องแยกภาวะนี้ก่อน."}, {"topic": "General/GI Surgery", "q": "A 60-year-old man 5 days after bowel anastomosis develops fever, tachycardia, abdominal pain, and feculent drainage from the wound. What is the most likely complication?", "choices": ["Wound infection", "Deep vein thrombosis", "Ileus", "Atelectasis", "Anastomotic leak"], "ans": 4, "exp": "Anastomotic leak: มักเกิดวันที่ 5-7 หลังผ่าตัด — ไข้, ปวดท้อง, tachycardia, มี enteric/feculent content ออกจากแผล/drain, sepsis. ยืนยันด้วย CT with contrast. รักษา: resuscitation, antibiotic, drainage; รุนแรง → re-operation ± stoma. เป็นภาวะแทรกซ้อนร้ายแรงของ bowel surgery."}, {"topic": "General/GI Surgery", "q": "On postoperative day 2 after abdominal surgery, a patient develops fever. Which is the most likely cause at this early stage?", "choices": ["Atelectasis", "Wound infection", "Anastomotic leak", "Deep vein thrombosis", "Urinary tract infection"], "ans": 0, "exp": "สาเหตุไข้หลังผ่าตัดตามเวลา (5 Ws): วันที่ 1-2 = atelectasis (Wind, พบบ่อยสุดช่วงแรก); 3-5 = UTI (Water)/pneumonia; 5-7 = wound infection (Wound)/anastomotic leak; DVT (Walking); drug/line (Wonder drugs). วันที่ 2 → atelectasis. รักษา: incentive spirometry, กายภาพหายใจ, early mobilization."}, {"topic": "General/GI Surgery", "q": "A 7-day-old premature neonate has abdominal distension, bloody stools, and pneumatosis intestinalis on X-ray. What is the diagnosis?", "choices": ["Intussusception", "Necrotizing enterocolitis", "Hirschsprung disease", "Malrotation", "Meconium ileus"], "ans": 1, "exp": "Necrotizing enterocolitis (NEC): พบในทารกคลอดก่อนกำหนด — ท้องอืด, ถ่ายเป็นเลือด, ไม่ทน feed; X-ray เห็น pneumatosis intestinalis (ลมในผนังลำไส้) ± portal venous gas. รักษา: NPO, NG decompression, antibiotic; ผ่าตัดถ้า perforation/necrosis (pneumoperitoneum)."}, {"topic": "General/GI Surgery", "q": "A 55-year-old woman has recurrent right upper quadrant pain and gallstones. During laparoscopic cholecystectomy, the surgeon must identify structures in which anatomical landmark to avoid bile duct injury?", "choices": ["Pouch of Douglas", "Foramen of Winslow", "Calot triangle", "Triangle of Koch", "Hesselbach triangle"], "ans": 2, "exp": "Calot's triangle (cystohepatic triangle): ขอบเขต cystic duct, common hepatic duct, และ liver edge — มี cystic artery. การทำ 'critical view of safety' โดยระบุโครงสร้างใน Calot's triangle ช่วยป้องกัน bile duct injury ระหว่าง cholecystectomy. (Hesselbach = inguinal; Koch = หัวใจ)."}, {"topic": "General/GI Surgery", "q": "A 3-year-old boy has not passed stool well since birth, with chronic constipation and abdominal distension. Rectal biopsy shows absence of ganglion cells. What is the pathophysiology?", "choices": ["Anal stenosis for this patient", "Meconium plug for this patient", "Hypothyroidism for this patient", "Aganglionosis of the distal bowel", "Neuronal dysplasia in this case"], "ans": 3, "exp": "Hirschsprung disease = การไม่มี ganglion cells (aganglionosis) ในชั้น submucosal (Meissner) และ myenteric (Auerbach) plexus เริ่มจาก rectum ขึ้นไป → ลำไส้ส่วนนั้นหดเกร็งไม่คลาย → obstruction เชิงหน้าที่. วินิจฉัยด้วย rectal biopsy. รักษา: pull-through resection ส่วนที่ไม่มี ganglion."}, {"topic": "General/GI Surgery", "q": "A 45-year-old woman has a 3 cm gastric submucosal mass; biopsy shows spindle cells positive for CD117 (c-KIT). What is the diagnosis?", "choices": ["Adenocarcinoma in this case", "Lymphoma for this patient", "Leiomyoma for this patient", "Carcinoid tumor in this case", "Gastrointestinal stromal tumor"], "ans": 4, "exp": "Gastrointestinal stromal tumor (GIST): เนื้องอก mesenchymal จาก interstitial cells of Cajal, มัก CD117 (c-KIT) positive. พบบ่อยที่กระเพาะ. รักษา: surgical resection (ไม่ต้องเลาะ node); imatinib (tyrosine kinase inhibitor) สำหรับ unresectable/metastatic/adjuvant. ความเสี่ยงประเมินจากขนาด + mitotic rate."}, {"topic": "General/GI Surgery", "q": "A 60-year-old man has rectal bleeding and tenesmus. Digital rectal exam reveals a mass 4 cm from the anal verge; biopsy confirms adenocarcinoma. Which imaging best assesses local T-staging?", "choices": ["Pelvic MRI", "Abdominal ultrasound", "Chest X-ray", "Barium enema", "Plain abdominal film"], "ans": 0, "exp": "Rectal cancer local staging (T และ circumferential resection margin, nodes) ประเมินดีที่สุดด้วย 'pelvic MRI' (± endorectal US สำหรับ early T). CT chest/abdomen สำหรับ distant metastasis. การ staging กำหนดว่าต้อง neoadjuvant chemoradiation ก่อนผ่าตัด (TME) หรือไม่."}, {"topic": "General/GI Surgery", "q": "A 50-year-old man with cirrhosis develops progressive abdominal distension with shifting dullness and a fluid wave. What is the most likely cause?", "choices": ["Congestive heart failure alone", "Portal hypertension causing ascites", "Bowel obstruction as first step", "Ovarian mass for this patient", "Nephrotic syndrome as first step"], "ans": 1, "exp": "Ascites ในผู้ป่วย cirrhosis เกิดจาก portal hypertension (+ hypoalbuminemia, Na/water retention). ประเมินด้วย diagnostic paracentesis + SAAG (≥1.1 = portal HT). เฝ้าระวัง spontaneous bacterial peritonitis (SBP - PMN ≥250). รักษา: จำกัดเกลือ + diuretics (spironolactone ± furosemide), LVP, TIPS."}, {"topic": "General/GI Surgery", "q": "A 30-year-old man is stabbed in the epigastrium. He is hemodynamically stable but has peritonitis on examination. What is the most appropriate management?", "choices": ["Observation and serial exams", "Antibiotics alone", "Exploratory laparotomy", "CT then discharge", "Diagnostic peritoneal lavage only"], "ans": 2, "exp": "Penetrating abdominal trauma ที่มี peritonitis, evisceration, หรือ hemodynamic instability = ข้อบ่งชี้ 'exploratory laparotomy' ทันที (ไม่ต้อง imaging เพิ่ม). Stab wound ที่ stable ไม่มี peritonitis อาจ selective non-operative + serial exam/CT. Gunshot ช่องท้องส่วนใหญ่ต้อง laparotomy."}, {"topic": "General/GI Surgery", "q": "A 24-year-old man is diagnosed with an appendiceal mass 6 days into his illness; he is stable without peritonitis. What is the appropriate initial management?", "choices": ["Immediate appendectomy for this patient", "Right hemicolectomy for this patient", "Percutaneous drainage of stool for this patient", "Antibiotics and observation (consider interval appendectomy)", "Barium enema for this patient"], "ans": 3, "exp": "Appendiceal mass/phlegmon ที่มาช้า (>5 วัน) และ stable: รักษาแบบ conservative ด้วยยาปฏิชีวนะ ± drainage ถ้ามี abscess — เพราะผ่าตัดทันทีในช่วงนี้ยากและเสี่ยงบาดเจ็บอวัยวะข้างเคียง. พิจารณา interval appendectomy ภายหลัง (± colonoscopy ในผู้สูงอายุแยกมะเร็ง)."}, {"topic": "General/GI Surgery", "q": "A 70-year-old man has painless massive lower GI bleeding. Colonoscopy is difficult due to bleeding. Which is the most common cause of significant lower GI bleeding in the elderly?", "choices": ["Anal fissure", "Hemorrhoids", "Colorectal polyp", "Ischemic colitis", "Diverticulosis"], "ans": 4, "exp": "Diverticulosis เป็นสาเหตุที่พบบ่อยที่สุดของ lower GI bleeding รุนแรงในผู้สูงอายุ (เลือดออกไม่เจ็บ ปริมาณมาก มักหยุดเอง). สาเหตุอื่น: angiodysplasia, ischemic colitis, มะเร็ง. ประเมิน: resuscitation → colonoscopy; ต่อเนื่อง → CT angiography/embolization หรือผ่าตัด."}, {"topic": "General/GI Surgery", "q": "A 40-year-old man has severe, constant epigastric pain radiating to the back and is leaning forward for relief; serum amylase is elevated. Which scoring system assesses severity at admission?", "choices": ["Ranson criteria", "Glasgow Coma Scale", "CURB-65", "Child-Pugh score", "Alvarado score"], "ans": 0, "exp": "Acute pancreatitis severity ประเมินด้วย Ranson criteria (แรกรับ + 48 ชม.), APACHE II, หรือ BISAP. รุนแรง → เฝ้าระวัง organ failure, necrosis. Child-Pugh = ประเมินตับแข็ง; Alvarado = appendicitis; CURB-65 = pneumonia. การประเมินความรุนแรงกำหนดระดับการดูแล (ICU)."}, {"topic": "General/GI Surgery", "q": "A 6-week-old boy has persistent jaundice, pale stools, and dark urine; direct bilirubin is elevated. Ultrasound shows an absent/contracted gallbladder. What is the diagnosis requiring urgent surgery?", "choices": ["Physiologic jaundice", "Biliary atresia", "Neonatal hepatitis", "Choledochal cyst", "Gilbert syndrome"], "ans": 1, "exp": "Biliary atresia: conjugated (direct) hyperbilirubinemia ต่อเนื่องในทารก + อุจจาระซีด (acholic) + ปัสสาวะเข้ม. เป็นภาวะเร่งด่วน — Kasai portoenterostomy ควรทำก่อนอายุ ~8 สัปดาห์เพื่อผลดี (มิฉะนั้น cirrhosis → ต้อง liver transplant). ทารกที่ prolonged jaundice ต้องตรวจ direct bilirubin เสมอ."}, {"topic": "General/GI Surgery", "q": "A 3-year-old girl has recurrent abdominal pain, jaundice, and a palpable RUQ mass; ultrasound shows a cystic dilation of the common bile duct. What is the diagnosis?", "choices": ["Biliary atresia", "Gallbladder empyema", "Choledochal cyst", "Hepatic cyst", "Pancreatic pseudocyst"], "ans": 2, "exp": "Choledochal cyst: cystic dilation ของ bile duct — classic triad (ปวดท้อง + ดีซ่าน + ก้อน RUQ) พบครบไม่บ่อย. วินิจฉัย US/MRCP. เสี่ยง cholangiocarcinoma → รักษาด้วยผ่าตัด excision + hepaticojejunostomy. พบในเด็ก/หญิงเอเชียมากกว่า."}, {"topic": "General/GI Surgery", "q": "A 62-year-old man who had a gastrectomy develops sweating, palpitations, dizziness, and diarrhea 15-30 minutes after meals. What is the diagnosis?", "choices": ["Afferent loop syndrome", "Anastomotic stricture", "Bile reflux gastritis", "Dumping syndrome", "Recurrent ulcer"], "ans": 3, "exp": "Early dumping syndrome (หลัง gastric surgery): อาหารถึง small bowel เร็ว → osmotic fluid shift → อาการ vasomotor (เหงื่อ, ใจสั่น, มึน) + GI (ปวดบิด, ท้องเสีย) ภายใน 15-30 นาทีหลังอาหาร. Late dumping (1-3 ชม.) จาก reactive hypoglycemia. รักษา: แบ่งมื้อเล็ก, ลด carbohydrate เชิงเดี่ยว, แยกของเหลว."}, {"topic": "General/GI Surgery", "q": "A 55-year-old man with dysphagia is found to have a mid-esophageal squamous cell carcinoma. Which is the strongest risk factor?", "choices": ["Chronic GERD", "Obesity", "Barrett esophagus", "Hiatal hernia", "Smoking and alcohol"], "ans": 4, "exp": "Esophageal SCC (มัก upper/mid esophagus) — ปัจจัยเสี่ยงหลักคือ 'บุหรี่และแอลกอฮอล์' (เสริมฤทธิ์กัน), อาหารร้อนจัด, achalasia เรื้อรัง. ต่างจาก adenocarcinoma (distal esophagus, สัมพันธ์ GERD/Barrett/obesity). วินิจฉัย endoscopy + biopsy."}, {"topic": "General/GI Surgery", "q": "A 58-year-old man has heartburn and regurgitation for years and is found to have Barrett esophagus on endoscopy. What is the main clinical significance?", "choices": ["Risk of adenocarcinoma", "No clinical significance", "Risk of squamous carcinoma", "Risk of perforation", "Risk of achalasia"], "ans": 0, "exp": "Barrett esophagus = intestinal metaplasia ของ distal esophagus จาก chronic GERD — เป็น premalignant สำหรับ esophageal 'adenocarcinoma'. ต้อง surveillance endoscopy + biopsy; dysplasia → endoscopic therapy (RFA/EMR). รักษา GERD ด้วย PPI. ควบคุมอาการและเฝ้าระวังมะเร็ง."}, {"topic": "General/GI Surgery", "q": "A 45-year-old man ingested a strong alkaline cleaning agent and has drooling and odynophagia. What is the most appropriate early management?", "choices": ["Induce vomiting for this patient", "Endoscopy to assess injury, do not induce emesis", "Neutralize with acid for this patient", "Immediate laparotomy for this patient", "Barium swallow immediately for this patient"], "ans": 1, "exp": "Caustic ingestion (alkali ทำให้ liquefactive necrosis ลึก): ห้ามทำให้อาเจียน/neutralize/ใส่ NG blindly. ประเมิน airway, NPO, และทำ endoscopy ภายใน 24-48 ชม.เพื่อประเมินความรุนแรง (grade). ภาวะแทรกซ้อน: perforation (เฉียบพลัน), esophageal stricture (ระยะยาว)."}, {"topic": "General/GI Surgery", "q": "A 2-hour-old neonate is noted to have excessive drooling and chokes with feeds; a nasogastric tube coils in the upper esophagus on X-ray. What is the diagnosis?", "choices": ["Choanal atresia", "Pyloric stenosis", "Esophageal atresia", "Duodenal atresia", "Diaphragmatic hernia"], "ans": 2, "exp": "Esophageal atresia (มักมี tracheoesophageal fistula): น้ำลายมาก, สำลักเมื่อ feed, NG tube ขดในหลอดอาหารส่วนต้น. สัมพันธ์กับ VACTERL association. รักษา: ผ่าตัดซ่อม. ต้องระวัง aspiration ก่อนผ่าตัด (upright, suction)."}, {"topic": "General/GI Surgery", "q": "A 60-year-old man with a long-standing duodenal ulcer has recurrent vomiting of undigested food and a succussion splash. What is the complication?", "choices": ["Malignant transformation", "Perforation", "Gastric volvulus", "Gastric outlet obstruction", "Zollinger-Ellison syndrome"], "ans": 3, "exp": "Gastric outlet obstruction: จาก chronic peptic ulcer (pyloric scarring) หรือ malignancy — อาเจียนอาหารเก่าไม่ย่อย, succussion splash, น้ำหนักลด, metabolic alkalosis. รักษา: NG decompression, แก้เกลือแร่, endoscopy (แยกมะเร็ง/ balloon dilation), ผ่าตัดถ้าจำเป็น."}, {"topic": "General/GI Surgery", "q": "A patient underwent splenectomy after trauma. What prophylaxis is essential to prevent overwhelming post-splenectomy infection?", "choices": ["Lifelong warfarin for this patient", "No prophylaxis needed for this patient", "Daily proton pump inhibitor in this case", "Routine antifungals for this patient", "Vaccination against encapsulated organisms"], "ans": 4, "exp": "หลัง splenectomy เสี่ยง overwhelming post-splenectomy infection (OPSI) จากเชื้อ encapsulated (Streptococcus pneumoniae, Haemophilus influenzae type b, Neisseria meningitidis) → ต้องฉีดวัคซีนทั้งสาม (ควรก่อนผ่าตัด 2 สัปดาห์ถ้า elective) + พิจารณา prophylactic antibiotic ในเด็ก และให้ความรู้เรื่องไข้."}, {"topic": "General/GI Surgery", "q": "A 40-year-old shepherd has a large liver cyst with daughter cysts and calcified wall on CT; serology for Echinococcus is positive. What is the appropriate treatment?", "choices": ["Albendazole plus surgery/PAIR", "Metronidazole alone", "Aspiration alone", "Observation", "Broad-spectrum antibiotics"], "ans": 0, "exp": "Hydatid cyst (Echinococcus granulosus, สัมพันธ์เลี้ยงแกะ/สุนัข): CT เห็น daughter cysts/calcification. รักษา: albendazole + surgery (pericystectomy) หรือ PAIR (puncture-aspiration-injection-reaspiration) โดยระวัง spillage (anaphylaxis/dissemination). ห้ามเจาะแบบไม่เตรียม."}, {"topic": "General/GI Surgery", "q": "A 65-year-old woman with a porcelain gallbladder on imaging is counseled about her risk. What is the concern?", "choices": ["Gallstone ileus", "Gallbladder carcinoma", "Cholangitis", "Pancreatitis", "Bile leak"], "ans": 1, "exp": "Porcelain gallbladder (ผนังถุงน้ำดี calcified) สัมพันธ์กับความเสี่ยง gallbladder carcinoma → พิจารณา cholecystectomy. Gallbladder cancer พยากรณ์แย่ (มักวินิจฉัยระยะท้าย). ปัจจัยเสี่ยงอื่น: gallstone เรื้อรัง, large polyp (>1 cm), chronic infection."}, {"topic": "General/GI Surgery", "q": "A young man with ulcerative colitis develops a distended, tender abdomen, fever, and tachycardia; X-ray shows a dilated transverse colon >6 cm. What is the diagnosis?", "choices": ["Sigmoid volvulus", "Small bowel obstruction", "Toxic megacolon", "Diverticulitis", "Ischemic colitis"], "ans": 2, "exp": "Toxic megacolon: ภาวะแทรกซ้อนของ severe colitis (UC, C. difficile) — colon ขยาย >6 cm + systemic toxicity (ไข้, tachycardia, ปวดท้อง). เสี่ยงทะลุ. รักษา: IV steroid/antibiotic, bowel rest, แก้เกลือแร่; ไม่ดีขึ้น/ทะลุ → colectomy ฉุกเฉิน. หลีกเลี่ยง antimotility/opioid."}, {"topic": "General/GI Surgery", "q": "A 30-year-old man with Crohn disease has a chronic enterocutaneous fistula. Which is a key principle of management?", "choices": ["Immediate resection always alone", "No intervention for this patient", "High-dose opioids for this patient", "Optimize nutrition and control sepsis", "Barium enema for this patient"], "ans": 3, "exp": "Enterocutaneous fistula management (SNAP/SOWATS): control Sepsis, optimize Nutrition (มัก TPN), skin/wound care, define Anatomy (fistulogram/CT). ~1/3 ปิดเองด้วย conservative; ปัจจัยที่ปิดยาก (FRIEND: Foreign body, Radiation, IBD, Epithelialization, Neoplasm, Distal obstruction). ผ่าตัดเมื่อ optimize แล้ว."}, {"topic": "General/GI Surgery", "q": "A 70-year-old man 7 days after midline laparotomy has serosanguineous wound discharge and a 'give' sensation; bowel is visible through the wound. What is the diagnosis?", "choices": ["Wound infection for this patient", "Incisional hernia as first step", "Seroma for this patient", "Hematoma for this patient", "Burst abdomen (fascial dehiscence)"], "ans": 4, "exp": "Burst abdomen (fascial dehiscence): แผลผ่าตัดแยกถึงชั้น fascia — สัญญาณเตือนคือ serosanguineous ('pink') discharge วันที่ ~5-8, อาจมี evisceration. เป็น surgical emergency → คลุมด้วยผ้าชุ่ม saline + ผ่าตัดปิดซ่อม. ปัจจัยเสี่ยง: ติดเชื้อ, ไอ, malnutrition, steroid."}, {"topic": "General/GI Surgery", "q": "A 25-year-old man has right lower quadrant pain, and Alvarado score is calculated. Which clinical feature is part of the Alvarado score for appendicitis?", "choices": ["Migratory RLQ pain", "Jaundice", "Hematuria", "Melena", "Splenomegaly"], "ans": 0, "exp": "Alvarado score (MANTRELS) สำหรับ appendicitis: Migration of pain, Anorexia, Nausea, Tenderness RLQ, Rebound, Elevated temp, Leukocytosis, Shift to left. คะแนนสูงสนับสนุนการวินิจฉัย/ผ่าตัด; กลางๆ → imaging (US/CT). ช่วยลด negative appendectomy."}, {"topic": "General/GI Surgery", "q": "A pregnant woman at 20 weeks has right-sided abdominal pain higher than usual; appendicitis is suspected. Which imaging is preferred to avoid radiation?", "choices": ["CT abdomen for this patient", "Ultrasound (then MRI if needed)", "Plain X-ray for this patient", "Barium enema for this patient", "PET scan for this patient"], "ans": 1, "exp": "Appendicitis ในหญิงตั้งครรภ์: ตำแหน่งปวดอาจสูงขึ้นตามมดลูกที่โต. Imaging เลือก ultrasound ก่อน (ไม่มีรังสี), ถ้าไม่ชัดใช้ MRI. หลีกเลี่ยง CT (รังสี). Appendicitis เป็นภาวะ non-obstetric surgical ที่พบบ่อยสุดในครรภ์ — ผ่าตัดเมื่อวินิจฉัย (ล่าช้าเสี่ยง perforation/fetal loss)."}, {"topic": "General/GI Surgery", "q": "A 68-year-old man has an obstructing left-sided colon cancer with distension. He is stable. Which option can relieve obstruction and allow one-stage surgery or bridge to surgery?", "choices": ["Immediate right hemicolectomy for this patient", "Barium enema for this patient", "Endoscopic stenting or resection with primary anastomosis", "Long-term laxatives for this patient", "Observation only"], "ans": 2, "exp": "Obstructing left colon cancer: ทางเลือกได้แก่ resection + primary anastomosis (± on-table lavage), Hartmann procedure (resection + end colostomy), หรือ 'self-expanding metal stent' เป็น bridge to surgery/palliation ในรายที่เหมาะสม. ประเมิน staging และสภาพผู้ป่วย."}, {"topic": "General/GI Surgery", "q": "A 55-year-old woman has multiple hundreds of colonic polyps and a family history of colon cancer at a young age. Genetic testing shows an APC mutation. What is the diagnosis?", "choices": ["Peutz-Jeghers syndrome", "Lynch syndrome in this case", "Juvenile polyposis initially", "Familial adenomatous polyposis", "Sporadic polyps in this case"], "ans": 3, "exp": "Familial adenomatous polyposis (FAP): APC gene mutation → polyps หลายร้อย-พันชิ้นในลำไส้ใหญ่ตั้งแต่วัยรุ่น, มะเร็งลำไส้เกือบ 100% ถ้าไม่รักษา → prophylactic total colectomy. เฝ้าระวัง extracolonic (desmoid, duodenal, thyroid). Lynch = mismatch repair, polyp น้อยกว่าแต่มะเร็งเร็ว."}, {"topic": "General/GI Surgery", "q": "A newborn is born with abdominal contents herniating through a defect to the right of the umbilical cord, without a covering sac. What is the diagnosis?", "choices": ["Prune belly syndrome", "Omphalocele", "Umbilical hernia", "Diaphragmatic hernia", "Gastroschisis"], "ans": 4, "exp": "Gastroschisis: ผนังหน้าท้องแยก 'ด้านขวาของสายสะดือ' ลำไส้โผล่ 'ไม่มีถุงหุ้ม' → เสี่ยงสูญเสียน้ำ/อุณหภูมิ, bowel injury. มักไม่สัมพันธ์ความผิดปกติอื่น. รักษา: คลุม bowel ชุ่ม/พันด้วย silo, สารน้ำ, ผ่าตัดปิด. ต่างจาก omphalocele (ผ่านสายสะดือ, มีถุงหุ้ม, สัมพันธ์ anomaly หลายอย่าง)."}, {"topic": "General/GI Surgery", "q": "A newborn has abdominal contents protruding through the umbilical ring covered by a membranous sac. This condition is associated with other anomalies. What is the diagnosis?", "choices": ["Omphalocele", "Gastroschisis", "Meckel diverticulum", "Umbilical hernia", "Patent urachus"], "ans": 0, "exp": "Omphalocele: อวัยวะโผล่ผ่าน 'umbilical ring' มี 'ถุงหุ้ม' (peritoneum/amnion) และสัมพันธ์กับความผิดปกติอื่น (cardiac, chromosomal - trisomy 13/18, Beckwith-Wiedemann). ต่างจาก gastroschisis (ไม่มีถุง, ด้านขวาสายสะดือ, มัก isolated). ประเมิน anomaly ร่วมและผ่าตัดปิด."}, {"topic": "General/GI Surgery", "q": "A neonate has severe respiratory distress at birth with a scaphoid abdomen and bowel sounds heard in the chest. Chest X-ray shows bowel loops in the left hemithorax. What is the diagnosis?", "choices": ["Pneumothorax", "Congenital diaphragmatic hernia", "Esophageal atresia", "Cystic adenomatoid malformation", "Pleural effusion"], "ans": 1, "exp": "Congenital diaphragmatic hernia (มัก left, Bochdalek): อวัยวะช่องท้องเลื่อนเข้าทรวงอก → respiratory distress, scaphoid abdomen, bowel sounds ในอก, mediastinal shift. ปัญหาหลักคือ pulmonary hypoplasia + pulmonary hypertension. รักษา: stabilize (intubate, ห้าม bag-mask นาน), แก้ pulmonary HT, แล้วผ่าตัดซ่อมเมื่อ stable."}, {"topic": "General/GI Surgery", "q": "A 30-year-old man from an endemic area has chronic right lower quadrant pain, weight loss, and a mass; colonoscopy shows ileocecal ulcers and biopsy shows caseating granulomas. What is the diagnosis?", "choices": ["Lymphoma", "Crohn disease", "Intestinal tuberculosis", "Appendiceal cancer", "Amoebiasis"], "ans": 2, "exp": "Intestinal tuberculosis (ชอบ ileocecal region): ปวด RLQ เรื้อรัง, น้ำหนักลด, ก้อน; biopsy พบ 'caseating' granuloma + AFB/PCR. ต่างจาก Crohn (non-caseating granuloma). รักษาด้วย anti-TB; ผ่าตัดเมื่อมีภาวะแทรกซ้อน (obstruction, perforation, fistula). พบบ่อยในไทย."}, {"topic": "General/GI Surgery", "q": "A 25-year-old man has typhoid fever for 2 weeks and suddenly develops severe abdominal pain with peritonitis and free air on X-ray. Where is the perforation most likely located?", "choices": ["Appendix", "Sigmoid colon", "Stomach", "Terminal ileum", "Duodenum"], "ans": 3, "exp": "Typhoid (enteric fever) perforation มักเกิดที่ 'terminal ileum' (Peyer patches necrosis) ในสัปดาห์ที่ 2-3 → peritonitis + pneumoperitoneum. เป็น surgical emergency: resuscitation, antibiotic ครอบคลุม Salmonella + gut flora, laparotomy ซ่อม/resection. พบในพื้นที่ endemic."}, {"topic": "General/GI Surgery", "q": "A 45-year-old woman has episodic flushing, diarrhea, and wheezing; urinary 5-HIAA is elevated, and imaging shows a small bowel mass with liver metastases. What is the diagnosis?", "choices": ["Pheochromocytoma for this patient", "VIPoma for this patient", "Gastrinoma for this patient", "Insulinoma for this patient", "Carcinoid tumor with carcinoid syndrome"], "ans": 4, "exp": "Carcinoid tumor (neuroendocrine, มัก small bowel/appendix) — carcinoid syndrome (flushing, diarrhea, wheezing, right heart valve disease) เกิดเมื่อมี liver metastasis (serotonin ไม่ถูก first-pass metabolism). วินิจฉัย: urinary 5-HIAA, chromogranin A. รักษา: octreotide, resection."}, {"topic": "General/GI Surgery", "q": "A 60-year-old man is 3 days post-op after abdominal surgery and has not passed flatus, with a distended, non-tender, silent abdomen and no air-fluid levels of obstruction. What is the diagnosis?", "choices": ["Paralytic ileus", "Anastomotic leak", "Mechanical obstruction", "Peritonitis", "Colonic pseudo-obstruction"], "ans": 0, "exp": "Postoperative paralytic ileus: ลำไส้ไม่บีบตัวชั่วคราวหลังผ่าตัด — ท้องอืด, silent bowel sounds, ไม่ผายลม, X-ray มีลมกระจายทั้ง small และ large bowel (ไม่มี transition point). รักษาประคับประคอง (NPO/NG, แก้เกลือแร่ - hypokalemia, ลด opioid, early mobilization). ต่างจาก mechanical obstruction."}, {"topic": "General/GI Surgery", "q": "A patient develops profuse watery diarrhea after a course of broad-spectrum antibiotics; stool tests positive for Clostridioides difficile toxin. What is the treatment?", "choices": ["Loperamide for this patient", "Oral vancomycin or fidaxomicin", "Metronidazole IV alone", "Ciprofloxacin as first step", "Probiotics only"], "ans": 1, "exp": "C. difficile infection (หลังยาปฏิชีวนะ): ท้องเสียเป็นน้ำ, toxin/PCR บวก, อาจ pseudomembranous colitis. รักษา (แนวทางปัจจุบัน): oral vancomycin หรือ fidaxomicin เป็น first-line (metronidazole สำหรับ non-severe ที่ไม่มีทางเลือก). Fulminant/toxic megacolon → colectomy. หยุดยาปฏิชีวนะต้นเหตุ, หลีกเลี่ยง antimotility."}, {"topic": "General/GI Surgery", "q": "A 55-year-old man with diabetes has severe perianal pain, fever, and crepitus with rapidly spreading necrosis of the perineum. What is the diagnosis and management?", "choices": ["Perianal abscess, drainage", "Anal fissure, sphincterotomy", "Fournier gangrene, emergency debridement", "Hemorrhoids, banding", "Cellulitis, oral antibiotics"], "ans": 2, "exp": "Fournier gangrene: necrotizing fasciitis ของ perineum/genitalia — พบในเบาหวาน/ภูมิคุ้มกันต่ำ, ลุกลามเร็ว, crepitus, ปวดเกินกว่าที่เห็น, sepsis. เป็น surgical emergency → broad-spectrum antibiotic + 'aggressive surgical debridement' ด่วน + resuscitation. อัตราตายสูงถ้าล่าช้า."}, {"topic": "General/GI Surgery", "q": "A 50-year-old man has an asymptomatic 1.5 cm gallbladder polyp found incidentally on ultrasound. What is the appropriate management?", "choices": ["Observation only", "ERCP", "Ursodeoxycholic acid", "Cholecystectomy", "Percutaneous drainage"], "ans": 3, "exp": "Gallbladder polyp: ขนาด ≥1 cm (หรือ ≥6-9 mm + ปัจจัยเสี่ยง เช่น อายุ >50, sessile, PSC) เสี่ยงมะเร็ง → แนะนำ cholecystectomy. Polyp <6 mm ไม่มีปัจจัยเสี่ยง → ติดตาม US. Polyp 1.5 cm → ผ่าตัด."}, {"topic": "General/GI Surgery", "q": "A 40-year-old woman has a firm 2 cm liver lesion found incidentally; it shows a central scar and is hypervascular. She is asymptomatic. What is the most likely benign diagnosis?", "choices": ["Hepatocellular carcinoma", "Hepatic adenoma", "Hemangioma", "Metastasis", "Focal nodular hyperplasia"], "ans": 4, "exp": "Focal nodular hyperplasia (FNH): benign, พบในหญิง, มี 'central scar' (stellate) + hypervascular, ไม่มีความเสี่ยงมะเร็ง/แตก → มักติดตามได้ ไม่ต้องผ่าตัด. ต่างจาก hepatic adenoma (สัมพันธ์ OC, เสี่ยงแตก/malignant → พิจารณาผ่าตัดถ้า >5 cm) และ HCC (บน chronic liver disease)."}, {"topic": "General/GI Surgery", "q": "A 60-year-old man with primary sclerosing cholangitis develops worsening jaundice and weight loss; MRCP shows a hilar biliary stricture. What malignancy should be suspected?", "choices": ["Cholangiocarcinoma", "Hepatocellular carcinoma", "Pancreatic cancer", "Gallbladder polyp", "Gastric cancer"], "ans": 0, "exp": "Cholangiocarcinoma (bile duct cancer): เสี่ยงในผู้มี primary sclerosing cholangitis, choledochal cyst, liver fluke (Opisthorchis - พบในอีสาน), hepatolithiasis. Hilar (Klatskin) tumor → obstructive jaundice + weight loss. Marker: CA 19-9. วินิจฉัย MRCP/ERCP + brush cytology. รักษา: resection ถ้า resectable (มักวินิจฉัยระยะท้าย)."}, {"topic": "General/GI Surgery", "q": "A 3-year-old boy has an empty right scrotum, and the testis is palpable in the inguinal canal. What is the appropriate management?", "choices": ["Observation until puberty", "Orchidopexy", "Herniorrhaphy only", "Orchidectomy", "Hormone therapy only"], "ans": 1, "exp": "Undescended testis (cryptorchidism): ถ้าไม่ลงเองภายใน ~6 เดือน → orchidopexy (นิยมทำก่อนอายุ 1-2 ปี) เพื่อลดความเสี่ยง infertility และให้คลำตรวจได้ (เสี่ยงมะเร็ง testis เพิ่มแม้ผ่าตัดแล้ว). Non-palpable testis → laparoscopy หา. ไม่รอถึง puberty."}, {"topic": "General/GI Surgery", "q": "A 45-year-old man has a reducible bulge at the umbilicus that increases with straining. He is asymptomatic. What is the management for a symptomatic or enlarging umbilical hernia?", "choices": ["Truss application", "Observation always", "Elective surgical repair", "Manual reduction only", "Sclerotherapy"], "ans": 2, "exp": "Umbilical hernia ในผู้ใหญ่ (ต่างจากเด็กที่มักหายเอง ≤4-5 ปี): ที่มีอาการ, ใหญ่ขึ้น, หรือเสี่ยง incarceration → elective repair (mesh). สัมพันธ์กับความดันในช่องท้องสูง (ascites, obesity, ตั้งครรภ์). Incarcerated/strangulated → ผ่าตัดฉุกเฉิน."}, {"topic": "General/GI Surgery", "q": "A malnourished patient started on aggressive feeding develops hypophosphatemia, hypokalemia, and hypomagnesemia. What is this syndrome?", "choices": ["Dumping syndrome", "Short bowel syndrome", "Tumor lysis syndrome", "Refeeding syndrome", "SIADH"], "ans": 3, "exp": "Refeeding syndrome: ในผู้ขาดอาหารรุนแรงที่เริ่มให้อาหารเร็วเกิน → insulin surge ดึง phosphate/potassium/magnesium เข้าเซลล์ → hypophosphatemia (เด่น), hypokalemia, hypomagnesemia → เสี่ยง arrhythmia/หัวใจล้มเหลว. ป้องกัน: เริ่มให้อาหารช้าๆ, เสริม thiamine, ติดตามเกลือแร่."}, {"topic": "General/GI Surgery", "q": "A patient with extensive small bowel resection has chronic diarrhea, malabsorption, and weight loss. What is the diagnosis?", "choices": ["Blind loop syndrome", "Dumping syndrome", "Chronic pancreatitis", "Celiac disease", "Short bowel syndrome"], "ans": 4, "exp": "Short bowel syndrome: หลังตัด small bowel มาก (เหลือ <200 cm) → malabsorption, ท้องเสีย, น้ำหนักลด, ขาดสารอาหาร/vitamin. รักษา: nutritional support (อาจ TPN), ยาลด motility/secretion, ค่อยๆ ปรับ enteral. Ileocecal valve และความยาวที่เหลือมีผลต่อ prognosis."}, {"topic": "General/GI Surgery", "q": "A 58-year-old man undergoing major abdominal cancer surgery needs venous thromboembolism prophylaxis. Which is appropriate perioperatively?", "choices": ["Mechanical plus pharmacologic prophylaxis", "No prophylaxis for this patient", "High-dose aspirin only", "Warfarin loading for this patient", "Therapeutic heparin infusion initially"], "ans": 0, "exp": "ผู้ป่วยผ่าตัดมะเร็งช่องท้อง = high VTE risk → แนะนำ mechanical (intermittent pneumatic compression) + pharmacologic prophylaxis (LMWH/heparin) และมัก extended prophylaxis ~4 สัปดาห์หลังผ่าตัดมะเร็ง. Early mobilization ช่วย. ประเมินความเสี่ยงเลือดออกร่วมด้วย."}, {"topic": "General/GI Surgery", "q": "A surgeon wants to reduce surgical site infection for a clean-contaminated colorectal operation. Which measure is most appropriate?", "choices": ["Antibiotics for 7 days postop for this patient", "Prophylactic antibiotic within 60 minutes before incision", "Shaving with a razor the night before for this patient", "Hypothermia during surgery for this patient", "No antibiotics needed for this patient"], "ans": 1, "exp": "การป้องกัน SSI: ให้ prophylactic antibiotic ครอบคลุมเชื้อที่คาด 'ภายใน 60 นาทีก่อนลงมีด' (ให้ครบก่อน incision), รักษา normothermia/normoglycemia/oxygenation, clipping (ไม่ใช้ razor), skin prep (chlorhexidine). ไม่จำเป็นต้องให้ยาปฏิชีวนะยาวหลังผ่าตัดใน clean case."}, {"topic": "General/GI Surgery", "q": "A 45-year-old man is diagnosed with ascending cholangitis with hypotension and confusion despite antibiotics. What is the most important definitive intervention?", "choices": ["Continue antibiotics only", "Cholecystectomy immediately", "Urgent biliary drainage (ERCP)", "Percutaneous liver biopsy", "Barium study"], "ans": 2, "exp": "Severe/suppurative cholangitis (Reynolds pentad: Charcot triad + hypotension + confusion) → ต้อง 'biliary decompression/drainage ด่วน' (ERCP + sphincterotomy/stent เป็นวิธีเลือก; ถ้าไม่ได้ใช้ PTBD หรือผ่าตัด) ร่วมกับ resuscitation + antibiotic. การให้ยาปฏิชีวนะอย่างเดียวไม่พอเมื่อมีการอุดกั้น."}, {"topic": "General/GI Surgery", "q": "A 30-year-old woman has a periumbilical hernia. During examination you note the defect is at the linea alba above the umbilicus. What type of hernia is this?", "choices": ["Spigelian hernia", "Femoral hernia", "Obturator hernia", "Epigastric hernia", "Lumbar hernia"], "ans": 3, "exp": "Epigastric hernia: ยื่นผ่าน linea alba 'เหนือสะดือ' (ระหว่าง xiphoid กับ umbilicus), มักเล็กและมี preperitoneal fat. Spigelian = ผ่าน semilunar line (ด้านข้าง). Obturator = ผ่าน obturator foramen (พบในหญิงสูงอายุผอม, Howship-Romberg sign). การระบุตำแหน่งช่วยแยกชนิด hernia."}, {"topic": "General/GI Surgery", "q": "A 55-year-old man with cirrhosis has ascites and develops fever and abdominal pain. Paracentesis shows 400 neutrophils/mm3. What is the diagnosis?", "choices": ["Pancreatic ascites", "Secondary peritonitis", "Tuberculous peritonitis", "Malignant ascites", "Spontaneous bacterial peritonitis"], "ans": 4, "exp": "Spontaneous bacterial peritonitis (SBP): ในผู้ป่วย cirrhosis + ascites — ไข้/ปวดท้อง + ascitic PMN ≥250/mm3 (โดยไม่มีแหล่งติดเชื้อในช่องท้องที่ผ่าตัดได้). รักษาด้วย cefotaxime/ceftriaxone + IV albumin (ลด hepatorenal syndrome). ป้องกันซ้ำด้วย norfloxacin. แยกจาก secondary peritonitis (polymicrobial, ต้องผ่าตัด)."}, {"topic": "General/GI Surgery", "q": "A 40-year-old woman has recurrent right upper quadrant pain; HIDA scan shows a gallbladder ejection fraction of 20% with no stones. What is the diagnosis?", "choices": ["Biliary dyskinesia", "Sphincter of Oddi stenosis", "Acute cholecystitis", "Choledocholithiasis", "Chronic pancreatitis"], "ans": 0, "exp": "Biliary dyskinesia (functional gallbladder disorder): อาการ biliary colic แต่ 'ไม่มีนิ่ว' + HIDA scan พบ gallbladder ejection fraction ต่ำ (<35-40%). รักษาด้วย cholecystectomy ในรายที่อาการเข้าได้และ EF ต่ำ. ต้องแยกสาเหตุอื่นของ RUQ pain ก่อน."}, {"topic": "General/GI Surgery", "q": "A 62-year-old man with a colonic adenocarcinoma is found to have three liver metastases confined to one lobe. He is otherwise fit. What is the potential management for resectable liver metastases?", "choices": ["Palliative care only", "Hepatic resection with chemotherapy", "Radiotherapy alone", "Observation for this patient", "Antibiotics for this patient"], "ans": 1, "exp": "Colorectal liver metastases ที่ resectable (จำกัด, ทำงานตับพอ) สามารถรักษาด้วย hepatic resection ± perioperative chemotherapy → ให้โอกาสหายระยะยาว. ประเมินโดยทีม multidisciplinary. Ablation/portal vein embolization ช่วยในบางราย. ต่างจากมะเร็งอื่นที่ metastasis มักหมายถึง palliative."}, {"topic": "General/GI Surgery", "q": "A 20-year-old man has painless rectal bleeding with multiple hamartomatous polyps and mucocutaneous pigmentation of the lips. What is the diagnosis?", "choices": ["Lynch syndrome", "Familial adenomatous polyposis", "Peutz-Jeghers syndrome", "Juvenile polyposis", "Cronkhite-Canada syndrome"], "ans": 2, "exp": "Peutz-Jeghers syndrome (STK11 mutation): hamartomatous polyps ทั่ว GI + mucocutaneous pigmentation (ริมฝีปาก/buccal). เสี่ยง intussusception, เลือดออก, และมะเร็งหลายชนิด (GI, เต้านม, รังไข่, ตับอ่อน). ต้อง surveillance. ต่างจาก FAP (adenomatous polyps, APC)."}, {"topic": "General/GI Surgery", "q": "A 50-year-old man has weight loss and iron-deficiency anemia. Colonoscopy is normal but capsule endoscopy shows an angiodysplasia in the small bowel. What is the significance of angiodysplasia?", "choices": ["A premalignant lesion", "An infectious lesion", "A congenital atresia", "A source of GI bleeding", "A parasitic infection"], "ans": 3, "exp": "Angiodysplasia (vascular ectasia): หลอดเลือดผิดปกติในผนัง GI (มัก right colon, small bowel) เป็นสาเหตุ GI bleeding (ซ่อนเร้น/ชัดเจน) โดยเฉพาะผู้สูงอายุ, สัมพันธ์กับ aortic stenosis (Heyde syndrome), CKD. รักษา: endoscopic coagulation; ดื้อ → embolization/resection."}, {"topic": "General/GI Surgery", "q": "A 68-year-old man with atherosclerosis has crampy left-sided abdominal pain and bloody diarrhea after an episode of hypotension. Colonoscopy shows mucosal edema at the splenic flexure. What is the diagnosis?", "choices": ["Diverticulitis", "Ulcerative colitis", "C. difficile colitis", "Colon cancer", "Ischemic colitis"], "ans": 4, "exp": "Ischemic colitis: มักผู้สูงอายุที่มี atherosclerosis/hypotension (low-flow) → ปวดท้องซ้าย + ถ่ายเป็นเลือด; ตำแหน่งเสี่ยงคือ 'watershed areas' (splenic flexure, rectosigmoid). ส่วนใหญ่ mucosal (หายด้วย supportive: IV fluid, bowel rest, antibiotic); transmural/gangrene → ผ่าตัด. ต่างจาก acute mesenteric ischemia (SMA, รุนแรงกว่า)."}]}, {"id": "surg2", "title": "Surgery ชุดที่ 2 — Trauma, Burns, Critical Care, Breast & Endocrine Surgery", "subject": "surg", "questions": [{"topic": "Trauma & Critical Care", "q": "A 25-year-old man is brought to the trauma bay after a motorcycle crash. According to ATLS, what is the first priority in the primary survey?", "choices": ["Airway with cervical spine control", "Breathing assessment initially", "Exposure of the patient alone", "Circulation control in this case", "Disability assessment initially"], "ans": 0, "exp": "ATLS primary survey เรียงตาม ABCDE: 'Airway with cervical spine protection' มาก่อนเสมอ (ทางเดินหายใจอุดตันฆ่าเร็วสุด) — พร้อมป้องกัน c-spine. ตามด้วย Breathing, Circulation (ห้ามเลือด), Disability (GCS/pupils), Exposure. จัดการปัญหาที่พบทันทีก่อนไปขั้นถัดไป."}, {"topic": "Trauma & Critical Care", "q": "A trauma patient is tachycardic and hypoxic with decreased breath sounds on the left, a trachea deviated to the right, and distended neck veins. What is the most critical immediate intervention?", "choices": ["Endotracheal intubation", "Needle decompression", "Pericardiocentesis", "Chest tube insertion first", "Emergency thoracotomy"], "ans": 1, "exp": "Tension pneumothorax: หายใจลำบาก + เสียงหายใจลด + trachea เบนไปด้านตรงข้าม + neck vein โป่ง + hypotension. เป็น clinical diagnosis (ไม่รอ X-ray) → 'needle decompression' ทันที (2nd ICS midclavicular หรือ 5th ICS anterior axillary) ตามด้วย chest tube. เป็นภาวะฉุกเฉินที่ต้องแก้ทันที."}, {"topic": "Trauma & Critical Care", "q": "A trauma patient has hypotension, muffled heart sounds, and distended neck veins after blunt chest trauma. What is the diagnosis (Beck triad)?", "choices": ["Tension pneumothorax", "Flail chest", "Cardiac tamponade", "Massive hemothorax", "Aortic rupture"], "ans": 2, "exp": "Cardiac tamponade — Beck triad: hypotension + muffled heart sounds + distended neck veins (JVP สูง). ยืนยันด้วย FAST (pericardial fluid). รักษา: pericardiocentesis เป็น bridge, definitive คือ pericardial window/thoracotomy. ต่างจาก tension pneumothorax (trachea เบน, เสียงหายใจลด)."}, {"topic": "Trauma & Critical Care", "q": "A trauma patient has decreased breath sounds and dullness to percussion on the left with hypotension; over 1500 mL of blood drains after chest tube insertion. What is the diagnosis?", "choices": ["Tension pneumothorax", "Cardiac tamponade", "Pulmonary contusion", "Massive hemothorax", "Simple pneumothorax"], "ans": 3, "exp": "Massive hemothorax: เสียงหายใจลด + percussion ทึบ (dull) + hypotension; chest tube ออกเลือด >1,500 mL ทันที หรือ >200 mL/ชม. × 2-4 ชม. → ข้อบ่งชี้ thoracotomy. รักษา: resuscitation + chest tube + พิจารณาผ่าตัด. ต่างจาก pneumothorax (percussion hyperresonant)."}, {"topic": "Trauma & Critical Care", "q": "A 30-year-old man has multiple rib fractures with a segment of chest wall that moves paradoxically with respiration. What is the diagnosis?", "choices": ["Diaphragmatic rupture", "Tension pneumothorax", "Massive hemothorax", "Cardiac tamponade", "Flail chest"], "ans": 4, "exp": "Flail chest: ซี่โครงหัก ≥2 ตำแหน่งต่อซี่ใน ≥2 ซี่ติดกัน → segment เคลื่อน 'paradoxical' (บุ๋มตอนหายใจเข้า). ปัญหาหลักคือ pulmonary contusion ข้างใต้ → hypoxia. รักษา: ควบคุมความปวด (ช่วยหายใจ), O2/ventilation support, กายภาพ; รุนแรง → intubation หรือ surgical fixation."}, {"topic": "Trauma & Critical Care", "q": "A trauma patient has lost an estimated 30-40% of blood volume, with tachycardia, hypotension, and confusion. What class of hemorrhagic shock is this?", "choices": ["Class III", "Class II", "Class I", "Class IV", "No shock"], "ans": 0, "exp": "Hemorrhagic shock (ATLS): Class I (<15%, ปกติ), Class II (15-30%, tachycardia, narrowed pulse pressure), Class III (30-40%, hypotension, tachycardia, confused, oliguria), Class IV (>40%, ใกล้ตาย). Class III เริ่มมี hypotension ชัด. รักษา: ห้ามเลือด + balanced resuscitation (blood products)."}, {"topic": "Trauma & Critical Care", "q": "A hypotensive blunt trauma patient has a positive FAST scan (free fluid in the abdomen). What is the most appropriate management?", "choices": ["CT abdomen then decide", "Exploratory laparotomy", "Diagnostic peritoneal lavage", "Observation and repeat FAST", "Angioembolization only"], "ans": 1, "exp": "Blunt abdominal trauma ที่ 'hemodynamically unstable' + FAST positive (free fluid) → 'exploratory laparotomy' ทันที (ไม่รอ CT). ผู้ป่วย stable + FAST positive → CT scan เพื่อ grade injury และพิจารณา non-operative management (โดยเฉพาะ solid organ). FAST ประเมิน hemoperitoneum/tamponade เร็วข้างเตียง."}, {"topic": "Trauma & Critical Care", "q": "A restrained driver has a 'seat belt sign' bruise across the lower abdomen. This is most associated with injury to which structures?", "choices": ["Rib and lung initially", "Myocardium in this case", "Small bowel and mesentery", "Liver only", "Kidney only"], "ans": 2, "exp": "Seat belt sign (รอยฟกช้ำตามแนวเข็มขัดที่ท้องน้อย) สัมพันธ์กับ 'small bowel/mesenteric injury' และ lumbar spine fracture (Chance fracture). แม้แรกรับ stable ก็ต้องเฝ้าระวัง/CT เพราะ hollow viscus injury อาจแสดงอาการช้า (peritonitis)."}, {"topic": "Trauma & Critical Care", "q": "A trauma patient has pelvic instability and hypotension. What is an appropriate immediate measure to reduce pelvic bleeding?", "choices": ["CT pelvis first", "Immediate laparotomy", "Traction of the legs", "Apply a pelvic binder", "Foley catheter only"], "ans": 3, "exp": "Unstable pelvic fracture + hypotension: 'pelvic binder' (ที่ระดับ greater trochanter) ลดปริมาตรและ stabilize เพื่อลดเลือดออก (venous/bony). ต่อด้วย resuscitation; ถ้ายัง unstable → angioembolization (arterial) หรือ preperitoneal packing. ประเมิน associated injury (urethra - ตรวจก่อนใส่ Foley)."}, {"topic": "Trauma & Critical Care", "q": "A 35-year-old man with severe facial trauma, midface instability, and active bleeding cannot maintain his airway. What is the most appropriate method to secure the airway?", "choices": ["Nasotracheal intubation", "Orotracheal intubation with RSI", "Await CT imaging", "Bag-mask ventilation only", "Cricothyroidotomy if intubation fails"], "ans": 4, "exp": "Severe midface/facial trauma ที่ airway เสี่ยง: หลีกเลี่ยง nasotracheal (เสี่ยง cribriform plate). พยายาม orotracheal intubation (RSI); ถ้าล้มเหลว/ทำไม่ได้ → 'surgical airway (cricothyroidotomy)'. ยึดหลัก 'definitive airway' เมื่อ protect ไม่ได้ (GCS ต่ำ, ทางเดินหายใจเสียหาย)."}, {"topic": "Trauma & Critical Care", "q": "A 30-year-old man has 50% total body surface area burns and weighs 80 kg. Using the Parkland formula (4 mL/kg/%TBSA), how should the calculated fluid be given?", "choices": ["Half over the first 8 hours, half over next 16 hours", "All as an immediate bolus for this patient", "Evenly over 24 hours for this patient", "Half over the first 4 hours for this patient", "Over 48 hours equally for this patient"], "ans": 0, "exp": "Parkland formula: 4 mL × น้ำหนัก(kg) × %TBSA ของ crystalloid (Ringer's lactate) ใน 24 ชม.แรก — ให้ 'ครึ่งแรกใน 8 ชม.แรก' (นับจากเวลาที่โดนไฟ) และครึ่งหลังใน 16 ชม.ถัดไป. ปรับตาม urine output (0.5 mL/kg/hr ผู้ใหญ่). ตัวอย่าง: 4×80×50 = 16,000 mL."}, {"topic": "Trauma & Critical Care", "q": "A burn victim has full-thickness circumferential burns of the forearm with a cold, pulseless hand. What is the most appropriate intervention?", "choices": ["Elevation only", "Escharotomy", "Fasciotomy", "Amputation", "Observation"], "ans": 1, "exp": "Circumferential full-thickness burn ทำให้ eschar แข็งรัด → compartment syndrome/ischemia (แขน) หรือจำกัดการหายใจ (ทรวงอก). รักษาด้วย 'escharotomy' (กรีด eschar ตามยาว) เพื่อคลายแรงกด. ต่างจาก fasciotomy (กรีดถึง fascia ใน compartment syndrome จาก crush/vascular)."}, {"topic": "Trauma & Critical Care", "q": "A house-fire victim has facial burns, singed nasal hairs, carbonaceous sputum, and hoarseness. What is the priority?", "choices": ["Delay intubation for this patient", "Oral antibiotics for this patient", "Early intubation for airway protection", "High-dose steroids for this patient", "Wait for edema to develop initially"], "ans": 2, "exp": "สัญญาณ inhalation injury (ขนจมูกไหม้, เสมหะดำ, เสียงแหบ, บวมใบหน้า/ในปาก) → airway edema จะแย่ลงเร็ว → 'early intubation' ก่อนบวมจนใส่ท่อไม่ได้. ประเมิน carbon monoxide (ให้ O2 100%) และ cyanide poisoning. อย่ารอ."}, {"topic": "Trauma & Critical Care", "q": "A construction worker sustained a high-voltage electrical injury with entry and exit wounds. Besides cardiac monitoring, what complication requires monitoring of urine output for pigment?", "choices": ["Hypernatremia for this patient", "Hyperkalemia only", "Refeeding syndrome in this case", "Rhabdomyolysis with myoglobinuria", "Fat embolism for this patient"], "ans": 3, "exp": "Electrical injury ทำให้กล้ามเนื้อลึกถูกทำลาย (แผลภายนอกอาจดูน้อยแต่ภายในมาก) → rhabdomyolysis → myoglobinuria → acute kidney injury. เฝ้าระวัง: อัตราการให้สารน้ำสูงกว่า Parkland เพื่อคง urine output, ปัสสาวะสีเข้ม/แดง, hyperkalemia, arrhythmia, compartment syndrome. ตรวจ CK."}, {"topic": "Trauma & Critical Care", "q": "A 45-year-old farmer is bitten by a pit viper 30 minutes ago; the limb is swollen and painful. What is the most appropriate first action?", "choices": ["Apply an arterial tourniquet for this patient", "Incise and suck the wound for this patient", "Give antivenom to everyone for this patient", "Apply ice packs for this patient", "Immobilize the limb and obtain coagulation studies"], "ans": 4, "exp": "Snakebite (pit viper/งูกลุ่มพิษต่อเลือด): ปฐมพยาบาล — ให้ผู้ป่วยนิ่ง, 'immobilize' แขนขาระดับหัวใจ, นำส่ง รพ., และประเมิน envenomation (coagulation studies - VCT/INR, platelet, local swelling). ให้ antivenom เมื่อมี systemic/severe local envenomation (ไม่ใช่ทุกราย). ห้าม tourniquet แน่น/กรีดดูด/ประคบน้ำแข็ง."}, {"topic": "Trauma & Critical Care", "q": "A 5-year-old is pulled from a pool, apneic but with a palpable pulse. What is the most critical next step?", "choices": ["Provide rescue breaths/ventilation", "Start chest compressions", "Establish IV access", "Administer epinephrine", "Perform cricothyroidotomy"], "ans": 0, "exp": "เด็กจมน้ำที่ apneic แต่ 'มีชีพจร' → ปัญหาหลักคือ respiratory (hypoxia) → ให้ 'rescue breaths/ventilation' ทันที (ในเด็ก respiratory arrest นำ cardiac arrest). ถ้าไม่มีชีพจร → เริ่ม CPR. Pediatric arrest ส่วนใหญ่เป็น respiratory/hypoxic origin ต่างจากผู้ใหญ่ (cardiac)."}, {"topic": "Trauma & Critical Care", "q": "A 50-year-old woman has a hard, fixed breast lump with skin dimpling and an enlarged axillary node. What is the appropriate diagnostic approach?", "choices": ["Reassure and repeat in 1 year in this case", "Triple assessment (clinical, imaging, biopsy)", "Antibiotics and observe for this patient", "Aspirate and discard for this patient", "Immediate mastectomy for this patient"], "ans": 1, "exp": "ก้อนเต้านมสงสัยมะเร็ง (แข็ง ติดแน่น ผิวบุ๋ม + axillary node): ประเมินด้วย 'triple assessment' — clinical exam + imaging (mammogram ± US, MRI บางราย) + core needle biopsy (histology). ยืนยันก่อนวางแผนรักษา (surgery ± chemo/RT/endocrine ตาม receptor/stage)."}, {"topic": "Trauma & Critical Care", "q": "A 60-year-old woman has newly diagnosed invasive ductal carcinoma. Which receptors must be assessed to guide systemic therapy?", "choices": ["CEA and CA 15-3", "AFP and hCG", "ER, PR, and HER2", "CA 19-9 only", "PSA and ALP"], "ans": 2, "exp": "Breast cancer ต้องตรวจ ER, PR (hormone receptor) และ HER2 (± Ki-67) เพื่อกำหนดการรักษา: ER/PR positive → endocrine therapy (tamoxifen/aromatase inhibitor); HER2 positive → trastuzumab; triple-negative → chemotherapy. เป็นตัวกำหนด systemic therapy และพยากรณ์โรค."}, {"topic": "Trauma & Critical Care", "q": "A 25-year-old woman has a mobile, well-defined 2 cm breast lump confirmed as a fibroadenoma by triple assessment. What is the appropriate management if it is small and stable?", "choices": ["Mastectomy for this patient", "Chemotherapy for this patient", "Radiotherapy for this patient", "Observation or excision if it grows", "Long-term tamoxifen in this case"], "ans": 3, "exp": "Fibroadenoma ที่ยืนยัน triple assessment ในหญิงสาว ขนาดเล็กและคงที่ → ติดตามได้ (มักคงที่/ฝ่อ). Excision ถ้าโตขึ้น, >2-3 cm, มีอาการ, ผลไม่สอดคล้อง หรือผู้ป่วยต้องการ. เป็น benign ไม่ใช่มะเร็ง."}, {"topic": "Trauma & Critical Care", "q": "A 40-year-old man has bilateral tender breast enlargement. Which is a common cause of gynecomastia to evaluate?", "choices": ["Endometriosis in this case", "Ovarian cyst in this case", "Pyloric stenosis initially", "Cholelithiasis initially", "Drugs and hormonal imbalance"], "ans": 4, "exp": "Gynecomastia (proliferation ของ glandular tissue) จากความไม่สมดุล estrogen:androgen — สาเหตุ: ยา (spironolactone, cimetidine, antipsychotics, anabolic steroid), liver/renal disease, hyperthyroid, hypogonadism, tumor (testicular, adrenal). แยกจาก pseudogynecomastia (ไขมัน) และมะเร็งเต้านมชาย (ก้อนแข็ง eccentric). ประเมินยา/ฮอร์โมน."}, {"topic": "Trauma & Critical Care", "q": "A 45-year-old woman has a solitary 2 cm thyroid nodule. Ultrasound shows suspicious features. What is the most appropriate next investigation?", "choices": ["Fine-needle aspiration cytology", "Thyroid scan for this patient", "Observation only", "Thyroidectomy as first step", "CT neck for this patient"], "ans": 0, "exp": "Thyroid nodule ที่มีลักษณะ US น่าสงสัย (hypoechoic, microcalcification, irregular margin, taller-than-wide) → 'fine-needle aspiration (FNA) cytology' (ตาม Bethesda system) เป็นการตรวจหลักแยก benign/malignant. Thyroid scan ใช้เมื่อ TSH ต่ำ (แยก autonomous 'hot' nodule ซึ่งไม่ค่อยเป็นมะเร็ง)."}, {"topic": "Trauma & Critical Care", "q": "A 35-year-old woman has a thyroid nodule; FNA shows papillary thyroid carcinoma. Which feature is characteristic of this cancer?", "choices": ["Spread mainly via blood", "Lymphatic spread with good prognosis", "Very poor prognosis", "Amyloid deposition", "Secretes catecholamines"], "ans": 1, "exp": "Papillary thyroid carcinoma (พบบ่อยสุด ~80%): แพร่ทาง 'lymphatic' (cervical nodes) แต่พยากรณ์ 'ดีมาก'. Histology: Orphan Annie nuclei, psammoma bodies. รักษา: thyroidectomy ± node dissection ± radioiodine. Follicular = hematogenous spread; Medullary = calcitonin/amyloid (MEN2); Anaplastic = พยากรณ์แย่มาก."}, {"topic": "Trauma & Critical Care", "q": "A patient with a thyroid nodule has an elevated calcitonin level and a family history of thyroid cancer and pheochromocytoma. Which cancer and syndrome is likely?", "choices": ["Papillary carcinoma, MEN1", "Lymphoma, sporadic", "Medullary carcinoma, MEN2", "Follicular carcinoma, MEN1", "Anaplastic carcinoma, MEN2"], "ans": 2, "exp": "Medullary thyroid carcinoma (จาก parafollicular C cells): หลั่ง 'calcitonin' (marker) + CEA, มี amyloid stroma. สัมพันธ์กับ MEN2 (RET mutation) — MTC + pheochromocytoma + parathyroid (2A)/mucosal neuroma (2B). ต้องตรวจ RET, คัดกรอง pheo ก่อนผ่าตัด, total thyroidectomy + central node dissection."}, {"topic": "Trauma & Critical Care", "q": "A patient has hypercalcemia, an elevated PTH, and kidney stones. Imaging localizes a single parathyroid adenoma. What is the diagnosis and treatment?", "choices": ["Secondary hyperparathyroidism, calcium", "Malignancy, chemotherapy", "Hypoparathyroidism, vitamin D", "Primary hyperparathyroidism, parathyroidectomy", "Sarcoidosis, steroids"], "ans": 3, "exp": "Primary hyperparathyroidism: hypercalcemia + PTH สูง (inappropriate) — 'stones, bones, groans, psychiatric moans'. สาเหตุบ่อยสุดคือ single parathyroid adenoma → localize (sestamibi/US) → 'parathyroidectomy' (รักษาหาย). Secondary = จาก CKD (Ca ต่ำ/PO4 สูง → PTH สูงชดเชย)."}, {"topic": "Trauma & Critical Care", "q": "A 40-year-old with episodic headache, palpitations, sweating, and severe hypertension has elevated plasma metanephrines and an adrenal mass. Before surgery, which must be started first?", "choices": ["Beta-blocker first for this patient", "Diuretic first for this patient", "ACE inhibitor first for this patient", "Calcium channel blocker only", "Alpha-blockade first, then beta-blocker"], "ans": 4, "exp": "Pheochromocytoma (catecholamine-secreting adrenal tumor): triad ปวดศีรษะ + ใจสั่น + เหงื่อ + HT เป็นพักๆ; วินิจฉัยด้วย plasma/urine metanephrines. เตรียมผ่าตัดต้อง 'alpha-blockade ก่อน' (phenoxybenzamine/doxazosin) 1-2 สัปดาห์ แล้วค่อยเพิ่ม beta-blocker — ห้ามให้ beta ก่อน alpha (เกิด unopposed alpha → hypertensive crisis)."}, {"topic": "Trauma & Critical Care", "q": "A 6 cm adrenal mass is found incidentally. Which features raise concern for malignancy (adrenocortical carcinoma)?", "choices": ["Large size and irregular features", "Small size and low density", "Bilateral small nodules", "High lipid content", "Homogeneous appearance"], "ans": 0, "exp": "Adrenal incidentaloma: ประเมิน (1) functional (hormone workup: cortisol/dexamethasone, metanephrines, aldosterone:renin) และ (2) malignant potential. ลักษณะเสี่ยงมะเร็ง (adrenocortical carcinoma/metastasis): ขนาดใหญ่ (>4-6 cm), irregular, heterogeneous, high HU (>10) non-contrast, โตเร็ว → ผ่าตัด. Small (<4 cm), lipid-rich, homogeneous มัก benign adenoma."}, {"topic": "Trauma & Critical Care", "q": "A 55-year-old man has severe pain, swelling, and rapidly spreading erythema of the leg with skin necrosis and crepitus, and is septic. What is the diagnosis and management?", "choices": ["Cellulitis, oral antibiotics for this patient", "Necrotizing fasciitis, urgent surgical debridement", "Abscess, drainage for this patient", "DVT, anticoagulation for this patient", "Erysipelas, penicillin for this patient"], "ans": 1, "exp": "Necrotizing fasciitis: ลุกลามเร็ว, ปวดเกินกว่าที่เห็น, ผิวคล้ำ/necrosis/bullae, crepitus, systemic toxicity. เป็น surgical emergency → 'early aggressive surgical debridement' + broad-spectrum antibiotic (รวม clindamycin) + resuscitation. LRINEC score ช่วยประเมิน. ล่าช้าตายสูง. ต่างจาก cellulitis (ผิวเผิน, ตอบสนองยา)."}, {"topic": "Trauma & Critical Care", "q": "A 30-year-old woman has an asymmetric, irregularly bordered, variably colored skin lesion that has enlarged. Biopsy is planned. Which cancer is suspected?", "choices": ["Basal cell carcinoma", "Seborrheic keratosis", "Melanoma", "Squamous cell carcinoma", "Actinic keratosis"], "ans": 2, "exp": "Melanoma — ABCDE: Asymmetry, Border irregular, Color variegation, Diameter >6 mm, Evolving. วินิจฉัยด้วย 'excisional biopsy' (full thickness) — Breslow thickness กำหนดพยากรณ์/margin. หลีกเลี่ยง shave biopsy. รักษา: wide local excision ± sentinel node ± systemic (immunotherapy/targeted)."}, {"topic": "Trauma & Critical Care", "q": "An elderly man has a slow-growing, pearly papule with rolled borders and central ulceration on the face that rarely metastasizes. What is the diagnosis?", "choices": ["Keratoacanthoma", "Squamous cell carcinoma", "Melanoma", "Basal cell carcinoma", "Actinic keratosis"], "ans": 3, "exp": "Basal cell carcinoma (BCC): มะเร็งผิวหนังที่พบบ่อยสุด — ตุ่ม pearly/waxy, rolled border, telangiectasia, central ulcer ('rodent ulcer'), บริเวณโดนแดด. โตช้า, ลุกลามเฉพาะที่, 'แทบไม่ metastasis'. รักษา: excision (± Mohs บริเวณใบหน้า). SCC โตเร็วกว่าและ metastasis ได้."}, {"topic": "Trauma & Critical Care", "q": "A patient has resistant hypertension, hypokalemia, and metabolic alkalosis; the aldosterone-to-renin ratio is high with an adrenal adenoma. What is the diagnosis?", "choices": ["Cushing syndrome for this patient", "Pheochromocytoma for this patient", "Addison disease for this patient", "Bartter syndrome for this patient", "Primary hyperaldosteronism (Conn syndrome)"], "ans": 4, "exp": "Primary hyperaldosteronism (Conn syndrome): HT ดื้อยา + hypokalemia + metabolic alkalosis + aldosterone:renin ratio สูง. สาเหตุ: adrenal adenoma (Conn) หรือ bilateral hyperplasia. Adenoma ข้างเดียว (ยืนยัน adrenal vein sampling) → adrenalectomy; hyperplasia → spironolactone/eplerenone. เป็นสาเหตุ secondary HT ที่รักษาได้."}, {"topic": "Trauma & Critical Care", "q": "A trauma patient opens eyes to pain, makes incomprehensible sounds, and withdraws from pain. What is his Glasgow Coma Scale score?", "choices": ["GCS 8", "GCS 6", "GCS 12", "GCS 10", "GCS 14"], "ans": 0, "exp": "GCS: Eye opening to pain = 2, Verbal incomprehensible sounds = 2, Motor withdrawal to pain = 4 → รวม = 8. GCS ≤8 = ข้อบ่งชี้ 'definitive airway' (intubation, 'GCS 8 = intubate'). GCS สูงสุด 15, ต่ำสุด 3. ใช้ประเมินระดับความรู้สึกตัวและติดตามการเปลี่ยนแปลง."}, {"topic": "Trauma & Critical Care", "q": "A soldier has severe arterial bleeding from a mangled limb that is not controlled by direct pressure. What is the appropriate immediate measure?", "choices": ["Elevate the limb only", "Apply a tourniquet proximal to the wound", "Apply ice for this patient", "Start IV antibiotics for this patient", "Wait for surgery for this patient"], "ans": 1, "exp": "เลือดออกจากหลอดเลือดแดงที่แขนขา ที่ direct pressure คุมไม่ได้ (exsanguinating) → ใช้ 'tourniquet' เหนือแผลทันที (บันทึกเวลา) เป็นมาตรการช่วยชีวิต. ต่อด้วย resuscitation และ definitive vascular control. ต่างจาก snakebite (ไม่ใช้ tourniquet)."}, {"topic": "Trauma & Critical Care", "q": "A massively bleeding trauma patient receives blood products. Which ratio approximates balanced resuscitation (massive transfusion protocol)?", "choices": ["Crystalloid only", "4:1:1 crystalloid ratio for this patient", "1:1:1 of packed cells, plasma, and platelets", "Plasma alone", "Platelets alone"], "ans": 2, "exp": "Massive transfusion / balanced resuscitation: ให้ packed RBC : FFP : platelet ในอัตราส่วนใกล้ '1:1:1' เพื่อป้องกัน trauma-induced coagulopathy. หลีกเลี่ยงการให้ crystalloid ปริมาณมาก (dilutional coagulopathy). ควบคุม 'lethal triad': hypothermia + acidosis + coagulopathy. ใช้ TXA ภายใน 3 ชม.และ damage control."}, {"topic": "Trauma & Critical Care", "q": "A trauma patient in extremis undergoes abbreviated surgery to control hemorrhage and contamination, with definitive repair delayed. What is this strategy called?", "choices": ["Elective staged repair", "Second-look laparotomy", "Definitive laparotomy", "Damage control surgery", "Conservative management"], "ans": 3, "exp": "Damage control surgery: ในผู้ป่วยวิกฤต (lethal triad) — ทำผ่าตัดสั้นๆ เพื่อ 'ห้ามเลือด + ควบคุมการปนเปื้อน' (packing, temporary closure) แล้วนำไป ICU แก้ physiology (อุ่น, แก้ acidosis/coagulopathy) ก่อนกลับมาผ่าตัด definitive ภายหลัง. ช่วยลดการตายในผู้ป่วยที่ทน prolonged surgery ไม่ไหว."}, {"topic": "Trauma & Critical Care", "q": "A man has a pelvic fracture with blood at the urethral meatus and inability to void. What must be done before urethral catheterization?", "choices": ["Insert Foley immediately", "CT abdomen only", "Suprapubic tap blindly", "No evaluation needed", "Retrograde urethrogram"], "ans": 4, "exp": "Pelvic fracture + blood at meatus + high-riding prostate + ไม่ปัสสาวะ = สงสัย 'urethral injury' → ห้ามใส่ Foley ก่อน (อาจทำให้บาดเจ็บเพิ่ม/สมบูรณ์) → ทำ 'retrograde urethrogram' ก่อน. ถ้ามี urethral injury → suprapubic catheter. Anterior/posterior urethral injury สัมพันธ์กับ pelvic trauma/straddle."}, {"topic": "Trauma & Critical Care", "q": "A trauma patient develops the 'lethal triad'. Which three components make it up?", "choices": ["Hypothermia, acidosis, coagulopathy", "Fever, leukocytosis, tachycardia", "Hypertension, bradycardia, apnea", "Hyperkalemia, acidosis, uremia", "Hypoxia, hypercarbia, acidosis"], "ans": 0, "exp": "Trauma lethal triad (vicious cycle): 'hypothermia + metabolic acidosis + coagulopathy' — เสริมกันทำให้เลือดออกไม่หยุดและตายสูง. การจัดการ: keep warm, balanced blood product resuscitation, TXA, damage control surgery, permissive hypotension (ในบางกรณี), หลีกเลี่ยง crystalloid มากเกิน."}, {"topic": "Trauma & Critical Care", "q": "A child weighing 20 kg has burns; a 60-year-old man has burns. Which burn characteristic makes a burn 'full-thickness' (third-degree)?", "choices": ["Painful and blistering", "Dry, leathery, insensate", "Red and blanching", "Superficial peeling", "Erythema only"], "ans": 1, "exp": "Burn depth: superficial (1st, แดง เจ็บ blanch), superficial partial (blister, เจ็บมาก, blanch), deep partial (เจ็บน้อยลง), full-thickness (3rd, 'dry, leathery, white/charred, insensate' - เส้นประสาทถูกทำลาย, ไม่ blanch). Full-thickness ต้อง excision + skin graft. ประเมินเพื่อวางแผนรักษา/ส่งต่อ."}, {"topic": "Trauma & Critical Care", "q": "Using the 'rule of nines' in an adult, burns to the entire anterior trunk and one whole arm represent approximately what percent TBSA?", "choices": ["9%", "18%", "27%", "45%", "36%"], "ans": 2, "exp": "Rule of nines (ผู้ใหญ่): ศีรษะ 9%, แขนแต่ละข้าง 9%, ลำตัวหน้า 18%, ลำตัวหลัง 18%, ขาแต่ละข้าง 18%, perineum 1%. Anterior trunk (18%) + แขนทั้งข้าง (9%) = 27%. ใช้ประเมิน %TBSA (นับเฉพาะ partial/full-thickness) เพื่อคำนวณสารน้ำและตัดสินใจส่งต่อ burn center."}, {"topic": "Trauma & Critical Care", "q": "A 55-year-old woman has an eczematous, scaly, ulcerated change of the nipple with underlying breast malignancy. What is the diagnosis?", "choices": ["Mastitis for this patient", "Fibrocystic change alone", "Duct ectasia in this case", "Paget disease of the nipple", "Eczema only"], "ans": 3, "exp": "Paget disease of the nipple: ผื่น eczematous/scaly/ulcerated ที่หัวนม (ไม่ตอบสนอง topical) มักสัมพันธ์กับ underlying breast cancer (DCIS/invasive). ต้อง biopsy หัวนม + ประเมินเต้านม (mammogram/MRI). ต่างจาก eczema (มักเริ่มที่ areola, ตอบสนอง steroid)."}, {"topic": "Trauma & Critical Care", "q": "A 45-year-old woman has a rapidly enlarging, erythematous, warm breast with 'peau d'orange' skin. What aggressive cancer must be considered?", "choices": ["Mastitis as first step", "Fibroadenoma initially", "Lipoma for this patient", "Fat necrosis initially", "Inflammatory breast cancer"], "ans": 4, "exp": "Inflammatory breast cancer: เต้านมแดง ร้อน บวม 'peau d'orange' (จาก dermal lymphatic invasion) โตเร็ว — เป็นมะเร็งรุนแรง (T4d) มักไม่มีก้อนชัด. ต้องแยกจาก mastitis (ตอบสนองยาปฏิชีวนะ). ถ้า 'mastitis' ไม่ดีขึ้นใน 1-2 สัปดาห์ ต้อง biopsy. รักษา: neoadjuvant chemo → surgery → RT."}, {"topic": "Trauma & Critical Care", "q": "At what age does routine screening mammography generally begin for average-risk women?", "choices": ["Age 40-50", "Age 20-25", "Age 70", "Age 60", "No screening needed"], "ans": 0, "exp": "คัดกรองมะเร็งเต้านมด้วย mammography เริ่มช่วงอายุ 40-50 ปี ทุก 1-2 ปี (แนวทางต่างกันเล็กน้อย). ผู้เสี่ยงสูง (BRCA, ประวัติครอบครัวชัดเจน, ประวัติฉายรังสีทรวงอก) เริ่มเร็วกว่าและอาจเสริม MRI. Clinical breast exam และ awareness ก็มีบทบาท."}, {"topic": "Trauma & Critical Care", "q": "A woman with breast cancer undergoes sentinel lymph node biopsy. What is its purpose?", "choices": ["To treat the primary tumor for this patient", "To stage the axilla and reduce full dissection", "To detect metastasis in bone as first step", "To remove all axillary nodes as first step", "To biopsy the breast for this patient"], "ans": 1, "exp": "Sentinel lymph node biopsy (SLNB): ระบุ node แรกที่รับน้ำเหลืองจากก้อน (dye/tracer) เพื่อ 'stage axilla' โดยไม่ต้องเลาะ node ทั้งหมด → ลด lymphedema/morbidity. ถ้า SLN บวก (จำนวนมาก) จึงพิจารณา axillary dissection/RT. ทำในผู้ที่ node ตรวจร่างกาย/US ปกติ (clinically node-negative)."}, {"topic": "Trauma & Critical Care", "q": "A 50-year-old woman has ductal carcinoma in situ (DCIS) on biopsy. What best describes DCIS?", "choices": ["Invasive cancer with metastasis alone", "A benign fibroadenoma for this patient", "Malignant cells confined within the ducts", "An infection of the duct as first step", "A normal variant for this patient"], "ans": 2, "exp": "Ductal carcinoma in situ (DCIS): เซลล์มะเร็งอยู่ 'ภายในท่อ' ยังไม่ทะลุ basement membrane (non-invasive, ไม่ metastasis) — เป็น precursor ของ invasive cancer. รักษา: breast-conserving surgery + RT หรือ mastectomy; ± endocrine therapy ถ้า ER positive. มักพบเป็น microcalcification จาก screening mammogram."}, {"topic": "Trauma & Critical Care", "q": "A 60-year-old man has hyperthyroidism from Graves disease and opts for surgery. What is a key preoperative preparation to avoid thyroid storm?", "choices": ["Give IV calcium for this patient", "Withhold all medication as first step", "Give high-dose steroids only", "Start beta-blocker and antithyroid drugs", "No preparation needed for this patient"], "ans": 3, "exp": "เตรียมผ่าตัด Graves (thyroidectomy): ต้องทำให้ euthyroid ก่อนด้วย antithyroid drug (methimazole/PTU) + beta-blocker (คุมอาการ) และให้ 'Lugol's iodine' ก่อนผ่าตัด ~10 วัน (ลด vascularity + Wolff-Chaikoff). ป้องกัน thyroid storm (ภาวะฉุกเฉิน: ไข้สูง, tachycardia, agitation) จากการปล่อยฮอร์โมนขณะผ่าตัด."}, {"topic": "Trauma & Critical Care", "q": "After a total thyroidectomy, a patient develops perioral numbness, tingling, and carpopedal spasm (positive Chvostek sign). What is the cause?", "choices": ["Hypoglycemia", "Hyperkalemia", "Recurrent laryngeal nerve injury", "Hypernatremia", "Hypocalcemia from hypoparathyroidism"], "ans": 4, "exp": "ภาวะแทรกซ้อนหลัง total thyroidectomy: 'hypocalcemia' จากการบาดเจ็บ/เอา parathyroid ออกโดยไม่ได้ตั้งใจ → ชา รอบปาก/ปลายมือ, tetany, Chvostek/Trousseau sign. รักษาด้วย calcium (± vitamin D/calcitriol). ภาวะแทรกซ้อนสำคัญอื่น: recurrent laryngeal nerve injury (เสียงแหบ), เลือดออก (airway compromise - hematoma)."}, {"topic": "Trauma & Critical Care", "q": "After thyroid surgery, a patient has a hoarse voice and difficulty with high-pitched sounds. Which nerve was likely injured?", "choices": ["Recurrent laryngeal nerve", "External branch of superior laryngeal nerve", "Vagus nerve trunk", "Hypoglossal nerve", "Phrenic nerve"], "ans": 0, "exp": "Recurrent laryngeal nerve injury (ข้างเดียว) → เสียงแหบ (vocal cord paralysis ด้าน paramedian); สองข้าง → airway obstruction (ฉุกเฉิน). External branch of superior laryngeal nerve injury → เสียงล้าเวลาออกเสียงสูง/ร้องเพลง (cricothyroid). ต้องระวังเส้นประสาทเหล่านี้ระหว่างผ่าตัดไทรอยด์."}, {"topic": "Trauma & Critical Care", "q": "A patient has recurrent peptic ulcers in unusual locations, diarrhea, and a high fasting gastrin level. What is the diagnosis?", "choices": ["Insulinoma in this case", "Zollinger-Ellison syndrome", "Carcinoid syndrome", "VIPoma for this patient", "Glucagonoma in this case"], "ans": 1, "exp": "Zollinger-Ellison syndrome (gastrinoma): เนื้องอกหลั่ง gastrin (มัก duodenum/pancreas) → กรดมากเกิน → แผลในกระเพาะ/ลำไส้หลายตำแหน่ง/ตำแหน่งผิดปกติ + ท้องเสีย. Fasting gastrin สูง (+ secretin test). สัมพันธ์กับ MEN1. รักษา: high-dose PPI + localize/resect tumor."}, {"topic": "Trauma & Critical Care", "q": "A patient has episodes of confusion and diaphoresis relieved by eating, with low glucose and high insulin/C-peptide during episodes. What is the diagnosis?", "choices": ["Pheochromocytoma", "Gastrinoma", "Insulinoma", "Glucagonoma", "Carcinoid"], "ans": 2, "exp": "Insulinoma (pancreatic neuroendocrine tumor หลั่ง insulin): Whipple triad — อาการ hypoglycemia + glucose ต่ำขณะมีอาการ + หายเมื่อให้น้ำตาล. ตรวจ 72-hour fast: insulin/C-peptide สูงขณะ glucose ต่ำ (แยก exogenous insulin ที่ C-peptide ต่ำ). สัมพันธ์ MEN1. รักษา: enucleation/resection."}, {"topic": "Trauma & Critical Care", "q": "A large retrosternal goiter causes positional dyspnea and a positive Pemberton sign. What is the main concern?", "choices": ["Malignant transformation only", "Hyperthyroidism only", "Hypocalcemia", "Airway/venous compression", "Vocal cord palsy"], "ans": 3, "exp": "Retrosternal (substernal) goiter: กดเบียด trachea (airway - dyspnea, stridor), esophagus (dysphagia), และ SVC/veins → Pemberton sign (ยกแขนเหนือศีรษะ → หน้าแดง/บวม/หายใจลำบาก จาก venous congestion). เป็นข้อบ่งชี้ผ่าตัด (thyroidectomy) แม้ euthyroid. ประเมิน airway ก่อนผ่าตัด."}, {"topic": "Trauma & Critical Care", "q": "A patient has a subcutaneous, mobile, non-tender, soft mass with a central punctum that occasionally discharges cheesy material. What is the diagnosis?", "choices": ["Abscess for this patient", "Lipoma for this patient", "Ganglion cyst initially", "Lymph node as first step", "Epidermoid (sebaceous) cyst"], "ans": 4, "exp": "Epidermoid/sebaceous cyst: ก้อนใต้ผิวหนัง เคลื่อนที่ได้กับผิวหนัง, มี 'central punctum', อาจมี keratin (cheesy) ออก. ติดเชื้อ → แดงเจ็บ (I&D). รักษา: excision ทั้งถุง (ป้องกันเป็นซ้ำ). ต่างจาก lipoma (นุ่ม เคลื่อนใต้ผิว ไม่มี punctum) และ ganglion (ใกล้ข้อ/เอ็น)."}, {"topic": "Trauma & Critical Care", "q": "A 30-year-old woman has a soft, rubbery, mobile, non-tender subcutaneous mass that has grown slowly. It transilluminates poorly. What is the most likely diagnosis?", "choices": ["Lipoma", "Sarcoma", "Sebaceous cyst", "Abscess", "Lymphoma"], "ans": 0, "exp": "Lipoma: เนื้องอกไขมัน benign — นุ่ม ยืดหยุ่น เคลื่อนที่ได้ ไม่เจ็บ โตช้า. มักไม่ต้องรักษา; excision ถ้าโต/มีอาการ/สงสัย. ลักษณะที่ควรระวัง sarcoma: โตเร็ว, ใหญ่ (>5 cm), ลึกใต้ fascia, ตรึงแน่น, เจ็บ → imaging + biopsy."}, {"topic": "Trauma & Critical Care", "q": "A patient steps on a rusty nail and has a contaminated puncture wound. His last tetanus booster was 8 years ago. What prophylaxis is appropriate?", "choices": ["No prophylaxis needed", "Tetanus toxoid booster", "Tetanus immunoglobulin only", "Antibiotics only", "Full 3-dose primary series"], "ans": 1, "exp": "Tetanus prophylaxis สำหรับแผลสกปรก/ทะลุ (tetanus-prone): ถ้าเคยได้ครบ ≥3 เข็มและเข็มสุดท้าย >5 ปี → ให้ 'tetanus toxoid booster' (Td/Tdap). ถ้าประวัติวัคซีนไม่ครบ/ไม่ทราบ + แผลสกปรก → ให้ทั้ง toxoid + tetanus immunoglobulin (TIG). แผลสะอาดที่เข็มสุดท้าย <10 ปีไม่ต้อง booster."}, {"topic": "Trauma & Critical Care", "q": "A patient is bitten on the hand by a cat, with a deep puncture wound. Besides wound care, which antibiotic covers the likely organism (Pasteurella)?", "choices": ["Ciprofloxacin alone", "Metronidazole", "Amoxicillin-clavulanate", "Vancomycin", "Azithromycin"], "ans": 2, "exp": "Cat/dog bite → Pasteurella multocida (และ anaerobes, Capnocytophaga) → 'amoxicillin-clavulanate' เป็น first-line prophylaxis/treatment. Cat bites (puncture ลึก) เสี่ยงติดเชื้อสูง. ล้างแผล, พิจารณาไม่เย็บปิดแผล bite (โดยเฉพาะมือ), tetanus, และ rabies prophylaxis ตามความเสี่ยง."}, {"topic": "Trauma & Critical Care", "q": "A firefighter rescued from a smoky building is confused with a headache and cherry-red skin; pulse oximetry reads normal. What is the diagnosis?", "choices": ["Cyanide poisoning only", "Simple smoke irritation", "Hypoglycemia", "Carbon monoxide poisoning", "Heat stroke"], "ans": 3, "exp": "Carbon monoxide poisoning: CO จับ hemoglobin (COHb) → tissue hypoxia; pulse oximeter 'อ่านปกติ' (แยก O2Hb กับ COHb ไม่ได้) → ต้องตรวจ carboxyhemoglobin (co-oximetry). อาการ: ปวดศีรษะ, สับสน, cherry-red (พบน้อย). รักษา: 100% O2 (± hyperbaric ในรายรุนแรง/ตั้งครรภ์/หมดสติ). ระวัง cyanide ร่วมในไฟไหม้."}, {"topic": "Trauma & Critical Care", "q": "A 70-year-old man has a firm, indurated, ulcerated skin lesion on the lower lip that has grown over months; he is a chronic smoker. What is the likely diagnosis?", "choices": ["Basal cell carcinoma", "Melanoma", "Keratoacanthoma", "Actinic keratosis", "Squamous cell carcinoma"], "ans": 4, "exp": "Squamous cell carcinoma (SCC): แผล/ก้อนแข็ง มี ulceration/crust บริเวณโดนแดด (ริมฝีปากล่าง, หู, หลังมือ), สัมพันธ์ UV/บุหรี่/immunosuppression/chronic wound (Marjolin ulcer). โตเร็วกว่า BCC และ 'metastasis ได้' (lymph node). วินิจฉัย biopsy; รักษา excision (margin) ± node. Actinic keratosis เป็น precursor."}, {"topic": "Trauma & Critical Care", "q": "A trauma patient becomes hypotensive during resuscitation and is found to have a distended abdomen with rising airway pressures and low urine output. What is the diagnosis?", "choices": ["Abdominal compartment syndrome", "Tension pneumothorax alone", "Cardiac tamponade initially", "Neurogenic shock initially", "Anaphylaxis for this patient"], "ans": 0, "exp": "Abdominal compartment syndrome: intra-abdominal pressure สูง (>20 mmHg) + organ dysfunction — ท้องตึง, airway pressure สูง (ดัน diaphragm), oliguria (กด renal), hypotension (ลด venous return). วัดด้วย bladder pressure. รักษา: decompression (medical → surgical decompressive laparotomy). พบหลัง massive resuscitation/trauma/packing."}, {"topic": "Trauma & Critical Care", "q": "A young man is stabbed in the chest and has a sucking chest wound with air movement through it. What is the initial management of this open pneumothorax?", "choices": ["Immediate thoracotomy", "Occlusive dressing taped on three sides", "Full airtight seal on four sides", "Oral antibiotics", "Observation"], "ans": 1, "exp": "Open pneumothorax ('sucking chest wound'): ปิดด้วย 'occlusive dressing taped on three sides' (flutter/one-way valve — ให้ลมออกได้ ป้องกันไม่ให้เข้า → ป้องกันกลายเป็น tension pneumothorax). ตามด้วย chest tube (ตำแหน่งอื่น) และผ่าตัดปิดแผล. ปิดสี่ด้านสนิทเสี่ยงเกิด tension."}, {"topic": "Trauma & Critical Care", "q": "A trauma patient has a widened mediastinum on chest X-ray after a high-speed deceleration injury. What injury must be excluded?", "choices": ["Esophageal rupture", "Rib fracture", "Traumatic aortic injury", "Pneumothorax", "Diaphragmatic hernia"], "ans": 2, "exp": "Widened mediastinum + deceleration injury (high-speed MVC/fall) → สงสัย 'traumatic aortic injury' (มักที่ aortic isthmus ใกล้ ligamentum arteriosum). ยืนยันด้วย CT angiography. รักษา: คุม BP/HR (impulse control) + repair (endovascular/open). เป็นสาเหตุการตายทันทีที่พบบ่อยใน blunt trauma."}, {"topic": "Trauma & Critical Care", "q": "A 40-year-old woman has a large, rapidly growing but well-circumscribed breast mass; histology shows a phyllodes tumor. What is the appropriate management?", "choices": ["Simple aspiration for this patient", "Antibiotics for this patient", "Observation for this patient", "Wide local excision with clear margins", "Radiotherapy alone"], "ans": 3, "exp": "Phyllodes tumor: fibroepithelial breast tumor ที่โตเร็ว, อาจใหญ่, มี benign/borderline/malignant. รักษาด้วย 'wide local excision with clear margins (≥1 cm)' เพราะเสี่ยง local recurrence; malignant phyllodes แพร่ทาง hematogenous (ไม่ค่อยไป node) → ไม่ต้องเลาะ axilla. ต่างจาก fibroadenoma (โตช้า, enucleate ได้)."}, {"topic": "Trauma & Critical Care", "q": "A patient is found unconscious in a cold environment with a core temperature of 29°C and bradycardia. What is the diagnosis and a key management principle?", "choices": ["Sepsis, give antibiotics for this patient", "Heat stroke, cool rapidly for this patient", "Hypoglycemia, give glucose only", "Stroke, give thrombolysis for this patient", "Hypothermia, rewarm gradually and handle gently"], "ans": 4, "exp": "Severe hypothermia (<30°C): bradycardia, ลดระดับความรู้สึกตัว, เสี่ยง arrhythmia (VF). รักษา: 'rewarming' (active internal/external), handle gently (การกระตุ้นทำให้ VF), ทำ CPR ต่อเนื่อง ('not dead until warm and dead'). ระวัง Osborn (J) wave ใน ECG. หลีกเลี่ยงการเคลื่อนย้ายรุนแรง."}, {"topic": "Trauma & Critical Care", "q": "A polytrauma patient is hypotensive with warm, dry skin, bradycardia, and neurologic deficit after a spinal injury. What type of shock is this?", "choices": ["Neurogenic shock", "Hypovolemic shock", "Anaphylactic shock", "Cardiogenic shock", "Septic shock"], "ans": 0, "exp": "Neurogenic shock (จาก spinal cord injury เหนือ T6): สูญเสีย sympathetic tone → vasodilation → hypotension + 'bradycardia' (ไม่ tachycardia) + ผิวอุ่นแห้ง. ต่างจาก hypovolemic (เย็นซีด tachycardia). รักษา: fluid + vasopressor (norepinephrine), atropine ถ้า bradycardia. ต้องแยก hemorrhagic shock ร่วมเสมอ (rule out bleeding ก่อน)."}, {"topic": "Trauma & Critical Care", "q": "A patient develops hypotension, urticaria, wheezing, and facial swelling minutes after an antibiotic. What is the first-line drug?", "choices": ["Intravenous fluids only", "Intramuscular epinephrine", "Intravenous hydrocortisone", "Oral antihistamine", "Nebulized salbutamol only"], "ans": 1, "exp": "Anaphylaxis (distributive shock จาก IgE): hypotension + urticaria + wheeze/angioedema หลังสัมผัส allergen. First-line = 'IM epinephrine' (0.3-0.5 mg, 1:1,000 ที่ต้นขา) ทันที, ซ้ำได้ทุก 5-15 นาที. เสริม: O2, IV fluid, antihistamine, steroid (ป้องกัน biphasic), airway. Epinephrine สำคัญสุด อย่ารีรอ."}, {"topic": "Trauma & Critical Care", "q": "A burn patient has burns to the face, hands, perineum, and a burn crossing a major joint. What does this warrant?", "choices": ["Discharge home", "Observation for 1 hour", "Referral to a burn center", "Outpatient dressing only", "Oral antibiotics only"], "ans": 2, "exp": "เกณฑ์ส่งต่อ burn center: partial thickness >10% TBSA, burns บริเวณ 'face, hands, feet, genitalia/perineum, major joints', full-thickness ทุกอายุ, electrical/chemical/inhalation injury, เด็ก, comorbidity, circumferential. บริเวณเหล่านี้มีผลต่อ function/cosmesis จึงควรส่งต่อผู้เชี่ยวชาญ."}, {"topic": "Trauma & Critical Care", "q": "A worker splashes a strong acid on the skin. What is the most important immediate management?", "choices": ["Neutralize with alkali", "Cover and wait", "Apply ointment", "Copious water irrigation", "Debride immediately"], "ans": 3, "exp": "Chemical burn (acid = coagulative necrosis, alkali = liquefactive ลึกกว่า): ปฐมพยาบาลคือ 'irrigate ด้วยน้ำปริมาณมากนานๆ' (ถอดเสื้อผ้าเปื้อน, ปัดผงแห้งก่อน). ห้าม neutralize (ปฏิกิริยาความร้อน). ยกเว้น hydrofluoric acid → ให้ calcium gluconate เพิ่ม (จับ fluoride, เสี่ยง hypocalcemia/arrhythmia)."}, {"topic": "Trauma & Critical Care", "q": "A 65-year-old man has a firm breast lump beneath the nipple. Male breast cancer should be suspected. Which is a risk factor?", "choices": ["Testicular torsion", "Varicocele", "Prostatitis", "Gynecomastia is protective", "Klinefelter syndrome and BRCA2"], "ans": 4, "exp": "Male breast cancer (พบน้อย, มัก ER-positive ductal): ปัจจัยเสี่ยง — Klinefelter syndrome (47,XXY), BRCA2 mutation, ประวัติครอบครัว, ฉายรังสี, ตับแข็ง/estrogen สูง. ก้อนแข็ง eccentric ใต้หัวนม + retraction. ประเมิน triple assessment. ต่างจาก gynecomastia (นุ่ม central, สองข้าง)."}, {"topic": "Trauma & Critical Care", "q": "A patient has a thyroid gland that is diffusely enlarged and painful with fever after a viral illness; ESR is high and radioiodine uptake is low. What is the diagnosis?", "choices": ["Subacute (de Quervain) thyroiditis", "Hashimoto thyroiditis initially", "Graves disease for this patient", "Thyroid cancer for this patient", "Toxic adenoma for this patient"], "ans": 0, "exp": "Subacute (de Quervain) thyroiditis: ต่อมไทรอยด์เจ็บ + ไข้หลัง viral infection, ESR สูง, 'radioiodine uptake ต่ำ' (ต่างจาก Graves ที่ uptake สูง) — ระยะแรก thyrotoxic (ปล่อยฮอร์โมนที่เก็บ) แล้ว hypothyroid ก่อนหาย. รักษา: NSAIDs/steroid + beta-blocker (อาการ). Self-limited ส่วนใหญ่."}, {"topic": "Trauma & Critical Care", "q": "A child has a midline neck mass that moves upward with tongue protrusion and swallowing. What is the diagnosis?", "choices": ["Lymph node", "Thyroglossal duct cyst", "Branchial cleft cyst", "Cystic hygroma", "Dermoid cyst"], "ans": 1, "exp": "Thyroglossal duct cyst: ก้อน 'กลางคอ' ที่เคลื่อนขึ้นเมื่อ 'แลบลิ้น/กลืน' (ติดกับ hyoid/foramen cecum). รักษา: Sistrunk procedure (excision cyst + midportion of hyoid) ป้องกันเป็นซ้ำ. ต้องยืนยันว่ามี normal thyroid อื่น. ต่างจาก branchial cleft cyst (ด้านข้างคอ, ขอบ SCM)."}, {"topic": "Trauma & Critical Care", "q": "A young adult has a smooth, fluctuant lateral neck mass at the anterior border of the sternocleidomastoid. What is the most likely diagnosis?", "choices": ["Thyroid nodule", "Thyroglossal duct cyst", "Branchial cleft cyst", "Carotid body tumor", "Lymphoma"], "ans": 2, "exp": "Branchial cleft cyst (มัก 2nd cleft): ก้อน 'ด้านข้างคอ' ที่ขอบหน้าของ sternocleidomastoid, อาจติดเชื้อ/เป็น sinus. รักษา: surgical excision. ในผู้ใหญ่ >40 ปีที่มี cystic neck mass ต้องแยก 'cystic metastasis จาก HPV-related oropharyngeal SCC' (biopsy/imaging) ก่อน."}, {"topic": "Trauma & Critical Care", "q": "A 55-year-old man has a painless, firm, enlarging cervical lymph node for weeks with weight loss and night sweats. What is the appropriate next step?", "choices": ["Reassure and observe", "Course of antibiotics", "Aspirate and discard", "Excisional lymph node biopsy", "Warm compress"], "ans": 3, "exp": "Persistent painless cervical lymphadenopathy (>2-4 สัปดาห์) + B symptoms (น้ำหนักลด, ไข้, เหงื่อกลางคืน) สงสัย lymphoma/malignancy → 'excisional biopsy' (ได้ architecture, ดีสำหรับ lymphoma). ในผู้ใหญ่ที่สงสัย metastatic SCC ควรตรวจ primary (ENT) ก่อน + FNA. ต่อมน้ำเหลืองที่แข็ง ติดแน่น โตขึ้นเรื่อยๆ น่ากังวล."}, {"topic": "Trauma & Critical Care", "q": "A diabetic patient has a deep foot ulcer with surrounding cellulitis and probing to bone. What complication must be evaluated?", "choices": ["Venous eczema", "Simple contact dermatitis", "Gout", "Cellulitis only", "Osteomyelitis"], "ans": 4, "exp": "Diabetic foot ulcer ที่ 'probe to bone' positive หรือแผลลึก/เรื้อรัง → เสี่ยง osteomyelitis (ยืนยันด้วย MRI/bone biopsy, X-ray อาจปกติช่วงแรก). รักษา: ควบคุมน้ำตาล, debridement, antibiotic (ตาม culture), off-loading, ประเมิน vascular (ABI). รุนแรง/ischemia → revascularization/amputation."}, {"topic": "Trauma & Critical Care", "q": "A patient has a deep wound contaminated with soil and develops crepitus, foul discharge, and rapidly spreading myonecrosis. Gram stain shows gram-positive rods. What is the diagnosis?", "choices": ["Gas gangrene (Clostridial myonecrosis)", "Contact dermatitis for this patient", "Simple cellulitis for this patient", "Erysipelas for this patient", "Abscess for this patient"], "ans": 0, "exp": "Gas gangrene (Clostridium perfringens myonecrosis): แผลลึกปนเปื้อนดิน → crepitus (gas), กล้ามเนื้อตายเร็ว, discharge เหม็น, systemic toxicity, gram-positive rods. เป็น surgical emergency → 'aggressive debridement/amputation' + penicillin + clindamycin ± hyperbaric O2. ล่าช้าตายสูง."}, {"topic": "Trauma & Critical Care", "q": "A long-bone fracture patient develops respiratory distress, confusion, and a petechial rash 24-48 hours after injury. What is the diagnosis?", "choices": ["Pulmonary embolism", "Fat embolism syndrome", "Pneumonia", "Cardiac tamponade", "Acute lung injury from transfusion"], "ans": 1, "exp": "Fat embolism syndrome: 24-72 ชม.หลัง long-bone/pelvic fracture — triad: respiratory distress (hypoxia) + neurologic (confusion) + petechial rash (axilla/conjunctiva). รักษาประคับประคอง (O2/ventilation) + early fracture fixation (ป้องกัน). ต่างจาก PE (thrombotic, ขาบวม)."}, {"topic": "Trauma & Critical Care", "q": "A patient trapped under rubble is released after hours; he develops dark urine, hyperkalemia, and acute kidney injury. What is the diagnosis?", "choices": ["Hemolytic anemia", "Fat embolism", "Crush syndrome (rhabdomyolysis)", "Compartment syndrome only", "Contrast nephropathy"], "ans": 2, "exp": "Crush syndrome: กล้ามเนื้อถูกกดทับนาน → rhabdomyolysis (myoglobin, CK สูง) → myoglobinuria (ปัสสาวะเข้ม) + AKI + 'hyperkalemia' (เสี่ยง arrhythmia/cardiac arrest เมื่อปล่อย) + hypocalcemia + metabolic acidosis. รักษา: aggressive IV fluid, ติดตาม/รักษา hyperkalemia, พิจารณา fasciotomy (compartment syndrome ร่วม)."}, {"topic": "Trauma & Critical Care", "q": "A patient with severe sepsis has hypotension despite adequate fluid resuscitation, warm extremities, and a high cardiac output. What type of shock is this?", "choices": ["Obstructive shock", "Cardiogenic shock", "Hypovolemic shock", "Septic (distributive) shock", "Neurogenic shock"], "ans": 3, "exp": "Septic shock (distributive): vasodilation → hypotension ที่ไม่ตอบสนอง fluid เพียงพอ, ต้องใช้ vasopressor + lactate สูง. ระยะแรก 'warm shock' (แขนขาอุ่น, high CO). รักษา (Surviving Sepsis): เพาะเชื้อ + antibiotic เร็ว, IV fluid (crystalloid ~30 mL/kg), norepinephrine (first-line vasopressor), source control."}, {"topic": "Trauma & Critical Care", "q": "A patient after acute myocardial infarction is hypotensive with cold, clammy skin, raised JVP, and pulmonary edema. What type of shock is this?", "choices": ["Hypovolemic shock", "Distributive shock", "Neurogenic shock", "Anaphylactic shock", "Cardiogenic shock"], "ans": 4, "exp": "Cardiogenic shock: pump failure (มัก post-MI) → hypotension + สัญญาณ congestion (JVP สูง, pulmonary edema, ผิวเย็นชื้น, oliguria). รักษา: revascularization (post-MI), inotrope/vasopressor, ± mechanical support (IABP/ECMO), หลีกเลี่ยง fluid overload. ต่างจาก hypovolemic (JVP ต่ำ)."}, {"topic": "Trauma & Critical Care", "q": "A woman has newly diagnosed early breast cancer that is HER2-positive. Which targeted therapy is added?", "choices": ["Trastuzumab", "Rituximab", "Tamoxifen", "Imatinib", "Bevacizumab"], "ans": 0, "exp": "HER2-positive breast cancer → เพิ่ม 'trastuzumab' (anti-HER2 monoclonal antibody) ± pertuzumab ร่วมกับ chemotherapy — เพิ่ม survival อย่างมาก. ต้องเฝ้าระวัง cardiotoxicity (ประเมิน LVEF). ER-positive → tamoxifen/AI. Triple-negative → chemotherapy ± immunotherapy."}, {"topic": "Trauma & Critical Care", "q": "A patient with Cushing syndrome is found to have an ACTH-secreting pituitary adenoma. What is this specific condition called?", "choices": ["Conn syndrome", "Cushing disease", "Addison disease", "Nelson syndrome", "Sheehan syndrome"], "ans": 1, "exp": "Cushing 'disease' = Cushing syndrome จาก 'ACTH-secreting pituitary adenoma' (สาเหตุ endogenous ที่พบบ่อยสุด). Cushing 'syndrome' = ภาวะ cortisol เกินจากสาเหตุใดก็ได้ (รวม exogenous steroid, adrenal tumor, ectopic ACTH). วินิจฉัย: dexamethasone suppression, ACTH, MRI pituitary. รักษา: transsphenoidal resection."}, {"topic": "Trauma & Critical Care", "q": "A 3-year-old has a large, painless abdominal mass crossing the midline; it is a neuroblastoma. Which is characteristic?", "choices": ["Is always benign for this patient", "Arises from kidney, does not cross midline for this patient", "Arises from adrenal/sympathetic chain, elevated urinary catecholamines", "Secretes insulin for this patient", "Secretes gastrin for this patient"], "ans": 2, "exp": "Neuroblastoma: เนื้องอกจาก 'neural crest/sympathetic chain/adrenal medulla' ในเด็กเล็ก — ก้อนในท้องที่ข้าม midline, urinary catecholamines (VMA/HVA) สูง, อาจมี 'raccoon eyes'/opsoclonus-myoclonus. ต่างจาก Wilms tumor (จากไต, ไม่ข้าม midline, hematuria). N-myc amplification = พยากรณ์แย่."}, {"topic": "Trauma & Critical Care", "q": "A 4-year-old has a painless, unilateral abdominal mass confined to one side, with hematuria and hypertension. Which tumor is likely?", "choices": ["Neuroblastoma in this case", "Hepatoblastoma initially", "Rhabdomyosarcoma initially", "Wilms tumor (nephroblastoma)", "Lymphoma for this patient"], "ans": 3, "exp": "Wilms tumor (nephroblastoma): มะเร็งไตในเด็ก (~2-5 ปี) — ก้อนในท้อง 'ไม่ข้าม midline', hematuria, hypertension (renin). สัมพันธ์ WAGR/Beckwith-Wiedemann. รักษา: nephrectomy + chemo ± RT, พยากรณ์ดี. หลีกเลี่ยงคลำก้อนแรงๆ (เสี่ยงแตก). ต่างจาก neuroblastoma (ข้าม midline, catecholamine)."}, {"topic": "Trauma & Critical Care", "q": "A patient has recurrent hyperparathyroidism, a pancreatic neuroendocrine tumor, and a pituitary adenoma. Which syndrome is this?", "choices": ["MEN2B", "MEN2A", "Von Hippel-Lindau", "Neurofibromatosis", "MEN1"], "ans": 4, "exp": "MEN1 (Wermer, MEN1 gene) = '3 Ps': Parathyroid hyperplasia (hyperparathyroidism - พบบ่อยสุด/แรกสุด), Pancreatic/duodenal NET (gastrinoma, insulinoma), Pituitary adenoma. MEN2A = medullary thyroid CA + pheochromocytoma + parathyroid (RET). MEN2B = MTC + pheo + mucosal neuroma + marfanoid."}, {"topic": "Trauma & Critical Care", "q": "A woman has a breast abscess while breastfeeding, with a fluctuant tender mass. What is the appropriate management?", "choices": ["Drainage (aspiration/incision) plus antibiotics", "Continue antibiotics only", "Mastectomy for this patient", "Stop breastfeeding permanently as first step", "Observation for this patient"], "ans": 0, "exp": "Breast abscess (มัก S. aureus, ภาวะแทรกซ้อนของ mastitis): คลำได้ก้อน fluctuant → 'drainage' (needle aspiration ภายใต้ US สำหรับก้อนเล็ก หรือ I&D) + antibiotic + ให้นม/ปั๊มออกต่อ. ในหญิงไม่ให้นมที่เป็นซ้ำ ระวัง underlying malignancy (biopsy)."}, {"topic": "Trauma & Critical Care", "q": "A screening mammogram shows clustered, pleomorphic microcalcifications. What do these most commonly indicate?", "choices": ["Simple cyst initially", "Ductal carcinoma in situ", "Lipoma as first step", "Normal breast alone", "Fat necrosis initially"], "ans": 1, "exp": "Clustered pleomorphic/branching microcalcifications บน mammogram เป็นลักษณะที่น่าสงสัย 'DCIS' (หรือ invasive) → ต้อง stereotactic core biopsy. ต่างจาก benign calcification (coarse, popcorn-like ใน fibroadenoma; rim/eggshell ใน cyst). BI-RADS ช่วยจัดระดับความเสี่ยง."}, {"topic": "Trauma & Critical Care", "q": "A patient with locally advanced breast cancer is treated with chemotherapy before surgery. What is this approach called?", "choices": ["Palliative chemotherapy", "Adjuvant chemotherapy", "Neoadjuvant chemotherapy", "Salvage therapy", "Consolidation therapy"], "ans": 2, "exp": "Neoadjuvant chemotherapy = ให้เคมีบำบัด 'ก่อนผ่าตัด' — ลดขนาดก้อน (อาจทำ breast-conserving ได้แทน mastectomy), ประเมินการตอบสนอง (pathologic complete response = พยากรณ์ดี), และรักษา micrometastasis. ใช้ใน locally advanced/inflammatory/triple-negative/HER2-positive. Adjuvant = ให้หลังผ่าตัด."}, {"topic": "Trauma & Critical Care", "q": "A patient presents with acute adrenal crisis (hypotension, hyponatremia, hyperkalemia, hypoglycemia). What is the immediate treatment?", "choices": ["Oral prednisolone next day", "IV insulin", "Beta-blocker", "IV hydrocortisone and fluids", "Vasopressin only"], "ans": 3, "exp": "Adrenal crisis (acute adrenal insufficiency): hypotension ดื้อ fluid + hyponatremia + hyperkalemia + hypoglycemia (± ประวัติหยุด steroid/Addison/adrenal hemorrhage-Waterhouse-Friderichsen). รักษาทันที: 'IV hydrocortisone 100 mg' + IV fluid (normal saline + dextrose) + แก้เกลือแร่. อย่ารอผลตรวจ. หา precipitant (infection)."}, {"topic": "Trauma & Critical Care", "q": "A 30-year-old woman has a painful axillary and groin skin condition with recurrent abscesses, sinus tracts, and scarring. What is the diagnosis?", "choices": ["Simple furuncle", "Sebaceous cyst", "Lymphadenitis", "Pilonidal disease", "Hidradenitis suppurativa"], "ans": 4, "exp": "Hidradenitis suppurativa: การอักเสบเรื้อรังของ apocrine gland-bearing areas (รักแร้, ขาหนีบ, ใต้ราวนม) → ฝีซ้ำ, sinus tract, พังผืด. สัมพันธ์ obesity/สูบบุหรี่. รักษา: หยุดบุหรี่/ลดน้ำหนัก, topical/oral antibiotic, biologics (adalimumab), ผ่าตัด wide excision ในรายรุนแรง."}, {"topic": "Trauma & Critical Care", "q": "A patient has a firm, cystic swelling on the dorsum of the wrist that transilluminates and is attached to a tendon sheath. What is the diagnosis?", "choices": ["Ganglion cyst", "Lipoma", "Rheumatoid nodule", "Sebaceous cyst", "Sarcoma"], "ans": 0, "exp": "Ganglion cyst: ถุงน้ำ (mucin) ใกล้ข้อ/tendon sheath (พบบ่อยที่หลังข้อมือ) — แข็ง/ยืดหยุ่น, transilluminate ได้, สัมพันธ์กับ joint/tendon. ส่วนใหญ่ benign และหายเองได้; รักษา: aspiration (เป็นซ้ำบ่อย) หรือ excision ถ้ามีอาการ. ไม่แนะนำทุบด้วยหนังสือ (โบราณ)."}, {"topic": "Trauma & Critical Care", "q": "A patient with severe hyperthyroidism develops high fever, agitation, tachyarrhythmia, and heart failure after an infection. What is the diagnosis and a key treatment?", "choices": ["Adrenal crisis, hydrocortisone", "Thyroid storm, beta-blocker and antithyroid drugs", "Sepsis, antibiotics only", "Malignant hyperthermia, dantrolene", "Neuroleptic malignant syndrome, bromocriptine"], "ans": 1, "exp": "Thyroid storm (thyrotoxic crisis): ภาวะฉุกเฉิน — ไข้สูง, agitation/delirium, tachyarrhythmia/AF, heart failure, GI symptoms, มักมี precipitant (infection, surgery, iodine). รักษา: beta-blocker (propranolol), antithyroid (PTU), iodine (หลัง PTU ≥1 ชม.), hydrocortisone, cooling, รักษา precipitant. Burch-Wartofsky score ช่วยประเมิน."}, {"topic": "Trauma & Critical Care", "q": "A trauma patient sustains blunt chest trauma and has ECG changes and elevated troponin without coronary disease. What is the likely diagnosis?", "choices": ["Aortic dissection", "Acute coronary thrombosis", "Myocardial (cardiac) contusion", "Pericarditis", "Pulmonary embolism"], "ans": 2, "exp": "Myocardial contusion (blunt cardiac injury): จาก blunt chest trauma (steering wheel) → ECG ผิดปกติ (arrhythmia, ST changes), troponin สูง, wall motion abnormality (echo). รักษา: cardiac monitoring (arrhythmia), supportive. เฝ้าระวัง arrhythmia/heart failure. สัมพันธ์กับ sternal fracture."}, {"topic": "Trauma & Critical Care", "q": "A 50-year-old man has a slowly enlarging, painless mass deep to the fascia of the thigh that is over 5 cm and firm. What must be excluded?", "choices": ["Hematoma", "Simple lipoma", "Abscess", "Soft tissue sarcoma", "Cyst"], "ans": 3, "exp": "ก้อน soft tissue ที่ 'ใหญ่ >5 cm, ลึกใต้ fascia, แข็ง, โตขึ้น, เจ็บ' → ต้องแยก soft tissue sarcoma → MRI + 'core/incisional biopsy' (วางแนวให้ตัดออกได้ในผ่าตัดภายหลัง, หลีกเลี่ยง excisional biopsy ที่ทำไม่ถูกหลัก). รักษา: wide excision ± RT โดยทีมเฉพาะทาง. อย่าคิดว่าเป็น lipoma เสมอ."}, {"topic": "Trauma & Critical Care", "q": "A trauma patient's chest X-ray shows the stomach bubble in the left chest and a nasogastric tube tip in the thorax after blunt trauma. What is the diagnosis?", "choices": ["Tension pneumothorax alone", "Hemothorax for this patient", "Hiatal hernia as first step", "Esophageal rupture initially", "Traumatic diaphragmatic rupture"], "ans": 4, "exp": "Traumatic diaphragmatic rupture (มักด้านซ้าย จาก blunt trauma): อวัยวะช่องท้องเลื่อนเข้าทรวงอก — CXR เห็น gastric bubble/NG tube ในอก, bowel loops. อาจแสดงอาการช้า (herniation). วินิจฉัย CT; รักษาด้วยผ่าตัดซ่อม. เฝ้าระวัง associated injuries."}, {"topic": "Trauma & Critical Care", "q": "A trauma patient has a lung injury with hypoxia and patchy consolidation on CT developing over hours after blunt chest trauma, without pneumothorax. What is the diagnosis?", "choices": ["Pulmonary contusion", "Aspiration pneumonia", "Pulmonary embolism", "ARDS from sepsis", "Atelectasis"], "ans": 0, "exp": "Pulmonary contusion: เลือดออก/edema ในเนื้อปอดจาก blunt chest trauma — hypoxia + infiltrate ที่แย่ลงใน 24-48 ชม. (ไม่ตรงกับ anatomical border). รักษาประคับประคอง: O2/ventilation, ควบคุมสารน้ำ (เลี่ยง overload), analgesia, กายภาพ. เป็นภาวะที่ทำให้ flail chest อันตราย."}, {"topic": "Trauma & Critical Care", "q": "A 45-year-old woman has bloody discharge from a single duct of one breast. What is the appropriate evaluation?", "choices": ["Reassure and observe for this patient", "Imaging and evaluation for papilloma/carcinoma", "Dopamine agonist for this patient", "Antibiotics for this patient", "Squeeze it out regularly for this patient"], "ans": 1, "exp": "Pathologic nipple discharge (ข้างเดียว, ท่อเดียว, เป็นเลือด/serosanguineous, spontaneous) → สาเหตุบ่อยคือ intraductal papilloma (benign) แต่ต้องแยกมะเร็ง (DCIS) → mammogram/US ± ductography/MRI + biopsy/duct excision. ต่างจาก galactorrhea (bilateral, milky, prolactin)."}, {"topic": "Trauma & Critical Care", "q": "A patient after subtotal thyroidectomy develops sudden neck swelling, difficulty breathing, and stridor. What is the immediate management?", "choices": ["Give nebulized adrenaline only", "Await CT neck", "Open the wound to evacuate hematoma", "High-dose steroids only", "Reassure and observe"], "ans": 2, "exp": "Post-thyroidectomy hematoma → airway compression (คอบวมเร็ว, stridor, หายใจลำบาก) = ภาวะฉุกเฉิน → 'เปิดแผลระบายเลือด (evacuate hematoma) ข้างเตียงทันที' เพื่อคลาย airway แล้วจึงกลับห้องผ่าตัด. อย่ารอ imaging. เป็นภาวะแทรกซ้อนที่อันตรายถึงชีวิตในชั่วโมงแรกๆ."}, {"topic": "Trauma & Critical Care", "q": "A young man has painless testicular enlargement; ultrasound shows a solid intratesticular mass and tumor markers (AFP, beta-hCG) are elevated. What is the appropriate surgical approach?", "choices": ["Trans-scrotal biopsy", "Observation", "Fine-needle aspiration", "Radical inguinal orchidectomy", "Testicular-sparing enucleation"], "ans": 3, "exp": "Testicular tumor (germ cell - seminoma/non-seminoma): ก้อนแข็งในลูกอัณฑะ, marker AFP/β-hCG/LDH. การวินิจฉัย/รักษาคือ 'radical inguinal orchidectomy' (ห้ามเจาะ/ผ่าทาง scrotum → เสี่ยง seeding). Staging CT + markers; เสริม chemo/RT/RPLND ตามชนิด/ระยะ. พยากรณ์ดี (โดยเฉพาะ seminoma)."}, {"topic": "Trauma & Critical Care", "q": "A burn patient's fluid resuscitation is being monitored. What is the best endpoint of adequate resuscitation in an adult?", "choices": ["Blood pressure over 140", "Heart rate under 60", "Central venous pressure of 15", "Skin color only", "Urine output 0.5 mL/kg/hr"], "ans": 4, "exp": "เป้าหมายการให้สารน้ำใน burn (ผู้ใหญ่) = urine output ~0.5 mL/kg/hr (เด็ก ~1 mL/kg/hr) — Parkland เป็นเพียงจุดเริ่มต้น ต้องปรับตาม urine output/perfusion. ให้มากเกิน (fluid creep) → ภาวะแทรกซ้อน (compartment syndrome, edema). ใน 24 ชม.แรกใช้ crystalloid."}, {"topic": "Trauma & Critical Care", "q": "A patient has a hard, irregular thyroid nodule fixed to surrounding tissue with hoarseness and a rapidly enlarging neck mass in an elderly patient. Which aggressive cancer is likely?", "choices": ["Anaplastic thyroid carcinoma", "Papillary carcinoma", "Follicular adenoma", "Subacute thyroiditis", "Colloid nodule"], "ans": 0, "exp": "Anaplastic thyroid carcinoma: พบในผู้สูงอายุ — ก้อนคอโตเร็วมาก, แข็ง, ตรึงแน่น, กดเบียด (hoarseness, dyspnea, dysphagia). เป็นมะเร็งที่ 'ร้ายแรงที่สุด/พยากรณ์แย่มาก' (survival เป็นเดือน). มักลุกลามเกินผ่าตัด → ประคับประคอง airway + chemo/RT. ต่างจาก papillary (พยากรณ์ดี)."}, {"topic": "Trauma & Critical Care", "q": "A patient with a large goiter is scheduled for surgery. Which preoperative assessment is important to detect airway compromise?", "choices": ["Check serum calcium only", "Assess for tracheal deviation/compression", "Measure BMI only", "Skin testing for this patient", "No assessment needed for this patient"], "ans": 1, "exp": "ก่อนผ่าตัด goiter ใหญ่/retrosternal ต้องประเมิน airway: tracheal deviation/compression (CT/flow-volume loop), อาการ dyspnea/stridor/positional. ช่วยวางแผน anesthesia (difficult airway) และการผ่าตัด. หลังผ่าตัดเฝ้าระวัง tracheomalacia, hematoma, และ recurrent laryngeal nerve/hypocalcemia."}, {"topic": "Trauma & Critical Care", "q": "A patient is stung/bitten and develops isolated local swelling and pain without systemic symptoms or coagulopathy after a snakebite. What is the appropriate management?", "choices": ["Give antivenom immediately for this patient", "Apply arterial tourniquet for this patient", "Observe with serial coagulation studies and limb monitoring", "Incise and suck the wound for this patient", "Amputate the limb for this patient"], "ans": 2, "exp": "Snakebite ที่มีเฉพาะ local envenomation เล็กน้อย โดยไม่มี systemic/severe local signs → 'สังเกตอาการ' + ติดตาม coagulation (VCT/INR, platelet) และ progression ของ swelling เป็นระยะ (≥24 ชม.). ให้ antivenom เมื่อมีข้อบ่งชี้ (systemic envenomation, severe/progressive local, coagulopathy) — ไม่ให้ทุกราย (เสี่ยง reaction)."}, {"topic": "Trauma & Critical Care", "q": "A previously well patient after major surgery has decreased urine output; labs suggest prerenal acute kidney injury. What is the initial management?", "choices": ["Nephrotoxic contrast study alone", "Immediate dialysis as first step", "Loop diuretic bolus as first step", "Fluid challenge to restore perfusion", "Fluid restriction for this patient"], "ans": 3, "exp": "Postoperative prerenal AKI (จาก hypovolemia/hypoperfusion): oliguria, BUN/Cr ratio สูง, FeNa <1%, urine เข้มข้น. รักษาเบื้องต้น: 'fluid challenge' เพื่อฟื้น renal perfusion + แก้สาเหตุ (เลือดออก, sepsis), หยุด nephrotoxin. ไม่ตอบสนอง/overload/hyperkalemia/uremia → พิจารณา dialysis. Diuretic ไม่แก้ prerenal."}, {"topic": "Trauma & Critical Care", "q": "A woman with a breast lump has a benign-appearing cyst on ultrasound; aspiration yields clear fluid and the lump resolves completely. What is the next step?", "choices": ["Repeated aspiration weekly", "Excisional biopsy", "Mastectomy", "Chemotherapy", "Reassurance and routine follow-up"], "ans": 4, "exp": "Simple breast cyst ที่เจาะดูดได้ของเหลว 'ใส' (ไม่มีเลือด) และก้อนยุบหมด → benign, reassure + ติดตามปกติ. ถ้าของเหลวเป็นเลือด, ก้อนไม่ยุบหมด, หรือกลับเป็นซ้ำ → imaging + biopsy (แยก intracystic/complex lesion). เป็นส่วนหนึ่งของ triple assessment."}]}, {"id": "surg3", "title": "Surgery ชุดที่ 3 — Orthopedics (Fractures, Pediatric Ortho, Spine, Bone Tumors, Hand)", "subject": "surg", "questions": [{"topic": "Orthopedics", "q": "A 40-year-old man sustains a closed tibial fracture. Six hours later he has severe pain worsened by passive toe extension, a tense swollen calf, and paresthesia. What is the diagnosis?", "choices": ["Compartment syndrome", "Fat embolism", "Deep vein thrombosis", "Cellulitis", "Nerve contusion"], "ans": 0, "exp": "Acute compartment syndrome: ปวดรุนแรง 'เกินกว่าที่ควร' + ปวดเมื่อ passive stretch + tense compartment + paresthesia (สัญญาณแรก). Pulselessness/pallor เป็น 'สัญญาณสาย'. วินิจฉัยทางคลินิก (± วัด compartment pressure). รักษา: 'emergency fasciotomy' — อย่ารอ pulse หาย. พบบ่อยหลัง tibial fracture/reperfusion/crush."}, {"topic": "Orthopedics", "q": "A motorcyclist has an open tibial fracture with a 3 cm wound and moderate soft tissue damage but adequate coverage (Gustilo type II). What is the initial management priority?", "choices": ["Delayed surgery in 1 week for this patient", "Antibiotics, tetanus, wound care, and urgent debridement", "Immediate internal fixation only", "Close the wound primarily for this patient", "Apply a cast and discharge for this patient"], "ans": 1, "exp": "Open fracture management: ให้ 'IV antibiotic เร็ว' (ภายใน 1 ชม.), tetanus prophylaxis, คลุมแผลด้วย saline dressing, จัดกระดูก/splint, และ 'urgent surgical debridement + irrigation' + fracture stabilization. Gustilo grading (I <1cm, II 1-10cm, III >10cm/มาก) กำหนดยาปฏิชีวนะ/การดูแล. ไม่เย็บปิด primary ในแผลปนเปื้อน."}, {"topic": "Orthopedics", "q": "A 70-year-old woman falls and has a shortened, externally rotated right leg with groin pain; she cannot bear weight. What is the most likely diagnosis?", "choices": ["Trochanteric bursitis", "Hip dislocation", "Femoral neck fracture", "Pubic ramus fracture", "Lumbar radiculopathy"], "ans": 2, "exp": "Hip (femoral neck/intertrochanteric) fracture ในผู้สูงอายุหลังล้ม: ขา 'สั้นและ external rotation' + ปวดขาหนีบ + ลงน้ำหนักไม่ได้. Displaced femoral neck fracture เสี่ยง avascular necrosis (เลือดเลี้ยง retrograde) → มัก hemiarthroplasty/THA; intertrochanteric → internal fixation (DHS/nail). ผ่าตัดเร็วลด morbidity/mortality."}, {"topic": "Orthopedics", "q": "A young adult falls on an outstretched hand and has tenderness in the anatomical snuffbox, but the initial X-ray is normal. What is the appropriate management?", "choices": ["Immediate surgery for this patient", "Discharge with reassurance as first step", "Ignore if X-ray is normal as first step", "Immobilize and repeat imaging in 10-14 days", "Aspirate the wrist for this patient"], "ans": 3, "exp": "Scaphoid fracture: FOOSH + กดเจ็บ anatomical snuffbox — X-ray แรกอาจปกติ (occult). จัดการ: 'immobilize (thumb spica) แล้ว X-ray/MRI ซ้ำใน 10-14 วัน' หรือ MRI เลย. สำคัญเพราะเลือดเลี้ยง retrograde → เสี่ยง avascular necrosis/nonunion ที่ proximal pole ถ้าพลาดการวินิจฉัย."}, {"topic": "Orthopedics", "q": "A 60-year-old woman falls on an outstretched hand and has a 'dinner fork' deformity of the wrist. What fracture is this?", "choices": ["Smith fracture", "Scaphoid fracture", "Galeazzi fracture", "Monteggia fracture", "Colles fracture"], "ans": 4, "exp": "Colles fracture: distal radius fracture ที่ 'dorsal angulation/displacement' → 'dinner fork deformity', พบหลัง FOOSH ในผู้สูงอายุ (fragility fracture - ควรประเมิน osteoporosis). รักษา: closed reduction + cast; unstable → ORIF/K-wire. Smith = volar displacement ('reverse Colles')."}, {"topic": "Orthopedics", "q": "A 25-year-old man has a first-time anterior shoulder dislocation after a fall. Which nerve is most commonly injured, causing numbness over the deltoid?", "choices": ["Axillary nerve", "Median nerve", "Radial nerve", "Ulnar nerve", "Musculocutaneous nerve"], "ans": 0, "exp": "Anterior shoulder dislocation (พบบ่อยสุด): แขนอยู่ท่า abduction/external rotation, สูญเสีย contour. เส้นประสาทที่เสี่ยงคือ 'axillary nerve' (ชาบริเวณ deltoid 'regimental badge', deltoid อ่อนแรง). ต้องตรวจ neurovascular ก่อน/หลัง reduction. เสี่ยง Bankart/Hill-Sachs lesion, recurrence สูงในคนหนุ่ม."}, {"topic": "Orthopedics", "q": "A child falls and sustains a supracondylar humeral fracture. Which structure is most at risk, requiring urgent neurovascular assessment?", "choices": ["Sciatic nerve for this patient", "Brachial artery and median nerve", "Femoral vein for this patient", "Common peroneal nerve alone", "Vertebral artery in this case"], "ans": 1, "exp": "Supracondylar humeral fracture (พบบ่อยในเด็ก, FOOSH): เสี่ยงบาดเจ็บ 'brachial artery และ median nerve (โดยเฉพาะ anterior interosseous)'. ต้องตรวจ pulse/perfusion + motor/sensory ('OK sign' = AIN). Displaced (Gartland III) → urgent reduction + K-wire. ภาวะแทรกซ้อน: Volkmann ischemic contracture (จาก compartment syndrome/vascular)."}, {"topic": "Orthopedics", "q": "A child has a fracture through the growth plate and metaphysis (Salter-Harris type II). Why is growth plate injury clinically important?", "choices": ["Always heals with malunion", "No clinical significance", "Risk of growth arrest and deformity", "Requires amputation", "Causes osteomyelitis always"], "ans": 2, "exp": "Salter-Harris classification (physeal fractures): I (through physis), II (physis + Metaphysis - พบบ่อยสุด), III (physis + ePiphysis, intra-articular), IV (Through all), V (cRush - พยากรณ์แย่สุด). สำคัญเพราะเสี่ยง 'growth arrest/angular deformity/limb length discrepancy' → ต้องการ reduction ที่ดีและติดตาม. Type III/IV/V เสี่ยงสูงกว่า."}, {"topic": "Orthopedics", "q": "An infant is found to have asymmetric skin folds and a positive Ortolani/Barlow test. What is the diagnosis?", "choices": ["Slipped capital femoral epiphysis", "Septic arthritis", "Perthes disease", "Developmental dysplasia of the hip", "Transient synovitis"], "ans": 3, "exp": "Developmental dysplasia of the hip (DDH): asymmetric skin folds, limited abduction, 'Ortolani (relocate) / Barlow (dislocate)' positive ในทารก. เสี่ยง: female, breech, family history, first-born. คัดกรอง US (<6 เดือน), X-ray (>4-6 เดือน). รักษา: Pavlik harness (<6 เดือน); ช้า → closed/open reduction + cast."}, {"topic": "Orthopedics", "q": "A 6-year-old boy has an insidious limp and hip/knee pain; X-ray shows a sclerotic, fragmented femoral head. What is the diagnosis?", "choices": ["DDH", "Slipped capital femoral epiphysis", "Septic arthritis", "Transient synovitis", "Legg-Calve-Perthes disease"], "ans": 4, "exp": "Legg-Calve-Perthes disease: idiopathic avascular necrosis ของ femoral head ในเด็ก (~4-8 ปี, ชาย) — เดินกะเผลก, ปวดสะโพก/เข่า, X-ray เห็น head sclerosis/fragmentation. รักษา: containment (limit activity, brace, บางราย osteotomy) เพื่อคง sphericity. พยากรณ์ขึ้นกับอายุ/ปริมาณ head ที่ affected."}, {"topic": "Orthopedics", "q": "An obese 13-year-old boy has hip/knee pain and a limp; the affected leg is externally rotated. X-ray shows the femoral head slipping posteroinferiorly. What is the diagnosis?", "choices": ["Slipped capital femoral epiphysis", "Perthes disease as first step", "Septic arthritis as first step", "DDH for this patient", "Transient synovitis initially"], "ans": 0, "exp": "Slipped capital femoral epiphysis (SCFE): วัยรุ่นอ้วน/growth spurt — ปวดสะโพก/'เข่า' (referred), external rotation, จำกัดการงอ/internal rotation. X-ray (frog-leg) เห็น epiphysis เลื่อน. เป็น orthopedic urgency → 'in situ pinning' (fix ป้องกันเลื่อนเพิ่ม/avascular necrosis). อย่าพยายาม reduce แรงๆ."}, {"topic": "Orthopedics", "q": "A 4-year-old refuses to bear weight on the leg, has a fever, and holds the hip flexed/externally rotated with severe pain on any movement. What is the most urgent diagnosis to exclude?", "choices": ["Cellulitis", "Septic arthritis", "Transient synovitis", "Perthes disease", "Growing pains"], "ans": 1, "exp": "Septic arthritis (โดยเฉพาะสะโพก) เป็น 'orthopedic emergency' — ไข้ + ปวดมาก + ไม่ให้ขยับข้อ (pseudoparalysis) + ลงน้ำหนักไม่ได้. Kocher criteria (ไข้, non-weight bearing, ESR/CRP สูง, WBC สูง) ช่วยแยกจาก transient synovitis. รักษา: 'urgent joint aspiration/drainage + IV antibiotic' (ล่าช้าทำลาย cartilage/growth plate)."}, {"topic": "Orthopedics", "q": "A patient develops progressive bilateral leg weakness, saddle anesthesia, urinary retention, and back pain after a disc herniation. What is the diagnosis?", "choices": ["Spinal stenosis", "Sciatica", "Cauda equina syndrome", "Mechanical back pain", "Vertebral fracture"], "ans": 2, "exp": "Cauda equina syndrome: การกดทับ cauda equina (มักจาก central disc herniation) → 'red flags': saddle anesthesia, bladder/bowel dysfunction (retention → overflow), bilateral leg weakness/sciatica, ลด anal tone. เป็น 'surgical emergency' → urgent MRI + decompression (ภายใน 24-48 ชม.) เพื่อป้องกัน permanent deficit."}, {"topic": "Orthopedics", "q": "A 15-year-old has knee pain and a large mass around the distal femur; X-ray shows a 'sunburst' periosteal reaction and Codman triangle. What is the diagnosis?", "choices": ["Osteochondroma", "Ewing sarcoma", "Giant cell tumor", "Osteosarcoma", "Chondrosarcoma"], "ans": 3, "exp": "Osteosarcoma: มะเร็งกระดูกปฐมภูมิที่พบบ่อยสุดในวัยรุ่น (metaphysis รอบเข่า - distal femur/proximal tibia). X-ray: 'sunburst/spiculated periosteal reaction + Codman triangle', bone destruction. วินิจฉัย biopsy; รักษา neoadjuvant chemo + limb-sparing resection. แพร่ไปปอด."}, {"topic": "Orthopedics", "q": "A 12-year-old has bone pain and fever; X-ray of the diaphysis shows an 'onion-skin' periosteal reaction. Biopsy shows small round blue cells with t(11;22). What is the diagnosis?", "choices": ["Osteosarcoma", "Osteomyelitis", "Osteoid osteoma", "Chondrosarcoma", "Ewing sarcoma"], "ans": 4, "exp": "Ewing sarcoma: เด็ก/วัยรุ่น, มัก diaphysis ของ long bone/pelvis — ปวด + ไข้ (เลียนแบบ osteomyelitis/infection). X-ray: 'onion-skin (lamellated) periosteal reaction'. Histology: small round blue cells, 't(11;22)' EWSR1-FLI1. รักษา: chemo + surgery/RT."}, {"topic": "Orthopedics", "q": "An adult has a lytic, expansile lesion at the epiphysis/metaphysis of the distal femur with a 'soap bubble' appearance; it is usually benign but locally aggressive. What is the diagnosis?", "choices": ["Giant cell tumor of bone", "Osteosarcoma initially", "Ewing sarcoma alone", "Enchondroma initially", "Osteoid osteoma alone"], "ans": 0, "exp": "Giant cell tumor of bone (osteoclastoma): มักที่ 'epiphysis' ของ long bone (distal femur, proximal tibia, distal radius) ในผู้ใหญ่วัยหนุ่มสาว — lytic 'soap bubble', ขยาย. Benign แต่ locally aggressive และเป็นซ้ำได้ (บางรายเป็น malignant/metastasize ปอด). รักษา: curettage + adjuvant (± denosumab)/resection."}, {"topic": "Orthopedics", "q": "A 65-year-old man with known prostate cancer has new severe back pain and a lytic vertebral lesion. What is the most likely cause of bone lesions in this age group?", "choices": ["Paget disease", "Metastatic carcinoma", "Primary osteosarcoma", "Osteomyelitis", "Osteoid osteoma"], "ans": 1, "exp": "ในผู้สูงอายุ 'metastatic carcinoma' เป็นสาเหตุมะเร็งกระดูกที่พบบ่อยที่สุด (มากกว่า primary bone tumor). Primary ที่แพร่ไปกระดูกบ่อย: prostate, breast, lung, kidney, thyroid ('BLT with Kosher Pickle'). Prostate มัก osteoblastic (sclerotic). เฝ้าระวัง pathologic fracture และ spinal cord compression."}, {"topic": "Orthopedics", "q": "A patient with breast cancer develops sudden back pain, leg weakness, and a sensory level; MRI shows epidural cord compression from a vertebral metastasis. What is the immediate management?", "choices": ["Physiotherapy for this patient", "Bed rest and analgesia only", "High-dose steroids and urgent oncology/surgery referral", "Wait for radiotherapy in 2 weeks for this patient", "Discharge home for this patient"], "ans": 2, "exp": "Metastatic spinal cord compression (oncologic emergency): back pain + progressive weakness + sensory level + bladder/bowel dysfunction. รักษาทันที: 'high-dose corticosteroid (dexamethasone)' + urgent MRI whole spine + ปรึกษา surgery (decompression/stabilization) และ/หรือ radiotherapy. ยิ่งรักษาเร็วก่อนสูญเสีย function ยิ่งฟื้นดี."}, {"topic": "Orthopedics", "q": "A patient develops fever and localized bone pain; X-ray shows a lytic lesion with periosteal reaction, and MRI confirms osteomyelitis. In children, which organism is most common?", "choices": ["Pseudomonas", "Escherichia coli", "Salmonella", "Staphylococcus aureus", "Mycobacterium tuberculosis"], "ans": 3, "exp": "Acute hematogenous osteomyelitis (มักที่ metaphysis ของ long bone ในเด็ก): เชื้อบ่อยสุดคือ 'Staphylococcus aureus'. Salmonella พบใน sickle cell disease. รักษา: IV antibiotic + surgical drainage/debridement ถ้ามีหนอง/ตอบสนองช้า. X-ray เปลี่ยนช้า (~2 สัปดาห์) → MRI ไวกว่า."}, {"topic": "Orthopedics", "q": "A patient has an elbow injury; on exam there is weakness of finger and wrist extension and a wrist drop. Which nerve is injured (commonly with humeral shaft fracture)?", "choices": ["Ulnar nerve", "Median nerve", "Axillary nerve", "Musculocutaneous nerve", "Radial nerve"], "ans": 4, "exp": "Radial nerve injury (มักกับ 'humeral shaft fracture' หรือ Saturday night palsy): 'wrist drop' (สูญเสีย wrist/finger extension) + ชาหลังมือด้าน radial (first web space). ส่วนใหญ่เป็น neuropraxia → ฟื้นเอง (สังเกต ~3 เดือน), splint. Median = 'hand of benediction'/thenar; Ulnar = 'claw hand'/hypothenar."}, {"topic": "Orthopedics", "q": "A patient with a mid-shaft humeral fracture cannot extend the wrist. This nerve runs in which groove of the humerus?", "choices": ["Spiral (radial) groove", "Bicipital groove", "Ulnar groove", "Deltopectoral groove", "Intercondylar groove"], "ans": 0, "exp": "Radial nerve วิ่งใน 'spiral (radial) groove' ของ humerus จึงเสี่ยงบาดเจ็บใน mid-shaft humeral fracture → wrist drop. เป็นเหตุผลทางกายวิภาคที่ humeral shaft fracture สัมพันธ์กับ radial nerve palsy. ตรวจ radial nerve function ก่อน/หลัง reduction เสมอ."}, {"topic": "Orthopedics", "q": "A patient sleeps with the arm over a chair and wakes with numbness of the little finger and a 'claw hand'. Which nerve is affected?", "choices": ["Long thoracic nerve", "Ulnar nerve", "Radial nerve", "Median nerve", "Axillary nerve"], "ans": 1, "exp": "Ulnar nerve (มักที่ cubital tunnel/elbow หรือ Guyon canal): ชานิ้วก้อย + ครึ่ง ring finger, 'claw hand' (โดยเฉพาะเมื่อ lesion ที่ wrist - ulnar paradox), อ่อนแรง interossei/hypothenar (Froment sign). สัมพันธ์ medial epicondyle fracture. Median = carpal tunnel/thenar; Radial = wrist drop."}, {"topic": "Orthopedics", "q": "A patient with a fibular neck fracture develops foot drop and cannot dorsiflex or evert the foot. Which nerve is injured?", "choices": ["Tibial nerve for this patient", "Sciatic nerve trunk initially", "Common peroneal (fibular) nerve", "Femoral nerve as first step", "Sural nerve for this patient"], "ans": 2, "exp": "Common peroneal (fibular) nerve พันรอบ 'fibular neck' จึงเสี่ยงบาดเจ็บใน fibular neck fracture/tight cast/prolonged pressure → 'foot drop' (สูญเสีย dorsiflexion + eversion) + ชาหลังเท้า/first web space. ผู้ป่วยเดินแบบ high-stepping. Splint + ป้องกันแรงกด; ส่วนใหญ่ฟื้นถ้าเป็น neuropraxia."}, {"topic": "Orthopedics", "q": "A patient falls and lands on the point of the shoulder; there is a step deformity at the acromioclavicular joint. What is the injury?", "choices": ["Shoulder dislocation", "Clavicle fracture midshaft", "Rotator cuff tear", "Acromioclavicular joint separation", "Sternoclavicular dislocation"], "ans": 3, "exp": "Acromioclavicular (AC) joint injury: ล้มกระแทกไหล่โดยตรง → เจ็บ + 'step deformity' ที่ AC joint (clavicle ปลายนอกยกขึ้น). แบ่งตาม Rockwood I-VI. รักษา: ส่วนใหญ่ (I-III) conservative (sling, physio); severe (IV-VI) → surgery. ต่างจาก clavicle midshaft fracture (ก้อนกลางกระดูกไหปลาร้า)."}, {"topic": "Orthopedics", "q": "A patient jams a finger and cannot actively extend the distal interphalangeal joint, which droops. What is the diagnosis?", "choices": ["Boutonniere deformity", "Swan-neck deformity", "Trigger finger", "Dupuytren contracture", "Mallet finger"], "ans": 4, "exp": "Mallet finger: การบาดเจ็บ 'extensor tendon ที่ DIP' (avulsion ± bony) จากแรงงอ DIP ขณะเหยียด → DIP งอตกและเหยียดเองไม่ได้. รักษา: splint DIP ในท่า extension ต่อเนื่อง 6-8 สัปดาห์; bony mallet ที่ subluxed หรือ fragment ใหญ่ → surgery."}, {"topic": "Orthopedics", "q": "A boxer punches a wall and fractures the neck of the 5th metacarpal. What is this fracture called?", "choices": ["Boxer fracture", "Smith fracture", "Bennett fracture", "Rolando fracture", "Colles fracture"], "ans": 0, "exp": "Boxer's fracture: fracture ที่ 'neck ของ 5th metacarpal' จากการชกกำปั้น → knuckle บุ๋ม/angulation. รักษาส่วนใหญ่ closed (buddy strap/cast) ถ้า angulation ยอมรับได้; rotational deformity/มาก → reduction/fixation. ประเมิน 'fight bite' (บาดแผลจากฟันคน → ติดเชื้อ Eikenella)."}, {"topic": "Orthopedics", "q": "A patient has knee pain and swelling after a twisting injury with a 'pop'; the knee gives way and the anterior drawer/Lachman test is positive. What is injured?", "choices": ["Medial meniscus only", "Anterior cruciate ligament", "Posterior cruciate ligament", "Patellar tendon", "Medial collateral ligament"], "ans": 1, "exp": "Anterior cruciate ligament (ACL) tear: บิดเข่า (pivot) + 'pop' + hemarthrosis (บวมเร็ว) + instability (giving way). ตรวจ 'Lachman (ไวสุด) / anterior drawer / pivot shift' positive. ยืนยัน MRI. รักษา: reconstruction ในผู้ที่ active/instability; conservative + physio ในบางราย. มักร่วมกับ meniscus (O'Donoghue triad)."}, {"topic": "Orthopedics", "q": "An athlete feels a sudden 'kick' to the back of the ankle with an inability to plantarflex; the calf squeeze test (Thompson) shows no foot movement. What is the diagnosis?", "choices": ["Plantar fasciitis", "Ankle sprain", "Achilles tendon rupture", "Gastrocnemius strain", "Peroneal tendon subluxation"], "ans": 2, "exp": "Achilles tendon rupture: รู้สึกเหมือนถูก 'เตะ/ตี' ที่ส้น + plantarflexion อ่อน + คลำพบ gap + 'Thompson test positive' (บีบน่องแล้วเท้าไม่ plantarflex). รักษา: functional bracing/immobilization (equinus) หรือ surgical repair (โดยเฉพาะนักกีฬา/young). วินิจฉัยทางคลินิก ± US/MRI."}, {"topic": "Orthopedics", "q": "A middle-aged worker has numbness/tingling of the thumb, index, and middle fingers, worse at night; Tinel and Phalen tests are positive. What is the diagnosis?", "choices": ["Guyon canal syndrome", "Cubital tunnel syndrome", "Cervical radiculopathy", "Carpal tunnel syndrome", "De Quervain tenosynovitis"], "ans": 3, "exp": "Carpal tunnel syndrome (median nerve compression ที่ข้อมือ): ชา/เสียว thumb-index-middle-half ring, แย่ตอนกลางคืน/สะบัดมือดีขึ้น, thenar atrophy (สาย). Tinel/Phalen positive. สัมพันธ์ ตั้งครรภ์, DM, hypothyroid, RA, ใช้มือซ้ำ. รักษา: splint, steroid injection; ดื้อ/มี atrophy → carpal tunnel release."}, {"topic": "Orthopedics", "q": "A patient in a car crash has a flexed, adducted, internally rotated, shortened hip. Which injury and nerve are at risk?", "choices": ["Femoral neck fracture, obturator nerve", "Anterior hip dislocation, femoral nerve", "Pelvic fracture, pudendal nerve", "Knee dislocation, peroneal nerve", "Posterior hip dislocation, sciatic nerve"], "ans": 4, "exp": "Posterior hip dislocation (พบบ่อยสุด, จาก dashboard injury): สะโพก 'flexed, adducted, internally rotated, shortened'. เสี่ยงบาดเจ็บ 'sciatic nerve' (foot drop) และ avascular necrosis ของ femoral head → เป็น orthopedic urgency ต้อง reduce เร็ว (<6 ชม.). Anterior dislocation → abducted/externally rotated."}, {"topic": "Orthopedics", "q": "A young man has a closed femoral shaft fracture. How much blood can be lost internally, potentially causing shock?", "choices": ["Up to 1-1.5 liters", "Under 200 mL", "Exactly 3 liters always", "No significant blood loss", "Only external bleeding"], "ans": 0, "exp": "Femoral shaft fracture สามารถเสียเลือดภายในต้นขาได้มาก (~1-1.5 ลิตร ต่อข้าง) → อาจ hypovolemic shock (โดยเฉพาะ fracture หลายตำแหน่ง/pelvis). รักษา: resuscitation, analgesia, traction splint (ลดเลือดออก/ปวด), แล้ว definitive fixation (intramedullary nail). ประเมิน fat embolism/associated injury."}, {"topic": "Orthopedics", "q": "A patient has an ankle injury with a fracture of the fibula above the level of the syndesmosis (Weber C). What does this imply?", "choices": ["Growth plate injury for this patient", "Likely syndesmotic disruption needing fixation", "Always stable, cast only", "No treatment needed for this patient", "Isolated soft tissue injury for this patient"], "ans": 1, "exp": "Ankle fracture Weber classification (ตามระดับ fibular fracture เทียบ syndesmosis): A (below - stable), B (at level - variable), C (above - มัก syndesmotic injury, unstable → ORIF ± syndesmotic screw). Weber C บ่งชี้ high-energy/unstable. ประเมิน medial malleolus/deltoid ligament (bimalleolar equivalent)."}, {"topic": "Orthopedics", "q": "A forearm injury shows a fracture of the proximal ulna with dislocation of the radial head. What is this pattern called?", "choices": ["Bennett fracture", "Galeazzi fracture-dislocation", "Monteggia fracture-dislocation", "Colles fracture", "Nightstick fracture"], "ans": 2, "exp": "Monteggia: 'proximal ulna fracture + radial head dislocation'. Galeazzi: 'distal radius fracture + distal radioulnar joint dislocation'. (จำ MUGR: Monteggia-Ulna, Galeazzi-Radius). ทั้งคู่ต้องประเมิน joint ที่ dislocate + fix กระดูก (มัก ORIF ในผู้ใหญ่). ต้องตรวจ posterior interosseous nerve ใน Monteggia."}, {"topic": "Orthopedics", "q": "A 5-year-old has a fracture where the bone is bent and cracked on one side only (cortex intact on the other). What is this fracture called?", "choices": ["Torus (buckle) fracture", "Comminuted fracture", "Spiral fracture", "Greenstick fracture", "Pathologic fracture"], "ans": 3, "exp": "Greenstick fracture: กระดูกเด็ก (อ่อน) หักไม่สมบูรณ์ — cortex ด้านหนึ่งหัก อีกด้าน 'งอ' (คล้ายกิ่งไม้สด). Torus/buckle = cortex buckle จาก compression (stable). พบเฉพาะในเด็ก (bone plasticity). รักษา: cast; angulation มาก → reduction."}, {"topic": "Orthopedics", "q": "An infant presents with multiple fractures of different ages, posterior rib fractures, and a metaphyseal 'corner' fracture. What must be considered?", "choices": ["Osteogenesis imperfecta only", "Normal variant", "Rickets only", "Scurvy", "Non-accidental injury (child abuse)"], "ans": 4, "exp": "Non-accidental injury (child abuse): สงสัยเมื่อมี 'fractures หลายตำแหน่ง/หลายอายุ', posterior rib fractures, metaphyseal corner ('bucket-handle') fractures, ประวัติไม่สอดคล้อง, มาช้า. ต้อง skeletal survey, ประเมินภาพรวม, รายงานตามกฎหมาย. แยกจาก osteogenesis imperfecta (blue sclera, family history)."}, {"topic": "Orthopedics", "q": "A 55-year-old man has an acutely painful, swollen, red first metatarsophalangeal joint; aspiration shows negatively birefringent needle-shaped crystals. What is the diagnosis?", "choices": ["Gout", "Septic arthritis", "Pseudogout", "Rheumatoid arthritis", "Osteoarthritis"], "ans": 0, "exp": "Gout (acute): ปวด/บวม/แดงเฉียบพลันที่ 1st MTP (podagra) — aspiration พบ 'needle-shaped, negatively birefringent' monosodium urate crystals. รักษาเฉียบพลัน: NSAIDs/colchicine/steroid; ป้องกันด้วย allopurinol (ไม่เริ่มขณะ acute). Pseudogout = calcium pyrophosphate, rhomboid, positively birefringent (มัก knee)."}, {"topic": "Orthopedics", "q": "A 70-year-old woman sustains a vertebral compression fracture after minimal trauma. What underlying condition should be evaluated and treated?", "choices": ["Multiple myeloma only", "Osteoporosis", "Osteomalacia only", "Paget disease only", "Normal aging, no action"], "ans": 1, "exp": "Fragility fracture (จาก low-energy trauma เช่น vertebral compression, hip, distal radius) ในผู้สูงอายุ → บ่งชี้ 'osteoporosis' → ประเมิน BMD (DXA, T-score ≤-2.5), เสริม calcium/vitamin D, และรักษาด้วย bisphosphonate/denosumab. ต้องแยก secondary causes (myeloma, malignancy) โดยเฉพาะถ้าลักษณะผิดปกติ."}, {"topic": "Orthopedics", "q": "A 60-year-old man has bone pain, an enlarged skull, bowing of the tibia, and a very high alkaline phosphatase with normal calcium. What is the diagnosis?", "choices": ["Osteoporosis", "Osteomalacia", "Paget disease of bone", "Multiple myeloma", "Hyperparathyroidism"], "ans": 2, "exp": "Paget disease of bone: การ remodeling ผิดปกติ (osteoclast/osteoblast) → กระดูกใหญ่/อ่อน/deformity (bowing, skull enlargement, ปวด, หูตึง), 'ALP สูงมาก' แต่ Ca/PO4 ปกติ. เสี่ยง fracture, high-output heart failure, osteosarcoma (rare). รักษา: bisphosphonate. X-ray: cortical thickening, lytic/sclerotic."}, {"topic": "Orthopedics", "q": "A young adult has night pain in the leg relieved dramatically by NSAIDs; X-ray shows a small lucent nidus with surrounding sclerosis. What is the diagnosis?", "choices": ["Osteosarcoma", "Ewing sarcoma", "Osteomyelitis", "Osteoid osteoma", "Enchondroma"], "ans": 3, "exp": "Osteoid osteoma: benign bone tumor ในวัยรุ่น/หนุ่มสาว — 'ปวดตอนกลางคืน + ตอบสนอง NSAIDs ดีมาก' (prostaglandin). X-ray: nidus (lucent) เล็ก <1.5 cm ล้อมด้วย reactive sclerosis. รักษา: NSAIDs หรือ CT-guided radiofrequency ablation. ต่างจาก osteoblastoma (>2 cm)."}, {"topic": "Orthopedics", "q": "A 65-year-old man has bone pain, anemia, renal impairment, hypercalcemia, and lytic 'punched-out' skull lesions. What is the diagnosis?", "choices": ["Metastatic prostate cancer", "Osteoporosis", "Paget disease", "Hyperparathyroidism", "Multiple myeloma"], "ans": 4, "exp": "Multiple myeloma (plasma cell malignancy): 'CRAB' — hyperCalcemia, Renal impairment, Anemia, Bone lesions (lytic 'punched-out', ไม่มี osteoblastic reaction → bone scan อาจ negative). ตรวจ serum/urine protein electrophoresis (M-protein), Bence-Jones, marrow. เสี่ยง pathologic fracture/cord compression. รักษา hematology (chemo)."}, {"topic": "Orthopedics", "q": "A patient from an endemic area has chronic back pain, low-grade fever, and a gibbus deformity; MRI shows vertebral destruction with a paravertebral abscess. What is the diagnosis?", "choices": ["Spinal tuberculosis (Pott disease)", "Ankylosing spondylitis", "Pyogenic osteomyelitis", "Metastasis", "Osteoporotic fracture"], "ans": 0, "exp": "Spinal tuberculosis (Pott disease): มัก thoracolumbar — ปวดหลังเรื้อรัง, ไข้ต่ำ, night sweats, 'gibbus' (angular kyphosis), paravertebral/psoas abscess (cold abscess). MRI + biopsy/culture. รักษา anti-TB นาน; ผ่าตัดถ้ามี cord compression/instability/deformity. พบในไทย."}, {"topic": "Orthopedics", "q": "A patient has an unstable cervical spine injury after a diving accident. During airway management, what must be maintained?", "choices": ["No precautions for this patient", "In-line cervical spine immobilization", "Full neck extension as first step", "Neck flexion for this patient", "Rotation to one side as first step"], "ans": 1, "exp": "ผู้บาดเจ็บที่สงสัย cervical spine injury: ต้อง 'in-line manual immobilization' ขณะจัดการ airway (หลีกเลี่ยงการขยับคอ). ใช้ orotracheal intubation with in-line stabilization. ประเมิน/clear c-spine ตาม NEXUS/Canadian C-spine rules. Unstable injury เสี่ยง spinal cord damage เพิ่มเมื่อขยับ."}, {"topic": "Orthopedics", "q": "A 45-year-old has back pain radiating down the leg past the knee with a positive straight leg raise, worse on coughing. What is the diagnosis?", "choices": ["Mechanical back pain in this case", "Cauda equina syndrome in this case", "Lumbar disc herniation with sciatica", "Ankylosing spondylitis initially", "Vertebral fracture as first step"], "ans": 2, "exp": "Lumbar disc herniation (มัก L4-5, L5-S1) → sciatica (ปวดร้าวตามขาเลยเข่า, dermatomal), 'straight leg raise positive', แย่เมื่อไอ/นั่ง. ส่วนใหญ่หายด้วย conservative (analgesia, physio, activity). Red flags (cauda equina, progressive deficit, infection/tumor) → urgent MRI/surgery."}, {"topic": "Orthopedics", "q": "A 30-year-old man has an acutely painful, swollen knee with fever; joint aspiration shows purulent fluid with 80,000 WBC/mm3. What is the diagnosis and management?", "choices": ["Hemarthrosis, aspiration only", "Gout, colchicine for this patient", "Reactive arthritis, NSAIDs for this patient", "Septic arthritis, urgent drainage and antibiotics", "Osteoarthritis, analgesia for this patient"], "ans": 3, "exp": "Septic arthritis (adult): ข้อบวมแดงร้อนเฉียบพลัน + ไข้ + aspiration พบ WBC สูงมาก (>50,000, PMN เด่น), gram stain/culture. เชื้อบ่อย S. aureus (gonococcal ในคนหนุ่มสาว sexually active). เป็น emergency → 'urgent joint drainage/washout + IV antibiotic' (ล่าช้าทำลาย cartilage). ส่ง crystals แยก gout."}, {"topic": "Orthopedics", "q": "A patient has anterior shoulder pain and weakness on abduction and external rotation; there is a positive drop-arm test. What is the diagnosis?", "choices": ["Biceps tendon rupture", "Adhesive capsulitis", "AC joint arthritis", "Cervical radiculopathy", "Rotator cuff tear"], "ans": 4, "exp": "Rotator cuff tear (มัก supraspinatus): ปวดไหล่ + อ่อนแรง abduction/external rotation, 'drop-arm test positive', painful arc. พบในผู้สูงอายุ/overuse/trauma. วินิจฉัย US/MRI. รักษา: physio/steroid (partial/degenerative); ผ่าตัดซ่อมใน acute traumatic tear/young/large tear. ต่างจาก frozen shoulder (จำกัด passive ด้วย)."}, {"topic": "Orthopedics", "q": "A 55-year-old diabetic woman has progressive shoulder stiffness with loss of both active and passive range of motion, without weakness. What is the diagnosis?", "choices": ["Adhesive capsulitis (frozen shoulder)", "Rotator cuff tear for this patient", "Shoulder dislocation as first step", "Osteoarthritis for this patient", "Septic arthritis for this patient"], "ans": 0, "exp": "Adhesive capsulitis (frozen shoulder): การจำกัดการเคลื่อนไหวไหล่ 'ทั้ง active และ passive' (โดยเฉพาะ external rotation) โดยไม่มีอ่อนแรงจริง, ปวด. สัมพันธ์ DM, thyroid, immobilization. ดำเนินโรค 3 ระยะ (freezing-frozen-thawing) หายได้เองใน 1-3 ปี. รักษา: physio, analgesia, steroid injection; ดื้อ → manipulation/release."}, {"topic": "Orthopedics", "q": "A tennis player has lateral elbow pain worsened by resisted wrist extension. What is the diagnosis?", "choices": ["Cubital tunnel syndrome initially", "Lateral epicondylitis (tennis elbow)", "Medial epicondylitis in this case", "Olecranon bursitis as first step", "Radial head fracture in this case"], "ans": 1, "exp": "Lateral epicondylitis (tennis elbow): ปวด lateral elbow ที่ common extensor origin, แย่เมื่อ resisted wrist/finger extension (grip). Medial epicondylitis (golfer's elbow) = flexor origin, ปวด medial. รักษา: relative rest, NSAIDs, brace, physio/eccentric exercise; ดื้อ → steroid injection/PRP/surgery."}, {"topic": "Orthopedics", "q": "A patient has a finger that catches and locks in flexion, then releases with a painful click. What is the diagnosis?", "choices": ["Ganglion for this patient", "Dupuytren contracture for this patient", "Trigger finger (stenosing tenosynovitis)", "Mallet finger for this patient", "Boutonniere deformity for this patient"], "ans": 2, "exp": "Trigger finger (stenosing flexor tenosynovitis): นิ้วติด/ล็อกในท่างอ แล้วสะดุด 'click' เมื่อเหยียด — จากปมที่ A1 pulley. สัมพันธ์ DM, RA, ใช้มือซ้ำ. รักษา: splint, NSAIDs, 'corticosteroid injection'; ดื้อ → A1 pulley release. ต่างจาก Dupuytren (พังผืด palmar, งอถาวร)."}, {"topic": "Orthopedics", "q": "A 60-year-old man has progressive flexion contracture of the ring and little fingers with palpable palmar cords and nodules. What is the diagnosis?", "choices": ["Rheumatoid hand", "Trigger finger", "Carpal tunnel syndrome", "Dupuytren contracture", "Ganglion"], "ans": 3, "exp": "Dupuytren contracture: การหนาตัว/หดของ palmar fascia → nodule + cord + งอถาวร (มัก ring/little finger). สัมพันธ์ พันธุกรรม (ยุโรปเหนือ), เหล้า, DM, ลมชัก. รักษา: สังเกต (mild); collagenase injection, needle aponeurotomy, หรือ fasciectomy เมื่อ contracture รบกวน (Hueston tabletop test)."}, {"topic": "Orthopedics", "q": "A skier falls with the thumb forced into abduction and has instability of the ulnar collateral ligament of the thumb MCP joint. What is the diagnosis?", "choices": ["Trigger thumb", "Mallet thumb", "Bennett fracture", "De Quervain tenosynovitis", "Gamekeeper's/skier's thumb"], "ans": 4, "exp": "Gamekeeper's/skier's thumb: การบาดเจ็บ 'ulnar collateral ligament ของ thumb MCP' จากแรง abduction/hyperextension (ล้มถือไม้สกี) → instability, อ่อนแรงหยิบจับ. ระวัง 'Stener lesion' (ligament พับ ไม่หายเอง → ต้องผ่าตัด). Complete tear/Stener → surgical repair; partial → cast."}, {"topic": "Orthopedics", "q": "A patient has radial-sided wrist pain over the first dorsal compartment; the Finkelstein test is positive. What is the diagnosis?", "choices": ["De Quervain tenosynovitis", "Wrist osteoarthritis", "Carpal tunnel syndrome", "Scaphoid fracture", "Trigger thumb"], "ans": 0, "exp": "De Quervain tenosynovitis: การอักเสบของ 1st dorsal compartment (APL/EPB tendons) — ปวด radial wrist ที่ base of thumb, 'Finkelstein test positive' (กำนิ้วหัวแม่มือแล้วเบี่ยง ulnar → ปวด). พบในแม่ลูกอ่อน/ใช้มือซ้ำ. รักษา: thumb spica splint, NSAIDs, steroid injection; ดื้อ → release."}, {"topic": "Orthopedics", "q": "A young man twists the knee and has locking and a positive McMurray test with joint-line tenderness. What structure is injured?", "choices": ["Medial collateral ligament", "Meniscus", "Anterior cruciate ligament", "Patellar tendon", "Quadriceps tendon"], "ans": 1, "exp": "Meniscal tear: บิดเข่า → ปวด joint-line, 'locking/catching', บวมช้าๆ (effusion), 'McMurray test positive'. วินิจฉัย MRI. รักษา: peripheral/vascular zone → repair; central/degenerative → conservative หรือ partial meniscectomy. มักร่วมกับ ACL injury."}, {"topic": "Orthopedics", "q": "An adolescent basketball player has pain and a bony prominence at the tibial tuberosity, worse with activity. What is the diagnosis?", "choices": ["Meniscal tear", "Patellar dislocation", "Osgood-Schlatter disease", "ACL tear", "Septic arthritis"], "ans": 2, "exp": "Osgood-Schlatter disease: apophysitis ของ tibial tuberosity (traction จาก patellar tendon) ในวัยรุ่นที่ active (กระโดด/วิ่ง) — ปวด/นูนที่ tibial tuberosity, แย่เมื่อออกกำลัง. เป็น self-limited (หายเมื่อ growth plate ปิด). รักษา: relative rest, ice, stretching, NSAIDs."}, {"topic": "Orthopedics", "q": "A runner has heel pain that is worst on the first steps in the morning, with tenderness at the medial calcaneal tuberosity. What is the diagnosis?", "choices": ["Achilles tendinopathy", "Calcaneal fracture", "Tarsal tunnel syndrome", "Plantar fasciitis", "Gout"], "ans": 3, "exp": "Plantar fasciitis: ปวดส้นเท้า 'ก้าวแรกตอนเช้า/หลังพัก' (start-up pain), กดเจ็บ medial calcaneal tuberosity. สัมพันธ์ overuse, ยืน/วิ่งนาน, obesity, tight calf. รักษา: stretching (plantar fascia/calf), heel cushion/orthotics, NSAIDs; ส่วนใหญ่หายด้วย conservative. Heel spur เป็น incidental."}, {"topic": "Orthopedics", "q": "A newborn has a foot that is rigidly held in equinus, varus, and adduction that cannot be passively corrected. What is the diagnosis?", "choices": ["Metatarsus adductus for this patient", "Calcaneovalgus foot for this patient", "Vertical talus for this patient", "Flat foot for this patient", "Congenital talipes equinovarus (clubfoot)"], "ans": 4, "exp": "Congenital talipes equinovarus (clubfoot): เท้าบิด rigid — equinus (ปลายเท้าจิก), varus (ส้นบิดใน), adductus (หน้าเท้าเข้า), cavus. รักษา: 'Ponseti method' (serial casting + Achilles tenotomy + brace) ตั้งแต่แรกเกิด. ต่างจาก positional deformity (แก้ passive ได้). ประเมิน associated (spina bifida, DDH)."}, {"topic": "Orthopedics", "q": "A patient has a knee dislocation from high-energy trauma that reduced spontaneously. Which injury must be actively excluded?", "choices": ["Popliteal artery injury", "Simple contusion", "Isolated meniscus tear", "Patellar tendon rupture", "Ankle sprain"], "ans": 0, "exp": "Knee dislocation (high-energy) เสี่ยง 'popliteal artery injury' (tethered ที่ adductor hiatus/soleus arch) และ common peroneal nerve — แม้ reduce เองแล้วก็ต้องประเมิน vascular (ABI, serial exam, CT angiography ถ้า abnormal). Vascular injury ที่พลาด → limb loss. multiligament injury มัก ต้อง reconstruction."}, {"topic": "Orthopedics", "q": "A patient has a comminuted fracture that has failed to heal after 9 months with a persistent gap. What is this complication called?", "choices": ["Malunion", "Nonunion", "Delayed union", "Avascular necrosis", "Osteomyelitis"], "ans": 1, "exp": "Nonunion: fracture ที่ไม่ติดหลังเวลาที่คาด (มัก >6-9 เดือน, ไม่มี progression). ปัจจัย: poor blood supply, infection, instability/motion, gap, สูบบุหรี่, NSAIDs. รักษา: stable fixation + bone graft (± แก้ไข infection/biology). Malunion = ติดในตำแหน่งผิด; Delayed union = ช้าแต่ยังดำเนินอยู่."}, {"topic": "Orthopedics", "q": "A patient who took long-term corticosteroids has progressive hip pain; MRI shows a subchondral crescent sign of the femoral head. What is the diagnosis?", "choices": ["Osteoarthritis for this patient", "Septic arthritis for this patient", "Avascular necrosis of the femoral head", "Stress fracture for this patient", "Transient osteoporosis in this case"], "ans": 2, "exp": "Avascular (osteo)necrosis ของ femoral head: ปัจจัยเสี่ยง 'corticosteroid, alcohol', sickle cell, femoral neck fracture/dislocation, SLE, caisson. MRI ไวสุด (crescent sign, สาย). รักษาตามระยะ: core decompression (early, pre-collapse), joint-preserving; collapsed → total hip replacement."}, {"topic": "Orthopedics", "q": "A baby is delivered with shoulder dystocia and now holds the arm adducted, internally rotated, with the forearm pronated ('waiter's tip'). Which brachial plexus injury is this?", "choices": ["Klumpke palsy (C8-T1)", "Radial nerve palsy", "Total plexus palsy", "Erb palsy (C5-C6)", "Axillary nerve palsy"], "ans": 3, "exp": "Erb-Duchenne palsy (upper trunk C5-C6): จาก shoulder dystocia/traction → 'waiter's tip' (arm adducted, internally rotated, forearm pronated, wrist flexed). Klumpke (lower trunk C8-T1) → 'claw hand' ± Horner syndrome. ส่วนใหญ่ Erb ฟื้นเองด้วย physio; ไม่ฟื้น → microsurgery."}, {"topic": "Orthopedics", "q": "A patient falls on an outstretched hand and has elbow pain with inability to fully extend; X-ray shows a subtle radial head fracture with a positive 'sail sign' (fat pad). What is the management for a non-displaced fracture?", "choices": ["Long-arm cast for 8 weeks", "Immediate ORIF always", "Radial head excision", "No follow-up needed", "Early mobilization with a sling"], "ans": 4, "exp": "Radial head fracture (พบบ่อยหลัง FOOSH): X-ray อาจเห็นเพียง 'fat pad/sail sign'. Non-displaced/minimally displaced (Mason I) → 'early mobilization' (sling สั้นๆ) เพื่อป้องกันข้อติด. Displaced/block to motion → ORIF/replacement. หลีกเลี่ยง immobilization นาน (เสี่ยง stiffness)."}, {"topic": "Orthopedics", "q": "A patient falls and cannot actively extend the knee; there is a palpable gap above the patella with a high-riding patella. What is the diagnosis?", "choices": ["Quadriceps tendon rupture", "Patellar tendon rupture", "Patellar fracture", "ACL tear", "Meniscal tear"], "ans": 0, "exp": "Quadriceps tendon rupture (มัก >40 ปี): สูญเสีย active knee extension + gap เหนือ patella + patella baja (ต่ำ)... ขออภัย: quadriceps rupture → patella 'อยู่ต่ำกว่าปกติ'. Patellar tendon rupture (<40 ปี) → gap ใต้ patella + patella alta (สูง). ทั้งคู่สูญเสีย extensor mechanism → surgical repair. (ตำแหน่ง gap ช่วยแยก)."}, {"topic": "Orthopedics", "q": "A patient has a knee injury; the tibia can be pushed backward relative to the femur (positive posterior drawer). Which ligament is torn?", "choices": ["Anterior cruciate ligament", "Posterior cruciate ligament", "Medial collateral ligament", "Lateral collateral ligament", "Patellar tendon"], "ans": 1, "exp": "Posterior cruciate ligament (PCL) tear: มักจาก 'dashboard injury' (tibia กระแทกไปหลัง) หรือ hyperflexion → 'posterior drawer positive', posterior sag sign. ส่วนใหญ่ isolated PCL รักษา conservative (physio, quadriceps strengthening); combined/multiligament → reconstruction. ต่างจาก ACL (anterior drawer/Lachman)."}, {"topic": "Orthopedics", "q": "A patient has valgus knee injury with pain and laxity on the medial side. Which ligament is injured?", "choices": ["Lateral collateral ligament", "Anterior cruciate ligament", "Medial collateral ligament", "Posterior cruciate ligament", "Patellar tendon"], "ans": 2, "exp": "Medial collateral ligament (MCL) injury: จากแรง 'valgus' → ปวด/laxity ด้าน medial (valgus stress test). MCL เป็น extra-articular และหายเองได้ดี → รักษา conservative (hinged brace, physio) เป็นส่วนใหญ่. LCL/posterolateral corner injury (varus) พบน้อยกว่าและมักต้องผ่าตัด."}, {"topic": "Orthopedics", "q": "A patient is on the surgical ward after a hip fracture. Which measure reduces the high risk of venous thromboembolism?", "choices": ["High-dose aspirin only", "Bed rest without prophylaxis", "Therapeutic anticoagulation always", "Mechanical and pharmacologic prophylaxis", "No prophylaxis needed"], "ans": 3, "exp": "ผู้ป่วยผ่าตัด hip/ major orthopedic (hip/knee arthroplasty, hip fracture) = 'high VTE risk' → prophylaxis: pharmacologic (LMWH, DOAC, aspirin ในบางแนวทางของ arthroplasty) + mechanical (IPC/stocking) + early mobilization. Extended prophylaxis (~4-5 สัปดาห์) หลัง hip fracture/arthroplasty."}, {"topic": "Orthopedics", "q": "A patient with a total knee replacement 1 year ago has increasing joint pain, effusion, and a sinus tract. What complication should be suspected?", "choices": ["Aseptic loosening only", "Gout", "Simple bursitis", "Referred pain", "Prosthetic joint infection"], "ans": 4, "exp": "Prosthetic joint infection (PJI): ปวดข้อเทียมเรื้อรัง, บวม, warmth, sinus tract, ± ไข้. วินิจฉัย: ESR/CRP สูง, 'joint aspiration' (cell count, culture), imaging. รักษา: debridement + antibiotic; อาจต้อง 1- หรือ 2-stage revision (เอา prosthesis ออก + spacer). แยกจาก aseptic loosening (ไม่มี infection markers)."}, {"topic": "Orthopedics", "q": "A patient has an ankle inversion injury with lateral swelling and tenderness over the anterior talofibular ligament, able to bear weight partially. What grade sprain and management?", "choices": ["Ligament sprain, functional treatment (RICE, brace)", "Achilles rupture for this patient", "Fracture needing ORIF for this patient", "Complete dislocation needing surgery in this case", "Compartment syndrome for this patient"], "ans": 0, "exp": "Ankle sprain (inversion): มักบาดเจ็บ 'anterior talofibular ligament' (lateral). Ottawa ankle rules ช่วยตัดสินใจ X-ray (แยก fracture). ส่วนใหญ่รักษาแบบ functional: RICE, early mobilization, brace, proprioceptive rehab (ดีกว่า immobilization นาน). Severe/instability เรื้อรัง → พิจารณาผ่าตัด."}, {"topic": "Orthopedics", "q": "A runner has localized shin pain and tenderness; X-ray is initially normal but bone scan/MRI shows a stress fracture of the tibia. What is the management?", "choices": ["Immediate surgery for this patient", "Relative rest and activity modification", "Continue running for this patient", "Long-leg cast for 3 months initially", "Amputation for this patient"], "ans": 1, "exp": "Stress fracture (overuse, เปลี่ยนกิจกรรม/เพิ่มระยะเร็ว): ปวดเฉพาะจุด, X-ray แรกปกติ (MRI/bone scan ไวกว่า). รักษา: 'relative rest + activity modification', แก้ปัจจัย (biomechanics, nutrition, female athlete triad). ตำแหน่ง high-risk (anterior tibia, femoral neck, navicular, 5th MT base) เสี่ยง nonunion → อาจต้อง fixation."}, {"topic": "Orthopedics", "q": "An elderly patient has an intertrochanteric hip fracture. Which fixation is typically used?", "choices": ["Total hip replacement always", "Hemiarthroplasty always", "Dynamic hip screw or intramedullary nail", "Conservative traction only", "External fixator"], "ans": 2, "exp": "Intertrochanteric (extracapsular) hip fracture: เลือดเลี้ยงดี (นอก capsule) → 'internal fixation' ด้วย dynamic hip screw (DHS) หรือ intramedullary nail (cephalomedullary). ต่างจาก 'displaced femoral neck' (intracapsular, เสี่ยง AVN) ที่มัก arthroplasty (hemi/total). ผ่าตัดเร็ว + mobilize ลด complication."}, {"topic": "Orthopedics", "q": "A middle-aged patient has bilateral leg pain on walking that is relieved by leaning forward/sitting, with normal pedal pulses. What is the diagnosis?", "choices": ["Peripheral arterial disease for this patient", "DVT for this patient", "Osteoarthritis of the hip for this patient", "Lumbar spinal stenosis (neurogenic claudication)", "Sciatica from disc for this patient"], "ans": 3, "exp": "Lumbar spinal stenosis → 'neurogenic claudication': ปวด/อ่อนแรงขาเมื่อเดิน/ยืน (extension) ดีขึ้นเมื่อ 'ก้มตัว/นั่ง' (flexion เปิด canal), 'pulses ปกติ' (แยกจาก vascular claudication). MRI ยืนยัน. รักษา: physio, analgesia, epidural steroid; ดื้อ → decompressive laminectomy."}, {"topic": "Orthopedics", "q": "A patient has an inversion ankle injury and cannot bear weight; there is bony tenderness at the base of the 5th metatarsal. Per Ottawa rules, what is indicated?", "choices": ["No imaging needed", "MRI first", "CT first", "Immediate surgery", "Ankle/foot X-ray"], "ans": 4, "exp": "Ottawa ankle/foot rules: ทำ X-ray เมื่อมีปวด malleolar/midfoot zone + (bony tenderness ที่ posterior edge/tip ของ malleolus, base of 5th metatarsal, navicular) หรือ 'ลงน้ำหนักไม่ได้ ≥4 ก้าว'. ช่วยลด X-ray โดยไม่พลาด fracture. Base of 5th MT tenderness → X-ray (แยก avulsion/Jones fracture)."}, {"topic": "Orthopedics", "q": "A patient with knee osteoarthritis has pain and functional limitation not controlled by conservative measures. What is the definitive surgical option?", "choices": ["Total knee arthroplasty", "Meniscectomy", "Arthroscopic washout", "Synovectomy", "Fasciotomy"], "ans": 0, "exp": "Knee osteoarthritis: รักษาเริ่มด้วย conservative (ลดน้ำหนัก, exercise/physio, analgesia - paracetamol/NSAIDs, intra-articular steroid). เมื่อ end-stage + failed conservative + คุณภาพชีวิตแย่ → 'total knee arthroplasty' (definitive). Arthroscopic washout ไม่แนะนำใน OA (ไม่ได้ผล)."}, {"topic": "Orthopedics", "q": "A patient sustains a fall from height landing on the feet, with heel pain and swelling; X-ray shows a calcaneal fracture. What associated injury must be checked?", "choices": ["Rib fracture for this patient", "Spinal (thoracolumbar) fracture", "Skull fracture as first step", "Wrist fracture as first step", "Clavicle fracture initially"], "ans": 1, "exp": "Calcaneal fracture (fall from height, axial load): ต้องประเมิน 'associated injuries ตามแนวแรง' — 'thoracolumbar spine fracture' (บ่อย), contralateral calcaneus, pilon/tibial plateau, pelvis. Intra-articular calcaneal fracture (Bohler angle ลด) มัก CT + surgery. เฝ้าระวัง compartment syndrome ของเท้า."}, {"topic": "Orthopedics", "q": "A teenager has progressive lateral curvature of the spine noted on forward bending (rib hump), without pain. What is the diagnosis?", "choices": ["Scheuermann kyphosis", "Ankylosing spondylitis", "Adolescent idiopathic scoliosis", "Vertebral fracture", "Spinal tumor"], "ans": 2, "exp": "Adolescent idiopathic scoliosis: การโค้งด้านข้างของกระดูกสันหลัง (Cobb angle) พบในวัยรุ่น (หญิง), มัก 'ไม่ปวด', ตรวจพบ rib hump เมื่อก้ม (Adam's forward bend). รักษาตาม Cobb angle/skeletal maturity: สังเกต (<20°), brace (20-40° ที่ยังโต), surgery (>45-50°). ปวด/neurologic ต้องหาสาเหตุอื่น."}, {"topic": "Orthopedics", "q": "A 3-year-old refuses to walk after a minor fall; there is a subtle spiral fracture of the tibia (toddler's fracture). What is a key consideration in a child with a spiral fracture?", "choices": ["Always benign, no concern for this patient", "Requires amputation for this patient", "Always pathologic for this patient", "Consider mechanism and abuse if inconsistent", "Immediate surgery for this patient"], "ans": 3, "exp": "Toddler's fracture (spiral/oblique distal tibia) มักเกิดจาก low-energy twisting ในเด็กหัดเดิน (accidental). อย่างไรก็ตาม 'spiral fracture' โดยเฉพาะในเด็กที่ยังเดินไม่ได้ หรือประวัติไม่สอดคล้อง ต้องพิจารณา 'non-accidental injury'. Toddler's fracture ที่เข้าได้กับประวัติรักษาด้วย cast/observation."}, {"topic": "Orthopedics", "q": "A young man has low back pain and stiffness worse in the morning and improving with exercise, with reduced spinal mobility; HLA-B27 positive. What is the diagnosis?", "choices": ["Spinal stenosis", "Mechanical back pain", "Disc herniation", "Osteoporotic fracture", "Ankylosing spondylitis"], "ans": 4, "exp": "Ankylosing spondylitis (seronegative spondyloarthropathy, HLA-B27): ปวดหลัง 'inflammatory' (แย่ตอนเช้า/พัก, ดีขึ้นเมื่อออกกำลัง, อายุ <40), sacroiliitis, ลด spinal mobility, 'bamboo spine' (สาย). รักษา: NSAIDs + exercise, biologics (anti-TNF/IL-17). เสี่ยง fracture (rigid spine), uveitis. ต่างจาก mechanical back pain."}, {"topic": "Orthopedics", "q": "A patient has a hip fracture and, before surgery, is placed in skin traction. What is the main purpose?", "choices": ["Pain relief and provisional immobilization", "Correct rotation permanently initially", "Definitive treatment for this patient", "Prevent infection for this patient", "Reduce blood loss to zero as first step"], "ans": 0, "exp": "Skin/skeletal traction ก่อนผ่าตัด: ช่วย 'บรรเทาปวดและ immobilize ชั่วคราว' (แต่หลักฐานประโยชน์ routine skin traction จำกัด). ไม่ใช่ definitive treatment. Definitive คือผ่าตัด fixation/arthroplasty เร็ว. Skeletal traction ใช้ใน femoral shaft fracture บางกรณีเป็น temporizing."}, {"topic": "Orthopedics", "q": "A neonate has a lateral neck mass and the head tilted toward one side with the chin rotated to the opposite side. What is the diagnosis?", "choices": ["Cervical lymphadenitis", "Congenital muscular torticollis", "Klippel-Feil syndrome", "Branchial cyst", "Cystic hygroma"], "ans": 1, "exp": "Congenital muscular torticollis: การหดสั้น/fibrosis ของ sternocleidomastoid (อาจคลำได้ก้อน 'sternomastoid tumor') → head tilt เข้าด้าน affected, chin หันออก. สัมพันธ์ breech/birth trauma, DDH. รักษา: 'stretching/physiotherapy' (ส่วนใหญ่หาย); ดื้อ → surgical release. ประเมิน plagiocephaly/DDH ร่วม."}, {"topic": "Orthopedics", "q": "A child has bowed legs, delayed growth, widened wrists, and a rachitic rosary; labs show low vitamin D, low phosphate, and high alkaline phosphatase. What is the diagnosis?", "choices": ["Osteogenesis imperfecta", "Achondroplasia", "Rickets", "Scurvy", "Blount disease"], "ans": 2, "exp": "Rickets: การขาด mineralization ของ growth plate (vitamin D deficiency พบบ่อย) → bowing legs (genu varum), widened wrists/costochondral junction ('rachitic rosary'), frontal bossing, growth delay; ALP สูง, Ca/PO4 ต่ำ. รักษา: vitamin D + calcium (± phosphate ใน hypophosphatemic types). Osteomalacia = ในผู้ใหญ่."}, {"topic": "Orthopedics", "q": "A patient has an olecranon fracture with an inability to actively extend the elbow against gravity. What is the appropriate management for a displaced fracture?", "choices": ["Long-arm cast only", "Sling and early motion initially", "Radial head excision in this case", "Open reduction and internal fixation", "Observation for this patient"], "ans": 3, "exp": "Olecranon fracture ที่ 'displaced' (สูญเสีย extensor mechanism - triceps ดึงแยก) → 'ORIF' (tension band wiring หรือ plate) เพื่อฟื้น extensor function และ articular congruity. Non-displaced/stable → immobilization สั้นๆ + early motion. ประเมิน ulnar nerve."}, {"topic": "Orthopedics", "q": "A young athlete dislocates the patella laterally after a twisting injury. After reduction, what is the initial management for a first-time dislocation?", "choices": ["Long cast for 3 months", "Immediate reconstruction", "Patellectomy", "No treatment", "Bracing/rehabilitation"], "ans": 4, "exp": "Patellar dislocation (มัก lateral, จาก valgus/twist): reduce (extend knee) → 'bracing + rehabilitation' (quadriceps/VMO strengthening) สำหรับ first-time ที่ไม่มี osteochondral fragment. Recurrent/large osteochondral fragment/MPFL rupture → surgery (MPFL reconstruction). ประเมิน predisposing factors (patella alta, trochlear dysplasia)."}, {"topic": "Orthopedics", "q": "A patient develops a hot, swollen, painful great toe joint; aspiration shows positively birefringent, rhomboid-shaped crystals. What is the diagnosis?", "choices": ["Pseudogout (CPPD)", "Septic arthritis", "Gout", "Rheumatoid arthritis", "Reactive arthritis"], "ans": 0, "exp": "Pseudogout (calcium pyrophosphate deposition, CPPD): crystals 'rhomboid, positively birefringent', มัก knee/wrist (แต่พบที่อื่นได้), chondrocalcinosis บน X-ray. สัมพันธ์ hyperparathyroidism, hemochromatosis, hypomagnesemia, สูงอายุ. รักษาเฉียบพลัน: NSAIDs/colchicine/steroid. ต่างจาก gout (urate, needle, negatively birefringent)."}, {"topic": "Orthopedics", "q": "A patient has forefoot pain and a burning sensation with a clicking on compression between the 3rd and 4th toes (Mulder click). What is the diagnosis?", "choices": ["Plantar fasciitis", "Morton neuroma", "Stress fracture", "Hallux valgus", "Gout"], "ans": 1, "exp": "Morton neuroma: perineural fibrosis ของ interdigital nerve (มัก 3rd-4th webspace) → ปวดแสบ/ชานิ้วเท้า, 'Mulder click' เมื่อบีบ. สัมพันธ์รองเท้าคับ/ส้นสูง. รักษา: metatarsal pad, รองเท้ากว้าง, steroid injection; ดื้อ → excision. ต่างจาก stress fracture (bony tenderness)."}, {"topic": "Orthopedics", "q": "A patient has a deformity where the great toe deviates laterally toward the other toes with a prominent medial eminence. What is the diagnosis?", "choices": ["Claw toe", "Hammer toe", "Hallux valgus (bunion)", "Hallux rigidus", "Morton neuroma"], "ans": 2, "exp": "Hallux valgus (bunion): นิ้วหัวแม่เท้าเบนออก (valgus) + medial eminence นูน, สัมพันธ์รองเท้าคับ/พันธุกรรม/หญิง. รักษา: รองเท้ากว้าง, orthotics, spacer (conservative); ปวด/deformity มาก → surgery (osteotomy). Hallux rigidus = OA ของ 1st MTP (จำกัดการงอ/เหยียด)."}, {"topic": "Orthopedics", "q": "A patient has an ingrown toenail with a red, painful, swollen nail fold with granulation tissue. What is the appropriate management for recurrent/severe cases?", "choices": ["No treatment for this patient", "Systemic antifungals for this patient", "Complete toe amputation in this case", "Partial nail avulsion with matricectomy", "Oral steroids for this patient"], "ans": 3, "exp": "Ingrown toenail (onychocryptosis): ขอบเล็บฝังเข้าเนื้อ → อักเสบ/granulation. เบื้องต้น: แช่น้ำอุ่น, ยกขอบเล็บ, สุขอนามัย, antibiotic ถ้าติดเชื้อ. เป็นซ้ำ/รุนแรง → 'partial nail avulsion + matricectomy' (phenol/surgical) เพื่อกำจัด nail matrix ด้านนั้นถาวร. ในเบาหวานระวังภาวะแทรกซ้อน."}, {"topic": "Orthopedics", "q": "A 2-year-old has a limp; imaging shows a hip joint effusion, and he has a low-grade fever after a recent viral illness with normal inflammatory markers. What is the most likely diagnosis?", "choices": ["SCFE", "Septic arthritis", "Perthes disease", "Osteomyelitis", "Transient synovitis"], "ans": 4, "exp": "Transient synovitis (irritable hip): สาเหตุ hip pain/limp ที่พบบ่อยในเด็ก (3-8 ปี) หลัง viral URI — ไข้ต่ำ/ไม่มี, inflammatory markers ปกติ/สูงเล็กน้อย, ยังพอลงน้ำหนักได้บ้าง. เป็น self-limited (NSAIDs, rest). สำคัญคือต้อง 'แยก septic arthritis' (Kocher criteria) ซึ่งเป็น emergency."}, {"topic": "Orthopedics", "q": "A patient with rheumatoid arthritis has ulnar deviation of the fingers, swan-neck and boutonniere deformities. What is the underlying process?", "choices": ["Chronic synovitis eroding joints and tendons", "Infection for this patient", "Crystal deposition for this patient", "Degenerative wear only", "Nerve compression for this patient"], "ans": 0, "exp": "Rheumatoid arthritis: chronic autoimmune 'synovitis' (pannus) → erosion ของ joint/cartilage + laxity ของ ligament/tendon → deformity (ulnar deviation, swan-neck, boutonniere, Z-thumb, MCP subluxation). รักษา: DMARDs (methotrexate)/biologics ควบคุมโรค; surgery (synovectomy, arthroplasty, tendon repair) ในรายที่เสียหาย. ต่างจาก OA (Heberden/Bouchard, DIP)."}, {"topic": "Orthopedics", "q": "A patient in a plaster cast complains of increasing pain, tightness, and numbness of the fingers hours later. What is the immediate action?", "choices": ["Apply a tighter cast", "Split/remove the cast and assess", "Give more analgesia and wait", "Elevate and reassure only", "Order an MRI first"], "ans": 1, "exp": "ปวดเพิ่มขึ้น + tightness + ชา/เย็นปลายมือหลังใส่เฝือก = สงสัย 'cast too tight / compartment syndrome' → 'split หรือถอดเฝือกทันที' (bivalve, ตัด padding ถึงผิว) และประเมิน neurovascular. อย่าให้ยาแก้ปวดแล้วรอ. ป้องกันภาวะแทรกซ้อน ischemia/Volkmann contracture."}, {"topic": "Orthopedics", "q": "A patient sustains a high-energy axial load to the knee; X-ray shows a depressed lateral tibial plateau fracture. What imaging best defines the fracture for surgical planning?", "choices": ["DEXA scan", "Ultrasound", "CT scan", "Bone scan", "Plain X-ray only"], "ans": 2, "exp": "Tibial plateau fracture: 'CT scan' ประเมิน articular depression/split, comminution เพื่อวางแผนผ่าตัด (ORIF ใน displaced/depressed intra-articular). ประเมิน soft tissue (compartment syndrome, ligament/meniscus, popliteal vessel ใน high-energy). Depressed articular surface >กำหนด → surgery เพื่อคง joint congruity."}, {"topic": "Orthopedics", "q": "A patient has midfoot pain after a fall; X-ray shows widening between the 1st and 2nd metatarsal bases with a small avulsion ('fleck sign'). What injury is this?", "choices": ["Calcaneal fracture", "Jones fracture", "March fracture", "Lisfranc injury", "Ankle sprain"], "ans": 3, "exp": "Lisfranc injury (tarsometatarsal joint complex): midfoot pain/swelling, ลงน้ำหนักไม่ได้, 'fleck sign' (avulsion ที่ base 2nd MT) + widening 1st-2nd MT. อาจพลาดได้ง่าย → weight-bearing X-ray/CT. Unstable/displaced → ORIF (missed injury → chronic pain/arthritis). ระวัง compartment syndrome ของเท้า."}, {"topic": "Orthopedics", "q": "A patient has an elbow dislocation (posterior). After reduction, what must be assessed and documented?", "choices": ["Only the X-ray for this patient", "Blood glucose for this patient", "Chest X-ray for this patient", "Abdominal exam for this patient", "Neurovascular status and joint stability"], "ans": 4, "exp": "Elbow dislocation (posterior พบบ่อยสุด): ประเมิน 'neurovascular ก่อน/หลัง reduction' (brachial artery, ulnar/median nerve) + ตรวจ stability + X-ray หลัง reduce (แยก associated fracture - 'terrible triad': radial head + coronoid + LCL). Simple → early motion; complex/unstable → surgery."}, {"topic": "Orthopedics", "q": "A patient with chronic osteomyelitis has a persistent draining sinus; imaging shows a segment of dead bone (sequestrum). What is the definitive treatment principle?", "choices": ["Surgical debridement of dead bone plus antibiotics", "Amputation always for this patient", "Antibiotics alone indefinitely for this patient", "Observation for this patient", "Splinting only"], "ans": 0, "exp": "Chronic osteomyelitis: มี 'sequestrum' (dead bone) และ involucrum, sinus tract. ยาปฏิชีวนะอย่างเดียวไม่พอ (เข้าไม่ถึง dead bone) → ต้อง 'surgical debridement/sequestrectomy' เอา dead/infected bone ออก + antibiotic (ตาม culture) + จัดการ dead space/soft tissue. เสี่ยง Marjolin ulcer (SCC) ใน sinus เรื้อรัง."}, {"topic": "Orthopedics", "q": "A patient falls on an outstretched hand and has a scaphoid fracture at the proximal pole. What complication is this location prone to?", "choices": ["Compartment syndrome alone", "Avascular necrosis and nonunion", "Rapid healing as first step", "Growth arrest as first step", "Infection for this patient"], "ans": 1, "exp": "Scaphoid มีเลือดเลี้ยง 'retrograde' (จาก distal → proximal) จึง fracture ที่ 'proximal pole' เสี่ยง avascular necrosis และ nonunion สูงสุด → มักต้อง fixation (screw) + ติดตาม. Waist fracture (พบบ่อยสุด) ก็เสี่ยงพอควร. Displaced/proximal → surgical fixation."}, {"topic": "Orthopedics", "q": "A patient has a displaced patellar fracture with loss of active knee extension and a palpable gap. What is the management?", "choices": ["Sling and rest for this patient", "Long-leg cast only", "Open reduction and internal fixation", "Patellectomy always as first step", "Observation for this patient"], "ans": 2, "exp": "Patellar fracture ที่ 'displaced' + สูญเสีย extensor mechanism (active extension ไม่ได้/gap) → 'ORIF' (tension band/screw) เพื่อฟื้น extensor function + articular surface. Non-displaced ที่ extensor mechanism ยังทำงาน → immobilization + protected weight bearing. Comminuted รุนแรง → partial patellectomy."}, {"topic": "Orthopedics", "q": "A 60-year-old man with hip osteoarthritis has groin pain and reduced internal rotation. Conservative treatment has failed. What is the definitive option?", "choices": ["Arthroscopy", "Core decompression", "Osteotomy always", "Total hip arthroplasty", "Fusion"], "ans": 3, "exp": "Hip osteoarthritis: ปวดขาหนีบ, ลด internal rotation, X-ray (joint space narrowing, osteophyte, subchondral sclerosis/cyst). รักษาเริ่ม conservative (exercise, ลดน้ำหนัก, analgesia). End-stage + failed conservative → 'total hip arthroplasty' (definitive, ผลดีมาก). ต่างจาก AVN early ที่อาจ core decompression."}, {"topic": "Orthopedics", "q": "A trauma patient has a suspected cervical spine injury. Which criteria can be used to clinically clear the c-spine without imaging in a low-risk patient?", "choices": ["Alvarado score", "Ottawa ankle rules", "Wells score", "Glasgow-Blatchford score", "NEXUS or Canadian C-spine rule"], "ans": 4, "exp": "การ clear cervical spine ทางคลินิก (low-risk, alert, ไม่มึนเมา): ใช้ 'NEXUS criteria' (no midline tenderness, no focal deficit, normal alertness, no intoxication, no distracting injury) หรือ 'Canadian C-spine rule'. ถ้าไม่ผ่านเกณฑ์ → imaging (CT). ช่วยลด imaging ที่ไม่จำเป็นอย่างปลอดภัย."}, {"topic": "Orthopedics", "q": "A young man is in a rear-end collision and develops neck pain and stiffness 1-2 days later with normal imaging. What is the diagnosis and management?", "choices": ["Whiplash-associated disorder, analgesia and early mobilization", "Cervical fracture, halo for this patient", "Cord compression, surgery for this patient", "Meningitis, antibiotics for this patient", "Cervical dislocation, traction for this patient"], "ans": 0, "exp": "Whiplash-associated disorder: soft tissue (cervical) strain จาก acceleration-deceleration (rear-end) → ปวด/ตึงคอ (มักแย่ขึ้น 1-2 วัน), ปวดศีรษะ; imaging ปกติ. รักษา: analgesia, 'early mobilization/exercise' (ดีกว่า immobilization/collar นาน), reassurance. ส่วนใหญ่หายเอง. ต้อง exclude fracture ก่อน (rules/imaging)."}, {"topic": "Orthopedics", "q": "A child has a completely displaced distal radius fracture. Compared with adults, what is a key difference in management?", "choices": ["Heals more slowly than adults for this patient", "Greater remodeling potential allows some residual deformity", "Never needs reduction for this patient", "Always needs plating for this patient", "Cannot be casted for this patient"], "ans": 1, "exp": "Fractures ในเด็กมี 'remodeling potential สูง' (โดยเฉพาะใกล้ physis, angulation ในระนาบการเคลื่อนไหวของข้อ) → ยอมรับ residual angulation ได้มากกว่าผู้ใหญ่ และหายเร็วกว่า. รักษาส่วนใหญ่ closed reduction + cast. หลีกเลี่ยงรบกวน growth plate. Rotational deformity ไม่ remodel."}, {"topic": "Orthopedics", "q": "A patient after major trauma has flaccid paralysis and areflexia below the level of a spinal cord injury in the acute phase. What is this transient state called?", "choices": ["Neurogenic shock", "Cauda equina syndrome", "Spinal shock", "Central cord syndrome", "Brown-Sequard syndrome"], "ans": 2, "exp": "Spinal shock: ภาวะชั่วคราวหลัง spinal cord injury เฉียบพลัน — flaccid paralysis + areflexia + ไม่มี sensation ใต้ระดับ (reflex arc หยุดทำงานชั่วคราว). การกลับมาของ 'bulbocavernosus reflex' บ่งชี้สิ้นสุด spinal shock (แล้วจึงประเมิน deficit ที่แท้จริง). ต่างจาก neurogenic shock (hemodynamic - hypotension/bradycardia)."}, {"topic": "Orthopedics", "q": "A patient has an amputated fingertip/digit brought in on ice. What is a key principle for transport of the amputated part for possible replantation?", "choices": ["Freeze it solid for this patient", "Place directly on dry ice for this patient", "Immerse in warm water for this patient", "Wrap in saline gauze, seal in a bag, place on ice (not direct)", "Discard it for this patient"], "ans": 3, "exp": "การเก็บ amputated part เพื่อ replantation: ห่อด้วย 'saline-moistened gauze', ใส่ถุงกันน้ำ, แล้ววางบน ice (ไม่สัมผัสน้ำแข็ง/dry ice โดยตรง - เสี่ยง frostbite). ไม่แช่น้ำหรือแช่แข็ง. Replantation พิจารณาใน thumb, multiple digits, เด็ก, ระดับ palm/proximal. Warm ischemia time สำคัญ."}, {"topic": "Orthopedics", "q": "A patient has an untreated developmental dysplasia of the hip diagnosed late in childhood with a dislocated hip. What is a consequence of late/untreated DDH?", "choices": ["No long-term effect for this patient", "Spontaneous full recovery for this patient", "Bone tumor for this patient", "Osteomyelitis for this patient", "Early osteoarthritis and limb length discrepancy"], "ans": 4, "exp": "DDH ที่ไม่รักษา/รักษาช้า → acetabular dysplasia, hip dislocation ต่อเนื่อง → 'early degenerative osteoarthritis', limb length discrepancy, กะเผลก (Trendelenburg gait). จึงเน้นคัดกรอง/รักษาแต่เนิ่น (Pavlik <6 เดือน). ช้า → closed/open reduction + osteotomy ตามอายุ. ยิ่งช้ายิ่งผลลัพธ์แย่."}]}, {"id": "surg4", "title": "Surgery ชุดที่ 4 — Neurosurgery, Cardiothoracic & Vascular Surgery", "subject": "surg", "questions": [{"topic": "Neuro/CVT/Vascular", "q": "A young man is hit on the temple, briefly loses consciousness, then has a 'lucid interval' before deteriorating. CT shows a biconvex (lens-shaped) hyperdensity. What is the diagnosis?", "choices": ["Epidural hematoma", "Subdural hematoma", "Subarachnoid hemorrhage", "Diffuse axonal injury", "Cerebral contusion"], "ans": 0, "exp": "Epidural (extradural) hematoma: มัก 'middle meningeal artery' (temporal bone fracture) → 'lucid interval' แล้วทรุด. CT: 'biconvex/lens-shaped' (ไม่ข้าม suture line). เป็น neurosurgical emergency → craniotomy evacuation. พยากรณ์ดีถ้ารักษาเร็ว (ก่อน herniation)."}, {"topic": "Neuro/CVT/Vascular", "q": "An elderly man on anticoagulants has gradual confusion and headache weeks after a minor fall. CT shows a crescent-shaped hyperdensity crossing suture lines. What is the diagnosis?", "choices": ["Subarachnoid hemorrhage", "Subdural hematoma", "Epidural hematoma", "Intracerebral hemorrhage", "Brain tumor"], "ans": 1, "exp": "Subdural hematoma: จาก 'bridging veins' tear — พบในผู้สูงอายุ/anticoagulant/alcoholic (brain atrophy), มักหลัง minor trauma, อาการค่อยเป็นค่อยไป. CT: 'crescent-shaped' (concave), ข้าม suture line ได้ (แต่ไม่ข้าม midline/dural reflection). Acute (hyperdense) vs chronic (hypodense). รักษา: evacuation ถ้ามีอาการ/large."}, {"topic": "Neuro/CVT/Vascular", "q": "A patient has a sudden severe 'thunderclap' headache ('worst of my life') with neck stiffness. CT shows blood in the basal cisterns. What is the diagnosis?", "choices": ["Epidural hematoma", "Migraine", "Subarachnoid hemorrhage", "Meningitis", "Tension headache"], "ans": 2, "exp": "Subarachnoid hemorrhage (มักจาก 'ruptured berry aneurysm'): 'thunderclap headache' (รุนแรงเฉียบพลันสุดในชีวิต) + meningism + อาจ LOC. CT (blood ใน basal cisterns); ถ้า CT ปกติแต่สงสัย → LP (xanthochromia). หา aneurysm (CTA) → coiling/clipping. ภาวะแทรกซ้อน: rebleed, vasospasm, hydrocephalus."}, {"topic": "Neuro/CVT/Vascular", "q": "A trauma patient with a GCS of 6 is deteriorating with a blown (dilated, fixed) pupil on one side. What does this indicate?", "choices": ["Simple concussion in this case", "Migraine for this patient", "Bell palsy for this patient", "Uncal (transtentorial) herniation", "Horner syndrome as first step"], "ans": 3, "exp": "Unilateral fixed/dilated pupil + ทรุดลง = 'uncal herniation' กด CN III (parasympathetic) และ midbrain → เป็น neurosurgical emergency. จัดการ raised ICP: head up 30°, controlled ventilation, hyperosmolar (mannitol/hypertonic saline), และ 'urgent CT + neurosurgery' (evacuate mass). Cushing triad (HT, bradycardia, irregular breathing) = สัญญาณสาย."}, {"topic": "Neuro/CVT/Vascular", "q": "A head injury patient has raised intracranial pressure. Which triad of signs indicates impending herniation (Cushing reflex)?", "choices": ["Hypotension, tachycardia, fever", "Hypertension, tachycardia, tachypnea", "Hypotension, bradycardia, apnea", "Fever, neck stiffness, rash", "Hypertension, bradycardia, irregular respiration"], "ans": 4, "exp": "Cushing reflex/triad (สัญญาณ raised ICP รุนแรง/impending herniation): 'hypertension (widened pulse pressure) + bradycardia + irregular respiration'. เป็นสัญญาณสาย — ต้องลด ICP ด่วน. หลักการ ICP: keep CPP (=MAP-ICP), หลีกเลี่ยง hypoxia/hypercarbia/hypotension (secondary injury)."}, {"topic": "Neuro/CVT/Vascular", "q": "A patient has clear fluid draining from the nose after a basilar skull fracture, with periorbital bruising ('raccoon eyes'). What is this fluid?", "choices": ["CSF rhinorrhea", "Saliva", "Nasal mucus", "Blood only", "Lymph"], "ans": 0, "exp": "Basilar skull fracture: 'raccoon eyes' (periorbital ecchymosis), Battle sign (mastoid), hemotympanum, และ 'CSF leak' (rhinorrhea/otorrhea - ตรวจ 'halo/ring sign' หรือ beta-2 transferrin). เสี่ยง meningitis. ส่วนใหญ่ CSF leak หายเอง (bed rest, head up); persistent → repair. หลีกเลี่ยงใส่ NG ทางจมูก (risk intracranial)."}, {"topic": "Neuro/CVT/Vascular", "q": "A middle-aged woman has progressive headache, seizures, and a dural-based, well-circumscribed extra-axial mass that enhances homogeneously on MRI. What is the most likely diagnosis?", "choices": ["Glioblastoma", "Meningioma", "Metastasis", "Acoustic neuroma", "Pituitary adenoma"], "ans": 1, "exp": "Meningioma: benign extra-axial tumor จาก arachnoid cap cells — 'dural-based, well-circumscribed, homogeneous enhancement, dural tail', พบในหญิงวัยกลางคน. ส่วนใหญ่โตช้า. รักษา: สังเกต (เล็ก/ไม่มีอาการ) หรือ surgical resection ± RT. ต่างจาก glioblastoma (intra-axial, infiltrative, ring-enhancing, พยากรณ์แย่)."}, {"topic": "Neuro/CVT/Vascular", "q": "A patient with lung cancer develops headache, vomiting, and papilledema; MRI shows multiple ring-enhancing lesions at the gray-white junction. What is the most likely diagnosis?", "choices": ["Brain abscess", "Primary glioma", "Brain metastases", "Meningioma", "Multiple sclerosis"], "ans": 2, "exp": "Brain metastases: มะเร็งที่แพร่ไปสมองบ่อย (lung, breast, melanoma, renal, GI) — 'multiple lesions ที่ gray-white junction', ring-enhancing + edema. เป็นสาเหตุ brain tumor ในผู้ใหญ่ที่พบบ่อยกว่า primary. รักษา: steroid (edema), surgery/SRS/WBRT + รักษามะเร็งต้นเหตุ. แยกจาก abscess (ประวัติติดเชื้อ, DWI restriction)."}, {"topic": "Neuro/CVT/Vascular", "q": "A patient has bitemporal hemianopia, headache, and hormonal disturbance. MRI shows a sellar/suprasellar mass. What is the diagnosis?", "choices": ["Acoustic neuroma", "Meningioma", "Craniopharyngioma only", "Pituitary adenoma", "Glioma"], "ans": 3, "exp": "Pituitary adenoma: sellar mass กด optic chiasm → 'bitemporal hemianopia' + hormonal (prolactinoma - galactorrhea/amenorrhea; acromegaly - GH; Cushing - ACTH; หรือ hypopituitarism). วินิจฉัย MRI + hormone panel. รักษา: prolactinoma → dopamine agonist; อื่นๆ/กดเบียด → transsphenoidal surgery. Pituitary apoplexy = ฉุกเฉิน."}, {"topic": "Neuro/CVT/Vascular", "q": "A patient has progressive unilateral hearing loss, tinnitus, and imbalance; MRI shows a mass at the cerebellopontine angle. What is the diagnosis?", "choices": ["Glioma for this patient", "Meningioma for this patient", "Pituitary adenoma for this patient", "Metastasis for this patient", "Acoustic neuroma (vestibular schwannoma)"], "ans": 4, "exp": "Acoustic neuroma (vestibular schwannoma): เนื้องอกจาก CN VIII ที่ cerebellopontine angle → progressive sensorineural hearing loss, tinnitus, imbalance; ใหญ่ขึ้นกด CN V/VII, brainstem. Bilateral สัมพันธ์ NF2. รักษา: สังเกต, SRS, หรือ microsurgery. MRI internal auditory canal."}, {"topic": "Neuro/CVT/Vascular", "q": "An elderly patient has the triad of gait disturbance, urinary incontinence, and dementia; CT shows enlarged ventricles out of proportion to atrophy. What is the diagnosis?", "choices": ["Normal pressure hydrocephalus", "Parkinson disease", "Alzheimer disease", "Brain tumor", "Chronic subdural hematoma"], "ans": 0, "exp": "Normal pressure hydrocephalus (NPH): triad 'wet, wacky, wobbly' (urinary incontinence + dementia + gait apraxia - 'magnetic gait'), ventriculomegaly ไม่สมกับ atrophy. เป็นสาเหตุ dementia ที่ 'รักษาได้' → ตอบสนอง 'VP shunt' (large-volume LP tap test ทำนายการตอบสนอง). Gait มักดีขึ้นชัดสุด."}, {"topic": "Neuro/CVT/Vascular", "q": "A child has an obstructing posterior fossa tumor causing hydrocephalus with headache, vomiting, and papilledema. What is the mechanism of hydrocephalus?", "choices": ["Meningitis only", "Obstruction of CSF flow", "Overproduction of CSF only", "Cerebral atrophy", "Normal variant"], "ans": 1, "exp": "Obstructive (non-communicating) hydrocephalus: การอุดกั้นการไหลของ CSF (เช่น posterior fossa tumor กด 4th ventricle/aqueduct) → CSF คั่งเหนือจุดอุดตัน → raised ICP (headache, vomiting, papilledema, ในทารก head circumference โต/sunset eyes). รักษา: แก้สาเหตุ (resect tumor) + CSF diversion (EVD/VP shunt/ETV)."}, {"topic": "Neuro/CVT/Vascular", "q": "A patient has a spinal cord injury with ipsilateral motor loss and proprioception loss, and contralateral pain/temperature loss below the lesion. What syndrome is this?", "choices": ["Cauda equina syndrome", "Central cord syndrome", "Brown-Sequard syndrome", "Anterior cord syndrome", "Complete transection"], "ans": 2, "exp": "Brown-Sequard syndrome (hemisection ของ cord): 'ipsilateral' motor (corticospinal) + proprioception/vibration (dorsal column) loss + 'contralateral' pain/temperature loss (spinothalamic, cross แล้ว) ใต้ระดับ. มักจาก penetrating trauma. พยากรณ์ค่อนข้างดีในการฟื้น."}, {"topic": "Neuro/CVT/Vascular", "q": "An elderly patient with cervical spondylosis has a hyperextension neck injury; he has weakness worse in the upper limbs than lower limbs. What syndrome is this?", "choices": ["Posterior cord syndrome", "Anterior cord syndrome", "Brown-Sequard syndrome", "Central cord syndrome", "Complete injury"], "ans": 3, "exp": "Central cord syndrome (พบบ่อยสุดใน incomplete cord injury): มักจาก hyperextension ในผู้สูงอายุที่มี cervical spondylosis → 'แขนอ่อนแรงมากกว่าขา' (upper limb fibers อยู่กลาง/medial), ± sensory/bladder. รักษา: ส่วนใหญ่ conservative + rehab; decompression ในรายที่มี compression/ไม่ดีขึ้น. พยากรณ์ฟื้นตัวได้บ้าง."}, {"topic": "Neuro/CVT/Vascular", "q": "A neonate has a lumbar sac protruding from the back containing neural tissue, with lower limb weakness. What is the diagnosis?", "choices": ["Meningocele", "Spina bifida occulta", "Encephalocele", "Sacrococcygeal teratoma", "Myelomeningocele"], "ans": 4, "exp": "Myelomeningocele (open neural tube defect): ถุงยื่นออกมามี 'neural tissue' (spinal cord/nerve roots) → neurologic deficit (ขาอ่อนแรง, bladder/bowel), มัก hydrocephalus/Chiari II. ป้องกันด้วย folic acid. รักษา: ผ่าตัดปิดเร็ว (ลดติดเชื้อ) + จัดการ hydrocephalus. ต่างจาก meningocele (มีแค่ meninges/CSF, มัก neuro ปกติ)."}, {"topic": "Neuro/CVT/Vascular", "q": "A patient with a middle ear infection develops fever, headache, and a ring-enhancing lesion with central restricted diffusion on MRI. What is the diagnosis?", "choices": ["Brain abscess", "Glioblastoma", "Metastasis", "Meningioma", "Infarct"], "ans": 0, "exp": "Brain abscess: มักจากการลุกลามของการติดเชื้อข้างเคียง (otitis/sinusitis/mastoiditis), hematogenous (endocarditis, cyanotic heart), หรือ penetrating. MRI: ring-enhancing + 'central restricted diffusion (DWI)' (แยกจาก tumor). รักษา: antibiotic + aspiration/excision (ถ้าใหญ่/มีอาการ) + แก้แหล่งติดเชื้อ."}, {"topic": "Neuro/CVT/Vascular", "q": "A 55-year-old man has sudden severe tearing chest pain radiating to the back; CT shows an intimal flap in the ascending aorta. What is the diagnosis and management?", "choices": ["Myocardial infarction, PCI for this patient", "Stanford type A aortic dissection, emergency surgery", "Type B dissection, medical only", "Pulmonary embolism, thrombolysis for this patient", "Pericarditis, NSAIDs for this patient"], "ans": 1, "exp": "Aortic dissection: ปวดอกฉีกขาด (tearing) ร้าวหลัง, BP ต่างสองแขน, widened mediastinum. Stanford 'A' (involves ascending aorta) = 'surgical emergency' (เสี่ยง tamponade, aortic regurgitation, coronary/stroke). Stanford 'B' (descending เท่านั้น) = medical (impulse control: beta-blocker คุม HR/BP) เว้นมี complication. คุม BP/HR ทันที."}, {"topic": "Neuro/CVT/Vascular", "q": "A 70-year-old man has a pulsatile abdominal mass; ultrasound shows a 6 cm abdominal aortic aneurysm. He is asymptomatic. What is the management?", "choices": ["Immediate rupture repair", "Observation indefinitely", "Elective surgical/endovascular repair", "Anticoagulation only", "Antibiotics"], "ans": 2, "exp": "Abdominal aortic aneurysm (AAA): asymptomatic → 'elective repair' เมื่อ diameter ≥5.5 cm (ชาย), โตเร็ว (>0.5 cm/6 เดือน), หรือมีอาการ — ด้วย open หรือ EVAR. <5.5 cm → surveillance (US). Ruptured AAA (ปวดท้อง/หลัง + hypotension + pulsatile mass) = emergency repair. คัดกรอง US ในชายสูงอายุที่สูบบุหรี่."}, {"topic": "Neuro/CVT/Vascular", "q": "A 65-year-old smoker has calf pain on walking that resolves with rest (intermittent claudication) and an ankle-brachial index of 0.6. What is the diagnosis?", "choices": ["Deep vein thrombosis", "Spinal stenosis", "Venous insufficiency", "Peripheral arterial disease", "Compartment syndrome"], "ans": 3, "exp": "Peripheral arterial disease (PAD): intermittent claudication (ปวดน่องเมื่อเดิน หายเมื่อพัก), pulses ลด, ABI <0.9 (0.4-0.9 = claudication). ปัจจัยเสี่ยง: บุหรี่, DM, HT, dyslipidemia. รักษา: 'risk factor modification + supervised exercise + antiplatelet + statin'; critical limb ischemia → revascularization. เลิกบุหรี่สำคัญสุด."}, {"topic": "Neuro/CVT/Vascular", "q": "A patient presents with a sudden, cold, pale, painful, pulseless leg. What are the classic '6 Ps', and what is the management priority?", "choices": ["Chronic PAD, observe for this patient", "DVT, anticoagulate only", "Cellulitis, antibiotics for this patient", "Compartment syndrome, elevate for this patient", "Acute limb ischemia, urgent revascularization and heparin"], "ans": 4, "exp": "Acute limb ischemia (6 Ps: Pain, Pallor, Pulselessness, Paresthesia, Paralysis, Poikilothermia/Perishingly cold): จาก embolism (AF, mural thrombus) หรือ thrombosis. เป็น emergency → 'IV heparin ทันที + urgent revascularization' (embolectomy/thrombolysis/bypass). Paralysis/paresthesia = สัญญาณ threatened limb. Time = limb. เฝ้าระวัง reperfusion/compartment syndrome."}, {"topic": "Neuro/CVT/Vascular", "q": "A patient has a transient episode of unilateral arm/leg weakness that resolved in 30 minutes; carotid Doppler shows 80% stenosis on the symptomatic side. What is the appropriate management?", "choices": ["Carotid endarterectomy plus medical therapy", "Immediate thrombolysis for this patient", "No treatment for this patient", "Anticoagulation only", "Observation only"], "ans": 0, "exp": "Symptomatic carotid stenosis (TIA/minor stroke) ที่ stenosis 70-99% → 'carotid endarterectomy' (CEA) + best medical therapy (antiplatelet, statin, risk factor) ลดความเสี่ยง stroke, ทำเร็ว (ภายใน ~2 สัปดาห์). Asymptomatic รักษา medical เป็นหลัก. Carotid stenting เป็นทางเลือกในบางราย."}, {"topic": "Neuro/CVT/Vascular", "q": "A postoperative patient develops a swollen, tender, warm calf with a positive Homan sign. Doppler confirms a deep vein thrombosis. What is the treatment?", "choices": ["Antibiotics", "Anticoagulation", "Compression only", "Immediate surgery", "Elevation only"], "ans": 1, "exp": "Deep vein thrombosis (DVT): ขาบวมข้างเดียว ปวด warmth. ยืนยัน compression ultrasound (Wells score guide). รักษา: 'anticoagulation' (LMWH → DOAC/warfarin, หรือ DOAC ตั้งแต่แรก). เฝ้าระวัง pulmonary embolism. Massive iliofemoral/phlegmasia → พิจารณา thrombolysis/thrombectomy. ป้องกัน post-thrombotic syndrome."}, {"topic": "Neuro/CVT/Vascular", "q": "A patient collapses with sudden dyspnea, pleuritic chest pain, and hypoxia after a long flight; CT pulmonary angiography confirms pulmonary embolism. If hemodynamically unstable, what is indicated?", "choices": ["Observation", "Anticoagulation only", "Thrombolysis", "Antibiotics", "Diuretics"], "ans": 2, "exp": "Pulmonary embolism (PE): dyspnea + pleuritic pain + hypoxia + tachycardia (± RV strain). ยืนยัน CTPA. 'Hemodynamically unstable (massive PE)' → 'systemic thrombolysis' (หรือ embolectomy ถ้าห้าม lysis). Stable → anticoagulation. Wells/PERC + D-dimer guide. ป้องกันด้วย VTE prophylaxis."}, {"topic": "Neuro/CVT/Vascular", "q": "A patient has varicose veins with a healed ulcer over the medial malleolus and hemosiderin skin staining. What is the underlying cause?", "choices": ["Arterial insufficiency", "Diabetic neuropathy", "Lymphedema", "Chronic venous insufficiency", "Vasculitis"], "ans": 3, "exp": "Chronic venous insufficiency: varicose veins, edema, hemosiderin (brown) staining, lipodermatosclerosis, และ 'venous ulcer ที่ medial malleolus (gaiter area)'. รักษา: compression therapy (mainstay), wound care, leg elevation; venous ablation. ต่างจาก arterial ulcer (ปลายนิ้ว/pressure point, punched-out, ปวด, pulses ลด)."}, {"topic": "Neuro/CVT/Vascular", "q": "A 60-year-old man has a lung mass; biopsy shows non-small cell carcinoma. A tumor at the apex causes shoulder/arm pain and Horner syndrome. What is this called?", "choices": ["SVC syndrome", "Mesothelioma", "Carcinoid", "Metastasis", "Pancoast tumor"], "ans": 4, "exp": "Pancoast (superior sulcus) tumor: มะเร็งปอดที่ยอดปอด ลุกลาม brachial plexus (C8-T1 - ปวด/อ่อนแรงแขนด้าน ulnar), sympathetic chain (Horner: ptosis, miosis, anhidrosis), ± bone. มัก NSCLC. วินิจฉัย/รักษาซับซ้อน (neoadjuvant chemoRT + surgery). ต่างจาก SVC syndrome (facial/arm swelling, distended veins)."}, {"topic": "Neuro/CVT/Vascular", "q": "A patient with a right hilar lung mass develops facial swelling, distended neck/chest veins, and headache. What is the diagnosis?", "choices": ["Superior vena cava syndrome", "Pulmonary embolism", "Pancoast tumor", "Cardiac tamponade", "Pneumothorax"], "ans": 0, "exp": "Superior vena cava (SVC) syndrome: การอุดกั้น SVC (มักจาก lung cancer - โดยเฉพาะ small cell, lymphoma) → บวมหน้า/คอ/แขน, distended veins, headache, plethora, dyspnea. วินิจฉัย CT. รักษา: จัดการมะเร็ง (chemo/RT), stent ในรายรุนแรง, steroid/diuretic เสริม. ยกศีรษะสูง."}, {"topic": "Neuro/CVT/Vascular", "q": "A tall thin young man has sudden pleuritic chest pain and dyspnea; chest X-ray shows a small primary spontaneous pneumothorax without tension. What is the management for a small, stable pneumothorax?", "choices": ["Antibiotics", "Observation/oxygen or aspiration", "Immediate chest tube always", "Emergency thoracotomy", "Pleurodesis first-line"], "ans": 1, "exp": "Primary spontaneous pneumothorax (tall thin young men, สูบบุหรี่, จาก apical bleb rupture): small + stable → 'observation ± oxygen หรือ needle aspiration'. Large/symptomatic → chest tube. Recurrent/persistent air leak → VATS + pleurodesis/bullectomy. Tension pneumothorax = needle decompression ทันที (คนละภาวะ)."}, {"topic": "Neuro/CVT/Vascular", "q": "A patient with pneumonia develops a loculated, purulent pleural effusion (empyema). What is the definitive management if the fluid is thick/loculated?", "choices": ["Diuretics for this patient", "Oral antibiotics alone", "Chest tube drainage (and possibly surgery/decortication)", "Observation for this patient", "Repeated aspiration only"], "ans": 2, "exp": "Empyema (pus ใน pleural space, มักจาก pneumonia): pleural fluid pH <7.2/glucose ต่ำ/pus/organisms → ต้อง 'chest tube drainage' + IV antibiotics; loculated/ล้มเหลว → intrapleural fibrinolytics หรือ 'VATS/decortication'. Simple parapneumonic effusion อาจหายด้วยยาปฏิชีวนะ. Stage (exudative→fibrinopurulent→organizing)."}, {"topic": "Neuro/CVT/Vascular", "q": "A child has a harsh pansystolic murmur at the left sternal border; echocardiography shows a ventricular septal defect. Which is true about a small VSD?", "choices": ["Requires transplantation", "Always needs urgent surgery", "Causes cyanosis at birth", "Many close spontaneously", "Is untreatable"], "ans": 3, "exp": "Ventricular septal defect (VSD, congenital heart lesion ที่พบบ่อยสุด): pansystolic murmur ที่ LLSB. Small VSD 'มักปิดเอง' และ asymptomatic. Large VSD → left-to-right shunt → heart failure/pulmonary HT → ผ่าตัดปิด (ป้องกัน Eisenmenger). ไม่ทำให้เขียวแรกเกิด (acyanotic) จนกว่าจะ shunt reversal."}, {"topic": "Neuro/CVT/Vascular", "q": "A cyanotic infant has a boot-shaped heart on X-ray, and 'tet spells' relieved by squatting. Which four features make up this condition?", "choices": ["Atrial septal defect for this patient", "Transposition of great arteries for this patient", "Coarctation of aorta for this patient", "Patent ductus arteriosus for this patient", "Tetralogy of Fallot (VSD, PS, overriding aorta, RVH)"], "ans": 4, "exp": "Tetralogy of Fallot (cyanotic CHD ที่พบบ่อยสุดหลังวัยทารก): VSD + Pulmonary stenosis (RVOT obstruction) + Overriding aorta + Right ventricular hypertrophy → 'boot-shaped heart'. 'Tet spells' (cyanotic, ดีขึ้นเมื่อ squat/knee-chest → เพิ่ม SVR ลด shunt). รักษา: ผ่าตัดซ่อม; spell → knee-chest, O2, morphine, fluid, beta-blocker."}, {"topic": "Neuro/CVT/Vascular", "q": "A 68-year-old man has exertional syncope, angina, and dyspnea with an ejection systolic murmur radiating to the carotids and a slow-rising pulse. What valvular lesion is this?", "choices": ["Aortic stenosis", "Aortic regurgitation", "Mitral regurgitation", "Mitral stenosis", "Tricuspid stenosis"], "ans": 0, "exp": "Aortic stenosis: triad 'syncope, angina, dyspnea (heart failure)' (exertional), ejection systolic murmur ที่ RUSB ร้าวไป carotids, slow-rising pulse (pulsus parvus et tardus), soft S2. สาเหตุ: calcific (สูงอายุ), bicuspid. Symptomatic severe AS → 'aortic valve replacement (SAVR/TAVI)' (พยากรณ์แย่ถ้าไม่ผ่าตัด). หลีกเลี่ยง vasodilator."}, {"topic": "Neuro/CVT/Vascular", "q": "A patient has a history of rheumatic fever and now has a mid-diastolic murmur with a loud S1 and atrial fibrillation. What valvular lesion is this?", "choices": ["Pulmonary stenosis", "Mitral stenosis", "Aortic stenosis", "Mitral regurgitation", "Aortic regurgitation"], "ans": 1, "exp": "Mitral stenosis (มักจาก 'rheumatic heart disease'): mid-diastolic rumbling murmur ที่ apex (นอนตะแคงซ้าย) + loud S1 + opening snap. ภาวะแทรกซ้อน: atrial fibrillation (LA โต), left atrial thrombus/emboli, pulmonary HT, hemoptysis. รักษา: rate control/anticoagulation (AF), 'balloon valvuloplasty' หรือ valve replacement."}, {"topic": "Neuro/CVT/Vascular", "q": "A patient has a soft, diastolic decrescendo murmur, wide pulse pressure, and a collapsing (water-hammer) pulse. What valvular lesion is this?", "choices": ["Mitral stenosis", "Aortic stenosis", "Aortic regurgitation", "Mitral regurgitation", "Tricuspid regurgitation"], "ans": 2, "exp": "Aortic regurgitation: early diastolic decrescendo murmur ที่ LSB (นั่งโน้มไปหน้า/หายใจออก), 'wide pulse pressure', 'collapsing/water-hammer pulse', Corrigan/Quincke/de Musset signs. สาเหตุ: bicuspid, rheumatic, endocarditis, aortic root dilation (Marfan, dissection). Severe symptomatic/LV dysfunction → valve replacement."}, {"topic": "Neuro/CVT/Vascular", "q": "A patient with infective endocarditis on a native valve develops heart failure from valve destruction despite antibiotics. What is an indication for surgery?", "choices": ["Small vegetation", "Fever alone", "Positive blood culture alone", "Heart failure from valve dysfunction", "Single embolic event resolved"], "ans": 3, "exp": "Infective endocarditis — ข้อบ่งชี้ผ่าตัด (นอกเหนือยาปฏิชีวนะ): 'heart failure จาก severe valve regurgitation/destruction', uncontrolled infection (abscess, persistent bacteremia, fungal/resistant), recurrent emboli หรือ large mobile vegetation (>10 mm). Surgery ซ่อม/เปลี่ยนลิ้น. Duke criteria วินิจฉัย."}, {"topic": "Neuro/CVT/Vascular", "q": "A patient with coronary artery disease has left main stenosis and triple-vessel disease with reduced ejection fraction. What is the recommended revascularization?", "choices": ["Medical therapy only", "Single stent for this patient", "No treatment for this patient", "Valve replacement initially", "Coronary artery bypass grafting"], "ans": 4, "exp": "CABG ได้ประโยชน์เหนือ PCI ใน: 'left main disease, triple-vessel (โดยเฉพาะ + DM หรือ LV dysfunction), complex/diffuse disease (high SYNTAX score)'. ใช้ LIMA to LAD (patency ดี) ± vein/radial grafts. ประเมินโดย heart team. Single/simple lesion → PCI."}, {"topic": "Neuro/CVT/Vascular", "q": "A young athlete collapses; echocardiography shows asymmetric septal hypertrophy with LVOT obstruction. What is the diagnosis?", "choices": ["Hypertrophic cardiomyopathy", "Aortic stenosis", "Dilated cardiomyopathy", "Myocarditis", "Pericarditis"], "ans": 0, "exp": "Hypertrophic cardiomyopathy (HCM): asymmetric septal hypertrophy → LVOT obstruction (murmur เพิ่มเมื่อ preload ลด - Valsalva/standing), เป็นสาเหตุ 'sudden cardiac death ในนักกีฬาหนุ่ม'. รักษา: beta-blocker, หลีกเลี่ยงกีฬาหนัก/dehydration, ICD ในกลุ่มเสี่ยง, septal myectomy/alcohol ablation. ตรงข้ามกับ AS (murmur ลดเมื่อ Valsalva)."}, {"topic": "Neuro/CVT/Vascular", "q": "A 60-year-old smoker has a solitary 2.5 cm spiculated lung nodule with an increasing size on serial CT. What is the appropriate next step?", "choices": ["Ignore it for this patient", "Biopsy/resection for tissue diagnosis", "Repeat CT in 2 years as first step", "Antibiotics for this patient", "Observation only"], "ans": 1, "exp": "Solitary pulmonary nodule ที่มีลักษณะ 'high-risk' (ขนาด >8 mm-2 cm, spiculated, โตขึ้น, upper lobe, ผู้สูบบุหรี่/อายุมาก) → ต้องได้ tissue diagnosis (PET-CT staging + biopsy/CT-guided/bronchoscopy หรือ surgical resection). Low-risk small nodule → surveillance CT (Fleischner criteria). โตขึ้นบ่งชี้มะเร็ง."}, {"topic": "Neuro/CVT/Vascular", "q": "A lung cancer patient has hyponatremia (SIADH) and Cushing-like features. Which lung cancer type is most associated with paraneoplastic syndromes?", "choices": ["Carcinoid", "Squamous cell carcinoma", "Small cell lung carcinoma", "Adenocarcinoma", "Large cell carcinoma"], "ans": 2, "exp": "Small cell lung carcinoma (central, สัมพันธ์บุหรี่มากสุด, แพร่เร็ว): paraneoplastic เด่น — 'SIADH (hyponatremia)', ectopic ACTH (Cushing), Lambert-Eaton myasthenic syndrome. รักษาหลักคือ chemo/RT (ไม่ค่อยผ่าตัด เพราะมัก extensive). Squamous → hypercalcemia (PTHrP), central, cavitation."}, {"topic": "Neuro/CVT/Vascular", "q": "A patient has an anterior mediastinal mass and muscle weakness that worsens with activity (myasthenia gravis). Which tumor is associated?", "choices": ["Teratoma", "Lymphoma", "Neurogenic tumor", "Thymoma", "Thyroid goiter"], "ans": 3, "exp": "Anterior mediastinal masses '4 Ts': Thymoma/Thymic, Teratoma (germ cell), Terrible lymphoma, Thyroid (retrosternal). 'Thymoma' สัมพันธ์กับ 'myasthenia gravis' (anti-AChR), pure red cell aplasia, hypogammaglobulinemia. รักษา thymoma: resection (thymectomy) ± RT; thymectomy ช่วย MG. Posterior mediastinum → neurogenic tumors."}, {"topic": "Neuro/CVT/Vascular", "q": "A patient with a history of asbestos exposure has pleural thickening and a pleural effusion; biopsy shows malignant mesothelioma. What is the key exposure?", "choices": ["Radon only", "Silica", "Coal dust", "Tobacco only", "Asbestos"], "ans": 4, "exp": "Malignant pleural mesothelioma: สัมพันธ์อย่างมากกับ 'asbestos exposure' (latency นานหลายสิบปี) — pleural thickening/effusion, ปวดอก, dyspnea. พยากรณ์แย่. Asbestos ยังเพิ่ม lung cancer (เสริมฤทธิ์บุหรี่). วินิจฉัย pleural biopsy. รักษาส่วนใหญ่ palliative (multimodal ในบางราย)."}, {"topic": "Neuro/CVT/Vascular", "q": "A patient has massive hemoptysis (>500 mL/24h) and is at risk of asphyxiation. What is the immediate priority?", "choices": ["Airway protection and position bleeding side down", "Immediate lobectomy for this patient", "Oral tranexamic acid only", "Discharge home for this patient", "CT then wait for this patient"], "ans": 0, "exp": "Massive hemoptysis: อันตรายหลักคือ 'asphyxiation' (ไม่ใช่ exsanguination) → ป้องกัน airway: 'ให้ผู้ป่วยนอนตะแคงข้างที่เลือดออกลง' (ป้องกันสำลักเข้าปอดดี), intubate (± protect good lung), resuscitate. หาตำแหน่ง (bronchoscopy/CTA) → 'bronchial artery embolization' (first-line) หรือ surgery. สาเหตุ: TB, bronchiectasis, cancer."}, {"topic": "Neuro/CVT/Vascular", "q": "A patient has a chest tube for a pneumothorax with continuous bubbling in the water-seal chamber. What does persistent bubbling indicate?", "choices": ["Normal function", "Ongoing air leak", "Tube blockage", "Full lung re-expansion", "Infection"], "ans": 1, "exp": "Chest tube: bubbling ใน water-seal chamber = 'air leak' (จาก pleural space หรือ system). Bubbling ที่หายไปเมื่อหายใจปกติ + ปอดขยาย = ปกติ. 'Continuous/persistent bubbling' = ongoing air leak (จากปอด - bronchopleural fistula) หรือรอยรั่วในระบบ/รอบท่อ. Tidaling (swing) = ท่อทำงาน; ไม่ swing = อุดตัน/ปอดขยายเต็ม."}, {"topic": "Neuro/CVT/Vascular", "q": "A 40-year-old male smoker has painful ischemia of the fingers and toes with superficial thrombophlebitis; angiography shows 'corkscrew' collaterals. What is the diagnosis?", "choices": ["Atherosclerotic PAD for this patient", "Raynaud phenomenon for this patient", "Thromboangiitis obliterans (Buerger disease)", "Vasculitis (GCA) for this patient", "Diabetic angiopathy for this patient"], "ans": 2, "exp": "Thromboangiitis obliterans (Buerger disease): ชายหนุ่มสูบบุหรี่จัด → ischemia ปลายนิ้ว/นิ้วเท้า (rest pain, ulcer, gangrene), migratory superficial thrombophlebitis, Raynaud. Angiography: 'corkscrew collaterals'. รักษาที่สำคัญสุดคือ 'เลิกบุหรี่เด็ดขาด' (มิฉะนั้นลุกลาม/ตัดนิ้ว). ไม่ใช่ atherosclerosis."}, {"topic": "Neuro/CVT/Vascular", "q": "A patient needs long-term hemodialysis. What is the preferred permanent vascular access?", "choices": ["Central venous catheter", "Peripheral IV", "AV graft only", "Arteriovenous fistula", "Peritoneal only"], "ans": 3, "exp": "Arteriovenous fistula (AVF, เช่น radiocephalic/brachiocephalic) เป็น 'access ที่ดีที่สุด' สำหรับ hemodialysis ระยะยาว (patency นาน, ติดเชื้อน้อยกว่า graft/catheter). ต้องเวลา 'maturation' 6-8 สัปดาห์. AV graft ใช้เมื่อ vein ไม่ดี; central catheter ใช้ชั่วคราว (ติดเชื้อ/thrombosis สูง). 'Fistula first'."}, {"topic": "Neuro/CVT/Vascular", "q": "A patient has a lower limb that is chronically swollen with non-pitting edema and skin thickening after lymph node dissection. What is the diagnosis?", "choices": ["Deep vein thrombosis", "Chronic venous insufficiency", "Cardiac failure", "Cellulitis", "Lymphedema"], "ans": 4, "exp": "Lymphedema: การคั่งของ lymph จากการอุดตัน/ทำลาย lymphatics — บวม 'non-pitting' (ระยะหลัง), skin thickening/fibrosis, 'positive Stemmer sign' (หยิบผิวโคนนิ้วไม่ขึ้น). Secondary: หลัง node dissection/RT (มะเร็ง), filariasis. รักษา: complex decongestive therapy (compression, MLD, exercise, skin care); ไม่มี diuretic ช่วย."}, {"topic": "Neuro/CVT/Vascular", "q": "A young woman has episodic color changes of the fingers (white to blue to red) triggered by cold or stress, without tissue loss. What is the diagnosis?", "choices": ["Primary Raynaud phenomenon", "Cellulitis", "Buerger disease", "Acute limb ischemia", "Frostbite"], "ans": 0, "exp": "Raynaud phenomenon: vasospasm ของนิ้วเมื่อเย็น/เครียด → เปลี่ยนสี 'white (ischemia) → blue (cyanosis) → red (reperfusion)'. Primary (idiopathic, หญิงสาว, สองข้าง, ไม่มี tissue loss) vs secondary (สัมพันธ์ connective tissue disease - scleroderma/SLE, มี ulcer/asymmetry). รักษา: หลีกเลี่ยงเย็น/บุหรี่, calcium channel blocker. หา secondary cause."}, {"topic": "Neuro/CVT/Vascular", "q": "A trauma patient has a penetrating brain injury with a retained fragment. Besides surgery, which prophylaxis is commonly given?", "choices": ["Beta-blocker for this patient", "Antiepileptic (seizure) prophylaxis", "Long-term anticoagulation alone", "Antifungals for this patient", "Statins for this patient"], "ans": 1, "exp": "Penetrating/severe traumatic brain injury: ให้ 'early seizure prophylaxis (phenytoin/levetiracetam) ~7 วัน' เพื่อลด early post-traumatic seizure (ไม่ลด late seizure). ร่วมกับจัดการ raised ICP, ป้องกัน secondary injury (avoid hypoxia/hypotension), surgical debridement, antibiotic. ประเมิน GCS/pupils ต่อเนื่อง."}, {"topic": "Neuro/CVT/Vascular", "q": "A boxer sustains a rotational head injury; CT is relatively normal but he is comatose. MRI shows multiple small hemorrhages at the gray-white junction and corpus callosum. What is the diagnosis?", "choices": ["Epidural hematoma", "Concussion only", "Diffuse axonal injury", "Subdural hematoma", "Brain abscess"], "ans": 2, "exp": "Diffuse axonal injury (DAI): จาก 'rotational/shearing' forces → axonal disruption ที่ gray-white junction, corpus callosum, brainstem. CT มักดู 'ไม่สมกับ' ระดับความรู้สึกตัว (coma); MRI ไวกว่า (petechial hemorrhages/DWI). พยากรณ์ขึ้นกับความรุนแรง; รักษาประคับประคอง/ICP. เป็นสาเหตุ persistent coma หลัง trauma."}, {"topic": "Neuro/CVT/Vascular", "q": "A patient has trigeminal neuralgia with severe, brief, electric-shock-like facial pain triggered by touch. What is the first-line treatment?", "choices": ["Opioids", "Surgery first", "NSAIDs", "Carbamazepine", "Antibiotics"], "ans": 3, "exp": "Trigeminal neuralgia: ปวดหน้าแปลบเหมือนไฟช็อตสั้นๆ ตาม trigeminal distribution, trigger จากการสัมผัส/เคี้ยว. มักจาก neurovascular compression. First-line = 'carbamazepine' (หรือ oxcarbazepine). ดื้อยา → microvascular decompression, gamma knife, rhizotomy. MRI แยก secondary cause (tumor, MS)."}, {"topic": "Neuro/CVT/Vascular", "q": "A child has a posterior fossa tumor; the most common malignant brain tumor in children arising in the cerebellum/vermis is which?", "choices": ["Glioblastoma", "Meningioma", "Craniopharyngioma", "Ependymoma", "Medulloblastoma"], "ans": 4, "exp": "Medulloblastoma: embryonal tumor ที่ cerebellum/vermis — มะเร็งสมองที่พบบ่อยในเด็ก → ataxia + สัญญาณ raised ICP (obstructive hydrocephalus จากกด 4th ventricle). แพร่ทาง CSF ('drop metastases'). รักษา: resection + craniospinal RT + chemo. Pilocytic astrocytoma = benign, พยากรณ์ดี."}, {"topic": "Neuro/CVT/Vascular", "q": "A patient develops fever, headache, and focal neurologic deficit; MRI shows a subdural collection with enhancement after sinusitis. What is the diagnosis?", "choices": ["Subdural empyema", "Epidural hematoma", "Chronic subdural hematoma", "Meningioma", "Brain abscess"], "ans": 0, "exp": "Subdural empyema: หนองใน subdural space (มักลุกลามจาก sinusitis/otitis/mastoiditis) → ไข้ + headache + focal deficit/seizure + ลุกลามเร็ว. เป็น neurosurgical emergency → 'urgent surgical drainage' + IV antibiotics + แก้แหล่งติดเชื้อ. ต่างจาก chronic SDH (ไม่ติดเชื้อ, ผู้สูงอายุ)."}, {"topic": "Neuro/CVT/Vascular", "q": "A patient with severe head injury has refractory raised intracranial pressure. Which is an appropriate medical measure to lower ICP?", "choices": ["Warming blanket for this patient", "Hyperosmolar therapy (mannitol/hypertonic saline)", "Aggressive IV fluid to hypertension initially", "Trendelenburg positioning for this patient", "Hypoventilation for this patient"], "ans": 1, "exp": "การลด ICP: head-up 30° (neutral neck), adequate sedation/analgesia, 'hyperosmolar therapy (mannitol หรือ hypertonic saline)', maintain CPP (avoid hypotension/hypoxia), controlled ventilation (normocapnia; hyperventilation ชั่วคราวเฉพาะ herniation), CSF drainage (EVD), และ decompressive craniectomy ในรายดื้อ. หลีกเลี่ยงสิ่งที่เพิ่ม ICP."}, {"topic": "Neuro/CVT/Vascular", "q": "A patient has a thoracic aortic aneurysm found incidentally. Which underlying connective tissue disorder should be considered in a young patient?", "choices": ["Rheumatoid arthritis", "Osteoarthritis", "Marfan syndrome", "Gout", "Diabetes"], "ans": 2, "exp": "Thoracic aortic aneurysm/dissection ในคนอายุน้อย → นึกถึง connective tissue disorder: 'Marfan syndrome' (FBN1 - tall, arachnodactyly, lens dislocation, aortic root dilation), Loeys-Dietz, Ehlers-Danlos vascular type, bicuspid aortic valve. ต้องเฝ้าระวัง/ผ่าตัดที่ threshold เล็กกว่าปกติ + beta-blocker/ARB."}, {"topic": "Neuro/CVT/Vascular", "q": "A patient has a chronic lung condition with foul sputum, recurrent infections, and 'tram-track' airway dilation on CT. What is the diagnosis?", "choices": ["Pneumothorax", "Lung abscess", "Pulmonary embolism", "Bronchiectasis", "Mesothelioma"], "ans": 3, "exp": "Bronchiectasis: การขยายถาวรของ bronchi จากการทำลาย (post-infection - TB/pertussis, cystic fibrosis, immunodeficiency, obstruction) → ไอเสมหะมากเรื้อรัง/มีกลิ่น, hemoptysis, การติดเชื้อซ้ำ. CT: 'tram-track/signet-ring' dilated airways. รักษา: airway clearance, antibiotics, จัดการสาเหตุ; localized รุนแรง → resection."}, {"topic": "Neuro/CVT/Vascular", "q": "A patient aspirates and develops a cavity with an air-fluid level in the lung containing pus. What is the diagnosis and treatment?", "choices": ["Empyema, decortication", "Pneumothorax, chest tube", "Pulmonary embolism, anticoagulation", "Mesothelioma, surgery", "Lung abscess, antibiotics and drainage"], "ans": 4, "exp": "Lung abscess (มักจาก aspiration - dependent segments, anaerobes): ไข้, ไอเสมหะเหม็น, CT/X-ray เห็น 'cavity + air-fluid level'. รักษา: 'antibiotics ระยะยาว (ครอบคลุม anaerobe)' + postural drainage; ล้มเหลว/ใหญ่ → percutaneous/surgical drainage. ต่างจาก empyema (ใน pleural space)."}, {"topic": "Neuro/CVT/Vascular", "q": "A neonate is cyanotic from birth with 'egg-on-a-string' cardiac silhouette; the aorta arises from the right ventricle and pulmonary artery from the left. What is the diagnosis?", "choices": ["Transposition of the great arteries", "VSD for this patient", "Tetralogy of Fallot in this case", "Coarctation for this patient", "Patent ductus arteriosus alone"], "ans": 0, "exp": "Transposition of the great arteries (TGA): aorta จาก RV, pulmonary artery จาก LV → 2 circulations แยกกัน → cyanosis รุนแรงแรกเกิด (survival ต้องมี mixing: PDA/PFO/VSD). X-ray: 'egg-on-a-string'. รักษา: 'prostaglandin E1' (คง PDA), balloon atrial septostomy, แล้ว arterial switch operation."}, {"topic": "Neuro/CVT/Vascular", "q": "An asymptomatic newborn has a continuous 'machinery' murmur; echocardiography shows a patent ductus arteriosus. In a premature infant, which drug may close it?", "choices": ["Furosemide in this case", "Indomethacin or ibuprofen", "Prostaglandin E1 alone", "Digoxin as first step", "Adenosine in this case"], "ans": 1, "exp": "Patent ductus arteriosus (PDA): continuous 'machinery' murmur (left infraclavicular). ใน 'preterm' ที่มีอาการ → 'indomethacin/ibuprofen' (ยับยั้ง prostaglandin → ปิด duct) หรือ surgical/catheter closure. ตรงข้าม: ใน duct-dependent CHD ให้ 'prostaglandin E1' เพื่อ 'คง' duct เปิด. Term/persistent → catheter/surgical closure."}, {"topic": "Neuro/CVT/Vascular", "q": "A hypertensive young patient has upper limb hypertension with weak/delayed femoral pulses and rib notching on X-ray. What is the diagnosis?", "choices": ["Pheochromocytoma", "Renal artery stenosis", "Coarctation of the aorta", "Aortic stenosis", "Takayasu arteritis"], "ans": 2, "exp": "Coarctation of the aorta: การตีบของ aorta (มักหลัง left subclavian) → 'upper limb hypertension + radiofemoral delay/weak femoral pulses', 'rib notching' (collateral จาก intercostal arteries), '3 sign'. สัมพันธ์ bicuspid aortic valve, Turner syndrome. รักษา: surgical repair หรือ balloon/stent. เป็นสาเหตุ secondary HT ในเด็ก/หนุ่มสาว."}, {"topic": "Neuro/CVT/Vascular", "q": "A patient sustains a concussion in sport with brief confusion but a normal CT. What is the appropriate return-to-play principle?", "choices": ["Return immediately if CT normal", "Never return to sport", "Return after 24 hours regardless", "Graduated return only after symptom-free", "Return once pain-free with medication"], "ans": 3, "exp": "Concussion (mild TBI): อาการชั่วคราว (สับสน, ปวดศีรษะ, มึน), CT ปกติ. การกลับเล่นกีฬาต้อง 'graduated return-to-play' หลัง 'หายอาการ' (symptom-free) ทีละขั้น. หลีกเลี่ยง second impact syndrome (การกระแทกซ้ำก่อนหาย → สมองบวมรุนแรง). พักสมอง (cognitive/physical rest) ช่วงแรก."}, {"topic": "Neuro/CVT/Vascular", "q": "An elderly patient with a chronic subdural hematoma has progressive symptoms and a large hypodense collection with mass effect. What is the management?", "choices": ["Anticoagulation as first step", "Observation always initially", "Antibiotics for this patient", "Lumbar puncture as first step", "Surgical evacuation (burr holes)"], "ans": 4, "exp": "Chronic subdural hematoma ที่มีอาการ/ใหญ่/mass effect → 'surgical drainage (burr hole evacuation)' — พยากรณ์ดี. Small/asymptomatic → สังเกต ± หยุด anticoagulant. พบในผู้สูงอายุ/atrophy/anticoagulant. CT: hypodense (chronic) crescent collection. อาจเป็นซ้ำ."}, {"topic": "Neuro/CVT/Vascular", "q": "A patient is found to have an unruptured 8 mm cerebral aneurysm incidentally. What determines management (observe vs treat)?", "choices": ["Size, location, and rupture risk factors", "Anticoagulate for this patient", "Always immediate clipping in this case", "Always ignore for this patient", "Antibiotics for this patient"], "ans": 0, "exp": "Unruptured intracranial aneurysm: การตัดสินใจ (surveillance vs coiling/clipping) ขึ้นกับ 'size (ใหญ่เสี่ยงกว่า), location (posterior circulation เสี่ยงกว่า), morphology, growth, อายุ, ประวัติ SAH/ครอบครัว, symptoms'. ใช้ PHASES score ช่วย. Ruptured aneurysm (SAH) = ต้องรักษาเร็ว. เลิกบุหรี่/คุมความดัน."}, {"topic": "Neuro/CVT/Vascular", "q": "A child with a ventriculoperitoneal shunt develops headache, vomiting, and lethargy. What must be suspected?", "choices": ["Ear infection in this case", "Shunt malfunction/obstruction", "Migraine for this patient", "Gastroenteritis initially", "Normal behavior initially"], "ans": 1, "exp": "VP shunt malfunction (obstruction/infection/disconnection) → กลับมามี raised ICP: headache, vomiting, lethargy, ± bulging fontanelle/sunset eyes (ทารก). ประเมิน: shunt series (X-ray), CT (ventricle โต), shunt tap. เป็น emergency → neurosurgery (revision). Shunt infection มักภายในไม่กี่เดือนหลังใส่."}, {"topic": "Neuro/CVT/Vascular", "q": "A patient has severe mitral regurgitation from a flail leaflet with worsening heart failure. What is the definitive treatment?", "choices": ["Antibiotics for this patient", "Beta-blocker only", "Mitral valve repair or replacement", "Observation for this patient", "Diuretics alone"], "ans": 2, "exp": "Mitral regurgitation (chronic primary, เช่น flail leaflet/prolapse/endocarditis): pansystolic murmur ที่ apex ร้าวไปรักแร้. Severe + symptomatic หรือ LV dysfunction/dilation → 'mitral valve repair (นิยม, ผลดีกว่า) หรือ replacement'. Acute severe MR (papillary muscle rupture post-MI, endocarditis) = emergency surgery."}, {"topic": "Neuro/CVT/Vascular", "q": "A patient with a mechanical prosthetic heart valve requires which long-term therapy?", "choices": ["Aspirin only", "No anticoagulation initially", "DOAC preferred in this case", "Lifelong warfarin (target INR)", "Antibiotics lifelong alone"], "ans": 3, "exp": "Mechanical prosthetic valve ต้องการ 'lifelong warfarin' (target INR ตามชนิด/ตำแหน่งลิ้น, มัก 2.5-3.5) — 'DOAC ห้ามใช้' (RE-ALIGN trial). Bioprosthetic valve ต้องการ anticoagulation สั้นๆ แล้ว aspirin. ทั้งคู่ต้อง endocarditis prophylaxis. ให้คำปรึกษาเรื่อง durability vs anticoagulation ในการเลือกลิ้น."}, {"topic": "Neuro/CVT/Vascular", "q": "A patient has syncope and a diastolic 'tumor plop'; echocardiography shows a mobile left atrial mass. What is the diagnosis?", "choices": ["Aortic stenosis", "Mitral stenosis", "Endocarditis vegetation", "Thrombus only", "Atrial myxoma"], "ans": 4, "exp": "Atrial myxoma (เนื้องอกหัวใจ primary ที่พบบ่อยสุด, มัก left atrium): อาจอุดกั้น mitral valve (syncope เปลี่ยนตามท่า, 'tumor plop'), embolization, constitutional symptoms (ไข้, น้ำหนักลด - เลียนแบบ endocarditis/vasculitis). Echo วินิจฉัย. รักษา: surgical resection."}, {"topic": "Neuro/CVT/Vascular", "q": "A patient after cardiac surgery has hypotension, raised JVP, pulsus paradoxus, and equalization of diastolic pressures. What is the diagnosis?", "choices": ["Cardiac tamponade", "Tension pneumothorax", "Pulmonary embolism", "Myocardial infarction", "Sepsis"], "ans": 0, "exp": "Post-op cardiac tamponade: hypotension + raised JVP + pulsus paradoxus + muffled heart sounds; echo เห็น effusion + diastolic collapse. หลังผ่าตัดหัวใจ (bleeding into pericardium) เป็น emergency → 'pericardiocentesis/surgical re-exploration'. ต่างจาก tension pneumothorax (trachea เบน, เสียงหายใจลด)."}, {"topic": "Neuro/CVT/Vascular", "q": "A stable patient has a Stanford type B aortic dissection (descending aorta only) without complications. What is the initial management?", "choices": ["Thrombolysis for this patient", "Medical therapy (impulse control with beta-blocker)", "Emergency surgery always for this patient", "Anticoagulation for this patient", "No treatment for this patient"], "ans": 1, "exp": "Uncomplicated Stanford type B dissection (descending) → 'medical management': 'impulse control' ด้วย IV beta-blocker (ลด HR <60 และ BP) ± vasodilator, ปวด. Complicated type B (malperfusion, rupture, refractory pain/HT, expansion) → TEVAR/surgery. ต่างจาก type A (ascending) ที่ต้องผ่าตัดฉุกเฉิน."}, {"topic": "Neuro/CVT/Vascular", "q": "A lung cancer is confirmed as non-small cell carcinoma confined to the lung without nodal spread (early stage). What is the preferred treatment?", "choices": ["Chemotherapy only", "Radiotherapy only", "Surgical resection (lobectomy)", "Palliative care in this case", "Observation for this patient"], "ans": 2, "exp": "Non-small cell lung cancer (NSCLC) ระยะต้น (I-II, resectable, adequate lung function) → 'surgical resection (lobectomy + mediastinal node sampling)' เป็นการรักษาหลัก ± adjuvant chemo. Locally advanced (IIIA) → multimodal. Metastatic → systemic (chemo/targeted/immunotherapy). ต่างจาก SCLC (chemo/RT เป็นหลัก, ไม่ค่อยผ่าตัด)."}, {"topic": "Neuro/CVT/Vascular", "q": "A pleural effusion is analyzed with Light criteria showing an exudate. Which finding indicates an exudate?", "choices": ["Very low protein for this patient", "Low LDH for this patient", "Transudative appearance initially", "Pleural/serum protein ratio over 0.5", "Normal glucose only"], "ans": 3, "exp": "Light criteria (exudate ถ้าเข้า ≥1 ข้อ): pleural/serum protein >0.5, pleural/serum LDH >0.6, หรือ pleural LDH >2/3 upper normal. Exudate = inflammatory/malignant/infective (pneumonia, TB, cancer, PE). Transudate = hydrostatic/oncotic (heart failure, cirrhosis, nephrotic). ช่วยแยกสาเหตุและการดูแล."}, {"topic": "Neuro/CVT/Vascular", "q": "A patient has a popliteal artery aneurysm. What is a major complication distinguishing it from an aortic aneurysm?", "choices": ["No complications for this patient", "Rupture is the main risk for this patient", "Causes hypertension for this patient", "Causes stroke for this patient", "Thromboembolism causing acute limb ischemia"], "ans": 4, "exp": "Popliteal artery aneurysm (peripheral aneurysm ที่พบบ่อยสุด, มัก bilateral, สัมพันธ์ AAA): ภาวะแทรกซ้อนหลักคือ 'thrombosis/thromboembolism → acute limb ischemia' (ไม่ใช่ rupture เป็นหลักเหมือน AAA). อาจกด vein/nerve. รักษา: ผ่าตัด (bypass + ligation) หรือ endovascular เมื่อ symptomatic/ใหญ่. ตรวจ AAA ร่วม."}, {"topic": "Neuro/CVT/Vascular", "q": "A patient has arm claudication and neurologic symptoms of vertebrobasilar insufficiency when using the arm; there is a blood pressure difference between arms. What is the diagnosis?", "choices": ["Subclavian steal syndrome", "Raynaud phenomenon", "Thoracic outlet syndrome", "Carotid stenosis", "Buerger disease"], "ans": 0, "exp": "Subclavian steal syndrome: การตีบ/อุดตันของ subclavian artery 'ก่อน' vertebral origin → เมื่อใช้แขน เลือดถูก 'ดึง' จาก vertebral artery (retrograde) → vertebrobasilar insufficiency (มึน, เห็นภาพซ้อน) + arm claudication + 'BP ต่างสองแขน'. รักษา: revascularization ถ้ามีอาการ. ตรวจ duplex/angiography."}, {"topic": "Neuro/CVT/Vascular", "q": "A young woman has hypertension resistant to medication; imaging shows a 'string of beads' appearance of the renal artery. What is the diagnosis?", "choices": ["Conn syndrome", "Fibromuscular dysplasia", "Atherosclerotic renal artery stenosis", "Pheochromocytoma", "Coarctation"], "ans": 1, "exp": "Renal artery stenosis จาก 'fibromuscular dysplasia' (หญิงสาว, 'string of beads' ที่ mid-distal renal artery) → secondary HT (renin-angiotensin). ต่างจาก atherosclerotic RAS (สูงอายุ, ostial/proximal). รักษา FMD: angioplasty (มัก ไม่ stent) ± antihypertensive. ระวัง AKI เมื่อให้ ACEI ใน bilateral RAS."}, {"topic": "Neuro/CVT/Vascular", "q": "A patient has chronic postprandial abdominal pain, weight loss (food fear), and a bruit; angiography shows stenosis of two mesenteric arteries. What is the diagnosis?", "choices": ["Gastric cancer", "Peptic ulcer", "Chronic mesenteric ischemia", "Chronic pancreatitis", "IBD"], "ans": 2, "exp": "Chronic mesenteric ischemia ('intestinal angina'): ปวดท้องหลังอาหาร 15-30 นาที + 'weight loss/food fear' (sitophobia) + bruit; มักต้องตีบ ≥2 ใน 3 mesenteric arteries (celiac, SMA, IMA - collateral). สัมพันธ์ atherosclerosis/สูบบุหรี่. รักษา: revascularization (endovascular/bypass). ต่างจาก acute mesenteric ischemia (เฉียบพลันรุนแรง)."}, {"topic": "Neuro/CVT/Vascular", "q": "A patient develops a pulsatile, painful mass at a femoral arterial puncture site after catheterization, with a bruit. What is the diagnosis?", "choices": ["True aneurysm as first step", "Hematoma only", "AV fistula for this patient", "Pseudoaneurysm (false aneurysm)", "Cellulitis for this patient"], "ans": 3, "exp": "Pseudoaneurysm (false aneurysm): เลือดรั่วออกนอกผนังหลอดเลือดแต่ถูกกักด้วย surrounding tissue (ไม่มีผนัง 3 ชั้น) — มัก 'หลัง arterial puncture' (femoral cath) → pulsatile mass + bruit + 'to-and-fro' flow บน duplex. รักษา: ultrasound-guided compression/thrombin injection หรือ surgery. ต่างจาก true aneurysm (ผนังครบ 3 ชั้น)."}, {"topic": "Neuro/CVT/Vascular", "q": "A patient has a superficial vein that is tender, red, and cord-like along its course (superficial thrombophlebitis). If it extends near the saphenofemoral junction, what is the concern?", "choices": ["Arterial occlusion as first step", "Lymphedema for this patient", "Cellulitis only", "No concern for this patient", "Progression to deep vein thrombosis"], "ans": 4, "exp": "Superficial thrombophlebitis: vein แข็งเป็นลำ แดง เจ็บ. ส่วนใหญ่ benign (warm compress, NSAIDs). แต่ถ้า 'ลุกลามใกล้ saphenofemoral junction หรือยาว >5 cm' เสี่ยงลามเข้า deep system (DVT/PE) → พิจารณา anticoagulation + duplex ติดตาม. Recurrent/migratory → หา malignancy (Trousseau) / thrombophilia."}, {"topic": "Neuro/CVT/Vascular", "q": "A patient has a spinal epidural abscess with back pain, fever, and progressive neurologic deficit. What is the appropriate management?", "choices": ["Urgent decompression and antibiotics", "Antibiotics alone always initially", "Observation for this patient", "Physiotherapy for this patient", "Bracing only"], "ans": 0, "exp": "Spinal epidural abscess: triad ปวดหลัง + ไข้ + neurologic deficit (progressive). เชื้อบ่อย S. aureus (hematogenous/IVDU/DM). MRI ยืนยัน. เป็น emergency → 'surgical decompression + drainage + IV antibiotics' (โดยเฉพาะเมื่อมี neuro deficit); เล็ก/ไม่มี deficit อาจ antibiotic + monitoring ใกล้ชิด. ล่าช้า → paralysis ถาวร."}, {"topic": "Neuro/CVT/Vascular", "q": "A patient has a syrinx (fluid-filled cavity) in the spinal cord causing a 'cape-like' loss of pain/temperature sensation with preserved touch. What is the diagnosis?", "choices": ["Cord tumor", "Syringomyelia", "Multiple sclerosis", "Transverse myelitis", "Cervical spondylosis"], "ans": 1, "exp": "Syringomyelia: fluid cavity (syrinx) ใน central cord → กด crossing spinothalamic fibers → 'cape-like/dissociated sensory loss' (สูญเสีย pain/temperature ที่แขน/ไหล่ แต่คง touch/proprioception), ± lower motor neuron แขน. สัมพันธ์ 'Chiari I malformation', trauma, tumor. MRI. รักษาที่สาเหตุ (posterior fossa decompression) ± shunt."}, {"topic": "Neuro/CVT/Vascular", "q": "A patient after a cardiac operation develops fever, sternal instability, and purulent wound discharge. What is the diagnosis?", "choices": ["Pneumonia for this patient", "Simple superficial infection initially", "Deep sternal wound infection/mediastinitis", "Pericarditis for this patient", "Costochondritis for this patient"], "ans": 2, "exp": "Deep sternal wound infection/mediastinitis (หลัง median sternotomy): ไข้ + sternal instability/click + purulent discharge + sepsis. เชื้อ S. aureus/gram-negative. เป็นภาวะแทรกซ้อนร้ายแรง → 'surgical debridement + sternal rewiring/reconstruction (flap) + IV antibiotics'. ปัจจัยเสี่ยง: DM, obesity, BIMA harvest, prolonged surgery."}, {"topic": "Neuro/CVT/Vascular", "q": "A patient with atrial fibrillation and a left atrial thrombus is at risk of which complication relevant to vascular/cardiac surgery?", "choices": ["Deep vein thrombosis", "Pulmonary embolism", "Hemorrhage", "Systemic (arterial) embolism", "Aneurysm"], "ans": 3, "exp": "Atrial fibrillation → stasis ใน left atrium/appendage → thrombus → 'systemic arterial embolism' (stroke, acute limb ischemia, mesenteric/renal/splenic infarct). ป้องกันด้วย anticoagulation (CHA2DS2-VASc). เป็นสาเหตุ embolic acute limb ischemia และ cardioembolic stroke ที่พบบ่อย. ต่างจาก DVT/PE (venous system)."}, {"topic": "Neuro/CVT/Vascular", "q": "A patient with COPD has a solitary pulmonary nodule that is stable in size for over 2 years on serial imaging. What does stability suggest?", "choices": ["Definitely malignant", "Requires immediate resection", "Metastasis", "Active infection", "Likely benign"], "ans": 4, "exp": "Solitary pulmonary nodule ที่ 'ขนาดคงที่ ≥2 ปี' (บน serial imaging) บ่งชี้ 'benign' (doubling time ยาว) → มักติดตามต่อ/หยุด. Benign features: เล็ก, ขอบเรียบ, calcification (central/popcorn/laminated). Malignant: โตขึ้น, spiculated, >8mm, ผู้สูบบุหรี่ → biopsy/PET. Growth rate สำคัญในการตัดสิน."}, {"topic": "Neuro/CVT/Vascular", "q": "A patient develops chylothorax (milky pleural fluid high in triglycerides) after thoracic surgery. What structure was injured?", "choices": ["Thoracic duct", "Bronchus", "Azygos vein", "Esophagus", "Pericardium"], "ans": 0, "exp": "Chylothorax: การรั่วของ 'thoracic duct' (lymph) → milky pleural fluid, triglyceride สูง (>110 mg/dL), chylomicrons. สาเหตุ: iatrogenic (esophagectomy/thoracic surgery), trauma, malignancy (lymphoma อุดตัน). รักษา: chest drainage + low-fat/MCT diet หรือ NPO+TPN, octreotide; ล้มเหลว → thoracic duct ligation/embolization."}, {"topic": "Neuro/CVT/Vascular", "q": "A patient with hand pain and pallor on overhead activity has a cervical rib compressing the brachial plexus and subclavian vessels. What is the diagnosis?", "choices": ["Carpal tunnel syndrome", "Thoracic outlet syndrome", "Cubital tunnel syndrome", "Raynaud phenomenon", "Buerger disease"], "ans": 1, "exp": "Thoracic outlet syndrome: การกด neurovascular bundle (brachial plexus + subclavian vessels) ที่ thoracic outlet (จาก cervical rib, กล้ามเนื้อ scalene, ท่าทาง) → อาการทาง neurogenic (ชา/อ่อนแรงมือ, มัก ulnar - พบบ่อยสุด), vascular (pallor/pain เมื่อยกแขน, Adson test). รักษา: physio/posture; ดื้อ/vascular → decompression (rib resection)."}, {"topic": "Neuro/CVT/Vascular", "q": "A patient is confirmed brain dead. Which is a criterion for brainstem death?", "choices": ["Low GCS only", "Fixed reversible coma for this patient", "Absent brainstem reflexes and apnea with a known irreversible cause", "Abnormal EEG only", "Cardiac arrest only"], "ans": 2, "exp": "การวินิจฉัย brain(stem) death: มี 'known irreversible cause' + exclude confounders (hypothermia, drugs, metabolic) + 'coma ลึก + absent brainstem reflexes (pupillary, corneal, oculocephalic/vestibular, gag/cough) + positive apnea test'. ทำโดยแพทย์ที่มีคุณสมบัติ 2 คน ตามเกณฑ์. สำคัญต่อ organ donation/withdrawal."}, {"topic": "Neuro/CVT/Vascular", "q": "A patient after limb revascularization for prolonged acute ischemia develops a tense, painful compartment. What is the appropriate management?", "choices": ["Elevation only", "Anticoagulation only", "Observation", "Fasciotomy", "Amputation"], "ans": 3, "exp": "Reperfusion หลัง prolonged limb ischemia (revascularization) → 'reperfusion injury/edema' → compartment syndrome. รักษา: 'fasciotomy' (มัก prophylactic ในผู้ที่ ischemia นาน >4-6 ชม.). เฝ้าระวัง 'reperfusion syndrome': hyperkalemia, myoglobinuria (AKI), acidosis (คล้าย crush). ตรวจ compartment pressure/clinical."}, {"topic": "Neuro/CVT/Vascular", "q": "A patient has diabetes and a black, dry, mummified toe with a clear demarcation line and no active infection. What type of gangrene is this?", "choices": ["Fournier gangrene", "Wet gangrene", "Gas gangrene", "Necrotizing fasciitis", "Dry gangrene"], "ans": 4, "exp": "Dry gangrene: เนื้อตายจาก ischemia (arterial insufficiency) — แห้ง ดำ mummified, มี demarcation ชัด, 'ไม่มีการติดเชื้อ/หนอง'. มัก auto-amputate หรือรอ demarcation แล้วตัด. ต่างจาก 'wet gangrene' (ติดเชื้อร่วม, บวม เหม็น, sepsis → ต้องตัดฉุกเฉิน + antibiotic). จัดการ ischemia/revascularization + ควบคุมเบาหวาน."}, {"topic": "Neuro/CVT/Vascular", "q": "A patient has an ankle-brachial index of 0.35 with rest pain and non-healing ulcers. What does this indicate?", "choices": ["Critical limb ischemia needing revascularization", "Normal circulation for this patient", "Mild claudication only", "Venous disease for this patient", "No intervention needed for this patient"], "ans": 0, "exp": "ABI: >0.9 ปกติ; 0.4-0.9 claudication; '<0.4 = critical limb ischemia (CLI)' → rest pain, tissue loss (ulcer/gangrene) → 'urgent revascularization' (endovascular/bypass) เพื่อ save limb + wound care + risk factor. (ABI >1.3 = incompressible/calcified - DM/CKD, แปลผลระวัง → ใช้ toe pressure)."}, {"topic": "Neuro/CVT/Vascular", "q": "A patient has an incidental finding of a carotid body tumor (paraganglioma) at the carotid bifurcation, splaying the internal and external carotid ('lyre sign'). What is the treatment for a symptomatic/enlarging tumor?", "choices": ["Observation always", "Surgical resection", "Chemotherapy", "Radiotherapy alone always", "Antibiotics"], "ans": 1, "exp": "Carotid body tumor (paraganglioma): ก้อนที่ carotid bifurcation, pulsatile, เคลื่อนด้านข้างได้แต่ไม่ขึ้นลง, 'splaying ICA/ECA (lyre sign)' บน angiography. ส่วนใหญ่ benign แต่โตช้าและ vascular. รักษา symptomatic/enlarging: 'surgical resection' (± preoperative embolization); RT ในบางราย. ประเมิน catecholamine (functional) ก่อนผ่าตัด."}, {"topic": "Neuro/CVT/Vascular", "q": "A neonate has bilious vomiting and the surgical team suspects a duct-dependent cyanotic lesion. Which drug maintains ductal patency while awaiting surgery?", "choices": ["Furosemide", "Indomethacin", "Prostaglandin E1", "Adenosine", "Digoxin"], "ans": 2, "exp": "Duct-dependent congenital heart lesions (เช่น TGA, pulmonary atresia, critical coarctation, HLHS): การอยู่รอดต้องมี PDA เพื่อ mixing/perfusion → ให้ 'prostaglandin E1 (alprostadil)' คง duct เปิด ระหว่างรอผ่าตัด. ตรงข้ามกับ preterm PDA ที่ต้องการปิด (indomethacin/ibuprofen). Cyanosis + duct-dependent = PGE1."}, {"topic": "Neuro/CVT/Vascular", "q": "A patient has a spinal cord injury with loss of motor function and pain/temperature below the lesion, but preserved proprioception and vibration. What syndrome is this?", "choices": ["Central cord syndrome", "Brown-Sequard syndrome", "Posterior cord syndrome", "Anterior cord syndrome", "Cauda equina syndrome"], "ans": 3, "exp": "Anterior cord syndrome: บาดเจ็บ anterior 2/3 ของ cord (มักจาก anterior spinal artery infarct/flexion injury) → สูญเสีย motor (corticospinal) + pain/temperature (spinothalamic) ใต้ระดับ แต่ 'คง proprioception/vibration (dorsal column)'. พยากรณ์ฟื้นตัวแย่ที่สุดในกลุ่ม incomplete."}, {"topic": "Neuro/CVT/Vascular", "q": "A patient has a chest X-ray showing a large abdominal aortic aneurysm and presents with sudden severe back/abdominal pain and hypotension. What is the management?", "choices": ["Elective repair later", "CT then observe", "Anticoagulation", "Antibiotics", "Emergency repair (open/EVAR)"], "ans": 4, "exp": "Ruptured AAA: triad 'ปวดท้อง/หลังเฉียบพลัน + hypotension + pulsatile abdominal mass' → 'emergency repair' (open หรือ EVAR) ทันที. ผู้ป่วย unstable → ห้องผ่าตัดเลย (ไม่รอ imaging); stable → CT ด่วนอาจช่วยวางแผน EVAR. permissive hypotension ระหว่างรอ. อัตราตายสูงมาก."}, {"topic": "Neuro/CVT/Vascular", "q": "A child has an atrial septal defect with a fixed, widely split S2. What is characteristic of ASD?", "choices": ["Fixed splitting of S2", "Rib notching", "Continuous machinery murmur", "Cyanosis at birth", "Boot-shaped heart"], "ans": 0, "exp": "Atrial septal defect (ASD): left-to-right shunt → 'fixed widely split S2' (ไม่เปลี่ยนตามการหายใจ) + systolic ejection murmur (เพิ่ม flow ผ่าน pulmonary valve). Acyanotic; อาจไม่มีอาการจนโต (heart failure, AF, pulmonary HT/Eisenmenger, paradoxical emboli). รักษา: catheter/surgical closure ในราย significant."}, {"topic": "Neuro/CVT/Vascular", "q": "A patient has recurrent spontaneous pneumothorax on the same side. What is the appropriate definitive treatment?", "choices": ["Antibiotics for this patient", "VATS with bullectomy and pleurodesis", "Repeated needle aspiration alone", "Observation for this patient", "Long-term oxygen for this patient"], "ans": 1, "exp": "Recurrent (or persistent air leak) spontaneous pneumothorax → 'VATS bullectomy + pleurodesis (mechanical/chemical)' เพื่อป้องกันการเป็นซ้ำ. ข้อบ่งชี้ surgery: recurrence (ครั้งที่ 2 ข้างเดิม หรือ contralateral), persistent air leak >3-5 วัน, bilateral, อาชีพเสี่ยง (นักบิน/นักดำน้ำ), hemothorax."}, {"topic": "Neuro/CVT/Vascular", "q": "A patient with chronic venous insufficiency and varicose veins with reflux at the saphenofemoral junction has recurrent symptoms despite compression. What is a definitive treatment option?", "choices": ["Anticoagulation in this case", "Antibiotics for this patient", "Endovenous ablation or surgery", "Diuretics for this patient", "Bed rest for this patient"], "ans": 2, "exp": "Varicose veins (superficial venous reflux): เริ่มด้วย conservative (compression stockings, leg elevation, exercise). Symptomatic/complications (ulcer, bleeding, thrombophlebitis) หรือดื้อ → 'endovenous thermal ablation (laser/radiofrequency)' หรือ surgery (high ligation + stripping)/foam sclerotherapy. ประเมิน reflux ด้วย duplex ก่อน. ต้องแน่ใจ deep system ปกติ."}, {"topic": "Neuro/CVT/Vascular", "q": "A patient after major vascular surgery is at high risk of VTE. What is appropriate prophylaxis?", "choices": ["No prophylaxis", "Therapeutic anticoagulation always", "Aspirin only", "Mechanical plus pharmacologic prophylaxis", "Bed rest only"], "ans": 3, "exp": "ผู้ป่วยผ่าตัดใหญ่ = high VTE risk → 'mechanical (IPC/stockings) + pharmacologic (LMWH/heparin) prophylaxis' + early mobilization. ประเมิน bleeding risk ร่วม (ผ่าตัด neuro/บางกรณีเริ่ม pharmacologic ช้าลง). Caprini score ช่วยประเมิน. ป้องกัน DVT/PE ซึ่งเป็นสาเหตุการตายที่ป้องกันได้."}, {"topic": "Neuro/CVT/Vascular", "q": "A patient develops sudden ventricular fibrillation after cardiac surgery. What is the immediate management?", "choices": ["Diuretics for this patient", "Give beta-blocker in this case", "Observe for this patient", "Pacing only", "Immediate defibrillation and CPR"], "ans": 4, "exp": "Ventricular fibrillation (pulseless) = cardiac arrest → 'immediate defibrillation (unsynchronized shock) + CPR' ตาม ACLS, epinephrine, amiodarone, หาสาเหตุ (5H5T - post-op: hypoxia, electrolyte-hyperkalemia, tamponade, MI/ischemia). Post-cardiac surgery arrest มี protocol เฉพาะ (พิจารณา resternotomy). Shockable rhythm → shock เร็ว."}, {"topic": "Neuro/CVT/Vascular", "q": "A patient has a spinal cord injury at the conus medullaris (L1-L2). Which feature distinguishes conus from cauda equina syndrome?", "choices": ["Early symmetric bladder/bowel dysfunction with mixed signs", "Pure motor deficit for this patient", "Only unilateral leg pain for this patient", "No bladder involvement for this patient", "Preserved reflexes always for this patient"], "ans": 0, "exp": "Conus medullaris syndrome: บาดเจ็บที่ปลาย cord (L1-2) → 'early, symmetric' bladder/bowel/sexual dysfunction, saddle anesthesia, mixed UMN+LMN signs, ปวดน้อยกว่า. Cauda equina syndrome: บาดเจ็บ nerve roots ใต้ conus → asymmetric, ปวดมาก (radicular), LMN signs, bladder dysfunction มาช้ากว่า. ทั้งคู่ต้อง urgent MRI + decompression."}, {"topic": "Neuro/CVT/Vascular", "q": "A patient with lung cancer needs staging. Which imaging assesses distant metastasis and nodal involvement for treatment planning?", "choices": ["No imaging", "PET-CT", "Chest X-ray only", "Abdominal ultrasound", "Bone X-ray only"], "ans": 1, "exp": "Lung cancer staging (TNM): 'CT chest/upper abdomen + PET-CT' (ประเมิน nodes/distant metastasis - adrenal, liver, bone), + brain MRI (ในบางระยะ), ± EBUS/mediastinoscopy สำหรับ mediastinal nodes. Staging กำหนดการรักษา (resectable vs systemic). PET-CT ช่วยแยก resectable/unresectable และหลีกเลี่ยงผ่าตัดที่ไม่ได้ประโยชน์."}, {"topic": "Neuro/CVT/Vascular", "q": "A patient has a stab wound to the chest and develops hypotension with distended neck veins; ultrasound shows pericardial fluid with tamponade. What is the definitive management?", "choices": ["Antibiotics only", "Oral fluids for this patient", "Surgical pericardial decompression (thoracotomy)", "Chest physiotherapy for this patient", "Observation for this patient"], "ans": 2, "exp": "Penetrating cardiac injury with tamponade (Beck triad + FAST pericardial fluid): pericardiocentesis เป็น temporizing เท่านั้น → definitive คือ 'emergency surgery (thoracotomy/sternotomy) เพื่อ decompress + repair cardiac wound'. Unstable penetrating chest trauma อาจต้อง ED thoracotomy. เป็น surgical emergency."}, {"topic": "Neuro/CVT/Vascular", "q": "A patient with severe head injury has a cerebral perfusion pressure (CPP) that must be maintained. How is CPP calculated?", "choices": ["Systolic BP minus ICP for this patient", "ICP minus MAP for this patient", "MAP plus ICP for this patient", "Mean arterial pressure minus intracranial pressure", "Diastolic BP only"], "ans": 3, "exp": "Cerebral perfusion pressure 'CPP = MAP − ICP' (เป้าหมายมัก ≥60-70 mmHg ใน severe TBI). การลด CPP (จาก ICP สูงหรือ MAP ต่ำ - hypotension) → cerebral ischemia (secondary injury). จึงต้องคุม ICP และหลีกเลี่ยง hypotension/hypoxia. เป็นหลักการดูแล neurocritical care."}, {"topic": "Neuro/CVT/Vascular", "q": "A patient has a large hemothorax with over 1500 mL initial drainage or ongoing bleeding of 200 mL/hr. What is the indication?", "choices": ["Observation only", "Antibiotics only", "Repeat chest X-ray in 24 hours", "Diuretics", "Thoracotomy for surgical control"], "ans": 4, "exp": "Massive hemothorax: chest tube ออกเลือด '>1,500 mL ทันที' หรือ 'ongoing >200 mL/hr × 2-4 ชม.' หรือ hemodynamic instability → ข้อบ่งชี้ 'thoracotomy' เพื่อควบคุมแหล่งเลือด (systemic - intercostal/internal mammary, hilar, great vessels). ร่วมกับ resuscitation. ส่วนใหญ่ hemothorax เล็ก-กลางหายด้วย chest tube."}]}, {"id": "nl2-2021", "title": "NL 2 ปี 2021 (VICHAKARN_SMST)", "subject": "past", "questions": [{"topic": "Cardiology", "q": "A 50-year-old male, heavy smoker, presented with a severe chest pain for 30 minutes at a community hospital. He has no known underlying diseases. PE: V/S stable; CVS - no neck vein engorged, PMI 5th ICS MCL, normal S1S2, S3 gallop; RS - fine crepitation both basal lungs; EKG: STE at V4-6, STD II, III, aVF; TropT: Elevated. It takes 150 minutes to travel from this community hospital to the cardiac center. Aside from aspirin and clopidogrel, what is the proper management in this patient?", "choices": ["Streptokinase", "Enoxaparin", "Ticagrelor", "Furosemide", "Refer for primary PCI"], "ans": 0, "exp": "STEMI (anterior). กฎเวลา reperfusion: ถ้าคาดว่า first-medical-contact ถึง PCI-device นานเกิน 120 นาที ให้เลือก fibrinolysis (ในที่นี้ระยะทาง 150 นาที > 120) — ยาละลายลิ่มที่มีคือ streptokinase แล้วจึงส่งต่อทำ PCI (pharmaco-invasive). *หมายเหตุ: ไฟล์ต้นฉบับไฮไลต์ตัวเลือก “Refer for primary PCI” แต่ตามแนวทางเวลา >120 นาที ควรให้ยาละลายลิ่มก่อน จึงเลือก Streptokinase*", "sys": "IX"}, {"topic": "Cardiology", "q": "A 30-year-old female presented with lightheadedness with paroxysmal palpitation for 1 month. She experienced this symptom 2-3 times per week especially after voiding. PE: unremarkable. EKG: normal sinus rhythm, HR 80/min, no ST-T change, no AV block. What is investigation?", "choices": ["Echo", "Tilt table test", "Exercise stress test", "24 hr holter monitoring", "Carotid ultrasound"], "ans": 1, "exp": "อาการเป็นลม/หน้ามืดสัมพันธ์กับการถ่ายปัสสาวะ (post-void) เข้าได้กับ situational/reflex (vasovagal) syncope — การตรวจยืนยันคือ tilt table test. EKG ปกติและไม่มี structural clue จึงไม่ใช่ arrhythmia (holter) หรือ ischemia (EST).", "sys": "IX"}, {"topic": "Cardiology", "q": "A man known case ESRD (not on RRT). EKG as shown (wide bizarre QRS / sine-wave pattern). What is the most proper management?", "choices": ["Furosemide", "Insulin", "10% calcium gluconate", "7.5% bicarbonate"], "ans": 2, "exp": "ESRD + EKG QRS กว้างผิดรูป/sine wave = severe hyperkalemia. ลำดับแรกต้องให้ calcium gluconate เพื่อ stabilize cardiac membrane ป้องกัน arrhythmia (แม้ไม่ลดระดับ K). จากนั้นจึง shift K เข้าเซลล์ (insulin+glucose, bicarbonate) และกำจัด K (diuretic/dialysis).", "img": "https://cdn.jsdelivr.net/gh/MercenzK/Web-quiz-images@main/NL2-2021-Q5.png", "sys": "IX"}, {"topic": "Cardiology", "q": "Female s/p radical mastectomy, currently on doxorubicin for 6 months, presented with dyspnea. PE: V/S - RR 20/min, PR 120 bpm, BP 80/60 mmHg; CVS - faint heart sound, normal S1S2 no murmur; Lung - clear and equal breath sound; Abd - Liver 3 cm bcm. What's proper management?", "choices": ["IV Furosemide", "IV Dobutamine", "Pericardiocentesis", "Echocardiogram"], "ans": 3, "exp": "Doxorubicin เป็น anthracycline ที่ทำให้เกิด cardiotoxicity ได้ทั้ง dilated cardiomyopathy และ pericardial effusion. อาการ hypotension + faint heart sound + tachycardia + hepatic congestion ต้องแยกระหว่าง cardiomyopathy กับ tamponade — จึงทำ echocardiogram เพื่อประเมิน EF/effusion ก่อนเลือกการรักษา (furosemide/inotrope/pericardiocentesis).", "sys": "IX"}, {"topic": "Cardiology", "q": "ผู้ป่วยชาย 40 ปี มาตรวจสุขภาพประจำปี ไม่มีประวัติโรคหัวใจ ไม่มีอาการ ไม่เคยออกกำลังกาย ให้แนะนำ activity ที่ช่วยป้องกัน cardiovascular disease", "choices": ["15 min jogging 3 days/week", "Walking 2000 steps/day", "2 set of 10 squatting per day", "One hour yoga per day", "30 min brief walking 5 days/week"], "ans": 4, "exp": "คำแนะนำการออกกำลังกายเพื่อป้องกันโรคหัวใจและหลอดเลือด = aerobic ระดับปานกลางอย่างน้อย 150 นาที/สัปดาห์ → เดินเร็ว 30 นาที × 5 วัน = 150 นาที/สัปดาห์ ตรงเป้าที่สุดและเหมาะกับผู้เริ่มต้น.", "sys": "IX"}, {"topic": "Cardiology", "q": "ให้ประวัติเข้าได้กับ pericarditis (pericardial effusion เจาะดูดน้ำออกมา ให้ profile) ถาม long term prophylaxis เพื่อป้องกันภาวะแทรกซ้อนระยะยาว", "choices": ["Prednisolone", "ASA", "Colchicine", "Anti TB Drug"], "ans": 0, "exp": "กรณี pericardial effusion ที่ profile เข้าได้กับ TB pericarditis (lymphocyte เด่น, ADA สูง) การให้ adjunctive corticosteroid (prednisolone) ร่วมกับ anti-TB ช่วยลดโอกาสเกิด constrictive pericarditis ในระยะยาว. *ถ้าเป็น idiopathic/viral recurrent pericarditis การป้องกันการเป็นซ้ำจะใช้ colchicine — ต้องดู profile ประกอบ*", "sys": "IX"}, {"topic": "Cardiology", "q": "ชาย 60 ปี มาด้วย chest pain, dx MI s/p PCI กำลังจะ discharge กลับบ้าน u/d DLP, HT. Lipid profile: cho 180, TG 250, HDL 40. ก่อนกลับบ้านควรทำอย่างไรกับ DLP?", "choices": ["Direct LDL", "High intensity statin", "Repeat lipid profile ก่อนให้ยา", "Low intensity statin + fenofibrate", "Moderate intensity statin"], "ans": 1, "exp": "ผู้ป่วยหลัง MI/PCI = ASCVD ความเสี่ยงสูงมาก ต้องได้ high-intensity statin (atorvastatin 40-80 หรือ rosuvastatin 20-40) โดยไม่ต้องรอ/ขึ้นกับระดับ LDL เป้าหมาย LDL < 55 มก./ดล. และลด ≥ 50%.", "sys": "IX"}, {"topic": "Neurology", "q": "A 50-year-old woman presented with episodic sharp stabbing pain at left mandible radiate to TM joint and then deep in left ear. These episodes are triggered with smiling and touching face. PE: no neurological deficit, no dental caries. What is the most appropriate treatment?", "choices": ["Tramadol", "Ibuprofen", "Carbamazepine", "Amitriptyline", "Prednisolone"], "ans": 2, "exp": "ปวดแปลบสั้น ๆ ตามแนว trigeminal (mandibular) กระตุ้นด้วยการสัมผัส/ยิ้ม โดยไม่มี neuro deficit = trigeminal neuralgia. ยา first-line คือ carbamazepine (หรือ oxcarbazepine).", "sys": "VI"}, {"topic": "Pulmonology", "q": "ผู้ชาย 22 ปี เล่นฟุตบอลแล้วอยู่ดี ๆ ก็เหนื่อย PE: mild hyperresonance on percussion left side. CXR: visceral pleural line ห่างจาก chest wall 1 cm. What is the most proper management?", "choices": ["O2 supplement", "Simple aspiration", "Tube thoracostomy", "Observe", "Surgical thoracotomy"], "ans": 3, "exp": "Primary spontaneous pneumothorax ขนาดเล็ก (rim < 2 ซม. ที่นี่ 1 ซม.) อาการน้อย = observe (± ให้ O2 เร่งการดูดกลับของอากาศ). ถ้าขนาดใหญ่/อาการมากจึงพิจารณา aspiration หรือ ICD.", "sys": "X"}, {"topic": "Pulmonology", "q": "A 25-year-old female presented with dyspnea and cyanosis for 1 hour, U/D myasthenia gravis, lost follow up 1 month. PE: V/S - BP 90/60 mmHg, PR 100 bpm, RR 30/min; Lung - shallow breathing, cyanosis, no adventitious sound. What is most likely the etiology (mechanism of hypoxemia)?", "choices": ["Shunt", "Dead space", "Diffusion defect", "V/Q mismatch", "Hypoventilation"], "ans": 4, "exp": "MG ที่ขาดยา → myasthenic crisis กล้ามเนื้อหายใจอ่อนแรง → หายใจตื้น (shallow breathing) = alveolar hypoventilation ทำให้ PaCO2 สูงและ PaO2 ต่ำ (เขียว) โดยปอดเองปกติ (no adventitious sound). กลไก hypoxemia คือ hypoventilation.", "sys": "X"}, {"topic": "Pulmonology", "q": "ผู้ชายมาด้วย respiratory distress RR 10 เหงื่อแตก มี retraction. PE: lung - clear both lungs, poor air entry, minimal wheezing. What's proper management?", "choices": ["ETT", "Salbutamol NB", "Ipratropium NB"], "ans": 0, "exp": "RR ต่ำ (10) + เหงื่อแตก + retraction + poor air entry = ผู้ป่วยกำลังหมดแรงหายใจ (impending respiratory failure). ต้อง secure airway ด้วย endotracheal intubation ทันที ไม่ใช่แค่พ่นยา.", "sys": "X"}, {"topic": "Pulmonology", "q": "A 50-year-old female with advanced stage CA pancreas presented with shortness of breath and chest tightness 3 hours prior to admission. PE: V/S - BT 37.8°C, PR 110 bpm, RR 30/min, BP 110/70 mmHg, SpO2 90% RA; Heart - normal S1S2, no murmur, no gallop; EKG: sinus tachycardia; CXR: no infiltration. What is the most appropriate management?", "choices": ["IV fluid loading", "LMWH", "ASA Nitrate", "Thrombolytics", "Observe and Follow up EKG next 12h"], "ans": 1, "exp": "มะเร็ง (hypercoagulable) + เหนื่อยเฉียบพลัน + tachycardia + hypoxia (SpO2 90%) + EKG sinus tachy + CXR ปกติ = pulmonary embolism. ผู้ป่วย hemodynamic ยังคงที่ (ไม่ใช่ massive) จึงรักษาด้วย anticoagulation (LMWH); thrombolytics ใช้เฉพาะ massive PE ที่ช็อก.", "sys": "X"}, {"topic": "Pulmonology", "q": "A 70-year-old male came in with an acute exacerbation from U/D COPD. He received antimicrobial agent, bronchodilator, oxygen cannula 5 LPM and became clinically improved. Two days later, he looks stuporous but still arousal. He has a very slow respiratory rate. What is the most appropriate management?", "choices": ["Add dexamethasone", "Change antimicrobial agent", "endotracheal intubation", "increase bronchodilator dose", "discontinue oxygen treatment"], "ans": 2, "exp": "COPD ที่ได้ O2 flow สูง (5 LPM) เกินไป → CO2 คั่ง (hypercapnia/CO2 narcosis) ทำให้ซึมและ RR ช้าลง = hypercapnic respiratory failure ที่มีระดับความรู้สึกตัวลด. ต้องช่วยหายใจ (NIV/intubation) — ในตัวเลือกนี้คือ endotracheal intubation. (การ off O2 ทันทีจะทำให้ hypoxia)", "sys": "X"}, {"topic": "Pulmonology", "q": "Patient with COPD exacerbation ได้ ATB กับ O2 cannula 5 LPM อาการเริ่มดีขึ้น 2 วันต่อมาอาการแย่ลง stupor RR ร่วง (ลดลง) ถามว่าทำอย่างไร", "choices": ["เปลี่ยน ATB", "ให้ dexamethasone", "off O2", "ETT"], "ans": 3, "exp": "เหมือนข้อก่อนหน้า (CO2 narcosis จาก O2 มากเกินใน COPD) — ผู้ป่วยซึม RR ช้า = hypercapnic respiratory failure ต้องช่วยหายใจด้วย ETT. *ไฟล์ต้นฉบับไฮไลต์ “ให้ dexamethasone” ซึ่งไม่แก้ปัญหา CO2 คั่งเฉียบพลัน จึงเลือก ETT ตามหลักการ*", "sys": "X"}, {"topic": "Pulmonology", "q": "ชายไทย หอบเหนื่อย ตรวจเจอ pleural effusion, pleural profile: ADA 50. ถามทำอะไรต่อ", "choices": ["Antibiotics", "ส่ง pleural cytology ต่อ", "Anti tb drug", "Repeat ซ้ำ"], "ans": 2, "exp": "Pleural effusion ที่ ADA สูง (> 40 U/L, ที่นี่ 50) ในผู้ป่วยไทยที่มี exudative lymphocytic effusion เข้าได้กับ tuberculous pleuritis อย่างมาก → เริ่ม anti-TB drug (ADA สูงมีความไวสูงในการวินิจฉัย TB pleuritis).", "sys": "X"}, {"topic": "Pulmonology", "q": "20 years old male playing soccer then sudden has dyspnea and chest pain. CXR shows 1 cm of pneumothorax. What is the proper management?", "choices": ["oxygen therapy", "ICD", "Thoracentesis"], "ans": 0, "exp": "Primary spontaneous pneumothorax ขนาดเล็ก (1 ซม. < 2 ซม.) → ให้ oxygen therapy + observe (O2 ช่วยเร่งการดูดกลับของอากาศในเยื่อหุ้มปอด). ยังไม่ต้องใส่ ICD/aspiration ถ้าขนาดเล็กและอาการไม่มาก.", "sys": "X"}, {"topic": "Rheumatology", "q": "A 40-year-old woman present with chronic cough and mild dyspnea for 1 month. She had generalized skin thickening for 5 years. PE: Raynaud phenomenon at both fingers and toes, skin thickening at extremities, chest wall, abdomen. What is the most likely cause of pulmonary abnormality in this patient?", "choices": ["Pneumothorax", "Pulmonary fibrosis", "Pleural effusion", "Pulmonary nodule"], "ans": 1, "exp": "ผิวหนังหนาทั้งตัว + Raynaud = systemic sclerosis (scleroderma). ภาวะปอดที่พบบ่อยและเป็นสาเหตุอาการไอ/เหนื่อยเรื้อรังคือ interstitial lung disease → pulmonary fibrosis (ควรเฝ้าระวัง PAH ด้วย).", "sys": "XIII"}, {"topic": "Hematology", "q": "A 50-year-old female with an underlying disease of acute myeloblastic leukemia was admitted for chemotherapy. Lab pre-chemotherapy: Hb 9, WBC 198,000 (N1 L1 blast98). Post-CMT Day 1, she developed oliguria (urine output = 50 ml/day) with creatinine rising from 1 to 2.5 mg/dL. Elyte: Na 140, K 6, Cl 100, HCO3 15, Ca 7.5, Alb 4, Phosphate 7. What is the most likely diagnosis?", "choices": ["Obstructive nephropathy", "Rhabdomyolysis", "Tumor lysis syndrome", "Drug induced nephropathy"], "ans": 2, "exp": "หลังให้ chemo ในมะเร็งที่ tumor burden สูง (blast 98%, WBC สูง) เกิด AKI + hyperK + hyperphosphatemia + hypocalcemia = tumor lysis syndrome (เซลล์มะเร็งแตกปล่อย K/PO4/uric acid). ป้องกัน/รักษาด้วย hydration + allopurinol/rasburicase + แก้ electrolyte.", "sys": "III"}, {"topic": "Hematology", "q": "A 16-year-old female presented with oral mucosal bleeding and hypermenorrhea. She has no family history of bleeding disorder. Lab: CBC - WNL (Plt normal); Coagulogram - PT 10, aPTT 33 correctable with mixing test. What is the most likely diagnosis?", "choices": ["Factor 7 deficiency", "Factor 8 inhibitor", "Factor 8 deficiency", "vWF deficiency", "Antiphospholipid syndrome"], "ans": 3, "exp": "เลือดออกแบบ mucocutaneous (เยื่อบุ + ประจำเดือนมาก) + platelet ปกติ + PT ปกติ + aPTT ยาวเล็กน้อยที่ correct ด้วย mixing (= ขาด factor ไม่ใช่ inhibitor) = von Willebrand disease (vWF พา factor VIII จึงทำ aPTT ยาวได้). *ต้นฉบับไฮไลต์ Factor 7 deficiency แต่ factor VII จะทำ PT ยาว (ที่นี่ PT ปกติ) จึงไม่ใช่*", "sys": "III"}, {"topic": "Hematology", "q": "A 28-year-old female presented with dyspnea on exertion for 4 days. CBC: Hb 7, Hct 21, MCV 58. PBS: anisocytosis 2+ poikilocytosis 1+. Hb typing: homozygous Hb E. What is the cause of anemia in this patient?", "choices": ["Anemia of inflammation", "Iron deficiency anemia", "Pernicious anemia", "Autoimmune hemolytic anemia", "Hemoglobin E disease"], "ans": 4, "exp": "Hb typing เป็น homozygous Hb E → Hemoglobin E disease (microcytic anemia, MCV ต่ำ, target cell). เป็น hemoglobinopathy ที่พบบ่อยในไทย — ระวังอย่าให้ธาตุเหล็กเกินถ้าไม่ได้ขาดจริง.", "img": "https://cdn.jsdelivr.net/gh/MercenzK/Web-quiz-images@main/NL2-2021-Q24.png", "sys": "III"}, {"topic": "Hematology", "q": "ชาย 20 ปี acute dyspnea on exertion, intermittent dark urine 3 months. CBC: Hb 6.2, MCV 68, Polychromasia 1+, Schistocyte 2+. What is the most likely diagnosis?", "choices": ["PNH", "AIHA", "G6PD", "HbH", "HS"], "ans": 0, "exp": "ปัสสาวะสีเข้มเป็นพัก ๆ (hemoglobinuria) เรื้อรังหลายเดือน + hemolysis (polychromasia, schistocyte) = paroxysmal nocturnal hemoglobinuria (PNH). การเสีย hemoglobin/iron ทางปัสสาวะเรื้อรังทำให้ MCV ต่ำได้. วินิจฉัยด้วย flow cytometry (CD55/CD59).", "sys": "III"}, {"topic": "Hematology", "q": "หญิง มาด้วย bleed เยอะ ประจำเดือนมาเยอะ ส่ง CBC เจอ isolated thrombocytopenia ส่งอะไรต่อ", "choices": ["Bleeding time", "Anti HIV Anti HCV", "Bone marrow aspiration"], "ans": 1, "exp": "หญิงสาว isolated thrombocytopenia นึกถึง ITP ซึ่งเป็น diagnosis of exclusion — ควรคัดกรองสาเหตุ secondary ก่อน โดยส่ง anti-HIV, anti-HCV (เป็นสาเหตุ secondary ITP ที่พบบ่อย). Bone marrow ไม่จำเป็นในคนอายุน้อยที่ line อื่นปกติ.", "sys": "III"}, {"topic": "Hematology", "q": "A 68-year-old woman presents with dyspnea on exertion 4 months PTA. She had gait ataxia and paresthesia. PE: marked pallor, no jaundice, no hepatosplenomegaly, loss of proprioception and vibration test. CBC: Hb 6.8, Hct 20.4, MCV 115, RDW 24, WBC 3500 (N 53, L 35), Plt 85,000. What is diagnosis?", "choices": ["Acute leukemia", "Aplastic anemia", "Cobalamin deficiency", "Folate deficiency", "Paroxysmal Nocturnal Hemoglobinuria"], "ans": 2, "exp": "Macrocytic anemia (MCV 115) + อาการทางระบบประสาทของ dorsal column (สูญเสีย proprioception/vibration, gait ataxia = subacute combined degeneration) + mild pancytopenia = vitamin B12 (cobalamin) deficiency. Folate ขาดจะไม่มีอาการทางประสาท. *ต้นฉบับไฮไลต์ PNH ซึ่งไม่เข้ากับ macrocytosis + neuro sign*", "sys": "III"}, {"topic": "Hematology", "q": "70 yo Female patient with paresthesia. CBC: MCV 110. What is the diagnosis?", "choices": ["Folate deficiency", "Cobalamin deficiency"], "ans": 1, "exp": "Macrocytic anemia (MCV 110) + paresthesia (อาการทางประสาท) = vitamin B12 (cobalamin) deficiency (subacute combined degeneration). Folate deficiency ให้ภาพ megaloblastic เหมือนกันแต่ไม่มีอาการทางประสาท.", "sys": "III"}, {"topic": "Hematology", "q": "หญิงไทย มาด้วย mucosal bleeding, มีประวัติ recurrent mucosal bleeding มาก่อน ไม่มีประวัติคนในครอบครัวเป็น bleeding disorder. Lab: Hct 12.5%, WBC 4500, Plt 222,000, Coag PT normal, aPTT prolong, Correct by mixing study. What is diagnosis?", "choices": ["VwD disease", "Factor VII deficiency", "Factor VIII Inhibitor", "Hemophilia"], "ans": 0, "exp": "เลือดออกเยื่อบุซ้ำ ๆ + platelet ปกติ + PT ปกติ + aPTT ยาวที่ correct ด้วย mixing (ขาด factor ไม่ใช่ inhibitor) + ไม่มีประวัติครอบครัว/เป็นหญิง = von Willebrand disease. (Hemophilia = X-linked ในผู้ชาย เลือดออกในข้อ/กล้ามเนื้อ; Factor VII จะทำ PT ยาว).", "sys": "III"}, {"topic": "GI/Hepatology", "q": "A 60-year-old male came to the ER because of hematemesis. He has a history of alcohol drinking. BP 100/70 mmHg. PE: GA - Drowsiness; Abdomen - spider nevi, palmar erythema, splenomegaly, ascites. NG content is 200ml fresh blood, Hct 25%. After fluid resuscitation, what is next management?", "choices": ["EGD", "Cold NSS lavage", "Transamine", "Plasma transfusion", "Sengstaken blakemore"], "ans": 0, "exp": "Cirrhosis (spider nevi, palmar erythema, ascites) + hematemesis = variceal bleeding. หลัง resuscitation ขั้นถัดไปคือ EGD เพื่อวินิจฉัยและทำ endoscopic band ligation (ร่วมกับ vasoactive drug + prophylactic antibiotic). *ต้นฉบับไฮไลต์ Sengstaken-Blakemore ซึ่งเป็นแค่ balloon tamponade ชั่วคราวเมื่อ endoscopy คุมไม่ได้ ไม่ใช่ขั้นแรก*", "sys": "XI"}, {"topic": "GI/Hepatology", "q": "A 25-year-old man presented with acute abdominal pain and nausea/vomiting for 1 day. Previously, he took NSAIDs for his migraine and drank 2 cans of beer once a week. PE: BT 38°C, epigastric pain, eruptive xanthoma both ankles. What is the most likely etiology of his illness?", "choices": ["NSAIDs", "Hypertriglyceridemia", "Gallstone", "Hypercholesterolemia", "Alcohol"], "ans": 1, "exp": "Acute pancreatitis (ปวด epigastrium + N/V + ไข้) + eruptive xanthoma (สัญญาณของ triglyceride สูงมาก) → สาเหตุคือ hypertriglyceridemia (TG มัก> 1000). Eruptive xanthoma เป็นเบาะแสสำคัญของ severe hypertriglyceridemia.", "sys": "XI"}, {"topic": "Cardiology", "q": "A 50-year-old male with poor controlled HT presented with a severe progressive chest pain radiating to back 1 hr PTA. PE: pulse regular (upper 2+ lower 1+), BP 100/80 mmHg. What is the diagnosis?", "choices": ["Acute pericarditis", "Acute MI", "Aortic dissection", "PE", "Acute pancreatitis"], "ans": 2, "exp": "เจ็บอกรุนแรงร้าวไปหลัง + ประวัติ HT คุมไม่ดี + ชีพจร/ความดันแขน-ขาไม่เท่ากัน (upper 2+ lower 1+) = aortic dissection. ยืนยันด้วย CT angiography; รักษาคุม HR/BP (beta-blocker) และผ่าตัดถ้า type A.", "sys": "IX"}, {"topic": "GI/Hepatology", "q": "A 50-year-old female with underlying disease of T2DM had a fever and abdominal pain for 3 wks. PE: V/S - BT 38.3°C, P 100 bpm, RR 20/min, BP 130/80 mmHg; Abdomen - mild jaundice, tenderness at RUQ, Murphy's sign negative, liver 2 cm BRCM, liver span 12 cm, impalpable spleen. Lab: Albumin 3, Globulin 4, TB 4, DB 2.2, AST 248, ALT 310, ALP 386. What is the next appropriate management?", "choices": ["Melioid titer", "H/C", "E. histolytica titer", "U/S upper abd", "MRI/MRCP"], "ans": 3, "exp": "ไข้เรื้อรัง 3 สัปดาห์ + RUQ pain + ตับโตกดเจ็บ + ตัวเหลือง + enzyme ตับขึ้น ในผู้ป่วยเบาหวาน → สงสัย liver abscess/โรคทางเดินน้ำดี. ขั้นถัดไปที่เหมาะสมและทำง่ายคือ ultrasound upper abdomen เพื่อหา abscess/ท่อน้ำดีอุดตันก่อนตรวจอื่น.", "sys": "XI"}, {"topic": "Pulmonology", "q": "Case: 55 yo Thai lady suspected CA pancreas. CC: 3hr PTA chest tightness. V/S: BT 37.8, PR 110 bpm, BP 110/70, O2 sat 90% RA, JVP 5cm, others wnl. EKG: Sinus tachycardia. Initial management? (ตัวเลือกแต่งขึ้นมาเอง ต้นฉบับไม่มีตัวเลือก)", "choices": ["IV fluid loading", "ASA + Nitrate", "Thrombolytics", "Observe and repeat EKG in 12h", "LMWH (anticoagulation)"], "ans": 4, "exp": "มะเร็ง (hypercoagulable) + เหนื่อย/แน่นอกเฉียบพลัน + tachycardia + hypoxia (SpO2 90%) + sinus tachy = pulmonary embolism. ผู้ป่วยยัง hemodynamic คงที่ → รักษาด้วย anticoagulation (LMWH). thrombolytics เฉพาะ massive PE ที่ช็อก. *ต้นฉบับไม่มีตัวเลือก — แต่งขึ้นตามแนวข้อคล้ายกันในชุดนี้*", "sys": "X"}, {"topic": "Hematology", "q": "A young man presented with dark urine and jaundice. A few days ago, he had URI symptoms. PBS as in picture. What is the diagnosis? (ต้นฉบับตัวเลือกไม่ครบ — ใส่เท่าที่มี)", "choices": ["G6PD deficiency", "Thalassemia"], "ans": 0, "exp": "ภาวะเม็ดเลือดแดงแตกเฉียบพลันหลังติดเชื้อ (URI) + ปัสสาวะเข้ม + ตัวเหลือง = G6PD deficiency (oxidative hemolysis ที่ถูกกระตุ้นด้วยการติดเชื้อ/ยา/ถั่วปากอ้า) — PBS พบ bite cell และ Heinz body.", "sys": "III"}, {"topic": "GI/Hepatology", "q": "A 40-year-old male presented with epigastric pain & burning sensation for 8 weeks. Symptoms are relieved by omeprazole & simethicone. He has a weight loss of 5 kg. PE: stable v/s, mild pale conjunctiva, mild epigastric distension, otherwise normal. What is the most appropriate management?", "choices": ["Urea breath test", "Gastroduodenoscopy", "Stool occult blood", "Switch omeprazole to pantoprazole", "CT upper abdomen"], "ans": 1, "exp": "Dyspepsia ที่มี alarm features (น้ำหนักลด 5 กก., ซีด/pale conjunctiva) → ต้องส่อง gastroduodenoscopy (EGD) เพื่อตัดมะเร็งกระเพาะ/แผล. ไม่ใช่แค่ปรับยาหรือ urea breath test.", "sys": "XI"}, {"topic": "GI/Hepatology", "q": "A 50 years old male came to the hospital for a regular check up. PE: mild pale conjunctiva, dull splenic positive (splenomegaly), left lobe liver just palpate. Lab: CBC - Hb 9, MCV 100, Plt 80,000; LFT - Albumin 3, Globulin 5, AST 85, ALT 62, ALP 102. What is the most likely diagnosis?", "choices": ["Fatty liver", "Hypersplenism", "Cirrhosis", "Hb H", "Vit. 12 def."], "ans": 2, "exp": "Anemia + thrombocytopenia (Plt 80,000) + splenomegaly + hepatomegaly + A/G reversed (Alb 3 ต่ำ Globulin 5 สูง) + transaminase ขึ้นเล็กน้อย = chronic liver disease → cirrhosis ที่มี portal hypertension/hypersplenism (ทำให้ cytopenia). *ต้นฉบับไฮไลต์ Fatty liver แต่ fatty liver ไม่ทำให้ม้ามโต/เกล็ดเลือดต่ำ/globulin สูง*", "sys": "XI"}, {"topic": "GI/Hepatology", "q": "A 45-year-old man presents with acute sharp epigastric pain. He has a history of NSAIDs use due to back pain. PE: V/S - BT 37.2°C, PR 120 bpm, RR 24/min, BP 140/90 mmHg; GA - agitated and sweating; Abdomen - marked tenderness at upper abdomen, loss of hepatic dullness. What is the initial investigation?", "choices": ["serum amylase", "ultrasound abdomen", "CT abdomen", "acute abdomen series", "CTA whole aorta"], "ans": 3, "exp": "ประวัติ NSAIDs + ปวดท้องเฉียบพลัน + loss of hepatic dullness = สงสัย perforated peptic ulcer (มี free air). การตรวจเบื้องต้นคือ acute abdomen series (upright CXR/abdomen film) เพื่อดู free air ใต้กระบังลม.", "sys": "XI"}, {"topic": "GI/Hepatology", "q": "A female came in for a check up. PE: liver span 11 cm, normal เกือบหมด ยกเว้น AST 260, ALT 120, ALP 100. Dx?", "choices": ["Fatty liver", "Drug induced hepatitis", "Alcoholic hepatitis", "Chronic viral hepatitis"], "ans": 2, "exp": "AST 260 > ALT 120 (AST:ALT ≈ 2:1) โดยค่าไม่สูงมาก (< 300) = ลักษณะเฉพาะของ alcoholic hepatitis. (Fatty liver/NAFLD มักมี ALT > AST; viral hepatitis มัก ALT สูงเด่น). ควรถามประวัติดื่มสุราประกอบ", "sys": "XI"}, {"topic": "Neurology", "q": "A 50-year-old alcoholic man presents with acute confusion. DTX 45 mg/dl. What is the most appropriate initial management?", "choices": ["Thiamine", "Serum blood sugar", "Repeat DTX", "50% Glucose bolus", "Serum electrolyte"], "ans": 0, "exp": "ผู้ป่วยติดสุรา + hypoglycemia (DTX 45) + สับสน — ต้องให้ thiamine ก่อน/พร้อมกับ glucose เพื่อป้องกัน Wernicke encephalopathy (การให้ glucose ก่อนในคนขาด thiamine อาจกระตุ้นให้เกิด Wernicke). จึงเริ่มด้วย thiamine.", "sys": "VI"}, {"topic": "GI/Hepatology", "q": "หญิง 20 ปี รักษา acne vulgaris อยู่ มาด้วย chest pain when swallow กับมี occasional heart burn ไม่สัมพันธ์กับ exertion ไม่มี sign ของ hypovolemia, V/S stable, ตรวจร่างกายปกติหมด. ถาม most proper investigation?", "choices": ["EKG 12 lead", "Barium esophagography", "24 hr pH monitor", "CXR AP Lat", "Esophageal manometry"], "ans": 1, "exp": "หญิงสาวกินยารักษาสิว (มัก doxycycline) + เจ็บอกเวลากลืน (odynophagia) + แสบยอดอก ไม่สัมพันธ์การออกแรง = pill-induced esophagitis/โรคหลอดอาหาร. ในตัวเลือกนี้ barium esophagography ใช้ประเมินหลอดอาหาร (แผล/ตีบ) ได้. *ที่จริง endoscopy (EGD) เหมาะสุดแต่ไม่มีในตัวเลือก*", "sys": "XI"}, {"topic": "GI/Hepatology", "q": "เป็น GERD ถามควรกินอะไร (อาหารที่เหมาะกับผู้ป่วย GERD)", "choices": ["Vegetables with chilli pepper", "Sausage with tomato sauces", "Pancake with honey syrup", "Fried (ของทอด)"], "ans": 2, "exp": "GERD ควรเลี่ยงอาหารกระตุ้นกรด/คลายหูรูด: เผ็ด (พริก), มะเขือเทศ/ซอสเปรี้ยว, ของทอด/ไขมันสูง, ช็อกโกแลต, คาเฟอีน. ในตัวเลือกนี้ pancake ราดน้ำผึ้งกระตุ้นน้อยที่สุด.", "sys": "XI"}, {"topic": "GI/Hepatology", "q": "ผู้ชายอายุ 55 ปี สุขภาพดีมาตลอด มาตรวจสุขภาพ V/S stable, LFT: TP 7, Alb 3.5, TB 0.8, DB 0.2, AST 260, ALT 127, ALP 102. เป็นอะไร", "choices": ["Fatty liver", "Autoimmune hepatitis", "Chronic HBV hepatitis", "Alcoholic hepatitis", "Drug-induced hepatitis"], "ans": 3, "exp": "AST 260 > ALT 127 (ratio ≈ 2:1) ค่าไม่สูงมาก = alcoholic hepatitis (จุดสำคัญคือ AST:ALT > 2:1). *ต้นฉบับไฮไลต์ Fatty liver — ซึ่งมักให้ ALT > AST; ถ้าไม่มีประวัติสุราจริงค่อยพิจารณา NAFLD*", "sys": "XI"}, {"topic": "GI/Hepatology", "q": "A previous healthy 50-year-old came for health checkup. V/S: BT 37, PR 98, RR 16, BP 130/80 mmHg. PE: Liver 1 FB BRCM (liver span 14 cm), others unremarkable. Lab: LFT - TP 7, TB 0.8, DB 0.4, AST 267, ALT 127, ALP 102, other investigations WNL. What is the most likely diagnosis?", "choices": ["Fatty liver", "AIH", "Drug induced hepatitis", "Chronic viral hepatitis B", "Alcoholic hepatitis"], "ans": 4, "exp": "ตับโต (span 14 ซม.) + AST 267 > ALT 127 (AST:ALT ≈ 2:1) = alcoholic hepatitis. รูปแบบ AST เด่นกว่า ALT ~2 เท่าเป็นเบาะแสสำคัญของภาวะจากสุรา.", "sys": "XI"}, {"topic": "Nephrology", "q": "A 60-year-old male presents with acute dyspnea. PE: BP 180/110 mmHg, Lung - crepitation, Extremities - pitting edema. ให้ IV Furosemide ไปแล้ว ต้องให้อะไรเพิ่ม?", "choices": ["nitroprusside", "labetalol", "amlodipine", "hydralazine", "nitroglycerine"], "ans": 0, "exp": "Acute pulmonary edema + hypertensive emergency (180/110) → หลัง diuretic ต้องให้ vasodilator ลด afterload/preload อย่างรวดเร็ว. Nitroprusside (ขยายทั้ง artery+vein) ลด afterload ได้ดีในภาวะความดันสูงมาก. *nitroglycerine ก็ใช้ได้ (เน้นลด preload) และมักเลือกใน pulmonary edema เช่นกัน*", "sys": "XIV"}, {"topic": "Endocrinology", "q": "A 70-year-old female presented with alteration of consciousness (ซึม). PE: V/S - BP 120/80 mmHg; Neuro - drowsiness. Elyte: Ca 18. What is the next appropriate management?", "choices": ["NSS + furosemide", "Calcitonin + pamidronate", "NSS + pamidronate", "Calcitonin + furosemide", "Hemodialysis"], "ans": 1, "exp": "Hypercalcemic crisis (Ca 18 + ซึม) ต้องลด Ca เร็ว: calcitonin (ออกฤทธิ์เร็วใน 2-4 ชม.) + bisphosphonate (pamidronate, ฤทธิ์นานแต่ช้า) — จึงเลือก calcitonin + pamidronate. *สำคัญ: ต้องให้ IV isotonic saline hydration ควบคู่เสมอ; furosemide ไม่แนะนำ routine; hemodialysis สงวนไว้กรณีไตวาย/ดื้อการรักษา*", "sys": "IV"}, {"topic": "Nephrology", "q": "A 25 years old man presented with generalized edema for 2 months. PE: BP 110/70 mmHg, puffy eyelids, pitting edema 4+. Labs: UA - Protein 4+, RBC 0-1, WBC 0-1; 24 hrs protein 8 g; Blood chem - Albumin 2, Cholesterol 450, Creatinine 0.8. What is the diagnosis?", "choices": ["IgA nephropathy", "Membranous nephropathy", "Minimal change disease", "Focal segmental", "Membrano-proliferative glomerulonephritis"], "ans": 2, "exp": "Nephrotic syndrome (proteinuria > 3.5 g/วัน [8 g], hypoalbuminemia [2], hyperlipidemia [chol 450], edema) + urine sediment สะอาด (ไม่มี RBC/WBC) ในคนอายุน้อย (25 ปี) = minimal change disease (สาเหตุ nephrotic ที่พบบ่อยในเด็ก/วัยรุ่น, ตอบสนอง steroid ดี). IgA/MPGN มักมี hematuria.", "sys": "XIV"}, {"topic": "Endocrinology", "q": "A 13-year-old girl presented with acanthosis nigricans, no nocturia, no weight loss. BW 70 kg, HT 150 cm, FBS 105, HbA1C 6. What should be done next?", "choices": ["Leptin level", "Insulin level", "C-Peptide Level", "Oral glucose tolerance test", "Anti-GAD"], "ans": 3, "exp": "เด็กอ้วน + acanthosis nigricans (insulin resistance) + FBS 105 (impaired fasting glucose) + HbA1c 6 (prediabetes) — ขั้นถัดไปเพื่อยืนยันเบาหวาน/IGT คือ oral glucose tolerance test (75 g OGTT).", "sys": "IV"}, {"topic": "Endocrinology", "q": "A 70-year-old female, U/D Grave's disease s/p radioactive iodine ablation, presented with hoarseness, slow thinking and weight gain for 3 months. Which parameter is the most sensitive in this patient?", "choices": ["FreeT3", "FreeT4", "Thyroid antibody", "Thyroid anti globin", "TSH"], "ans": 4, "exp": "หลัง RAI ablation มักเกิด hypothyroidism (เสียงแหบ คิดช้า น้ำหนักขึ้น). ใน primary hypothyroidism ค่าที่ไวที่สุด (เปลี่ยนก่อนและมากสุด) คือ TSH (สูงขึ้น).", "sys": "IV"}, {"topic": "Neurology", "q": "A 56-year-old male with U/D tetraplegia (quadriplegia) presents with paroxysmal throbbing headache and intermittent hypertension. PE: V/S - BT 36.5°C, BP 150/100 mmHg, PR 50 bpm, RR 20/min; GA - flushing and sweating. After bed rest for 30 minutes BP 150/100 mmHg. What is the diagnosis?", "choices": ["Autonomic dysreflexia", "Anxiety disorder", "Pheochromocytoma", "Migraine headache", "Essential hypertension"], "ans": 0, "exp": "ผู้ป่วยบาดเจ็บไขสันหลัง (tetraplegia, รอยโรคเหนือ T6) + ปวดหัวเป็นพัก ๆ + ความดันพุ่ง + หน้าแดง/เหงื่อออก + หัวใจเต้นช้า (reflex bradycardia) = autonomic dysreflexia (สิ่งกระตุ้นใต้รอยโรค เช่นปัสสาวะคั่ง → sympathetic surge). *ต้นฉบับไฮไลต์ Migraine ซึ่งไม่อธิบาย HT/flushing/bradycardia*", "sys": "VI"}, {"topic": "Endocrinology", "q": "A 52-year-old woman presented with abdominal discomfort, bloating and flatulence for a month. She had a history of type 2 DM and was on multiple oral hypoglycemic drugs. Which drug can cause this side effect?", "choices": ["Glipizide", "Acarbose", "Metformin", "Pioglitazone", "Sitagliptin"], "ans": 1, "exp": "ท้องอืด/มีลมมาก (bloating, flatulence) เป็นผลข้างเคียงเด่นของ acarbose (alpha-glucosidase inhibitor) เพราะยับยั้งการย่อยแป้ง → น้ำตาลไปหมักที่ลำไส้ใหญ่เกิดแก๊ส.", "sys": "IV"}, {"topic": "Endocrinology", "q": "A female with U/D of Grave's disease on MMI for 6 months visits the hospital for her first ANC. Her LMP was 8 weeks. She is clinically stable with normal TFT. What is the best management?", "choices": ["Discontinue MMI", "Increase dose MMI", "Switch to PTU", "Decrease dose MMI", "Continue MMI ตามเดิม"], "ans": 2, "exp": "ตั้งครรภ์ไตรมาสแรก (LMP 8 สัปดาห์) ที่ใช้ methimazole (MMI) → ควรเปลี่ยนเป็น PTU เพราะ MMI ในไตรมาสแรกเสี่ยง teratogenic (aplasia cutis, choanal/esophageal atresia). (หลังไตรมาสแรกมักเปลี่ยนกลับเป็น MMI เพราะ PTU เสี่ยงตับ)", "sys": "IV"}, {"topic": "Neurology", "q": "A 60 years old male, U/D DMT2, active smoking, on metformin/simvastatin/enalapril, presented with Rt hemiparesis, BP 200/100. CT: hypodense lesion at Lt internal capsule. Lab: FBS 120, LDL 110, Cr 0.8. What is the most appropriate management?", "choices": ["rTPA", "Warfarin", "Nicardipine IV", "change simvastatin to atorvastatin", "Add glipizide"], "ans": 3, "exp": "Ischemic stroke ที่ CT เห็น hypodense lesion แล้ว (= infarct เกิดขึ้นชัด/พ้นหน้าต่าง) → ไม่ให้ rtPA. BP 200/100 ยังไม่เกิน 220/120 จึงไม่ลด (permissive HT). การจัดการที่เหมาะคือ secondary prevention → เปลี่ยนเป็น high-intensity statin (atorvastatin) + antiplatelet + คุมปัจจัยเสี่ยง.", "sys": "VI"}, {"topic": "Endocrinology", "q": "ผู้หญิง 20 ปี shaking hand, palpitation, ก่อนหน้านั้นมีไข้ เจ็บ anterior neck, V/S ปกติ, thyroid enlargement 25g, no bruit, กดไม่เจ็บ. ถาม management", "choices": ["MMI", "Propranolol", "PTU"], "ans": 1, "exp": "ไข้นำมาก่อน + เจ็บบริเวณต่อมไทรอยด์ + thyrotoxicosis (มือสั่น ใจสั่น) = subacute (de Quervain) thyroiditis (หลังติดเชื้อไวรัส). thyrotoxicosis เกิดจากต่อมถูกทำลายปล่อยฮอร์โมนออกมา ไม่ใช่การสร้างเกิน → รักษาตามอาการด้วย propranolol (+ NSAID) ไม่ใช้ยาต้านไทรอยด์ (MMI/PTU).", "sys": "IV"}, {"topic": "Endocrinology", "q": "ผู้ป่วยมี น้ำตาลต่ำ, Na ต่ำ, K สูง, BP ตก (adrenal crisis). ให้อะไร", "choices": ["Hydrocortisone", "Fluticasone"], "ans": 0, "exp": "Hypoglycemia + hyponatremia + hyperkalemia + hypotension = adrenal insufficiency/crisis → ให้ IV hydrocortisone ทันที (glucocorticoid + mineralocorticoid effect). Fluticasone เป็น steroid สูดพ่นเฉพาะที่ ใช้ไม่ได้.", "sys": "IV"}, {"topic": "Endocrinology", "q": "DKA มา load NSS 500 ไม่ให้แลปอะไรมาเลย ถามว่าทำอะไรต่อ", "choices": ["IV+KCl", "NSS ต่อ", "Insulin"], "ans": 1, "exp": "DKA ลำดับการรักษา: IV fluid resuscitation ก่อน (ยังขาดน้ำมาก) และต้องรู้ระดับ K ก่อนเริ่ม insulin (ถ้า K < 3.3 ต้องเติม K ก่อน). เมื่อยังไม่มีผลแลป → ให้ continue NSS resuscitation + ส่งแลปก่อน ยังไม่รีบให้ insulin/KCl แบบไม่รู้ค่า.", "sys": "IV"}, {"topic": "Infectious disease", "q": "A 36-year-old man with chronic alcohol drinking presented with fever, pain and skin lesions (hemorrhagic bullae) for one day PTA. He had signs of chronic liver disease. Recently, he had seafood. PE: V/S - BT 39°C, BP 90/60 mmHg, PR 120 bpm; Abd - palmar erythema, spider nevi, superficial vein dilate. What is the causative pathogen?", "choices": ["Streptococcus pyogenes", "Staphylococcus aureus", "Vibrio vulnificus", "Aeromonas hydrophila", "Clostridium perfringens"], "ans": 2, "exp": "Cirrhosis (spider nevi, palmar erythema) + กินอาหารทะเล + hemorrhagic bullae ลุกลามเร็ว + sepsis = Vibrio vulnificus (พบในผู้ป่วยตับแข็ง/ภูมิคุ้มกันบกพร่องหลังสัมผัสน้ำทะเล/อาหารทะเลดิบ → necrotizing soft tissue infection + septic shock).", "img": "https://cdn.jsdelivr.net/gh/MercenzK/Web-quiz-images@main/NL2-2021-Q55.png", "sys": "I"}, {"topic": "Infectious disease", "q": "A man came to ask about his hepatitis serology profile. His result is HBsAg: negative, anti-HBs: negative, anti-HBc: positive. What is your advice?", "choices": ["HBV vaccine", "Lamivudine", "Anti-HDV", "Reassurance"], "ans": 3, "exp": "Isolated anti-HBc (HBsAg−, anti-HBs−, anti-HBc+) ในประเทศที่ HBV ชุก (ไทย) ส่วนใหญ่หมายถึง resolved/past infection (anti-HBs หายไปตามเวลา) — ถือว่าเคยติดและหายแล้ว จึงให้ reassurance (ไม่ใช่ active infection, ไม่ต้อง lamivudine; anti-HDV ตรวจเฉพาะเมื่อ HBsAg+). *ต้นฉบับไฮไลต์ Anti-HDV ซึ่งไม่ถูกต้อง; บางแนวทางพิจารณาให้ HBV vaccine challenge เพื่อดู immunity*", "sys": "I"}, {"topic": "Infectious disease", "q": "A 19-year-old male who has a history of visiting a national park, presents with fever and malaise. PE: V/S - BT 39°C others are normal; Skin - 8 mm oval lesion with black scale and central crust (eschar) at inguinal area. What is the most likely complication from this condition?", "choices": ["Toxic shock syndrome", "Intravascular sequestration", "Splenic rupture", "Hypoglycemia", "Aseptic meningitis"], "ans": 4, "exp": "ไข้ + eschar (แผลสะเก็ดดำ) หลังเข้าป่า/อุทยาน = scrub typhus (Orientia tsutsugamushi). ภาวะแทรกซ้อนที่พบได้คือ meningoencephalitis (aseptic meningitis) รวมถึง ARDS/AKI/myocarditis. (Intravascular sequestration/hypoglycemia เป็นของ malaria; splenic rupture ของ EBV/typhoid)", "sys": "I"}, {"topic": "Infectious disease", "q": "Melioidosis — ส่ง Investigation อะไรเพื่อ confirm", "choices": ["Hemoculture", "Melioid titer", "HAV IgM"], "ans": 0, "exp": "การวินิจฉัยยืนยัน melioidosis (Burkholderia pseudomallei) มาตรฐานคือ culture (เลือด/หนอง/สารคัดหลั่ง) → hemoculture. Serology (titer) มีความจำเพาะต่ำในพื้นที่ระบาด.", "sys": "I"}, {"topic": "Infectious disease", "q": "A 50-year-old female U/D Type 2 DM presents with fever and abdominal pain for 2 weeks. V/S: BT 40°C. LFT: TB 5, DB 4, AST 120, ALT 140, ALP 400. U/S: Multiple hypoechoic lesions in liver and spleen. ถามเชื้อที่เป็น etiology", "choices": ["Enterobacter", "Burkholderia pseudomallei", "Klebsiella", "Pseudomonas", "TB"], "ans": 1, "exp": "ผู้ป่วยเบาหวานในไทย + ไข้เรื้อรัง + ฝีหลายจุดทั้งใน ตับและม้าม (multiple hepatosplenic microabscesses) = melioidosis (Burkholderia pseudomallei) ซึ่งเป็นลักษณะเฉพาะ. *ต้นฉบับไฮไลต์ Klebsiella ซึ่งมักเป็นฝีตับก้อนเดี่ยว ไม่ค่อยลามไปม้าม*", "sys": "I"}, {"topic": "Infectious disease", "q": "ชาย 26 ปี HIV positive มาด้วยปวดหัว, nausea, ตามัว, stiff neck positive. CT: no space occupying lesion. What is the diagnosis?", "choices": ["Toxoplasmosis", "Bact. meningitis", "Crypto meningitis", "HSV encephalitis", "CMV encephalitis"], "ans": 2, "exp": "HIV + ปวดหัว + คลื่นไส้ + ตามัว (raised ICP) + คอแข็ง + CT ไม่มี mass = cryptococcal meningitis (Cryptococcus neoformans, พบเมื่อ CD4 < 100, ทำให้ ICP สูง). Toxoplasmosis จะเห็น ring-enhancing lesion บน CT (มี SOL) ซึ่งข้อนี้ไม่มี.", "sys": "I"}, {"topic": "Infectious disease", "q": "A 70-year-old patient has been admitted with pneumonia and receives ceftriaxone for 10 days. Later, the patient develops watery diarrhea and fever. V/S: BT 38°C, BP 110/70 mmHg. C. diff toxin: positive. What is the most appropriate management? (ตัวเลือกแต่งขึ้นมาเอง ต้นฉบับไม่มีตัวเลือก)", "choices": ["Oral metronidazole", "Loperamide (antimotility)", "Continue ceftriaxone", "Oral vancomycin", "IV ciprofloxacin"], "ans": 3, "exp": "Antibiotic-associated diarrhea + C. difficile toxin positive = C. difficile infection. รักษา first-line ด้วย oral vancomycin (หรือ fidaxomicin) และหยุด antibiotic ต้นเหตุ (ceftriaxone). metronidazole เป็นทางเลือกรอง; หลีกเลี่ยง antimotility (loperamide) เพราะเสี่ยง toxic megacolon.", "sys": "I"}, {"topic": "Infectious disease", "q": "ผู้ป่วยกินอาหารมา มี clinical เป็น diarrhea แล้วต่อมากลายเป็น HUS (hemolytic uremic syndrome) ถามว่าน่าจะกินอะไรมา", "choices": ["Sushi", "Foie Gras", "Soft boiled egg", "Pork Chop", "Beef burger"], "ans": 4, "exp": "ท้องเสียแล้วตามด้วย HUS (MAHA + thrombocytopenia + AKI) เกิดจาก Shiga toxin-producing E. coli O157:H7 ซึ่งพบใน เนื้อวัวปรุงไม่สุก (hamburger/beef burger). *หลีกเลี่ยง antibiotic/antimotility เพราะเพิ่มการปล่อย toxin*", "sys": "I"}, {"topic": "Infectious disease", "q": "A 15 years old girl presents with a painful genital ulcer. G/S: gram-negative coccobacilli in parallel rows (school of fish). What is the treatment?", "choices": ["Azithromycin", "Cefdinir", "Doxycycline"], "ans": 0, "exp": "แผลอวัยวะเพศที่ เจ็บ + gram-negative coccobacilli เรียงตัวแบบ school of fish = chancroid (Haemophilus ducreyi). รักษาด้วย azithromycin (single dose) หรือ ceftriaxone/ciprofloxacin. (ต่างจาก syphilis ที่แผลไม่เจ็บ)", "sys": "I"}, {"topic": "Infectious disease", "q": "An elderly male, U/D ESRD on regular HD, presents with clinical pneumonia c sepsis. Film: Bilateral opacity infiltration. ถาม causative agents", "choices": ["B.cepacia complex", "P.aeruginosa", "Influenza", "CMV"], "ans": 1, "exp": "ผู้ป่วย ESRD ที่ฟอกเลือดประจำ = กลุ่ม healthcare-associated → pneumonia c sepsis จากเชื้อ gram-negative ที่พบบ่อยคือ Pseudomonas aeruginosa. ควรเลือก empiric ATB ที่คลุม Pseudomonas.", "sys": "I"}, {"topic": "Neurology", "q": "Male 20 ปี present with behavior change with convulsion for 1 day. He has severe headache for 3 days. PE: BT 38.9°C, BP 140/80 mmHg, PR 98/min, Drowsiness, Stiffness of neck positive, No neurodeficit, otherwise unremarkable. LP: Numerous RBC with xanthochromia, WBC 20, protein 80, CSF glucose:plasma glucose ratio = 0.4. Diagnosis?", "choices": ["Rupture aneurysm", "Cryptococcal meningitis", "Herpes encephalitis", "TB meningoencephalitis", "Meningococcal meningitis"], "ans": 2, "exp": "พฤติกรรมเปลี่ยน + ชัก + ไข้ + ปวดหัว + CSF มี RBC/xanthochromia (จาก hemorrhagic necrosis ของ temporal lobe) = herpes simplex encephalitis. ต้องเริ่ม IV acyclovir ทันทีโดยไม่รอผล PCR. (Rupture aneurysm/SAH ไม่มีไข้+behavior change+ชัก)", "sys": "VI"}, {"topic": "Neurology", "q": "A previously healthy 40 YOM present with fever, chill and severe diffuse headache for 3 days. BT 40, PR 120, RR 20, BP 100/70 mmHg, Positive neck stiffness and papilledema, other neurological normal. After blood drawn for investigation, which of the following is appropriate initial management?", "choices": ["LP", "CT brain with contrast", "NSS loading", "IV antibiotic", "IV dexamethasone"], "ans": 3, "exp": "สงสัย bacterial meningitis + มี papilledema (ICP สูง) → ห้าม LP ก่อน (เสี่ยง herniation) ต้อง CT ก่อน LP. แต่ห้ามหน่วงการรักษา — หลังเจาะ hemoculture แล้ว ให้ empiric IV antibiotic (พร้อม/ก่อนหน้าด้วย dexamethasone) ทันที แล้วค่อยทำ CT → LP. *dexamethasone ควรให้ก่อน/พร้อม dose ATB แรก*", "sys": "VI"}, {"topic": "Pediatrics", "q": "A 3 years old patient presented with fever and dysuria. PE: V/S BT 38.9°C, PR 110, RR 30, BP 90/60 mmHg. UA: WBC 30-50, RBC 5-10, nitrite 1+, Epi 1-2. Which of the following is the lab which able to confirm her diagnosis?", "choices": ["E.coli 10^4 from midstream urine", "E.coli 10^3 from urine catheterization", "E.faecalis 10^3 from urine catheterization", "S.saprophyticus 10^3 from urine catheterization", "E.coli 10^1 from suprapubic aspiration"], "ans": 4, "exp": "เกณฑ์ยืนยัน UTI ตามวิธีเก็บปัสสาวะ: suprapubic aspiration = พบเชื้อ uropathogen ปริมาณเท่าใดก็ตามถือว่ามีความหมาย (กระเพาะปัสสาวะปกติปลอดเชื้อ) จึง E.coli จาก SPA = confirm ได้. Midstream ต้อง ≥ 10^5, catheterization ต้อง ≥ 10^4 จึงไม่เข้าเกณฑ์.", "sys": "XIV"}, {"topic": "Infectious disease", "q": "HIV patient with fever, multiple stage vesicles on trunk and extremities, develops dyspnea. PE: lung - fine crepitation. What is the management?", "choices": ["IV acyclovir + steroids", "oral acyclovir"], "ans": 0, "exp": "HIV (immunocompromised) + ตุ่มน้ำหลายระยะกระจายทั้งตัว (disseminated varicella) + ปอดอักเสบ (varicella pneumonia, visceral involvement) → ต้องให้ IV acyclovir (ไม่ใช่ oral) เพราะเป็น disseminated/visceral disease ในคนภูมิคุ้มกันต่ำ.", "sys": "I"}, {"topic": "Cardiology", "q": "Patient has low grade fever, dry cough, weight loss, clear lung sound, normal S1S2, pericardial friction rub. What is the management for this complication (TB pericarditis)?", "choices": ["ASA", "Prednisolone", "ibuprofen"], "ans": 1, "exp": "ภาพเข้าได้กับ TB pericarditis. การให้ adjunctive corticosteroid (prednisolone) ช่วยลดการเกิด constrictive pericarditis ในระยะยาว (ควบคู่กับ anti-TB). NSAID/ASA ใช้ใน viral/idiopathic pericarditis มากกว่า.", "sys": "IX"}, {"topic": "Infectious disease", "q": "Patient with genital ulcer, shallow, painful, Gram stain shows gram negative coccobacilli in school of fish pattern (H. ducreyi). What is proper management?", "choices": ["Cefdinir", "Amoxicillin", "Levofloxacin"], "ans": 2, "exp": "Chancroid (Haemophilus ducreyi). ยาที่ใช้ได้: azithromycin, ceftriaxone, ciprofloxacin/fluoroquinolone, erythromycin. ในตัวเลือกนี้ levofloxacin (fluoroquinolone) ครอบคลุม H. ducreyi. (Amoxicillin ไม่ไว้ใจเพราะเชื้อสร้าง beta-lactamase)", "sys": "I"}, {"topic": "Neurology", "q": "A 40-year-old man was found unconscious in his bedroom. He has a history of complex partial seizure well controlled by phenytoin for 5 years. PE: V/S - BT 37°C, RR 12/min, BP 165/80 mmHg, PR 110 bpm; Neuro - mid gaze pinpoint pupils, absent oculocephalic reflex, frequent extension posture. What is the diagnosis?", "choices": ["thalamic infarction", "medulla hemorrhage", "encephalitis", "pontine hemorrhage", "phenytoin intoxication"], "ans": 3, "exp": "Coma + pinpoint pupils (รูม่านตาเล็กมาก) + absent oculocephalic (doll's eye) + decerebrate/extension posture + mid-position gaze + HT = pontine hemorrhage (คลาสสิก: pinpoint pupils + quadriparesis + coma).", "sys": "VI"}, {"topic": "Neurology", "q": "A 60-year-old female presented with progressive muscle weakness for 2 weeks. She also had a fever and right side headache. U/D: DM, HT, chronic sinusitis. PE: V/S - BT 39°C, PR 100, BP 150/100 mmHg; CNS - drowsy, Lt side hemiparesis with Lt side facial palsy (UMN). What is the most likely diagnosis?", "choices": ["Brain tumor", "Cerebral infarction", "Bacterial meningitis", "Intracerebral hemorrhage", "Brain abscess"], "ans": 4, "exp": "อาการค่อยเป็นค่อยไป (2 สัปดาห์) + ไข้ + ปวดหัว + focal deficit (hemiparesis, facial palsy UMN) + มีแหล่งติดเชื้อ (chronic sinusitis) ในผู้ป่วยเบาหวาน = brain abscess (ลามจาก sinusitis). ยืนยันด้วย CT/MRI with contrast (ring-enhancing lesion).", "sys": "VI"}, {"topic": "Neurology", "q": "A 70-year-old male with U/D HT came to the hospital with an alteration of consciousness 1 hour PTA. He had left motor weakness with dysarthria and headache at 3 hours PTA and for the next 2 hours he developed lethargy and vomiting. PE: BP 160/100 mmHg; Neuro - E3M4V3, pupil 3 mm RTL, Lt.Hemiparesis, Lt BBK positive, stiffness of neck negative. What is the most likely diagnosis?", "choices": ["Intracranial hemorrhage", "Brain abscess", "Cerebral infarction", "Subarachnoid hemorrhage", "Hypertensive encephalopathy"], "ans": 0, "exp": "HT + อ่อนแรงครึ่งซีกเฉียบพลัน + ปวดหัว + ระดับความรู้สึกตัวแย่ลงเร็ว + อาเจียน (raised ICP) = intracerebral (intracranial) hemorrhage. (Ischemic infarct มักไม่ปวดหัว/อาเจียน/ซึมเร็วในช่วงแรกเท่า ICH)", "sys": "VI"}, {"topic": "Neurology", "q": "A 15-year-old girl presented with progressive ascending limb weakness 3 days ago. She had a history of URI symptoms 2 weeks ago. PE: CNS - Generalized weakness, absent DTR, decreased pin-prick sensation at palm and sole. What is the likely diagnosis?", "choices": ["Rhabdomyolysis", "GBS", "MS", "Transverse myelitis", "HypoK periodic paralysis"], "ans": 1, "exp": "อ่อนแรงแบบ ascending + areflexia (absent DTR) + หลังติดเชื้อ (URI 2 สัปดาห์ก่อน) = Guillain-Barré syndrome (GBS). CSF จะพบ albuminocytologic dissociation; เฝ้าระวังการหายใจล้มเหลว. รักษาด้วย IVIG/plasma exchange.", "sys": "VI"}, {"topic": "Neurology", "q": "Female มาด้วย behavioral change 1 day, ทำปากขมุบขมิบ (lip smacking), chewing, fumbling เป็นอยู่ไม่กี่นาที (จำไม่ได้), หลังจากนั้นหมดสติไม่รู้สึกตัว แล้วค่อย ๆ gain conscious ใน 15 นาที. Dx?", "choices": ["Factitious disorder", "Dissociative disorder", "Absence seizure"], "ans": 2, "exp": "มี automatisms (ปากขมุบขมิบ เคี้ยว fumbling) + สับสน/ไม่รู้สึกตัว + postictal (ค่อย ๆ ฟื้นใน 15 นาที) = อาการชักแบบ focal impaired awareness (complex partial) — เป็นอาการชักจริง (organic) ไม่ใช่ psychiatric (dissociative/factitious). *ในตัวเลือกนี้ Absence seizure เป็นตัวเลือกชักที่ใกล้สุด แม้ทางคลินิกจะเป็น complex partial มากกว่า*", "sys": "VI"}, {"topic": "Neurology", "q": "A 50-year-old female patient U/D DM type2 (diagnosed 2 years) presented with bilateral hand numbness for 6 months with normal feeling in both feet. PE: bilateral thenar muscle atrophy, decreased pinprick sensation thumb to middle finger. Both feet are normal. Dx?", "choices": ["C-spondylosis", "Diabetic distal symmetric polyneuropathy", "Vit. B12 deficiency", "carpal tunnel syndrome"], "ans": 3, "exp": "ชาสองมือในแนว median nerve (นิ้วโป้งถึงนิ้วกลาง) + thenar atrophy + เท้าปกติ = carpal tunnel syndrome (median nerve entrapment) ทั้งสองข้าง. ต่างจาก diabetic polyneuropathy ที่จะเริ่มที่เท้าแบบ stocking ก่อน.", "sys": "VI"}, {"topic": "Neurology", "q": "A 65-year-old man presents with a progressive weakness for 8 hours. PE: V/S - BP 160/100; CNS - Lt hemiparesis grade III spastic dysarthria, no aphasia. CT brain non CM: internal capsule infarction. What is the cause?", "choices": ["Large vessel", "Thrombosis", "Vessel to vessel emboli", "Cardiac to vessel emboli", "Small vessel"], "ans": 4, "exp": "Lacunar infarct ที่ internal capsule + pure motor hemiparesis + ไม่มี cortical sign (no aphasia) + HT = small vessel disease (lipohyalinosis ของหลอดเลือดเล็ก).", "sys": "VI"}, {"topic": "Neurology", "q": "Thai female 30 year old has recurrent right side troubling headache 3 mo with intense severity and progressive worsening with N/V last 6 hr, it happens before menstruation cycle. What is the Dx?", "choices": ["Migraine headache", "Brain tumor", "Tension type headache", "Trigeminal neuralgia", "Arteriovenous malformation"], "ans": 0, "exp": "ปวดหัวข้างเดียวเป็นซ้ำ ๆ + คลื่นไส้อาเจียน + สัมพันธ์กับรอบเดือน (menstrual/catamenial migraine) = migraine headache. *ต้นฉบับไฮไลต์ Trigeminal neuralgia ซึ่งเป็นปวดแปลบสั้น ๆ ที่ใบหน้า ไม่ใช่ปวดหัวตุบ ๆ พร้อมคลื่นไส้*", "sys": "VI"}, {"topic": "Neurology", "q": "A 65-year-old active smoker presents with weakness for 8 hours. His right-sided suddenly weak accompanying slur speech. V/S: BP 160/90, PR 88 (regular), RR 16, normal heart examination. Spastic dysarthria, no aphasia, Rt. hemiparesis grade III both UE and LE, normal sensation. EKG: normal sinus rhythm. CT: hypodense lesion at Lt.internal capsule. What is the most likely cause of the mechanism?", "choices": ["Cardiac to vessel embolism", "Small vessels thrombosis", "Large arterial thrombosis", "Vessel to vessel embolism", "Thrombophilia"], "ans": 1, "exp": "Pure motor hemiparesis (แขนขาข้างเดียวเท่ากัน) + ไม่มี cortical sign (no aphasia, sensation ปกติ) + lacune ที่ internal capsule + จังหวะหัวใจปกติ (ไม่มี AF) = lacunar stroke จาก small vessel disease (small vessels thrombosis / lipohyalinosis).", "sys": "VI"}, {"topic": "Neurology", "q": "A 20 years old man came with an alteration of consciousness. He had high grade fever with myalgia yesterday. V/S: BT 39°C, PR 100 bpm, BP 90/60 mmHg. CNS: Drowsiness, Pupils 2 mm RTLBE, Motor power at least gr.IV all extremities. Skin: Petechial rash on both legs. CBC: Hb 14, Platelets 150,000, WBC 20,000 (N80 L8 M2). CSF: RBC 1-2, WBC 120 (PMN90%), Protein 50, Sugar 20 (serum 90). CSF g/s: gram negative coccobacilli. Which is appropriate management?", "choices": ["Penicillin G", "Metronidazole", "Meropenem", "Erythromycin", "Piperacillin and tazobactam"], "ans": 2, "exp": "Bacterial meningitis (CSF PMN เด่น, glucose ต่ำ ratio ~0.22, protein สูง) + gram-negative coccobacilli → ในตัวเลือกนี้ meropenem คลุมเชื้อ gram-negative และผ่าน CSF ได้ดี (penicillin G ไม่ครอบคลุมเชื้อที่สร้าง beta-lactamase). *มาตรฐาน empiric จริงคือ ceftriaxone ± vancomycin ซึ่งไม่มีในตัวเลือก; ถ้าเป็น meningococcus จาก petechiae จะใช้ penicillin G ได้*", "sys": "VI"}, {"topic": "Neurology", "q": "A 30-year-old man weakness 30 min PTA. His symptom occurs 2 hr after finishing playing football. He had also experienced symptoms like this before last 6 month and the symptom was resolved spontaneously. PE: anterior deltoid and iliopsoas grade 3, intact sensory, DTR 2+ all. Electrolyte: Na 137, K 2.3, Cl 105, HCO3 24. What is the prevention?", "choices": ["Regularly exercise", "Avoid high-lipid food", "Take high potassium diet", "Avoid high-carbohydrate food", "Take potassium"], "ans": 3, "exp": "อ่อนแรงกล้ามเนื้อต้นแขน/ขาเป็นพัก ๆ หลังออกกำลัง + K ต่ำมาก (2.3) + หายเอง = hypokalemic periodic paralysis (มักเป็น thyrotoxic PP ในชายเอเชีย). ถูกกระตุ้นด้วยอาหารคาร์บสูงและการพักหลังออกกำลัง → ป้องกันด้วยการหลีกเลี่ยงอาหารคาร์โบไฮเดรตสูง (และรักษา hyperthyroid ถ้ามี). ระดับ K รวมในตัวปกติ การกิน K ไม่ป้องกัน", "sys": "VI"}, {"topic": "Neurology", "q": "Case female 25 yr, GA 8 wk, Hx GTC seizure 1 mo, เคยใช้ยา carbamazepine แล้ว MP rash ขึ้น. มีอาการชักอีกครั้ง 1 wk PTA. ถามว่าต่อไปจะให้ยากันชักอะไร", "choices": ["Phenytoin", "Phenobarbital", "Valproate", "Topiramate", "Levetiracetam"], "ans": 4, "exp": "หญิงตั้งครรภ์ที่ต้องใช้ยากันชัก + แพ้ carbamazepine (MP rash) → เลือก levetiracetam (หรือ lamotrigine) เพราะเสี่ยง teratogenic ต่ำที่สุด. หลีกเลี่ยง valproate (teratogenic สูงสุด), phenytoin/phenobarbital/topiramate (เสี่ยงเช่นกัน).", "sys": "VI"}, {"topic": "Infectious disease", "q": "A 24 years old female presented with a headache and blurred vision intermittently for 2 weeks. U/D: HIV with poor medication. What is diagnosis?", "choices": ["Cryptococcal meningitis", "Bacterial meningitis", "Toxoplasmosis", "Herpes encephalitis", "CMV Encephalitis"], "ans": 0, "exp": "HIV ที่กินยาไม่สม่ำเสมอ + ปวดหัว + ตามัวเป็นพัก ๆ (raised ICP) 2 สัปดาห์ = cryptococcal meningitis (Cryptococcus neoformans ทำให้ ICP สูง). วินิจฉัยด้วย serum/CSF cryptococcal antigen + LP วัด opening pressure.", "sys": "I"}, {"topic": "Neurology", "q": "ชายหนุ่ม 20 ปี มาด้วย behavioral change 1 วัน, ก่อนหน้านั้นสามวัน มีประวัติปวดหัวมากเหมือนจะระเบิด, ตรวจร่างกายมี stiff neck ไม่มี neuro deficit, เจาะ LP ไปเจอ numerous RBC, xanthochromia, Protein 80, glucose ratio 0.5. ถาม diagnosis", "choices": ["Cryptococcal meningitis", "Subarachnoid hemorrhage", "TB meningitis", "Bacterial meningitis"], "ans": 1, "exp": "ปวดหัวรุนแรงเฉียบพลันเหมือนจะระเบิด (thunderclap headache) + คอแข็ง + CSF มี RBC จำนวนมาก + xanthochromia + glucose ปกติ (ratio 0.5) = subarachnoid hemorrhage (SAH). ยืนยัน/หาสาเหตุด้วย CT/CT angiography (aneurysm).", "sys": "VI"}, {"topic": "Neurology", "q": "Pt. with U/D hypertension presented with Rt.side weakness, BBK+ve at Rt., Rt.motor gr.3 แขนเท่ากับขา. CT: hypodensity lesion at Lt.internal capsule. What is the etiology of this condition?", "choices": ["Cardioembolic", "vessel to vessel", "small vessel thrombosis", "large vessel thrombosis"], "ans": 2, "exp": "Pure motor hemiparesis (แขน = ขา) + lacune ที่ internal capsule + HT = lacunar stroke จาก small vessel thrombosis (lipohyalinosis).", "sys": "VI"}, {"topic": "Dermatology", "q": "ผู้หญิง 25 ปี มีผื่นขึ้น itchy rash มา 2 วัน แขนทั้งสองข้างที่ flexor area. ถามจะให้ยาอะไร", "choices": ["Ranitidine", "Omalizumab", "Prednisolone", "Cetirizine", "Azathioprine"], "ans": 3, "exp": "ผื่นคันเฉียบพลันบริเวณข้อพับ (eczema/urticaria) → รักษาอาการคันด้วย antihistamine เช่น cetirizine (2nd gen). (Ranitidine เป็น H2-blocker; omalizumab/azathioprine/steroid ใช้ในรายรุนแรง/เรื้อรัง)", "sys": "XII"}, {"topic": "Dermatology", "q": "A 55-year-old female presented with itchy rashes on both legs for 4 months. PE: symmetrical ill defined lichenification at both medial sides of ankles with multiple varicose veins. What is the most appropriate management?", "choices": ["Oral steroid", "Clotrimazole cream", "ไม่ใช้รองเท้าที่ทำจากหนังหรือพลาสติก", "Emollient", "Low potency topical steroid"], "ans": 4, "exp": "Lichenification ที่ข้อเท้าด้านในทั้งสองข้าง + เส้นเลือดขอด (varicose veins) = stasis dermatitis (venous eczema). รักษาการอักเสบด้วย topical corticosteroid + emollient + compression/ยกขา. *ต้นฉบับไฮไลต์ 'ไม่ใส่รองเท้าหนัง/พลาสติก' ซึ่งเป็นของ contact dermatitis ไม่ตรงกับ stasis dermatitis*", "sys": "XII"}, {"topic": "Ophthalmology", "q": "ผู้หญิงมี left upper lid mass, size 4 mm, no growth, well demarcated. Mx?", "choices": ["Excisional biopsy", "Incisional and curettage", "Incisional biopsy", "Steroid injection"], "ans": 0, "exp": "ก้อนที่เปลือกตาขนาดเล็ก (4 มม.) ขอบชัด ไม่โต (benign) → excisional biopsy (ตัดออกทั้งก้อน) เพื่อทั้งรักษาและส่งพยาธิ. (ถ้าเป็น chalazion อาจ incision & curettage หรือ steroid injection)", "sys": "VII"}, {"topic": "Dermatology", "q": "A 40 years old farmer presents with non pruritic lesion at thumb 4 months, lesion described by picture (multiple black dots at thumb tip). What is the cause of this lesion?", "choices": ["Latex glove", "HPV infection", "Chronic friction at effect side", "Frequently washing hand", "Contact pesticide"], "ans": 1, "exp": "รอยโรคที่นิ้วโป้ง ผิวขรุขระ มีจุดดำหลายจุด (thrombosed capillaries) = verruca vulgaris (common wart) ซึ่งเกิดจาก HPV infection.", "img": "https://cdn.jsdelivr.net/gh/MercenzK/Web-quiz-images@main/NL2-2021-Q88.png", "sys": "XII"}, {"topic": "Dermatology", "q": "A 20 years old female (pregnancy) presents with non-pruritic lesion at face for 1 month. Lesion: multiple inflammation, multistage of papule, macule, nodule (acne). What is the most appropriate treatment?", "choices": ["Topical isotretinoin", "Topical adapalene", "Topical azelaic acid", "Topical steroid", "Oral isotretinoin"], "ans": 2, "exp": "Acne ในหญิงตั้งครรภ์ → ห้ามใช้ retinoid ทั้ง oral และ topical (isotretinoin/adapalene เป็น teratogen). ยาที่ปลอดภัยในการตั้งครรภ์คือ topical azelaic acid (หรือ topical erythromycin/benzoyl peroxide). *ต้นฉบับไฮไลต์ Oral isotretinoin ซึ่งเป็นข้อห้ามเด็ดขาดในหญิงตั้งครรภ์*", "sys": "XII"}, {"topic": "Rheumatology", "q": "A female had symptoms of calcinosis, Raynaud phenomenon, sclerodactyly, telangiectasia. What is the diagnosis?", "choices": ["Pulmonary fibrosis", "Systemic sclerosis", "Dermatomyositis", "CREST syndrome"], "ans": 3, "exp": "Calcinosis + Raynaud + Sclerodactyly + Telangiectasia = CREST syndrome (limited cutaneous systemic sclerosis; C-R-E-S-T = Calcinosis, Raynaud, Esophageal dysmotility, Sclerodactyly, Telangiectasia). สัมพันธ์กับ anti-centromere antibody.", "sys": "XIII"}, {"topic": "Rheumatology", "q": "A 25 years old female presents with fever and joint pain for 2 months. PE: BT 38.5°C, BP 130/80, PR 96, RR 20; Skin - erythematous rash both cheeks sparing nasolabial fold; MSK - warm tender swelling both knees and wrists. CBC: HCT normal, WBC 3,600 (N80 L20), PLT 180,000. PBS: microspherocyte 1+ polychromasia 2+. What is the most likely diagnosis?", "choices": ["Evan's syndrome", "Rheumatoid arthritis", "Acute rheumatic fever", "Mixed connective tissue", "SLE"], "ans": 4, "exp": "malar rash เว้น nasolabial fold + arthritis (เข่า/ข้อมือ) + leukopenia (WBC 3,600) + hemolysis (spherocyte/polychromasia) + ไข้ ในหญิงสาว = SLE (เข้าหลายเกณฑ์: mucocutaneous + arthritis + hematologic). ตรวจ ANA/anti-dsDNA ยืนยัน.", "sys": "XIII"}, {"topic": "Rheumatology", "q": "ปวดเข่า 6 เดือน กิน NSAIDs ดีขึ้น, รอบนี้เจ็บเข่า 2 วัน บวมแดงร้อน เจาะน้ำในข้อ เจอ crystal รูป rhomboid shape. ส่งอะไร (investigation)", "choices": ["Serum Ca, PO4", "ANA", "Anti-CCP", "ASO titer", "Serum uric"], "ans": 0, "exp": "ผลึกรูป rhomboid (positive birefringence) = calcium pyrophosphate (CPPD/pseudogout). CPPD สัมพันธ์กับโรคเมตาบอลิก โดยเฉพาะ hyperparathyroidism → ควรส่ง serum Ca, PO4 (และ Mg/ferritin) หาสาเหตุ. (Serum uric ใช้กับ gout ที่ผลึกรูปเข็ม negative birefringence)", "sys": "XIII"}, {"topic": "Rheumatology", "q": "A 64-year-old female presents with both hand pain and hand movement difficulty in the early morning for 3 months. PE: swelling and tenderness at both wrists and MCP joint. X-ray: soft tissue swelling both hands, periarticular osteopenia at MCP joint, erosion of ulnar styloid, mild intercarpal space narrowing. What is the diagnosis?", "choices": ["Gouty arthritis", "Rheumatoid arthritis", "Psoriatic arthritis", "CPPD arthropathy", "Erosive osteoarthritis"], "ans": 1, "exp": "ปวดข้อเล็กสองข้างแบบสมมาตร (MCP, wrist) + ข้อฝืดตอนเช้านาน + X-ray มี periarticular osteopenia + marginal erosion (ulnar styloid) = rheumatoid arthritis. ตรวจ RF/anti-CCP ยืนยัน.", "sys": "XIII"}, {"topic": "Rheumatology", "q": "Pt age 70 yrs U/D HTN, ให้ clinical setting of SLE มา. ถามว่า which anti-hypertensive drug ที่ผู้ป่วยกินมาตลอด (ทำให้เกิด drug-induced lupus)", "choices": ["Amlodipine", "Enalapril", "Hydralazine", "HCTZ"], "ans": 2, "exp": "Drug-induced lupus ที่พบบ่อยเกิดจาก hydralazine (และ procainamide, isoniazid) — มี anti-histone antibody, มัก spares ไต/CNS และหายเมื่อหยุดยา.", "sys": "XIII"}, {"topic": "Rheumatology", "q": "A 58 years old man U/D CKD stage 3 presents with intermittent arthralgia for 2 days. His symptoms began after activity and lasted for 4-5 days. His symptoms affect both the ankle and knee but only 1-2 joints were affected during each episode. Synovial fluid reveals a negative birefringent crystal. What is proper management?", "choices": ["Tramadol", "Ibuprofen", "Colchicine", "Prednisolone"], "ans": 3, "exp": "Acute gout (ผลึก negative birefringent = monosodium urate) ในผู้ป่วย CKD stage 3 → NSAIDs (ibuprofen) ควรหลีกเลี่ยง (ทำไตแย่), colchicine ต้องปรับขนาด/ระวังใน CKD → เลือก corticosteroid (prednisolone) ซึ่งปลอดภัยกว่าในผู้ป่วยไต.", "sys": "XIII"}, {"topic": "Surgery", "q": "A man presented with fever and perianal mass with fluctuation and redness. What is management?", "choices": ["Warm sitz bath", "ATB", "I&D", "lateral internal sphincterotomy"], "ans": 2, "exp": "ก้อนรอบทวารหนักที่มี fluctuation + แดง + ไข้ = perianal abscess → รักษาด้วย incision and drainage (I&D). Antibiotic เป็นตัวเสริมในรายที่มี cellulitis/ภูมิคุ้มกันต่ำ/เบาหวาน แต่หลักคือระบายหนอง.", "sys": "II"}, {"topic": "Surgery", "q": "A 35-year-old man presented with whooshing sounds in his right ear with headache and diplopia for 1 day. He had a past history of a high-speed motorcycle accident and had a frontal skull fracture with mild TBI which he had just discharged from hospitalization 10 days ago. PE: bilateral conjunctival injection, Rt. eye proptosis and pulsatile exophthalmos. What is the most likely diagnosis?", "choices": ["carotid-cavernous fistula", "cavernous sinus thrombosis", "retrobulbar hemorrhage"], "ans": 0, "exp": "หลังบาดเจ็บศีรษะ + เสียงฟู่ในหู (bruit) + pulsatile exophthalmos (ตาโปนเต้นตามชีพจร) + conjunctival injection = carotid-cavernous fistula (การเชื่อมต่อผิดปกติระหว่าง carotid กับ cavernous sinus). *ต้นฉบับไฮไลต์ retrobulbar hemorrhage ซึ่งเกิดเฉียบพลันหลังบาดเจ็บและไม่ pulsatile/ไม่มี bruit*", "sys": "VI"}, {"topic": "Surgery", "q": "An 85-year-old man presented with aspiration and voice changing while eating and drinking. The symptoms worsened when drinking than eating solid food. His underlying disease is dementia. What is the most likely diagnosis?", "choices": ["Achalasia", "Oropharyngeal dysphagia", "Diffuse esophageal spasm", "Esophageal cancer", "GERD"], "ans": 1, "exp": "สำลัก + เสียงเปลี่ยนขณะกลืน + แย่กับของเหลวมากกว่าของแข็ง + ผู้สูงอายุที่มีภาวะสมองเสื่อม (สาเหตุทางประสาท) = oropharyngeal dysphagia (transfer dysphagia). ต่างจากโรคหลอดอาหาร (achalasia/CA) ที่มักกลืนของแข็งลำบากกว่า", "sys": "II"}, {"topic": "Surgery", "q": "A 63-year-old man presents with an acute urinary retention. He previously had lower urinary tract symptoms for 1 year. A yellowish urine of 600 ml was obtained by urine catheterization. DRE: prostate gland enlarge, no nodule. What is the most proper initial investigation?", "choices": ["UA, PSA", "Ultrasonography", "BUN, Cr", "Cystoscope", "Retrograde urethrogram"], "ans": 2, "exp": "BPH + acute urinary retention (ปัสสาวะ 600 มล.) — การตรวจเบื้องต้นที่สำคัญคือประเมิน renal function (BUN, Cr) เพราะการอุดกั้นอาจทำให้เกิด post-obstructive/post-renal AKI. (PSA ไม่ควรเจาะช่วงเพิ่งคาสาย/มี retention เพราะสูงลวง)", "sys": "XIV"}, {"topic": "Surgery", "q": "A 30-year-old male presents with right groin mass and nausea vomiting for 8 hours after lifting a heavy box. PE: V/S - BT 38, BP 130/90; Abdomen - right groin mass swelling, marked tenderness. What is the most appropriate management?", "choices": ["Ultrasound", "CT", "Manual reduction", "Groin exploration", "I&D"], "ans": 3, "exp": "ก้อนที่ขาหนีบหลังยกของหนัก + N/V + กดเจ็บมาก + ไข้ = strangulated inguinal hernia (ลำไส้ขาดเลือด) เป็นภาวะฉุกเฉิน → surgical groin exploration ทันที. ห้าม manual reduction (เสี่ยงดันลำไส้ที่ตายกลับเข้าช่องท้อง).", "sys": "II"}, {"topic": "Surgery", "q": "A 6-year-old boy visits an emergency room unconsciously with a well demarcated second degree burn from abdomen to both feet, sparing popliteal fossae and skin creases. What is the appropriate investigation for diagnosis?", "choices": ["MRI for musculoskeletal trauma", "CT scan for intracranial hemorrhage", "Bun, Cr, CPK, electrolyte", "Ophthalmoscope for retinal hemorrhage", "Plain film for fracture of extremities"], "ans": 4, "exp": "แผลไฟลวกขอบชัด เว้นข้อพับ/รอยย่น (immersion/stocking-glove pattern) = สงสัย non-accidental injury (child abuse). การตรวจสำคัญคือ skeletal survey (plain film หา fracture เก่า/ซ่อนเร้นหลายตำแหน่ง).", "sys": "IV"}, {"topic": "Pediatrics", "q": "An otherwise healthy 1 month child presents with sudden greenish vomiting for 6 hours. He has occasional crying with mild abdominal distension. PE: V/S - BT 37.4°C, BP 60/40, PR 160/min, RR 50/min; HEENT - dry lips; Abdomen - mild distension, hyperactive bowel sounds, no tenderness or guarding, no mass, bloody mucous stool on per rectal examination. Plain abdominal x-ray: distended stomach, without air in bowel. What is the most likely diagnosis?", "choices": ["Midgut volvulus", "Hypertrophic pyloric stenosis", "Duodenal atresia", "Jejunal atresia", "Intussusception"], "ans": 0, "exp": "ทารก + อาเจียนสีเขียว (bilious) เฉียบพลัน + ถ่ายมูกเลือด (bowel ischemia) + x-ray ท้องไม่มีลม (gasless) = midgut volvulus จาก malrotation (ภาวะฉุกเฉินทางศัลยกรรม). Bilious vomiting ในทารกต้องนึกถึง malrotation/volvulus จนกว่าจะพิสูจน์เป็นอื่น", "sys": "XVII"}, {"topic": "Pediatrics", "q": "A 2 month old boy presented with progressive non bilious vomiting after breastfeeding for 2 wk. He was born at term with BW 3000 g. PE: V/S - BT 37°C, PR 140 bpm, RR 40, Weight 2900 g; GA - lethargy; HEENT - sunken eyeballs; Abdomen - movable olive mass at epigastrium. What is the most proper investigation?", "choices": ["Plain film abdomen", "U/S abdomen", "Barium swallowing", "CT abdomen", "EGD"], "ans": 1, "exp": "อาเจียนพุ่งไม่มีน้ำดี (non-bilious) + คลำได้ olive mass ที่ลิ้นปี่ + ขาดน้ำ/น้ำหนักลด = hypertrophic pyloric stenosis. ตรวจยืนยันด้วย ultrasound abdomen (วัดความหนา/ยาวของ pyloric muscle).", "sys": "II"}, {"topic": "Surgery", "q": "ผู้ป่วยชาย acute sharp epigastric pain, can't maintain upright position, V/S ดี, PE: board-like rigidity (สงสัย perforate). What is the most proper investigation?", "choices": ["Serum amylase", "CT abdomen", "Acute abdomen series", "CTA"], "ans": 2, "exp": "ปวดท้องเฉียบพลันรุนแรง + board-like rigidity (peritonitis) = สงสัย perforated viscus (perforated peptic ulcer). ตรวจเบื้องต้นด้วย acute abdomen series (upright film) เพื่อดู free air ใต้กระบังลม.", "sys": "XI"}, {"topic": "Orthopedics", "q": "Male U/D BPH s/p TURP มาด้วย Right foot drop 1 day. PE: Rt. Foot cannot dorsiflex, loss sensation at dorsal and lateral malleolus of Rt. Foot, tibialis anterior/peroneal muscle weakness. Diagnosis?", "choices": ["L5-S1 nerve root injury", "Tibial nerve injury", "Sciatic nerve injury", "Peroneal nerve injury", "Sural nerve injury"], "ans": 3, "exp": "Foot drop (dorsiflex ไม่ได้) + eversion อ่อนแรง + ชาหลังเท้า/malleolus ด้านนอก + อ่อนแรง tibialis anterior/peroneal = common peroneal (fibular) nerve injury (มักจากท่าขาช่วงผ่าตัด/การกดทับที่ fibular head).", "sys": "XIII"}, {"topic": "Pediatrics", "q": "Term 38 wk, excessive saliva after birth, hx of polyhydramnios, insert OG tube cannot pass into stomach. Film chest include abdomen: curling of OG tube at neck level, normal bowel gas pattern. Diagnosis?", "choices": ["esophageal atresia", "esophageal web", "duodenal atresia", "HPS"], "ans": 0, "exp": "น้ำลายมากตั้งแต่แรกเกิด + ประวัติ polyhydramnios + ใส่ OG tube ไม่ลงกระเพาะ (ขดที่คอ) + มีลมในลำไส้ปกติ = esophageal atresia with tracheoesophageal fistula (type C — มีลมในลำไส้จาก fistula).", "sys": "XVII"}, {"topic": "Neurology", "q": "ผช 70 ปี u/d HT มาด้วย Weak Lt side แขน พูดไม่ชัด, ก่อนหน้านี้ 2 ชม.มีปวดหัวหนักมาก หลังจากนั้น 3 ชม.มีอ้วก, BP 160/110. What is the most likely diagnosis?", "choices": ["Intracerebral hemorrhage", "Subdural hemorrhage", "Hypertension encephalopathy", "Subarachnoid hemorrhage"], "ans": 0, "exp": "HT + อ่อนแรงครึ่งซีก + พูดไม่ชัด + ปวดหัวรุนแรง + อาเจียน (raised ICP) + BP สูง = intracerebral hemorrhage (hypertensive ICH, มักที่ basal ganglia/internal capsule).", "sys": "VI"}, {"topic": "Surgery", "q": "Hx of head trauma มาด้วย ปวดหัว, bilateral proptosis, ฟังได้ orbital bruits. Diagnosis? (ตัวเลือกแต่งขึ้นมาเอง ต้นฉบับไม่มีตัวเลือก)", "choices": ["Cavernous sinus thrombosis", "Carotid-cavernous fistula", "Retrobulbar hemorrhage", "Orbital cellulitis"], "ans": 1, "exp": "หลังบาดเจ็บศีรษะ + ตาโปนสองข้าง + ได้ยิน orbital bruit = carotid-cavernous fistula (การเชื่อมต่อผิดปกติของ carotid กับ cavernous sinus ทำให้เลือดแดงไหลย้อนเข้า orbital veins).", "sys": "VII"}, {"topic": "Surgery", "q": "ชายอายุ 55 ปี ปัสสาวะไม่ออก 8 ชั่วโมง มีไข้ ฉี่แสบขัด ปวด perineum. PE: V/S - BT 39°C, PR 110 bpm, BP 140/100; Abdomen - suprapubic mass; PR - prostate enlargement and tenderness. Diagnosis?", "choices": ["Benign prostate hyperplasia", "Gonococcal Urethritis", "Acute prostatitis", "Prostate cancer", "Bladder cancer"], "ans": 2, "exp": "ไข้ + ปัสสาวะแสบขัด + ปวด perineum + ต่อมลูกหมากโต กดเจ็บ (tender) + ปัสสาวะไม่ออก = acute (bacterial) prostatitis. ต่อมลูกหมากที่กดเจ็บ + ไข้เป็นเบาะแสสำคัญ (ระวังการคลึงต่อมแรง ๆ เสี่ยง bacteremia).", "sys": "II"}, {"topic": "Surgery", "q": "A 14 years old boy presents with acute left scrotal pain described as abrupt and severe pain while playing sports. PE: BT 37.6°C, Lt. Scrotal swelling redness tenderness. UA: normal. What is appropriate management?", "choices": ["NSAIDs", "Antibiotic", "Color doppler ultrasound", "Surgical exploration", "Hernioplasty"], "ans": 3, "exp": "ปวดถุงอัณฑะเฉียบพลันรุนแรงในเด็กชายวัยรุ่นขณะออกกำลัง + บวมแดง + UA ปกติ = testicular torsion (ภาวะฉุกเฉิน ต้องคลายภายใน ~6 ชม.). เมื่อสงสัยชัดควร surgical exploration ทันที (detorsion + orchiopexy) โดยไม่รอ imaging", "sys": "I"}, {"topic": "Surgery", "q": "ชายหนุ่ม ตกจากเสาไฟฟ้า คนเห็นเหตุการณ์ให้ประวัติว่าสลบไป 2 นาที หลังจากนั้นตื่นดีพูดคุยรู้เรื่อง พอ EMS มาถึงยัง alert อยู่ แต่ต่อมาเริ่ม stupor (lucid interval). Diagnosis?", "choices": ["Subdural hematoma", "Epidural hematoma", "Post Concussion"], "ans": 1, "exp": "บาดเจ็บศีรษะ + สลบสั้น ๆ → ตื่นดี (lucid interval) → แล้วซึมลง = epidural hematoma (เลือดออกจาก middle meningeal artery, ภาพ CT รูปเลนส์ biconvex). ต้องผ่าตัดระบายเลือดด่วน", "sys": "VI"}, {"topic": "Surgery", "q": "มาด้วยริดสีดวงที่ก้น มีสามก้อนอยู่ทางด้าน left lateral, right anterior, right posterior, ดันกลับไม่เข้า. ถามทำอย่างไร", "choices": ["Hemorrhoidectomy", "Warm sitz bath", "Daflon", "Rubber band ligation"], "ans": 0, "exp": "ริดสีดวงทวารหลายก้อน (ครบทั้ง 3 ตำแหน่งหลัก) ที่ดันกลับไม่เข้า (irreducible, grade IV) → รักษาด้วย hemorrhoidectomy. Rubber band ligation เหมาะกับ grade I-III ก้อนเดี่ยว; sitz bath/Daflon เป็นการรักษาประคับประคอง", "sys": "XI"}, {"topic": "Surgery", "q": "หญิงตั้งครรภ์ (จำอายุครรภ์ไม่ได้) มาด้วยปวดท้องฝั่งขวา มีคลื่นไส้ อาเจียนหลายรอบ ตรวจร่างกายปวดฝั่งขวาจริง ดันมดลูกไปทางฝั่งขวาแล้วเจ็บมากขึ้น. Diagnosis?", "choices": ["Ureteric stone", "Acute appendicitis", "Acute cholecystitis"], "ans": 1, "exp": "หญิงตั้งครรภ์ + ปวดท้องขวา + N/V + กดเจ็บขวา + ดันมดลูกไปขวาแล้วเจ็บมากขึ้น (uterine displacement sign) = acute appendicitis (เป็น non-obstetric surgical emergency ที่พบบ่อยสุดในหญิงตั้งครรภ์; ไส้ติ่งถูกดันสูงขึ้นตามมดลูก).", "sys": "XV"}, {"topic": "Surgery", "q": "ผู้ป่วยมาด้วยไข้ ปวดขา 6 วัน โดย 7 วันก่อนโดนไม้แทงขา ทำแผลเองที่บ้าน. PE: laceration wound with greenish discharge with bleb around lesion. ถาม management", "choices": ["I&D", "wound dressing", "debridement c fasciotomy"], "ans": 2, "exp": "แผลหลังถูกแทง + หนองเขียว + bleb (bullae) รอบแผล + ไข้ + ปวดมาก = necrotizing soft tissue infection (necrotizing fasciitis) → ต้อง surgical debridement + fasciotomy ด่วน (ร่วม broad-spectrum ATB). แค่ I&D/wound dressing ไม่พอ", "sys": "XVIII"}, {"topic": "Surgery", "q": "Prostate คลำได้ nodule, PSA = 4.5. ทำอย่างไร (ไม่มีตัวเลือก MRI)", "choices": ["F/U 1mo", "TURP", "TRUS biopsy"], "ans": 2, "exp": "คลำต่อมลูกหมากได้ nodule (DRE ผิดปกติ) + PSA สูงเล็กน้อย (4.5) → สงสัยมะเร็งต่อมลูกหมาก ต้องทำ TRUS-guided biopsy (การมี nodule เป็นข้อบ่งชี้ biopsy ไม่ว่า PSA เท่าใด). *ต้นฉบับไฮไลต์ F/U 1 เดือน ซึ่งไม่เหมาะเมื่อคลำได้ nodule*", "sys": "XIV"}, {"topic": "Orthopedics", "q": "ทำ TURP มาแล้ว foot drop ถามว่าเป็นที่ nerve ไหน", "choices": ["Peroneal", "L5-S1 Root", "Tibial"], "ans": 0, "exp": "Foot drop หลังผ่าตัดในท่า lithotomy = common peroneal (fibular) nerve palsy (ถูกกดที่บริเวณ fibular head). อาการ: dorsiflex ไม่ได้ + ชาหลังเท้า", "sys": "XIII"}, {"topic": "Infectious disease", "q": "กินอาหารทะเลมา มี hemorrhagic bleb คลำได้ crepitation. ถามเชื้อ (ต้นฉบับตัวเลือกไม่ครบ — ใส่เท่าที่มี)", "choices": ["vibrio vulnificus", "clostridium perfringen"], "ans": 0, "exp": "กินอาหารทะเล + hemorrhagic bulla + soft tissue infection = Vibrio vulnificus (พบในผู้ป่วยตับแข็ง/ภูมิคุ้มกันต่ำ ทำให้เกิด hemorrhagic bullae + necrotizing fasciitis + septic shock).", "sys": "I"}, {"topic": "Surgery", "q": "วัยรุ่นชายปวดไข่ขวา 1 วัน PS 6/10, cremasteric reflex positive. ทำอย่างไร", "choices": ["ตัดไข่ขวา (right orchiectomy)", "ATB (antibiotic/conservative)", "ตัดไข่ให้หมด (bilateral orchiectomy)"], "ans": 1, "exp": "ปวดอัณฑะที่ยังมี cremasteric reflex (positive) → torsion ของอัณฑะมีโอกาสน้อย (torsion มัก reflex หายไป) นึกถึง epididymo-orchitis หรือ torsion of appendix testis → รักษาแบบประคับประคอง/antibiotic ไม่ผ่าตัดตัดอัณฑะ", "sys": "flex"}, {"topic": "Surgery", "q": "เด็กอายุ 18 เดือน ไข่ไม่ลง 1 ข้าง (undescended testis) ทำอย่างไร", "choices": ["Testosterone", "Follow up", "Orchidopexy"], "ans": 2, "exp": "Undescended testis (cryptorchidism) ที่ยังไม่ลงเมื่ออายุเกิน 6-12 เดือน (ที่นี่ 18 เดือน) → ทำ orchidopexy (ผ่าตัดนำอัณฑะลงถุงและตรึงไว้) เพื่อลดเสี่ยงมะเร็ง/มีบุตรยาก. *ต้นฉบับไฮไลต์ Testosterone ซึ่งการรักษาด้วยฮอร์โมนไม่ได้ผล/ไม่แนะนำ*", "sys": "XVII"}, {"topic": "Cardiology", "q": "Male 44 yr มาตรวจร่างกายเฉย ๆ เจอว่า BP แขนสองข้างไม่เท่ากัน บนกับล่างก็ไม่เท่ากัน. ถามว่าเป็นอะไร", "choices": ["Coarctation", "Takayasu"], "ans": 0, "exp": "ความดันแขนสูงกว่าขา (upper > lower) เป็นลักษณะเฉพาะของ coarctation of aorta (มี radio-femoral delay, HT ที่แขน). Takayasu (pulseless disease) มักในหญิงเอเชียอายุน้อย", "sys": "IX"}, {"topic": "Surgery", "q": "30 ปี มาด้วย off and on anal bleeding, V/S stable. Procto: irreducible, internal hemorrhoid. Mx?", "choices": ["stool softener", "Ligation", "hemorrhoidectomy"], "ans": 2, "exp": "Internal hemorrhoid ที่ดันกลับไม่เข้า (irreducible = grade IV) → รักษาด้วย hemorrhoidectomy. Rubber band ligation เหมาะกับ grade I-III", "sys": "XI"}, {"topic": "Forensic", "q": "อธิบายลักษณะแผล: มี satellite lesion, เห็น skin bridge, can't defined edge (ขอบไม่ชัด). เรียกว่าแผลชนิดใด", "choices": ["Laceration", "Abrasion", "Contusion", "Cut wound"], "ans": 0, "exp": "แผลที่มี tissue/skin bridge คร่อมอยู่ + ขอบไม่เรียบ/ไม่ชัด = laceration (แผลฉีกขาดจากแรงทื่อ). ต่างจาก cut/incised wound (แผลจากของมีคม ขอบเรียบ ไม่มี tissue bridge)", "sys": "general"}, {"topic": "Surgery", "q": "30 years old Thai male fall from electrical pole 4 meters. Unconscious 2 min then awake, active ระหว่างอยู่บนรถพยาบาลตื่นดี active ดี พอมาถึง ER มี drowsiness, confusion. ถามว่าเป็นอะไร", "choices": ["Subdural hematoma", "Epidural hematoma", "Electrical injury", "Diffuse axonal injury", "Post concussion"], "ans": 1, "exp": "สลบสั้น ๆ → ตื่นดี (lucid interval) → แล้วซึม/สับสนลง = epidural hematoma (เลือดออก middle meningeal artery). *ต้นฉบับไฮไลต์ Subdural hematoma แต่ lucid interval เป็นลักษณะคลาสสิกของ epidural hematoma*", "sys": "VI"}, {"topic": "Obstetrics & Gynecology", "q": "A 25-year-old female GA 8 wk with a history of GTC 2 episodes happened one month and one week ago. She also had a history of carbamazepine-induced rash. What is the next management?", "choices": ["Phenytoin", "Topiramate", "Levetiracetam", "Valproate", "Phenobarbital"], "ans": 2, "exp": "หญิงตั้งครรภ์ + ต้องคุมชัก + แพ้ carbamazepine → เลือก levetiracetam (หรือ lamotrigine) เพราะเสี่ยง teratogenic ต่ำสุด. หลีกเลี่ยง valproate (teratogen สูงสุด), phenytoin/phenobarbital/topiramate", "sys": "XII"}, {"topic": "Obstetrics & Gynecology", "q": "A 29-year-old female G3P2 (2 previous C/S, fetal birth weight 3,600 and 3,800 g). First ANC at 12 wk. Her past ANC visits were unremarkable. What is the appropriate management at GA 20 wk?", "choices": ["50 g OGTT", "Plan vaginal delivery", "Plan C/S at GA 37 wk with tubal sterilization", "Routine ultrasound"], "ans": 3, "exp": "ที่อายุครรภ์ 20 สัปดาห์ การดูแลตามปกติคือ routine (anomaly) ultrasound (ตรวจโครงสร้างทารกที่ ~18-22 wk). 50 g OGTT ทำที่ 24-28 wk; ผู้มี 2 previous C/S จะวางแผน elective repeat C/S ในช่วงใกล้คลอด (ไม่ใช่ที่ 20 wk)", "sys": "XV"}, {"topic": "Obstetrics & Gynecology", "q": "A 30-year-old female G2P1001 GA 36 wk with a history of previous C/S came to the hospital with bright red blood bleeding per vagina. PE: P120/min, BP 80/60 mmHg, generalized abdominal tenderness with rebound tenderness, palpable fetal part. What is the most likely diagnosis?", "choices": ["Placenta previa", "Abruptio placenta", "Ruptured Vasa previa", "Mucous blood show", "Uterine rupture"], "ans": 4, "exp": "แผลผ่าคลอดเดิม + เลือดออก + ปวดท้องทั่ว + rebound + คลำ fetal part ได้ชัด (ทารกออกมาในช่องท้อง) + shock = uterine rupture (มดลูกแตก ภาวะฉุกเฉิน ต้องผ่าตัดด่วน)", "sys": "XV"}, {"topic": "Obstetrics & Gynecology", "q": "A 20-year old pregnant woman presents with a non pruritic lesion at face for 1 month. PE: multiple stages of inflammation papule, pustule, nodule (acne). What is the most appropriate management?", "choices": ["Topical azelaic acid", "Topical tretinoin", "Topical adapalene", "Topical steroid lotion", "Oral isotretinoin"], "ans": 0, "exp": "สิวในหญิงตั้งครรภ์ → ห้ามใช้ retinoid ทั้ง oral/topical (tretinoin, adapalene, isotretinoin = teratogen). ยาที่ปลอดภัยคือ topical azelaic acid (หรือ topical erythromycin/benzoyl peroxide)", "sys": "XV"}, {"topic": "Obstetrics & Gynecology", "q": "A 18-year-old female puerperium, breastfeeding, delivered an infant 6 weeks ago. Which contraception is the most appropriate?", "choices": ["DMPA", "Subdermal implant", "Combined pills", "Condom", "Contraceptive patch"], "ans": 1, "exp": "หญิงให้นมบุตร → หลีกเลี่ยงฮอร์โมนที่มี estrogen (combined pills, patch — ลดน้ำนม + เสี่ยง VTE). เลือก progestin-only ที่มีประสิทธิภาพสูง เช่น subdermal implant (LARC) — ปลอดภัยในการให้นมและคุมกำเนิดได้ดีที่สุด (DMPA ก็เป็น progestin-only ที่ใช้ได้เช่นกัน)", "sys": "XV"}, {"topic": "Obstetrics & Gynecology", "q": "A 20-year-old woman GA 10 wk came to ANC. No hx of jaundice. PE: unremarkable. Lab: HBsAg Positive. What is the appropriate management (next test)?", "choices": ["HbcAg", "Anti HBs", "HbeAg", "Anti HBc", "Anti HDV"], "ans": 2, "exp": "หญิงตั้งครรภ์ HBsAg positive → ตรวจ HBeAg (และ HBV DNA) เพื่อประเมินความสามารถในการแพร่เชื้อ/ความเสี่ยงถ่ายทอดสู่ทารก. ถ้า HBeAg+ หรือ viral load สูง ให้ antiviral (tenofovir) ไตรมาสสาม + ทารกได้ HBIG + วัคซีนแรกเกิด", "sys": "XI"}, {"topic": "Obstetrics & Gynecology", "q": "A 30-year-old patient complained of amenorrhea after an abortion. She underwent dilation and curettage. What is the most proper investigation?", "choices": ["FSH and E2 level", "TSH and PRL level", "Pelvic ultrasound", "Hysteroscopy", "SIS"], "ans": 3, "exp": "ขาดประจำเดือนหลังขูดมดลูก (D&C) = สงสัย Asherman syndrome (พังผืดในโพรงมดลูก). การตรวจที่ดีที่สุดคือ hysteroscopy (มองเห็นและแยกพังผืดได้โดยตรง). SIS/HSG ก็ช่วยได้", "sys": "XIV"}, {"topic": "Obstetrics & Gynecology", "q": "A 18 years old female G2P0 GA 32 weeks presents with fluid leakage from vagina 2 hr PTA. No fever, no abdominal pain, normal fetal movement as the day before. What is the next appropriate management?", "choices": ["U/S", "Cervical swab culture", "PV", "EFM", "Nitrazine test"], "ans": 4, "exp": "สงสัย preterm PROM (น้ำเดินที่ 32 สัปดาห์) → ยืนยันการแตกของถุงน้ำคร่ำด้วย nitrazine test (น้ำคร่ำเป็นด่างเปลี่ยนสี) หรือ sterile speculum (pooling/ferning). หลีกเลี่ยงการตรวจภายในด้วยนิ้ว (digital PV) เพราะเพิ่มการติดเชื้อ", "sys": "XV"}, {"topic": "Obstetrics & Gynecology", "q": "Case pregnancy G1, มี labor pain, cervix 8 cm 100% effaced, FHR 90 bpm, PV มี cord in vagina (cord prolapse). ถาม management", "choices": ["c/s emer", "reverse trendelenburg", "empty bladder", "ดัน cord กลับเข้าไป"], "ans": 0, "exp": "Umbilical cord prolapse + fetal bradycardia (FHR 90) = ภาวะฉุกเฉินทางสูติกรรม → emergency C/S. ระหว่างเตรียม: ยกส่วนนำของทารกออกจากสายสะดือด้วยมือ + จัดท่า knee-chest/Trendelenburg. *ห้ามดันสายสะดือกลับเข้าไป*", "sys": "XV"}, {"topic": "Obstetrics & Gynecology", "q": "ท้อง 25 wk ตรวจร่างกายพบ heart failure. ให้ยาอะไร (ต้นฉบับตัวเลือกไม่ครบ — ใส่เท่าที่มี)", "choices": ["ARB", "IV furosemide"], "ans": 1, "exp": "หญิงตั้งครรภ์ที่มี heart failure/pulmonary congestion → ให้ IV furosemide ลด volume ได้. *ARB (และ ACEI) เป็นข้อห้ามในการตั้งครรภ์ (teratogenic)*", "sys": "IX"}, {"topic": "Obstetrics & Gynecology", "q": "A 52-year-old female u/d DM, para 2, present with vaginal spotting for 1 mo. No pelvic pain. PE: BW 70, H 150, V/S 140/90 mmHg, No pale conjunctiva. PV: MIUB normal; VG - atrophic mucosa, blood; Os - close, minimal bloody d/c per os; Ut - normal size; Adnexa - no mass, not tender. Most proper investigation?", "choices": ["Pap", "CA125", "F&C", "TVS", "FSH, E2"], "ans": 2, "exp": "เลือดออกทางช่องคลอดในวัยหมดประจำเดือน (postmenopausal bleeding) + ปัจจัยเสี่ยง (อ้วน, DM) → ต้องตัดมะเร็งเยื่อบุโพรงมดลูก. การตรวจที่ได้ชิ้นเนื้อวินิจฉัยคือ fractional curettage (F&C). (TVS วัดความหนาเยื่อบุมดลูกใช้เป็น initial screening ได้)", "sys": "VII"}, {"topic": "Obstetrics & Gynecology", "q": "Pregnancy เป็น DM อยู่เดิม ได้ยา Glipizide อยู่ ถาม management", "choices": ["ให้ Glipizide ต่อ", "Glipizide + metformin", "Lifestyle modification", "เปลี่ยนเป็น metformin (MFM)"], "ans": 3, "exp": "เบาหวานที่ตั้งครรภ์ — gold standard คือเปลี่ยนเป็น insulin. เมื่อไม่มี insulin ในตัวเลือก metformin ปลอดภัยกว่า sulfonylurea (glipizide ผ่านรก เสี่ยง neonatal hypoglycemia). *ต้นฉบับไฮไลต์ 'ให้ glipizide ต่อ' ซึ่งไม่เหมาะ; ตัวเลือกที่ควรมีจริงคือ insulin*", "sys": "XV"}, {"topic": "Obstetrics & Gynecology", "q": "25 yo Pregnancy GA 8 weeks มีประวัติชักแบบ GTC มา 2 ครั้ง เคยได้ carbamazepine แล้วผื่นขึ้น. ควรให้ยาอะไร", "choices": ["Phenytoin", "Topiramate", "Phenobarbital", "Valproic acid", "Levetiracetam"], "ans": 4, "exp": "หญิงตั้งครรภ์ + คุมชัก + แพ้ carbamazepine → levetiracetam (หรือ lamotrigine) เสี่ยง teratogenic ต่ำสุด. หลีกเลี่ยง valproic acid (teratogen สูงสุด)", "sys": "XV"}, {"topic": "Obstetrics & Gynecology", "q": "A 34 yr women has been aborted for 3 pregnancies at 7, 11, 8 wk. What is the most likely cause of her miscarriage?", "choices": ["Chromosome abnormality", "Myoma uteri", "Bicornuate uterus", "Recurrent infection", "Cervical incompetence"], "ans": 0, "exp": "แท้งซ้ำในไตรมาสแรก (7, 11, 8 สัปดาห์ ล้วนช่วงต้น) → สาเหตุที่พบบ่อยที่สุดคือความผิดปกติของโครโมโซม (เช่น parental balanced translocation/fetal aneuploidy). Cervical incompetence/bicornuate มักทำให้แท้งไตรมาสสอง", "sys": "XV"}, {"topic": "Obstetrics & Gynecology", "q": "คลอดเด็กแล้วเกิด shoulder dystocia. Management (ขั้นแรก)?", "choices": ["posterior shoulder", "McRobert", "Wood screw maneuver", "Suprapubic pressure"], "ans": 1, "exp": "Shoulder dystocia — ขั้นแรกคือ McRoberts maneuver (งอสะโพกแม่เข้าหาท้อง) ± suprapubic pressure. การคลอดไหล่หลัง (deliver posterior shoulder/arm)/Wood screw เป็น maneuver ลำดับถัดไป. *ต้นฉบับไฮไลต์ posterior shoulder ซึ่งไม่ใช่ขั้นแรก*", "sys": "XI"}, {"topic": "Obstetrics & Gynecology", "q": "Thai female 28 years old G1P0 GA 38 wks คลอดลูกที่บ้านมาแล้ว 2 hrs PTA แต่รกยังไม่คลอด (retained placenta), แม่ V/S BP 120/80 PR 100. ทำ cord controlled traction แล้วเกิด avulsed cord. ควรทำอะไรต่อ", "choices": ["Crede maneuver", "Ergonovine", "Manual extraction of placenta"], "ans": 2, "exp": "รกค้าง (retained placenta) + สายสะดือขาดขณะดึง (avulsed cord) → ต้องทำ manual removal of placenta (ล้วงรก) ในห้องผ่าตัด/ภายใต้ยาระงับความรู้สึก. Crede/ergonovine ไม่ช่วยเมื่อสายสะดือขาดแล้ว", "sys": "XV"}, {"topic": "Obstetrics & Gynecology", "q": "แม่ No ANC คลอดก่อนมาโรงพยาบาล โดยใช้กรรไกรที่บ้านตัด cord (unclean). PE: BT 37°C, PR 100, BP 70/50, RR 30. นอกจากการให้ IV penicillin จะให้อะไรเพิ่ม", "choices": ["Gentamicin", "Gentamicin + Tetanus toxoid", "Gentamicin + Tetanus immunoglobulin", "Gentamicin + Tetanus toxoid + Tetanus immunoglobulin", "Tetanus immunoglobulin"], "ans": 3, "exp": "คลอดสกปรก (ตัดสายสะดือด้วยกรรไกรบ้าน) + ไม่ได้ ANC/ไม่ทราบประวัติวัคซีน = tetanus-prone → ให้ทั้ง active (tetanus toxoid) + passive (tetanus immunoglobulin) ร่วมกับ antibiotic (penicillin + gentamicin คลุมกว้างสำหรับ sepsis). *โจทย์ไม่ชัดว่าถามแม่หรือทารก แต่กรณี unknown vaccination + dirty ให้ toxoid + TIG*", "sys": "XV"}, {"topic": "Obstetrics & Gynecology", "q": "A 27 y/o GA 38, low risk, labor pain, FHR 150, longitudinal, contraction interval 7 min duration 45 sec, cx 4 cm eff 80% station 0, membrane intact. Management?", "choices": ["C/S", "PGE1", "Oxytocin", "Observe", "Amniotomy"], "ans": 4, "exp": "ปากมดลูก 4 ซม. บาง 80% (favorable) แต่ contraction ห่าง (7 นาที = inadequate) + ถุงน้ำยังไม่แตก → augment labor ด้วย amniotomy (AROM) ก่อน แล้วค่อยพิจารณา oxytocin. *ต้นฉบับไฮไลต์ PGE1 ซึ่งใช้ ripening ปากมดลูกที่ยังไม่พร้อม — แต่ที่นี่ปากมดลูกพร้อมแล้ว*", "sys": "XV"}, {"topic": "Obstetrics & Gynecology", "q": "Postpartum 2 wk รู้สึกหงุดหงิด มีปากเสียงกับสามีหลายครั้ง รู้สึกผิด เลี้ยงลูกไม่ดี บางครั้งอยากทำร้ายลูกเวลาลูกร้อง. ถามว่าเป็นอะไร", "choices": ["Postpartum depression", "Adjustment disorder", "Factitious disorder", "GAD"], "ans": 0, "exp": "หลังคลอด 2 สัปดาห์ + อารมณ์เศร้า/หงุดหงิด + รู้สึกผิด/ตนเองเลี้ยงลูกไม่ดี + คิดทำร้ายลูก = postpartum depression (ต่างจาก postpartum blues ที่อาการน้อยและหายเองใน 2 สัปดาห์). ความคิดทำร้ายลูกเป็นสัญญาณอันตราย ต้องรีบดูแล", "sys": "XV"}, {"topic": "Obstetrics & Gynecology", "q": "Pregnancy c placenta previa, ให้ advice เรื่อง sexual intercourse (SI)", "choices": ["Be Gentle", "No SI", "Side by side", "Wait until GA 36 wk", "SI as usual"], "ans": 1, "exp": "ภาวะรกเกาะต่ำ (placenta previa) → แนะนำ งดการมีเพศสัมพันธ์ (No SI) และหลีกเลี่ยงการตรวจภายใน/สอดใส่ เพราะเสี่ยงกระตุ้นเลือดออก", "sys": "XV"}, {"topic": "Obstetrics & Gynecology", "q": "A 20 year-old primigravida came for the first ANC. No history of jaundice. Physical examination is unremarkable. All investigations are within normal limits except HBsAg positive. What is the proper investigation?", "choices": ["HBc Ag", "Anti-HBs Ab", "HBe Ag", "Anti-HbcAb", "Anti-HDV"], "ans": 2, "exp": "หญิงตั้งครรภ์ HBsAg+ → ตรวจ HBeAg (และ HBV DNA) ประเมินความสามารถในการแพร่เชื้อสู่ทารก. *ต้นฉบับไฮไลต์ Anti-HDV ซึ่งไม่ใช่ priority ในการประเมินการถ่ายทอดสู่ทารก*", "sys": "XV"}, {"topic": "Obstetrics & Gynecology", "q": "Female ~28 y/o presented with vaginal bleeding. PV: bleeding per cervical os, uterus 12 wk size. TVS: intrauterine pregnancy without fetal heartbeat, US calculated GA 12 wk. What is the most proper management?", "choices": ["F/U 1 wk", "Oxytocin", "MVA", "Misoprostol", "D&C"], "ans": 3, "exp": "IUP ที่ไม่มี fetal heartbeat + ขนาด 12 สัปดาห์ = missed abortion. รักษาด้วย medical management (misoprostol) เพื่อขับชิ้นเนื้อ หรือ surgical evacuation (MVA/suction D&C) เป็นทางเลือก. Oxytocin ไม่ได้ผลในไตรมาสแรก", "sys": "XV"}, {"topic": "Obstetrics & Gynecology", "q": "หญิงท้อง GA 25 Wk no u/d, presented progressive dyspnea on exertion. PE: JVP 5 cm above sternal notch, PMI at 6th ICS anterior mid axillary line (displaced), rales both lower lungs, pitting edema both legs. Appropriate management?", "choices": ["PO diuretic", "Dobutamine", "IV morphine", "IV nitroglycerin", "IV furosemide"], "ans": 4, "exp": "ภาวะหัวใจล้มเหลวในหญิงตั้งครรภ์ (JVP สูง, หัวใจโต, rales, ขาบวม = volume overload/pulmonary congestion) → IV furosemide ลด preload/คั่งน้ำ. Dobutamine ใช้เมื่อ cardiogenic shock; nitroglycerin เป็น adjunct", "sys": "IX"}, {"topic": "Obstetrics & Gynecology", "q": "A 26 year-old pregnant woman, G1P0 GA 34 wks, comes for routine antenatal care. She reports that her baby is less active than usual. On PE, you cannot detect a fetal heart beat either by a stethoscope or a fetal heart doppler. Which is the most appropriate management?", "choices": ["Ultrasonogram", "Non stress test", "Vibroacoustic stimulation test", "Internal fetal monitoring", "Terminate of pregnancy"], "ans": 0, "exp": "ตรวจไม่พบเสียงหัวใจทารกด้วย stethoscope/doppler → ต้องยืนยันด้วย real-time ultrasound (ดู fetal cardiac activity) ก่อนสรุปว่าเป็น fetal demise หรือหาสาเหตุ. NST/VST ต้องมี FHR อยู่ก่อนจึงทำได้", "sys": "XV"}, {"topic": "Obstetrics & Gynecology", "q": "A 33 year-old pregnant woman G2P1001 GA 34 week come to ANC. She has had a persistent headache and epigastric pain for 1 day. PE: BP 150/90 mmHg, pitting edema 2+. Lab: BUN 20, Cr 1.2, Hb 10.2, WBC 10500, Plt 90000, AST 30, ALT 50. What is the diagnosis?", "choices": ["Gestational GDM", "Preeclampsia with severe features", "Preeclampsia without severe features", "Eclampsia", "Chronic hypertension with superimposed preeclampsia with severe features"], "ans": 1, "exp": "BP ≥ 140/90 หลัง 20 สัปดาห์ + มี severe features (ปวดหัวต่อเนื่อง, epigastric pain, thrombocytopenia Plt < 100,000) = preeclampsia with severe features. (ไม่ใช่ eclampsia เพราะยังไม่ชัก; ไม่มีประวัติ HT ก่อน 20 wk จึงไม่ใช่ superimposed)", "sys": "XV"}, {"topic": "Obstetrics & Gynecology", "q": "แม่อายุ 34 แท้งบ่อย แท้งตอน GA 7,11,8 ตามลำดับ. ถามว่าเกิดจากอะไร", "choices": ["Myoma uteri", "Bicornuate uterus", "chromosome abnormality", "recurrent infection", "cervix incompetent"], "ans": 2, "exp": "แท้งซ้ำในไตรมาสแรก (7,11,8 สัปดาห์) → สาเหตุที่พบบ่อยสุดคือความผิดปกติของโครโมโซม (parental balanced translocation/fetal aneuploidy). cervical incompetence/bicornuate มักแท้งไตรมาสสอง", "sys": "XVII"}, {"topic": "Obstetrics & Gynecology", "q": "30 yr old G2P1001 GA ใกล้ term มาด้วย bright red bleeding per vagina with abdominal pain. PE: PR 120, BP drop, palpable fetal part, FHS 80. Dx?", "choices": ["Mucous bloody show", "Abruptio placenta", "Uterine rupture"], "ans": 1, "exp": "เลือดออกทางช่องคลอด + ปวดท้อง + มารดาช็อก + fetal distress (FHS 80) ในมดลูกที่ไม่มีแผลผ่าตัดเดิม = abruptio placentae (รกลอกตัวก่อนกำหนด). *ถ้ามีแผลผ่าคลอดเดิม + คลำ fetal part ได้ชัด ให้คิดถึง uterine rupture*", "sys": "XV"}, {"topic": "Obstetrics & Gynecology", "q": "28 y/o G2P1 GA 14 wk second visit ANC. Lab: Patient - MCV 61, DCIP+, HbE 19%; husband - MCV 58, DCIP+, HbE 98%. Proper management?", "choices": ["Routine ANC", "Cordocentesis for fetal alpha thal", "Amniocentesis for fetal DNA B-thal", "Husband alpha thal PCR", "Patient DNA test for B-thal"], "ans": 4, "exp": "ทั้งคู่ MCV ต่ำมาก + DCIP+ (มี HbE). ภรรยา HbE trait (E 19%) แต่ MCV ต่ำผิดปกติ (61) ชวนให้มี beta-thal ร่วม; สามี HbE สูงมาก (E 98% = homozygous HbE หรือ HbE/beta-thal). เพื่อประเมินความเสี่ยงลูกเป็น beta-thalassemia/HbE ต้องตรวจ DNA beta-thal ในภรรยา (ถ้าเป็นพาหะ beta-thal ร่วม → ลูกเสี่ยงโรครุนแรง → prenatal diagnosis)", "sys": "XV"}, {"topic": "Obstetrics & Gynecology", "q": "30 yr G2P1001 GA 36 wk hx of Cesarean section มาด้วย Red bright blood from vagina. PE: BP 80/60 PR 120. Abd: Generalized tender c rebound tenderness, Palpable fetal part, FHS 80. Dx?", "choices": ["Uterine rupture", "Placenta previa", "Abrubtio placenta", "Rupture vasa previa", "Mucous bloody show"], "ans": 0, "exp": "มีแผลผ่าคลอดเดิม (previous C/S) + เลือดออก + ปวดท้องทั่ว + rebound + คลำ fetal part ได้ชัด (ทารกออกมาในช่องท้อง) + ช็อก + fetal distress = uterine rupture (มดลูกแตกจากรอยแผลเดิม)", "sys": "XV"}, {"topic": "Obstetrics & Gynecology", "q": "A 50 year-old healthy female feels a sudden hot and cold sensation all over the body and cannot sleep well. She feels pain in vagina during having sex. Her husband says that she has mood swings. She underwent hysterectomy due to myoma uteri 2 years ago. What is the appropriate management?", "choices": ["OCP", "E only pill", "P only pill", "cyclic E+P", "continuous E+P"], "ans": 1, "exp": "อาการวัยทอง (ร้อนวูบวาบ, นอนไม่หลับ, ช่องคลอดแห้ง/เจ็บเวลามีเพศสัมพันธ์, อารมณ์แปรปรวน) ในผู้ที่ตัดมดลูกไปแล้ว → ให้ estrogen-only replacement (ไม่ต้องมี progestin เพราะไม่มีมดลูกให้ป้องกัน endometrial hyperplasia)", "sys": "XIII"}, {"topic": "Obstetrics & Gynecology", "q": "A 20 years old female presented with massive vaginal bleeding after illegal abortion. PE: pale, BP 90/60 mmHg, PR 120 bpm, RR 24, Hct 25%. ได้ NSS กับ PRC. หลังจากนั้น 10 min มี chest tightness and agitation. V/S: BP 80/60, HR 120, RR 30. Lung: wheezing both lungs. ถามสาเหตุเกิดจากอะไร", "choices": ["Acute pulmonary edema", "Pulmonary embolism", "Mismatch transfusion", "Amniotic embolism", "Septic shock"], "ans": 2, "exp": "อาการเฉียบพลันหลังให้ PRC ~10 นาที (แน่นอก กระสับกระส่าย ความดันตก wheezing) = acute hemolytic transfusion reaction จาก ABO mismatch (mismatch transfusion). ต้องหยุดให้เลือดทันที + resuscitate + ตรวจซ้ำ", "sys": "XV"}, {"topic": "Obstetrics & Gynecology", "q": "คนท้อง GA 12 มาด้วยลูกดิ้นน้อยลง มาตรวจฟังด้วย stethoscope และตรวจตาม ANC ไม่เจอ FHS. ถาม most proper management", "choices": ["นัดอีก 1 week มาตรวจใหม่", "Termination", "PV", "UGS (ultrasound)"], "ans": 3, "exp": "ฟังไม่พบเสียงหัวใจทารก → ยืนยันด้วย ultrasound (UGS) ว่ามี fetal cardiac activity หรือไม่ ก่อนตัดสินใจ. ไม่ควรนัดรอ 1 สัปดาห์หรือ terminate โดยไม่ยืนยันก่อน", "sys": "XV"}, {"topic": "Obstetrics & Gynecology", "q": "Pregnancy ประมาณ first trimester เป็น hyperthyroid กิน MMI (methimazole) อยู่แล้ว เพิ่งรู้ว่าท้อง. ควรทำอย่างไร (ตัวเลือกแต่งขึ้นมาเอง ต้นฉบับไม่มีตัวเลือกชัด)", "choices": ["Continue MMI same dose", "Increase MMI dose", "Decrease MMI dose", "Discontinue MMI", "Switch to PTU"], "ans": 4, "exp": "หญิงตั้งครรภ์ไตรมาสแรกที่ใช้ MMI → เปลี่ยนเป็น PTU เพราะ MMI ในไตรมาสแรกเสี่ยง teratogenic (aplasia cutis, choanal/esophageal atresia). หลังไตรมาสแรกมักเปลี่ยนกลับเป็น MMI", "sys": "XV"}, {"topic": "Obstetrics & Gynecology", "q": "มารดา G1P0 GA 41 wk มาฝากครรภ์ตามนัด ตรวจร่างกายปกติดี ลูกดิ้นดี V/S stable. ถามทำอย่างไรดี", "choices": ["Membranous stripping เลย", "นัดติดตามอาการ อีกที 1 wk", "นัด admit เพื่อผ่าคลอด อีกที 1 wk", "เจาะถุงน้ำคร่ำ ณ visit นั้นเลย"], "ans": 0, "exp": "GA 41 สัปดาห์ (ใกล้ post-term) → ควรกระตุ้นให้เข้าสู่การคลอด. Membrane stripping/sweeping ช่วยกระตุ้นการคลอดตามธรรมชาติและลด post-term. การรอ 1 สัปดาห์เสี่ยง post-term; C/S ไม่มีข้อบ่งชี้; amniotomy ทำเมื่อพร้อมคลอด/admit", "sys": "XVIII"}, {"topic": "Obstetrics & Gynecology", "q": "Female pt underwent illegal abortion, she has amenorrhea ever since. What is the proper management?", "choices": ["Ultrasound", "hysteroscopy"], "ans": 1, "exp": "ขาดประจำเดือนหลังทำแท้ง/ขูดมดลูก = Asherman syndrome (พังผืดในโพรงมดลูก) → hysteroscopy วินิจฉัยและแยกพังผืดได้โดยตรง", "sys": "XIV"}, {"topic": "Obstetrics & Gynecology", "q": "ผู้ป่วยหญิงอายุ 60 มี N/V เคยมีประวัติ PPH (postpartum hemorrhage) ไม่ได้บอกว่าเมื่อไหร่. ถามว่าเป็นอะไร", "choices": ["empty sella syndrome", "Sheehan syndrome"], "ans": 1, "exp": "ประวัติตกเลือดหลังคลอด (PPH) รุนแรง + ต่อมามีอาการ hypopituitarism (คลื่นไส้อาเจียนจาก adrenal insufficiency ฯลฯ) = Sheehan syndrome (ต่อมใต้สมองส่วนหน้าตายจากการขาดเลือดหลัง PPH)", "sys": "XV"}, {"topic": "Obstetrics & Gynecology", "q": "หญิงมีก้อน fluctuate ที่ตำแหน่ง 4 นาฬิกาของ labia ขนาด 4x4 cm. ถามว่าทำอะไร", "choices": ["Marsupialization", "i&d"], "ans": 0, "exp": "ก้อนที่ labia ตำแหน่ง 4-5 นาฬิกา = Bartholin gland cyst/abscess. การรักษาที่ลดการเป็นซ้ำ (definitive) คือ marsupialization. (I&D เดี่ยว ๆ เป็นซ้ำง่าย; abscess เฉียบพลันอาจใช้ I&D + Word catheter)", "sys": "flex"}, {"topic": "Obstetrics & Gynecology", "q": "หญิงมาฝากครรภ์ แม่ MCV ต่ำ DCIP+ HbE trait; พ่อ MCV ต่ำ DCIP+ HbA2/E 98% เป็น homozygous HbE. ถามว่าต้องตรวจอะไรต่อ", "choices": ["ANC ปกติ", "ส่ง alpha-thal ทั้งพ่อทั้งแม่"], "ans": 1, "exp": "ทั้งคู่ MCV ต่ำที่อธิบายด้วย HbE อย่างเดียวไม่พอ → สงสัยมี alpha-thalassemia ร่วมทั้งคู่ ต้องส่ง alpha-thal gene (PCR) ทั้งพ่อและแม่ เพื่อประเมินความเสี่ยงลูกเป็น Hb Bart's hydrops fetalis (ถ้าทั้งคู่เป็น alpha-thal-1 carrier)", "sys": "XV"}, {"topic": "Obstetrics & Gynecology", "q": "หญิงท้อง GA จำไม่ได้แต่พร้อมคลอด cx 3 cm efface จำไม่ได้ uc 45\"/7' (contraction 45 วินาที ห่าง 7 นาที = inadequate). ถามว่าทำอะไร", "choices": ["เจาะถุงน้ำ (amniotomy)", "iv oxytocin"], "ans": 0, "exp": "contraction ยังห่าง (inadequate) + ถุงน้ำยังไม่แตก → augment labor ด้วย amniotomy (เจาะถุงน้ำ) ก่อน แล้วค่อยพิจารณา oxytocin ถ้ายังไม่พอ", "sys": "XV"}, {"topic": "Obstetrics & Gynecology", "q": "A 30 years old presented with recurrent postcoital bleeding 3 mon PTA, LMP 2 weeks ago. PE: Smooth surface, finger-like mass with narrow stalk protruding from cervical os. ให้ทำอะไรต่อ", "choices": ["HBV DNA", "Polypectomy", "Sclerotherapy", "Punch biopsy", "Colposcopy with biopsy"], "ans": 1, "exp": "ก้อนผิวเรียบ รูปนิ้วมือ มีก้านแคบยื่นจากปากมดลูก + เลือดออกหลังมีเพศสัมพันธ์ = cervical polyp → รักษาด้วย polypectomy (บิด/ตัดออก + ส่งพยาธิ)", "sys": "II"}, {"topic": "Obstetrics & Gynecology", "q": "A 29 year old woman presented with galactorrhea and absent menstruation for several months. BP 141/90 PR 50. No cushingoid appearance, no acromegaly. Pituitary MRI show mass 1 cm at gland with no chiasmatic invasion. Dx?", "choices": ["Schwannoma", "Craniopharyngioma", "Prolactinoma", "Sheehan syndrome"], "ans": 2, "exp": "น้ำนมไหล (galactorrhea) + ขาดประจำเดือน + pituitary microadenoma 1 ซม. = prolactinoma. รักษาด้วย dopamine agonist (cabergoline/bromocriptine)", "sys": "II"}, {"topic": "Obstetrics & Gynecology", "q": "Female 30 ปี U/D Grave disease on MMI 6 mo มา 1st ANC, LMP 2 mo. V/S stable, TFT normal, No thyroid gl enlargement. Mx?", "choices": ["stop MMI", "decreased dose MMI", "increased dose MMI", "change to PTU", "continued dose MMI"], "ans": 3, "exp": "หญิงตั้งครรภ์ไตรมาสแรกที่ใช้ MMI → เปลี่ยนเป็น PTU (MMI ในไตรมาสแรกเสี่ยง teratogenic). ไม่หยุดยา (เพราะยังต้องคุม hyperthyroid ระวัง thyroid storm)", "sys": "IV"}, {"topic": "Obstetrics & Gynecology", "q": "ผู้หญิง sexual active มาด้วยปวดหน่วงท้องน้อยด้านขวาล่าง, ใส่ IUD มา 2 ปีแล้ว. PE: RLQ tenderness and rebound tenderness. PV: mucopurulent per os, inflammatory Cx, cervical motion tenderness, Rt adnexal mass 5 cm. What is the most appropriate mx?", "choices": ["UPT", "ผ่า explore laparotomy", "Remove IUD", "Cervical swab C/S for aerobe", "IV ATB"], "ans": 4, "exp": "PID ที่มี tubo-ovarian abscess (adnexal mass 5 ซม. + cervical motion tenderness + mucopurulent discharge) → เริ่มด้วย IV broad-spectrum antibiotics. พิจารณาถอด IUD + drainage/surgery ถ้าไม่ตอบสนอง/แตก", "sys": "II"}, {"topic": "Obstetrics & Gynecology", "q": "แม่เด็ก 15 ปี กำลังให้นมบุตร คลอดไปเมื่อ 6 สัปดาห์ก่อน. จะแนะนำให้ใช้ contraception อะไรดี", "choices": ["Subdermal implant", "DMPA", "Contraceptive pill", "Condom", "Contraceptive patch"], "ans": 0, "exp": "หญิงให้นมบุตร → หลีกเลี่ยง estrogen (pill/patch). เลือก progestin-only ที่มีประสิทธิภาพสูงและเหมาะกับวัยรุ่น = subdermal implant (LARC). (DMPA ก็เป็น progestin-only ที่ใช้ได้)", "sys": "XIV"}, {"topic": "Pediatrics", "q": "เด็กชายไข้ + DOE 2 วัน. PE: V/S BT 38.5°C, PR 116 bpm, BP and RR normal; GA - marked pallor; HEENT - mild icteric sclera; GI - hepatosplenomegaly. Labs: CBC - Hb 7, Hct 21, MCV 68, MCHC 28, RDW 23%, WBC 11800 (pmn 80), platelet normal. PBS: anisopoikilocytosis, hypochromic microcytic 2+, polychromasia, basophilic stippling. What is the most proper investigation?", "choices": ["OF test", "Hb typing", "Urine hemosiderin", "G6PD level", "DAT"], "ans": 1, "exp": "เด็กที่มี microcytic hypochromic anemia + hemolysis (ตัวเหลือง, ตับม้ามโต, polychromasia) + basophilic stippling + anisopoikilocytosis = thalassemia → ตรวจ Hb typing เพื่อวินิจฉัยชนิด", "sys": "III"}, {"topic": "Pediatrics", "q": "A Newborn day of life 3, PE: positive Ortolani's test of Lt. hip. What is the appropriate management?", "choices": ["F/U 2 wk", "F/U 2 months", "U/S", "CT", "MRI"], "ans": 2, "exp": "Ortolani positive = developmental dysplasia of the hip (DDH) — ข้อสะโพกเคลื่อน. ในทารก (< 6 เดือน กระดูกยังไม่ ossify) ตรวจยืนยันด้วย ultrasound ของสะโพก (ไม่ใช้ X-ray/CT). รักษาด้วย Pavlik harness", "sys": "XVI"}, {"topic": "Pediatrics", "q": "A newborn day of life 5. Mother had a mucopurulent vaginal discharge. Gram stain found intracellular gram negative diplococci. Clinical: active newborn, no fever, no eye discharge. What is the proper management?", "choices": ["Topical neomycin", "Topical polymyxin B", "IV cloxacillin + gentamicin", "IV Ceftriaxone", "IV ampicillin + gentamicin"], "ans": 3, "exp": "แม่ติดเชื้อ gonorrhea (intracellular gram-negative diplococci) → ทารกที่สัมผัสเชื้อต้องได้ ceftriaxone (single dose IV/IM) เพื่อป้องกัน/รักษา gonococcal ophthalmia neonatorum (ยาหยอดตาเฉพาะที่ไม่พอ)", "sys": "XVI"}, {"topic": "Pediatrics", "q": "A term male newborn jaundice, กินนมแม่ดี, อายุ 2 วัน. ลูก group B, Rh positive, DAT negative. แม่ group O, Rh positive. Blood smear เป็น hemolysis (schistocytes, polychromasia), reticulocyte 3%. What is the cause of jaundice?", "choices": ["Hereditary spherocytosis", "ABO incompatibility", "G6PD def"], "ans": 1, "exp": "แม่ group O + ลูก group B = ABO incompatibility (ABO hemolytic disease of newborn) — anti-A/anti-B (IgG) ของแม่ผ่านรกทำลายเม็ดเลือดลูก. DAT อาจ negative/weak ได้ใน ABO HDN (ต่างจาก Rh ที่ DAT positive ชัด)", "sys": "XVI"}, {"topic": "Pediatrics", "q": "Term neonate มีอาการเหนื่อย (respiratory distress). PE: scaphoid abdomen, decreased breath sound ด้านขวา. ถาม appropriate initial mx", "choices": ["ET tube", "CXR", "Oxygen mask ventilation", "Nasal CPAP", "Rt. pleural tapping"], "ans": 0, "exp": "scaphoid abdomen + เสียงหายใจลดข้างหนึ่ง + หายใจลำบากในทารกแรกเกิด = congenital diaphragmatic hernia (CDH). การจัดการเบื้องต้นคือ ET tube (intubation) + NG decompression. *ห้าม bag-mask ventilation เพราะดันลมเข้าลำไส้ที่อยู่ในทรวงอก ทำให้ปอดถูกกดมากขึ้น*", "sys": "XVI"}, {"topic": "Pediatrics", "q": "Term NB, V/S at 1 hr, PE: RR 48, MAP 44, BW 4000. Collected blood only at the right parietal bone (ไม่ข้าม suture). Mx?", "choices": ["Blood gas", "Serial hct", "DTX", "U/s brain", "X-ray scalp"], "ans": 1, "exp": "เลือดคั่งใต้ periosteum จำกัดที่กระดูก parietal ข้างเดียว ไม่ข้าม suture = cephalohematoma. ส่วนใหญ่หายเอง → ติดตามด้วย serial hct (เฝ้าภาวะซีดจากเสียเลือด) และเฝ้าระวัง hyperbilirubinemia", "sys": "flex"}, {"topic": "Pediatrics", "q": "A term infant was born at home to a mother with no ANC. She cut umbilical cord with scissors. PE: BT 37°C, BP 55/38 mmHg, HR 140 bpm, RR 50/min, others WNL. นอกจากรักษาด้วย ampicillin แล้วให้อะไรอีก", "choices": ["Gentamicin", "Tetanus toxoid", "Gentamicin + tetanus toxoid + immune globulin", "Gentamicin + tetanus toxoid", "Immune globulin"], "ans": 2, "exp": "ทารกคลอดสกปรก (ตัดสายสะดือด้วยกรรไกร) + ไม่มี ANC → เสี่ยง neonatal sepsis + neonatal tetanus → เพิ่ม gentamicin (คลุม sepsis ร่วม ampicillin) + tetanus immune globulin (TIG, passive) ± tetanus toxoid. ตัวเลือกที่ครบสุดคือ gentamicin + toxoid + immune globulin", "sys": "XV"}, {"topic": "Pediatrics", "q": "1 day old term presents with tachypnea. Mother had PROM for 24 hr. PE: V/S - HR 170 bpm, RR 90 bpm, BP 64/38 mmHg, O2sat 98%; Lung - Subcostal retraction, normal breath sound, no crepitation. Lab: WBC 25,000 (pmn 85, L 10), Platelet 180,000. CXR: Normal. What is the most proper investigation?", "choices": ["Urine culture", "Lumbar puncture", "CRP", "Hemoculture", "Arterial blood gas"], "ans": 3, "exp": "ทารกแรกเกิด + PROM 24 ชม. (risk factor) + tachypnea + leukocytosis (WBC 25,000, left shift) = สงสัย neonatal sepsis → ตรวจยืนยันด้วย hemoculture (gold standard) ก่อนให้ empiric antibiotic", "sys": "XVI"}, {"topic": "Pediatrics", "q": "NB 4200 g, vacuum delivery, BP 60/30, เจอ fluctuate boggy mass with head skin ecchymosis. ถามว่า diag อะไร", "choices": ["caput succedaneum", "Cephalhematoma", "subgaleal hematoma", "ICH"], "ans": 2, "exp": "หลังคลอดด้วย vacuum + ก้อนนุ่มยวบข้ามรอยต่อกะโหลก + ecchymosis + ความดันตก (เสียเลือดมาก) = subgaleal hemorrhage (เลือดออกใต้ galea ปริมาณมาก เสี่ยงช็อก). ต่างจาก caput (บวมน้ำ ข้าม suture ไม่ช็อก) และ cephalohematoma (ไม่ข้าม suture)", "sys": "II"}, {"topic": "Pediatrics", "q": "เด็กแรกเกิด GA 38 wk BW 4000 g แม่เป็นเบาหวาน APGAR 2,5 เจาะน้ำตาลที่ 1 ชม.แรกได้ 45 มีอาการ hypotonia ร่วม. ถามทำอย่างไร", "choices": ["IV 10% dextrose 8 ml (bolus)", "Early feed", "IV 10% dextrose ปรับ rate", "Follow up อีกที่ 2 ชม"], "ans": 0, "exp": "ทารกแม่เบาหวาน (IDM) ตัวโต + hypoglycemia (45) + มีอาการ (hypotonia) = symptomatic neonatal hypoglycemia → ให้ IV dextrose bolus (D10 2 mL/kg ≈ 8 mL สำหรับ 4 กก.) ไม่ใช่แค่ให้กินนม/รอดู", "sys": "XVI"}, {"topic": "Pediatrics", "q": "เด็ก 6 ปี มี left rhinorrhea with left facial pain. PE: bilateral congestion at inferior turbinate, Lt nasal discharge. Diagnosis?", "choices": ["allergic rhinitis", "foreign body in Lt nostril", "adenoid hypertrophy", "Lt sinusitis"], "ans": 1, "exp": "น้ำมูก/หนองข้างเดียว (unilateral) ในเด็กเล็ก = สิ่งแปลกปลอมในจมูก (nasal foreign body) จนกว่าจะพิสูจน์เป็นอื่น (มักมีกลิ่นเหม็น). *โจทย์ต้นฉบับจัดรูปแบบตัวเลือกไม่ชัด — เรียบเรียงตามที่ปรากฏ; ถ้าเน้นปวดใบหน้า+น้ำมูกข้างเดียวอาจเป็น sinusitis*", "sys": "X"}, {"topic": "Pediatrics", "q": "วัยรุ่น urticaria 2 วัน (เป็นแค่แขน). First line treatment? (ตัวเลือกแต่งขึ้นมาเอง ต้นฉบับตัวเลือกหาย)", "choices": ["1st-generation antihistamine", "Systemic corticosteroid", "2nd-generation (non-sedating) antihistamine เช่น cetirizine", "IM epinephrine", "Topical corticosteroid"], "ans": 2, "exp": "Urticaria (ลมพิษ) รักษา first-line ด้วย second-generation (non-sedating) antihistamine เช่น cetirizine/loratadine. steroid ใช้ในรายรุนแรง/ดื้อ; epinephrine ใช้เมื่อมี anaphylaxis", "sys": "IX"}, {"topic": "Pediatrics", "q": "A child presented with dyspnea. She sat in a tripod position. Lateral neck film shows thumb sign. What is the diagnosis?", "choices": ["Epiglottitis", "Viral croup"], "ans": 0, "exp": "หายใจลำบาก + นั่งท่า tripod + lateral neck film เห็น thumb sign (epiglottis บวม) = acute epiglottitis (ภาวะฉุกเฉินทางเดินหายใจ ห้ามตรวจคอกระตุ้น secure airway โดยผู้เชี่ยวชาญ + ceftriaxone). (Croup = steeple sign)", "img": "https://cdn.jsdelivr.net/gh/MercenzK/Web-quiz-images@main/NL2-2021-Q186.png", "sys": "X"}, {"topic": "Pediatrics", "q": "เด็กมีไข้ ไอ มา 3 วันแล้ว มาวันนี้มี barking cough + stridor + mucopurulent rhinorrhea. Dx?", "choices": ["Acute epiglottitis", "Pneumonia", "Bacterial tracheitis", "Viral croup"], "ans": 3, "exp": "ไอเสียงก้อง (barking/seal-like cough) + stridor + นำมาด้วย URI (rhinorrhea) = viral croup (laryngotracheobronchitis จาก parainfluenza). Epiglottitis จะ toxic + drooling ไม่มี barking cough; bacterial tracheitis toxic + ไข้สูง เสมหะข้น ไม่ตอบสนอง croup treatment", "sys": "I"}, {"topic": "Pediatrics", "q": "เด็กหญิง ~10 ขวบ มาด้วยเหนื่อย สงสัย pneumonia ได้ Ceftriaxone 4 วันแล้วไม่ดีขึ้น ยังมีไข้สูงอยู่. CXR: moderate pleural effusion, เจาะน้ำมาเป็น transudate. ต้องทำยังไงต่อ", "choices": ["Add Azithromycin", "Add Levofloxacin", "Switch to Imipenem", "Repeat thoracentesis", "Insert chest tube"], "ans": 0, "exp": "เด็กวัยเรียนที่ pneumonia ไม่ตอบสนอง beta-lactam (ceftriaxone) → คิดถึงเชื้อ atypical (Mycoplasma pneumoniae) → เพิ่ม macrolide (azithromycin). Effusion เป็น transudate (uncomplicated) จึงยังไม่ต้องใส่ chest tube", "sys": "X"}, {"topic": "Pediatrics", "q": "เด็ก 6 ปี มี sleeping problem 2 ปี + bilateral nasal obstruction, runny nose, aural fullness. Sleep test: mild OSA. PE: bilateral pale swelling nasal mucosa, tonsil grade I both sides. Lateral neck: adenoid gland hypertrophy 50%. Most appropriate mx?", "choices": ["Nasal CPAP", "Adenoidectomy", "Intranasal steroid", "Oral prednisone", "Oral antihistamine"], "ans": 1, "exp": "OSA ในเด็กจาก adenoid hypertrophy (adenoid โต 50%, tonsil เล็ก grade I) → adenoidectomy เป็นการรักษาที่จัดการต้นเหตุทางกายวิภาค. *ใน mild OSA ที่มี allergic rhinitis ร่วม intranasal steroid เป็นทางเลือกเริ่มต้นแบบไม่ผ่าตัดได้เช่นกัน*", "sys": "X"}, {"topic": "Pediatrics", "q": "เด็ก 1 ปี มีอาการ cyanosis when crying or defecation เคยมีอาการมาก่อน (hypoxic spell). PE: central cyanosis, clubbing finger. ถาม mx", "choices": ["Digitalis", "Furosemide", "Morphine", "Adenosine"], "ans": 2, "exp": "เขียวเวลาร้อง/เบ่ง + clubbing + hypoxic (cyanotic/tet) spell = Tetralogy of Fallot. การรักษา tet spell: knee-chest position, O2, morphine (ลด hyperpnea/infundibular spasm), IV fluid, propranolol. ในตัวเลือกนี้คือ morphine", "sys": "XIII"}, {"topic": "Pediatrics", "q": "เด็กมี palpable purpura ที่ขา 2 ข้าง ปวดท้อง ปัสสาวะมี red cell. Diagnosis? (ตัวเลือกแต่งขึ้นมาเอง ต้นฉบับไม่มีตัวเลือก)", "choices": ["Immune thrombocytopenic purpura (ITP)", "Hemolytic uremic syndrome", "Meningococcemia", "Henoch-Schönlein purpura (IgA vasculitis)", "Systemic lupus erythematosus"], "ans": 3, "exp": "จุดเลือดออกคลำได้ (palpable purpura) ที่ขาทั้งสองข้าง + ปวดท้อง + ปัสสาวะมีเม็ดเลือดแดง (renal involvement) = Henoch-Schönlein purpura (IgA vasculitis) — tetrad คือ purpura ที่ก้น/ขา, arthritis, abdominal pain, nephritis. ต่างจาก ITP ที่ purpura ไม่นูน (non-palpable) และเกล็ดเลือดต่ำ", "sys": "III"}, {"topic": "Pediatrics", "q": "A 9-year-old girl presented with a brief episode of staring and decreased school performance for 3 months. She usually stared for 10-15 seconds without responding to a call. PE: stable vital signs, no neurological deficits. What is the most appropriate management?", "choices": ["CT brain", "LP", "Phenytoin", "Diazepam", "EEG"], "ans": 4, "exp": "เหม่อลอย จ้องนิ่ง 10-15 วินาที ไม่ตอบสนอง + การเรียนแย่ลง = absence seizure (childhood absence epilepsy). ขั้นตอนที่เหมาะสมคือทำ EEG (พบ 3 Hz generalized spike-and-wave) เพื่อยืนยัน. *ต้นฉบับไฮไลต์ phenytoin ซึ่งผิด — phenytoin ทำให้ absence แย่ลง ยาที่ใช้จริงคือ ethosuximide/valproate*", "sys": "VI"}, {"topic": "Pediatrics", "q": "เด็กชาย 16 ปี unresponsiveness 1 hr. PE: BT 37°C, PR 60 bpm, RR 10/min, BP 152/84 mmHg. CNS - withdrawal to painful stimulation, pupil Rt 5 mm not react to light, pupil Lt 3 mm not react to light, DTR 2+ all. What is the initial management?", "choices": ["ETT (endotracheal intubation)", "CT brain", "MRI brain", "Raise head 30-45 degree", "IV dexamethasone"], "ans": 0, "exp": "ผู้ป่วยหมดสติ (GCS ต่ำ, withdrawal to pain) + Cushing's reflex (BP สูง 152/84, bradycardia PR 60, RR ต่ำ 10) + pupil ไม่เท่ากันไม่ตอบสนองแสง = ภาวะ raised ICP/herniation. Initial management ตามหลัก ABC คือ secure airway ด้วย ETT (GCS ≤ 8 ต้องใส่ท่อ) ก่อน แล้วจึงจัดการ ICP อื่น", "sys": "IV"}, {"topic": "Pediatrics", "q": "A 3 years old with no underlying disease presents with abdominal distention for 2 weeks. PE: Rt mass at RUQ 8×8 cm. CBC: Hct 37%, WBC normal. UA: RBC 30-50 cells, WBC 3-5 cells. What is the diagnosis?", "choices": ["Neuroblastoma", "Wilms tumor", "Hepatoblastoma", "Pheochromocytoma"], "ans": 1, "exp": "ก้อนในท้องเด็ก 3 ขวบ + ปัสสาวะมีเม็ดเลือดแดง (hematuria) ชี้ว่ามาจากไต = Wilms tumor (nephroblastoma). Neuroblastoma มักข้าม midline + ไม่มี hematuria, hepatoblastoma มาจากตับ AFP สูง, pheochromocytoma มี HT/เหงื่อออก", "sys": "II"}, {"topic": "Pediatrics", "q": "เด็กชาย 4 ปี ไข้ 2 วัน shortness of breath เมื่อคืน ปัสสาวะสีเข้ม. PE: BT 37.5°C, RR 40, PR 140, BP 100/60, moderate pale conjunctiva. CBC: Hb 5.0, WBC 15,000 (N80 L20), Platelet 390,000. UA: dark urine, Urobilinogen +ve, Blood 2+. What is management?", "choices": ["Force diuresis", "Urine alkalinization", "PRC transfusion", "Prednisolone", "IV immunoglobulin"], "ans": 2, "exp": "ไข้เป็นตัวกระตุ้น + ซีดเฉียบพลันรุนแรง (Hb 5.0) + ปัสสาวะสีเข้ม (hemoglobinuria, urobilinogen +) = acute hemolysis (นึกถึง G6PD deficiency). ซีดรุนแรงมีอาการ (เหนื่อย หัวใจเต้นเร็ว) → รักษาด้วย PRC transfusion + หยุดตัวกระตุ้น", "sys": "III"}, {"topic": "Pediatrics", "q": "คนไข้เด็ก มาด้วย vomiting and diarrhea. V/S ปกติ ตรวจเจอ hyperpigmented ที่ nipple และ palmar crease. Lab: hypoNa, hyperK น่าจะเป็น Addison disease. Most appropriate management?", "choices": ["3% NaCl", "HCO3", "Fludrocortisone", "Hydrocortisone"], "ans": 3, "exp": "Adrenal insufficiency/Addisonian crisis (hyperpigmentation, hypoNa/hyperK) → รักษาเฉียบพลันด้วย hydrocortisone (stress-dose มีทั้งฤทธิ์ gluco- และ mineralocorticoid) ร่วมกับ IV NSS. Fludrocortisone ใช้ maintenance ระยะยาว ไม่ใช่ภาวะเฉียบพลัน", "sys": "IV"}, {"topic": "Pediatrics", "q": "เด็กหญิงวัยรุ่น ตัวใหญ่ อ้วนมาก มี acanthosis nigricans. HbA1c 6%, FBS 83 mg/dL. Investigate อะไรดี", "choices": ["OGTT", "Insulin level", "C-peptide"], "ans": 0, "exp": "วัยรุ่นอ้วน + acanthosis nigricans (ภาวะดื้ออินซูลิน) + HbA1c 6% (ก้ำกึ่ง prediabetes) แต่ FBS ปกติ → ตรวจ OGTT (oral glucose tolerance test) เพื่อยืนยัน prediabetes/DM ที่ระดับ 2 ชม.หลังกินกลูโคส", "sys": "IV"}, {"topic": "Pediatrics", "q": "เด็กน้อยอ้วก ถ่ายเป็นเลือด (currant jelly stool). Diagnosis? (ต้นฉบับมีตัวเลือกไม่ครบ ใส่เท่าที่มี)", "choices": ["Intussusception"], "ans": 0, "exp": "เด็กเล็กอาเจียน + ถ่ายเป็นเลือดมูก (currant jelly stool) ± ก้อนไส้กรอกในท้อง = Intussusception (ลำไส้กลืนกัน). วินิจฉัยด้วย US (target sign) รักษาด้วย air/contrast enema reduction", "sys": "XI"}, {"topic": "Pediatrics", "q": "A child usually makes an abnormal sound. Sometimes he can control the symptom. No abnormal movement was observed. What is the diagnosis?", "choices": ["Tourette syndrome", "Tic disorder (vocal tic)"], "ans": 1, "exp": "มีแค่เสียงผิดปกติ (vocal tic) กดข่มได้ชั่วคราว และ 'ไม่มี' การเคลื่อนไหวผิดปกติ (ไม่มี motor tic) = tic disorder (persistent vocal tic). Tourette syndrome ต้องมีทั้ง motor และ vocal tics นานกว่า 1 ปี", "sys": "flex"}, {"topic": "Pediatrics", "q": "A 9 years old girl presents with a minor headache and stomachache and refuses to go to school. She is afraid that if something bad happens, she will not be with her mother. She sometimes dreams that she is alone and is found alone crying. PE: unremarkable. What is the most likely diagnosis?", "choices": ["Normal reaction", "Simple phobia", "Separation anxiety disorder", "Schizophrenia", "Sibling rivalry"], "ans": 2, "exp": "ปวดหัว/ปวดท้อง (somatic) + ไม่ยอมไปโรงเรียน + กลัวพลัดพรากจากแม่ (กลัวไม่ได้อยู่กับแม่) + ฝันว่าอยู่คนเดียว = Separation anxiety disorder", "sys": "V"}, {"topic": "Pediatrics", "q": "เด็กชอบป่วยวันธรรมดา ไม่ยอมไปโรงเรียน เสาร์อาทิตย์อาการดี อยู่กับแม่ตลอด กลัวแม่หาย. Diagnosis? (ต้นฉบับมีตัวเลือกไม่ครบ ใส่เท่าที่มี)", "choices": ["Social phobia", "Separation anxiety disorder"], "ans": 1, "exp": "ป่วยเฉพาะวันไปโรงเรียน หายในวันหยุด + ติดแม่ กลัวแม่หาย = Separation anxiety disorder. *ต้นฉบับไฮไลต์ social phobia ซึ่งไม่ตรง — social phobia คือกลัวการเข้าสังคม/ถูกจับจ้อง ไม่ใช่กลัวพลัดพรากจากผู้เลี้ยง*", "sys": "V"}, {"topic": "Pediatrics", "q": "เด็กผู้หญิง 3 ขวบ นน 19 กก. สูง 102 ซม. กินข้าววันละ 4 มื้อ นมวันละ 6 แก้ว. คำแนะนำที่เหมาะสม", "choices": ["ออกกำลังกาย", "เปลี่ยนนมจาก whole milk เป็น skim milk", "กินเท่าเดิม", "ลดข้าว", "ลดนมและข้าว"], "ans": 4, "exp": "เด็ก 3 ขวบ นน 19 กก. (เกินเกณฑ์ ปกติ ~14 กก.) = overweight จากพลังงานเกิน โดยเฉพาะนม 6 แก้ว/วัน (มากเกิน) + ข้าว 4 มื้อ → แนะนำลดปริมาณนมและข้าวลง (ลดพลังงานส่วนเกินทั้งสองแหล่ง)", "sys": "flex"}, {"topic": "Pediatrics", "q": "เด็ก มีไข้ 2 วัน barking cough. V/S: BT 38°C, SpO2 92%. What is the prevention of this disease?", "choices": ["Frequent hand washing", "Vaccination", "Wearing mask when going outside"], "ans": 0, "exp": "ไอเสียงก้อง (barking cough) = viral croup จาก parainfluenza virus ซึ่งยังไม่มีวัคซีนเฉพาะ. ป้องกันการแพร่เชื้อทางเดินหายใจ (droplet/contact) ด้วยการล้างมือบ่อย ๆ (frequent hand washing)", "sys": "I"}, {"topic": "Pediatrics", "q": "Five children visited the ER with bloody diarrhea and acute renal failure after eating together at a birthday party. What did they eat?", "choices": ["Soft boiled egg", "Beef hamburger", "Sushi", "Foie gras", "Pork chop"], "ans": 1, "exp": "ถ่ายเป็นเลือด + ไตวายเฉียบพลันเป็นกลุ่ม = Hemolytic Uremic Syndrome (HUS) จาก E. coli O157:H7 (Shiga toxin) ที่สัมพันธ์กับ 'เนื้อบดปรุงไม่สุก' (undercooked ground beef/hamburger) แบบคลาสสิก. *ต้นฉบับไฮไลต์ pork chop ซึ่งไม่ตรงกับ EHEC/HUS ที่โยงกับเนื้อวัวบด*", "sys": "XI"}, {"topic": "Pediatrics", "q": "A child presented with high grade fever, drowsiness and purple (purpuric) rash as in a picture. What is proper management?", "choices": ["Ciprofloxacin", "Rifampicin", "PGS (Penicillin G sodium)", "Colistin", "Cloxacillin"], "ans": 2, "exp": "ไข้สูง + ซึม + purpura/petechiae ทั่วตัว = meningococcemia (Neisseria meningitidis, ± Waterhouse-Friderichsen). รักษาด้วย Penicillin G (PGS) หรือ ceftriaxone. Rifampicin/ciprofloxacin ใช้เป็น prophylaxis ผู้สัมผัส ไม่ใช่การรักษา", "img": "https://cdn.jsdelivr.net/gh/MercenzK/Web-quiz-images@main/NL2-2021-Q205.png", "sys": "III"}, {"topic": "Pediatrics", "q": "A child presented with high grade fever, conjunctivitis, strawberry tongue, hand edema, lymphadenopathy. What is the most serious complication of this disease? (ตัวเลือกแต่งขึ้นมาเอง ต้นฉบับให้คำตอบว่า coronary aneurysm)", "choices": ["Valvular heart disease", "Myocarditis", "Arrhythmia", "Coronary artery aneurysm", "Pericardial effusion"], "ans": 3, "exp": "ไข้สูง + เยื่อบุตาแดง + strawberry tongue + มือบวม + ต่อมน้ำเหลืองโต = Kawasaki disease. ภาวะแทรกซ้อนที่ร้ายแรงที่สุดคือ coronary artery aneurysm (เส้นเลือดหัวใจโป่งพอง) → ต้องรักษาด้วย IVIG + aspirin ภายใน 10 วัน", "sys": "I"}, {"topic": "Pediatrics", "q": "A child presented with fever, mass at preauricular area on both sides (bilateral parotid swelling). What is the complication of this disease?", "choices": ["Myocarditis", "Orchitis"], "ans": 1, "exp": "ก้อนบริเวณหน้าหู 2 ข้าง (bilateral parotitis) = mumps (คางทูม). ภาวะแทรกซ้อนที่พบคือ orchitis (อัณฑะอักเสบ ในเด็กชายวัยหลังวัยรุ่น), รวมถึง aseptic meningitis, pancreatitis", "sys": "II"}, {"topic": "Pediatrics", "q": "A 14-day-old infant presented with eye redness (neonatal conjunctivitis). What is the treatment? (ต้นฉบับมีตัวเลือกไม่ครบ ใส่เท่าที่มี)", "choices": ["Erythromycin"], "ans": 0, "exp": "เยื่อบุตาอักเสบในทารกช่วงวันที่ 5-14 = Chlamydia trachomatis → รักษาด้วย oral erythromycin (systemic) เพื่อป้องกัน chlamydial pneumonia ร่วมด้วย", "sys": "XVI"}, {"topic": "Pediatrics", "q": "A 12 years old girl presented with tachypnea on day 7 of being diagnosed with dengue shock syndrome. PE: BT 36.5°C, RR 40/min. Lung - fine crepitation lower lung, decreased Rt breath sound. Skin - present of convalescent rash. What is proper management?", "choices": ["NB Salbutamol", "IV Diuretic", "IV Morphine", "IV Corticosteroids", "IV Aminophylline"], "ans": 1, "exp": "วันที่ 7 ของ dengue = convalescent (reabsorption) phase สารน้ำที่รั่วออกไปถูกดูดกลับ → fluid overload/pulmonary edema + pleural effusion (crepitation, breath sound ลดลง). รักษาด้วย IV diuretic (furosemide) เพื่อขับน้ำส่วนเกิน", "sys": "I"}, {"topic": "Pediatrics", "q": "A 5 years old girl presents with high grade fever and severe right ear pain. PE: BT 38.5°C, PR 110 bpm. Right ear effusion behind inflamed and bulging tympanic membrane. What is the appropriate treatment?", "choices": ["Cloxacillin", "Clindamycin", "Amoxicillin", "Cephalexin", "Ciprofloxacin"], "ans": 2, "exp": "เยื่อแก้วหูแดงโป่ง + มี effusion + ไข้ + ปวดหู = acute otitis media. ยา first-line คือ amoxicillin (high-dose) ครอบคลุมเชื้อหลัก S. pneumoniae, H. influenzae, M. catarrhalis", "sys": "I"}, {"topic": "Pediatrics", "q": "A 12-year-old boy arrives with pain and inflammation over the ball of his left foot and red streaks extending up the inner aspect of his leg. He remembers removing a wood splinter from the sole of his foot on the previous day. Which of the following is the most likely infecting organism?", "choices": ["C. perfringens", "S. aureus", "Strep Group A"], "ans": 2, "exp": "เส้นแดงลามขึ้นตามขา (lymphangitis) หลังบาดแผลที่เท้า = Group A Streptococcus (Streptococcus pyogenes) เป็นสาเหตุคลาสสิกของ lymphangitis/cellulitis ที่ลามเร็ว", "sys": "XII"}, {"topic": "Pediatrics", "q": "3 year old girl present with dysuria and fever. PE: BT 38.9°C, PR 110 bpm, RR 30, BP 90/60 mmHg. UA: sp.gr 1.025 turbid, WBC 20-30, RBC 5-10, sq 1-2, nitrite +ve. Which is correct UTI diagnosis?", "choices": ["10^4 E.coli in midstream urine", "10^3 E.coli in urine cath", "10^3 E. faecalis urine cath", "10^3 S. saprophyticus urine cath", "10^1 E.coli in suprapubic aspiration"], "ans": 4, "exp": "เกณฑ์วินิจฉัย UTI ขึ้นกับวิธีเก็บ: suprapubic aspiration = ขึ้นเชื้อเท่าไรก็ถือว่ามีความหมาย (แม้ 10^1); catheterized ต้อง ≥5×10^4; midstream clean-catch ต้อง ≥10^5. ดังนั้นข้อที่ถูกต้องคือ 10^1 E.coli จาก suprapubic (ข้ออื่นปริมาณไม่ถึงเกณฑ์ตามวิธีเก็บ)", "sys": "XIV"}, {"topic": "Pediatrics", "q": "Child with prolonged fever, palm and sole erythema, papular rash at trunk, bilateral conjunctival injection, Rt cervical LN tenderness. What is the complication of this disease?", "choices": ["Coronary aneurysm", "Myocarditis", "Pericarditis"], "ans": 0, "exp": "ไข้เรื้อรัง + ฝ่ามือฝ่าเท้าแดง + ผื่นที่ลำตัว + เยื่อบุตาแดง 2 ข้าง + ต่อมน้ำเหลืองคอโต = Kawasaki disease → ภาวะแทรกซ้อนที่สำคัญคือ coronary artery aneurysm", "sys": "I"}, {"topic": "Pediatrics", "q": "เด็กปวดแก้มสองข้าง (bilateral parotitis) ได้วัคซีนตาม EPI. ต้องหาภาวะแทรกซ้อนอะไรเพิ่ม (ต้นฉบับมีตัวเลือกไม่ครบ ใส่เท่าที่มี)", "choices": ["Orchitis"], "ans": 0, "exp": "คางทูม (mumps parotitis) → ต้องเฝ้าระวัง/ตรวจหา orchitis (อัณฑะอักเสบ) ในเด็กชาย รวมถึง aseptic meningitis, pancreatitis", "sys": "VI"}, {"topic": "Pediatrics", "q": "A 2 year-old boy presents with fever, reddening of eye & mouth, erythematous swelling of palms and soles with periungual desquamation, enlargement of cervical LN. Treatment initiates this patient to avoid following consequences?", "choices": ["Endarteritis obliterans", "Rheumatic Heart disease", "Coronary artery aneurysm", "Leukocytoclastic vasculitis", "Cerebral venous sinus thrombosis"], "ans": 2, "exp": "Kawasaki disease (ไข้ + ตา/ปากแดง + ฝ่ามือฝ่าเท้าบวมแดง + ลอกรอบเล็บ + ต่อมน้ำเหลืองโต). การรักษาด้วย IVIG + aspirin ภายใน 10 วัน มีเป้าหมายเพื่อป้องกัน coronary artery aneurysm. *ต้นฉบับไฮไลต์ endarteritis obliterans ซึ่งไม่ใช่ผลลัพธ์หลักที่ต้องการป้องกัน*", "sys": "I"}, {"topic": "Orthopedics", "q": "A 20-year-old basketball player presented with a finger as in a picture (mallet finger — DIP ยืดไม่ขึ้น). What is the appropriate management? (ต้นฉบับมีตัวเลือกไม่ครบ ใส่เท่าที่มี)", "choices": ["Buddy splint", "Aluminium splint", "K-wire"], "ans": 1, "exp": "นิ้วปลายงอเหยียดไม่ขึ้น (mallet finger — extensor tendon avulsion ที่ DIP) → รักษาด้วยการดาม DIP ให้เหยียดตรงต่อเนื่อง 6-8 สัปดาห์ด้วย aluminium (mallet) splint. K-wire ใช้เมื่อมี bony fragment ใหญ่/ไม่ตอบสนอง", "img": "https://cdn.jsdelivr.net/gh/MercenzK/Web-quiz-images@main/NL2-2021-Q216.png", "sys": "XIII"}, {"topic": "Orthopedics", "q": "A Thai male 50 years old presents with chronic bilateral knee pain. He complained about epigastric pain for 3 months. He took OTC ibuprofen for 6 months to relieve his knee pain. PE: no abdominal tenderness, bilateral valgus knee, crepitation both knees. EGD: diffuse erythematous gastritis. Histopathology: reactive gastritis suspicious from medication-induced. What is the best management?", "choices": ["Add omeprazole", "Stop ibuprofen, add omeprazole", "Add alginic acid (gaviscon)", "Change ibuprofen to paracetamol and orphenadrine"], "ans": 1, "exp": "NSAID-induced gastritis (ibuprofen 6 เดือน + reactive gastritis) → best management คือหยุดยาต้นเหตุ (ibuprofen) และเพิ่ม PPI (omeprazole) เพื่อรักษาแผลกระเพาะ. การให้ PPI อย่างเดียวโดยไม่หยุด NSAID ไม่เพียงพอ", "sys": "XIII"}, {"topic": "Orthopedics", "q": "เด็กชาย 6 ขวบ มา รพ ด้วยไม่ยอมยืนด้วยขาซ้าย 2 สัปดาห์. PE: BT 38.6°C, ขาซ้ายอยู่ในท่า flex hip ตลอดเวลา, pain on motion, บวม. CBC: WBC 25,000 PMN predominate. Film hip ดูเหมือนปกติ. จะส่ง investigation อะไร", "choices": ["U/S (ultrasound of hip)", "ESR", "Bone scan", "CT", "MRI"], "ans": 0, "exp": "ไข้ + ไม่ลงน้ำหนัก + สะโพกงอค้าง (position of comfort) + WBC สูง PMN + film ปกติ = สงสัย septic arthritis of hip. Investigation ที่เหมาะสมคือ ultrasound สะโพก (ตรวจหา joint effusion และใช้นำการเจาะดูดข้อ = diagnosis ยืนยัน)", "sys": "XIII"}, {"topic": "Orthopedics", "q": "ผู้ป่วย 70 ปี ปวดเข่า 2 ข้าง ปวดมากตอนแบกของ. PE: Genu varus, crepitation. Diagnosis? (ตัวเลือกแต่งขึ้นมาเอง ต้นฉบับไม่มีตัวเลือก)", "choices": ["Rheumatoid arthritis", "Osteoarthritis of knee", "Gouty arthritis", "Septic arthritis", "Pseudogout (CPPD)"], "ans": 1, "exp": "ผู้สูงอายุ ปวดเข่า 2 ข้างเวลาลงน้ำหนัก/แบกของ + genu varus (เข่าโก่ง) + crepitation = primary osteoarthritis of knee (ข้อเข่าเสื่อม)", "sys": "XIII"}, {"topic": "Psychiatry", "q": "A 28 years old female presented with left wrist pain after falling at 2 AM. PE: BP 120/80, PR 80, poor eye contact, multiple stage contusion at back, costal margin, and mild contusion at left wrist. She wants to go home due to concern about a 7-days old baby. What is the initial management?", "choices": ["Tell the police", "Film left wrist", "More history taking", "Send CBC, PT, PTT", "D/C with ibuprofen"], "ans": 2, "exp": "รอยฟกช้ำหลายระยะ (multiple stage contusion) ในตำแหน่งที่ไม่สอดคล้องกับการล้ม + poor eye contact + มีลูกอ่อน 7 วัน = สงสัย intimate partner violence (ความรุนแรงในครอบครัว). Initial management คือซักประวัติเพิ่ม (สร้างความไว้วางใจ ประเมินความปลอดภัย) ไม่ใช่แจ้งตำรวจทันทีโดยไม่ได้รับความยินยอม", "sys": "V"}, {"topic": "Orthopedics", "q": "ผู้ป่วยชาย ปวดหลัง. PE: Rt EHL grade 4, decreased anteromedial sensation of leg. Film: L-S spine osteophyte L4-5 and narrow disc space. What is diagnosis? (ต้นฉบับมีตัวเลือกไม่ครบ ใส่เท่าที่มี)", "choices": ["Disc herniation", "Spinal stenosis", "Spondylolisthesis"], "ans": 0, "exp": "อ่อนแรง EHL (extensor hallucis longus = L5) + ชาด้าน anteromedial ของขา + ช่องหมอนรองกระดูก L4-5 แคบ = herniated disc L4-5 กดรากประสาท L5 (L5 radiculopathy). Spinal stenosis ให้ neurogenic claudication 2 ข้างสัมพันธ์ท่าทาง", "sys": "XIII"}, {"topic": "Psychiatry", "q": "A 30-year-old female presents with a history of palpitation, chest tightness, dizziness and fear of dying 3 times in a month. This happened unexpectedly and she has a fear of going out alone. What is the most appropriate management?", "choices": ["Propranolol", "Diazepam", "Fluoxetine", "Carbamazepine"], "ans": 2, "exp": "panic attack ที่เกิดขึ้นเองซ้ำ ๆ (ใจสั่น แน่นหน้าอก กลัวตาย) + กลัวออกนอกบ้านคนเดียว = panic disorder with agoraphobia. การรักษาหลักระยะยาวคือ SSRI (fluoxetine). benzodiazepine ใช้ระยะสั้นเท่านั้น", "sys": "V"}, {"topic": "Psychiatry", "q": "A 14-year-old female was brought to the ER by her mother 1 hour after taking 20 paracetamol pills. She admits to having done the same thing 6 months ago after her father and mother got divorced. PE: patient is irritable, refuses to do anything. What is the diagnosis?", "choices": ["Adjustment disorder", "Adolescent turmoil", "Borderline disorder", "Anxiety disorder", "Major depressive disorder"], "ans": 0, "exp": "พฤติกรรมทำร้ายตัวเอง (กินยาเกินขนาด) ที่สัมพันธ์กับความเครียดที่ระบุได้ (พ่อแม่หย่า) ภายในไม่กี่เดือน + อารมณ์หงุดหงิด = adjustment disorder. borderline PD มักไม่วินิจฉัยก่อนอายุ 18 และต้องมี pattern ที่ pervasive", "sys": "V"}, {"topic": "Psychiatry", "q": "A 50-year-old man presents with fever, chill, agitation and confusion. He has a history of long term medical use for mental illness. PE: BT 40°C, HR 110 bpm, BP 140/100 mmHg, RR 20/min, muscle rigidity, diaphoresis with disorientation. What is the most likely cause?", "choices": ["Alprazolam", "Haloperidol", "Fluoxetine", "Lithium", "Sodium valproate"], "ans": 1, "exp": "ไข้สูง + เกร็งกล้ามเนื้อ (rigidity) + autonomic instability + สับสน = Neuroleptic Malignant Syndrome (NMS) ซึ่งเกิดจากยา antipsychotic → haloperidol", "sys": "V"}, {"topic": "Psychiatry", "q": "เด็กสาว ขี้อายมาตั้งแต่เด็ก รู้สึกเข้ากับเพื่อนไม่ได้ รู้สึกว่าตัวเองไม่ดีพอ ร่วมกับกินเยอะ นอนเยอะ น้ำหนักขึ้น (เรื้อรัง). ถามว่าเป็นอะไร", "choices": ["Major depressive disorder", "Avoidant personality", "Dysthymia (persistent depressive disorder)", "Social phobia"], "ans": 2, "exp": "อารมณ์ซึมเศร้าเรื้อรังระดับต่ำ ๆ มานาน + อาการแบบ atypical (กินเยอะ นอนเยอะ น้ำหนักขึ้น) + รู้สึกด้อยค่า = dysthymia (persistent depressive disorder). *มีลักษณะ avoidant ปนอยู่ แต่อาการ vegetative ชี้ไปทาง depressive disorder เรื้อรัง*", "sys": "V"}, {"topic": "Psychiatry", "q": "เด็กหญิงวัยรุ่น ขาดเรียนหลายเดือน เลือกกินอาหาร/คุมอาหาร (diet control) น้ำหนักลดลงมาก v/s stable ดูผอมมาก. Diagnosis? (ต้นฉบับมีตัวเลือกไม่ครบ ใส่เท่าที่มี)", "choices": ["Anorexia nervosa", "Bulimia nervosa"], "ans": 0, "exp": "จำกัดอาหาร/คุมอาหารเข้มงวด + น้ำหนักลดมาก + ผอมมาก (low body weight) = anorexia nervosa (restricting type). bulimia มักน้ำหนักปกติ + binge/purge", "sys": "V"}, {"topic": "Psychiatry", "q": "A 75 years old male comes for an annual check up. No U/D. Last year's check up was normal. In the past 6 months he had a memory problem — cannot remember visitors he has not met for decades, and forgot some things in shopping list. He is homebound, no stress. What is diagnosis?", "choices": ["Normal forgetfulness", "Dementia", "Major depressive disorder", "Ill-anxiety disorder", "Mild cognitive impairment"], "ans": 4, "exp": "ความจำถดถอยเกินวัยปกติแต่ยังทำกิจวัตรประจำวัน (ADL) ได้ ไม่กระทบการดำเนินชีวิต = mild cognitive impairment (MCI). dementia ต้องมี functional impairment ในชีวิตประจำวันร่วมด้วย", "sys": "V"}, {"topic": "Psychiatry", "q": "A 70-year-old woman underwent an operation for a right hip fracture. After 2 days, she says that she saw ghosts and climbed out of bed. PE: CNS - disorientation, inattention. What is proper treatment?", "choices": ["Haloperidol", "Amitriptyline", "Alprazolam", "Diazepam", "Sodium valproate"], "ans": 0, "exp": "หลังผ่าตัด 2 วัน + เห็นภาพหลอน + disorientation + inattention (อาการขึ้น ๆ ลง ๆ) = postoperative delirium. รักษาภาวะกระวนกระวายด้วย low-dose haloperidol. benzodiazepine ทำให้ delirium แย่ลง (ยกเว้น alcohol withdrawal)", "sys": "V"}, {"topic": "Psychiatry", "q": "ผู้ป่วยหญิง มีอาการกลัวต้องออกไปข้างนอก เช่น ไปขึ้นรถไฟฟ้า มีใจสั่น (palpitation) ร่วมด้วย เป็นมาหลายเดือน อย่างอื่นปกติดี. Diagnosis? (ต้นฉบับมีตัวเลือกไม่ครบ ใส่เท่าที่มี)", "choices": ["Panic disorder", "Agoraphobia", "Specific phobia", "Adjustment disorder"], "ans": 1, "exp": "กลัวสถานการณ์ที่หนีออกยาก/ขอความช่วยเหลือยาก เช่น ที่สาธารณะ รถไฟฟ้า = agoraphobia. ต่างจาก panic disorder ที่เด่นเรื่อง panic attack เกิดเองไม่คาดคิดซ้ำ ๆ", "sys": "V"}, {"topic": "Psychiatry", "q": "A 30 years old female with irritable mood, insomnia and chronic headache for 6 months after her work got promoted, with impaired work function. What is the specific treatment?", "choices": ["Clonazepam", "Lithium", "Fluoxetine", "Sertraline", "Valproate"], "ans": 2, "exp": "อาการวิตกกังวล/ซึมเศร้าเรื้อรังหลังเจอความเครียด (เลื่อนตำแหน่ง) + กระทบการทำงาน → รักษาจำเพาะด้วย SSRI (fluoxetine). *sertraline ก็เป็น SSRI ที่ใช้ได้เช่นกัน; benzodiazepine ใช้เสริมระยะสั้น*", "sys": "V"}, {"topic": "Psychiatry", "q": "A 25 years old woman presented with sudden paresthesia of right hand and foot with mild weakness of left hand. The event occurred after she drove and hit another car at slow speed. She denied LOC and confusion. PE: unremarkable. What is the most likely diagnosis?", "choices": ["Adjustment disorder", "Factitious disorder", "Acute stress disorder", "Conversion disorder", "Panic disorder"], "ans": 3, "exp": "อาการทางระบบประสาท (ชา/อ่อนแรง) ที่ไม่เข้ากับ anatomy + เกิดหลังเหตุการณ์เครียด (อุบัติเหตุ) + ตรวจร่างกายปกติ = conversion disorder (functional neurological symptom disorder)", "sys": "V"}, {"topic": "Psychiatry", "q": "A 30 years old female presented with irritable mood and agitation. She works all day and nights, spends all money for many creative projects, and has a history of depressive episodes and suicidal attempts. What is the most likely diagnosis?", "choices": ["Bipolar disorder", "Conversion disorder", "Schizoaffective disorder", "Persistent depressive disorder"], "ans": 0, "exp": "อาการ mania (นอนน้อย ใช้เงินเยอะ ทำโปรเจกต์เยอะ หงุดหงิด พลังงานสูง) + ประวัติ depressive episodes = bipolar disorder (มี manic + depressive episodes)", "sys": "V"}, {"topic": "Psychiatry", "q": "นักแสดงหญิง กังวลเรื่องรูปร่าง/กลัวอ้วน 1 เดือนก่อนมามีคลื่นไส้อาเจียน ปวดตามตัว และได้ยินเพื่อน ๆ นินทาตนเอง (paranoia). น่าจะใช้สารอะไร", "choices": ["Amphetamine", "PTSD", "Cocaine", "Cannabis"], "ans": 0, "exp": "กังวลเรื่องหุ่น/กลัวอ้วน (ใช้ยาลดน้ำหนัก) + อาการ paranoid (ได้ยินคนนินทา) + คลื่นไส้ ปวดตัว (withdrawal) = amphetamine (ยากระตุ้น ใช้คุมน้ำหนัก ทำให้เกิด psychosis/paranoia)", "sys": "V"}, {"topic": "Psychiatry", "q": "ผู้หญิงขับรถชนแล้วมีอาการอ่อนแรง (weakness) โดยตรวจร่างกายไม่พบพยาธิสภาพ. เป็นอะไร (ต้นฉบับมีตัวเลือกไม่ครบ ใส่เท่าที่มี)", "choices": ["Factitious disorder", "Conversion disorder"], "ans": 1, "exp": "อ่อนแรงเกิดขึ้นหลังเหตุการณ์เครียด (อุบัติเหตุ) โดยไม่มีสาเหตุทางกาย = conversion disorder. factitious disorder คือแกล้งป่วยเพื่อรับบทผู้ป่วย (โดยไม่มีผลประโยชน์ภายนอก)", "sys": "V"}, {"topic": "Psychiatry", "q": "A 65 year-old retired woman presented with recent memory impairment 6 months after her husband passed away. She has poor concentration, decreased interest in her hobbies, insomnia, and weight loss. She sometimes wishes for her death but denies suicidal idea. No underlying disease nor medication. What is the most likely diagnosis?", "choices": ["Adjustment disorder", "Generalized anxiety disorder", "Major depressive disorder", "Somatic symptom disorder", "Major neurocognitive disorder"], "ans": 2, "exp": "อาการซึมเศร้าครบ (anhedonia, insomnia, น้ำหนักลด, สมาธิแย่, อยากตาย) หลังสูญเสียคู่สมรส ≥ 6 เดือน + ความจำแย่ (pseudodementia จากซึมเศร้า) = major depressive disorder", "sys": "V"}, {"topic": "Psychiatry", "q": "ชายสูงอายุ มาด้วย fever with chill, agitation, confusion หลังกินยาหลายตัว. PE: BT 40°C, PR 110, RR 20, BP ปกติ, muscle rigidity, disorientation, diaphoresis. Cause น่าจะจากอะไร", "choices": ["Alprazolam", "Lithium", "Sertraline", "Haloperidol", "Sodium valproate"], "ans": 3, "exp": "ไข้สูง + rigidity + autonomic instability + สับสน หลังได้ยา antipsychotic = Neuroleptic Malignant Syndrome (NMS) → haloperidol", "sys": "V"}, {"topic": "Ophthalmology", "q": "A 14-year-old boy presented with cannot close his Lt eye and drooling from his Lt lip for 1 day. No pain. No other neurological deficit. What is the most appropriate treatment?", "choices": ["Gabapentin", "Prednisolone"], "ans": 1, "exp": "อ่อนแรงกล้ามเนื้อใบหน้าครึ่งซีก (หลับตาไม่สนิท + มุมปากตก น้ำลายไหล) แบบ lower motor neuron เส้นเดียว ไม่มี deficit อื่น = Bell's palsy. รักษาด้วย corticosteroid (prednisolone) เริ่มเร็วภายใน 72 ชม. + ดูแลกระจกตา", "sys": "VII"}, {"topic": "Ophthalmology", "q": "A 25-year-old female developed progressive vision loss of the right eye for 5 days. Right eye - pain provoked by eye movement & globe palpation, loss of color vision + cecocentral scotoma. VA: Right 6/24, Left 6/6. PE: hyperemia + swelling of optic disc, +RAPD Rt eye. What is the diagnosis?", "choices": ["Optic neuritis", "Papilledema", "Compressive optic neuropathy", "Anterior ischemic optic neuropathy", "Hereditary optic neuropathy"], "ans": 0, "exp": "หญิงสาว + สูญเสียการมองเห็นข้างเดียวแบบมีปวดเวลากรอกตา + เห็นสีผิดเพี้ยน (dyschromatopsia) + RAPD + จานประสาทตาบวม = optic neuritis (มักสัมพันธ์ MS)", "sys": "VII"}, {"topic": "Ophthalmology", "q": "An 84-year-old female presents with eye irritation and tearing for months, with off and on redness at the nasal side of eyes. PE: both eyes 20/25, pink triangular tissue at limbus extending to cornea. What is management?", "choices": ["Topical steroid", "Artificial tear", "Topical mupirocin", "Excision", "I&D"], "ans": 1, "exp": "เนื้อสามเหลี่ยมสีชมพูจาก limbus เข้าหากระจกตา = pterygium (ต้อเนื้อ). ขนาดเล็ก VA ดี มีแค่ระคายเคือง → รักษาตามอาการด้วย artificial tears. ผ่าตัด (excision) เมื่อบังแกนการมองเห็น/โตมาก/รบกวนความสวยงาม", "sys": "VII"}, {"topic": "Ophthalmology", "q": "Acute pain with visual loss at Rt eye. PE: dilated (mid-dilated) pupil Rt eye, shallow anterior chamber, conjunctival injection. What is the proper investigation?", "choices": ["VA", "Confrontation test", "Tonometry", "External eye movement"], "ans": 2, "exp": "ตาแดงปวดเฉียบพลัน + รูม่านตาขยายค้าง + ช่องหน้าลูกตาตื้น = acute angle-closure glaucoma → investigation ที่เหมาะสมคือ tonometry (วัดความดันลูกตา IOP ซึ่งจะสูงมาก)", "sys": "VII"}, {"topic": "Ophthalmology", "q": "A 68-year-old woman presents with a left upper eyelid mass for 1 month. Not painful, not growing. PE: 4-mm round nodule, well demarcated and smooth surface on left upper eyelid. What is the most appropriate management?", "choices": ["Warm compression and oral antibiotic", "Intralesional steroid injection", "Incisional biopsy", "Incision and curettage", "Excisional biopsy"], "ans": 3, "exp": "ก้อนเปลือกตาไม่เจ็บ เรื้อรัง กลม ขอบชัด = chalazion (ต้อกุ้งยิงชนิดไม่อักเสบ). ก้อนที่คงอยู่นาน ~1 เดือน รักษาด้วย incision and curettage. (chalazion เป็น granuloma ปลอดเชื้อ ไม่จำเป็นต้องกิน antibiotic)", "sys": "VII"}, {"topic": "Ophthalmology", "q": "Patient had done facial filler injection then presented with Rt eye acute painless visual loss (image shows CRAO). What is the diagnosis? (ตัวเลือกแต่งขึ้นมาเอง ต้นฉบับไม่มีตัวเลือก)", "choices": ["Central retinal vein occlusion (CRVO)", "Optic neuritis", "Retinal detachment", "Vitreous hemorrhage", "Central retinal artery occlusion (CRAO)"], "ans": 4, "exp": "สูญเสียการมองเห็นเฉียบพลันแบบไม่ปวดหลังฉีด filler ใบหน้า = central retinal artery occlusion (CRAO) จาก filler อุดหลอดเลือด (retrograde embolization). จอตาซีด + cherry-red spot", "sys": "VII"}, {"topic": "Ophthalmology", "q": "ผู้ชายขี่รถจักรยานยนต์ แล้วรู้สึกระคายเคืองตาเวลากระพริบตา. VA 20/20, cornea clear. What is the proper investigation?", "choices": ["Upper lid eversion", "Fluorescein stain", "IOP measurement"], "ans": 0, "exp": "รู้สึกเคืองเวลากระพริบตา + ขี่มอเตอร์ไซค์ (ลม/ผงเข้าตา) + กระจกตาใส = สงสัย subtarsal foreign body ใต้เปลือกตาบน → ตรวจด้วยการปลิ้นเปลือกตาบน (upper lid eversion) หา FB", "sys": "VII"}, {"topic": "Ophthalmology", "q": "74 y/o female, both eyes tearing and irritation, redness at nasal side. PE: VA 20/25 both eyes, no injection, pink triangular fibrotic tissue 1 mm extended to cornea. Management?", "choices": ["Dexamethasone eye drop", "Artificial tear", "Antihistamine eye drop", "Excision"], "ans": 1, "exp": "pterygium ขนาดเล็ก (1 mm) VA ดี มีแค่ระคายเคือง → artificial tears ตามอาการ", "sys": "VII"}, {"topic": "Ophthalmology", "q": "หญิงอายุมาก เคืองตาด้าน nasal 2 ข้าง น้ำตาไหล ตรวจพบ pterygium at nasal side both eyes เลย limbus เข้าไปเล็กน้อย, อื่น ๆ ปกติ. Management?", "choices": ["Dexamethasone eye drop", "Polymyxin eye drop", "Artificial tear", "NSAIDs eye drop", "Pterygium excision"], "ans": 2, "exp": "pterygium ขนาดเล็ก อาการน้อย → รักษาตามอาการด้วย artificial tears. ผ่าตัดเมื่อโตเข้าใกล้/บังแกนการมองเห็น", "sys": "VII"}, {"topic": "Ophthalmology", "q": "หญิง มาด้วยตา 2 ข้าง tearing, irritating หลายเดือน ตาแดงด้าน nasal. PE: VA 20/25 both eyes, no ciliary injection, fibrovascular tissue extending from limbus to cornea 1 mm. จะทำอะไรดี", "choices": ["Dexamethasone eye drop", "Diclofenac eye drop", "Polymyxin B eye drop", "Artificial tear", "Excision of fibrovascular membrane"], "ans": 3, "exp": "pterygium ขนาดเล็ก (1 mm) VA ดี ไม่มี ciliary injection → รักษาตามอาการด้วย artificial tears", "sys": "VII"}, {"topic": "ENT", "q": "A man presented with a tender mass at the right peritonsillar area with uvular deviation. What should be done next?", "choices": ["Incision & drainage", "External drainage", "Needle aspiration"], "ans": 2, "exp": "ก้อนกดเจ็บบริเวณ peritonsillar + ลิ้นไก่เบี้ยว = peritonsillar abscess (ฝีรอบทอนซิล). ขั้นต่อไปคือ needle aspiration (ทั้งวินิจฉัยและระบายหนอง) ± I&D + antibiotic", "sys": "VIII"}, {"topic": "ENT", "q": "A 20 years old female presented with vertigo for 2 days with a history of URI 3 weeks ago. There was neither hearing loss nor tinnitus. PE: spontaneous nystagmus to the right side, normal otoscope, normal neuro exam, Weber no lateralization, Rinne positive both ears. What is the most likely diagnosis?", "choices": ["Vestibular neuritis", "Labyrinthitis", "Acoustic neuroma", "Meniere's disease", "BPPV"], "ans": 0, "exp": "เวียนหัวต่อเนื่องหลัง URI + 'ไม่มี' การได้ยินลดลง/tinnitus + การได้ยินปกติ = vestibular neuritis. Labyrinthitis จะมีการได้ยินลดลงร่วม; Meniere มี hearing loss + tinnitus + aural fullness", "sys": "VIII"}, {"topic": "ENT", "q": "After a shooting practice, a 17-year-old man presents with continuous buzzing noise in his right ear for 2 days. He still can hear normal conversation. PE: normal eardrum, Weber no lateralization, Rinne AC>BC both ears. What is the most likely diagnosis?", "choices": ["Otosclerosis", "Acoustic trauma", "Otomastoiditis", "Meniere's disease", "Ossicular chain disruption"], "ans": 1, "exp": "เสียงดังจากปืน (loud noise exposure) → tinnitus + sensorineural hearing loss ความถี่สูง (Rinne AC>BC = ไม่ใช่ conductive) = acoustic trauma / noise-induced hearing loss", "sys": "VIII"}, {"topic": "ENT", "q": "A 45 year old male presents with swelling and erythema at bilateral upper neck and chin for 2 days. PE: BT 38°C, RR 24, PR 100, mild dyspnea, generalized swelling and erythema at submental + bilateral submandibular area, swelling at floor of mouth with tongue protrusion. What is the diagnosis?", "choices": ["Peritonsillar abscess", "Parapharyngeal abscess", "Ludwig's angina", "Retropharyngeal abscess", "Submandibular space abscess"], "ans": 2, "exp": "การติดเชื้อลามทั้ง submental + submandibular 2 ข้าง + พื้นปากบวมดันลิ้น + เริ่มหายใจลำบาก = Ludwig's angina (cellulitis ของ floor of mouth) — ภาวะฉุกเฉินที่ต้องเฝ้าระวัง airway", "sys": "VIII"}, {"topic": "ENT", "q": "ให้รูป impacted cerumen (ขี้หูอุดตัน). What is the diagnosis? (ตัวเลือกแต่งขึ้นมาเอง ต้นฉบับไม่มีตัวเลือก)", "choices": ["Otomycosis", "Foreign body in ear canal", "Cholesteatoma", "Impacted cerumen", "Acute otitis media"], "ans": 3, "exp": "ก้อนขี้หู (cerumen) อุดตันช่องหูภายนอก = impacted cerumen. รักษาด้วย cerumenolytic / irrigation / manual removal", "sys": "VIII"}, {"topic": "ENT", "q": "Patient with bilateral submandibular swelling and tongue protrusion. What is the diagnosis?", "choices": ["Submandibular abscess", "Ludwig's angina", "Peritonsillar abscess"], "ans": 1, "exp": "บวม submandibular 2 ข้าง + ดันลิ้น = Ludwig's angina (การติดเชื้อ floor of mouth 2 ข้าง เสี่ยงอุดกั้นทางเดินหายใจ)", "sys": "VIII"}, {"topic": "ENT", "q": "Presented with thyroid nodule 3 cm, TFT normal. What is proper management?", "choices": ["FNA", "Ultrasound", "Thyroid scan"], "ans": 0, "exp": "ก้อนไทรอยด์ขนาด 3 ซม. + TFT ปกติ (euthyroid) → ทำ FNA (fine needle aspiration) เพื่อดู cytology (มักทำภายใต้ ultrasound). thyroid scan ใช้เมื่อ TSH ต่ำ (สงสัย hot nodule)", "sys": "VIII"}, {"topic": "ENT", "q": "Acute otitis externa in a long-standing DM patient (beware malignant otitis externa). Which antibiotic?", "choices": ["Ceftriaxone", "Ceftazidime"], "ans": 1, "exp": "malignant (necrotizing) otitis externa ในผู้ป่วยเบาหวาน เกิดจาก Pseudomonas aeruginosa → ต้องใช้ยาคลุม Pseudomonas เช่น ceftazidime (หรือ ciprofloxacin/piperacillin-tazobactam)", "sys": "VIII"}, {"topic": "Forensic", "q": "A 40-year-old male was found dead in a closely sealed car in the driver seat. Inside the car, a stove was found. Postmortem change: livor mortis was blanchable dark red (cherry-red) color at back and buttock. What is the cause of death?", "choices": ["Environmental asphyxia", "Cyanide toxicity", "Carbon monoxide toxicity", "Methane toxicity", "Hydrogen sulfide toxicity"], "ans": 2, "exp": "รถปิดสนิท + มีเตาเผาไหม้ในรถ + livor mortis สีแดงสด (cherry-red) = carbon monoxide poisoning (CO จับ Hb เป็น carboxyhemoglobin สีแดงสด)", "sys": "general"}, {"topic": "Forensic", "q": "A 16-year-old girl was sexually assaulted 3 days ago. PE: two oval marks at neck. PV: new tear posterior fourchette with bleeding. Spermatozoa and acid phosphatase were tested negative. What is true about this case?", "choices": ["Oval mark is bite mark", "Acid phosphatase is false negative", "No sperm indicates no sexual intercourse", "New tear indicated vaginal penetration", "Oval mark indicated sexual assault"], "ans": 3, "exp": "3 วันหลังเหตุ การตรวจไม่พบ sperm/acid phosphatase เป็นเรื่องปกติ (สลายภายใน ~48-72 ชม.) ไม่ใช่ false negative และไม่ได้แปลว่าไม่มีการร่วมเพศ. รอยฉีกใหม่ที่ posterior fourchette บ่งชี้การสอดใส่ทางช่องคลอด (penetration) จึงเป็นข้อที่ถูก", "sys": "general"}, {"topic": "Forensic", "q": "A 50 years old man was crushed by a truck, admitted with hypovolemic shock (liver laceration + femur fracture). Surgery successful, discharged. One week later he developed MI, admitted to CCU; 2 weeks later developed bronchopneumonia progressing to septic shock and died. What is the cause of death that should be written on the death certificate?", "choices": ["Septicemia", "Massive blood loss", "Liver rupture", "Fracture of femur", "Traffic injury"], "ans": 4, "exp": "ใบมรณบัตรระบุ 'underlying cause of death' = เหตุการณ์แรกที่เริ่มลูกโซ่นำไปสู่การตาย. ทุกอย่าง (shock → MI → pneumonia → sepsis) สืบเนื่องจากอุบัติเหตุจราจร (traffic injury) จึงเป็น underlying cause", "sys": "general"}, {"topic": "Forensic", "q": "A 45-year-old female was found dead in the middle of the road. Police suspected traffic injury. Her back has a patterned mark. What is the cause of the mark? (ต้นฉบับมีตัวเลือกไม่ครบ ใส่เท่าที่มี)", "choices": ["Tyre mark"], "ans": 0, "exp": "รอยลายบนหลังผู้ถูกรถทับ = tyre mark (รอยดอกยางรถ) — เป็น patterned abrasion/bruise ที่บ่งชี้ว่าถูกล้อรถทับ", "img": "https://cdn.jsdelivr.net/gh/MercenzK/Web-quiz-images@main/NL2-2021-Q258.png", "sys": "general"}, {"topic": "Forensic", "q": "A case of gunshot injury (image shows a round central hole surrounded by wide soot blackening and seared margins). What can be assumed from this wound?", "choices": ["Exit wound", "Close contact gunshot wound"], "ans": 1, "exp": "มีเขม่าดำ (soot) + ขอบไหม้เกรียม (searing) รอบรูกระสุน = บาดแผลกระสุนทางเข้าระยะประชิด/สัมผัส (close-contact entrance wound). แผลทางออก (exit) จะไม่มีเขม่า ขอบปลิ้นออก", "img": "https://cdn.jsdelivr.net/gh/MercenzK/Web-quiz-images@main/NL2-2021-Q259.png", "sys": "general"}, {"topic": "Forensic", "q": "แผลที่ขมับกะโหลก เป็นรอยกระสุนกลม ไม่แตกเป็นรูปดาว มีรอยดินปืน (tattooing/stippling) แต่ไม่มีเขม่า (soot). คิดว่าเกิดจากระยะไหน", "choices": ["Blast wound", "Stab wound", "Near/Close (intermediate) range", "Contact range", "Long distance range"], "ans": 2, "exp": "มี powder tattooing (stippling) แต่ 'ไม่มี' soot และไม่ stellate = intermediate (near/close) range. Contact = มี soot + stellate + muzzle imprint; distant = ไม่มีทั้ง soot และ tattooing", "img": "https://cdn.jsdelivr.net/gh/MercenzK/Web-quiz-images@main/NL2-2021-Q260.png", "sys": "general"}, {"topic": "Forensic", "q": "A man brought to ER after traffic injury: fractures Lt 6th-8th ribs, decreased breath sound Lt lung, received CPR before death. Autopsy: Rt butterfly fracture of tibia, multiple abrasions at Lt trunk, CXR Lt hemothorax. What is the sign that indicates traffic injury?", "choices": ["Hemothorax due to rib fractures", "Brush abrasions are dice injury", "Injury from side injury", "Tibial fracture is from a bumper injury", "Was hit with a motorcycle"], "ans": 3, "exp": "butterfly (wedge) fracture ของกระดูก tibia = bumper fracture คลาสสิกของคนเดินถนนที่ถูกกันชนรถชน บ่งชี้ว่าเป็น traffic injury และบอกทิศทางการชน", "sys": "general"}, {"topic": "Forensic", "q": "เด็กหญิง GA 16 wk มากับแม่ ขอทำแท้งเพราะตั้งครรภ์จากการถูกล่วงละเมิดทางเพศ (sexual assault) โดยเพื่อนร่วมชั้น. ต้องทำอย่างไร", "choices": ["ถามศาล", "ถามตำรวจ", "ถามพ่อของเด็กในครรภ์", "ทำไม่ได้เพราะ advance GA", "ทำได้เลย เป็นสิทธิที่ถูกต้องตามกฎหมาย"], "ans": 4, "exp": "การตั้งครรภ์จากการถูกข่มขืน/ล่วงละเมิดทางเพศ เป็นข้อบ่งชี้ที่ยุติการตั้งครรภ์ได้ตามกฎหมายไทย (แม้ GA เกิน 12 สัปดาห์) → ทำได้เลยเป็นสิทธิที่ถูกต้อง (ภายใต้การให้คำปรึกษา)", "sys": "general"}, {"topic": "Forensic", "q": "มารดาพาเด็กมาด้วยปัสสาวะเป็นเลือด ตรวจพบ posterior hymen tear ไม่พบคราบสเปิร์ม สงสัยการล่วงละเมิดทางเพศเด็ก. Initial management?", "choices": ["ทำให้เด็กรู้สึกปลอดภัยก่อน", "โทรหาตำรวจ", "ซักประวัติแม่เพิ่มเติม", "ถามประวัติญาติคนอื่นเพิ่มเติม"], "ans": 0, "exp": "สงสัยการล่วงละเมิดทางเพศเด็ก → initial management คือทำให้เด็กรู้สึกปลอดภัยและไว้วางใจก่อน (establish safety/rapport) ก่อนซักประวัติและตรวจร่างกาย", "sys": "general"}, {"topic": "Forensic", "q": "A 25 years old man brought to ER after traffic injury with a 3-cm stellate lesion at scalp. Soft tissue strands were seen bridging and undermining the wound edge. Which term best describes the type of lesion?", "choices": ["Avulsion", "Laceration", "Abrasion", "Contusion", "Incision"], "ans": 1, "exp": "แผลขอบไม่เรียบ (stellate) + มี tissue bridging (เนื้อเยื่อขึงข้ามแผล) + undermined edge = laceration (แผลฉีกขาดจากแรงทื่อ). แผล incision จากของมีคมจะขอบเรียบ ไม่มี tissue bridge", "sys": "general"}, {"topic": "Forensic", "q": "แพทย์นิติเวชไปดูศพแขวนคอ พบรอยเชือกที่หน้าคอเฉียงขึ้นไปหลังหู (inverted V สูง) รอบปากมีแผลจากน้ำยาล้างห้องน้ำ และมีขวดน้ำยาวางข้างศพ. สาเหตุการตาย", "choices": ["Neck fracture due to hanging", "Brain anoxia due to hanging", "Neck vessels compression due to hanging"], "ans": 2, "exp": "การแขวนคอทั่วไป (ไม่ใช่ judicial hanging) กลไกการตายหลักคือการกดหลอดเลือดที่คอ (carotid/jugular) ทำให้สมองขาดเลือด — ใช้แรงน้อยกว่าการอุดทางเดินหายใจ และไม่จำเป็นต้องมีกระดูกคอหัก", "sys": "general"}, {"topic": "Forensic", "q": "ชันสูตรศพในรถที่ปิดผนึกด้วยเทปรอบกระจกและประตู พบ livor ที่หลังและหลังขา (ตามท่าศพ) มี red-black skin sign และพบเตาเผาไหม้ในรถ. ตายจากอะไร", "choices": ["Carbon monoxide", "Cyanide"], "ans": 0, "exp": "รถปิดผนึก + เตาเผาไหม้ (การเผาไหม้ไม่สมบูรณ์) = carbon monoxide poisoning (CO) — livor สีแดง (carboxyhemoglobin)", "sys": "general"}, {"topic": "Emergency", "q": "A 3-year-old presented with unconsciousness after drinking unknown fluid at a jewelry store. PE: PR 100 bpm, RR 10/min, BP 50/30 mmHg, SpO2 80%, capillary refill 6 seconds, pupil 3 mm sluggish response. What is the most likely cause?", "choices": ["Alcohol", "Non-acetone nail remover", "Glass cleaner", "Cyanide"], "ans": 3, "exp": "ร้านทอง/เครื่องประดับ ใช้ cyanide (ชุบ/ล้างทอง). กินแล้วหมดสติเร็ว + ช็อก + SpO2 ต่ำ (cellular hypoxia จาก cyanide ยับยั้ง cytochrome oxidase) = cyanide poisoning", "sys": "emergency"}, {"topic": "Emergency", "q": "Wasp sting with 30 wounds, no stridor, no dyspnea. Apart from anaphylaxis, which condition should be observed?", "choices": ["Rhabdomyolysis", "Encephalopathy"], "ans": 0, "exp": "ถูกต่อ/แตนต่อยหลายแผล (envenomation ปริมาณมาก) → พิษทำให้เกิด rhabdomyolysis + hemolysis → เสี่ยง AKI จึงต้องเฝ้าระวัง rhabdomyolysis", "sys": "emergency"}, {"topic": "Emergency", "q": "โดนแมงกะพรุนต่อย. Management?", "choices": ["Cold immersion 30 min", "Remove tentacle ด้วย NSS", "Irrigate แผลด้วย sterile water", "Irrigate ด้วย sodium bicarbonate"], "ans": 1, "exp": "แมงกะพรุนต่อย: ห้ามใช้น้ำจืด (hypotonic กระตุ้น nematocyst ยิงพิษเพิ่ม) → ล้าง/เอาหนวด (tentacle) ออกด้วยน้ำเกลือ (NSS, isotonic) หรือน้ำทะเล; box jellyfish ใช้ vinegar", "sys": "emergency"}, {"topic": "Emergency", "q": "A woman was stabbed with a knife in the abdomen. V/S: BP 90/60, PR 100. What is the most appropriate management?", "choices": ["FAST", "CT abdomen", "Exploratory laparotomy", "Diagnostic laparoscopy", "Remove knife and explore wound"], "ans": 2, "exp": "penetrating abdominal trauma (ถูกแทง) + hemodynamic instability (BP ตก, tachycardia) → exploratory laparotomy ทันที ไม่เสียเวลาส่ง imaging (และห้ามดึงมีด/ของที่คาอยู่ออกนอกห้องผ่าตัด)", "sys": "emergency"}, {"topic": "Emergency", "q": "ผู้ป่วยชายถูกต่อต่อยหลายตัว v/s stable. Complication ที่ต้องป้องกัน", "choices": ["Encephalopathy", "Meningitis", "Peripheral neuropathy", "Rhabdomyolysis", "CHF"], "ans": 3, "exp": "ถูกต่อ/แตนต่อยหลายแผล → พิษก่อ rhabdomyolysis (+ hemolysis) → เสี่ยง acute kidney injury จึงต้องเฝ้าระวัง/ป้องกัน rhabdomyolysis (ให้ IV fluid)", "sys": "emergency"}, {"topic": "Emergency", "q": "กิน seafood แล้วเกิด wheal and flare (urticaria). PE: v/s stable, BP 100/60, lung: wheezing both lungs. Management?", "choices": ["Adrenaline IM", "ยา antihistamine IV", "Salbutamol NB"], "ans": 0, "exp": "ปฏิกิริยาแพ้ที่มี wheezing (หลอดลมหดเกร็ง = respiratory involvement) ร่วมกับ urticaria = anaphylaxis → first-line คือ adrenaline (epinephrine) IM ทันที แม้ความดันยังปกติ", "sys": "emergency"}, {"topic": "Emergency", "q": "ผู้หญิงนักศึกษา มา ER หลังซ้อมเชียร์ มีหายใจเร็วและ carpopedal spasm = hyperventilation syndrome. Management?", "choices": ["บอกให้หายใจช้า ๆ (coaching/reassurance)", "หายใจในถุงพลาสติก"], "ans": 0, "exp": "hyperventilation syndrome → รักษาด้วยการให้ความมั่นใจและฝึกหายใจช้า ๆ (slow breathing coaching). การหายใจในถุง (rebreathing) เลิกแนะนำแล้วเพราะเสี่ยงภาวะขาดออกซิเจน", "sys": "emergency"}, {"topic": "Emergency", "q": "เด็กกินน้ำยาล้างห้องน้ำ (สารกัดกร่อน) มา 1 ชม.ก่อน. ทำอะไรดี", "choices": ["Activated charcoal", "EGD (endoscopy)", "NG lavage", "Alkalinization"], "ans": 1, "exp": "กลืนสารกัดกร่อน (caustic ingestion): ห้ามให้ activated charcoal, ห้าม NG lavage, ห้าม neutralize → ทำ endoscopy (EGD) ภายใน 12-24 ชม. เพื่อประเมินความรุนแรงของแผลในหลอดอาหาร/กระเพาะ", "sys": "emergency"}, {"topic": "Emergency", "q": "โดน box jellyfish (แมงกะพรุนกล่อง) ต่อย. Proper management? (ตัวเลือกแต่งขึ้นมาเอง ต้นฉบับตัวเลือกไม่ชัด)", "choices": ["ราดด้วยน้ำจืด/น้ำกลั่น (DW)", "ถูบริเวณที่โดนต่อย", "ราดด้วยน้ำส้มสายชู (vinegar/acetic acid) แล้วเอาหนวดออก", "ประคบน้ำแข็งลงบนแผลโดยตรง"], "ans": 2, "exp": "box jellyfish: ราดด้วยน้ำส้มสายชู (vinegar 4-6% acetic acid) เพื่อยับยั้ง nematocyst ก่อนเอาหนวดออก. ห้ามใช้น้ำจืด/น้ำกลั่น (hypotonic กระตุ้นการยิงพิษเพิ่ม) และห้ามถู", "sys": "emergency"}, {"topic": "Emergency", "q": "ผู้ชายจะฆ่าตัวตาย มา ER โวยวาย วุ่นวาย (agitated). ทำอย่างไร", "choices": ["ให้พูดระบาย death wish", "Sedate", "มัด (restrain)", "จัดให้อยู่ในมุมสงบ/ปลอดภัยของ ER พร้อมเฝ้าดูแล"], "ans": 3, "exp": "ผู้ป่วยฆ่าตัวตายที่กระวนกระวายรุนแรง → เริ่มด้วยการจัดสิ่งแวดล้อมที่สงบและปลอดภัย ลดสิ่งกระตุ้น + เฝ้าระวังใกล้ชิด (de-escalation) ก่อน. sedate/restrain ใช้เมื่อ verbal de-escalation ไม่ได้ผลและเสี่ยงอันตราย", "sys": "emergency"}, {"topic": "Emergency", "q": "เด็ก (อายุ > 1 ปี) มีอะไรติดคอ หายใจไม่ออก ไอไม่ออก (complete airway obstruction, ยังรู้สึกตัว). ทำอย่างไร", "choices": ["Back blow", "Heimlich maneuver (abdominal thrust)"], "ans": 1, "exp": "เด็กโต (>1 ปี) ที่สำลักอุดกั้นทางเดินหายใจสมบูรณ์ (ไอไม่ออก) และยังรู้สึกตัว → ทำ Heimlich maneuver (abdominal thrust). ทารก <1 ปี จึงใช้ back blow 5 ครั้งสลับ chest thrust", "sys": "emergency"}, {"topic": "Emergency", "q": "ผู้ป่วย cardiac arrest ในรถ ambulance เปิดเส้น IV ไม่ได้. ทำอย่างไร", "choices": ["Intraosseous (IO) access", "Chest compression only"], "ans": 0, "exp": "ขณะ CPR ถ้าเปิด IV ไม่ได้ภายในเวลาอันสั้น → ใช้ intraosseous (IO) access เพื่อให้ยา/สารน้ำ (เร็วและเชื่อถือได้)", "sys": "emergency"}, {"topic": "Emergency", "q": "ผู้ป่วยมีแผ่นฝ้า (membrane) สกปรกที่คอ + stridor + contact bleeding (เยื่อเปื่อยเลือดออกง่าย). ทำอย่างไรเพื่อเปิดทางเดินหายใจ", "choices": ["ETT (endotracheal intubation)", "Emergency tracheostomy"], "ans": 1, "exp": "เยื่อ (pseudomembrane เช่น diphtheria) ที่เปื่อยเลือดออกง่าย + อุดกั้นทางเดินหายใจส่วนบน → การใส่ ETT เสี่ยงดันเยื่อหลุด/เลือดออกซ้ำ จึงเลือก emergency tracheostomy เพื่อเปิดทางเดินหายใจใต้ตำแหน่งอุดกั้น", "sys": "emergency"}, {"topic": "Community/EBM", "q": "In a study about asthma in children: of 100 children who lived with a smoker father, 20 developed asthma; of 200 children who lived with a non-smoker father, 10 developed asthma. What is the relative risk of asthma among children who lived with a smoking father?", "choices": ["0.05", "0.25", "4.00", "0.33", "2.00"], "ans": 2, "exp": "RR = (risk ในกลุ่มสัมผัส)/(risk ในกลุ่มไม่สัมผัส) = (20/100)/(10/200) = 0.20/0.05 = 4.00", "sys": "general"}, {"topic": "Community/EBM", "q": "A village near a gold mine. Many people developed generalized multiple nodular (hyperkeratotic) lesions on both hands with peripheral numbness and lightheadedness. What is the cause?", "choices": ["Lead", "Nickel", "Mercury", "Arsenic", "Cadmium"], "ans": 3, "exp": "เหมืองทอง + ผิวหนังหนาตัวเป็นตุ่ม (arsenical keratosis) ที่ฝ่ามือ 2 ข้าง + peripheral neuropathy (ชาปลายมือปลายเท้า) = พิษสารหนู (arsenic)", "img": "https://cdn.jsdelivr.net/gh/MercenzK/Web-quiz-images@main/NL2-2021-Q281.png", "sys": "general"}, {"topic": "Community/EBM", "q": "A man visited OPD with BP 140/90 twice, 15 mins apart at the hospital. At home, his BP is always below 140/90. What should be done next?", "choices": ["Reassurance", "Start anti-hypertensive drug"], "ans": 0, "exp": "ความดันสูงเฉพาะที่ รพ. แต่ที่บ้านปกติ = white coat hypertension → ให้ความมั่นใจ (reassurance) + ติดตามด้วย home/ambulatory BP ไม่จำเป็นต้องเริ่มยาลดความดันทันที", "sys": "general"}, {"topic": "Community/EBM", "q": "You are a doctor in a rural area with heavy use of insecticide. Which lab should be used to monitor the health risk of this community?", "choices": ["Serum for cholinesterase level", "Urine for paraquat level", "Urine for organophosphate level", "Serum for organophosphate level", "Serum for pyrethroid level"], "ans": 0, "exp": "ยาฆ่าแมลงกลุ่ม organophosphate/carbamate ยับยั้งเอนไซม์ cholinesterase → ใช้ระดับ serum (plasma/RBC) cholinesterase เป็นตัวเฝ้าระวังการสัมผัสของชุมชน", "sys": "general"}, {"topic": "Emergency", "q": "ญาตินำส่งผู้ป่วยที่พยายามแขวนคอ (suicide attempt) มาที่ ER. เราควรทำอะไร", "choices": ["ให้ผู้ป่วยอยู่มุมเงียบ ๆ ที่ ER", "พูดคุยเรื่อง death wish (ถามความคิดฆ่าตัวตายอย่างเปิดเผย)", "Restrain", "Sedate", "คุยกับผู้ป่วยด้วยเหตุผล"], "ans": 1, "exp": "ผู้ป่วยหลังพยายามฆ่าตัวตาย → ควรพูดคุยประเมินความคิดฆ่าตัวตาย (death wish/suicidal ideation) อย่างเปิดเผยและไม่ตัดสิน. การถามเรื่องฆ่าตัวตายไม่ได้เพิ่มความเสี่ยง แต่ช่วยประเมินและสร้างความไว้วางใจ", "sys": "emergency"}, {"topic": "Ethics", "q": "A man with CA head of pancreas is planned for elective Whipple's operation. It was canceled because the pre-booked ICU was taken by a major hospital donor planning for elective knee arthroplasty. According to the four principles of ethics, which is breached?", "choices": ["Autonomy", "Beneficence", "Distributive justice", "Non-maleficence", "Absolute veracity"], "ans": 2, "exp": "การให้สิทธิ์ทรัพยากร (ICU) แก่ผู้บริจาคก่อนผู้ป่วยที่จำเป็นกว่า = ละเมิดหลัก distributive justice (การจัดสรรทรัพยากรอย่างเป็นธรรม)", "sys": "general"}, {"topic": "Community/EBM", "q": "In a food poisoning outbreak, the investigator interviewed 80 students who went to the party. 45 of 60 who drank cocktails developed food poisoning whereas 1 of 20 who didn't drink developed it. Other foods showed no significance. Which type of study is this?", "choices": ["Prospective cohort study", "Case control study", "Experimental study", "Retrospective cohort study", "Cross sectional study"], "ans": 3, "exp": "สอบสวนการระบาดโดยย้อนดูการสัมผัส แล้วแบ่งกลุ่มตาม 'exposure' (ดื่ม/ไม่ดื่ม cocktail) เปรียบเทียบ attack rate = retrospective cohort study (คำนวณ RR ได้)", "sys": "general"}, {"topic": "Community/EBM", "q": "A 40-year-old man smokes 40 cigarettes/day for 10 years. His wife wants him to stop but he doesn't. He usually smokes when he wakes up. What should be done?", "choices": ["Nicotine replacement therapy", "Bupropion therapy", "Acupuncture therapy", "Cognitive behavioral therapy", "Assess pros and cons of smoking"], "ans": 4, "exp": "ผู้ป่วย 'ยังไม่พร้อมเลิก' (precontemplation) → ใช้ motivational interviewing โดยประเมินข้อดี-ข้อเสียของการสูบบุหรี่ก่อน. ยา (NRT/bupropion) เหมาะกับผู้ที่พร้อมเลิกแล้ว", "sys": "general"}, {"topic": "Ethics", "q": "เด็กหญิงอายุ 14 ปี ตั้งครรภ์ 12 สัปดาห์ มากับแม่เพื่อขอทำแท้ง ท้องนี้เกิดจากการถูกล่วงละเมิดทางเพศ (sexual assault) โดยเพื่อนร่วมชั้น. จะทำแท้งให้ไหม", "choices": ["ทำได้ เป็นสิทธิตามกฎหมาย (rightful)", "รอคำสั่งศาล", "ถามตำรวจก่อน", "ขออนุญาตพ่อของเด็กในครรภ์ก่อน", "สายเกินไป ท้องแก่เกิน"], "ans": 0, "exp": "ตั้งครรภ์จากการถูกข่มขืน/ล่วงละเมิดทางเพศ เป็นข้อบ่งชี้ที่ยุติการตั้งครรภ์ได้ตามกฎหมาย → ทำได้เลย (ไม่ต้องรอศาล/ตำรวจ/พ่อเด็ก)", "sys": "general"}, {"topic": "Family Medicine", "q": "ทีมเยี่ยมบ้านไปเยี่ยมผู้ป่วยหญิง มี recurrent dizziness อาศัยอยู่กับลูกชายวัยรุ่น กังวลเรื่องอนาคตของลูก. ตาม family life cycle task ควรแนะนำอย่างไร", "choices": ["Make more family network", "Discuss appropriate freedom and responsibility", "Balance her son's need and interest", "Build mother-son relationship"], "ans": 1, "exp": "ครอบครัวที่มีลูกวัยรุ่น (family with adolescents) task คือปรับขอบเขตครอบครัวให้ยืดหยุ่น ให้ลูกมีอิสระควบคู่กับความรับผิดชอบที่เหมาะสม (freedom & responsibility)", "sys": "general"}, {"topic": "Family Medicine", "q": "A multidisciplinary team visits a 50-year-old woman with recurrent dizziness. She lives with her teenage son and is always concerned about his education and future. According to the appropriate family life cycle, what is the most appropriate advice?", "choices": ["Make more family network", "Balance son's interest and need", "Balance son's freedom and responsibility", "Adjust satisfying home", "Rebuild mother-son relationship"], "ans": 2, "exp": "ครอบครัวที่มีลูกวัยรุ่น (adolescent stage) → task คือเพิ่มความยืดหยุ่นของขอบเขต ให้ลูกมีอิสระคู่กับความรับผิดชอบ (balance freedom and responsibility)", "sys": "general"}, {"topic": "Community/EBM", "q": "A 60-year-old man diagnosed with cirrhosis for 3 months, drinks 35 units of alcohol daily for 40 years. Doctor advised cessation. The patient said that his friend died after stopping drinking. What stage of change is the man in?", "choices": ["Contemplation", "Planning", "Action", "Precontemplation", "Maintenance"], "ans": 3, "exp": "ผู้ป่วยยังไม่คิดจะเปลี่ยนพฤติกรรม + หาข้ออ้าง/ต่อต้าน (เพื่อนตายหลังเลิกเหล้า) = precontemplation stage (ตาม transtheoretical model)", "sys": "general"}, {"topic": "Community/EBM", "q": "In a survey, weights of primary school girls are 20, 25, 30, 30, 35, 40, 45 kg. Which is correct regarding the central tendency?", "choices": ["Mean > mode > median", "Mean > median > mode", "Median > mode > mean", "Median > mode = mean", "Mean > median = mode"], "ans": 4, "exp": "เรียงข้อมูล: 20,25,30,30,35,40,45 (n=7). median = ค่ากลาง = 30; mode = 30 (ซ้ำมากสุด); mean = 225/7 ≈ 32.1. ดังนั้น mean (32.1) > median (30) = mode (30)", "sys": "general"}, {"topic": "Ethics", "q": "ผู้ป่วย CA head of pancreas มีคิวผ่าตัดแล้ว อยู่ ๆ มี VIP มาแย่งคิว OR ไป (เคสไม่ฉุกเฉิน). ผิดหลักจริยธรรมข้อใด", "choices": ["Distributive justice", "Beneficence", "Non-maleficence"], "ans": 0, "exp": "การให้ VIP แย่งคิวห้องผ่าตัดจากผู้ป่วยที่จำเป็นกว่า/มีคิวก่อน = ละเมิดหลัก distributive justice (การจัดสรรทรัพยากรอย่างเป็นธรรม)", "sys": "general"}, {"topic": "Ethics", "q": "หญิง GA 16 สัปดาห์ ตั้งครรภ์จากการถูกล่วงละเมิดทางเพศ (sexual assault) โดยเพื่อนร่วมห้อง มา รพ. กับแม่ ถามว่าทำแท้งได้ไหม", "choices": ["ไม่ทำ", "ทำได้เลย", "ถามพ่อของเด็กในครรภ์ก่อน", "ถามศาลก่อน"], "ans": 1, "exp": "ตั้งครรภ์จากการถูกข่มขืน/ล่วงละเมิดทางเพศ เป็นข้อบ่งชี้ที่ยุติการตั้งครรภ์ได้ตามกฎหมายไทย → ทำได้เลย (ภายใต้การให้คำปรึกษาตามขั้นตอน)", "sys": "general"}]}, {"id": "nl2-2022-am", "title": "NL 2 ปี 2022 ภาคเช้า", "subject": "past", "questions": [{"topic": "Obstetrics", "q": "A 30-year-old woman delivers a 4,000 g newborn with vacuum extraction. After the placenta is delivered, she develops bleeding per vagina not relieved by uterine compression. PE: good uterine contraction. Most appropriate management?", "choices": ["Birth canal exploration", "IV Methergine", "Uterine packing", "Uterine compression", "Hysterectomy"], "ans": 0, "exp": "ตกเลือดหลังคลอดทั้งที่มดลูกหดรัดตัวดี (uterus firm) + คลอดยากด้วย vacuum ทารกตัวโต → นึกถึงการฉีกขาดของช่องทางคลอด → สำรวจช่องทางคลอด (birth canal exploration) หา laceration แล้วเย็บซ่อม", "sys": "XV"}, {"topic": "Pediatrics", "q": "A 3-year-old boy has watery diarrhea 3-4 times/day for 2 days, vomited once, still eats and plays. PE: BW 14 kg, dry lips, no sunken eyeballs, capillary refill <2 s. Most appropriate management?", "choices": ["NSS 10 ml/kg/hr", "ORS", "Zinc solution", "Ondansetron", "Ceftriaxone"], "ans": 1, "exp": "ท้องเสียเฉียบพลันขาดน้ำเล็กน้อย (ริมฝีปากแห้งอย่างเดียว ยังกินเล่นได้ cap refill ปกติ) → ให้ ORS ทดแทนตาม plan B. (zinc เป็นตัวเสริม, ยาปฏิชีวนะไม่จำเป็นใน viral diarrhea)", "sys": "XI"}, {"topic": "Psychiatry", "q": "A 40-year-old man is worried he has an illness because a friend was diagnosed with lung cancer, and requests a CT scan. He has no somatic symptoms. Most likely diagnosis?", "choices": ["Somatic symptom disorder", "Generalized anxiety disorder", "Illness anxiety disorder", "Panic disorder", "Personality disorder"], "ans": 2, "exp": "กังวลว่าจะป่วยเป็นโรคร้ายโดยไม่มีอาการทางกายจริง + ขอตรวจซ้ำ = illness anxiety disorder. ต่างจาก somatic symptom disorder ที่มีอาการทางกายเด่นจริง ๆ", "sys": "V"}, {"topic": "Ophthalmology", "q": "A patient with eye trauma. PE: dark brown stain at the lower limbus and a peaked pupil. Most likely diagnosis?", "choices": ["Corneal abrasion", "Traumatic endophthalmitis", "Corneal foreign body", "Corneal perforation", "Acute uveitis"], "ans": 3, "exp": "peaked pupil (รูม่านตารูปหยดน้ำ) + เนื้อสีน้ำตาล (uveal tissue/iris) ที่ limbus = iris ถูกดึงไปอุดรอยทะลุ = corneal/globe perforation → ภาวะฉุกเฉิน ปิดตาแล้วส่งจักษุ", "sys": "VII"}, {"topic": "Pediatrics", "q": "Prenatal screening: mother Hb typing A 75%, A2 3%, E 22%; father A 75%, E 25%. Which condition can be found in this couple's child?", "choices": ["Bart's hydrops fetalis", "HbH/HbE disease", "Beta thalassemia/HbE disease", "Beta thalassemia disease", "Homozygous HbE thalassemia"], "ans": 4, "exp": "ทั้งพ่อและแม่เป็น HbE trait (AE, A2 ปกติ <3.5%) → ลูกมีโอกาส 1/4 เป็น homozygous HbE (EE). Bart's hydrops ต้องพ่อแม่เป็น alpha-thal-1 ทั้งคู่ (ไม่ใช่กรณีนี้)", "sys": "III"}, {"topic": "Pediatrics", "q": "A child with acute otitis media, never received medication before, tympanic membrane intact. Most appropriate antibiotic? (ต้นฉบับมีตัวเลือกไม่ครบ ใส่เท่าที่มี)", "choices": ["Cefdinir", "A fluoroquinolone", "Amoxicillin-clavulanate"], "ans": 2, "exp": "AOM first-line จริง ๆ คือ high-dose amoxicillin (ไม่มีในตัวเลือก); ในบรรดาที่ให้มา amoxicillin-clavulanate เป็น aminopenicillin ที่เหมาะสมสุด. *ต้นฉบับตัวเลือกไม่ครบ*", "sys": "V"}, {"topic": "ENT", "q": "A 30-year-old woman has right earache with otorrhea 2 days after snorkeling 5 days ago. PE: diffuse external auditory canal stenosis with yellow discharge. Proper management?", "choices": ["Oral antibiotics", "Topical antibiotics", "IV antibiotics", "Topical steroid", "Ear packing"], "ans": 1, "exp": "ปวดหู + หูน้ำหนวก + ช่องหูบวมแคบหลังดำน้ำ = acute otitis externa (swimmer's ear, มัก Pseudomonas) → topical antibiotic ear drop (+/- steroid) เป็นหลัก", "sys": "VIII"}, {"topic": "Pediatrics", "q": "A 9-year-old with severe pneumonia: BT 39, BP 80/50, Hb 9.5, WBC 28,000, platelet 85,000, prolonged PT and PTT. Most likely diagnosis?", "choices": ["Evans syndrome", "Hemolytic uremic syndrome", "Disseminated intravascular coagulation", "Thrombotic thrombocytopenic purpura", "Immune thrombocytopenia"], "ans": 2, "exp": "sepsis + เกล็ดเลือดต่ำ + PT/PTT ยืดทั้งคู่ = DIC (consumptive coagulopathy). HUS/TTP จะมี MAHA แต่ PT/PTT ปกติ", "sys": "I"}, {"topic": "Pediatrics", "q": "An infant refuses to walk. PE: knee pain on passive motion, mild swelling, no redness, petechiae on both legs. Proper investigation?", "choices": ["ESR", "PT, PTT", "Platelet function test", "Complete blood count", "Film both knees"], "ans": 3, "exp": "ปวดข้อ + จุดเลือดออก (petechiae) ในเด็ก → ต้องแยก leukemia/ภาวะเกล็ดเลือด → เริ่มด้วย CBC (ดู blast, เกล็ดเลือด, ซีด) ก่อนเสมอ", "sys": "II"}, {"topic": "Pediatrics", "q": "A 6-year-old with high-grade fever and sore throat. PE: BT 39, posterior pharyngeal wall bulging, 1 cm lymphadenopathy. Most likely diagnosis?", "choices": ["Acute epiglottitis", "Peritonsillar abscess", "Infectious mononucleosis", "Ludwig's angina", "Retropharyngeal abscess"], "ans": 4, "exp": "ผนังคอหอยด้านหลังโป่ง (posterior pharyngeal wall bulging) ในเด็กเล็ก = retropharyngeal abscess", "sys": "I"}, {"topic": "Pediatrics", "q": "A 9-year-old boy with fever, sore throat, dysphagia 3 days. PE: anxious, leaning forward, drooling, inspiratory stridor. Most useful investigation?", "choices": ["Film lateral neck", "CBC, ESR, CRP", "Hemoculture", "Film adenoid gland", "Chest X-ray"], "ans": 0, "exp": "นั่งโน้มตัว (tripod) + น้ำลายไหล + stridor = acute epiglottitis → lateral neck film เห็น thumb sign (ต้องระวัง airway, ไม่กระตุ้นคอ)", "sys": "X"}, {"topic": "Surgery", "q": "An 80-year-old woman with DM, HT presents with RUQ pain 1 day. BP 90/60, Murphy's sign positive. Apart from antibiotics, most proper management?", "choices": ["Observe", "Percutaneous transhepatic gallbladder drainage", "Open cholecystectomy", "Laparoscopic cholecystectomy", "ERCP"], "ans": 1, "exp": "acute cholecystitis ในผู้สูงอายุความเสี่ยงสูง/สัญญาณชีพไม่ดี (BP 90/60) → percutaneous cholecystostomy (PTGBD) ระบายก่อน แทนการผ่าตัดทันที", "sys": "XI"}, {"topic": "Infectious disease", "q": "A 25-year-old woman with fever every other day; blood smear shown suggests malaria. Causative organism?", "choices": ["Plasmodium falciparum", "Plasmodium ovale", "Plasmodium vivax", "Plasmodium malariae", "Plasmodium knowlesi"], "ans": 2, "exp": "ไข้วันเว้นวัน (tertian, 48 ชม.) = benign tertian malaria ที่พบบ่อยสุดในไทยคือ P. vivax (มี Schuffner's dots, ring โต, RBC ขยาย). *อ้างอิงภาพ blood smear*", "img": "https://cdn.jsdelivr.net/gh/MercenzK/Web-quiz-images@main/NL2-2022-AM-Q13.png", "sys": "I"}, {"topic": "Obstetrics & Gynecology", "q": "A 30-year-old with abnormal discharge, multiple partners, prior PID, family history of cervical cancer. Pelvic exam: mucopurulent discharge from cervical os with contact bleeding, no cervical motion tenderness, no adnexal tenderness. Most likely diagnosis?", "choices": ["Vaginitis", "Cervical inversion", "Cervical polyp", "Cervicitis", "Cervical cancer"], "ans": 3, "exp": "หนองจาก cervical os + contact bleeding + ไม่มี CMT/adnexal tenderness = mucopurulent cervicitis (มัก Chlamydia/Gonococcus)", "sys": "II"}, {"topic": "Pediatrics", "q": "A newborn delivered by vacuum, BW 4,000 g, develops dyspnea and an actively swelling mass over the left parietal area. BP 55/34, MAP 44. Next proper investigation?", "choices": ["Blood sugar", "Skull film", "Ultrasound brain", "Capillary blood gas", "Serial hematocrit"], "ans": 4, "exp": "ก้อนนุ่มโตเร็วข้าม suture หลัง vacuum + ความดันตก = subgaleal hemorrhage (เสียเลือดมาก) → serial hematocrit เฝ้าระวังเสียเลือด/ช็อก", "sys": "XVI"}, {"topic": "Emergency", "q": "A patient has muscle soreness and inability to void; urinalysis shows blood 3+. Most likely diagnosis? (ตัวเลือกแต่งขึ้นมาเอง ต้นฉบับไม่มีตัวเลือก)", "choices": ["Rhabdomyolysis", "Acute glomerulonephritis", "Urinary tract infection", "Bladder carcinoma", "Nephrolithiasis"], "ans": 0, "exp": "ปวดกล้ามเนื้อ + dipstick blood บวกแต่ไม่มี RBC ใน microscopy = myoglobinuria จาก rhabdomyolysis → เสี่ยง AKI ให้ IV fluid", "sys": "emergency"}, {"topic": "Infectious disease", "q": "A 60-year-old man with fever and left thigh pain after brushwood stab while gardening. BT 40, BP 80/40. PE: erythematous purplish-black blebs with crepitation and extreme tenderness; Gram stain shows gram-positive bacilli. Causative pathogen?", "choices": ["Bacillus anthracis", "Clostridium perfringens", "Clostridium tetani", "Corynebacterium striatum", "Erysipelothrix rhusiopathiae"], "ans": 1, "exp": "แผลปนเปื้อนดิน + ตุ่มเลือดม่วงดำ + crepitation (แก๊สใต้ผิว) + ช็อก + GPB = gas gangrene จาก Clostridium perfringens → ต้อง debride ด่วน + penicillin+clindamycin", "sys": "I"}, {"topic": "Forensic", "q": "A 5-year-old drowned in a pool, developed pulmonary edema, then pneumonia and ARDS, and died 2 days later. Cause of death to specify in the death certificate?", "choices": ["Pneumonia", "Acute respiratory distress syndrome", "Accidental drowning", "Sepsis", "Cardiopulmonary failure"], "ans": 2, "exp": "ใบมรณบัตรระบุ underlying cause = เหตุการณ์แรกที่เริ่มลูกโซ่ = accidental drowning (จมน้ำ) ซึ่งนำไปสู่ pulmonary edema -> pneumonia -> ARDS", "sys": "general"}, {"topic": "Psychiatry", "q": "A patient with amphetamine dependence refuses to eat, saying the food is poisoned and that his father is trying to assault him. Most proper initial management?", "choices": ["Lithium", "Lorazepam", "Risperidone", "Haloperidol", "Fluoxetine"], "ans": 3, "exp": "amphetamine-induced psychosis (paranoid delusion) → ควบคุมอาการโรคจิต/กระวนกระวายด้วย antipsychotic เช่น haloperidol", "sys": "V"}, {"topic": "ENT", "q": "A 40-year-old woman has vertigo when rolling in bed for 2 months, no tinnitus or hearing loss, previous head injury 4 months ago. Most likely diagnosis?", "choices": ["Labyrinthitis", "Vestibular neuritis", "Meniere disease", "Central vertigo", "Benign paroxysmal positional vertigo"], "ans": 4, "exp": "เวียนหัวสัมพันธ์ท่าทาง (พลิกตัวบนเตียง) เป็นวินาที + ไม่มีการได้ยินผิดปกติ + เคยบาดเจ็บศีรษะ = BPPV → ทำ Dix-Hallpike / Epley", "sys": "VIII"}, {"topic": "Cardiology", "q": "A 40-year-old woman with dyspnea on exertion. PE: BP 90/60, PR 110, JVP 20 cmH2O, clear equal breath sounds, low-intensity heart sounds, pitting edema 1+. Most likely diagnosis?", "choices": ["Cardiac tamponade", "Pulmonary embolism", "Nephrotic syndrome", "Chronic renal failure", "LV failure"], "ans": 0, "exp": "JVP สูง + เสียงหัวใจเบา (muffled) + ความดันต่ำ + ปอดใส = Beck's triad ของ cardiac tamponade", "sys": "IX"}, {"topic": "Infectious disease", "q": "A patient presents with an eschar. Next proper investigation? (ต้นฉบับมีตัวเลือกไม่ครบ ใส่เท่าที่มี)", "choices": ["Scrub typhus IgM", "Weil-Felix test", "Blood culture"], "ans": 0, "exp": "eschar (แผลบุ๋มดำ) = ลักษณะเด่นของ scrub typhus (Orientia tsutsugamushi) → ตรวจ scrub typhus IgM; รักษาด้วย doxycycline", "sys": "I"}, {"topic": "Neurology", "q": "A 30-year-old woman with persistent progressive headache 2 weeks, occasional vomiting and visual impairment; other PE unremarkable. Most likely diagnosis?", "choices": ["Meningitis", "Migraine", "Intracranial hypertension", "Tension headache", "Ocular headache"], "ans": 2, "exp": "ปวดหัวเรื้อรังก้าวหน้า + อาเจียน + ตามัว = สัญญาณ raised intracranial pressure (intracranial hypertension) → ต้อง image สมอง", "sys": "VI"}, {"topic": "Emergency", "q": "A 50-year-old farmer bitten by a snake. PE: swelling, redness, two fang marks on right foot dorsum, otherwise unremarkable. Most appropriate management?", "choices": ["Coagulogram", "Antivenom", "Fasciotomy", "Serial venous clotting time", "Wound debridement"], "ans": 3, "exp": "งูกัดที่มีเฉพาะบวมแดงเฉพาะที่ ยังไม่มี systemic/coagulopathy → เฝ้าระวังด้วย serial VCT (20-min whole blood clotting test) แล้วให้ antivenom เมื่อมีข้อบ่งชี้ (VCT ผิดปกติ/systemic bleeding)", "sys": "emergency"}, {"topic": "Neurology", "q": "A previously healthy man with fluctuating consciousness, agitation, dysphagia, and drooling of saliva. Diagnosis?", "choices": ["Japanese encephalitis", "Herpes encephalitis", "Tetanus", "Botulism", "Rabies"], "ans": 4, "exp": "สติขึ้น ๆ ลง ๆ + กลืนลำบาก + น้ำลายไหล (hydrophobia/hypersalivation) = rabies encephalitis", "sys": "VI"}, {"topic": "Orthopedics", "q": "An elderly woman fell on an outstretched hand and is diagnosed with a wrist fracture; she fears another fracture. Strongest predictor of recurrent fracture?", "choices": ["History of previous fragility fracture", "L1-4 BMD T-score < -2.5", "Low body weight", "Advanced age", "Low calcium intake"], "ans": 0, "exp": "ตัวทำนายการเกิดกระดูกหักซ้ำที่แรงที่สุดคือ 'ประวัติกระดูกหักจาก fragility มาก่อน' (แรงกว่าค่า BMD เดี่ยว ๆ)", "sys": "XIII"}, {"topic": "Obstetrics & Gynecology", "q": "A 52-year-old postmenopausal woman with urine leakage on coughing, no urgency/nocturia. PE: anterior vaginal prolapse stage 1, positive cough stress test, normal UA, PVR 45 ml. Most appropriate management?", "choices": ["Observe", "Pelvic floor exercise", "Timed voiding", "Antimuscarinic drugs", "Urodynamic study"], "ans": 1, "exp": "stress urinary incontinence (leak on cough, ไม่มี urgency) → first-line = pelvic floor (Kegel) exercise", "sys": "X"}, {"topic": "Surgery", "q": "A man with chronic constipation and bright red blood per rectum; internal hemorrhoid grade II. Most proper management?", "choices": ["Stool softening", "Rubber band ligation", "Stool softening + rigid sigmoidoscopy", "Rubber band ligation + rigid sigmoidoscopy", "Rubber band ligation + barium enema"], "ans": 2, "exp": "ริดสีดวงภายใน grade II first-line เป็น conservative (fiber/stool softener); เลือดออกทางทวารในผู้ใหญ่ควรส่องกล้อง sigmoidoscopy เพื่อแยกสาเหตุอื่นด้วย", "sys": "XI"}, {"topic": "Medicine", "q": "A 45-year-old obese woman with daytime sleepiness; husband reports snoring with choking sounds; BMI 28. Most likely diagnosis?", "choices": ["Primary snoring", "Obesity hypoventilation syndrome", "Idiopathic sleep apnea", "Obstructive sleep apnea", "Central sleep apnea"], "ans": 3, "exp": "ง่วงกลางวัน + นอนกรน + สำลัก/หยุดหายใจ + อ้วน = obstructive sleep apnea → ยืนยันด้วย polysomnography", "sys": "IV"}, {"topic": "Medicine", "q": "A 45-year-old woman with dizziness and headache; home BP always >150 mmHg but two clinic readings are 138/88 and 135/85. Most proper management?", "choices": ["Reassure", "Anxiolytics", "Beta blocker", "Repeat clinic BP", "ACE inhibitor"], "ans": 4, "exp": "BP ที่บ้านสูงแต่ที่ รพ.ปกติ = masked hypertension ซึ่งเสี่ยง CV เท่ากับ HT จริง → รักษาด้วยยาลดความดัน (ACE inhibitor)", "sys": "VI"}, {"topic": "Orthopedics", "q": "Which physical examination confirms knee osteoarthritis? (ต้นฉบับมีตัวเลือกไม่ครบ ใส่เท่าที่มี)", "choices": ["Crepitus on extension/flexion", "Varus/valgus stress test", "Anterior drawer test", "McMurray test", "Knee gliding test"], "ans": 0, "exp": "ข้อเข่าเสื่อมตรวจพบ crepitus (เสียงกรอบแกรบ) เวลางอ/เหยียดเข่า. drawer/McMurray ใช้ประเมิน ligament/meniscus", "sys": "XIII"}, {"topic": "Endocrinology", "q": "A 14-year-old girl with rapid weight gain. PE: increased nape fat pad, abdominal striae, BW 80 kg, Ht 138 cm, BP 150/110. Na 146, K 2.5, CO2 20. Most likely diagnosis?", "choices": ["Bartter syndrome", "Cushing syndrome", "Metabolic syndrome", "Renal artery stenosis", "Renal tubular acidosis"], "ans": 1, "exp": "buffalo hump + striae + ความดันสูง + hypokalemic alkalosis + อ้วนขึ้นเร็ว = Cushing syndrome", "sys": "IV"}, {"topic": "Surgery", "q": "A 35-year-old man with chronic perianal discharge and prior perianal infection. PE: small dimple with turbid brown discharge 2 cm from the anal verge, no palpable mass in the anal canal. Most appropriate management?", "choices": ["Warm sitz bath", "Topical metronidazole", "Surgical treatment (fistulotomy/excision)", "Oral metronidazole", "Incisional biopsy"], "ans": 2, "exp": "รูเปิดข้างทวารมีหนองเรื้อรังหลังฝีคัณฑสูตร = anal fistula → รักษาด้วยการผ่าตัด (fistulotomy/excision)", "sys": "II"}, {"topic": "Medicine", "q": "A 40-year-old woman for check-up: FPG 116, HbA1c 6%, TG 250, cholesterol 250, HDL 50, BP 140/90, BMI 31, waist 94 cm. Apart from exercise, appropriate dietary advice?", "choices": ["High protein diet", "High carbohydrate diet", "Normal sodium intake", "High fiber diet", "Normal saturated fat intake"], "ans": 3, "exp": "metabolic syndrome → แนะนำอาหารกากใยสูง (high fiber) ลดไขมัน/น้ำตาล ควบคุมน้ำหนัก", "sys": "IV"}, {"topic": "Neurology", "q": "A woman with altered consciousness and high-grade fever. BT 40. CT: hypodense lesion at left temporal lobe. CSF: lymphocyte-predominant. Cause?", "choices": ["Autoimmune encephalitis", "Streptococcus suis", "Streptococcus pneumoniae", "Japanese encephalitis", "Herpes simplex virus type 1"], "ans": 4, "exp": "encephalitis ที่ชอบ temporal lobe + CSF lymphocyte เด่น = HSV-1 encephalitis → ให้ IV acyclovir ทันที", "sys": "VI"}, {"topic": "Medicine", "q": "A 70-year-old man with acute dyspnea and productive cough 3-5 days. BT 39, PR 120, RR 30, BP 80/50, SpO2 90%. Lung: lower crepitations. After IV fluid resuscitation, what should be done first?", "choices": ["High-flow oxygen", "Chest X-ray", "Hemoculture", "Dobutamine", "12-lead ECG"], "ans": 0, "exp": "septic shock จากปอดอักเสบ + hypoxia (SpO2 90%) → หลังให้สารน้ำ จัดการ oxygenation ด้วย high-flow oxygen เป็นลำดับต้น (ABC)", "sys": "I"}, {"topic": "Forensic", "q": "Gunshot wounds: right temple has a circular wound with a muzzle imprint at the margin; left temple has a stellate wound with no soot. Skull film shows no bullet. Which is correct?", "choices": ["The trajectory is from left to right", "The patient was shot at close (contact) range", "The patient was murdered", "The wound is an exit on the right", "Range cannot be determined"], "ans": 1, "exp": "muzzle imprint = รอยปากกระบอกปืนกดผิว = บาดแผลทางเข้าระยะสัมผัส (contact) -> 'ถูกยิงระยะประชิด'. แผลทางเข้าคือด้านขวา (contact) แผลทางออกด้านซ้าย (stellate) -> วิถีจากขวาไปซ้าย", "sys": "general"}, {"topic": "Emergency", "q": "A 14-year-old boy after partying presents with chest tightness, agitation, and lightheadedness. BT 37.7, PR 130, RR 22, BP 130/50, pupils 2 mm RTLBE. Most plausible cause?", "choices": ["Heroin", "Cannabis", "Amphetamine", "Tramadol", "Ketamine"], "ans": 2, "exp": "งานปาร์ตี้ + กระวนกระวาย + หัวใจเต้นเร็ว + pulse pressure กว้าง (สาร sympathomimetic) = amphetamine/methamphetamine", "sys": "emergency"}, {"topic": "Pediatrics", "q": "A 10-year-old boy had severe acute pancreatitis a month ago, now with epigastric pain 4-5 days. PE: fixed palpable epigastric mass of cystic consistency, non-tender. Most proper investigation?", "choices": ["Abdominal MRI", "Upper GI study", "Esophagogastroduodenoscopy", "Abdominal ultrasound", "Serum lipase and amylase"], "ans": 3, "exp": "ก้อน cystic ที่ลิ้นปี่หลัง pancreatitis ~4 สัปดาห์ = pancreatic pseudocyst -> ประเมินด้วย abdominal ultrasound ก่อน", "sys": "II"}, {"topic": "Surgery", "q": "A 48-year-old woman with a thyroid nodule 2 months, no hoarseness/compressive symptoms, goiter 10 years. PE: diffuse thyroid enlargement with a 2 cm hard nodule. TFT normal. Appropriate investigation?", "choices": ["Thyroid antibody", "Thyroid ultrasonography", "Thyroid scan", "CT neck", "Fine needle aspiration biopsy"], "ans": 4, "exp": "thyroid nodule แข็ง 2 ซม. + TFT ปกติ -> FNA (fine needle aspiration) เพื่อดู cytology (มักทำร่วม/หลัง ultrasound)", "sys": "IV"}, {"topic": "Medicine", "q": "A 60-year-old man on hydrochlorothiazide and enalapril for HT complains of dizziness on positional change. BP supine 150/100, sitting 140/100, BMI 28. Most proper management?", "choices": ["Recommend home BP monitoring", "Reassure that it is a physiologic change", "Increase hydrochlorothiazide", "Increase the third drug", "Recommend a polysomnogram"], "ans": 0, "exp": "ความดันยังคุมไม่ดี (140-150/90-100) + มีอาการเวียนหัวเปลี่ยนท่า -> ควรให้วัด BP ที่บ้าน (home BP monitoring) เพื่อประเมินก่อนปรับยา", "sys": "flex"}, {"topic": "Forensic", "q": "A 40-year-old construction worker was found dead; police suspect a fall from height. Which is the best supporting evidence?", "choices": ["Lung laceration", "Calcaneus fracture", "Liver rupture", "Pelvic fracture", "Ring fracture of the skull base"], "ans": 1, "exp": "ตกจากที่สูงลงด้วยเท้า -> แรงกระแทกตามแนวแกน ทำให้ calcaneus (กระดูกส้นเท้า) หัก เป็นหลักฐานคลาสสิก (ร่วมกับ burst fracture ของกระดูกสันหลังและ ring fracture ฐานกะโหลก)", "sys": "general"}, {"topic": "Psychiatry", "q": "An 18-year-old woman found unconscious; parents report she is very strict about her diet, counts calories, sometimes purges, and is very conscious about her weight. PE: thin, BMI below standard. Most likely diagnosis?", "choices": ["Obsessive-compulsive disorder", "Bulimia nervosa", "Anorexia nervosa", "Body dysmorphic disorder", "Adjustment disorder"], "ans": 2, "exp": "จำกัดอาหารเข้มงวด + กลัวอ้วน + BMI ต่ำกว่าเกณฑ์ = anorexia nervosa (แม้จะมี purge บ้าง แต่ตัดสินด้วยน้ำหนักตัวต่ำ). bulimia มักน้ำหนักปกติ", "sys": "V"}, {"topic": "Dermatology", "q": "A 17-year-old woman with recurrent itchy vesicles on her hands. PE: deep-seated papulovesicles on the middle and index fingers of both hands. Proper management?", "choices": ["Topical mupirocin", "Topical salicylate", "Topical acyclovir", "Topical triamcinolone", "Topical ketoconazole"], "ans": 3, "exp": "ตุ่มน้ำคันฝังลึกที่นิ้ว/มือเป็นซ้ำ ๆ = dyshidrotic eczema (pompholyx) -> รักษาด้วย topical corticosteroid (triamcinolone)", "sys": "XII"}, {"topic": "Surgery", "q": "A 25-year-old breastfeeding woman with left breast pain 5 days. PE: T 38, a 4 cm red, warm, tender mass at the outer quadrant; US: mixed hypo-hyperechoic 5x5x6 cm. Apart from IV antibiotics, most appropriate management?", "choices": ["Cold compression", "Incision and drainage", "Wide excision", "Observation", "Needle aspiration (may repeat)"], "ans": 4, "exp": "lactational breast abscess -> first-line ปัจจุบันคือ US-guided needle aspiration (ทำซ้ำได้) + antibiotics; ทำ I&D เมื่อก้อนใหญ่มาก/ผิวหนังใกล้แตก/ดูดไม่ได้ผล", "sys": "II"}, {"topic": "Obstetrics & Gynecology", "q": "A postmenopausal woman with diabetes has continuous urine leakage. Post-void residual is 250 ml. Pelvic exam: atrophic vagina, no prolapse. UA: WBC 3-5, RBC 2. Most likely diagnosis?", "choices": ["Neurogenic bladder", "Cervicitis", "Mixed urinary incontinence", "Stress incontinence", "Urge incontinence"], "ans": 0, "exp": "ปัสสาวะเล็ดตลอดเวลา + PVR สูง (250 ml, ปัสสาวะคั่ง) ในผู้ป่วยเบาหวาน = overflow incontinence จาก neurogenic (diabetic) bladder", "sys": "IV"}, {"topic": "Obstetrics & Gynecology", "q": "A pregnant woman GA 12 weeks: fundal height GA 16 weeks. US: uterus with multiple cystic structures, ovaries with bilateral anechoic multiloculated cysts. Identity of the ovarian cysts?", "choices": ["Serous adenoma", "Theca luteal cyst", "Corpus luteal cyst", "Mucinous cyst", "Dermoid cyst"], "ans": 1, "exp": "มดลูกโตกว่าอายุครรภ์ + multiple cystic (molar pregnancy) + รังไข่ 2 ข้างเป็น multiloculated cyst = theca lutein cysts จากการกระตุ้นของ hCG ที่สูงมาก", "sys": "XV"}, {"topic": "Neurology", "q": "An elderly patient has hand shaking when holding an object, normal gait, and otherwise normal exam. Appropriate management?", "choices": ["Levodopa", "Diazepam", "Propranolol", "Trihexyphenidyl", "Primidone"], "ans": 2, "exp": "tremor ขณะถือของ (action/postural tremor) โดย gait ปกติ = essential tremor -> first-line propranolol", "sys": "VI"}, {"topic": "Orthopedics", "q": "A 33-year-old man with back pain after lifting a heavy object. PE: weakness of extensor hallucis longus, positive straight leg raise. Most likely diagnosis?", "choices": ["Spondylolisthesis", "Spondylolysis", "Ankylosing spondylitis", "Disc herniation", "Acute back strain"], "ans": 3, "exp": "อ่อนแรง EHL (L5) + SLR บวก = lumbar disc herniation (L4-5) กดรากประสาท L5", "sys": "XIII"}, {"topic": "Pediatrics", "q": "A boy with difficulty breathing, rhinorrhea and nasal congestion. PE: bilateral pale nasal turbinates, expiratory wheezing both lungs. Most likely diagnosis?", "choices": ["Pneumonia", "Acute bronchitis", "Acute bronchiolitis", "Foreign body aspiration", "Acute asthmatic attack"], "ans": 4, "exp": "เยื่อบุจมูกซีดบวม (allergic) + expiratory wheeze ทั้งสองข้าง = acute asthmatic attack (asthma มี atopy ร่วม)", "sys": "X"}, {"topic": "Ophthalmology", "q": "A 44-year-old woman with blurred near vision when reading for 6 months, frequent headaches and periocular pain without red eyes. VA 20/20. Which lens should be prescribed?", "choices": ["Plus (convex) lens", "Prism lens", "Minus (concave) lens", "Cylinder lens", "Bifocal only"], "ans": 0, "exp": "อายุ 44 ปี มองใกล้ไม่ชัด + ปวดกระบอกตา = presbyopia/hyperopia -> ใช้ plus (convex) lens ช่วยการเพ่งมองใกล้", "sys": "VII"}, {"topic": "Dermatology", "q": "A 22-year-old woman with target-lesion rashes on her palms and soles after taking over-the-counter drugs. Most likely diagnosis?", "choices": ["Acute HIV", "Drug eruption (erythema multiforme)", "Secondary syphilis", "Hand-foot-mouth disease", "Contact dermatitis"], "ans": 1, "exp": "target lesion (ผื่นวงเป้า) หลังกินยา = erythema multiforme ซึ่งเป็น drug eruption. secondary syphilis เป็น copper-colored macules ที่ฝ่ามือฝ่าเท้า ไม่ใช่ target", "sys": "XII"}, {"topic": "Obstetrics & Gynecology", "q": "A 40-year-old woman with abnormal uterine bleeding, last menstruation 15 days ago, denies herbal use. Next appropriate management?", "choices": ["Transvaginal ultrasonography", "Endometrial sampling", "Urine pregnancy test", "Hysteroscopy", "Reassurance"], "ans": 2, "exp": "AUB ในวัยเจริญพันธุ์ -> ต้อง 'exclude pregnancy' ก่อนเสมอด้วย urine pregnancy test ก่อนสืบค้นอื่น ๆ", "sys": "XV"}, {"topic": "Ethics", "q": "A 12-year-old boy in a car accident: BP 90/60, PR 140, E1VTM5, needs immediate exploratory laparotomy; parents are on the way. Who can give consent?", "choices": ["His teacher", "His parents", "His brother", "Consent can be omitted", "Hospital director"], "ans": 3, "exp": "ภาวะฉุกเฉินคุกคามชีวิตและไม่มีผู้แทนโดยชอบธรรมอยู่ทันเวลา -> ใช้หลัก emergency (implied consent) ทำได้เลยโดยละเว้นการขอความยินยอม", "sys": "general"}, {"topic": "Forensic", "q": "A male found dead in a car with an extinguished burning stove, seated at the driver position. Postmortem lividity is bright red at the lower back. Cause of death?", "choices": ["Cyanide poisoning", "Hydrogen sulfide poisoning", "Sulfur dioxide poisoning", "Carbon dioxide poisoning", "Carbon monoxide poisoning"], "ans": 4, "exp": "เตาเผาไหม้ในรถปิด + livor สีแดงสด (cherry-red) = carbon monoxide poisoning (CO จับ Hb เป็น carboxyhemoglobin)", "sys": "general"}, {"topic": "Ophthalmology", "q": "A 50-year-old woman with a pterygium: wedge-shaped fibrovascular tissue with 3 mm corneal invasion. Which associated symptom is an indication for excision?", "choices": ["Astigmatism", "Glaucoma", "Cataract", "Strabismus", "Myopia"], "ans": 0, "exp": "ข้อบ่งชี้ผ่าตัด pterygium ได้แก่ ลุกลามใกล้/บังแกนการมองเห็น หรือทำให้เกิด astigmatism (สายตาเอียง) รบกวนการมองเห็น", "sys": "VII"}, {"topic": "Community/EBM", "q": "A community intervention reduces sweetness in desserts, reduces selling of sweet products, and builds a playground to prevent dental caries and obesity. Which type of prevention?", "choices": ["Primary", "Primordial", "Secondary", "Tertiary", "Quaternary"], "ans": 1, "exp": "การปรับสิ่งแวดล้อม/สังคมเพื่อป้องกันไม่ให้ 'ปัจจัยเสี่ยง' เกิดขึ้นในประชากร (ลดการขายของหวาน สร้างสนามเด็กเล่น) = primordial prevention", "sys": "general"}, {"topic": "Psychiatry", "q": "A man admitted with pancreatitis develops agitation and disorientation to time, place, and person on the third day. Most proper drug?", "choices": ["Haloperidol", "Risperidone", "Diazepam", "Quetiapine", "Lorazepam"], "ans": 2, "exp": "pancreatitis มักสัมพันธ์กับสุรา + สับสน/กระวนกระวายวันที่ 3 = alcohol withdrawal (delirium tremens) -> รักษาด้วย benzodiazepine (diazepam) + thiamine. *ถ้าเป็น delirium ทั่วไปไม่ใช่ถอนสุรา จะใช้ haloperidol*", "sys": "V"}, {"topic": "Orthopedics", "q": "A 25-year-old man with severe left knee pain after a motorcycle accident, cannot bend the knee. PE: stable vitals, no open wound, swelling and deformity at the left knee. Appropriate management?", "choices": ["Merchant view of the knee", "CT of the knee", "MRI of the knee", "Palpate distal pulse", "Emergency fasciotomy"], "ans": 3, "exp": "เข่าผิดรูปหลังอุบัติเหตุ (สงสัย knee dislocation) -> ประเมิน neurovascular ก่อน โดยเฉพาะคลำชีพจรปลายเท้า (เสี่ยง popliteal artery injury)", "img": "https://cdn.jsdelivr.net/gh/MercenzK/Web-quiz-images@main/NL2-2022-AM-Q59.png", "sys": "XIII"}, {"topic": "Obstetrics & Gynecology", "q": "A primigravida GA 10 weeks with vaginal bleeding. PV: cervical os open 1 cm, no tissue, no fetal heart rate, CRL 8 weeks. Proper management?", "choices": ["Follow-up ultrasound", "Progesterone", "Fractional curettage", "Expectant management", "Manual vacuum aspiration (MVA)"], "ans": 4, "exp": "เลือดออก + ปากมดลูกเปิด + ไม่มี FHR (ตัวอ่อนไม่รอด) = inevitable/incomplete abortion ในไตรมาสแรก -> ยุติด้วย MVA (manual vacuum aspiration)", "sys": "XV"}, {"topic": "Medicine", "q": "A 50-year-old man for check-up: LFT near normal (Alb 3.3). US: diffuse coarse liver echogenicity and a 2 cm hypoechoic nodule in the right lobe. Next proper investigation?", "choices": ["CT whole abdomen (triphasic)", "CEA and CA19-9", "HBsAg and anti-HCV", "Hepatic fibroscan", "Liver biopsy"], "ans": 0, "exp": "ก้อนในตับที่มีพื้นหลัง cirrhosis (coarse echogenicity) -> characterize ด้วย triphasic CT/MRI เพื่อประเมิน HCC", "sys": "XI"}, {"topic": "Pediatrics", "q": "A 10-year-old boy develops generalized rash and wheezing after eating shrimp. Appropriate initial management?", "choices": ["IV hydrocortisone", "Intramuscular epinephrine", "IV antihistamine", "Nebulized salbutamol", "IV fluids only"], "ans": 1, "exp": "ผื่นลมพิษทั่วตัว + wheezing (respiratory) หลังกินอาหารทะเล = anaphylaxis -> IM adrenaline (epinephrine) ทันที", "sys": "IV"}, {"topic": "Pediatrics", "q": "A 1-month-old infant with non-bilious projectile vomiting. PE: dry lips, palpable 2 cm ill-defined (olive) mass. Most likely diagnosis?", "choices": ["Midgut volvulus", "Intussusception", "Hypertrophic pyloric stenosis", "Duodenal web", "Gastroesophageal reflux"], "ans": 2, "exp": "อาเจียนพุ่ง 'ไม่มีน้ำดี' อายุ ~1 เดือน + คลำได้ก้อน olive = hypertrophic pyloric stenosis", "sys": "XI"}, {"topic": "Pediatrics", "q": "A 3-year-old girl with dark urine and fatigue 3 days. Hb 8, MCV 62, WBC 20,000, platelet 450,000. PBS: anisopoikilocytosis, pencil cells, target cells. Most proper investigation?", "choices": ["Serum ferritin", "G6PD assay", "Direct Coombs test", "Hb typing", "Osmotic fragility test"], "ans": 3, "exp": "ซีด microcytic (MCV 62) + target cell/pencil cell ในเด็กไทย = thalassemia -> ตรวจ Hb typing เพื่อวินิจฉัย", "sys": "III"}, {"topic": "Ethics", "q": "A 75-year-old man with resectable CA head of pancreas planned for Whipple. On the day of surgery he refuses the operation while his family insists on proceeding. Which ethical principle guides the decision?", "choices": ["Beneficence", "Non-maleficence", "Professionalism", "Justice", "Autonomy"], "ans": 4, "exp": "ผู้ป่วยที่มีความสามารถในการตัดสินใจมีสิทธิ์ปฏิเสธการรักษา = หลัก autonomy (เหนือความต้องการของครอบครัว)", "sys": "general"}, {"topic": "Emergency", "q": "A 70-year-old man with DM/HT: chest pain radiating to the back, then right-sided weakness. BP right arm 130/60, left arm 200/100; dysarthria, left facial palsy, right hemiplegia. Most appropriate management?", "choices": ["Labetalol", "rt-PA", "Amlodipine", "Sodium nitroprusside", "Aspirin + clopidogrel"], "ans": 0, "exp": "ปวดอกร้าวหลัง + ความดันแขนสองข้างต่างกันมาก + stroke = aortic dissection (ลามถึง carotid) -> ควบคุม HR/BP ด้วย labetalol. ห้ามให้ rt-PA (อันตรายถึงชีวิตใน dissection)", "sys": "emergency"}, {"topic": "Pediatrics", "q": "A 3-month-old boy with constipation and rectal bleeding. PE: palpable mass at LLQ, no toilet training, fed cow milk 3 cartons/day, dislikes vegetables. Proper management?", "choices": ["Probiotics", "Decrease the amount of milk intake", "Change to another type of milk", "Toilet training", "Yoghurt supplement"], "ans": 1, "exp": "ท้องผูกจากดื่มนมวัวมากเกิน (3 กล่อง/วัน) + กินผักน้อย = functional constipation -> ลดปริมาณนม เพิ่มใยอาหาร/น้ำ", "sys": "II"}, {"topic": "Infectious disease", "q": "A woman with 1-month fever and weight loss, generalized rubbery movable lymphadenopathy; anti-HIV positive, CD4 250. Proper management?", "choices": ["Reassurance", "Isoniazid alone", "Tenofovir/Lamivudine/Dolutegravir", "Isoniazid/Rifampin/Ethambutol/Pyrazinamide", "Trimethoprim-sulfamethoxazole prophylaxis"], "ans": 2, "exp": "ผู้ป่วย HIV ต้องเริ่ม ART โดยเร็วไม่ว่า CD4 เท่าไร -> tenofovir/lamivudine/dolutegravir (TDF/3TC/DTG)", "sys": "I"}, {"topic": "Pediatrics", "q": "A child delivered at home is diagnosed with neonatal tetanus. Proper tetanus vaccine regimen?", "choices": ["Today, 2, 4 months", "Today, 4, 6 months", "2, 4, 6 months", "Today, 2, 4, 6 months", "4, 6 months"], "ans": 3, "exp": "การป่วยเป็นบาดทะยักไม่สร้างภูมิคุ้มกัน -> ต้องให้ tetanus toxoid เป็น active immunization ครบชุด เริ่มวันนี้แล้วต่อเนื่องตามตาราง (today, 2, 4, 6 เดือน)", "sys": "XVI"}, {"topic": "Medicine", "q": "A 60-year-old with DM/HT and infectious diarrhea is on ceftriaxone, enalapril, hydrochlorothiazide, metformin; then given diclofenac for gout. Labs: Cr 3.5, Na 132, K 5.8, HCO3 15. Which drug can be continued?", "choices": ["Enalapril", "Hydrochlorothiazide", "Metformin", "Diclofenac", "Ceftriaxone"], "ans": 4, "exp": "AKI + hyperkalemia -> ต้องหยุด enalapril (hyperK/AKI), HCTZ, metformin (lactic acidosis), diclofenac (NSAID nephrotoxic). ceftriaxone ให้ต่อได้ (รักษาการติดเชื้อ ปรับขนาดตามไต)", "sys": "III"}, {"topic": "Surgery", "q": "A 40-year-old man with abdominal pain 6 hours, starting abruptly from the epigastrium then generalized, not relieved by NSAIDs. PE: BT 38, generalized tenderness, rebound tenderness, guarding. Apart from fluid resuscitation, most appropriate initial management?", "choices": ["Upright film / CT to confirm perforation", "MRI abdomen", "Ultrasound abdomen", "Colonoscopy", "Observation"], "ans": 0, "exp": "peritonitis เฉียบพลัน (rebound + guarding) สงสัย perforated viscus -> ยืนยันด้วย upright film/CT (หา free air) แล้วเตรียมผ่าตัด", "sys": "I"}, {"topic": "Pediatrics", "q": "A 7-year-old boy with fever and sore throat 3 days. PE: BT 39, injected pharynx with petechiae on soft palate, tonsil 3+ with exudate, tender left cervical node. Most appropriate management?", "choices": ["Cloxacillin", "Amoxicillin", "Cefditoren", "Azithromycin", "Supportive treatment"], "ans": 1, "exp": "exudative tonsillitis + petechiae เพดานอ่อน + ต่อมน้ำเหลืองเจ็บ = group A strep pharyngitis -> amoxicillin/penicillin", "sys": "X"}, {"topic": "Pediatrics", "q": "A newborn Apgar 4,5 with effective PPV, HR 140, but persistent apnea and SpO2 65% at 2 minutes. Maternal pethidine 2 hours before delivery. Next most proper management?", "choices": ["Give naloxone", "Increase FiO2", "Endotracheal intubation", "Give O2 by tubing", "Give CPAP"], "ans": 2, "exp": "apnea ต่อเนื่องแม้ PPV มีประสิทธิภาพ (แต่ SpO2 ยังต่ำ) -> secure airway ด้วย endotracheal intubation. *NRP ปัจจุบันไม่แนะนำ naloxone ในห้องคลอด (เสี่ยงชักถ้าแม่ติดยา)*", "sys": "XVI"}, {"topic": "Psychiatry", "q": "A man was yelled at by his boss; at home he shouts at his wife, who shouts at their son, who kicks the dog. What is the role of the wife, son, and the dog?", "choices": ["Alliance", "Coalition", "Follower", "Scapegoat", "Identified patient"], "ans": 3, "exp": "อารมณ์โกรธถูกโยน/displaced ลงมาตามลำดับ ผู้ที่รับอารมณ์แทน = scapegoat (แพะรับบาป)", "sys": "V"}, {"topic": "Medicine", "q": "A woman with dyspnea 5 days after knee surgery. PE: RR 22, SpO2 90%, leg swelling. ECG normal sinus rhythm, CXR normal. Proper management?", "choices": ["rt-PA", "NSAIDs", "Aspirin", "Observation", "Heparin (anticoagulation)"], "ans": 4, "exp": "หลังผ่าตัดเข่า + หอบ + ขาบวม + hypoxia + ECG/CXR ปกติ = pulmonary embolism -> ผู้ป่วย stable ให้ anticoagulation (heparin)", "sys": "I"}, {"topic": "Ophthalmology", "q": "A patient with progressive painless blurred vision worsened by bright light. VA 20/40, IOP 18 mmHg both eyes. Appropriate management?", "choices": ["Wear sunglasses (conservative)", "Laser iridotomy", "Timolol eye drops", "Urgent surgical intervention", "Pilocarpine drops"], "ans": 0, "exp": "ตามัวก้าวหน้าไม่ปวด + แย่ลงในที่สว่าง (glare) + IOP ปกติ = cataract ระยะต้น (VA 20/40) -> conservative (แว่นกันแดด/ปรับสายตา); ผ่าตัดเมื่อรบกวนการมองเห็นมาก", "sys": "VII"}, {"topic": "Pediatrics", "q": "A 14-year-old obese boy with acanthosis nigricans, HDL 50, TC 200, TG 200, FBS 105. Appropriate management?", "choices": ["Simvastatin", "Weight reduction (lifestyle)", "Metformin", "Enalapril", "Orlistat"], "ans": 1, "exp": "วัยรุ่นอ้วน + acanthosis nigricans + prediabetes (FBS 105) -> first-line คือ lifestyle/weight reduction ก่อนพิจารณายา", "sys": "IV"}, {"topic": "Dermatology", "q": "A 60-year-old with 6-month leg pruritus. PE: symmetrical, ill-defined hyperpigmented lichenified plaques on the medial ankles with varicose veins. Most likely diagnosis?", "choices": ["Atopic dermatitis", "Shoe dermatitis", "Stasis (venous) eczema", "Asteatotic eczema", "Nummular eczema"], "ans": 2, "exp": "ผื่นคันหนาคล้ำที่ข้อเท้าด้านในทั้งสองข้าง + เส้นเลือดขอด = stasis (venous) dermatitis จากภาวะเลือดดำคั่ง", "sys": "XII"}, {"topic": "Neurology", "q": "A patient with asymmetrical bradykinesia and cogwheel rigidity. Treatment? (ต้นฉบับมีตัวเลือกไม่ครบ ใส่เท่าที่มี)", "choices": ["Propranolol", "Trihexyphenidyl", "Levodopa", "Amantadine"], "ans": 2, "exp": "bradykinesia + cogwheel rigidity แบบไม่สมมาตร = Parkinson disease -> levodopa เป็นยาหลักที่ได้ผลดีสุด", "sys": "VI"}, {"topic": "Surgery", "q": "A 70-year-old woman with painless rectal bleeding and a history of cervical cancer treated with radiotherapy 20 years ago. PR: tenderness in the rectal canal, fresh blood, no mass. Diagnosis?", "choices": ["Bleeding hemorrhoid", "Bleeding diverticulosis", "Recurrent cervical cancer", "Rectal carcinoma", "Radiation proctitis"], "ans": 4, "exp": "เลือดออกทวารไม่ปวด + ประวัติฉายแสงบริเวณเชิงกราน (cervical cancer) เมื่อ 20 ปีก่อน = radiation proctitis (เยื่อบุลำไส้ตรงอักเสบจากรังสี)", "sys": "II"}, {"topic": "Pediatrics", "q": "A 10-year-old boy with left knee pain after football and a history of multiple ecchymoses. CBC: Hb 10.5, WBC 4000, Plt 160,000; aPTT 50 s, INR 1.1. Most likely diagnosis?", "choices": ["Hemophilia", "Septic arthritis", "Platelet dysfunction with eosinophilia", "von Willebrand disease", "Immune thrombocytopenia"], "ans": 0, "exp": "เลือดออกในข้อ (hemarthrosis) + aPTT ยืด แต่ PT/เกล็ดเลือดปกติ = ความผิดปกติ intrinsic pathway = hemophilia (factor VIII/IX deficiency)", "sys": "III"}, {"topic": "Pediatrics", "q": "A 9-year-old boy with asthma has dyspnea and wheezing not resolved after salbutamol 1 hour ago. BT 38, SpO2 92%. PE: poor air entry, expiratory wheezing both lungs. Most proper management? (ต้นฉบับมีตัวเลือกไม่ครบ ใส่เท่าที่มี)", "choices": ["Endotracheal intubation", "Nebulized salbutamol (continuous) + steroid", "IV magnesium sulfate", "IV aminophylline"], "ans": 1, "exp": "acute asthma exacerbation ที่ยังหายใจได้ (SpO2 92) -> ให้ nebulized salbutamol (ต่อเนื่อง) + systemic steroid (+/- ipratropium); ETT เก็บไว้เมื่อใกล้ respiratory failure", "sys": "IX"}, {"topic": "Community/EBM", "q": "You are a physician at a 30-bed hospital. What is the most effective measure to prevent tuberculosis in healthcare workers?", "choices": ["Instruct every healthcare worker to wear an N95 mask", "Perform tuberculin testing in healthcare workers", "Instruct every suspected TB patient to wear a mask (source control)", "Separate a ward for TB patients", "Install air conditioners in every OPD clinic"], "ans": 2, "exp": "ตามลำดับการควบคุมการติดเชื้อ administrative/source control (ให้ผู้ป่วยที่สงสัย TB ใส่หน้ากากปิดแหล่งแพร่) มีประสิทธิภาพและคุ้มค่าสุด เหนือ environmental และ PPE (N95)", "sys": "general"}, {"topic": "Pediatrics", "q": "A 10-year-old boy treated with ORS and probiotics for diarrhea; stool culture grows Salmonella Paratyphi. He is now afebrile with no diarrhea. Proper management?", "choices": ["Cefdinir", "Continue probiotics", "No treatment", "Norfloxacin (or ceftriaxone/azithromycin)", "Loperamide"], "ans": 3, "exp": "Salmonella Paratyphi = เชื้อกลุ่ม enteric (typhoidal) fever ต้องให้ยาปฏิชีวนะ (fluoroquinolone/ceftriaxone/azithromycin) แม้อาการดีขึ้น (ต่างจาก non-typhoidal salmonella gastroenteritis ที่หายเอง)", "sys": "I"}, {"topic": "Infectious disease", "q": "A butcher presents with headache and fever; Gram stain shows gram-positive cocci. Most likely causative agent? (ต้นฉบับมีตัวเลือกไม่ครบ ใส่เท่าที่มี)", "choices": ["Streptococcus suis", "Streptococcus pneumoniae", "Haemophilus influenzae"], "ans": 0, "exp": "คนชำแหละหมู/สัมผัสหมู + เยื่อหุ้มสมองอักเสบ GPC = Streptococcus suis (มักหูหนวกตามมา)", "sys": "I"}, {"topic": "Pediatrics", "q": "A 9-month-old with high-grade fever 2 days and a history of influenza contact. PE: BT 39, otherwise unremarkable; UA unremarkable. Next proper investigation?", "choices": ["Swab for influenza", "Urine culture", "Hemoculture", "Lumbar puncture", "Chest X-ray"], "ans": 0, "exp": "เด็กดูสบายดี ไข้สูง + ประวัติสัมผัสไข้หวัดใหญ่ + UA ปกติ -> ตรวจ influenza swab เพื่อยืนยัน/ให้ oseltamivir", "sys": "I"}, {"topic": "Neurology", "q": "A patient with generalized headache, denies nausea and vomiting. Most appropriate prevention? (ต้นฉบับมีตัวเลือกไม่ครบ ใส่เท่าที่มี)", "choices": ["Propranolol", "Ibuprofen", "Amitriptyline"], "ans": 2, "exp": "ปวดหัวแบบ tension-type (ทั่วศีรษะ ไม่มีคลื่นไส้อาเจียน) -> ยาป้องกันคือ amitriptyline. (propranolol ใช้ป้องกัน migraine)", "sys": "VI"}, {"topic": "Emergency", "q": "A 20-year-old brought from a burning building: unconscious, SpO2 96%. ABG: pH 7.25, PaCO2 40, PaO2 90, HCO3 18, O2 sat 95%. Most appropriate initial management?", "choices": ["NSS loading", "IV methylene blue", "100% oxygen", "IV dexamethasone", "Endotracheal tube"], "ans": 2, "exp": "ควันไฟ + ไม่รู้สึกตัว + metabolic acidosis ทั้งที่ SpO2/PaO2 ปกติ = พิษ CO/cyanide (tissue hypoxia) -> เริ่มด้วย 100% oxygen ทันที (antidote cyanide คือ hydroxocobalamin)", "sys": "emergency"}, {"topic": "Obstetrics", "q": "A woman G1P0 GA 33 weeks with fluid leakage. PE: uterine contractions, FHR 90 bpm. PV: cervix 3 cm, membrane rupture and a pulsatile tubular structure protruding. Most appropriate initial management?", "choices": ["Bladder filling", "Left lateral decubitus", "Emergency Cesarean delivery", "Lift the presenting part off the cord", "Fowler position"], "ans": 3, "exp": "สายสะดือย้อย (cord prolapse) + FHR ช้า -> ยกส่วนนำขึ้นพ้นสายสะดือทันทีเพื่อลดการกดทับ พร้อมเตรียมผ่าตัดคลอดฉุกเฉิน", "sys": "XV"}, {"topic": "Ophthalmology", "q": "A 35-year-old metal welder without protective glasses has sudden bilateral eye pain 2 hours, burning sensation, mixed conjunctival injection, photophobia, and blepharospasm. Most appropriate management?", "choices": ["Tetracaine eye drops", "Antihistamine eye drops", "Oral acetazolamide", "Oral prednisolone", "Artificial tears (lubrication + support)"], "ans": 4, "exp": "ช่างเชื่อมโลหะไม่ใส่แว่น + ปวดตาสองข้างเฉียบพลัน = ultraviolet (arc) photokeratitis -> รักษาประคับประคองด้วย lubricant/artificial tears (+/- cycloplegic, ปิดตา). ห้ามให้ topical anesthetic กลับบ้าน (เป็นพิษต่อกระจกตา)", "sys": "VII"}, {"topic": "Medicine", "q": "A 70-year-old man for annual check-up: BP 160/90, Cr 1.2, FBS 100, urine protein 1+, glucose trace. Most proper management?", "choices": ["Enalapril", "Atenolol", "Amlodipine", "Hydrochlorothiazide", "Doxazosin"], "ans": 0, "exp": "ความดันสูง + proteinuria -> เลือก ACE inhibitor (enalapril) เพื่อ renoprotection และลด proteinuria", "sys": "XIV"}, {"topic": "Psychiatry", "q": "A 14-year-old girl with angry outbursts, skipping school (no friends), staying in her room, failing tests, and admitted suicidal thoughts and self-harm; she used to be a good, friendly girl. Most likely diagnosis?", "choices": ["Conduct disorder", "Adjustment disorder", "School refusal", "Borderline personality disorder", "Oppositional defiant disorder"], "ans": 1, "exp": "เปลี่ยนแปลงพฤติกรรม/อารมณ์ (หงุดหงิด แยกตัว เรียนตก ทำร้ายตัวเอง) แบบเป็นปฏิกิริยา = adjustment disorder (ในวัยรุ่นแยกจาก MDD ด้วยระยะเวลา/ตัวกระตุ้น). *ควรประเมิน/เฝ้าระวัง suicidality อย่างใกล้ชิด*", "sys": "V"}, {"topic": "Emergency", "q": "A 30-year-old after a car accident with chest discomfort. PE: BP 80/60, RR 30, SpO2 70%, tracheal deviation to the left, decreased breath sound on the right, non-tender abdomen. Most appropriate initial management?", "choices": ["Tube thoracostomy", "Chest thoracotomy", "Needle thoracostomy (decompression)", "Endotracheal tube", "Exploratory laparotomy"], "ans": 2, "exp": "tracheal shift ไปซ้าย + เสียงหายใจขวาลด + ช็อก/hypoxia = tension pneumothorax ด้านขวา -> needle decompression ทันที แล้วตามด้วย chest tube", "sys": "emergency"}, {"topic": "Obstetrics", "q": "A breastfeeding woman with bilateral breast congestion, no swelling/tenderness/redness/mass, normal vital signs. Proper management?", "choices": ["Hot pack compression", "Dicloxacillin", "Bromocriptine", "Frequent breastfeeding", "Breast binder"], "ans": 3, "exp": "คัดตึงเต้านม (engorgement) ทั้งสองข้างโดยไม่มีการอักเสบ -> ให้ลูกดูดบ่อย ๆ (frequent breastfeeding) ระบายน้ำนม", "sys": "III"}, {"topic": "Pediatrics", "q": "A 10-year-old with poor school performance, cannot do homework, does not play with same-age children but gets along with younger children, delayed development since 1st grade. Most likely diagnosis?", "choices": ["Attention-deficit hyperactivity disorder", "Autism spectrum disorder", "Specific learning disorder", "Oppositional defiant disorder", "Intellectual disability"], "ans": 4, "exp": "พัฒนาการช้าตั้งแต่เล็ก + การเรียน/การปรับตัวต่ำกว่าวัย + เล่นกับเด็กเล็กกว่าได้ = intellectual disability", "sys": "V"}, {"topic": "Emergency", "q": "A 25-year-old man with a snake bite at the right ankle 4 hours ago. PE: fang marks, swelling and tenderness up to the inguinal area; VCT >30 min (coagulopathy). Most likely diagnosis?", "choices": ["Green pit viper bite", "Cobra bite", "Banded krait bite", "Malayan krait bite", "Malayan pit viper bite"], "ans": 0, "exp": "บวมเฉพาะที่มาก + coagulopathy (VCT ยืด) = งูพิษต่อระบบเลือด (hematotoxic) กลุ่ม pit viper; ที่พบบ่อยสุดในไทยคือ green pit viper. *Malayan pit viper ก็ทำให้ local รุนแรง+coagulopathy ได้เช่นกัน*", "sys": "emergency"}, {"topic": "Neurology", "q": "A 13-year-old girl with headache and vomiting; throbbing frontal pain, tingling in the right hand for 15 minutes then persistent pain, relieved by a dark quiet room. Most likely diagnosis?", "choices": ["Focal seizure", "Migraine with aura", "Tension-type headache", "Transient ischemic attack", "Idiopathic intracranial hypertension"], "ans": 1, "exp": "ปวดหัวตุบ ๆ + aura (ชามือ 15 นาที) + ดีขึ้นในที่มืดเงียบ = migraine with aura", "sys": "VI"}, {"topic": "Ophthalmology", "q": "A 30-year-old woman with painful red left eye and vision loss for a week. PE: ciliary injection, 1 mm hypopyon in the anterior chamber, irregular pupil. Most likely diagnosis?", "choices": ["Bacterial keratitis", "Fungal keratitis", "Acute anterior uveitis", "Herpes simplex keratitis", "Acute glaucoma"], "ans": 2, "exp": "ciliary injection + hypopyon + รูม่านตาผิดรูป (posterior synechiae) = acute anterior uveitis (iritis)", "sys": "VII"}, {"topic": "Pediatrics", "q": "A 3-year-old with severe otalgia 2 days; 4 days ago had mild otalgia and took amoxicillin. BT 38.5. PE: normal ear canal with a hemorrhagic vesicle on the tympanic membrane. Most proper management?", "choices": ["Add topical antibiotics", "IV ceftriaxone", "Vesicle breakage", "Change to amoxicillin-clavulanate", "Myringotomy"], "ans": 3, "exp": "ตุ่มเลือดที่แก้วหู = bullous myringitis (มักร่วม AOM) ที่ไม่ตอบสนอง amoxicillin -> เปลี่ยนเป็น amoxicillin-clavulanate (คลุมเชื้อดื้อ beta-lactamase) + ยาแก้ปวด", "sys": "V"}, {"topic": "Neurology", "q": "A patient with intermittent bilateral dull tightness around the forehead 2 months, no nausea or photophobia, each lasting 6 hours, twice a week, normal neuro exam. Most appropriate prevention?", "choices": ["Fluoxetine", "Ibuprofen", "Alprazolam", "Propranolol", "Amitriptyline"], "ans": 4, "exp": "ปวดตื้อรัดรอบศีรษะ 2 ข้าง ไม่มีคลื่นไส้/กลัวแสง = tension-type headache -> ยาป้องกันคือ amitriptyline", "sys": "VI"}, {"topic": "Surgery", "q": "A young woman with right lower quadrant pain, nausea, no fever/vomiting/diarrhea, no appetite loss. PE: mild RLQ tenderness, no guarding/rebound, normal PV. WBC 5,300. Appropriate management?", "choices": ["Serial abdominal examination", "Serial hematocrit", "Appendectomy", "Film abdomen", "Ultrasound RLQ"], "ans": 0, "exp": "อาการก้ำกึ่ง appendicitis (WBC ปกติ ไม่มี rebound/guarding) -> สังเกตอาการด้วย serial abdominal examination", "sys": "XI"}, {"topic": "Surgery", "q": "A 75-year-old man with poorly controlled HT and sudden abdominal pain. PE: BP 200/110, acutely ill, palpable pulsatile mass 6 cm above the umbilicus, no tenderness/guarding. Most likely diagnosis?", "choices": ["Aortic dissection", "Abdominal aortic aneurysm", "Ruptured splenic hematoma", "Mesenteric ischemia", "Small bowel obstruction"], "ans": 1, "exp": "ก้อนเต้นได้ (pulsatile) กลางท้อง 6 ซม. = abdominal aortic aneurysm", "sys": "II"}, {"topic": "Hematology", "q": "A 65-year-old with severe pneumonia 5 days, high fever. Hb 10, WBC 30,000 (N90%), Plt 30,000; PT 17, PTT 42; PBS: polychromasia and schistocytes. Etiology?", "choices": ["Evans syndrome", "Leukemoid reaction", "Disseminated intravascular coagulation", "Hemolytic uremic syndrome", "Thrombotic thrombocytopenic purpura"], "ans": 2, "exp": "sepsis + เกล็ดเลือดต่ำ + PT/PTT ยืด + schistocyte (MAHA) = DIC", "sys": "III"}, {"topic": "Pediatrics", "q": "A 12-hour-old newborn with mild jaundice. Hct 30%, total bilirubin 18, blood group A (mother O), reticulocyte 15, DAT mildly positive. Appropriate management?", "choices": ["Conventional phototherapy", "Partial exchange transfusion", "Total exchange transfusion", "Intensive phototherapy", "Observe"], "ans": 3, "exp": "ABO incompatibility hemolysis (mother O, baby A, DAT+) + bilirubin 18 ที่อายุ 12 ชม. (สูงมากในระยะแรก) -> intensive phototherapy และเตรียม exchange ถ้าไม่ลด", "sys": "XVI"}, {"topic": "Surgery", "q": "A 40-year-old woman for check-up, no breast mass. Mammogram + US: several small well-defined anechoic lesions with posterior enhancement. Most appropriate management?", "choices": ["Aspiration", "Core needle biopsy", "Excision", "Wide excision", "Reassure"], "ans": 4, "exp": "anechoic + posterior enhancement + ขอบชัด = simple cysts (BI-RADS 2, benign) -> reassure/สังเกต", "sys": "flex"}, {"topic": "Hematology", "q": "A 20-year-old man with fever and fatigue 1 day, mild pale and jaundice. CBC: Hb 7, WBC 12,000 with left shift (metamyelocytes), Plt normal, MCV 94. What would be found on the peripheral blood smear?", "choices": ["Bite cell", "Blast cell", "Pencil cell", "Inclusion body", "Basophilic stippling"], "ans": 0, "exp": "ซีดเฉียบพลัน + ตัวเหลือง + reticulocytosis (left shift) ในชายหนุ่มหลังมีไข้ = acute hemolysis จาก G6PD deficiency -> พบ bite cell (และ blister cell) ในสเมียร์", "sys": "III"}, {"topic": "Dermatology", "q": "A 28-year-old man with perianal itching and protruding masses; multiple male partners. PE: several small cauliflower masses with mucoid discharge. Most appropriate management?", "choices": ["Topical podophyllin", "Topical imiquimod", "HPV vaccine", "Cryoablation", "Excision"], "ans": 1, "exp": "condyloma acuminata (หูดหงอนไก่) ก้อนเล็กหลายก้อน -> ทาเองด้วย topical imiquimod (หรือ podophyllotoxin); cryotherapy/TCA เป็นทางเลือกที่ทำโดยแพทย์", "sys": "XII"}, {"topic": "Infectious disease", "q": "A 70-year-old farmer with DM presents with fever, headache, myalgia, and jaundice. PE: a black eschar-like lesion at the left groin. Most appropriate treatment?", "choices": ["Ceftazidime", "Ceftriaxone", "Doxycycline", "Meropenem", "Penicillin G"], "ans": 2, "exp": "ไข้ + ปวดเมื่อย + แผล eschar สีดำ = scrub typhus -> รักษาด้วย doxycycline. (ceftazidime ใช้ melioidosis)", "sys": "I"}, {"topic": "Dermatology", "q": "A 20-year-old with small papules, nodules, and pustules on the face. Most appropriate management?", "choices": ["Topical mupirocin", "Topical corticosteroid", "Oral clindamycin", "Topical retinoid (isotretinoin/adapalene)", "Systemic corticosteroid"], "ans": 3, "exp": "สิวอักเสบ (papulopustular) -> รากฐานการรักษาคือ topical retinoid (+/- topical antibiotic/BPO); ถ้าเป็น nodular รุนแรงจึงพิจารณา oral isotretinoin", "sys": "XII"}, {"topic": "Obstetrics", "q": "A G3P2 GA 38 weeks with previous Cesarean delivery presents with labor pain 5 hours, aggravated the last 30 minutes. PE: hypotension and absent fetal heart sounds. Most likely diagnosis?", "choices": ["Placental abruption", "Placenta previa", "Ruptured ovarian cyst", "Amniotic fluid embolism", "Uterine rupture"], "ans": 4, "exp": "ประวัติผ่าคลอดเดิม + เจ็บครรภ์แล้วอยู่ ๆ ความดันตก + ไม่ได้ยินเสียงหัวใจทารก = uterine rupture", "sys": "XV"}, {"topic": "Pediatrics", "q": "A 3-month-old boy: left testis not palpable in the scrotum since birth. PE: 1 cm firm oval at the left groin, empty left scrotum; right testis normal. Most appropriate management?", "choices": ["Follow up in 3 months", "Ultrasound groin", "Orchidopexy now", "hCG stimulation test", "Herniorrhaphy"], "ans": 0, "exp": "undescended testis ที่คลำได้ในขาหนีบ อายุ 3 เดือน -> ส่วนใหญ่ลงเองภายใน 6 เดือน จึงติดตามก่อน; ถ้าอายุ >6 เดือนยังไม่ลง จึง orchidopexy", "sys": "XVII"}, {"topic": "Obstetrics", "q": "A 35-year-old primigravida GA 35 weeks with a generalized tonic-clonic seizure. BP 150/100, no labor pain. PV: cervix 3 cm, station -1, membrane intact. Appropriate management?", "choices": ["IV labetalol", "IV magnesium sulfate", "IV phenytoin", "Emergency Cesarean delivery", "IV diazepam"], "ans": 1, "exp": "eclampsia (ชักในหญิงตั้งครรภ์ + ความดันสูง) -> ควบคุมชักด้วย magnesium sulfate เป็นอันดับแรก แล้วจึงคุมความดันและวางแผนคลอด", "sys": "XV"}, {"topic": "Obstetrics", "q": "A pregnant woman GA 38 weeks in labor with ruptured membranes. EFM: repeated variable decelerations, baseline 120-130. Proper management?", "choices": ["Pelvic examination", "Cesarean delivery", "Lie in left lateral decubitus position", "Amnioinfusion", "Oxytocin augmentation"], "ans": 2, "exp": "variable deceleration = การกดสายสะดือ -> จัดการเบื้องต้นด้วยการเปลี่ยนท่ามารดา (นอนตะแคงซ้าย) + ให้ออกซิเจน; amnioinfusion ถ้าเป็นซ้ำต่อเนื่อง", "sys": "XV"}, {"topic": "Neurology", "q": "A 30-year-old man with muscle weakness 2 hours after dinner, cannot get up. PE: proximal weakness grade III, DTR 1+, intact sensation, no cranial nerve involvement. Most useful investigation?", "choices": ["CXR", "EMG", "Muscle enzyme", "Thyroid function test", "Acetylcholine receptor antibody"], "ans": 3, "exp": "อ่อนแรงเป็นพัก ๆ หลังกินอาหาร (คาร์บ) = hypokalemic periodic paralysis ซึ่งในชายเอเชียมักสัมพันธ์ thyrotoxicosis -> ตรวจ TFT (ร่วมกับ serum K)", "sys": "VI"}, {"topic": "Forensic", "q": "A woman assaulted with corrosive acid leaving a 10 cm wound, now under treatment. The inquiry official asks you, her doctor, for comment. What is appropriate?", "choices": ["Tell the police she may have a scar", "Tell the police she will be permanently disfigured", "Tell the police this is life-threatening", "Tell the police who the suspect is", "Do not provide a definitive prognosis/information without proper process and patient consent"], "ans": 4, "exp": "ระยะแรกยังประเมิน 'อันตรายสาหัส/เสียโฉมถาวร' ไม่ได้ + ต้องรักษาความลับผู้ป่วย -> ไม่ให้ความเห็นชี้ขาด/ข้อมูลนอกกระบวนการที่ถูกต้องโดยไม่ได้รับความยินยอม (ออกความเห็นภายหลังตามกระบวนการทางการแพทย์-กฎหมาย)", "sys": "general"}, {"topic": "Cardiology", "q": "A patient with suspected infective endocarditis and multiple dental caries. Most appropriate empiric antibiotics?", "choices": ["Ceftriaxone + Gentamicin", "Cloxacillin", "Azithromycin", "Meropenem", "Vancomycin"], "ans": 0, "exp": "IE จากแหล่งฟันผุ = viridans streptococci -> empiric ceftriaxone + gentamicin (คลุม strep + synergy)", "sys": "IX"}, {"topic": "Obstetrics", "q": "A pregnant woman G1P0 GA 39 weeks in labor. EFM shows the figure. Interpretation?", "choices": ["Early deceleration", "Variable deceleration", "Late deceleration", "Sinusoidal pattern", "Bradycardia"], "ans": 1, "exp": "*จากกราฟจริง* FHR ลดลงแบบฉับพลันเป็นรูปตัว V ลึกและแคบ (onset ถึง nadir <30 วินาที) ไม่สัมพันธ์คงที่กับ contraction = variable deceleration (มักจาก cord compression). *ไม่ใช่ late เพราะ late จะค่อย ๆ ลงเป็นรูป U สมมาตร และ nadir ตามหลัง peak ของ contraction*", "img": "https://cdn.jsdelivr.net/gh/MercenzK/Web-quiz-images@main/NL2-2022-AM-Q117.png", "sys": "XV"}, {"topic": "Pediatrics", "q": "A 3-year-old boy cannot speak any word but can draw a circle, ride a tricycle, and dress himself. PE: normal eye contact, obeys commands with gesture, normal social interaction. Proper management?", "choices": ["IQ test", "MRI brain", "Auditory evaluation", "Methylphenidate", "Speech-behavioral intervention"], "ans": 2, "exp": "พัฒนาการช้าเฉพาะด้านภาษา (ไม่พูดเลยเมื่ออายุ 3 ปี) แต่ด้านอื่นปกติ -> ประเมินการได้ยิน (auditory evaluation) เป็นอันดับแรกเพื่อแยก hearing loss", "sys": "VIII"}, {"topic": "Ophthalmology", "q": "A patient hit by a golf ball on the left eye. VA 20/200. PE: laceration around the lateral canthus, distorted pupil, ecchymosis. Which condition is urgent for ophthalmology consultation?", "choices": ["Conjunctival laceration", "Corneal abrasion", "Subconjunctival hemorrhage", "Soft eye globe (suspected ruptured globe)", "Periorbital ecchymosis"], "ans": 3, "exp": "ลูกตานิ่ม (hypotony) + รูม่านตาผิดรูป หลัง blunt trauma = สงสัย globe rupture -> ภาวะฉุกเฉิน ปิดตาด้วย eye shield แล้วปรึกษาจักษุด่วน", "sys": "VII"}, {"topic": "Neurology", "q": "A 35-year-old woman with fluctuating proximal muscle weakness improved with rest. RR 40 with accessory muscle use, proximal weakness II/IV. Most likely diagnosis?", "choices": ["Lambert-Eaton syndrome", "Chronic inflammatory demyelinating polyradiculoneuropathy", "Guillain-Barre syndrome", "Periodic paralysis", "Myasthenia gravis"], "ans": 4, "exp": "อ่อนแรง proximal ที่ 'ดีขึ้นเมื่อพัก' (fatigable) + เริ่มมีปัญหาการหายใจ = myasthenia gravis (ระวัง myasthenic crisis)", "sys": "VI"}, {"topic": "Cardiology", "q": "A 65-year-old with ischemic cardiomyopathy (LVEF 35%) presents with dyspnea. BP 170/100, Cr 1.5, GFR 45. Which antihypertensive should be given?", "choices": ["Nitroglycerine", "Esmolol", "Labetalol", "Nicardipine", "Sodium nitroprusside"], "ans": 0, "exp": "หัวใจล้มเหลว + ความดันสูง + ปอดคั่งน้ำ -> nitroglycerine (ลด preload, ช่วย ischemia). หลีกเลี่ยง beta-blocker ใน acute decompensated HF และ nitroprusside ใน renal impairment", "sys": "IX"}, {"topic": "Orthopedics", "q": "A 30-year-old falls from 2 meters and is diagnosed with a calcaneus fracture. Next investigation for associated injury?", "choices": ["Film C-spine", "Film LS spine", "Film left knee", "Film left hip", "Film pelvis"], "ans": 1, "exp": "calcaneal fracture จากตกที่สูงลงด้วยเท้า สัมพันธ์กับ thoracolumbar (LS spine) burst fracture ตามแนวแกน -> ถ่ายฟิล์ม LS spine", "sys": "XIII"}, {"topic": "Endocrinology", "q": "A 60-year-old with poorly controlled DM and altered consciousness. PE: hyperpnea, BS 500. ABG: wide anion-gap metabolic acidosis. UA: protein 4+, sugar 2+, ketone negative. Most appropriate investigation?", "choices": ["Serum electrolytes", "Serum anion gap", "Serum beta-hydroxybutyrate", "Urine anion gap", "Urine electrolytes"], "ans": 2, "exp": "น้ำตาลสูง + wide-gap acidosis แต่ urine ketone (nitroprusside) ลบ เพราะตรวจไม่ได้ beta-hydroxybutyrate -> ยืนยัน DKA ด้วย serum beta-hydroxybutyrate", "sys": "IV"}, {"topic": "Rheumatology", "q": "An elderly man with end-stage renal disease has an acute gouty attack. Proper drug?", "choices": ["Colchicine", "Allopurinol", "Probenecid", "Prednisolone", "NSAIDs"], "ans": 3, "exp": "acute gout ใน ESRD: NSAIDs ห้ามใช้, colchicine สะสม/เสี่ยงพิษ, allopurinol/probenecid ไม่ใช้ในระยะเฉียบพลัน -> ให้ systemic corticosteroid (prednisolone)", "sys": "XIII"}, {"topic": "Pediatrics", "q": "A child with fever and blood sugar 200 mg/dL. Proper further investigation? (ต้นฉบับมีตัวเลือกไม่ครบ ใส่เท่าที่มี)", "choices": ["HbA1c", "Serum ketone", "Serum lactate"], "ans": 1, "exp": "เด็กมีไข้ + น้ำตาลสูง -> ตรวจ serum/urine ketone เพื่อแยก DKA/เบาหวานชนิดที่ 1 ที่เพิ่งเกิด จาก stress hyperglycemia", "sys": "IV"}, {"topic": "Psychiatry", "q": "A patient talks a lot more, spends too much money, and believes he was granted the moons power from God. He has a history of major depressive disorder and takes fluoxetine. Most likely diagnosis?", "choices": ["Bipolar disorder", "Brief psychotic disorder", "Schizophrenia", "Major depressive disorder with psychotic features", "Substance-induced psychosis"], "ans": 0, "exp": "อารมณ์ครึกครื้น พูดมาก ใช้เงินเยอะ + grandiose delusion = manic episode; เมื่อมีทั้ง manic และประวัติ depressive = bipolar disorder (อาจถูกกระตุ้นด้วย antidepressant)", "sys": "V"}, {"topic": "Pediatrics", "q": "A 12-year-old girl with epigastric pain, postprandial fullness, and nocturnal pain; mother had H. pylori infection. Appropriate initial management?", "choices": ["Stool occult blood", "Esophagogastroduodenoscopy", "Serum lipase", "Upper GI study", "Abdominal ultrasonography"], "ans": 1, "exp": "dyspepsia ที่มี alarm feature (ปวดกลางคืน) + ประวัติ H. pylori ในครอบครัว -> ส่องกล้อง EGD เพื่อประเมินและตรวจหา H. pylori", "sys": "XI"}, {"topic": "Medicine", "q": "A patient with dyspnea 2 days and 10 days of low-grade fever and cough. CXR: ground-glass appearance. Next proper investigation? (ต้นฉบับมีตัวเลือกไม่ครบ ใส่เท่าที่มี)", "choices": ["Serology for TB", "Serology/test for Pneumocystis (PCP)", "Sputum bacterial culture"], "ans": 1, "exp": "อาการกึ่งเฉียบพลัน + ground-glass ทั้งปอด -> นึกถึง Pneumocystis pneumonia (PCP) -> ตรวจหา PCP (induced sputum immunofluorescence/PCR) และหา HIV", "sys": "I"}, {"topic": "Pediatrics", "q": "A 5-year-old boy with a burning sensation in the mouth. BT 38.5. PE: vesicles on the lips, buccal mucosa, and anterior/lateral tongue. Proper management?", "choices": ["Oral penciclovir", "Topical acyclovir", "Topical penciclovir", "Oral acyclovir", "Oral dicloxacillin"], "ans": 3, "exp": "ตุ่มน้ำในช่องปาก + ไข้ ในเด็ก = herpetic gingivostomatitis (HSV) -> oral acyclovir (ได้ผลดีถ้าเริ่มเร็ว) + ดูแลการกิน/น้ำ", "sys": "III"}, {"topic": "Pediatrics", "q": "A 42-week newborn delivered to a 40-year-old mother without antenatal care. Apgar 6,9, low birth weight (<P10), unilateral cleft lip, meconium-stained cord. Most useful investigation?", "choices": ["Serial hematocrit", "Chest film", "Cranial ultrasound", "TORCH screening", "Chromosome study"], "ans": 4, "exp": "IUGR + cleft lip + มารดาสูงอายุ ไม่ฝากครรภ์ -> สงสัยความผิดปกติโครโมโซม (เช่น trisomy 13) -> chromosome study", "sys": "XV"}]}, {"id": "nl2-2022-pm", "title": "NL 2 ปี 2022 ภาคบ่าย (VICHAKARN_SMST)", "subject": "past", "questions": [{"topic": "Orthopedics", "q": "A 38-year-old woman with right wrist pain 4 months after delivery. PE: tenderness at the right radial styloid, pain on passive ulnar deviation. Most likely diagnosis?", "choices": ["De Quervain tenosynovitis", "Trigger thumb", "Intersection syndrome", "Carpal tunnel syndrome", "FCR tendinitis"], "ans": 0, "exp": "ปวดกดเจ็บที่ radial styloid + Finkelstein (ปวดเมื่อ passive ulnar deviation) หลังคลอด = De Quervain tenosynovitis", "sys": "XIII"}, {"topic": "Infectious disease", "q": "A 23-year-old man with a 2-day rash spreading from the upper torso downward, preceded by fever, sore throat and polyarthritis; denies sexual activity. PE: petechiae on soft palate, maculopapular rash, posterior auricular and posterior cervical lymphadenopathy. Most likely diagnosis?", "choices": ["Measles", "Rubella", "Infectious mononucleosis", "Acute retroviral syndrome", "Disseminated gonorrhea"], "ans": 1, "exp": "ผื่นลามจากศีรษะลงล่าง + ต่อมน้ำเหลืองหลังหู/ท้ายทอย/คอด้านหลัง + ข้ออักเสบในผู้ใหญ่ + Forchheimer spots = rubella (หัดเยอรมัน)", "sys": "I"}, {"topic": "Infectious disease", "q": "A 15-year-old with fever and headache 2 days, petechial purpura, positive stiff neck. CSF Gram stain: numerous PMN with intracellular gram-negative diplococci. After IV ceftriaxone, how long should isolation precautions continue?", "choices": ["48 hours", "72 hours", "24 hours", "60 hours", "Until discharge"], "ans": 2, "exp": "meningococcal meningitis ใช้ droplet precaution จนได้ยาปฏิชีวนะที่เหมาะสมครบ 24 ชั่วโมง", "sys": "I"}, {"topic": "Endocrinology", "q": "A 10-year-old girl with diffuse thyroid enlargement, eats seafood. PE: no nodule, diffuse non-tender thyroid 30 g. TSH, T3, T4 normal; anti-TPO negative. Most likely diagnosis?", "choices": ["Iodine deficiency", "Hashimoto thyroiditis", "Subacute thyroiditis", "Simple goiter", "Graves disease"], "ans": 3, "exp": "ต่อมไทรอยด์โตทั่ว ๆ ไม่เจ็บ + euthyroid + anti-TPO ลบ + ได้ไอโอดีนพอ (กินอาหารทะเล) = simple (colloid) goiter", "sys": "IV"}, {"topic": "Infectious disease", "q": "A 25-year-old man with a stray dog bite (3 cm laceration). He completed rabies and tetanus vaccination 5 years ago and received a rabies booster last year. Proper management?", "choices": ["Complete rabies vaccine + tetanus antitoxin", "Complete rabies vaccine + ERIG", "Rabies booster + ERIG", "No vaccine needed", "Rabies booster shot only"], "ans": 4, "exp": "เคยฉีดวัคซีนพิษสุนัขบ้าครบ + booster ปีที่แล้ว -> ให้แค่ booster 2 เข็ม (วันที่ 0, 3) ไม่ต้องให้ rabies immunoglobulin (RIG)", "sys": "I"}, {"topic": "Pediatrics", "q": "A 10-year-old with RLQ pain 12 hours, nausea, no vomiting/diarrhea. PE: mild RLQ tenderness, no rebound, active bowel sounds; PR minimal feces. WBC 9,800, UA normal. Most proper management?", "choices": ["Ultrasonography of the abdomen", "Serial abdominal examination", "Follow-up CBC", "Film abdomen", "Appendectomy"], "ans": 0, "exp": "สงสัยไส้ติ่งอักเสบก้ำกึ่งในเด็ก (WBC ปกติ ไม่มี rebound) -> ultrasonography เป็น imaging แรกในเด็กเพื่อยืนยัน", "sys": "XI"}, {"topic": "Pediatrics", "q": "A teenage girl with menorrhagia (7 days, 20-day interval, 4 pads/day), Hb 7, MCV 65 (iron-deficiency picture). Which supplement should be prescribed?", "choices": ["Folic acid", "Iron supplement", "Hb typing", "Vitamin B12", "Vitamin C"], "ans": 1, "exp": "เสียเลือดประจำเดือนมาก + microcytic hypochromic (Hb 7, MCV 65) = iron deficiency anemia -> ให้ iron supplement + หาสาเหตุเลือดออก", "sys": "III"}, {"topic": "Psychiatry", "q": "A 45-year-old brought to the ED with agitation and visual hallucinations that began 3 days after stopping alcohol. Proper initial management?", "choices": ["Haloperidol", "Risperidone", "Lorazepam", "Fluoxetine", "Sodium valproate"], "ans": 2, "exp": "alcohol withdrawal (agitation + visual hallucination ~3 วันหลังหยุด = delirium tremens) -> รักษาด้วย benzodiazepine (lorazepam) + thiamine", "sys": "V"}, {"topic": "Emergency", "q": "A 3-year-old drank a bleaching agent 15-30 minutes ago. V/S stable. Next most proper management?", "choices": ["NG lavage", "Activated charcoal", "Ipecac syrup", "Esophagogastroduodenoscopy", "Acid neutralization"], "ans": 3, "exp": "กลืนสารกัดกร่อน (caustic) -> ห้าม NG lavage/charcoal/ipecac/neutralize -> ทำ endoscopy (EGD) ภายใน 12-24 ชม.เพื่อประเมินความรุนแรงของแผล", "sys": "emergency"}, {"topic": "Obstetrics", "q": "A 25-year-old breastfeeding woman with left breast pain and difficulty feeding due to short nipples. PE: BT 38, left breast tenderness, no mass, no fluctuation. Proper management?", "choices": ["Stop breastfeeding from the left breast", "Switch to infant formula", "Suggest a breast binder", "Prescribe oral contraceptive pills", "Prescribe oral dicloxacillin + continue feeding"], "ans": 4, "exp": "lactational mastitis (เจ็บ + ไข้ ไม่มีก้อน/fluctuation) -> ให้นมต่อ (ระบายน้ำนม) + ยาปฏิชีวนะ oral dicloxacillin", "sys": "III"}, {"topic": "Orthopedics", "q": "A 10-year-old boy fell from a bicycle with right shoulder pain. X-ray: middle 1/3 right clavicle fracture, inferior displacement, anterior angulation. Most proper management?", "choices": ["Figure-of-eight binder / arm sling", "Spica cast", "Closed reduction with percutaneous pinning", "ORIF with plate and screws", "ORIF with K-wire"], "ans": 0, "exp": "กระดูกไหปลาร้าส่วนกลางหักในเด็ก -> รักษา conservative ด้วย figure-of-eight binder หรือ arm sling (หายได้ดี remodeling ดี)", "sys": "XIII"}, {"topic": "Obstetrics & Gynecology", "q": "A 25-year-old woman with cyclic dysmenorrhea and dyspareunia. PE: normal uterus, left cystic mass 6 cm, non-tender, tender nodule at the uterosacral ligament. Most likely diagnosis?", "choices": ["Dermoid cyst", "Endometrioma", "Theca lutein cyst", "Tubo-ovarian abscess", "Functional ovarian cyst"], "ans": 1, "exp": "ปวดประจำเดือน + เจ็บเวลามีเพศสัมพันธ์ + ก้อน cystic ที่รังไข่ + tender nodule ที่ uterosacral ligament = endometriosis/endometrioma", "sys": "II"}, {"topic": "Family Medicine", "q": "A 50-year-old woman cares for her bedridden mother with dementia all day and never brings the mother for follow-up; she asks how to care for her. Which type of home visit is appropriate?", "choices": ["Emergency home visit", "Assessment home visit", "Chronic illness home visit", "Acute illness home visit", "Palliative care home visit"], "ans": 2, "exp": "มารดามีโรคเรื้อรัง (dementia, ติดเตียง) ที่ต้องดูแลต่อเนื่องและขาดการติดตาม -> chronic illness home visit เพื่อประเมิน/วางแผนดูแลโรคเรื้อรังที่บ้าน", "sys": "general"}, {"topic": "Dermatology", "q": "A 70-year-old man with fever, rash, and a burning sensation on the left side of his chest (dermatomal). What would be found microscopically on a scrape of the lesion?", "choices": ["Inclusion body", "Spaghetti and meatballs", "Gram-negative coccobacilli", "Multinucleated giant cells", "Basophilic stippling"], "ans": 3, "exp": "ผื่นตุ่มน้ำเรียงตาม dermatome + แสบร้อน = herpes zoster -> Tzanck smear พบ multinucleated giant cells", "img": "https://cdn.jsdelivr.net/gh/MercenzK/Web-quiz-images@main/NL2-2022-PM-Q14.png", "sys": "XII"}, {"topic": "Psychiatry", "q": "A police officer with sleep trouble and nightmares 3 weeks after starting a murder case 5 weeks ago; he has startle, agitation, and flashbacks and took sick leave. Most likely diagnosis?", "choices": ["Panic disorder", "Acute stress disorder", "Normal reaction", "Adjustment disorder", "Post-traumatic stress disorder"], "ans": 4, "exp": "อาการ re-experiencing/hyperarousal/avoidance ที่คงอยู่ 'เกิน 1 เดือน' หลังเหตุการณ์สะเทือนใจ = post-traumatic stress disorder (ASD จะภายใน 1 เดือน)", "sys": "V"}, {"topic": "Pediatrics", "q": "A child with abdominal pain and both knee pain. PE: mild generalized abdominal tenderness, no joint swelling, palpable purpura on arms and legs. CBC and coagulogram normal. Next proper investigation?", "choices": ["Urinalysis", "ESR, CRP", "ANA, anti-dsDNA", "Rheumatoid factor", "Acute abdomen series"], "ans": 0, "exp": "palpable purpura + ปวดข้อ + ปวดท้อง + coagulogram ปกติ = HSP (IgA vasculitis) -> ตรวจ urinalysis หา renal involvement (HSP nephritis)", "sys": "III"}, {"topic": "Orthopedics", "q": "A 45-year-old marathon runner with right heel pain without trauma, worse when initiating a walk. PE: tenderness at the plantar side of the heel, no swelling, full ankle ROM. Diagnosis?", "choices": ["Achilles tendinitis", "Plantar fasciitis", "Ankle arthritis", "Stress fracture of the calcaneus", "Tarsal tunnel syndrome"], "ans": 1, "exp": "ปวดส้นเท้าฝ่าเท้า เจ็บมากตอนก้าวแรก (first-step pain) ในนักวิ่ง = plantar fasciitis", "sys": "XIII"}, {"topic": "Obstetrics & Gynecology", "q": "A woman with a protruding mass. PE: a 3 cm cystocele, cervix descends to within 1 cm of the ischial spine. Appropriate management?", "choices": ["Observe", "Kegel exercise", "Pessary", "Progesterone", "Hysterectomy"], "ans": 2, "exp": "pelvic organ prolapse (cystocele) ที่มีอาการก้อนยื่น -> ผู้ที่ไม่ผ่าตัด/ยังไม่พร้อมผ่า ใช้ pessary (ร่วม pelvic floor exercise)", "sys": "XIV"}, {"topic": "Hematology", "q": "A 50-year-old man with fatigue and altered consciousness 2 weeks, fever, hematuria, LDH 800. CBC: anemia, leukocytosis, thrombocytopenia. PBS: MAHA, normal PT/PTT. Most likely diagnosis?", "choices": ["Disseminated intravascular coagulation", "Immune thrombocytopenic purpura", "Hemolytic uremic syndrome", "Thrombotic thrombocytopenic purpura", "Evans syndrome"], "ans": 3, "exp": "MAHA + thrombocytopenia + ไข้ + ไต (hematuria) + ระบบประสาท (AOC) + PT/PTT ปกติ = TTP (pentad) -> รักษาด้วย plasma exchange", "sys": "III"}, {"topic": "Psychiatry", "q": "A 50-year-old widow feels depressed, bored, loss of appetite, wants to die, and sometimes hears a whisper telling her she should die; symptoms began after her 25-year-old son died 2 months ago. Most likely diagnosis?", "choices": ["Normal grief", "Schizophrenia with depressed mood", "Schizoaffective disorder", "Adjustment disorder with depressed mood", "Major depressive disorder with psychotic features"], "ans": 4, "exp": "อาการซึมเศร้าครบเกณฑ์ + อยากตาย + ประสาทหลอนที่สอดคล้องอารมณ์ (mood-congruent) หลังสูญเสียบุตร = major depressive disorder with psychotic features", "sys": "V"}, {"topic": "Emergency", "q": "A patient with shortness of breath and carpopedal spasm. Most proper management? (ต้นฉบับมีตัวเลือกไม่ครบ ใส่เท่าที่มี)", "choices": ["Reassure and coach slow breathing", "Cover the face with a bag and breathe", "IV calcium gluconate", "IV diazepam"], "ans": 0, "exp": "hyperventilation syndrome (หายใจเร็ว + carpopedal spasm) -> ให้ความมั่นใจและฝึกหายใจช้า ๆ; เลิกแนะนำถุงครอบหน้า (เสี่ยง hypoxia)", "sys": "emergency"}, {"topic": "Cardiology", "q": "A 40-year-old woman with dyspnea on exertion 6 months. PE: PMI at 6th ICS MCL (displaced), left parasternal heave, pansystolic murmur grade III at the apex radiating to the axilla. ECG: LA enlargement, LVH. Most likely diagnosis?", "choices": ["Pulmonary stenosis", "Mitral regurgitation", "Aortic stenosis", "Ventricular septal defect", "Hypertrophic cardiomyopathy"], "ans": 1, "exp": "pansystolic murmur ที่ apex ร้าวไป axilla + LA enlargement + displaced PMI = mitral regurgitation", "sys": "IX"}, {"topic": "Surgery", "q": "A woman with jaundice and pruritus. PE: marked icteric sclerae, palpable gallbladder. Lab: AST 50, ALT 60, ALP 300. Diagnosis?", "choices": ["Common bile duct stone", "Hepatocellular carcinoma", "CA ampulla (periampullary)", "Hilar cholangiocarcinoma", "CA body of pancreas"], "ans": 2, "exp": "ดีซ่านแบบอุดกั้น (ALP สูงเด่น) + ถุงน้ำดีโตคลำได้ (Courvoisier +) = อุดกั้นใต้ต่อ cystic duct = periampullary/ampullary carcinoma. (hilar cholangiocarcinoma อุดกั้นเหนือ cystic duct ถุงน้ำดีจะไม่โต)", "sys": "II"}, {"topic": "Obstetrics & Gynecology", "q": "A 25-year-old woman with RLQ pain awakening from sleep, severe, with nausea and vomiting. PE: RLQ tenderness with rebound; PV: right cervical motion tenderness, right adnexal mass. TVUS: 6 cm ovarian cyst. Diagnosis?", "choices": ["Ectopic pregnancy", "Tubo-ovarian abscess", "Ruptured appendiceal abscess", "Ovarian torsion", "Endometrioma"], "ans": 3, "exp": "ปวดท้องน้อยขวาเฉียบพลันรุนแรง + คลื่นไส้อาเจียน + ก้อนรังไข่ (cyst 6 ซม.) = ovarian torsion (ภาวะฉุกเฉินทางนรีเวช)", "sys": "XV"}, {"topic": "Surgery", "q": "A 50-year-old man with abdominal pain 1 day. V/S: BT 38, BP 80/50, PR 124. PE: generalized guarding, an irreducible tender right groin mass above the inguinal ligament. Most likely diagnosis?", "choices": ["Sliding hernia", "Femoral hernia", "Obstructed hernia", "Incarcerated hernia", "Strangulated hernia"], "ans": 4, "exp": "ไส้เลื่อนดันกลับไม่ได้ + กดเจ็บ + ภาวะ peritonitis/ช็อก (ไข้ + guarding + BP ตก) = strangulated hernia (ลำไส้ขาดเลือด) -> ผ่าตัดด่วน", "sys": "II"}, {"topic": "Obstetrics", "q": "A pregnant woman G2P1 GA 37 weeks with decreased fetal movement. US: no cardiac activity. PV: cervix 1 cm, 50% effacement, mild irregular contractions, cephalic. Most appropriate next management?", "choices": ["Misoprostol vaginal suppository", "Observe labor pain", "Oxytocin IV", "Amniotomy", "Cesarean delivery"], "ans": 0, "exp": "ทารกเสียชีวิตในครรภ์ (IUFD) + ปากมดลูกยังไม่พร้อม (1 ซม.) -> เร่งคลอดทางช่องคลอดด้วย misoprostol (cervical ripening/induction)", "sys": "XV"}, {"topic": "Forensic", "q": "Four workers unconsciously fell into a shallow cement tank and died. What is the most appropriate hazard?", "choices": ["Physical hazard", "Chemical hazard", "Biological hazard", "Biochemical hazard", "Psychological hazard"], "ans": 1, "exp": "หมดสติแล้วเสียชีวิตในถังปิด (confined space) หลายคน = แก๊สพิษ/ออกซิเจนต่ำ (เช่น H2S) = chemical hazard", "sys": "general"}, {"topic": "Pediatrics", "q": "A child with fever, cough, and rhinorrhea; nursery contacts recently diagnosed with influenza. BT 39, otherwise unremarkable. Most proper treatment?", "choices": ["Favipiravir", "Oseltamivir", "Reassure and supportive treatment", "Amoxicillin", "Azithromycin"], "ans": 2, "exp": "ไข้หวัดใหญ่ที่ไม่มีภาวะแทรกซ้อนในเด็กที่แข็งแรงดี -> รักษาประคับประคอง (supportive). *พิจารณา oseltamivir ถ้าเด็กเล็ก <2 ปี/กลุ่มเสี่ยง/รุนแรง ภายใน 48 ชม.*", "sys": "I"}, {"topic": "Pediatrics", "q": "An 8-month-old girl with cough and rhinorrhea 2 days. PE: conjunctivitis, injected pharynx, and whitish lesions on the oral mucosa. Possible associated complication?", "choices": ["Orchitis", "Glomerulonephritis", "Stevens-Johnson syndrome", "Subacute sclerosing panencephalitis", "Aseptic meningitis"], "ans": 3, "exp": "ไอ + น้ำมูก + ตาแดง (3 Cs) + Koplik spots (จุดขาวในปาก) = measles (หัด) -> ภาวะแทรกซ้อนระยะยาวคือ subacute sclerosing panencephalitis (SSPE)", "sys": "I"}, {"topic": "Psychiatry", "q": "A 15-year-old girl found unconscious; she has been on a diet and sometimes purges after meals. Weight 40 kg, height 165 cm (BMI 14.7). Most likely diagnosis?", "choices": ["Bulimia nervosa", "Binge eating disorder", "Body dysmorphic disorder", "Major depressive disorder", "Anorexia nervosa"], "ans": 4, "exp": "BMI ต่ำมาก (14.7) + จำกัดอาหาร/ล้วงอาเจียน = anorexia nervosa (binge-purge type). ตัดสินด้วยน้ำหนักตัวต่ำกว่าเกณฑ์", "sys": "V"}, {"topic": "Infectious disease", "q": "A patient with fever 3 days, multiple joint pain, and rash; a neighbor has the same manifestations. Most likely diagnosis?", "choices": ["Chikungunya", "Rubella", "Dengue", "Zika", "Leptospirosis"], "ans": 0, "exp": "ไข้ + ปวดข้อหลายข้อ + ผื่น เป็นกลุ่ม (outbreak) = chikungunya (เด่นเรื่องปวดข้อรุนแรง)", "sys": "I"}, {"topic": "Forensic", "q": "A car accident occurred at 18:00. The driver's blood alcohol at 23:00 (5 hours later) is 45 mg%. What was it at the time of the accident?", "choices": ["45 mg%", "120 mg%", "75 mg%", "200 mg%", "300 mg%"], "ans": 1, "exp": "แอลกอฮอล์ถูกกำจัด ~15 mg%/ชม. -> ย้อนกลับ 5 ชม. = 45 + (15x5) = 45 + 75 = 120 mg%", "sys": "general"}, {"topic": "ENT", "q": "A 40-year-old man after air travel with right-sided hearing loss. Otoscopy: right hemotympanum. Weber lateralizes to the right; Rinne right BC>AC. Most appropriate management?", "choices": ["Topical antibiotics", "Oral antibiotics", "Oral decongestant", "Tympanostomy tube", "Intratympanic steroid"], "ans": 2, "exp": "หลังขึ้นเครื่องบิน + hemotympanum + conductive loss ขวา = otitic barotrauma (มี middle ear effusion) -> oral decongestant + autoinflation (ส่วนใหญ่หายเอง)", "sys": "VIII"}, {"topic": "Endocrinology", "q": "A 47-year-old with type 2 diabetes: Cr 2.4, GFR 20. Which drug is contraindicated?", "choices": ["Pioglitazone", "Sitagliptin", "Glargine", "Metformin", "Lispro"], "ans": 3, "exp": "metformin ห้ามใช้เมื่อ eGFR < 30 (เสี่ยง lactic acidosis) -> contraindicated ในผู้ป่วยรายนี้ (GFR 20)", "sys": "IV"}, {"topic": "Orthopedics", "q": "A patient with a tibial fracture in a leg cast develops leg pain, pain on passive stretch of the EHL, and paresthesia at the 1st web space. Most likely diagnosis?", "choices": ["Tendon injury", "Peroneal nerve injury", "Muscle injury", "Deep vein thrombosis", "Compartment syndrome"], "ans": 4, "exp": "ปวดมากผิดปกติ + ปวดเมื่อยืดกล้ามเนื้อ (passive stretch) + ชา ในขาที่ใส่เฝือก = acute compartment syndrome -> fasciotomy ด่วน", "sys": "XIII"}, {"topic": "Surgery", "q": "A patient with obstipation and chronic constipation using high-dose laxatives develops left-sided abdominal pain. Abdominal film shown; the rectum is empty. Diagnosis?", "choices": ["Sigmoid volvulus", "Adhesive small bowel obstruction", "Toxic megacolon", "Obstructing colon cancer", "Pseudo-obstruction"], "ans": 0, "exp": "ท้องผูกเรื้อรัง + ปวดท้องซ้าย + ฟิล์มเห็นลำไส้โป่งรูปเมล็ดกาแฟ + rectum ว่าง = sigmoid volvulus", "img": "https://cdn.jsdelivr.net/gh/MercenzK/Web-quiz-images@main/NL2-2022-PM-Q36.png", "sys": "II"}, {"topic": "Community/EBM", "q": "A 40-year-old healthy man with good health literacy and no family history comes for a routine check-up. What is a strong recommendation at every check-up?", "choices": ["Fasting blood sugar", "BMI (weight/height)", "Lipid profile", "Chest X-ray", "Electrocardiogram"], "ans": 1, "exp": "การวัด BMI/น้ำหนัก-ส่วนสูง (และความดันโลหิต) เป็นสิ่งที่แนะนำให้ทำทุกครั้งที่มาตรวจสุขภาพ ส่วน CXR/ECG ไม่แนะนำเป็น routine ในคนสุขภาพดี", "sys": "general"}, {"topic": "Community/EBM", "q": "A study finds the correlation between cervical cancer and HPV infection with a relative risk of 1.6 (95% CI 1.2-2.3). Interpretation?", "choices": ["Not statistically significant", "No association", "Statistically significant; 1.6 times higher risk", "Protective effect", "Cannot be interpreted"], "ans": 2, "exp": "95% CI (1.2-2.3) ไม่คร่อม 1 -> statistically significant และ RR 1.6 = ความเสี่ยงสูงขึ้น 1.6 เท่า", "sys": "general"}, {"topic": "Emergency", "q": "A 15-year-old brought with stupor. BT 37, RR 8, HR 70, BP 130/70, pupils 1 mm RTLBE. Most likely causative substance?", "choices": ["Cannabis", "Methamphetamine", "Ketamine", "Tramadol (opioid)", "Alcohol"], "ans": 3, "exp": "ซึม + หายใจช้า (RR 8) + รูม่านตาหด pinpoint (1 mm) = opioid toxidrome -> tramadol", "sys": "emergency"}, {"topic": "Obstetrics", "q": "A 30-year-old primigravida with vaginal bleeding/pelvic pain 30 minutes. PE: hypotension, generalized guarding, pelvic tenderness. Next management after fluid resuscitation?", "choices": ["PRC 2 units", "Methotrexate", "Observation", "Repeat ultrasound", "Exploratory laparotomy"], "ans": 4, "exp": "สงสัย ruptured ectopic pregnancy (ช็อก + peritonitis) -> หลังกู้สารน้ำ ต้องผ่าตัดด่วน exploratory laparotomy เพื่อห้ามเลือด", "sys": "XV"}, {"topic": "Pediatrics", "q": "A 12-month-old boy with episodic cessation of breathing lasting 1-2 minutes with full recovery. No history of birth asphyxia or head trauma. PE unremarkable. Diagnosis? (ต้นฉบับมีตัวเลือกไม่ครบ ใส่เท่าที่มี)", "choices": ["Breath-holding spell", "Hypoxic (cyanotic) spell", "Absence seizure", "Gastroesophageal reflux"], "ans": 0, "exp": "หยุดหายใจเป็นพัก ๆ สั้น ๆ แล้วหายเองสนิทในเด็กเล็กที่ปกติ + ไม่มีประวัติ asphyxia = breath-holding spell (มักสัมพันธ์การร้องไห้)", "sys": "XVI"}, {"topic": "Medicine", "q": "A 60-year-old woman with colicky abdominal pain, bloating, loose stool. V/S normal, mild LLQ tenderness. Colonoscopy: normal mucosa, a 5 mm hyperplastic polyp, small internal hemorrhoids. Most appropriate treatment?", "choices": ["Domperidone", "Mebeverine (antispasmodic)", "Loperamide", "Omeprazole", "Simethicone"], "ans": 1, "exp": "ปวดบิด + ท้องอืด + ถ่ายเหลว โดยส่องกล้องปกติ = irritable bowel syndrome -> ยาลดการบีบเกร็ง (antispasmodic เช่น mebeverine)", "sys": "general"}, {"topic": "Ophthalmology", "q": "A 15-month-old boy with intermittent epiphora for 1 year. PE: mucopurulent discharge from the punctum on compression at the medial canthus. Most appropriate management?", "choices": ["Lacrimal sac irrigation", "Massage", "Nasolacrimal duct probing", "Incision and drainage", "Normal saline drops"], "ans": 2, "exp": "congenital nasolacrimal duct obstruction ที่อายุ >12 เดือน (massage ไม่หาย) -> ทำ nasolacrimal duct probing", "sys": "VII"}, {"topic": "Neurology", "q": "A 65-year-old woman with sudden right arm weakness and slurred speech 30 minutes ago, spontaneously recovered. BP 140/90, left carotid bruit, no deficit. CT normal; CTA: 80% stenosis of the left extracranial ICA. Most appropriate management to prevent recurrence?", "choices": ["Aspirin", "Clopidogrel", "Warfarin", "Carotid endarterectomy", "Rivaroxaban"], "ans": 3, "exp": "TIA จาก symptomatic ICA stenosis 70-99% -> carotid endarterectomy (CEA) ลด stroke ซ้ำได้ดีที่สุด (ร่วมกับ antiplatelet/statin)", "sys": "VI"}, {"topic": "Obstetrics & Gynecology", "q": "A 28-year-old woman with a painful vulvar mass 3 days, no discharge/fever. PE: erythematous tender mass at 5 o'clock. Most appropriate treatment?", "choices": ["Warm sitz bath", "Antibiotics", "Aspiration", "Excision", "Marsupialization (or Word catheter)"], "ans": 4, "exp": "Bartholin abscess -> ระบายหนองด้วย marsupialization หรือใส่ Word catheter (I&D อย่างเดียวมักเป็นซ้ำ)", "sys": "II"}, {"topic": "Emergency", "q": "A patient with a femoral fracture received PRC 10 units, FFP 6 units, platelets 5 units, then developed bradycardia, widened QRS, widened/dropped P waves, and cardiac arrest. Cause?", "choices": ["Hyperkalemia", "Hypocalcemia", "Transfusion mismatch", "Fat embolism", "Hypothermia"], "ans": 0, "exp": "massive transfusion จากเลือดเก่า -> potassium รั่วสูง (hyperkalemia): peaked T, P แบน, QRS กว้าง จนถึง sine wave/arrest", "sys": "emergency"}, {"topic": "Pediatrics", "q": "A 1-month-old male infant with seizure, born at home. PE: anterior fontanelle 2x2 cm, tense. PT and PTT prolonged. CT: subdural hematoma. Diagnosis?", "choices": ["Child abuse", "Idiopathic vitamin K deficiency of infancy", "Factor VIII deficiency", "Hemophilia B", "Hemorrhagic disease from sepsis"], "ans": 1, "exp": "คลอดที่บ้าน (ไม่ได้ vitamin K) + เลือดออกในสมอง (subdural) + PT/PTT ยืดทั้งคู่ = late-onset vitamin K deficiency bleeding (VKDB)", "sys": "I"}, {"topic": "Ophthalmology", "q": "A 25-year-old man needs a medical document for a driving license. VA 20/20 both eyes. Proper next investigation?", "choices": ["Refraction test", "Schiotz test", "Ishihara test (color vision)", "Fundoscopy", "Extraocular movement"], "ans": 2, "exp": "ใบรับรองขับขี่ต้องตรวจการมองเห็นสี -> Ishihara test (color vision)", "sys": "VII"}, {"topic": "Surgery", "q": "A 28-year-old man with a 10 cm cut wound on the volar right forearm, no active bleeding, but absent both radial and ulnar pulses. Next appropriate management?", "choices": ["Fasciotomy", "Conventional angiography", "CT angiography", "Surgical exploration and vascular repair", "Intraoperative angiography"], "ans": 3, "exp": "มี hard sign ของ vascular injury (คลำชีพจรไม่ได้ทั้งสอง) + ตำแหน่งชัด -> ไปห้องผ่าตัดสำรวจและซ่อมหลอดเลือด (vascular repair) ทันที ไม่ต้องเสียเวลา imaging ก่อน", "sys": "XVIII"}, {"topic": "Obstetrics & Gynecology", "q": "A 46-year-old woman with hot flushes, night sweats, and insomnia 2 months. She had a total abdominal hysterectomy 5 years ago for myoma. Most proper investigation?", "choices": ["LH", "Estrogen", "Prolactin", "GnRH", "FSH"], "ans": 4, "exp": "อาการวัยทอง + เคยตัดมดลูก (ประเมินจากประจำเดือนไม่ได้) -> ตรวจ FSH (สูงในภาวะรังไข่หยุดทำงาน/menopause)", "sys": "IV"}, {"topic": "Surgery", "q": "A 58-year-old woman with a 2 cm hard thyroid nodule, no compressive symptoms, goiter 10 years, normal TFT. Appropriate investigation?", "choices": ["Fine needle aspiration biopsy", "Thyroid antibody", "Thyroid ultrasonography", "Thyroid scan", "CT neck"], "ans": 0, "exp": "thyroid nodule แข็ง + TFT ปกติ -> FNA เพื่อดู cytology (แยกมะเร็ง)", "sys": "IV"}, {"topic": "Psychiatry", "q": "A woman brought to the ED after cutting her right arm following a fight with her partner; she says she did so because she follows a voice from above, and has a history of suicide attempts. Most proper management?", "choices": ["Counseling", "Hospitalization", "Group psychotherapy", "Long-acting antipsychotics", "Cognitive therapy"], "ans": 1, "exp": "command hallucination (ทำร้ายตัวเองตามเสียงสั่ง) + เสี่ยงฆ่าตัวตายซ้ำ -> รับไว้ในโรงพยาบาล (hospitalization) เพื่อความปลอดภัยก่อน", "sys": "V"}, {"topic": "Emergency", "q": "An 11-year-old boy with a cut wound. He received 5 doses of Td since age 4 and another booster last year. Most proper management?", "choices": ["Td vaccine", "TT vaccine", "No vaccination required", "Tetanus immunoglobulin", "TdaP"], "ans": 2, "exp": "ได้วัคซีนบาดทะยักครบ + booster ปีที่แล้ว (<5 ปี) -> ไม่ต้องให้วัคซีน/TIG เพิ่ม (No vaccination required)", "sys": "emergency"}, {"topic": "ENT", "q": "A 10-year-old with nasal congestion and morning rhinorrhea for 6 months, not relieved by nasal irrigation or antihistamines. PE: pale inferior turbinates. Proper management?", "choices": ["Nasal irrigation", "Antileukotrienes", "Pseudoephedrine", "Topical (intranasal) corticosteroids", "Topical decongestant"], "ans": 3, "exp": "allergic rhinitis ที่ไม่ตอบสนอง antihistamine (turbinate ซีดบวม) -> intranasal corticosteroid เป็นยาที่ได้ผลดีสุด", "sys": "VIII"}, {"topic": "Dermatology", "q": "A 72-year-old man with multiple non-tender tense fluid-filled bullae on the lower abdomen and thighs. Tzanck smear: no multinucleated giant cells, no acantholytic cells, but eosinophils are seen. Most likely diagnosis?", "choices": ["Pemphigus vulgaris", "Toxic epidermal necrolysis", "Pemphigus foliaceus", "Friction bullae", "Bullous pemphigoid"], "ans": 4, "exp": "ผู้สูงอายุ + ตุ่มน้ำตึงหนา ไม่เจ็บ + ไม่มี acantholytic cell แต่มี eosinophil = bullous pemphigoid (subepidermal, anti-BP180/230)", "sys": "XII"}, {"topic": "Psychiatry", "q": "An 8-year-old girl with abdominal pain 3 weeks, refuses school, does not want to leave her mother (nightmare that her mother left her), previously had a good relationship with her mother. Most likely diagnosis? (ต้นฉบับตัวเลือกไม่มีคำตอบที่ถูก จึงเพิ่มให้)", "choices": ["Separation anxiety disorder", "Adjustment disorder", "Specific phobia", "Social anxiety disorder", "Major depressive disorder"], "ans": 0, "exp": "กลัวพลัดพรากจากแม่ + ไม่ยอมไปโรงเรียน + อาการทางกาย (ปวดท้อง) = separation anxiety disorder. *ต้นฉบับไม่มีตัวเลือกนี้ จึงเพิ่มคำตอบที่ถูกต้องให้*", "sys": "V"}, {"topic": "ENT", "q": "A child with fever and trismus. PE: floor-of-mouth edema and tongue protrusion. Most likely diagnosis?", "choices": ["Retropharyngeal abscess", "Submandibular space abscess (Ludwig's angina)", "Parapharyngeal abscess", "Parotid space abscess", "Peritonsillar abscess"], "ans": 1, "exp": "บวมที่พื้นปาก (floor of mouth) + ดันลิ้น = การติดเชื้อ submandibular space (Ludwig's angina) -> เฝ้าระวัง airway", "sys": "VIII"}, {"topic": "Obstetrics", "q": "A woman develops fever and abdominal pain after delivery. PE: no rebound tenderness; pelvic exam: foul-smelling lochia. Most appropriate antibiotics?", "choices": ["Ceftriaxone", "Amoxicillin/clavulanic acid", "Clindamycin + Gentamicin", "Ampicillin + Gentamicin", "Cefazolin + Metronidazole"], "ans": 2, "exp": "postpartum endometritis (ไข้ + น้ำคาวปลาเหม็น) -> ยามาตรฐานคือ clindamycin + gentamicin", "sys": "XV"}, {"topic": "Pediatrics", "q": "A 7-day-old term female with bilateral eye discharge for 4 days; received silver nitrate at birth. Gram stain: few PMN, no organisms. Most likely diagnosis?", "choices": ["Gonococcal conjunctivitis", "Viral conjunctivitis", "Chemical conjunctivitis", "Chlamydial conjunctivitis", "Atopic conjunctivitis"], "ans": 3, "exp": "เยื่อบุตาอักเสบเริ่มวันที่ 5-14 + gram stain ไม่พบเชื้อ = Chlamydia trachomatis (chemical จาก silver nitrate จะเกิดวันแรก ๆ; gonococcus เห็น GNDC)", "sys": "XVI"}, {"topic": "Pediatrics", "q": "A 10-month-old with a flat facial profile, upslanting palpebral fissures, low-set ears, and a single palmar crease. What is commonly associated with this condition?", "choices": ["Ambiguous genitalia", "Brainstem hypoplasia", "Polycystic kidney", "Cleft palate", "Hypothyroidism"], "ans": 4, "exp": "ลักษณะ Down syndrome (trisomy 21) -> สัมพันธ์กับ hypothyroidism (รวมถึง CHD, duodenal atresia, leukemia)", "sys": "XVII"}, {"topic": "Medicine", "q": "A 70-year-old man with progressive headache and chest tightness 2 weeks, worse when lying supine, decreased appetite and weight loss. PE: JVP 8 cm sitting, facial plethora, facial and neck swelling. Appropriate investigation?", "choices": ["Plain chest X-ray", "CT brain", "Electrocardiogram", "Ultrasound abdomen", "Paranasal sinus film"], "ans": 0, "exp": "หน้าบวมแดง + คอบวม + JVP สูง + แย่ลงเวลานอน = superior vena cava syndrome (มักจากก้อนในช่องอก/มะเร็งปอด) -> เริ่มด้วย chest X-ray หาก้อน mediastinum", "sys": "VI"}, {"topic": "Infectious disease", "q": "A 20-year-old man with fever and altered consciousness. PE: BT 39, petechial rash, positive stiff neck. CSF: gram-positive coccobacilli, some in pairs or short chains. Most likely organism?", "choices": ["Staphylococcus aureus", "Listeria monocytogenes", "Streptococcus suis", "Streptococcus pyogenes", "Streptococcus pneumoniae"], "ans": 1, "exp": "gram-positive coccobacilli ใน CSF = Listeria monocytogenes (streptococci เป็น cocci เรียงสาย ไม่ใช่ coccobacilli)", "sys": "I"}, {"topic": "Neurology", "q": "A patient with fever, headache, vomiting, and stiff neck. CT: density at the temporal lobe. LP: opening pressure 30, RBC 50-100, WBC 300 (lymphocyte predominant), high protein, normal glucose. Most likely diagnosis? (ต้นฉบับมีตัวเลือกไม่ครบ ใส่เท่าที่มี)", "choices": ["Bacterial meningitis", "Tuberculous meningitis", "Herpes encephalitis", "Cryptococcal meningitis"], "ans": 2, "exp": "temporal lobe + CSF lymphocyte + เม็ดเลือดแดง (hemorrhagic) + protein สูง + glucose ปกติ = HSV encephalitis -> IV acyclovir", "sys": "VI"}, {"topic": "Surgery", "q": "A 60-year-old man with suprapubic pain, has not voided for 12 hours, with 1-year history of difficulty urinating and post-void dribbling. PE: ballooning bladder, enlarged prostate without nodularity. Foley drains 800 ml. UA: WBC 3-5, RBC 15. Most appropriate management?", "choices": ["Check serum PSA", "5-alpha reductase inhibitor", "Prostate biopsy", "Alpha-1 antagonist", "IV ceftriaxone"], "ans": 3, "exp": "acute urinary retention จาก BPH (คลำต่อมลูกหมากโตเรียบ) -> หลังใส่สายสวนระบายปัสสาวะ เริ่มยา alpha-1 blocker เพื่อคลายกล้ามเนื้อคอกระเพาะปัสสาวะ", "sys": "XIV"}, {"topic": "Pediatrics", "q": "A 9-month-old girl with altered consciousness/stupor, multiple-stage bruises, and bilateral retinal hemorrhages. Most likely diagnosis?", "choices": ["Hemophilia", "Idiopathic vitamin K deficiency", "Immune thrombocytopenia", "Meningitis", "Shaken baby syndrome (child abuse)"], "ans": 4, "exp": "ซึม + รอยฟกช้ำหลายระยะ + retinal hemorrhage 2 ข้าง = shaken baby syndrome (abusive head trauma)", "sys": "III"}, {"topic": "Obstetrics & Gynecology", "q": "A couple has been trying to conceive for 2 years; the wife has regular menstruation without cramps. What more should the physician ask?", "choices": ["Frequency of sexual intercourse", "History of STDs", "Underlying diseases of both", "Family history of infertility", "Occupational exposures"], "ans": 0, "exp": "ในการซักประวัติภาวะมีบุตรยาก สิ่งสำคัญที่มักถูกมองข้ามคือความถี่/จังหวะการมีเพศสัมพันธ์ (coital frequency and timing)", "sys": "flex"}, {"topic": "Orthopedics", "q": "A woman with wrist pain worse on wrist movement or carrying her baby; she delivered 3 months ago. Most likely diagnosis?", "choices": ["Tennis elbow", "De Quervain tenosynovitis", "Carpal tunnel syndrome", "Cubital tunnel syndrome", "Trigger finger"], "ans": 1, "exp": "ปวดข้อมือด้าน radial แย่ลงเวลาอุ้มลูก หลังคลอด = De Quervain tenosynovitis (mommy's wrist)", "sys": "XIII"}, {"topic": "Ophthalmology", "q": "A 75-year-old woman with right eye pain 4 hours. PE: mixed conjunctival injection, corneal edema, shallow anterior chamber, semi-dilated pupil. Most likely diagnosis?", "choices": ["Endophthalmitis", "Keratitis", "Acute angle-closure glaucoma", "Uveitis", "Orbital cellulitis"], "ans": 2, "exp": "ปวดตาเฉียบพลัน + กระจกตาบวม + ช่องหน้าลูกตาตื้น + รูม่านตากึ่งขยายค้าง = acute angle-closure glaucoma", "sys": "VII"}, {"topic": "ENT", "q": "A 68-year-old man with DM, fever, sore throat, and dysphagia 5 days, multiple dental caries, trismus, limited mouth opening. PE: medial displacement of the lateral pharyngeal wall and tonsil. Most likely diagnosis?", "choices": ["Peritonsillar abscess", "Masticator space abscess", "Retropharyngeal abscess", "Parapharyngeal abscess", "Ludwig's angina"], "ans": 3, "exp": "ผนัง lateral pharyngeal wall ถูกดันเข้าด้านใน + trismus = parapharyngeal space abscess", "sys": "VIII"}, {"topic": "Emergency", "q": "A man with acute retrosternal chest pain suddenly collapses. ECG: 3rd-degree AV block, no pulse, no spontaneous breathing. Initial management?", "choices": ["Epinephrine 1 mg IM", "Transcutaneous pacing", "Atropine 1 mg", "Defibrillation", "Chest compression (CPR)"], "ans": 4, "exp": "ไม่มีชีพจร ไม่หายใจ = cardiac arrest -> เริ่ม high-quality chest compression (CPR) ทันที", "sys": "emergency"}, {"topic": "Psychiatry", "q": "A 20-year-old man with auditory hallucinations and delusions for 3 months, plus poor self-care and social withdrawal for a year. No underlying disease or substance use. Most likely diagnosis?", "choices": ["Schizophrenia", "Brief psychotic disorder", "Major depressive disorder with psychotic features", "Schizophreniform disorder", "Delusional disorder"], "ans": 0, "exp": "อาการโรคจิต (hallucination/delusion) + เสื่อมหน้าที่ (poor self-care, withdrawal) รวมระยะเวลา > 6 เดือน = schizophrenia", "sys": "V"}, {"topic": "Forensic", "q": "A married woman reports sexual assault by her husband. PE: old tear at the posterior fourchette, spermatozoa on the left inner thigh, no external wounds. Pelvic exam: no sperm, acid phosphatase negative. Interpretation?", "choices": ["Cannot be evaluated", "Confirmed sexual contact (sperm present)", "No sexual intercourse", "Probable sexual intercourse", "Suspected sexual intercourse"], "ans": 1, "exp": "พบตัวอสุจิ (spermatozoa) ที่ต้นขา = หลักฐานยืนยันการสัมผัสทางเพศ (การพบ sperm เป็น confirmatory) แม้ในช่องคลอดจะตรวจไม่พบแล้วก็ตาม", "sys": "general"}, {"topic": "Community/EBM", "q": "A screening test measures a substance to detect a life-threatening condition that is completely curable if treated early. Where should the cut-off between normal and abnormal be set?", "choices": ["Point B", "Point C", "Point A (highest sensitivity)", "Point D", "Point E (highest specificity)"], "ans": 2, "exp": "โรคที่ร้ายแรงแต่รักษาหายถ้าเจอเร็ว -> ต้องการ 'ไม่พลาดผู้ป่วย' = เน้น sensitivity สูง -> ตั้ง cut-off ที่จุดซึ่งให้ sensitivity สูงสุด. *คำตอบขึ้นกับกราฟจริง (จุดที่ค่าต่ำสุด/ซ้ายสุด)*", "img": "https://cdn.jsdelivr.net/gh/MercenzK/Web-quiz-images@main/NL2-2022-PM-Q73.png", "sys": "general"}, {"topic": "Ethics", "q": "A 7-year-old girl is diagnosed with acute lymphoblastic leukemia. You are breaking the news to her mother; she says she knows the diagnosis and cries. How should you respond?", "choices": ["I understand. Bad luck can happen to anyone", "I understand you are sad. Please don't cry", "Don't worry, there is modern medicine to cure her", "Could you tell me how you are feeling?", "We can't talk today; let's make another appointment"], "ans": 3, "exp": "การตอบสนองที่เหมาะสมคือการเปิดโอกาสให้ผู้ปกครองระบายและแสดง empathy -> ถามความรู้สึก 'Could you tell me how you are feeling?'", "sys": "general"}, {"topic": "Surgery", "q": "A 30-year-old high-speed trauma. PE: BP 80/60, PR 120, abdominal distention and tenderness, FAST positive for intra-abdominal fluid; urethral catheter reveals minimal clear urine. Etiology of oliguria?", "choices": ["Bladder injury", "False catheter tract", "Acute tubular necrosis", "Renal artery injury", "Hemorrhagic (hypovolemic) shock"], "ans": 4, "exp": "เลือดออกในช่องท้อง (FAST +) + ช็อก + ปัสสาวะออกน้อยแต่ใส = prerenal oliguria จาก hemorrhagic shock (ไตยังปกติ)", "sys": "IX"}, {"topic": "Obstetrics & Gynecology", "q": "A woman with malodorous vaginal discharge; wet mount shows clue cells. She is allergic to metronidazole. Appropriate management?", "choices": ["Clindamycin", "Doxycycline", "Tinidazole", "Fluconazole", "Azithromycin"], "ans": 0, "exp": "bacterial vaginosis (clue cells) + แพ้ metronidazole -> ใช้ clindamycin (tinidazole เป็น nitroimidazole เสี่ยง cross-reaction)", "sys": "XIV"}, {"topic": "Medicine", "q": "A 70-year-old with DM and CKD (Cr 1.4, eGFR 48) plans cardiac catheterization. What prevents contrast-induced nephropathy?", "choices": ["Oral enalapril", "Isotonic saline (NSS) infusion", "Oral N-acetylcysteine", "IV dopamine", "IV sodium bicarbonate"], "ans": 1, "exp": "การป้องกัน contrast-induced nephropathy ที่ได้ผลชัดสุดคือการให้สารน้ำ isotonic (NSS) ก่อน-หลังฉีดสารทึบรังสี (NAC/bicarb ประโยชน์ไม่ชัด)", "sys": "IX"}, {"topic": "Psychiatry", "q": "An 18-year-old girl with palpitations, numbness of hands and fingers, sweating, a feeling of dying, dyspnea, and feeling out of control; episodes last about 5 minutes. Most likely diagnosis?", "choices": ["Conversion disorder", "Hyperventilation syndrome", "Panic attack", "Generalized anxiety disorder", "Post-traumatic stress disorder"], "ans": 2, "exp": "อาการรุนแรงเป็นพักสั้น ~5 นาที (ใจสั่น ชา เหงื่อแตก กลัวตาย คุมตัวไม่ได้) = panic attack", "sys": "V"}, {"topic": "Obstetrics", "q": "A pregnant woman GA 39 weeks in labor: cervix 3 cm, 100% effacement, 0 station, vertex. After 2 hours, cervix is 7 cm with good FHR and contractions. Appropriate management? (ต้นฉบับตัวเลือกไม่ครบ จึงเพิ่มคำตอบที่ถูก)", "choices": ["Cesarean delivery", "Oxytocin augmentation", "PGE1", "Observe labor progression", "Amniotomy"], "ans": 3, "exp": "ปากมดลูกเปิด 3->7 ซม.ใน 2 ชม. + FHR/contraction ดี = ดำเนินคลอดปกติ (active phase ก้าวหน้าดี) -> เฝ้าสังเกตต่อ ไม่ต้อง augment หรือผ่าตัด", "sys": "XV"}, {"topic": "Pediatrics", "q": "A 40-year-old mother delivers at GA 40 weeks without antenatal care. The infant is below P10, head circumference at P50, with an isolated unilateral cleft lip. Most proper investigation?", "choices": ["LFT", "Chest X-ray", "Chromosome studies", "Hemoculture", "TORCH IgM"], "ans": 4, "exp": "asymmetric IUGR (หัวปกติ ตัวเล็ก) + ไม่ฝากครรภ์ + ความผิดปกติแต่กำเนิด -> ตรวจ TORCH IgM หาการติดเชื้อในครรภ์", "sys": "XV"}, {"topic": "Endocrinology", "q": "A 22-year-old woman with 1 kg weight loss, palpitation, and hand tremor 1 month. PE: firm thyroid 25 g, no bruit, no exophthalmos, no onycholysis. T3 200, T4 3.4, TSH 0.01. Most proper investigation?", "choices": ["TSH receptor antibody (TRAb)", "ESR", "Thyroid peroxidase antibody", "Thyroid stimulating immunoglobulin", "Fine needle aspiration biopsy"], "ans": 0, "exp": "thyrotoxicosis โดยไม่มี eye signs -> ยืนยันสาเหตุ Graves ด้วย TSH receptor antibody (TRAb) [TSI ก็ใช้ได้]. หากต้องแยกจาก thyroiditis ใช้ thyroid scan (RAIU)", "sys": "IV"}, {"topic": "Forensic", "q": "Which is correct about examination of a sexual assault case? (ต้นฉบับมีตัวเลือกไม่ครบ ใส่เท่าที่มี)", "choices": ["Motile sperm persist for over 7 days in the vagina", "Spermatozoa may be detected in the cervix for up to ~1-2 weeks", "Acid phosphatase persists longer than sperm heads", "Sperm cannot be detected after 24 hours"], "ans": 1, "exp": "ตัวอสุจิที่เคลื่อนไหวอยู่ในช่องคลอด <24-48 ชม. แต่ sperm head (ไม่เคลื่อนไหว) โดยเฉพาะใน cervix ตรวจพบได้นานหลายวันถึง ~1-2 สัปดาห์", "sys": "general"}, {"topic": "Emergency", "q": "A 35-year-old after a car accident. PE: RR 30, PR 110, BP 140/90, SpO2 85%, multiple left rib fractures with a flail segment. CXR: multiple rib fractures, no pneumothorax. Most proper initial management?", "choices": ["Pain control", "Central line insertion", "Endotracheal intubation (positive pressure ventilation)", "Taping the flail chest", "Left tube thoracostomy"], "ans": 2, "exp": "flail chest + respiratory failure (SpO2 85%) -> ใส่ท่อช่วยหายใจให้ positive pressure ventilation (internal splint). ห้าม taping (จำกัดการขยายปอด)", "sys": "emergency"}, {"topic": "Emergency", "q": "A 20-year-old MVA victim with paraplegia. PE: PR 60, RR 24, BP 70/40, drowsy E3V4M6, contusion over the lower thoracic spine, poor anal sphincter tone. Appropriate initial management?", "choices": ["Immediate endotracheal intubation", "Alpha-agonist infusion", "Pulse methylprednisolone", "Isotonic crystalloid loading", "Immediate MRI of the spine"], "ans": 3, "exp": "neurogenic shock (hypotension + bradycardia + spinal cord injury) -> เริ่มด้วย isotonic crystalloid loading ก่อน แล้วจึงพิจารณา vasopressor ถ้าไม่ตอบสนอง", "sys": "emergency"}, {"topic": "Medicine", "q": "A man with HIV and PCP has severe vomiting, euvolemic. Serum osm 246, urine osm 453, urine Na 68, Na 111, K 3.6. Most likely diagnosis?", "choices": ["Pseudohyponatremia", "Cerebral salt wasting", "Salt-wasting nephropathy", "Volume depletion hyponatremia", "SIADH"], "ans": 4, "exp": "euvolemic hyponatremia + serum osm ต่ำ + urine osm สูง (453) + urine Na สูง (68) = SIADH (พบร่วมกับโรคปอด/PCP)", "sys": "I"}, {"topic": "Obstetrics", "q": "A mother of a 2-week-old infant has breast pain 4 hours; she breastfeeds every 4 hours. BT 37.5. PE: generalized tenderness with engorgement of both breasts, no discharge. Appropriate management?", "choices": ["Frequent breastfeeding", "Warm compression", "Breast binder", "Oral antibiotics", "Parenteral antibiotics"], "ans": 0, "exp": "คัดตึงเต้านม 2 ข้าง (engorgement) โดยไม่มีการติดเชื้อ -> ให้ลูกดูดบ่อย ๆ ระบายน้ำนม (frequent breastfeeding) +/- ประคบอุ่นก่อนให้นม", "sys": "flex"}, {"topic": "Pediatrics", "q": "A 7-year-old with severe pneumonia on cefotaxime 4 days; respiratory symptoms improved but persistent high fever. Thoracentesis: straw color, sp.gr 1.030, protein 3, sugar 49, WBC 1500 (PMN 85%), no organism. Most proper management?", "choices": ["Add cloxacillin", "Chest tube drainage (ICD)", "Change to imipenem", "Repeat thoracentesis", "Surgical decortication"], "ans": 1, "exp": "parapneumonic effusion (exudate) ที่ยังไข้สูงแม้ได้ยาปฏิชีวนะเหมาะสม -> ระบายด้วย chest tube (intercostal drainage)", "sys": "X"}, {"topic": "Medicine", "q": "A 36-year-old man treated for H. pylori gastritis with omeprazole, amoxicillin, and metronidazole for 10 days, now asymptomatic. Most appropriate advice?", "choices": ["No further treatment", "Long-term omeprazole", "Urea breath test in 4 weeks", "Annual barium upper GI", "Repeat EGD in 4 weeks"], "ans": 2, "exp": "หลังรักษา H. pylori ควรยืนยันการกำจัดเชื้อด้วย urea breath test (หรือ stool antigen) ที่ >4 สัปดาห์หลังหยุดยา", "sys": "XI"}, {"topic": "Pediatrics", "q": "A 7-year-old, malnourished, with chronic mucous bloody diarrhea and low-grade fever 4 weeks. PE: tender hepatomegaly. Lab: AST 90, ALT 60, ALP 420, albumin 2. Proper investigation?", "choices": ["Abdominal ultrasonography", "MRI abdomen", "Colonoscopy", "Stool examination for parasites", "Stool culture"], "ans": 3, "exp": "ถ่ายมูกเลือดเรื้อรัง + ตับโตกดเจ็บ = amebiasis (ลำไส้ + amebic liver abscess) -> ตรวจ stool exam หา Entamoeba histolytica", "sys": "I"}, {"topic": "Pediatrics", "q": "A 2-year-old with watery diarrhea and vomiting. PE: BT 38, PR 130, dry lips, sunken anterior fontanelle, sunken eyeballs, capillary refill 3 s. Appropriate management?", "choices": ["Ceftriaxone", "Racecadotril", "Ondansetron", "Lactose-free milk", "Resuscitation with 0.9% NaCl (IV)"], "ans": 4, "exp": "ขาดน้ำปานกลาง-รุนแรง (กระหม่อม/ตาลึก, cap refill 3 วิ) -> ให้สารน้ำทางหลอดเลือดดำ (0.9% NaCl) resuscitation", "sys": "XI"}, {"topic": "Emergency", "q": "A 15-year-old with palpitation and dizziness. PE: PR 180, BP 100/60, capillary refill <3 s, SpO2 98%. ECG monitoring shown (narrow-complex SVT). Most appropriate management?", "choices": ["Vagal maneuver (carotid massage)", "NSS loading", "Amiodarone 150 mg IV over 10 min", "Synchronized cardioversion", "Unsynchronized cardioversion"], "ans": 0, "exp": "SVT ที่ยังคงที่ (stable) -> เริ่มด้วย vagal maneuver (carotid massage/Valsalva) แล้วตามด้วย adenosine ถ้าไม่หาย", "img": "https://cdn.jsdelivr.net/gh/MercenzK/Web-quiz-images@main/NL2-2022-PM-Q91.png", "sys": "emergency"}, {"topic": "Orthopedics", "q": "A 33-year-old man with sudden low back pain after lifting a heavy object. PE: positive straight leg raise. Most likely diagnosis?", "choices": ["Spinal stenosis", "Disc herniation", "Spondylolisthesis", "Spondylolysis", "Acute back strain"], "ans": 1, "exp": "ปวดหลังเฉียบพลันหลังยกของ + SLR บวก (radiculopathy) = lumbar disc herniation", "sys": "XIII"}, {"topic": "Medicine", "q": "A 30-year-old with fever 4 days, dry cough, dyspnea, ear pain, and diarrhea. PE: BT 38, injected pharynx, erythematous swollen right TM (bullous myringitis), fine crepitation RLL. WBC 15,000 (N70%), CXR patchy RLL infiltration. Most likely diagnosis?", "choices": ["Legionella pneumophila pneumonia", "Chlamydophila pneumoniae pneumonia", "Mycoplasma pneumoniae pneumonia", "Klebsiella pneumoniae pneumonia", "Streptococcus pneumoniae pneumonia"], "ans": 2, "exp": "atypical pneumonia + bullous myringitis + อาการนอกปอด (หูอักเสบ, ท้องเสีย) = Mycoplasma pneumoniae", "sys": "VIII"}, {"topic": "Forensic", "q": "A boy reports anal tenderness from a sexual assault 2 weeks ago. Proper specimen for diagnosis?", "choices": ["Swab for spermatozoa", "Swab for epithelial cells", "Anal washing for acid phosphatase", "Swab/test for sexually transmitted organisms", "Anal washing for PSA"], "ans": 3, "exp": "ผ่านมา 2 สัปดาห์ sperm/acid phosphatase/PSA สลายหมดแล้ว -> ตรวจหาเชื้อโรคติดต่อทางเพศสัมพันธ์ (STI) เป็นหลักฐานที่เหมาะสม", "sys": "general"}, {"topic": "ENT", "q": "A patient with dizziness associated with position/posture; blood pressures in two positions are not different. Most likely diagnosis?", "choices": ["Orthostatic hypotension", "Meniere disease", "Vestibular neuritis", "Central vertigo", "Benign paroxysmal positional vertigo"], "ans": 4, "exp": "เวียนหัวสัมพันธ์กับท่าทาง แต่ความดัน 2 ท่าไม่ต่างกัน (ไม่ใช่ orthostatic) = BPPV", "sys": "VIII"}, {"topic": "Emergency", "q": "A 50-year-old farmer bitten by a cobra; at the ER, exam is normal with no neurodeficit. Most proper management?", "choices": ["Serial peak flow (monitor respiratory)", "Antivenom now", "Coagulogram", "Serial VCT", "Fasciotomy"], "ans": 0, "exp": "งูเห่า = neurotoxic -> เฝ้าระวังกล้ามเนื้อหายใจ/อ่อนแรง ด้วยการตรวจซ้ำ (serial peak flow / single-breath count); ให้ antivenom เมื่อมีอาการ envenomation (VCT ใช้กับงูพิษต่อเลือด)", "sys": "emergency"}, {"topic": "Infectious disease", "q": "A 65-year-old with cough, dyspnea, fever 3 days. BUN 8. Gram stain: gram-negative rods with a capsule. Proper antibiotic?", "choices": ["Levofloxacin", "Ceftriaxone + azithromycin", "Ceftazidime", "Piperacillin/tazobactam", "Meropenem"], "ans": 1, "exp": "gram-negative rod มี capsule = Klebsiella pneumoniae (community) -> รักษาด้วย 3rd-gen cephalosporin (ceftriaxone) + macrolide คลุม atypical ตามแนวทาง CAP", "sys": "I"}, {"topic": "Psychiatry", "q": "A 20-year-old woman with palpitations and shaking during class presentations and social events for years. Most likely diagnosis?", "choices": ["Panic disorder", "Agoraphobia", "Social anxiety disorder", "Adjustment disorder", "Avoidant personality disorder"], "ans": 2, "exp": "กลัว/มีอาการเฉพาะเวลาถูกจับจ้องในสถานการณ์สังคม (นำเสนอหน้าชั้น) เรื้อรังหลายปี = social anxiety disorder", "sys": "V"}, {"topic": "Obstetrics", "q": "A primigravida GA 38 weeks with clear fluid leakage 2 hours. FHR 140. PV: cervix 3 cm, 80% effacement, -1 station. Contractions every 8 min, 30 s. After 4 hours: contractions every 6 min, 35 s, cervix 4 cm. Appropriate management?", "choices": ["Evaluate fetal weight by ultrasound", "Continuous electronic fetal monitoring", "Ultrasound", "Observe labor progression", "Emergency Cesarean delivery"], "ans": 3, "exp": "ยังอยู่ latent phase (3->4 ซม.) + FHR ปกติ -> latent phase ยืดยาวได้เป็นปกติ จึงเฝ้าสังเกตความก้าวหน้าต่อ (observe)", "sys": "XV"}, {"topic": "Pediatrics", "q": "A 2000 g term female (history of fetal growth restriction), Apgar 5,9. PE: alert, HR 140, RR 40. Glucose 35 mg/dL, Hct 64%. Most appropriate nutrition/management?", "choices": ["10% DW 2 ml/kg bolus", "10% DW 65 ml/kg/day", "10% DW 65 ml/kg/day + 3% deficit", "Early feeding + infant formula only", "Early feeding + dextrose (monitor glucose)"], "ans": 4, "exp": "IUGR + hypoglycemia เล็กน้อยแต่ไม่มีอาการ (alert) -> เริ่มด้วย early feeding + ให้ dextrose/ติดตามน้ำตาลใกล้ชิด (ถ้ามีอาการ/ต่ำมากจึงให้ IV dextrose)", "sys": "XVI"}, {"topic": "Rheumatology", "q": "A 35-year-old woman with left knee pain, swelling, warmth, positive ballottement. Arthrocentesis: gram-negative diplococci. Proper antibiotic?", "choices": ["Ceftriaxone", "Penicillin G", "Doxycycline", "Clindamycin", "Gentamicin"], "ans": 0, "exp": "septic arthritis จาก gram-negative diplococci = Neisseria gonorrhoeae -> ceftriaxone", "sys": "XIII"}, {"topic": "Pediatrics", "q": "A 2200 g term infant with respiratory distress 1 hour after birth. PE: cyanosis, decreased breath sound on the left, heart sounds shifted to the right, scaphoid abdomen. Most proper management?", "choices": ["Nasal high-flow oxygen", "Endotracheal tube insertion", "Positive pressure (bag-mask) ventilation", "Gastric tube insertion", "Left thoracostomy"], "ans": 1, "exp": "congenital diaphragmatic hernia (scaphoid abdomen + heart shift + เสียงหายใจข้างซ้ายลด) -> ใส่ท่อช่วยหายใจ (ETT) + NG decompression; หลีกเลี่ยง bag-mask (ทำให้ลำไส้ในทรวงอกโป่ง)", "sys": "XVII"}, {"topic": "Dermatology", "q": "A 38-year-old woman with an annular erythematous lesion with central clearing and decreased pinprick sensation over the lesion. Diagnosis? (ต้นฉบับมีตัวเลือกไม่ครบ ใส่เท่าที่มี)", "choices": ["Tinea corporis", "Granuloma annulare", "Leprosy (Hansen disease)", "Sarcoidosis"], "ans": 2, "exp": "ผื่นวงแหวนขอบชัด + 'ชา' บนรอยโรค (hypoesthesia) = leprosy (โรคเรื้อน) จนกว่าจะพิสูจน์เป็นอื่น (tinea จะคันไม่ชา)", "sys": "XII"}, {"topic": "Obstetrics", "q": "A 38-year-old G3P2 GA 12 weeks for first ANC (chronic HT), took enalapril 3 years but stopped after pregnancy. BP 150/80. Most appropriate management?", "choices": ["Represcribe enalapril", "Prescribe atenolol", "Prescribe losartan", "Prescribe methyldopa", "Home BP monitoring only"], "ans": 3, "exp": "ACEi/ARB ห้ามใช้ในหญิงตั้งครรภ์ -> เปลี่ยนเป็นยาที่ปลอดภัยในครรภ์ เช่น methyldopa (หรือ labetalol/nifedipine)", "sys": "XV"}, {"topic": "ENT", "q": "A patient with a history of allergy. PE: swollen pale turbinates, otherwise unremarkable. Most appropriate management? (ต้นฉบับมีตัวเลือกไม่ครบ ใส่เท่าที่มี)", "choices": ["Intranasal corticosteroids", "Decongestant", "Oral antihistamine", "Antibiotics"], "ans": 0, "exp": "allergic rhinitis (turbinate ซีดบวม) -> intranasal corticosteroid เป็นยาที่ได้ผลดีสุด", "sys": "VIII"}, {"topic": "Hematology", "q": "A 70-year-old woman with dyspnea on exertion 3 months plus gait problem and paresthesia. PE: marked pale, impaired proprioception and vibration. CBC: Hb 6.2, MCV 115, RDW 25%, WBC 3500, Plt 80,000. Most proper investigation for definite diagnosis?", "choices": ["Serum vitamin B12", "Urine hemosiderin", "Serum folate", "Serum iron and TIBC", "Bone marrow aspiration"], "ans": 0, "exp": "macrocytic anemia + pancytopenia + subacute combined degeneration (สูญเสีย proprioception/vibration) = vitamin B12 deficiency -> ตรวจ serum B12", "sys": "III"}, {"topic": "Obstetrics", "q": "Which vaccine is contraindicated in a pregnant woman at GA 24 weeks?", "choices": ["Hepatitis B", "MMR", "COVID-19", "Influenza (inactivated)", "Tetanus toxoid"], "ans": 1, "exp": "MMR เป็น live-attenuated vaccine -> ห้ามให้ในหญิงตั้งครรภ์", "sys": "XV"}, {"topic": "Psychiatry", "q": "A 35-year-old man refuses an MRI, reporting palpitations, sweating, and body shaking whenever he enters a narrow space. Most likely diagnosis?", "choices": ["Panic disorder", "Dissociative disorder", "Specific phobia (claustrophobia)", "Illness anxiety disorder", "Somatic symptom disorder"], "ans": 2, "exp": "กลัวเฉพาะสถานการณ์ (ที่แคบ) + มีอาการวิตกเมื่อเผชิญ = specific phobia (claustrophobia)", "sys": "V"}, {"topic": "Orthopedics", "q": "A 40-year-old woman with elbow pain, no trauma. PE: lateral epicondyle tenderness, positive Cozen test and middle-finger extension test, no neurological deficit. Most likely diagnosis?", "choices": ["Golfer's elbow", "Cubital tunnel syndrome", "Olecranon bursitis", "Tennis elbow (lateral epicondylitis)", "Radial tunnel syndrome"], "ans": 3, "exp": "เจ็บ lateral epicondyle + Cozen/middle finger test บวก = lateral epicondylitis (tennis elbow)", "sys": "XIII"}, {"topic": "Infectious disease", "q": "A man with tuberculosis on 5 drugs develops pain and swelling at the right big toe. Which drug causes this?", "choices": ["Isoniazid", "Rifampin", "Ethambutol", "Streptomycin", "Pyrazinamide"], "ans": 4, "exp": "pyrazinamide ยับยั้งการขับกรดยูริก -> hyperuricemia/gouty attack (ปวดบวมนิ้วโป้งเท้า)", "sys": "I"}, {"topic": "Forensic", "q": "A teenage girl brought by her mother who suspects she was raped by her father. Most appropriate investigation to confirm sexual intercourse? (ต้นฉบับมีตัวเลือกไม่ครบ ใส่เท่าที่มี)", "choices": ["Serum PSA", "A new tear", "Spermatozoa from a vaginal swab", "Acid phosphatase"], "ans": 2, "exp": "หลักฐานยืนยันการร่วมเพศที่ดีที่สุด (confirmatory) คือการพบตัวอสุจิ (spermatozoa) จาก vaginal swab", "sys": "general"}, {"topic": "Obstetrics", "q": "A pregnant woman with vaginal bleeding. PE: cervical os open 1 cm. Most likely diagnosis?", "choices": ["Threatened abortion", "Inevitable abortion", "Complete abortion", "Incomplete abortion", "Missed abortion"], "ans": 1, "exp": "เลือดออก + ปากมดลูก 'เปิด' แต่ยังไม่มีเนื้อออก = inevitable abortion (threatened จะปากมดลูกปิด)", "sys": "XV"}, {"topic": "ENT", "q": "A man with left nasal obstruction and whitish discharge. Anterior rhinoscopy: polypoid mass with whitish discharge. CT: homogeneous soft tissue density, no bony lysis. Most likely diagnosis?", "choices": ["Mucocele", "Meningocele", "Nasal polyp", "CA nasal cavity", "Inverted papilloma"], "ans": 2, "exp": "ก้อน polypoid + CT soft tissue homogeneous ไม่มีการทำลายกระดูก = nasal polyp (benign). มะเร็งจะมี bone destruction", "sys": "VIII"}, {"topic": "Dermatology", "q": "An 18-year-old with multi-stage inflammatory papules on the face. Proper drug?", "choices": ["Oral isotretinoin", "Oral clindamycin", "Topical triamcinolone", "Topical clindamycin", "Mupirocin cream"], "ans": 3, "exp": "สิวอักเสบระดับปานกลาง (inflammatory papules) -> topical antibiotic (clindamycin) ร่วม topical retinoid/BPO; เก็บ oral isotretinoin ไว้สำหรับ nodulocystic รุนแรง", "sys": "XII"}, {"topic": "Emergency", "q": "A 60-year-old with high fever and rash 1 day, 4 days after an IM analgesic injection in the right buttock. PE: T 39.5, BP 80/50, stupor, diffuse erythema, few flaccid bullae over the trunk. WBC 19,000, bullae gram stain: no organism. Most appropriate management?", "choices": ["Piperacillin/tazobactam", "Penicillin + clindamycin", "Ceftriaxone + clindamycin", "Clindamycin + vancomycin", "Meropenem + vancomycin (+ clindamycin)"], "ans": 4, "exp": "necrotizing soft tissue infection + septic shock -> ยาปฏิชีวนะครอบคลุมกว้างสุด (carbapenem + vancomycin คลุม MRSA) ร่วมกับ clindamycin (ลด toxin) + ผ่าตัด debride ด่วน", "sys": "emergency"}, {"topic": "Pediatrics", "q": "A 10-year-old boy with fever and sore throat, then pallor and fatigue; a similar episode occurred last year. PE: pale conjunctivae. Hct 21%, Hb 7, MCV 85. Most proper investigation?", "choices": ["G6PD level", "Hb typing", "Urinalysis", "Direct Coombs test", "Bone marrow study"], "ans": 0, "exp": "ซีดเฉียบพลันเป็นซ้ำ ๆ ถูกกระตุ้นด้วยการติดเชื้อ (normocytic) = acute hemolysis จาก G6PD deficiency -> ตรวจ G6PD level", "sys": "III"}, {"topic": "Pediatrics", "q": "A cystic-consistency mass in a male newborn. Diagnosis? (ตำแหน่งในต้นฉบับไม่ชัด)", "choices": ["Sarcoma", "Teratoma", "Meningioma", "Meningoencephalocele", "Hemangioma"], "ans": 1, "exp": "ก้อน cystic ในทารกแรกเกิด (เช่น sacrococcygeal) ที่พบบ่อยคือ teratoma. *ถ้าเป็นก้อน midline ที่ศีรษะ/หลังต่อ dura อาจเป็น meningoencephalocele*", "sys": "XVI"}, {"topic": "Pediatrics", "q": "A term newborn with cleft lip and palate, bilateral postaxial polydactyly, AV septal defect, a round scalp lesion (aplasia cutis), and an omphalocele. Most appropriate investigation?", "choices": ["DNA sequencing", "Ultrasound brain", "Chromosome study", "Echocardiogram", "TORCH screening"], "ans": 2, "exp": "cleft lip/palate + postaxial polydactyly + AVSD + aplasia cutis + omphalocele = ลักษณะ trisomy 13 (Patau) -> ยืนยันด้วย chromosome study (karyotype)", "sys": "XVI"}, {"topic": "Hematology", "q": "A 60-year-old woman with fatigue 1 month. PE: pallor, petechiae and purpura on both legs. CBC: Hb 6.5, WBC 3,500 (N25%, L65%), Plt 15,000 (pancytopenia). Appropriate investigation?", "choices": ["Coagulogram", "ESR, CRP", "Peripheral blood smear", "Bone marrow study", "ANA"], "ans": 3, "exp": "pancytopenia ที่ไม่ทราบสาเหตุ -> ตรวจไขกระดูก (bone marrow study) เพื่อวินิจฉัย (leukemia/aplastic/MDS)", "sys": "III"}, {"topic": "Neurology", "q": "A 35-year-old with chronic alcohol use has a generalized tonic-clonic seizure 1 day after stopping drinking (due to a cold). Afterward stable, good conscious, mild hand tremor, no stiff neck. Most likely diagnosis?", "choices": ["Hepatic encephalopathy", "Thiamine deficiency", "Meningitis", "Idiopathic epilepsy", "Alcohol withdrawal seizure"], "ans": 4, "exp": "ชักภายใน 1-2 วันหลังหยุดดื่มสุรา + tremor = alcohol withdrawal seizure", "sys": "VI"}, {"topic": "Obstetrics", "q": "A breastfeeding mother with unilateral breast engorgement and fever. Proper management?", "choices": ["Prescribe cloxacillin (+ continue feeding)", "Breastfeed from the other breast only", "Cold compression", "Breast binding", "Bromocriptine"], "ans": 0, "exp": "เต้านมข้างเดียวคัด + ไข้ = สงสัย mastitis -> ให้ยาปฏิชีวนะ (cloxacillin) + ให้ลูกดูดจากข้างที่เป็นต่อเพื่อระบายน้ำนม", "sys": "flex"}, {"topic": "Pediatrics", "q": "A 6-year-old naughty boy, 1st grade, with poor school performance, loud play, running around the class, but normal developmental milestones. Diagnosis?", "choices": ["Learning disability", "Attention-deficit hyperactivity disorder", "Intellectual disability", "Conduct disorder", "Pervasive developmental disorder"], "ans": 1, "exp": "ซน อยู่ไม่นิ่ง วิ่งในห้อง + สมาธิสั้น/เรียนแย่ โดยพัฒนาการปกติ = attention-deficit hyperactivity disorder (ADHD)", "sys": "flex"}, {"topic": "Obstetrics", "q": "A pregnant woman GA 41+3 weeks for planned amniotomy: cervix 6 cm, station 0, contractions every 2 min lasting 60 s. After 2 hours: cervix 7 cm, station 0 (adequate contractions). Proper management?", "choices": ["Increase the rate of oxytocin", "Decrease the rate of oxytocin", "Observe", "Maintain the same rate of oxytocin", "Cesarean delivery"], "ans": 2, "exp": "contractions เพียงพอ (q2 นาที 60 วิ) + ปากมดลูกยังก้าวหน้า (6->7) ยังไม่เข้าเกณฑ์ arrest -> เฝ้าสังเกตต่อ (ไม่เพิ่ม oxytocin เพราะเสี่ยง tachysystole)", "sys": "XV"}, {"topic": "Pediatrics", "q": "A 20-year-old man with fever 2 days; 2 weeks ago he had cheek swelling (parotid enlargement) and left scrotal swelling. Most likely diagnosis?", "choices": ["Testicular torsion", "Epididymo-orchitis (bacterial)", "Testicular tumor", "Mumps orchitis", "Inguinal hernia"], "ans": 3, "exp": "parotitis (คางทูม) ตามด้วยอัณฑะบวม = mumps orchitis", "sys": "II"}, {"topic": "Pediatrics", "q": "A 9-month-old with tetralogy of Fallot presents with hyperpnea, crying, and dyspnea; RR 40, no hepatomegaly, pansystolic murmur at the left lower sternal border. Proper management?", "choices": ["Enalapril", "Furosemide", "Digoxin", "Adenosine", "Morphine"], "ans": 4, "exp": "hypercyanotic (tet) spell ใน TOF -> knee-chest position, O2, และ morphine (ลด hyperpnea/infundibular spasm)", "sys": "IX"}, {"topic": "Obstetrics", "q": "What is the treatment for a threatened abortion?", "choices": ["Observe (expectant, pelvic rest)", "Dilation and curettage", "Uterine evacuation", "Oxytocin", "Methotrexate"], "ans": 0, "exp": "threatened abortion (เลือดออก + ปากมดลูกปิด + ตัวอ่อนยังมีชีวิต) -> รักษาแบบ expectant (สังเกตอาการ + pelvic rest). *inevitable/incomplete จึงพิจารณา evacuation*", "sys": "XV"}, {"topic": "Orthopedics", "q": "A 45-year-old man with wrist pain 2 months, often at night. PE: paresthesia on the volar thumb, index, and middle fingers; thenar atrophy; positive Tinel's sign. Most appropriate management?", "choices": ["NSAIDs", "Surgical release", "Thumb splint", "Physical therapy", "Steroid injection"], "ans": 1, "exp": "carpal tunnel syndrome ที่มี thenar muscle atrophy (severe, motor involvement) -> surgical release (carpal tunnel decompression)", "sys": "XIII"}, {"topic": "Medicine", "q": "A 35-year-old heavy smoker with acute dyspnea 3 hours. PE: BP 180/100, CVP 14, copper-wire retinal vessels, crepitations both lungs, abdominal bruit both sides. ECG: LVH. Cr 3, HCO3 30. CXR: cephalization, normal cardiothoracic ratio. Most appropriate investigation?", "choices": ["Urine VMA", "Cardiac troponin", "Duplex ultrasound of the renal arteries", "Echocardiography", "CT whole abdomen"], "ans": 2, "exp": "ความดันสูงดื้อยา + abdominal bruit + ไตเสื่อม = สงสัย renovascular hypertension (renal artery stenosis) -> duplex ultrasound ของ renal artery", "sys": "VII"}, {"topic": "Ethics", "q": "A physician wants to post a picture on Facebook. Which one can be done?", "choices": ["Patient information without the patient's name", "A patient's skin lesion", "A ward with a patient", "A staff member who works on the ward (with consent)", "A bedside round with a patient"], "ans": 3, "exp": "ภาพที่โพสต์ได้โดยไม่ละเมิดความลับผู้ป่วยคือภาพเจ้าหน้าที่ (ไม่ใช่ผู้ป่วย) โดยได้รับความยินยอม; ภาพผู้ป่วย/รอยโรค/ในวอร์ด อาจระบุตัวผู้ป่วยได้ต้องขอความยินยอม", "sys": "general"}, {"topic": "Cardiology", "q": "A 60-year-old with DM/HT/DLP has acute retrosternal chest pain 2 hours. PE: BP 140/90, JVP 14, fine crepitations both lungs. ECG: 2 mm ST depression V2-V6. hs-TropT 400. He received oxygen, aspirin, clopidogrel, enoxaparin. Most appropriate management?", "choices": ["rt-PA", "Furosemide", "Nicardipine", "Hydralazine + isosorbide dinitrate", "Nitroglycerin"], "ans": 4, "exp": "NSTEMI (ST depression + troponin สูง) + ภาวะปอดคั่งน้ำ -> nitroglycerin (ลด preload, บรรเทา ischemia). ห้ามให้ thrombolytic (rt-PA) ใน NSTEMI", "sys": "IX"}]}, {"id": "nl2-2023", "title": "NL 2 ปี 2023 (VICHAKARN_SMST)", "subject": "past", "questions": [{"topic": "Cardiology", "q": "A 70-year-old man with dizziness and syncope on and off for 3 months. PE: BP 130/70, HR 70/min with dropped beats. EKG shown. Diagnosis?", "choices": ["AV block", "Pericarditis", "Sick sinus syndrome", "SVT", "Myocardial infarction"], "ans": 0, "exp": "มี 'dropped beat' (QRS หายเป็นบางจังหวะ) = AV block. *อ้างอิงภาพ EKG*", "img": "https://cdn.jsdelivr.net/gh/MercenzK/Web-quiz-images@main/NL2-2023-Med-Q1.png", "sys": "IX"}, {"topic": "Cardiology", "q": "A 65-year-old woman with on-and-off syncope over 2 months. EKG shown. Diagnosis? (ต้นฉบับมีตัวเลือกไม่ครบ ใส่เท่าที่มี)", "choices": ["AV block", "Sick sinus syndrome", "Paroxysmal supraventricular tachycardia"], "ans": 1, "exp": "เป็นลมเป็นพัก ๆ หลายเดือน + EKG มี pause/bradyarrhythmia = sick sinus syndrome. *อ้างอิงภาพ EKG*", "img": "https://cdn.jsdelivr.net/gh/MercenzK/Web-quiz-images@main/NL2-2023-Med-Q2.png", "sys": "IX"}, {"topic": "Cardiology", "q": "A 50-year-old man with fever and dark urine after blood transfusion (hemolysis). BP 90/60, SpO2 99%. EKG shown. Most appropriate management?", "choices": ["NSS loading", "Amiodarone", "Calcium gluconate", "Magnesium sulfate", "Sodium bicarbonate"], "ans": 2, "exp": "hemolytic transfusion reaction -> hyperkalemia + EKG เปลี่ยนแปลง -> ให้ calcium gluconate stabilize หัวใจก่อน. *อ้างอิงภาพ EKG*", "img": "https://cdn.jsdelivr.net/gh/MercenzK/Web-quiz-images@main/NL2-2023-Med-Q3.png", "sys": "IX"}, {"topic": "Cardiology", "q": "A 45-year-old man with severe chest pain 1 hour, DM and heavy smoking. BP 100/70, PR 110. EKG: ST elevation V1-V4, ST depression II/III/aVF. Nearest PCI center is 150 minutes away. After aspirin and clopidogrel, most appropriate management?", "choices": ["Dobutamine", "Enoxaparin", "Furosemide", "Streptokinase (fibrinolysis)", "Refer to PCI center"], "ans": 3, "exp": "STEMI ที่ไปถึง PCI center ใช้เวลา >120 นาที -> ให้ยาละลายลิ่มเลือด (streptokinase/fibrinolysis) ทันทีแทนการส่งไปทำ PCI", "sys": "IX"}, {"topic": "Cardiology", "q": "A 30-year-old woman with syncope while lying on the bed for 3 months. PE unremarkable, 12-lead EKG normal. Most appropriate management?", "choices": ["EEG", "Tilt table test", "Echocardiography", "CT brain", "Holter monitoring"], "ans": 4, "exp": "เป็นลมขณะ 'นอนราบ' (ไม่เข้ากับ vasovagal/orthostatic) -> สงสัยหัวใจเต้นผิดจังหวะเป็นพัก ๆ -> Holter monitoring", "sys": "IX"}, {"topic": "Cardiology", "q": "A 58-year-old with type 2 DM and HT on enalapril 40 mg/day. BP 150/100, FPG 120, HbA1c 6.5%, urine protein 2+, EKG LVH. Which medication should be added?", "choices": ["Amlodipine", "Atenolol", "Hydrochlorothiazide", "Verapamil", "Losartan"], "ans": 0, "exp": "คุมไม่ได้ทั้งที่ ACEi เต็มขนาด + มี proteinuria -> เพิ่มยากลุ่ม 2 เป็น calcium channel blocker (amlodipine) หรือ thiazide. ไม่ควรรวม ACEi + ARB (losartan)", "sys": "IX"}, {"topic": "Cardiology", "q": "A 50-year-old man with exertional chest tightness radiating to both sides of the mandible for a month; HT with poor compliance, smoker. PE: apical heave, BP 160/90. Most appropriate management?", "choices": ["Enalapril", "Atenolol", "Amlodipine", "Hydralazine", "Hydrochlorothiazide"], "ans": 1, "exp": "stable angina + HT -> beta-blocker (atenolol) ลดทั้งอาการ angina และความดัน", "sys": "IX"}, {"topic": "Cardiology", "q": "A 50-year-old woman with progressive dyspnea 1 week, post-radical mastectomy with 6 months of doxorubicin. RR 20, PR 120, BP 90/60, faint heart sounds, clear lungs. Most appropriate management?", "choices": ["Furosemide", "Right heart catheterization", "Pericardiocentesis", "IV fluid", "Beta-blocker"], "ans": 2, "exp": "เสียงหัวใจเบา + ความดันต่ำ + ปอดใส (หลัง doxorubicin/มะเร็ง) = cardiac tamponade จาก pericardial effusion -> pericardiocentesis", "sys": "IX"}, {"topic": "Medicine", "q": "A patient with fatigue and limb pain 1 month on amlodipine, metformin, simvastatin. PE: motor grade V, DTR 2+. AST 20, ALT 32, CPK 300. Most likely cause?", "choices": ["Polymyositis", "Fibromyalgia", "Diabetic neuropathy", "Drug-induced (statin) myopathy", "Hypothyroidism"], "ans": 3, "exp": "ปวดกล้ามเนื้อ + CPK สูงเล็กน้อยขณะใช้ simvastatin = statin-induced myopathy", "sys": "IV"}, {"topic": "Medicine", "q": "A 50-year-old man with muscle pain on amlodipine, simvastatin, metformin. PE: motor grade IV all extremities, sensory intact, DTR 2+. Most likely diagnosis?", "choices": ["Pyomyositis", "Fibromyalgia", "Peripheral neuropathy", "Hypothyroidism", "Drug-induced (statin) myopathy"], "ans": 4, "exp": "อ่อนแรง proximal + ปวดกล้ามเนื้อขณะใช้ statin = statin-induced myopathy", "sys": "IV"}, {"topic": "Cardiology", "q": "A 20-year-old man with fever, known rheumatic mitral stenosis. BT 38, petechiae at conjunctiva and fingertips, diastolic rumble and pansystolic murmur at apex. Most likely diagnosis?", "choices": ["Infective endocarditis", "Acute rheumatic fever", "Pericarditis", "Acute heart failure", "Aortic dissection"], "ans": 0, "exp": "ไข้ + ลิ้นหัวใจผิดปกติเดิม + petechiae ที่เยื่อบุตา/ปลายนิ้ว (embolic) = infective endocarditis", "sys": "IX"}, {"topic": "Nephrology", "q": "A 75-year-old with DM/HT started enalapril; at follow-up BP 150/100 but creatinine rose from 1 to 1.5 mg/dL. Appropriate management?", "choices": ["Continue enalapril, recheck Cr in 1 week", "Discontinue enalapril and recheck Cr in 1 week", "Continue enalapril, recheck Cr in 1 month", "Decrease enalapril to 5 mg, recheck in 1 week", "Switch to amlodipine"], "ans": 1, "exp": "Cr เพิ่มจาก 1 -> 1.5 (50% >30% threshold) หลังเริ่ม ACEi -> หยุด enalapril แล้วตรวจ Cr ซ้ำ (สงสัย renal artery stenosis)", "sys": "XIV"}, {"topic": "Cardiology", "q": "A middle-aged man with BP 173/110 (right arm) and 153/100 (left arm). Most appropriate management?", "choices": ["Nicardipine", "rt-PA", "Esmolol", "Warfarin", "Aspirin"], "ans": 2, "exp": "ความดันแขนสองข้างต่างกันมาก = สงสัย aortic dissection -> ควบคุม HR/BP ด้วย beta-blocker (esmolol) ก่อน", "sys": "IX"}, {"topic": "Cardiology", "q": "A 20-year-old woman with low-grade fever 1 month, known rheumatic MS/MR. BT 38. PE: fine petechiae at conjunctivae and fingertips, diastolic rumble and blowing murmur at apex. Most likely diagnosis?", "choices": ["Rheumatic carditis", "Meningococcal meningitis", "Disseminated tuberculosis", "Infective endocarditis", "Acute rheumatic fever"], "ans": 3, "exp": "ไข้เรื้อรัง + ลิ้นหัวใจผิดปกติเดิม + embolic petechiae = infective endocarditis", "sys": "IX"}, {"topic": "Cardiology", "q": "A 20-year-old woman with transient loss of consciousness preceded by lightheadedness, nausea, and blurred vision, then a few myoclonic jerks 30 s later with full recovery. No orthostatic hypotension, normal exam. Most useful investigation?", "choices": ["Plasma sugar", "EEG", "CT brain", "Echocardiography", "Tilt table test"], "ans": 4, "exp": "prodrome (มึน คลื่นไส้ ตาพร่า) แล้วหมดสติสั้น ๆ + convulsive movement = vasovagal (neurally-mediated) syncope -> tilt table test", "sys": "IX"}, {"topic": "Pulmonology", "q": "A 60-year-old man with dyspnea, smoking 20 years. BP 130/90, RR 30, drowsiness, cyanosis, poor air entry both lungs. Most appropriate initial management?", "choices": ["Endotracheal intubation", "Nebulized salbutamol", "O2 mask", "IV aminophylline", "Chest X-ray"], "ans": 0, "exp": "COPD ที่มี drowsiness (CO2 narcosis) + cyanosis + poor air entry = respiratory failure ใกล้หยุดหายใจ -> secure airway ด้วย ETT (พิจารณา NIV ถ้ายังตื่นดี)", "sys": "X"}, {"topic": "Pulmonology", "q": "A 60-year-old with COPD and ischemic cardiomyopathy has frequent exacerbations and still smokes 20 cigarettes/day despite advice. What should be done next?", "choices": ["Arrange more frequent follow-up", "Assess the patient's reason to smoke", "Advise him to stop smoking immediately", "Refer to a smoking cessation clinic", "Order nicotine gum"], "ans": 1, "exp": "ผู้ป่วยยังไม่พร้อมเลิก (สูบต่อแม้แนะนำแล้ว) -> ใช้ motivational interviewing ประเมินเหตุผล/แรงจูงใจในการสูบก่อน", "sys": "X"}, {"topic": "Hematology", "q": "A woman with hemolytic anemia received 2 units of PRC over 2 hours and developed dyspnea. BP 140/90, JVP 6 cm, liver 2 cm below costal margin, coarse crepitations with wheezing both lungs. Management? (ต้นฉบับตัวเลือกไม่มีคำตอบที่ถูก จึงเพิ่มให้)", "choices": ["Adrenaline", "Nebulized salbutamol", "Furosemide (transfusion-associated circulatory overload)"], "ans": 2, "exp": "หายใจเหนื่อย + ปอดมี crepitation/คั่งน้ำ + ตับโตหลังให้เลือดเร็ว = TACO (volume overload) -> ให้ furosemide + หยุด/ชะลอเลือด. *ต้นฉบับตัวเลือกไม่มีคำตอบที่ถูก จึงเพิ่มให้*", "sys": "III"}, {"topic": "GI/Hepatology", "q": "A 30-year-old with nausea and vomiting; drinks 1-2 bottles of whiskey daily for 10 years and took paracetamol 2 tabs 4 times/day for a week. PE: jaundice, spider angioma, palmar erythema, hepatomegaly, mild RUQ tenderness. Diagnosis?", "choices": ["Acute pancreatitis", "Acute viral hepatitis B", "Ascending cholangitis", "Acetaminophen toxicity", "Alcoholic intoxication"], "ans": 3, "exp": "ผู้ป่วยโรคตับจากสุราเรื้อรัง (glutathione พร่อง) + กิน paracetamol ~4 กรัม/วัน หลายวัน -> acetaminophen hepatotoxicity (ตับเสียหายที่ขนาดต่ำกว่าปกติในคนดื่มสุรา)", "sys": "XI"}, {"topic": "GI/Hepatology", "q": "A 55-year-old for check-up: liver span 11 cm. AST 270, ALT 137. Most likely diagnosis?", "choices": ["Autoimmune hepatitis", "Drug-induced hepatitis", "Fatty liver", "Chronic hepatitis B", "Alcoholic hepatitis"], "ans": 4, "exp": "AST:ALT ~2:1 (AST เด่น) = alcoholic hepatitis", "sys": "XI"}, {"topic": "GI/Hepatology", "q": "A 55-year-old woman with epigastric burning for 1 month, no other disease. Most appropriate management?", "choices": ["Esophagogastroduodenoscopy (EGD)", "Omeprazole", "Domperidone", "Ultrasound RUQ", "Amoxicillin"], "ans": 0, "exp": "dyspepsia รายใหม่อายุ >=55 ปี -> ควรส่องกล้อง EGD เพื่อแยกมะเร็ง (แม้ยังไม่มี alarm feature ชัด)", "sys": "XI"}, {"topic": "Surgery", "q": "A 50-year-old woman with RUQ pain radiating to the right arm, chronic alcohol use, prior self-resolving biliary colic; fever but no jaundice. When the doctor presses under the right ribs she suddenly stops breathing (Murphy's sign). Diagnosis?", "choices": ["Acute pancreatitis", "Acute cholecystitis", "Acute cholangitis", "Alcoholic hepatitis", "Gastric ulcer"], "ans": 1, "exp": "ปวด RUQ + ไข้ + Murphy's sign positive = acute cholecystitis (ยังไม่มีดีซ่าน/Charcot triad จึงไม่ใช่ cholangitis)", "sys": "XI"}, {"topic": "GI/Hepatology", "q": "A 45-year-old with severe epigastric pain radiating to the back and vomiting, alcohol use, amylase 2,000. After NPO and hydration 1 day, pain declined from 8/10 to 5/10. Most proper dietary management?", "choices": ["Continue NPO", "Soft diet", "Clear fluid", "Low-fat diet", "Regular diet"], "ans": 2, "exp": "acute pancreatitis ที่อาการดีขึ้น -> เริ่มให้อาหารทางปากเร็ว โดยเริ่มจาก clear fluid แล้วค่อย advance เป็น low-fat diet (ไม่ต้อง NPO จนหายปวดสนิท)", "sys": "XI"}, {"topic": "Neurology", "q": "A 60-year-old with right arm and leg weakness for 1 hour. BP 170/100, PR 100 irregular. Neuro: left forced eye deviation, right hemiparesis, aphasia. CT: no hemorrhage. Most appropriate management?", "choices": ["Aspirin", "Aspirin + clopidogrel", "Nicardipine", "Alteplase (IV thrombolysis)", "Enoxaparin"], "ans": 3, "exp": "acute ischemic stroke ภายใน window + CT ไม่มีเลือดออก + BP ไม่เกินเกณฑ์ -> IV thrombolysis (alteplase)", "sys": "VI"}, {"topic": "Neurology", "q": "A 40-year-old man with drooping eyelids that worsen in the evening. PE: asymmetrical ptosis, lateral rectus palsy, positive curtain sign. Diagnosis?", "choices": ["Cavernous sinus syndrome", "Horner syndrome", "Third nerve palsy", "Thyroid eye disease", "Ocular myasthenia gravis"], "ans": 4, "exp": "หนังตาตกที่แย่ลงตอนเย็น (fatigable) + curtain sign = ocular myasthenia gravis", "sys": "VI"}, {"topic": "Neurology", "q": "A 20-year-old man with limb weakness 2 hours after a full meal, recurrent over the past year (takes 3 hours to recover). PE: normal cranial nerves, intact sensation, proximal weakness grade III, DTR 1+. Most likely diagnosis?", "choices": ["Periodic paralysis", "Myasthenia gravis", "Cord compression", "Guillain-Barre syndrome", "Polymyositis"], "ans": 0, "exp": "อ่อนแรงเป็นพัก ๆ หลังกินอาหาร (คาร์บ) หายเองใน 3 ชม. = hypokalemic periodic paralysis (มักสัมพันธ์ thyrotoxicosis)", "sys": "VI"}, {"topic": "Neurology", "q": "An elderly woman cannot perform ADLs and needs help bathing; at night she has disorientation to time and place. Cognitive test is poor (cannot recall 3 words, cannot draw). Diagnosis?", "choices": ["Delirium", "Alzheimer disease", "Korsakoff encephalopathy", "Mild cognitive impairment", "Depression"], "ans": 1, "exp": "ความจำ/การรู้คิดถดถอยเรื้อรัง + ทำ ADL ไม่ได้ (functional decline) = dementia (Alzheimer disease); การสับสนกลางคืน = sundowning ของ dementia", "sys": "VI"}, {"topic": "Hematology", "q": "An elderly patient with dyspnea, normal neuro exam, pancytopenia with MCV 110 fL. Most proper investigation?", "choices": ["Serum folate", "Bone marrow aspiration", "Serum vitamin B12", "Serum iron", "Reticulocyte count"], "ans": 2, "exp": "macrocytic (MCV 110) + pancytopenia -> ตรวจ serum vitamin B12 (และ folate) หา megaloblastic anemia", "sys": "III"}, {"topic": "Neurology", "q": "A 35-year-old construction worker with deteriorating weakness 2 weeks, long history of alcohol and cannabis use. BMI 18, motor grade III all extremities, areflexia, paresthesia of hands and feet, pupils 2 mm. Most likely diagnosis?", "choices": ["Periodic paralysis", "Myasthenia gravis", "Alcoholic myopathy", "Thiamine deficiency", "Cannabis intoxication"], "ans": 3, "exp": "ดื่มสุรา + ขาดอาหาร (BMI 18) + peripheral neuropathy (areflexia, ชาปลายมือปลายเท้า) = thiamine (B1) deficiency = dry beriberi", "sys": "VI"}, {"topic": "Neurology", "q": "A 25-year-old with drooping and weakness of the left side of the face. PE: weakness of orbicularis oculi and oris (whole hemiface), normal ear exam. Most proper management?", "choices": ["Observation", "Gabapentin", "Oral acyclovir", "Vitamin B complex", "Prednisolone"], "ans": 4, "exp": "อ่อนแรงกล้ามเนื้อใบหน้าครึ่งซีกแบบ LMN (รวมหน้าผาก) หูปกติ = Bell's palsy -> corticosteroid (prednisolone) เริ่มเร็วภายใน 72 ชม.", "sys": "VI"}, {"topic": "Neurology", "q": "A 50-year-old secretary with dizziness and headache 3 months, not improved with anti-migraine or anti-vertigo drugs. PE: right trapezius and scalene muscles show a tight bundle with marked tenderness radiating to the right temporal area; no weakness or sensory loss. Most likely diagnosis?", "choices": ["Myofascial pain syndrome", "Fibromyalgia", "Cervical spondylosis", "Atypical migraine", "Hypertension headache"], "ans": 0, "exp": "trigger point/tight band ที่กล้ามเนื้อ (trapezius/scalene) กดแล้วปวดร้าว = myofascial pain syndrome", "sys": "VI"}, {"topic": "Neurology", "q": "A 40-year-old woman with progressive weakness 3 days: unstable gait then weakness. PE: no gag reflex, symmetrical proximal weakness grade III, loss of proprioception in both hands, areflexia, Babinski plantarflexion. Most useful investigation?", "choices": ["Tensilon test", "CSF analysis", "EEG", "MRI spine", "CT brain"], "ans": 1, "exp": "อ่อนแรงขึ้นเรื่อย ๆ + areflexia + proprioception เสีย = Guillain-Barre syndrome -> CSF พบ albuminocytologic dissociation (protein สูง, cell ปกติ)", "sys": "VI"}, {"topic": "Neurology", "q": "A 40-year-old woman with progressive weakness over a few days: gait difficulty then weakness. PE: proximal weakness grade III, decreased proprioception at fingers/toes, areflexia, absent gag reflex, Babinski negative. Diagnosis? (ต้นฉบับตัวเลือกไม่มีคำตอบที่ถูก จึงเพิ่มให้)", "choices": ["Hemorrhagic stroke", "Ischemic stroke", "Guillain-Barre syndrome", "Meningitis", "Brain tumor"], "ans": 2, "exp": "อ่อนแรงขึ้นเรื่อย ๆ แบบสมมาตร + areflexia + proprioception เสีย = Guillain-Barre syndrome. *ต้นฉบับให้แต่ตัวเลือกโรคสมองส่วนกลาง ซึ่งไม่ตรง จึงเพิ่มคำตอบที่ถูก*", "sys": "VI"}, {"topic": "Neurology", "q": "A 30-year-old woman with headache for 6 months, 2-3 days/week, worse in the afternoon, bilateral frontal and occipital. What type of headache?", "choices": ["Cluster headache", "Migraine", "Pseudotumor cerebri", "Tension headache", "Increased intracranial pressure"], "ans": 3, "exp": "ปวดตื้อรัดรอบศีรษะ (หน้าผาก+ท้ายทอย) 2 ข้าง เรื้อรัง = tension-type headache", "sys": "VI"}, {"topic": "Neurology", "q": "An obese woman with bilateral non-throbbing headache 1 month. PE: papilledema, otherwise normal. CT brain with contrast normal. Most proper management?", "choices": ["Cerebral angiography", "MRI brain", "Prescribe TCA", "Prescribe corticosteroid", "Lumbar puncture"], "ans": 4, "exp": "หญิงอ้วน + papilledema + CT ปกติ = idiopathic intracranial hypertension -> lumbar puncture (วัด/ลด opening pressure, ทั้งวินิจฉัยและรักษา)", "sys": "VI"}, {"topic": "Infectious disease", "q": "A patient with fever, meningeal signs, and left sensorineural hearing loss; low CSF sugar. Causative organism?", "choices": ["Streptococcus suis", "Klebsiella pneumoniae", "Staphylococcus aureus", "Mycobacterium tuberculosis", "Neisseria meningitidis"], "ans": 0, "exp": "เยื่อหุ้มสมองอักเสบ + หูหนวกประสาท (sensorineural) โดยเฉพาะในคนสัมผัสหมู = Streptococcus suis", "sys": "I"}, {"topic": "Infectious disease", "q": "A 30-year-old woman with headache 3 days; HIV and CKD stage 4. CSF stain shown. Diagnosis?", "choices": ["Aspergillosis", "Cryptococcosis", "Mucormycosis", "Candidiasis", "Toxoplasmosis"], "ans": 1, "exp": "HIV + เยื่อหุ้มสมองอักเสบ + CSF stain (India ink) พบยีสต์มี capsule = cryptococcosis. *อ้างอิงภาพ*", "img": "https://cdn.jsdelivr.net/gh/MercenzK/Web-quiz-images@main/NL2-2023-Med-Q37.png", "sys": "I"}, {"topic": "Infectious disease", "q": "A 38-year-old with fever, myalgia, and headache not improved by amoxicillin/clavulanate. BT 38, a pale maculopapular rash with central necrosis (eschar). Most appropriate treatment?", "choices": ["Ciprofloxacin", "Meropenem", "Azithromycin (or doxycycline)", "Ceftriaxone", "Vancomycin"], "ans": 2, "exp": "eschar + ไข้ไม่ตอบสนอง beta-lactam = scrub typhus -> doxycycline (หรือ azithromycin)", "sys": "I"}, {"topic": "Infectious disease", "q": "A 40-year-old with altered consciousness and fever 3 days. BT 40. CT: hypodensity at the left temporal lobe. CSF: WBC high (monocyte predominant), normal glucose, protein 60. Most appropriate management?", "choices": ["Praziquantel", "Dexamethasone", "Ceftriaxone", "Acyclovir", "Doxycycline"], "ans": 3, "exp": "temporal lobe + CSF lymphocyte/monocyte + glucose ปกติ = HSV encephalitis -> IV acyclovir ทันที", "sys": "I"}, {"topic": "Infectious disease", "q": "A 40-year-old with altered consciousness and fever. CT: hypodensity at the left temporal lobe. CSF lymphocyte-predominant. Most appropriate antibiotic? (ต้นฉบับให้แต่ยาปฏิชีวนะ; ยาที่ถูกจริงคือ acyclovir)", "choices": ["Ceftriaxone (empiric) — but true treatment is acyclovir", "Amoxicillin", "Ciprofloxacin"], "ans": 0, "exp": "ภาพ+CSF = HSV encephalitis ซึ่งรักษาด้วย 'acyclovir' (antiviral). *ต้นฉบับให้แต่ยาปฏิชีวนะ ในบรรดานั้น ceftriaxone ใช้คลุม bacterial meningitis เชิง empiric ระหว่างรอ*", "sys": "I"}, {"topic": "Infectious disease", "q": "A 30-year-old farmer with headache 2 weeks, positive stiff neck, CT normal. LP: OP 30, cloudy CSF, WBC 100 (Neutrophil 60%, Eosinophil 40%), protein 200, glucose 50. Causative organism? (ต้นฉบับตัวเลือกไม่มีคำตอบที่ถูก จึงเพิ่มให้)", "choices": ["Angiostrongylus cantonensis", "JE virus", "Herpes simplex virus", "Mycobacterium tuberculosis", "Streptococcus pneumoniae"], "ans": 0, "exp": "CSF มี eosinophil 40% = eosinophilic meningitis -> Angiostrongylus cantonensis (พยาธิปอดหนู). *ต้นฉบับไม่มีตัวเลือกนี้ จึงเพิ่มคำตอบที่ถูก*", "sys": "I"}, {"topic": "Neurology", "q": "A 35-year-old with headache and generalized convulsion. Neuro exam normal, no stiff neck. CT: calcified cystic lesion. Etiologic agent?", "choices": ["Toxoplasma spp.", "Taenia solium", "Gnathostoma spp.", "Angiostrongylus spp.", "Mycobacterium tuberculosis"], "ans": 1, "exp": "ชัก + CT เห็นถุงน้ำมีหินปูน (calcified cyst) = neurocysticercosis จาก Taenia solium", "sys": "VI"}, {"topic": "Infectious disease", "q": "A 40-year-old with headache 2 weeks, BT 39. CT: mild hydrocephalus with enhanced basal cistern. CSF: OP 21, WBC 15,000, glucose 20 (low), protein 160. Diagnosis?", "choices": ["Eosinophilic meningitis", "Cryptococcal meningitis", "Tuberculous meningitis", "Bacterial meningitis", "Viral meningitis"], "ans": 2, "exp": "hydrocephalus + basal cistern enhancement + glucose ต่ำ protein สูง = TB meningitis (ภาพคลาสสิก แม้ระยะแรก cell อาจ PMN เด่น)", "sys": "I"}, {"topic": "Infectious disease", "q": "A patient with fever and meningeal irritation; CSF shows many eosinophils. Causative organism?", "choices": ["Taenia solium", "Trichuris trichiura", "Strongyloides stercoralis", "Angiostrongylus cantonensis", "Gnathostoma spinigerum"], "ans": 3, "exp": "eosinophilic meningitis = Angiostrongylus cantonensis (พบบ่อยสุด, จากกินหอย/ผักดิบ)", "sys": "I"}, {"topic": "Endocrinology", "q": "A 30-year-old woman with acute fever and painful sore throat 3 days; she has Graves disease treated with PTU 200 mg/day and propranolol for a month. Proper investigation?", "choices": ["Thyroid function test", "Thyroid receptor antibody", "Throat swab culture", "ESR", "CBC"], "ans": 4, "exp": "PTU ทำให้เกิด agranulocytosis -> ไข้ + เจ็บคอ = สงสัยเม็ดเลือดขาวต่ำ -> ตรวจ CBC ด่วน (หยุด PTU)", "sys": "IV"}, {"topic": "Endocrinology", "q": "A 50-year-old with disorientation. BT 38.9, PR 153, agitated, thyroid enlargement, warm moist skin. TFT: FT4 8.0, TSH 0.001. Appropriate management?", "choices": ["PTU + Lugol's solution + dexamethasone", "PTU + Propranolol", "MMI + Propranolol", "PTU + Haloperidol", "MMI + Haloperidol + dexamethasone"], "ans": 0, "exp": "thyroid storm -> PTU (block synthesis) + Lugol's iodine (ให้ >1 ชม.หลัง PTU, block release) + beta-blocker + dexamethasone (ลด peripheral conversion + คลุม adrenal)", "sys": "IV"}, {"topic": "Endocrinology", "q": "A patient with myxedema coma and BP ~80/60. Management? (ต้นฉบับมีตัวเลือกไม่ครบ ใส่เท่าที่มี)", "choices": ["NSS loading", "Hydrocortisone (before thyroid hormone)", "L-thyroxine"], "ans": 1, "exp": "myxedema coma -> ให้ IV hydrocortisone ก่อนให้ thyroid hormone (กันการกระตุ้น adrenal crisis) ร่วมกับ IV levothyroxine + ประคับประคอง (อุ่น, สารน้ำ)", "sys": "IV"}, {"topic": "Endocrinology", "q": "An image shows eruptive xanthomas. What should be investigated?", "choices": ["CBC", "HbA1c", "Lipid profile", "Electrolytes", "Liver function test"], "ans": 2, "exp": "eruptive xanthoma สัมพันธ์กับ 'ไตรกลีเซอไรด์สูงมาก' -> ตรวจ lipid profile", "sys": "IV"}, {"topic": "Nephrology", "q": "A 60-year-old with well-controlled DM and fatigue 1 week. JVP 4 cm (euvolemic), no edema. Na 126, osm 250 (low). Urine Na 60, urine osm 500 (concentrated). Lung nodules on CXR. Most appropriate management?", "choices": ["NaCl tablet", "IV 0.9% NaCl", "IV 3% NaCl", "Restrict fluid intake", "Insulin"], "ans": 3, "exp": "euvolemic hyponatremia + urine เข้มข้น + urine Na สูง + ก้อนในปอด = SIADH (paraneoplastic) -> รักษาด้วยการจำกัดน้ำ (fluid restriction)", "sys": "XIV"}, {"topic": "Endocrinology", "q": "A 40-year-old woman drowsy 2 days, fatigue for 2 years. LMP 5 years ago (after last delivery). PE: PR 56, BP 90/60, puffy eyelids, pallor, decreased pubic and axillary hair, dry skin. Most likely diagnosis?", "choices": ["Uremia", "Hypercalcemia", "Hypothyroidism", "Primary adrenal insufficiency", "Panhypopituitarism (Sheehan)"], "ans": 4, "exp": "ประวัติหลังคลอด + ขาดประจำเดือน + ขนรักแร้/หัวหน่าวบาง + อาการ hypothyroid/hypocortisol = panhypopituitarism (Sheehan syndrome)", "sys": "IV"}, {"topic": "Endocrinology", "q": "A 50-year-old with a cold and poor appetite 2 days, found unconscious. DM on 2 oral hypoglycemic agents for 1 year. BT 36.5, BP 100/50, HR 150, dry lips, flaccid. Diagnosis?", "choices": ["Hypoglycemia", "Lactic acidosis", "Cerebral edema", "Diabetic ketoacidosis", "Hyperosmolar hyperglycemic state"], "ans": 0, "exp": "กินได้น้อย + ยากลุ่ม sulfonylurea + หมดสติ = hypoglycemia (สาเหตุที่พบบ่อยของการหมดสติในผู้ป่วยเบาหวานที่กินยาแล้วกินอาหารน้อย)", "sys": "IV"}, {"topic": "Endocrinology", "q": "A 60-year-old with T2DM has progressive respiratory distress 1 week. PE: PR 120, RR 30, fine crepitations both lungs, JVP engorged, displaced PMI, palpable liver, pitting edema 2+. Which drug can precipitate this?", "choices": ["Metformin", "Pioglitazone", "Sulfonylurea", "Insulin glargine", "Alpha-glucosidase inhibitor"], "ans": 1, "exp": "ภาวะหัวใจล้มเหลว (คั่งน้ำ) -> pioglitazone (thiazolidinedione) ทำให้บวมน้ำ/หัวใจล้มเหลวกำเริบ", "sys": "IV"}, {"topic": "Infectious disease", "q": "A 30-year-old Thai woman with fever and chills 2 weeks, liver span 10 cm. PBS shown (malaria). Most appropriate treatment?", "choices": ["Quinine + Clindamycin", "Chloroquine + Primaquine", "Artesunate + Mefloquine", "Chloroquine + Doxycycline", "Quinine + Mefloquine"], "ans": 2, "exp": "*จากภาพจริง* เม็ดเลือดแดงขนาดปกติ ติดเชื้อหลายวงต่อเซลล์ (multiply-infected) + ring form บาง มี double chromatin dots + appliqué/accolé form = P. falciparum -> รักษาด้วย artesunate-based (artesunate + mefloquine). *ไม่ใช่ vivax เพราะเซลล์ไม่โต ไม่มี Schuffner's dots*", "img": "https://cdn.jsdelivr.net/gh/MercenzK/Web-quiz-images@main/NL2-2023-Med-Q53.png", "sys": "I"}, {"topic": "Infectious disease", "q": "A 40-year-old construction worker with fever and muscle spasm when stimulated. PE: BT 39, jaw lock, back arching, a healed punctate wound on the right sole. Diagnosis?", "choices": ["Botulism", "Parkinson disease", "Necrotizing fasciitis", "Tetanus", "Strychnine poisoning"], "ans": 3, "exp": "trismus (jaw lock) + opisthotonus (back arching) + เกร็งเมื่อกระตุ้น + แผลเก่าที่เท้า = tetanus", "sys": "I"}, {"topic": "Infectious disease", "q": "A 40-year-old woman with fever, cough, and myalgia; her daughter had the same last week. PE: weight 100 kg, BT 39, RR 28. Most proper management?", "choices": ["Ibuprofen", "Amoxicillin", "Azithromycin", "Supportive only", "Oseltamivir"], "ans": 4, "exp": "ไข้หวัดใหญ่ในผู้ป่วยกลุ่มเสี่ยง (อ้วนมาก BMI สูง) -> ให้ oseltamivir ภายใน 48 ชม.", "sys": "I"}, {"topic": "Infectious disease", "q": "A 4th-year medical student has a PPD of 16 mm (0 mm last year), asymptomatic, normal CXR. Next management?", "choices": ["INH (treat latent TB)", "Close observation", "Sputum for AFB", "Interferon-gamma release assay", "IRZE (full anti-TB)"], "ans": 0, "exp": "PPD เปลี่ยนจาก 0 -> 16 มม. (recent conversion) + ไม่มีอาการ + CXR ปกติ = latent TB infection -> รักษาด้วย INH", "sys": "I"}, {"topic": "Infectious disease", "q": "A 25-year-old with fever and sore throat 5 days. PE: gray patches on both tonsils, generalized maculopapular rash, lymphadenopathy, hepatosplenomegaly. CBC: WBC 4,000 (lymphocyte 58%, monocyte 20%, atypical lymphocytes). Diagnosis?", "choices": ["Diphtheria", "EBV infection (infectious mononucleosis)", "SARS-CoV-2 infection", "Acute retroviral syndrome", "Streptococcal tonsillitis"], "ans": 1, "exp": "เจ็บคอ + ต่อมน้ำเหลือง/ตับม้ามโต + atypical lymphocyte + ผื่น (มักหลังได้ amoxicillin) = EBV infectious mononucleosis", "sys": "I"}, {"topic": "Infectious disease", "q": "A woman with rash and lymphadenopathy 2 weeks; her husband was diagnosed with acute retroviral syndrome. Most appropriate investigation?", "choices": ["HIV ELISA (antibody)", "HIV PCR", "HIV p24 antigen", "HIV viral load", "Western blot"], "ans": 2, "exp": "acute HIV (window period, antibody อาจยังลบ) -> ตรวจ HIV p24 antigen (หรือ HIV RNA/NAT ซึ่งขึ้นเร็วสุด)", "sys": "I"}, {"topic": "Nephrology", "q": "An HIV patient on ARV for 2 years presents with nausea, vomiting, and no urine for 1 day. Abdomen soft, non-tender; only 20 ml urine from catheterization. Cr 4.5. Appropriate investigation?", "choices": ["CT abdomen", "Cystography", "Renal biopsy", "Ultrasound abdomen", "Retrograde pyelography"], "ans": 3, "exp": "AKI/anuria -> ultrasound ช่องท้อง/ไต เพื่อแยก obstruction (hydronephrosis) และประเมิน (tenofovir nephrotoxicity)", "sys": "XIV"}, {"topic": "Dermatology", "q": "Multiple papulovesicular lesions in the web spaces between the middle and index fingers (dyshidrotic eczema). Scabies prep and Tzanck smear negative. Treatment?", "choices": ["Topical antibiotics", "Permethrin cream", "Topical antifungal", "Oral acyclovir", "Corticosteroid"], "ans": 4, "exp": "dyshidrotic eczema (pompholyx) -> topical corticosteroid", "sys": "XII"}, {"topic": "Dermatology", "q": "A 25-year-old nurse with skin-colored vesicles on the lateral index and middle fingers. Most appropriate management? (ต้นฉบับมีตัวเลือกไม่ครบ ใส่เท่าที่มี)", "choices": ["Topical corticosteroid", "Electrocauterization"], "ans": 0, "exp": "ตุ่มน้ำที่นิ้วมือ (ถ้าเป็น dyshidrotic eczema) -> topical corticosteroid. *ถ้าเป็น herpetic whitlow ในบุคลากรทางการแพทย์ ให้ประคับประคอง +/- acyclovir และห้ามกรีด/จี้*", "sys": "XII"}, {"topic": "Dermatology", "q": "A 30-year-old woman with oval-shaped rashes that became itchy 1 week later. PE: oval erythematous rashes on the face, chest, abdomen, and back with a Christmas-tree distribution. Management?", "choices": ["Mupirocin ointment", "Reassure (self-limited)", "20% urea cream", "Clotrimazole cream", "Oral itraconazole"], "ans": 1, "exp": "ผื่นวงรีเรียงแบบ Christmas tree (มัก herald patch นำมาก่อน) = pityriasis rosea ซึ่งหายเองใน 6-8 สัปดาห์ -> reassure", "sys": "XII"}, {"topic": "Hematology", "q": "A 23-year-old with fatigue and dark urine 2 days and fever 3 days. PE: pallor, mild jaundice, hepatosplenomegaly. Hb 7, MCV 58, RDW 20%. PBS: hypochromic microcytic, anisopoikilocytosis, schistocytes, polychromasia. Most likely diagnosis?", "choices": ["G6PD deficiency", "Hereditary spherocytosis", "Thalassemia disease", "Autoimmune hemolytic anemia", "Paroxysmal nocturnal hemoglobinuria"], "ans": 2, "exp": "ซีด microcytic (MCV 58) เรื้อรัง + เม็ดเลือดแตกเฉียบพลัน (ตัวเหลือง ปัสสาวะเข้ม) ระหว่างมีไข้ = thalassemia disease ที่มี hemolytic crisis (G6PD จะ normocytic)", "sys": "III"}, {"topic": "Hematology", "q": "A 25-year-old with DVT on warfarin (femur fracture) is planned for surgery in 24 hours. PE: ecchymosis, no petechiae. INR 3. Most proper management?", "choices": ["Fresh frozen plasma", "Cryoprecipitate", "Platelet transfusion", "Vitamin K IV", "Protamine"], "ans": 3, "exp": "ต้อง reverse warfarin ก่อนผ่าตัดใน 24 ชม. (ไม่ฉุกเฉิน มีเวลา) -> vitamin K IV (FFP/PCC ใช้เมื่อต้อง reverse ทันทีหรือมีเลือดออกรุนแรง)", "sys": "III"}, {"topic": "Hematology", "q": "A patient with fever and fatigue 2 weeks. Liver 1 cm, spleen 1 cm. Hb 7.5, MCV 105, reticulocyte 7%. PBS: polychromasia, poikilocytosis, microspherocytes. Most appropriate investigation? (ต้นฉบับตัวเลือกไม่มีคำตอบที่ถูก จึงเพิ่มให้)", "choices": ["Bone marrow aspiration", "Wright stain", "Hb typing", "G6PD activity", "Direct Coombs test"], "ans": 4, "exp": "reticulocyte สูง + microspherocyte + polychromasia = hemolytic anemia -> ตรวจ direct Coombs test เพื่อแยก autoimmune (AIHA) จาก hereditary spherocytosis. *ต้นฉบับไม่มีตัวเลือกนี้ จึงเพิ่ม*", "sys": "III"}, {"topic": "Hematology", "q": "A 65-year-old with fatigue 5 months, no surgery. PE: moderately pale, mild jaundice. Hb 6, MCV 116, RDW 20%, WBC 3,800, Plt 110,000 (pancytopenia). Most useful investigation?", "choices": ["Bone marrow aspiration", "Wright stain", "Hb typing", "G6PD activity", "Serum ferritin"], "ans": 0, "exp": "macrocytic anemia + pancytopenia + ตัวเหลืองเล็กน้อย (ineffective erythropoiesis) -> ตรวจ bone marrow (และ B12/folate) หา megaloblastic/MDS", "sys": "III"}, {"topic": "Hematology", "q": "A postpartum woman received 2 units of PRC after postpartum hemorrhage, now with fatigue. CBC: anemia. Direct Coombs 1+, indirect Coombs 3+. Most likely diagnosis?", "choices": ["Microangiopathic hemolytic anemia", "Delayed (late) hemolytic transfusion reaction", "Chronic DIC", "Autoimmune hemolytic anemia", "ABO acute hemolytic reaction"], "ans": 1, "exp": "ซีด/hemolysis หลังรับเลือดหลายวัน + Coombs บวก = delayed hemolytic transfusion reaction (anamnestic antibody ต่อ minor antigen)", "sys": "III"}, {"topic": "Hematology", "q": "A 20-year-old with beta-thalassemia/HbE on regular transfusions, taking deferiprone 3 months for iron overload. Most watchful complication?", "choices": ["Aplastic crisis", "Thrombocytopenia", "Agranulocytosis/transaminitis", "Acute renal failure", "Acute hemolytic crisis"], "ans": 2, "exp": "deferiprone -> ต้องเฝ้าระวัง agranulocytosis/neutropenia (ร้ายแรงสุด ต้องตรวจ CBC สม่ำเสมอ) และ transaminitis", "sys": "III"}, {"topic": "Hematology", "q": "A patient with chronic mucous bloody diarrhea; PBS shown, CBC with low platelets. Diagnosis?", "choices": ["Disseminated intravascular coagulation", "Hyperosmolar hyperglycemic state", "Dengue", "Hemolytic uremic syndrome (HUS)", "Thrombotic thrombocytopenic purpura"], "ans": 3, "exp": "ถ่ายมูกเลือด + เกล็ดเลือดต่ำ + schistocyte (MAHA) + ไตวาย = hemolytic uremic syndrome (E. coli O157). *อ้างอิงภาพ*", "img": "https://cdn.jsdelivr.net/gh/MercenzK/Web-quiz-images@main/NL2-2023-Med-Q69.png", "sys": "III"}, {"topic": "Rheumatology", "q": "A 30-year-old woman with 2 hours of morning joint stiffness. PE: edema and tenderness of multiple PIP and MCP joints. RF negative, anti-CCP positive. Apart from NSAIDs, which drug should be given?", "choices": ["Prednisolone", "Paracetamol", "Gabapentin", "Diazepam", "Methotrexate"], "ans": 4, "exp": "anti-CCP บวก + polyarthritis สมมาตรของมือ + morning stiffness = rheumatoid arthritis -> เริ่ม DMARD (methotrexate) เร็ว", "sys": "XIII"}, {"topic": "Rheumatology", "q": "A 60-year-old man on HCTZ for well-controlled HT, low-risk drinker, no joint pain or stones. PE: no arthritis or tophi. Uric acid 10, Cr 0.8. Most appropriate management?", "choices": ["Change HCTZ to losartan", "Add colchicine", "Add allopurinol", "Stop alcohol drinking", "Advise a low-protein diet"], "ans": 0, "exp": "asymptomatic hyperuricemia (ไม่มี gout/นิ่ว) ไม่ต้องให้ urate-lowering; HCTZ เพิ่มกรดยูริก -> เปลี่ยนเป็น losartan (มีฤทธิ์ uricosuric ลดกรดยูริก)", "sys": "XIII"}, {"topic": "Rheumatology", "q": "A 20-year-old woman with polyarthralgia 1 month, morning stiffness 30 min. PE: BT 38, mild tenderness of both knees, wrists, PIP joints. Plt 110,000. UA: protein 3+, RBC 5-10, UPCR 2.0. Most useful investigation for diagnosis?", "choices": ["ESR", "ANA (with anti-dsDNA)", "Anti-CCP", "Rheumatoid factor", "X-ray both hands"], "ans": 1, "exp": "หญิงสาว + ไข้ + ข้ออักเสบ + เกล็ดเลือดต่ำ + proteinuria/hematuria (nephritis) = SLE -> ตรวจ ANA (และ anti-dsDNA)", "sys": "XIII"}, {"topic": "Surgery", "q": "A 50-year-old with DM has skin swelling with crepitus. Next management? (ต้นฉบับมีตัวเลือกไม่ครบ ใส่เท่าที่มี)", "choices": ["Radical debridement", "Incision and drainage", "Fasciotomy"], "ans": 0, "exp": "บวม + crepitus (แก๊สใต้ผิว) = necrotizing fasciitis/gas gangrene -> ผ่าตัด radical debridement เอาเนื้อตายออกให้หมด + ยาปฏิชีวนะกว้าง", "sys": "flex"}, {"topic": "Surgery", "q": "A man stabbed in the back by a bamboo stick develops necrotizing fasciitis with hemorrhagic blebs. Which antibiotic?", "choices": ["Ceftriaxone", "Penicillin G", "Metronidazole", "Ceftazidime", "Amoxicillin/clavulanate"], "ans": 3, "exp": "แผลปนเปื้อนดิน/พืชในไทย + necrotizing infection -> ต้องคลุม Burkholderia pseudomallei (melioidosis)/Aeromonas -> ceftazidime", "sys": "I"}, {"topic": "Surgery", "q": "An 80-year-old develops tachypnea and dyspnea during subclavian venous catheterization; SpO2 drops to 90%. Most likely diagnosis?", "choices": ["Air embolism", "Tracheal injury", "Pulmonary embolism", "Subclavian artery injury", "Pneumothorax"], "ans": 4, "exp": "หายใจเหนื่อย + SpO2 ตกทันทีระหว่างแทง subclavian line = pneumothorax (ภาวะแทรกซ้อนที่พบบ่อยสุด)", "sys": "IX"}, {"topic": "Surgery", "q": "A 55-year-old woman with varicose veins (great saphenous dilatation), duplex US: no DVT, reflux at the saphenofemoral junction. Most common long-term complication?", "choices": ["Stasis dermatitis with ulceration", "Venous gangrene", "Thrombosed vein rupture", "Pulmonary thromboembolism", "DIC"], "ans": 0, "exp": "เส้นเลือดขอด (chronic venous insufficiency) ภาวะแทรกซ้อนระยะยาวที่พบบ่อยคือ stasis dermatitis และแผลเรื้อรัง (venous ulcer)", "sys": "III"}, {"topic": "Surgery", "q": "A non-pregnant woman with right lower abdominal pain, no guarding, fever, nausea without vomiting. What to do? (ต้นฉบับมีตัวเลือกไม่ครบ ใส่เท่าที่มี)", "choices": ["Appendectomy", "Ultrasound whole abdomen", "CT abdomen"], "ans": 1, "exp": "หญิงปวดท้องน้อยขวา -> ultrasound ช่องท้อง/อุ้งเชิงกรานเพื่อแยกสาเหตุทางนรีเวชและไส้ติ่ง ก่อนตัดสินใจผ่าตัด", "sys": "XV"}, {"topic": "Surgery", "q": "A man with RLQ pain, nausea, vomiting, no fever. PE: stable, RLQ tenderness with rebound and guarding (appendicitis). Most appropriate antibiotic?", "choices": ["Ceftriaxone", "Ceftriaxone + clindamycin", "Ciprofloxacin + metronidazole", "Cefoxitin + metronidazole", "Ampicillin"], "ans": 2, "exp": "appendicitis ต้องคลุม gram-negative + anaerobe -> ciprofloxacin + metronidazole (หรือ ceftriaxone + metronidazole)", "sys": "XI"}, {"topic": "Surgery", "q": "A 25-year-old healthy man with 30 mL fresh hematemesis after drinking alcohol; he vomited food many times before vomiting fresh blood. Stable, unremarkable exam. Diagnosis?", "choices": ["Eosinophilic esophagitis", "Bleeding esophageal varices", "Ruptured esophageal ulcer", "Mallory-Weiss tear", "Gastric ulcer"], "ans": 3, "exp": "อาเจียนซ้ำ ๆ ก่อน แล้วตามด้วยเลือดออก = Mallory-Weiss tear (รอยฉีกที่รอยต่อ GE junction)", "sys": "XI"}, {"topic": "Surgery", "q": "A 35-year-old with persistent fever and right-sided abdominal pain 2 weeks. BT 39, RUQ tenderness, liver span 15 cm, ALP 389. US: 8 cm round homogeneous hypoechoic lesion in the right lobe. Most proper management?", "choices": ["IV ceftriaxone", "Aspiration", "Radiofrequency ablation", "Surgical resection", "Percutaneous drainage + antibiotics"], "ans": 4, "exp": "liver abscess ขนาดใหญ่ (8 ซม.) -> percutaneous drainage ร่วมกับยาปฏิชีวนะ (amebic ให้ metronidazole; ก้อนใหญ่/ไม่ตอบสนองจึงระบาย)", "sys": "XI"}, {"topic": "Surgery", "q": "A 64-year-old woman with RLQ pain 1 day (fever, nausea 6 hours). PE: BT 39, a 5 cm tender RLQ mass, no guarding, decreased bowel sounds. Most appropriate management?", "choices": ["IV antibiotics (appendiceal mass/phlegmon)", "CT whole abdomen", "Ultrasonography", "Acute abdomen series", "Appendectomy"], "ans": 0, "exp": "ก้อนที่ท้องน้อยขวา + ไข้ = appendiceal mass/phlegmon -> รักษาแบบ conservative ด้วย IV antibiotics ก่อน (interval appendectomy ภายหลัง)", "sys": "flex"}, {"topic": "Surgery", "q": "A 40-year-old man with constipation and abdominal distension. PE: soft, distended, a palpable 5 cm mass toward the right groin, cannot get above the mass. Management? (ต้นฉบับมีตัวเลือกไม่ครบ ใส่เท่าที่มี)", "choices": ["Emergency surgery", "Antibiotics", "Analgesic and manual reduction"], "ans": 0, "exp": "ก้อนที่ขาหนีบ 'คลำขอบบนไม่ได้' + มี bowel obstruction (ท้องผูก/อืด) = incarcerated inguinal hernia อุดตัน -> emergency surgery", "sys": "II"}, {"topic": "Surgery", "q": "A 65-year-old man with vomiting and a groin mass; hernia is suspected. Most appropriate management? (ต้นฉบับมีตัวเลือกไม่ครบ ใส่เท่าที่มี)", "choices": ["NG decompression", "Emergency surgery", "Manual reduction"], "ans": 1, "exp": "ไส้เลื่อน + อาเจียน (bowel obstruction/incarceration) -> emergency surgery", "sys": "XI"}, {"topic": "Surgery", "q": "A 30-year-old lactating woman with right breast pain 2 days (delivered last month). PE: BT 38.5, warm, erythematous, tender periareolar area, no fluctuation. Diagnosis?", "choices": ["Galactocele", "Plugged duct", "Breast engorgement", "Mastitis", "Breast abscess"], "ans": 3, "exp": "เต้านมแดงร้อนเจ็บ + ไข้ ในหญิงให้นม โดยไม่มี fluctuation (ยังไม่เป็นฝี) = mastitis", "sys": "XI"}, {"topic": "Surgery", "q": "A 48-year-old woman with a 2 cm hard right thyroid nodule 2 months, no compressive symptoms/hoarseness, goiter 10 years. Most proper investigation?", "choices": ["Ultrasound", "Thyroid scan", "CT neck", "Lobectomy", "FNA"], "ans": 4, "exp": "thyroid nodule แข็ง + TFT ปกติ -> FNA เพื่อดู cytology (มักทำร่วม/หลัง ultrasound)", "sys": "IV"}, {"topic": "Surgery", "q": "A 30-year-old with Graves disease 10 years now has a 2 cm firm right thyroid nodule. Most appropriate further investigation?", "choices": ["FNA", "Lobectomy", "CT neck", "Ultrasound thyroid", "Thyroid scan"], "ans": 0, "exp": "ก้อนไทรอยด์แข็ง (สงสัยมะเร็ง) -> FNA ประเมิน cytology", "sys": "IV"}, {"topic": "Surgery", "q": "A woman with simple goiter has a growing neck mass; a thyroid nodule is found, asymptomatic, normal TFT. Most appropriate investigation?", "choices": ["Ultrasound", "FNA", "Thyroid scan", "CT neck", "Thyroid antibody"], "ans": 1, "exp": "nodule ที่โตขึ้น + TFT ปกติ -> FNA (หลัง/ร่วมกับ ultrasound characterization)", "sys": "IV"}, {"topic": "Surgery", "q": "A woman in her twenties with an asymptomatic thyroid nodule, normal TFT, eats seafood often. Most likely diagnosis?", "choices": ["Iodine deficiency", "Hashimoto thyroiditis", "Simple thyroid cyst", "Subacute thyroiditis", "Papillary carcinoma"], "ans": 2, "exp": "nodule ไม่มีอาการ + euthyroid + ได้ไอโอดีนพอ (กินอาหารทะเล) = simple thyroid cyst/colloid nodule", "sys": "II"}, {"topic": "Surgery", "q": "A 30-year-old woman with Graves disease, severe exophthalmos, and compressive symptoms when sleeping. Definitive treatment?", "choices": ["Iodine-131", "Lugol's solution", "High-dose antithyroid drugs", "Surgical thyroidectomy", "Radiofrequency ablation"], "ans": 3, "exp": "Graves ที่มี exophthalmos รุนแรง + อาการกดเบียด -> surgical thyroidectomy (I-131 อาจทำให้ ophthalmopathy แย่ลง และไม่แก้อาการกดเบียด)", "sys": "IV"}, {"topic": "Surgery", "q": "A 47-year-old for check-up; father was diagnosed with rectosigmoid cancer at age 55. Most proper cancer screening?", "choices": ["Stool occult blood test", "Serum CEA", "Barium enema", "Sigmoidoscopy", "Colonoscopy"], "ans": 4, "exp": "มีญาติสายตรงเป็นมะเร็งลำไส้ (<60 ปี) -> colonoscopy เริ่มเร็ว (อายุ 40 หรือ 10 ปีก่อนอายุที่ญาติเป็น)", "sys": "II"}, {"topic": "Surgery", "q": "A 47-year-old with a father diagnosed with colon cancer at age 55. Most appropriate screening test?", "choices": ["Colonoscopy", "Stool occult blood test", "Serum CEA", "Barium enema", "Sigmoidoscopy"], "ans": 0, "exp": "ญาติสายตรงเป็นมะเร็งลำไส้ก่อน 60 ปี -> คัดกรองด้วย colonoscopy", "sys": "II"}, {"topic": "Surgery", "q": "A 25-year-old woman with painful defecation and low-grade fever; she cannot sit well and cannot insert a finger into the anal sphincter due to pain. Diagnosis?", "choices": ["Proctalgia fugax", "Perianal/intersphincteric abscess", "Thrombosed external hemorrhoid", "Internal hemorrhoid", "Solitary rectal ulcer"], "ans": 1, "exp": "ปวดทวารมาก + ไข้ + ตรวจไม่ได้เพราะเจ็บ = perianal/intersphincteric abscess -> ผ่าระบายหนอง", "sys": "XI"}, {"topic": "Surgery", "q": "A 34-year-old woman with painful defecation and bright red blood, no improvement after 6 months of medication. PE: a longitudinal ulcer at the posterior midline of the anus with a hypertrophic anal papilla. Most appropriate management?", "choices": ["Warm sitz bath", "Biopsy", "Lateral internal sphincterotomy", "Botulinum A injection", "Anal dilation"], "ans": 2, "exp": "chronic anal fissure ที่ไม่ตอบสนองการรักษา conservative 6 เดือน -> lateral internal sphincterotomy", "sys": "XI"}, {"topic": "Surgery", "q": "A 30-year-old woman with bleeding per anus 5 days and a 1-year history of intermittent fresh blood after defecation. Proctoscope: venous dilatation with active bleeding above the dentate line. Most appropriate management?", "choices": ["Steroid suppository", "Hemorrhoidectomy", "Bulk-forming laxatives", "Rubber band ligation", "Gelfoam embolization"], "ans": 3, "exp": "internal hemorrhoid (เหนือ dentate line) ที่มีเลือดออก -> rubber band ligation", "sys": "XI"}, {"topic": "Surgery", "q": "A 1-month-old who passed meconium at 48 hours after birth presents with abdominal distension 1 week. PE: hyperactive bowel sounds, no guarding/rebound. Diagnosis?", "choices": ["Neurogenic bowel", "Anal stenosis", "Meconium ileus", "Intestinal atresia", "Hirschsprung disease"], "ans": 4, "exp": "ถ่ายขี้เทาช้า (>48 ชม.) + ท้องอืดเรื้อรัง = Hirschsprung disease (aganglionic megacolon)", "sys": "XVI"}, {"topic": "Surgery", "q": "An infant is born with an imperforate anus (anorectal malformation). Which investigation should be done to find associated anomalies? (ต้นฉบับมีตัวเลือกไม่ครบ ใส่เท่าที่มี)", "choices": ["Upper GI study", "CT brain", "Renal ultrasound"], "ans": 2, "exp": "imperforate anus สัมพันธ์กับ VACTERL -> ตรวจ renal ultrasound หาความผิดปกติทางไต/ทางเดินปัสสาวะ (+ echocardiogram, spine)", "sys": "XVII"}, {"topic": "Surgery", "q": "A 3-year-old boy put a 1-baht coin in his mouth; he is asymptomatic with a normal exam. Most appropriate initial management?", "choices": ["Reassure", "X-ray chest and abdomen", "Laxative", "NPO, admit, observe 24 hours", "EGD"], "ans": 1, "exp": "กลืนเหรียญ -> ถ่ายภาพรังสี chest/abdomen เพื่อระบุตำแหน่ง (หลอดอาหาร vs กระเพาะ) ก่อนวางแผน", "sys": "flex"}, {"topic": "Surgery", "q": "A 3-month-old with a scrotal mass since birth. PE: 2.5 cm scrotal enlargement, positive transillumination, negative silk sign, unpalpable right testis. Most appropriate management? (ต้นฉบับมีตัวเลือกไม่ครบ ใส่เท่าที่มี)", "choices": ["Incision and drainage", "Observe", "Hydrocelectomy"], "ans": 1, "exp": "hydrocele ในทารก (transillumination +) ส่วนใหญ่หายเองภายใน 1 ปี -> สังเกต (observe)", "sys": "II"}, {"topic": "Surgery", "q": "A 6-month-old boy with a hydrocele. Treatment? (ต้นฉบับมีตัวเลือกไม่ครบ ใส่เท่าที่มี)", "choices": ["Observe", "Hydrocelectomy"], "ans": 0, "exp": "hydrocele ในทารก <1-2 ปี -> สังเกต (มักหายเอง); ผ่าตัดถ้ายังอยู่หลังอายุ 1-2 ปี", "sys": "flex"}, {"topic": "Surgery", "q": "A 13-year-old with right testicular pain after playing tennis 4 hours ago. PE: stable, erythematous swollen right scrotum, transverse lie of the right testis, pain worse on testicular elevation. Most proper management?", "choices": ["NSAIDs", "Manual reduction", "Doppler ultrasound of the testis", "Antibiotics", "Surgical exploration of the scrotum"], "ans": 4, "exp": "testicular torsion (ปวดเฉียบพลัน + testis อยู่แนวขวาง + Prehn negative) -> surgical exploration ทันที (อย่ารอ imaging ถ้าอาการชัด, golden period 6 ชม.)", "sys": "I"}, {"topic": "Urology", "q": "A 52-year-old woman with frequent urine leakage on activity, coughing, and sneezing. PE: urethral hypermobility. Normal UA. Diagnosis?", "choices": ["Stress urinary incontinence", "Coital incontinence", "Mixed urinary incontinence", "Urgency incontinence", "Overflow incontinence"], "ans": 0, "exp": "ปัสสาวะเล็ดตอนไอ/จาม/ออกแรง + urethral hypermobility = stress urinary incontinence", "sys": "X"}, {"topic": "Urology", "q": "A 70-year-old man with frequency and difficulty urinating 2 years. PE: bilateral flank masses, suprapubic mass, enlarged smooth prostate. US: bilateral hydronephrosis. BUN 30, Cr 1.5. Most appropriate management?", "choices": ["Alpha antagonist", "TURP (surgery)", "5-alpha reductase inhibitor", "Alpha antagonist + 5-alpha reductase inhibitor", "Finasteride"], "ans": 1, "exp": "BPH ที่มีภาวะแทรกซ้อน (retention + bilateral hydronephrosis + ไตเสื่อม) = ข้อบ่งชี้ผ่าตัด -> TURP", "sys": "XIV"}, {"topic": "Surgery", "q": "A patient with a 20% TBSA superficial second-degree burn arrives 2 hours after injury. Per modified Brooke's formula, what is the approximate initial fluid rate? (assume ~60 kg)", "choices": ["200 mL/hr", "120 mL/hr", "150 mL/hr", "100 mL/hr", "250 mL/hr"], "ans": 2, "exp": "modified Brooke = 2 mL x kg x %TBSA/24 ชม., ให้ครึ่งแรกใน 8 ชม.แรก. เช่น 60 กก. x 20% x 2 = 2400 mL, ครึ่งแรก 1200 mL/8 ชม. ~150 mL/ชม. *ค่าขึ้นกับน้ำหนักตัว*", "sys": "XVIII"}, {"topic": "Surgery", "q": "A CT of the head is shown. Diagnosis?", "choices": ["Epidural hemorrhage", "Subarachnoid hemorrhage", "Intracerebral hemorrhage", "Subdural hemorrhage", "Intraventricular hemorrhage"], "ans": 3, "exp": "*จากภาพจริง* เลือดออก hyperdense รูปพระจันทร์เสี้ยว (crescent) เกาะตามผิวโค้งของกะโหลก ข้าม suture line + มี mass effect/midline shift = subdural hemorrhage. *ไม่ใช่ epidural เพราะ epidural เป็นรูป biconvex/lens ไม่ข้าม suture*", "img": "https://cdn.jsdelivr.net/gh/MercenzK/Web-quiz-images@main/NL2-2023-Sx-32.png", "sys": "II"}, {"topic": "Surgery", "q": "A 33-year-old woman with an itchy scar on the right shoulder after an infected, sutured wound that was later drained. PE: erythematous, widespread, raised, mildly tender scar. Most appropriate management?", "choices": ["Pressure garment", "Topical silicone gel", "Laser ablation", "Excision", "Intralesional steroid injection"], "ans": 4, "exp": "แผลเป็นนูนแดงคัน (hypertrophic scar/keloid) -> first-line intralesional corticosteroid injection (+/- silicone gel)", "sys": "XII"}, {"topic": "Surgery", "q": "A child with pneumonia on ceftriaxone 5 days has improved but still has fever. CXR: pleural effusion. Fluid WBC 1,500. Appropriate management? (ต้นฉบับมีตัวเลือกไม่ครบ ใส่เท่าที่มี)", "choices": ["Intercostal drainage", "Change antibiotics", "Decortication"], "ans": 0, "exp": "parapneumonic effusion ที่ยังมีไข้แม้ยาปฏิชีวนะเหมาะสม -> ระบายด้วย intercostal drainage (chest tube)", "sys": "X"}, {"topic": "Pediatrics", "q": "A term neonate delivered by vacuum extraction develops dyspnea 1 hour after birth. PE: PR 190, BP 40/30, weak pulse, pallor, a large bluish fluctuant mass across the midline of the scalp. Most appropriate initial management?", "choices": ["PPV", "NSS 10 mL/kg IV push over 15 min", "Ultrasound head", "Dopamine", "10% D/W 65 mL/kg/day"], "ans": 1, "exp": "subgaleal hemorrhage (ก้อนนุ่มข้าม midline) -> เสียเลือดมากจนช็อก -> ให้สารน้ำ NSS 10 mL/kg IV bolus แก้ hypovolemic shock", "sys": "XVI"}, {"topic": "Pediatrics", "q": "A term newborn delivered by C/S for respiratory distress with meconium-stained fluid. PE: central cyanosis, HR 80, poor tone (non-vigorous). Most appropriate initial management?", "choices": ["100% oxygen", "Intubation with meconium aspirator suction", "Positive pressure ventilation (PPV)", "Warm and tactile stimulation", "Chest compression"], "ans": 2, "exp": "non-vigorous + MSAF ตาม NRP ปัจจุบัน -> เริ่ม PPV (ไม่ทำ routine tracheal suction แล้ว) เพราะ HR<100 และหายใจไม่ดี", "sys": "XVI"}, {"topic": "Pediatrics", "q": "A newborn from a GA 32-week mother with no ANC and 24-hour PROM (inadequate antibiotics). BT 36.5, otherwise well. Besides CBC, what additional investigation?", "choices": ["CRP", "Hemoculture", "Hemoculture + urine culture", "Hemoculture, urine culture, lumbar puncture", "Hemoculture + CRP"], "ans": 3, "exp": "ทารกเสี่ยง sepsis สูง (preterm + PROM + no ANC) -> ส่ง full sepsis workup: hemoculture + urine culture + lumbar puncture (ร่วม CBC)", "sys": "XV"}, {"topic": "Pediatrics", "q": "A male newborn GA 37 weeks with jaundice 18 hours after birth. Microbilirubin 17, Hct 37. (phototherapy/exchange nomogram shown). Most appropriate treatment?", "choices": ["Partial exchange transfusion", "Total exchange transfusion", "Reassure", "IVIG", "Phototherapy"], "ans": 4, "exp": "ตัวเหลืองเริ่มเร็ว (<24 ชม.) + bilirubin 17 -> เกินเส้น phototherapy -> intensive phototherapy (เตรียม exchange ถ้าสูงถึงเส้น). *อ้างอิงกราฟ*", "img": "https://cdn.jsdelivr.net/gh/MercenzK/Web-quiz-images@main/NL2-2023-Ped-Q4.png", "sys": "XVI"}, {"topic": "Pediatrics", "q": "A newborn with low birth weight, low APGAR, and jaundice requiring phototherapy. Which factor indicates the need for a hearing screen?", "choices": ["Hyperbilirubinemia (microbilirubin)", "Low APGAR", "Low birth weight", "Phototherapy", "Maternal fever"], "ans": 0, "exp": "ภาวะ hyperbilirubinemia (เสี่ยง kernicterus) เป็นปัจจัยเสี่ยงสำคัญต่อการสูญเสียการได้ยิน (ร่วมกับ low BW, low APGAR, NICU) -> ควรคัดกรองการได้ยิน", "sys": "XVI"}, {"topic": "Pediatrics", "q": "A 2-day-old with mild jaundice. Mother O Rh+, baby A. CBC normal, microbilirubin 18, DAT weakly positive, PBS polychromasia. Cause?", "choices": ["Thalassemia", "ABO incompatibility", "G6PD deficiency", "Breastfeeding jaundice", "Breast milk jaundice"], "ans": 1, "exp": "แม่กรุ๊ป O ลูกกรุ๊ป A + DAT บวก + polychromasia (hemolysis) = ABO incompatibility", "sys": "III"}, {"topic": "Pediatrics", "q": "A 2,100 g infant (no ANC). PE: HC 27 cm, clouded lens (cataract), SEM grade III at LUSB (PDA), hepatosplenomegaly. Most likely diagnosis?", "choices": ["Congenital CMV", "Congenital syphilis", "Congenital rubella", "Congenital toxoplasmosis", "Congenital Zika"], "ans": 2, "exp": "IUGR + cataract + PDA + hepatosplenomegaly = congenital rubella syndrome (classic triad: cataract, cardiac defect, deafness)", "sys": "XVII"}, {"topic": "Pediatrics", "q": "A newborn with parental Hb studies and a PBS showing a thalassemia picture. Most appropriate investigation? (ต้นฉบับมีตัวเลือกไม่ครบ ใส่เท่าที่มี)", "choices": ["Osmotic fragility test", "Direct Coombs test", "Hb typing"], "ans": 2, "exp": "สงสัย thalassemia -> ตรวจ Hb typing เพื่อวินิจฉัยชนิด", "sys": "XVI"}, {"topic": "Pediatrics", "q": "A child with upslanting eyes and a single palmar crease. Diagnosis? (ต้นฉบับมีตัวเลือกไม่ครบ ใส่เท่าที่มี)", "choices": ["Down syndrome", "Trisomy 13", "Trisomy 18"], "ans": 0, "exp": "upslanting palpebral fissures + single palmar crease = Down syndrome (trisomy 21)", "sys": "XVII"}, {"topic": "Pediatrics", "q": "An infant eats a lot then vomits; the mother feeds every 2 hours. Cause? (ต้นฉบับมีตัวเลือกไม่ครบ ใส่เท่าที่มี)", "choices": ["Achalasia", "Hypertrophic pyloric stenosis", "Tracheoesophageal fistula", "Overfeeding"], "ans": 3, "exp": "ให้นมถี่เกินไป (ทุก 2 ชม.) แล้วอาเจียน = overfeeding (regurgitation จากให้นมมากเกิน)", "sys": "XVII"}, {"topic": "Pediatrics", "q": "A 3-year-old with nephrotic syndrome: BP 80/50, PR 100, clinical heart failure, ascites, albumin 1.2. Initial management? (ต้นฉบับมีตัวเลือกไม่ครบ ใส่เท่าที่มี)", "choices": ["Furosemide", "Dobutamine", "20% albumin (then furosemide)"], "ans": 2, "exp": "nephrotic + hypovolemia (ความดันตก, albumin ต่ำมาก) -> ให้ 20% albumin เพิ่ม intravascular volume + oncotic แล้วตามด้วย furosemide", "sys": "IX"}, {"topic": "Pediatrics", "q": "A boy with rheumatic heart disease presents with fever, rash, and a pansystolic murmur. Most serious complication? (ต้นฉบับมีตัวเลือกไม่ครบ ใส่เท่าที่มี)", "choices": ["Heart failure", "Sepsis", "Mitral valve prolapse"], "ans": 0, "exp": "rheumatic carditis (mitral regurgitation) -> ภาวะแทรกซ้อนร้ายแรงสุดคือ heart failure", "sys": "I"}, {"topic": "Pediatrics", "q": "A 4-year-old with cough and dyspnea after playing with toys. Most appropriate management? (ต้นฉบับมีตัวเลือกไม่ครบ ใส่เท่าที่มี)", "choices": ["Heimlich maneuver", "Chest X-ray", "CT abdomen"], "ans": 1, "exp": "สงสัยสำลักสิ่งแปลกปลอมแต่ยังไอ/หายใจได้ (partial) -> ถ่าย chest X-ray หา FB/air trapping (Heimlich ใช้เมื่ออุดกั้นสมบูรณ์ ไอไม่ออก)", "sys": "X"}, {"topic": "Pediatrics", "q": "A 4-year-old boy with sudden dyspnea without fever 6 hours ago. PE: RR 40, SpO2 92, irritable, decreased breath sound at the left lung. CXR shown. Most likely diagnosis?", "choices": ["Pneumothorax", "Aspiration pneumonia", "Massive pleural effusion", "Large mediastinal tumor", "Foreign body aspiration"], "ans": 4, "exp": "หายใจเหนื่อยเฉียบพลันไม่มีไข้ + เสียงหายใจข้างซ้ายลด + CXR (air trapping/hyperinflation ข้างเดียว) = foreign body aspiration. *อ้างอิงภาพ*", "img": "https://cdn.jsdelivr.net/gh/MercenzK/Web-quiz-images@main/NL2-2023-Ped-Q14.png", "sys": "II"}, {"topic": "Pediatrics", "q": "A 4-month-old with noisy breathing 1 month, improving supine, with inspiratory stridor and suprasternal retraction. Diagnosis?", "choices": ["Laryngomalacia", "Viral croup", "Vascular ring", "Vocal cord paralysis", "Subglottic hemangioma"], "ans": 0, "exp": "stridor หายใจเข้าเรื้อรังตั้งแต่เล็ก + สัมพันธ์ท่าทาง = laryngomalacia (สาเหตุ stridor เรื้อรังที่พบบ่อยสุดในทารก)", "sys": "X"}, {"topic": "Pediatrics", "q": "A 7-year-old with severe productive cough 3 days and prior runny nose 1 week. PE: BT 37, normal turbinates, no wheezing, coarse crepitations both lungs. Most likely diagnosis?", "choices": ["Asthma", "Acute bronchitis", "Pneumonia", "Acute sinusitis", "Acute bronchiolitis"], "ans": 1, "exp": "ไอมีเสมหะหลัง URI + coarse crepitation 2 ข้างโดยไม่มีไข้/consolidation เฉพาะที่ = acute bronchitis", "sys": "X"}, {"topic": "Pediatrics", "q": "A 5-year-old boy with watery rhinorrhea and bilateral inferior turbinate swelling. Most proper management?", "choices": ["Inhaled corticosteroid", "Oral prednisolone", "Intranasal corticosteroid", "Salbutamol nebulizer", "Oral antihistamine"], "ans": 2, "exp": "allergic rhinitis -> intranasal corticosteroid เป็นยาที่ได้ผลดีสุด", "sys": "X"}, {"topic": "Pediatrics", "q": "A 15-month-old with noisy breathing today, preceded by runny nose, cough, low-grade fever 2 days. PE: BT 38, RR 50, suprasternal retraction, brassy (barking) cough, inspiratory stridor, rhonchi both lungs. Most appropriate initial management?", "choices": ["Ceftriaxone", "Oral prednisone", "Nebulized salbutamol", "Nebulized epinephrine", "Nebulized hypertonic saline"], "ans": 3, "exp": "croup ที่มี stridor ขณะพัก + retraction (moderate-severe) -> nebulized (racemic) epinephrine + dexamethasone", "sys": "X"}, {"topic": "Pediatrics", "q": "A child with URI not improved after 4 days of amoxicillin. CXR: LUL interstitial infiltration, mild injected pharynx. Which drug? (ต้นฉบับมีตัวเลือกไม่ครบ ใส่เท่าที่มี)", "choices": ["Augmentin", "Azithromycin", "Ceftriaxone"], "ans": 1, "exp": "ปอดอักเสบ interstitial ไม่ตอบสนอง amoxicillin = atypical (Mycoplasma) -> azithromycin (macrolide)", "sys": "flex"}, {"topic": "Pediatrics", "q": "A 3-year-old with abdominal distension 3 days, passed meconium within 24 hours, well feeding, stool 1-2 times/week. PE: stable, irritable, distension, a 3 cm mass at LLQ. Most appropriate next step?", "choices": ["Rectal examination", "Stool examination", "Acute abdomen series", "Ultrasound abdomen", "Oral simethicone"], "ans": 0, "exp": "ท้องผูก + ก้อนอุจจาระที่ LLQ -> ตรวจ rectal examination ประเมิน tone/impaction (functional constipation)", "sys": "general"}, {"topic": "Pediatrics", "q": "A 2-year-old with hard defecation 4 months, defecates less frequently and cries; mother unsure of meconium history. PE: ill-defined 3 cm mass at LLQ, anal fissure. Diagnosis?", "choices": ["Physiologic dyschezia", "Fecal impaction (functional constipation)", "Hirschsprung disease", "Anal stenosis", "Hypothyroidism"], "ans": 1, "exp": "ท้องผูกเรื้อรัง + ก้อนอุจจาระ + anal fissure = functional constipation with fecal impaction", "sys": "XVI"}, {"topic": "Pediatrics", "q": "A child with RUQ pain, jaundice, and hepatomegaly; classmates have the same symptoms. Most proper investigation?", "choices": ["Stool culture for parasites", "Entamoeba histolytica antibody titer", "Hepatitis A serology (anti-HAV)", "Anti-HBs", "Anti-HCV"], "ans": 2, "exp": "ตับอักเสบเป็นกลุ่ม (fecal-oral outbreak) = hepatitis A -> ตรวจ anti-HAV (IgM สำหรับการติดเชื้อเฉียบพลัน)", "sys": "I"}, {"topic": "Pediatrics", "q": "A 4-year-old with a 5-minute GTC seizure; 30 minutes later at the hospital develops another seizure. Most appropriate initial management?", "choices": ["IV phenytoin", "IV phenobarbital", "IM phenobarbital", "Diazepam (benzodiazepine)", "IV valproate"], "ans": 3, "exp": "ชักซ้ำ/ต่อเนื่อง -> ยาลำดับแรกคือ benzodiazepine (diazepam IV/rectal); phenytoin/phenobarbital เป็น second-line", "sys": "VI"}, {"topic": "Pediatrics", "q": "A 13-year-old with a 30-minute GTC seizure, headache and edema 3 days. BP 160/100, drowsy, crepitations, leg edema, puffy eyelids. Cr 1.5, RBC 50-100 in urine. Aside from furosemide, most proper management?", "choices": ["3% NaCl IV", "Phenytoin IV", "7.5% NaHCO3 IV", "10% calcium gluconate IV", "Nicardipine IV"], "ans": 4, "exp": "acute glomerulonephritis + hypertensive encephalopathy (ชัก + BP สูง) -> ควบคุมความดันด้วย IV nicardipine (นอกจาก furosemide)", "sys": "VI"}, {"topic": "Pediatrics", "q": "A 1-year-old with recurrent cyanosis and increased muscle tone for 2-3 seconds after crying; the child can walk and say some words. PE: no cyanosis, normal heart, no murmur. Most proper management?", "choices": ["Reassure", "EEG", "Chest X-ray", "Serum calcium", "Echocardiography"], "ans": 0, "exp": "เขียว/เกร็งสั้น ๆ หลังร้องไห้แล้วหายเอง ในเด็กที่ปกติ = breath-holding spell -> reassure", "sys": "IX"}, {"topic": "Pediatrics", "q": "A 6-month-old with altered consciousness and fever. PE: BT 39, Brudzinski positive. CSF: OP 210, WBC PMN 75%, protein 120. Most appropriate management?", "choices": ["Acyclovir", "Cefotaxime", "Anti-TB", "Ampicillin", "Amphotericin B"], "ans": 1, "exp": "bacterial meningitis ในเด็ก 6 เดือน (PMN เด่น, protein สูง) -> cefotaxime (3rd-gen cephalosporin) +/- vancomycin", "sys": "VI"}, {"topic": "Pediatrics", "q": "A 4-year-old girl with a GTC seizure recurs at the ER with unconsciousness. Initial management? (ต้นฉบับมีตัวเลือกไม่ครบ ใส่เท่าที่มี)", "choices": ["Diazepam (benzodiazepine)", "Endotracheal intubation"], "ans": 0, "exp": "ชักซ้ำ -> ให้ benzodiazepine (diazepam) เป็นลำดับแรก (ETT เมื่อ airway ไม่ปลอดภัย/ชักไม่หยุด)", "sys": "VI"}, {"topic": "Pediatrics", "q": "A 13-year-old with red urine 1 day and acute pharyngitis 3 days ago. No edema. UA: blood 4+, RBC >100, C3 normal (1.0). Most likely diagnosis?", "choices": ["IgA vasculitis", "Henoch-Schonlein purpura", "Membranoproliferative GN", "IgA nephropathy", "Acute post-streptococcal GN"], "ans": 3, "exp": "hematuria เกิด 'ไม่กี่วัน' หลังเจ็บคอ (synpharyngitic) + C3 'ปกติ' = IgA nephropathy (PSGN จะเกิด 1-3 สัปดาห์ + C3 ต่ำ)", "sys": "III"}, {"topic": "Pediatrics", "q": "A 4-year-old with edema, puffy eyes, BP 150/100, no fever. Na 130, K 5. UA: protein 3+, RBC 50-100. Aside from furosemide, what else? (ต้นฉบับมีตัวเลือกไม่ครบ ใส่เท่าที่มี)", "choices": ["Albumin", "10% calcium gluconate", "Nicardipine", "3% NaCl"], "ans": 2, "exp": "acute nephritic syndrome + ความดันสูง -> ควบคุมความดันด้วย nicardipine (นอกจาก furosemide)", "sys": "XIV"}, {"topic": "Pediatrics", "q": "A 3-year-old girl with abdominal distension 2 weeks. PE: 8x8 cm firm RUQ mass, BP 130/80. Hct 33%, UA: RBC 30-50. Most likely diagnosis?", "choices": ["Wilms tumor", "Neuroblastoma", "Hepatoblastoma", "Burkitt lymphoma", "Pheochromocytoma"], "ans": 0, "exp": "ก้อนในท้องเด็ก + hematuria (RBC ในปัสสาวะ) + ความดันสูง = Wilms tumor (nephroblastoma)", "sys": "II"}, {"topic": "Pediatrics", "q": "A 6-year-old with a honey-crusted skin infection above the mouth, then hematuria. Most proper investigation? (ต้นฉบับมีตัวเลือกไม่ครบ ใส่เท่าที่มี)", "choices": ["ASO titer", "Anti-DNase B", "Anti-dsDNA"], "ans": 1, "exp": "post-streptococcal GN หลังการติดเชื้อที่ 'ผิวหนัง' (impetigo/honey crust) -> anti-DNase B ไวกว่า ASO ในการติดเชื้อผิวหนัง", "sys": "XII"}, {"topic": "Pediatrics", "q": "A 12-year-old girl with generalized thyroid enlargement 6 months, eats seafood. PE: diffuse non-tender thyroid 30 g, no nodule, no exophthalmos. FT4 1.1, TSH 12, anti-TPO and anti-thyroglobulin negative. Most likely diagnosis?", "choices": ["Simple goiter", "Graves disease", "Hashimoto thyroiditis", "Iodine deficiency", "Subacute thyroiditis"], "ans": 2, "exp": "คอพอก + TSH สูง (hypothyroid) ในเด็ก -> Hashimoto (chronic lymphocytic) thyroiditis เป็นสาเหตุที่พบบ่อยสุด (แม้ antibody อาจลบในบางราย)", "sys": "IV"}, {"topic": "Pediatrics", "q": "A 6-month-old with generalized edema, fed diluted condensed milk since birth. PE: round face, apathy, pitting edema, thin hair, dry peeling skin with hyperkeratosis. Most likely diagnosis?", "choices": ["Lymphedema", "Chronic renal failure", "Nephrotic syndrome", "Kwashiorkor", "Heart failure"], "ans": 3, "exp": "ขาดโปรตีน (นมข้นหวานเจือจาง) + บวม + ผมบาง + ผิวลอก + apathy = kwashiorkor (protein-energy malnutrition แบบบวม)", "sys": "IV"}, {"topic": "Pediatrics", "q": "A 2-year-old in a daycare with vesicles on the hands, feet, and oral mucosa; no other children affected. Most effective method to prevent spread in the nursery?", "choices": ["Immunization", "Alcohol hand sanitizer", "Close the nursery for 1 week", "Face masks for children and caretakers", "Frequent hand washing"], "ans": 4, "exp": "hand-foot-mouth disease (enterovirus) แพร่ทาง fecal-oral/contact -> ล้างมือบ่อย ๆ (frequent hand washing) ป้องกันได้ดีสุด (แอลกอฮอล์ฆ่า enterovirus ได้ไม่ดี)", "sys": "I"}, {"topic": "Pediatrics", "q": "A 4-year-old boy with high-grade fever, drooling, and dysphagia, preferring to sit with an extended neck. PE: BT 40, stridor, suprasternal retraction. Causative organism?", "choices": ["Haemophilus influenzae", "Moraxella catarrhalis", "Streptococcus pneumoniae", "Staphylococcus aureus", "Mycoplasma pneumoniae"], "ans": 0, "exp": "acute epiglottitis (ไข้สูง + น้ำลายไหล + นั่งคอยื่น + stridor) -> เชื้อคลาสสิกคือ Haemophilus influenzae type b", "sys": "I"}, {"topic": "Pediatrics", "q": "A 1-year-old with dyspnea and drooling, preferring to sit with the arm extended back. BP 160/90, BT 40, suprasternal retraction and wheezing. Causative agent?", "choices": ["Moraxella catarrhalis", "Haemophilus influenzae type B", "Staphylococcus aureus", "Streptococcus pyogenes", "Mycoplasma pneumoniae"], "ans": 1, "exp": "epiglottitis (น้ำลายไหล + นั่งคอยื่น + stridor) -> Haemophilus influenzae type b", "sys": "I"}, {"topic": "Pediatrics", "q": "A 7-year-old with high-grade fever 1 day and a leg wound from a bicycle accident 5 days ago. PE: ill, dyspneic, fine crepitations both lower lungs, redness around the wound. CXR: scattered nodular infiltration. Most likely causative organism?", "choices": ["Moraxella catarrhalis", "Mycoplasma pneumoniae", "Staphylococcus aureus", "Streptococcus pyogenes", "Haemophilus influenzae type B"], "ans": 2, "exp": "แผลผิวหนังติดเชื้อ -> septic emboli ไปปอด เกิด nodular infiltration = Staphylococcus aureus (hematogenous staph pneumonia)", "sys": "I"}, {"topic": "Pediatrics", "q": "A 10-year-old with fever, nasal obstruction, and otalgia 4 days. PE: swollen turbinates, posterior nasal discharge, injected tonsils 3+, an erythematous bulging left tympanic membrane. Most appropriate management?", "choices": ["Azithromycin", "Dicloxacillin", "Ceftriaxone", "Amoxicillin", "Cefdinir"], "ans": 3, "exp": "acute otitis media (แก้วหูแดงโป่ง) -> first-line high-dose amoxicillin", "sys": "III"}, {"topic": "Pediatrics", "q": "A 7-year-old with high-grade fever and a leg wound 5 days ago; ill and dyspneic, crepitations both lungs, CXR patchy infiltration. Most appropriate antibiotic?", "choices": ["Ceftazidime", "Vancomycin", "Ciprofloxacin", "Trimethoprim/sulfamethoxazole", "Cloxacillin"], "ans": 4, "exp": "staph pneumonia จากแผลผิวหนัง (community MSSA) -> cloxacillin (ถ้าสงสัย MRSA จึงใช้ vancomycin)", "sys": "X"}, {"topic": "Pediatrics", "q": "A 15-year-old with HIV presents with left otorrhea, otalgia, eardrum perforation, right hemiparesis, and right facial weakness (motor grade III). Diagnosis?", "choices": ["Brain abscess", "Toxoplasmosis", "Cysticercosis", "Tuberculoma", "Lymphoma"], "ans": 0, "exp": "หูน้ำหนวก (otogenic source) + focal deficit = brain abscess จากการลุกลามของหูชั้นกลางอักเสบ", "sys": "II"}, {"topic": "Pediatrics", "q": "A 5-year-old with altered consciousness 1 day, high fever and sore throat 3 days. PE: shallow ulcers at the anterior pillars and soft palate, vesicles on the palms and soles, hyperreflexia. Causative organism?", "choices": ["Coxsackievirus B", "Enterovirus 71", "Parvovirus B19", "Herpes simplex virus", "Varicella-zoster virus"], "ans": 1, "exp": "hand-foot-mouth disease ที่มีอาการทางระบบประสาท (encephalitis, hyperreflexia) = enterovirus 71 (รุนแรงกว่า coxsackie)", "sys": "I"}, {"topic": "Pediatrics", "q": "A 5-year-old with abdominal pain 2 days, preceded by rash and joint pain without fever for 1 week. PE: stable, palpable purpura on legs and feet (shown). Most serious complication?", "choices": ["Anemia", "Carditis", "Kidney damage (HSP nephritis)", "GI hemorrhage", "Intracerebral hemorrhage"], "ans": 2, "exp": "HSP (IgA vasculitis) -> ภาวะแทรกซ้อนที่กำหนดพยากรณ์โรคระยะยาวคือ renal involvement (HSP nephritis). *ภาวะเฉียบพลันที่ต้องระวังคือ GI hemorrhage/intussusception*", "img": "https://cdn.jsdelivr.net/gh/MercenzK/Web-quiz-images@main/NL2-2023-Ped-Q42.png", "sys": "III"}, {"topic": "Pediatrics", "q": "A child with fever and petechiae on both legs (meningococcemia). Complication to watch for?", "choices": ["Anemia", "GI bleeding", "Intracranial hemorrhage", "Adrenal insufficiency (Waterhouse-Friderichsen)", "Renal failure"], "ans": 3, "exp": "meningococcemia -> เลือดออกที่ต่อมหมวกไต 2 ข้าง (Waterhouse-Friderichsen) -> adrenal insufficiency/ช็อก", "sys": "III"}, {"topic": "Pediatrics", "q": "A patient with meningococcemia. What is the prevention for family members?", "choices": ["Throat swab", "Nasopharyngeal swab", "Azithromycin", "Ofloxacin", "Rifampicin"], "ans": 4, "exp": "chemoprophylaxis ผู้สัมผัสใกล้ชิด meningococcus = rifampicin (หรือ ceftriaxone/ciprofloxacin)", "sys": "flex"}, {"topic": "Pediatrics", "q": "A 9-month-old with fever and rash, no prior medication. PE: erythroderma with scaly erythematous patches and desquamation around the eyes, nose, mouth, and genitals. Most likely diagnosis?", "choices": ["Staphylococcal scalded skin syndrome (SSSS)", "Impetigo", "Scarlet fever", "Kawasaki disease", "Toxic epidermal necrolysis"], "ans": 0, "exp": "erythroderma + ลอกรอบรูเปิด (perioral/periorificial) + ไม่มี mucosal involvement = SSSS (จาก exfoliative toxin ของ S. aureus)", "sys": "I"}, {"topic": "Pediatrics", "q": "A 1-month-old with small, clear, dew-drop, flaccid vesicles on the forehead, neck, upper trunk, and occluded areas. BT 37. Most appropriate management?", "choices": ["Emollient", "Reassure (cool environment)", "Topical mupirocin", "Topical steroid", "Topical antifungal"], "ans": 1, "exp": "ตุ่มน้ำใสเล็ก ๆ ในบริเวณอับชื้น = miliaria crystallina (ผดร้อน) -> หายเองเมื่อลดความร้อน/ความอับ -> reassure", "sys": "XII"}, {"topic": "Pediatrics", "q": "A child with itching in the interdigital spaces; the father has the same. Most appropriate management?", "choices": ["Mupirocin ointment", "Topical steroid", "Benzyl benzoate (or permethrin)", "Topical antibiotic", "Topical antifungal"], "ans": 2, "exp": "คันตามง่ามนิ้ว + คนในบ้านเป็นด้วย = scabies -> ยาฆ่าไร benzyl benzoate หรือ permethrin (รักษาทุกคนในบ้าน)", "sys": "XII"}, {"topic": "Pediatrics", "q": "A 10-year-old with a facial skin lesion 3 days. PE: honey-crusted lesion surrounded by erythema on the nose and upper lip. Most appropriate management?", "choices": ["Wet dressing with NSS", "Acyclovir cream", "Clotrimazole cream", "Mupirocin ointment", "Mometasone cream"], "ans": 3, "exp": "honey-crusted lesion = impetigo (Staph/Strep) -> topical mupirocin (รอยโรคเฉพาะที่)", "sys": "XII"}, {"topic": "Pediatrics", "q": "A 1-month-old with a slowly progressive solitary scalp mass noticed since birth (image shown), otherwise unremarkable. Most appropriate management?", "choices": ["Propranolol", "Intralesional steroid", "Laser therapy", "Surgical removal", "Reassure/observe"], "ans": 4, "exp": "รอยโรคที่พบตั้งแต่แรกเกิดและค่อย ๆ โต ถ้าเป็น infantile hemangioma ที่ไม่มีภาวะแทรกซ้อน -> สังเกต (ส่วนใหญ่ยุบเอง); propranolol ใช้เมื่อโตเร็ว/มีภาวะแทรกซ้อน. *คำตอบขึ้นกับภาพจริง*", "img": "https://cdn.jsdelivr.net/gh/MercenzK/Web-quiz-images@main/NL2-2023-Ped-Q49.png", "sys": "II"}, {"topic": "Pediatrics", "q": "A 15-year-old with neck and groin masses 3 months, night fever, and weight loss. PE: multiple painless 2-4 cm cervical and groin lymph nodes. Hb 11.5, WBC 12,000, platelets 250,000. Most useful investigation for diagnosis?", "choices": ["Lymph node biopsy", "Chest X-ray", "CT head and neck", "Gastric wash for AFB", "Bone marrow study"], "ans": 0, "exp": "ต่อมน้ำเหลืองโตหลายตำแหน่ง ไม่เจ็บ + B symptoms (ไข้กลางคืน น้ำหนักลด) = lymphoma -> excisional lymph node biopsy เพื่อวินิจฉัย", "sys": "II"}, {"topic": "Pediatrics", "q": "A 2-year-old with fever and fatigue and a history of neonatal jaundice treated with phototherapy. PE: hepatosplenomegaly, moderate pallor, mild jaundice. Hb 7, Hct 21. Most useful investigation?", "choices": ["Mycoplasma titer", "Hb typing", "LFT", "Red cell flow cytometry", "Direct antiglobulin test"], "ans": 1, "exp": "เม็ดเลือดแดงแตกเรื้อรังตั้งแต่แรกเกิด (neonatal jaundice) + ตับม้ามโต + ซีด = thalassemia -> ตรวจ Hb typing", "sys": "XVI"}, {"topic": "Pediatrics", "q": "A 2-year-old with abdominal pain and watery then bloody diarrhea. Hct low, platelets 50,000, PBS MAHA (schistocytes). BUN 35, Cr 3, K 5.5. Diagnosis?", "choices": ["ITP", "TTP", "HUS", "DIC", "Dengue"], "ans": 2, "exp": "ถ่ายเป็นเลือด + MAHA (schistocyte) + เกล็ดเลือดต่ำ + ไตวาย = hemolytic uremic syndrome (HUS)", "sys": "I"}, {"topic": "Pediatrics", "q": "A child with fever, then pallor and dark urine with many RBCs in urine. PBS: Hb-leakage (bite) cells (shown). Diagnosis?", "choices": ["Thalassemia disease", "Autoimmune hemolytic anemia", "DIC", "G6PD deficiency", "Paroxysmal nocturnal hemoglobinuria"], "ans": 3, "exp": "เม็ดเลือดแดงแตกเฉียบพลันหลังไข้ + bite cell/blister cell (Hb leakage) = G6PD deficiency. *อ้างอิงภาพ PBS*", "img": "https://cdn.jsdelivr.net/gh/MercenzK/Web-quiz-images@main/NL2-2023-Ped-Q53.png", "sys": "III"}, {"topic": "Pediatrics", "q": "A previously healthy 3-year-old with pallor and dark urine, fever and sore throat 3 days, no family history of anemia. Hb 7, MCV 85, dark urine blood 4+. PBS: Hb-leakage (bite) cells. Most useful investigation?", "choices": ["Urinalysis", "Osmotic fragility test", "Direct antiglobulin test", "Bone marrow aspiration", "Supravital stain (Heinz bodies)"], "ans": 4, "exp": "acute hemolysis จากไข้ + bite cell = G6PD deficiency -> supravital stain เห็น Heinz bodies (G6PD assay อาจ falsely normal ช่วง acute เพราะ reticulocyte สูง)", "sys": "III"}, {"topic": "Pediatrics", "q": "A 3-month-old with a URI and dark urine 2 days. PE: BT 38, anicteric, hepatomegaly. Hb 7, MCV 85, platelets normal. Which investigation helps diagnosis?", "choices": ["Supravital stain (Heinz bodies)", "Urinalysis", "Osmotic fragility test", "Direct antiglobulin test", "Bone marrow aspiration"], "ans": 0, "exp": "เม็ดเลือดแดงแตกเฉียบพลันถูกกระตุ้นด้วยการติดเชื้อ (normocytic) = G6PD deficiency -> supravital stain หา Heinz bodies", "sys": "III"}, {"topic": "Pediatrics", "q": "A 5-year-old boy with frequent brief staring spells for 1 month; unresponsive when the teacher calls, with declining school performance. Diagnosis?", "choices": ["Daydreaming", "Absence seizure", "Complex partial seizure", "Delayed development", "ADHD"], "ans": 1, "exp": "จ้องเหม่อสั้น ๆ บ่อย ๆ ไม่ตอบสนอง + การเรียนแย่ลง = absence seizure (childhood absence epilepsy)", "sys": "V"}, {"topic": "Pediatrics", "q": "A 10-year-old with behavioral problems 2 years; he hums and coughs throughout the day and can control it sometimes. Diagnosis?", "choices": ["Epilepsy", "Malingering", "Tic disorder (vocal tic)", "Tourette syndrome", "Attention deficit disorder"], "ans": 2, "exp": "เสียงผิดปกติ (ฮัม/ไอ) ที่กดข่มได้ชั่วคราว โดยไม่มี motor tic = vocal tic disorder. Tourette ต้องมีทั้ง motor และ vocal tics >1 ปี", "sys": "VI"}, {"topic": "Obstetrics & Gynecology", "q": "A 12-week pregnant woman with vaginal bleeding. VE: os closed. TVS: fetus present without heart sound. Diagnosis?", "choices": ["Inevitable abortion", "Incomplete abortion", "Complete abortion", "Missed abortion", "Threatened abortion"], "ans": 3, "exp": "ปากมดลูก 'ปิด' + ตัวอ่อนไม่มีหัวใจเต้น = missed abortion (แท้งค้าง)", "sys": "XV"}, {"topic": "Obstetrics & Gynecology", "q": "A 32-year-old primigravida received rubella vaccination 2 weeks ago, then found she is pregnant (GA 8 weeks). Most appropriate management?", "choices": ["Maternal rubella IgG", "Cordocentesis for rubella IgM", "Amniocentesis for rubella PCR", "Termination of pregnancy", "Reassurance"], "ans": 4, "exp": "ได้วัคซีน rubella (live) ช่วงต้นครรภ์โดยไม่รู้ว่าตั้งครรภ์ -> ความเสี่ยง CRS ในทางทฤษฎีต่ำมาก ไม่มีรายงานจริง -> reassurance (ไม่ใช่ข้อบ่งชี้ยุติครรภ์)", "sys": "XV"}, {"topic": "Obstetrics & Gynecology", "q": "A 32-year-old primigravida GA 12 weeks with severe nausea and vomiting, no bleeding/pain. PE: fundal height 2/3 above the pubic symphysis (larger than dates). Most proper investigation?", "choices": ["Transabdominal ultrasonography", "Serum beta-hCG", "75 g OGTT", "Serum electrolytes", "Thyroid function test"], "ans": 0, "exp": "มดลูกโตกว่าอายุครรภ์ + แพ้ท้องรุนแรง -> สงสัย molar pregnancy/multiple -> ultrasound เพื่อวินิจฉัย", "sys": "XV"}, {"topic": "Obstetrics & Gynecology", "q": "A 20-year-old GA 12 weeks with severe nausea/vomiting and vaginal bleeding; clomiphene was used. PE: fundal height 2/3 above the pubic symphysis. Most beneficial investigation?", "choices": ["Serum beta-hCG", "Transabdominal ultrasound", "Serum electrolytes", "Thyroid function test", "75 g OGTT"], "ans": 1, "exp": "มดลูกโตกว่าอายุครรภ์ + เลือดออก + แพ้ท้องรุนแรง (+ clomiphene = เสี่ยงครรภ์แฝด/molar) -> ultrasound เพื่อวินิจฉัย", "sys": "IV"}, {"topic": "Obstetrics & Gynecology", "q": "A 32-year-old G2P1 GA 12 weeks; previous baby weighed 4,700 g. 50 g GCT is 130 mg/dL. Most appropriate management?", "choices": ["Monitor 2-hr postprandial blood sugar", "HbA1c at GA 24 weeks", "Repeat 50 g GCT at GA 28 weeks", "100 g OGTT now", "Start insulin"], "ans": 2, "exp": "ประวัติ macrosomia = เสี่ยง GDM แต่ 50 g GCT ตอนนี้ 130 (<140 = ลบ) -> คัดกรองซ้ำด้วย 50 g GCT ที่ GA 24-28 สัปดาห์", "sys": "XV"}, {"topic": "Obstetrics & Gynecology", "q": "An 18-year-old GA 23 weeks, normal exam, UA trace glucosuria. Most proper management? (ต้นฉบับมีตัวเลือกไม่ครบ ใส่เท่าที่มี)", "choices": ["50 g GCT", "Reassure"], "ans": 0, "exp": "คัดกรอง GDM ตามปกติที่ GA 24-28 สัปดาห์ด้วย 50 g GCT (trace glucosuria อย่างเดียวไม่วินิจฉัย)", "sys": "flex"}, {"topic": "Obstetrics & Gynecology", "q": "A 30-year-old G1P0 GA 23 weeks; felt quickening 4 weeks ago. PE: fundal height 23 cm, no detectable fetal movement or heart sound. Most appropriate management?", "choices": ["Reassurance", "Fetal movement counting", "Vibroacoustic stimulation", "Return appointment in 1 week", "Transabdominal ultrasound"], "ans": 4, "exp": "ไม่พบการเคลื่อนไหว/เสียงหัวใจทารก -> ต้อง ultrasound ยืนยันภาวะทารกเสียชีวิต/มีชีวิต ทันที", "sys": "flex"}, {"topic": "Obstetrics & Gynecology", "q": "A 25-year-old GA 29 weeks with PROM 4 hours ago, no contractions. Os closed, single viable fetus, FHR 140, DVP 3 cm. Apart from corticosteroids, what management?", "choices": ["Antibiotics for latency", "MgSO4 for neuroprotection", "Tocolytic", "Oxytocin", "Emergency C/S"], "ans": 0, "exp": "PPROM ที่ preterm (29 สัปดาห์) ไม่มี contraction -> ให้ latency antibiotics + corticosteroid (+ MgSO4 neuroprotection ถ้า <32 สัปดาห์)", "sys": "XV"}, {"topic": "Obstetrics & Gynecology", "q": "Normal labor complicated by anterior shoulder dystocia. Initial management?", "choices": ["Rubin maneuver", "McRoberts maneuver", "Zavanelli maneuver", "Posterior shoulder delivery", "Wood corkscrew maneuver"], "ans": 1, "exp": "shoulder dystocia -> เริ่มด้วย McRoberts maneuver (งอสะโพก) + suprapubic pressure ก่อน", "sys": "XV"}, {"topic": "Obstetrics & Gynecology", "q": "A 32-year-old G2P1 GA 38 weeks with severe headache 60 min. BP 200/105, no contractions. She then develops drowsiness and a generalized tonic-clonic seizure. Besides airway management, most appropriate initial management?", "choices": ["Nicardipine", "Labetalol", "Magnesium sulfate", "Methyldopa", "Diazepam"], "ans": 2, "exp": "eclampsia -> ควบคุมชักด้วย magnesium sulfate เป็นอันดับแรก (แล้วจึงคุมความดันและวางแผนคลอด)", "sys": "XV"}, {"topic": "Obstetrics & Gynecology", "q": "A 37-week pregnant woman (no ANC) in labor. PE: fully dilated cervix, effacement 100%, station 0. EFM shown. Most appropriate management?", "choices": ["Vacuum extraction", "Forceps extraction", "IV oxytocin", "Observe labor progression", "Emergency C/S"], "ans": 3, "exp": "ปากมดลูกเปิดหมด station 0 -> ให้ผู้ป่วยเบ่งคลอดและเฝ้าติดตามความก้าวหน้า (station ยังสูงเกินสำหรับ vacuum/forceps). *ถ้า EFM แสดง fetal distress ให้รีบคลอด/ผ่าตัด — คำตอบขึ้นกับกราฟจริง*", "img": "https://cdn.jsdelivr.net/gh/MercenzK/Web-quiz-images@main/NL2-2023-ObGyne-Q11.png", "sys": "XV"}, {"topic": "Obstetrics & Gynecology", "q": "A G2P1 GA 39 weeks in labor, no complications. EFM: contractions every 2-3 min, 50 s. PE: cervix 8 cm, effacement 100%, station +1. Most proper management?", "choices": ["IV oxytocin", "Non-stress test", "Sedation", "Intrauterine resuscitation", "Observe labor progression for 1 hour"], "ans": 4, "exp": "active phase ที่ contraction เพียงพอและก้าวหน้าดี -> เฝ้าสังเกตความก้าวหน้าต่อ (observe)", "sys": "XV"}, {"topic": "Obstetrics & Gynecology", "q": "A GA-term woman in labor (no ANC): contractions every 2-2.5 min, fully dilated, ruptured membranes. EFM: FHR drops after uterine contractions (late deceleration). Most proper management?", "choices": ["Intrauterine resuscitation", "Terbutaline", "Oxytocin", "Immediate forceps", "Reassure"], "ans": 0, "exp": "late deceleration = uteroplacental insufficiency -> intrauterine resuscitation (นอนตะแคง, O2, หยุด oxytocin, ให้สารน้ำ) แล้วรีบคลอด", "sys": "XV"}, {"topic": "Obstetrics & Gynecology", "q": "A G4P3 GA 39 weeks in labor. PE: fundal height 35 cm, transverse lie, FHR 152. Contractions every 3 min. Cervix 5 cm, station -3. Most appropriate management?", "choices": ["IV oxytocin", "Emergency C/S", "Observe progression of labor", "Internal podalic version", "Amniotomy"], "ans": 1, "exp": "transverse lie ในระยะเจ็บครรภ์ -> คลอดทางช่องคลอดไม่ได้ -> emergency C/S", "sys": "XV"}, {"topic": "Obstetrics & Gynecology", "q": "A woman delivered a term infant by vacuum extraction and is still bleeding after the third stage. PE: good uterine tone, fundal height at the umbilicus. Most likely cause?", "choices": ["Uterine atony", "Retained placenta", "Genital tract (vaginal) laceration", "Coagulopathy", "Uterine inversion"], "ans": 2, "exp": "ตกเลือดทั้งที่มดลูกหดรัดตัวดี + คลอดด้วย vacuum = การฉีกขาดของช่องทางคลอด (genital tract laceration)", "sys": "XV"}, {"topic": "Obstetrics & Gynecology", "q": "A 25-year-old in the puerperium with severe pain 4 hours. PE: a 5 cm bluish mass at the episiotomy wound. Most appropriate management?", "choices": ["Broad-spectrum antibiotics", "Cold packing", "Aspiration", "Evacuation (incision and drainage of hematoma)", "Observation"], "ans": 3, "exp": "vulvar/perineal hematoma ขนาดใหญ่ (5 ซม.) ที่ปวดมาก -> ผ่าเปิดระบายก้อนเลือด (evacuation) + ห้ามเลือด", "sys": "XV"}, {"topic": "Obstetrics & Gynecology", "q": "An 8-year-old girl with vaginal bleeding. PE: Tanner pubic hair II, breast II. Diagnosis?", "choices": ["Early puberty", "Premature menarche", "Premature pubarche", "Premature thelarche", "Precocious puberty"], "ans": 4, "exp": "มีลักษณะเพศทุติยภูมิ (breast + pubic hair) + ประจำเดือน ก่อนอายุ 8 ปี = precocious puberty", "sys": "XVI"}, {"topic": "Obstetrics & Gynecology", "q": "A 16-year-old with chronic cyclic pelvic pain and primary amenorrhea. Pelvic exam shown. Diagnosis?", "choices": ["Imperforate hymen (hematocolpos)", "PCOS", "Prolactinoma", "Anorexia nervosa", "Mullerian agenesis"], "ans": 0, "exp": "ปวดท้องน้อยเป็นรอบ ๆ + ไม่เคยมีประจำเดือน + เยื่อพรหมจารีปิด (bulging) = imperforate hymen ที่มี hematocolpos. *อ้างอิงภาพ*", "img": "https://cdn.jsdelivr.net/gh/MercenzK/Web-quiz-images@main/NL2-2023-ObGyne-Q18.png", "sys": "IV"}, {"topic": "Obstetrics & Gynecology", "q": "A 50-year-old with hot/cold flashes, insomnia, dyspareunia, and mood swings. She had a hysterectomy 2 years ago for myoma. Most appropriate management?", "choices": ["Combined oral contraceptive pill", "Estrogen-only therapy", "Progesterone-only pill", "Cyclic estrogen + progesterone", "Continuous estrogen + progesterone"], "ans": 1, "exp": "อาการวัยทองในผู้ที่ 'ตัดมดลูกแล้ว' -> ให้ estrogen-only HRT (ไม่ต้องเติม progestogen เพราะไม่มีมดลูกให้ป้องกัน endometrial hyperplasia)", "sys": "XIV"}, {"topic": "Obstetrics & Gynecology", "q": "A woman with galactorrhea and amenorrhea; she delivered her first child 10 years ago. Investigation for diagnosis?", "choices": ["FSH", "Estrogen", "Prolactin", "Thyroid function test", "LH"], "ans": 2, "exp": "น้ำนมไหลผิดปกติ + ขาดประจำเดือน = สงสัย hyperprolactinemia/prolactinoma -> ตรวจ prolactin (ร่วม TSH เพื่อแยก hypothyroid)", "sys": "IV"}, {"topic": "Obstetrics & Gynecology", "q": "A 49-year-old obese woman with 3 months of continuous scanty vaginal bleeding, no HRT. Pelvic exam normal, PAP: NILM. Most appropriate management?", "choices": ["Serum FSH, estriol", "Oral cyclic progestin", "Transvaginal ultrasound", "Endometrial sampling", "Hysterectomy"], "ans": 3, "exp": "AUB ในหญิงอ้วนวัยใกล้หมดประจำเดือน (เสี่ยง endometrial hyperplasia/cancer) -> endometrial sampling เพื่อตัดชิ้นเนื้อ", "sys": "II"}, {"topic": "Obstetrics & Gynecology", "q": "A 20-year-old with a swollen, very painful right vulva 3 days. Pelvic exam: 3 cm fluctuant, markedly tender mass at the right vulva. Most appropriate management?", "choices": ["Wide excision", "Needle aspiration", "Incisional biopsy", "Topical antibiotics", "Incision and drainage"], "ans": 4, "exp": "Bartholin abscess -> incision and drainage (+/- Word catheter)", "sys": "II"}, {"topic": "Obstetrics & Gynecology", "q": "Homogeneous white-grayish, foul-smelling vaginal discharge with itchiness. Pelvic exam: contact bleeding at cervix. Wet smear: numerous PMNs. Causative etiology?", "choices": ["Trichomonas vaginalis", "Gardnerella vaginalis (BV)", "Chlamydia trachomatis", "Candida albicans", "Neisseria gonorrhoeae"], "ans": 0, "exp": "ตกขาว + 'PMN จำนวนมาก' + contact bleeding (การอักเสบ) = Trichomonas vaginalis (BV จะมี clue cell และ PMN น้อย ไม่มี contact bleeding)", "sys": "XIV"}, {"topic": "Obstetrics & Gynecology", "q": "A 25-year-old with yellowish discharge 5 days. Pelvic exam: mucopurulent discharge with contact bleeding at the cervix, no cervical motion/adnexal tenderness. Wet smear: numerous PMNs without organisms. Most appropriate management?", "choices": ["Ceftriaxone", "Doxycycline", "Metronidazole", "Ofloxacin", "Clindamycin"], "ans": 1, "exp": "mucopurulent cervicitis + wet smear PMN 'ไม่พบเชื้อ' = Chlamydia -> doxycycline (พิจารณาเพิ่ม ceftriaxone คลุม gonococcus)", "sys": "XIV"}, {"topic": "Obstetrics & Gynecology", "q": "A 32-year-old with odorous discharge and pruritus 1 week, no improvement with OTC. Pelvic exam: excoriated vulva, frothy watery greyish discharge, inflamed cervix with contact bleeding (strawberry cervix). Causative etiology?", "choices": ["Gardnerella vaginalis", "Neisseria gonorrhoeae", "Trichomonas vaginalis", "Chlamydia trachomatis", "Ureaplasma urealyticum"], "ans": 2, "exp": "ตกขาวเป็นฟอง + strawberry cervix (contact bleeding) + คัน = Trichomonas vaginalis", "sys": "XII"}, {"topic": "Obstetrics & Gynecology", "q": "A pregnant woman with bacterial vaginosis. Most appropriate treatment? (ต้นฉบับมีตัวเลือกไม่ครบ ใส่เท่าที่มี)", "choices": ["Metronidazole", "Doxycycline"], "ans": 0, "exp": "bacterial vaginosis -> metronidazole (ปลอดภัยในหญิงตั้งครรภ์)", "sys": "XV"}, {"topic": "Orthopedics", "q": "A 58-year-old man with chronic elbow pain 3 months, worse when lifting; pain aggravated by resisting wrist flexion, medial tenderness. Diagnosis?", "choices": ["Pulled elbow", "Olecranon bursitis", "Myofascial pain", "Osteoarthritis of the elbow", "Medial epicondylitis (golfer's elbow)"], "ans": 4, "exp": "ปวด medial epicondyle + แย่ลงเมื่อต้าน wrist flexion (flexor origin) = medial epicondylitis (golfer's elbow)", "sys": "XIII"}, {"topic": "Orthopedics", "q": "A 39-year-old woman with left elbow pain at the medial epicondyle, worse on resisting pronation, not aggravated by passive motion. Diagnosis?", "choices": ["Golfer's elbow (medial epicondylitis)", "Tennis elbow", "Olecranon bursitis", "Reactive arthritis", "Rheumatoid arthritis"], "ans": 0, "exp": "เจ็บ medial epicondyle + แย่ลงเมื่อต้าน pronation = golfer's elbow (medial epicondylitis)", "sys": "XIII"}, {"topic": "Orthopedics", "q": "A 6-year-old with fever and a painful left elbow 3 days, held in mid-flexion, warm and erythematous. BT 39. Most useful initial investigation?", "choices": ["ESR, CRP", "Arthrocentesis", "ASO titer", "X-ray (AP, lateral)", "Ultrasound elbow"], "ans": 1, "exp": "สงสัย septic arthritis (ไข้ + ข้อบวมแดงร้อน + ปวดมาก) -> arthrocentesis (เจาะดูดน้ำในข้อ) เพื่อ Gram stain/culture วินิจฉัย", "sys": "XIII"}, {"topic": "Orthopedics", "q": "A 25-year-old cannot extend the left wrist after a motorcycle accident. X-ray: fracture of the distal 1/3 shaft of the left humerus. Which structure is most likely injured?", "choices": ["Ulnar nerve", "Axillary nerve", "Radial nerve", "Median nerve", "Musculocutaneous nerve"], "ans": 2, "exp": "humeral shaft fracture -> radial nerve injury (wrist drop, เหยียดข้อมือไม่ได้)", "sys": "XIII"}, {"topic": "Orthopedics", "q": "A child's foot is shown. Diagnosis? (ต้นฉบับมีตัวเลือกไม่ครบ ใส่เท่าที่มี)", "choices": ["Calcaneovalgus", "Congenital clubfoot (talipes equinovarus)", "Metatarsus adductus", "Pes planus"], "ans": 1, "exp": "เท้าบิดเข้าใน + เอ็นร้อยหวายตึง (equinovarus) = congenital clubfoot. *คำตอบขึ้นกับภาพจริง*", "img": "https://cdn.jsdelivr.net/gh/MercenzK/Web-quiz-images@main/NL2-2023-Ortho-Q5.png", "sys": "XIII"}, {"topic": "Orthopedics", "q": "A 68-year-old woman with chronic knee pain 10 years, morning stiffness <10 min. PE: genu varum, crepitation in both knees. Most likely diagnosis?", "choices": ["Septic arthritis", "Rheumatoid arthritis", "Gouty arthritis", "Ligament injury", "Osteoarthritis"], "ans": 4, "exp": "ปวดเข่าเรื้อรัง + morning stiffness สั้น (<30 นาที) + genu varum + crepitus = osteoarthritis", "sys": "XIII"}, {"topic": "Orthopedics", "q": "A man with back pain radiating to the right leg, worse on bending forward, positive straight leg raise. Diagnosis? (ต้นฉบับมีตัวเลือกไม่ครบ ใส่เท่าที่มี)", "choices": ["Herniated nucleus pulposus", "Spondylolisthesis", "Spinal stenosis"], "ans": 0, "exp": "ปวดหลังร้าวลงขา + SLR บวก = herniated nucleus pulposus (lumbar disc herniation)", "sys": "XIII"}, {"topic": "Orthopedics", "q": "A 60-year-old man with right knee pain and swelling, positive patellar ballottement. Joint aspiration: rhomboid crystals. Management?", "choices": ["Cold compression", "Celecoxib (NSAID)", "Ketoprofen gel", "Colchicine", "Tramadol"], "ans": 1, "exp": "rhomboid, positively birefringent crystal = CPPD (pseudogout) -> รักษา acute attack ด้วย NSAID (celecoxib) หรือ colchicine", "sys": "XIII"}, {"topic": "Orthopedics", "q": "Joint pain 4 days: right ankle for 3 days then migrated to the left knee, with inflammatory signs. Management?", "choices": ["Colchicine", "Antibiotics", "NSAIDs", "Cold compression", "Allopurinol"], "ans": 2, "exp": "migratory polyarthritis (ย้ายข้อ) + inflammatory = ลักษณะ rheumatic fever/reactive -> NSAIDs (aspirin/NSAID) เป็นการรักษาอาการข้อ", "sys": "XIII"}, {"topic": "Ophthalmology", "q": "A 4-year-old with impaired night vision and diarrhea. PE: triangular dry whitish foamy lesions on the eye (Bitot spots), follicular keratosis on elbows and knees. Most useful investigation?", "choices": ["EEG", "Slit lamp examination", "Ocular tonometry", "Serum retinol", "Skin biopsy"], "ans": 3, "exp": "ตาบอดกลางคืน + Bitot spot + follicular keratosis = vitamin A deficiency -> ตรวจ serum retinol (vitamin A)", "sys": "VII"}, {"topic": "Ophthalmology", "q": "A child with orthotropia and ptosis. What will happen if untreated? (ต้นฉบับมีตัวเลือกไม่ครบ ใส่เท่าที่มี)", "choices": ["Cataract", "Deprivation amblyopia", "Glaucoma"], "ans": 1, "exp": "หนังตาตก (ptosis) บังการมองเห็นในเด็ก -> deprivation amblyopia (ตาขี้เกียจจากการถูกบัง) ถ้าไม่รักษา", "sys": "VII"}, {"topic": "Ophthalmology", "q": "A 9-month-old with leukocoria. Most likely diagnosis?", "choices": ["Retinoblastoma", "Neuroblastoma", "Congenital cataract", "Lens dislocation", "Coats disease"], "ans": 0, "exp": "leukocoria (ตาวาวขาว) ในทารก -> ต้องแยก retinoblastoma (มะเร็งจอตา) เป็นอันดับแรก. *อ้างอิงภาพ; congenital cataract ก็ทำให้ leukocoria ได้*", "img": "https://cdn.jsdelivr.net/gh/MercenzK/Web-quiz-images@main/NL2-2023-Eye-Q3.png", "sys": "VII"}, {"topic": "Ophthalmology", "q": "A 25-year-old with left eye pain and excessive tearing. VA 6/6, follicular conjunctivitis with tender preauricular lymphadenopathy. Most appropriate management?", "choices": ["Topical steroid", "Supportive care + contact precautions", "Topical antiviral/antifungal", "Topical antibiotic", "Oral antibiotic"], "ans": 1, "exp": "follicular conjunctivitis + preauricular node = viral (adenoviral) conjunctivitis -> รักษาประคับประคอง + contact precaution (ติดต่อง่ายมาก)", "sys": "VII"}, {"topic": "Ophthalmology", "q": "A patient with left eye pain after contact with hot glue 3 hours ago. Exam: ciliary injection with abnormal corneal light reflex. Most proper initial management?", "choices": ["Cold compression", "Topical antihistamine", "Frequent artificial tears + topical antibiotic prophylaxis", "Topical anesthetic with steroid drops", "Pressure patch"], "ans": 2, "exp": "corneal injury/burn -> frequent lubrication (artificial tears) + topical antibiotic prophylaxis. ห้ามใช้ topical anesthetic/steroid (เป็นพิษ/ติดเชื้อ)", "sys": "VII"}, {"topic": "Ophthalmology", "q": "A 25-year-old with a left eyelid mass 3 months, no improvement after 1 month of topical antibiotics. PE: 5 mm movable non-tender mass. Most appropriate management?", "choices": ["Observe and follow-up", "Warm compression", "Topical antibiotic ointment", "Incision and curettage", "Oral antibiotic"], "ans": 3, "exp": "chalazion เรื้อรังที่ไม่ตอบสนอง conservative -> incision and curettage", "sys": "VII"}, {"topic": "Ophthalmology", "q": "A 20-year-old with right upper eyelid swelling 1 day: tender, erythematous, warm, no fluctuation. Most appropriate management?", "choices": ["Needle aspiration", "Incision and curettage", "Pressure patch", "Incisional biopsy", "Warm compression"], "ans": 4, "exp": "hordeolum (stye) เฉียบพลัน -> warm compression (ประคบอุ่น)", "sys": "VII"}, {"topic": "Ophthalmology", "q": "A 70-year-old with an upper-eyelid mass and on-and-off discharge for 1 year, now erythematous with excessive tearing. Diagnosis?", "choices": ["Dacryocystitis", "Hordeolum", "Lacrimal sac tumor", "Canaliculitis", "Chalazion"], "ans": 0, "exp": "ก้อนบริเวณถุงน้ำตา + หนองไหลเป็น ๆ หาย ๆ + น้ำตาไหล (epiphora) = dacryocystitis (การอักเสบของถุงน้ำตา)", "sys": "VII"}, {"topic": "Ophthalmology", "q": "A young man hit in the orbit by a baseball bat; the anterior chamber is half-filled with blood (hyphema), vision hand-movement, no orbital fracture. Management?", "choices": ["CT orbit", "Absolute bed rest with head elevation", "Topical antibiotics", "Pressure patch", "Artificial tear drops"], "ans": 1, "exp": "hyphema (เลือดในช่องหน้าลูกตา) -> นอนพัก + ยกศีรษะสูง 30-45 องศา (ให้เลือดตกตะกอน, ลด rebleeding) + eye shield", "sys": "VII"}, {"topic": "ENT", "q": "An 18-year-old with left ear pain 1 day after ear-picking; otoscopy shows the tympanic membrane (image). Most appropriate treatment?", "choices": ["Ear toilet / keep dry", "Topical antibiotics", "Paper patch", "Myringoplasty", "Tympanoplasty"], "ans": 2, "exp": "traumatic TM perforation -> ส่วนใหญ่หายเอง (keep dry, ห้ามน้ำเข้า); paper patch ช่วยประกบขอบให้หายเร็วขึ้น. *อ้างอิงภาพ*", "img": "https://cdn.jsdelivr.net/gh/MercenzK/Web-quiz-images@main/NL2-2023-ENT-Q1.png", "sys": "VIII"}, {"topic": "ENT", "q": "A 25-year-old Thai boxer with right ear pain 2 days (image shows auricular involvement). Most appropriate antibiotic? (ต้นฉบับมีตัวเลือกไม่ครบ ใส่เท่าที่มี)", "choices": ["Amoxicillin", "Ciprofloxacin", "Ceftriaxone"], "ans": 1, "exp": "perichondritis ของใบหูจากการบาดเจ็บ (นักมวย) -> เชื้อ Pseudomonas -> ciprofloxacin. *อ้างอิงภาพ*", "img": "https://cdn.jsdelivr.net/gh/MercenzK/Web-quiz-images@main/NL2-2023-ENT-Q2.png", "sys": "VIII"}, {"topic": "ENT", "q": "A 40-year-old with dizziness and a spinning sensation when lying on the left side. Ear exam and otoscopy normal. Diagnosis?", "choices": ["Acute otitis media", "Meniere disease", "Vestibular insufficiency", "Vestibular neuritis", "Benign paroxysmal positional vertigo"], "ans": 4, "exp": "เวียนหัวหมุนสัมพันธ์ท่าทาง (นอนตะแคง) + หูปกติ = BPPV", "sys": "VIII"}, {"topic": "ENT", "q": "A 78-year-old for check-up, independent in ADL; his son fears Alzheimer because he has trouble understanding what family members say. Exam normal, no cerumen. Most appropriate next management?", "choices": ["Audiometry", "Reassure as normal aging", "TMSE test", "Geriatric depression scale", "CT brain"], "ans": 0, "exp": "ทำ ADL ได้ปกติ แต่ 'ฟังไม่เข้าใจ' -> น่าจะเป็นปัญหาการได้ยิน (presbycusis) มากกว่า dementia -> ตรวจ audiometry", "sys": "VIII"}, {"topic": "ENT", "q": "A 60-year-old with left-sided epistaxis. PE: minimal oozing from the anterior nasal septum, normal mucosa. Most appropriate management?", "choices": ["Antibiotic ointment", "Cauterization", "Cold packing", "Anterior nasal packing", "Posterior packing"], "ans": 1, "exp": "เลือดออกน้อยจากจุดที่เห็นชัดที่ผนังกั้นจมูกด้านหน้า -> จี้ห้ามเลือด (cauterization)", "sys": "VIII"}, {"topic": "ENT", "q": "A 5-year-old boy with ALL has 50 mL nasal bleeding not stopping with pressure. Management? (ต้นฉบับมีตัวเลือกไม่ครบ ใส่เท่าที่มี)", "choices": ["Cold packing", "Posterior nasal packing", "Anterior nasal packing"], "ans": 2, "exp": "เลือดกำเดาไหลไม่หยุดด้วยการกด (+ เกล็ดเลือดต่ำจาก ALL) -> anterior nasal packing", "sys": "VIII"}, {"topic": "ENT", "q": "A 12-year-old girl with left nasal obstruction and mucoid discharge 2 months. Anterior rhinoscopy: no mass; posterior rhinoscopy: a glistening mass obstructing with discharge; Valsalva does not change its size. Diagnosis?", "choices": ["Foreign body", "Glioma", "Meningocele", "Antrochoanal polyp", "Dermoid cyst"], "ans": 3, "exp": "ก้อน glistening ที่ posterior choana ข้างเดียว + ไม่เปลี่ยนขนาดตาม Valsalva (ไม่ใช่ encephalocele) = antrochoanal polyp", "sys": "VIII"}, {"topic": "ENT", "q": "A 50-year-old with DM presents with facial pain. X-ray: opacity of the maxillary antrum. PE: pale nasal mucosa, obstruction, and purulent discharge. Most appropriate next step?", "choices": ["Irrigation", "Nasal swab culture", "MRI", "Antifungal drug", "CT"], "ans": 4, "exp": "เบาหวาน + sinusitis + เยื่อบุซีด (สงสัย invasive fungal sinusitis/mucormycosis) -> imaging (CT) ประเมินการลุกลาม + biopsy ด่วน (แล้วให้ antifungal/ผ่าตัด)", "sys": "VIII"}, {"topic": "ENT", "q": "A 5-year-old boy with watery rhinorrhea, sneezing, and eye itching 5 days/week for 3 months, missing school. PE: bilateral inferior turbinate swelling. Most appropriate treatment?", "choices": ["Intranasal corticosteroids", "Inhaled corticosteroids", "Leukotriene receptor antagonist", "Oral prednisone", "Salbutamol MDI"], "ans": 0, "exp": "allergic rhinitis (persistent, moderate-severe) -> intranasal corticosteroid เป็นยาที่ได้ผลดีสุด", "sys": "VIII"}, {"topic": "ENT", "q": "A previously healthy 3-year-old with snoring 4 months. PE: tonsils 3+ bilaterally, pale inferior turbinates. Most proper management?", "choices": ["Topical pseudoephedrine", "Intranasal corticosteroid", "Oral pseudoephedrine", "Oral chlorpheniramine", "Nasal irrigation"], "ans": 1, "exp": "กรน + ต่อมทอนซิลโต + จมูกซีด (allergic) -> เริ่มด้วย intranasal corticosteroid (ลด adenoid/turbinate); ถ้ามี OSA ชัดเจนพิจารณา adenotonsillectomy", "sys": "VIII"}, {"topic": "ENT", "q": "A 40-year-old develops hoarseness immediately after regaining consciousness from cholecystectomy under GA. Cause?", "choices": ["Laryngeal web", "Vocal cord nodule", "Cricoarytenoid joint dislocation", "Vocal cord paralysis", "Intubation granuloma"], "ans": 2, "exp": "เสียงแหบทันทีหลังใส่ท่อช่วยหายใจ = cricoarytenoid joint dislocation (หรือ vocal cord paralysis จากการบาดเจ็บ); granuloma/nodule เป็นภาวะเรื้อรัง", "sys": "VIII"}, {"topic": "ENT", "q": "A 62-year-old with DM has difficulty breathing 1 day; tooth extraction 2 weeks ago then mouth swelling 5 days. PE: BT 38, stridor, marked bilateral submandibular and floor-of-mouth swelling with tongue protrusion (Ludwig's angina). Apart from IV antibiotics, proper next step?", "choices": ["Needle aspiration", "Incision and drainage", "Debridement", "Tracheostomy (secure airway)", "Endotracheal intubation"], "ans": 3, "exp": "Ludwig's angina ที่มี airway obstruction + กายวิภาคผิดรูป (พื้นปากบวมดันลิ้น) -> secure airway; การใส่ ETT ทางปากยากมาก -> tracheostomy (หรือ awake fiberoptic intubation)", "sys": "VIII"}, {"topic": "Emergency", "q": "A 40-year-old woman burned in a gas explosion at home. BP 140/80, SpO2 95%, 45% TBSA superficial partial-thickness burn involving the face and neck, singed facial hair, raw oral mucosa. Most appropriate initial management?", "choices": ["Rinse with cold water", "Measure carboxyhemoglobin", "Tracheobronchoscopy", "Silver-containing wound dressing", "Endotracheal intubation"], "ans": 4, "exp": "ไฟไหม้ที่หน้า/คอ + ขนจมูกไหม้ + เยื่อบุปากไหม้ = inhalation/airway burn -> ใส่ท่อช่วยหายใจ (ETT) ก่อนที่ทางเดินหายใจจะบวมปิด", "sys": "emergency"}, {"topic": "Emergency", "q": "A 60-year-old with dyspnea, fever, and no urine 2 hours. HR 120, BP 80/60, flat neck veins, dry lips, sunken eyeballs. Na 150, K 3, glucose 600. ABG pH 6.9. Most appropriate initial management?", "choices": ["0.9% NSS + KCl", "0.45% NSS", "0.9% NSS", "0.45% NSS + KCl", "0.9% NSS + regular insulin"], "ans": 0, "exp": "HHS/hyperglycemia + hypovolemic shock -> เริ่มสารน้ำ isotonic 0.9% NSS; K ต่ำ (3) จึงเติม KCl และ 'ยังไม่ให้ insulin' จนกว่า K >= 3.3", "sys": "emergency"}, {"topic": "Emergency", "q": "A 36-year-old with shortness of breath at rest 1 hour. PR 90, SpO2 95%, clear lungs, S3 gallop, JVP engorgement, cold and clammy skin. EKG: sinus tachycardia. Diagnosis?", "choices": ["Cardiac tamponade", "Pulmonary embolism", "Severe pneumonia", "Ruptured chordae tendineae", "Acute MI"], "ans": 1, "exp": "เหนื่อยเฉียบพลัน + ปอดใส + JVP สูง (RV strain) + ช็อก (cold clammy) = massive pulmonary embolism. *tamponade ก็มี JVP สูง+ปอดใส แต่เสียงหัวใจเบา ไม่มี S3*", "sys": "emergency"}, {"topic": "Emergency", "q": "A 20-year-old with massive vaginal bleeding after an illegal abortion received NSS and PRC. 10 minutes later she develops chest tightness, agitation, BP 80/60, wheezing both lungs. Cause?", "choices": ["Acute pulmonary edema", "Pulmonary embolism", "Mismatch (acute hemolytic) transfusion reaction", "Amniotic fluid embolism", "Septic shock"], "ans": 2, "exp": "เกิดขึ้นเร็ว ~10 นาทีหลังให้เลือด + ช็อก + wheezing = acute hemolytic transfusion reaction (mismatch)", "sys": "emergency"}, {"topic": "Emergency", "q": "A patient in cardiac arrest; during CPR the monitor shows a shockable rhythm (EKG). Treatment for this arrhythmia?", "choices": ["Lidocaine", "Magnesium sulfate", "Calcium gluconate", "Amiodarone", "Sodium bicarbonate"], "ans": 3, "exp": "VF/pulseless VT ระหว่าง CPR -> defibrillation + amiodarone (antiarrhythmic). *ถ้าเป็น torsades (polymorphic) ให้ magnesium — คำตอบขึ้นกับกราฟจริง*", "sys": "emergency"}, {"topic": "Emergency", "q": "A 50-year-old with DM/HT/DLP had left chest pain radiating to the arm for 20 minutes while watching TV, not relieved by rest. Troponin T normal, ECG no ST-T change. Condition?", "choices": ["Stable angina", "NSTEMI", "Esophageal spasm", "GERD", "Unstable angina"], "ans": 4, "exp": "เจ็บอกขณะพัก นานกว่าปกติ ไม่ดีขึ้นด้วยการพัก + troponin/ECG ปกติ = unstable angina", "sys": "emergency"}, {"topic": "Emergency", "q": "A 30-year-old with face swelling and low-grade fever 4 weeks; 3 days ago developed facial plethora, arm swelling, and stridor. PE: left cervical lymph node 3 cm, hepatosplenomegaly. Most appropriate management?", "choices": ["Dexamethasone", "Chemotherapy", "Emergency radiation", "Endotracheal tube", "Furosemide"], "ans": 0, "exp": "SVC syndrome จากมะเร็ง (lymphoma) + stridor (airway) -> ให้ corticosteroid (dexamethasone) ลดบวมเฉียบพลัน ระหว่างจัดการรักษาจำเพาะ (chemo/RT). *lymphoma ตอบสนอง chemo ดี*", "sys": "emergency"}, {"topic": "Emergency", "q": "A 40-year-old found unresponsive, with complex partial seizures on phenytoin 5 years. RR 12, mid-gaze, pinpoint pupils, extensor posture. Cause?", "choices": ["Thalamic infarction", "Pontine hemorrhage", "Medullary hemorrhage", "Encephalitis", "Phenytoin intoxication"], "ans": 1, "exp": "รูม่านตาเล็กมาก (pinpoint) + extensor posturing + coma = pontine hemorrhage", "sys": "emergency"}, {"topic": "Emergency", "q": "A patient with altered consciousness and head trauma: no fever, no Cushing reflex, fixed dilated pupils, absent oculocephalic reflex, extensor motor response. Diagnosis?", "choices": ["Medullary hemorrhage", "Thalamic infarction", "Brainstem injury/herniation (fixed dilated pupils, absent reflexes)", "Encephalitis", "Pontine hemorrhage"], "ans": 2, "exp": "หลัง trauma + รูม่านตาขยายค้าง fixed + absent brainstem reflexes + extensor = brainstem herniation/severe brainstem injury (uncal/midbrain). *ต้นฉบับตัวเลือกไม่มีคำที่ตรงนัก จึงระบุกลุ่ม brainstem herniation*", "sys": "emergency"}, {"topic": "Emergency", "q": "A restrained motorcyclist with a 6 cm right flank contusion and RLQ tenderness. BP 120/70, HR 80. FAST negative. Most proper management?", "choices": ["Serial abdominal examination", "Diagnostic peritoneal lavage", "Diagnostic laparoscopy", "CT abdomen", "Exploratory laparotomy"], "ans": 3, "exp": "blunt abdominal trauma ที่ 'stable' + FAST ลบ + มีอาการกดเจ็บ -> CT abdomen ประเมินอวัยวะภายใน", "sys": "emergency"}, {"topic": "Emergency", "q": "A 30-year-old woman with blunt abdominal injury, FAST negative, hemodynamically stable. What next?", "choices": ["Serial abdominal examination", "Diagnostic peritoneal lavage", "Diagnostic laparoscopy", "Exploratory laparotomy", "CT abdomen"], "ans": 4, "exp": "stable + FAST ลบ -> CT abdomen เพื่อประเมินการบาดเจ็บภายใน", "sys": "emergency"}, {"topic": "Emergency", "q": "A stab wound to the abdomen with omental evisceration. Appropriate management?", "choices": ["Exploratory laparotomy", "CT abdomen", "FAST", "Diagnostic peritoneal lavage", "Local wound exploration"], "ans": 0, "exp": "บาดแผลแทงที่มี omental evisceration (ไส้/omentum โผล่) = ข้อบ่งชี้ผ่าตัดเปิดหน้าท้อง (exploratory laparotomy) ทันที", "sys": "emergency"}, {"topic": "Emergency", "q": "A 40-year-old bitten by a stray dog; she completed rabies vaccination 4 months ago. Abrasion with oozing. Most appropriate management?", "choices": ["Observe", "2 booster doses of rabies vaccine (day 0, 3)", "1 booster dose of rabies vaccine", "5 doses of rabies vaccine", "Rabies immunoglobulin"], "ans": 1, "exp": "เคยฉีดวัคซีนพิษสุนัขบ้าครบ -> ถูกกัดซ้ำ ให้ booster 2 เข็ม (วันที่ 0 และ 3) ไม่ต้องให้ RIG", "sys": "emergency"}, {"topic": "Emergency", "q": "A 5-year-old bitten by a cat (small laceration with bleeding); she completed a full rabies vaccine course 2 years ago. Appropriate management?", "choices": ["Full course of rabies vaccine", "Booster 1 dose", "Booster 2 doses (day 0, 3)", "ERIG + 1 dose", "ERIG + 2 doses"], "ans": 2, "exp": "เคยฉีดครบ -> re-exposure ให้ booster 2 เข็ม (วันที่ 0, 3) ไม่ต้องให้ RIG", "sys": "emergency"}, {"topic": "Emergency", "q": "A 10-year-old with complete EPI vaccination, bitten by a dog 4 months ago and got a full rabies course; today bitten again. Most appropriate rabies vaccination?", "choices": ["No vaccination needed", "Booster 1 dose", "Booster 1 dose + immunoglobulin", "Booster 2 doses (day 0, 3)", "Booster 2 doses + immunoglobulin"], "ans": 3, "exp": "เคยฉีดวัคซีนครบ -> ถูกกัดซ้ำ ให้ booster 2 เข็ม (วันที่ 0, 3) โดยไม่ต้องให้ immunoglobulin", "sys": "emergency"}, {"topic": "Emergency", "q": "A 25-year-old with dizziness and blindness 4 hours after drinking local liquor. Most appropriate management?", "choices": ["Sodium thiosulfate", "N-acetylcysteine", "Naloxone", "Atropine", "Ethyl alcohol (or fomepizole)"], "ans": 4, "exp": "ตามัว/ตาบอดหลังดื่มเหล้าเถื่อน = methanol poisoning -> ให้ ethanol (หรือ fomepizole) ยับยั้ง alcohol dehydrogenase (+/- dialysis)", "sys": "emergency"}, {"topic": "Emergency", "q": "A gardener with disorientation. BP 100/60, pupils 1 mm, stupor, hypersalivation (cholinergic toxidrome). Antidote?", "choices": ["Atropine", "Naloxone", "Magnesium sulfate", "Ethyl alcohol", "Sodium thiosulfate"], "ans": 0, "exp": "cholinergic toxidrome (รูม่านตาเล็ก + น้ำลายมาก) จาก organophosphate -> atropine (+/- pralidoxime)", "sys": "emergency"}, {"topic": "Emergency", "q": "A 12-year-old with euphoria, agitation, and pressured speech after eating sweets/beverages at a party. PE: normal pupils, rapid pulse, red eyes, dry mouth, hyperactivity. Most likely substance?", "choices": ["Ecstasy", "Cannabis", "Opioid", "Alcohol", "Amphetamine"], "ans": 1, "exp": "euphoria + ตาแดง (conjunctival injection) + ปากแห้ง + หัวใจเต้นเร็ว = cannabis", "sys": "emergency"}, {"topic": "Emergency", "q": "A 14-year-old ingested 50 paracetamol 500 mg tablets 8 hours ago; good conscious, no jaundice, normal exam. Most appropriate management?", "choices": ["NG lavage", "Activated charcoal", "N-acetylcysteine", "EGD", "Observation"], "ans": 2, "exp": "paracetamol overdose (~25 กรัม) ที่ 8 ชม. -> ให้ N-acetylcysteine (ได้ผลดีถ้าเริ่มภายใน 8 ชม.; แปลผลตาม nomogram)", "sys": "emergency"}, {"topic": "Emergency", "q": "A patient bitten by a cobra. What should be done? (ต้นฉบับมีตัวเลือกไม่ครบ ใส่เท่าที่มี)", "choices": ["Coagulation panel", "Observe for neurological deficit signs", "Serial venous clotting time"], "ans": 1, "exp": "งูเห่า = neurotoxic -> เฝ้าระวังอาการอ่อนแรง/หนังตาตก/กล้ามเนื้อหายใจ (neurological deficit); VCT ใช้กับงูพิษต่อเลือด", "sys": "emergency"}, {"topic": "Emergency", "q": "A woman found drowsy in a room with burning charcoal and a history of drug overdose; now conscious. Appropriate management? (ต้นฉบับมีตัวเลือกไม่ครบ ใส่เท่าที่มี)", "choices": ["Gastric lavage", "EGD", "Observe (supportive care)"], "ans": 2, "exp": "มาพบช้า + รู้สึกตัวดีแล้ว -> รักษาประคับประคอง/สังเกตอาการ (gastric lavage ไม่มีประโยชน์เมื่อพ้นเวลา/รู้สึกตัวดี); ถ้ามี CO จากเผาถ่าน ให้ 100% oxygen", "sys": "emergency"}, {"topic": "Psychiatry", "q": "A 3-year-old with delayed speech, aggressive behavior, and poor eye contact 1 year. MSE: tiptoe walking, echolalia, hyperactivity. Diagnosis?", "choices": ["Autism spectrum disorder", "Intellectual disability", "ADHD", "Neglected child", "Language disorder"], "ans": 0, "exp": "delayed speech + poor eye contact + echolalia + repetitive/stereotyped (tiptoe) = autism spectrum disorder", "sys": "V"}, {"topic": "Psychiatry", "q": "A withdrawn man who does not socialize, participates little, has average grades, no friends know his background; appears introverted and emotionless. Diagnosis?", "choices": ["Avoidant personality disorder", "Schizoid personality disorder", "Borderline personality disorder", "Dysthymia", "Social anxiety disorder"], "ans": 1, "exp": "ชอบเก็บตัว ไม่ต้องการความสัมพันธ์ + อารมณ์เรียบเฉย (emotionless) = schizoid personality disorder (avoidant จะ 'อยาก' มีสัมพันธ์แต่กลัวถูกปฏิเสธ)", "sys": "V"}, {"topic": "Psychiatry", "q": "A 25-year-old woman with a headache requests only a male doctor, flirts with him, and asks him to dinner. Diagnosis?", "choices": ["Adjustment disorder", "Borderline personality disorder", "Histrionic personality disorder", "Dependent personality disorder", "Narcissistic personality disorder"], "ans": 2, "exp": "เรียกร้องความสนใจ + ยั่วยวน/เจ้าชู้ (seductive) = histrionic personality disorder", "sys": "V"}, {"topic": "Psychiatry", "q": "A 50-year-old single woman with tiredness, irritability, and sleep disturbance; she left a successful job 5 years ago to care for her bedridden mother; her brother supports her financially. What is the problem? (ต้นฉบับมีตัวเลือกไม่ครบ ใส่เท่าที่มี)", "choices": ["Financial problem", "Midlife crisis / caregiver role strain"], "ans": 1, "exp": "ทิ้งอาชีพที่ประสบความสำเร็จมาดูแลแม่ + อ่อนล้า/หงุดหงิด = ภาระผู้ดูแล/วิกฤตวัยกลางคน (ไม่ใช่ปัญหาการเงินเพราะพี่ชายช่วย)", "sys": "V"}, {"topic": "Psychiatry", "q": "A woman with sleep problems, muscle tension, and fatigue for a year, worried about being a good mother and about her husband's work. Most likely diagnosis? (ต้นฉบับมีตัวเลือกไม่ครบ ใส่เท่าที่มี)", "choices": ["Generalized anxiety disorder", "Somatic symptom disorder"], "ans": 0, "exp": "กังวลมากเกินเรื่องหลายด้านเรื้อรัง >6 เดือน + muscle tension + นอนไม่หลับ + เหนื่อย = generalized anxiety disorder", "sys": "V"}, {"topic": "Psychiatry", "q": "A 40-year-old with a femoral fracture who lost her husband and child; she was unconscious for a few days post-op, then became agitated, wanting to die, removing her fixator and resisting care, with fluctuating consciousness. Diagnosis?", "choices": ["Delirium", "Brief psychotic disorder", "MDD with psychotic features", "Adjustment disorder", "Post-traumatic stress disorder"], "ans": 0, "exp": "หลังผ่าตัด + ระดับความรู้สึกตัวขึ้น ๆ ลง ๆ + กระวนกระวาย/ดึงสาย = delirium (acute confusional state)", "sys": "V"}, {"topic": "Psychiatry", "q": "A 20-year-old woman, 3 months after being rescued from a mass shooting, avoids public places, has anhedonia, and frequent nightmares disturbing her sleep. Most likely diagnosis?", "choices": ["Agoraphobia", "Post-traumatic stress disorder", "Specific phobia", "Generalized anxiety disorder", "Adjustment disorder with anxiety"], "ans": 1, "exp": "re-experiencing (ฝันร้าย) + avoidance + negative mood หลังเหตุการณ์สะเทือนใจ 'เกิน 1 เดือน' (3 เดือน) = PTSD", "sys": "V"}, {"topic": "Psychiatry", "q": "A 14-year-old with dyspnea while studying at school, with multiple prior similar visits. RR 30. Cause? (ต้นฉบับมีตัวเลือกไม่ครบ ใส่เท่าที่มี)", "choices": ["Panic attack", "Hyperventilation syndrome"], "ans": 1, "exp": "หายใจเหนื่อยเป็นซ้ำ ๆ สัมพันธ์กับความเครียด (เรียน) โดยตรวจร่างกายปกติ = hyperventilation syndrome", "sys": "V"}, {"topic": "Psychiatry", "q": "The night before a final exam, a student feels angry when a roommate tells them to prepare. Diagnosis? (โจทย์สั้น/ก้ำกึ่งกับปฏิกิริยาปกติ)", "choices": ["Major depressive disorder", "Acute stress disorder", "Bipolar disorder", "Adjustment disorder", "Normal reaction"], "ans": 3, "exp": "อารมณ์/พฤติกรรมตอบสนองต่อความเครียด (สอบ) = adjustment disorder (ถ้าอาการไม่มาก/สั้นอาจถือเป็นปฏิกิริยาปกติ). *โจทย์ให้ข้อมูลน้อย*", "sys": "V"}, {"topic": "Psychiatry", "q": "A 25-year-old actress worried about getting fat, easily angry with labile mood, accuses coworkers of gossiping about her. Most likely cause?", "choices": ["Kratom", "Marijuana", "Thyroxine", "Alcohol", "Amphetamine"], "ans": 4, "exp": "กังวลเรื่องหุ่น (ใช้ยาลดน้ำหนัก) + หงุดหงิด/อารมณ์แปรปรวน + paranoid (คิดว่าคนนินทา) = amphetamine (ยากระตุ้น)", "sys": "V"}, {"topic": "Psychiatry", "q": "An actress worried about her weight has nausea, vomiting, irritability, mood swings, and hears friends gossiping about her. Most likely drug used?", "choices": ["Amphetamine", "Ecstasy", "Cocaine", "Cannabis", "L-thyroxine"], "ans": 0, "exp": "คุมน้ำหนัก + paranoid + หงุดหงิด + คลื่นไส้ (withdrawal) = amphetamine", "sys": "V"}, {"topic": "Psychiatry", "q": "A 20-year-old with shortness of breath, facial numbness, and bilateral carpopedal spasm, 3 times within an hour; she keeps her eyes closed but responds to commands; normal breath sounds. Most appropriate management?", "choices": ["Rebreathing therapy", "Reassure and coach breathing", "Diazepam", "Haloperidol", "Sodium valproate"], "ans": 1, "exp": "hyperventilation syndrome (carpopedal spasm + ชาหน้า) -> ให้ความมั่นใจและฝึกหายใจช้า ๆ (เลิกแนะนำ rebreathing bag)", "sys": "V"}, {"topic": "Psychiatry", "q": "A 30-year-old with palpitations and chest discomfort at night, cannot sleep for a week, thinks she might die, no medical problems or drug abuse. Proper management?", "choices": ["Psychotherapy alone", "Midazolam", "Sertraline", "Propranolol", "Haloperidol"], "ans": 2, "exp": "panic disorder -> รักษาระยะยาวด้วย SSRI (sertraline) + CBT", "sys": "V"}, {"topic": "Psychiatry", "q": "A 30-year-old, 3 days postpartum, with depressed mood and worry that she cannot care for her baby. Most appropriate management?", "choices": ["Consult psychiatrist", "CBT", "Sertraline and stop breastfeeding", "Family consultation / reassurance", "Lorazepam and stop breastfeeding"], "ans": 3, "exp": "อาการซึมเศร้าเล็กน้อยวันที่ 3 หลังคลอด = postpartum blues (baby blues) ซึ่งหายเองใน ~2 สัปดาห์ -> ให้กำลังใจ/ปรึกษาครอบครัว + เฝ้าระวังพัฒนาเป็น postpartum depression", "sys": "V"}, {"topic": "Psychiatry", "q": "A panic attack. Most appropriate treatment? (ต้นฉบับมีตัวเลือกไม่ครบ ใส่เท่าที่มี)", "choices": ["Sertraline (SSRI)", "Psychotherapy"], "ans": 0, "exp": "panic disorder -> first-line ระยะยาวคือ SSRI (sertraline) ร่วมกับ CBT", "sys": "V"}, {"topic": "Psychiatry", "q": "A 55-year-old woman, newly a manager, with insomnia, irritability, frequent arguments, fatigue, disappointment, and wanting to disappear. Most proper management?", "choices": ["Sertraline", "Alprazolam", "Diazepam", "Quetiapine", "Haloperidol"], "ans": 0, "exp": "อาการซึมเศร้า (นอนไม่หลับ หงุดหงิด เหนื่อย ท้อแท้ อยากหายไป = passive suicidal) -> รักษาด้วย SSRI (sertraline)", "sys": "V"}, {"topic": "Psychiatry", "q": "A man with insomnia 1 month after his property was seized by court order; he drinks alcohol daily, refuses to eat, and vents anger at his family. Most appropriate treatment?", "choices": ["Lorazepam", "Sertraline", "Haloperidol", "Risperidone", "Sodium valproate"], "ans": 1, "exp": "ภาวะซึมเศร้าหลังสูญเสีย (นอนไม่หลับ ไม่กินข้าว หงุดหงิด) -> รักษาด้วย SSRI (sertraline)", "sys": "V"}, {"topic": "Psychiatry", "q": "A 25-year-old man with dyspnea and palpitations while driving, feeling like dying, having to park for half an hour; no disease or drug use, normal exam and EKG. Most appropriate management?", "choices": ["Diazepam", "Alprazolam", "Fluoxetine (SSRI)", "Risperidone", "Valproate"], "ans": 2, "exp": "panic disorder -> first-line ระยะยาว SSRI (fluoxetine); benzodiazepine ใช้ระยะสั้นเท่านั้น", "sys": "V"}, {"topic": "Psychiatry", "q": "A 40-year-old developed confusion 1 day after appendectomy; he drinks rice wine daily for 10 years and has hand tremors. Most appropriate medication?", "choices": ["Haloperidol", "Amitriptyline", "Risperidone", "Diazepam", "Lorazepam"], "ans": 3, "exp": "สับสนหลังผ่าตัด + ประวัติดื่มสุราทุกวัน + มือสั่น = alcohol withdrawal (delirium tremens) -> benzodiazepine (diazepam) + thiamine", "sys": "V"}, {"topic": "Psychiatry", "q": "Palpitations, dizziness, and a feeling of impending death. Treatment? (ต้นฉบับมีตัวเลือกไม่ครบ ใส่เท่าที่มี)", "choices": ["Diazepam", "Methylphenidate", "Midazolam", "Sertraline (SSRI)"], "ans": 3, "exp": "panic disorder -> SSRI (sertraline) เป็นการรักษาหลักระยะยาว", "sys": "V"}, {"topic": "Psychiatry", "q": "A patient with obsessive-compulsive disorder. Treatment?", "choices": ["Sertraline (SSRI)", "Haloperidol", "Diazepam", "Sodium valproate", "Lithium"], "ans": 0, "exp": "OCD -> first-line คือ SSRI (sertraline, ขนาดมักสูงกว่าที่ใช้ในซึมเศร้า) + ERP therapy", "sys": "V"}, {"topic": "Community/EBM", "q": "A study on high-school sexual activity used two methods: face-to-face interview (10% reported activity) and a paper questionnaire (20%). What bias occurred?", "choices": ["Selection bias", "Social desirability bias", "Exclusion bias", "Attrition bias", "Recall bias"], "ans": 1, "exp": "หัวข้อละเอียดอ่อน (พฤติกรรมทางเพศ) ถูกรายงานต่ำกว่าจริงเมื่อสัมภาษณ์ต่อหน้า = social desirability bias", "sys": "general"}, {"topic": "Community/EBM", "q": "A meta-analysis of corticosteroids vs placebo in pneumonia. Which is the most beneficial outcome (largest absolute benefit)?", "choices": ["30-day mortality in severe pneumonia (ARR 6%, NNT 17)", "30-day mortality in non-severe pneumonia (ARR 0%)", "Prevention of shock (ARR 21%, NNT 5)", "Prevention of mechanical ventilation (ARR 3%, NNT 33)", "Hyperglycemia (NNH 11, harm)"], "ans": 2, "exp": "ประโยชน์มากสุด = ผลลัพธ์ที่มี absolute risk reduction สูงสุด/NNT ต่ำสุด = prevention of shock (ARR 21%, NNT 5)", "sys": "general"}, {"topic": "Community/EBM", "q": "Hypertension prevalence in a district is 30%. The hospital runs a low-salt diet promotion campaign. What type of prevention?", "choices": ["Primordial prevention", "Secondary prevention", "Tertiary prevention", "Primary prevention", "Quaternary prevention"], "ans": 3, "exp": "ส่งเสริมลดเค็มเพื่อป้องกันไม่ให้เกิดโรคความดันในผู้ที่ยังไม่ป่วย = primary prevention (health promotion ลดปัจจัยเสี่ยงในบุคคล)", "sys": "general"}, {"topic": "Community/EBM", "q": "A garment factory worker of 25 years with dyspnea worst on the first day of the week, improving on weekends. CXR: perihilar interstitial infiltration. Diagnosis?", "choices": ["Silicosis", "Asbestosis", "Melioidosis", "Hypersensitivity pneumonitis", "Byssinosis"], "ans": 4, "exp": "ฝุ่นฝ้าย (โรงงานสิ่งทอ) + อาการแน่นหน้าอกวันแรกของสัปดาห์ (Monday feeling) ดีขึ้นวันหยุด = byssinosis", "sys": "general"}, {"topic": "Community/EBM", "q": "A survey shows goiter prevalence of 15%. Which group should be screened for this disease?", "choices": ["School-age children", "Pre-school children", "Teenagers", "Pregnant women", "Elderly"], "ans": 0, "exp": "WHO ใช้ 'เด็กวัยเรียน (school-age)' เป็นกลุ่มดัชนีในการเฝ้าระวัง iodine deficiency/goiter ในประชากร", "sys": "general"}, {"topic": "Community/EBM", "q": "A 35-year-old woman, sexually inactive, no family history of ASCVD, eats healthily, exercises, non-smoker. Which is strongly recommended at periodic health examination?", "choices": ["Mammogram", "Blood pressure", "Pap smear", "Fasting blood sugar and lipid profile", "Stool occult blood test"], "ans": 1, "exp": "การวัดความดันโลหิตแนะนำสำหรับผู้ใหญ่ทุกคน (universal). mammogram/FBS-lipid/stool เป็น risk/age-based; Pap smear ในหญิงที่ยังไม่เคยมีเพศสัมพันธ์ความเสี่ยงต่ำ", "sys": "general"}, {"topic": "Forensic", "q": "A 20-year-old was assaulted with a baseball bat, sustaining a 5 cm scalp laceration. Two years later in court, a lawyer asks about the type of object. Most appropriate answer?", "choices": ["The patient was hit by a baseball bat", "The patient could be hit by a blunt or sharp object", "The patient sustained impact by a blunt object", "The exact object cannot be determined at all", "It was a sharp object"], "ans": 2, "exp": "แผลถลอก/ฉีก (laceration) เกิดจากแรงกระแทกของ 'ของแข็งไม่มีคม' (blunt object) -> ให้ความเห็นได้เพียงว่าเกิดจากของทื่อ ไม่สามารถระบุว่าเป็นไม้เบสบอลแน่นอน", "sys": "general"}, {"topic": "Forensic", "q": "At a burnt building, a male body has no burn wounds. Autopsy: dark red livor mortis, pink oral/upper-airway/laryngeal mucosa, no soot in the airway, serum CO undetectable. What should be told to police?", "choices": ["Cause of death is smoke inhalation", "Cause of death is laryngeal spasm", "Manner of death is natural", "The body was brought (dead) before the building burned", "Manner of death is homicide"], "ans": 3, "exp": "ไม่มีเขม่าในทางเดินหายใจ + CO ตรวจไม่พบ = ไม่ได้หายใจขณะเกิดไฟไหม้ -> เสียชีวิตก่อนไฟไหม้ (นำศพมาก่อน)", "sys": "general"}, {"topic": "Forensic", "q": "A man is found prone with a gun in his hand and a gunshot wound to the head. Which finding indicates a close/contact-range shot?", "choices": ["Marginal (abrasion) collar", "Gunpowder tattooing in the wound", "Contusion", "A gun in his hand", "Star-shaped (stellate) wound"], "ans": 4, "exp": "บาดแผลรูปดาว (stellate) จากแก๊สดันใต้ผิวเหนือกระดูก = contact/close-range wound (ร่วมกับ soot/muzzle imprint). gunpowder tattooing = intermediate range", "sys": "general"}, {"topic": "Forensic", "q": "A 20-year-old woman went to a pub, lost consciousness, and woke up in a hotel. Exam: elliptical marks and petechiae on the neck, a new hymen tear at 5 o'clock. Most appropriate action?", "choices": ["Test for sedative drug levels", "Notify the police", "Certify vaginal penetration occurred", "Certify that intercourse occurred", "Discharge with reassurance"], "ans": 0, "exp": "สงสัย drug-facilitated sexual assault -> เก็บหลักฐานที่ไวต่อเวลา คือตรวจระดับ sedative drug (ยานอนหลับ) ก่อนที่จะสลาย", "sys": "general"}, {"topic": "Forensic", "q": "A 25-year-old with a car accident (femur fracture and splenic rupture) had surgery and suddenly died 1 day later; his left calf was swollen and painful. What is the cause of death on the death certificate?", "choices": ["Splenic rupture", "Traffic accident", "Pulmonary embolism", "Fracture of femur", "Complication of surgery"], "ans": 1, "exp": "ใบมรณบัตรระบุ 'underlying cause' = เหตุการณ์แรกที่เริ่มลูกโซ่ = traffic accident (นำไปสู่กระดูกหัก/DVT -> PE -> เสียชีวิต)", "sys": "general"}, {"topic": "Forensic", "q": "A schoolgirl had fever and cough on Jan 3, was seen at a clinic on Jan 5 (tonsillitis, improved), then came to the hospital on Jan 7 requesting a medical certificate. What statement is appropriate?", "choices": ["Certify school leave Jan 3-7", "Certify school leave Jan 3-9", "Certify only the examination on January 7", "Certify school leave Jan 5-7", "Certify school leave Jan 7-9"], "ans": 2, "exp": "แพทย์ออกใบรับรองได้เฉพาะสิ่งที่ตรวจพบจริงในวันที่ตรวจ (Jan 7) เท่านั้น ไม่สามารถรับรองย้อนหลังวันที่ไม่ได้ตรวจ", "sys": "general"}, {"topic": "Forensic", "q": "A 20-year-old conscious, cooperative drunk patient after a traffic accident. Police request a blood alcohol test but the patient refuses. Most appropriate management?", "choices": ["Take blood alcohol for treatment purposes", "Send blood alcohol per the Criminal Procedure Code", "Ask police to use a breathalyzer instead", "State the patient's refusal in the medical record", "Do not send a blood alcohol test"], "ans": 3, "exp": "ผู้ป่วยรู้สึกตัวดีและมีสิทธิ์ปฏิเสธการตรวจที่ไม่ใช่เพื่อการรักษา -> เคารพการปฏิเสธและบันทึกการปฏิเสธไว้ในเวชระเบียน", "sys": "general"}, {"topic": "Forensic", "q": "A 14-year-old is brought by his father for illicit-drug testing without the boy's knowledge; he has warnings for skipping class, smoking, and drug use. Most proper management?", "choices": ["Perform urinalysis", "Getting to know the boy first", "Obtain informed consent from the father", "Refuse to test", "Inform the boy about the test before performing"], "ans": 4, "exp": "วัยรุ่นมีสิทธิ์ในการตัดสินใจ/ความยินยอม -> ต้องแจ้ง/ขอความยินยอมจากตัวเด็กก่อนตรวจ (ไม่ทำลับหลัง)", "sys": "general"}, {"topic": "Forensic", "q": "A 15-year-old with a ruptured ectopic pregnancy requested the doctor not to write 'ectopic pregnancy' in the record, so the doctor wrote 'intra-abdominal bleeding'. Which ethical principle is involved?", "choices": ["Confidentiality", "Beneficence", "Non-maleficence", "Truth telling", "Autonomy"], "ans": 0, "exp": "การปกป้องข้อมูลส่วนตัวของผู้ป่วยตามที่ผู้ป่วยร้องขอ = หลัก confidentiality (การรักษาความลับ)", "sys": "general"}, {"topic": "Forensic", "q": "A man diagnosed with HIV asks the doctor not to tell his wife. What should the doctor do? (ต้นฉบับมีตัวเลือกไม่ครบ ใส่เท่าที่มี)", "choices": ["Advise the patient to tell his wife himself", "Comply with the patient's request", "Tell the wife directly"], "ans": 0, "exp": "สมดุลระหว่างความลับผู้ป่วยกับความเสี่ยงของคู่ -> แนะนำ/สนับสนุนให้ผู้ป่วยเปิดเผยกับภรรยาด้วยตนเองก่อน (partner notification counseling)", "sys": "general"}]}, {"id": "nl2-2024", "title": "NL 2 ปี 2024 (VICHAKARN_SMST)", "subject": "past", "questions": [{"topic": "Internal medicine", "q": "A patient with a history of previous NSTEMI is being managed in the OPD. LDL cholesterol is 150 mg/dL. Which medication is most appropriate?", "choices": ["Atorvastatin 40 mg/day", "Metformin 1000 mg/day", "Simvastatin 20 mg/day", "Ezetimibe 10 mg/day", "Propanolol 120 mg/day"], "ans": 0, "exp": "ผู้ป่วยหลัง NSTEMI = secondary prevention -> ต้องการ high-intensity statin. Atorvastatin 40-80 mg เป็น high-intensity (ลด LDL >=50%). Simvastatin 20 เป็น moderate-intensity ไม่พอ; ezetimibe ใช้เสริมเมื่อ statin ไม่ถึงเป้า", "sys": "IX"}, {"topic": "Internal medicine", "q": "A 58-year-old man with T2DM, HT, DLP presents to ER with sudden dyspnea and anuria. BP 180/100, HR 110, RR 28, bilateral crackles. EKG shows peaked T-waves and widened QRS consistent with hyperkalemia. Most appropriate management?", "choices": ["Amiodarone", "Calcium gluconate", "Intravenous fluid loading", "Furosemide", "Cardioversion"], "ans": 1, "exp": "hyperkalemia ที่มี EKG เปลี่ยนแปลง (peaked T, wide QRS) = ภาวะฉุกเฉิน -> ให้ calcium gluconate ก่อนเพื่อ stabilize เยื่อหุ้มเซลล์กล้ามเนื้อหัวใจ แล้วค่อยลด K (insulin+glucose, ขับออก). *อ้างอิงภาพ EKG*", "img": "https://cdn.jsdelivr.net/gh/MercenzK/Web-quiz-images@main/NL2-2024-Q2.png", "sys": "IV"}, {"topic": "Internal medicine", "q": "A 30-year-old woman with sudden loss of consciousness while resting; had a prior LOC during an argument with complete recovery within minutes. BP 120/80 sitting, 110/75 standing, no carotid bruit, no murmur, normal neuro exam. Most appropriate management?", "choices": ["CT scan of brain", "Echocardiogram", "Tilt table test", "Holter monitoring", "EEG"], "ans": 2, "exp": "ลักษณะเป็น vasovagal (neurally mediated) syncope: มี trigger ทางอารมณ์ (ทะเลาะ) ฟื้นเร็ว ตรวจร่างกาย/หัวใจปกติ ไม่มี orthostatic drop ชัด -> ยืนยันด้วย tilt table test. ไม่ใช่ cardiac (echo/Holter) หรือ neuro (CT/EEG)", "sys": "VI"}, {"topic": "Internal medicine", "q": "A Thai male with T2DM, DLP presents with agitation, palpitation, chest pain. HR 100, BP stable. ECG obtained (shown). Given aspirin and clopidogrel. Appropriate next step of treatment?", "choices": ["Enoxaparin", "Metoprolol", "Nitrate", "Alteplase", "Atorvastatin"], "ans": 3, "exp": "ECG เข้าได้กับ STEMI -> หลัง antiplatelet ต้อง reperfusion ทันที ถ้าทำ primary PCI ไม่ได้ในเวลาให้ fibrinolysis (alteplase). *อ้างอิงภาพ ECG*", "img": "https://cdn.jsdelivr.net/gh/MercenzK/Web-quiz-images@main/NL2-2024-Q4.png", "sys": "IX"}, {"topic": "Internal medicine", "q": "A 65-year-old woman with T2DM, DLP developed palpitation, sweating, chest tightness 3 hours ago. Irregular pulse ~100, BP 110/70, normal S1S2 no murmur, lungs clear. ECG shown. Given aspirin and clopidogrel. Most proper next step?", "choices": ["Alteplase", "Atorvastatin", "Metoprolol", "Isosorbide dinitrate", "Enoxaparin"], "ans": 4, "exp": "ชีพจรไม่สม่ำเสมอ + เจ็บแน่นอกเฉียบพลัน 3 ชม. เข้าได้กับ NSTE-ACS (ECG ไม่มี ST elevation ชัด) -> หลัง dual antiplatelet ให้ anticoagulant (enoxaparin). ไม่ให้ fibrinolysis ใน NSTEMI. *อ้างอิงภาพ ECG*", "img": "https://cdn.jsdelivr.net/gh/MercenzK/Web-quiz-images@main/NL2-2024-Q5.png", "sys": "IX"}, {"topic": "Internal medicine", "q": "A 55-year-old man with 3-month intermittent chest tightness, pressure-like, on exertion and relieved by rest (HT, DLP). PE and vitals unremarkable. Office ECG normal. Most appropriate investigation to confirm the diagnosis?", "choices": ["Exercise stress test", "Coronary angiography", "Cardiac MRI", "CT coronary angiography", "Echocardiogram"], "ans": 0, "exp": "อาการ stable angina ทั่วไป + ECG ขณะพักปกติ -> ยืนยันด้วย exercise stress test (ตรวจ inducible ischemia) เป็นขั้นแรก. CAG เป็น invasive เก็บไว้เมื่อ stress test ผิดปกติหรือเสี่ยงสูง", "sys": "IX"}, {"topic": "Internal medicine", "q": "A 30-year-old woman with gradual DOE for 1 month, no chest pain/fever. PR 80 and totally irregular, RV heave 1+, loud S1, normal S2, grade III/VI diastolic rumbling murmur. Most likely diagnosis?", "choices": ["Atrial Septal Defect", "Mitral Stenosis", "Aortic Regurgitation", "Ruptured chordae tendineae", "Hypertrophic Cardiomyopathy"], "ans": 1, "exp": "loud S1 + diastolic rumbling murmur ที่ apex + AF (pulse irregular) + สัญญาณ pulmonary HT (RV heave) = mitral stenosis (มักจาก rheumatic). AR เป็น diastolic murmur แต่เป็น decrescendo ไม่ใช่ rumbling", "sys": "IX"}, {"topic": "Internal medicine", "q": "A 60-year-old man follow-up, well-controlled HT on thiazide, low-risk alcohol, no joint pain/stones. BMI 24, BP 130/75, no arthritis/tophi. Creatinine 0.8, uric acid 10. Most appropriate management?", "choices": ["Allopurinol", "Colchicine", "Switch thiazide to losartan", "Advise high-protein diet", "Advise weight reduction"], "ans": 2, "exp": "asymptomatic hyperuricemia ไม่ต้องให้ urate-lowering (allopurinol) หรือ colchicine. thiazide เพิ่มกรดยูริก -> เปลี่ยนเป็น losartan ซึ่งมีฤทธิ์ uricosuric ช่วยลดกรดยูริกและคุมความดันได้. อาหารโปรตีนสูงยิ่งแย่ *ดูคู่กับข้อ 9*", "sys": "XIII"}, {"topic": "Internal medicine", "q": "A 60-year-old man follow-up, well-controlled HT on thiazide, low-risk alcohol, no joint pain/stones. BMI 24, BP 130/75, no arthritis/tophi. Creatinine 0.8, uric acid 10. Most appropriate management?", "choices": ["Allopurinol", "Colchicine", "Advise weight reduction", "Continue current medications and monitor", "Switch thiazide to losartan"], "ans": 3, "exp": "asymptomatic hyperuricemia (ไม่มีเกาต์/นิ่ว) -> แนวทางคือไม่รักษาด้วยยา เพียงติดตาม. ในข้อนี้มีตัวเลือก 'continue and monitor' จึงเป็นคำตอบที่ถูกที่สุด *ดูคู่กับข้อ 8 ที่ไม่มีตัวเลือกติดตาม*", "sys": "XIII"}, {"topic": "Internal medicine", "q": "A 58-year-old woman with T2DM on enalapril 40 mg/day. BP 150/90, UA 3+ protein no sugar/RBC/WBC, FBS 120, HbA1c 6.5%, EKG shows LVH. Which antihypertensive should be added?", "choices": ["Hydrochlorothiazide", "Atenolol", "Losartan", "Verapamil", "Amlodipine"], "ans": 4, "exp": "คุม BP ไม่ได้ด้วย ACEI ขนาดสูงสุด -> เพิ่มยากลุ่มที่ใช้ร่วมได้ดี คือ CCB (amlodipine) หรือ thiazide; แนว ACCOMPLISH สนับสนุน ACEI+amlodipine ในผู้ป่วยเสี่ยงสูง. ไม่รวม ACEI+ARB (losartan). ในผู้ป่วยเบาหวาน amlodipine คุมความดันได้ดีและปลอดภัย", "sys": "IX"}, {"topic": "Internal medicine", "q": "A 35-year-old man check-up, father with early T2DM and IHD. BP 140/90, 90 kg, 175 cm, acanthosis nigricans. FBS 140, total cholesterol 300, LDL 190, HDL 30, AST 80, ALT 75. Most appropriate management?", "choices": ["Lifestyle modification", "Enalapril", "Simvastatin", "Metformin", "Fenofibrate"], "ans": 0, "exp": "ผู้ป่วย metabolic syndrome (อ้วน BMI 29, HT, dyslipidemia, ภาวะเบาหวาน, ตับอักเสบจาก NAFLD). การจัดการพื้นฐานและสำคัญที่สุดเป็นอันดับแรกคือ lifestyle modification (ลดน้ำหนัก อาหาร ออกกำลังกาย) ซึ่งแก้ได้หลายปัญหาพร้อมกัน ก่อน/ควบคู่การเริ่มยา", "sys": "IV"}, {"topic": "Internal medicine", "q": "A 48-year-old obese man health check-up, family history of diabetes. FBS 142, repeat 148. HbA1c 6.0%. Most appropriate management?", "choices": ["Repeat FBS, HbA1C in 6 months", "Metformin", "Exercise and lifestyle modification", "Sitagliptin", "Pioglitazone"], "ans": 1, "exp": "FBS >=126 สองครั้ง (142 และ 148) = วินิจฉัยเบาหวานแล้ว (ไม่ต้องรอ HbA1c) -> เริ่ม metformin เป็น first-line ควบคู่ปรับพฤติกรรม. การรอ 6 เดือนไม่เหมาะเพราะวินิจฉัยได้แล้ว", "sys": "IV"}, {"topic": "Internal medicine", "q": "A male chronic alcohol drinker with fever and foul-smelling sputum for 2 weeks. Crepitations in right upper lung. CXR provided. Most appropriate antibiotic treatment?", "choices": ["Ceftriaxone", "Azithromycin", "Amoxicillin-clavulanate", "Cotrimoxazole", "Isoniazid/Rifampicin/Pyrazinamide/Ethambutol"], "ans": 2, "exp": "ดื่มสุราเรื้อรัง + เสมหะเหม็น (foul-smelling) + ฝีในปอด/aspiration = เชื้อ anaerobe -> amoxicillin-clavulanate (หรือ clindamycin) ครอบคลุม anaerobe. *อ้างอิงภาพ CXR*", "img": "https://cdn.jsdelivr.net/gh/MercenzK/Web-quiz-images@main/NL2-2024-Q13.png", "sys": "flex"}, {"topic": "Internal medicine", "q": "A 70-year-old female with fever, dyspnea, productive cough for 3 days, no underlying disease. CXR shown. Most appropriate antibiotic treatment?", "choices": ["Cefotaxime", "Ceftazidime", "Piperacillin/Tazobactam", "Ceftriaxone + Clarithromycin", "Imipenem"], "ans": 3, "exp": "community-acquired pneumonia ที่ต้อง admit -> beta-lactam (ceftriaxone) + macrolide (clarithromycin) ครอบคลุม typical + atypical. ยากลุ่ม antipseudomonal (ceftazidime/pip-tazo/imipenem) ไม่จำเป็นในผู้ป่วยไม่มีปัจจัยเสี่ยง. *อ้างอิงภาพ CXR*", "img": "https://cdn.jsdelivr.net/gh/MercenzK/Web-quiz-images@main/NL2-2024-Q14.png", "sys": "X"}, {"topic": "Internal medicine", "q": "A 70-year-old male with fever and dyspnea 3 days. T 38, PR 130, RR 30, BP 140/90, SpO2 95% on 10 LPM mask with bag. Bronchial breath sounds and fine crepitations right lower lung. Most appropriate antibiotic treatment?", "choices": ["Cefotaxime", "Ciprofloxacin", "Levofloxacin", "Piperacillin + Tazobactam", "Ceftriaxone + Clarithromycin"], "ans": 4, "exp": "severe CAP (RR สูง ต้องใช้ O2 flow สูง) -> beta-lactam + macrolide (ceftriaxone + clarithromycin) เป็น regimen มาตรฐานครอบคลุม typical + atypical/Legionella", "sys": "X"}, {"topic": "Internal medicine", "q": "A 28-year-old man with fever, dry cough, DOE, weight loss for 10 days, chronic alcohol abuse. T 38, PR 100, RR 30, SpO2 85% room air, oral thrush, pale conjunctiva, papular eruption, cervical lymphadenopathy. CXR bilateral diffuse interstitial infiltration. Most proper management?", "choices": ["Co-trimoxazole", "IRZE regimen", "Ceftriaxone", "Azithromycin", "Amphotericin B"], "ans": 0, "exp": "ภาพรวมเข้าได้กับ HIV (thrush, น้ำหนักลด, ผื่น, ต่อมน้ำเหลืองโต) + Pneumocystis jirovecii pneumonia (PCP): SpO2 ต่ำมาก + interstitial infiltration ทั้งสองข้าง -> รักษาด้วย high-dose co-trimoxazole (+ steroid ถ้า PaO2 ต่ำ)", "sys": "I"}, {"topic": "Internal medicine", "q": "A 62-year-old man with chronic dry cough 3 months, no fever/weight loss, smoking 1 pack/day for 30 years. Wheezing in left middle lung zone. CXR shown. Most likely diagnosis?", "choices": ["Thymoma", "Lung cancer", "Lymphoma", "Tuberculosis", "Germ cell tumor"], "ans": 1, "exp": "สูบบุหรี่หนัก 30 pack-years + ไอเรื้อรัง + wheeze เฉพาะที่ (localized -> จาก endobronchial mass อุดหลอดลม) = lung cancer จนกว่าจะพิสูจน์เป็นอื่น. *อ้างอิงภาพ CXR*", "img": "https://cdn.jsdelivr.net/gh/MercenzK/Web-quiz-images@main/NL2-2024-Q17.png", "sys": "II"}, {"topic": "Internal medicine", "q": "A 25-year-old man with swelling of face and chest wall for 2 weeks. PR 100, RR 30. Edema of face/arms/chest wall (SVC obstruction), gynecomastia, impalpable nodes, no hepatosplenomegaly. Most likely diagnosis?", "choices": ["Thymoma", "Lymphoma", "Germ cell tumor", "Lung cancer", "Tuberculoma"], "ans": 2, "exp": "ชายอายุน้อย + ก้อน mediastinum ส่วนหน้าทำให้เกิด SVC obstruction + gynecomastia (จาก beta-hCG) = germ cell tumor (mediastinal). อายุน้อยเกินไปสำหรับ lung cancer; ไม่มีต่อมน้ำเหลืองโตทำให้ lymphoma น้อยลง", "sys": "II"}, {"topic": "Internal medicine", "q": "A 56-year-old man with COPD and ischemic cardiomyopathy visits for frequent COPD exacerbations. Still smokes 20 cigarettes/day after being advised to stop. What intervention should be done next?", "choices": ["Arrange more frequent follow-up visits.", "Advise him to stop smoking immediately.", "Arrange an appointment at the smoking cessation clinic.", "Assess the patient's reason to smoke.", "Order him nicotine gum to help stop smoking."], "ans": 3, "exp": "ผู้ป่วยยังสูบต่อแม้แนะนำแล้ว -> ตามหลัก 5A/motivational interviewing ขั้นต่อไปคือประเมินเหตุผล/ความพร้อมในการเลิก (assess) เพื่อวางแผนที่เหมาะสม การพูดซ้ำ 'ให้เลิกทันที' ไม่ได้ผล; ยา/ส่งคลินิกตามมาเมื่อผู้ป่วยพร้อม", "sys": "IX"}, {"topic": "Internal medicine", "q": "A 40-year-old man with large varicose veins on his abdomen and chest, progressive swelling over months, occasional dyspnea and fatigue, prominent venous patterns on chest and abdomen. Next appropriate investigation?", "choices": ["Electrocardiogram", "Bronchoscopy", "Laryngoscopy", "Colonoscopy", "Chest X-ray"], "ans": 4, "exp": "หลอดเลือดดำโป่งพองที่ผนังหน้าอก/ท้อง + บวม + เหนื่อย = SVC obstruction (มี venous collateral) มักจากก้อนใน mediastinum -> ตรวจ chest X-ray เป็นขั้นแรกเพื่อหาก้อน/mass", "sys": "IX"}, {"topic": "Internal medicine", "q": "A 65-year-old man with HBV cirrhosis presents with massive hematemesis, no alcohol use, stable vitals, pale conjunctivae, signs of chronic liver disease. Besides NSS resuscitation and PPI, what is the other initial management?", "choices": ["Intravenous somatostatin", "Intravenous tranexamic acid", "Sengstaken-Blakemore tube insertion", "Esophagogastroduodenoscopy", "Blood transfusion"], "ans": 0, "exp": "เลือดออกจาก esophageal varices (cirrhosis) -> ให้ vasoactive drug (somatostatin/octreotide) เพื่อลดแรงดัน portal ทันทีตั้งแต่แรก ร่วมกับ antibiotic prophylaxis; EGD เพื่อ band ligation ทำภายใน 12 ชม. SB tube เป็นทางเลือกสุดท้ายเมื่อคุมไม่ได้", "sys": "III"}, {"topic": "Internal medicine", "q": "A 65-year-old man with HBV cirrhosis, massive hematemesis, no alcohol, stable vitals, pale conjunctivae, varicose veins and telangiectasia on trunk/abdomen. Besides IV fluid, other appropriate initial management?", "choices": ["Recombinant factor VII", "Intravenous somatostatin", "Proton pump inhibitor", "Esophagogastroduodenoscopy", "Sengstaken-Blakemore tube insertion"], "ans": 1, "exp": "variceal bleeding -> vasoactive drug (IV somatostatin) เป็นการรักษาเบื้องต้นที่สำคัญที่สุดร่วมกับการกู้ชีพ ก่อนทำ EGD; rFVIIa ไม่มีที่ใช้ประจำ", "sys": "VII"}, {"topic": "Internal medicine", "q": "A woman with cryptogenic liver cirrhosis, lost follow-up 4 months. Last US, CBC, BUN, Cr, LFT unremarkable. Last EGD 4 years ago showed no varices. Spider nevi and palmar erythema. Most appropriate management?", "choices": ["Ultrasound of the upper abdomen", "Alpha-fetoprotein (AFP)", "Esophagogastroduodenoscopy (EGD)", "HBsAg and anti-HCV", "Triple phase computed tomography"], "ans": 2, "exp": "ผู้ป่วย cirrhosis ที่เคย EGD ไม่พบ varices ควรทำ surveillance EGD ซ้ำทุก 2-3 ปี; ครั้งนี้ห่างไป 4 ปีถือว่าเกินกำหนด -> ทำ EGD. (US/AFP สำหรับ HCC ทุก 6 เดือน แต่ US ล่าสุดปกติแล้ว) *ดูคู่กับข้อ 24*", "sys": "XI"}, {"topic": "Internal medicine", "q": "A middle-aged man with cryptogenic cirrhosis lost follow-up 4 months. 4 months ago CBC/LFT normal; US of upper abdomen and EGD done 3 years ago showed no varices. Appropriate investigation this visit?", "choices": ["Esophagogastroduodenoscopy (EGD)", "Liver function tests (LFT)", "Alpha-fetoprotein (AFP)", "Ultrasound of the upper abdomen", "Colonoscopy"], "ans": 3, "exp": "HCC surveillance ในผู้ป่วย cirrhosis ต้องทำ ultrasound ทุก 6 เดือน; ครั้งนี้ US ครั้งสุดท้าย 3 ปีก่อน ถือว่าเกินกำหนดมาก -> ทำ ultrasound upper abdomen. (EGD ไม่พบ varices ทำซ้ำทุก 2-3 ปี) *ดูคู่กับข้อ 23*", "sys": "XI"}, {"topic": "Internal medicine", "q": "A 30-year-old man with nausea and vomiting, drinking 1-2 bottles of whiskey daily for 10 years, took paracetamol 2 tabs 4 times/day for headache 1 week ago. BT 37, mild pallor, jaundice, spider angioma, palmar erythema, hepatomegaly, mild RUQ tenderness, no ascites. Most likely diagnosis?", "choices": ["Acute pancreatitis", "Acute viral hepatitis B", "Ascending cholangitis", "Alcoholic intoxication", "Acetaminophen toxicity"], "ans": 4, "exp": "ผู้ติดสุราเรื้อรัง (glutathione พร่อง) ได้ paracetamol ~4 g/วัน นาน 1 สัปดาห์ -> เกิด acetaminophen hepatotoxicity แม้ขนาดที่ปกติถือว่าปลอดภัย. อาการดีซ่าน + ตับโต + RUQ เข้าได้", "sys": "VI"}, {"topic": "Internal medicine", "q": "A 60-year-old man with HBV cirrhosis presents with alteration of consciousness 2 hours PTA, no fever/abdominal pain/hematemesis. Drowsiness, disorientation to time-place-person, asterixis. Initial management?", "choices": ["Lactulose", "NG lavage", "Tramadol", "Ceftriaxone", "Benzodiazepines"], "ans": 0, "exp": "drowsy + disorientation + asterixis ใน cirrhosis = hepatic encephalopathy -> รักษาด้วย lactulose (ลดการดูดซึม/สร้างแอมโมเนีย). หลีกเลี่ยง benzodiazepine/tramadol ที่กดประสาท", "sys": "XI"}, {"topic": "Internal medicine", "q": "A 55-year-old male with jaundice for 1 week, now fever/chills and RUQ pain for 1 day, alcohol 10 years. BT 39, PR 130, RR 24, BP 90/50, marked icteric sclerae, RUQ tenderness. TB 9.3 DB 8.2 AST 300 ALT 200 ALP 255, HBsAg positive. Most likely diagnosis?", "choices": ["Alcoholic hepatitis", "Acute cholangitis", "Acute cholecystitis", "Liver abscess", "Fulminant viral hepatitis"], "ans": 1, "exp": "Charcot triad (ไข้ + ดีซ่าน + ปวด RUQ) + ความดันตก (septic) = acute cholangitis (Reynolds pentad ถ้ามี AMS/hypotension). DB เด่น (obstructive pattern) สนับสนุนการอุดตันทางเดินน้ำดี", "sys": "I"}, {"topic": "Internal medicine", "q": "A 45-year-old with severe epigastric pain radiating to back, relieved leaning forward. T 38, RR 28, PR 120. Normal breath sounds. HCT 38%, WBC 1,400, platelets 400,000, amylase 2,000, BUN 20, Cr 0.9, AST 70, ALT 65, ALP 130, TB 2.5. Which indicates severity?", "choices": ["BUN level", "Amylase", "Systemic Inflammatory Response Syndrome (SIRS)", "Hematocrit", "Agitation"], "ans": 2, "exp": "acute pancreatitis: ความรุนแรงประเมินจาก SIRS/organ failure ไม่ใช่ระดับ amylase (สูงแค่ไหนไม่บอกความรุนแรง). ผู้ป่วยมี SIRS (T สูง, RR>20, PR>90, WBC ผิดปกติ) = บ่งความรุนแรง", "sys": "I"}, {"topic": "Internal medicine", "q": "A 70-year-old man with T2DM diagnosed with acute cholangitis. Initial BP 80/60. After NSS 500 ml over 15 min: BP 80/60, PR 120, RR 20, JVP 1 cm, no adventitious breath sounds. Most appropriate management?", "choices": ["Dopamine intravenous", "Dobutamine intravenous", "5% Albumin infusion", "NSS 500 ml in 15 minutes", "IV hydrocortisone"], "ans": 3, "exp": "septic shock ที่ยัง hypovolemic (JVP ต่ำ 1 cm, ไม่มี crackles) และยังตอบสนองต่อสารน้ำ -> ให้ crystalloid (NSS) ต่อจนพอ ก่อนพิจารณา vasopressor. Dopamine/norepinephrine ใช้เมื่อ fluid พอแล้วยังช็อก", "sys": "I"}, {"topic": "Internal medicine", "q": "A 70-year-old female with new-onset epigastric pain and postprandial fullness for 4 months without weight loss or alarm features. Most appropriate management?", "choices": ["Prokinetic agent", "CT abdomen", "Lifestyle modification", "Proton Pump Inhibitor (PPI)", "Esophagogastroduodenoscopy (EGD)"], "ans": 4, "exp": "dyspepsia ที่เริ่มใหม่ในผู้สูงอายุ (อายุ >50-55 ปี) ถือเป็น alarm feature ในตัวเอง -> ต้องส่อง EGD เพื่อ exclude มะเร็งกระเพาะ ไม่ควรรักษาแบบ empirical อย่างเดียว", "sys": "XI"}, {"topic": "Internal medicine", "q": "A 20-year-old man with epigastric pain for 4 months, lasts 30 minutes and resolves spontaneously, not relieved by defecation, no diarrhea/constipation/weight loss/nocturnal pain. Most appropriate treatment?", "choices": ["Proton pump inhibitor", "Psychotherapy", "Lactose restriction", "Smooth muscle relaxant", "Triple-drug regimen for H. pylori"], "ans": 0, "exp": "อายุน้อย ไม่มี alarm feature + ปวด epigastrium = functional dyspepsia (epigastric pain syndrome) -> เริ่มด้วย PPI เป็น first-line (หรือ test-and-treat H. pylori ในพื้นที่ชุก). ไม่ใช่ IBS เพราะไม่สัมพันธ์การถ่าย", "sys": "XI"}, {"topic": "Internal medicine", "q": "A 35-year-old female with diarrhea, abdominal pain, burping, bloating, loose stools for 2 years, no weight loss/red flags, symptoms since changing workplace. Normal PE and EGD. Most likely diagnosis?", "choices": ["Functional dyspepsia", "Irritable Bowel Syndrome (IBS)", "Functional diarrhea", "Inflammatory Bowel Disease (IBD)", "Somatic symptom disorder"], "ans": 1, "exp": "ปวดท้องเรื้อรัง + ท้องเสีย/ถ่ายเหลว สัมพันธ์กับความเครียด (เปลี่ยนที่ทำงาน) ไม่มี red flag ตรวจปกติ = irritable bowel syndrome (IBS-D). Functional diarrhea ไม่มีอาการปวด", "sys": "XI"}, {"topic": "Internal medicine", "q": "A 48-year-old male with DM, HT, DLP had right cerebral infarction 4 months ago with full recovery, well-controlled since. Recurrent stroke 1 hour ago. BP 160/90, left-sided weakness. What should be done to prevent another recurrent stroke?", "choices": ["Add enalapril", "Double dose aspirin", "Carotid angioplasty and stenting", "Add EPA", "Smoking cessation program"], "ans": 2, "exp": "stroke ซ้ำใน territory เดิม (R hemisphere -> อ่อนแรงซ้าย) ทั้งที่คุมปัจจัยเสี่ยงและกิน aspirin ดี ชี้ว่ามี embolic source จาก carotid stenosis ข้างเดียวกัน -> ประเมินและรักษาด้วย carotid endarterectomy/stenting. การเพิ่มขนาด aspirin ไม่ช่วยและเพิ่มเลือดออก", "sys": "VI"}, {"topic": "Internal medicine", "q": "A 30-year-old woman with bilateral ptosis, binocular diplopia, dysarthria, weakness, and fatigability on sustained upper gaze and arm abduction for 3 weeks. Proximal muscle weakness, normal DTR. Most useful investigation?", "choices": ["Muscle biopsy", "Electromyography", "Nerve conduction study", "Repetitive nerve stimulation test", "Serum CPK level"], "ans": 3, "exp": "อ่อนแรงมากขึ้นเมื่อใช้งานซ้ำ (fatigability) + ptosis/diplopia + DTR ปกติ = myasthenia gravis -> ตรวจ repetitive nerve stimulation (พบ decremental response) หรือ anti-AChR antibody", "sys": "VI"}, {"topic": "Internal medicine", "q": "A 60-year-old man with untreated HT 10 years, sudden difficulty speaking with impaired fluency but preserved comprehension and repetition. EKG totally irregular, CT shows wedge-shaped infarction in inferior frontal lobe. Most likely etiology?", "choices": ["Lipohyalinosis", "Atherosclerotic plaque emboli", "Large vessel infarction", "Small vessel disease", "Cardiac emboli"], "ans": 4, "exp": "EKG irregular = atrial fibrillation + CT พบ infarct รูปลิ่ม (wedge, cortical) = cardioembolic stroke จาก AF. Lipohyalinosis/small vessel ทำให้เกิด lacunar (subcortical) ไม่ใช่ cortical wedge", "sys": "VI"}, {"topic": "Internal medicine", "q": "A 35-year-old construction worker with deteriorating weakness for 2 weeks, chronic alcohol and cannabis use. BMI 18, spider nevi, palmar erythema, ascites, disoriented, motor grade III/V all, areflexia, paresthesia of hands and feet, pupil 2 mm RTL. Most likely diagnosis?", "choices": ["Thiamine deficiency", "Periodic paralysis", "Myasthenia gravis", "Alcoholic myopathy", "Cannabis intoxication"], "ans": 0, "exp": "ผู้ติดสุรา ขาดอาหาร (BMI 18) + สับสน + peripheral neuropathy (areflexia, paresthesia) = thiamine (B1) deficiency (Wernicke encephalopathy + beriberi/polyneuropathy). Alcoholic myopathy ไม่มี areflexia/paresthesia", "sys": "VI"}, {"topic": "Internal medicine", "q": "A 28-year-old man with 6 weeks of low-grade fever, fatigue, weakness, difficulty climbing stairs and combing hair. Purple rash on both eyelids, proximal weakness grade III, distal normal, sensory intact, DTR 2+, no ptosis. Most likely diagnosis?", "choices": ["Periodic paralysis", "Dermatomyositis", "Myasthenia Gravis (MG)", "Systemic sclerosis", "Polymyositis"], "ans": 1, "exp": "proximal muscle weakness + heliotrope rash (ผื่นม่วงที่หนังตาทั้งสองข้าง) = dermatomyositis. ถ้าไม่มีผื่นจะเป็น polymyositis; ที่นี่มีผื่นชัดจึงเป็น dermatomyositis", "sys": "VI"}, {"topic": "Internal medicine", "q": "A 30-year-old man in hospital wakes up unable to get out of bed with weakness in all extremities. Alert, quadriparesis with proximal weakness, lower > upper extremities, no respiratory distress. Most appropriate investigation?", "choices": ["Cerebrospinal fluid (CSF) examination", "CT scan of the brain", "Serum electrolytes", "Nerve conduction studies", "MRI of the cervical spine"], "ans": 2, "exp": "อ่อนแรงเฉียบพลันตอนตื่นนอน quadriparesis เด่นส่วนต้น = hypokalemic periodic paralysis -> ตรวจ serum electrolytes (โพแทสเซียม) เป็นอันดับแรก รักษาได้ทันที", "sys": "IV"}, {"topic": "Internal medicine", "q": "A 50-year-old male with 2-year history of hand shaking, difficulty picking up objects and using utensils, improves with alcohol, mother has similar symptom. PR 64, BP 120/70, full EOM no nystagmus, tremor in both hands when stretching arms, no cerebellar signs, normal gait. Most appropriate management?", "choices": ["Levodopa", "Lorazepam", "Amitriptyline", "Propranolol", "Trihexyphenidyl"], "ans": 3, "exp": "postural tremor สองข้าง ดีขึ้นเมื่อดื่มแอลกอฮอล์ + มีประวัติครอบครัว = essential tremor -> ยาตัวแรกคือ propranolol (beta-blocker) หรือ primidone", "sys": "flex"}, {"topic": "Internal medicine", "q": "A 55-year-old man with 3-year hand tremor when picking up objects, improves after alcohol, mother has similar tremor. Intention/action tremor worsening as he reaches a target. Most appropriate management?", "choices": ["Diazepam", "Gabapentin", "Amitriptyline", "Trihexyphenidyl", "Propranolol"], "ans": 4, "exp": "essential tremor (action tremor, ประวัติครอบครัว, ดีขึ้นกับแอลกอฮอล์) -> ยาตัวแรก propranolol. ไม่ใช่ Parkinson (จึงไม่ใช้ levodopa/trihexyphenidyl)", "sys": "VI"}, {"topic": "Internal medicine", "q": "A 25-year-old man cannot get up from bed this morning, recurrent over 3 months. BP 150/90, PR 100, moist skin, fine tremor both hands, motor grade II proximal, DTR 2+. Na 139, K 2.5, Cl 102, HCO3 20, BUN 16, Cr 0.8. Most likely diagnosis?", "choices": ["Periodic paralysis", "Polymyositis", "Polyneuropathy", "Myasthenia gravis (MG)", "Guillain-Barre syndrome (GBS)"], "ans": 0, "exp": "อ่อนแรงเป็นพัก ๆ + K ต่ำ (2.5) + อาการ thyrotoxic (เหงื่อออก มือสั่น ชีพจรเร็ว ความดันสูง) = thyrotoxic periodic paralysis (hypokalemic periodic paralysis). แก้โพแทสเซียมและภาวะไทรอยด์เป็นพิษ", "sys": "VI"}, {"topic": "Internal medicine", "q": "A 30-year-old man with fever and runny nose for 5 days, then difficulty urinating and weakness of both legs for 3 days. Loose anal sphincter tone, decreased tone and power grade II/IV both legs, sensory loss up to umbilicus, absent knee and ankle reflexes, bilateral plantar extension. Most likely diagnosis?", "choices": ["Polymyositis", "Acute transverse myelitis", "Poliomyelitis", "Myasthenia gravis", "Guillain barre syndrome"], "ans": 1, "exp": "มี sensory level ชัด (ระดับสะดือ = T10) + เสียการควบคุมหูรูด (bladder/bowel) + UMN sign (plantar extension) หลังติดเชื้อ = acute transverse myelitis. GBS จะไม่มี sensory level และหูรูดปกติในระยะแรก", "sys": "VI"}, {"topic": "Internal medicine", "q": "A 40-year-old woman with leg weakness for 3 days, gait difficulty then progressive. Absent gag reflex, symmetrical proximal weakness grade 3, loss of proprioception bilateral fingers/toes, generalized areflexia, clonus negative, plantarflexion. Most useful investigation?", "choices": ["EEG", "Serum electrolyte", "CSF analysis", "MRI spine", "Tensilon test"], "ans": 2, "exp": "อ่อนแรงขึ้นเรื่อย ๆ แบบ ascending + areflexia + involve cranial nerve (gag หาย) = Guillain-Barre syndrome -> CSF analysis พบ albuminocytologic dissociation (โปรตีนสูง เซลล์ปกติ)", "sys": "IV"}, {"topic": "Internal medicine", "q": "A 25-year-old male with drooping and weakness on the left side of his face. Normal vitals. Weakness of orbicularis oculi and orbicularis oris, normal ear examination, otherwise normal. Most proper management?", "choices": ["Observation", "Gabapentin", "Oral Acyclovir", "Prednisolone", "Vitamin B complex"], "ans": 3, "exp": "อ่อนแรงใบหน้าครึ่งซีกครบทั้งใบ (รวมหน้าผาก = LMN) หูปกติ = Bell's palsy -> ให้ prednisolone (corticosteroid) ภายใน 72 ชม. ช่วยการฟื้นตัว", "sys": "flex"}, {"topic": "Internal medicine", "q": "A 40-year-old with intermittent mild-to-moderate tension-like tightness headaches, typically in the afternoon, unresponsive to paracetamol. Most appropriate management?", "choices": ["Propranolol", "Flunarizine", "Ibuprofen", "Cognitive-behavioral therapy", "Amitriptyline"], "ans": 4, "exp": "tension-type headache ที่เป็นบ่อยและไม่ตอบสนองยาแก้ปวด -> ยาป้องกันตัวแรกคือ amitriptyline (TCA). propranolol/flunarizine ใช้ป้องกันไมเกรน", "sys": "VI"}, {"topic": "Internal medicine", "q": "A 30-year-old woman with intermittent headache 3 months over left frontal/orbital/temporal, each episode ~6 hours then resolves, with nausea. Normal exam, no papilledema/deficits. Most appropriate preventive medication?", "choices": ["Amitriptyline", "Triptans", "Ergotamine", "Ibuprofen", "Paracetamol"], "ans": 0, "exp": "ปวดศีรษะข้างเดียว + คลื่นไส้ = migraine. คำถามถามยา 'ป้องกัน' -> amitriptyline (หรือ propranolol/topiramate). triptan/ergotamine/NSAID เป็นยาแก้ปวดเฉียบพลันไม่ใช่ยาป้องกัน", "sys": "VI"}, {"topic": "Internal medicine", "q": "A 25-year-old woman with intermittent severe headaches with photophobia for 3 months, unilateral temporal and occipital, lasting 4-24 hours, self-resolving, aggravated by physical activity. Proper management?", "choices": ["Amlodipine", "NSAIDs", "ESR and CRP", "Lumbar puncture (LP)", "CT scan of the brain with contrast"], "ans": 1, "exp": "ลักษณะ migraine ชัด (ข้างเดียว กลัวแสง ปวดมากขึ้นเมื่อขยับ) ไม่มี red flag -> รักษาอาการเฉียบพลันด้วย NSAIDs ไม่ต้องส่งภาพสมอง/เจาะหลัง", "sys": "I"}, {"topic": "Internal medicine", "q": "A 30-year-old woman with intermittent severe headaches for 2 years, with vomiting and photophobia, unilateral. Normal neurological examination. Most appropriate management?", "choices": ["ESR and CRP", "CT scan of the brain with contrast", "NSAIDs", "Lumbar puncture (LP)", "Amlodipine"], "ans": 2, "exp": "migraine เรื้อรัง 2 ปี ตรวจ neuro ปกติ ไม่มี red flag -> ไม่ต้อง imaging; รักษาอาการด้วย NSAIDs (หรือ triptan). การส่ง CT/LP ทำเมื่อมีสัญญาณอันตราย", "sys": "I"}, {"topic": "Internal medicine", "q": "A 30-year-old man with two generalized tonic-clonic seizures (1 month and 1 week ago). History of carbamazepine-induced rash. All investigations including neuroimaging normal. Most appropriate prevention for recurrent seizures?", "choices": ["Phenytoin", "Clonazepam", "Phenobarbital", "Valproic acid", "Ketogenic diet"], "ans": 3, "exp": "seizure 2 ครั้ง = epilepsy ต้องเริ่มยากันชัก. เคยแพ้ carbamazepine (aromatic AED) -> เลี่ยง phenytoin/phenobarbital ที่ cross-react -> เลือก valproic acid (broad spectrum, ไม่ใช่ aromatic)", "sys": "VI"}, {"topic": "Internal medicine", "q": "A 35-year-old man with generalized tonic-clonic convulsions and headache. T 36.8, PR 110, RR 18, BP 110/70. No sensory/motor deficit, neck not stiff, bilateral papilledema. CT brain shows multiple calcified cystic lesions. Most likely etiologic organism?", "choices": ["Ascaris lumbricoides", "Mycobacterium tuberculosis", "Pseudomonas aeruginosa", "Gnathostoma spinigerum", "Taenia solium"], "ans": 4, "exp": "หลาย cystic lesion ที่มี calcification ในสมอง + ชัก = neurocysticercosis จากตัวอ่อนพยาธิตืดหมู Taenia solium", "sys": "I"}, {"topic": "Internal medicine", "q": "A 40-year-old female with confusion for 1 day and fever for 3 days. CT brain shows hypodense lesion in left temporal lobe. CSF: WBC 90 (100% lymphocytes), RBC 10, glucose 80 (blood 120), protein 60. Most appropriate treatment?", "choices": ["Acyclovir", "Ceftriaxone", "Vancomycin", "Amphotericin B", "Dexamethasone"], "ans": 0, "exp": "temporal lobe involvement + CSF lymphocyte เด่น + มี RBC (hemorrhagic) + น้ำตาลปกติ = herpes simplex encephalitis -> ให้ IV acyclovir ทันที (อย่ารอผล PCR)", "sys": "VI"}, {"topic": "Internal medicine", "q": "A 50-year-old man with fever and severe headache 2 days. T 40, HR 100, RR 24, BP 130/85, conscious. Left-sided sensorineural hearing loss. LP: OP 24, cloudy CSF, WBC 1500 (90% PMN), protein 500, glucose 10 (serum 90). Most likely causative organism?", "choices": ["Naegleria fowleri", "Streptococcus suis", "Neisseria meningitidis", "Streptococcus pneumoniae", "Listeria monocytogenes"], "ans": 1, "exp": "bacterial meningitis (CSF ขุ่น, PMN เด่น, น้ำตาลต่ำมาก) + สูญเสียการได้ยิน (sensorineural hearing loss) เป็นลักษณะเด่นของ Streptococcus suis ซึ่งพบบ่อยในไทย (สัมพันธ์กินหมูดิบ/เลือดดิบ)", "sys": "VI"}, {"topic": "Internal medicine", "q": "A 40-year-old man with low-grade fever and malaise 7 days, then behavior changes progressing to fluctuating hyperactivity, throat discomfort when drinking and salivary expulsion. Agitated, pupils 4 mm reactive, no neck stiffness, no wounds. Most likely diagnosis?", "choices": ["Neurosyphilis", "Herpes", "Rabies", "Japanese Encephalitis (JE)", "Enterovirus"], "ans": 2, "exp": "กลัวน้ำ/สำลักเมื่อดื่ม (hydrophobia) + น้ำลายมาก + สับสนกระวนกระวายเป็นพัก ๆ = rabies (encephalitic form). อาการ hydrophobia จำเพาะกับพิษสุนัขบ้า", "sys": "I"}, {"topic": "Internal medicine", "q": "An 80-year-old male with acute confusion, urinary retention, and constipation for 1 day, treated for acute rhinorrhea 1 week ago. Stable vitals, dry skin and mydriasis. Which medication most likely causes these symptoms?", "choices": ["Acetaminophen", "Ibuprofen", "Amoxicillin", "Chlorpheniramine", "Bromhexine"], "ans": 3, "exp": "กลุ่มอาการ anticholinergic (สับสน ปัสสาวะคั่ง ท้องผูก ผิวแห้ง รูม่านตาขยาย) ในผู้สูงอายุ -> จากยาแก้แพ้ chlorpheniramine (antihistamine รุ่นเก่า มีฤทธิ์ anticholinergic)", "sys": "XI"}, {"topic": "Internal medicine", "q": "A 40-year-old man with confusion for 2 days, drinking one bottle of alcohol almost daily since age 30. Stable vitals, parotid gland enlargement, disoriented to time/place/person, nystagmus and ataxia. Most likely diagnosis?", "choices": ["Delirium", "Delirium tremens", "Chronic subdural hematoma", "Alcohol withdrawal syndrome", "Wernicke encephalopathy"], "ans": 4, "exp": "triad: confusion + nystagmus/ophthalmoplegia + ataxia ในผู้ติดสุรา = Wernicke encephalopathy (ขาด thiamine) -> ให้ thiamine ก่อนกลูโคส", "sys": "V"}, {"topic": "Internal medicine", "q": "A 50-year-old man with swelling of both legs for 2 weeks, taking OTC medication for knee pain, no underlying disease. BP 130/80, mild leg swelling. Cr 3.0, urine SG 1.010, UA protein 1+, WBC 10-20/HPF (eosinophils), RBC 2-3/HPF. Most likely diagnosis?", "choices": ["Acute interstitial nephritis", "Nephrotic syndrome", "Acute papillary necrosis", "Acute tubular necrosis", "Acute glomerulonephritis"], "ans": 0, "exp": "ไตวายเฉียบพลัน + eosinophiluria (WBC ในปัสสาวะเป็น eosinophil) หลังใช้ NSAIDs = acute interstitial nephritis (AIN). โปรตีนรั่วน้อย (1+) ไม่เข้ากับ nephrotic", "sys": "I"}, {"topic": "Internal medicine", "q": "A female with DM and CKD presents with anginal chest pain; cardiac catheterization is planned. Most appropriate regimen for preventing contrast-induced nephropathy?", "choices": ["Intravenous dopamine", "Normal saline (NSS) infusion", "Intravenous sodium bicarbonate", "Oral bicarbonate", "Oral N-acetylcysteine (NAC)"], "ans": 1, "exp": "การป้องกัน contrast-induced nephropathy ที่มีหลักฐานดีที่สุดคือ IV isotonic fluid (NSS) ก่อนและหลังฉีดสารทึบรังสี. NAC/bicarbonate หลักฐานไม่ชัด", "sys": "IX"}, {"topic": "Internal medicine", "q": "A 50-year-old female with T2DM on hypoglycemic medication brought in unconscious. Two days of cold and poor appetite. RR normal, HR 100, BP 100/50, generalized weakness in all four limbs. Most likely diagnosis?", "choices": ["Hypoglycemia", "Lactic acidosis", "Hyperosmolar hyperglycemic state (HHS)", "Diabetic ketoacidosis (DKA)", "Septic shock"], "ans": 2, "exp": "ผู้สูงอายุ T2DM + มีตัวกระตุ้น (ติดเชื้อ/กินได้น้อย) + ซึมหมดสติ + ขาดน้ำ (BP ต่ำ) + RR ปกติ (ไม่มี Kussmaul = ไม่ acidosis) = hyperosmolar hyperglycemic state (HHS). RR ปกติเป็นตัวแยกจาก DKA", "sys": "I"}, {"topic": "Internal medicine", "q": "A 30-year-old female with high-grade fever and severe sore throat, diagnosed with Graves' disease last month, on PTU and propranolol. T 39, PR 100, BP 130/90, multiple ulcers in the peritonsillar fossa. Most likely provisional diagnosis?", "choices": ["Thyroid storm", "Acute leukemia", "Infectious mononucleosis", "Agranulocytosis", "Dengue hemorrhagic fever"], "ans": 3, "exp": "ไข้สูง + เจ็บคอ + แผลใน peritonsillar ในผู้ป่วยที่เพิ่งเริ่ม PTU = agranulocytosis (ผลข้างเคียงรุนแรงของ thionamide) -> ต้องหยุดยาและตรวจ CBC ทันที", "sys": "II"}, {"topic": "Internal medicine", "q": "A 30-year-old female with high fever and severe sore throat, diagnosed Graves' last month, on PTU and propranolol. T 39, PR 100, BP 130/90, peritonsillar ulcers (agranulocytosis). Most appropriate treatment?", "choices": ["Prednisolone", "Switch to methimazole (MMI)", "Thyroidectomy", "Radioiodine ablation", "Propranolol"], "ans": 4, "exp": "agranulocytosis จาก PTU -> ต้องหยุด thionamide ทันที และห้ามเปลี่ยนไป MMI (cross-reactivity). ควบคุมอาการ thyrotoxic ด้วย propranolol ระหว่างรักษา neutropenia/ติดเชื้อ แล้วค่อยวางแผนรักษาถาวร (RAI/ผ่าตัด) ภายหลัง", "sys": "III"}, {"topic": "Internal medicine", "q": "A 15-year-old female with diffuse thyroid enlargement 6 months, no symptoms. Thyroid diffusely enlarged ~30 grams, no exophthalmos. FT4 1.1 ng/dL, TSH 2 uIU/mL. Appropriate management?", "choices": ["Observation and regular monitoring", "Initiate methimazole (MMI) therapy", "Start propranolol", "Thyroidectomy", "Radioiodine ablation"], "ans": 0, "exp": "คอพอกโตทั่วเล็กน้อยในวัยรุ่น + FT4/TSH ปกติ (euthyroid simple/colloid goiter) ไม่มีอาการ -> เพียงสังเกตและติดตาม ไม่ต้องให้ยาหรือผ่าตัด", "sys": "IV"}, {"topic": "Internal medicine", "q": "A 60-year-old man with weight gain of 3 kg, cold intolerance for 6 months, puffy face and eyelids, BMI 30. Most useful investigation to diagnose this condition?", "choices": ["Albuminuria", "Thyroid function test", "BUN, Cr", "Urinalysis", "Plasma glucose"], "ans": 1, "exp": "น้ำหนักขึ้น + ทนหนาวไม่ได้ + หน้า/เปลือกตาบวม = hypothyroidism -> ตรวจ thyroid function test (TSH, FT4) ยืนยัน", "sys": "IV"}, {"topic": "Internal medicine", "q": "A 65-year-old woman with fatigue, anorexia, weight loss 5 kg over 3 months, chronic knee pain on herbal medication. Obese with moon face and acanthosis nigricans. FBS 60, BUN 10, Cr 0.8, Na 122, K 5.1, Cl 91, HCO3 22. Most useful investigation?", "choices": ["Thyroid function test", "Dexamethasone suppression test", "Serum morning cortisol", "Aldosterone level", "Fractional excretion of sodium"], "ans": 2, "exp": "hyponatremia + hyperkalemia + hypoglycemia = adrenal insufficiency. ยาสมุนไพรมักผสม steroid ทำให้หน้า Cushingoid แล้วเมื่อหยุด/กดต่อมหมวกไต -> เกิด adrenal insufficiency -> ตรวจ serum morning cortisol", "sys": "IV"}, {"topic": "Infectious disease", "q": "A 40-year-old woman returns from hiking with fever and RUQ abdominal pain. BP stable but tachycardic. Cr 2.1, peripheral blood smear reveals multiple ring forms in RBCs. Most appropriate management?", "choices": ["Quinine", "Quinidine", "Mefloquine", "Artesunate", "Chloroquine"], "ans": 3, "exp": "malaria ที่มี organ dysfunction (ไตวาย Cr 2.1) = severe malaria (มัก P. falciparum, multiple rings) -> รักษาด้วย IV artesunate เป็นตัวเลือกแรก", "sys": "I"}, {"topic": "Infectious disease", "q": "A 40-year-old woman with fever and RUQ pain after camping in a forest. Febrile, tachycardic, BP stable. Cr 2.1. Peripheral blood smear shows multiple ring forms and trophozoites in RBCs. Most appropriate treatment?", "choices": ["Mefloquine", "Primaquine", "Chloroquine", "Atovaquone-proguanil", "Artemisinin"], "ans": 4, "exp": "severe falciparum malaria (multiple rings + ไตวาย) -> รักษาด้วย artemisinin-based (artesunate) เป็นหลัก. chloroquine ใช้ไม่ได้เพราะ falciparum ดื้อ; primaquine ใช้กำจัด hypnozoite ของ vivax/ovale", "sys": "I"}, {"topic": "Infectious disease", "q": "A 55-year-old man with TB on a 5-drug regimen presents with pain, swelling, tenderness, and erythema at his right big toe, warm to touch. On medication several months. Which drug is most likely responsible?", "choices": ["Pyrazinamide", "Isoniazid", "Rifampin", "Ethambutol", "Streptomycin"], "ans": 0, "exp": "ข้ออักเสบเฉียบพลันที่นิ้วหัวแม่เท้า (gout) = pyrazinamide ยับยั้งการขับกรดยูริก -> hyperuricemia/gout เป็นผลข้างเคียงเด่น", "sys": "I"}, {"topic": "Infectious disease", "q": "A 30-year-old man with generalized maculopapular rash including palms and soles, no medication use. Anti-HIV non-reactive, VDRL titer 1:128, denies STI history. Most appropriate management?", "choices": ["Ceftriaxone", "Benzathine Penicillin G", "Doxycycline", "Azithromycin", "Ciprofloxacin"], "ans": 1, "exp": "ผื่นทั่วตัวรวมฝ่ามือฝ่าเท้า + VDRL บวกไทเตอร์สูง = secondary syphilis -> รักษาด้วย benzathine penicillin G ฉีดเข้ากล้าม (first-line)", "sys": "I"}, {"topic": "Infectious disease", "q": "A 60-year-old man with severe flank pain and rash 5 days, IM analgesic injection in buttocks 1 day ago. T 39.5, BP 80/60, RR 24, stupor, fine crepitations, diffuse erythematous rash, multiple flaccid bullae on trunk. Hct 36, WBC 19,000 (N90% band2%), plt 100,000. Bullae culture no organism. Most appropriate antimicrobial treatment?", "choices": ["Piperacillin + Tazobactam", "Ceftriaxone + Clindamycin", "Penicillin + Clindamycin", "Clindamycin + Vancomycin", "Meropenem + Vancomycin"], "ans": 2, "exp": "necrotizing soft tissue infection/streptococcal toxic shock หลังฉีดยา + ช็อก + bullae + ผื่นแดงกระจาย = group A streptococcus -> penicillin + clindamycin (clindamycin ยับยั้งการสร้าง exotoxin). ต้อง debride ร่วมด้วย", "sys": "I"}, {"topic": "Infectious disease", "q": "A middle-aged patient with fever and malaise 3 days. T 39, BP 120/70, PR 100, normal RR. Liver palpable 1-2 cm, spleen not palpable. Hb 13, Hct 40, WBC 4,100 (N 40-50%, L 40%, Mono 10%), platelets 80,000. Peripheral blood smear shown. Most appropriate investigation?", "choices": ["Leptospirosis serology", "Nasopharyngeal swab for influenza", "Epstein-Barr virus (EBV) serology", "Dengue serology", "Blood cultures"], "ans": 3, "exp": "ไข้ + เม็ดเลือดขาวต่ำ + เกล็ดเลือดต่ำ + lymphocyte/monocyte เด่น (atypical lymphocyte) = dengue -> ส่ง dengue serology (NS1/IgM). *อ้างอิงภาพ blood smear*", "img": "https://cdn.jsdelivr.net/gh/MercenzK/Web-quiz-images@main/NL2-2024-Q69.png", "sys": "I"}, {"topic": "Dermatology", "q": "A 50-year-old woman with chronic painless mass on forehead 2 years, slow-growing, occasionally bleeds. 1-cm raised lesion with pearly edges and central ulcer. Most likely diagnosis?", "choices": ["Seborrheic Keratosis", "Epidermal Inclusion Cyst", "Squamous Cell Carcinoma", "Seborrheic Dermatophyte", "Basal Cell Carcinoma"], "ans": 4, "exp": "ก้อนโตช้า ขอบมันวาว (pearly) + แผลตรงกลาง (central ulcer) + เลือดออกง่าย บนใบหน้าที่โดนแดด = basal cell carcinoma (rodent ulcer)", "sys": "XII"}, {"topic": "Dermatology", "q": "A 30-year-old woman with painful, erythematous, warm nodules on the anterior and lateral aspects of both legs. No underlying disease, no medications. Most likely diagnosis?", "choices": ["Erythema Nodosum", "Cellulitis", "Abscesses", "Erysipelas", "Gnathostomiasis"], "ans": 0, "exp": "ตุ่มก้อนแดงเจ็บ อุ่น ที่หน้าแข้งทั้งสองข้าง (bilateral) = erythema nodosum (panniculitis) มักสัมพันธ์กับการติดเชื้อ/ยา/โรคระบบ. cellulitis/erysipelas มักเป็นข้างเดียว. *อ้างอิงภาพ*", "img": "https://cdn.jsdelivr.net/gh/MercenzK/Web-quiz-images@main/NL2-2024-Q71.png", "sys": "XII"}, {"topic": "Dermatology", "q": "A 32-year-old man with AIDS on cotrimoxazole 2 tablets daily for 4 weeks, develops rash over 3 days: erythematous papules with central dusky red areas, fibrinous tops, and bilateral conjunctivitis. Most appropriate management?", "choices": ["Prompt systemic antibiotics", "Prompt withdrawal of the offending agent", "Gently dressing the denuded area daily", "Debridement of the necrotic center", "Dapsone administration instead of the offending agent"], "ans": 1, "exp": "target lesion + mucosal involvement (เยื่อบุตาอักเสบสองข้าง) หลังได้ cotrimoxazole = Stevens-Johnson syndrome -> การรักษาสำคัญที่สุดคือหยุดยาที่เป็นสาเหตุทันที (prompt withdrawal)", "sys": "XII"}, {"topic": "Dermatology", "q": "A 50-year-old male with chronic intermittent well-defined erythematous scaly greasy plaques at external ear canal, eyebrows, glabella, and nasolabial folds. Most likely diagnosis?", "choices": ["Pityriasis Rosea", "Atopic Dermatitis", "Seborrheic Dermatitis", "Acne", "Verruca Vulgaris"], "ans": 2, "exp": "ผื่นแดงเป็นขุยมัน (greasy scale) ตามบริเวณที่มีต่อมไขมันมาก (คิ้ว ร่องจมูก รูหู) = seborrheic dermatitis", "sys": "XII"}, {"topic": "Dermatology", "q": "A 40-year-old patient with generalized erythematous rash 2 years. Multiple well-demarcated, scaly, erythematous plaques on elbows, knees, extensor forearms, lower legs, buttocks, and scalp. Most likely diagnosis?", "choices": ["Lichen Planus", "Lichen Simplex Chronicus", "Atopic Dermatitis", "Psoriasis Vulgaris", "Seborrheic Dermatitis"], "ans": 3, "exp": "ผื่นแดงขอบชัด มีขุยหนา ตามด้าน extensor (ศอก เข่า) และหนังศีรษะ = psoriasis vulgaris", "sys": "XII"}, {"topic": "Dermatology", "q": "A 40-year-old female with generalized itchy rash 2 years. Well-demarcated, scaly, erythematous plaques on both elbows, knees, extensor areas, back, and scalp. Most likely diagnosis?", "choices": ["Lichen Simplex Chronicus", "Lichen Planus", "Allergic Contact Dermatitis", "Seborrheic Dermatitis", "Psoriasis Vulgaris"], "ans": 4, "exp": "ผื่นแดงขอบชัดมีขุยที่ศอก เข่า ด้าน extensor และหนังศีรษะ = psoriasis vulgaris. *อ้างอิงภาพ*", "img": "https://cdn.jsdelivr.net/gh/MercenzK/Web-quiz-images@main/NL2-2024-Q75.png", "sys": "XII"}, {"topic": "Hematology", "q": "A 17-year-old female with easy fatigue 2 months. Marked pallor, no jaundice or hepatosplenomegaly. Hb 6, Hct 17.5%, WBC 6,500 (N65 L30 M5), platelets 650,000. Peripheral blood smear shown. Most useful investigation for diagnosis?", "choices": ["Serum Ferritin", "G6PD Enzyme", "Hemoglobin Typing", "Direct Antiglobulin Test (DAT)", "Bone Marrow Aspiration"], "ans": 0, "exp": "ซีดชนิด microcytic + เกล็ดเลือดสูง (reactive thrombocytosis) ในหญิงวัยเจริญพันธุ์ = iron deficiency anemia -> ตรวจ serum ferritin ยืนยัน. *อ้างอิงภาพ blood smear*", "img": "https://cdn.jsdelivr.net/gh/MercenzK/Web-quiz-images@main/NL2-2024-Q76.png", "sys": "III"}, {"topic": "Hematology", "q": "A 70-year-old woman with myelodysplastic syndrome received 2 units of PRC, developed dyspnea during the second unit. BT 37.2, BP 160/90, PR 100, RR 28, JVP 6 cm above sternal angle, fine crepitations and occasional wheezing both lungs, liver 2 cm below RCM. Most appropriate initial management?", "choices": ["Adrenaline", "Furosemide", "Dexamethasone", "Chlorpheniramine", "Salbutamol nebulizer"], "ans": 1, "exp": "หายใจเหนื่อยระหว่างให้เลือด + ความดันสูง + JVP สูง + crepitation = transfusion-associated circulatory overload (TACO, ภาวะน้ำเกิน) -> หยุดเลือดและให้ furosemide ขับน้ำ", "sys": "III"}, {"topic": "Hematology", "q": "A 50-year-old male with alcoholic cirrhosis presents with hematemesis. BP 100/60, HR 102, moderate pallor, mild jaundice, minimal ascites, splenomegaly. Hct 27%, WBC 4000, platelets 85,000, aPTT 42 s, INR 1.7. Scheduled for EGD. Most appropriate transfusion strategy?", "choices": ["PRC transfusion", "FFP transfusion", "No transfusion required", "Platelet transfusion", "PRC and FFP transfusion"], "ans": 2, "exp": "variceal bleeding ใช้ restrictive strategy: ให้ PRC เมื่อ Hb <7 (Hct ~27 = Hb ~9 ยังไม่ถึงเกณฑ์); เกล็ดเลือด 85,000 (>50,000) และ INR 1.7 เล็กน้อย ยังไม่ต้องให้ -> no transfusion required", "sys": "III"}, {"topic": "Hematology", "q": "A 35-year-old woman with prolonged bleeding after tooth extraction and ecchymosis on legs. Normal platelet count with 1-2 eosinophils on smear. Most appropriate management?", "choices": ["FFP transfusion", "Platelet transfusion", "Factor VIII administration", "Desmopressin (DDAVP)", "Cryoprecipitate transfusion"], "ans": 3, "exp": "เลือดออกแบบ mucocutaneous (เหงือก จ้ำเลือด) + เกล็ดเลือดปกติ = von Willebrand disease (ผิดปกติเชิงหน้าที่) -> รักษาด้วย desmopressin (DDAVP) กระตุ้นปล่อย vWF", "sys": "III"}, {"topic": "Hematology", "q": "A 40-year-old woman with fatigue 1 month, moderately pale, no jaundice. Hct 21%, WBC 7500, platelets 180,000, MCV 70. After proper treatment, which parameter is expected to increase first?", "choices": ["Hb level", "Ferritin level", "MCV", "Transferrin saturation", "Reticulocyte count"], "ans": 4, "exp": "iron deficiency anemia (microcytic, MCV 70) เมื่อให้ธาตุเหล็ก -> reticulocyte count จะขึ้นก่อน (ภายใน 5-7 วัน) ก่อน Hb/MCV จะกลับมาปกติ", "sys": "III"}, {"topic": "Hematology", "q": "A 30-year-old woman with ALL. CBC Hb 9.5, Hct 29%, WBC 198,000 (blasts 98%), Plt 90,000, Cr 1.0. One day after chemotherapy urine output drops to 50 mL/day. Na 132, K 6, Cl 99, HCO3 19, Cr 2.5, Ca 7.5, P 7. Most likely diagnosis?", "choices": ["Tumor lysis syndrome", "Rhabdomyolysis", "Obstructive uropathy", "Leukemic nephropathy", "Drug-induced nephropathy"], "ans": 0, "exp": "หลังเคมีบำบัดใน leukemia ที่ WBC สูงมาก -> เซลล์แตก: K สูง, phosphate สูง, Ca ต่ำ, uric acid สูง + ไตวาย = tumor lysis syndrome", "sys": "III"}, {"topic": "Hematology", "q": "A 65-year-old female with anemia 5 months, previously healthy, no medications. Moderate pallor, no hepatosplenomegaly or lymphadenopathy. Hb 7, Hct 20%, WBC 3,800 (N55 L40 M5), platelets 110,000, RDW 20%. Most appropriate investigation?", "choices": ["Hb typing", "Bone marrow aspiration", "Liver function tests (LFT)", "Direct antiglobulin test (DAT)", "Vitamin B12 level"], "ans": 1, "exp": "pancytopenia (ซีด + เม็ดเลือดขาวต่ำ + เกล็ดเลือดต่ำ) ในผู้สูงอายุ ไม่มีสาเหตุชัด -> ต้องเจาะไขกระดูก (bone marrow aspiration) เพื่อวินิจฉัย (MDS/leukemia/aplastic)", "sys": "III"}, {"topic": "Hematology", "q": "A 50-year-old man with massive bleeding received a blood transfusion and developed slight hematuria. VS stable: BP 130/80, RR 16, BT 37, PR 90. PE unremarkable. Most appropriate management?", "choices": ["Sodium bicarbonate", "Normal saline solution (NSS) loading", "Stop blood transfusion", "Furosemide", "Dexamethasone"], "ans": 2, "exp": "สงสัย acute hemolytic transfusion reaction (ปัสสาวะเป็นเลือดขณะให้เลือด) -> ขั้นแรกต้องหยุดให้เลือดทันที แล้วจึงให้สารน้ำ/รักษาประคับประคอง", "sys": "III"}, {"topic": "Hematology", "q": "A 70-year-old man with history of CVA on warfarin presents with new-onset one-sided weakness. CT reveals hyperdense lesion indicating intracerebral hemorrhage. Besides vitamin K, next step in management?", "choices": ["Fresh Frozen Plasma (FFP)", "Cryoprecipitate", "Platelet transfusion", "Prothrombin Complex Concentrate (PCC)", "Intravenous thrombolysis"], "ans": 3, "exp": "warfarin-related intracerebral hemorrhage -> ต้อง reverse INR เร็วที่สุดด้วย prothrombin complex concentrate (PCC, มี factor II, VII, IX, X) ร่วมกับ vitamin K. PCC เร็วและปริมาตรน้อยกว่า FFP. *อ้างอิงภาพ CT*", "img": "https://cdn.jsdelivr.net/gh/MercenzK/Web-quiz-images@main/NL2-2024-Q84.png", "sys": "III"}, {"topic": "Hematology", "q": "A 30-year-old woman with bleeding gums and hypermenorrhea, no prior bleeding history. Generalized petechiae on both legs. Hb 12.4, MCV 85, WBC 7,800 (N75 L25), platelets 15,000. Anti-HIV/HCV non-reactive, ANA negative. Proper management?", "choices": ["Platelet transfusion", "Fresh Frozen Plasma (FFP)", "Vitamin K", "Eltrombopag (Thrombopoietin receptor agonist)", "Prednisolone"], "ans": 4, "exp": "เกล็ดเลือดต่ำเดี่ยว ๆ (isolated thrombocytopenia) + petechiae โดยเม็ดเลือดอื่นปกติ HIV/ANA ลบ = immune thrombocytopenia (ITP) -> รักษาด้วย corticosteroid (prednisolone) เป็น first-line. ไม่ให้เกล็ดเลือดยกเว้นเลือดออกรุนแรง", "sys": "III"}, {"topic": "Hematology", "q": "A 28-year-old male with DOE and fever 2 days, no medications. T 38.5, PR 115, RR 16, BP 120/70, marked pallor and mild jaundice. Hct 24%, Hb 7.1, WBC 14,000, platelets 240,000. Smear: hypochromia 2+, anisopoikilocytosis 2+, polychromasia 2+, basophilic stippling. Most likely diagnosis?", "choices": ["Hb H disease", "Lead poisoning", "Autoimmune hemolytic anemia (AIHA)", "G6PD deficiency", "Thalassemia"], "ans": 0, "exp": "ซีด microcytic hypochromic + anisopoikilocytosis + polychromasia + basophilic stippling + เม็ดเลือดแตกเฉียบพลันเมื่อมีไข้ = HbH disease (alpha-thalassemia) ซึ่ง Hb ไม่เสถียร แตกง่ายเมื่อติดเชื้อ/ไข้", "sys": "III"}, {"topic": "Hematology", "q": "A 19-year-old male with fatigue and fever 3 days, no medication. Pale, moderate jaundice, no hepatosplenomegaly. Hb 8, Hct 24%, WBC 4,200, platelets 154,000. Peripheral blood smear shown. Most likely complication?", "choices": ["Chronic leg ulcer", "Gallstone", "Venous thrombosis", "Acute kidney injury (AKI)", "Opportunistic infection"], "ans": 1, "exp": "ภาวะเม็ดเลือดแดงแตกเรื้อรัง (hemolytic anemia, ดีซ่าน) -> bilirubin สูงเรื้อรังทำให้เกิด pigment gallstone เป็นภาวะแทรกซ้อนที่พบบ่อย. *อ้างอิงภาพ blood smear*", "img": "https://cdn.jsdelivr.net/gh/MercenzK/Web-quiz-images@main/NL2-2024-Q87.png", "sys": "III"}, {"topic": "Hematology", "q": "A 30-year-old female with progressive fatigue 1 week, postpartum hemorrhage 2 weeks ago. Pale conjunctiva. Hb 9, MCV 90, WBC 9,000 (N80), platelets normal. Both DAT and IAT positive. Most likely etiology?", "choices": ["Citrate intoxication", "Autoimmune hemolytic anemia (AIHA)", "Delayed transfusion reaction", "Iron deficiency anemia", "Postpartum anemia"], "ans": 2, "exp": "DAT บวก + IAT บวก ~2 สัปดาห์หลังได้รับเลือด (ตอน PPH) = delayed hemolytic transfusion reaction (สร้าง alloantibody ต่อ minor antigen). ไม่ใช่ AIHA (autoantibody) *ดูคู่กับข้อ 89, 90*", "sys": "III"}, {"topic": "Hematology", "q": "A Thai 30-year-old woman with progressive fatigue 1 week postpartum. PPH from uterine atony 2 weeks ago, given 2 units PRC. Moderate pallor, mild jaundice. Hb 9, WBC 9,000, MCV 90, platelets 145,000, reticulocyte 6%, DAT +1, IAT +3. Most likely diagnosis?", "choices": ["Citrate intoxication", "Adrenal insufficiency", "Iron deficiency anemia", "Delayed hemolytic transfusion reaction", "Autoimmune hemolytic anemia (AIHA)"], "ans": 3, "exp": "ซีด + ดีซ่าน + retic สูง + DAT/IAT บวก ~2 สัปดาห์หลังรับเลือด = delayed hemolytic transfusion reaction จาก alloantibody ต่อ RBC antigen ของเลือดที่ได้รับ", "sys": "III"}, {"topic": "Hematology", "q": "A 30-year-old female with dyspnea and history of PPH with 2 units PRC 2 weeks ago. Pale with lung crepitations and wheezing. Positive direct Coombs (+1) and indirect Coombs (+3). Most likely diagnosis?", "choices": ["Autoimmune hemolytic anemia (AIHA)", "Chronic disseminated intravascular coagulation (DIC)", "Microangiopathic hemolytic anemia (MAHA)", "Transfusion-related acute lung injury (TRALI)", "Late hemolytic transfusion reaction"], "ans": 4, "exp": "DAT/IAT บวก 2 สัปดาห์หลังรับเลือด = late (delayed) hemolytic transfusion reaction. TRALI เกิดภายใน 6 ชม.หลังให้เลือด จึงไม่ใช่ (เวลาไม่เข้า); อาการปอด/เหนื่อยจากภาวะซีด/heart failure", "sys": "III"}, {"topic": "Hematology", "q": "A 38-year-old woman with fatigue 2 weeks. Low Hct with high MCV 110, normal WBC and platelets. Smear: normochromic normocytic RBCs with 1+ microspherocytes and 1+ polychromasia. Most appropriate management?", "choices": ["Prednisolone", "Vitamin B12 supplementation", "Intravenous immunoglobulin (IVIG)", "Erythropoiesis-stimulating agents", "Folate supplementation"], "ans": 0, "exp": "microspherocyte + polychromasia (reticulocyte สูงทำ MCV สูง) = hemolytic anemia ชนิด warm autoimmune (AIHA) -> รักษาด้วย prednisolone เป็น first-line. MCV สูงจาก reticulocytosis ไม่ใช่ B12/folate ขาด", "sys": "III"}, {"topic": "Hematology", "q": "A 38-year-old female with fatigue and moderate pallor, mild jaundice. Hb 8, WBC 9,000, platelets 163,000, MCV 110, reticulocyte 10%, PBS normochromic normocytic with 1+ microspherocytes and 1+ polychromasia. Most appropriate treatment?", "choices": ["Vitamin B12", "Prednisolone", "PRC transfusion", "Cyclophosphamide", "IV immunoglobulin"], "ans": 1, "exp": "retic สูง 10% + microspherocyte + polychromasia = autoimmune hemolytic anemia (AIHA) -> prednisolone เป็นการรักษาหลัก (first-line)", "sys": "III"}, {"topic": "Hematology", "q": "A 28-year-old man with fatigue, mild pallor, mild icteric sclera, enlarged liver (span 14 cm), splenic dullness. Hb 7, MCV 68, platelets 240,000, WBC 4,500. PBS: microcytic RBCs with 2+ polychromasia and basophilic stippling. Most likely diagnosis?", "choices": ["Lead poisoning", "G6PD deficiency with acute hemolysis", "HbH disease", "Hereditary spherocytosis (HS)", "Thalassemia major"], "ans": 2, "exp": "ซีด microcytic เรื้อรัง + ตับม้ามโต + polychromasia + basophilic stippling ในผู้ใหญ่ไทย = HbH disease (alpha-thalassemia) ที่แสดงอาการในวัยผู้ใหญ่. Thalassemia major มักแสดงตั้งแต่วัยเด็กและต้องเติมเลือดประจำ", "sys": "III"}, {"topic": "Rheumatology", "q": "A 50-year-old woman with 2-day high fever and right knee pain. T 40, BP 120/80, PR 100, RR 20, swelling with marked tenderness and redness of the right knee. Joint fluid WBC 50,000 with 90% neutrophils. Most appropriate treatment?", "choices": ["Ceftazidime", "Levofloxacin", "Meropenem", "Ceftriaxone", "Vancomycin"], "ans": 3, "exp": "septic arthritis (joint fluid WBC สูงมาก PMN เด่น) -> empiric ครอบคลุมเชื้อที่พบบ่อย (S. aureus, streptococci, gonococcus) ด้วย ceftriaxone. ถ้าย้อม gram พบ gram-positive cocci เสี่ยง MRSA จึงเพิ่ม vancomycin", "sys": "XIII"}, {"topic": "Rheumatology", "q": "A 70-year-old male with well-controlled HT on amlodipine and furosemide. Annual checkup uric acid 11 mg/dL, no arthritis symptoms. Most proper management?", "choices": ["Add losartan", "Discontinue amlodipine", "Change amlodipine to losartan", "Start allopurinol", "Discontinue furosemide"], "ans": 4, "exp": "asymptomatic hyperuricemia ที่เกิดจากยา furosemide (loop diuretic เพิ่มกรดยูริก) -> จัดการโดยหยุด/เปลี่ยน furosemide ซึ่งเป็นสาเหตุ ไม่ใช่เริ่ม allopurinol (ยังไม่มีข้อบ่งชี้). amlodipine ไม่เพิ่มกรดยูริก", "sys": "XIII"}, {"topic": "Rheumatology", "q": "A 50-year-old man with HT on amlodipine, serum uric acid 11 mg/dL, history of passing urine stones, heavy alcohol drinker. No arthritis or tophi, Cr 0.8. Most appropriate management?", "choices": ["Allopurinol", "Change amlodipine to enalapril", "Low carb diet", "Colchicine", "Benzbromarone"], "ans": 0, "exp": "hyperuricemia + ประวัตินิ่วทางเดินปัสสาวะ (uric acid stone) = มีข้อบ่งชี้ให้ urate-lowering therapy -> allopurinol (ลดการสร้างกรดยูริก ป้องกันนิ่วซ้ำ). ไม่ใช้ benzbromarone (uricosuric เพิ่มความเสี่ยงนิ่ว)", "sys": "XIII"}, {"topic": "Rheumatology", "q": "A 30-year-old woman with several swollen and painful joints for 2 months, morning stiffness 2 hours, no rash. Swelling and tenderness at PIPs, MCPs, wrists. X-rays: juxta-articular osteopenia and marginal erosions. Most appropriate management?", "choices": ["NSAIDs", "Prednisolone", "Colchicine", "Tramadol", "Acetaminophen"], "ans": 1, "exp": "ข้ออักเสบหลายข้อแบบสมมาตรที่ข้อเล็ก (PIP/MCP/wrist) + เช้าฝืด >1 ชม. + erosion บนภาพรังสี = rheumatoid arthritis. ควรเริ่ม DMARD (methotrexate) แต่ในตัวเลือกนี้ prednisolone คุมการอักเสบได้ดีสุดระหว่างรอ DMARD (ไม่ใช่แค่ยาแก้ปวด NSAID/paracetamol)", "sys": "XIII"}, {"topic": "Rheumatology", "q": "A 70-year-old woman with right knee pain 2 years, worse with weight-bearing/walking, relieved by rest, morning stiffness, intermittent swelling. Crepitation and ballottement of right knee, no inflammation. Most likely diagnosis?", "choices": ["Pseudogout", "Gouty arthritis", "Osteoarthritis", "Reactive arthritis", "Rheumatoid arthritis"], "ans": 2, "exp": "ปวดเข่าเรื้อรังในผู้สูงอายุ ปวดเวลาลงน้ำหนัก ดีขึ้นเมื่อพัก + crepitus ไม่มีการอักเสบชัด = osteoarthritis", "sys": "XIII"}, {"topic": "Rheumatology", "q": "A 70-year-old female with right knee pain 2 years, worse with weight-bearing/walking, improves with rest, morning stiffness, intermittent swelling. Crepitus and ballottement at right knee, no acute inflammation. Most likely diagnosis?", "choices": ["Rheumatoid arthritis", "Reactive arthritis", "Gout", "Osteoarthritis", "Pseudogout"], "ans": 3, "exp": "อาการเข้าได้กับ osteoarthritis (ปวดเมื่อใช้งาน/ลงน้ำหนัก crepitus ไม่มีอักเสบเฉียบพลัน) *เหมือนข้อ 98 สลับตัวเลือก*", "sys": "XIII"}, {"topic": "Rheumatology", "q": "A 28-year-old woman with left knee pain and fever. Yesterday had right ankle pain (resolved). Today pain/swelling/redness/warmth in left knee. Pustules on right calf and redness along extensor tendons of right middle finger. Most likely diagnosis?", "choices": ["Systemic lupus erythematosus (SLE)", "Reactive arthritis", "Acute rheumatic fever", "Adult-onset Still's disease", "Systemic gonococcal infection"], "ans": 4, "exp": "triad ของ disseminated gonococcal infection: migratory/additive polyarthritis (ข้อเท้าย้ายมาเข่า) + tenosynovitis (เอ็นนิ้วอักเสบ) + ผื่นตุ่มหนอง (pustule) ที่ผิวหนัง", "sys": "XIII"}, {"topic": "Rheumatology", "q": "A 28-year-old woman with fever and joint pain 2 days. Initially right ankle pain (resolved), now left knee mildly swollen/warm/red/tender. Small pustule on right calf, swelling and tenderness along extensor tendons of left middle finger. Most likely diagnosis?", "choices": ["Disseminated gonococcal infection", "Systemic lupus erythematosus (SLE)", "Reactive arthritis", "Acute rheumatic fever", "Adult-onset Still's disease"], "ans": 0, "exp": "migratory arthritis + tenosynovitis + pustular skin lesion = disseminated gonococcal infection", "sys": "XIII"}, {"topic": "Rheumatology", "q": "A 28-year-old female with left knee pain. Initially left ankle pain/tenderness (resolved). Now left knee warm/red/tender. Small pustules on right calf, swelling and tenderness along extensor tendon of left middle finger. Most likely diagnosis?", "choices": ["Systemic lupus erythematosus (SLE)", "Disseminated gonococcal infection", "Reactive arthritis", "Adult-onset Still's disease", "Acute rheumatic fever"], "ans": 1, "exp": "migratory arthritis + tenosynovitis + pustule = disseminated gonococcal infection (DGI)", "sys": "XIII"}, {"topic": "Surgery", "q": "A 66-year-old female with DM and HT presents with RUQ pain and fever. T 38.9, BP 150/90, PR 100, RR 18, icteric sclera, RUQ tenderness, liver span 10 cm, spleen not palpable. Most appropriate investigation?", "choices": ["Anti-HCV and anti-HIV testing", "Serum amylase", "Abdominal ultrasound (USG)", "Acute abdomen series (X-ray)", "Alpha-fetoprotein (AFP) testing"], "ans": 2, "exp": "ปวด RUQ + ไข้ + ดีซ่าน สงสัยโรคทางเดินน้ำดี (cholangitis/cholecystitis) -> ตรวจ abdominal ultrasound เป็นอันดับแรกเพื่อดูนิ่ว/ท่อน้ำดีขยาย", "sys": "I"}, {"topic": "Surgery", "q": "A 25-year-old man with fever and right abdominal pain 2 weeks. T 38, PR 90, BP 120/80. RUQ tenderness, liver palpable 5 fingerbreadths below RCM, span 15 cm. TB 0.9, DB 0.6, AST 123, ALT 98, ALP 389, albumin 3.6. Ultrasound: 8 cm round homogenous hypoechoic lesion at upper lobe of liver. Most appropriate management?", "choices": ["Surgical resection", "Oral praziquantel", "Percutaneous drainage", "Oral metronidazole", "Intravenous Ceftriaxone"], "ans": 3, "exp": "ฝีในตับก้อนเดียว homogenous hypoechoic ในคนหนุ่ม = amoebic liver abscess -> รักษาด้วย metronidazole เป็นหลัก (ตอบสนองดี). ระบายผ่านผิวหนังเมื่อก้อนใหญ่มาก/ไม่ตอบสนอง/เสี่ยงแตก", "sys": "I"}, {"topic": "Surgery", "q": "A 67-year-old male with abdominal pain and obstipation 2 days, history of mucous bloody diarrhea for 4 months. Normal vitals. Abdominal film shows colonic dilatation without air in the rectum. Most likely etiology?", "choices": ["Ulcerative colitis", "Diverticulitis", "Ischemic colitis", "Infectious colitis", "Sigmoid colon cancer"], "ans": 4, "exp": "ถ่ายมูกเลือดเรื้อรัง 4 เดือน + ลำไส้อุดตัน (obstipation + colon โป่ง ไม่มีลมใน rectum) ในผู้สูงอายุ = obstructing sigmoid/left colon cancer", "sys": "II"}, {"topic": "Surgery", "q": "A 70-year-old patient with epigastric pain and postprandial fullness 4 weeks, no red flag signs, no nocturnal pain, no anemia. Most appropriate management?", "choices": ["Esophagogastroduodenoscopy (EGD)", "Proton Pump Inhibitor (PPI)", "Simethicone", "Domperidone", "H. pylori testing"], "ans": 0, "exp": "dyspepsia ที่เริ่มใหม่ในผู้สูงอายุ (>50-55 ปี) ถือเป็น alarm feature -> ควรส่อง EGD เพื่อคัดกรองมะเร็งกระเพาะก่อน", "sys": "general"}, {"topic": "Surgery", "q": "A 55-year-old man with DM presents with left leg pain 2 days. T 39, PR 120, RR 24, erythematous, warm, edematous, tender left calf with crepitus. Gram stain shows mixed organisms. Most appropriate management?", "choices": ["Intravenous Ceftriaxone", "Radical Debridement", "Intravenous Metronidazole", "Fasciotomy", "Intravenous Clindamycin"], "ans": 1, "exp": "necrotizing fasciitis (crepitus + เชื้อผสม + ติดเชื้อลุกลามเร็วในผู้ป่วยเบาหวาน) = ภาวะฉุกเฉินทางศัลยกรรม -> การรักษาสำคัญที่สุดคือ radical surgical debridement ทันที (ยาปฏิชีวนะเป็นแค่ส่วนเสริม)", "sys": "XII"}, {"topic": "Surgery", "q": "A 45-year-old man with acute right leg pain 2 hours, history of atrial fibrillation. T 36.8, BP 140/85, PR 80 irregular, RR 18. Right leg: absent PTA and DPA pulses, pain at big toe, cold pale skin below knee, paresthesia below ankle without paralysis. Most likely diagnosis?", "choices": ["Rupture of Baker cyst", "Thromboangiitis obliterans", "Acute popliteal embolism", "Compartment syndrome", "Deep vein thrombosis"], "ans": 2, "exp": "AF + ปวดขาเฉียบพลัน + ชีพจรคลำไม่ได้ + ขาเย็นซีดชา (6P: pain, pallor, pulselessness, paresthesia, poikilothermia) = acute arterial embolism จากลิ่มเลือดในหัวใจไปอุด (acute limb ischemia)", "sys": "IX"}, {"topic": "Surgery", "q": "An 18-year-old male with a stab wound to the neck, inferior to the mandible and anterior to the left SCM. Blood in the oropharynx and active bleeding from the neck wound. No exit wound, HR 120, RR 20, BP 100/85. Most appropriate management?", "choices": ["CT angiogram of neck", "Contrast esophagography", "Plain biplanar neck radiography", "Explore neck", "Doppler ultrasonography of neck"], "ans": 3, "exp": "penetrating neck injury ที่มี hard sign (เลือดออกไม่หยุด, active bleeding, เลือดใน oropharynx) -> ต้อง surgical neck exploration ทันที ไม่ต้องเสียเวลาถ่ายภาพ", "sys": "XI"}, {"topic": "Surgery", "q": "A 48-year-old female with left breast mass 3 months, 2 cm at 10 o'clock, normal skin/nipple. Mammography spiculated mass BIRADS 4C. Core needle biopsy returned normal. Most appropriate management?", "choices": ["Simple mastectomy", "Follow up in next 3 months", "Follow mammography/ultrasound in the next 6 months", "Ultrasound-guided fine needle biopsy", "Excisional biopsy"], "ans": 4, "exp": "ภาพ mammogram สงสัยมะเร็งสูง (BIRADS 4C, spiculated) แต่ core biopsy ได้เนื้อปกติ = ผลไม่สอดคล้อง (discordant) -> ต้องทำ excisional biopsy เพื่อยืนยัน ไม่ควรติดตามเฉย ๆ", "sys": "II"}, {"topic": "Surgery", "q": "A 48-year-old woman with left breast mass 3 years, 2 cm at 10 o'clock, skin/areola intact, no palpable nodes. Mammography and ultrasound spiculated mass BIRADS 4C. Core needle biopsy returned normal breast tissue but imaging concerning. Most appropriate management?", "choices": ["Excisional biopsy", "Simple mastectomy", "Ultrasound-guided fine needle aspiration", "Reevaluate in 3 months", "Mammogram/ultrasound in 6 months"], "ans": 0, "exp": "imaging BIRADS 4C แต่ core biopsy ปกติ (discordant) -> excisional biopsy เพื่อตัดชิ้นเนื้อยืนยัน", "sys": "II"}, {"topic": "Surgery", "q": "A 30-year-old man with a stab wound to the RUQ, epigastric pain but no tenderness or guarding. Stable vitals, acute abdomen film normal. Most appropriate next investigation?", "choices": ["CT whole abdomen", "Exploration of the wound", "Observation", "Exploratory laparotomy", "Double examination in the operating room"], "ans": 1, "exp": "stab wound ที่หน้าท้อง ผู้ป่วย stable ไม่มี peritonitis -> ทำ local wound exploration ดูว่าทะลุ anterior fascia/peritoneum หรือไม่ ก่อนตัดสินใจผ่าตัด", "sys": "XVIII"}, {"topic": "Surgery", "q": "A 40-year-old female with goiter underwent total thyroidectomy. On postoperative day 2 she has numbness in both hands, circumferential hypoesthesia at thumbs and carpopedal spasm. What caused these symptoms?", "choices": ["Hypokalemia", "Hypercalcemia", "Hypoparathyroidism", "Hypothyroid", "Hyperventilation"], "ans": 2, "exp": "หลังผ่าตัดต่อมไทรอยด์ออกหมด อาจตัด/ทำลายต่อมพาราไทรอยด์ -> hypoparathyroidism -> hypocalcemia (ชาปลายมือ carpopedal spasm, Trousseau/Chvostek)", "sys": "IV"}, {"topic": "Surgery", "q": "A 25-year-old female with RLQ pain, anorexia, nausea, vomiting. LMP 6 weeks ago, irregular cycles. Guarding in RLQ, no rebound. WBC 15,000 with PMN predominance. Most appropriate initial management?", "choices": ["CT abdomen", "Ultrasound of the lower abdomen", "Complete blood count (CBC) with differential", "Urine pregnancy test (UPT)", "Pelvic examination"], "ans": 3, "exp": "หญิงวัยเจริญพันธุ์ + ปวดท้องน้อย + ประจำเดือนขาด -> ต้องตรวจ urine pregnancy test ก่อนเสมอ เพื่อแยก ectopic pregnancy ก่อนวินิจฉัยไส้ติ่งอักเสบ", "sys": "XV"}, {"topic": "Surgery", "q": "A 30-year-old woman with rectal bleeding 5 days, similar episodes intermittently over the past year. Proctoscope reveals a small varicose vein above the dentate line. Most appropriate management?", "choices": ["Gel foam pack", "Steroid suppository", "Rubber band ligation", "Hemorrhoidectomy", "Bulk forming laxative"], "ans": 4, "exp": "internal hemorrhoid ระยะแรก (เส้นเลือดขอดเล็ก ๆ เหนือ dentate line) เลือดออกเล็กน้อย -> เริ่มด้วยการรักษาแบบอนุรักษ์: เพิ่มกากใย/bulk-forming laxative ก่อน. *ดูคู่กับข้อ 116 ที่มี active bleeding*", "sys": "IX"}, {"topic": "Surgery", "q": "A 30-year-old female with bleeding per anus 5 days, fresh blood after defecation intermittently for a year. Proctoscopy: venous dilatation lump with active bleeding above the dentate line. Appropriate management?", "choices": ["Rubber band ligation", "Steroid suppository", "Hemorrhoidectomy", "Bulk-forming laxative", "Gel foam"], "ans": 0, "exp": "internal hemorrhoid ที่มี active bleeding เหนือ dentate line -> rubber band ligation (การรักษาหัตถการที่เหมาะสมเมื่อมีเลือดออก/ล้มเหลวจากการรักษาอนุรักษ์)", "sys": "XI"}, {"topic": "Surgery", "q": "A male with severe low back pain and inability to urinate. Decreased sensation in a saddle pattern, loose sphincter tone, palpable cystic mass in the suprapubic area. Most appropriate management?", "choices": ["Pelvic traction", "MRI of the lumbar spine", "Epidural steroid injection", "Immediate urinary catheterization", "Surgical decompression"], "ans": 1, "exp": "cauda equina syndrome (saddle anesthesia + หูรูดหลวม + ปัสสาวะคั่ง) = ภาวะฉุกเฉิน -> ตรวจ MRI lumbar spine ด่วนเพื่อยืนยันและวางแผน emergency decompression (ควรใส่สายสวนระบายกระเพาะปัสสาวะควบคู่)", "sys": "II"}, {"topic": "Neurosurgery", "q": "A 50-year-old man with sudden severe headache 1 hour ago while watching TV. Neck stiffness, right pupil 4 mm fixed and dilated, left pupil 3 mm reactive. Motor normal in all extremities. Most likely diagnosis?", "choices": ["Acute subdural hematoma", "Right basal pontine hemorrhage", "Subarachnoid hemorrhage", "Epidural hematoma", "Intracerebral hemorrhage"], "ans": 2, "exp": "ปวดหัวรุนแรงเฉียบพลัน (thunderclap) + คอแข็ง + CN III palsy (รูม่านตาขวาโต fixed) = subarachnoid hemorrhage จาก aneurysm ที่ posterior communicating กดเส้นประสาทสมองคู่ที่ 3", "sys": "VI"}, {"topic": "Neurosurgery", "q": "A man in ER after a traffic accident. BP 140/90, RR 22, PR 90, BT 37, GCS 14. Laceration at right parietal area, otherwise unremarkable. While undergoing chest radiograph, he suddenly loses consciousness and is only responsive to pain. Most likely etiology?", "choices": ["Subdural hematoma", "Diffuse axonal injury", "Intracerebral hemorrhage", "Epidural hematoma", "Subarachnoid hemorrhage"], "ans": 3, "exp": "บาดเจ็บศีรษะบริเวณ temporo-parietal + มีช่วงรู้สึกตัวดี (lucid interval) แล้วซึมลงอย่างรวดเร็ว = epidural hematoma (มัก middle meningeal artery ฉีก)", "sys": "VI"}, {"topic": "Neurosurgery", "q": "A 30-year-old male after motorcycle accident with quadriplegia and loss of sensation below C6, absent anal wink and bulbocavernosus reflex. Stable vitals, no active bleeding. UMN and LMN signs. Acute spinal cord injury. Most appropriate management?", "choices": ["Colloid solution", "Methylprednisolone", "Adrenaline IM", "Hypertonic saline", "IV fluids with crystalloids"], "ans": 4, "exp": "acute spinal cord injury ที่ hemodynamic stable -> การดูแลหลักคือ supportive (immobilization + IV crystalloid รักษา perfusion). ปัจจุบันไม่แนะนำ high-dose methylprednisolone เป็น routine (ประโยชน์ไม่ชัด เสี่ยงภาวะแทรกซ้อน)", "sys": "IV"}, {"topic": "Neurosurgery", "q": "A 20-year-old man with neck pain and quadriplegia after motorcycle accident. PR 48, BP 74/40, RR 18. Motor 0/5 all limbs except deltoid and biceps 3/5. No perianal sensation, absent anal wink, lost sphincter tone. Besides IV fluid resuscitation, most appropriate management?", "choices": ["Intravenous Inotropes", "Blood transfusion", "Colloid IV", "Intravenous Methylprednisolone (IVMP)", "Intramuscular Adrenaline"], "ans": 0, "exp": "neurogenic shock (ความดันตก + หัวใจเต้นช้า จากเสีย sympathetic tone) จาก cervical cord injury -> เมื่อให้สารน้ำแล้วยังช็อก ให้ vasopressor/inotrope (เช่น norepinephrine) ปรับ perfusion. IVMP ไม่ช่วยและไม่แนะนำ", "sys": "III"}, {"topic": "Pediatrics", "q": "A newborn male found to have an empty scrotal sac on routine physical examination. Most appropriate next step in management?", "choices": ["Orchidopexy", "Reexamination in 6 months", "CT whole abdomen", "Ultrasound of the testes", "Hormonal therapy"], "ans": 1, "exp": "cryptorchidism ในทารกแรกเกิด -> อัณฑะส่วนใหญ่เลื่อนลงเองภายใน 6 เดือน จึงนัดตรวจซ้ำที่อายุ 6 เดือน ถ้ายังไม่ลงจึงผ่าตัด orchidopexy (ก่อนอายุ 1-1.5 ปี)", "sys": "XVI"}, {"topic": "Pediatrics", "q": "A 4-week-old male with intermittent abdominal distention, no stool for 5 days, passed meconium on day 3, infrequent bowel movements with progressive distention, feeding well, bilious vomiting 2 days. Distended non-tender abdomen, decreased bowel sounds. Digital rectal exam produces explosive release of stool. Gold standard investigation?", "choices": ["Barium enema", "Anal sphincter manometry", "Rectal biopsy", "Acute abdomen series (X-ray)", "Per rectal examination"], "ans": 2, "exp": "ถ่ายขี้เทาช้า (>48 ชม.) + ท้องอืดเรื้อรัง + explosive stool หลังตรวจทวาร = Hirschsprung disease -> gold standard คือ rectal biopsy (พบไม่มี ganglion cells)", "sys": "XVI"}, {"topic": "Surgery", "q": "A 40-year-old female with scald burns 2 hours ago, stable vitals, 60 kg, 10% TBSA first-degree and 40% TBSA second-degree. Per ATLS, how much fluid in the first hour? (modified Parkland 4 mL)", "choices": ["1,200 mL", "1,800 mL", "2,400 mL", "600 mL", "3,000 mL"], "ans": 3, "exp": "คิดเฉพาะแผลลึก (2nd degree 40%): 4 x 60 kg x 40 = 9,600 mL/24 ชม. ให้ครึ่งหนึ่งใน 8 ชม.แรก = 4,800 mL -> เฉลี่ย 600 mL/ชม. (แผล 1st degree ไม่นับ)", "sys": "XVIII"}, {"topic": "Surgery", "q": "A 60 kg man with burns on right arm (9%), right leg (18%), and anterior trunk (18%) = 45% TBSA. Per modified Parkland and rule of nines, fluid in the first 8 hours?", "choices": ["5% Dextrose in Normal Saline, 3600 mL", "5% Dextrose in Normal Saline, 5400 mL", "Ringer Lactate solution, 3600 mL", "Ringer Lactate solution, 10800 mL", "Ringer Lactate solution, 5400 mL"], "ans": 4, "exp": "TBSA 45%: 4 x 60 x 45 = 10,800 mL/24 ชม. ให้ครึ่งหนึ่งใน 8 ชม.แรก = 5,400 mL ของ Ringer Lactate (สารน้ำที่เลือกใน burn resuscitation)", "sys": "XVIII"}, {"topic": "Surgery", "q": "A 60 kg man with burns to anterior trunk (18%), right upper extremity (9%), right lower extremity (18%) = 45% TBSA. Using modified Parkland and rule of nines, fluid in the first 8 hours?", "choices": ["Ringer Lactate solution, 10800 mL", "Ringer Lactate solution, 5400 mL", "5% Dextrose in Normal Saline, 5400 mL", "5% Dextrose in Normal Saline, 10800 mL"], "ans": 1, "exp": "TBSA 45%: 4 x 60 x 45 = 10,800 mL/24 ชม.; ครึ่งแรกใน 8 ชม. = 5,400 mL Ringer Lactate", "sys": "XVIII"}, {"topic": "Surgery", "q": "A 60 kg man 2 hours post thermal burn with 10% BSA first-degree and 40% BSA second-degree. Calculate the rate of fluid in the first hour per ATLS guidelines (2 mL).", "choices": ["400 mL/hr", "300 mL/hr", "500 mL/hr", "375 mL/hr", "1000 mL/hr"], "ans": 1, "exp": "ATLS ปัจจุบันใช้ 2 mL/kg/%TBSA สำหรับ thermal burn: 2 x 60 x 40 = 4,800 mL/24 ชม.; ครึ่งแรกใน 8 ชม. = 2,400 mL -> 300 mL/ชม.", "sys": "XVIII"}, {"topic": "Urosurgery", "q": "A 65-year-old male with difficulty urinating, incomplete bladder emptying, frequency and nocturia 3 times/night. DRE: enlarged prostate, no nodules, firm consistency. PSA 3 ng/mL (normal <4). Most appropriate management?", "choices": ["Transurethral resection of the prostate (TUR-P)", "5-alpha reductase inhibitor", "Alpha blocker", "Combination of alpha blocker and 5-alpha reductase inhibitor", "Watchful waiting"], "ans": 2, "exp": "BPH ที่มีอาการปานกลาง (LUTS) PSA ปกติ ไม่มีก้อนแข็ง -> เริ่มยา alpha-blocker (เช่น tamsulosin) คลายกล้ามเนื้อคอกระเพาะปัสสาวะ ให้ผลเร็ว เป็น first-line", "sys": "XIV"}, {"topic": "Urosurgery", "q": "A 65-year-old man with LUTS (straining, incomplete emptying, poor stream). DRE reveals enlarged prostate, no nodules. Appropriate treatment?", "choices": ["Transurethral resection of the prostate (TURP)", "Urodynamic study", "Behavior modification", "Alpha antagonist", "5-alpha reductase inhibitor"], "ans": 3, "exp": "BPH ที่มีอาการ (LUTS) ไม่มีข้อบ่งชี้ผ่าตัด -> เริ่มยา alpha-antagonist (alpha-blocker) เป็นการรักษาหลัก. TURP เก็บไว้เมื่อมีภาวะแทรกซ้อน/ล้มเหลวจากยา", "sys": "XIV"}, {"topic": "Urosurgery", "q": "A 21-year-old man with pain and swelling of the prepuce after sexual intercourse. Retracted foreskin cannot be returned to normal position, with swelling and pain. Diagnosis?", "choices": ["Balanitis", "Balanophimosis", "Paraffinoma", "Peyronie's disease", "Paraphimosis"], "ans": 4, "exp": "หนังหุ้มปลายที่รูดลงแล้วดันกลับไม่ได้ + บวมเจ็บ = paraphimosis (ภาวะฉุกเฉิน ต้องรีบดันกลับเพื่อป้องกัน ischemia)", "sys": "flex"}, {"topic": "Urosurgery", "q": "A 40-year-old male with right flank pain and hematuria following a motor vehicle accident. 10 cm abrasion at right flank with mild tenderness. UA RBC >100, WBC 2-3. FAST negative. Most appropriate investigation?", "choices": ["CT scan of the whole abdomen", "Observation", "Intravenous pyelogram (IVP)", "Serial urinalysis", "Ultrasound of the kidneys, ureters, and bladder (KUB)"], "ans": 0, "exp": "สงสัยบาดเจ็บไต (flank trauma + gross hematuria) -> CT whole abdomen with contrast เป็น investigation ที่ดีที่สุดในการประเมินระดับความรุนแรงของ renal injury (FAST ลบไม่ได้แปลว่าไม่มีบาดเจ็บไต)", "sys": "XIV"}, {"topic": "Pediatrics", "q": "A term newborn, birth weight 2100g, with immediate respiratory distress after birth. T 36.5, RR 60, PR 150, dyspnea, cyanosis, decreased breath sounds on the left side, scaphoid abdomen. Initial management step?", "choices": ["Positive pressure ventilation", "Endotracheal intubation", "Chest X-ray", "Abdominal X-ray", "Emergency pleural tapping"], "ans": 1, "exp": "scaphoid abdomen + เสียงหายใจซ้ายลด + distress ทันทีหลังคลอด = congenital diaphragmatic hernia -> ใส่ท่อช่วยหายใจ (ETT) และ NG decompression; ห้ามใช้ bag-mask/PPV เพราะจะทำให้ลำไส้ในทรวงอกโป่ง กดปอดมากขึ้น", "sys": "XVI"}, {"topic": "Pediatrics", "q": "A term newborn 3100g, born via cesarean for fetal distress with thick meconium-stained amniotic fluid, HR 80 and hypotonia immediately after birth. Initial next step in management?", "choices": ["Intubation with meconium aspiration", "Positive pressure ventilation", "Provide warm and tactile stimulation", "100% oxygen via free flow", "Perform a Chest X-Ray (CXR)"], "ans": 2, "exp": "ทารก non-vigorous ที่มี meconium -> แนวทาง NRP ปัจจุบัน 'ไม่' ดูด/ใส่ท่อดูด meconium เป็น routine แล้ว แต่ให้ทำ initial steps (ให้ความอบอุ่น เช็ดตัว กระตุ้น) ก่อน แล้วประเมิน HR หากยังต่ำจึง PPV", "sys": "XV"}, {"topic": "Pediatrics", "q": "A term infant with Apgar 2 and 6, required intubation. Two hours later develops subtle seizures. Lethargic, T 36.7, HR 150, RR 50, BP 60/38, hypotonia, pupils 4 mm reactive. Hct 48%, DTX 50 mg/dL. Most appropriate initial management?", "choices": ["10% Dextrose Water (DW)", "Phenytoin", "Midazolam", "Phenobarbital", "Sodium valproate"], "ans": 3, "exp": "ทารกขาดออกซิเจนแรกคลอด (HIE) + ชัก โดยน้ำตาลปกติ (DTX 50) -> ยากันชักตัวแรกในทารกแรกเกิดคือ phenobarbital", "sys": "XVI"}, {"topic": "Pediatrics", "q": "A 36-week infant delivered by emergency cesarean, dyspnea shortly after birth. CXR shows hyperaeration and bilateral interstitial infiltration. Most appropriate management?", "choices": ["Intubation", "Continuous Positive Airway Pressure (CPAP)", "Surfactant therapy", "Antibiotics", "Oxygen supplement"], "ans": 4, "exp": "C/S + หายใจเร็วหลังคลอด + CXR hyperaeration/interstitial infiltrate = transient tachypnea of newborn (TTN) -> รักษาแบบประคับประคองด้วยออกซิเจน (self-limited ภายใน 24-72 ชม.)", "sys": "XV"}, {"topic": "Pediatrics", "q": "A 36-week infant delivered by emergency cesarean, tachypnea 2 hours after birth. HR 150, RR 65, SpO2 94% room air, nasal flaring and mild subcostal retraction. CXR slight hyperaeration and bilateral interstitial infiltration. Most appropriate management?", "choices": ["Nasal Continuous Positive Airway Pressure (CPAP)", "Intubation", "Intravenous antibiotics", "Oxygen supplement", "Surfactant"], "ans": 0, "exp": "TTN ที่มี work of breathing เพิ่ม (nasal flaring, retraction) แต่ SpO2 ยังพอ -> nasal CPAP ช่วยลดงานการหายใจและคง functional residual capacity ได้ดีในภาวะน้ำในปอดคั่ง", "sys": "XV"}, {"topic": "Pediatrics", "q": "A term 2000g infant, jitteriness at 2 hours, plethoric. Hct 68%, capillary glucose 30 mg/dL. Given 10% glucose IV push 2 cc/kg then GIR 6 mg/kg/min, TV 65 ml/kg/day. Next appropriate management step?", "choices": ["Phenobarbital", "Partial plasma exchange", "10% Calcium gluconate", "Early feeding", "Increase total volume to 90 ml/kg/day"], "ans": 1, "exp": "Hct 68 = polycythemia และมีอาการ (jitteriness) หลังแก้น้ำตาลแล้ว -> ทำ partial exchange transfusion เพื่อลด hematocrit (symptomatic polycythemia Hct >65)", "sys": "III"}, {"topic": "Pediatrics", "q": "A 3-month-old female with fever and irritability, refusing feeds, high-pitched cry. T 38.5, HR 160, RR 40, lethargic, stiff neck, no bulging anterior fontanelle. Next appropriate step in management?", "choices": ["Head ultrasound", "Blood cultures", "Lumbar puncture", "Intravenous antibiotics", "Computed tomography (CT) scan of the head"], "ans": 2, "exp": "สงสัยเยื่อหุ้มสมองอักเสบ (ไข้ ซึม คอแข็ง เสียงร้องแหลม) ในทารก ที่ยังไม่มีสัญญาณ increased ICP ชัด -> ทำ lumbar puncture เพื่อวินิจฉัย แล้วให้ยาปฏิชีวนะทันที (ถ้า LP ล่าช้าให้ ATB ก่อน)", "sys": "flex"}, {"topic": "Pediatrics", "q": "A term newborn delivered by vacuum extraction with a soft, fluctuant mass on the head that crosses suture lines. Subsequently develops a drop in blood pressure. Most likely diagnosis?", "choices": ["Caput succedaneum", "Cephalhematoma", "Subdural hematoma", "Subgaleal hemorrhage", "Epidural hematoma"], "ans": 3, "exp": "ก้อนนุ่มบนศีรษะที่ข้าม suture line + มีภาวะช็อก/ความดันตก (เสียเลือดปริมาณมาก) หลังคลอดด้วย vacuum = subgaleal hemorrhage. cephalhematoma จะไม่ข้าม suture และไม่ทำให้ช็อก", "sys": "XVI"}, {"topic": "Pediatrics", "q": "A 39-week newborn with progressive jaundice within the first 24 hours. Mother had no ANC, Group A Rh-positive. Birth weight 3000g, active baby with mild jaundice. Microbilirubin 10%, reticulocyte 10%, mild positive direct antiglobulin test. Most likely diagnosis?", "choices": ["Hypothyroidism", "Neonatal sepsis", "Alpha thalassemia", "Breastfeeding jaundice", "ABO incompatibility"], "ans": 4, "exp": "ดีซ่านภายใน 24 ชม.แรก + เม็ดเลือดแดงแตก (retic สูง) + DAT บวก = isoimmune hemolysis จาก ABO incompatibility. เกิดจากแอนติบอดีของแม่ต่อหมู่เลือดลูก (จาก mismatch) *ดีซ่านเร็วเกินไปสำหรับ breastfeeding jaundice*", "sys": "XVI"}, {"topic": "Pediatrics", "q": "A 2-day-old exclusively breastfed infant, 38 weeks, birth weight 3300g (now 3000g), Apgar 6/9. Mother O Rh-positive. T 37.3, HR 128, RR 68, BP 60/40. At 48 hours: microbilirubin 14 mg/dL, Hct 65. Most appropriate management?", "choices": ["Phototherapy", "Follow-up in the next 2 days", "Follow-up at age 2 weeks", "Total exchange transfusion", "Infant formula supplementation"], "ans": 0, "exp": "bilirubin 14 mg/dL ที่อายุ 48 ชม. เมื่อ plot บน nomogram อยู่ในโซนเสี่ยงสูงที่ควรได้ phototherapy. *อ้างอิงกราฟ nomogram*", "img": "https://cdn.jsdelivr.net/gh/MercenzK/Web-quiz-images@main/NL2-2024-Q141.1.png", "sys": "XVI"}, {"topic": "Pediatrics", "q": "A term female newborn (mother no ANC) with flat facial appearance, upslanted palpebral fissures, wide-spaced eyes, single transverse palmar crease, hypotonia, and a pansystolic murmur. Most likely chromosomal anomaly?", "choices": ["Trisomy 13", "Trisomy 21", "Trisomy 18", "XO chromosome", "XXY chromosome"], "ans": 1, "exp": "หน้าแบน ตาเฉียงขึ้น เส้นลายมือขวางเส้นเดียว (simian crease) + hypotonia + murmur (AVSD/VSD) = Down syndrome = trisomy 21", "sys": "XVI"}, {"topic": "Pediatrics", "q": "A 2100g male infant (mother no ANC). HC 27 cm, chest 27 cm, length 40 cm. Clouded lens, no pallor/jaundice, grade III systolic ejection murmur at left upper parasternal border, clear lungs, liver +4 cm, spleen +1 cm. Most likely diagnosis?", "choices": ["Congenital cytomegalovirus (CMV) infection", "Congenital syphilis", "Congenital rubella syndrome", "Congenital toxoplasmosis", "Retinoblastoma"], "ans": 2, "exp": "ต้อกระจกแต่กำเนิด (clouded lens) + โรคหัวใจ (PDA/PS ที่ murmur LUSB) + ตับม้ามโต + IUGR = congenital rubella syndrome (triad: cataract, heart defect, deafness)", "sys": "XVII"}, {"topic": "Pediatrics", "q": "A 9-year-old boy in cardiac arrest. After 2 minutes of CPR, the EKG is shown and there is no pulse. Next appropriate management step?", "choices": ["Adenosine", "Synchronized cardioversion", "Defibrillation", "Adrenaline (Epinephrine)", "Amiodarone"], "ans": 3, "exp": "*จากภาพจริง* EKG เป็นเส้นแบน/แทบไม่มี QRS = asystole (non-shockable rhythm) -> ทำ CPR ต่อและให้ adrenaline (epinephrine) ทุก 3-5 นาที ไม่ช็อกไฟฟ้า (defibrillation ใช้เฉพาะ VF/pulseless VT)", "img": "https://cdn.jsdelivr.net/gh/MercenzK/Web-quiz-images@main/NL2-2024-Q144.png", "sys": "IV"}, {"topic": "Pediatrics", "q": "An 18-month-old boy with crying, hyperpnea, and cyanosis following vaccination. T 37, HR 180, RR 50, limpness, deep cyanosis, normal S1S2, no murmur, clear lungs, clubbing of fingers. Most likely diagnosis?", "choices": ["Seizure", "Anaphylaxis", "Breath holding spell", "Hypotonia hyporesponsive episode", "Anoxic spell"], "ans": 4, "exp": "clubbing = โรคหัวใจเขียวเรื้อรัง (เช่น TOF); ร้อง -> เขียวเฉียบพลัน + hyperpnea = hypercyanotic (anoxic/Tet) spell ถูกกระตุ้นจากการร้อง", "sys": "VI"}, {"topic": "Pediatrics", "q": "An 18-month-old boy with crying, hyperpnea, cyanosis, and clubbing of the fingers following vaccination. Other examination normal. Most likely diagnosis?", "choices": ["Anoxic spell", "Breath holding spell", "Hypotonic-hyporesponsive episode", "Vasovagal syncope", "Febrile seizure"], "ans": 0, "exp": "clubbing บ่งโรคหัวใจเขียวเรื้อรัง + เขียวเมื่อร้อง = anoxic spell (hypercyanotic spell) ของ tetralogy of Fallot", "sys": "VI"}, {"topic": "Pediatrics", "q": "A 10-year-old boy with fever and pharyngitis 4 days, not improved with amoxicillin. Today developed dyspnea. T 38, BP 100/60, RR 25, fine crepitations at left lower lobe. CXR interstitial infiltration LLL. No improvement. Most appropriate management?", "choices": ["Cefdinir", "Azithromycin", "Ceftriaxone", "High-dose amoxicillin", "Amoxicillin-clavulanic acid"], "ans": 1, "exp": "ปอดอักเสบที่ไม่ตอบสนอง beta-lactam (amoxicillin) + interstitial infiltrate ในเด็กโต = atypical pneumonia (Mycoplasma) -> รักษาด้วย macrolide (azithromycin)", "sys": "X"}, {"topic": "Pediatrics", "q": "A 9-month-old infant eating round foods presents with coughing followed by aphonia, conscious but cyanotic, with an ineffective cough. Most appropriate management?", "choices": ["Heimlich maneuver", "Two-thumb compression", "Back blows and chest thrusts", "Endotracheal intubation (ETT)", "Chest X-Ray"], "ans": 2, "exp": "สำลักสิ่งแปลกปลอมอุดหลอดลมรุนแรง (ไอไม่ได้ผล เขียว) ในทารก (<1 ปี) + ยังรู้สึกตัว -> ทำ back blows 5 ครั้ง สลับ chest thrusts 5 ครั้ง (ไม่ใช้ Heimlich ในทารก)", "sys": "X"}, {"topic": "Pediatrics", "q": "A 4-year-old child with dyspnea and cough after playing with a toy. No fever, PR 100, no cyanosis, expiratory wheezing in the right lung. Initial management?", "choices": ["Bronchoscopy", "Heimlich maneuver", "Laryngoscope", "Chest X-ray (CXR)", "Administration of bronchodilators"], "ans": 3, "exp": "สงสัยสำลักสิ่งแปลกปลอม (unilateral wheeze หลังเล่นของเล่น) ในเด็กที่ยัง stable -> เริ่มด้วย chest X-ray เพื่อประเมิน/ระบุตำแหน่ง ก่อนทำ rigid bronchoscopy เอาออก", "sys": "X"}, {"topic": "Pediatrics", "q": "A 2-year-old child with sudden dyspnea and cough while playing with a toy alone. T 37.5, PR 100, RR 32, no cyanosis, expiratory wheezing in the right lung. Most appropriate initial management?", "choices": ["Bronchoscopy", "Heimlich maneuver", "Inhalation of salbutamol", "Direct laryngoscope", "Chest X-ray (CXR)"], "ans": 4, "exp": "foreign body aspiration ที่ stable -> chest X-ray เป็น initial investigation (อาจพบ hyperinflation/air trapping ข้างที่อุด) ก่อนส่ง rigid bronchoscopy", "sys": "X"}, {"topic": "Pediatrics", "q": "A 3-year-old boy with incomplete vaccination presents with fever, runny nose, cough 3 days, worse today with dyspnea. T 39, PR 110, RR 35, BP 90/60, hoarseness, stridor, grayish-dirty patches on tonsils and pharynx with contact bleeding, suprasternal and intercostal retractions. Most appropriate management?", "choices": ["Tracheostomy", "Chest X-ray", "Throat swab culture", "Epinephrine nebulizer", "Endotracheal intubation"], "ans": 0, "exp": "แผ่นเทาสกปรก (pseudomembrane) ที่ทอนซิล/คอหอย เลือดออกเมื่อสัมผัส + stridor + วัคซีนไม่ครบ = diphtheria + ทางเดินหายใจอุดกั้น -> ต้อง secure airway ด้วย tracheostomy (การใส่ ETT เสี่ยงดัน membrane หลุดอุดหลอดลม/เลือดออก)", "sys": "X"}, {"topic": "Pediatrics", "q": "A 3-year-old child with watery rhinorrhea and nasal itching 5 days/week over 6 weeks, severe enough that the child could not attend swimming class for 3 weeks. Most appropriate treatment?", "choices": ["Oral corticosteroids", "Intranasal corticosteroids", "Inhaled beta2 agonist", "Inhaled corticosteroids", "Intranasal decongestant"], "ans": 1, "exp": "allergic rhinitis ชนิด persistent moderate-severe (เป็น >4 วัน/สัปดาห์ นานหลายสัปดาห์ รบกวนกิจกรรม) -> ยาที่ได้ผลดีที่สุดคือ intranasal corticosteroids", "sys": "X"}, {"topic": "Pediatrics", "q": "A 3-year-old boy with watery rhinorrhea and nasal itching 5 days/week over 6 weeks, significant enough to interfere with activities and prevent swimming lessons for 3 weeks. Most appropriate management?", "choices": ["Oral corticosteroid", "Inhaled corticosteroid", "Intranasal corticosteroid", "Inhaled beta2 agonist", "Intranasal decongestant"], "ans": 2, "exp": "persistent moderate-severe allergic rhinitis -> intranasal corticosteroid เป็นยาที่มีประสิทธิภาพสูงสุด", "sys": "X"}, {"topic": "Pediatrics", "q": "A 1-year-old girl with 2-day worsening respiratory symptoms, initially mild cough and low-grade fever. Now inspiratory stridor, harsh cough, hoarseness, suprasternal retraction, SpO2 93%. T 38.5, HR 120, RR 28, no wheezing, alert but distressed, worse when agitated. Most appropriate management?", "choices": ["Nebulized ipratropium", "Oral corticosteroids", "Intranasal decongestants", "Nebulized epinephrine", "Endotracheal intubation"], "ans": 3, "exp": "croup ระดับปานกลาง-รุนแรง (stridor + suprasternal retraction ขณะพัก) -> พ่น nebulized epinephrine เพื่อลดบวมทางเดินหายใจส่วนบนอย่างรวดเร็ว (ร่วมกับ dexamethasone)", "sys": "X"}, {"topic": "Pediatrics", "q": "A 1-year-old boy with fever, cough, hoarseness, inspiratory stridor, no wheezing, SpO2 94%, suprasternal retraction, moderate croup. Most appropriate management?", "choices": ["Nebulized salbutamol", "Nebulized ipratropium", "Normal saline", "Hypertonic saline", "Nebulized adrenaline"], "ans": 4, "exp": "moderate croup ที่มี stridor + retraction -> พ่น nebulized adrenaline (epinephrine) ลดบวม subglottic (ร่วมกับ steroid). salbutamol/ipratropium ไม่ช่วยใน croup", "sys": "IV"}, {"topic": "Pediatrics", "q": "A 4-year-old with dyspnea, no improvement after three doses of nebulized salbutamol. T 38, BP 100/70, RR 40, PR 130, SpO2 90%, poor air entry. Most appropriate management?", "choices": ["Nebulized ipratropium", "Intravenous theophylline", "Oral prednisolone", "Nebulized budesonide", "Subcutaneous terbutaline"], "ans": 0, "exp": "asthma exacerbation รุนแรงที่ไม่ตอบสนอง SABA -> เพิ่ม nebulized ipratropium (anticholinergic) ร่วมกับ salbutamol และให้ systemic corticosteroid ควบคู่", "sys": "IX"}, {"topic": "Pediatrics", "q": "A 4-year-old boy with dyspnea, symptoms persist despite three doses of bronchodilator nebulization. T 38, RR 40, PR 100, BP 110/70, poor air entry. Next step in management?", "choices": ["Inhaled budesonide", "Intravenous magnesium sulfate", "Inhaled ipratropium", "Subcutaneous terbutaline", "Oral prednisolone"], "ans": 1, "exp": "asthma รุนแรงที่ล้มเหลวจาก SABA + ipratropium + steroid -> ขั้นถัดไปคือ IV magnesium sulfate ช่วยคลายหลอดลมในรายรุนแรง", "sys": "X"}, {"topic": "Pediatrics", "q": "A 6-year-old boy with asthma, dyspnea after 3 days fever/coryza. RR 55, BP 90/50, PR 120, SpO2 90%, retractions, wheeze. After three doses of nebulized salbutamol he is drowsy with severe retractions, SpO2 still 90%, poor air entry (silent chest). Most beneficial next management besides intubation?", "choices": ["Nebulized ipratropium bromide", "Subcutaneous terbutaline", "Intravenous magnesium sulfate", "Intravenous antibiotics", "Intravenous corticosteroids"], "ans": 2, "exp": "near-fatal asthma (ซึม silent chest หลังให้ SABA เต็มที่) -> IV magnesium sulfate เป็นยาช่วยคลายหลอดลมในรายวิกฤต (นอกเหนือจากการใส่ท่อช่วยหายใจ)", "sys": "X"}, {"topic": "Pediatrics", "q": "A 12-year-old girl with 2-month intermittent vomiting, cough, and epigastric pain, prefers snacks and high-fat foods. Obese, weight 70 kg, height 130 cm. Most appropriate management?", "choices": ["Aluminum hydroxide suspension", "Sucralfate", "Ranitidine", "Omeprazole", "Domperidone"], "ans": 3, "exp": "อาการ GERD ในเด็กอ้วน (ปวดลิ้นปี่ อาเจียน ไอ) -> ยาที่ได้ผลดีที่สุดคือ proton pump inhibitor (omeprazole)", "sys": "X"}, {"topic": "Pediatrics", "q": "A 2-year-old child with vomiting and watery diarrhea 2 days, preceded by rhinorrhea and cough. T 38, BP 90/60, dry lips, hyperactive bowel sounds, perianal erythema. Stool exam shows no RBC or WBC. Most likely causative organism?", "choices": ["Vibrio cholerae", "Giardia lamblia", "Salmonella", "Staphylococcus aureus", "Rotavirus"], "ans": 4, "exp": "ท้องเสียเป็นน้ำ (ไม่มี WBC/RBC ในอุจจาระ = non-inflammatory) นำมาด้วยอาการหวัด + ผื่นแดงรอบทวารจากอุจจาระเป็นกรด ในเด็กเล็ก = rotavirus", "sys": "I"}, {"topic": "Pediatrics", "q": "A 4-year-old with status epilepticus given two doses of diazepam but continues to seize. ABC management completed. Most appropriate next step?", "choices": ["Phenytoin", "Midazolam", "Repeat diazepam", "Phenobarbital", "Levetiracetam"], "ans": 0, "exp": "status epilepticus ที่ไม่หยุดหลัง benzodiazepine 2 ครั้ง -> ยา second-line คือ phenytoin (fosphenytoin) (หรือ levetiracetam/valproate) เพื่อหยุดชัก", "sys": "VI"}, {"topic": "Pediatrics", "q": "A 4-year-old girl with fever, decreased appetite, drowsiness, stiff neck. T 38.5, RR 24, HR 100, DTR 3+. CSF: opening pressure 30, WBC 550 (80% lymphocytes), glucose 20, protein ~800. Gram stain and Indian ink negative. Most appropriate treatment?", "choices": ["Acyclovir", "Isoniazid, Rifampin, Pyrazinamide, Ethambutol (IRZE)", "Oseltamivir", "Cefotaxime", "Amphotericin B"], "ans": 1, "exp": "CSF: lymphocyte เด่น + น้ำตาลต่ำมาก + โปรตีนสูงมาก + OP สูง gram/India ink ลบ = tuberculous meningitis -> รักษาด้วย anti-TB (IRZE) + steroid", "sys": "VI"}, {"topic": "Pediatrics", "q": "A 14-year-old girl with severe headache, vomiting, confusion. T 39, BP 80/60, PR 140, RR 24. Confusion, stiff neck, purpuric rash on arms and trunk. Most appropriate management?", "choices": ["Ciprofloxacin", "Imipenem", "Ceftriaxone", "Amoxicillin-clavulanate", "Vancomycin"], "ans": 2, "exp": "meningococcemia/meningitis (ไข้ + คอแข็ง + ผื่นจ้ำเลือด purpura + ช็อก) -> ให้ ceftriaxone ทันที (empiric ครอบคลุม Neisseria meningitidis/pneumococcus)", "sys": "III"}, {"topic": "Pediatrics", "q": "A 3-year-old with nephrotic syndrome presents with generalized edema, hypotension (BP 80/50), PR 100, drowsy, anasarca, bilateral lung crepitations, marked ascites, albumin 1.2. Most appropriate initial management?", "choices": ["Furosemide", "Dobutamine", "Intravenous antibiotics", "20% albumin", "Intravenous corticosteroids"], "ans": 3, "exp": "nephrotic syndrome ที่มี hypovolemic shock (ความดันตก ซึม แม้บวมทั้งตัว เพราะ intravascular volume ต่ำจาก albumin ต่ำ) -> ให้ 20% albumin เพิ่ม intravascular volume แล้วตามด้วย furosemide", "sys": "IX"}, {"topic": "Pediatrics", "q": "A 20-year-old male with red urine for 1 day, history of acute pharyngitis for 3 days. T 37, BP 120/80, PR 80, RR 20. No puffy eyelids, rash, or arthralgia. UA: SG 1.010, trace protein, 4+ blood, dysmorphic RBCs. Most likely diagnosis?", "choices": ["Henoch-Schonlein purpura (HSP)", "Acute poststreptococcal glomerulonephritis (APSGN)", "Membranoproliferative glomerulonephritis", "Alport syndrome", "IgA nephropathy"], "ans": 4, "exp": "ปัสสาวะเป็นเลือด (dysmorphic RBC = glomerular) พร้อม ๆ กับคออักเสบ (synpharyngitic, 1-3 วัน) โดยไม่มีบวม/ความดันสูง = IgA nephropathy. APSGN จะเกิดหลังติดเชื้อ 1-3 สัปดาห์ และมีบวม/ความดันสูง. *อ้างอิงภาพ*", "img": "https://cdn.jsdelivr.net/gh/MercenzK/Web-quiz-images@main/NL2-2024-Q165.png", "sys": "III"}, {"topic": "Pediatrics", "q": "A 4-year-old with generalized edema worsening over a week. T 37, HR 100, BP 80/60, puffy eyelids, decreased breath sounds lower lungs bilaterally, ascites, scrotal edema, pitting edema both legs. UA: SG 1.015, 4+ protein, 0-1 WBC/RBC. Serum albumin 1.2. Most appropriate initial management?", "choices": ["20% albumin", "Furosemide", "Dobutamine", "Spironolactone", "Hydrochlorothiazide (HCTZ)"], "ans": 0, "exp": "nephrotic syndrome + บวมรุนแรง (anasarca, effusion, ascites) + albumin ต่ำมาก + ความดันค่อนข้างต่ำ (intravascular depletion) -> ให้ 20% albumin เพื่อดึงน้ำกลับเข้าหลอดเลือดแล้วตามด้วย furosemide (การให้ diuretic เดี่ยว ๆ เสี่ยง hypovolemia)", "sys": "XI"}, {"topic": "Pediatrics", "q": "A 7-month-old with 2-day fever and persistent crying during urination. T 38, HR 140. CBC WBC 14,000 with PMN predominance. UA: WBC 50-100, positive leukocyte esterase, positive nitrites. Most appropriate management?", "choices": ["Imipenem", "Ceftriaxone", "Ciprofloxacin", "Ampicillin", "Fluid hydration"], "ans": 1, "exp": "febrile UTI/pyelonephritis ในทารก -> ให้ยาปฏิชีวนะฉีด ceftriaxone (third-generation cephalosporin) ครอบคลุมเชื้อ gram-negative (E. coli)", "sys": "XIV"}, {"topic": "Pediatrics", "q": "A healthy 7-month-old boy with fever 2 days and crying every time he voids. T 39, PR 130, RR 30. CBC Hb 11.5, WBC 14,500 (N70 L30), platelets 220,000. UA: WBC 50-100/HPF, RBC 1-2, leukocyte esterase positive, nitrite positive. Most appropriate treatment?", "choices": ["Ampicillin IV", "Imipenem IV", "Ceftriaxone IV", "Ciprofloxacin PO", "Amoxicillin-clavulanic acid PO"], "ans": 2, "exp": "febrile UTI ในทารก 7 เดือน -> เริ่มยาฉีด ceftriaxone IV (ครอบคลุม E. coli, admit เพราะเด็กเล็กมีไข้)", "sys": "XIV"}, {"topic": "Pediatrics", "q": "A teenage female with palpitations, tremors, weight loss for 3 months. Diffuse smooth firm non-tender thyroid enlargement. FT3 elevated, FT4 2.1 (elevated), TSH 3 (normal). Most appropriate management?", "choices": ["Propranolol", "Prednisolone", "Thyroidectomy", "Methimazole", "Radioactive iodine therapy (RAI)"], "ans": 3, "exp": "hyperthyroidism (Graves) ในวัยรุ่น (คอพอกโตทั่ว + อาการ thyrotoxic) -> ยา first-line คือ methimazole (antithyroid). RAI/ผ่าตัดเก็บไว้กรณีล้มเหลว/แพ้ยา", "sys": "IV"}, {"topic": "Pediatrics", "q": "A 15-year-old girl with progressive thyroid enlargement over 6 months, diffuse ~30 grams, no nodules, no hyper/hypothyroid signs. FT4 normal, TSH normal, anti-TPO negative, anti-TSH receptor negative. Most appropriate management?", "choices": ["Methimazole", "Thyroxine", "Surgery", "Prednisolone", "Reassure"], "ans": 4, "exp": "euthyroid diffuse goiter ในวัยรุ่น (simple/colloid goiter) TFT ปกติ antibody ลบ -> เพียง reassure และติดตาม ไม่ต้องรักษาด้วยยา/ผ่าตัด", "sys": "IV"}, {"topic": "Pediatrics", "q": "A 14-year-old girl with fever and neck pain. Mild thyroid enlargement, normal thyroid function tests, no hyper/hypothyroid symptoms. Most appropriate management?", "choices": ["Ibuprofen", "Prednisolone", "Methimazole", "Amoxicillin", "Iodine solution"], "ans": 0, "exp": "ต่อมไทรอยด์โตเจ็บ + ไข้ + TFT ปกติ = subacute (de Quervain) thyroiditis -> รักษาด้วย NSAIDs (ibuprofen) บรรเทาปวด/อักเสบ (รายรุนแรงใช้ steroid)", "sys": "I"}, {"topic": "Pediatrics", "q": "A 4-year-old boy with impaired night vision and history of chronic diarrhea. Weight 12 kg, height 95 cm, dry conjunctivae with follicular keratosis on both elbows and knees. Most appropriate investigation?", "choices": ["Skin biopsy", "Serum retinol", "Ocular tonometry", "EEG", "Slit lamp"], "ans": 1, "exp": "ตาบอดกลางคืน + เยื่อบุตาแห้ง (xerophthalmia) + follicular keratosis + ท้องเสียเรื้อรัง (ดูดซึมไม่ดี) = vitamin A deficiency -> ตรวจ serum retinol (vitamin A)", "sys": "VII"}, {"topic": "Pediatrics", "q": "A 7-year-old girl with chronic-relapsing itchy rash since age 4 (shown). Most likely diagnosis?", "choices": ["Psoriasis", "Allergic contact dermatitis", "Atopic dermatitis", "Irritant contact dermatitis", "Scabiasis"], "ans": 2, "exp": "ผื่นคันเรื้อรังเป็น ๆ หาย ๆ ตั้งแต่เด็ก (มักที่ข้อพับ) = atopic dermatitis. *อ้างอิงภาพ*", "img": "https://cdn.jsdelivr.net/gh/MercenzK/Web-quiz-images@main/NL2-2024-Q173.png", "sys": "XII"}, {"topic": "Pediatrics", "q": "A 12-year-old boy with abdominal pain for 2 days, history of rash and arthralgia but no fever for the past 10 days. Stable vitals, soft non-tender abdomen, no hepatosplenomegaly. Most serious complication associated with his condition?", "choices": ["Carditis", "Gastrointestinal hemorrhage", "Acute hemolysis", "Glomerulonephritis", "Intracerebral hemorrhage"], "ans": 3, "exp": "ผื่น (palpable purpura) + ปวดข้อ + ปวดท้อง = Henoch-Schonlein purpura (IgA vasculitis). ภาวะแทรกซ้อนที่ร้ายแรงที่สุดในระยะยาวคือ glomerulonephritis (HSP nephritis) ที่อาจนำไปสู่ไตวายเรื้อรัง", "sys": "III"}, {"topic": "Pediatrics", "q": "A 9-year-old boy with fever and malaise 5 days. T 39.5, PR 110, RR 22, BP 110/70. Bilateral conjunctival injection, mild icteric sclera, calf pain, hepatomegaly. WBC 16,000 (90% N), Hct 36, platelets 100,000. UA: SG 1.008, protein 1+, RBC 2+, WBC 10-20/hpf. Most appropriate antibiotic?", "choices": ["Ceftazidime", "Doxycycline", "Azithromycin", "Ciprofloxacin", "Penicillin G"], "ans": 4, "exp": "conjunctival suffusion + ปวดน่อง (myalgia) + ดีซ่าน + ตับโต + ไตอักเสบ = leptospirosis (Weil's disease รุนแรง) -> รักษาด้วย IV penicillin G (รายไม่รุนแรงใช้ doxycycline)", "sys": "I"}, {"topic": "Pediatrics", "q": "A 7-year-old boy with high fever 39 for 1 day, wound on left leg from bicycle accident 5 days ago. Ill and dyspneic, PR 120, BP 100/60. Fine crepitations bilaterally, multiple abrasions with surrounding redness around the leg wound. CXR shows scattered nodular infiltrates. Most appropriate antibiotic?", "choices": ["Cloxacillin", "Ceftazidime", "Clindamycin", "Meropenem", "Vancomycin"], "ans": 0, "exp": "แผลผิวหนังติดเชื้อ -> bacteremia -> septic pulmonary emboli (scattered nodular infiltrates เป็นลักษณะเด่น) = Staphylococcus aureus -> cloxacillin (ครอบคลุม MSSA); ถ้าสงสัย MRSA จึงใช้ vancomycin", "sys": "IX"}, {"topic": "Pediatrics", "q": "A 7-month-old girl with UTI symptoms (irritability, fever), urinalysis positive nitrites. Ill-appearing, stable vitals, T 38.3, soft non-tender abdomen. Urine culture pending. Most appropriate antibiotics?", "choices": ["Ciprofloxacin", "Ceftriaxone", "Ceftazidime", "Amoxicillin-clavulanate", "Gentamicin"], "ans": 1, "exp": "febrile UTI ในทารก -> ceftriaxone (third-generation cephalosporin ฉีด) ครอบคลุม E. coli เป็น first-line", "sys": "XIV"}, {"topic": "Pediatrics", "q": "A 2-year-old male with 3-day fever and rash of vesicles on hands, feet, and oral mucosa, in various stages. Attends daycare. What is the most effective method to prevent spreading in the nursery?", "choices": ["Immunization", "Hand sanitization with alcohol", "Frequent hand washing", "Close nursery for 1 week", "Face masks for children and caretakers"], "ans": 2, "exp": "hand-foot-mouth disease (enterovirus/coxsackie) แพร่ทาง fecal-oral -> ป้องกันการแพร่ได้ดีที่สุดด้วยการล้างมือบ่อย ๆ ด้วยสบู่และน้ำ (แอลกอฮอล์ฆ่า enterovirus ที่ไม่มีเปลือกได้ไม่ดี)", "sys": "I"}, {"topic": "Pediatrics", "q": "A 6-year-old boy with 4-day high fever and generalized myalgia, now RUQ tenderness and dyspnea. Febrile 39.5, RUQ tenderness, hepatomegaly, bilateral crepitations. WBC with atypical lymphocytes 10%, platelets 80,000. PBS: atypical lymphocytes. Most appropriate investigation to confirm diagnosis?", "choices": ["Dengue IgM/IgG", "Indirect immunofluorescence assay (IFA) for scrub typhus", "Influenza testing", "NS1 antigen", "Leptospirosis serology"], "ans": 3, "exp": "ไข้ + ปวดเมื่อย + ตับโต + atypical lymphocyte + เกล็ดเลือดต่ำ = dengue. ในช่วงไข้วันแรก ๆ (<5 วัน) ตรวจ NS1 antigen ยืนยันได้ดีที่สุด", "sys": "I"}, {"topic": "Pediatrics", "q": "A 7-year-old boy (20 kg) with high fever, poor intake, nausea, vomiting, now abdominal pain. T 37.8, PR 120, RR 30, BP 90/70. Petechiae on both arms, hepatomegaly 3 cm, abdominal tenderness. Appropriate initial management within the first hour?", "choices": ["Normal saline (NSS) 100 ml", "5% dextrose in normal saline (D5NS) 100 ml", "5% dextrose in normal saline (D5NS) 200 ml", "5% albumin 100 ml", "Normal saline (NSS) 200 ml"], "ans": 4, "exp": "dengue ที่มี narrow pulse pressure (90/70 = 20 mmHg) = compensated shock -> ให้ isotonic crystalloid (NSS) 10 ml/kg = 200 ml ใน 1 ชม.แรก", "sys": "I"}, {"topic": "Pediatrics", "q": "A 4-year-old boy (10 kg) with recurrent abdominal pain and vomiting, mild pallor. Abdominal film shows generalized small bowel dilatation. Stool exam reveals eggs (shown). Most likely infectious cause?", "choices": ["Ascariasis", "Strongyloidiasis", "Gnathostomiasis", "Taenia solium infestation", "Hookworm infestation"], "ans": 0, "exp": "ลำไส้เล็กอุดตันจากก้อนพยาธิ + ไข่พยาธิในอุจจาระ = Ascaris lumbricoides (พยาธิไส้เดือน) ก้อนพยาธิจำนวนมากทำให้ลำไส้อุดตัน. *อ้างอิงภาพไข่พยาธิ*", "img": "https://cdn.jsdelivr.net/gh/MercenzK/Web-quiz-images@main/NL2-2024-Q181.png", "sys": "XI"}, {"topic": "Pediatrics", "q": "A 28-year-old female with meningococcemia is hospitalized on appropriate antibiotics. Family concerned about spread within the household. Recommended prophylactic measure for family members?", "choices": ["Throat swab", "Rifampicin", "Nasopharyngeal swab", "Azithromycin", "Ofloxacin"], "ans": 1, "exp": "chemoprophylaxis สำหรับผู้สัมผัสใกล้ชิดผู้ป่วย meningococcal disease = rifampicin (หรือ ciprofloxacin/ceftriaxone) เพื่อกำจัดเชื้อพาหะในโพรงจมูก/คอ", "sys": "flex"}, {"topic": "Pediatrics", "q": "A previously healthy 10-year-old boy with rash for 3 days, preceded by 1 day of low-grade fever and malaise. T 38, RR 24, PR 90. Rash with lesions in various stages (macules, papules, vesicles) on back, trunk, and extremities. Most appropriate treatment?", "choices": ["Oral acyclovir", "Mupirocin ointment", "Oral acetaminophen", "Intravenous acyclovir", "Intravenous cloxacillin"], "ans": 2, "exp": "ผื่นหลายระยะพร้อมกัน (macule/papule/vesicle) = varicella (อีสุกอีใส). ในเด็กแข็งแรงที่มาช้า (>24-72 ชม.) รักษาแบบประคับประคองด้วย acetaminophen (เลี่ยง aspirin -> Reye). acyclovir พิจารณาในผู้ป่วย >12 ปี/เสี่ยงสูง/มาเร็ว. *อ้างอิงภาพ*", "img": "https://cdn.jsdelivr.net/gh/MercenzK/Web-quiz-images@main/NL2-2024-Q183.png", "sys": "I"}, {"topic": "Dermatology", "q": "A 5-year-old boy with chronic pruritus on his back for several months, multiple discolored (hypo/hyperpigmented) macules and patches, not improved with OTC. KOH stain shown. Most appropriate management?", "choices": ["Tar shampoo", "Topical corticosteroid cream", "Antihistamine cream", "Clotrimazole cream", "Emollient lotion"], "ans": 3, "exp": "ผื่นด่างขาว/ด่างสีหลายสีที่ลำตัว + KOH พบ 'spaghetti and meatballs' = pityriasis (tinea) versicolor จากเชื้อ Malassezia -> รักษาด้วยยาฆ่าเชื้อรา topical (clotrimazole/ketoconazole). *อ้างอิงภาพ KOH*", "img": "https://cdn.jsdelivr.net/gh/MercenzK/Web-quiz-images@main/NL2-2024-Q184.png", "sys": "XII"}, {"topic": "Dermatology", "q": "A 5-year-old boy with vesicles and pustules on the sole of his foot, back, and web spaces of his hands. Family members have similar symptoms. Significant itching. Most appropriate treatment?", "choices": ["Triamcinolone acetonide (TA) cream", "Mupirocin", "Clotrimazole cream", "Oral Dicloxacillin", "Benzyl benzoate"], "ans": 4, "exp": "ตุ่มน้ำ/ตุ่มหนองคันตามซอกนิ้ว ฝ่าเท้า + คนในบ้านเป็นเหมือนกัน = scabies (หิด) -> รักษาด้วยยาทาฆ่าตัวหิด benzyl benzoate (หรือ permethrin) และรักษาทุกคนในบ้าน", "sys": "XII"}, {"topic": "Dermatology", "q": "A 10-year-old girl with chronic itching, erythematous scaly lichenified plaques on flexural areas of elbows and knees. History of similar episodes, mother notes history of asthma and allergic rhinitis. Most likely diagnosis?", "choices": ["Atopic dermatitis", "Tinea corporis", "Irritant contact dermatitis", "Scabiasis", "Psoriasis"], "ans": 0, "exp": "ผื่นคันเรื้อรัง lichenified ที่ข้อพับ (flexural) + ประวัติภูมิแพ้ (asthma, allergic rhinitis) = atopic dermatitis. *อ้างอิงภาพ*", "img": "https://cdn.jsdelivr.net/gh/MercenzK/Web-quiz-images@main/NL2-2024-Q186.png", "sys": "XII"}, {"topic": "Pediatrics", "q": "A 14-year-old girl with 2-week joint pain worse with movement. Palpable liver, erythematous macules on skin, mid-diastolic murmur at apex. This week developed orthopnea. Most appropriate investigation?", "choices": ["Antinuclear antibody (ANA)", "Antistreptolysin O (ASO) titer", "Rheumatoid factor", "Erythrocyte sedimentation rate (ESR)", "C-reactive protein (CRP)"], "ans": 1, "exp": "acute rheumatic fever (polyarthritis + carditis จาก mitral murmur + erythema marginatum + หัวใจล้มเหลว) -> ยืนยันการติดเชื้อ streptococcus ก่อนหน้าด้วย ASO titer (เป็นหลักฐานสนับสนุนตาม Jones criteria)", "sys": "IX"}, {"topic": "Pediatrics", "q": "A 2-year-old boy with abdominal distension, mild pallor, and chemosis. A mass is felt in the right upper quadrant. Hb 10, WBC 15,000, platelets 90,000. Likely diagnosis?", "choices": ["Wilms tumor", "Hepatoblastoma", "Neuroblastoma", "Burkitt lymphoma", "Germ cell tumor"], "ans": 2, "exp": "ก้อนในท้อง + periorbital/proptosis (chemosis จาก metastasis เข้ากระบอกตา 'raccoon eyes') ในเด็กเล็ก = neuroblastoma (มักจากต่อมหมวกไต แพร่กระจายเข้ากระดูกเบ้าตา)", "sys": "II"}, {"topic": "Pediatrics", "q": "A 3-year-old boy with a 2-minute GTC seizure 30 minutes before arrival. Lives near a battery factory, frequently complains of abdominal pain. Normal vitals, pallor, no jaundice/hepatosplenomegaly. Hct 24%, WBC 4,200, platelets 140,000, MCV 70. PBS shown. Appropriate management?", "choices": ["CT brain", "Serum iron", "Hemoglobin typing", "Lead level", "Electroencephalography"], "ans": 3, "exp": "อยู่ใกล้โรงงานแบตเตอรี่ + ปวดท้องเรื้อรัง + ซีด microcytic + basophilic stippling + ชัก (encephalopathy) = lead poisoning -> ตรวจ blood lead level. *อ้างอิงภาพ blood smear*", "img": "https://cdn.jsdelivr.net/gh/MercenzK/Web-quiz-images@main/NL2-2024-Q189.png", "sys": "VI"}, {"topic": "Pediatrics", "q": "A 17-year-old boy with 2-month easy fatigue, marked pallor, no jaundice. Hb 6, Hct 17.5%, WBC 6,500 (N60 L45 M4), platelets 650,000. PBS sent. Most appropriate investigation?", "choices": ["Hemoglobin typing", "G6PD assay", "Direct Coombs test", "Bone marrow biopsy", "Serum ferritin"], "ans": 4, "exp": "ซีด microcytic + เกล็ดเลือดสูง (reactive) = iron deficiency anemia -> ตรวจ serum ferritin ยืนยัน", "sys": "III"}, {"topic": "Pediatrics", "q": "A 15-year-old boy with neck and groin masses for 3 months, night fever and weight loss. Multiple 2-4 cm painless cervical and groin lymph nodes. Hb 11.5, WBC 12,000 (N60 L40), platelets 250,000. Most useful investigation for diagnosis?", "choices": ["Lymph node biopsy", "Chest X-ray", "CT scan of head and neck", "Gastric lavage for AFB", "Bone marrow study"], "ans": 0, "exp": "ต่อมน้ำเหลืองโตหลายตำแหน่งไม่เจ็บ + B symptoms (ไข้กลางคืน น้ำหนักลด) = lymphoma -> วินิจฉัยด้วย excisional lymph node biopsy", "sys": "II"}, {"topic": "Pediatrics", "q": "A 15-year-old female with easy fatigue, marked pallor, no jaundice, no hepatosplenomegaly, no lymphadenopathy. Hb 6, Hct 17.5%, WBC 6,500 (N63 L26 M4). PBS shown. Most useful investigation for diagnosis?", "choices": ["G6PD level", "Serum ferritin", "Hemoglobin typing", "Direct antiglobulin test", "Bone marrow aspiration"], "ans": 1, "exp": "ซีดรุนแรง microcytic โดยไม่มีตับม้ามโต/ดีซ่าน (ไม่เข้า hemolysis) = iron deficiency anemia -> ตรวจ serum ferritin. *อ้างอิงภาพ blood smear*", "img": "https://cdn.jsdelivr.net/gh/MercenzK/Web-quiz-images@main/NL2-2024-Q192.png", "sys": "III"}, {"topic": "Pediatrics", "q": "A 4-year-old boy with 2-day fever, moderate pallor, mild icteric sclera, hepatomegaly (3 cm), splenomegaly (2 cm). Hct 22%, WBC 9,700 (N60 L40), platelets 400,000. PBS shown. Most useful investigation for diagnosis?", "choices": ["G6PD level", "Serum ferritin", "Hemoglobin typing", "Direct Coombs test", "Bone marrow aspiration"], "ans": 2, "exp": "ซีด + ดีซ่าน + ตับม้ามโต (เม็ดเลือดแดงแตกเรื้อรัง) ในเด็ก = thalassemia -> ตรวจ hemoglobin typing ยืนยันชนิด. *อ้างอิงภาพ blood smear*", "img": "https://cdn.jsdelivr.net/gh/MercenzK/Web-quiz-images@main/NL2-2024-Q193.png", "sys": "III"}, {"topic": "Hematology", "q": "A 10-year-old girl with tooth extraction and persistent bleeding that does not stop. WBC 8,200 (50N 10E 40L), platelets 180,000 (normal). PBS shown. Most appropriate management?", "choices": ["Platelet transfusion", "Adrenaline pack gauze", "Fresh frozen plasma (FFP) transfusion", "Cryoprecipitate", "Intravenous immunoglobulin (IVIG)"], "ans": 3, "exp": "เลือดออกแบบ mucocutaneous หลังถอนฟัน โดยเกล็ดเลือดปกติ = von Willebrand disease/factor deficiency -> ให้ cryoprecipitate (มี vWF + factor VIII + fibrinogen) เมื่อไม่มี DDAVP/vWF concentrate. *อ้างอิงภาพ*", "img": "https://cdn.jsdelivr.net/gh/MercenzK/Web-quiz-images@main/NL2-2024-Q194.png", "sys": "III"}, {"topic": "Hematology", "q": "A previously healthy 18-year-old man with pallor and dark urine, fever and sore throat 3 days. T 38.5, BP 110/70, HR 110, pale conjunctiva, no icteric sclera, injected pharynx, no hepatosplenomegaly. Hct 20%, Hb 7, WBC 5,500, platelets 170,000, MCV 85, reticulocyte 10%. Most useful investigation for cause of anemia?", "choices": ["Hemoglobin typing", "Osmotic fragility (OF) test", "Direct antiglobulin test (DAT)", "Serum iron and ferritin levels", "Glucose-6-phosphate dehydrogenase (G6PD) assay"], "ans": 4, "exp": "เม็ดเลือดแดงแตกเฉียบพลัน (ปัสสาวะสีเข้ม/hemoglobinuria + retic สูง) หลังติดเชื้อ ในชายหนุ่ม = G6PD deficiency -> ตรวจ G6PD assay (ควรตรวจซ้ำหลัง hemolysis หายเพราะช่วง acute อาจปกติลวง)", "sys": "III"}, {"topic": "Hematology", "q": "A 10-year-old boy with moderate pallor, mild jaundice, hepatomegaly, and splenomegaly. Hb 7, Hct 22%. PBS shown. Most useful investigation for confirming diagnosis?", "choices": ["Hemoglobin typing", "Glucose-6-phosphate dehydrogenase (G6PD) level", "Osmotic fragility (OF) test", "Ceftriaxone", "Direct antiglobulin test (DAT)"], "ans": 0, "exp": "ซีดเรื้อรัง + ดีซ่าน + ตับม้ามโต ในเด็ก = thalassemia -> ยืนยันด้วย hemoglobin typing. *อ้างอิงภาพ blood smear*", "img": "https://cdn.jsdelivr.net/gh/MercenzK/Web-quiz-images@main/NL2-2024-Q196.png", "sys": "III"}, {"topic": "Hematology", "q": "A 6-year-old boy with ecchymosis, no history of hemarthrosis or family history of bleeding. WBC 5,400 (45N 40L 10E), platelets 180,000. PBS shown. Most appropriate management?", "choices": ["Fresh frozen plasma (FFP)", "Factor VIII", "Adrenaline packing", "Platelet transfusion", "Vitamin K"], "ans": 1, "exp": "เลือดออก/จ้ำเลือดโดยเกล็ดเลือดปกติ (ไม่ใช่ปัญหาเกล็ดเลือด) บ่งความผิดปกติของ coagulation factor -> ถ้าเป็น hemophilia A ให้ factor VIII concentrate. *อ้างอิงภาพ (ขึ้นกับผลตรวจการแข็งตัวของเลือด)*", "img": "https://cdn.jsdelivr.net/gh/MercenzK/Web-quiz-images@main/NL2-2024-Q197.png", "sys": "III"}, {"topic": "Pediatrics", "q": "A 6-month-old girl with bruising on buttocks, upper thighs, forearms, and occipital swelling. 18-year-old mother reports the child fell from bed. Mild pallor, subconjunctival hemorrhage, no neuro deficits, normal coagulogram, platelets 200,000. Most appropriate management?", "choices": ["Report case to police", "Refer the mother to a psychiatrist", "Report case to child protection services", "Discharge and make a home visit", "Separate the child to stay with relatives"], "ans": 2, "exp": "จ้ำเลือดหลายตำแหน่ง/หลายระยะในทารกที่ยังเคลื่อนไหวเองไม่ได้ + ประวัติไม่สอดคล้อง + subconjunctival hemorrhage + coagulogram ปกติ = สงสัย child abuse -> ต้องรายงาน child protection services เพื่อประเมิน/คุ้มครองเด็ก", "sys": "VII"}, {"topic": "Obstetrics & Gynecology", "q": "A 30-year-old woman with a missed period for 2 months, usually irregular menstruation, denies herbal supplements. Normal physical and pelvic exam. Most appropriate management?", "choices": ["Serum FSH", "Serum estradiol", "Pelvic ultrasound", "Serum beta hCG", "Progesterone challenge test"], "ans": 3, "exp": "ประจำเดือนขาดในหญิงวัยเจริญพันธุ์ -> ต้องตรวจ serum beta-hCG (แยกการตั้งครรภ์) ก่อนเสมอเป็นอันดับแรก", "sys": "flex"}, {"topic": "Obstetrics & Gynecology", "q": "A 30-year-old woman with a missed period for 2 months, usually irregular, denies hormones. BMI 28. Pelvic exam normal, closed os, normal uterus, no adnexal mass. Urine pregnancy test negative. Most appropriate management?", "choices": ["Serum FSH", "Serum estradiol", "Serum beta hCG", "Pelvic ultrasound", "Progesterone challenge test"], "ans": 4, "exp": "secondary amenorrhea เมื่อ UPT ลบแล้ว -> ทำ progesterone challenge test เพื่อประเมินระดับเอสโตรเจนและ outflow tract (ถ้ามีเลือดออก = มีเอสโตรเจนพอ + outflow ปกติ)", "sys": "XV"}, {"topic": "Obstetrics & Gynecology", "q": "A 35-year-old woman with dysmenorrhea and an enlarged, globular-shaped uterus. History of heavy menstrual bleeding and pelvic pain worsening during menstruation, regular cycles. Most likely diagnosis?", "choices": ["Adenomyosis", "Leiomyoma", "Endometriosis", "Endometrioma", "Cancer of the uterus"], "ans": 0, "exp": "ปวดประจำเดือน + เลือดออกมาก + มดลูกโตรูปทรงกลม (globular, โตสมมาตร) = adenomyosis (เยื่อบุโพรงมดลูกฝังในกล้ามเนื้อมดลูก). myoma มักทำให้มดลูกโตขรุขระไม่สมมาตร", "sys": "II"}, {"topic": "Obstetrics & Gynecology", "q": "A 30-year-old woman with dysmenorrhea. Cystic mass in the left adnexa, tenderness from nodules in the cul-de-sac, pelvic ultrasound shows a left hypoechoic adnexal mass. Most likely diagnosis?", "choices": ["Dermoid cyst", "Endometrioma", "Paratubal cyst", "Follicular cyst", "Pregnancy"], "ans": 1, "exp": "ปวดประจำเดือน + ก้อนถุงน้ำที่ปีกมดลูก + nodule เจ็บใน cul-de-sac = endometriosis/endometrioma (chocolate cyst, ผนัง hypoechoic ground-glass)", "sys": "XV"}, {"topic": "Obstetrics & Gynecology", "q": "A 28-year-old woman with amenorrhea for 3 months, history of irregular menstruation, BMI 28. Pelvic exam normal, no adnexal mass, no CMT. Urine pregnancy test negative. Most appropriate investigation?", "choices": ["Transvaginal ultrasound (TVS)", "Serum HCG", "Progesterone challenge test", "Serum estradiol", "Serum FSH"], "ans": 2, "exp": "secondary amenorrhea + UPT ลบ -> progesterone challenge test ประเมินสถานะเอสโตรเจน/outflow tract เป็นขั้นตอนถัดไป", "sys": "XV"}, {"topic": "Obstetrics & Gynecology", "q": "A 51-year-old woman with hot and cold sensations, mood swings, and postcoital bleeding. Last menstrual period 6 months ago. Most appropriate management for her symptoms?", "choices": ["Combined oral contraception", "Only estrogen", "Only progesterone", "Cyclic estrogen and progesterone", "Continuous estrogen and progesterone"], "ans": 3, "exp": "อาการ vasomotor ในวัยใกล้หมดประจำเดือน (perimenopause, LMP 6 เดือน ยังไม่ครบ 1 ปี) ที่ยังมีมดลูก -> ให้ hormone therapy แบบ cyclic estrogen + progesterone (progesterone ป้องกัน endometrial hyperplasia). *ควรตรวจหาสาเหตุ postcoital bleeding ก่อนเริ่มฮอร์โมน*", "sys": "XIV"}, {"topic": "Obstetrics & Gynecology", "q": "A 51-year-old healthy woman with sudden hot and cold flashes, difficulty sleeping, dyspareunia, and mood swings. Last menstrual period 6 months ago. Most appropriate treatment?", "choices": ["Combined oral contraceptive pills", "Oral estrogen", "Oral progesterone", "Continuous estrogen and progesterone", "Cyclic estrogen and progesterone"], "ans": 4, "exp": "perimenopausal symptoms (LMP 6 เดือน) ในหญิงที่มีมดลูก -> cyclic estrogen + progesterone. เอสโตรเจนเดี่ยวใช้ได้เฉพาะผู้ที่ตัดมดลูกแล้ว", "sys": "XIII"}, {"topic": "Obstetrics & Gynecology", "q": "A 26-year-old female with foamy leukorrhea, pruritus, and irritation. Pelvic exam shows the cervix (shown). Causative agent?", "choices": ["Trichomonas vaginalis", "Candida albicans", "Bacteroides fragilis", "Gardnerella vaginalis", "Enterobacteriaeceae"], "ans": 0, "exp": "ตกขาวเป็นฟอง (foamy) + คัน + strawberry cervix (จุดเลือดออกที่ปากมดลูก) = Trichomonas vaginalis -> รักษาด้วย metronidazole (รักษาคู่นอนด้วย). *อ้างอิงภาพปากมดลูก*", "img": "https://cdn.jsdelivr.net/gh/MercenzK/Web-quiz-images@main/NL2-2024-Q206.png", "sys": "XII"}, {"topic": "Obstetrics & Gynecology", "q": "A 30-year-old female with a painful ulcer on the left labia majora and a painful mass in the left groin for a few days. Large painful ulcer with well-defined edges, enlarged tender inguinal node. Most appropriate treatment?", "choices": ["Doxycycline", "Azithromycin", "Penicillin G", "Clindamycin", "Vancomycin"], "ans": 1, "exp": "แผลริมอ่อนเจ็บ + ต่อมน้ำเหลืองขาหนีบโตเจ็บ (bubo) = chancroid (Haemophilus ducreyi) -> รักษาด้วย azithromycin (หรือ ceftriaxone) ครั้งเดียว", "sys": "II"}, {"topic": "Obstetrics & Gynecology", "q": "A 20-year-old woman with a genital ulcer for 3 days. Pelvic exam shows a 2 cm dirty-based ulcer on the left labia majora. Most appropriate management?", "choices": ["Doxycycline", "Ceftriaxone", "Azithromycin", "Amoxicillin", "Amoxicillin-clavulanate"], "ans": 2, "exp": "แผลเจ็บก้นสกปรก (dirty base) ที่อวัยวะเพศ = chancroid -> azithromycin (single dose) หรือ ceftriaxone", "sys": "flex"}, {"topic": "Obstetrics & Gynecology", "q": "A 30-year-old woman with a painful genital ulcer (dirty base) and an enlarged, tender left groin mass for about a week. Most appropriate treatment?", "choices": ["Ofloxacin", "Doxycycline", "Benzathine penicillin G", "Azithromycin", "Ceftriaxone"], "ans": 3, "exp": "chancroid (แผลเจ็บก้นสกปรก + bubo เจ็บ) -> azithromycin (หรือ ceftriaxone/ciprofloxacin). benzathine penicillin ใช้กับ syphilis (แผลไม่เจ็บ)", "sys": "II"}, {"topic": "Obstetrics & Gynecology", "q": "A 28-year-old pregnant woman with curd-like vaginal discharge and significant pruritus, thick white cottage cheese-like discharge, no systemic illness. Most appropriate treatment?", "choices": ["Oral ketoconazole", "Oral fluconazole", "Vaginal metronidazole", "Vaginal boric acid", "Clotrimazole cream (vaginal)"], "ans": 4, "exp": "vulvovaginal candidiasis ในหญิงตั้งครรภ์ -> ใช้ยาทา/เหน็บช่องคลอดกลุ่ม azole (clotrimazole) เพราะยารับประทาน fluconazole/ketoconazole หลีกเลี่ยงในครรภ์", "sys": "XV"}, {"topic": "Obstetrics & Gynecology", "q": "A 45-year-old woman with urinary leakage during coughing and exercise. Urethral hypermobility, no significant prolapse, positive cough stress test. Normal UA, minimal post-void residual. Most appropriate initial management?", "choices": ["Pelvic floor exercises", "Timed voiding", "Bladder training", "Vaginal pessary", "Anticholinergic drugs"], "ans": 0, "exp": "stress urinary incontinence (ปัสสาวะเล็ดตอนไอ/ออกแรง + cough stress test บวก) -> เริ่มด้วย pelvic floor muscle exercise (Kegel) เป็น first-line. anticholinergic ใช้กับ urge incontinence", "sys": "X"}, {"topic": "Obstetrics & Gynecology", "q": "A 25-year-old primigravida at 10 weeks presents with bright red vaginal bleeding. Cervical os closed, minimal old bloody discharge. Ultrasound shows an intrauterine gestational sac with mean diameter 40 mm but no fetal pole. Most appropriate management?", "choices": ["Foley catheter", "Manual vacuum aspiration (MVA)", "Oxytocin", "Progesterone supplement", "Dilatation and evacuation (D&E)"], "ans": 1, "exp": "ถุงการตั้งครรภ์ใหญ่ (MSD 40 mm >25 mm) แต่ไม่มี fetal pole = anembryonic pregnancy/missed abortion -> ขับออกด้วย MVA (manual vacuum aspiration) ในไตรมาสแรก (หรือใช้ยา). D&E ใช้ไตรมาสสอง", "sys": "XV"}, {"topic": "Obstetrics & Gynecology", "q": "A 27-year-old G2P1 at 16 weeks with vaginal spotting. Ultrasound reveals an intrauterine gestational sac measuring 8 weeks with no fetal pole. What should be done next?", "choices": ["Perform B-hCG assay", "Follow-up ultrasound in 1 week", "Dilation and curettage (D&C)", "Wait for spontaneous abortion", "Initiate medical abortion"], "ans": 2, "exp": "อายุครรภ์จริง 16 สัปดาห์แต่ถุงการตั้งครรภ์ขนาดแค่ 8 สัปดาห์และไม่มี fetal pole = missed abortion (ตัวอ่อนเสียชีวิต) -> ขับออกด้วย D&C (ขนาดยังเล็ก) หรือยา", "sys": "XV"}, {"topic": "Obstetrics & Gynecology", "q": "An 18-year-old female with vaginal spotting for 5 days, LMP 6 weeks ago, cervical motion tenderness. Beta-hCG 1000 IU/L. Most appropriate next step?", "choices": ["Administer methotrexate", "Repeat beta-hCG in 48 hours", "Perform dilation and curettage (D&C)", "Perform a pelvic ultrasound", "Start oral contraceptives"], "ans": 3, "exp": "สงสัย ectopic (spotting + CMT) hCG 1000 -> ทำ pelvic/transvaginal ultrasound หาตำแหน่งการตั้งครรภ์. ถ้า US ไม่เห็นและ hCG ต่ำกว่า discriminatory zone จึงตรวจ hCG ซ้ำใน 48 ชม.", "sys": "XIV"}, {"topic": "Obstetrics & Gynecology", "q": "A 40-year-old woman G4P3 with absent menstruation for 8 weeks. BP 140/90, mild pitting edema. Uterus consistent with 12 weeks' size, bilateral adnexal cysts on ultrasound. Most likely diagnosis?", "choices": ["Twin pregnancy", "Chronic hypertension", "Transient hypertension", "Ectopic pregnancy", "Molar pregnancy"], "ans": 4, "exp": "มดลูกโตกว่าอายุครรภ์ (12 สัปดาห์ที่ 8 สัปดาห์) + theca lutein cysts สองข้าง + ความดันสูงเร็ว = molar pregnancy (hydatidiform mole)", "sys": "XV"}, {"topic": "Obstetrics & Gynecology", "q": "A 40-year-old woman G4P3 with amenorrhea and nausea/vomiting for 8 weeks. BP 140/90, proteinuria 3+. Uterus consistent with 12 weeks' size, bilateral adnexal cysts on ultrasound. Most likely diagnosis?", "choices": ["Molar pregnancy", "Twin pregnancy", "Mild preeclampsia", "Chronic hypertension", "Transient hypertension"], "ans": 0, "exp": "ความดันสูง + โปรตีนรั่ว (ดูเหมือน preeclampsia) แต่เกิดก่อน 20 สัปดาห์ + มดลูกโตเกินอายุครรภ์ + theca lutein cysts = molar pregnancy (preeclampsia ก่อน 20 สัปดาห์ให้นึกถึง mole)", "sys": "XV"}, {"topic": "Obstetrics & Gynecology", "q": "A 30-year-old primigravida at 10 weeks with persistent hyperemesis gravidarum, treated with vitamin B6 and diphenhydramine without improvement. Dry lips and lethargy. Ultrasound shows single viable fetus, normal. Most appropriate next step?", "choices": ["MRI Brain", "Thyroid function test", "Test for GERD", "EEG", "Lumbar puncture"], "ans": 1, "exp": "hyperemesis gravidarum ที่รุนแรง/ไม่ดีขึ้น -> ตรวจ thyroid function test เพราะ beta-hCG สูงกระตุ้นต่อมไทรอยด์ทำให้เกิด gestational transient thyrotoxicosis ได้", "sys": "XV"}, {"topic": "Obstetrics & Gynecology", "q": "A primigravida at 16 weeks with persistent hyperemesis gravidarum not improved despite dimenhydrinate and vitamin B6. Sunken eyeballs, dry lips, tachycardia, inattentive. Most appropriate investigation?", "choices": ["MRI brain", "Termination of pregnancy", "Thyroid function test", "Consult psychiatrist", "Increase dose of Vitamin B6"], "ans": 2, "exp": "hyperemesis gravidarum รุนแรง -> ตรวจ thyroid function test (มักพบ gestational thyrotoxicosis จาก hCG กระตุ้น TSH receptor)", "sys": "XV"}, {"topic": "Obstetrics & Gynecology", "q": "A 25-year-old primigravida with persistent hyperemesis gravidarum from GA 8-16 weeks, not improved despite IV fluids, dimenhydrinate, and vitamin B6. Ultrasound shows single viable fetus, no anomalies. Most appropriate next step?", "choices": ["MRI brain", "Terminate the pregnancy", "Investigation for GERD", "Thyroid function test (TFT)", "Consult psychiatrist"], "ans": 3, "exp": "hyperemesis gravidarum ที่ดื้อการรักษา -> ตรวจ thyroid function test หา gestational thyrotoxicosis (hCG กระตุ้นไทรอยด์)", "sys": "XV"}, {"topic": "Obstetrics & Gynecology", "q": "A 34-year-old woman with three consecutive miscarriages at 7, 8, and 11 weeks. No significant medical history, asymptomatic between pregnancies, normal exam. Most likely cause?", "choices": ["Myoma uteri", "Bicornuate uterus", "Recurrent infection", "Cervical incompetence", "Chromosome abnormality"], "ans": 4, "exp": "แท้งซ้ำในไตรมาสแรก (recurrent early pregnancy loss) สาเหตุที่พบบ่อยสุดคือความผิดปกติของโครโมโซม (เช่น balanced translocation ของพ่อแม่/aneuploidy). cervical incompetence ทำให้แท้งไตรมาสสอง", "sys": "XV"}, {"topic": "Obstetrics & Gynecology", "q": "A 25-year-old sexually active woman with RLQ pain for 3 hours, LMP 6 weeks ago, fever, nausea, vomiting. RLQ tenderness without guarding/rebound. WBC 15,000 with 85% neutrophils. Most appropriate initial management?", "choices": ["Urine pregnancy test", "Ultrasound of the kidneys and ureters", "Ultrasound of the lower abdomen", "Computed tomography of the abdomen", "Emergency surgery"], "ans": 0, "exp": "หญิงวัยเจริญพันธุ์ประจำเดือนขาด + ปวดท้องน้อย -> ตรวจ urine pregnancy test ก่อน เพื่อแยก ectopic pregnancy ก่อนวินิจฉัยไส้ติ่ง", "sys": "XV"}, {"topic": "Obstetrics & Gynecology", "q": "A 32-year-old G2P1 at 12 weeks first ANC. Previous child birth weight 4,700 g (prior GDM). 50-g GCT at this visit is 130 mg/dL. Most appropriate management?", "choices": ["Self-monitoring of 2-hour postprandial blood sugar", "50-gram glucose challenge test (GCT) at gestational age 28 weeks", "HbA1c at gestational age 24 weeks", "100-gram oral glucose tolerance test (OGTT)", "Observe and follow-up"], "ans": 1, "exp": "ผู้มีความเสี่ยง (เคยคลอดลูกตัวโต) คัดกรอง GCT ตั้งแต่ต้น; ค่า 130 < 140 mg/dL = ยังไม่ผิดปกติ -> คัดกรองซ้ำด้วย GCT ที่อายุครรภ์ 28 สัปดาห์", "sys": "XV"}, {"topic": "Obstetrics & Gynecology", "q": "A 32-year-old G2P1 at 21 weeks routine ANC. Previous child birth weight 4,700 g. 50-g GCT shows 130 mg/dL. Most appropriate next step?", "choices": ["Self-monitoring of 2-hour postprandial blood sugar", "Hemoglobin A1c (HbA1c) at gestational age 24 weeks", "50-gram glucose challenge test (GCT) at 28 weeks of gestation", "100-gram oral glucose tolerance test (OGTT)", "Fasting blood sugar (FBS)"], "ans": 2, "exp": "GCT 130 < 140 mg/dL = ผลลบ -> ผู้มีความเสี่ยงให้คัดกรองซ้ำ GCT ที่ 28 สัปดาห์ (ถ้า GCT >=140 จึงทำ 100-g OGTT ยืนยัน)", "sys": "XV"}, {"topic": "Obstetrics & Gynecology", "q": "A 30-year-old G1 at 16 weeks for ANC, with a complete course of Td vaccination (from an accident). Most appropriate vaccination to administer today?", "choices": ["Tetanus vaccine", "Hepatitis B virus (HBV) vaccine", "Tdap (tetanus, diphtheria, and pertussis) vaccine", "Influenza vaccine", "Human papilloma virus (HPV) vaccine"], "ans": 3, "exp": "มี Td ครบแล้ว (บาดทะยักครอบคลุม) -> ที่ 16 สัปดาห์ให้ influenza vaccine ได้ทุกไตรมาส. Tdap แนะนำช่วง 27-36 สัปดาห์เพื่อป้องกันไอกรนในทารก; HPV ห้ามในครรภ์", "sys": "I"}, {"topic": "Obstetrics & Gynecology", "q": "A 20-year-old primigravida at 37 weeks in labor, no ANC. Fully dilated, 100% effaced, station +1, FH 3/4 above umbilicus, membranes ruptured 1 hour. EFM shown. Appropriate management?", "choices": ["Vacuum extraction", "Forceps extraction", "Oxytocin infusion", "Emergency cesarean section (C/S)", "Observe labor progression"], "ans": 4, "exp": "*จากกราฟจริง* EFM เป็น reassuring (baseline ~140 variability ดี มี acceleration ไม่มี deceleration) + เพิ่งเข้าสู่ระยะที่สอง (station +1) ในครรภ์แรก -> ให้เฝ้าติดตามและปล่อยเบ่งคลอดตามธรรมชาติ (observe). vacuum/forceps ใช้เมื่อมี fetal distress หรือระยะที่สองยืดเยื้อ", "img": "https://cdn.jsdelivr.net/gh/MercenzK/Web-quiz-images@main/NL2-2024-Q225.png", "sys": "XV"}, {"topic": "Obstetrics & Gynecology", "q": "A 19-year-old primigravida at 38 weeks in labor. FH 3/4 above umbilicus, cephalic, cervix 4 cm/100% effaced/station 0, membranes intact, contractions every 7 minutes for 45 seconds. Initial management?", "choices": ["Observe uterine contraction", "Amniotomy", "Cesarean section (C/S)", "Cervical ripening with prostaglandin E (PGE)", "Augmentation with oxytocin"], "ans": 0, "exp": "4 ซม. + มดลูกหดตัวห่าง (ทุก 7 นาที = ยังไม่เข้า active labor ที่ดี) contractions ไม่แรงพอ -> สังเกตการหดตัว (observe) ยังไม่ต้อง intervene", "sys": "XV"}, {"topic": "Obstetrics & Gynecology", "q": "A 32-year-old G2P1 at 32 weeks with uterine bleeding. FH 2/4 above umbilicus, FHR 140, no uterine contractions, blood clot per vagina. Most appropriate initial management?", "choices": ["Rectal examination", "Ultrasonography", "Pelvic examination", "Double exam in the operating room", "Monitor and observe"], "ans": 1, "exp": "antepartum hemorrhage -> ห้ามตรวจภายในทางช่องคลอด (digital vaginal exam) จนกว่าจะแยก placenta previa -> ทำ ultrasound หาตำแหน่งรกก่อน", "sys": "XV"}, {"topic": "Obstetrics & Gynecology", "q": "A 24-year-old primigravida at 34 weeks with leakage of fluid per vagina, confirmed amniotic fluid from cervix. Cervix 50% effaced, dilated 4 cm, station -1. Most appropriate management?", "choices": ["Nicardipine", "Oxytocin", "Intravenous (IV) ampicillin", "Intravenous (IV) dexamethasone", "Test lung maturity"], "ans": 2, "exp": "PPROM ที่ 34 สัปดาห์ + เข้าสู่ระยะคลอด (เปิด 4 ซม.) -> จะคลอด ให้ IV ampicillin เพื่อ GBS prophylaxis/latency antibiotics", "sys": "XV"}, {"topic": "Obstetrics & Gynecology", "q": "A 34-week pregnant woman G1 with fluid leak, no uterine contractions. Pelvic exam: fluid leakage, cervical dilation 3 cm, 80% effacement, station -1. Most appropriate management?", "choices": ["Oxytocin", "Intravenous (IV) ampicillin", "Group B Streptococcus (GBS) screening", "Dexamethasone", "Tocolytics"], "ans": 3, "exp": "PPROM ที่ 34 สัปดาห์ ยังไม่เข้าสู่ระยะคลอดชัด -> ให้ corticosteroid (dexamethasone) เร่งปอดทารก (ให้ได้ถึง 34-36+6 สัปดาห์) ร่วมกับ latency antibiotics; ไม่ให้ tocolytics ใน PPROM", "sys": "XV"}, {"topic": "Obstetrics & Gynecology", "q": "A 30-year-old woman at 39 weeks in second stage of labor. The baby's head is delivered but the anterior shoulder is not delivering (shoulder dystocia). Next step in management?", "choices": ["Fundal pressure", "Pubic symphysis pressure", "Posterior shoulder delivery", "Reinsert the head and set up for emergency cesarean section (C/S)", "Hyperflex thighs to the abdomen"], "ans": 4, "exp": "shoulder dystocia -> ทำ McRoberts maneuver (งอต้นขาทั้งสองแนบหน้าท้อง) เป็นขั้นแรก ร่วมกับ suprapubic pressure. ห้ามกด fundal pressure (ยิ่งอัดไหล่ติด)", "sys": "XV"}, {"topic": "Obstetrics & Gynecology", "q": "A 30-year-old woman at 39 weeks in active labor, cervical dilation 8 cm, 100% effaced, intact membranes, regular contractions, no fetal distress, reassuring FHR. Most appropriate management?", "choices": ["Continuous fetal monitoring", "Artificial rupture of membranes", "Administration of oxytocin", "Intravenous fluid administration", "No ambulation"], "ans": 0, "exp": "active labor ที่ดำเนินไปปกติ (8 ซม.) FHR ปกติ -> เพียงเฝ้าติดตามด้วย continuous fetal monitoring ไม่ต้อง intervene", "sys": "XV"}, {"topic": "Obstetrics & Gynecology", "q": "A 27-year-old primigravida at 38 weeks in labor. Longitudinal lie, vertex, FHS 150. Cervix 4 cm dilated, 80% effaced, station 0, membranes intact. Most appropriate management?", "choices": ["Amniotomy", "Observe progression of labor", "Cervical ripening with prostaglandin E1 (PGE1)", "Augmentation with oxytocin", "Continuous fetal monitoring"], "ans": 1, "exp": "เข้าสู่ active labor ระยะแรก (4 ซม.) ดำเนินไปปกติ -> สังเกตความก้าวหน้าของการคลอด (observe) ยังไม่ต้อง intervene", "sys": "XV"}, {"topic": "Obstetrics & Gynecology", "q": "A G1 at 37 weeks in labor, no underlying disease. EFM shows contractions every 7 minutes for 45 seconds. Cervix 4 cm dilated, 80% effaced, station 0. Most appropriate management?", "choices": ["Prostaglandin E2 (PGE2)", "Oxytocin", "Observe", "Amniotomy", "Continuous fetal monitoring"], "ans": 2, "exp": "มดลูกหดตัวห่าง (ทุก 7 นาที) ที่ 4 ซม. = latent/early ยังไม่เข้า active labor ที่ดี -> observe ก่อน", "sys": "XV"}, {"topic": "Obstetrics & Gynecology", "q": "A 28-year-old primigravida at 39 weeks, in labor 8 hours. Active labor 4 cm, now 5 cm/station 0 after 4 hours of active labor with adequate contractions every 3-4 minutes. Reassuring FHR. Most appropriate management?", "choices": ["Oxytocin infusion", "Continuous fetal monitoring", "Cesarean section", "Amniotomy", "Observe progression of labor"], "ans": 3, "exp": "protraction ของ active phase ทั้งที่ contraction เพียงพอ + ถุงน้ำยังไม่แตก -> ทำ amniotomy (เจาะถุงน้ำ) เพื่อกระตุ้นการคลอดก่อน (ตามด้วย oxytocin ถ้ายังช้า)", "sys": "XV"}, {"topic": "Obstetrics & Gynecology", "q": "A 34-year-old G2P1 at 38 weeks in labor with a previous cesarean section. Develops severe abdominal pain and generalized abdominal rigidity. Fundal height >3/4 above the umbilicus, FHR 80. Most likely diagnosis?", "choices": ["Placenta previa", "Placental abruption", "Preterm labor", "Amniotic fluid embolism", "Uterine rupture"], "ans": 4, "exp": "แผลผ่าคลอดเดิม + ปวดท้องรุนแรงเฉียบพลัน + ท้องแข็งเกร็ง + fetal bradycardia (FHR 80) + ระดับยอดมดลูกเปลี่ยน = uterine rupture", "sys": "XV"}, {"topic": "Obstetrics & Gynecology", "q": "A 31-year-old primigravida at 37 weeks in labor. Contractions every 2 minutes for 30 seconds. During exam, accidental membrane rupture and cord prolapse identified. FHR 80. Most appropriate management?", "choices": ["Emergency cesarean section", "Vacuum extraction", "Forceps extraction", "Repositioning the cord", "Observation"], "ans": 0, "exp": "cord prolapse + fetal bradycardia (FHR 80) = ภาวะฉุกเฉิน -> emergency cesarean section ทันที (ระหว่างรอ ให้ดันศีรษะทารกขึ้นลดการกดสายสะดือ)", "sys": "XV"}, {"topic": "Obstetrics & Gynecology", "q": "A 28-year-old G2P1 at 39 weeks in labor 2 hours, contractions every 2-3 minutes for 50 seconds, FHR 150. Cervix 8 cm/100% effaced/station +1, clear amniotic fluid. Most appropriate next step?", "choices": ["Sedate with opioid", "Observe cervical progression for an additional 2 hours", "Augmentation with oxytocin", "Intrauterine resuscitation (IUR)", "Monitor FHR every 60 minutes"], "ans": 1, "exp": "active labor ที่ดำเนินไปดี (8 ซม. contraction ดี FHR ปกติ น้ำคร่ำใส) -> สังเกตความก้าวหน้าต่อ ไม่ต้องเร่งหรือ intervene", "sys": "XV"}, {"topic": "Obstetrics & Gynecology", "q": "A 27-year-old at 38 weeks low-risk pregnancy in labor. FH 3/4 above umbilicus, longitudinal lie, cephalic. Contractions every 7 minutes for 45 seconds. Cervix 4 cm/80% effaced/station 0, intact membranes. Most appropriate management?", "choices": ["Amniotomy", "Cesarean section", "Observation of uterine contractions", "Cervical ripening with prostaglandin E1 (PGE1)", "Augmentation with oxytocin"], "ans": 2, "exp": "contraction ห่าง (ทุก 7 นาที) ที่ 4 ซม. = ยังไม่เข้า active labor ที่แท้จริง -> สังเกตการหดตัวของมดลูก (observe)", "sys": "XV"}, {"topic": "Obstetrics & Gynecology", "q": "A 25-year-old postpartum with severe perineal pain 4 hours after forceps-assisted delivery. BT 37, BP 140/90, P 90. Uterus well-contracted, fundal height at umbilicus. A 5 cm bluish mass at the episiotomy site. Most appropriate management?", "choices": ["Aspiration", "Broad-spectrum antibiotics", "Observation", "Evacuation", "Cold compression"], "ans": 3, "exp": "vulvar/perineal hematoma ขนาดใหญ่ (5 ซม.) เจ็บมากหลังใช้ forceps -> ผ่าเปิดระบายก้อนเลือด (evacuation) และผูกจุดเลือดออก. ก้อนเล็ก <3 ซม.จึงสังเกต/ประคบเย็น", "sys": "XV"}, {"topic": "Obstetrics & Gynecology", "q": "A 30-year-old postpartum with severe perineal pain. Four hours after delivery, a 5 cm tender, bluish mass at the episiotomy site. Stable vitals, uterus well-contracted. Most appropriate management for the mass?", "choices": ["Evacuation", "Aspiration", "Broad-spectrum antibiotics", "Observation and cold compression", "Incision and drainage (I&D)"], "ans": 4, "exp": "perineal hematoma ขนาดใหญ่ (5 ซม.) เจ็บ -> incision and drainage ระบายก้อนเลือดและห้ามเลือด. ก้อนเล็กจึงสังเกต/ประคบเย็น", "sys": "XV"}, {"topic": "Obstetrics & Gynecology", "q": "A 40-year-old postpartum with vaginal bleeding for 5 days, using 5 pads/day since cesarean section 2 weeks ago (for fetal distress). Stable vitals. Uterus tender, 18-week size, continued bleeding, cervix open to 1 fingertip. Most appropriate treatment?", "choices": ["Dilation and Curettage (D&C)", "Antibiotics", "Tranexamic acid", "Uterine artery embolization", "Hysterectomy"], "ans": 0, "exp": "secondary postpartum hemorrhage จาก retained products of conception (มดลูกโต 18 สัปดาห์ กดเจ็บ ปากมดลูกเปิด เลือดออกต่อเนื่อง 2 สัปดาห์หลังคลอด) -> ขูดมดลูก (D&C) เอาชิ้นเนื้อออก (+ ยาปฏิชีวนะถ้ามี endometritis)", "sys": "XV"}, {"topic": "Obstetrics & Gynecology", "q": "A 30-year-old female with right breast pain for 1 day, 1 week postpartum, exclusively breastfeeding. Right breast firm, swollen, and tender, but no redness. Most likely diagnosis?", "choices": ["Mastitis", "Breast engorgement", "Breast abscess", "Plugged duct", "Galactocele"], "ans": 1, "exp": "เต้านมคัดตึงบวมเจ็บทั้งเต้าโดยไม่มีแดง/ไข้ ในช่วงหลังคลอดที่น้ำนมมา = breast engorgement (เต้านมคัด). mastitis จะมีแดงและไข้", "sys": "XV"}, {"topic": "Obstetrics & Gynecology", "q": "A 30-year-old woman 1 week postpartum, exclusively breastfeeding, with tender right breast pain localized to the periareolar area. Most likely diagnosis?", "choices": ["Breast engorgement", "Mastitis", "Clogged duct", "Galactocele", "Breast abscess"], "ans": 2, "exp": "เจ็บเฉพาะที่ (localized) โดยไม่มีอาการทั่วร่างกาย/แดงร้อน = clogged (plugged) duct. รักษาด้วยการให้นมบ่อย ๆ/นวดระบายน้ำนม", "sys": "XV"}, {"topic": "Obstetrics & Gynecology", "q": "A 40-year-old female with vaginal bleeding for 5 days, using 10 pads/day since cesarean section 2 weeks ago (fetal distress). Uterus tender, 18-week size, blood clots, cervix open 1 fingerbreadth. Most appropriate treatment?", "choices": ["Intravenous antibiotics (IV ATB)", "Hysterectomy", "Tranexamic acid", "Dilation and Curettage (D&C)", "Uterine artery embolization"], "ans": 3, "exp": "secondary PPH จาก retained products of conception (มดลูกโตกดเจ็บ ปากมดลูกเปิด เลือดออก 2 สัปดาห์หลังคลอด) -> D&C ขูดเอาชิ้นเนื้อออก", "sys": "XV"}, {"topic": "Obstetrics & Gynecology", "q": "A 25-year-old nulliparous female with migraines with aura around menstruation, regular cycles, plans pregnancy next year. Normal exam. Most appropriate contraceptive method?", "choices": ["Depo-Provera (DMPA)", "Vaginal contraceptive ring", "Oral contraceptive pills (OCP)", "Transdermal contraceptive patch", "Levonorgestrel intrauterine device (IUD)"], "ans": 4, "exp": "migraine with aura = ข้อห้ามของฮอร์โมนเอสโตรเจน (เสี่ยง stroke) -> เลี่ยง OCP/ring/patch. ต้องการตั้งครรภ์ปีหน้า จึงเลือกวิธีที่ไม่มีเอสโตรเจนและกลับมามีบุตรได้เร็ว = levonorgestrel IUD (DMPA ทำให้ภาวะเจริญพันธุ์กลับช้า)", "sys": "XV"}, {"topic": "Orthopedics", "q": "A 45-year-old man with pain around the right scapula, relieved by analgesics and massage, occasional numbness in the right thumb and index finger. Neck flexion causes pain to radiate down the arm and intensify. Most likely diagnosis?", "choices": ["Disc herniation with C6 radiculopathy", "Cervical spondylosis", "Thoracic outlet syndrome", "Rotator cuff tendinitis", "Herpes zoster infection"], "ans": 0, "exp": "ชาที่นิ้วหัวแม่มือและนิ้วชี้ (C6 dermatome) + ปวดร้าวลงแขนเมื่อก้มคอ (radicular) = cervical disc herniation กด C6 nerve root", "sys": "XIII"}, {"topic": "Orthopedics", "q": "A 57-year-old man with upper back pain, relieved by analgesics and massage, numbness in right thumb and index finger. Extreme neck flexion intensifies pain. Most likely diagnosis?", "choices": ["Cervical spondylosis", "C6 herniation with radiculopathy", "Myofascial syndrome", "Thoracic outlet syndrome", "Rotator cuff injury"], "ans": 1, "exp": "ชานิ้วหัวแม่มือ+นิ้วชี้ (C6) + ปวดมากขึ้นเมื่อก้มคอ = C6 disc herniation with radiculopathy", "sys": "XIII"}, {"topic": "Orthopedics", "q": "A 45-year-old female housewife with shooting pain in the right elbow, tenderness at the right lateral epicondyle, pain worse with gripping or lifting, present for weeks, no trauma or neck pain. Most likely diagnosis?", "choices": ["Peripheral neuritis", "Overuse injury", "Tennis elbow (lateral epicondylitis)", "Cervical disc syndrome", "Bursitis"], "ans": 2, "exp": "ปวด/กดเจ็บที่ lateral epicondyle + แย่ลงเมื่อกำ/ยกของ = tennis elbow (lateral epicondylitis)", "sys": "XIII"}, {"topic": "Orthopedics", "q": "A 10-year-old male fell off a bicycle and injured his shoulder. No wound. X-ray shows a middle-third clavicle fracture with inferior displacement and anterior angulation. Most appropriate management?", "choices": ["Spica shoulder cast", "Open reduction with plate", "Open reduction with K-wire", "Closed reduction with arm sling", "Closed reduction with nail"], "ans": 3, "exp": "กระดูกไหปลาร้าหักส่วนกลางในเด็ก (ไม่มีแผล ไม่มี NV compromise) -> รักษาแบบอนุรักษ์ด้วย arm sling/figure-of-eight (เด็กหายและ remodel ได้ดี)", "sys": "XIII"}, {"topic": "Orthopedics", "q": "A 50-year-old female with numbness in her left hand, T2DM for 2 years. Atrophy of thenar eminence and decreased pinprick sensation in thumb to middle finger of left hand. Normal right hand and both feet. Most likely diagnosis?", "choices": ["Vitamin B12 deficiency", "Diabetic polyneuropathy", "Cervical radiculopathy", "Ulnar nerve neuropathy", "Carpal tunnel syndrome"], "ans": 4, "exp": "ชาเฉพาะ median nerve distribution (นิ้วโป้งถึงนิ้วกลาง) + thenar atrophy ข้างเดียว = carpal tunnel syndrome. diabetic polyneuropathy จะเป็นสองข้างแบบถุงมือถุงเท้า", "sys": "XIII"}, {"topic": "Orthopedics", "q": "A 12-year-old male fell from a height with clavicular injury. X-ray shows middle-third clavicular fracture with inferior displacement and superior angulation. Mild swelling and pain, no neurovascular compromise or open wound. Most appropriate management?", "choices": ["Closed reduction with arm sling", "Shoulder spica cast", "Open reduction and internal fixation (ORIF) with K-wire", "Open reduction and internal fixation (ORIF) with plate and screws", "Closed reduction with percutaneous pinning"], "ans": 0, "exp": "กระดูกไหปลาร้าหักในเด็กที่ไม่มีภาวะแทรกซ้อน -> รักษาแบบอนุรักษ์ด้วย arm sling (closed reduction + sling)", "sys": "XIII"}, {"topic": "Orthopedics", "q": "A 72-year-old female with severe right hip pain following a fall. Tenderness and swelling in the right hip, with abnormal external rotation of the affected limb. Most likely diagnosis?", "choices": ["Fracture of the shaft of femur", "Fracture of the neck of femur", "Fracture of the acetabulum", "Anterior hip dislocation", "Posterior hip dislocation"], "ans": 1, "exp": "ผู้สูงอายุล้ม + ปวดสะโพก + ขาสั้นและหมุนออก (external rotation) = femoral neck fracture. *อ้างอิงภาพ*", "img": "https://cdn.jsdelivr.net/gh/MercenzK/Web-quiz-images@main/NL2-2024-Q251.png", "sys": "XIII"}, {"topic": "Orthopedics", "q": "A 72-year-old female with right hip pain and swelling following a fall one day ago. Right leg abducted and externally rotated, tenderness at the right hip. Hip X-ray shown. Most likely diagnosis?", "choices": ["Fracture of the acetabulum", "Fracture of the shaft of the right femur", "Fracture of the neck of the right femur", "Anterior dislocation of the hip", "Posterior dislocation of the hip"], "ans": 2, "exp": "ผู้สูงอายุล้ม + ปวดสะโพก + ขาหมุนออก = femoral neck fracture (พบบ่อยสุดในผู้สูงอายุที่ล้ม). *อ้างอิงภาพ X-ray*", "img": "https://cdn.jsdelivr.net/gh/MercenzK/Web-quiz-images@main/NL2-2024-Q252.png", "sys": "XIII"}, {"topic": "Pediatrics", "q": "A 1-year-old child brought for bowlegs. Normal overall clinical development. Slight genu varum, otherwise unremarkable exam. Most appropriate management?", "choices": ["X-ray both knees", "Check serum calcium levels", "Refer to a pediatric orthopedic specialist", "Reassure the parents", "Measure vitamin D levels"], "ans": 3, "exp": "genu varum เล็กน้อยในเด็กอายุ <2 ปี ที่พัฒนาการปกติ = physiologic bowing -> reassure ผู้ปกครอง (หายเองเมื่อโตขึ้น)", "sys": "XIII"}, {"topic": "Orthopedics", "q": "A 70-year-old female with right knee pain for 2 years, morning stiffness. Crepitus and positive ballottement, no warmth or significant inflammation, ROM not limited. Most likely diagnosis?", "choices": ["Pseudogout", "Rheumatoid arthritis", "Reactive arthritis", "Gout", "Osteoarthritis (OA)"], "ans": 4, "exp": "ปวดเข่าเรื้อรังในผู้สูงอายุ + crepitus + ไม่มีการอักเสบชัด = osteoarthritis", "sys": "XIII"}, {"topic": "Orthopedics", "q": "A 30-year-old man with severe left leg pain following a car crash 4 hours ago. Contusion along the left leg, tense feeling, no open wound or deformity. Dorsalis pedis pulse 2+, numbness in the first web space of the foot, severe pain on plantar flexion. Most likely etiology of the numbness?", "choices": ["Compartment syndrome", "Nerve injury", "Arterial injury", "Tibial fracture", "Soft tissue injury"], "ans": 0, "exp": "ขาตึงแข็ง (tense) + ปวดมากเมื่อ passive stretch (plantar flexion) + ชาที่ first web space (deep peroneal nerve) โดยชีพจรยังคลำได้ = compartment syndrome (ความดันในช่องกล้ามเนื้อสูงกดเส้นประสาท/หลอดเลือดฝอย)", "sys": "XIII"}, {"topic": "Orthopedics", "q": "A 45-year-old woman with pain and tenderness at the radial styloid area of the wrist, swelling and tenderness at the base of the thumb, worse with thumb movement and gripping. Most likely diagnosis?", "choices": ["Carpal tunnel syndrome", "De Quervain's tenosynovitis", "Cubital tunnel syndrome", "C6 cervical spondylosis", "Saturday night palsy"], "ans": 1, "exp": "ปวด/กดเจ็บที่ radial styloid + โคนนิ้วโป้ง แย่ลงเมื่อขยับนิ้วโป้ง = De Quervain's tenosynovitis (Finkelstein test บวก)", "sys": "XIII"}, {"topic": "Orthopedics", "q": "A 30-year-old male after a traffic accident, stable vitals. A 3 cm laceration on the left shin with an open wound exposing fragmented bone. Most appropriate antimicrobial treatment?", "choices": ["Cefazolin", "Penicillin G sodium", "Cefazolin + Gentamicin", "Ceftriaxone + Gentamicin", "Cloxacillin + Gentamicin"], "ans": 2, "exp": "open fracture ที่มีกระดูกแตกกระจายโผล่ออกมา (แนวโน้ม Gustilo type III) -> cefazolin (gram-positive) + gentamicin (gram-negative). *ถ้าเป็น type I-II แผลเล็กปนเปื้อนน้อย ใช้ cefazolin เดี่ยว*", "sys": "XIII"}, {"topic": "Orthopedics", "q": "A 30-year-old male after a car accident, stable vitals. A 3 cm laceration on the shin with minimal contamination exposing fragmented bone, nerve function intact. Most appropriate antimicrobial treatment?", "choices": ["Penicillin G", "Amoxicillin + Gentamicin", "Cefazolin + Gentamicin", "Cefazolin", "Amoxicillin-clavulanate (Augmentin)"], "ans": 3, "exp": "open fracture แผล 3 ซม. (1-10 ซม.) ปนเปื้อนน้อย ไม่มี soft tissue damage มาก = Gustilo type II -> ให้ cefazolin (first-generation cephalosporin) เดี่ยว", "sys": "XIII"}, {"topic": "Orthopedics", "q": "A 30-year-old man after a car accident, stable vitals. A 3 cm laceration on the shin with minimal contamination and an open comminuted fracture, no significant soft tissue damage or neurovascular compromise. Most appropriate antimicrobial agent?", "choices": ["Cloxacillin + Gentamicin", "Cefazolin + Gentamicin", "Amoxicillin-clavulanate (Augmentin)", "Vancomycin + Ceftriaxone", "Cefazolin"], "ans": 4, "exp": "open fracture ปนเปื้อนน้อย ไม่มี soft tissue damage มาก (Gustilo type II) -> cefazolin เดี่ยวเพียงพอ (ยังไม่ต้อง gentamicin)", "sys": "XIII"}, {"topic": "Rheumatology", "q": "A 30-year-old female with swelling and tenderness in joints, morning stiffness 2 hours, edema and tenderness in multiple PIP and MCP joints. X-ray shows juxta-articular osteopenia and marginal bone erosion. Most appropriate management?", "choices": ["Prednisolone", "NSAIDs", "Colchicine", "Acetaminophen", "Tramadol"], "ans": 0, "exp": "rheumatoid arthritis (ข้อเล็กสมมาตร PIP/MCP + เช้าฝืด >1 ชม. + erosion) -> ควรเริ่ม DMARD; ในตัวเลือกนี้ prednisolone คุมการอักเสบได้ดีสุดระหว่างรอ DMARD", "sys": "XIII"}, {"topic": "Orthopedics", "q": "A 45-year-old female with numbness in thumb and index finger, atrophy of thenar muscles, diminished sensation in median nerve distribution, weakness in thumb opposition, worse with repetitive hand use and improved with rest. Most likely diagnosis?", "choices": ["De Quervain's tenosynovitis", "Carpal tunnel syndrome", "Cervical spondylosis", "Cubital tunnel syndrome", "Radial nerve palsy"], "ans": 1, "exp": "ชา median distribution + thenar atrophy + อ่อนแรง thumb opposition + สัมพันธ์การใช้งานซ้ำ = carpal tunnel syndrome (median nerve กดที่ข้อมือ)", "sys": "XIII"}, {"topic": "Orthopedics", "q": "A 45-year-old man with right wrist pain at the radial styloid area, worse with certain hand movements. A clinical test shown is positive. Most likely diagnosis?", "choices": ["Carpal tunnel syndrome", "Ulnar tunnel syndrome", "De Quervain's tenosynovitis", "Flexor carpi radialis tendonitis", "Extensor carpi ulnaris tendonitis"], "ans": 2, "exp": "ปวด radial styloid + Finkelstein test บวก = De Quervain's tenosynovitis. *อ้างอิงภาพ (Finkelstein test)*", "img": "https://cdn.jsdelivr.net/gh/MercenzK/Web-quiz-images@main/NL2-2024-Q262.png", "sys": "XIII"}, {"topic": "Rehabilitation medicine", "q": "A 65-year-old man with left hemiparesis from ischemic stroke 1 month ago, left shoulder pain for a week. 2 cm gap between acromion and humerus, flaccid tone of left shoulder, spastic left elbow flexion. Most appropriate management?", "choices": ["U slab", "Closed reduction", "Overhead pulley", "Arm sling", "Strengthening exercise"], "ans": 3, "exp": "hemiplegic shoulder subluxation (ช่องว่าง acromion-humerus + ไหล่ flaccid หลัง stroke) -> ใช้ arm sling พยุงข้อไหล่ป้องกันการเลื่อนหลุด. ห้ามใช้ overhead pulley (ทำให้บาดเจ็บมากขึ้น)", "sys": "VI"}, {"topic": "Ophthalmology", "q": "A 50-year-old man after a nail penetrated his right eye. VA 6/6 left, finger count at 2 feet right. Severe conjunctival injection, sclera not visible due to redness, foreign body in cornea extending into the pupil. Most appropriate initial management?", "choices": ["Eye irrigation", "Pressure patch", "Topical antibiotics", "Remove foreign body", "Eye shield"], "ans": 4, "exp": "open globe injury (ตะปูทะลุตา + สิ่งแปลกปลอมในกระจกตาถึงรูม่านตา) -> ครอบตาด้วย eye shield ป้องกันแรงกด ห้ามล้าง/กด/ดึงสิ่งแปลกปลอมออก แล้วส่งจักษุแพทย์ผ่าตัด", "sys": "VII"}, {"topic": "Ophthalmology", "q": "A 25-year-old woman with redness in her right eye for 3 days, now also left eye, with itching and irritation. Peripheral conjunctivitis, chemosis with follicular reaction, injection, watery discharge, and tender preauricular lymph node. Most likely diagnosis?", "choices": ["Epidemic keratoconjunctivitis", "Trachoma", "Allergic conjunctivitis", "Hay fever conjunctivitis", "Gonococcal conjunctivitis"], "ans": 0, "exp": "ตาแดงสองข้าง + follicular reaction + ขี้ตาใส (watery) + ต่อมน้ำเหลืองหน้าหูโตเจ็บ = viral (adenovirus) = epidemic keratoconjunctivitis", "sys": "VII"}, {"topic": "Ophthalmology", "q": "A 28-year-old woman who works night shifts and wears contact lenses presents with tearing, ciliary injection, and mucopurulent discharge from her right eye. A 1.5 mm whitish corneal infiltration. Most likely causative organism?", "choices": ["Streptococcus species", "Pseudomonas aeruginosa", "Staphylococcus species", "Haemophilus influenzae", "Acinetobacter baumannii"], "ans": 1, "exp": "bacterial keratitis (corneal ulcer, มี infiltration ขาว) ในผู้ใส่ contact lens -> เชื้อที่พบบ่อยและรุนแรงคือ Pseudomonas aeruginosa", "sys": "VII"}, {"topic": "Ophthalmology", "q": "A 28-year-old female with a red eye and history of forgetting to remove contact lenses. Gradual onset redness and discomfort. Ciliary injection, mucopurulent discharge, and a white corneal infiltration at the nasal side. Most likely pathogen?", "choices": ["Staphylococcus aureus", "Staphylococcus epidermidis", "Pseudomonas aeruginosa", "Haemophilus influenzae", "Streptococcus species"], "ans": 2, "exp": "contact lens keratitis (แผลกระจกตาติดเชื้อ) -> เชื้อที่พบบ่อยที่สุดคือ Pseudomonas aeruginosa", "sys": "VII"}, {"topic": "Ophthalmology", "q": "A 70-year-old female with intermittent epiphora for a year. Last year noticed a mass near the lacrimal duct that, when compressed, produced purulent discharge. Palpable mass over the lacrimal sac with purulent discharge. Most appropriate management?", "choices": ["Nasal irrigation", "Nasal probing", "Nasal massage", "Dacryocystorhinostomy", "Incision and drainage (I&D)"], "ans": 3, "exp": "chronic dacryocystitis จากการอุดตันท่อน้ำตา (nasolacrimal duct) + กดมีหนอง -> รักษาแบบถาวรด้วย dacryocystorhinostomy (DCR, สร้างทางระบายน้ำตาใหม่)", "sys": "VII"}, {"topic": "Ophthalmology", "q": "A 70-year-old diabetic woman with intermittent epiphora and mucopurulent discharge from the left eye over a year. Slight bulging of the nasolacrimal sac with mucopurulent reflux from puncta on compression, no tenderness/swelling. Most appropriate management?", "choices": ["Nasolacrimal massage", "Nasolacrimal probing", "Nasolacrimal irrigation", "Incision and drainage (I&D) of the lacrimal sac", "Dacryocystorhinostomy"], "ans": 4, "exp": "chronic dacryocystitis (nasolacrimal duct obstruction, มีหนอง reflux จาก puncta) ในผู้ใหญ่ -> รักษาด้วย dacryocystorhinostomy", "sys": "VII"}, {"topic": "Ophthalmology", "q": "A 70-year-old female with a mass on the upper eyelid present for 1 year with intermittent discharge, now erythematous with excessive tearing. Localized to upper eyelid, no lacrimal sac or punctal involvement. Most likely diagnosis?", "choices": ["Chalazion", "Hordeolum", "Lacrimal sac tumor", "Dacryocystitis", "Canaliculitis"], "ans": 0, "exp": "ก้อนที่เปลือกตาเรื้อรัง (1 ปี) ไม่เจ็บ (granuloma ของต่อม Meibomian) = chalazion (ครั้งนี้มีการอักเสบซ้ำจึงแดง)", "sys": "VII"}, {"topic": "Ophthalmology", "q": "A 70-year-old female with pain and tenderness in the lower eyelid for 3 days. Tender, non-fluctuant mass on the lower lid, red and swollen, no discharge, no systemic infection. Most appropriate management?", "choices": ["Incision and curettage (I&C)", "Warm compression", "Intravenous antibiotics (IV ATB)", "Oral antibiotics", "Topical antibiotic ointment"], "ans": 1, "exp": "hordeolum (stye) ระยะเฉียบพลัน ก้อนเจ็บยังไม่เป็นหนอง (non-fluctuant) -> เริ่มด้วยประคบอุ่น (warm compression). I&C ทำเมื่อเป็นหนอง/ไม่ตอบสนอง", "sys": "VII"}, {"topic": "Ophthalmology", "q": "A 68-year-old woman for routine eye check-up. VA 6/12 right, 6/18 left. Anterior segment normal with mild cataract. Cup-to-disc ratio 0.7 both eyes, retina normal. Next most appropriate examination?", "choices": ["Confrontation test", "Cover-uncover test", "Intraocular pressure measurement", "Corneal light reflex", "Extraocular movement"], "ans": 2, "exp": "cup-to-disc ratio 0.7 (โต) = สงสัย glaucoma -> ตรวจ intraocular pressure ต่อเป็นอันดับถัดไป", "sys": "VII"}, {"topic": "Ophthalmology", "q": "A middle-aged woman with acute right eye pain. IOP 30 mmHg, ciliary injection, shallow anterior chamber (acute angle-closure glaucoma). Appropriate initial management?", "choices": ["Antihistamine eye drop", "Antibiotic eye drop", "Atropine eye drop", "Timolol eye drop", "Antibiotic ointment"], "ans": 3, "exp": "acute angle-closure glaucoma -> ลด IOP ด้วย timolol (beta-blocker) + ยาลดความดันตาอื่น ๆ. ห้ามให้ atropine/ยาขยายม่านตา (ทำให้มุมปิดแย่ลง)", "sys": "VII"}, {"topic": "Ophthalmology", "q": "A 60-year-old female with acute left eye pain, visual loss, and blurred vision. VA finger count left, shallow anterior chamber (acute angle-closure glaucoma). Most appropriate initial treatment?", "choices": ["Dexamethasone eye drop", "Antihistamine eye drop", "Antibiotic eye drop", "1% Prednisolone acetate eye drops", "0.5% Timolol eye drops"], "ans": 4, "exp": "acute angle-closure glaucoma -> ให้ยาลดความดันตา 0.5% timolol เป็นเบื้องต้น (ร่วมกับยาอื่น ๆ) แล้วส่งจักษุแพทย์", "sys": "VII"}, {"topic": "Ophthalmology", "q": "A 60-year-old woman with acute painful and decreased vision in the left eye over a day. VA 6/18 right, finger count left. Left eye ciliary injection, cloudy cornea, shallow anterior chamber, dense cataract (acute angle-closure glaucoma). Most appropriate initial management?", "choices": ["Timolol eye drop", "Atropine eye drop", "Antibiotic eye drop", "Antihistamine eye drop", "Tobramycin eye ointment"], "ans": 0, "exp": "acute angle-closure glaucoma -> ลด IOP ด้วย timolol. ห้ามใช้ atropine (ขยายม่านตา ทำให้มุมปิดมากขึ้น)", "sys": "VII"}, {"topic": "Ophthalmology", "q": "A 30-year-old male with tearing and irritation in the left eye for 1 day. Mild ciliary injection and moderate chemosis. A vertical scratch on the cornea. Next appropriate step in diagnosis?", "choices": ["Discharge and follow up in 1 week", "Upper lid eversion", "Fluorescent stain of the eye", "Slit lamp examination", "Eye irrigation"], "ans": 1, "exp": "รอยถลอกกระจกตาแนวตั้ง (vertical linear abrasion) บ่งว่ามีสิ่งแปลกปลอมใต้เปลือกตาบน -> ต้องพลิกเปลือกตาบน (upper lid eversion) หาและเอาสิ่งแปลกปลอมออก", "sys": "VII"}, {"topic": "Ophthalmology", "q": "A 30-year-old man with eye pain, mild chemosis, ciliary injection, and multiple vertical corneal abrasions. Significant discomfort and tearing. Most appropriate management?", "choices": ["Corneal scrape", "Pressure patch", "Lid eversion", "Fluorescein dye", "Antibiotic eye drops"], "ans": 2, "exp": "รอยถลอกกระจกตาแนวตั้งหลายเส้น = มีสิ่งแปลกปลอมใต้เปลือกตาบน -> พลิกเปลือกตา (lid eversion) เอาสิ่งแปลกปลอมออก (แก้ที่ต้นเหตุ)", "sys": "VII"}, {"topic": "Ophthalmology", "q": "A 25-year-old female with SLE on prednisolone 30 mg/day and azathioprine 50 mg/day, blurred vision in both eyes for 3 months. VA 20/40 both eyes, normal fundoscopy. Most likely diagnosis?", "choices": ["Iritis", "Optic neuritis", "Vasculitis", "Cataract", "Maculopathy"], "ans": 3, "exp": "ใช้ steroid ขนาดสูงนาน -> posterior subcapsular cataract (ตาพร่าค่อยเป็นค่อยไป จอตาปกติ) = cataract", "sys": "VII"}, {"topic": "Otolaryngology", "q": "An 18-year-old male with left ear pain for 1 day after cleaning his ear with a cotton swab. Otoscopy shown. Most appropriate treatment?", "choices": ["Ear toilet", "Topical antibiotics", "Myringoplasty", "Tympanoplasty", "Paper patch"], "ans": 4, "exp": "บาดเจ็บแก้วหูทะลุจากไม้พันสำลี (traumatic TM perforation) -> ส่วนใหญ่หายเอง; ช่วยด้วย paper patch และรักษาให้แห้ง (ไม่ผ่าตัด myringoplasty/tympanoplasty ในระยะแรก). *อ้างอิงภาพ otoscopy*", "img": "https://cdn.jsdelivr.net/gh/MercenzK/Web-quiz-images@main/NL2-2024-Q279.png", "sys": "VIII"}, {"topic": "Otolaryngology", "q": "A 25-year-old male Thai boxer with right ear pain for 2 days. Redness and swelling of the pinna, sparing the earlobe area, after a boxing match. Most likely diagnosis?", "choices": ["Perichondritis", "Cellulitis", "Subperichondrial abscess", "Auricular hematoma", "Chondrodermatitis nodularis helicis"], "ans": 0, "exp": "ใบหูบวมแดงเฉพาะส่วนที่มีกระดูกอ่อน 'เว้นติ่งหู' (lobule ไม่มีกระดูกอ่อน) หลังบาดเจ็บ = perichondritis. cellulitis จะลามถึงติ่งหูด้วย. *อ้างอิงภาพ*", "img": "https://cdn.jsdelivr.net/gh/MercenzK/Web-quiz-images@main/NL2-2024-Q280.png", "sys": "VIII"}, {"topic": "Otolaryngology", "q": "A 40-year-old male with ear fullness, decreased hearing, and mild discomfort in the right ear for a week. Large cerumen occluding the ear canal. Most appropriate initial management?", "choices": ["Myringotomy", "Ear toilet", "Topical antibiotics", "Topical steroids", "Topical cerumenolytics"], "ans": 1, "exp": "ขี้หูอุดตัน (cerumen impaction) ทำให้หูอื้อ -> เอาขี้หูออก (ear toilet) เป็นการรักษาเบื้องต้น. *อ้างอิงภาพ*", "img": "https://cdn.jsdelivr.net/gh/MercenzK/Web-quiz-images@main/NL2-2024-Q281.png", "sys": "VIII"}, {"topic": "Otolaryngology", "q": "A 15-year-old male with left ear pain and hearing loss for 3 days, began after swimming. Tenderness in the ear canal, thick layer of cerumen. Most appropriate management?", "choices": ["Myringotomy", "Antibiotics", "Ear toilet", "Antifungal", "Steroid drops"], "ans": 2, "exp": "otitis externa หลังว่ายน้ำ + ขี้หูอุดตันบดบัง -> เริ่มด้วย ear toilet (ทำความสะอาดช่องหู) เพื่อประเมินและให้ยาหยอดได้ผล. *อ้างอิงภาพ*", "img": "https://cdn.jsdelivr.net/gh/MercenzK/Web-quiz-images@main/NL2-2024-Q282.png", "sys": "VIII"}, {"topic": "Otolaryngology", "q": "A 10-year-old boy with acute severe left ear pain over 2 days, fever, and fullness. Left tympanic membrane shown. Most appropriate antibiotic treatment?", "choices": ["Doxycycline", "Ciprofloxacin", "Amoxicillin-clavulanic acid", "Amoxicillin", "Vancomycin"], "ans": 3, "exp": "acute otitis media (แก้วหูโป่งแดง) -> ยาตัวแรกคือ high-dose amoxicillin. *อ้างอิงภาพ TM*", "img": "https://cdn.jsdelivr.net/gh/MercenzK/Web-quiz-images@main/NL2-2024-Q283.png", "sys": "VIII"}, {"topic": "Otolaryngology", "q": "A 6-year-old male with fever and right ear pain for 3 days, started a week after cough and runny nose. T 39, otoscopy shown. Most appropriate management?", "choices": ["Cefdinir", "Ceftriaxone", "Azithromycin", "Amoxicillin-clavulanate", "Amoxicillin"], "ans": 4, "exp": "acute otitis media หลังติดเชื้อทางเดินหายใจส่วนบน -> first-line คือ amoxicillin (ขนาดสูง). *อ้างอิงภาพ otoscopy*", "img": "https://cdn.jsdelivr.net/gh/MercenzK/Web-quiz-images@main/NL2-2024-Q284.png", "sys": "VIII"}, {"topic": "Otolaryngology", "q": "A 10-year-old female with hearing loss and snoring over 3 months. Bilateral tympanic membrane retraction with air-fluid level in the middle ear. History of frequent URIs. Most likely diagnosis?", "choices": ["Adenoid hypertrophy", "Tympanosclerosis", "Otosclerosis", "Allergic rhinitis", "Chronic sinusitis"], "ans": 0, "exp": "หูอื้อ (otitis media with effusion, TM retraction + air-fluid level) + นอนกรน + URI บ่อยในเด็ก = adenoid hypertrophy (ต่อมอะดีนอยด์โตอุด eustachian tube และทางเดินหายใจ)", "sys": "VIII"}, {"topic": "Otolaryngology", "q": "A 3-year-old boy with hearing loss and snoring over 3 months. Bilateral tympanic membrane retraction with air-fluid levels in the middle ears. Rest of exam unremarkable. Most likely diagnosis?", "choices": ["Otosclerosis", "Adenoid hypertrophy", "Tympanosclerosis", "Allergic rhinitis", "Gastroesophageal reflux"], "ans": 1, "exp": "OME สองข้าง + นอนกรนในเด็กเล็ก = adenoid hypertrophy", "sys": "VIII"}, {"topic": "Otolaryngology", "q": "A 20-year-old female with vertigo for 2 days, history of URI 3 weeks ago. Spontaneous nystagmus to the right, normal otoscopy and neuro exam. Weber shows no lateralization, Rinne positive both ears. Most likely diagnosis?", "choices": ["Labyrinthitis", "Acoustic neuroma", "Vestibular neuritis", "Meniere's disease", "Benign paroxysmal positional vertigo (BPPV)"], "ans": 2, "exp": "เวียนศีรษะต่อเนื่องหลัง URI + nystagmus โดยการได้ยินปกติ (Weber/Rinne ปกติ) = vestibular neuritis. ถ้ามีการได้ยินลดลงด้วยจะเป็น labyrinthitis", "sys": "VIII"}, {"topic": "Otolaryngology", "q": "Otoscopy shows right-sided TM retraction/effusion. Weber lateralizes to the right, Rinne right AC < BC (conductive), left AC > BC (normal). Most appropriate management?", "choices": ["Topical antibiotics", "Oral antibiotics", "Oral decongestant", "Tympanostomy with tube insertion", "Steroid injection directly"], "ans": 3, "exp": "middle ear effusion เรื้อรังที่มี conductive hearing loss (Weber ไปข้างเป็นโรค, Rinne AC<BC ข้างนั้น) -> ระบายของเหลวด้วย tympanostomy with tube insertion (grommet)", "sys": "VIII"}, {"topic": "Otolaryngology", "q": "A 10-year-old girl with hearing loss and snoring. Effusion with air-fluid level in the middle ear. History of recurrent URIs. Most likely diagnosis?", "choices": ["Labyrinthitis", "Meniere's disease", "Tympanitis", "Gastroesophageal reflux disease (GERD)", "Adenoid hypertrophy"], "ans": 4, "exp": "OME (effusion + air-fluid level) + นอนกรน + URI บ่อยในเด็ก = adenoid hypertrophy", "sys": "VIII"}, {"topic": "Otolaryngology", "q": "A 43-year-old female with 3 weeks of facial pain and nasal congestion. Symptoms initially improved with 3 days of oral antibiotics but persisted. Most appropriate next step?", "choices": ["Oral antibiotics", "IV antibiotics", "Intranasal steroid", "CT paranasal sinus", "Refer to ENT consultation"], "ans": 0, "exp": "bacterial rhinosinusitis ที่ได้ยาปฏิชีวนะสั้นเกินไป (3 วัน) แล้วอาการกลับมา -> ให้ยาปฏิชีวนะชนิดรับประทานให้ครบคอร์ส (10-14 วัน เช่น amoxicillin-clavulanate) ก่อนพิจารณา imaging/refer", "sys": "VIII"}, {"topic": "Emergency medicine", "q": "A 40-year-old obese male after a minor car accident from falling asleep while driving. Frequent daytime sleepiness and loud snoring. Most likely diagnosis?", "choices": ["Tonsillar hypertrophy", "Obstructive sleep apnea", "Narcolepsy", "Nonconvulsive seizure", "Bilateral nasal obstruction"], "ans": 1, "exp": "อ้วน + ง่วงนอนกลางวันมาก + นอนกรนเสียงดัง + หลับใน = obstructive sleep apnea", "sys": "emergency"}, {"topic": "Otolaryngology", "q": "A 16-year-old student with severe hoarseness starting 1 day ago after a day of cheering loudly at a football match. Larynx cannot be visualized due to strong gag reflex. Most appropriate management?", "choices": ["Oral antibiotics", "Oral steroids", "Voice rest", "Oral decongestants", "Speech therapy"], "ans": 2, "exp": "acute laryngitis จากการใช้เสียงมากเกินไป (voice abuse) -> รักษาด้วยการพักเสียง (voice rest) หายเองได้", "sys": "VIII"}, {"topic": "Otolaryngology", "q": "A 2-year-old girl with 4-day low-grade fever, painful swallowing, and drooling after being fed fish, then high fever, neck swelling, and torticollis. BT 39, PR 120, tonsils not injected. Lateral neck X-ray shown. Most likely diagnosis?", "choices": ["Viral croup", "Acute epiglottitis", "Infectious mononucleosis", "Retropharyngeal abscess", "Bacterial tracheitis"], "ans": 3, "exp": "เด็กเล็ก + กลืนเจ็บ/น้ำลายไหล + คอบวม + คอเอียง (torticollis) หลังกินปลา (ก้างทิ่ม) + ต่อมทอนซิลปกติ + ฟิล์มคอด้านข้างเห็น prevertebral space กว้าง = retropharyngeal abscess. *อ้างอิงภาพ X-ray*", "img": "https://cdn.jsdelivr.net/gh/MercenzK/Web-quiz-images@main/NL2-2024-Q293.png", "sys": "VIII"}, {"topic": "Emergency medicine", "q": "A 25-year-old male with chest discomfort and breathlessness, no chest pain or palpitations. Both cardiovascular and respiratory examinations normal. Next step in management?", "choices": ["Alprazolam", "Haloperidol", "Rebreathing", "Relaxation", "EKG"], "ans": 4, "exp": "เจ็บแน่นอกในคนหนุ่ม ตรวจร่างกายปกติ (สงสัย panic/hyperventilation) -> ยังต้องทำ EKG ก่อนเพื่อแยกสาเหตุหัวใจ ก่อนวินิจฉัยว่าเป็นภาวะทางจิตใจ", "sys": "emergency"}, {"topic": "Emergency medicine", "q": "A 12-year-old girl with generalized edema, puffy eyelids, lung crepitations, mild ascites, pitting edema. BP 80/60, PR 120, serum albumin 12 g/L. Despite crystalloid loading, vitals nearly unchanged. Next proper initial management?", "choices": ["20% albumin", "Furosemide", "Dobutamine", "Spironolactone", "Hydrochlorothiazide"], "ans": 0, "exp": "nephrotic syndrome + hypovolemic shock (albumin ต่ำมาก, ความดันตก) ที่ไม่ตอบสนอง crystalloid -> ให้ 20% albumin เพิ่ม intravascular volume แล้วตามด้วย furosemide", "sys": "emergency"}, {"topic": "Emergency medicine", "q": "A 35-year-old man post-CABG 3 years ago on daily warfarin. Sudden headache and left hemiparesis. CT shows intracranial hemorrhage in right parietal lobe. PT 30 s, INR 5. Warfarin stopped and IV vitamin K given. Most appropriate management to stop bleeding immediately?", "choices": ["Cryoprecipitate", "Fresh frozen plasma", "Protamine sulfate", "Tranexamic acid", "Repeated dose of vitamin K"], "ans": 1, "exp": "warfarin-related intracranial hemorrhage + INR สูง -> reverse ทันทีด้วย prothrombin complex concentrate (ถ้ามี) หรือ fresh frozen plasma ร่วมกับ vitamin K (vitamin K ออกฤทธิ์ช้า จึงต้องใช้ factor ทดแทนเพื่อหยุดเลือดทันที)", "sys": "emergency"}, {"topic": "Emergency medicine", "q": "A 35-year-old male, CABG 3 years ago on warfarin, sudden headache and right-sided hemiparesis. Non-contrast CT reveals intracerebral hemorrhage. INR significantly elevated. IV vitamin K given, warfarin stopped. Most appropriate management to immediately stop bleeding?", "choices": ["Cryoprecipitate", "Tranexamic acid", "Fresh frozen plasma (FFP)", "Repeat intravenous vitamin K", "Protamine sulfate"], "ans": 2, "exp": "warfarin-associated ICH -> reverse ทันทีด้วย fresh frozen plasma (หรือ PCC) + vitamin K. protamine ใช้ reverse heparin ไม่ใช่ warfarin", "sys": "emergency"}, {"topic": "Emergency medicine", "q": "A 60-year-old female with fever and dyspnea 2 days. T 38, PR 110, RR 30, BP 80/60, dry lips, flat neck veins. Random glucose 600, Na 155, K 3.4, Cl 80, HCO3 12, BUN 50, Cr 3. ABG pH 6.9, CO2 30, SpO2 80%. Most appropriate initial management?", "choices": ["0.9% NaCl", "0.45% NaCl", "0.45% NaCl with KCl", "0.9% NaCl with KCl", "0.45% NaCl with Regular Insulin (RI)"], "ans": 3, "exp": "DKA/hyperglycemic crisis + ขาดน้ำรุนแรง (ความดันตก) -> เริ่มด้วย 0.9% NaCl กู้ปริมาตร; K = 3.4 (ต่ำ) ต้องเติม KCl ก่อน/พร้อมเริ่ม insulin (ถ้า K <3.3 ต้องชะลอ insulin) -> 0.9% NaCl with KCl", "sys": "emergency"}, {"topic": "Emergency medicine", "q": "A 45-year-old male with chest tightness, dizziness, and palpitations. Vitals stable except HR 110. Normal breath and heart sounds, no significant findings. Most appropriate next step?", "choices": ["Alprazolam IV", "Fluoxetine", "Oxygen via nasal cannula", "Cardiac troponin testing", "Electrocardiogram (EKG)"], "ans": 4, "exp": "เจ็บแน่นอก + ใจสั่น + ชีพจรเร็ว -> ทำ EKG ก่อนเป็นอันดับแรกเพื่อแยกภาวะหัวใจ/arrhythmia ก่อนวินิจฉัยเป็น panic", "sys": "emergency"}, {"topic": "Emergency medicine", "q": "A 48-year-old male with severe headache started 1 hour ago. BP 210/100, engorged neck veins, normal heart sounds, clear lungs. Which medication should be given?", "choices": ["Nicardipine", "Labetalol", "Hydralazine", "Thiazide", "Sodium nitroprusside"], "ans": 0, "exp": "hypertensive emergency (BP สูงมาก + อาการปวดหัวรุนแรง = end-organ) -> ให้ยาลดความดันทางหลอดเลือดดำที่ปรับขนาดได้ เช่น nicardipine (หรือ labetalol) ค่อย ๆ ลดความดัน", "sys": "emergency"}, {"topic": "Emergency medicine", "q": "A 40-year-old male with severe headache for 1 day. BP 210/120, HR 90, clear lungs, no other findings. Most appropriate initial medication?", "choices": ["Nicardipine", "Labetalol", "Nitroglycerin", "Enalapril", "Sodium Nitroprusside"], "ans": 1, "exp": "hypertensive emergency -> ให้ยา IV ที่ปรับขนาดได้ เช่น labetalol (หรือ nicardipine) ลดความดันอย่างค่อยเป็นค่อยไป", "sys": "emergency"}, {"topic": "Emergency medicine", "q": "A 25-year-old male with chest discomfort after a motor vehicle accident. BP 80/40, RR 28, PR 110, faint heart sounds, tracheal shift to the right, hyperresonance on percussion of the left lung. Most appropriate initial management?", "choices": ["Emergency thoracotomy", "Endotracheal intubation", "Needle thoracostomy", "Pericardiocentesis", "Insertion of an indwelling chest drain (ICD)"], "ans": 2, "exp": "tension pneumothorax ซ้าย (trachea เบนขวา + เคาะโปร่งซ้าย + ช็อก) -> ระบายลมด่วนด้วย needle thoracostomy ทันที แล้วตามด้วยใส่ ICD", "sys": "emergency"}, {"topic": "Emergency medicine", "q": "A 30-year-old woman stabbed in the left chest. BP 70/40, HR 130, RR 30, stab wound at left 5th ICS midclavicular line. Jugular vein distention, trachea midline, normal breath sounds, distant heart sounds. Most likely diagnosis?", "choices": ["Hemothorax", "Pneumothorax", "Open chest wound", "Cardiac tamponade", "Diaphragmatic injury"], "ans": 3, "exp": "Beck's triad (ความดันตก + JVD + เสียงหัวใจเบา) + trachea อยู่กลาง + เสียงหายใจปกติ หลังถูกแทงบริเวณหัวใจ = cardiac tamponade", "sys": "emergency"}, {"topic": "Emergency medicine", "q": "A 55-year-old man after a motor vehicle accident. BP 70/50, HR 130, decreased breath sounds on the left, trachea shifted to the right, faint heart sounds, jugular vein distention. Most appropriate management?", "choices": ["Thoracotomy", "Pericardiocentesis", "Intercostal drainage", "Fluid resuscitation", "Needle thoracostomy"], "ans": 4, "exp": "tension pneumothorax ซ้าย (เสียงหายใจซ้ายลด + trachea เบนขวา + JVD + ช็อก) -> needle thoracostomy ระบายลมทันที", "sys": "emergency"}, {"topic": "Emergency medicine", "q": "A 30-year-old woman bitten by a stray dog. Completed rabies immunization 2 years ago. Abrasion wound on right calf with oozing blood. Appropriate rabies prophylaxis?", "choices": ["1 booster dose", "Rabies immunoglobulin", "1 booster dose + rabies immunoglobulin", "2 booster doses + rabies immunoglobulin", "5 doses of rabies vaccine"], "ans": 0, "exp": "ผู้ที่เคยฉีดวัคซีนพิษสุนัขบ้าครบชุดมาก่อน เมื่อถูกกัดซ้ำ -> ให้ booster (มาตรฐานคือ 2 เข็ม วันที่ 0 และ 3) และ 'ไม่ต้องให้ rabies immunoglobulin' *ต้นฉบับไม่มีตัวเลือก '2 boosters ไม่มี RIG' โดยตรง; หลักการสำคัญคือไม่ให้ RIG ในผู้เคยฉีดครบ*", "sys": "emergency"}, {"topic": "Emergency medicine", "q": "A 30-year-old Thai male who completed a full rabies vaccination series 2 years ago, now bitten by a dog of unknown vaccination status on the leg. Most appropriate management?", "choices": ["Administer one rabies booster shot.", "Administer two rabies booster shots.", "Take no further action.", "Administer one rabies booster shot and provide Human Rabies Immunoglobulin (HRIG).", "Provide only Human Rabies Immunoglobulin (HRIG)."], "ans": 1, "exp": "เคยฉีดวัคซีนครบชุดมาก่อน + สัมผัสซ้ำ -> ฉีด booster 2 เข็ม (วันที่ 0 และ 3) โดยไม่ต้องให้ HRIG", "sys": "emergency"}, {"topic": "Emergency medicine", "q": "A 25-year-old woman with a contaminated avulsion wound from a motorcycle accident. Full tetanus vaccination 8 years ago. Most appropriate tetanus prophylaxis?", "choices": ["No need for tetanus prophylaxis", "Tetanus immunoglobulin", "Single booster tetanus vaccination", "Full course tetanus vaccination", "Full course tetanus vaccination with tetanus immunoglobulin"], "ans": 2, "exp": "แผลสกปรก + เคยฉีดครบชุดแต่เข็มสุดท้าย >5 ปี -> ให้ booster (Td) เข็มเดียว ไม่ต้องให้ TIG (เพราะเคยได้ภูมิครบแล้ว)", "sys": "emergency"}, {"topic": "Emergency medicine", "q": "A 25-year-old woman with a contaminated avulsion wound following a motorcycle accident. Completed a full course of tetanus vaccination 8 years ago. Most appropriate management for tetanus prophylaxis?", "choices": ["No further management", "Tetanus immunoglobulin", "Full course of tetanus vaccine", "Single dose of tetanus vaccine", "Full course of tetanus vaccine with tetanus immunoglobulin"], "ans": 3, "exp": "แผลสกปรก + วัคซีนครบแต่เข็มสุดท้าย >5 ปี -> ให้ tetanus toxoid booster เข็มเดียว (ไม่ต้องให้ TIG)", "sys": "emergency"}, {"topic": "Emergency medicine", "q": "A 40-year-old man stung by a box jellyfish while swimming. Severe pain, erythema, tentacle marks, nausea, vomiting, difficulty breathing. Stable vitals but mild hypotension and tachycardia. Most appropriate management?", "choices": ["Cold water immersion", "Normal saline (NSS) irrigation", "Immediate administration of antivenom", "Application of hot water to the affected area", "Vinegar irrigation"], "ans": 4, "exp": "box jellyfish sting -> ราดด้วยน้ำส้มสายชู (vinegar/acetic acid) เพื่อยับยั้ง nematocyst ไม่ให้ปล่อยพิษเพิ่ม เป็นการปฐมพยาบาลสำคัญ (รายรุนแรงพิจารณา antivenom)", "sys": "emergency"}, {"topic": "Emergency medicine", "q": "A 35-year-old man bitten by a cobra. Appears well, no distress. A fang mark at the bite site, no bleeding or abnormal findings. Stable vitals. Appropriate management?", "choices": ["Monitor peak flow spirometry", "Antivenom", "Blood clotting time", "Administer tetanus prophylaxis", "Observe and provide symptomatic treatment"], "ans": 0, "exp": "งูเห่า (cobra) = พิษต่อระบบประสาท (neurotoxic) -> เฝ้าระวังภาวะหายใจล้มเหลวด้วยการติดตามการทำงานของปอด (peak flow/spirometry, single-breath count) ให้ antivenom เมื่อมีอาการ. (blood clotting time ใช้กับงูพิษต่อเลือด เช่น งูแมวเซา)", "sys": "emergency"}, {"topic": "Emergency medicine", "q": "A 10-year-old child with drooling and stridor after ingesting toilet cleaner 2 hours ago. In respiratory distress, ETT inserted for airway compromise. Most appropriate management?", "choices": ["Activated charcoal", "Esophagogastroduodenoscopy (EGD)", "Induce vomiting", "Nasogastric (NG) lavage", "CT abdomen"], "ans": 1, "exp": "กลืนสารกัดกร่อน (caustic) -> ห้ามทำให้อาเจียน/ล้างท้อง/ให้ถ่านกัมมันต์ (ยิ่งทำลายซ้ำ). ทำ EGD เพื่อประเมินระดับการบาดเจ็บของหลอดอาหารภายใน 24-48 ชม.", "sys": "emergency"}, {"topic": "Emergency medicine", "q": "A 5-year-old boy who accidentally ingested liquid cleanser 1 hour ago. BP 90/60, HR 120, RR 28. Injected oral mucosa with mild erosion, otherwise normal. Most appropriate management?", "choices": ["Activated charcoal", "Induce vomiting", "Esophagogastroscopy (EGD)", "Nasogastric (NG) lavage", "Administer intravenous fluids"], "ans": 2, "exp": "caustic ingestion (เยื่อบุปากแดง/erosion) -> ทำ EGD ประเมินการบาดเจ็บหลอดอาหาร; ห้ามกระตุ้นอาเจียน/ล้างท้อง/ถ่านกัมมันต์", "sys": "emergency"}, {"topic": "Emergency medicine", "q": "A 25-year-old man electrocuted by an electric shock to his right hand. Numbness and tingling in the right hand, entrance and exit wounds, stable vitals. Most appropriate management?", "choices": ["Serum creatine phosphokinase (CPK)", "Serum creatinine (Cr)", "Monitor for cardiac arrhythmias", "Electrocardiogram (EKG)", "Obtain a chest X-ray"], "ans": 3, "exp": "electrical injury เสี่ยงหัวใจเต้นผิดจังหวะ -> ทำ EKG เป็นอันดับแรกเพื่อประเมิน arrhythmia (และตรวจ CPK/ปัสสาวะประเมิน rhabdomyolysis ต่อไป)", "sys": "emergency"}, {"topic": "Emergency medicine", "q": "A 14-year-old boy with euphoria, agitation, and pressured speech after consuming sweets and beverages at a birthday party 1 hour ago. PR 120, red eyes, pupils 3 mm, dry mouth, hyperactivity. Most probable cause?", "choices": ["Ecstasy", "Opioid", "Alcohol", "Amphetamine", "Cannabis"], "ans": 4, "exp": "ตาแดง (conjunctival injection) + ปากแห้ง + ครึกครื้น/euphoria + ชีพจรเร็ว โดยรูม่านตาปกติ (3 มม.) หลังกินขนม/เครื่องดื่ม (edible) = cannabis. amphetamine/ecstasy จะรูม่านตาขยาย", "sys": "emergency"}, {"topic": "Emergency medicine", "q": "A 35-year-old man with drowsiness and respiratory distress, history of consuming homemade alcohol. BP 110/60, HR 110, RR 28 with hyperpnea, SpO2 94%, alcohol odor, no crepitations, no neuro deficit. ABG pH 7.2, PCO2 30, HCO3 15. Na 135, K 4.0, Cl 100. Most likely diagnosis?", "choices": ["Methanol intoxication", "Paraquat intoxication", "Amphetamine intoxication", "Organophosphate intoxication", "Pneumonia"], "ans": 0, "exp": "เหล้าเถื่อน (homemade alcohol) + high anion gap metabolic acidosis (AG = 135-100-15 = 20) + หายใจหอบลึก (Kussmaul) = methanol intoxication -> รักษาด้วย fomepizole/ethanol + hemodialysis", "sys": "emergency"}, {"topic": "Emergency medicine", "q": "A 45-year-old male found unconscious with excessive salivation and copious oral secretions, airway compromised, with significant agitation and muscle twitching. Most likely causative agent?", "choices": ["Barbiturates", "Cholinesterase inhibitors", "Amphetamine", "Carboxyhemoglobin", "Anticholinergic agents"], "ans": 1, "exp": "น้ำลาย/สารคัดหลั่งมาก + muscle fasciculation (SLUDGE + กล้ามเนื้อกระตุก) = organophosphate/cholinesterase inhibitor poisoning -> รักษาด้วย atropine + pralidoxime", "sys": "emergency"}, {"topic": "Psychiatry", "q": "A 28-year-old woman rescued from a collapsed building 4 months ago. Since then nightmares, intrusive memories, and avoiding tall buildings. No prior drug abuse or mental health issues. Most likely diagnosis?", "choices": ["Acute Stress Disorder", "Specific Phobia", "Posttraumatic Stress Disorder", "Generalized Anxiety Disorder", "Adjustment Disorder with Anxiety"], "ans": 2, "exp": "อาการ re-experiencing (ฝันร้าย/ภาพเหตุการณ์) + avoidance หลังเหตุการณ์สะเทือนใจ นานเกิน 1 เดือน (ที่นี่ 4 เดือน) = post-traumatic stress disorder. Acute stress disorder จะน้อยกว่า 1 เดือน", "sys": "V"}, {"topic": "Psychiatry", "q": "A 45-year-old woman with fatigue and dizziness after learning of a celebrity's death from cancer, now anxious about having cancer and requesting a CT. Also worried about her daughter's late hours and her husband's commute/accidents. Difficulty sleeping. Most likely diagnosis?", "choices": ["Illness Anxiety Disorder", "Adjustment Disorder", "Panic Disorder", "Generalized Anxiety Disorder", "Obsessive-Compulsive Disorder"], "ans": 3, "exp": "กังวลมากเกินหลายเรื่อง (สุขภาพตัวเอง ลูก สามี) + นอนไม่หลับ = generalized anxiety disorder (กังวลกระจายหลายด้าน ไม่ได้จำกัดที่โรคอย่างเดียว)", "sys": "V"}, {"topic": "Psychiatry", "q": "A 30-year-old businessperson feeling excessively sleepy for a month, with lethargy and lack of motivation over the past year (after his business declined). Recently invested in a new venture spending long hours. Most likely diagnosis?", "choices": ["Bipolar Disorder", "Personality Disorder", "Attention-Deficit/Hyperactivity Disorder (ADHD)", "Adjustment Disorder", "Depressive Disorder"], "ans": 4, "exp": "อ่อนเพลีย เบื่อ ไม่มีแรงจูงใจ นอนมาก (hypersomnia) เรื้อรังหลังธุรกิจล้มเหลว = depressive disorder", "sys": "V"}, {"topic": "Psychiatry", "q": "A 20-year-old male with chest tightness, a feeling of losing control, sweating, and agitation. The EKG is shown (normal/sinus tachycardia). Initial management?", "choices": ["Alprazolam", "Hospitalization", "Sertraline", "Oxygen therapy", "Beta-blockers"], "ans": 0, "exp": "panic attack (แน่นอก กลัวเสียการควบคุม เหงื่อออก EKG ปกติ) -> รักษาเฉียบพลันด้วย benzodiazepine ออกฤทธิ์เร็ว (alprazolam) + reassurance. *อ้างอิงภาพ EKG*", "img": "https://cdn.jsdelivr.net/gh/MercenzK/Web-quiz-images@main/NL2-2024-Q320.png", "sys": "V"}, {"topic": "Psychiatry", "q": "A 30-year-old female with initial insomnia for 2 weeks following a breakup, feeling sad and guilty, no suicidal thoughts, able to work but reduced concentration. Most likely diagnosis?", "choices": ["Acute Stress Disorder", "Adjustment Disorder", "Major Depressive Disorder (MDD)", "Posttraumatic Stress Disorder (PTSD)", "Dependent Personality Disorder"], "ans": 1, "exp": "อารมณ์เศร้าหลังเหตุการณ์เครียดชัดเจน (เลิกกับแฟน) ภายใน 3 เดือน โดยยังทำงานได้และไม่ครบเกณฑ์ MDD = adjustment disorder", "sys": "V"}, {"topic": "Psychiatry", "q": "A 30-year-old female with insomnia starting 2 weeks ago after a breakup, feeling sad and guilty, able to work but decreased concentration, denies suicidal thoughts, no prior mood disorder. Most likely diagnosis?", "choices": ["Acute Stress Disorder", "Major Depressive Disorder (MDD)", "Adjustment Disorder", "Posttraumatic Stress Disorder (PTSD)", "Dependent Personality Disorder"], "ans": 2, "exp": "อาการเศร้าตอบสนองต่อความเครียด (breakup) ไม่ครบเกณฑ์ MDD = adjustment disorder", "sys": "V"}, {"topic": "Psychiatry", "q": "A 25-year-old male with a preference for solitude and limited social interaction, minimal class participation, average grades. Introverted with an emotionless demeanor. Most likely diagnosis?", "choices": ["Avoidant Personality Disorder", "Borderline Personality Disorder", "Dysthymia", "Schizoid Personality Disorder", "Social Anxiety Disorder"], "ans": 3, "exp": "ชอบอยู่คนเดียว ไม่สนใจสัมพันธ์กับผู้อื่น อารมณ์เรียบเฉย (ไม่ได้กลัว/อยากเข้าสังคมแต่ทำไม่ได้) = schizoid personality disorder. avoidant/social anxiety จะอยากเข้าสังคมแต่กลัวถูกปฏิเสธ", "sys": "V"}, {"topic": "Psychiatry", "q": "A 30-year-old newly married housewife diagnosed with depressive disorder, symptoms began after marriage. Husband asked her to quit her job (after a promotion), move, and start a family. Most significant issue in this couple's situation?", "choices": ["Arrange the traditional family norm", "Divide the clear couple role", "Establish mutually satisfying relationship", "Maintain relationship with own family of origin", "Accept the new role as a couple"], "ans": 4, "exp": "คู่แต่งงานใหม่ต้องปรับตัวเข้าสู่บทบาทคู่สมรส -> ประเด็นสำคัญคือการยอมรับบทบาทใหม่ในฐานะคู่สมรส (accept the new role as a couple)", "sys": "V"}, {"topic": "Psychiatry", "q": "A 30-year-old female with depressive symptoms shortly after marriage. Married her college sweetheart, both work at the same company. Recently promoted but spouse suggests she leave her job for homemaking. Now feels worthless and withdrawn. Developmental task this couple is struggling with?", "choices": ["Negotiate and integrate new roles and expectations", "Create a mutual need relationship", "Life after marriage acceptance", "Clarify family role", "Establish good connection with family origin"], "ans": 0, "exp": "งานพัฒนาการของคู่แต่งงานใหม่ = การต่อรองและปรับบทบาท/ความคาดหวังใหม่ร่วมกัน (negotiate and integrate new roles and expectations)", "sys": "V"}, {"topic": "Psychiatry", "q": "A 35-year-old man with schizophrenia on haloperidol 20 mg/day for 10 years. One month ago exacerbation, haloperidol increased to 30 mg/day. Hallucinations improved but now agitation, restlessness, and excessive walking around the house. Best management?", "choices": ["Relaxation techniques", "Add benzodiazepines", "Add chlorpromazine", "Electroconvulsive therapy", "Increase haloperidol dosage"], "ans": 1, "exp": "restlessness/เดินไปมาไม่หยุดหลังเพิ่ม haloperidol = akathisia (extrapyramidal side effect) -> ลดขนาดยา + เพิ่ม benzodiazepine (หรือ propranolol). ไม่เพิ่ม haloperidol (จะยิ่งแย่)", "sys": "V"}, {"topic": "Psychiatry", "q": "A 35-year-old man with schizophrenia on haloperidol 20 mg/day for 10 years, dose increased to 30 mg/day for exacerbation. Psychotic symptoms improved but now agitation, cannot stand still, keeps walking around for 2 weeks. Appropriate management?", "choices": ["Increase haloperidol dosage", "Add chlorpromazine", "Add benzodiazepine", "Relaxation therapy", "Electroconvulsive therapy"], "ans": 2, "exp": "akathisia จาก haloperidol -> เพิ่ม benzodiazepine (หรือ propranolol) และลดขนาด antipsychotic; ไม่เพิ่มขนาด haloperidol", "sys": "V"}, {"topic": "Psychiatry", "q": "A 30-year-old woman frequently visits the ER with pounding heart, shaking, breathlessness, choking sensations, and fear of losing control. Agitation, sweating, PR 112, RR 24, BP 110/70, SpO2 98%, normal heart/lungs, ECG sinus tachycardia. Most appropriate initial management?", "choices": ["Oxygen cannula", "Oral propranolol", "IV diazepam", "Rebreathing in the paper bag", "IV amiodarone"], "ans": 3, "exp": "panic attack ที่มี hyperventilation (หายใจเร็ว มือ/เท้าชา) -> ให้ reassurance และหายใจในถุงกระดาษ (rebreathing) ช่วยแก้ respiratory alkalosis; EKG sinus tachycardia ไม่ใช่ arrhythmia จริง", "sys": "V"}, {"topic": "Psychiatry", "q": "A 20-year-old male in the ER with hyperventilation (dizziness, tingling in extremities, chest tightness), anxious and agitated. RR 28, HR 100, BP 115/75, SpO2 99%. Normal exam/workup, ECG sinus tachycardia, normal labs. Most appropriate initial management?", "choices": ["Consult psychiatry", "Oxygen supplement", "IV diazepam", "Assessment for possible underlying metabolic or respiratory causes", "Rebreathing therapy"], "ans": 4, "exp": "hyperventilation syndrome จากความวิตกกังวล (ตรวจทุกอย่างปกติ) -> รักษาด้วย rebreathing therapy (หายใจในถุง/เทคนิคควบคุมการหายใจ) แก้ respiratory alkalosis", "sys": "V"}, {"topic": "Psychiatry", "q": "A 35-year-old man admitted for elective herniorrhaphy. Three days after hospitalization he develops confusion, agitation, and reports seeing rats all over his bed. Agitation and disorientation, no focal deficits. Blood cultures and LP pending. Most likely diagnosis?", "choices": ["Substance abuse", "Prior head injury", "Septic meningitis", "Previous psychiatric cause", "Septic encephalitis"], "ans": 0, "exp": "สับสน + เห็นภาพหลอน (เห็นหนู) + agitation ในวันที่ 3 ของการนอน รพ. = alcohol withdrawal delirium (delirium tremens) -> เป็นภาวะจากการหยุดสุรา (substance abuse)", "sys": "V"}, {"topic": "Psychiatry", "q": "A 35-year-old man admitted for elective herniorrhaphy. Three days postoperatively develops confusion, agitation, and hallucinations (seeing rats). Agitation and disorientation, no psychiatric history, on postoperative medications. Most likely psychiatric diagnosis?", "choices": ["Acute stress disorder", "Delirium", "Substance use disorder", "Psychotic disorder", "Brief psychotic disorder"], "ans": 1, "exp": "สับสนเฉียบพลัน + สมาธิ/การรับรู้แปรปรวน + ภาพหลอน หลังผ่าตัด = delirium (มักจาก alcohol withdrawal/ยา) เป็นการวินิจฉัยทางจิตเวชที่ถูกต้อง", "sys": "V"}, {"topic": "Psychiatry", "q": "A postoperative man develops confusion, agitation, paranoia, and reports seeing rats running on his bed. Agitation, disorientation, hallucinations. No psychiatric history, no head injury, on postoperative medications. Most likely etiology?", "choices": ["Previous head injury", "Previous psychotic disorder", "Substance-induced disorder", "Septic encephalopathy", "Acute stress disorder"], "ans": 2, "exp": "delirium ที่มีภาพหลอนเห็นสัตว์ (เห็นหนู) วันที่ 3 หลังผ่าตัด = substance-induced (alcohol withdrawal) delirium", "sys": "V"}, {"topic": "Psychiatry", "q": "A 40-year-old male developed confusion and asterixis one day after appendectomy. History of daily rice wine consumption for 10 years. Signs of hepatic encephalopathy (asterixis), elevated liver enzymes and bilirubin. Most appropriate medication?", "choices": ["Lorazepam", "Haloperidol", "Amitriptyline", "Lactulose", "N-acetylcysteine"], "ans": 3, "exp": "hepatic encephalopathy (สับสน + asterixis + ตับผิดปกติ ในผู้ติดสุรา) -> รักษาด้วย lactulose ลดการดูดซึม/สร้างแอมโมเนีย", "sys": "V"}, {"topic": "Psychiatry", "q": "A 3-year-old child with delayed speech, aggressive behavior, and poor eye contact for the past year. Tip-toe walking, echolalia, hyperactivity, difficulty with social interactions, repetitive behaviors. No neglect or trauma, delayed milestones, no intellectual disability. Most likely diagnosis?", "choices": ["Intellectual disability", "Neglected child", "Language learning disorder", "Attention-Deficit/Hyperactivity Disorder (ADHD)", "Autism Spectrum Disorder"], "ans": 4, "exp": "พูดช้า + สบตาน้อย + echolalia + พฤติกรรมซ้ำ ๆ + เดินเขย่งเท้า + บกพร่องปฏิสัมพันธ์สังคม = autism spectrum disorder", "sys": "V"}, {"topic": "Psychiatry", "q": "A mother asks about her 4-year-old son who had a tantrum in public (threw himself on the floor, cried loudly, demanded a toy). Frequent tantrums when he doesn't get his way, often in public. Otherwise healthy, no developmental concerns. Most appropriate approach during tantrums?", "choices": ["Ignore but look for safety", "Time-out technique", "Give him what he wants", "Tell him to stop crying", "Console him during the tantrum"], "ans": 0, "exp": "temper tantrum เพื่อเรียกร้อง -> ไม่ควรตามใจ (จะเสริมพฤติกรรม) แต่ให้เพิกเฉยอย่างมีการดูแลความปลอดภัย (ignore but ensure safety) จนสงบ", "sys": "V"}, {"topic": "Psychiatry", "q": "A 20-year-old medical student preparing for a final exam tomorrow feels bored, unmotivated, and disinterested in studying. Becomes irritable and argues with friends who encourage him. Increased stress from the exam, no history of mood/anxiety disorder. Most likely diagnosis?", "choices": ["Major Depressive Disorder (MDD)", "Adjustment Disorder", "Generalized Anxiety Disorder (GAD)", "Acute Stress Disorder", "Bipolar Disorder"], "ans": 1, "exp": "อาการทางอารมณ์/พฤติกรรม (เบื่อ หงุดหงิด) ตอบสนองต่อความเครียดเฉพาะ (สอบ) โดยไม่ครบเกณฑ์โรคอื่น = adjustment disorder", "sys": "V"}, {"topic": "Psychiatry", "q": "A college student has a major test tomorrow. Today she feels exhausted, lacks motivation to study, becomes angry and irritable when her roommate suggests studying. Overwhelmed by academic pressure. Most likely diagnosis?", "choices": ["Major Depressive Disorder (MDD)", "Adjustment Disorder", "Acute Stress Disorder", "Bipolar Disorder"], "ans": 1, "exp": "อารมณ์/พฤติกรรมตอบสนองต่อความเครียด (สอบ) ในระยะสั้น ไม่ครบเกณฑ์ MDD = adjustment disorder", "sys": "V"}, {"topic": "Community medicine", "q": "A mother has been aggressive and violent toward her family for 6 months, a change from a previously good relationship. Escalation began after her only son (with end-stage renal disease and leukemia relapse) deteriorated 3 months ago. Married 10 years, previously harmonious, now frequent arguments. Most important problem affecting this family?", "choices": ["Mid-life crisis", "Couple violence", "Family of the chronic illness disease", "Family of the dying", "Family of young adult"], "ans": 3, "exp": "ลูกคนเดียวป่วยระยะสุดท้าย (ESRD + leukemia relapse) ทรุดลง -> ครอบครัวกำลังเผชิญการสูญเสีย = family of the dying (พฤติกรรมก้าวร้าวของแม่เป็นปฏิกิริยาความโศกเศร้า)", "sys": "II"}, {"topic": "Psychiatry", "q": "A 70-year-old male admitted for pneumonia. Two days later develops agitation, confusion, and sleep disturbances. No alcohol/substance history. Verbal aggression, disorientation, and hallucinations. Refuses medical intervention. Most appropriate medication?", "choices": ["Valproate", "Benzodiazepine", "Midazolam", "Amitriptyline", "Haloperidol"], "ans": 4, "exp": "delirium ในผู้ป่วยสูงอายุที่มีภาวะกระวนกระวาย/ก้าวร้าว (ไม่ใช่จากสุรา) -> ให้ haloperidol ขนาดต่ำควบคุมอาการ (benzodiazepine เหมาะกับ delirium จากการหยุดสุราเท่านั้น)", "sys": "V"}, {"topic": "Psychiatry", "q": "A 40-year-old man admitted for elective appendectomy. Postoperatively develops disorientation and confusion. History of 1 bottle of whisky/day for 10 years. Stable vitals, no fever, no tremors or significant agitation. Most appropriate management?", "choices": ["Lorazepam", "Haloperidol", "Sertraline", "Methadone", "Disulfiram"], "ans": 0, "exp": "alcohol withdrawal (สับสนหลังผ่าตัดในผู้ติดสุราที่ขาดสุรา) -> รักษาด้วย benzodiazepine (lorazepam)", "sys": "V"}, {"topic": "Psychiatry", "q": "A 25-year-old actress concerned about weight gain. Over the past month: labile mood, easy anger, and auditory hallucinations. Also nausea, vomiting, sweating, tachycardia. Accusing coworkers of gossiping. Most likely cause?", "choices": ["Kratom", "Amphetamine", "Marijuana", "Thyroxine", "Cocaine"], "ans": 1, "exp": "ใช้เพื่อลดน้ำหนัก + อาการ sympathetic (เหงื่อ ใจสั่น) + โรคจิตหวาดระแวง (paranoia, hallucination) = amphetamine intoxication/psychosis", "sys": "V"}, {"topic": "Psychiatry", "q": "A 17-year-old male at a friend's party had some snacks and then felt nauseous and vomited. Agitated with red, bloodshot eyes. No significant past history, otherwise healthy. Most likely cause?", "choices": ["Marijuana", "Amphetamine", "Cannabis", "Opioid", "Alcohol"], "ans": 2, "exp": "ตาแดง (conjunctival injection) + ครึกครื้น/agitation หลังกินขนม (edible) = cannabis (กัญชา)", "sys": "V"}, {"topic": "Preventive medicine", "q": "A 40-year-old carpenter with 2-year history of dyspnea, cough, chest tightness, worse on weekdays at work and improving on weekends away from work. Mild dyspnea and wheezing, CXR unremarkable. Most likely diagnosis?", "choices": ["Bronchiectasis", "Lung cancer", "Intestinal pneumatosis", "Occupational asthma", "Chronic Obstructive Pulmonary Disease (COPD)"], "ans": 3, "exp": "อาการหอบ/wheeze แย่ลงในวันทำงานและดีขึ้นวันหยุด = occupational asthma (สัมพันธ์กับสารก่อภูมิแพ้/สารระคายที่ทำงาน)", "sys": "II"}, {"topic": "Preventive medicine", "q": "A 76-year-old man with well-controlled DM, HT, BPH, living with his family, with 1 month of frequent dizziness and fainting. Follow-up every 3 months. Most important initial assessment during a home visit?", "choices": ["Caregiver", "Nutrition", "Medication", "Disability", "Safety"], "ans": 4, "exp": "ผู้สูงอายุที่เวียนศีรษะ/เป็นลม (เสี่ยงล้ม) -> ประเมิน safety (ความปลอดภัย/ความเสี่ยงการหกล้มในบ้าน) เป็นอันดับแรกในการเยี่ยมบ้าน", "sys": "XIV"}, {"topic": "Preventive medicine", "q": "A 76-year-old man with DM, HT, BPH, with dizziness and fainting over a month, living with family, regular follow-up. Concerns about safety and well-being at home. Most appropriate initial assessment?", "choices": ["Safety", "Nutrition", "Caregiver", "Immobility", "Medication"], "ans": 0, "exp": "เวียนศีรษะ/เป็นลม เสี่ยงหกล้มบาดเจ็บ -> ประเมิน safety เป็นอันดับแรกในการเยี่ยมบ้าน", "sys": "XIV"}, {"topic": "Preventive medicine", "q": "A 60-year-old man with HT, DM, BPH lives with his wife. Frequent episodes of dizziness and lightheadedness. Most likely cause of his symptoms?", "choices": ["Hypertension", "Medication", "Diabetes Mellitus", "Benign Prostatic Hyperplasia", "Dehydration"], "ans": 1, "exp": "เวียนศีรษะ/หน้ามืดในผู้สูงอายุที่กินยาหลายชนิด (ยาลดความดัน/ยา BPH เช่น alpha-blocker) -> สาเหตุที่พบบ่อยคือ medication (orthostatic hypotension จากยา)", "sys": "IV"}, {"topic": "Preventive medicine", "q": "Health surveillance shows hypertension prevalence of 30%. The hospital initiates a campaign to reduce salt intake to prevent the development of hypertension. What category of prevention?", "choices": ["Primordial prevention", "Secondary prevention", "Primary prevention", "Tertiary prevention", "Quaternary prevention"], "ans": 2, "exp": "ลดการบริโภคเกลือเพื่อป้องกันไม่ให้เกิดโรคความดันโลหิตสูง (ลดปัจจัยเสี่ยงก่อนเกิดโรค) = primary prevention", "sys": "general"}, {"topic": "Preventive medicine", "q": "A physician in a community hospital observes rising pulmonary TB infection among OPD healthcare workers. Best control measure?", "choices": ["Provide training program", "Notify infection control team", "Establish PPE policy in hospital", "Provide N95 face mask", "Temporarily close this OPD for 1 week"], "ans": 3, "exp": "ป้องกันการติดเชื้อ TB (airborne) ในบุคลากร -> ให้ N95 respirator เป็นการป้องกันทางเดินหายใจโดยตรง (ร่วมกับ administrative/environmental controls)", "sys": "I"}, {"topic": "Community/EBM", "q": "In an RCT of a new drug vs placebo for preventing ASCVD (100 per group), the new drug prevents ASCVD in 70% and placebo in 50%. How many patients need to be treated with the new drug to prevent one additional case?", "choices": ["2", "10", "15", "20", "5"], "ans": 4, "exp": "ARR = 70% - 50% = 20% = 0.2; NNT = 1/ARR = 1/0.2 = 5", "sys": "general"}, {"topic": "Community/EBM", "q": "A study evaluates d-dimer (>400) for detecting DVT (by ultrasound). Of 100 patients, 70 have DVT; of these, 40 have d-dimer >400. Of 30 without DVT, 20 have d-dimer >400. Sensitivity and specificity?", "choices": ["Sensitivity = 57.14%, Specificity = 33.33%", "Sensitivity = 40%, Specificity = 66.67%", "Sensitivity = 33.33%, Specificity = 57.14%", "Sensitivity = 66.67%, Specificity = 40%", "Sensitivity = 50%, Specificity = 50%"], "ans": 0, "exp": "Sensitivity = TP/(TP+FN) = 40/70 = 57.14%; Specificity = TN/(TN+FP) = 10/30 = 33.33%", "sys": "general"}, {"topic": "Forensic medicine", "q": "An autopsy of a roadside traffic accident victim: multiple high-impact injuries, blunt trauma to the lower extremities, extensive bruising and lacerations. Which sign is most suggestive of a pedestrian injury?", "choices": ["Liver rupture", "Bumper injury with tibial fracture", "Lung laceration", "Cerebral contusion", "Frontal bone fracture"], "ans": 1, "exp": "bumper injury (รอยกันชนรถ) ที่ทำให้กระดูก tibia หัก เป็นลักษณะจำเพาะของคนเดินเท้าที่ถูกรถชน (pedestrian)", "sys": "general"}, {"topic": "Forensic medicine", "q": "A 17-year-old driving at 120 km/h crashed into a fixed object and died at the scene. Autopsy reveals blunt injuries to the chest and abdomen. Most likely cause of sudden death?", "choices": ["Rib fractures", "Lung contusions", "Aortic laceration", "Spleen laceration", "Liver laceration"], "ans": 2, "exp": "การชนความเร็วสูง (deceleration injury) -> traumatic aortic laceration/transection ทำให้เสียชีวิตทันที", "sys": "general"}, {"topic": "Forensic medicine", "q": "A police officer sustained a lip laceration and multiple rib fractures. Regarding the typical healing course, which statement is accurate?", "choices": ["The injuries and laceration will require up to 30 days for healing, assuming no complications.", "The injuries and laceration will require approximately 30 days for medical treatment, assuming no complications.", "Healing is expected within 20 days.", "The injuries will require more than 20 days for healing.", "The lip laceration will heal in 7 days, and rib fractures do not require specific treatment."], "ans": 3, "exp": "กระดูกซี่โครงหักหลายซี่ใช้เวลารักษา >20 วัน (ประมาณ 4-6 สัปดาห์) -> เข้าเกณฑ์ 'อันตรายสาหัส' ตามกฎหมาย (รักษา/ทุพพลภาพเกิน 20 วัน)", "sys": "general"}, {"topic": "Forensic medicine", "q": "A deceased body: pupils 1 mm (miosis) and obvious massive respiratory secretion. Most likely cause of death?", "choices": ["Carbamate poisoning", "Opioid overdose", "Heroin overdose", "Cyanide poisoning", "Organophosphate poisoning"], "ans": 4, "exp": "รูม่านตาหด (miosis) + สารคัดหลั่งทางเดินหายใจมาก (bronchorrhea) = cholinergic crisis จาก organophosphate poisoning (opioid หด rูม่านตาแต่ไม่มีสารคัดหลั่งมาก)", "sys": "general"}, {"topic": "Forensic medicine", "q": "A deceased individual with constricted pupils and massive airway secretion. Most appropriate diagnostic laboratory test to determine the cause of death?", "choices": ["Cholinesterase level", "Opioid level", "Barbiturates level", "Methamphetamine level", "Arterial blood gas analysis"], "ans": 0, "exp": "miosis + สารคัดหลั่งมาก = organophosphate poisoning -> ตรวจ cholinesterase level (จะต่ำ) ยืนยัน", "sys": "general"}, {"topic": "Forensic medicine", "q": "A 25-year-old found unconscious in a pub after a fire. Normal oxygen saturation, normal ABG, and cherry-red skin coloration. Most likely diagnosis?", "choices": ["Cyanide poisoning", "Carbon monoxide poisoning", "Methanol poisoning", "Hydrogen sulfide poisoning", "Nitrogen dioxide poisoning"], "ans": 1, "exp": "ผิวสีแดงเชอร์รี่ (cherry-red) + SpO2/ABG ปกติลวง (pulse oximeter อ่าน carboxyhemoglobin ผิด) หลังไฟไหม้ = carbon monoxide poisoning", "sys": "general"}, {"topic": "Forensic medicine", "q": "A man found dead in a hotel room: a knife with old blood near the bed, a plastic bag over his head secured with duct tape, multiple transverse cut wounds on the left forearm, and an empty alprazolam bottle. Most likely cause of death?", "choices": ["Sexual asphyxia", "Alprazolam toxicity", "Suicide", "Torture before death", "Homicide with assistive suicide"], "ans": 2, "exp": "หลายวิธีการทำร้ายตนเอง (ถุงพลาสติกคลุมหัว + แผลกรีดข้อมือแนวขวางแบบ hesitation + ยา alprazolam) = suicide (การฆ่าตัวตาย)", "sys": "general"}, {"topic": "Forensic medicine", "q": "A man had a car accident at 6 PM, reported consuming alcohol 2 hours before. Alcohol level at 11 PM was 45 mg%. Estimated blood alcohol level at the time of the accident?", "choices": ["30 mg%", "45 mg%", "60 mg%", "90 mg%", "75 mg%"], "ans": 3, "exp": "back-extrapolation: อัตราการกำจัดแอลกอฮอล์ ~15 mg%/ชม. จาก 6 โมงเย็นถึง 5 ทุ่ม = 5 ชม. -> ประมาณ 45 + (15 x 5) ~ 120 mg% (ในตัวเลือกนี้ค่าใกล้เคียงสูงสุดคือ 90 mg%) *ดูข้อ 361 ที่มีตัวเลือกครบ = 120 mg%*", "sys": "general"}, {"topic": "Forensic medicine", "q": "A body found lying on her back at 10 PM: rigidity of the muscles of the jaws, wrists, and elbows, and unfixed livor mortis at the back. Most likely time of death?", "choices": ["12:00-14:00", "16:00-18:00", "18:00-20:00", "20:00-22:00", "14:00-16:00"], "ans": 4, "exp": "rigor mortis ลามถึงแขนส่วนบน (ขากรรไกร ข้อมือ ศอก) ~6-8 ชม. + livor mortis ยังไม่ fixed (<8 ชม.) -> เสียชีวิตราว 6-8 ชม.ก่อน 22:00 = ประมาณ 14:00-16:00", "sys": "general"}, {"topic": "Forensic medicine", "q": "A 30-year-old man found unconscious beside a damaged motorcycle, diagnosed with subdural hemorrhage and brain edema. After 5 months hospitalized, develops pneumonia, then septicemia, and dies. Per Thai death certificate and ICD-10, most appropriate cause of death?", "choices": ["MOTORCYCLE ACCIDENT", "PNEUMONIA", "SEPTICEMIA", "SEVERE BRAIN INJURY", "UNDETERMINED, PENDING AUTOPSY"], "ans": 0, "exp": "underlying cause of death ในการบาดเจ็บ = สาเหตุภายนอกที่เริ่มลำดับเหตุการณ์ = motorcycle accident (pneumonia/septicemia เป็นสาเหตุที่ตามมา/immediate cause)", "sys": "general"}, {"topic": "Forensic medicine", "q": "A car accident at 6:00 PM. The driver consumed alcohol 2 hours prior. BAC tested at 11:00 PM was 45 mg%. Estimated BAC at the time of the accident?", "choices": ["45 mg%", "120 mg%", "75 mg%", "200 mg%", "300 mg%"], "ans": 1, "exp": "back-extrapolation: 45 + (15 mg%/ชม. x 5 ชม. จาก 18:00 ถึง 23:00) = 45 + 75 = 120 mg%", "sys": "general"}, {"topic": "Forensic medicine", "q": "A 30-year-old male presents 3 weeks after a sexual assault for forensic evidence collection. What investigation provides evidence of the sexual assault?", "choices": ["Spermatozoa in anal swab", "Epithelial cells of the assailant in anal swab", "Gonococcal culture (GC) in anal swab", "Acid phosphatase levels in anal swab", "Prostate-specific antigen (PSA) in anal swab"], "ans": 2, "exp": "ผ่านมา 3 สัปดาห์ อสุจิ/acid phosphatase/PSA สลายไปหมดแล้ว (ตรวจได้ไม่กี่วัน) -> หลักฐานที่ยังตรวจได้คือการติดเชื้อทางเพศ เช่น gonococcal culture", "sys": "general"}, {"topic": "Forensic medicine", "q": "A 12-year-old boy presents with anal tenderness starting 3 weeks after a suspected sexual assault. No signs of acute trauma or infection. Most appropriate diagnostic test for evidence of sexual assault?", "choices": ["Swab for spermatozoa", "Swab for epithelial cells", "Anus washing fluid for acid phosphatase enzyme", "Swab for Neisseria gonorrhoeae", "Anus washing fluid for prostate-specific antigen (PSA) and semenogelin"], "ans": 3, "exp": "ผ่านมา 3 สัปดาห์ อสุจิ/enzyme/PSA ตรวจไม่พบแล้ว -> ตรวจหาเชื้อ Neisseria gonorrhoeae (STI) เป็นหลักฐานที่ยังคงอยู่", "sys": "general"}, {"topic": "Medical ethics", "q": "A 60-year-old man with end-stage liver cancer in cardiac arrest, resuscitated, BP 70/40, in VF. His brother requests full resuscitation, but his daughter presents the patient's living will indicating he wished to die peacefully without resuscitation. Most appropriate management?", "choices": ["Ask his brother to sign a consent form for continuing resuscitation", "Continue resuscitation until the patient's brother and daughter reach an agreement", "Continue resuscitation while consulting the hospital's legal officer", "Continue resuscitation while consulting the palliative care team", "Stop resuscitation as per the patient's wishes"], "ans": 4, "exp": "ผู้ป่วยมี living will (advance directive) ระบุไม่ต้องการการกู้ชีพ -> เคารพเจตนาของผู้ป่วย หยุดการกู้ชีพ (ความประสงค์ของผู้ป่วยมีน้ำหนักเหนือญาติ)", "sys": "general"}, {"topic": "Medical ethics", "q": "A 43-year-old woman in the OPD in an angry mood, complaining about a long wait and that the nurse let an elderly patient be seen first. According to the principle of empathy, how should you respond?", "choices": ["I'm sorry for the long wait, but I understand your anger.", "The nurse should be blamed.", "I will tell the nurse not to do this again.", "Normally, the nurse lets patients enter the room according to the queue.", "You can file a complaint with the hospital's risk management."], "ans": 0, "exp": "empathy = รับรู้และเข้าใจความรู้สึกของผู้ป่วย -> 'ขอโทษที่ต้องรอนาน และเข้าใจความรู้สึกโกรธของคุณ'", "sys": "general"}, {"topic": "Medical ethics", "q": "A 22-year-old with ruptured appendicitis scheduled for emergency appendectomy refuses an HIV test preoperatively. Most appropriate management?", "choices": ["Perform the HIV test despite the patient's refusal", "Perform the HIV test with informed consent", "Perform the HIV test anonymously", "Perform the HIV test along with other laboratory studies", "Do not perform the HIV test and postpone the operation until consent is granted"], "ans": 1, "exp": "การตรวจ HIV ต้องได้รับความยินยอม (informed consent) เสมอ -> ให้คำปรึกษาและตรวจเมื่อยินยอมเท่านั้น หากปฏิเสธก็เคารพสิทธิ์ และผ่าตัดฉุกเฉินต่อได้โดยใช้ universal precautions (ไม่เลื่อนผ่าตัด/ไม่แอบตรวจ)", "sys": "general"}, {"topic": "Medical ethics", "q": "An 80-year-old man with metastatic prostate cancer. His daughter requests you not disclose the diagnosis, fearing he cannot handle it and it could hasten decline (he was very distressed when his wife died of cancer). Most appropriate management?", "choices": ["Agree and promise not to tell the patient", "Tell the patient directly despite the daughter's request", "Negotiate with the daughter, suggesting that we can tell the patient because he might already know", "Consult a palliative care specialist for further guidance", "Inform his daughter to notify the doctor when the patient is ready to be informed"], "ans": 2, "exp": "เคารพสิทธิ์การรับรู้ของผู้ป่วย (autonomy) พร้อมดูแลความกังวลของญาติ -> เจรจากับลูกสาว อธิบายว่าควรบอกผู้ป่วย (ผู้ป่วยอาจรับรู้อยู่แล้ว) และประเมินความต้องการรับรู้ของผู้ป่วยเอง", "sys": "general"}, {"topic": "Medical ethics", "q": "A 55-year-old woman with an undiagnosed skin lesion. You wish to document it with photographs for a case presentation. Most appropriate way to obtain informed consent?", "choices": ["Explain the necessity of sharing this interesting case and request permission to take photographs", "Verbally inform the patient about taking photographs", "Take the photographs without requesting any consent", "Obtain written consent from the patient, stating that her identity and the hospital's name will be kept confidential", "Obtain verbal consent but also provide written documentation of the consent process"], "ans": 3, "exp": "การถ่ายภาพผู้ป่วยเพื่อนำเสนอ/เผยแพร่ -> ต้องขอความยินยอมเป็นลายลักษณ์อักษร (written consent) ระบุการปกปิดตัวตนผู้ป่วยและชื่อโรงพยาบาล", "sys": "general"}, {"topic": "Medical ethics", "q": "A 10-year-old Thai boy with swelling and mucopurulent discharge at a dog bite site (2 days ago). Absent from school since injury; teacher requests a medical certificate for absence. Most appropriate management?", "choices": ["Consult forensic medicine", "Notify the hospital director", "Issue a medical certificate from the last 2 days", "Inform the mother that the doctor is not allowed to issue a retrospective medical certificate", "Issue a medical certificate that the boy was bitten by a dog and has a wound infection"], "ans": 4, "exp": "ออกใบรับรองแพทย์ตามสิ่งที่ตรวจพบจริงในวันนี้ (ถูกสุนัขกัด + แผลติดเชื้อ) ไม่ออกใบรับรองย้อนหลังลงวันที่ก่อนตรวจ", "sys": "general"}, {"topic": "Medical ethics", "q": "A 6-year-old with a bite wound on the right arm 2 days ago, now with purulent discharge. Absent from school since; teacher requests a medical certificate. Most appropriate course of action?", "choices": ["Provide a medical certificate stating that the child was bitten by a dog 2 days ago and currently has an infected wound", "Consult forensic specialist", "Notify hospital administration", "Issue a backdated medical certificate for 2 days", "Inform the mother that backdated medical certificates cannot be issued"], "ans": 0, "exp": "ออกใบรับรองแพทย์ตามข้อเท็จจริงที่ตรวจพบ (ประวัติถูกสุนัขกัด 2 วันก่อน + ปัจจุบันแผลติดเชื้อ) โดยลงวันที่ตรวจจริง ไม่ออกย้อนหลัง", "sys": "general"}]}, {"id": "nl2-2025-apr", "title": "NL 2 ปี 2025 เมษายน (VICHAKARN_SMST)", "subject": "past", "questions": [{"topic": "Internal medicine", "q": "A 30-year-old male with headache and convulsions. Normal vitals, no motor/sensory deficits. Brain CT reveals multiple calcified cystic lesions. Most likely causative pathogen?", "choices": ["Taenia solium", "Toxoplasma gondii", "Gnathostoma spinigerum", "Angiostrongylus cantonensis", "Mycobacterium tuberculosis"], "ans": 0, "exp": "หลาย cystic lesion ที่มี calcification ในสมอง + ชัก = neurocysticercosis จากตัวอ่อนพยาธิตืดหมู Taenia solium", "sys": "I"}, {"topic": "Internal medicine", "q": "An elderly male with classic Parkinson's disease (bradykinesia, resting tremor, cogwheel rigidity, postural instability). Which best describes the pathogenesis?", "choices": ["Accumulation of beta-amyloid plaques and neurofibrillary tangles in the cerebral cortex", "Degeneration of dopaminergic neurons in the substantia nigra pars compacta", "Autoantibodies against acetylcholine receptors at the neuromuscular junction", "Demyelination of neurons in the central nervous system", "Degeneration of GABAergic neurons in the striatum"], "ans": 1, "exp": "Parkinson's disease = การเสื่อมของเซลล์ประสาท dopaminergic ใน substantia nigra pars compacta", "sys": "VI"}, {"topic": "Internal medicine", "q": "A 35-year-old woman with SLE on high-dose prednisone presents with 2 weeks of watery diarrhea, epigastric pain, and cough. Urticarial rashes along buttocks and thighs. Stool shows the parasite. Most likely responsible parasite?", "choices": ["Ascaris lumbricoides", "Giardia lamblia", "Strongyloides stercoralis", "Hookworm (Ancylostoma duodenale)", "Toxoplasma gondii"], "ans": 2, "exp": "ผู้ได้ steroid ขนาดสูง + ผื่นลมพิษเลื้อย (larva currens) + อาการทางเดินอาหาร/ปอด = Strongyloides stercoralis (hyperinfection). *อ้างอิงภาพ*", "img": "https://cdn.jsdelivr.net/gh/MercenzK/Web-quiz-images@main/NL2-2025-Apr-Q3.png", "sys": "I"}, {"topic": "Internal medicine", "q": "A 58-year-old man with HT and dyslipidemia has progressive bilateral leg pain for 1 month; deep aching in thighs/calves, unrelated to exertion. On simvastatin 40 mg daily. No weakness/rash. CPK 300 (mildly elevated), normal electrolytes/TSH/renal. Most likely cause?", "choices": ["Hypothyroidism", "Rhabdomyolysis", "Polymyositis", "Drug-induced myopathy", "Peripheral arterial disease"], "ans": 3, "exp": "ปวดกล้ามเนื้อ + CPK สูงเล็กน้อยในผู้ใช้ statin โดยไม่มีอ่อนแรง = statin-induced myopathy (drug-induced)", "sys": "IV"}, {"topic": "Internal medicine", "q": "A 68-year-old man with small-cell lung cancer after a generalized tonic-clonic seizure. Euvolemic. Na 112, serum osmolality 240, urine osmolality 520, urine SG 1.028. Normal thyroid/adrenal/renal, no diuretic/excess fluids. Most likely diagnosis?", "choices": ["Psychogenic polydipsia", "Cerebral salt wasting", "Diuretic-induced hyponatremia", "Addisonian crisis", "Syndrome of Inappropriate ADH Secretion (SIADH)"], "ans": 4, "exp": "hyponatremia + euvolemic + serum osm ต่ำ + urine osm สูง (เข้มข้น) ใน SCLC = SIADH (สร้าง ADH นอกตำแหน่ง)", "sys": "II"}, {"topic": "Internal medicine", "q": "A 28-year-old healthy mechanic with a firm, hyperkeratotic, cauliflower-like papule on the dorsal right thumb for 4 months, tender with pressure, no infection. Most appropriate immediate procedural intervention?", "choices": ["Electrocauterization", "20% urea cream", "0.1% TA cream", "Shaving", "Incisional biopsy"], "ans": 0, "exp": "หูดที่ผิวหนัง (verruca vulgaris) -> การรักษาโดยหัตถการคือทำลายรอยโรค เช่น electrocauterization (หรือจี้เย็น/cryotherapy). *อ้างอิงภาพ*", "img": "https://cdn.jsdelivr.net/gh/MercenzK/Web-quiz-images@main/NL2-2025-Apr-Q6.png", "sys": "XII"}, {"topic": "Internal medicine", "q": "A 70-year-old woman with progressive forgetfulness, daytime inattention, and nocturnal confusion over 3 months, with deficits in attention and short-term recall, no focal signs, worsening agitation in evenings. Most likely diagnosis?", "choices": ["Alzheimer disease", "Delirium", "Age-related forgetfulness", "Vascular dementia", "Lewy body dementia"], "ans": 1, "exp": "ความบกพร่องของ 'สมาธิ (attention)' ที่เด่น + อาการแปรปรวนตามช่วงเวลา (สับสนกลางคืน/agitation ตอนเย็น) = delirium (inattention + fluctuating course เป็นลักษณะเด่น ควรหาสาเหตุทางกาย)", "sys": "V"}, {"topic": "Internal medicine", "q": "A 40-year-old man with fever, cough, left pleuritic chest pain. CXR moderate pleural effusion. Pleural fluid: pH 7.4, WBC 2500 (90% neutrophils), ADA 45, glucose 60% of serum. Most appropriate management?", "choices": ["Pleural biopsy", "CT chest", "Empirical antibiotics", "Insertion of chest drain (ICD)", "Anti-tuberculosis therapy"], "ans": 2, "exp": "uncomplicated parapneumonic effusion (pH >7.2, glucose ปกติ, neutrophil เด่น) -> รักษาด้วยยาปฏิชีวนะอย่างเดียว ยังไม่ต้องใส่ ICD", "sys": "I"}, {"topic": "Internal medicine", "q": "A 40-year-old man with acute confusion, agitation, fever 38.9, irregularly irregular pulse 130, diffuse goiter, moist skin. FT4 8.0 (high), TSH <0.001. Most appropriate initial management?", "choices": ["Propylthiouracil (PTU)", "Haloperidol", "Methimazole", "Propranolol", "Lugol solution"], "ans": 3, "exp": "thyroid storm -> ควบคุมอาการ adrenergic/หัวใจเต้นเร็ว (AF) ที่เป็นอันตรายเฉียบพลันด้วย propranolol เป็นอันดับแรก ตามด้วย PTU -> Lugol (หลัง PTU 1 ชม.) + corticosteroid", "sys": "IV"}, {"topic": "Internal medicine", "q": "A 20-year-old woman with rheumatic mitral valve disease has low-grade fever for 1 month. Conjunctival petechiae, splinter hemorrhages, pansystolic murmur with apical diastolic rumble. Most likely diagnosis?", "choices": ["Tuberculous pericarditis", "Meningococcemia", "Rheumatic carditis", "Systemic lupus erythematosus", "Infective endocarditis"], "ans": 4, "exp": "ลิ้นหัวใจผิดปกติเดิม + ไข้เรื้อรัง + peripheral stigmata (conjunctival petechiae, splinter hemorrhage) = infective endocarditis", "sys": "VII"}, {"topic": "Internal medicine", "q": "A 65-year-old man with 1 month of vague chest discomfort has a 5x5 cm pulsatile, non-tender abdominal mass. History of hypertension and smoking. Most appropriate initial investigation?", "choices": ["Ultrasound abdomen", "MRI abdomen", "CT abdomen", "Abdominal X-ray", "Aortography"], "ans": 0, "exp": "ก้อนเต้นตุบ ๆ ในช่องท้อง (สงสัย abdominal aortic aneurysm) -> ตรวจ ultrasound abdomen เป็นอันดับแรก (ปลอดภัย รวดเร็ว)", "sys": "IX"}, {"topic": "Internal medicine", "q": "An immunocompromised 45-year-old with confusion, nystagmus, and diplopia. MRI shows periventricular white matter lesions. CSF PCR positive for a neurotropic virus causing retinal necrosis. Most likely diagnosis?", "choices": ["Herpes meningitis", "CMV encephalitis", "West Nile virus encephalitis", "Progressive multifocal leukoencephalopathy", "Varicella-zoster vasculopathy"], "ans": 1, "exp": "ไวรัสที่ทำให้เกิด retinal necrosis + encephalitis + periventricular lesion ในผู้ภูมิคุ้มกันต่ำ = cytomegalovirus (CMV) encephalitis/retinitis", "sys": "I"}, {"topic": "Internal medicine", "q": "A 26-year-old HIV-positive man (CD4 80) with headache, nausea, blurred vision, neck stiffness. CT shows no mass lesion. Fundoscopy reveals papilledema. Most likely diagnosis?", "choices": ["Toxoplasmosis", "Bacterial meningitis", "Cryptococcal meningitis", "HSV encephalitis", "CMV encephalitis"], "ans": 2, "exp": "HIV CD4 ต่ำ + เยื่อหุ้มสมองอักเสบ + ความดันในกะโหลกสูง (papilledema) ไม่มีก้อน = cryptococcal meningitis", "sys": "II"}, {"topic": "Internal medicine", "q": "A 19-year-old male with 3 days of fever, fatigue, dark urine, no medications. Pallor, jaundice, no organomegaly. Peripheral smear shows 'blister cells' (hemoglobin puddled at edges). Most likely diagnosis?", "choices": ["Malaria", "Hb H disease", "Immune thrombocytopenic anemia", "G6PD deficiency", "Paroxysmal nocturnal hemoglobinuria"], "ans": 3, "exp": "เม็ดเลือดแดงแตกเฉียบพลัน + blister cells/bite cells = G6PD deficiency (oxidative hemolysis)", "sys": "I"}, {"topic": "Internal medicine", "q": "A 40-year-old woman with sudden loss of consciousness. BP 200/110, right ventricular heave and grade 3/6 apical diastolic rumble, bilateral lateral gaze palsy and quadriparesis (GCS E4V1M1). Most urgent intervention?", "choices": ["Aspirin", "IV recombinant tissue plasminogen activator (rTPA)", "IV nicardipine", "Low molecular weight heparin", "Endotracheal intubation (ETT)"], "ans": 4, "exp": "ผู้ป่วยซึมมาก (M1) + quadriparesis + gaze palsy (สงสัยเลือดออก brainstem/pons) -> สิ่งเร่งด่วนที่สุดคือ secure airway ด้วย ETT ก่อนจัดการอื่น", "sys": "VI"}, {"topic": "Internal medicine", "q": "A 29-year-old woman with recurrent headaches at the forehead and temples several afternoons weekly, resolving with sleep. No photophobia, nausea, or aura. Normal neuro exam. Most likely diagnosis?", "choices": ["Tension-type headache", "Migraine without aura", "Cluster headache", "Sinusitis-related headache", "Medication-overuse headache"], "ans": 0, "exp": "ปวดตื้อ ๆ บริเวณหน้าผาก/ขมับ ไม่มี aura/คลื่นไส้/กลัวแสง = tension-type headache", "sys": "VI"}, {"topic": "Internal medicine", "q": "A 50-year-old man with poorly controlled HT and sudden, severe 'tearing' chest pain radiating to the back. BP 200/130, pulse 120. ECG shows no ST changes. Most likely diagnosis?", "choices": ["Pulmonary embolism", "Acute aortic dissection", "Pneumothorax", "Acute myocardial infarction", "Acute pancreatitis"], "ans": 1, "exp": "เจ็บอกรุนแรงแบบฉีกขาด (tearing) ร้าวไปหลัง + ความดันสูงมาก + ECG ไม่มี ST changes = acute aortic dissection", "sys": "IX"}, {"topic": "Internal medicine", "q": "A 25-year-old man with acute left facial weakness involving both upper (cannot close eye) and lower (drooping mouth) facial muscles. Normal vitals, unremarkable ear exam, no rash or hearing loss. Appropriate treatment?", "choices": ["Reassurance", "Acyclovir", "Prednisolone", "Carbamazepine", "Gabapentin"], "ans": 2, "exp": "อ่อนแรงใบหน้าครึ่งซีกครบทั้งใบ (LMN) หูปกติ = Bell's palsy -> ให้ prednisolone ภายใน 72 ชม.", "sys": "VIII"}, {"topic": "Internal medicine", "q": "A 50-year-old man with hyperlipidemia, 3 days of dyspnea and intermittent chest discomfort. BP 120/70, pulse 150, bilateral crepitations, S3 gallop. Troponin T 200 ng/L. ECG shown. Most likely diagnosis?", "choices": ["Acute STEMI", "Acute myocarditis", "Acute pericarditis", "Acute NSTEMI", "Pulmonary embolism"], "ans": 3, "exp": "troponin สูง + หัวใจล้มเหลว (crepitation, S3) โดย ECG ไม่มี ST elevation ชัด = NSTEMI. *อ้างอิงภาพ ECG*", "img": "https://cdn.jsdelivr.net/gh/MercenzK/Web-quiz-images@main/NL2-2025-Apr-Q19.png", "sys": "IX"}, {"topic": "Internal medicine", "q": "A 30-year-old female with fatigue for 2 weeks. Pale conjunctiva, mild icteric sclera. Hb 8, WBC 5,000, platelet 200,000. PBS shown. What is the investigation for diagnosis?", "choices": ["Hb typing", "Antinuclear antibody", "Osmotic fragility test", "Protein electrophoresis", "Antiglobulin test"], "ans": 4, "exp": "ซีด + ดีซ่านเล็กน้อย (เม็ดเลือดแดงแตก) โดยเม็ดเลือดอื่นปกติ -> สงสัย autoimmune hemolytic anemia -> ตรวจ direct antiglobulin (Coombs) test. *อ้างอิงภาพ PBS*", "img": "https://cdn.jsdelivr.net/gh/MercenzK/Web-quiz-images@main/NL2-2025-Apr-Q20.png", "sys": "III"}, {"topic": "Internal medicine", "q": "A 28-year-old male with 1 week of lower back pain and bilateral foot numbness. Motor grade 5, decreased sensation in L5-S1 dermatomes, loose anal sphincter tone, absent bulbocavernosus reflex. No trauma or fever. Most likely diagnosis?", "choices": ["Disc herniation", "Spinal stenosis", "Spinal cord compression", "Transverse myelitis", "Guillain-Barre syndrome (GBS)"], "ans": 0, "exp": "cauda equina syndrome (ชาแบบ saddle, หูรูดหลวม, bulbocavernosus หาย) ที่ระดับ L5-S1 -> สาเหตุพบบ่อยคือ central disc herniation กด cauda equina", "sys": "VI"}, {"topic": "Internal medicine", "q": "A 32-year-old female collapses with loss of consciousness during an argument and recovers after resting, with similar prior episodes. Stable vitals, normal cardiac auscultation. Most appropriate initial investigation?", "choices": ["Holter monitor", "Tilt table test", "Echocardiogram", "Electroencephalogram (EEG)", "Serum electrolytes"], "ans": 1, "exp": "vasovagal syncope (เป็นลมจากอารมณ์ ฟื้นเร็ว เป็นซ้ำ) -> ยืนยันด้วย tilt table test", "sys": "IV"}, {"topic": "Internal medicine", "q": "A 25-year-old male with recurrent proximal muscle weakness (grade II) preventing rising from bed. BP 150/90, HR 100, fine hand tremors, hyperreflexia. Which electrolyte abnormality is most likely?", "choices": ["Hypocalcemia", "Hypernatremia", "Hypokalemia", "Hypercalcemia", "Hyperphosphatemia"], "ans": 2, "exp": "thyrotoxic periodic paralysis (อ่อนแรงเป็นพัก ๆ + อาการ thyrotoxic) -> hypokalemia", "sys": "IV"}, {"topic": "Internal medicine", "q": "A 55-year-old man with chronic alcohol use, severe epigastric pain radiating to back, nausea, vomiting 24h. Epigastric tenderness/guarding, absent bowel sounds. Amylase 1,200, lipase 900, CT shows pancreatic edema. Most appropriate investigation to identify the etiology?", "choices": ["Stool exam for parasites", "Serum triglycerides", "MRCP", "Abdominal ultrasound", "ERCP"], "ans": 3, "exp": "acute pancreatitis -> หาสาเหตุด้วย abdominal ultrasound เป็นอันดับแรก (มองหานิ่วในถุงน้ำดี ซึ่งเป็นสาเหตุที่พบบ่อย)", "sys": "I"}, {"topic": "Internal medicine", "q": "A 40-year-old male with a 4 cm tense, non-tender nodule with a central punctum on the upper back for over a month, firm and mobile, no erythema/discharge. Most likely diagnosis?", "choices": ["Lipoma", "Neurofibroma", "Sebaceous cyst", "Dermatofibroma", "Epidermal inclusion cyst"], "ans": 4, "exp": "ก้อนใต้ผิวหนังมี central punctum (รูเปิด) = epidermal inclusion cyst", "sys": "XII"}, {"topic": "Internal medicine", "q": "A 20-year-old male recovering from a motorcycle accident with LOC complains of right-sided hearing loss. Right facial palsy, bloody otorrhea, TM perforation. Weber lateralizes to the left, Rinne positive bilaterally. Most likely etiology?", "choices": ["Temporal bone fracture", "Zygomatic fracture", "Ossicle dislocation", "Perforation of tympanic membrane", "Hemotympanum"], "ans": 0, "exp": "facial palsy + bloody otorrhea + sensorineural hearing loss (Weber ไปข้างปกติ) หลังบาดเจ็บศีรษะ = temporal bone fracture", "sys": "V"}, {"topic": "Internal medicine", "q": "A 40-year-old with well-controlled focal seizures on phenytoin, found unconscious. BP 180/100, pulse 110, pinpoint pupils, absent oculocephalic reflex, frequent extensor posturing, normal temperature. Most likely diagnosis?", "choices": ["Narcotic overdose", "Pontine hemorrhage", "Phenytoin toxicity", "Epidural hematoma", "Thalamic infarction"], "ans": 1, "exp": "หมดสติ + รูม่านตาเล็กมาก (pinpoint) + posturing + absent oculocephalic + ความดันสูง = pontine hemorrhage", "sys": "VI"}, {"topic": "Internal medicine", "q": "A 35-year-old female with 2 weeks of fatigue and intermittent dark urine, moderate pallor and mild jaundice. MCV 98, reticulocyte 3%, negative Coombs test, no schistocytes. Most likely diagnosis?", "choices": ["Autoimmune hemolytic anemia (AIHA)", "G6PD deficiency", "Paroxysmal nocturnal hemoglobinuria (PNH)", "Microangiopathic hemolytic anemia", "Hereditary spherocytosis"], "ans": 2, "exp": "เม็ดเลือดแดงแตกในหลอดเลือด (ปัสสาวะเข้ม) + Coombs ลบ + ไม่มี schistocyte = paroxysmal nocturnal hemoglobinuria (PNH)", "sys": "III"}, {"topic": "Internal medicine", "q": "A 60-year-old man found unconscious. BP 90/50, pulse 130-150. ECG shows atrial fibrillation with rapid ventricular response, no prior cardiac history. Most appropriate management?", "choices": ["Adenosine", "Amiodarone", "Digoxin", "Synchronized cardioversion", "Defibrillation"], "ans": 3, "exp": "AF with RVR ที่ไม่คงที่ (hypotension/หมดสติ = unstable) -> synchronized cardioversion ทันที", "sys": "IX"}, {"topic": "Internal medicine", "q": "A 28-year-old female with recurrent left-sided headaches (retro-orbital, frontal, temporal) with photophobia and nausea, lasting 6-24 hours, normal neuro exam. Most appropriate prophylactic medication?", "choices": ["Sumatriptan", "Ibuprofen", "Acetaminophen", "Topiramate", "Propranolol"], "ans": 4, "exp": "migraine -> ยาป้องกัน (prophylaxis) first-line คือ propranolol (หรือ topiramate/amitriptyline). sumatriptan/NSAID เป็นยาแก้ปวดเฉียบพลัน", "sys": "VI"}, {"topic": "Internal medicine", "q": "A 20-year-old female on isotretinoin for acne with 3 days of retrosternal chest pain, heartburn, and dysphagia. No oral thrush/ulcers/pharyngeal inflammation. Most appropriate investigation?", "choices": ["Esophagogastroduodenoscopy (EGD)", "12-lead ECG", "24-hour pH monitoring", "Esophageal manometry", "Chest X-ray (PA/lateral)"], "ans": 0, "exp": "pill-induced esophagitis (isotretinoin) -> ตรวจ EGD ประเมินแผลหลอดอาหาร", "sys": "IX"}, {"topic": "Internal medicine", "q": "A 30-year-old healthy woman with acute dyspnea 2 days after a 7-day viral prodrome. BP 80/50, HR 130, RR 32, SpO2 80%, cold extremities, elevated JVP, S3 gallop, bibasilar crepitations. hs-troponin 440, ECG sinus tachycardia. Most likely diagnosis?", "choices": ["Acute myocardial infarction", "Acute myocarditis", "Hypovolemic shock", "Pneumonia with septic shock", "Acute massive pulmonary embolism"], "ans": 1, "exp": "หัวใจล้มเหลว/cardiogenic shock หลังไข้ไวรัส + troponin สูง + ECG sinus tach ในคนหนุ่มสาว = acute myocarditis", "sys": "I"}, {"topic": "Internal medicine", "q": "A 55-year-old man with T2DM on metformin and glipizide 5 years. BP 150/90, HbA1c 7%, urinalysis 1+ protein without glycosuria, no chest pain/edema, normal renal function. Which medication should be added?", "choices": ["Atenolol", "Hydrochlorothiazide (HCTZ)", "Enalapril", "Doxazosin", "Amlodipine"], "ans": 2, "exp": "เบาหวาน + ความดันสูง + โปรตีนรั่ว (albuminuria) -> เพิ่ม ACE inhibitor (enalapril) ช่วยชะลอไตเสื่อมและลดโปรตีนรั่ว", "sys": "IX"}, {"topic": "Internal medicine", "q": "A 20-year-old woman on isotretinoin with 3 days of retrosternal pain on swallowing and heartburn. Stable vitals, no oral lesions. Most appropriate investigation?", "choices": ["CXR upright", "24hr pH monitoring", "Esophageal manometry", "EGD", "Barium esophagogram"], "ans": 3, "exp": "pill-induced esophagitis จาก isotretinoin -> ตรวจ EGD", "sys": "XI"}, {"topic": "Internal medicine", "q": "A farmer with 5 days of fever, headache, bilateral conjunctival suffusion, jaundice, and severe myalgia. Hct 24%, platelets 100,000, WBC 15,000 (neutrophil predominance). No rash or eschar. Most likely diagnosis?", "choices": ["Hepatitis", "Melioidosis", "Scrub typhus", "Murine typhus", "Leptospirosis"], "ans": 4, "exp": "conjunctival suffusion + ปวดกล้ามเนื้อมาก + ดีซ่าน + ไต/เกล็ดเลือดผิดปกติ ในเกษตรกร = leptospirosis (scrub typhus จะมี eschar)", "sys": "I"}, {"topic": "Internal medicine", "q": "A 60-year-old man with T2DM, autoimmune hepatitis (on prednisolone and azathioprine), and COPD (on theophylline and budesonide/formoterol inhaler) presents with oral creamy whitish patches. Which medication is the most likely causative agent?", "choices": ["Budesonide/formoterol inhaler", "Metformin", "Low-dose prednisolone", "Azathioprine", "Theophylline"], "ans": 0, "exp": "oral candidiasis (thrush) -> สาเหตุคือ inhaled corticosteroid (budesonide/formoterol) ที่ไม่บ้วนปากหลังพ่น. *อ้างอิงภาพ*", "img": "https://cdn.jsdelivr.net/gh/MercenzK/Web-quiz-images@main/NL2-2025-Apr-Q36.png", "sys": "X"}, {"topic": "Internal medicine", "q": "A 24-year-old woman with 4 weeks of postprandial fullness and 1 kg weight loss despite intermittent omeprazole/simethicone. Mild conjunctival pallor, LUQ tenderness, mild abdominal distension. No fever/vomiting. Most appropriate management?", "choices": ["Antibiotics for H. pylori eradication", "Esophagogastroduodenoscopy (EGD)", "Sucralfate", "Increase omeprazole dose", "Abdominal ultrasound"], "ans": 1, "exp": "dyspepsia ที่มี alarm features (น้ำหนักลด + ซีด + กดเจ็บ/ก้อน LUQ) -> ส่อง EGD", "sys": "general"}, {"topic": "Internal medicine", "q": "A 70-year-old woman s/p partial gastrectomy for gastric cancer 5 years ago with progressive fatigue. Pallor, mild scleral icterus. Hb 9, MCV 115 (macrocytic), WBC 3,500, platelets 100,000. Most useful initial investigation?", "choices": ["Serum ferritin", "Folate level", "Vitamin B12 level", "Liver function tests", "Reticulocyte count"], "ans": 2, "exp": "หลังตัดกระเพาะบางส่วน -> ขาด intrinsic factor -> vitamin B12 deficiency (macrocytic anemia + pancytopenia เล็กน้อย) -> ตรวจ vitamin B12 level", "sys": "II"}, {"topic": "Internal medicine", "q": "A 70-year-old with acute RUQ pain and high fever (39.5). Moderate RUQ tenderness without guarding. TB 6, DB 4, AST 100, ALT 50, ALP 321, albumin 3.7, globulin 4. Most likely diagnosis?", "choices": ["Liver abscess", "Acute cholecystitis", "Pancreatitis", "Acute cholangitis", "Viral hepatitis"], "ans": 3, "exp": "ไข้สูง + ปวด RUQ + ดีซ่าน (DB เด่น, ALP สูง = obstructive pattern) = Charcot triad ของ acute cholangitis", "sys": "I"}, {"topic": "Internal medicine", "q": "A 50-year-old with 6 months of cardiac symptoms. Grade 3/6 pansystolic murmur loudest at the apex, radiating to the left axilla. Most likely cause?", "choices": ["Aortic stenosis", "Tricuspid regurgitation", "Ventricular septal defect", "Hypertrophic cardiomyopathy", "Mitral regurgitation"], "ans": 4, "exp": "pansystolic murmur ที่ apex ร้าวไปรักแร้ซ้าย = mitral regurgitation", "sys": "IX"}, {"topic": "Internal medicine", "q": "A 50-year-old man with prior pulmonary TB, 5 days of productive cough, fever (38-39), basilar crepitations, clubbing. Sputum AFB smear negative. Most likely diagnosis?", "choices": ["Infected bronchiectasis", "Aspergilloma", "Lung abscess", "Necrotizing pneumonia", "Relapse pulmonary TB"], "ans": 0, "exp": "ประวัติ TB เดิม + ไอมีเสมหะเป็นซ้ำ + clubbing + AFB ลบ = infected bronchiectasis (post-TB bronchiectasis). *อ้างอิงภาพ*", "img": "https://cdn.jsdelivr.net/gh/MercenzK/Web-quiz-images@main/NL2-2025-Apr-Q41.png", "sys": "I"}, {"topic": "Internal medicine", "q": "A 36-year-old woman with hyperthyroidism on methimazole and propranolol for 2 months, 3 days of high fever (39) and severe sore throat, with multiple oropharyngeal ulcers, appears toxic, tachycardic, no cough. Best initial investigation?", "choices": ["Blood culture", "Complete blood count (CBC)", "Epstein-Barr virus serology", "Rapid streptococcal antigen test", "Throat swab for bacterial culture"], "ans": 1, "exp": "ไข้สูง + เจ็บคอ + แผลในคอ ในผู้ใช้ methimazole = สงสัย agranulocytosis -> ตรวจ CBC ดู neutrophil count เป็นอันดับแรก", "sys": "IV"}, {"topic": "Internal medicine", "q": "A 35-year-old woman with fatigue and intermittent dark urine, pallor and mild scleral icterus. Hb 7, platelets 80,000, normal WBC. No hepatosplenomegaly. Most likely diagnosis?", "choices": ["Hereditary spherocytosis", "G6PD deficiency with hemolysis", "Autoimmune hemolytic anemia", "Hemoglobin H disease", "Paroxysmal nocturnal hemoglobinuria (PNH)"], "ans": 2, "exp": "เม็ดเลือดแดงแตก + เกล็ดเลือดต่ำร่วม = autoimmune hemolytic anemia (อาจร่วมกับ ITP เป็น Evans syndrome). *ถ้าปัสสาวะเข้มจาก hemoglobinuria เด่นและ Coombs ลบ ให้นึกถึง PNH ด้วย*", "sys": "III"}, {"topic": "Internal medicine", "q": "A 45-year-old man with 3 months of back pain, night sweats, weight loss, immigrated from a TB-endemic area. Spinal X-ray shows vertebral destruction, disc space loss, and a paraspinal abscess. Most likely diagnosis?", "choices": ["Metastatic cancer", "Osteomyelitis", "Ankylosing spondylitis", "Tuberculous spondylitis", "Vertebral fracture"], "ans": 3, "exp": "ปวดหลังเรื้อรัง + ไข้/เหงื่อออกกลางคืน/น้ำหนักลด + กระดูกสันหลังถูกทำลาย + paraspinal abscess = tuberculous spondylitis (Pott's disease)", "sys": "II"}, {"topic": "Internal medicine", "q": "A 50-year-old man with 3 months of headaches and dizziness, BP 150/95, no prior HTN/DM/smoking, BMI 23, unremarkable exam. Initial management?", "choices": ["ACE inhibitor", "Calcium channel blocker", "Beta-blocker", "Diuretic", "Lifestyle modification (diet/exercise)"], "ans": 4, "exp": "ความดันโลหิตสูงที่เพิ่งพบในคนสุขภาพดีความเสี่ยงต่ำ -> เริ่มด้วยปรับพฤติกรรม (lifestyle modification) และติดตาม (พิจารณาเริ่มยาถ้าคุมไม่ได้/เป็น stage 2 ต่อเนื่อง)", "sys": "VI"}, {"topic": "Internal medicine", "q": "A 60-year-old previously healthy woman with 3 days of progressive dyspnea after 7 days of fever/rhinorrhea/cough. BP 80/50, HR 130, RR 32, SpO2 80%. Cold extremities, elevated JVP, PMI displaced to 6th ICS, S3 gallop, bilateral crepitations. Troponin T elevated (440), ECG sinus tachycardia without ischemia. Most likely diagnosis?", "choices": ["Acute myocarditis", "Hypovolemic shock", "Acute myocardial infarction", "Pneumonia with septic shock", "Acute massive pulmonary embolism"], "ans": 0, "exp": "cardiogenic shock + หัวใจโต (PMI เลื่อน) + troponin สูง หลังไข้ไวรัส = acute myocarditis", "sys": "I"}, {"topic": "Internal medicine", "q": "A 50-year-old man with pulmonary TB 5 years ago, dyspnea and fine crepitations in both lower lung fields. CXR shows diffuse cystic lesions in both lower lobes. Most likely diagnosis?", "choices": ["Aspergilloma", "Bronchiectasis", "Lung abscess", "Recurrent tuberculosis", "Necrotizing pneumonia"], "ans": 1, "exp": "cystic lesion กระจายทั้งสองปอด + ประวัติ TB เดิม + crepitation = bronchiectasis (จากการทำลายหลอดลมหลัง TB)", "sys": "I"}, {"topic": "Internal medicine", "q": "A 40-year-old man with low-grade fever, dry cough, and occasional blood-streaked sputum for 1 month. T 39, coarse crepitations in LUL. CXR: fibronodular infiltration with a cavity in LUL. Next step in management?", "choices": ["CT chest", "Amoxicillin-clavulanate", "Sputum for AFB", "Azithromycin", "Sputum culture"], "ans": 2, "exp": "ภาพ fibronodular + cavity ที่ปอดส่วนบน + ไอเป็นเลือดเรื้อรัง = สงสัยวัณโรค -> ส่ง sputum for AFB (และ molecular test)", "sys": "X"}, {"topic": "Internal medicine", "q": "A 17-year-old female with fatigue, no family history. Hb 8.0, MCV 70 (microcytic), peripheral smear shows target cells 3+. Next investigation?", "choices": ["Serum ferritin", "Abdominal ultrasound", "Chest X-ray", "Hemoglobin electrophoresis (Hb typing)", "DNA testing for alpha-thalassemia"], "ans": 3, "exp": "ซีด microcytic + target cell มาก = thalassemia -> ตรวจ hemoglobin typing (electrophoresis) วินิจฉัย", "sys": "III"}, {"topic": "Internal medicine", "q": "A 70-year-old male with acute right knee swelling and pain. Synovial fluid: weakly positive birefringent rhomboid crystals. Serum uric acid normal. Most likely diagnosis?", "choices": ["Gouty arthritis", "Septic arthritis", "Rheumatoid arthritis", "Osteoarthritis", "CPPD deposition disease (pseudogout)"], "ans": 4, "exp": "ผลึกรูปสี่เหลี่ยมขนมเปียกปูน (rhomboid) + weakly positive birefringence = calcium pyrophosphate (CPPD) = pseudogout (gout จะเป็นเข็ม negative birefringence)", "sys": "XIII"}, {"topic": "Internal medicine", "q": "A 28-year-old male with three episodes of hematemesis after heavy alcohol consumption and recurrent vomiting. No stigmata of chronic liver disease, CBC unremarkable. Most likely cause?", "choices": ["Mallory-Weiss tear", "Alcoholic gastritis", "Erosive duodenitis", "Esophageal varices", "Hemorrhagic peptic ulcer"], "ans": 0, "exp": "อาเจียนรุนแรงซ้ำ ๆ แล้วอาเจียนเป็นเลือด โดยไม่มีตับแข็ง = Mallory-Weiss tear (รอยฉีกที่รอยต่อหลอดอาหาร-กระเพาะ)", "sys": "XI"}, {"topic": "Internal medicine", "q": "A 70-year-old male with sharp, electric-like pain in the right V2/V3 distribution triggered by tooth brushing, lasting seconds, normal neuro exam. Most likely diagnosis?", "choices": ["Migraine", "Trigeminal neuralgia", "Cluster headache", "Temporal arteritis", "Dental abscess"], "ans": 1, "exp": "ปวดแปลบเหมือนไฟช็อตตามแนวเส้นประสาทคู่ที่ 5 (V2/V3) กระตุ้นด้วยการสัมผัส/แปรงฟัน = trigeminal neuralgia", "sys": "VI"}, {"topic": "Internal medicine", "q": "A 45-year-old with pallor and jaundice. Peripheral smear shows red blood cell agglutination (resembling cold agglutinin disease). Most useful initial investigation?", "choices": ["ANA", "Osmotic fragility test", "Direct antiglobulin test (Coombs test)", "Serum haptoglobin", "Liver function tests"], "ans": 2, "exp": "RBC agglutination = cold agglutinin/autoimmune hemolytic anemia -> ตรวจ direct antiglobulin (Coombs) test", "sys": "III"}, {"topic": "Internal medicine", "q": "A 65-year-old female with DM, COPD, and polypharmacy presents with oral candidiasis (white curd-like plaques). On azathioprine, theophylline, metformin, prednisolone, and budesonide/formoterol inhaler. Which medication is most likely responsible for the oral candidiasis?", "choices": ["Azathioprine", "Theophylline", "Metformin", "Budesonide/Formoterol inhaler", "Prednisolone"], "ans": 3, "exp": "oral candidiasis สาเหตุเฉพาะที่จาก inhaled corticosteroid (budesonide/formoterol) ที่ไม่บ้วนปากหลังพ่น", "sys": "X"}, {"topic": "Internal medicine", "q": "A 35-year-old woman with beta-thalassemia/Hb E develops fever (38), chills, flushing, and hypotension (80/60) during a routine blood transfusion. Tachycardia 120, no wheezing/dyspnea/rash. Most appropriate initial management?", "choices": ["Normal saline (NSS) fluid bolus", "Oral paracetamol", "Intravenous hydrocortisone", "Intravenous chlorpheniramine", "Immediate cessation of the transfusion"], "ans": 4, "exp": "ปฏิกิริยาการให้เลือดที่รุนแรง (ไข้ + ความดันตก) -> ขั้นแรกต้องหยุดให้เลือดทันที (immediate cessation) แล้วประเมิน/รักษาต่อ", "sys": "III"}, {"topic": "Internal medicine", "q": "A 44-year-old man with recurrent nocturnal flaccid paralysis of all limbs (4 episodes in 2 years). During an attack: hypokalemia (K 2.0) and metabolic acidosis (HCO3 15). Underlying pathogenesis of the hypokalemia?", "choices": ["Defective H secretion at the distal tubule", "Decreased aldosterone secretion", "Increased renal potassium reabsorption", "Defective Na-K ATPase function", "Defective K reabsorption at the proximal tubule"], "ans": 0, "exp": "hypokalemia + normal anion gap metabolic acidosis + อัมพาตเป็นพัก ๆ = distal (type 1) renal tubular acidosis -> ความบกพร่องการหลั่ง H ที่ distal tubule ทำให้สูญเสีย K", "sys": "IV"}, {"topic": "Internal medicine", "q": "A 40-year-old woman with 6 months of palpitations and weight loss. BMI 18, pulse 120, a 2-cm left thyroid nodule. FT3 10.2 (high), FT4 4.6 (high), TSH 0.01 (low). Most appropriate next diagnostic step?", "choices": ["Anti-TPO antibody test", "Thyroid scan and uptake study", "TSH receptor antibody (TRAb)", "Thyroid ultrasound", "Fine-needle aspiration (FNA)"], "ans": 1, "exp": "hyperthyroidism + solitary thyroid nodule -> ทำ thyroid scan and uptake เพื่อดูว่าเป็น 'hot' (toxic) nodule หรือไม่ (nodule ที่ hot มักไม่ใช่มะเร็ง จึงไม่ต้อง FNA)", "sys": "IV"}, {"topic": "Internal medicine", "q": "An 80-year-old man with multiple large, tense, fluid-filled bullae on erythematous skin over trunk and limbs, non-rupturing and mildly pruritic. No mucosal involvement. Most likely diagnosis?", "choices": ["Pemphigus vulgaris", "Bullous impetigo", "Bullous pemphigoid", "Erythema multiforme", "Dermatitis herpetiformis"], "ans": 2, "exp": "ตุ่มน้ำใหญ่ตึง (tense bullae) ในผู้สูงอายุ ไม่มีเยื่อบุ = bullous pemphigoid (pemphigus จะเป็นตุ่มหย่อน flaccid + มีเยื่อบุ). *อ้างอิงภาพ*", "img": "https://cdn.jsdelivr.net/gh/MercenzK/Web-quiz-images@main/NL2-2025-Apr-Q58.png", "sys": "XII"}, {"topic": "Internal medicine", "q": "A 75-year-old woman with hypertension controlled 10 years on medication, presents with 2 weeks of fever, malaise, arthralgia, malar rash, oral ulcers, and pericardial friction rub. Hct 27%, WBC 2,800, platelets 88,000. Which medication is most likely responsible?", "choices": ["Enalapril", "Amlodipine", "Losartan", "Hydralazine", "Hydrochlorothiazide"], "ans": 3, "exp": "drug-induced lupus (malar rash, arthralgia, serositis, cytopenia) -> ยาที่พบบ่อยคือ hydralazine (และ procainamide, isoniazid)", "sys": "IX"}, {"topic": "Internal medicine", "q": "A 65-year-old man with chronic low back pain, acute epigastric pain after taking NSAIDs for 1 week. Abdominal tenderness. Upright abdominal X-ray shows no free air. Most appropriate initial investigation?", "choices": ["Gastroscopy", "Upper GI series (barium swallow)", "Serum amylase and lipase", "Abdominal CT scan", "Left lateral decubitus abdominal X-ray"], "ans": 4, "exp": "สงสัยแผลทะลุจาก NSAIDs แต่ upright film ไม่เห็นลม -> ถ่าย left lateral decubitus film (ไวกว่าในการจับลมอิสระปริมาณน้อย) ก่อนพิจารณา CT", "sys": "I"}, {"topic": "Internal medicine", "q": "A 25-year-old woman with beta/betaE thalassemia develops pruritus, nausea, and vomiting immediately after receiving leukocyte-depleted packed red cells. No fever, hemoglobinuria, or hypotension. Most appropriate initial management?", "choices": ["Chlorpheniramine IV (antihistamine)", "Normal saline IV bolus", "Hydrocortisone IV", "Furosemide IV", "Transfusion cessation"], "ans": 0, "exp": "allergic (urticarial) transfusion reaction ระดับเล็กน้อย (คัน คลื่นไส้ ไม่มีไข้/ความดันตก) -> หยุด/พักการให้เลือดชั่วคราวและให้ antihistamine (chlorpheniramine) แล้วให้ต่อได้ถ้าอาการดีขึ้น", "sys": "III"}, {"topic": "Internal medicine", "q": "A 45-year-old woman with 2 months of fatigue and pallor. CBC shows pancytopenia. Peripheral smear reveals hypersegmented neutrophils. Most useful initial investigation?", "choices": ["Serum folate level", "Serum vitamin B12 level", "Bone marrow biopsy", "Reticulocyte count", "Coombs test"], "ans": 1, "exp": "pancytopenia + hypersegmented neutrophil = megaloblastic anemia -> ตรวจ vitamin B12 level (และ folate) เป็นอันดับแรก", "sys": "III"}, {"topic": "Internal medicine", "q": "A 50-year-old woman with mitral valve prolapse presents with fever, new murmur, and splinter hemorrhages. Dental exam reveals multiple untreated caries. Most likely diagnosis?", "choices": ["Acute pericarditis", "Rheumatic fever", "Infective endocarditis", "Periodontal abscess", "Sepsis from dental source"], "ans": 2, "exp": "ลิ้นหัวใจผิดปกติ + ไข้ + murmur ใหม่ + splinter hemorrhage + แหล่งเชื้อจากฟันผุ = infective endocarditis", "sys": "I"}, {"topic": "Internal medicine", "q": "A 65-year-old woman with hypertension (on amlodipine and enalapril) presents with chest discomfort, bilateral pitting edema (2+), and fine crepitations in both lungs. BP 130/80. Initial management?", "choices": ["Sublingual nitroglycerin", "IV calcium gluconate", "IV normal saline 500 mL", "IV furosemide", "Increase enalapril dose"], "ans": 3, "exp": "acute heart failure ที่มีน้ำท่วมปอด (crepitation, บวม) -> ให้ IV furosemide ขับน้ำเป็นอันดับแรก", "sys": "IX"}, {"topic": "Internal medicine", "q": "A 60-year-old cirrhotic with hematemesis and melena, resuscitated with IV fluids, now stable (BP 110/70, HR 90). Endoscopy planned within 1 hour. Most appropriate pharmacologic management?", "choices": ["Urgent esophagogastroduodenoscopy (EGD)", "IV vasopressin", "Balloon tamponade", "Oral propranolol", "IV octreotide + IV proton pump inhibitor (PPI)"], "ans": 4, "exp": "variceal bleeding -> ให้ vasoactive drug (octreotide) + PPI ระหว่างรอ EGD (octreotide ลดแรงดัน portal). EGD เป็นหัตถการไม่ใช่ยา; balloon tamponade เป็นทางเลือกสุดท้าย", "sys": "XI"}, {"topic": "Internal medicine", "q": "A 22-year-old college student with fever, neck stiffness, and altered mental status. CSF confirms Neisseria meningitidis meningitis. Antibiotic of choice?", "choices": ["Ceftriaxone", "Penicillin G", "Vancomycin", "Ampicillin", "Meropenem"], "ans": 0, "exp": "meningococcal meningitis -> ยาหลักคือ ceftriaxone (third-generation cephalosporin)", "sys": "VI"}, {"topic": "Internal medicine", "q": "A 45-year-old woman with unilateral pleural effusion. Fluid: exudative, lymphocyte-predominant, ADA 85 (high). Night sweats and weight loss. Most likely diagnosis?", "choices": ["Bacterial pneumonia", "Tuberculosis", "Malignancy", "Heart failure", "Pulmonary embolism"], "ans": 1, "exp": "pleural effusion แบบ exudate + lymphocyte เด่น + ADA สูง (>40) + ไข้/น้ำหนักลด = tuberculous pleuritis", "sys": "II"}, {"topic": "Internal medicine", "q": "A 40-year-old woman with a diffuse, non-tender goiter. Free T3 3.5 (normal), TSH 2.0 (normal), anti-TPO antibodies 350 (high). Diagnosis?", "choices": ["Simple goiter", "Graves disease", "Hashimoto thyroiditis", "Subacute thyroiditis", "Thyroid lymphoma"], "ans": 2, "exp": "คอพอกโตทั่ว + euthyroid (TFT ปกติ) + anti-TPO สูง = Hashimoto thyroiditis (chronic autoimmune thyroiditis)", "sys": "II"}, {"topic": "Anesthesiology", "q": "A 75-year-old male on morphine 4 mg IV q2h for postop pain. 12 hours later he is drowsy, unresponsive to voice, RR 8, HR 60, BP 90/50. Most appropriate management?", "choices": ["Endotracheal intubation", "Normal saline bolus", "Atropine IV", "Naloxone IV", "50% dextrose IV"], "ans": 3, "exp": "opioid overdose (ซึม หายใจช้า RR 8) -> ให้ naloxone IV (antagonist) กลับฤทธิ์ opioid", "sys": "XVIII"}, {"topic": "Internal medicine", "q": "A 50-year-old woman with a shallow, smooth, soft ulcer on the lower lip for 1 week. No fever, lymphadenopathy, or prior episodes. Initial management?", "choices": ["Acyclovir cream", "Topical antibiotic", "Antiseptic mouthwash", "Oral amoxicillin-clavulanate", "Topical triamcinolone"], "ans": 4, "exp": "แผลในปาก/ริมฝีปากแบบ aphthous ulcer -> รักษาด้วย topical corticosteroid (triamcinolone in orabase)", "sys": "III"}, {"topic": "Surgery", "q": "A 10-year-old child with a recurrent, painless 2-cm midline neck mass at the hyoid level that enlarges after colds, smooth and fluctuant, elevates with tongue protrusion. Most appropriate initial management?", "choices": ["Ultrasound neck", "Surgical excision (Sistrunk procedure)", "Thyroid scan", "Lateral neck X-ray", "Fine-needle aspiration (FNA)"], "ans": 0, "exp": "thyroglossal duct cyst (ก้อนกลางคอเลื่อนตามการแลบลิ้น) -> การจัดการเบื้องต้นคือ ultrasound คอ เพื่อยืนยันและตรวจว่ามีเนื้อไทรอยด์ปกติก่อนผ่าตัด (Sistrunk เป็นการรักษาถาวร). *อ้างอิงภาพ*", "img": "https://cdn.jsdelivr.net/gh/MercenzK/Web-quiz-images@main/NL2-2025-Apr-Q71.png", "sys": "II"}, {"topic": "Otolaryngology", "q": "A 35-year-old female with progressive bilateral nasal obstruction 1 year, mouth breathing, hyposmia, snoring. Large, pale, grape-like masses bilaterally filling the nasal cavities (nasal polyps), no purulent discharge, no improvement after 6 weeks of intranasal corticosteroids. Most appropriate management?", "choices": ["Sublingual immunotherapy (SLIT)", "Surgical polypectomy (Functional Endoscopic Sinus Surgery, FESS)", "Intranasal corticosteroid spray", "Oral antihistamines", "Observation"], "ans": 1, "exp": "nasal polyps ที่ไม่ตอบสนองต่อ intranasal corticosteroid -> รักษาด้วยการผ่าตัด (FESS/polypectomy)", "sys": "VIII"}, {"topic": "Surgery", "q": "A 1-month-old boy with a solitary, rubbery, 3 cm mass on the posterior scalp since birth, slowly enlarging, non-tender, with a bluish hue, otherwise asymptomatic. Diagnosis?", "choices": ["Lipoma", "Neurofibroma", "Hemangioma", "Epidermal cyst", "Sebaceous cyst"], "ans": 2, "exp": "ก้อนนุ่มโตช้าตั้งแต่แรกเกิด สีออกน้ำเงิน = hemangioma (เนื้องอกหลอดเลือด)", "sys": "II"}, {"topic": "Surgery", "q": "A 60-year-old man with HT and dyslipidemia (on HCTZ, atenolol, simvastatin) reports new erectile dysfunction, otherwise healthy, unremarkable exam. Initial management?", "choices": ["Add sildenafil", "Refer to urologist", "Assess couple relationship", "Discontinue atenolol", "Check morning testosterone"], "ans": 3, "exp": "erectile dysfunction ที่น่าจะเกิดจากยา (beta-blocker atenolol และ thiazide) -> จัดการที่ต้นเหตุโดยหยุด/เปลี่ยน atenolol ก่อน", "sys": "flex"}, {"topic": "Surgery", "q": "A 2-year-old girl with a painless, reducible umbilical mass, 1.5 cm abdominal wall defect, no fever/vomiting/discoloration/tenderness. Most appropriate management?", "choices": ["Abdominal binding", "CT abdomen", "Ultrasound abdomen", "Surgical repair", "Reassure and follow up"], "ans": 4, "exp": "umbilical hernia ขนาดเล็กในเด็กเล็ก มักปิดเองภายในอายุ 4-5 ปี -> reassure และติดตาม (ผ่าตัดเมื่อยังไม่ปิด/ใหญ่/มีภาวะแทรกซ้อน)", "sys": "XI"}, {"topic": "Surgery", "q": "A 28-year-old woman with anorexia nervosa, 20 hours of migratory abdominal pain (umbilical to RLQ), T 38.7. RLQ guarding without rebound. Hct 35%, WBC 3,200 (80% neutrophils, 3% bands). Most appropriate management?", "choices": ["Appendectomy", "IV antibiotics", "Observe in hospital", "Abdominal ultrasound", "Esophagogastroduodenoscopy"], "ans": 0, "exp": "ปวดย้ายจากสะดือไป RLQ + ไข้ + guarding + neutrophil เด่น/bands = acute appendicitis -> appendectomy", "sys": "V"}, {"topic": "Surgery", "q": "A Thai male post-car accident with BP 120/90, soft non-tender abdomen, scrotal hematoma, and urethral bleeding, no pelvic instability. Most appropriate investigation?", "choices": ["Cystoscopy", "Retrograde urethrography", "IVP", "Ultrasound KUB", "CT abdomen with IV contrast"], "ans": 1, "exp": "เลือดออกที่ท่อปัสสาวะ (blood at meatus) + scrotal hematoma = สงสัยบาดเจ็บท่อปัสสาวะ -> ตรวจ retrograde urethrography (ห้ามใส่สายสวนก่อน)", "sys": "XIV"}, {"topic": "Surgery", "q": "A 42-year-old diabetic man with 7 days of fever and right thigh pain. Aspiration yields pus with neutrophils but no organisms on Gram stain. Localized swelling and erythema. Most appropriate antibiotic regimen?", "choices": ["Meropenem", "Vancomycin", "Cloxacillin + ceftazidime", "Ceftriaxone + clindamycin", "Clindamycin alone"], "ans": 2, "exp": "ฝีกล้ามเนื้อ (pyomyositis) ในผู้ป่วยเบาหวานในไทย -> ครอบคลุมทั้ง S. aureus (cloxacillin) และ Burkholderia pseudomallei/melioidosis (ceftazidime)", "sys": "I"}, {"topic": "Surgery", "q": "A 6-year-old boy with a congenital hyperpigmented patch on his back, now 25 cm with irregular borders and coarse hair, grown proportionally since birth, no tenderness/ulceration/nodularity. Which feature is an indication for surgical excision?", "choices": ["Presence of hair", "Rapid progression", "Irregular border", "Large size (>20 cm)", "Cosmetic concern"], "ans": 3, "exp": "giant congenital melanocytic nevus (>20 ซม.) มีความเสี่ยงเปลี่ยนเป็นมะเร็ง melanoma สูง -> ขนาดใหญ่ (>20 ซม.) เป็นข้อบ่งชี้ในการตัดออก", "sys": "XVII"}, {"topic": "Surgery", "q": "A 65-year-old woman with duodenal adenocarcinoma causing near-complete lumen obstruction, cachectic and vomiting after oral intake, surgery planned in 5 days. Best nutritional support?", "choices": ["Nasojejunal (NJ) tube feeding", "Partial parenteral nutrition", "Nasogastric tube feeding", "Oral liquid supplements", "Total parenteral nutrition (TPN)"], "ans": 4, "exp": "ลำไส้อุดตัน (ใช้ทางเดินอาหารไม่ได้) + ทุพโภชนาการ + รอผ่าตัด 5 วัน -> ให้ total parenteral nutrition (TPN)", "sys": "II"}, {"topic": "Surgery", "q": "A 20-year-old man stabbed in the right paraumbilical region. BP 90/60, HR 90. Generalized abdominal tenderness with guarding and rigidity. Most appropriate management?", "choices": ["Exploratory laparotomy", "FAST ultrasound", "Diagnostic peritoneal lavage (DPL)", "CT abdomen", "Ultrasound abdomen"], "ans": 0, "exp": "penetrating abdominal injury + peritonitis (guarding/rigidity) + ความดันเริ่มตก -> exploratory laparotomy ทันที (ไม่เสียเวลา imaging)", "sys": "XVIII"}, {"topic": "Internal medicine", "q": "A 50-year-old man with bilateral ptosis and proximal muscle weakness (myasthenia gravis). Which condition is most associated with this disease?", "choices": ["Vasculitis", "Thymoma", "Multiple sclerosis", "Lambert-Eaton syndrome", "Polymyositis"], "ans": 1, "exp": "myasthenia gravis สัมพันธ์กับ thymoma (เนื้องอกต่อมไทมัส) บ่อย -> ควรตรวจ CT ทรวงอกหา thymoma", "sys": "VI"}, {"topic": "Surgery", "q": "A 40-year-old man with high-grade fever and RUQ pain for 2 days, marked RUQ tenderness, liver edge 3 cm below costal margin. Ultrasound shows a 7 cm well-defined hypoechoic mass. Most appropriate initial investigation?", "choices": ["Complete blood count (CBC)", "Serum alpha-fetoprotein (AFP)", "Amebic serology", "Blood cultures", "CT-guided biopsy"], "ans": 2, "exp": "ฝีในตับก้อนเดียว well-defined hypoechoic + ไข้ -> ตรวจ amebic serology แยก amoebic (รักษาด้วยยา) จาก pyogenic abscess", "sys": "XI"}, {"topic": "Surgery", "q": "A 40-year-old man with 25% second-degree and 10% third-degree burns (total 35% TBSA), 2 hours after injury, weight 50 kg. Using the Parkland formula, what volume in the first hour?", "choices": ["875 mL", "1,000 mL", "1,750 mL", "500 mL", "3,500 mL"], "ans": 3, "exp": "Parkland: 4 x 50 kg x 35% = 7,000 mL/24 ชม.; ครึ่งแรก 3,500 mL ให้ใน 8 ชม.แรก -> เฉลี่ย 3,500/8 = 437.5 mL/ชม. (ตัวเลือกที่ใกล้สุด = 500 mL/ชม.)", "sys": "XVIII"}, {"topic": "Surgery", "q": "A 25-year-old man with a small, asymptomatic skin tag near the anus, no bleeding/pain/bowel changes, otherwise unremarkable. Most appropriate management?", "choices": ["Sphincterotomy", "Hemorrhoidectomy", "Steroid suppository", "Rubber band ligation", "Reassurance"], "ans": 4, "exp": "anal skin tag ที่ไม่มีอาการ -> reassurance (ไม่ต้องรักษา)", "sys": "XI"}, {"topic": "Surgery", "q": "A 70-year-old man with acute urinary retention for 24 hours after taking OTC cold medication (antihistamine/decongestant). Suprapubic mass, DRE shows enlarged rubbery prostate. Initial management?", "choices": ["Urinary catheterization", "Finasteride and doxazosin", "Abdominal ultrasound", "Transurethral resection of prostate (TURP)", "Discontinue cold medication"], "ans": 0, "exp": "acute urinary retention -> ระบายปัสสาวะด้วยการใส่สายสวน (catheterization) ทันที เพื่อบรรเทา แล้วจึงจัดการสาเหตุ (BPH/หยุดยา)", "sys": "XIV"}, {"topic": "Surgery", "q": "A 64-year-old man with atrial fibrillation on warfarin, acute left leg pain and coldness for 6 hours, absent dorsalis pedis and posterior tibial pulses. Diagnosis?", "choices": ["Deep vein thrombosis", "Acute arterial embolism", "Compartment syndrome", "Sciatica", "Cellulitis"], "ans": 1, "exp": "AF + ขาเย็นปวดเฉียบพลัน + ชีพจรคลำไม่ได้ = acute arterial embolism (ลิ่มเลือดจากหัวใจไปอุด)", "sys": "IX"}, {"topic": "Surgery", "q": "A 25-year-old man stabbed in the paraumbilical region with generalized abdominal tenderness, rebound tenderness, and guarding. BP 100/60, HR 110. Next step?", "choices": ["FAST ultrasound", "CT abdomen with contrast", "Exploratory laparotomy", "Diagnostic peritoneal lavage", "Serial abdominal exams"], "ans": 2, "exp": "penetrating abdominal injury + peritonitis (rebound/guarding) -> exploratory laparotomy", "sys": "XVIII"}, {"topic": "Pediatrics", "q": "A 2-year-old boy at a well-child clinic: runs well, walks upstairs, scribbles, helps wear clothes, says mama and papa, waves bye bye. Interpretation of development?", "choices": ["Normal development", "Delayed fine motor", "Delayed gross motor", "Delayed speech", "Global delayed development"], "ans": 3, "exp": "อายุ 2 ปีควรพูดได้ ~50 คำ/วลี 2 คำ แต่พูดได้แค่ mama/papa (gross motor/fine motor/social ปกติ) = delayed speech (language delay)", "sys": "flex"}, {"topic": "Pediatrics", "q": "A 4-year-old girl with close household contact with a grandfather on active pulmonary TB treatment for 2 weeks. The child is asymptomatic, CXR normal, tuberculin skin test induration 5 mm. Most appropriate next step?", "choices": ["Reassure", "Repeat tuberculin skin test in 6 weeks", "Repeat chest radiograph in 1 month", "IRZE for 6 months", "Initiate isoniazid therapy for 9 months"], "ans": 4, "exp": "เด็ก <5 ปี สัมผัสผู้ป่วย TB + TST >=5 มม. (บวกในผู้สัมผัส) + CXR ปกติ = latent TB infection -> ให้ isoniazid ป้องกัน 9 เดือน", "sys": "I"}, {"topic": "Pediatrics", "q": "A 14-year-old girl with 4 days of fever. T 40, BP 90/60, HR 120, RR 30, no hepatosplenomegaly, purpuric rashes on lower extremities. Normal Hct, normal WBC with increased atypical lymphocytes, thrombocytopenia, prolonged PT and aPTT. Most likely diagnosis?", "choices": ["Disseminated intravascular coagulation", "Acute leukemia", "Aplastic anemia", "Vitamin K deficiency", "Dysfibrinogenemia"], "ans": 0, "exp": "ไข้ + ช็อก + purpura + เกล็ดเลือดต่ำ + PT/aPTT ยาว = disseminated intravascular coagulation (DIC). *อ้างอิงภาพ*", "img": "https://cdn.jsdelivr.net/gh/MercenzK/Web-quiz-images@main/NL2-2025-Apr-Q91.png", "sys": "II"}, {"topic": "Pediatrics", "q": "A 3,600-gram male infant with vomiting at 2 weeks of age, formula-fed 3 ounces every 3 hours, passes normal stools. Birth weight 3,000 grams. Unremarkable exam. Most likely diagnosis?", "choices": ["Gastroenteritis", "Overfeeding", "Duodenal atresia", "Gastroesophageal reflux", "Gastric outlet obstruction"], "ans": 1, "exp": "ได้นม 3 ออนซ์ทุก 3 ชม. = ~24 ออนซ์/วัน (~200 mL/kg/day มากเกิน) + น้ำหนักขึ้นดี อุจจาระปกติ ตรวจปกติ = overfeeding", "sys": "XVI"}, {"topic": "Pediatrics", "q": "A 4-year-old with asthma, acute dyspnea, not improved after 3 doses of nebulized salbutamol. BT 38, BP 100/70, PR 130, RR 40, SpO2 90% on oxygen cannula, poor air entry. Next best step?", "choices": ["IV theophylline", "Nebulized salbutamol", "Oral prednisolone", "Nebulized budesonide", "Subcutaneous terbutaline"], "ans": 2, "exp": "asthma exacerbation ที่ไม่ตอบสนอง SABA -> ให้ systemic corticosteroid (oral prednisolone) เป็นขั้นต่อไปที่สำคัญ (ร่วมกับ ipratropium/O2; รายรุนแรงมากพิจารณา SC terbutaline/IV magnesium)", "sys": "IX"}, {"topic": "Pediatrics", "q": "A 2-year-old with 2 days of fever and rash, attends nursery. T 38.5, posterior pharyngeal ulcers, vesicles on soles and in the mouth. No other children affected. Most effective method to prevent transmission?", "choices": ["Allow the child to return to nursery as usual", "Vaccinate other children at the nursery", "Close the nursery for one week", "Advise the index case to stay at home", "Require all children to wear face masks"], "ans": 3, "exp": "hand-foot-mouth disease -> แนะนำให้เด็กที่ป่วย (index case) หยุดเรียนอยู่บ้านจนหายแพร่เชื้อ ร่วมกับสุขอนามัยล้างมือ", "sys": "I"}, {"topic": "Pediatrics", "q": "A 5-year-old boy (20 kg) with acute watery diarrhea (6 episodes/24h), active, tolerating oral, playing normally, stable vitals, no signs of dehydration. Most appropriate initial management?", "choices": ["Oral antibiotics", "5% Dextrose in Normal Saline (DNS) IV drip at 65 mL/hr", "5% Dextrose in Half-Normal Saline (D1/2NS) IV drip at 65 mL/hr", "Intravenous bolus of normal saline", "Oral rehydration solution (ORS) 1000 mL over the first 4 hours"], "ans": 4, "exp": "ท้องเสียเฉียบพลันโดยไม่มีภาวะขาดน้ำ + กินได้ -> ให้ oral rehydration solution (ORS) ทดแทนน้ำที่เสียไป (ไม่ต้องให้สารน้ำทางหลอดเลือด/ยาปฏิชีวนะ)", "sys": "XI"}, {"topic": "Pediatrics", "q": "A term macrosomic newborn (4200 g) with normal Apgar develops multifocal clonic jerks at 3 hours of life. Severe hypoglycemia (glucose 21) and hypocalcemia (calcium 8), normal CBC/electrolytes, stable vitals. Most urgent initial treatment?", "choices": ["Glucose infusion", "Intravenous antibiotics", "Intravenous anticonvulsants", "Intravenous calcium gluconate", "Packed red blood cell (PRC) transfusion"], "ans": 0, "exp": "ทารกแม่เบาหวาน (macrosomia) ชักจาก severe hypoglycemia (glucose 21) -> ให้กลูโคสทางหลอดเลือดด่วนเป็นอันดับแรก (glucose ต่ำรุนแรงกว่า Ca 8 ที่ borderline)", "sys": "XVI"}, {"topic": "Pediatrics", "q": "A 12-year-old with high fever (39.5) and acute confusion, mottled skin, palpable non-blanching purpuric rash over both lower extremities, BP 85/50, lethargic. Leukocytosis and thrombocytopenia. Most likely life-threatening complication?", "choices": ["Pancreatitis", "Adrenal hemorrhage", "Myocarditis", "Gallstone sludge", "Pulmonary hypertension"], "ans": 1, "exp": "meningococcemia (ไข้ + purpura + ช็อก) -> ภาวะแทรกซ้อนร้ายแรงคือ adrenal hemorrhage (Waterhouse-Friderichsen syndrome)", "sys": "III"}, {"topic": "Pediatrics", "q": "A 14-year-old boy with sudden severe right testicular pain 2 hours after playing tennis, no trauma. Erythema and swelling, significant tenderness, pain worsened by scrotal elevation, transverse lie of the right testis. Most appropriate management?", "choices": ["NSAIDs", "Manual reduction", "Surgical exploration of the right testis", "Reassure", "Testicular ultrasound"], "ans": 2, "exp": "testicular torsion (ปวดเฉียบพลัน + อัณฑะวางขวาง + Prehn negative) = ภาวะฉุกเฉิน -> ผ่าตัด exploration ทันที (ภายใน 6 ชม.) ไม่รอ ultrasound ถ้าอาการชัด", "sys": "I"}, {"topic": "Pediatrics", "q": "A 10-year-old girl with recurrent, intensely pruritic rashes on both palms for 6 months, worse in hot weather or stress with excessive sweating. Multiple deep-seated tiny vesicles ('tapioca pearls') without scaling/erythema/pustules, no soles/nails involvement. Most appropriate initial management?", "choices": ["Oral dicloxacillin", "Oral chlorpheniramine", "Topical ketoconazole", "Topical triamcinolone", "Topical benzyl benzoate"], "ans": 3, "exp": "ตุ่มน้ำเล็ก ๆ ฝังลึกคล้ายเม็ดสาคู (tapioca) ที่ฝ่ามือ คันมาก = dyshidrotic eczema (pompholyx) -> รักษาด้วย topical corticosteroid (triamcinolone)", "sys": "III"}, {"topic": "Pediatrics", "q": "A 3-year-old boy with painful retraction of the foreskin, no trauma/UTI. After antibiotics he voids fine. Exam: non-retractable foreskin (phimosis) without active inflammation/discharge. Most appropriate next management step?", "choices": ["Reassurance and observation", "Circumcision", "Dorsal slit procedure", "Widening prepuce with arterial clamp", "Topical steroid cream"], "ans": 4, "exp": "physiologic phimosis ในเด็ก -> รักษาด้วย topical corticosteroid cream (เช่น betamethasone) ช่วยให้หนังหุ้มปลายรูดได้ ก่อนพิจารณาผ่าตัด", "sys": "XVIII"}, {"topic": "Pediatrics", "q": "A 2-year-old girl with poor appetite, reduced oral intake, and drooling for 24 hours. Fever 39, HR 120, RR 24. Oropharynx shows hyperemia with yellow-white papulovesicular lesions on the soft palate and uvula. Most appropriate management?", "choices": ["Xylocaine viscous solution", "Oral antibiotics", "Oral acyclovir", "Topical steroid", "Topical acyclovir"], "ans": 0, "exp": "herpangina (ตุ่มน้ำ/แผลที่เพดานอ่อน/ลิ้นไก่ จาก coxsackievirus) -> รักษาประคับประคอง บรรเทาปวดด้วย xylocaine viscous (ไวรัสหายเอง ไม่ให้ antibiotic/acyclovir)", "sys": "IX"}, {"topic": "Pediatrics", "q": "A 10-year-old boy with petechiae on forearms and legs for 3 months, no hepatosplenomegaly/lymphadenopathy. Hb 12, MCV 82, platelet 24,000, WBC 6,500. Smear confirms isolated thrombocytopenia. Most appropriate treatment?", "choices": ["IVIG", "Reassurance", "Platelet transfusion", "Prednisolone", "Pulse methylprednisolone"], "ans": 1, "exp": "immune thrombocytopenia (ITP) ที่มีแค่จ้ำเลือดที่ผิวหนัง (minor bleeding) โดยเม็ดเลือดอื่นปกติ -> แนวทางปัจจุบันเน้นสังเกต (reassurance/observation) รักษาตามอาการเลือดออก ไม่ใช่ตามจำนวนเกล็ดเลือด", "sys": "III"}, {"topic": "Pediatrics", "q": "A 4-year-old with symmetric purpuric bruises on buttocks and lower extremities (shown), no trauma, with abdominal pain. Normal platelet count and coagulation studies. Most appropriate initial test?", "choices": ["PT, APTT", "Stool examination for occult blood", "Urinalysis", "Platelet count", "Bone marrow aspiration"], "ans": 2, "exp": "Henoch-Schonlein purpura (palpable purpura ที่ก้น/ขา + ปวดท้อง เกล็ดเลือด/coag ปกติ) -> ตรวจ urinalysis ประเมินไตอักเสบ", "sys": "III"}, {"topic": "Pediatrics", "q": "A 5-year-old girl with hard 'sausage-like' stools 4-6 times weekly for 3 months, bright red blood on stool surface for a month. Palpable hard feces in LLQ and a fresh anal fissure. No weight loss/vomiting, pain during defecation. Most appropriate initial management?", "choices": ["Oral commercial fiber supplements", "Probiotics", "Lactulose syrup", "Oral polyethylene glycol (PEG)", "Mineral oil enema"], "ans": 3, "exp": "functional constipation + fecal impaction ในเด็ก -> รักษาด้วย oral polyethylene glycol (PEG) เป็น first-line (disimpaction + maintenance)", "sys": "XI"}, {"topic": "Pediatrics", "q": "A newborn with left shoulder dystocia has stable vitals but absent Moro reflex, preserved grasp, 0/5 motor power in the left arm, absent DTR, no clavicular crepitus. Right arm normal. Most useful initial investigation?", "choices": ["Cervical spine MRI", "Cranial ultrasound", "Electromyography (EMG)", "Brachial plexus MRI", "Shoulder X-ray"], "ans": 4, "exp": "Erb's palsy (brachial plexus injury) หลัง shoulder dystocia -> ตรวจ shoulder X-ray เป็นอันดับแรก เพื่อแยกกระดูกไหปลาร้า/ต้นแขนหักที่พบร่วมได้", "sys": "XVI"}, {"topic": "Pediatrics", "q": "A 2-year-old with a giant congenital melanocytic nevus (25 cm) on the posterior trunk, irregular borders and coarse dark hair, grown proportionally, no ulceration/bleeding. Strongest indication for surgical excision?", "choices": ["Size", "Site", "Presence of hair", "Irregular borders", "Rapid progression"], "ans": 0, "exp": "giant congenital melanocytic nevus -> ขนาดใหญ่ (size >20 ซม.) เป็นปัจจัยเสี่ยง melanoma สูงสุด = ข้อบ่งชี้หลักในการตัดออก", "sys": "XVII"}, {"topic": "Pediatrics", "q": "A 2-year-old girl says only 'papa' and 'mama,' follows simple commands, runs steadily, walks up stairs with assistance, engages in social play and eye contact, but uses no 2-word phrases. Normal hearing. Primary developmental concern?", "choices": ["Global developmental delay", "Expressive language delay", "Isolated speech delay", "Gross motor delay", "Autism spectrum disorder"], "ans": 1, "exp": "เข้าใจคำสั่ง (receptive ปกติ) แต่พูดได้น้อยไม่มีวลี 2 คำ ด้านอื่นปกติ + สบตา/เล่นสังคมดี = expressive language delay (ไม่ใช่ ASD)", "sys": "V"}, {"topic": "Pediatrics", "q": "A 12-hour-old infant with moderate HIE who has never urinated. T 36.7, HR 140, RR 50, BP 55/35, generalized hypotonia, symmetric movements, pupils reactive. BUN 16, Cr 1.5, Na 132, K 6.5, Cl 100, HCO3 16. Next critical step in management?", "choices": ["Serum cortisol level", "Renal/bladder ultrasound (U/S KUB)", "Electrocardiogram (EKG)", "Arterial blood gas analysis", "Urinary catheterization"], "ans": 2, "exp": "AKI จาก HIE + hyperkalemia (K 6.5 เป็นค่าอันตราย) -> ขั้นวิกฤตถัดไปคือทำ EKG ประเมินผลของ hyperkalemia ต่อหัวใจ (peaked T, wide QRS) เพื่อรีบรักษา", "sys": "IV"}, {"topic": "Pediatrics", "q": "A 9-year-old with well-controlled asthma develops SOB and chest tightness after exercise, unresponsive to 2 puffs of salbutamol MDI. RR 30, PR 120, SpO2 94%, intercostal/subcostal retractions, bilateral expiratory wheezing, T 37. Next management step?", "choices": ["IV hydrocortisone", "Subcutaneous terbutaline", "Magnesium sulfate infusion", "Nebulized salbutamol", "Nebulized ipratropium bromide"], "ans": 3, "exp": "asthma exacerbation ที่ไม่ตอบสนอง MDI salbutamol -> เพิ่มการนำส่งด้วย nebulized salbutamol (ขนาดสูงกว่า) เป็นขั้นถัดไป (+ systemic steroid)", "sys": "IX"}, {"topic": "Pediatrics", "q": "A 2-day-old exclusively breastfed male (term, Apgar 7/9) with jaundice. Mother O Rh+, HBsAg-negative. Active infant, pulse 128, RR 48. Bilirubin 14, hematocrit 55. Appropriate management?", "choices": ["Exchange transfusion", "Follow-up in 2 days", "Switch to infant formula", "Reinforce breastfeeding frequency", "Phototherapy"], "ans": 4, "exp": "bilirubin 14 mg/dL ที่อายุ 48 ชม. + มารดา O (เสี่ยง ABO) -> plot บน nomogram อยู่ในโซนที่ควรได้ phototherapy", "sys": "XVI"}, {"topic": "Pediatrics", "q": "A 12-year-old with high-grade fever 2 days and altered consciousness today. T 39.5, R 26, P 140, BP 70/40, SpO2 94, capillary refill 3 sec, mottled with palpable purpura all extremities. Most associated complication of this disease?", "choices": ["Adrenal hemorrhage", "Pancreatitis", "Myocarditis", "Gallbladder sludge", "Hepatitis"], "ans": 0, "exp": "meningococcemia (ไข้ + purpura + ช็อก) -> ภาวะแทรกซ้อนที่สัมพันธ์คือ adrenal hemorrhage (Waterhouse-Friderichsen syndrome)", "sys": "III"}, {"topic": "Pediatrics", "q": "A 12-year-old with beta thalassemia/HbE receiving a regular leukocyte-poor red cell transfusion develops fever, chills, and nausea. BT 38, BP 90/60, PR 110, RR 25, no wheezing, soft non-tender abdomen. Most appropriate initial management?", "choices": ["NSS loading", "Transfusion cessation", "Paracetamol oral", "Hydrocortisone IV", "Chlorpheniramine IV"], "ans": 1, "exp": "ปฏิกิริยาจากการให้เลือด (ไข้ หนาวสั่น) -> ขั้นแรกต้องหยุดการให้เลือดทันที (transfusion cessation) แล้วประเมิน/รักษาต่อ", "sys": "III"}, {"topic": "Pediatrics", "q": "A 3-year-old with acute dyspnea and inspiratory stridor after playing with a small toy. RR 24, silent/nonproductive cough, no fever, SpO2 95%, no wheezing/cyanosis, mild intercostal retractions. Most appropriate immediate management?", "choices": ["IM adrenaline", "Endotracheal intubation", "Chest thrust", "Terbutaline nebulization", "Nebulized epinephrine"], "ans": 2, "exp": "สำลักสิ่งแปลกปลอมที่ไอไม่ได้ผล (silent cough) แต่ยังรู้สึกตัว -> ทำ airway clearance maneuver (ในเด็กเล็กใช้ back blows/chest thrust). *ถ้ายังหายใจได้ดีควรหลีกเลี่ยงการทำ maneuver แรง ๆ และรีบส่งส่องหลอดลมนำออก*", "sys": "IV"}, {"topic": "Pediatrics", "q": "A 6-year-old girl with 1 day of fatigue and abdominal pain; 1 month of polyuria, polydipsia, fatigue, 5 kg weight loss. HR 120, RR 30, BP 90/70. Glucose 500, Na 128, ketonuria 1+. Initial management?", "choices": ["Subcutaneous insulin", "Insulin infusion", "3% Saline infusion", "Normal saline (NSS) bolus", "7.5% NaHCO3 infusion"], "ans": 3, "exp": "DKA (เบาหวานชนิดที่ 1 มาใหม่) -> เริ่มด้วยการให้สารน้ำ NSS bolus กู้ปริมาตรก่อน แล้วจึงเริ่ม insulin infusion", "sys": "IV"}, {"topic": "Pediatrics", "q": "A 4,000 g newborn delivered by forceps (Apgar 6/9) received PPV. A mass superior to the posterior fontanelle. MAP 44, no respiratory distress. Most appropriate management?", "choices": ["Ultrasound head", "CT brain", "Percutaneous drainage", "Capillary blood glucose", "Serial hematocrit"], "ans": 4, "exp": "ก้อนที่ข้าม/เหนือกระหม่อม (subgaleal hemorrhage) เสี่ยงเสียเลือดมาก -> ติดตาม serial hematocrit เฝ้าระวังภาวะโลหิตจาง/ช็อก", "sys": "XVI"}, {"topic": "Pediatrics", "q": "A 20-year-old with epilepsy on phenytoin stops medication and presents with an ongoing generalized tonic-clonic seizure, unresponsive with tonic-clonic movements. Most appropriate immediate treatment?", "choices": ["Lorazepam", "Diazepam", "Phenytoin", "Levetiracetam", "Phenobarbital"], "ans": 0, "exp": "active seizure/status epilepticus -> ยาชุดแรกคือ benzodiazepine; IV lorazepam เป็นตัวเลือกที่นิยม (ออกฤทธิ์นานกว่า diazepam)", "sys": "VI"}, {"topic": "Pediatrics", "q": "A term newborn (4 kg) delivered by vacuum extraction (Apgar 6/9) received PPV once. A cephalohematoma is palpated superior to the posterior fontanelle. Most appropriate investigation?", "choices": ["Capillary blood glucose", "Serial hematocrit", "Ultrasound cranial", "Fine-needle aspiration", "Serum creatinine"], "ans": 1, "exp": "ก้อนที่เหนือกระหม่อม/ข้าม suture (subgaleal hemorrhage) -> ตรวจ serial hematocrit เฝ้าระวังการเสียเลือด", "sys": "XVI"}, {"topic": "Pediatrics", "q": "A 25-day-old exclusively breastfed newborn with jaundice since day 5, passing yellow stools, normal weight gain. Generalized jaundice without hepatosplenomegaly/pallor. Total bilirubin 18, direct 0.3 (unconjugated), Hb 14, normal liver enzymes. Most appropriate management?", "choices": ["Phototherapy", "Double phototherapy", "Reassure and continue breastfeeding", "Total exchange transfusion", "Switch to infant formula"], "ans": 2, "exp": "prolonged unconjugated jaundice ในทารกกินนมแม่ที่น้ำหนักขึ้นดี ไม่มี hemolysis/ตับผิดปกติ = breast milk jaundice -> reassure และให้นมแม่ต่อ", "sys": "XVI"}, {"topic": "Pediatrics", "q": "A 3,000 g neonate delivered by cesarean for non-reassuring fetal status, HR 80, hypotonia, poor respiratory effort. After drying and stimulation, HR remains 80. Next step in resuscitation?", "choices": ["Endotracheal intubation", "Inotropes", "Antibiotics", "Positive-pressure ventilation with face mask", "Chest compressions"], "ans": 3, "exp": "HR <100 หลัง initial steps -> เริ่ม positive-pressure ventilation ด้วย face mask (ขั้นตอน NRP)", "sys": "XV"}, {"topic": "Pediatrics", "q": "An 8-month-old girl with high-grade fever and a generalized maculo-erythematous scarlatiniform rash prominent around the mouth, previously treated with aspirin. No mucosal involvement or desquamation. Rash is sandpaper-like and confluent. Most likely diagnosis?", "choices": ["Staphylococcal scalded skin syndrome (SSSS)", "Seborrheic dermatitis", "Bullous impetigo", "Stevens-Johnson syndrome (SJS)", "Scarlet fever"], "ans": 4, "exp": "ผื่นแดงหยาบเหมือนกระดาษทราย (sandpaper) กระจายทั่ว = scarlet fever (จาก group A streptococcus toxin). *อ้างอิงภาพ*", "img": "https://cdn.jsdelivr.net/gh/MercenzK/Web-quiz-images@main/NL2-2025-Apr-Q120.png", "sys": "I"}, {"topic": "Pediatrics", "q": "A 4-month-old for routine vaccination developed fever after the previous DTwP-HB-Hib vaccine. Today scheduled for OPV, rotavirus, HB, and Hib. Afebrile and well. What additional vaccine should be administered?", "choices": ["DTaP", "Reassure (no additional vaccine)", "DTwP", "DTwP + IPV", "DTaP + IPV"], "ans": 0, "exp": "เคยมีไข้หลัง DTwP (whole-cell pertussis) ซึ่งเป็นปฏิกิริยาเล็กน้อย -> เปลี่ยนเป็น DTaP (acellular, ปฏิกิริยาน้อยกว่า) และต้องให้ในนัดนี้ (รายการที่ระบุขาดส่วน DTP)", "sys": "flex"}, {"topic": "Pediatrics", "q": "A term newborn (4,000 g) delivered by vacuum, Apgar 6/9, required PPV once. At 1 hour a fluctuant mass superior to the posterior fontanelle. HR 150, RR 48, MAP 44. Proper management?", "choices": ["Serum creatinine", "Serial hematocrit", "Cranial ultrasound", "Capillary blood glucose", "Needle aspiration of the mass"], "ans": 1, "exp": "subgaleal hemorrhage (ก้อนนุ่มข้ามกระหม่อมหลังคลอด vacuum) -> ติดตาม serial hematocrit เฝ้าระวังการเสียเลือด (ห้ามเจาะดูด)", "sys": "XVI"}, {"topic": "Pediatrics", "q": "A newborn delivered by elective cesarean at 36 weeks develops tachypnea at 48 hours. HR 120, RR 65, nasal flaring, mild subcostal retractions. CXR shows bilateral interstitial infiltrates and mild hyperinflation. No fever/cyanosis. Most appropriate management?", "choices": ["Endotracheal intubation", "Intravenous antibiotics", "Nasal CPAP", "Oxygen supplementation", "Surfactant replacement therapy"], "ans": 2, "exp": "transient tachypnea of newborn (C/S + CXR interstitial/hyperinflation) ที่มี work of breathing เพิ่ม (flaring, retraction) -> nasal CPAP ช่วยลดงานการหายใจ", "sys": "XV"}, {"topic": "Pediatrics", "q": "An 8-month-old boy with a generalized sandpaper-like maculoerythematous rash, prominent perioral and flexural, received acetaminophen 2 days prior. No mucosal lesions or systemic symptoms. Most likely diagnosis?", "choices": ["Stevens-Johnson syndrome (SJS)", "Staphylococcal scalded skin syndrome (SSSS)", "Drug reaction with eosinophilia (DRESS)", "Scarlet fever", "Kawasaki disease"], "ans": 3, "exp": "ผื่นหยาบเหมือนกระดาษทราย + เด่นตามข้อพับ (Pastia's lines) = scarlet fever", "sys": "I"}, {"topic": "Pediatrics", "q": "A 9-year-old with well-controlled asthma (on low-dose ICS) develops wheezing and dyspnea after soccer. Used 2 puffs of albuterol 15 minutes ago without improvement. No fever/URI. Next step?", "choices": ["Administer oral prednisone", "Administer ipratropium nebulizer", "Administer epinephrine IM", "Obtain chest X-ray", "Repeat albuterol 2 puffs"], "ans": 4, "exp": "asthma exacerbation ที่ยังไม่ดีขึ้นหลัง SABA ครั้งแรก -> ให้ SABA ซ้ำได้ (repeat albuterol) เป็นขั้นถัดไป", "sys": "X"}, {"topic": "Pediatrics", "q": "A 14-year-old girl with 2 days of fever (40), purpuric rash, and lethargy. Hb 7.2, WBC 2,400 (54% N, 14% atypical lymphocytes), platelets 18,000, prolonged PT/PTT. Peripheral smear shows schistocytes. Cause of the hemostatic defect?", "choices": ["Disseminated intravascular coagulation", "Aplastic anemia", "Acute leukemia", "Dysfibrinogenemia", "Vitamin K deficiency"], "ans": 0, "exp": "เกล็ดเลือดต่ำ + PT/PTT ยาว + schistocyte (microangiopathy) + purpura = disseminated intravascular coagulation (DIC)", "sys": "II"}, {"topic": "Pediatrics", "q": "A term newborn boy with an undescended right testicle, empty right scrotum, and a movable oval mass in the right inguinal canal. Left testis normal. Most appropriate management?", "choices": ["Orchidopexy", "Follow-up", "Ultrasound abdomen", "Chromosome study", "Hormonal therapy"], "ans": 1, "exp": "cryptorchidism แบบคลำได้ในขาหนีบในทารกแรกเกิด -> ติดตาม (อัณฑะมักเลื่อนลงเองภายใน 6 เดือน) ถ้ายังไม่ลงจึงผ่าตัด orchidopexy", "sys": "XVI"}, {"topic": "Pediatrics", "q": "A 16-hour-old newborn with moderate HIE and no urine output. Stable vitals, hypotonia. BUN 16, Cr 1.5, Na 132, K 6.5. Most appropriate management?", "choices": ["Serum cortisol", "Ultrasound KUB", "EKG", "ABG", "Urinary catheterization"], "ans": 2, "exp": "AKI จาก HIE + hyperkalemia (K 6.5) -> ทำ EKG ประเมินผลต่อหัวใจ (peaked T/wide QRS) เพื่อรีบจัดการ hyperkalemia", "sys": "XVI"}, {"topic": "Pediatrics", "q": "A 17-year-old male with fever, sore throat, and generalized lymphadenopathy for 10 days. Enlarged cervical, axillary, and inguinal nodes. Smear shows atypical lymphocytes (Downey cells). Spleen non-palpable. Most likely cause?", "choices": ["Cytomegalovirus (CMV)", "Toxoplasmosis", "Acute HIV infection", "Epstein-Barr virus (EBV)", "Hodgkin lymphoma"], "ans": 3, "exp": "infectious mononucleosis (ไข้ เจ็บคอ ต่อมน้ำเหลืองโตทั่ว + atypical lymphocyte/Downey cell) = Epstein-Barr virus", "sys": "II"}, {"topic": "Pediatrics", "q": "A 15-year-old girl with a neck mass for 3 months, no thyroid symptoms. Symmetric non-tender thyroid enlargement, no nodules/exophthalmos. FT4 1.2 (normal), TSH 2.5 (normal), anti-TPO 150 (elevated). Diagnosis?", "choices": ["Simple goiter", "Graves' disease", "Multinodular goiter", "Subacute thyroiditis", "Hashimoto thyroiditis"], "ans": 4, "exp": "คอพอกโตทั่ว euthyroid + anti-TPO สูง = Hashimoto (chronic autoimmune) thyroiditis", "sys": "II"}, {"topic": "Pediatrics", "q": "A 6-month-old with high fever (39.5) followed by a generalized maculopapular rash 24 hours later (as the fever subsides). Rash spares palms/soles, infant irritable but alert, no mucosal lesions or lymphadenopathy. Most likely diagnosis?", "choices": ["Roseola infantum", "Kawasaki disease", "Drug reaction", "Measles", "Scarlet fever"], "ans": 0, "exp": "ไข้สูง 3-4 วันแล้วผื่นขึ้นเมื่อไข้ลด ในเด็กเล็ก = roseola infantum (HHV-6). (paracetamol เป็นตัวลวง ไม่ใช่ drug reaction)", "sys": "I"}, {"topic": "Pediatrics", "q": "A 3-year-old hospitalized for pneumonia develops a seizure after 3 days of IV D5NS maintenance. No dehydration. Na 122, K 3.5, Cl 90, HCO3 22. Urine SG 1.028 (high), urine Na 80 (high). Most likely diagnosis?", "choices": ["Reset osmostat", "SIADH", "Diabetes insipidus (DI)", "Cerebral salt wasting", "Hypovolemic hyponatremia"], "ans": 1, "exp": "hyponatremia + euvolemic + urine เข้มข้น (SG สูง) + urine Na สูง ในผู้ป่วยปอดอักเสบ = SIADH", "sys": "IV"}, {"topic": "Pediatrics", "q": "A child with recurrent ecchymosis and 13% eosinophilia. Peripheral smear suggests acute promyelocytic leukemia (APL). No fever/trauma. Next best investigation?", "choices": ["PT/PTT", "von Willebrand factor assay", "Bone marrow biopsy", "Stool examination for parasites", "Factor VIII assay"], "ans": 2, "exp": "สงสัย acute promyelocytic leukemia -> ยืนยันด้วย bone marrow biopsy (และตรวจ PT/PTT ประเมิน DIC ที่มักร่วม)", "sys": "II"}, {"topic": "Pediatrics", "q": "A 4-year-old girl with poor night vision and follicular hyperkeratosis on elbows/knees. Weight 10 kg (3rd percentile). Ocular exam shows Bitot's spots. Most appropriate test?", "choices": ["Skin biopsy", "Ocular tonometry", "Electroencephalogram", "Serum retinol level", "Slit-lamp exam"], "ans": 3, "exp": "ตาบอดกลางคืน + Bitot's spots + follicular hyperkeratosis = vitamin A deficiency -> ตรวจ serum retinol. *อ้างอิงภาพ*", "img": "https://cdn.jsdelivr.net/gh/MercenzK/Web-quiz-images@main/NL2-2025-Apr-Q134.png", "sys": "XIII"}, {"topic": "Pediatrics", "q": "A 15-year-old with fever, headache, polyarthralgia, a maculopapular rash on trunk/extremities, and swollen hands/feet. WBC 5,500, platelets 156,000. Most useful diagnostic test?", "choices": ["Rubella IgM", "Measles IgM", "Scrub typhus IgM", "Dengue IgM/IgG", "Chikungunya IgM"], "ans": 4, "exp": "ไข้ + ปวด/บวมข้อมือข้อเท้ารุนแรง + ผื่น = chikungunya (เด่นเรื่องปวดข้อ) -> ตรวจ chikungunya IgM", "sys": "I"}, {"topic": "Pediatrics", "q": "A 10-year-old boy with headache, 'pink urine,' periorbital edema, non-pitting leg edema. BP 140/90. UA: SG 1.025, protein 1+, RBC >100/hpf. BUN 25, creatinine 0.6. Most useful test for diagnosis?", "choices": ["ASO titer", "Serum IgA level", "ANA", "24-hour urine protein", "Serum cholesterol/albumin"], "ans": 0, "exp": "nephritic syndrome (ปัสสาวะเป็นเลือด + บวม + ความดันสูง) = post-streptococcal GN -> ตรวจ ASO titer ยืนยันการติดเชื้อ strep", "sys": "VI"}, {"topic": "Pediatrics", "q": "A term newborn (3,000 g) delivered by C-section with immediate respiratory distress. Scaphoid abdomen, decreased left breath sounds, HR 150, mild cyanosis. Most appropriate initial management?", "choices": ["Abdominal X-ray", "Endotracheal intubation", "IV furosemide", "Positive pressure ventilation", "Needle thoracostomy"], "ans": 1, "exp": "congenital diaphragmatic hernia (scaphoid abdomen + เสียงหายใจซ้ายลด + distress) -> ใส่ท่อช่วยหายใจ (ETT) + NG decompression; ห้าม bag-mask PPV (ทำให้ลำไส้โป่ง)", "sys": "XV"}, {"topic": "Pediatrics", "q": "A 5-year-old with 3 months of cervical lymphadenopathy and progressive dyspnea. Facial plethora, JVD, upper limb edema, stridor, sternal retractions. Stable vitals. Initial management?", "choices": ["Start chemotherapy", "IV furosemide", "IV dexamethasone", "Emergency radiotherapy", "Emergency thoracotomy"], "ans": 2, "exp": "superior mediastinal/SVC syndrome จากก้อน mediastinum (lymphoma) ที่กดทางเดินหายใจ -> ให้ IV dexamethasone ลดขนาดก้อน/บวมอย่างเร็ว (lymphoma ตอบสนอง steroid) ก่อนการรักษาจำเพาะ", "sys": "II"}, {"topic": "Pediatrics", "q": "A 10-year-old girl with weight loss, tremors, palpitations, heat intolerance 3 months. Suppressed TSH and elevated free T4, diffuse goiter, no ophthalmopathy. First-line long-term pharmacological treatment?", "choices": ["Propylthiouracil (PTU)", "Potassium iodine", "Radioactive iodine ablation", "Methimazole (MMI)", "Near-total thyroidectomy"], "ans": 3, "exp": "hyperthyroidism ในเด็ก -> first-line คือ methimazole (MMI); หลีกเลี่ยง PTU เพราะพิษต่อตับ", "sys": "IV"}, {"topic": "Pediatrics", "q": "A 10-year-old boy with abrupt pallor and jaundice 2 days after a febrile sore throat. Moderate pharyngeal injection, mild scleral icterus, no hepatosplenomegaly. Hb 7 (MCV 90), platelets 180,000. Smear shows spherocytes and polychromasia. Most useful investigation?", "choices": ["Hemoglobin typing", "G6PD level", "Urine analysis", "Osmotic fragility test", "Direct Coombs test"], "ans": 4, "exp": "เม็ดเลือดแดงแตกเฉียบพลันหลังติดเชื้อ + spherocyte + polychromasia (reticulocytosis) = autoimmune hemolytic anemia -> ตรวจ direct Coombs test (แยกจาก hereditary spherocytosis)", "sys": "III"}, {"topic": "Pediatrics", "q": "A 10-year-old boy with a 2-week itchy rash on his chest. A 4 cm erythematous plaque with a scaly border and central clearing. No vesicles/pustules. Most appropriate treatment?", "choices": ["Clotrimazole cream", "Acyclovir cream", "Trimethoprim cream", "Mupirocin cream", "Triamcinolone cream"], "ans": 0, "exp": "ผื่นวงแดงขอบเป็นขุย ตรงกลางใส (central clearing) = tinea corporis (กลาก) -> รักษาด้วยยาทาฆ่าเชื้อรา clotrimazole", "sys": "XII"}, {"topic": "Pediatrics", "q": "A 3-year-old boy recently treated for UTI presents with acute urinary retention. Phimosis without erythema/discharge. Bladder distended, anxious. Immediate management?", "choices": ["Reassurance and observation", "Urethral catheterization", "Topical steroid cream", "Emergency circumcision", "Antibiotics"], "ans": 1, "exp": "acute urinary retention + กระเพาะปัสสาวะโป่ง -> ระบายปัสสาวะด้วย urethral catheterization ทันที", "sys": "XII"}, {"topic": "Pediatrics", "q": "An 8-month-old boy with erythematous, scaly plaques on bilateral elbows and knees for 2 months, itchy with excoriation and lichenification. Diaper area spared. Maternal eczema. Most likely diagnosis?", "choices": ["Psoriasis", "Scabies", "Atopic dermatitis", "Contact dermatitis", "Tinea corporis"], "ans": 2, "exp": "ผื่นคันเรื้อรัง lichenified + เว้นบริเวณผ้าอ้อม + ประวัติภูมิแพ้ในครอบครัว = atopic dermatitis", "sys": "XII"}, {"topic": "Pediatrics", "q": "A 25-day-old term male (birth weight 3,000 g, now 3,600 g) with parental concern about jaundice. Mild scleral icterus, otherwise normal, appropriate development, breastfeeding established. Appropriate management?", "choices": ["Reassurance only", "Phototherapy", "Liver function tests", "Serum bilirubin level", "Thyroid function tests"], "ans": 3, "exp": "prolonged jaundice (>2 สัปดาห์) -> ควรตรวจ serum bilirubin (แยก total/direct) เพื่อประเมินและแยก cholestasis/biliary atresia ก่อน reassure", "sys": "XVI"}, {"topic": "Pediatrics", "q": "A 1-year-old boy with barky cough, inspiratory stridor, and mild expiratory wheezing for 2 days, worse at night, afebrile, no drooling/toxicity. Most effective method to prevent recurrence?", "choices": ["Influenza vaccination", "Frequent hand washing", "Wearing face masks in public", "Breastfeeding", "Avoiding tobacco smoke"], "ans": 4, "exp": "croup มักเป็นซ้ำและสัมพันธ์กับการระคายเคืองทางเดินหายใจ -> หลีกเลี่ยงควันบุหรี่ (tobacco smoke) ช่วยลดการกำเริบซ้ำ", "sys": "I"}, {"topic": "Pediatrics", "q": "A 2-year-old boy says 'papa' and 'mama' meaningfully, waves 'bye-bye,' and walks independently, but cannot stack 2 blocks, point to body parts, or follow simple commands. How is his development classified?", "choices": ["Global developmental delay", "Normal development", "Isolated speech delay", "Motor delay", "Autism spectrum disorder"], "ans": 0, "exp": "บกพร่องหลายด้าน (fine motor: ต่อบล็อกไม่ได้; ภาษา receptive: ทำตามคำสั่งไม่ได้; cognitive) = global developmental delay", "sys": "V"}, {"topic": "Pediatrics", "q": "A 7-year-old with uncomplicated influenza and no risk factors for severe disease. Most appropriate management?", "choices": ["Favipiravir", "Supportive care", "Oseltamivir", "Acyclovir", "Amoxicillin"], "ans": 1, "exp": "influenza ที่ไม่มีภาวะแทรกซ้อน/ปัจจัยเสี่ยง -> รักษาประคับประคอง (supportive care); oseltamivir สงวนไว้กรณีรุนแรง/เสี่ยงสูง", "sys": "I"}, {"topic": "Pediatrics", "q": "A 1-month-old with a progressively enlarging, rubbery scalp mass since birth, non-tender, with overlying skin discoloration. Most likely diagnosis?", "choices": ["Lipoma", "Neurofibroma", "Infantile hemangioma", "Epidermal inclusion cyst", "Sebaceous cyst"], "ans": 2, "exp": "ก้อนนุ่มโตขึ้นเรื่อย ๆ ตั้งแต่แรกเกิด + ผิวเปลี่ยนสี = infantile hemangioma", "sys": "II"}, {"topic": "Pediatrics", "q": "A 6-year-old boy with a right knee injury playing soccer, with knee swelling and a positive ballottement test. No bleeding diathesis. Most likely diagnosis?", "choices": ["Septic arthritis", "Osteochondritis dissecans", "Meniscal tear", "Hemarthrosis", "Ligament sprain"], "ans": 3, "exp": "ข้อเข่าบวมเฉียบพลันหลังบาดเจ็บ + ballottement บวก (มีน้ำ/เลือดในข้อ) = hemarthrosis", "sys": "XIII"}, {"topic": "Pediatrics", "q": "A 6-year-old with pneumonia treated with ceftriaxone 4 days, improved but still febrile (38.5). New left pleural effusion. Thoracentesis: pH 7.1, glucose 47, LDH 400, no organisms. Most appropriate management?", "choices": ["Add vancomycin", "Change to ceftazidime", "Change to meropenem", "Continue ceftriaxone and observe", "Intercostal chest drainage"], "ans": 4, "exp": "complicated parapneumonic effusion/empyema (pH <7.2, glucose ต่ำ) -> ใส่ท่อระบายทรวงอก (intercostal chest drainage)", "sys": "X"}, {"topic": "Pediatrics", "q": "A term newborn delivered vaginally with shoulder dystocia has absent Moro and DTR in the left arm, intact grasp, motor power 0/5. Most useful initial investigation?", "choices": ["Shoulder X-ray", "Serial hematocrit", "Cranial ultrasound", "Cervical spine MRI", "Nerve conduction velocity"], "ans": 0, "exp": "Erb's palsy หลัง shoulder dystocia -> shoulder X-ray แยกกระดูกไหปลาร้า/ต้นแขนหักก่อน", "sys": "XVI"}, {"topic": "Pediatrics", "q": "A 10-year-old boy with fever for 1 week, then transient ankle pain resolving after 3 days, now knee pain with a non-pruritic, non-tender rash on his arms. Migratory arthritis and erythematous papules. No recent GI/GU infection. Most likely diagnosis?", "choices": ["Juvenile rheumatoid arthritis (JRA)", "Rheumatic fever", "Infective endocarditis", "Reactive arthritis", "Lyme disease"], "ans": 1, "exp": "migratory polyarthritis (ข้อเท้าย้ายมาเข่า) + ผื่น (erythema marginatum) หลังไข้/คออักเสบ = acute rheumatic fever", "sys": "IX"}, {"topic": "Pediatrics", "q": "A 2-month-old with a staccato cough for 2 weeks, bilateral conjunctivitis, and no fever. CXR shows patchy infiltrates in both lower lobes. Most appropriate treatment?", "choices": ["Oseltamivir", "Ceftriaxone", "Azithromycin", "Gentamicin", "Amoxicillin"], "ans": 2, "exp": "afebrile pneumonia ในทารก + staccato cough + conjunctivitis = Chlamydia trachomatis pneumonia -> รักษาด้วย macrolide (azithromycin)", "sys": "VII"}, {"topic": "Pediatrics", "q": "A 6-year-old Thai boy with acute fever and dyspnea. Hb 5 g/dL, normal WBC/platelets. Immediate management?", "choices": ["Folic acid", "Hemoglobin electrophoresis", "G6PD testing", "Blood transfusion", "IV fluids"], "ans": 3, "exp": "ซีดรุนแรง (Hb 5) + หายใจเหนื่อย (มีอาการ/heart failure) -> ให้เลือด (blood transfusion) ทันที. *อ้างอิงภาพ*", "img": "https://cdn.jsdelivr.net/gh/MercenzK/Web-quiz-images@main/NL2-2025-Apr-Q154.png", "sys": "III"}, {"topic": "Pediatrics", "q": "A 5-year-old with a soft, non-tender scalp mass since birth, 2 cm erythematous compressible lesion (infantile hemangioma), no ulceration or functional impairment. Next step?", "choices": ["Oral propranolol", "Surgical excision", "Topical timolol", "Systemic corticosteroids", "Reassurance and observation"], "ans": 4, "exp": "infantile hemangioma ที่ไม่มีภาวะแทรกซ้อน (ไม่แผล ไม่กีดขวางการทำงาน) -> reassurance และสังเกต (ส่วนใหญ่ยุบเองตามอายุ)", "sys": "II"}, {"topic": "Pediatrics", "q": "A term neonate develops generalized spasticity 24 hours after birth. T 37, HR 140, RR 50. WBC 12,000 (neutrophils 90%), blood glucose 21. No maternal fever or PROM. Most appropriate immediate management?", "choices": ["IV antibiotics + glucose infusion", "NSS IV bolus", "IV antibiotics", "10% dextrose IV infusion", "Lumbar puncture"], "ans": 0, "exp": "ทารกชัก/เกร็ง + hypoglycemia (glucose 21) + neutrophil สูง (อาจ sepsis) -> ให้กลูโคสแก้ hypoglycemia ร่วมกับยาปฏิชีวนะคลุม sepsis", "sys": "XVI"}, {"topic": "Pediatrics", "q": "A 2-year-old boy with 4 weeks of painful defecation, hard stools, and anal fissures. Avoids bowel movements. Low-fiber diet. Most appropriate initial management?", "choices": ["High-fiber diet and increased fluids", "Polyethylene glycol", "Topical lidocaine ointment", "Mineral oil (stool softener)", "Surgical fissure repair"], "ans": 1, "exp": "functional constipation ที่มี fissure + กลั้นอุจจาระ (withholding) -> ต้องทำให้อุจจาระนุ่มด้วย osmotic laxative (polyethylene glycol) เพื่อตัดวงจรเจ็บ-กลั้น ร่วมกับปรับอาหาร", "sys": "XI"}, {"topic": "Pediatrics", "q": "A 15-year-old boy with acute fever, headache, polyarthralgia, bilateral conjunctival redness, swollen erythematous wrists and knees, in a mosquito-endemic rural area. Most appropriate initial serologic test?", "choices": ["Dengue virus IgM", "Rubella virus IgM", "Chikungunya virus IgM", "Scrub typhus IgM", "Blood culture"], "ans": 2, "exp": "ไข้ + ปวด/บวมข้อรุนแรง + conjunctival injection ในพื้นที่ยุงชุก = chikungunya -> ตรวจ chikungunya IgM", "sys": "I"}, {"topic": "Pediatrics", "q": "A 4-year-old boy with generalized edema for 7 days (puffy eyelids, pretibial edema, ascites). Stable vitals. UA protein 4+, SG 1.025. Serum albumin 2.0. Most appropriate initial management?", "choices": ["20% albumin infusion", "Furosemide IV", "Fluid restriction", "Prednisolone oral", "Renal biopsy"], "ans": 3, "exp": "nephrotic syndrome ในเด็ก (มักเป็น minimal change disease) ที่ vital signs คงที่ -> เริ่มการรักษาด้วย corticosteroid (prednisolone). albumin/furosemide สงวนไว้กรณีบวมรุนแรง/hypovolemia", "sys": "XI"}, {"topic": "Pediatrics", "q": "A 3-month-old breastfed infant with dyspnea and tachypnea for 2 days. Mother fed him sticky rice and fish. T 37, P 160, RR 60, bilateral fine crepitations, liver 4 cm below costal margin. CXR shows cardiomegaly and pulmonary congestion. Most likely diagnosis?", "choices": ["Myocarditis", "Dilated cardiomyopathy", "Pericardial effusion", "Congenital heart disease", "Thiamine deficiency (infantile beriberi)"], "ans": 4, "exp": "ทารกกินนมแม่ที่แม่กินอาหารขาด thiamine (ข้าวเหนียว/ปลา) + หัวใจล้มเหลว (cardiomegaly, ตับโต) = infantile beriberi (ขาด vitamin B1) -> รักษาด้วย thiamine", "sys": "XVII"}, {"topic": "Pediatrics", "q": "A 4-year-old unvaccinated child with fever, cough, coryza, and conjunctivitis. Koplik spots on oral exam. Diagnosis?", "choices": ["Measles", "Rubella", "Scarlet fever", "Hand-foot-mouth disease", "Roseola"], "ans": 0, "exp": "3 C's (cough, coryza, conjunctivitis) + Koplik spots = measles (โรคหัด)", "sys": "I"}, {"topic": "Pediatrics", "q": "A 14-year-old boy with dry, dark patches in the axillae and neck. BMI 25. Fasting glucose 250, HbA1c 7.5%. Most appropriate pharmacologic management?", "choices": ["Glipizide", "Metformin", "Insulin injection", "Lifestyle modification only", "Liraglutide"], "ans": 1, "exp": "acanthosis nigricans + อ้วน + เบาหวานชนิดที่ 2 ในวัยรุ่น -> ยา first-line คือ metformin (ร่วมกับปรับพฤติกรรม)", "sys": "flex"}, {"topic": "Pediatrics", "q": "A 10-year-old boy with abnormal gait for 5 days, preceded by a URI 2 weeks ago. Hypotonia, motor strength grade 3 in both legs, decreased pain sensation in hands and feet. Most appropriate initial investigation?", "choices": ["CT brain", "MRI spine", "Lumbar puncture (CSF analysis)", "Serum creatine kinase", "Nerve conduction study"], "ans": 2, "exp": "Guillain-Barre syndrome (อ่อนแรงขึ้น + areflexia หลัง URI) -> ตรวจ CSF พบ albuminocytologic dissociation (โปรตีนสูง เซลล์ปกติ)", "sys": "VI"}, {"topic": "Pediatrics", "q": "A home-delivered newborn developed trismus and muscle spasms at day 7. Umbilical cord cut with unsterile scissors. Antibiotics were started for tetanus. What additional treatment is essential?", "choices": ["Tetanus toxoid", "Tetanus immunoglobulin (TIG)", "Tetanus toxoid + DTaP", "Tetanus toxoid + TIG", "Supportive care only"], "ans": 3, "exp": "neonatal tetanus -> ต้องให้ tetanus immunoglobulin (TIG) ลบล้าง toxin ที่ยังไม่จับ ร่วมกับ tetanus toxoid สร้างภูมิคุ้มกัน (การติดเชื้อไม่ทำให้เกิดภูมิ) = toxoid + TIG", "sys": "XVI"}, {"topic": "Pediatrics", "q": "A 3-year-old hospitalized for pneumonia develops a seizure on day 3 while on IV D5NS. T 37, pulse 100, RR 28, BP 90/60. Na 122, glucose 65, calcium 8.5, urine SG 1.028, urine sodium 80. Diagnosis?", "choices": ["Diabetes insipidus", "Decreased sodium intake", "Acute tubular necrosis", "Reset osmostat", "SIADH"], "ans": 4, "exp": "hyponatremia + euvolemic + urine เข้มข้น (SG สูง) + urine Na สูง ในผู้ป่วยปอดอักเสบ = SIADH", "sys": "IV"}, {"topic": "Obstetrics & Gynecology", "q": "A 38-year-old woman with progressive dysmenorrhea. Palpable left cystic mass, tender nodule at cul-de-sac. Pelvic ultrasound: 6 cm hypoechoic cystic left adnexal mass. Most likely diagnosis?", "choices": ["Endometriosis", "Dermoid cyst", "Paratubular cyst", "Functional cyst", "Serous cystadenoma"], "ans": 0, "exp": "ปวดประจำเดือนมากขึ้น + ก้อนถุงน้ำที่ปีกมดลูก + nodule เจ็บที่ cul-de-sac = endometriosis/endometrioma", "sys": "XIV"}, {"topic": "Obstetrics & Gynecology", "q": "A G1P0 at 34 weeks with 4 hours of labor pain, no discharge, BP 120/70, contractions every 5 min for 60 sec. Cervix 5 cm/100% effaced, intact membranes, cephalic. Most appropriate next step?", "choices": ["Administer a tocolytic agent", "Administer dexamethasone", "Perform amniotomy", "Initiate oxytocin", "Observe labor progression"], "ans": 1, "exp": "preterm labor ที่ 34 สัปดาห์ + ปากมดลูกเปิด 5 ซม. (active, ยับยั้งไม่ได้แล้ว) -> ให้ dexamethasone เร่งปอดทารก (ให้ได้ถึง 34 สัปดาห์) + GBS prophylaxis แล้วปล่อยคลอด", "sys": "XV"}, {"topic": "Obstetrics & Gynecology", "q": "A 30-year-old woman 2 weeks postpartum with fever and right breast pain. Erythema, warmth, tenderness, and a 5-cm fluctuant area in the upper quadrant. T 38.5, breastfeeding. Apart from antibiotics, most appropriate management?", "choices": ["Aspiration", "Warm compression", "Incision and drainage (I&D)", "Cold compression", "Stop breastfeeding"], "ans": 2, "exp": "breast abscess (ก้อน fluctuant 5 ซม.) -> นอกจากยาปฏิชีวนะ ต้องระบายหนองด้วย incision and drainage (I&D) (ก้อนใหญ่); ก้อนเล็กอาจใช้ needle aspiration", "sys": "XV"}, {"topic": "Obstetrics & Gynecology", "q": "An 18-year-old with vaginal discharge, no fever/pelvic pain. Microscopy: abundant PMNs, intracellular gram-negative diplococci, and scattered gram-positive cocci/coccobacilli. Most appropriate treatment?", "choices": ["Ceftriaxone", "Metronidazole", "Amoxicillin-clavulanate", "Metronidazole + ceftriaxone", "Metronidazole + doxycycline"], "ans": 3, "exp": "gram-negative diplococci ในเซลล์ = gonorrhea (รักษาด้วย ceftriaxone) + coccobacilli/mixed flora บ่ง bacterial vaginosis (รักษาด้วย metronidazole) -> metronidazole + ceftriaxone", "sys": "XIV"}, {"topic": "Obstetrics & Gynecology", "q": "A 29-year-old primigravida at 32 weeks with severe headache and blurred vision for 24 hours. BP 160/100, 3+ proteinuria. Cervix 2 cm/50%, regular contractions every 4 min, progressive facial edema. Most appropriate initial management?", "choices": ["Tocolytic therapy (e.g., nifedipine)", "Oxytocin augmentation", "Immediate cesarean section", "Labetalol IV bolus", "Intravenous magnesium sulfate"], "ans": 4, "exp": "severe preeclampsia ที่มีอาการทางระบบประสาท (ปวดหัว ตามัว) -> ให้ IV magnesium sulfate ป้องกันชัก (eclampsia) เป็นอันดับแรก ร่วมกับยาลดความดัน", "sys": "XV"}, {"topic": "Obstetrics & Gynecology", "q": "A 20-year-old with LMP 6 weeks ago presents with RLQ pain, tenderness, and vaginal bleeding. Urine pregnancy test positive. Most appropriate investigation?", "choices": ["Transvaginal ultrasound", "Repeat urine pregnancy test", "Serum beta hCG", "Complete blood count", "Serum progesterone"], "ans": 0, "exp": "สงสัย ectopic (ปวดท้องน้อย + เลือดออก + UPT บวก) -> ทำ transvaginal ultrasound หาตำแหน่งการตั้งครรภ์", "sys": "XV"}, {"topic": "Obstetrics & Gynecology", "q": "A 30-year-old with PID 2 months ago presents with 1 day of RLQ pain and rebound tenderness. LMP 6 weeks ago, no GI/GU symptoms. Next investigation?", "choices": ["Urinalysis", "Serum beta hCG", "KUB X-ray", "CT abdomen", "Pelvic ultrasound"], "ans": 1, "exp": "หญิงวัยเจริญพันธุ์ + ประจำเดือนขาด (LMP 6 สัปดาห์) + ปวดท้องน้อย -> ตรวจ serum beta-hCG ก่อน แยก ectopic pregnancy", "sys": "XV"}, {"topic": "Obstetrics & Gynecology", "q": "A 20-year-old primigravida at 38 weeks with fever (38.5) and foul-smelling vaginal discharge, ROM 24 hours prior. Cervix 5 cm/80%, station 0, FHR 150, contractions. Most appropriate management?", "choices": ["Cesarean section", "Group B Strep prophylaxis", "Broad-spectrum IV antibiotics", "Oxytocin augmentation", "Continue fetal monitoring"], "ans": 2, "exp": "chorioamnionitis (ไข้ + น้ำเดินนาน + ตกขาวเหม็น) -> ให้ broad-spectrum IV antibiotics และดำเนินการคลอด", "sys": "XV"}, {"topic": "Obstetrics & Gynecology", "q": "A 30-year-old primigravida at 39 weeks in second stage. Contractions every 3 min for 50 sec. Cervix fully dilated, station +1, cephalic, FHR reassuring. This describes?", "choices": ["Arrest of descent", "Poor contraction", "Secondary arrest of dilatation", "Normal labor progression", "Prolonged latent phase"], "ans": 3, "exp": "ปากมดลูกเปิดหมด + ศีรษะเคลื่อนลง (station +1) + contraction ดี + FHR ปกติ = normal labor progression (ระยะที่สอง)", "sys": "XV"}, {"topic": "Obstetrics & Gynecology", "q": "A 25-year-old at 37 weeks with fully dilated cervix (10 cm)/100%/station +2, ruptured membranes, strong regular contractions. FHR moderate variability, no decelerations. Appropriate management?", "choices": ["Vacuum-assisted delivery", "Forceps delivery", "Cesarean section", "Oxytocin augmentation", "Observe for spontaneous delivery"], "ans": 4, "exp": "ระยะที่สองที่ดำเนินไปปกติ (เปิดหมด station +2 contraction ดี FHR ปกติ) -> สังเกต/ปล่อยเบ่งคลอดเอง (observe for spontaneous delivery)", "sys": "XV"}, {"topic": "Obstetrics & Gynecology", "q": "A 16-year-old with primary amenorrhea. Height 140 cm, weight 45 kg, low posterior hairline, Tanner stage I breasts, normal pelvic ultrasound. Most critical investigation?", "choices": ["Chromosome study (karyotype)", "Serum estradiol", "Pelvic MRI", "TSH and prolactin", "FSH and LH levels"], "ans": 0, "exp": "เตี้ย + ไม่มีลักษณะทางเพศ (Tanner I) + คอผมต่ำ (สงสัย Turner syndrome) -> ตรวจ chromosome study (karyotype: 45,X)", "sys": "XVII"}, {"topic": "Obstetrics & Gynecology", "q": "A 38-year-old with 1 year of worsening dysmenorrhea and deep dyspareunia. Cul-de-sac tenderness, firm fixed 6 cm left adnexal mass. TVUS: hypoechoic unilocular mass with diffuse low-level echoes ('ground glass'). Most likely diagnosis?", "choices": ["Dermoid cyst", "Endometriosis", "Paratubal cyst", "Serous cystadenoma", "Functional cyst"], "ans": 1, "exp": "ก้อนถุงน้ำผนัง ground-glass (low-level echoes) + ปวดประจำเดือน + เจ็บลึกขณะมีเพศสัมพันธ์ = endometrioma (chocolate cyst)", "sys": "II"}, {"topic": "Obstetrics & Gynecology", "q": "A 20-year-old took isotretinoin, vitamin C, combined oral contraceptives, coenzyme Q10, and benzoyl peroxide over 6 months, discontinued 6 weeks ago, now with a confirmed pregnancy (LMP 5 weeks ago). Which medication is most likely to have affected embryogenesis?", "choices": ["Vitamin C", "Combined oral contraceptive pill", "Isotretinoin", "Coenzyme Q10", "Benzoyl peroxide"], "ans": 2, "exp": "isotretinoin เป็นสารก่อวิรูป (teratogen) ที่รุนแรง (retinoid embryopathy) -> เป็นยาที่มีโอกาสส่งผลต่อตัวอ่อนมากที่สุด", "sys": "XV"}, {"topic": "Obstetrics & Gynecology", "q": "A 25-year-old primigravida at 8 weeks with 6 hours of heavy vaginal bleeding and lightheadedness. BP 90/59. Cervical os dilated 1 cm, active bleeding. Ultrasound confirms a viable 8-week fetus. Most appropriate management?", "choices": ["Tranexamic acid", "Progesterone", "Intravenous fluids", "Manual vacuum aspiration", "Emergency cerclage"], "ans": 3, "exp": "inevitable abortion (ปากมดลูกเปิด + เลือดออกมาก) -> รักษาด้วยการขับ/ขูดมดลูก (manual vacuum aspiration) เพื่อหยุดเลือด ควบคู่การให้สารน้ำกู้ชีพ", "sys": "XV"}, {"topic": "Obstetrics & Gynecology", "q": "A 30-year-old with a 2-year IUD, intermittent leukorrhea 1 year, acute right pelvic pain 3 days. LMP 2 weeks ago. RLQ rebound tenderness, cervical mucopurulent discharge, cervical motion tenderness, palpable 5 cm tense cystic right adnexal mass. Ultrasound confirms a hypoechoic 5 cm right adnexal mass. Most appropriate management?", "choices": ["Remove IUD immediately", "Remove IUD in 2 weeks", "Emergency exploratory laparotomy", "Ultrasound-guided drainage", "Broad-spectrum intravenous antibiotics"], "ans": 4, "exp": "PID + tubo-ovarian abscess (CMT + mucopurulent + ก้อนถุงน้ำที่ปีกมดลูก) -> เริ่มด้วย broad-spectrum IV antibiotics; ระบาย/ผ่าตัดเมื่อไม่ตอบสนอง", "sys": "XIV"}, {"topic": "Obstetrics & Gynecology", "q": "A 38-year-old primigravida at 12 weeks with severe nausea and vomiting for 2 months unresponsive to diet. No bleeding. Fundal height 2/3 above symphysis (large for dates), no tenderness, fetal heart sounds audible. Most useful investigation?", "choices": ["Abdominal ultrasound", "Serum beta-hCG level", "Liver function tests", "Thyroid function tests", "Urinalysis for ketones"], "ans": 0, "exp": "มดลูกโตกว่าอายุครรภ์ + hyperemesis รุนแรง -> ตรวจ ultrasound ประเมินครรภ์แฝด/molar pregnancy (มีเสียงหัวใจทารกจึงไม่ใช่ complete mole)", "sys": "XV"}, {"topic": "Obstetrics & Gynecology", "q": "A term pregnant woman with sudden-onset vaginal bleeding and severe abdominal pain. Generalized abdominal tenderness with guarding, fetal parts palpable, fetal heart tones absent. Most likely diagnosis?", "choices": ["Abruptio placentae", "Uterine rupture", "Placenta previa", "Bloody show", "Vasa previa"], "ans": 1, "exp": "คลำ fetal parts ได้ทางหน้าท้อง (ทารกหลุดออกนอกมดลูก) + ปวดรุนแรง + FHT หาย = uterine rupture", "sys": "XV"}, {"topic": "Obstetrics & Gynecology", "q": "A 14-year-old female with short stature, webbed neck, primary amenorrhea, low posterior hairline, shield chest, no breast development (Tanner 1). Most appropriate initial investigation?", "choices": ["Pelvic ultrasound", "Serum FSH/LH", "Chromosomal analysis (karyotype)", "Thyroid function tests", "MRI pituitary"], "ans": 2, "exp": "Turner syndrome (เตี้ย คอมีพังผืด อกกว้าง ไม่มี puberty) -> ตรวจ karyotype (45,X)", "sys": "XVII"}, {"topic": "Obstetrics & Gynecology", "q": "A 25-year-old unbooked primigravida with labor pain. Fundal height at the umbilicus (~20 weeks). After MgSO4 for hypertension (170/100 to 130/90), contractions every 7-8 min for 35 sec, FHR 150. Most appropriate management?", "choices": ["Tocolytic therapy", "Dexamethasone", "Emergency cesarean section", "Observe labor progression", "Amniotomy"], "ans": 3, "exp": "อายุครรภ์ ~20 สัปดาห์ (previable) + มดลูกหดตัวห่าง ๆ อ่อน (ทุก 7-8 นาที) + ความดันคุมได้ -> สังเกตการดำเนินคลอด (tocolysis ไม่ใช้ในอายุครรภ์ยังไม่รอดชีวิต)", "sys": "XV"}, {"topic": "Obstetrics & Gynecology", "q": "A 25-year-old with 5 days of mucopurulent vaginal discharge. Gram stain shows mixed gram-positive and gram-negative bacilli. No cervical motion tenderness or adnexal masses. Most appropriate treatment?", "choices": ["Doxycycline", "Azithromycin", "Amoxicillin-clavulanate", "Ceftriaxone", "Metronidazole"], "ans": 4, "exp": "gram stain เป็น mixed bacilli (clue cells/BV pattern) ไม่มีเชื้อจำเพาะ = bacterial vaginosis -> metronidazole", "sys": "XIV"}, {"topic": "Obstetrics & Gynecology", "q": "A 20-year-old at 6 weeks (by LMP) with acute lower abdominal pain for 6 hours. Mild cervical congestion, minimal bleeding from os, right adnexal tenderness (left normal). Urine pregnancy test weakly positive. Most appropriate initial investigation?", "choices": ["Transvaginal ultrasound", "Repeat urine pregnancy test in 24 hours", "Serum beta-hCG", "Urinalysis", "Diagnostic laparoscopy"], "ans": 0, "exp": "สงสัย ectopic (ปวดท้องน้อยข้างเดียว + UPT บวก + adnexal tenderness) -> ทำ transvaginal ultrasound หาตำแหน่งการตั้งครรภ์", "sys": "XV"}, {"topic": "Obstetrics & Gynecology", "q": "A 30-year-old at 24 weeks with a prior cesarean section, fresh vaginal bleeding, abdominal pain, and guarding. Fetal parts palpable through the abdominal wall, fetal heart sounds absent. Most likely diagnosis?", "choices": ["Placenta previa", "Uterine rupture", "Abruptio placentae", "Ruptured vasa previa", "Amniotic fluid embolism"], "ans": 1, "exp": "แผลผ่าคลอดเดิม + ปวด/ท้องแข็ง + คลำ fetal parts ได้ทางหน้าท้อง + FHT หาย = uterine rupture", "sys": "XV"}, {"topic": "Obstetrics & Gynecology", "q": "A 30-year-old with postpartum hemorrhage after vacuum-assisted delivery of a 4,000 g infant. Bleeding persists despite a well-contracted uterus. Next step?", "choices": ["IV methylergonovine", "Vaginal packing", "Birth canal exploration for lacerations", "Uterine compression sutures", "Emergency hysterectomy"], "ans": 2, "exp": "PPH ที่มดลูกหดตัวดี (ไม่ใช่ atony) -> สาเหตุคือการฉีกขาดของช่องทางคลอด -> ตรวจสำรวจช่องคลอด/ปากมดลูก (birth canal exploration) หารอยฉีกและเย็บ", "sys": "XV"}, {"topic": "Obstetrics & Gynecology", "q": "A 20-year-old used isotretinoin for acne until 6 weeks ago, LMP 5 weeks prior, now with suspected pregnancy. Which medication is most likely responsible for teratogenic concern?", "choices": ["Vitamin C", "Coenzyme Q10", "Combined oral pills", "Isotretinoin", "Benzoyl peroxide"], "ans": 3, "exp": "isotretinoin เป็น teratogen รุนแรง (retinoid embryopathy)", "sys": "XV"}, {"topic": "Obstetrics & Gynecology", "q": "A 35-year-old with acute left vulvar pain and swelling. A tender, fluctuant 4 cm mass in the left labia majora (Bartholin gland abscess), erythematous overlying skin, worsening 3 days, T 38.1. Most appropriate initial management?", "choices": ["Ceftriaxone", "Sitz baths", "Amoxicillin-clavulanate", "Incision and drainage alone", "Word catheter placement/marsupialization"], "ans": 4, "exp": "Bartholin abscess -> ระบายหนองและใส่ Word catheter หรือทำ marsupialization (ป้องกันการกลับเป็นซ้ำ; I&D อย่างเดียวมักกลับเป็นซ้ำ)", "sys": "II"}, {"topic": "Obstetrics & Gynecology", "q": "A 36-year-old primigravida with severe preeclampsia (on MgSO4), stable at 34 weeks. Cervix 1 cm dilated, EFW 2,500 g. Next step?", "choices": ["Betamethasone", "Amniotomy", "Oxytocin induction", "Await spontaneous labor", "Cesarean section"], "ans": 0, "exp": "severe preeclampsia ที่ 34 สัปดาห์ ควรคลอด -> ให้ betamethasone เร่งปอดทารก (late preterm) ก่อนแล้วจึงชักนำคลอด", "sys": "XV"}, {"topic": "Obstetrics & Gynecology", "q": "A 25-year-old with yellowish vaginal discharge, mucopurulent cervical discharge, contact bleeding, no adnexal tenderness. Gram stain: mixed gram-positive/negative bacilli without intracellular organisms. Most appropriate treatment?", "choices": ["Metronidazole 500 mg BID x 7 days", "Doxycycline 100 mg BID x 7 days", "Ceftriaxone 250 mg IM x 1 dose", "Clindamycin vaginal cream", "Azithromycin 1 g PO x 1 dose"], "ans": 1, "exp": "mucopurulent cervicitis + contact bleeding โดยไม่พบ intracellular diplococci = สงสัย chlamydia -> doxycycline 100 mg BID x 7 วัน (first-line)", "sys": "XIV"}, {"topic": "Obstetrics & Gynecology", "q": "A 52-year-old, 2 years postmenopausal, with vaginal spotting for 2 months, unresolved after OTC hormone supplements. No obvious lesions. Most appropriate diagnostic step?", "choices": ["Serum CA-125", "Transvaginal ultrasound", "Endometrial biopsy", "Pap smear", "Hysteroscopy"], "ans": 2, "exp": "postmenopausal bleeding -> ต้องตัดชิ้นเนื้อเยื่อบุโพรงมดลูก (endometrial biopsy) เพื่อแยกมะเร็งเยื่อบุโพรงมดลูก", "sys": "XIV"}, {"topic": "Obstetrics & Gynecology", "q": "A 22-year-old with mucopurulent cervical discharge and contact bleeding for 5 days. Gram stain: mixed gram-positive and gram-negative coccobacilli. Sexually active with one partner. Most appropriate treatment?", "choices": ["Azithromycin oral", "Metronidazole oral", "Ceftriaxone IM", "Doxycycline oral", "Fluconazole oral"], "ans": 3, "exp": "mucopurulent cervicitis (สงสัย chlamydia; ไม่พบ intracellular gonococci) -> doxycycline เป็น first-line (ตาม CDC ปัจจุบัน)", "sys": "flex"}, {"topic": "Obstetrics & Gynecology", "q": "A 14-year-old girl reports rape 2 days ago, with regular 28-day cycles, LMP 6 days ago, requesting pregnancy prevention. Most appropriate management?", "choices": ["No contraceptive needed", "Ethinyl estradiol 20 mcg orally stat", "Depot medroxyprogesterone acetate 150 mg IM", "Medroxyprogesterone 10 mg orally stat and repeat in 12 hours", "Levonorgestrel 1.5 mg orally stat"], "ans": 4, "exp": "emergency contraception หลังถูกล่วงละเมิดภายใน 72-120 ชม. -> levonorgestrel 1.5 mg รับประทานครั้งเดียว", "sys": "XV"}, {"topic": "Obstetrics & Gynecology", "q": "A 25-year-old primigravida at 8 weeks with severe lower abdominal cramping and heavy vaginal bleeding for 6 hours. T 37, pulse 100, BP 90/50. Uterus 8 weeks, cervical os dilated 1 cm with active bleeding. TVUS confirms a single viable intrauterine fetus with cardiac activity. Most appropriate management?", "choices": ["Manual vacuum aspiration (MVA)", "Progesterone supplementation", "Misoprostol (prostaglandin)", "Cervical cerclage", "Methotrexate"], "ans": 0, "exp": "inevitable abortion (ปากมดลูกเปิด + เลือดออกมาก) แม้ทารกยังมีชีพจร -> ขับ/ขูดมดลูกด้วย MVA เพื่อหยุดเลือด ควบคู่กู้ชีพด้วยสารน้ำ", "sys": "XV"}, {"topic": "Orthopedics", "q": "A 45-year-old female gardener with 4 weeks of progressive left wrist pain at the radial styloid, worse with thumb motion and gripping. Focal swelling/tenderness over the tendon sheath at the radial styloid, positive Finkelstein test. Which tendon sheath is most likely affected?", "choices": ["Flexor tendon sheath of thumb", "Extensor tendon sheath of thumb", "Adductor tendon sheath of thumb", "Extensor pollicis longus tendon sheath", "Flexor carpi radialis tendon sheath"], "ans": 1, "exp": "De Quervain's tenosynovitis = การอักเสบของ first dorsal compartment (abductor pollicis longus + extensor pollicis brevis) = extensor tendon sheath ของนิ้วโป้ง", "sys": "XIII"}, {"topic": "Orthopedics", "q": "A term newborn with left shoulder dystocia. Left arm flaccid (0/5), absent Moro on the left, intact grasp reflex. No bruising/deformities. Most appropriate initial investigation?", "choices": ["Nerve conduction velocity", "Cervical MRI", "X-ray left humerus and clavicle", "Ultrasound brain", "X-ray cervical spine"], "ans": 2, "exp": "Erb's palsy หลัง shoulder dystocia -> ถ่าย X-ray humerus และ clavicle ข้างซ้าย แยกกระดูกหักที่พบร่วม", "sys": "XIII"}, {"topic": "Orthopedics", "q": "A 35-year-old with medial elbow pain exacerbated by resisted pronation, tenderness over the medial epicondyle, no neuro deficits, no pain on passive movement, full ROM. Most likely diagnosis?", "choices": ["Tennis elbow", "Reactive arthritis", "Olecranon bursitis", "Golfer's elbow", "Ulnar collateral ligament sprain"], "ans": 3, "exp": "ปวด medial epicondyle + แย่ลงเมื่อ pronation/flexion ต้านแรง = medial epicondylitis (golfer's elbow)", "sys": "XIII"}, {"topic": "Orthopedics", "q": "A 16-year-old boy with persistent left wrist pain and weakness 3 months after a motorcycle accident, cannot grip heavy objects. Anatomical snuffbox tenderness and reduced grip. X-ray shows a non-displaced scaphoid fracture with early avascular necrosis. Most likely diagnosis?", "choices": ["Lunate fracture", "Radioulnar subluxation", "Distal radius fracture", "Triquetrum fracture", "Scaphoid fracture"], "ans": 4, "exp": "เจ็บ anatomical snuffbox + X-ray กระดูก scaphoid หัก (เสี่ยง avascular necrosis จากเลือดไปเลี้ยงน้อย) = scaphoid fracture. *อ้างอิงภาพ*", "img": "https://cdn.jsdelivr.net/gh/MercenzK/Web-quiz-images@main/NL2-2025-Apr-Q200.png", "sys": "XIII"}, {"topic": "Orthopedics", "q": "A 50-year-old woman with acute left knee pain, swelling, erythema for 4 days. T 38.5, effusion, positive ballottement, warmth. WBC 15,000 (88% neutrophils). No trauma/prior arthritis. Most appropriate initial management?", "choices": ["Knee arthrocentesis", "NSAIDs", "Colchicine", "X-ray left knee", "Empirical antibiotics"], "ans": 0, "exp": "สงสัย septic arthritis (ข้ออักเสบเฉียบพลัน + ไข้ + WBC สูง) -> ต้องเจาะข้อ (arthrocentesis) ส่งวิเคราะห์/เพาะเชื้อ ก่อนเริ่มยาปฏิชีวนะ", "sys": "XIII"}, {"topic": "Orthopedics", "q": "A 28-year-old with 1 week of low back pain radiating to both legs with numbness. Motor power 5/5, sensory loss at L5-S1, reduced anal sphincter tone. Most likely diagnosis?", "choices": ["Guillain-Barre syndrome", "Cauda equina syndrome", "Transverse myelitis", "Spinal stenosis", "Spinal cord compression"], "ans": 1, "exp": "ชา L5-S1 + หูรูดทวารหลวม (saddle/sphincter) = cauda equina syndrome", "sys": "XIII"}, {"topic": "Orthopedics", "q": "A 7-year-old boy after closed reduction and cast for a left supracondylar humeral fracture 8 hours ago now reports paresthesia in the left fingers. Distal pulses palpable. Most appropriate initial action?", "choices": ["Fasciotomy", "X-ray of left arm", "Split cast and padding", "Elevate left arm", "Administer analgesics"], "ans": 2, "exp": "อาการเริ่มของ compartment syndrome/เฝือกแน่นหลังจัดกระดูก supracondylar -> ขั้นแรกคือคลายเฝือกและ padding (split cast) เพื่อลดแรงกด", "sys": "XIII"}, {"topic": "Orthopedics", "q": "A 30-year-old woman with radial-sided wrist pain worsened by thumb movement, positive Finkelstein test. Which structure is primarily involved?", "choices": ["Flexor carpi radialis tendon", "Median nerve", "Scaphoid bone", "Extensor pollicis brevis tendon sheath", "Ulnar collateral ligament"], "ans": 3, "exp": "De Quervain's tenosynovitis เกี่ยวข้องกับ extensor pollicis brevis (และ abductor pollicis longus) ใน first dorsal compartment", "sys": "XIII"}, {"topic": "Rehabilitation medicine", "q": "A 50-year-old woman with T2DM (2 years) with 3 months of numbness in the left hand. Atrophy of the left thenar eminence, reduced pinprick in thumb, index, and middle fingers. Right hand and both feet intact. Most likely diagnosis?", "choices": ["Vitamin B12 deficiency", "Diabetic polyneuropathy", "Cervical radiculopathy", "Ulnar nerve neuropathy", "Carpal tunnel syndrome"], "ans": 4, "exp": "ชาเฉพาะ median distribution ข้างเดียว + thenar atrophy = carpal tunnel syndrome (diabetic polyneuropathy จะเป็นสองข้างแบบถุงมือถุงเท้า)", "sys": "IV"}, {"topic": "Rehabilitation medicine", "q": "A 28-year-old man with progressive leg weakness, numbness (L5-S1), and urinary incontinence. Globally decreased motor power, absent bulbocavernosus reflex, loose anal tone. Most likely diagnosis?", "choices": ["Cauda equina syndrome", "Spinal stenosis", "Disc herniation", "Transverse myelitis", "Multiple sclerosis"], "ans": 0, "exp": "อ่อนแรงขา + ชา L5-S1 + หูรูดผิดปกติ + bulbocavernosus หาย = cauda equina syndrome", "sys": "VI"}, {"topic": "Rehabilitation medicine", "q": "A 30-year-old man with 5 days of fever and rhinorrhea, then urinary retention and bilateral leg weakness. Flaccid paralysis (2/5) in lower limbs, absent knee/ankle reflexes, sensory loss below T10, extensor plantar responses, reduced anal sphincter tone. Most likely diagnosis?", "choices": ["Myasthenia gravis", "Acute transverse myelitis", "Polymyositis", "Guillain-Barre syndrome", "Acute poliomyelitis"], "ans": 1, "exp": "มี sensory level ชัด (T10) + เสียหูรูด + UMN sign (extensor plantar) หลังติดเชื้อ = acute transverse myelitis", "sys": "VI"}, {"topic": "Rehabilitation medicine", "q": "A 30-year-old secretary with 3 months of neck pain alleviated by stretching and massage. Tension and tenderness in the right trapezius radiating to the right temporal area. Normal neuro exam. Most likely diagnosis?", "choices": ["Cervical spondylosis", "Fibromyalgia", "Myofascial pain syndrome", "Acromioclavicular bursitis", "Biceps tendinitis"], "ans": 2, "exp": "ปวดตึงกล้ามเนื้อ trapezius มีจุดกดเจ็บ (trigger point) ร้าวขึ้นขมับ ดีขึ้นเมื่อนวด/ยืด = myofascial pain syndrome", "sys": "XIII"}, {"topic": "Ophthalmology", "q": "A 56-year-old man with right eye irritation and mucopurulent discharge for 1 week, following a rice leaf corneal scratch 2 weeks prior. VA 6/60, 5x4 mm corneal whitish infiltrate, conjunctival injection. Most likely diagnosis?", "choices": ["Anterior uveitis", "Viral conjunctivitis", "Bacterial conjunctivitis", "Corneal ulcer", "Corneal abrasion"], "ans": 3, "exp": "corneal infiltrate + การมองเห็นลดลง หลังบาดเจ็บจากพืช (ใบข้าว) = corneal ulcer (แผลกระจกตาติดเชื้อ มักเป็นเชื้อรา)", "sys": "VII"}, {"topic": "Ophthalmology", "q": "A 33-year-old male with 1 week of photophobia and blurred vision, history of self-administering steroid eye drops for a red eye. Hypopyon in the anterior chamber. Most likely diagnosis?", "choices": ["Scleritis", "Endophthalmitis", "Anterior uveitis", "Conjunctivitis", "Corneal ulcer"], "ans": 4, "exp": "การใช้ steroid eye drop เองทำให้ติดเชื้อกระจกตา (fungal/herpetic) -> corneal ulcer with hypopyon", "sys": "VII"}, {"topic": "Ophthalmology", "q": "A 28-year-old with severe eye pain, photophobia, and tearing after a tree-branch injury. Fluorescein shows a 4 mm corneal abrasion under the upper eyelid, no foreign body. Most appropriate management?", "choices": ["Topical antibiotic (without patching)", "Artificial tears", "Antibiotic ointment + pressure patching", "Oral antihistamine", "Topical anesthetic drops"], "ans": 0, "exp": "corneal abrasion จากพืช/สารอินทรีย์ -> ให้ topical antibiotic (ป้องกันติดเชื้อ) โดยไม่ปิดตา (patching เพิ่มเสี่ยงติดเชื้อจากพืช)", "sys": "VII"}, {"topic": "Ophthalmology", "q": "A 25-year-old woman with bilateral red eyes, itching, and watery discharge for 3 days. Conjunctival chemosis, follicular reaction, tender preauricular node. No photophobia. Most likely diagnosis?", "choices": ["Trachoma", "Viral keratoconjunctivitis", "Allergic conjunctivitis", "Hay fever conjunctivitis", "Gonococcal conjunctivitis"], "ans": 1, "exp": "ตาแดงสองข้าง + follicular reaction + ขี้ตาใส + ต่อมน้ำเหลืองหน้าหูโตเจ็บ = viral (adenoviral) keratoconjunctivitis", "sys": "VII"}, {"topic": "Ophthalmology", "q": "A construction worker splashes an unknown chemical into his right eye with severe pain and blurred vision. Conjunctival injection and corneal haze. Immediate management?", "choices": ["Sterile water irrigation", "Instill antibiotic drops", "Normal saline eye irrigation", "Apply eye patch", "Urgent ophthalmology referral"], "ans": 2, "exp": "chemical eye injury -> ล้างตาด้วยน้ำเกลือ (normal saline) ปริมาณมากทันที เป็นอันดับแรก (ก่อนส่งต่อ)", "sys": "VII"}, {"topic": "Ophthalmology", "q": "A woman with severe left eye pain, facial drooling, vesicles in the left periauricular region, and facial pain. First-line treatment?", "choices": ["Prednisolone", "Artificial tears", "Patching", "Acyclovir", "Gabapentin"], "ans": 3, "exp": "herpes zoster oticus/Ramsay Hunt (ตุ่มน้ำรอบหู + facial palsy) -> ยาหลักคือ acyclovir (antiviral) ร่วมกับ corticosteroid", "sys": "VII"}, {"topic": "Ophthalmology", "q": "A 20-year-old female with sulfuric acid splashed into her right eye, severe pain and blurred vision. Slit-lamp: conjunctival chemosis and corneal epithelial defects. Most appropriate immediate management?", "choices": ["Sterile water irrigation", "Artificial tears every 2 hours", "Topical antibiotic (e.g., moxifloxacin)", "Urgent ophthalmology consultation + pH testing", "Copious normal saline (NSS) irrigation"], "ans": 4, "exp": "chemical (acid) eye burn -> ล้างตาด้วย NSS ปริมาณมากทันทีเป็นอันดับแรก (ก่อนตรวจ pH/ส่งต่อ)", "sys": "VII"}, {"topic": "Otolaryngology", "q": "A 52-year-old diabetic with severe right otalgia, vesicular eruptions on the pinna and external auditory canal, and acute right facial palsy (House-Brackmann IV), onset 48h ago with prodromal tingling. No hearing loss or vertigo. Most appropriate initial pharmacotherapy?", "choices": ["Oral acyclovir", "Oral amoxicillin-clavulanate", "Intravenous methylprednisolone", "Topical ciprofloxacin ear drops", "Oral gabapentin"], "ans": 0, "exp": "Ramsay Hunt syndrome (herpes zoster oticus + facial palsy) -> ยาหลักคือ antiviral (acyclovir) ร่วมกับ corticosteroid", "sys": "VIII"}, {"topic": "Otolaryngology", "q": "A 45-year-old woman with recurrent vertigo triggered by turning her head to the right, each episode lasting several minutes and resolving spontaneously, no hearing loss/tinnitus, normal neuro. Most likely cause?", "choices": ["Meniere's disease", "Benign paroxysmal positional vertigo (BPPV)", "Vestibular neuritis", "Labyrinthitis", "Acoustic neuroma"], "ans": 1, "exp": "เวียนศีรษะสั้น ๆ สัมพันธ์กับการหันศีรษะ โดยการได้ยินปกติ = BPPV", "sys": "VIII"}, {"topic": "Otolaryngology", "q": "An 18-year-old with acute left ear pain for 24 hours after cleaning with a cotton swab. Otoscopy: erythematous intact TM without perforation/discharge. No hearing loss/fever, discomfort with jaw movement. Most appropriate initial management?", "choices": ["Paper patch", "Tympanoplasty", "Topical antibiotics", "Myringoplasty", "Conservative management and follow-up"], "ans": 2, "exp": "otitis externa ระยะแรก (ช่องหูอักเสบ เจ็บเมื่อขยับกราม/tragus แก้วหูปกติ) -> ให้ยาหยอดหูปฏิชีวนะ (topical antibiotics)", "sys": "VIII"}, {"topic": "Otolaryngology", "q": "A 5-year-old boy with high fever (38.5) and severe right ear pain for 24 hours. Otoscopy: bulging TM with mucopurulent discharge. No hearing loss/facial weakness. Most appropriate management?", "choices": ["Cloxacillin", "Clindamycin", "Cefazolin", "Amoxicillin", "Ciprofloxacin"], "ans": 3, "exp": "acute otitis media -> ยา first-line คือ amoxicillin (ขนาดสูง)", "sys": "VIII"}, {"topic": "Otolaryngology", "q": "A 20-year-old post-motorcycle accident with right-sided hearing loss, right facial palsy, bloody otorrhea, perforated TM. Weber lateralizes left, Rinne positive bilaterally. Likely etiology?", "choices": ["Ear ossicle disruption", "TM perforation", "Blood in middle ear", "Acoustic neuroma", "Temporal bone fracture"], "ans": 4, "exp": "facial palsy + bloody otorrhea + sensorineural hearing loss หลังบาดเจ็บศีรษะ = temporal bone fracture", "sys": "VIII"}, {"topic": "Otolaryngology", "q": "A teenager with 3 days of right ear pain after frequent ear picking. Erythematous, tender external auditory canal with whitish discharge and edema obscuring the TM. No fever/lymphadenopathy. Initial management?", "choices": ["Oral analgesics + ear wick placement", "Topical antibiotic drops", "Topical steroid drops", "Systemic antibiotics", "Referral for ENT debridement"], "ans": 0, "exp": "otitis externa ที่ช่องหูบวมมากจนหยอดยาไม่ถึง -> ใส่ ear wick เพื่อนำส่งยาหยอด + ให้ยาแก้ปวด", "sys": "VIII"}, {"topic": "Otolaryngology", "q": "A 22-year-old man with sudden hearing loss and mild left ear pain after vigorous ear cleaning. Small central TM perforation without infection/discharge/vertigo/facial weakness. Most appropriate initial management?", "choices": ["Oral antibiotics (e.g., amoxicillin)", "Observation and avoidance of ear manipulation", "Myringotomy", "Tympanoplasty surgery", "Topical antibiotic ear drops"], "ans": 1, "exp": "traumatic TM perforation ที่ไม่มีการติดเชื้อ -> สังเกตและหลีกเลี่ยงการแคะหู/ให้แห้ง ส่วนใหญ่หายเอง", "sys": "VIII"}, {"topic": "Otolaryngology", "q": "An 18-year-old with severe left ear pain for 1 day after ear cleaning. Otoscopy shows a TM perforation. First-line treatment?", "choices": ["Paper patch myringoplasty", "Surgical myringoplasty", "Observation", "Tympanoplasty", "Oral antibiotics"], "ans": 2, "exp": "traumatic TM perforation -> first-line คือ observation (รักษาให้แห้ง ส่วนใหญ่หายเอง). *อ้างอิงภาพ*", "img": "https://cdn.jsdelivr.net/gh/MercenzK/Web-quiz-images@main/NL2-2025-Apr-Q223.png", "sys": "VIII"}, {"topic": "Otolaryngology", "q": "A 75-year-old man with IHD on daily aspirin, progressive nasal stuffiness and difficulty breathing for 3 months, bilateral nasal polyps obstructing the passages. He declines surgery. Most appropriate initial management?", "choices": ["Cetirizine", "Prednisolone", "Chlorpheniramine", "Budesonide nasal spray", "Xylometazoline nasal drops 0.005%"], "ans": 3, "exp": "nasal polyps -> การรักษาทางยาเบื้องต้นคือ intranasal corticosteroid (budesonide nasal spray)", "sys": "VIII"}, {"topic": "Otolaryngology", "q": "A 28-year-old with a traumatic right TM perforation 24 hours ago after a slap to the ear. Otoscopy: small central perforation, no active bleeding/infection. Most appropriate initial management?", "choices": ["Tympanoplasty surgery", "Antibiotic ear drops (ciprofloxacin)", "Oral amoxicillin-clavulanate", "Regular ear canal irrigation", "Keep the ear dry and avoid nose-blowing"], "ans": 4, "exp": "traumatic TM perforation -> รักษาให้ช่องหูแห้ง หลีกเลี่ยงการสั่งน้ำมูก/ให้น้ำเข้าหู ส่วนใหญ่หายเอง", "sys": "VIII"}, {"topic": "Otolaryngology", "q": "A 65-year-old man with right ear pain 3 days after using an ear pick. Diffuse swelling, tenderness, and whitish discharge in the external ear canal, TM obscured by edema. Most appropriate management?", "choices": ["Topical ciprofloxacin/dexamethasone ear drops", "Oral amoxicillin", "Oral prednisolone", "Ear canal irrigation", "Incision and drainage"], "ans": 0, "exp": "otitis externa -> รักษาด้วยยาหยอดหู topical antibiotic + steroid (ciprofloxacin/dexamethasone)", "sys": "VIII"}, {"topic": "Otolaryngology", "q": "A 12-year-old boy with a midline neck mass that elevates with swallowing, painless, mobile, 2 cm. Normal thyroid function. Initial diagnostic step?", "choices": ["Surgical excision", "Thyroid ultrasound", "Fine-needle aspiration", "Thyroid scintigraphy", "MRI neck"], "ans": 1, "exp": "thyroglossal duct cyst (ก้อนกลางคอเลื่อนตามการกลืน) -> ตรวจ thyroid ultrasound ยืนยันและดูว่ามีเนื้อไทรอยด์ปกติก่อนผ่าตัด", "sys": "VIII"}, {"topic": "Otolaryngology", "q": "A 45-year-old woman with pruritus around the right ear, then grouped vesicles and ipsilateral facial nerve palsy. Vesicular eruptions in the auricular region with unilateral facial droop. Most appropriate treatment?", "choices": ["Amoxicillin-clavulanate", "Topical antifungal", "Acyclovir", "Oral prednisolone", "Topical corticosteroid"], "ans": 2, "exp": "Ramsay Hunt syndrome (ตุ่มน้ำที่หู + facial palsy) -> รักษาด้วย acyclovir (antiviral) + steroid", "sys": "VIII"}, {"topic": "Otolaryngology", "q": "A 25-year-old woman with bilateral nasal obstruction for 1 year. Pale, boggy nasal mucosa with polyps. Most appropriate initial management?", "choices": ["Oral antibiotics", "Immunotherapy", "Oral prednisolone", "Intranasal corticosteroid spray", "Surgical polypectomy"], "ans": 3, "exp": "nasal polyps -> เริ่มด้วย intranasal corticosteroid spray", "sys": "VIII"}, {"topic": "Emergency medicine", "q": "A 68-year-old man on chronic warfarin for AF with sudden severe headache, vomiting, and right hemiparesis. CT confirms acute intracranial hemorrhage. INR 5.0, stable vitals, GCS 12. Most urgent intervention to reverse coagulopathy?", "choices": ["Intravenous vitamin K", "Prednisolone", "Protamine sulfate", "Platelet transfusion", "Fresh frozen plasma (FFP)"], "ans": 4, "exp": "warfarin-related ICH + INR สูง -> reverse ทันทีด้วย fresh frozen plasma (หรือ PCC) ร่วมกับ vitamin K (vitamin K ออกฤทธิ์ช้า จึงต้องใช้ factor ทดแทนเพื่อหยุดเลือดเร็ว)", "sys": "emergency"}, {"topic": "Emergency medicine", "q": "A 20-year-old with an anterior neck injury in a motorcycle accident, immediate voice changes and dyspnea. Hoarseness, cervical ecchymosis, subcutaneous emphysema, RR 24, SpO2 85% (only 88% on 10L O2), bilaterally diminished breath sounds. Most appropriate airway management?", "choices": ["Tracheostomy", "Cricothyroidotomy", "Endotracheal intubation", "Needle thoracostomy", "Emergency bronchoscopy"], "ans": 0, "exp": "laryngotracheal injury (เสียงแหบ + subcutaneous emphysema + hypoxia หลังบาดเจ็บคอ) -> secure airway ด้วย tracheostomy (การใส่ ETT/cricothyroidotomy เสี่ยงทำให้บาดเจ็บมากขึ้น/สร้าง false passage)", "sys": "emergency"}, {"topic": "Emergency medicine", "q": "A 30-year-old agitated after a high-speed motorcycle collision 1 hour ago. P 120, BP 80/60, RR 24. Abdominal distension, guarding, rebound tenderness. Foley drains clear urine but minimal output (<0.5 mL/kg/h). Most likely cause of oliguria?", "choices": ["Bladder rupture", "Hemorrhagic shock", "Urethral disruption", "False passage from catheterization", "Acute tubular necrosis"], "ans": 1, "exp": "ความดันตก (80/60) + สัญญาณเลือดออกในช่องท้อง (distension, guarding) -> hemorrhagic/hypovolemic shock ทำให้ไตกรองน้อย = oliguria", "sys": "emergency"}, {"topic": "Emergency medicine", "q": "A 60-year-old briefly unconscious after a car accident, alert (GCS 15) at ER, then 1 hour later deteriorates to GCS E1V1M1. CT pending. Most likely diagnosis?", "choices": ["Subdural hematoma", "Traumatic subarachnoid hemorrhage", "Epidural hematoma", "Diffuse axonal injury", "Intracerebral contusion"], "ans": 2, "exp": "lucid interval (รู้สึกตัวดีแล้วซึมลงเร็ว) หลังบาดเจ็บศีรษะ = epidural hematoma", "sys": "emergency"}, {"topic": "Emergency medicine", "q": "A 60-year-old woman with T2DM and ascending cholangitis, hypotensive (80/60) with deteriorating consciousness. After antibiotics and 500 mL NSS over 15 min: BP 80/60, pulse 110, JVP 1 cm, clear lungs (septic shock unresponsive to initial fluid). Most appropriate management?", "choices": ["IV hydrocortisone", "Dopamine infusion", "Norepinephrine infusion", "Repeat NSS 500 mL over 15 minutes", "5% albumin infusion (100 mL/hour)"], "ans": 3, "exp": "septic shock ที่ยัง hypovolemic (JVP ต่ำ 1 cm, ปอดใส) และยังตอบสนองต่อสารน้ำ -> ให้ crystalloid (NSS) ซ้ำต่อจนพอ ก่อนพิจารณา vasopressor (norepinephrine)", "sys": "emergency"}, {"topic": "Surgery", "q": "A 28-year-old male with a 2 cm stab wound to the right paraumbilical abdomen. Hemodynamically stable (BP 130/80, PR 90), alert. Mild tenderness but no peritonitis or active bleeding. Most appropriate initial management?", "choices": ["FAST ultrasound", "Diagnostic peritoneal lavage (DPL)", "Exploratory laparotomy", "CT abdomen", "Local wound exploration"], "ans": 4, "exp": "stab wound หน้าท้อง ผู้ป่วย stable ไม่มี peritonitis -> ทำ local wound exploration ดูว่าทะลุ anterior fascia/peritoneum หรือไม่", "sys": "XVIII"}, {"topic": "Emergency medicine", "q": "A 40-year-old farmer with acute confusion, sweating, excessive salivation, muscle twitching, and fasciculations 12 hours after pesticide exposure. Pupils 1 mm sluggish, bradycardia (HR 50), wet breath sounds. Initial management?", "choices": ["Atropine", "Naloxone", "Gastric lavage", "Activated charcoal", "Magnesium sulfate"], "ans": 0, "exp": "organophosphate poisoning (cholinergic crisis: น้ำลาย/สารคัดหลั่งมาก, miosis, bradycardia, fasciculation) -> ให้ atropine ทันที (+ pralidoxime)", "sys": "emergency"}, {"topic": "Emergency medicine", "q": "A 20-year-old tall, thin male with acute chest discomfort and mild respiratory distress for 1 day. Hyperresonance, decreased breath sounds, diminished vocal fremitus on the right. Trachea midline. Most appropriate initial management?", "choices": ["Observation", "Chest X-ray", "Needle aspiration", "Chest tube insertion", "High-flow oxygen therapy"], "ans": 1, "exp": "สงสัย spontaneous pneumothorax (ชายผอมสูง เคาะโปร่ง เสียงหายใจลด trachea อยู่กลาง = ไม่ tension) ที่ stable -> ยืนยันด้วย chest X-ray ก่อนรักษา", "sys": "emergency"}, {"topic": "Emergency medicine", "q": "A 5-year-old boy ingested a floor cleaning product 1 hour ago. BP 90/60, pulse 120, RR 28, mild oral mucosal erythema with erosions, no respiratory distress. Most appropriate treatment?", "choices": ["Activated charcoal", "Induce vomiting", "Esophagogastroscopy", "Nasogastric lavage", "Neutralization with milk"], "ans": 2, "exp": "caustic ingestion (เยื่อบุปากแดง/erosion) -> ทำ EGD ประเมินการบาดเจ็บหลอดอาหาร; ห้ามให้ถ่านกัมมันต์/กระตุ้นอาเจียน/ล้างท้อง/สารกลาง", "sys": "emergency"}, {"topic": "Emergency medicine", "q": "A 75-year-old with metastatic bone cancer on IV morphine (4 mg q2h). 12 hours later increasingly drowsy, RR 8, shallow breathing, SpO2 88%, pinpoint pupils, no lung disease. Most appropriate immediate management?", "choices": ["Endotracheal intubation", "Administer 50% glucose IV", "Administer atropine IV", "Administer naloxone IV", "Normal saline fluid bolus"], "ans": 3, "exp": "opioid overdose (ซึม RR 8 pinpoint pupils) -> ให้ naloxone IV", "sys": "emergency"}, {"topic": "Emergency medicine", "q": "A 60-year-old man with hypertension, fatigue and dizziness. BP 90/50, irregular pulse. ECG: atrial fibrillation with ventricular rate 130-150. Alert but diaphoretic and pale. Most appropriate immediate management?", "choices": ["Administer amiodarone", "Defibrillation", "Administer adenosine", "Administer metoprolol IV", "Synchronized cardioversion"], "ans": 4, "exp": "AF with RVR ที่ไม่คงที่ (ความดันตก เหงื่อออก ซีด) -> synchronized cardioversion", "sys": "emergency"}, {"topic": "Emergency medicine", "q": "A 22-year-old found unconscious after 5 hours outdoors in 38C heat, unresponsive with hot, dry skin. T 40, BP 90/55, P 120, RR 22. No head trauma/seizures. Most appropriate immediate management?", "choices": ["Initiate rapid cooling with ice packs and cold IV fluids", "Apply cold tepid sponges", "Administer epinephrine IM", "Perform CT brain", "Administer oxygen via non-rebreather mask"], "ans": 0, "exp": "heat stroke (T 40 + ผิวร้อนแห้ง + ซึม) -> ลดอุณหภูมิร่างกายอย่างรวดเร็ว (rapid cooling: ice packs, cold IV fluids, evaporative cooling)", "sys": "emergency"}, {"topic": "Emergency medicine", "q": "A 30-year-old after a high-speed MVC, hypotensive (BP 80/50), tachycardic, dyspneic. Absent breath sounds on the left, tracheal deviation to the right, jugular venous distension. Most appropriate immediate management?", "choices": ["Pericardiocentesis", "Needle thoracocentesis (left)", "Endotracheal intubation", "Chest tube insertion", "Rapid IV crystalloid infusion"], "ans": 1, "exp": "tension pneumothorax ซ้าย (trachea เบนขวา + JVD + ช็อก) -> needle thoracocentesis (decompression) ทันที", "sys": "emergency"}, {"topic": "Emergency medicine", "q": "A 40-year-old with controlled complex partial seizures (on phenytoin) found unresponsive. T 37, BP 180/100, P 110, RR 12. Mid-position pinpoint pupils, absent oculocephalic reflex, decerebrate posturing. Most likely diagnosis?", "choices": ["Narcotic overdose", "Thalamic infarction", "Pontine hemorrhage", "Epidural hematoma", "Phenytoin intoxication"], "ans": 2, "exp": "หมดสติ + pinpoint pupils + decerebrate posturing + absent oculocephalic = pontine hemorrhage", "sys": "emergency"}, {"topic": "Emergency medicine", "q": "A 52-year-old with HT, dyslipidemia, CKD stage 3, 6 hours of crushing substernal chest pain. BP 196/120, pulse 96, RR 22, fine bilateral crepitations. ECG: ST depression in anterior leads. Most appropriate management?", "choices": ["IV Labetalol", "Oral hydralazine", "Sublingual nifedipine", "Aspirin and heparin", "Sublingual nitroglycerin"], "ans": 3, "exp": "NSTE-ACS (ST depression + เจ็บอก) -> ให้ aspirin + anticoagulant (heparin) เป็นการรักษาหลัก (ควบคุมความดัน/ischemia ด้วย nitroglycerin ควบคู่)", "sys": "emergency"}, {"topic": "Emergency medicine", "q": "A 40-year-old woman unconscious (GCS E4V1M1). BP 200, RV heave, grade 3/6 apical diastolic rumble. Bidirectional gaze palsy, quadriplegia. Most appropriate immediate management?", "choices": ["Aspirin", "LMWH", "IV nicardipine", "IV rt-PA", "Endotracheal intubation"], "ans": 4, "exp": "ผู้ป่วยซึมมาก (M1) + quadriplegia + gaze palsy (เลือดออก brainstem) -> สิ่งเร่งด่วนที่สุดคือ secure airway ด้วย ETT", "sys": "emergency"}, {"topic": "Emergency medicine", "q": "A 50 kg patient rescued from a burning house with burns: 15% 1st-degree, 25% 2nd-degree, 10% 3rd-degree (total TBSA 50%), 1 hour post-injury. Parkland fluid rate for the FIRST hour?", "choices": ["500 mL/hr", "1,000 mL/hr", "1,250 mL/hr", "1,500 mL/hr", "2,000 mL/hr"], "ans": 0, "exp": "Parkland คิดเฉพาะแผลลึก (2nd+3rd = 35%): 4 x 50 x 35 = 7,000 mL/24 ชม.; ครึ่งแรก 3,500 mL ใน 8 ชม. -> 3,500/8 = 437.5 mL/ชม. (ใกล้สุด 500 mL/ชม.)", "sys": "emergency"}, {"topic": "Emergency medicine", "q": "A 30-year-old woman with two episodes of sudden syncope after emotional arguments, with rapid recovery. Orthostatic BP 120/80 sitting to 110/75 standing. Normal neuro exam. Which investigation is most appropriate?", "choices": ["EKG", "Tilt table test", "CT brain", "Holter monitoring", "EEG"], "ans": 1, "exp": "vasovagal syncope (เป็นลมจากอารมณ์ ฟื้นเร็ว ไม่มี orthostatic drop ชัด) -> tilt table test", "sys": "emergency"}, {"topic": "Emergency medicine", "q": "A patient after a box jellyfish sting with tentacles still adherent to the leg, severe pain and systemic symptoms (nausea, diaphoresis). Initial management?", "choices": ["Rinse with fresh water", "Apply ice packs", "Pour vinegar on tentacles", "Pressure immobilization", "Administer antivenom"], "ans": 2, "exp": "box jellyfish sting -> ราดน้ำส้มสายชู (vinegar) บนหนวดเพื่อยับยั้ง nematocyst ไม่ให้ปล่อยพิษเพิ่ม (ห้ามล้างด้วยน้ำจืดซึ่งกระตุ้นการปล่อยพิษ)", "sys": "emergency"}, {"topic": "Emergency medicine", "q": "A patient with 1 hour of crushing chest pain. ECG shows 2 mm ST-elevation in II, III, aVF. Nearest PCI center is 150 minutes away. Stable vitals. Best reperfusion strategy?", "choices": ["Primary PCI", "Heparin infusion", "Aspirin and clopidogrel", "Administer r-TPA", "Morphine and oxygen"], "ans": 3, "exp": "inferior STEMI + ทำ primary PCI ไม่ทันในเวลา (>120 นาที) -> ให้ fibrinolysis (r-TPA/alteplase) ทันที", "sys": "emergency"}, {"topic": "Emergency medicine", "q": "A 25-year-old man after falling from a tree with severe LUQ pain. FAST shows fluid in the splenorenal region, Foley shows gross hematuria, stable vitals (BP 120/80, HR 88), LUQ guarding. No dyspnea/chest trauma. Most appropriate initial imaging?", "choices": ["Cystogram", "Intravenous pyelography", "Retrograde pyelography", "Ultrasound whole abdomen", "CT abdomen with contrast (CTWA)"], "ans": 4, "exp": "บาดเจ็บ solid organ (ม้าม) + gross hematuria (สงสัยบาดเจ็บไต) ในผู้ป่วย stable -> CT abdomen with contrast ประเมินอวัยวะและระบบทางเดินปัสสาวะ", "sys": "emergency"}, {"topic": "Otolaryngology", "q": "A 30-year-old with frequent ear picking presents with ear pain. Whitish discharge in the external canal, TM not visible due to edema. Initial treatment?", "choices": ["Ear wick insertion", "IV antibiotics", "Topical antibiotic drops", "Topical steroid drops", "Oral analgesics"], "ans": 0, "exp": "otitis externa ที่ช่องหูบวมจนหยอดยาไม่ถึง -> ใส่ ear wick เพื่อนำส่งยาหยอด (แล้วให้ topical antibiotic/steroid)", "sys": "VIII"}, {"topic": "Internal medicine", "q": "A 35-year-old with poorly controlled HIV, 3 weeks of dyspnea on exertion and malaise. T 38, BP 100/70, oral thrush. CXR bilateral interstitial infiltrates. Most appropriate treatment?", "choices": ["Ceftriaxone", "Trimethoprim-sulfamethoxazole", "Azithromycin", "Ciprofloxacin", "Amphotericin B"], "ans": 1, "exp": "HIV + oral thrush + interstitial infiltrate สองข้าง + DOE = Pneumocystis jirovecii pneumonia (PCP) -> รักษาด้วย high-dose co-trimoxazole", "sys": "I"}, {"topic": "Pediatrics", "q": "A 7-year-old boy develops hives, angioedema, and wheezing minutes after playing in a garden. BP 100/70, SpO2 95%, no stridor. Most appropriate initial management?", "choices": ["Terbutaline SC", "Hydrocortisone IV", "Adrenaline IM", "Chlorpheniramine IV", "Salbutamol nebulization"], "ans": 2, "exp": "anaphylaxis (ลมพิษ + angioedema + wheeze เฉียบพลัน) -> ให้ adrenaline (epinephrine) IM ทันทีเป็นอันดับแรก", "sys": "I"}, {"topic": "Emergency medicine", "q": "A 25-year-old post-trauma with hypotension (BP 80/60). After urinary catheterization, urine output is 15 mL/hour. Cause of oliguria?", "choices": ["Bladder injury", "Acute tubular necrosis", "Urethral rupture", "Hypovolemic shock", "Neurogenic bladder"], "ans": 3, "exp": "ความดันตกหลังบาดเจ็บ + ปัสสาวะออกน้อย = hypovolemic (hemorrhagic) shock ทำให้ไตกรองน้อย", "sys": "emergency"}, {"topic": "Emergency medicine", "q": "A 20-year-old with epilepsy on phenytoin with an ongoing generalized tonic-clonic seizure after missing medication for a week. Tachycardia and hypertension. Seizure has lasted 5 minutes. Most appropriate initial management?", "choices": ["Intravenous diazepam", "Intravenous phenytoin", "Intravenous phenobarbital", "Intravenous sodium valproate", "Intravenous lorazepam"], "ans": 4, "exp": "status epilepticus -> ยาแรกคือ benzodiazepine; IV lorazepam เป็นตัวเลือกที่นิยม (ออกฤทธิ์นานกว่า diazepam)", "sys": "emergency"}, {"topic": "Emergency medicine", "q": "A 30-year-old woman with two episodes of sudden loss of consciousness (one at rest, one during an argument) with rapid spontaneous recovery. Unremarkable except a mild orthostatic BP drop. Most appropriate initial diagnostic test?", "choices": ["Tilt table test", "CT scan of brain", "Echocardiogram", "Holter monitoring", "EEG"], "ans": 0, "exp": "vasovagal syncope -> tilt table test", "sys": "emergency"}, {"topic": "Pediatrics", "q": "A 6-year-old on ceftriaxone for pneumonia develops fever and right pleural effusion. Thoracentesis: pH 7.1, WBC 1,500 (85% neutrophils), glucose 49 (serum 100), LDH 300, no organisms. Management?", "choices": ["Add vancomycin", "Intercostal drainage", "Switch to ceftazidime", "Bronchoscopy", "Continue ceftriaxone"], "ans": 1, "exp": "complicated parapneumonic effusion (pH <7.2, glucose ต่ำ) -> ใส่ท่อระบายทรวงอก (intercostal drainage)", "sys": "X"}, {"topic": "Emergency medicine", "q": "A 5-year-old hypotensive (80/40) 1 hour post-intubation for trauma, with abdominal distension and bruit. Initial step of management?", "choices": ["CT abdomen", "Emergency laparotomy", "FAST ultrasound", "Diagnostic peritoneal lavage", "Angiography"], "ans": 2, "exp": "ผู้ป่วยบาดเจ็บที่ไม่คงที่ (hypotension) + ท้องอืด -> ทำ FAST ultrasound ประเมินเลือดออกในช่องท้องเป็นอันดับแรก", "sys": "emergency"}, {"topic": "Emergency medicine", "q": "A 7-year-old Thai boy with a dog bite (small laceration, active oozing). At age 3 he received a full 5-dose rabies vaccine series after a cat bite (completed at age 5). Otherwise healthy. Most appropriate management?", "choices": ["Reassurance and wound cleaning", "Rabies vaccine booster + Rabies Immunoglobulin (RIG)", "Rabies vaccine booster + RIG + Tetanus toxoid", "Rabies vaccine booster only", "Tetanus toxoid alone"], "ans": 3, "exp": "เคยฉีดวัคซีนพิษสุนัขบ้าครบชุดมาก่อน + สัมผัสซ้ำ -> ฉีด booster (2 เข็ม) โดยไม่ต้องให้ RIG", "sys": "emergency"}, {"topic": "Emergency medicine", "q": "A 40-year-old gardener with pinpoint pupils (1 mm), agitation, and muscle fasciculations. Clothing smells of chemicals. No trauma/fever. Immediate intervention?", "choices": ["IV Naloxone", "IV Pralidoxime", "Activated charcoal", "Oxygen supplementation", "IV Atropine"], "ans": 4, "exp": "organophosphate poisoning -> ให้ atropine IV ทันทีเป็นอันดับแรก (แก้ muscarinic effect) แล้วตามด้วย pralidoxime", "sys": "emergency"}, {"topic": "Pediatrics", "q": "A previously healthy 3-year-old girl with sudden cough followed by stridor while playing with small toys. T 37.2, RR 34, HR 120. Silent cough, inspiratory stridor, suprasternal retractions, poor air entry bilaterally. No fever. Most appropriate immediate management?", "choices": ["Back blows/chest thrusts", "Nebulized adrenaline", "Nebulized salbutamol", "Endotracheal intubation", "IM adrenaline"], "ans": 0, "exp": "foreign body aspiration ที่อุดกั้นรุนแรง (silent cough = ไอไม่ได้ผล + poor air entry) แต่ยังรู้สึกตัว -> ทำ back blows/chest thrusts เพื่อขับสิ่งแปลกปลอม", "sys": "IV"}, {"topic": "Emergency medicine", "q": "A 60-year-old female farmer 30 minutes after a cobra bite to the dorsum of her foot. Mild swelling and two fang marks. Stable vitals, no ptosis/dyspnea/weakness. Most appropriate initial management?", "choices": ["Venom detection kit (VDK)", "Neurological observation alone", "Polyvalent snake antivenom", "Coagulation studies (PT/PTT)", "Wound debridement + broad-spectrum antibiotics"], "ans": 1, "exp": "งูเห่า (neurotoxic) กัด ยังไม่มีอาการพิษต่อระบบประสาท -> เฝ้าระวังอาการทางระบบประสาท (neurological observation) ให้ antivenom เมื่อมีสัญญาณพิษ", "sys": "emergency"}, {"topic": "Emergency medicine", "q": "A 35-year-old farmer bitten by a king cobra (neurotoxic) on the right hand 30 minutes ago, with localized pain, swelling, paresthesia, no systemic symptoms yet. Most appropriate immediate action?", "choices": ["Apply a tight tourniquet proximal to the bite", "Incise the wound and attempt venom suction", "Immobilize the limb and apply a pressure bandage", "Administer intravenous antivenom", "Clean the wound and apply ice packs"], "ans": 2, "exp": "งูพิษต่อระบบประสาท -> ปฐมพยาบาลด้วย pressure immobilization (ดามแขนขา + พันผ้ายืดกดเบา ๆ) ชะลอการดูดซึมพิษ; ห้ามรัด tourniquet แน่น/กรีดดูด", "sys": "emergency"}, {"topic": "Emergency medicine", "q": "A 10-year-old trapped in a house fire for 3 hours, initially comfortable then lightheaded. Cherry-red appearance. ABG: pH 7.35, pCO2 40, pO2 80, HCO3 18, lactate 5. Most appropriate antidote?", "choices": ["N-acetylcysteine", "Sodium bicarbonate", "100% oxygen", "Hydroxocobalamin", "Methylene blue"], "ans": 3, "exp": "ควันไฟ + lactic acidosis รุนแรง (lactate 5) + histotoxic hypoxia = cyanide poisoning -> antidote คือ hydroxocobalamin", "sys": "emergency"}, {"topic": "Emergency medicine", "q": "A 45-year-old collapses with sudden chest pain, unresponsive with no pulse. ECG shows asystole. Next immediate step?", "choices": ["IV atropine 1 mg", "IV amiodarone 300 mg", "Defibrillation 200 J", "Synchronized cardioversion", "Continue chest compressions"], "ans": 4, "exp": "asystole (non-shockable) -> ทำ CPR (chest compressions) ต่อเนื่อง + ให้ epinephrine (ไม่ช็อกไฟฟ้า/ไม่ atropine)", "sys": "emergency"}, {"topic": "Emergency medicine", "q": "A 34-year-old rescued from a burning building with carbonaceous sputum, hoarseness, singed eyebrows/nasal hairs, 2nd-degree facial burns, and 3rd-degree chest burns. P 110, BP 140/80, RR 28. Most immediate management?", "choices": ["Endotracheal intubation", "Escharotomy", "Sterile wound dressing", "Bronchoscopy", "IV Ringer's lactate bolus"], "ans": 0, "exp": "inhalation injury + สัญญาณทางเดินหายใจ (carbonaceous sputum, เสียงแหบ, ขนจมูก/คิ้วไหม้) -> รีบใส่ท่อช่วยหายใจ (ETT) ก่อนทางเดินหายใจบวมอุดตัน", "sys": "emergency"}, {"topic": "Emergency medicine", "q": "A 40-year-old with a 1-minute generalized tonic-clonic seizure, stopped daily heavy alcohol 1 day ago, no epilepsy/trauma. Diagnosis?", "choices": ["Epilepsy", "Alcohol withdrawal seizure", "Meningitis", "Hepatic encephalopathy", "Hyponatremia"], "ans": 1, "exp": "ชักภายใน 1-2 วันหลังหยุดสุราในผู้ดื่มหนัก = alcohol withdrawal seizure", "sys": "emergency"}, {"topic": "Emergency medicine", "q": "A 22-year-old woman with fever, headache, neck stiffness, and photophobia. CSF Gram stain shows gram-negative intracellular diplococci. Most appropriate antibiotic?", "choices": ["Vancomycin", "Clindamycin", "Ceftriaxone", "Ampicillin", "Gentamicin"], "ans": 2, "exp": "meningococcal meningitis (gram-negative intracellular diplococci) -> ceftriaxone", "sys": "emergency"}, {"topic": "Emergency medicine", "q": "A 35-year-old bitten by a cobra on the left leg 1 hour ago, hemodynamically stable, no ptosis/dysphagia/respiratory distress, minimal local swelling, normal neuro. Appropriate initial management?", "choices": ["Administer cobra-specific antivenom immediately", "Check venous clotting time", "Administer tetanus toxoid", "Serial neurological observations every 30 minutes", "IV antibiotics"], "ans": 3, "exp": "งูเห่ากัดที่ยังไม่มีสัญญาณพิษต่อระบบประสาท -> เฝ้าสังเกตอาการทางระบบประสาททุก 30 นาที (ให้ antivenom เมื่อมีอาการ)", "sys": "emergency"}, {"topic": "Psychiatry", "q": "A 25-year-old woman with acute hyperventilation, perioral numbness, and carpopedal spasms after an emotional stressor. Tachypnea and anxiety, no cyanosis. ABG confirms respiratory alkalosis. Most appropriate initial management?", "choices": ["Antipsychotic medication", "Benzodiazepine", "Rebreathing into a paper bag", "Cognitive behavioral therapy", "Reassurance and breathing exercises"], "ans": 4, "exp": "hyperventilation syndrome -> รักษาด้วยการให้ความมั่นใจ (reassurance) และฝึกควบคุมการหายใจช้า ๆ (paper-bag rebreathing ปัจจุบันไม่แนะนำเพราะเสี่ยง hypoxia)", "sys": "V"}, {"topic": "Psychiatry", "q": "An 18-year-old female with daily crying spells for 1 week after failing an exam and arguing with her father. Anorexia but continues basic activities. Denies suicidal ideation but expresses hopelessness. Most critical initial action?", "choices": ["Suicide risk assessment", "Inpatient hospitalization", "Psychotherapy referral", "Intramuscular haloperidol", "Cognitive behavioral therapy"], "ans": 0, "exp": "ผู้ป่วยที่แสดงความสิ้นหวัง (hopelessness) -> สิ่งสำคัญที่สุดคือประเมินความเสี่ยงการฆ่าตัวตาย (suicide risk assessment) ก่อน", "sys": "V"}, {"topic": "Psychiatry", "q": "A 30-year-old man with recurrent transient loss of consciousness (5 min) preceded by rhythmic jerking of the right hand spreading to the arm over 2 minutes, then generalized tonic-clonic movements, with post-ictal confusion and right arm weakness. Three attacks this year, EEG left temporal spikes. Most appropriate long-term management?", "choices": ["Diazepam PRN", "Phenytoin", "Clonazepam", "Phenobarbital", "Sodium valproate"], "ans": 1, "exp": "focal seizure with secondary generalization (Jacksonian march + Todd's paresis + EEG focal spikes) -> ยากันชักสำหรับ focal seizure เช่น phenytoin/carbamazepine", "sys": "V"}, {"topic": "Psychiatry", "q": "A 58-year-old widow grieving her husband's death 3 months ago, with insomnia but normal appetite and activities, denies suicidal ideation. Unremarkable exam. Most appropriate management?", "choices": ["Refer to psychiatrist", "Start antidepressant", "Reassure (normal grief process)", "Spiritual support", "Formal clinical assessment for depression"], "ans": 2, "exp": "ความโศกเศร้าปกติ (normal grief) 3 เดือน ยังทำหน้าที่ได้ ไม่มี SI -> ให้ความมั่นใจว่าเป็นกระบวนการโศกเศร้าปกติ", "sys": "V"}, {"topic": "Psychiatry", "q": "A 26-year-old male removed his pants in a public park claiming 'God ordered me to love all women.' Normal vitals and labs, no substance/psychiatric history. Most appropriate management?", "choices": ["Diazepam", "Clonazepam", "Haloperidol", "Psychiatric admission for evaluation", "Fluoxetine"], "ans": 3, "exp": "first-episode psychosis ที่มีพฤติกรรมเสี่ยง/ผิดปกติในที่สาธารณะ -> รับไว้ประเมินในโรงพยาบาลจิตเวช (psychiatric admission) เพื่อประเมินและรักษา", "sys": "V"}, {"topic": "Psychiatry", "q": "A 75-year-old woman with progressive memory loss, confusion, and difficulty performing daily tasks over 1 year. No focal deficits, no vascular history. Most appropriate pharmacotherapy?", "choices": ["Memantine", "Rivastigmine", "Sertraline", "Haloperidol", "Donepezil"], "ans": 4, "exp": "Alzheimer's dementia ระยะเริ่ม-ปานกลาง -> ยา first-line คือ cholinesterase inhibitor (donepezil)", "sys": "V"}, {"topic": "Psychiatry", "q": "An 18-year-old female ingests bath cream after failing a final exam. No suicidal intent/depression/prior attempts. After decontamination she is remorseful and denies further self-harm. Academic stressor only. Most likely diagnosis?", "choices": ["Adjustment disorder", "Generalized anxiety disorder", "Major depressive disorder (MDD)", "Conversion disorder", "Attention-seeking behavior"], "ans": 0, "exp": "พฤติกรรมทำร้ายตนเองแบบหุนหันหลังความเครียดเฉพาะ (สอบตก) โดยไม่มีเจตนาฆ่าตัวตาย/ซึมเศร้า = adjustment disorder", "sys": "V"}, {"topic": "Psychiatry", "q": "A 40-year-old with alcoholic hepatitis (6 beers/day for 15 years) seeking alcohol cessation, with nausea, vomiting, and tremors during abstinence. No seizures/hallucinations, tremors but no delirium. Most appropriate treatment?", "choices": ["Disulfiram", "Lorazepam", "Vitamins B1/B6/B12", "Alprazolam", "Haloperidol"], "ans": 1, "exp": "alcohol withdrawal (มือสั่น คลื่นไส้อาเจียน) -> รักษาด้วย benzodiazepine; เลือก lorazepam (ไม่มี active metabolite เหมาะกับผู้มีโรคตับ)", "sys": "V"}, {"topic": "Psychiatry", "q": "A 40-year-old brought by his wife for bizarre behavior (talking to traffic lights) and amnesia. Daily alcohol use, binge-drank today. Somnolent, flushed, with alcohol odor. RR 24, otherwise normal. Most likely diagnosis?", "choices": ["Hypoglycemia", "Transient global amnesia", "Acute alcohol intoxication", "Alcohol withdrawal", "Alcohol-induced psychosis"], "ans": 2, "exp": "ดื่มหนักวันนี้ + ซึม หน้าแดง กลิ่นสุรา + พฤติกรรมผิดปกติ/หลงลืม = acute alcohol intoxication", "sys": "V"}, {"topic": "Psychiatry", "q": "A 75-year-old woman with progressive memory loss over 5 years, unable to recognize family, requiring ADL assistance, with nocturnal agitation and hallucinations of her deceased husband. Disorientation and impaired memory. Most appropriate pharmacotherapy?", "choices": ["Vitamin B1 (thiamine)", "Diazepam", "Haloperidol", "Donepezil", "Ginkgo biloba"], "ans": 3, "exp": "dementia (Alzheimer) -> การรักษาโรคด้วย cholinesterase inhibitor (donepezil). (อาการ agitation/hallucination เฉียบพลันจึงใช้ยา antipsychotic ขนาดต่ำเฉพาะช่วง)", "sys": "V"}, {"topic": "Internal medicine", "q": "A 20-year-old woman with poorly controlled HIV (poor adherence) with fever (38), neck stiffness, oral hairy leukoplakia, and a generalized pruritic pustular rash. Most likely diagnosis?", "choices": ["Bacterial meningitis", "Viral meningitis", "Toxoplasma encephalitis", "CMV encephalitis", "Cryptococcal meningitis"], "ans": 4, "exp": "HIV ภูมิต่ำ + เยื่อหุ้มสมองอักเสบ + ผื่นตุ่มหนองกระจาย (disseminated cryptococcosis มักมีรอยโรคผิวหนังคล้าย molluscum) = cryptococcal meningitis", "sys": "I"}, {"topic": "Psychiatry", "q": "A 67-year-old woman with depressed mood 3 months after her husband's death, persistent worthlessness and suicidal ideation. For 2 weeks socially withdrawn and observed talking to herself. Most likely diagnosis?", "choices": ["Major depressive disorder", "Dysthymia", "Brief psychotic disorder", "Adjustment disorder with depressed mood", "Schizoaffective disorder, depressive type"], "ans": 0, "exp": "ซึมเศร้า + รู้สึกไร้ค่า + คิดฆ่าตัวตาย + มีอาการโรคจิต (พูดกับตัวเอง) ในช่วง depressive episode = major depressive disorder with psychotic features", "sys": "V"}, {"topic": "Psychiatry", "q": "A 65-year-old man with progressive forgetfulness over 6 months, nocturnal confusion, and wandering. Disorientation, inability to draw a clock, and word-finding difficulties. Most likely diagnosis?", "choices": ["Delirium", "Alzheimer disease", "Late-onset schizophrenia", "Vascular dementia", "Lewy body dementia"], "ans": 1, "exp": "ความจำเสื่อมค่อยเป็นค่อยไปหลายเดือน + สับสน + วาดนาฬิกาไม่ได้ + นึกคำไม่ออก = Alzheimer disease", "sys": "V"}, {"topic": "Psychiatry", "q": "A 70-year-old woman requiring full assistance for daily activities with nocturnal disorientation. Impaired recall, inability to draw figures, disorientation to time/place/person. Diagnosis?", "choices": ["Delirium", "Korsakoff encephalopathy", "Alzheimer disease", "Mild cognitive impairment", "Vascular dementia"], "ans": 2, "exp": "dementia รุนแรง (ช่วยเหลือตัวเองไม่ได้ + global cognitive impairment ค่อยเป็นค่อยไป) = Alzheimer disease", "sys": "V"}, {"topic": "Psychiatry", "q": "A 40-year-old chronic alcohol user with 2 days of confusion, parotid enlargement, nystagmus, and ataxia, disoriented to time/place/person. Diagnosis?", "choices": ["Delirium", "Delirium tremens", "Chronic subdural hematoma", "Wernicke encephalopathy", "Alcohol withdrawal"], "ans": 3, "exp": "triad: confusion + nystagmus/ophthalmoplegia + ataxia ในผู้ติดสุรา = Wernicke encephalopathy (ขาด thiamine)", "sys": "V"}, {"topic": "Psychiatry", "q": "A male with a generalized tonic-clonic seizure 1 day after alcohol cessation, with mild hand tremors. Diagnosis?", "choices": ["Meningitis", "Encephalitis", "Acute intoxication", "Metabolic encephalopathy", "Alcohol withdrawal seizure"], "ans": 4, "exp": "ชัก + มือสั่น ภายใน 1-2 วันหลังหยุดสุรา = alcohol withdrawal seizure", "sys": "V"}, {"topic": "Psychiatry", "q": "A 75-year-old woman with progressive memory loss over 5 years, inability to recognize family, loss of self-care, and nocturnal hallucinations of her deceased husband. Global cognitive impairment. Which medication is most appropriate for acute symptom control?", "choices": ["Haloperidol", "Vitamin B1 (Thiamine)", "Diazepam", "Donepezil", "Ginkgo biloba"], "ans": 0, "exp": "อาการ agitation/ประสาทหลอนเฉียบพลันใน dementia -> ควบคุมอาการด้วย antipsychotic ขนาดต่ำ (haloperidol) ระยะสั้น (donepezil ใช้รักษาโรค ไม่ใช่คุมอาการเฉียบพลัน)", "sys": "V"}, {"topic": "Psychiatry", "q": "A 24-year-old hypersthenic male brought to the ER after removing his pants in a public park, reporting auditory hallucinations of God commanding him to 'protect women.' Agitated, disorganized, no prior psychiatric history. Stable vitals. Most appropriate initial pharmacotherapy?", "choices": ["Valproic acid", "Haloperidol", "Diazepam", "Clonazepam", "Olanzapine"], "ans": 1, "exp": "acute psychosis + agitation -> ควบคุมอาการด้วย antipsychotic (haloperidol) เป็น first-line ในภาวะเฉียบพลัน", "sys": "V"}, {"topic": "Psychiatry", "q": "A 16-year-old girl with sudden palpitations, dizziness, hand numbness, a sensation of impending death, and dyspnea during a school exam. Symptoms peak in 5 minutes and resolve spontaneously. No prior cardiac/respiratory history. Most likely diagnosis?", "choices": ["Hyperventilation syndrome", "Conversion disorder", "Panic attack", "Generalized anxiety disorder", "Post-traumatic stress disorder"], "ans": 2, "exp": "อาการเฉียบพลันถึงจุดสูงสุดใน 5 นาที (ใจสั่น ชา กลัวตาย หายใจไม่อิ่ม) แล้วหายเอง = panic attack", "sys": "V"}, {"topic": "Psychiatry", "q": "A 25-year-old male brought by friends after claiming he is 'in heaven with angels.' History of recreational drug use, unknown substance. Marked bilateral conjunctival injection and euphoria. Which substance is most likely responsible?", "choices": ["Ecstasy", "Cocaine", "LSD", "Cannabis", "Amphetamines"], "ans": 3, "exp": "ตาแดง (conjunctival injection) + ครึกครื้น/euphoria = cannabis", "sys": "V"}, {"topic": "Family medicine", "q": "An 80-year-old woman with well-controlled HT and dyslipidemia at a routine visit. The physician reviews her medications, checks for adverse effects (edema, myalgia), and screens for drug interactions. What type of prevention is this?", "choices": ["Primordial prevention", "Primary prevention", "Secondary prevention", "Tertiary prevention", "Quaternary prevention"], "ans": 4, "exp": "การป้องกันอันตรายจากการรักษา/ยาเกินจำเป็น (ทบทวนยา ผลข้างเคียง ปฏิกิริยาระหว่างยา) = quaternary prevention (ป้องกัน over-medicalization/iatrogenesis)", "sys": "general"}, {"topic": "Family medicine", "q": "A 30-year-old male with BP 120/80 and waist circumference 95 cm. FBS 102, total cholesterol 200, triglycerides 250, HDL 20. No symptoms. Most likely diagnosis?", "choices": ["Metabolic syndrome", "Diabetes mellitus", "Pre-diabetes", "Dyslipidemia", "Obesity"], "ans": 0, "exp": "เข้าเกณฑ์ metabolic syndrome >=3 ข้อ: รอบเอวเกิน (>90 ชายเอเชีย) + TG >=150 + HDL <40 + FBS >=100 = metabolic syndrome", "sys": "general"}, {"topic": "Family medicine", "q": "A 35-year-old man with fever (38.5), myalgia, hoarseness, sore throat, and tender anterior cervical nodes for 2 days. No exudate or rash. Most appropriate treatment?", "choices": ["Amoxicillin", "Supportive care", "Oseltamivir", "Levofloxacin", "Azithromycin"], "ans": 1, "exp": "คออักเสบจากไวรัส (เสียงแหบ ไม่มี exudate) -> รักษาประคับประคอง (supportive care) ไม่ต้องยาปฏิชีวนะ", "sys": "general"}, {"topic": "Family medicine", "q": "A 25-year-old woman with 3 months of recurrent headaches, each ~4 hours, unilateral throbbing with scintillating scotoma, nausea, and photophobia, with prodromal visual symptoms lasting 15 minutes. No focal deficits. Most likely diagnosis?", "choices": ["Tension headache", "Intracranial aneurysm", "Migraine", "Cluster headache", "Sinusitis"], "ans": 2, "exp": "ปวดข้างเดียวตุบ ๆ + คลื่นไส้ กลัวแสง + aura (scintillating scotoma นำมาก่อน 15 นาที) = migraine with aura", "sys": "general"}, {"topic": "Family medicine", "q": "A 10-year-old boy with a 2-week enlarging rash on the anterior chest wall, a 4 cm erythematous patch with a scaly, raised border and central clearing, mildly pruritic. No fever/bites/travel. Most appropriate topical treatment?", "choices": ["Acyclovir cream", "Trimethoprim cream", "Mupirocin cream", "Clotrimazole cream", "Triamcinolone cream"], "ans": 3, "exp": "ผื่นวงแดงขอบนูนเป็นขุย ตรงกลางใส = tinea corporis -> ทายาฆ่าเชื้อรา clotrimazole", "sys": "general"}, {"topic": "Rehabilitation medicine", "q": "A 55-year-old woman with T2DM (on metformin) with 6 months of hand numbness. Thenar muscle atrophy, sensory loss in the volar thumb and index finger, positive Tinel's sign at the wrist. No neck/elbow abnormalities. Most likely diagnosis?", "choices": ["Diabetic neuropathy", "Cubital tunnel syndrome", "Medial epicondylitis", "Lateral epicondylitis", "Carpal tunnel syndrome"], "ans": 4, "exp": "thenar atrophy + ชา median distribution + Tinel's ที่ข้อมือบวก = carpal tunnel syndrome", "sys": "IV"}, {"topic": "Family medicine", "q": "A 22-year-old woman with a painful, shallow ulcer on the lower lip mucosa for 3 days. No fever/trauma/prior lesions. Single 5-mm ulcer with an erythematous halo. Best initial treatment?", "choices": ["Topical triamcinolone", "Oral acyclovir", "Topical antibiotic", "Oral prednisolone", "Observation only"], "ans": 0, "exp": "aphthous ulcer (แผลตื้นเจ็บ ขอบแดง แผลเดียว) -> topical corticosteroid (triamcinolone in orabase)", "sys": "general"}, {"topic": "Family medicine", "q": "A 20-year-old male with a hyperkeratotic, skin-colored papule on the dorsum of the hand (corn/callus), painless, present for 6 months. Most appropriate treatment?", "choices": ["Incision and drainage", "20% urea cream (keratolytic)", "Cryotherapy", "Electrocauterization", "0.1% triamcinolone ointment"], "ans": 1, "exp": "corn/callus (หนังด้าน) -> ใช้ยาละลายขี้ไคล (keratolytic) เช่น 20% urea cream", "sys": "general"}, {"topic": "Family medicine", "q": "A 40-year-old male with erythematous, greasy scales on the scalp, eyebrows, beard, and nasolabial folds. Non-pruritic and chronic. Most likely diagnosis?", "choices": ["Psoriasis", "Systemic lupus erythematosus", "Seborrheic dermatitis", "Tinea faciei/capitis", "Contact dermatitis"], "ans": 2, "exp": "ผื่นแดงเป็นขุยมัน (greasy) ตามบริเวณต่อมไขมันมาก (หนังศีรษะ คิ้ว ร่องจมูก เครา) = seborrheic dermatitis", "sys": "general"}, {"topic": "Family medicine", "q": "A shallow, soft oral ulcer with erythematous borders at the lower lip commissure, no vesicles/crusting, history of frequent lip-licking. First-line management?", "choices": ["Topical antibiotic", "Acyclovir cream", "Normal saline irrigation", "Triamcinolone cream", "Oral fluconazole"], "ans": 3, "exp": "แผลในปาก (aphthous/traumatic) -> topical corticosteroid (triamcinolone) เป็น first-line", "sys": "general"}, {"topic": "Family medicine", "q": "A 25-year-old man whose father was diagnosed with colorectal cancer at age 45. Asymptomatic, unremarkable exam, negative fecal occult blood test. Most appropriate screening plan?", "choices": ["Annual serum CEA", "Annual fecal occult blood test", "Sigmoidoscopy now", "Barium enema at age 45", "Colonoscopy at age 35"], "ans": 4, "exp": "ญาติสายตรงเป็นมะเร็งลำไส้ใหญ่ตอนอายุ 45 -> เริ่มส่องกล้อง colonoscopy ที่อายุ 40 หรือ 10 ปีก่อนอายุที่ญาติเป็น (45-10 = 35) แล้วแต่อันไหนก่อน = อายุ 35", "sys": "general"}, {"topic": "Family medicine", "q": "A 22-year-old man with acute fever, headache, sore throat, and enlarged cervical lymph nodes (2 cm). Pharyngeal erythema without exudate or tonsillar hypertrophy. Most appropriate treatment?", "choices": ["Supportive care", "Oral amoxicillin", "Oral acyclovir", "IM benzathine penicillin", "Oral fluconazole"], "ans": 0, "exp": "คออักเสบจากไวรัส (ไม่มี exudate/tonsillar hypertrophy) -> รักษาประคับประคอง (supportive care)", "sys": "general"}, {"topic": "Family medicine", "q": "A 21-year-old sexually active man requests hepatitis risk assessment. No underlying conditions/jaundice/symptoms, inconsistent condom use, HIV-negative. Most appropriate action?", "choices": ["Test for HBsAg and anti-HCV", "Administer hepatitis B vaccine", "Administer hepatitis A vaccine", "Liver function tests", "Reassure and discharge"], "ans": 1, "exp": "ชายมีเพศสัมพันธ์เสี่ยง (ไม่ป่วย/ไม่มีอาการ) -> ป้องกันด้วยการฉีดวัคซีนไวรัสตับอักเสบบี (hepatitis B vaccine) ถ้ายังไม่มีภูมิ", "sys": "general"}, {"topic": "Community/EBM", "q": "A district reports 10% overweight/obesity prevalence (national 5%). Which strategy is most effective for population-level prevention?", "choices": ["Increase health education time in schools", "Encourage periodic weight monitoring in schools", "Increase weekly physical exercise time in schools", "Mass media campaigns for obesity awareness", "Provide obesity health counseling"], "ans": 2, "exp": "มาตรการระดับประชากรที่ได้ผลคือการปรับสิ่งแวดล้อม/โครงสร้าง เช่น เพิ่มเวลาออกกำลังกายในโรงเรียน (ครอบคลุมทุกคน) มากกว่าการให้ความรู้/คำปรึกษารายบุคคล", "sys": "general"}, {"topic": "Community/EBM", "q": "A kindergarten reports one child with hand-foot-mouth disease; others asymptomatic. Per Thailand's public health guidelines, most effective measure to prevent an outbreak?", "choices": ["Allow the infected child to attend school", "Vaccinate all children", "Mandate mask-wearing", "Exclude the infected child until lesions crust", "Close the school for 1 week"], "ans": 3, "exp": "HFMD -> แยกเด็กที่ป่วยออก (ให้หยุดเรียนจนแผลตกสะเก็ด/หายแพร่เชื้อ) ร่วมสุขอนามัย ไม่ต้องปิดโรงเรียน", "sys": "general"}, {"topic": "Family medicine", "q": "A healthy 28-year-old woman with no anemia history and normal exam. CBC: Hb 10 (normocytic), WBC 8,500, normal platelets. Heavy menstrual bleeding. Most appropriate initial investigation?", "choices": ["Hemoglobin electrophoresis", "Vitamin B12 and folate levels", "Peripheral blood smear", "Coagulation studies", "Serum ferritin and TIBC"], "ans": 4, "exp": "ซีดจากประจำเดือนมามาก (เสียเลือดเรื้อรัง) = iron deficiency (ระยะแรกอาจ normocytic) -> ตรวจ serum ferritin และ TIBC", "sys": "general"}, {"topic": "Family medicine", "q": "A 55-year-old man with clinic BP 150/90 on two visits. Home BP logs (twice daily for 7 days) average 125/80. No diabetes/end-organ damage. Appropriate management?", "choices": ["Lifestyle modifications (salt restriction, exercise)", "Continue home BP monitoring for 4 weeks", "Start amlodipine 5 mg daily", "Ambulatory BP monitoring", "Reassurance and annual follow-up"], "ans": 0, "exp": "white coat hypertension (ความดันที่คลินิกสูงแต่ที่บ้านปกติ) -> ไม่ต้องเริ่มยา; แนะนำปรับพฤติกรรม (lifestyle) + ติดตามความดันที่บ้าน", "sys": "general"}, {"topic": "Family medicine", "q": "A 20-year-old female marathon runner with previously regular menses reports 6 months of amenorrhea. Trains intensively (80 km/week), low body fat, no other symptoms. Most appropriate initial investigation?", "choices": ["Prolactin level", "Urine pregnancy test (UPT)", "Estradiol level", "Thyroid-stimulating hormone (TSH)", "Follicle-stimulating hormone (FSH)"], "ans": 1, "exp": "secondary amenorrhea -> ตรวจ urine pregnancy test ก่อนเสมอ เพื่อแยกการตั้งครรภ์ (แม้จะสงสัย functional hypothalamic amenorrhea จากการออกกำลังหนัก)", "sys": "general"}, {"topic": "Community/EBM", "q": "A dengue vaccine trial: incidence 5% in vaccinated and 25% in placebo. Number needed to treat (NNT) to prevent one case?", "choices": ["0.2", "0.5", "5", "1.2", "20"], "ans": 2, "exp": "ARR = 25% - 5% = 20% = 0.2; NNT = 1/0.2 = 5", "sys": "general"}, {"topic": "Community/EBM", "q": "A cohort of 3,000 tracked 2000-2010 identifies 1,000 with Hepatitis B. By 2024, 400 HepB-positive and 200 HepB-negative develop HCC. Relative risk of HCC in Hepatitis B vs non-infected?", "choices": ["OR = 4.0", "AR = 6.0", "RR = 6.0", "RR = 4.0", "OR = 6.0"], "ans": 3, "exp": "risk ในกลุ่ม HepB = 400/1000 = 0.4; risk ในกลุ่มไม่ติดเชื้อ = 200/2000 = 0.1; RR = 0.4/0.1 = 4.0", "sys": "general"}, {"topic": "Community/EBM", "q": "An outbreak affects 15,000 people with 1,200 cases and 60 deaths. To identify risk factors in this defined population, most appropriate study design?", "choices": ["Case-control study", "Cross-sectional study", "Randomized controlled trial", "Ecological study", "Retrospective cohort study"], "ans": 4, "exp": "การสอบสวนการระบาดในประชากรที่นิยามได้ (15,000 คน) -> retrospective cohort study เปรียบเทียบอัตราป่วยตามการสัมผัสปัจจัยเสี่ยง", "sys": "general"}, {"topic": "Community/EBM", "q": "In a dengue vaccine trial, 5% of vaccinated and 25% of placebo develop dengue. Number needed to treat (NNT)?", "choices": ["5", "3", "4", "6", "10"], "ans": 0, "exp": "ARR = 25% - 5% = 20% = 0.2; NNT = 1/0.2 = 5", "sys": "general"}, {"topic": "Forensic medicine", "q": "A 40-year-old male found deceased with a gunshot wound (shown). Most likely firing distance?", "choices": ["Blast range", "Close range", "Blunt force trauma", "Contact range", "Distant range"], "ans": 1, "exp": "*จากภาพจริง* มี stippling/powder tattooing (จุดกระสุนดินปืนฝังรอบแผล) แต่ไม่มี muzzle imprint = close (intermediate) range. ระยะไกลจะไม่มี stippling; ระยะจ่อจะมีเขม่า/รอยปากกระบอกปืน. *อ้างอิงภาพ*", "img": "https://cdn.jsdelivr.net/gh/MercenzK/Web-quiz-images@main/NL2-2025-Apr-Q312.png", "sys": "general"}, {"topic": "Forensic medicine", "q": "A man found deceased in a hotel room with a plastic bag taped over his head, a deep wrist laceration, a knife nearby, and an empty alprazolam packet. Autopsy shows no defensive wounds or signs of struggle. Most likely autopsy conclusion?", "choices": ["Autopsy inconclusive", "Assisted suicide", "Suicide", "Accidental death", "Homicide"], "ans": 2, "exp": "หลายวิธีทำร้ายตนเอง (ถุงพลาสติกคลุมหัว + กรีดข้อมือ + ยา) + ไม่มีบาดแผลป้องกัน/ร่องรอยต่อสู้ = suicide", "sys": "general"}, {"topic": "Forensic medicine", "q": "A 10-year-old boy drowned in a swimming pool, leading to unconsciousness, pulmonary edema, and hyperkalemia. He developed hospital-acquired pneumonia and died 2 days later. Autopsy shows aspiration and diffuse alveolar damage. Underlying cause of death for certification?", "choices": ["Pneumonia", "Immersion death", "Cardiac arrhythmia", "Accidental drowning", "Respiratory failure"], "ans": 3, "exp": "underlying cause of death = เหตุการณ์ที่เริ่มลำดับการตาย = การจมน้ำ (accidental drowning); pneumonia/respiratory failure เป็นผลตามมา (immediate cause)", "sys": "general"}, {"topic": "Forensic medicine", "q": "A 10-year-old boy reports anal tenderness 2 weeks after a suspected sexual assault. No acute injury on exam. Proper specimen for forensic diagnosis?", "choices": ["Swab for spermatozoa", "Swab for epithelial cells (DNA)", "Anus washing for acid phosphatase", "Serum HIV test", "Swab for STI pathogens"], "ans": 4, "exp": "ผ่านมา 2 สัปดาห์ อสุจิ/acid phosphatase/DNA สลายไปแล้ว -> ตรวจหาเชื้อโรคติดต่อทางเพศ (STI pathogens) เป็นหลักฐาน", "sys": "general"}, {"topic": "Forensic medicine", "q": "A deceased person found in a locked room with a knife and old bloodstains on the bed, prescription sedatives nearby, a black bag over the head, no visible wounds, no suicide note. Appropriate conclusion?", "choices": ["Manner of death is suicide", "Cause of death cannot be determined", "Manner of death is homicide", "Manner of death is accident", "Natural causes"], "ans": 0, "exp": "ห้องล็อกจากด้านใน + ถุงคลุมศีรษะ (self-asphyxiation) + ยานอนหลับ = manner of death เป็น suicide (การไม่มีจดหมายลาตายไม่ตัดการฆ่าตัวตาย)", "sys": "general"}, {"topic": "Medical ethics", "q": "An Islamic adolescent boy found dead on a roadside with injuries suggesting vehicular trauma, no witnesses. Autopsy considered but religious concerns raised. Most appropriate action?", "choices": ["Not necessary - no offender identified", "Perform without parental consent", "Cannot perform due to religious prohibition", "Perform after parental consent", "Consult religious leaders first"], "ans": 1, "exp": "การตายผิดธรรมชาติ (อุบัติเหตุจราจร) เป็น medico-legal death -> ต้องผ่าชันสูตรตามกฎหมาย โดยไม่ต้องขอความยินยอมจากญาติ (แม้มีข้อกังวลทางศาสนา)", "sys": "general"}, {"topic": "Medical ethics", "q": "A 20-year-old sustained a 5 cm scalp laceration from a baseball bat 2 years ago. As a witness in court asked about the weapon type, most appropriate testimony?", "choices": ["'He was hit by a baseball bat.'", "'He could have been hit by a blunt or sharp object.'", "'The injury was caused by a blunt object.'", "'I cannot recall details after 2 years.'", "'I decline to answer.'"], "ans": 2, "exp": "แพทย์ให้การตามลักษณะบาดแผลที่ตรวจพบตามหลักวิชา -> แผลฉีก (laceration) เกิดจากของแข็งไม่มีคม (blunt object) ไม่ระบุอาวุธเฉพาะเจาะจง", "sys": "general"}, {"topic": "Forensic medicine", "q": "An unidentified male corpse found prone. Livor mortis fixed, rigor mortis incomplete, no trauma or chronic disease. Autopsy recommended but relatives decline citing no suspicion. As the attending physician, what should you do?", "choices": ["Certify death as 'cardiac failure'", "Notify local authorities for autopsy", "Respect the relatives' wishes without autopsy", "Notify police for mandatory autopsy", "Perform an external examination only"], "ans": 3, "exp": "ศพนิรนาม + ไม่ทราบสาเหตุการตาย (unnatural/unexplained death) -> ต้องแจ้งตำรวจเพื่อชันสูตรตามกฎหมาย (mandatory autopsy) ไม่ขึ้นกับความยินยอมญาติ", "sys": "general"}, {"topic": "Medical ethics", "q": "A 50-year-old man with end-stage hepatocellular carcinoma unresponsive to treatment, with severe pain, weight loss, jaundice, feels hopeless and asks the physician for a high dose of morphine to die peacefully. Most appropriate response?", "choices": ["Administer high-dose morphine as requested by the patient", "Discuss the situation and obtain consent from the patient's family", "Inform the patient that this request is illegal", "Review the patient's medication history and discuss cancer treatment instead", "Provide psychosocial support"], "ans": 4, "exp": "คำขอทำ euthanasia -> แพทย์ไม่กระทำการเร่งการตาย แต่ตอบสนองด้วยการดูแลความทุกข์ทรมาน (palliative) และให้การสนับสนุนด้านจิตสังคม (psychosocial support) รับฟังและจัดการอาการปวด", "sys": "general"}, {"topic": "Medical ethics", "q": "An 18-month-old boy receives DPT and OPV during a routine visit; the physician then realizes the child was fully vaccinated at 15 months (extra dose). The child is asymptomatic with normal vitals. What should the physician do?", "choices": ["Inform parents about the extra dose and explain minimal risks", "Do not disclose, as the extra dose is trivial", "Administer activated charcoal to mitigate effects", "Admit for 24-hour observation", "Advise monitoring for side effects without disclosure"], "ans": 0, "exp": "หลักความซื่อสัตย์/เปิดเผยความจริง (honesty/disclosure) -> แจ้งผู้ปกครองว่ามีการให้วัคซีนเกิน 1 เข็ม พร้อมอธิบายว่าความเสี่ยงน้อยมาก", "sys": "general"}, {"topic": "Medical ethics", "q": "An English-speaking patient calls to discuss recent treatment but there is a language barrier. He is anxious and seeks clarification. Most appropriate response?", "choices": ["Ask bilingual staff to take over", "Ask bilingual staff to join", "Request in-person visit", "Refer to English-fluent doctor", "Advise messaging via app"], "ans": 1, "exp": "มีอุปสรรคด้านภาษา -> ขอเจ้าหน้าที่ที่พูดได้สองภาษามาช่วยแปล (interpreter) ร่วมในการสื่อสาร โดยแพทย์ยังคงดูแลผู้ป่วยต่อ (ไม่โยนให้คนอื่นแทน)", "sys": "general"}]}, {"id": "nl2-2025-jul", "title": "NL 2 ปี 2025 กรกฎาคม (VICHAKARN_SMST)", "subject": "past", "questions": [{"topic": "Internal medicine", "q": "A 30-year-old man with nausea and vomiting, drinking 1-2 bottles of whiskey daily for 10 years, took paracetamol 2 tabs 4 times/day for headache 1 week ago. BT 37, mild pallor, jaundice, spider angioma, palmar erythema, hepatomegaly, mild RUQ tenderness, no ascites. Diagnosis?", "choices": ["Acetaminophen toxicity", "Acute pancreatitis", "Acute viral hepatitis B", "Ascending cholangitis", "Alcoholic intoxication"], "ans": 0, "exp": "ผู้ติดสุราเรื้อรัง (glutathione พร่อง) ได้ paracetamol ~4 g/วัน 1 สัปดาห์ -> acetaminophen hepatotoxicity แม้ขนาดปกติ", "sys": "VI"}, {"topic": "Internal medicine", "q": "A 40-year-old man with fever, cough, and left-sided pleuritic chest pain. RR 24, T 38. CXR shows moderate pleural effusion. Pleural fluid: pH 7.4, WBC 2500 (90% neutrophils), ADA 45 U/L, glucose 60% of serum. Most appropriate management?", "choices": ["Pleural biopsy", "Empirical antibiotics", "CT chest", "Insertion of chest drain (ICD)", "Anti-tuberculosis therapy"], "ans": 1, "exp": "parapneumonic effusion ชนิดไม่ซับซ้อน (uncomplicated): pH >7.2, glucose ปกติ, neutrophil เด่น (ไม่ใช่ TB ที่ lymphocyte เด่น) -> รักษาด้วยยาปฏิชีวนะอย่างเดียว ยังไม่ต้องใส่ ICD", "sys": "I"}, {"topic": "Internal medicine", "q": "A 65-year-old man with LUTS (straining, incomplete urination, poor stream). DRE reveals enlarged prostate, no nodules. Appropriate treatment?", "choices": ["Transurethral resection of the prostate (TURP)", "Urodynamic study", "Alpha antagonist", "Behavior modification", "5-alpha reductase inhibitor"], "ans": 2, "exp": "BPH ที่มีอาการ -> เริ่มด้วย alpha-antagonist (alpha-blocker) เป็น first-line", "sys": "XIV"}, {"topic": "Internal medicine", "q": "A 55-year-old man with hypertension found to have high LDL and elevated total cholesterol, no diabetes or CVD. Which drug is most appropriate to control his lipids?", "choices": ["Fibrate", "Niacin", "Ezetimibe", "Statin", "Bile acid sequestrant"], "ans": 3, "exp": "LDL สูงเป็นหลัก -> ยาลดไขมันที่ได้ผลและลดความเสี่ยง CV ดีที่สุดคือ statin", "sys": "IV"}, {"topic": "Internal medicine", "q": "A 30-year-old man on first-line tuberculosis therapy develops optic neuritis. Which antituberculosis drug is most likely responsible?", "choices": ["Isoniazid", "Rifampicin", "Pyrazinamide", "Streptomycin", "Ethambutol"], "ans": 4, "exp": "optic neuritis (ตามัว/เห็นสีผิดปกติ) = ผลข้างเคียงของ ethambutol", "sys": "I"}, {"topic": "Internal medicine", "q": "A 65-year-old man with chronic heart failure and exertional dyspnea, already on loop diuretics with partial relief. What additional drug class improves survival?", "choices": ["ACE inhibitor", "Calcium channel blocker", "Digoxin", "Nitrate", "Statin"], "ans": 0, "exp": "HFrEF -> ยาที่ลดอัตราตายคือ ACE inhibitor (และ beta-blocker, MRA, ARNI, SGLT2i). loop diuretic บรรเทาอาการแต่ไม่ลดอัตราตาย; digoxin ลดการ admit ไม่ลดตาย", "sys": "IX"}, {"topic": "Internal medicine", "q": "A 24-year-old woman with newly onset hyperthyroidism, not pregnant, no liver disease. Which medication is preferred as first-line therapy?", "choices": ["Propylthiouracil", "Methimazole", "Radioactive iodine", "Thyroidectomy", "Beta-blocker"], "ans": 1, "exp": "hyperthyroidism ทั่วไป -> methimazole เป็น first-line (ยกเว้นไตรมาสแรกของการตั้งครรภ์/thyroid storm ที่ใช้ PTU)", "sys": "XV"}, {"topic": "Internal medicine", "q": "A 40-year-old man with subacute fever and headache. CSF shows low glucose, high protein, elevated ADA, negative bacterial culture. Most likely diagnosis?", "choices": ["Viral meningitis", "Bacterial meningitis", "Tuberculous meningitis", "Cryptococcal meningitis", "Carcinomatous meningitis"], "ans": 2, "exp": "CSF น้ำตาลต่ำ + โปรตีนสูง + ADA สูง + เพาะเชื้อแบคทีเรียไม่ขึ้น + ดำเนินโรคกึ่งเฉียบพลัน = tuberculous meningitis", "sys": "II"}, {"topic": "Internal medicine", "q": "A 65-year-old man with small cell lung carcinoma presents with confusion and serum sodium 118 mmol/L. Most likely cause of hyponatremia?", "choices": ["Primary polydipsia", "Adrenal insufficiency", "Renal tubular acidosis", "Syndrome of inappropriate ADH", "Congestive heart failure"], "ans": 3, "exp": "small cell lung cancer สร้าง ADH นอกตำแหน่ง -> SIADH ทำให้ hyponatremia (euvolemic)", "sys": "II"}, {"topic": "Internal medicine", "q": "A 50-year-old woman with jaundice and fever. Labs show mildly elevated AST/ALT with disproportionately high alkaline phosphatase (ALP 300). Most likely diagnosis?", "choices": ["Acute viral hepatitis", "Alcoholic hepatitis", "Cirrhosis", "Non-alcoholic fatty liver disease", "Cholestasis"], "ans": 4, "exp": "ALP สูงเด่นกว่า AST/ALT (cholestatic pattern) = cholestasis (การอุดกั้น/คั่งน้ำดี)", "sys": "XI"}, {"topic": "Internal medicine", "q": "A 50-year-old man with alcohol use presents with hematemesis and melena. He is hemodynamically stable. Most appropriate next step?", "choices": ["Emergency endoscopy", "Abdominal CT scan", "Proton pump inhibitor", "Exploratory laparotomy", "Reassurance and discharge"], "ans": 0, "exp": "upper GI bleeding (สงสัย variceal ในผู้ติดสุรา) ที่ stable -> หลังกู้ชีพ/ให้ยา ควรทำ endoscopy เพื่อวินิจฉัยและห้ามเลือด (band ligation) เป็นขั้นตอนสำคัญถัดไป", "sys": "XI"}, {"topic": "Internal medicine", "q": "A 30-year-old man with recurrent, severe unilateral headaches, each with ipsilateral tearing and nasal congestion, occurring daily for several weeks then remitting. Most likely diagnosis?", "choices": ["Migraine", "Cluster headache", "Tension headache", "Trigeminal neuralgia", "Sinusitis"], "ans": 1, "exp": "ปวดศีรษะข้างเดียวรุนแรงเป็นชุด + autonomic symptom ข้างเดียวกัน (น้ำตาไหล คัดจมูก) เป็นทุกวันช่วงหนึ่งแล้วหาย = cluster headache", "sys": "VI"}, {"topic": "Internal medicine", "q": "A 25-year-old woman with painful, red, raised nodules on the anterior surfaces of both legs, with a sore throat 2 weeks ago. Most likely diagnosis?", "choices": ["Cellulitis", "Erythema multiforme", "Erythema nodosum", "Contact dermatitis", "Pyoderma gangrenosum"], "ans": 2, "exp": "ตุ่มก้อนแดงเจ็บที่หน้าแข้งทั้งสองข้าง หลังเจ็บคอ (post-streptococcal) = erythema nodosum. *อ้างอิงภาพ (ผื่นแดงที่ขา; ต้นฉบับตั้งชื่อไฟล์เป็น Q14 แต่เนื้อหาตรงกับข้อนี้)*", "img": "https://cdn.jsdelivr.net/gh/MercenzK/Web-quiz-images@main/NL2-2025-July-Q14.png", "sys": "X"}, {"topic": "Internal medicine", "q": "A 45-year-old woman with poorly controlled diabetes presents with painful white plaques on tongue and buccal mucosa that can be scraped off (oral candidiasis). Most appropriate first-line treatment?", "choices": ["Clotrimazole troche", "Fluconazole oral tablet", "Amphotericin B IV", "Nystatin suspension", "Chlorhexidine mouthwash"], "ans": 3, "exp": "oral candidiasis (thrush) ระดับเล็กน้อย-ปานกลาง -> ยาต้านเชื้อราเฉพาะที่ (nystatin suspension หรือ clotrimazole troche) เป็น first-line; fluconazole รับประทานใช้รายปานกลาง-รุนแรง", "sys": "IV"}, {"topic": "Internal medicine", "q": "A 65-year-old man with bone pain, fatigue, and recurrent infections. Normocytic anemia, hypercalcemia, elevated creatinine, serum protein electrophoresis reveals an M spike. Most likely diagnosis?", "choices": ["Lymphoma", "Waldenstrom macroglobulinemia", "Osteosarcoma", "Chronic lymphocytic leukemia", "Multiple myeloma"], "ans": 4, "exp": "CRAB (hyperCalcemia, Renal failure, Anemia, Bone pain) + M spike = multiple myeloma", "sys": "II"}, {"topic": "Internal medicine", "q": "A 40-year-old man with fever, right upper quadrant pain, and tender hepatomegaly. Ultrasound shows a single hypoechoic lesion in the right hepatic lobe. Amoebic serology positive. Most appropriate initial treatment?", "choices": ["Metronidazole", "Ceftriaxone", "Vancomycin", "Ciprofloxacin", "Amphotericin B"], "ans": 0, "exp": "amoebic liver abscess (ก้อนเดียว + serology บวก) -> รักษาด้วย metronidazole", "sys": "XI"}, {"topic": "Internal medicine", "q": "A 30-year-old woman with fluctuating muscle weakness worsening with activity and improving with rest, difficulty chewing, and diplopia in the evenings. Normal reflexes. Most likely diagnosis?", "choices": ["Guillain-Barre syndrome", "Myasthenia gravis", "Multiple sclerosis", "Lambert-Eaton syndrome", "Amyotrophic lateral sclerosis"], "ans": 1, "exp": "อ่อนแรงมากขึ้นเมื่อใช้งาน (fatigability) + ptosis/diplopia ตอนเย็น + DTR ปกติ = myasthenia gravis", "sys": "VI"}, {"topic": "Internal medicine", "q": "A 65-year-old woman with multiple flat, well-demarcated brown macules on the dorsum of her hands and face, asymptomatic, appearing gradually over several years. Most likely diagnosis?", "choices": ["Seborrheic keratosis", "Melanoma", "Solar lentigo", "Freckles (ephelides)", "Actinic keratosis"], "ans": 2, "exp": "จุดสีน้ำตาลแบนขอบชัดบนบริเวณโดนแดด (มือ/หน้า) ในผู้สูงอายุ ค่อย ๆ เกิด = solar lentigo. freckles มักปรากฏตั้งแต่วัยเด็กและจางในฤดูหนาว", "sys": "II"}, {"topic": "Internal medicine", "q": "A 55-year-old man with CKD presents with muscle weakness. ECG shows tall peaked T waves and widened QRS. Serum potassium 7.2 mmol/L. Most appropriate immediate management?", "choices": ["Insulin with glucose", "Sodium bicarbonate", "Hemodialysis", "Intravenous calcium gluconate", "Sodium polystyrene sulfonate"], "ans": 3, "exp": "hyperkalemia รุนแรงที่มี EKG เปลี่ยนแปลง -> ให้ IV calcium gluconate ก่อนเพื่อ stabilize เยื่อหุ้มหัวใจ แล้วจึงลด K (insulin+glucose, dialysis)", "sys": "IV"}, {"topic": "Internal medicine", "q": "A 28-year-old man with generalized maculopapular rash involving trunk, palms, and soles, with unprotected sexual contact 2 months ago. Most appropriate diagnostic test at this stage?", "choices": ["Dark-field microscopy", "HIV ELISA", "Gram stain", "ANA (antinuclear antibody) test", "VDRL test"], "ans": 4, "exp": "ผื่นทั่วตัวรวมฝ่ามือฝ่าเท้า = secondary syphilis -> ตรวจ serology VDRL/RPR (nontreponemal). dark-field ใช้กับแผล chancre ระยะปฐมภูมิ", "sys": "I"}, {"topic": "Pediatrics", "q": "A 12-month-old boy with relapsing rash at both cheeks for 1 month. Mother has allergic rhinitis. Ill-defined erythematous plaque with excoriation, scale, and yellow crust at both cheeks. Most likely diagnosis?", "choices": ["Atopic dermatitis", "Tinea faciei", "Contact dermatitis", "Impetigo contagiosa", "Seborrheic dermatitis"], "ans": 0, "exp": "ผื่นเรื้อรังเป็น ๆ หาย ๆ ที่แก้มทั้งสองข้างในทารก + ประวัติภูมิแพ้ในครอบครัว = atopic dermatitis (infantile, มักที่แก้ม/ด้าน extensor)", "sys": "X"}, {"topic": "Pediatrics", "q": "A 12-month-old boy with episodic cessation of inspiration and expiration when frustrated, lasting 1-2 minutes with full recovery. No birth asphyxia or head injury, normal exam. Most likely diagnosis?", "choices": ["Syncope", "Breath holding spell", "Hypoxic spell", "Absence seizure", "Temper tantrums"], "ans": 1, "exp": "หยุดหายใจชั่วคราวเมื่อโกรธ/ร้องไห้ แล้วฟื้นเองสนิท ในเด็กเล็ก = breath holding spell (ไม่อันตราย)", "sys": "XVI"}, {"topic": "Pediatrics", "q": "A 3-year-old girl with generalized edema for 2 weeks. Weight 9 kg, apathy, round face, pitting edema 1+, sparse thin hair, dry peeling skin with hyperkeratosis and hyperpigmentation, liver 3 cm below RCM. Most likely diagnosis?", "choices": ["Hypothyroidism", "Nephrotic syndrome", "Kwashiorkor", "Chronic Renal Failure", "Congestive heart failure"], "ans": 2, "exp": "ภาวะทุพโภชนาการชนิดบวมน้ำ: บวม + ผมบาง/สีจาง + ผิวลอก hyperkeratosis + ตับโต + เฉื่อยชา = kwashiorkor (ขาดโปรตีน)", "sys": "IV"}, {"topic": "Pediatrics", "q": "A 2-month-old infant with a pustular swelling at the BCG vaccination site given after birth. Localized fluctuance without systemic symptoms. Most appropriate management?", "choices": ["Needle aspiration", "Incision and drainage (I&D)", "Oral antibiotics", "Reassurance and observation", "Surgical excision"], "ans": 3, "exp": "ปฏิกิริยาเฉพาะที่หลังฉีด BCG (ตุ่มหนอง/แผลเล็กที่ค่อย ๆ กลายเป็นแผลเป็น) เป็นปกติ ไม่มีอาการทั่วร่างกาย -> reassurance และสังเกต หายเอง (ห้าม I&D เพราะทำให้เกิด sinus เรื้อรัง)", "sys": "IX"}, {"topic": "Pediatrics", "q": "A 6-year-old boy with multiple small pustules and honey-colored crusted lesions around his mouth. Most likely diagnosis?", "choices": ["Cellulitis", "Erysipelas", "Herpes simplex", "Varicella", "Impetigo"], "ans": 4, "exp": "ตุ่มหนอง + สะเก็ดสีน้ำผึ้ง (honey-colored crust) รอบปาก = impetigo (จาก S. aureus/Streptococcus)", "sys": "I"}, {"topic": "Pediatrics", "q": "A 9-year-old girl with fatigue. CBC shows pancytopenia. Small cervical lymph nodes (<0.5 cm). Most appropriate diagnostic test?", "choices": ["Bone marrow aspiration/biopsy", "Lymph node biopsy", "Peripheral blood smear", "CT scan chest/abdomen", "Coagulation profile"], "ans": 0, "exp": "pancytopenia ในเด็ก (สงสัย leukemia/aplastic anemia) -> ตรวจ bone marrow aspiration/biopsy วินิจฉัย", "sys": "II"}, {"topic": "Pediatrics", "q": "A 12-year-old boy recently recovered from post-streptococcal glomerulonephritis. Which condition is he at increased risk of developing in the future?", "choices": ["Nephrolithiasis", "Chronic kidney disease", "Renal artery stenosis", "Hypertensive encephalopathy", "Pyelonephritis"], "ans": 1, "exp": "ส่วนใหญ่ PSGN ในเด็กหายสนิท แต่มีความเสี่ยงระยะยาวเล็กน้อยต่อความดันโลหิตสูง/โปรตีนรั่ว และ chronic kidney disease", "sys": "XIV"}, {"topic": "Pediatrics", "q": "A 4-year-old boy with fever, cough, conjunctivitis, and a generalized maculopapular rash. Koplik spots noted. Most important treatment for this child?", "choices": ["Intravenous antibiotics", "Acyclovir", "Vitamin A supplementation", "Systemic corticosteroids", "Antihistamines"], "ans": 2, "exp": "ไข้ + ไอ + เยื่อบุตาอักเสบ + ผื่น + Koplik spots = โรคหัด (measles) -> ให้ vitamin A ลดความรุนแรงและอัตราตาย. *อ้างอิงภาพ*", "img": "https://cdn.jsdelivr.net/gh/MercenzK/Web-quiz-images@main/NL2-2025-July-Q28.png", "sys": "I"}, {"topic": "Pediatrics", "q": "A 2-year-old boy with developmental delay, hypotonia, up-slanting palpebral fissures, flat nasal bridge, and epicanthal folds. Which chromosomal abnormality is expected?", "choices": ["Trisomy 18", "Trisomy 13", "Monosomy X", "Trisomy 21", "47,XXY"], "ans": 3, "exp": "ลักษณะ Down syndrome (พัฒนาการช้า hypotonia ตาเฉียงขึ้น ดั้งจมูกแบน epicanthal folds) = trisomy 21", "sys": "XVII"}, {"topic": "Pediatrics", "q": "A 1-month-old infant with chronic constipation and abdominal distension, did not pass meconium within 48 hours after birth. Explosive passage of stool after digital rectal exam. Gold standard investigation?", "choices": ["Barium enema", "Digital rectal examination", "Abdominal ultrasound", "Anorectal manometry", "Rectal biopsy"], "ans": 4, "exp": "ถ่ายขี้เทาช้า + ท้องผูก/อืด + explosive stool หลังตรวจทวาร = Hirschsprung disease -> gold standard คือ rectal biopsy (ไม่มี ganglion cells)", "sys": "XVI"}, {"topic": "Pediatrics", "q": "A newborn with a large, well-circumscribed, darkly pigmented lesion with hair growth on the lower back. Most likely diagnosis?", "choices": ["Congenital melanocytic nevus", "Cafe-au-lait spot", "Mongolian spot", "Solar lentigo", "Melanoma"], "ans": 0, "exp": "ปื้นสีเข้มขอบชัดมีขนงอกตั้งแต่แรกเกิด = congenital melanocytic nevus. Mongolian spot เป็นสีน้ำเงินเทาไม่มีขน", "sys": "XVI"}, {"topic": "Pediatrics", "q": "A 3-year-old boy with 7 days of fever, conjunctival injection, strawberry tongue, rash, and swelling of hands and feet (Kawasaki suspected). Most serious complication if left untreated?", "choices": ["Renal failure", "Coronary artery aneurysm", "Rheumatic valvulitis", "Stroke", "Pericardial effusion"], "ans": 1, "exp": "Kawasaki disease ที่ไม่ได้รักษา (IVIG) -> ภาวะแทรกซ้อนร้ายแรงที่สุดคือ coronary artery aneurysm", "sys": "I"}, {"topic": "Psychiatry", "q": "A 20-year-old man with agitation, hallucinations, and auditory voices after taking an illicit drug. Which substance is most likely responsible?", "choices": ["Cannabis", "Opioid", "Amphetamine", "Alcohol", "Benzodiazepine"], "ans": 2, "exp": "stimulant psychosis (กระวนกระวาย ประสาทหลอน หูแว่ว) มักจาก amphetamine (methamphetamine)", "sys": "V"}, {"topic": "Psychiatry", "q": "A 25-year-old woman suddenly develops palpitations, sweating, chest tightness, shortness of breath, and fear of dying. The episode peaks within 10 minutes and resolves spontaneously. Most likely diagnosis?", "choices": ["Generalized anxiety disorder", "Acute stress reaction", "Myocardial infarction", "Panic attack", "Hyperthyroidism"], "ans": 3, "exp": "อาการเฉียบพลันถึงจุดสูงสุดใน 10 นาที (ใจสั่น เหงื่อ กลัวตาย) แล้วหายเอง = panic attack", "sys": "V"}, {"topic": "Psychiatry", "q": "A 28-year-old man lives alone, has few friends, prefers solitary activities, does not feel sad, is content with his lifestyle, and shows little interest in forming close relationships. Most likely diagnosis?", "choices": ["Major depressive disorder", "Schizophrenia", "Avoidant personality disorder", "Social anxiety disorder", "Schizoid personality disorder"], "ans": 4, "exp": "ชอบอยู่คนเดียว ไม่ต้องการความสัมพันธ์ พอใจกับวิถีชีวิต ไม่เศร้า = schizoid personality disorder (ต่างจาก avoidant ที่อยากมีสัมพันธ์แต่กลัวถูกปฏิเสธ)", "sys": "V"}, {"topic": "Psychiatry", "q": "A 24-year-old woman with repetitive behaviors (opening and closing the door several times before leaving), feeling anxious if she resists. Most appropriate first-line medication?", "choices": ["Sertraline", "Haloperidol", "Diazepam", "Lithium", "Carbamazepine"], "ans": 0, "exp": "obsessive-compulsive disorder (OCD) -> ยา first-line คือ SSRI (sertraline) ร่วมกับ CBT (ERP)", "sys": "V"}, {"topic": "Surgery", "q": "A 16-year-old boy with sudden onset severe left testicular pain for 3 hours. Testis is tender, high-riding, cremasteric reflex absent. Most appropriate initial investigation to confirm diagnosis?", "choices": ["Abdominal X-ray", "Testicular ultrasound with Doppler", "CT abdomen and pelvis", "Urine culture", "Scrotal aspiration"], "ans": 1, "exp": "testicular torsion (ปวดเฉียบพลัน อัณฑะยกสูง cremasteric reflex หาย) -> ยืนยันด้วย Doppler ultrasound (พบเลือดไปเลี้ยงลด) แต่ถ้าชัดเจนควรผ่าตัดทันทีไม่รอผล", "sys": "XIV"}, {"topic": "Surgery", "q": "A 20-year-old man underwent appendectomy for acute appendicitis, admitted 4 days on antibiotics. On postoperative day 4 he develops a fever. Next best step?", "choices": ["Continue same antibiotics", "Start antipyretics", "Abdominal imaging for intra-abdominal abscess", "Discharge and observe", "Repeat appendectomy"], "ans": 2, "exp": "ไข้วันที่ 4-5 หลังผ่าไส้ติ่ง -> สงสัย intra-abdominal/pelvic abscess -> ส่ง imaging (ultrasound/CT) หาฝีในช่องท้อง", "sys": "XI"}, {"topic": "Surgery", "q": "A 40-year-old man with severe anal pain during defecation, denies rectal bleeding. A blackish, tender lesion at the anal verge. Most likely diagnosis?", "choices": ["Anal fissure", "Rectal prolapse", "Perianal abscess", "Thrombosed external hemorrhoid", "Anal carcinoma"], "ans": 3, "exp": "ก้อนสีคล้ำ/ม่วงดำ เจ็บมากที่ขอบทวาร = thrombosed external hemorrhoid (ลิ่มเลือดในหัวริดสีดวงภายนอก)", "sys": "II"}, {"topic": "Obstetrics & Gynecology", "q": "A 15-year-old girl with painful genital ulcers and a history of unsafe sex. Ulcer pus gram stain: numerous WBC, gram negative coccobacilli in groups and parallel rows. Most appropriate treatment?", "choices": ["Cefdinir", "Doxycycline", "Levofloxacin", "Amoxicillin/clavulanic acid", "Azithromycin"], "ans": 4, "exp": "แผลริมอ่อนเจ็บ + gram negative coccobacilli เรียงตัวแบบ 'school of fish/railroad track' = Haemophilus ducreyi (chancroid) -> azithromycin (หรือ ceftriaxone)", "sys": "flex"}, {"topic": "Obstetrics & Gynecology", "q": "A 32-year-old GA 39 weeks primigravida in labor, unremarkable ANC. T 36.5, BP 110/60, fundal height 3/4 above umbilicus, cephalic, FHR 140, contractions every ~interval with 50 sec moderate intensity, cervix 5 cm/100% effaced, membranes intact, station 0. (source table missing) Most appropriate management?", "choices": ["Observation", "Epidural anesthesia", "Sedation with opioid", "Cesarean section", "Oxytocin augmentation"], "ans": 0, "exp": "active labor 5 ซม. contraction เพียงพอ (50 วินาที moderate) FHR ปกติ ดำเนินไปได้ -> เฝ้าติดตาม (observe) การดำเนินคลอด (ต้นฉบับตารางการดำเนินคลอดหายไป; ตอบตามข้อมูลที่มี = ปกติจึงสังเกต)", "sys": "XV"}, {"topic": "Obstetrics & Gynecology", "q": "A 28-year-old woman, 9 weeks pregnant, with severe nausea and vomiting for a week, unable to tolerate oral intake but with stable vital signs and no dehydration. Best initial management?", "choices": ["Ondansetron", "Metoclopramide", "Reassurance", "Oral rehydration solution (ORS)", "Hospitalization with IV fluids and thiamine"], "ans": 1, "exp": "nausea/vomiting of pregnancy ที่รบกวนแต่ยังไม่มีภาวะขาดน้ำ -> ให้ยาแก้อาเจียนที่ปลอดภัย (metoclopramide) หลัง/ร่วมกับ pyridoxine (B6). ยังไม่ต้อง admit ให้สารน้ำ (สงวนไว้กรณี dehydration/hyperemesis)", "sys": "XV"}, {"topic": "Obstetrics & Gynecology", "q": "A 28-year-old woman, 3 weeks postpartum, with painful swollen breast and fever. Best initial management?", "choices": ["Stop breastfeeding completely", "Warm compress", "Continue breastfeeding and give antibiotics", "Immediate incision and drainage", "Use tight breast binding"], "ans": 2, "exp": "mastitis (เต้านมบวมแดงเจ็บ + ไข้) -> ให้นมต่อ/ระบายน้ำนม + ยาปฏิชีวนะ (dicloxacillin/cephalexin). I&D เฉพาะเมื่อเป็นฝี (abscess)", "sys": "XV"}, {"topic": "Obstetrics & Gynecology", "q": "A 22-year-old woman with multiple painless cauliflower-like lesions on the vulva. Most likely causative agent?", "choices": ["Herpes simplex virus", "Treponema pallidum", "Chlamydia trachomatis", "Human papillomavirus", "Haemophilus ducreyi"], "ans": 3, "exp": "ก้อนหูดรูปดอกกะหล่ำ (cauliflower) ไม่เจ็บที่อวัยวะเพศ = condyloma acuminata จาก human papillomavirus (HPV)", "sys": "flex"}, {"topic": "Obstetrics & Gynecology", "q": "A 28-year-old woman at 8 weeks gestation for routine ultrasound. Fetal pole is seen without fetal heartbeat. Most appropriate next management?", "choices": ["Expectant management until spontaneous abortion", "Misoprostol administration", "Dilatation and curettage", "Progesterone supplementation", "Repeat ultrasound in 1 week"], "ans": 4, "exp": "fetal pole ที่ยังไม่พบการเต้นหัวใจ ควรยืนยันก่อนวินิจฉัย missed abortion -> นัด ultrasound ซ้ำใน 1 สัปดาห์ (ตามเกณฑ์ยืนยันก่อนขับ/ขูดมดลูก) *ถ้า CRL >=7 มม.ไม่มีหัวใจเต้น = ยืนยัน demise ได้เลย*", "sys": "XV"}, {"topic": "Obstetrics & Gynecology", "q": "A 30-year-old woman with lower abdominal pain and amenorrhea, positive urine pregnancy test, ectopic pregnancy suspected. What investigation should be obtained to confirm the diagnosis?", "choices": ["Serum beta-hCG", "Abdominal X-ray", "MRI pelvis", "Diagnostic laparoscopy", "Serum CA-125"], "ans": 0, "exp": "สงสัย ectopic -> ตรวจ serum beta-hCG เชิงปริมาณ ร่วมกับ transvaginal ultrasound (ถ้า hCG เกิน discriminatory zone แต่ไม่เห็นถุงในมดลูก = สนับสนุน ectopic)", "sys": "XV"}, {"topic": "Obstetrics & Gynecology", "q": "A 22-year-old sexually active woman with vaginal discharge and itching. Speculum shows an erythematous cervix with punctate lesions ('strawberry cervix'). Most appropriate next investigation?", "choices": ["Endometrial biopsy", "Vaginal wet mount microscopy", "Hysteroscopy", "Pelvic ultrasound", "CA-125 level"], "ans": 1, "exp": "strawberry cervix + ตกขาว = trichomoniasis -> ตรวจ vaginal wet mount พบ trichomonad เคลื่อนไหว", "sys": "XII"}, {"topic": "Obstetrics & Gynecology", "q": "A 26-year-old woman, 3 days postpartum, with painful swelling of both breasts. Afebrile, nipples appear normal. Best management?", "choices": ["Stop breastfeeding immediately", "Start antibiotics", "Encourage frequent breastfeeding", "Perform breast ultrasound", "Apply tight breast binders"], "ans": 2, "exp": "breast engorgement (เต้านมคัดทั้งสองข้าง ไม่มีไข้/แดง) -> ให้นมบ่อย ๆ ระบายน้ำนม", "sys": "XV"}, {"topic": "Obstetrics & Gynecology", "q": "A 25-year-old woman who delivered 1 week ago with painful, engorged breasts during breastfeeding, no fever, erythema, or localized tenderness. Most appropriate management?", "choices": ["Stop breastfeeding temporarily", "Cold compress", "Empiric antibiotics", "Frequent breastfeeding", "Needle aspiration"], "ans": 3, "exp": "เต้านมคัด (engorgement) ไม่มีการติดเชื้อ -> ให้นมบ่อย ๆ ระบายน้ำนม (ประคบอุ่นก่อนให้นม/ประคบเย็นหลังให้นมช่วยได้)", "sys": "XI"}, {"topic": "Emergency medicine", "q": "A 1-year-old boy with hemophilia A (diagnosed at 6 months) presents with stupor and localized seizure of left arm and leg for 10 min, no fever. T 37, BP 120/80, PR 60, right pupil 5 mm sluggish, left pupil 3 mm. Left hemiparesis, DTR 3+ left, left Babinski dorsiflexion, left ankle clonus. Initial management after intubation and hyperventilation?", "choices": ["Vitamin K", "Tranexamic acid", "Desmopressin", "Emergency craniotomy", "Mannitol"], "ans": 4, "exp": "intracranial hemorrhage ใน hemophilia + สัญญาณ herniation (รูม่านตาขวาโต, Cushing response, hemiparesis) -> หลัง intubate + hyperventilate ให้ mannitol ลด ICP ทันที (ร่วมกับให้ factor VIII ทดแทนและปรึกษาศัลยกรรมประสาท)", "sys": "emergency"}, {"topic": "Emergency medicine", "q": "A 35-year-old construction worker after an electric shock collapses and is pulseless. Monitor shows asystole. Most appropriate initial management?", "choices": ["Immediate CPR", "Endotracheal intubation (ETT)", "Defibrillation", "Intravenous epinephrine", "IV fluid bolus"], "ans": 0, "exp": "cardiac arrest ที่เป็น asystole (non-shockable) -> เริ่ม CPR (กดหน้าอก) ทันที แล้วให้ epinephrine ทุก 3-5 นาที (ไม่ช็อกไฟฟ้า)", "sys": "emergency"}, {"topic": "Emergency medicine", "q": "A 40-year-old man with type 1 diabetes treated for severe hypoglycemia in the ED, now alert and stable. How long should he be observed before safe discharge?", "choices": ["6 hours", "4 hours", "12 hours", "24 hours", "Overnight admission mandatory"], "ans": 1, "exp": "hypoglycemia จาก insulin (T1DM) ที่ฟื้นตัวดีและกินได้ -> สังเกตอาการอย่างน้อย ~4 ชั่วโมงเพื่อดูว่าไม่กลับเป็นซ้ำ ก่อนจำหน่าย (กรณี sulfonylurea ต้องสังเกตนานกว่า/admit)", "sys": "emergency"}, {"topic": "Emergency medicine", "q": "A 45-year-old man after a motor vehicle accident is unresponsive, pulseless, ECG shows asystole. Initial management?", "choices": ["Defibrillation", "Epinephrine injection", "CPR (high-quality chest compressions)", "Intubation", "Atropine injection"], "ans": 2, "exp": "asystole (non-shockable) -> เริ่ม high-quality CPR ทันที แล้วให้ epinephrine (ไม่ช็อกไฟฟ้า/ไม่ให้ atropine)", "sys": "emergency"}, {"topic": "Emergency medicine", "q": "A 25-year-old man with flame burns on his torso covering ~20% TBSA, hemodynamically stable. To assess the severity and depth of the burn, most appropriate first-line investigation?", "choices": ["Punch biopsy", "Skin ultrasound", "MRI of the burn site", "Clinical examination", "CT scan of chest and abdomen"], "ans": 3, "exp": "ประเมินความลึก/ความรุนแรงของแผลไฟไหม้เบื้องต้นด้วยการตรวจร่างกาย (clinical examination: ดูสี, blister, capillary refill, ความรู้สึก)", "sys": "emergency"}, {"topic": "Emergency medicine", "q": "A 28-year-old farmer bitten by a snake, 2 hours later develops progressive ptosis, difficulty swallowing, respiratory distress, muscle paralysis, and shallow breathing. Most appropriate next step?", "choices": ["Wound biopsy", "Intravenous antibiotics", "Antivenom", "Observation and supportive care", "Endotracheal intubation"], "ans": 4, "exp": "neurotoxic snake envenomation ที่มีอัมพาต + หายใจล้มเหลว -> ตาม ABC ต้อง secure airway (endotracheal intubation) ทันทีเพื่อช่วยหายใจ แล้วให้ antivenom ควบคู่", "sys": "emergency"}, {"topic": "Emergency medicine", "q": "A 22-year-old man stabbed in the chest, wound 0.5 x 1.5 cm at the left nipple line. Tachypnea, decreased breath sounds, and sucking air entry through the wound. Most appropriate immediate management?", "choices": ["Apply a three-sided occlusive dressing", "Immediate chest tube insertion without dressing", "Needle thoracostomy", "Surgical thoracotomy", "Observation"], "ans": 0, "exp": "open pneumothorax (sucking chest wound) -> ปิดแผลด้วย three-sided occlusive dressing (ให้ลมออกได้แต่ไม่เข้า ป้องกัน tension) แล้วจึงใส่ ICD", "sys": "emergency"}, {"topic": "Community/EBM", "q": "An 18-month-old boy is diagnosed with hand-foot-mouth disease. In a kindergarten outbreak, how should the school manage class closure?", "choices": ["Close the classroom for cleaning", "Isolate only the sick child at home", "Close the entire school floor", "Close the entire school", "No action required"], "ans": 1, "exp": "HFMD -> แยกเด็กที่ป่วยให้พักที่บ้านจนหายแพร่เชื้อ ร่วมกับทำความสะอาด/สุขอนามัย ไม่จำเป็นต้องปิดทั้งโรงเรียน", "sys": "general"}, {"topic": "Community/EBM", "q": "A 75-year-old female with a wound at mid-right forearm, bitten by her dog 5 hours ago, cleaned with drinking water. First and second tetanus doses were 8 years ago. 2-cm laceration with inactive bleeding. Most appropriate tetanus immunization?", "choices": ["No need for tetanus toxoid", "Tetanus toxoid 1 dose", "Tetanus toxoid 3 doses + tetanus immunoglobulin 1 dose", "Tetanus toxoid 3 doses", "Tetanus immunoglobulin 1 dose"], "ans": 2, "exp": "แผลสกปรก/tetanus-prone + ประวัติวัคซีนไม่ครบ (ได้เพียง 2 เข็ม) -> ต้องให้ tetanus toxoid ให้ครบชุด (3 เข็ม) ร่วมกับ tetanus immunoglobulin 1 โดส", "sys": "general"}, {"topic": "Otolaryngology", "q": "A 20-year-old student with severe sore throat, fever, and hot potato (muffled) voice. Peritonsillar swelling with deviation of the uvula. Most appropriate initial management?", "choices": ["IV corticosteroids", "IV antibiotics", "Tonsillectomy", "Needle aspiration", "Antihistamine"], "ans": 3, "exp": "peritonsillar abscess (quinsy: hot potato voice + uvula เบน + peritonsillar bulge) -> ระบายหนองด้วย needle aspiration (หรือ I&D) ร่วมกับยาปฏิชีวนะ", "sys": "VIII"}, {"topic": "Otolaryngology", "q": "A 22-year-old man with painful swelling and redness of the auricle following ear piercing (perichondritis suspected). Most appropriate antibiotic therapy?", "choices": ["Amoxicillin", "Erythromycin", "Vancomycin", "Clindamycin", "Ciprofloxacin"], "ans": 4, "exp": "perichondritis ของใบหูหลังเจาะหู -> เชื้อ Pseudomonas aeruginosa เป็นหลัก -> ciprofloxacin (fluoroquinolone)", "sys": "VIII"}, {"topic": "Otolaryngology", "q": "A 32-year-old man struck on the chin in a motorcycle accident, with pain/swelling of the lower jaw, tenderness over the mandibular condyles, and restricted mouth opening. Which radiographic view is most appropriate to evaluate condylar fractures?", "choices": ["Mandibular Towne view", "Water's view", "Lateral cephalometric view", "Panoramic (orthopantomogram) view", "Caldwell view"], "ans": 0, "exp": "ประเมิน condylar fracture ของขากรรไกรล่าง -> mandibular (reverse) Towne view เห็น condyle ได้ดี (panoramic ก็ช่วยดูทั้งขากรรไกร)", "sys": "VIII"}, {"topic": "Otolaryngology", "q": "A 60-year-old man with severe right ear pain, vesicular eruptions in the external auditory canal, and ipsilateral facial weakness (unable to close right eye, mouth drooping). Most likely diagnosis?", "choices": ["Bell's palsy", "Ramsay Hunt syndrome", "Trigeminal neuralgia", "Acoustic neuroma", "Herpes zoster ophthalmicus"], "ans": 1, "exp": "ตุ่มน้ำในช่องหู + อัมพาตใบหน้าครึ่งซีกข้างเดียวกัน + ปวดหูมาก = Ramsay Hunt syndrome (herpes zoster oticus กระทบเส้นประสาทคู่ที่ 7)", "sys": "VIII"}, {"topic": "Otolaryngology", "q": "A 40-year-old woman with acute onset left-sided facial weakness, left ear pain 2 days before, unable to close left eye and drooping of the left mouth corner, no vesicular lesions in the ear canal. Most appropriate treatment?", "choices": ["Oral corticosteroids", "Oral acyclovir alone", "Combination of steroid and acyclovir", "Facial massage", "No treatment, spontaneous recovery expected"], "ans": 2, "exp": "Bell's palsy (LMN facial palsy ไม่มีตุ่มน้ำ) -> corticosteroid เป็นหลัก; การเพิ่ม antiviral (acyclovir) ให้ประโยชน์เสริม โดยเฉพาะรายที่รุนแรง/มี prodrome -> การให้ steroid ร่วม antiviral เป็นทางเลือกที่เหมาะสม (*steroid เดี่ยวก็เป็นคำตอบที่ยอมรับได้ตามหลักฐาน*)", "sys": "VIII"}, {"topic": "Orthopedics", "q": "A 25-year-old man falls from a tree onto his shoulder, with pain and swelling over the clavicular area and difficulty raising the arm. X-ray shows displacement of the medial clavicle from the sternum. Most likely diagnosis?", "choices": ["Clavicle fracture", "Acromioclavicular joint dislocation", "Glenohumeral dislocation", "Sternoclavicular joint dislocation", "Scapular fracture"], "ans": 3, "exp": "กระดูกไหปลาร้าส่วนต้น (medial) เคลื่อนหลุดจากกระดูกอก = sternoclavicular joint dislocation", "sys": "XIII"}, {"topic": "Orthopedics", "q": "A 40-year-old office worker with chronic pain over the lateral elbow, worsened by wrist extension against resistance. Most likely diagnosis?", "choices": ["Golfer's elbow", "Olecranon bursitis", "Radial head fracture", "Carpal tunnel syndrome", "Tennis elbow"], "ans": 4, "exp": "ปวด lateral epicondyle แย่ลงเมื่อกระดกข้อมือต้านแรง = tennis elbow (lateral epicondylitis). golfer's elbow เป็นด้าน medial", "sys": "XIII"}, {"topic": "Ophthalmology", "q": "A 2-month-old infant with persistent tearing and discharge from the medial canthus. The area over the lacrimal sac is swollen and erythematous. Best next step?", "choices": ["Topical antibiotics", "Lacrimal sac massage", "Immediate probing of the nasolacrimal duct", "Surgical drainage", "Observation"], "ans": 0, "exp": "acute dacryocystitis (ถุงน้ำตาบวมแดง = ติดเชื้อ) ในทารกที่มี congenital NLD obstruction -> ให้ยาปฏิชีวนะรักษาการติดเชื้อก่อน (ห้ามนวด/probe ในระยะติดเชื้อเฉียบพลัน; นวด Crigler ใช้กับรายที่ไม่มีการติดเชื้อ)", "sys": "VII"}, {"topic": "Ophthalmology", "q": "A 14-year-old boy struck in the eye playing basketball, with decreased vision and pain. Slit lamp shows blood layering in the anterior chamber (hyphema). Most appropriate initial management?", "choices": ["Immediate surgical evacuation", "Eye shield protection", "Topical corticosteroids", "Systemic anticoagulation", "Warm compress to the eye"], "ans": 1, "exp": "hyphema (เลือดในช่องหน้าลูกตา) -> ครอบตาด้วย eye shield, พักผ่อน ยกศีรษะสูง หลีกเลี่ยงการกระทบ ป้องกัน rebleeding (ห้ามให้ยาต้านการแข็งตัวของเลือด)", "sys": "VII"}, {"topic": "Forensic medicine", "q": "A man shot with a small entrance wound with an abrasion collar and a larger, irregular exit wound. What does this indicate?", "choices": ["Exit wound mistaken for entry wound", "Contact gunshot wound", "Typical entry and exit wound pattern", "Evidence of close-range shot (powder tattooing)", "Ricochet injury"], "ans": 2, "exp": "แผลกระสุนเข้ามักเล็กและมี abrasion collar (ขอบถลอก) ส่วนแผลออกมักใหญ่และขอบไม่เรียบ = typical entrance/exit wound pattern", "sys": "general"}, {"topic": "Forensic medicine", "q": "A 35-year-old man found dead at home with a rope around his neck and pornographic magazines nearby. Most likely manner of death?", "choices": ["Suicide", "Homicide", "Natural death", "Autoerotic accident", "Undetermined"], "ans": 3, "exp": "เสียชีวิตขณะทำ autoerotic asphyxiation (รัดคอเพื่อเพิ่มความพึงพอใจทางเพศ) + มีสื่อลามกใกล้ตัว = autoerotic accident (เป็นอุบัติเหตุ ไม่ใช่ฆ่าตัวตาย)", "sys": "general"}, {"topic": "Forensic medicine", "q": "A 19-year-old woman presents after sexual assault involving oral penetration. Which site should be swabbed to collect forensic evidence?", "choices": ["Vaginal fornix", "Anal canal", "Skin of thighs", "Fingernails", "Oral cavity"], "ans": 4, "exp": "การล่วงละเมิดทางปาก -> เก็บ swab จากช่องปาก (oral cavity) เพื่อหาอสุจิ/DNA ตามช่องทางที่ถูกล่วงละเมิด", "sys": "general"}, {"topic": "Community/EBM", "q": "A screening test has sensitivity 90% and specificity 90%. In a population with disease prevalence of 40%, approximate positive predictive value (PPV)?", "choices": ["82%", "8%", "8.5%", "9%", "11.1%"], "ans": 0, "exp": "TP = 0.9 x 0.4 = 0.36; FP = 0.1 x 0.6 = 0.06; PPV = TP/(TP+FP) = 0.36/0.42 ~ 0.857 (~85.7%) ใกล้เคียง 82% มากที่สุด", "sys": "general"}, {"topic": "Medical ethics", "q": "A 40-year-old man angrily shouts in front of your office because of a long waiting time. Most appropriate action?", "choices": ["Tell him to come in the next queue", "Take him somewhere else to calm down", "Call the security guard to come control him", "Apologize and bargain with him", "Continue working and don't respond"], "ans": 1, "exp": "จัดการผู้ป่วยโกรธ -> พาไปยังที่เป็นส่วนตัวเพื่อให้สงบลง (de-escalation) รับฟังและแสดงความเข้าใจ ก่อนแก้ปัญหา", "sys": "general"}, {"topic": "Medical ethics", "q": "A patient asks the doctor to issue a medical certificate covering sick leave from January to July for a condition that still persists. Which period should the certificate state?", "choices": ["Any days since January as requested", "The entire 6-month period until July", "Only the days the physician has actually examined the patient", "Until symptoms fully resolve", "Doctor can backdate up to 6 months"], "ans": 2, "exp": "ใบรับรองแพทย์ต้องระบุตามข้อเท็จจริงที่ตรวจพบจริง -> ออกได้เฉพาะวันที่แพทย์ได้ตรวจผู้ป่วยจริงเท่านั้น ไม่ออกย้อนหลัง/ครอบคลุมช่วงที่ไม่ได้ตรวจ", "sys": "general"}]}, {"id": "nl2-2025-oct", "title": "NL 2 ปี 2025 ตุลาคม (VICHAKARN_SMST)", "subject": "past", "questions": [{"topic": "Internal medicine", "q": "A 25-year-old graduate student with 6 months of constant, bilateral band-like pressure headaches, no nausea/vomiting/photophobia, worse toward end of day, associated with study stress (episodic tension-type headache). Most appropriate first-line acute pharmacotherapy?", "choices": ["Acetaminophen or Ibuprofen", "Sumatriptan", "Oxycodone", "Prednisone", "Amitriptyline"], "ans": 0, "exp": "episodic tension-type headache -> รักษาอาการเฉียบพลันด้วย simple analgesic (acetaminophen หรือ NSAID). amitriptyline ใช้ 'ป้องกัน' ในรายที่เป็นบ่อย; triptan ใช้กับไมเกรน", "sys": "VI"}, {"topic": "Internal medicine", "q": "A 30-year-old woman with a firm reddish-brown 0.8 cm papule on the lower leg for over a year; when pinched from the sides, the lesion dimples inward. Most likely diagnosis?", "choices": ["Malignant Melanoma", "Dermatofibroma", "Neurofibroma", "Pyogenic Granuloma", "Basal Cell Carcinoma"], "ans": 1, "exp": "ตุ่มแข็งสีน้ำตาลแดงที่ขา + 'dimple sign' (บุ๋มลงเมื่อบีบด้านข้าง) = dermatofibroma", "sys": "II"}, {"topic": "Internal medicine", "q": "A 35-year-old woman with anxiety, palpitations, heat intolerance, 10-lb weight loss over a month despite increased appetite, fine tremor, tachycardia, mild exophthalmos. Most common cause of hyperthyroidism in this demographic?", "choices": ["Toxic Multinodular Goiter", "Subacute Thyroiditis", "Graves' Disease", "Solitary Toxic Adenoma", "Struma Ovarii"], "ans": 2, "exp": "หญิงสาว + thyrotoxicosis + exophthalmos = Graves' disease ซึ่งเป็นสาเหตุ hyperthyroidism ที่พบบ่อยที่สุดในกลุ่มนี้", "sys": "IV"}, {"topic": "Internal medicine", "q": "A 40-year-old man with a well-demarcated hyperpigmented violaceous-brown patch on the dorsum of his hand, recurring in the exact same location three times after taking trimethoprim-sulfamethoxazole for UTI. Asymptomatic. Most likely diagnosis?", "choices": ["Lichen Planus", "Psoriasis", "Granuloma Annulare", "Fixed Drug Eruption", "Secondary Syphilis"], "ans": 3, "exp": "ผื่นกลับมาที่ตำแหน่งเดิมซ้ำ ๆ หลังได้ยาชนิดเดิม (cotrimoxazole) = fixed drug eruption", "sys": "XII"}, {"topic": "Internal medicine", "q": "A 30-year-old man with a receding hairline at the temples and thinning at the crown, gradually progressing over years, father with similar baldness. No patches of complete hair loss, scaling, or inflammation. Most likely diagnosis?", "choices": ["Alopecia Areata", "Tinea Capitis", "Telogen Effluvium", "Trichotillomania", "Androgenic Alopecia"], "ans": 4, "exp": "ผมร่วงแบบ pattern (แนวผมถอยที่ขมับ + บางที่กลางกระหม่อม) + ประวัติครอบครัว = androgenic alopecia (male pattern)", "sys": "V"}, {"topic": "Internal medicine", "q": "A 45-year-old immigrant from rural Southeast Asia with chronic abdominal pain, diarrhea, and a recurrent serpiginous urticarial rash. CBC shows eosinophilia. Which parasite is most likely identified in stool?", "choices": ["Strongyloides stercoralis", "Enterobius vermicularis", "Taenia saginata", "Giardia lamblia", "Ascaris lumbricoides"], "ans": 0, "exp": "ผื่นลมพิษเลื้อย (larva currens, serpiginous) + eosinophilia + อาการทางเดินอาหารเรื้อรัง = Strongyloides stercoralis (autoinfection)", "sys": "I"}, {"topic": "Internal medicine", "q": "A 58-year-old woman brought to the ED after collapsing. She takes furosemide for hypertension. ECG shown. Most appropriate immediate pharmacological treatment?", "choices": ["Amiodarone IV", "Magnesium sulfate IV", "Lidocaine IV", "Procainamide IV", "Beta-blocker IV"], "ans": 1, "exp": "furosemide -> hypokalemia/hypomagnesemia -> QT ยาว -> Torsades de pointes -> รักษาด้วย IV magnesium sulfate. *อ้างอิงภาพ ECG*", "img": "https://cdn.jsdelivr.net/gh/MercenzK/Web-quiz-images@main/NL2-2025-Oct-Q7.png", "sys": "IV"}, {"topic": "Internal medicine", "q": "A 58-year-old man with chronic alcohol use presents with hematemesis. Scleral icterus, spider angioma, palmar erythema, distended abdomen with shifting dullness. Most likely cause of hematemesis?", "choices": ["Mallory-Weiss tear", "Peptic ulcer disease", "Esophageal varices", "Gastric cancer", "Dieulafoy's lesion"], "ans": 2, "exp": "สัญญาณตับแข็ง (ดีซ่าน spider angioma palmar erythema ascites) + อาเจียนเป็นเลือด = เลือดออกจาก esophageal varices (portal hypertension)", "sys": "II"}, {"topic": "Internal medicine", "q": "A 25-year-old woman with 2 days of dysuria, frequency, and urgency, no fever/flank pain/vaginal discharge. Urine dipstick positive for leukocyte esterase and nitrites, no drug allergies. Most appropriate initial antibiotic?", "choices": ["Amoxicillin", "Ciprofloxacin", "Trimethoprim-sulfamethoxazole", "Nitrofurantoin", "Ceftriaxone"], "ans": 3, "exp": "uncomplicated acute cystitis ในหญิง -> first-line คือ nitrofurantoin (หรือ TMP-SMX/fosfomycin). fluoroquinolone สงวนไว้เพราะผลข้างเคียง/ดื้อยา", "sys": "XIV"}, {"topic": "Internal medicine", "q": "A 16-year-old boy with cola-colored urine and a sore throat that resolved a week ago. BP 150/95. Creatinine 1.8 (baseline 0.8), BUN 20, albumin 3.2. UA: 5-10 dysmorphic RBC/HPF. Most likely diagnosis?", "choices": ["Acute tubular necrosis", "IgA nephropathy", "Lupus nephritis", "Minimal change disease", "Post-streptococcal glomerulonephritis"], "ans": 4, "exp": "nephritic syndrome (ปัสสาวะสีโคล่า dysmorphic RBC + ความดันสูง + Cr สูง) เกิด ~1-2 สัปดาห์หลังคออักเสบ = post-streptococcal GN. (IgA nephropathy เกิดพร้อม/ภายใน 1-3 วันหลัง URI)", "sys": "X"}, {"topic": "Internal medicine", "q": "A 52-year-old asymptomatic woman with a well-defined hyperechoic liver lesion on ultrasound. Contrast MRI shows gradual peripheral-to-central fill-in with no washout in the delayed phase. No liver disease or malignancy risk. Most likely diagnosis?", "choices": ["Cavernous hemangioma", "Hepatocellular carcinoma", "Focal nodular hyperplasia", "Hepatic adenoma", "Metastatic disease"], "ans": 0, "exp": "ก้อนตับ hyperechoic + MRI มี peripheral nodular discontinuous enhancement เติมเข้าใน (fill-in) ไม่มี washout = cavernous hemangioma (พบบ่อยสุด ไม่อันตราย)", "sys": "II"}, {"topic": "Internal medicine", "q": "A 50-year-old woman with intensely pruritic, violaceous, flat-topped papules on flexural wrists and ankles. Some resolved lesions left dark brown hyperpigmented macules. Oral exam reveals white, lacy, reticulated patches on the buccal mucosa. Most likely diagnosis?", "choices": ["Psoriasis", "Lichen planus", "Atopic dermatitis", "Pityriasis rosea", "Tinea corporis"], "ans": 1, "exp": "ตุ่มแบนสีม่วง คันมาก (5 P) ที่ข้อมือ/ข้อเท้า + รอยเส้นขาวลูกไม้ในปาก (Wickham striae/oral reticulate) = lichen planus", "sys": "XII"}, {"topic": "Internal medicine", "q": "A 45-year-old woman with a 4 cm well-defined hyperechoic liver mass. Triple-phase CT shows peripheral nodular enhancement in the arterial phase with progressive centripetal fill-in on delayed images. Healthy and asymptomatic. Most likely diagnosis?", "choices": ["Hepatocellular carcinoma", "Focal nodular hyperplasia", "Cavernous hemangioma", "Hepatic adenoma", "Metastatic lesion"], "ans": 2, "exp": "peripheral nodular enhancement + centripetal fill-in ไม่มี washout = cavernous hemangioma", "sys": "II"}, {"topic": "Internal medicine", "q": "A 45-year-old man with intensely pruritic, violaceous, flat-topped papules on wrists and ankles with fine white lacy Wickham's striae, and brownish hyperpigmentation where older lesions resolved. Most likely diagnosis?", "choices": ["Psoriasis vulgaris", "Eczema", "Pityriasis rosea", "Lichen planus", "Secondary syphilis"], "ans": 3, "exp": "ตุ่มแบนม่วงคัน + Wickham's striae + post-inflammatory hyperpigmentation = lichen planus", "sys": "XII"}, {"topic": "Internal medicine", "q": "A 50-year-old man with hypertension and BMI 30 presents with 6 months of substernal chest tightness and a sour taste in his mouth, almost daily, predominantly upon waking in the morning, with no exacerbation on physical exertion. Most likely diagnosis?", "choices": ["Stable angina", "Unstable angina", "Acute pericarditis", "Pulmonary embolism", "Gastroesophageal Reflux Disease (GERD)"], "ans": 4, "exp": "แน่นหน้าอก + รสเปรี้ยว เป็นตอนเช้าหลังตื่น ไม่สัมพันธ์การออกแรง = GERD (ไม่ใช่ angina ที่สัมพันธ์การออกแรง)", "sys": "IX"}, {"topic": "Internal medicine", "q": "A 16-year-old boy with cola-colored urine and periorbital swelling for 3 days, sore throat 1 week ago that resolved. BP 150/95. BUN 20, Creatinine 1.8 (baseline 0.8), Albumin 3.2. UA: 5-10 dysmorphic RBC/HPF with red blood cell casts. Most likely diagnosis?", "choices": ["Post-Streptococcal Glomerulonephritis", "Nephrolithiasis", "IgA Nephropathy", "Acute Interstitial Nephritis", "Minimal Change Disease"], "ans": 0, "exp": "nephritic syndrome (dysmorphic RBC + RBC casts + ความดันสูง + บวมรอบตา) ~1-2 สัปดาห์หลังคออักเสบ = post-streptococcal glomerulonephritis", "sys": "X"}, {"topic": "Internal medicine", "q": "A 78-year-old man hospitalized for pneumonia becomes acutely confused on day 3, found attempting to urinate into a trash can, disoriented to time and place. Most likely explanation?", "choices": ["Urinary tract infection", "Hospital-acquired delirium", "Development of dementia", "Reaction to a new medication", "Obstructive uropathy"], "ans": 1, "exp": "สับสนเฉียบพลัน สมาธิ/การรับรู้แปรปรวน (fluctuating) ในผู้สูงอายุที่ป่วย admit = hospital-acquired delirium", "sys": "V"}, {"topic": "Internal medicine", "q": "A 28-year-old man with a ventricular septal defect (VSD) presents for a dental cleaning with numerous caries. Pansystolic murmur at left lower sternal border. Which antibiotic prophylaxis before the dental procedure?", "choices": ["Amoxicillin", "Ciprofloxacin", "No antibiotic prophylaxis is indicated", "Vancomycin", "Metronidazole"], "ans": 2, "exp": "VSD ธรรมดา (ไม่ใช่ cyanotic/ไม่มี prosthetic material/ไม่เคยเป็น IE) ไม่อยู่ในกลุ่มเสี่ยงสูงตาม AHA -> ไม่ต้องให้ยาปฏิชีวนะป้องกัน endocarditis", "sys": "IX"}, {"topic": "Internal medicine", "q": "A 19-year-old woman with 2 days of fever, pustular skin lesions, and migratory arthritis/tenosynovitis. Gram stain of pustule shows gram-negative diplococci (disseminated gonococcal infection). What adjunctive antibiotic is given with ceftriaxone to cover co-existent infection?", "choices": ["Clarithromycin", "Azithromycin", "Metronidazole", "Doxycycline", "Ciprofloxacin"], "ans": 3, "exp": "DGI รักษาด้วย ceftriaxone + ให้ยาคลุม chlamydia ร่วมด้วย -> ปัจจุบัน CDC แนะนำ doxycycline (เปลี่ยนจาก azithromycin เดิม)", "sys": "XII"}, {"topic": "Internal medicine", "q": "A 65-year-old man from rural Thailand with CLL on high-dose corticosteroids develops abrupt septic shock and diffuse alveolar hemorrhage. Stool O&P shows filariform larvae. Which parasite is responsible for this hyperinfection syndrome?", "choices": ["Ascaris lumbricoides", "Enterobius vermicularis", "Taenia saginata", "Ancylostoma duodenale", "Strongyloides stercoralis"], "ans": 4, "exp": "filariform larvae + hyperinfection ในผู้ได้ steroid/ภูมิคุ้มกันต่ำ = Strongyloides stercoralis (autoinfection -> disseminated, septic shock, alveolar hemorrhage). *อ้างอิงภาพ*", "img": "https://cdn.jsdelivr.net/gh/MercenzK/Web-quiz-images@main/NL2-2025-Oct-Q20.png", "sys": "I"}, {"topic": "Internal medicine", "q": "An 80-year-old man with 6 months of progressive dysphagia; solids 'go down easier' than liquids, and he coughs and chokes when drinking water. No heartburn or weight loss. This pattern localizes to which structure?", "choices": ["Oropharynx", "Esophageal body", "Lower esophageal sphincter (LES)", "Gastric cardia", "Esophageal mucosa"], "ans": 0, "exp": "กลืนลำบากกับ 'ของเหลว' มากกว่าของแข็ง + สำลัก/ไอเวลาดื่มน้ำ = oropharyngeal dysphagia (ปัญหา neuromuscular ในการเริ่มกลืน) ไม่ใช่การอุดกั้นในหลอดอาหาร", "sys": "X"}, {"topic": "Internal medicine", "q": "A 55-year-old man with heavy alcohol use presents with massive hematemesis, scleral icterus, spider angioma, palmar erythema, distended abdomen with positive fluid wave. Most urgent definitive diagnostic and therapeutic procedure?", "choices": ["Start a high-dose IV proton pump inhibitor drip", "Perform an urgent esophagogastroduodenoscopy", "Obtain a surgical consultation for possible laparotomy", "Administer octreotide infusion", "Insert a nasogastric tube for lavage and monitoring"], "ans": 1, "exp": "variceal bleeding -> urgent EGD เป็นทั้งการวินิจฉัยและรักษา (band ligation) ที่ definitive (octreotide/PPI เป็นการรักษาเสริมระหว่างรอ)", "sys": "XI"}, {"topic": "Internal medicine", "q": "A 55-year-old man with 3 days of severe vomiting, profuse 'rice-water' watery diarrhea, and abdominal pain after visiting his rural village. Profoundly dehydrated and hypotensive. ECG shows QT prolongation. Which toxic exposure is most likely?", "choices": ["Lead poisoning", "Organophosphate poisoning", "Arsenic poisoning", "Cholera infection", "Iron overdose"], "ans": 2, "exp": "arsenic poisoning -> อาเจียน + ถ่ายเป็นน้ำคล้ายน้ำซาวข้าว (rice-water) + ขาดน้ำ + QT prolongation/arrhythmia. (โจทย์ถาม 'toxic exposure' -> arsenic; cholera เป็นการติดเชื้อ). *อ้างอิงภาพ*", "img": "https://cdn.jsdelivr.net/gh/MercenzK/Web-quiz-images@main/NL2-2025-Oct-Q23.png", "sys": "I"}, {"topic": "Internal medicine", "q": "A 35-year-old man with untreated HIV, 2 weeks of low-grade fever, progressive headache, and confusion. LP: opening pressure 120 mmH2O, CSF high lymphocytes, low glucose, high protein. Most appropriate initial management?", "choices": ["Intravenous acyclovir for herpes simplex encephalitis", "Broad-spectrum antibiotics for bacterial meningitis", "High-dose IV steroids for autoimmune encephalitis", "Start empiric anti-tuberculous therapy and adjunctive corticosteroids", "Administer mannitol for suspected idiopathic intracranial hypertension"], "ans": 3, "exp": "CSF lymphocyte เด่น + น้ำตาลต่ำ + โปรตีนสูง ในผู้ป่วย HIV ดำเนินกึ่งเฉียบพลัน = tuberculous meningitis -> เริ่ม anti-TB + corticosteroid", "sys": "I"}, {"topic": "Internal medicine", "q": "A 28-year-old man with sharp, pleuritic chest pain worse when lying flat and relieved by sitting up and leaning forward. A friction rub is heard. Most likely diagnosis?", "choices": ["Myocardial Infarction", "Pulmonary Embolism", "Pneumonia", "Aortic Dissection", "Acute Pericarditis"], "ans": 4, "exp": "เจ็บอกแบบ pleuritic ดีขึ้นเมื่อนั่งโน้มตัวไปหน้า + pericardial friction rub = acute pericarditis", "sys": "IX"}, {"topic": "Internal medicine", "q": "A 65-year-old man who worked 40 years in a coal mine with progressive dyspnea and chronic cough. CXR shows bilateral small nodular opacities with upper lobe predominance. Most likely diagnosis?", "choices": ["Coal Worker's Pneumoconiosis", "Silicosis", "Asbestosis", "Sarcoidosis", "Tuberculosis"], "ans": 0, "exp": "ทำงานเหมืองถ่านหินนาน + nodular opacity เด่นที่ปอดส่วนบน = coal worker's pneumoconiosis", "sys": "I"}, {"topic": "Psychiatry", "q": "A 45-year-old librarian with a firm belief that a famous news anchor is in love with her, sends numerous letters, and believes they communicate secretly via TV cues. She maintains her job with no other bizarre behaviors, flat affect, or disorganized speech. Most likely diagnosis?", "choices": ["Schizophrenia", "Delusional Disorder, Erotomanic Type", "Bipolar I Disorder, Current Episode Manic", "Obsessive-Compulsive Disorder", "Body Dysmorphic Disorder"], "ans": 1, "exp": "ความเชื่อผิด ๆ ว่ามีคนมีชื่อเสียงมาหลงรัก (erotomania) เพียงเรื่องเดียว โดยหน้าที่การงาน/ความคิดอื่นปกติ = delusional disorder, erotomanic type", "sys": "V"}, {"topic": "Psychiatry", "q": "A 78-year-old man becomes acutely confused and agitated the first night after emergency hip surgery, disoriented, pulling at his IV line, with visual hallucinations. Stable vitals, no psychiatric history. Most appropriate initial pharmacologic management for acute agitation?", "choices": ["Lorazepam 1 mg IV", "Olanzapine 10 mg PO", "Haloperidol 0.5 mg IV/IM/PO", "Morphine 2 mg IV", "Diphenhydramine 25 mg IV"], "ans": 2, "exp": "postoperative delirium ที่กระวนกระวายเป็นอันตราย -> ให้ haloperidol ขนาดต่ำ. หลีกเลี่ยง benzodiazepine/diphenhydramine (ทำให้ delirium แย่ลง ยกเว้น alcohol withdrawal)", "sys": "V"}, {"topic": "Psychiatry", "q": "A 19-year-old college student brought after a party where he used an unknown substance. Agitated, paranoid, claims to have 'magical powers' and ability to 'see the future.' Tachycardia and mild hypertension. Most likely diagnosis?", "choices": ["Schizophrenia", "Bipolar disorder, manic episode", "Delirium", "Substance-induced psychotic disorder", "Brief psychotic disorder"], "ans": 3, "exp": "อาการโรคจิตเฉียบพลัน + sympathetic (tachycardia, HT) หลังใช้สารเสพติด = substance-induced psychotic disorder", "sys": "V"}, {"topic": "Psychiatry", "q": "A 60-year-old man with atrial fibrillation on warfarin, therapeutic INR, asymptomatic with normal exams, expresses intense debilitating fear of stroke or internal bleeding, spends hours researching symptoms, with multiple unnecessary ED visits. Most likely diagnosis?", "choices": ["Panic disorder", "Somatic symptom disorder", "Obsessive-compulsive disorder", "Generalized anxiety disorder", "Illness anxiety disorder"], "ans": 4, "exp": "หมกมุ่นกลัวว่าจะป่วย/เป็นโรคร้าย โดยแทบไม่มีอาการทางกาย + ตรวจปกติแต่ยังกังวล + หาหมอบ่อย = illness anxiety disorder", "sys": "V"}, {"topic": "Psychiatry", "q": "A 65-year-old man with atrial fibrillation stable on warfarin, therapeutic INR for months, convinced he is at imminent risk of a life-threatening bleed. He presents weekly with new minor somatic complaints (small bruise, minor gingival bleeding) that he fears are catastrophic. Most accurate diagnosis?", "choices": ["Somatic symptom disorder", "Illness anxiety disorder", "Panic disorder", "Malingering", "Obsessive-compulsive disorder"], "ans": 0, "exp": "มี 'อาการทางกาย' จริง (จ้ำเลือด เลือดออกเหงือกเล็กน้อย) + ความคิด/ความกังวลเกินเหตุเกี่ยวกับอาการเหล่านั้น = somatic symptom disorder (ต่างจาก illness anxiety ที่แทบไม่มีอาการกาย)", "sys": "V"}, {"topic": "Psychiatry", "q": "A 38-year-old female nurse admitted with unexplained GI bleeding, improves with supportive care, then deteriorates with recurrent bleeding, found to have a packet of warfarin tablets hidden under her pillow. She denies knowing how it got there. Most likely diagnosis?", "choices": ["Illness Anxiety Disorder", "Munchausen Syndrome", "Malingering", "Conversion Disorder", "Somatic Symptom Disorder"], "ans": 1, "exp": "จงใจทำให้ตนเองป่วย (กินยา warfarin ลับ ๆ) เพื่อบทบาทผู้ป่วย โดยไม่มีผลประโยชน์ภายนอกชัดเจน = factitious disorder (Munchausen syndrome). malingering ต่างตรงที่มีผลประโยชน์ภายนอก", "sys": "V"}, {"topic": "Psychiatry", "q": "An 18-year-old male brought by friends after ingesting an unknown substance at a party. Agitated, claims he can 'see the future' and 'read minds,' paranoid that his friends are government agents. Stable vitals. Most likely diagnosis?", "choices": ["Bipolar I Disorder, current episode manic", "Brief Psychotic Disorder", "Substance-Induced Psychotic Disorder", "Delusional Disorder", "Schizophrenia"], "ans": 2, "exp": "อาการโรคจิตเฉียบพลันหลังใช้สารเสพติด = substance-induced psychotic disorder", "sys": "V"}, {"topic": "Psychiatry", "q": "A 22-year-old college student acting erratically and agitated, with conjunctival injection, euphoric mood, increased talkativeness, smelling faintly of burnt rope, heart rate 110. Which substance is most likely?", "choices": ["Cocaine", "Amphetamines", "LSD", "Cannabis", "Alcohol"], "ans": 3, "exp": "ตาแดง (conjunctival injection) + ครึกครื้น พูดมาก + กลิ่นเหมือนเชือกไหม้ (กลิ่นกัญชา) + ชีพจรเร็ว = cannabis", "sys": "V"}, {"topic": "Pediatrics", "q": "A 4-year-old child with a rash on the face: some lesions are honey-colored crusts and others are fluid-filled vesicles on a red base. Afebrile and playful. Most likely diagnosis?", "choices": ["Chickenpox (Varicella)", "Scabies", "Hand, Foot, and Mouth Disease", "Atopic Dermatitis", "Impetigo Contagiosum"], "ans": 4, "exp": "สะเก็ดสีน้ำผึ้ง (honey-colored crust) + ตุ่มน้ำบนฐานแดง ที่ใบหน้า เด็กสบายดีไม่มีไข้ = impetigo contagiosum", "sys": "I"}, {"topic": "Pediatrics", "q": "A 7-year-old girl frequently 'spaces out' in class; episodes last ~10 seconds with blank staring, then immediate return to normal with no post-ictal confusion, multiple times a day. First-line treatment?", "choices": ["Ethosuximide", "Phenytoin", "Carbamazepine", "Valproic Acid", "Levetiracetam"], "ans": 0, "exp": "absence seizure (เหม่อลอย ~10 วินาที ไม่มี post-ictal เป็นหลายครั้งต่อวัน) -> first-line คือ ethosuximide (valproate เป็นทางเลือกถ้ามี generalized tonic-clonic ร่วม)", "sys": "VI"}, {"topic": "Pediatrics", "q": "A 7-year-old boy with palpable purpura on the lower extremities and buttocks over 2 days, plus knee and ankle pain, a mild URI last week, and occasional abdominal pain. Most critical initial investigation?", "choices": ["Skin biopsy for immunofluorescence", "Urinalysis", "Antinuclear antibody (ANA) test", "Throat culture", "Serum IgE levels"], "ans": 1, "exp": "Henoch-Schonlein purpura (palpable purpura ที่ก้น/ขา + ปวดข้อ + ปวดท้อง หลัง URI) -> ตรวจ urinalysis ประเมินไตอักเสบ (ภาวะแทรกซ้อนสำคัญที่สุด)", "sys": "III"}, {"topic": "Pediatrics", "q": "A 7-year-old boy with multiple asymptomatic yellow-pink papules and nodules over elbows and knees in clusters, soft. Most critical investigation first?", "choices": ["Liver function tests", "Thyroid function tests", "Lipid profile", "Skin biopsy", "Serum protein electrophoresis"], "ans": 2, "exp": "ตุ่ม/ก้อนสีเหลืองชมพูเป็นกลุ่มที่ข้อศอก/เข่า = xanthoma -> ตรวจ lipid profile หาภาวะไขมันในเลือดสูง (familial hyperlipidemia)", "sys": "IV"}, {"topic": "Pediatrics", "q": "A 12-year-old boy with a raised, firm, hyperkeratotic, papillomatous growth on his finger; the surface is rough with small black dots. Most likely diagnosis?", "choices": ["Actinic keratosis", "Seborrheic keratosis", "Molluscum contagiosum", "Verruca vulgaris", "Squamous cell carcinoma"], "ans": 3, "exp": "ก้อนหูดผิวขรุขระ hyperkeratotic + จุดดำเล็ก ๆ (thrombosed capillaries) ที่นิ้ว = verruca vulgaris (common wart, HPV). *อ้างอิงภาพ*", "img": "https://cdn.jsdelivr.net/gh/MercenzK/Web-quiz-images@main/NL2-2025-Oct-Q39.png", "sys": "II"}, {"topic": "Pediatrics", "q": "A full-term newborn of a mother with poorly controlled gestational diabetes is 2 hours old and jittery. Bedside glucose is 30 mg/dL. Most appropriate initial management?", "choices": ["Feed with 5 mL of expressed breast milk", "Administer Glucagon IM", "Obtain a confirmatory venous serum glucose level", "Start a continuous dextrose infusion", "Administer 10% Dextrose, 2 mL/kg IV"], "ans": 4, "exp": "neonatal hypoglycemia ที่มีอาการ (jittery, glucose 30) -> ให้ 10% dextrose 2 mL/kg IV ทันที (อาการชัดจึงไม่รอ/ไม่ให้กินอย่างเดียว)", "sys": "XV"}, {"topic": "Pediatrics", "q": "A 9-year-old boy struggling to keep up with peers in reading and mathematics despite regular attendance and no behavioral problems; tries hard but has difficulty processing and retaining new information. Most likely underlying issue?", "choices": ["Specific learning disorder", "Attention-deficit/hyperactivity disorder (ADHD)", "Intellectual disability", "Absence of a supportive learning environment", "Auditory processing disorder"], "ans": 0, "exp": "เรียนตามเพื่อนไม่ทันเฉพาะบางด้าน (อ่าน/คณิต) ทั้งที่ตั้งใจและไม่มีปัญหาพฤติกรรม = specific learning disorder", "sys": "flex"}, {"topic": "Pediatrics", "q": "A 3-year-old with hyperactivity, short attention span, prefers to play alone, kept quiet with unlimited smartphone use, and below the 5th percentile for weight and height. Most significant contributing factor to growth delay?", "choices": ["Autism spectrum disorder", "Inadequate nutritional intake and psychosocial deprivation", "Hyperthyroidism", "Celiac disease", "Chromosomal abnormality"], "ans": 1, "exp": "เด็กตัวเล็ก + สภาพแวดล้อมที่ขาดการดูแล/กระตุ้น + ได้รับอาหารไม่พอ = inadequate nutritional intake and psychosocial deprivation (environmental/nonorganic failure to thrive)", "sys": "XVII"}, {"topic": "Pediatrics", "q": "A 7-year-old girl with easy bruising and recurrent epistaxis, now with multiple non-palpable petechiae and purpura. CBC shows a normal platelet count. Most appropriate next diagnostic test?", "choices": ["Bone marrow biopsy", "Factor VIII assay only", "Von Willebrand factor assay and activity", "Liver function tests", "Peripheral blood smear"], "ans": 2, "exp": "เลือดออกแบบ mucocutaneous (จ้ำเลือด เลือดกำเดา) โดยเกล็ดเลือดปกติ = von Willebrand disease -> ตรวจ von Willebrand factor antigen + activity", "sys": "III"}, {"topic": "Pediatrics", "q": "A 10-year-old from a low-vaccination area with severe sore throat, fever, and dysphagia. A grayish, adherent pseudomembrane covers the tonsils and pharynx with significant cervical lymphadenopathy. Most likely causative organism?", "choices": ["Streptococcus pyogenes", "Epstein-Barr virus", "Arcanobacterium haemolyticum", "Corynebacterium diphtheriae", "Fusobacterium necrophorum"], "ans": 3, "exp": "แผ่นเทาสีเทาเกาะแน่น (pseudomembrane) + คอบวม + วัคซีนไม่ครบ = diphtheria จาก Corynebacterium diphtheriae", "sys": "III"}, {"topic": "Pediatrics", "q": "A 4-year-old with acute asthma exacerbation given two doses of inhaled salbutamol via spacer. 20 minutes later wheezing resolved, SpO2 97% room air, playful and comfortable. Most appropriate next step?", "choices": ["Admit her to the hospital for observation", "Administer a dose of intravenous methylprednisolone", "Give a third dose of salbutamol", "Order a chest X-ray", "Prescribe a short course of oral prednisolone and discharge with follow-up"], "ans": 4, "exp": "asthma exacerbation ที่ตอบสนองดีต่อ SABA (อาการหาย SpO2 ปกติ) -> ให้ oral prednisolone สั้น ๆ แล้วกลับบ้านพร้อมนัดติดตาม", "sys": "X"}, {"topic": "Pediatrics", "q": "An 8-year-old girl with white, non-foul-smelling vaginal discharge, asymptomatic and well, no erythema/irritation/trauma. Most likely diagnosis?", "choices": ["Physiological leukorrhea", "Candidal vulvovaginitis", "A foreign body in the vagina", "Sexual abuse", "Factitious disorder"], "ans": 0, "exp": "ตกขาวสีขาวไม่มีกลิ่น ไม่มีการอักเสบ/ระคายเคือง ในเด็กหญิงที่สบายดี = physiological leukorrhea (ปกติ มักช่วงใกล้เข้าสู่วัยรุ่น)", "sys": "XII"}, {"topic": "Pediatrics", "q": "A healthy 6-month-old exclusively breastfed infant with normal development. Mother asks about introducing other foods. Most appropriate nutritional advice?", "choices": ["Continue exclusive breastfeeding until 1 year of age", "Continue breastfeeding and begin introducing iron-rich solid foods", "Wean from breastmilk and switch to iron-fortified formula", "Start giving whole cow's milk", "Introduce fruit and vegetable purees, but iron supplementation is unnecessary"], "ans": 1, "exp": "อายุ 6 เดือน -> ให้นมแม่ต่อและเริ่มอาหารเสริมที่มีธาตุเหล็กสูง (iron stores เริ่มลดลงหลัง 6 เดือน)", "sys": "flex"}, {"topic": "Pediatrics", "q": "A 4-year-old boy with short stature (<5th percentile), hyperactive behavior, and poor attention span. Mother gives him a smartphone for many hours daily; diet is mainly snacks and sweets and he refuses vegetables. Most significant contributing factor?", "choices": ["Attention-Deficit/Hyperactivity Disorder (ADHD)", "Growth Hormone Deficiency", "Environmental neglect", "Autism Spectrum Disorder", "Hypothyroidism"], "ans": 2, "exp": "ตัวเล็ก + อาหารไม่เหมาะสม + ปล่อยให้ใช้มือถือแทนการดูแล = environmental neglect (nonorganic failure to thrive)", "sys": "IV"}, {"topic": "Anesthesiology", "q": "During pre-anesthetic evaluation of a 45-year-old, you note a thyromental distance of less than 6 cm. This finding is most predictive of?", "choices": ["Difficult mask ventilation", "Increased risk of postoperative nausea", "High risk of aspiration", "Difficult laryngoscopy and endotracheal intubation", "Difficult regional anesthesia"], "ans": 3, "exp": "thyromental distance สั้น (<6 ซม.) ทำนาย difficult laryngoscopy/intubation (ใส่ท่อช่วยหายใจยาก)", "sys": "flex"}, {"topic": "Surgery", "q": "A 16-year-old boy with acute severe scrotal pain for 6 hours, afebrile. Right testis tender and elevated compared to the left; leaning forward while walking slightly alleviates the discomfort. This picture is most characteristic of?", "choices": ["Epididymitis", "Incarcerated Inguinal Hernia", "Testicular Tumor", "Varicocele", "Testicular Torsion"], "ans": 4, "exp": "ปวดอัณฑะเฉียบพลันรุนแรง + อัณฑะยกสูง (high-riding) ในวัยรุ่น = testicular torsion (ภาวะฉุกเฉิน ต้องผ่าตัดภายใน 6 ชม.)", "sys": "II"}, {"topic": "Surgery", "q": "A 40-year-old man in a motorcycle accident with a closed tibia-fibula fracture. After reduction the foot becomes cool and pale and the dorsalis pedis pulse is no longer palpable. Most appropriate diagnostic study for potential vascular injury?", "choices": ["CTA of the leg", "Doppler Ultrasound", "Conventional Angiography", "Magnetic Resonance Angiography (MRA)", "Plain X-ray"], "ans": 0, "exp": "สงสัยบาดเจ็บหลอดเลือดหลังจัดกระดูก -> CT angiography (CTA) ของขา เป็นการตรวจที่รวดเร็วและแม่นยำเป็นอันดับแรก (ถ้ามี hard sign ชัดและ ischemia รุนแรงอาจไปผ่าตัดเลย)", "sys": "XIII"}, {"topic": "Surgery", "q": "A 30-year-old man with second-degree burns over 50% TBSA, weight 80 kg. Parkland total is 8000 mL for the first 24 hours. How should this fluid be administered?", "choices": ["8000 mL evenly over 24 hours", "4000 mL over the first 8 hours, then 4000 mL over the next 16 hours", "2000 mL over the first 2 hours, then 6000 mL over the next 22 hours", "4000 mL over the first 4 hours, then 4000 mL over the next 20 hours", "The entire 8000 mL as a bolus immediately"], "ans": 1, "exp": "Parkland: ให้ครึ่งแรกของปริมาตรใน 8 ชม.แรก (4000 mL) และอีกครึ่งใน 16 ชม.ถัดมา (4000 mL)", "sys": "XVIII"}, {"topic": "Surgery", "q": "A 22-year-old after a high-speed motorcycle crash with an obvious left knee deformity. ABC intact. The left lower extremity is cool and pale; femoral pulse palpable but popliteal, posterior tibial, and dorsalis pedis pulses absent. Most urgent next step?", "choices": ["Obtain a CT angiogram of the lower extremity", "Apply traction and immobilize", "Perform immediate surgical exploration and vascular repair", "Obtain an ankle-brachial index (ABI) measurement", "Administer a therapeutic dose of heparin"], "ans": 2, "exp": "knee dislocation + hard signs ของ vascular injury (ชีพจรใต้เข่าหายหมด ขาเย็นซีด) = popliteal artery injury -> ผ่าตัด exploration + vascular repair ทันที (ischemia time จำกัด ~6 ชม.)", "sys": "XII"}, {"topic": "Surgery", "q": "A 3-month-old boy with a 'lump' in the right groin that comes and goes. Testis descended and normal. When he cries, a soft, non-tender mass in the right inguinal canal reduces with gentle pressure. Most appropriate management?", "choices": ["Immediate surgical repair (herniorrhaphy)", "Manual reduction and application of a truss", "Reassurance and annual monitoring", "Elective surgical repair (herniorrhaphy)", "Ultrasound-guided aspiration"], "ans": 3, "exp": "pediatric inguinal hernia (reducible) -> นัดผ่าตัดซ่อม (elective herniorrhaphy) เพราะมีโอกาส incarceration สูงในทารก (ไม่ใช้ truss/รอเฉย ๆ)", "sys": "II"}, {"topic": "Obstetrics & Gynecology", "q": "A 28-year-old woman after normal vaginal delivery has sudden large vaginal bleeding shortly after placental delivery. The uterus feels soft and boggy. Most appropriate initial management for this postpartum hemorrhage?", "choices": ["Administer Oxytocin", "Prepare for emergency hysterectomy", "Obtain STAT ultrasound", "Start a blood transfusion", "Perform uterine massage"], "ans": 4, "exp": "uterine atony (มดลูกนุ่ม boggy) -> ขั้นแรกทำ uterine massage ทันทีควบคู่การให้ oxytocin (uterotonic) เพื่อกระตุ้นมดลูกหดตัว", "sys": "XV"}, {"topic": "Obstetrics & Gynecology", "q": "A 25-year-old woman with irregular menstrual cycles, hirsutism, acne, BMI 32, and difficulty conceiving. Which lab test is most appropriate to initially confirm PCOS?", "choices": ["Serum Testosterone", "Serum Cortisol", "Serum Prolactin", "Karyotype", "17-hydroxyprogesterone"], "ans": 0, "exp": "PCOS (ประจำเดือนมาไม่ปกติ + hyperandrogenism) -> ตรวจ serum testosterone ยืนยันภาวะฮอร์โมนเพศชายสูง (prolactin/17-OHP ใช้แยกโรคอื่น)", "sys": "IV"}, {"topic": "Obstetrics & Gynecology", "q": "A 17-year-old girl with severe cramping pelvic pain each menstrual period, starting day 1 and lasting 2-3 days, no other symptoms, normal pelvic exam. Most appropriate first-line pharmacological treatment?", "choices": ["Opioid analgesics", "Combined oral contraceptive pill", "Danazol", "Gonadotropin-releasing hormone agonist", "Acetaminophen"], "ans": 1, "exp": "primary dysmenorrhea -> first-line คือ NSAIDs (ยับยั้ง prostaglandin) หรือ hormonal (COC); ในตัวเลือกนี้ NSAIDs ไม่มี จึงเลือก combined oral contraceptive pill ซึ่งเป็น first-line เช่นกัน. *ต้นฉบับไม่มี NSAIDs ในตัวเลือก*", "sys": "I"}, {"topic": "Obstetrics & Gynecology", "q": "A 32-year-old woman at 9 weeks by LMP for a prenatal visit, with resolved light spotting, no cramping/pain, closed cervical os. TVUS shows an intrauterine gestational sac measuring 9 weeks but no fetal pole or cardiac activity. Most likely diagnosis?", "choices": ["Missed abortion", "Threatened abortion", "Blighted ovum", "Inevitable abortion", "Complete abortion"], "ans": 2, "exp": "ถุงการตั้งครรภ์ขนาด 9 สัปดาห์แต่ไม่มี fetal pole เลย = anembryonic pregnancy = blighted ovum (เป็นชนิดหนึ่งของ missed abortion แต่คำที่เจาะจงที่สุดคือ blighted ovum)", "sys": "XV"}, {"topic": "Obstetrics & Gynecology", "q": "A 40-year-old at 38 weeks with GDM undergoes NST. Baseline FHR 140 bpm with no accelerations over 40 minutes (non-reactive). Most appropriate next step?", "choices": ["Continue monitoring for another 40 minutes", "Administer maternal oxygen", "Proceed with immediate cesarean delivery", "Perform a Biophysical Profile (BPP)", "Discharge home and repeat the test in one week"], "ans": 3, "exp": "non-reactive NST -> ประเมินต่อด้วย biophysical profile (BPP) เพื่อยืนยันสุขภาพทารกก่อนตัดสินใจ", "sys": "XV"}, {"topic": "Obstetrics & Gynecology", "q": "A 32-year-old G2P1 at 14 weeks with GDM not controlled by diet, and new essential hypertension. Which regimen is ACCEPTABLE during pregnancy?", "choices": ["Lisinopril and Metformin 2000 mg daily", "Metformin 2000 mg daily and Atorvastatin", "Metformin 2000 mg daily and Ibuprofen", "Losartan and Glyburide", "Labetalol and Metformin 2000 mg daily"], "ans": 4, "exp": "ในครรภ์: labetalol (คุมความดัน) + metformin (คุมเบาหวาน) ปลอดภัย. หลีกเลี่ยง ACEI/ARB (lisinopril, losartan), statin (atorvastatin), NSAIDs (ibuprofen)", "sys": "XV"}, {"topic": "Obstetrics & Gynecology", "q": "A 28-year-old at 12 weeks gestation with dysuria, frequency, urgency; urinalysis positive for nitrites and leukocytes, no fever/flank pain/CVA tenderness. Most appropriate antibiotic?", "choices": ["Amoxicillin", "Ciprofloxacin", "Gentamicin", "Doxycycline", "Trimethoprim-Sulfamethoxazole"], "ans": 0, "exp": "cystitis ในครรภ์ -> เลือกยาที่ปลอดภัย เช่น amoxicillin (หรือ cephalexin, nitrofurantoin). หลีกเลี่ยง fluoroquinolone, doxycycline, และ TMP-SMX (ไตรมาสแรก/ใกล้คลอด)", "sys": "XV"}, {"topic": "Obstetrics & Gynecology", "q": "A 14-year-old with primary amenorrhea, normal breast and pubic hair (Tanner 4), monthly cyclic lower abdominal pain. A bulging, bluish-hued membrane is noted at the vaginal introitus. Most consistent diagnosis?", "choices": ["Mullerian Agenesis", "Imperforate Hymen", "Transverse Vaginal Septum", "Androgen Insensitivity Syndrome", "Polycystic Ovarian Syndrome"], "ans": 1, "exp": "ขาดประจำเดือนปฐมภูมิ + ลักษณะทางเพศปกติ (Tanner 4) + ปวดท้องเป็นรอบ + เยื่อโป่งสีน้ำเงินที่ปากช่องคลอด (hematocolpos) = imperforate hymen", "sys": "general"}, {"topic": "Obstetrics & Gynecology", "q": "A 17-year-old nulliparous woman with severe primary dysmenorrhea, crampy lower abdominal pain beginning with menses, not alleviated by ibuprofen, normal pelvic exam. Most appropriate first-line therapy for long-term management?", "choices": ["Codeine", "Progestin-only pill", "Combined Oral Contraceptive Pills", "Gonadotropin-releasing hormone (GnRH) agonists", "Naproxen"], "ans": 2, "exp": "primary dysmenorrhea ที่ไม่ตอบสนอง NSAID (ibuprofen) -> ขั้นถัดไปคือ combined oral contraceptive pills สำหรับควบคุมระยะยาว (naproxen เป็น NSAID เหมือนกัน ซึ่งล้มเหลวแล้ว)", "sys": "XI"}, {"topic": "Emergency medicine", "q": "A 36-year-old woman drank 3 glasses of ammonia, complaining of oral pain and odynophagia, RR 30/min with stridor. Most appropriate initial management?", "choices": ["Acute abdomen series", "CT chest / abdomen", "Observation", "ET intubation", "EGD"], "ans": 3, "exp": "caustic ingestion + stridor (ทางเดินหายใจอุดกั้น/บวม) -> secure airway ด้วย endotracheal intubation ทันที เป็นอันดับแรก. *อ้างอิงภาพ*", "img": "https://cdn.jsdelivr.net/gh/MercenzK/Web-quiz-images@main/NL2-2025-Oct-Q64.png", "sys": "emergency"}, {"topic": "Emergency medicine", "q": "A 25-year-old after a high-speed MVC, diaphoretic, tachycardic, in severe respiratory distress. Absent breath sounds on the left, trachea deviated to the right, distant heart sounds. Most critical immediate intervention?", "choices": ["Endotracheal intubation", "Tube thoracostomy", "STAT chest X-ray", "Pericardiocentesis", "Needle thoracostomy"], "ans": 4, "exp": "tension pneumothorax ซ้าย (เสียงหายใจซ้ายหาย + trachea เบนขวา + distress) -> needle thoracostomy ระบายลมทันที (ไม่รอ X-ray)", "sys": "emergency"}, {"topic": "Emergency medicine", "q": "A 65-year-old hospitalized after a fall, on bed rest with an NG tube, complains of clear fluid draining from his nose when leaning forward. On tissue a 'halo/ring' sign is observed. This suggests a leak of what substance?", "choices": ["Cerebrospinal fluid (CSF)", "Serum", "Synovial fluid", "Lymph", "Mucus"], "ans": 0, "exp": "น้ำใสจากจมูก + halo/ring sign บนกระดาษ (CSF แยกวงรอบเลือด) = CSF rhinorrhea (รอยรั่วของน้ำไขสันหลัง)", "sys": "emergency"}, {"topic": "Emergency medicine", "q": "A 50-year-old woman 30 minutes after intentionally ingesting a household ammonia cleaner, with oral pain and odynophagia but no stridor, stable vitals. Most appropriate next step?", "choices": ["Immediate endotracheal intubation", "Perform esophagogastroduodenoscopy (EGD)", "Administer activated charcoal", "Give a vinegar", "Obtain an acute abdominal series X-ray"], "ans": 1, "exp": "caustic ingestion ที่ stable ไม่มีการอุดกั้นทางเดินหายใจ -> ทำ EGD (ภายใน 24-48 ชม.) ประเมินระดับการบาดเจ็บของหลอดอาหาร; ห้ามให้ถ่านกัมมันต์/สารกลาง/ทำให้อาเจียน", "sys": "emergency"}, {"topic": "Emergency medicine", "q": "An 8-year-old after a high-impact MVC, tachycardic, tachypneic, hypotensive, with distended neck veins and muffled heart sounds. Most urgent diagnosis?", "choices": ["Tension pneumothorax", "Hemothorax", "Cardiac tamponade", "Aortic dissection", "Myocardial contusion"], "ans": 2, "exp": "Beck's triad (ความดันตก + JVD + เสียงหัวใจเบา) = cardiac tamponade", "sys": "emergency"}, {"topic": "Emergency medicine", "q": "A 55-year-old man collapses 30 minutes into his run, diaphoretic and short of breath. ECG shows ST elevation in II, III, aVF. Nearest cath lab is 3 hours away. Most appropriate reperfusion therapy to give immediately?", "choices": ["Streptokinase", "Heparin infusion", "Clopidogrel", "Alteplase (tPA)", "Metoprolol"], "ans": 3, "exp": "inferior STEMI + ทำ primary PCI ไม่ทันในเวลา (>120 นาที) -> ให้ fibrinolysis; alteplase (tPA, fibrin-specific) เป็นตัวเลือกที่ดี", "sys": "emergency"}, {"topic": "Emergency medicine", "q": "A 17-year-old girl 4 hours after ingesting many tablets in a suicide attempt, nauseous and vomiting. Acetaminophen level is well above the treatment line on the Rumack-Matthew nomogram. Specific antidote?", "choices": ["Flumazenil", "Naloxone", "Activated Charcoal", "Fomepizole", "N-Acetylcysteine"], "ans": 4, "exp": "acetaminophen overdose เหนือ treatment line -> antidote คือ N-acetylcysteine (เติม glutathione)", "sys": "emergency"}, {"topic": "Emergency medicine", "q": "A 24-year-old woman 6 hours after ingesting ~30 paracetamol tablets in a suicide attempt, currently asymptomatic, stable vitals. Most critical next step?", "choices": ["Administer N-Acetylcysteine (NAC) immediately", "Wait for the 24-hour paracetamol level before acting", "Administer activated charcoal", "Start IV fluids and monitor liver enzymes", "Induce vomiting with ipecac syrup"], "ans": 0, "exp": "paracetamol overdose ปริมาณมากที่ 6 ชม. -> NAC ได้ผลดีที่สุดเมื่อให้ภายใน 8 ชม. จึงไม่ควรรอ (ตรวจระดับที่ >=4 ชม.ควบคู่ แต่ต้องรีบให้ NAC เพื่ออยู่ในกรอบเวลา)", "sys": "emergency"}, {"topic": "Emergency medicine", "q": "A 50-year-old man after accidentally drinking half a glass of household ammonia solution, with severe burning pain in mouth, throat, and chest. Most appropriate initial management?", "choices": ["Immediate upper endoscopy to assess injury", "Give milk or water to dilute and provide comfort", "Induce vomiting to remove the corrosive agent", "Administer a neutralizing agent (e.g., vinegar)", "Emergency surgical consultation"], "ans": 1, "exp": "caustic ingestion -> ห้ามทำให้อาเจียน และห้ามให้สารกลาง (vinegar เกิดปฏิกิริยาความร้อน). การให้นม/น้ำปริมาณเล็กน้อยเพื่อเจือจาง/บรรเทาเป็นการดูแลเบื้องต้น แล้วจึงประเมินด้วย EGD", "sys": "emergency"}, {"topic": "Emergency medicine", "q": "A 25-year-old struck in the head with a baseball bat, with brief loss of consciousness. Non-contrast CT head performed. Diagnosis?", "choices": ["Epidural hematoma", "Subarachnoid hemorrhage", "Subdural hematoma", "Intraparenchymal hemorrhage", "Diffuse axonal injury"], "ans": 2, "exp": "*จากภาพจริง* เลือดออก hyperdense รูปพระจันทร์เสี้ยว (crescent) เกาะตามผิวโค้งของสมอง + มี mass effect/midline shift = subdural hematoma (ไม่ใช่ epidural ที่เป็นรูป biconvex/lens). *อ้างอิงภาพ CT*", "img": "https://cdn.jsdelivr.net/gh/MercenzK/Web-quiz-images@main/NL2-2025-Oct-Q73.png", "sys": "emergency"}, {"topic": "Emergency medicine", "q": "A 35-year-old after a high-speed motorcycle collision with significant facial trauma, midface instability, active nasal bleeding, and GCS 14. Most appropriate method for securing the airway?", "choices": ["Nasotracheal intubation", "Cricothyroidotomy", "Awake fiberoptic orotracheal intubation", "Orotracheal intubation with rapid sequence induction", "Bag-valve-mask ventilation until surgery"], "ans": 3, "exp": "midface fracture instability -> ห้าม nasotracheal intubation (เสี่ยงเข้ากะโหลกผ่าน cribriform). ทางเลือกคือ orotracheal intubation with RSI (เตรียมทำ surgical airway สำรองถ้าล้มเหลว)", "sys": "emergency"}, {"topic": "Emergency medicine", "q": "A 45-year-old woman after a head-on MVC wearing a lap-and-shoulder belt, hemodynamically stable, with a linear 'seat belt sign' bruise across the lower abdomen. Increased risk of injury to which structure?", "choices": ["Rib fractures", "Myocardial contusion", "Lumbar spine fracture", "Diaphragmatic rupture", "Small bowel and mesentery"], "ans": 4, "exp": "seat belt sign ที่หน้าท้อง -> เพิ่มความเสี่ยงบาดเจ็บ hollow viscus โดยเฉพาะ small bowel และ mesentery (รวมถึง lumbar Chance fracture)", "sys": "emergency"}, {"topic": "Surgery", "q": "A 22-year-old tennis player collapses with sudden severe right scrotal pain and nausea after a twisting motion. The right testis is high-riding and exquisitely tender. Most likely diagnosis?", "choices": ["Testicular Torsion", "Epididymitis", "Incarcerated Inguinal Hernia", "Testicular Tumor", "Varicocele"], "ans": 0, "exp": "ปวดอัณฑะเฉียบพลันหลังบิดตัว + อัณฑะยกสูง (high-riding) เจ็บมาก = testicular torsion", "sys": "II"}, {"topic": "Emergency medicine", "q": "A 5-year-old pulled from a swimming pool. Bystanders started CPR. On paramedic arrival the child is apneic but has a palpable pulse. Most critical next step?", "choices": ["Start chest compressions", "Provide rescue breaths/ventilatory support", "Establish intravenous access", "Administer epinephrine", "Perform emergency cricothyroidotomy"], "ans": 1, "exp": "หยุดหายใจแต่ยังมีชีพจร (respiratory arrest) -> ให้ rescue breaths/ช่วยหายใจ (ไม่กดหน้าอกถ้ายังมีชีพจร)", "sys": "emergency"}, {"topic": "Emergency medicine", "q": "A 25-year-old after a high-speed collision, tachycardic and hypoxic. Decreased breath sounds on the left, trachea deviated to the right, heart sounds louder on the left. Most critical immediate intervention?", "choices": ["Endotracheal intubation", "Insertion of a chest tube", "Needle decompression", "Pericardiocentesis", "Emergency thoracotomy"], "ans": 2, "exp": "tension pneumothorax ซ้าย -> needle decompression (needle thoracostomy) ระบายลมทันที", "sys": "emergency"}, {"topic": "Emergency medicine", "q": "A 45-year-old farmer 30 minutes after a pit viper snake bite on the leg. Anxious, bite site swollen and painful. Most appropriate first action?", "choices": ["Administer polyvalent antivenom immediately", "Apply a tight arterial tourniquet proximal to the bite", "Incise and suction the wound to remove venom", "Immobilize the limb and obtain coagulation studies", "Administer prophylactic broad-spectrum antibiotics"], "ans": 3, "exp": "งูพิษต่อเลือด (pit viper) -> ปฐมพยาบาลด้วยการ immobilize แขนขา + ส่งตรวจ coagulation studies (VCT/20-min WBCT) เพื่อประเมิน envenomation. ให้ antivenom เมื่อมีสัญญาณพิษ; ห้ามรัด tourniquet แน่น/กรีดดูดพิษ", "sys": "emergency"}, {"topic": "Emergency medicine", "q": "A 19-year-old struck by lightning while camping, briefly unconscious but now awake, alert, with normal vital signs and no obvious injuries. Most appropriate next step?", "choices": ["Discharge him with instructions for rest", "Administer a bolus of intravenous fluids", "Order a full body CT scan", "Prescribe a course of oral analgesics", "Transfer to a hospital for 24 hours of cardiac monitoring"], "ans": 4, "exp": "lightning/electrical injury -> เสี่ยงหัวใจเต้นผิดจังหวะแม้อาการปกติ -> ควร monitor คลื่นไฟฟ้าหัวใจ ~24 ชม.", "sys": "emergency"}, {"topic": "Community/EBM", "q": "A 72-year-old immunocompetent man with hypertension and diabetes who has never received any pneumococcal vaccine. Which pneumococcal vaccine should be administered?", "choices": ["Both PCV13 and PPSV23", "Pneumococcal conjugate vaccine (PCV13)", "Pneumococcal polysaccharide vaccine (PPSV23)", "No pneumococcal vaccination is needed", "Hepatitis B vaccine"], "ans": 0, "exp": "ผู้สูงอายุ (>=65 ปี) ที่ยังไม่เคยได้ -> ให้วัคซีนนิวโมคอคคัสทั้ง PCV แล้วตามด้วย PPSV23 (ปัจจุบันอาจใช้ PCV15/PCV20 ตัวเดียว; ในตัวเลือกนี้คือ 'both PCV13 และ PPSV23')", "sys": "general"}, {"topic": "Community/EBM", "q": "A 30-year-old man with an open leg wound from a dog bite 24 hours ago, dog vaccination status unknown, who completed a full primary rabies vaccination series 5 years ago. Appropriate rabies post-exposure prophylaxis?", "choices": ["No vaccination is needed", "Two doses of rabies vaccine (on day 0 and day 3)", "Two doses of rabies vaccine (day 0 and day 3) plus Rabies Immunoglobulin (RIG)", "A full 4-dose vaccine series", "A single booster vaccine"], "ans": 1, "exp": "เคยฉีดวัคซีนพิษสุนัขบ้าครบชุดมาก่อน + สัมผัสซ้ำ -> ฉีด booster 2 เข็ม (วันที่ 0 และ 3) โดยไม่ต้องให้ RIG", "sys": "general"}, {"topic": "Community/EBM", "q": "A 40-year-old man with no significant history for a routine check-up, feeling well, with 10-pack-year smoking and a family history of early CAD. The physician orders a fasting lipid panel. This is an example of which level of prevention?", "choices": ["Primordial Prevention", "Primary Prevention", "Secondary Prevention", "Tertiary Prevention", "Quaternary Prevention"], "ans": 2, "exp": "การตรวจคัดกรอง (screening lipid panel) ในผู้ไม่มีอาการเพื่อค้นหาความผิดปกติระยะแรก = secondary prevention", "sys": "general"}, {"topic": "Community/EBM", "q": "A school health surveillance program identifies a high prevalence of obesity among students. Which population-based intervention likely has the greatest sustainable impact?", "choices": ["Invite only the obese children to a special after-school exercise program", "Send educational pamphlets about childhood obesity to all parents", "Perform individual BMI screenings for every student each month", "Implement a school-wide policy to improve the nutritional quality of school meals and promote physical activity for all students", "Prescribe a weight loss diet for each obese child"], "ans": 3, "exp": "มาตรการระดับประชากรที่ยั่งยืนที่สุด = นโยบายทั้งโรงเรียน (ปรับคุณภาพอาหาร + ส่งเสริมการออกกำลังกายสำหรับนักเรียนทุกคน)", "sys": "general"}, {"topic": "Otolaryngology", "q": "A 58-year-old woman with intense, brief spinning episodes (<1 minute) triggered by rolling over in bed or looking up. Most likely diagnosis and pathophysiology?", "choices": ["Vestibular neuritis; viral inflammation of the vestibular nerve", "Meniere's disease; endolymphatic hydrops", "Vertebrobasilar insufficiency; transient ischemia to the brainstem", "Acoustic neuroma; compression of the vestibulocochlear nerve", "Benign Paroxysmal Positional Vertigo (BPPV); displacement of otoconia into the semicircular canals"], "ans": 4, "exp": "เวียนศีรษะสั้น ๆ (<1 นาที) สัมพันธ์กับการเปลี่ยนท่าศีรษะ = BPPV จากตะกอนหินปูน (otoconia) หลุดเข้าไปใน semicircular canal", "sys": "VIII"}, {"topic": "Orthopedics", "q": "A 72-year-old woman with osteoporosis after a mechanical fall, with severe right thigh pain and unable to bear weight. X-ray shows a transverse fracture between the lesser trochanter and the isthmus of the femoral shaft. Most specific classification?", "choices": ["Subtrochanteric fracture", "Femoral neck fracture", "Intertrochanteric fracture", "Pathological fracture", "Supracondylar fracture"], "ans": 0, "exp": "กระดูกหักบริเวณใต้ lesser trochanter ลงไปถึง isthmus ของ femoral shaft = subtrochanteric fracture", "sys": "XIII"}, {"topic": "Orthopedics", "q": "A 25-year-old basketball player jammed his finger; he cannot actively extend the DIP joint (passive extension possible), mild swelling, no laceration. Most appropriate initial management?", "choices": ["Surgical fixation", "Aluminum splint with DIP joint in extension", "Buddy taping to adjacent finger", "Dynamic splinting", "Corticosteroid injection"], "ans": 1, "exp": "mallet finger (extensor tendon หลุดที่ DIP งอลงเอง เหยียดเองไม่ได้) -> ดามนิ้ว (aluminum splint) ให้ DIP เหยียดตรงต่อเนื่อง 6-8 สัปดาห์", "sys": "XIII"}, {"topic": "Orthopedics", "q": "A 32-year-old woman with a smooth, round, 1.5 cm mass on the dorsum of her wrist for months, non-tender, fluctuant, transilluminates brightly, fluctuates slightly in size. Most likely diagnosis?", "choices": ["Giant cell tumor of tendon sheath", "Lipoma", "Carpal ganglion cyst", "Rheumatoid nodule", "Sebaceous cyst"], "ans": 2, "exp": "ก้อนที่หลังข้อมือ นุ่ม ส่องไฟทะลุ (transilluminate) ขนาดเปลี่ยนได้ = carpal ganglion cyst (ถุงน้ำ)", "sys": "XIII"}, {"topic": "Orthopedics", "q": "A 17-year-old male with several weeks of right shoulder pain after starting weightlifting, localized to the lateral shoulder, worse with overhead activities. Pain with resisted abduction and external rotation, full passive range of motion. Most appropriate initial management?", "choices": ["Subacromial corticosteroid injection", "Surgical referral for arthroscopic decompression", "Prescription of NSAIDs and sling immobilization for 2 weeks", "Physical therapy focusing on rotator cuff and scapular stabilizer strengthening", "Magnetic Resonance Imaging (MRI) of the shoulder"], "ans": 3, "exp": "rotator cuff tendinopathy/impingement -> การรักษาเบื้องต้นคือ physical therapy (เสริมความแข็งแรง rotator cuff และ scapular stabilizer) ร่วมกับปรับกิจกรรม", "sys": "XIII"}, {"topic": "Orthopedics", "q": "A 45-year-old housewife with 2 months of pain on the outside of the right elbow, worse when lifting bags, wringing towels, or using a screwdriver. Tenderness over the lateral epicondyle, pain with resisted wrist extension. Most likely diagnosis?", "choices": ["Medial Epicondylitis (Golfer's Elbow)", "Olecranon Bursitis", "Radial Tunnel Syndrome", "Cervical Radiculopathy", "Lateral Epicondylitis (Tennis Elbow)"], "ans": 4, "exp": "ปวด lateral epicondyle + เจ็บเมื่อกระดกข้อมือต้านแรง = lateral epicondylitis (tennis elbow)", "sys": "XIII"}, {"topic": "Orthopedics", "q": "A 60-year-old man with a firm, non-tender, bony-hard lump on the back of the elbow, slowly growing over months, limiting full extension. History of heavy manual labor. Most likely diagnosis?", "choices": ["Osteophyte (bone spur) from osteoarthritis", "Olecranon bursitis", "Rheumatoid nodule", "Gouty tophus", "Osteochondroma"], "ans": 0, "exp": "ก้อนแข็งเหมือนกระดูก (bony-hard) ที่ข้อศอก โตช้า จำกัดการเหยียด ในผู้ใช้แรงงาน = osteophyte (bone spur) จาก osteoarthritis", "sys": "XIII"}, {"topic": "Orthopedics", "q": "A 35-year-old administrative assistant with a painless, firm, rubbery lump on the dorsum of the wrist for months, unchanged with activity, transilluminates brightly. Most likely diagnosis?", "choices": ["Giant Cell Tumor of the Tendon Sheath", "Carpal Ganglion Cyst", "Lipoma", "Rheumatoid Nodule", "Heberden's Node"], "ans": 1, "exp": "ก้อนที่หลังข้อมือ ส่องไฟทะลุ (transilluminate) = carpal ganglion cyst", "sys": "XIII"}, {"topic": "Orthopedics", "q": "A 70-year-old woman with longstanding bilateral knee pain, significant varus deformities, great difficulty walking, and X-rays showing bone-on-bone tricompartmental osteoarthritis. Most definitive long-term management?", "choices": ["Intra-articular corticosteroid injections", "Oral acetaminophen and physical therapy", "Total Knee Arthroplasty", "High tibial osteotomy", "Unicompartmental knee arthroplasty"], "ans": 2, "exp": "osteoarthritis รุนแรง bone-on-bone หลายช่อง (tricompartmental) + เดินลำบากมาก -> การรักษาถาวรที่ดีที่สุดคือ total knee arthroplasty (เปลี่ยนข้อเข่าเทียม)", "sys": "XIII"}, {"topic": "Orthopedics", "q": "A 22-year-old tennis player after a ball struck the tip of his right middle finger; the end joint is drooped and he cannot actively straighten it (passive extension possible). Most appropriate initial management?", "choices": ["Buddy taping to the adjacent finger", "Immediate surgical repair", "Application of a volar splint holding the MCP joint in flexion", "Application of a dorsal aluminum splint holding the DIP joint in extension", "Dynamic extension splinting"], "ans": 3, "exp": "mallet finger -> ดามด้วย dorsal aluminum splint ให้ DIP เหยียดตรงต่อเนื่อง. *อ้างอิงภาพ*", "img": "https://cdn.jsdelivr.net/gh/MercenzK/Web-quiz-images@main/NL2-2025-Oct-Q94.png", "sys": "XIII"}, {"topic": "Ophthalmology", "q": "A 55-year-old fisherman with a fleshy, triangular growth extending from the nasal conjunctiva onto the cornea of the right eye, with occasional redness and foreign body sensation, now encroaching 2 mm into the visual axis. Primary indication for surgical intervention?", "choices": ["Cosmetic concerns", "Chronic redness", "Risk of malignant transformation", "Pain", "Impending involvement of the visual axis causing reduced vision"], "ans": 4, "exp": "pterygium ที่ลามเข้าใกล้/ถึง visual axis จนกระทบการมองเห็น = ข้อบ่งชี้หลักในการผ่าตัด", "sys": "VII"}, {"topic": "Ophthalmology", "q": "A 38-year-old woman with progressive central weight gain, moon facies, easy bruising, hypertension, wide purple abdominal striae, and a buffalo hump. Abnormal secretion of which hormone?", "choices": ["Cortisol", "Insulin", "Thyroxine", "Aldosterone", "Adrenocorticotropic hormone"], "ans": 0, "exp": "Cushing syndrome (moon face, central obesity, purple striae, buffalo hump, ช้ำง่าย) = ฮอร์โมน cortisol เกิน", "sys": "VII"}, {"topic": "Ophthalmology", "q": "A 55-year-old farmer with severe ocular pain, photophobia, and decreased vision after being dusted in the eye harvesting corn. Slit-lamp shows a corneal ulcer with a feathery border and a hypopyon. Most likely causative organism?", "choices": ["Pseudomonas aeruginosa", "Fusarium spp.", "Herpes simplex virus", "Acanthamoeba spp.", "Staphylococcus aureus"], "ans": 1, "exp": "corneal ulcer ขอบขนนก (feathery) + hypopyon หลังโดนเศษพืช = fungal keratitis จากเชื้อรา filamentous เช่น Fusarium", "sys": "VII"}, {"topic": "Ophthalmology", "q": "A young child from a remote, arid region with chronic bilateral conjunctival injection, mucopurulent discharge, photophobia, follicular conjunctivitis, Herbert's pits on the superior limbus, and upper tarsal scarring with entropion and trichiasis. Most likely organism?", "choices": ["Staphylococcus aureus", "Adenovirus", "Chlamydia trachomatis serotypes A, B, C", "Neisseria gonorrhoeae", "Haemophilus influenzae"], "ans": 2, "exp": "trachoma (follicular conjunctivitis + Herbert's pits + tarsal scarring -> entropion/trichiasis) = Chlamydia trachomatis serotype A, B, C", "sys": "VII"}, {"topic": "Ophthalmology", "q": "A 35-year-old woman with 1 year of progressive weight gain, hirsutism, irregular menses, central obesity, moon face, and wide purple striae. Most likely laboratory finding?", "choices": ["Low serum ACTH level", "Elevated serum testosterone", "Positive anti-21-hydroxylase antibodies", "Elevated 24-hour urinary free cortisol", "Low serum aldosterone"], "ans": 3, "exp": "Cushing syndrome -> ตรวจพบ 24-hour urinary free cortisol สูง (คัดกรองภาวะคอร์ติซอลเกิน)", "sys": "VII"}, {"topic": "Ophthalmology", "q": "A 60-year-old farmer with a painful, red right eye and blurred vision after being struck by plant material. Slit-lamp shows a dry-looking, elevated corneal ulcer with feathery margins and a hypopyon. Most likely causative agent?", "choices": ["Pseudomonas aeruginosa", "Staphylococcus aureus", "Acanthamoeba spp.", "Herpes Simplex Virus", "Aspergillus spp."], "ans": 4, "exp": "fungal keratitis (แผลกระจกตาแห้ง นูน ขอบขนนก + hypopyon หลังบาดเจ็บจากพืช) = เชื้อรา filamentous เช่น Aspergillus/Fusarium", "sys": "VII"}, {"topic": "Ophthalmology", "q": "A 28-year-old woman with a small, painless, firm nodule in the mid-portion of the upper eyelid for 3 weeks, non-erythematous, overlying skin mobile, conjunctival surface slightly reddened. Recommended first-line treatment?", "choices": ["Application of warm compresses and gentle massage", "Incision and curettage", "Oral antibiotic therapy", "Topical antibiotic-steroid ointment", "Observation without intervention"], "ans": 0, "exp": "chalazion (ก้อนไม่เจ็บที่เปลือกตา จาก Meibomian gland อุดตัน) -> first-line คือประคบอุ่น + นวดเบา ๆ; I&C ทำเมื่อไม่ตอบสนอง", "sys": "VII"}, {"topic": "Forensic medicine", "q": "A 40-year-old man found dead with a blood-stained knife and multiple superficial slash wounds on the arms, a plastic bag tightly secured over his head with tape around the neck, and an empty bottle of alprazolam nearby. Most accurate primary cause of death to document?", "choices": ["Exsanguination from sharp force injuries", "Asphyxiation due to smothering/plastic bag suffocation", "Combined drug toxicity and traumatic injury", "Undetermined, pending toxicology results", "Suicide by multiple methods"], "ans": 1, "exp": "แผลกรีดตื้น ๆ (hesitation) ไม่ทำให้เสียชีวิต -> กลไกที่ทำให้ตายคือขาดอากาศจากถุงพลาสติกคลุมศีรษะ = asphyxiation (cause of death). ('suicide by multiple methods' เป็น manner ไม่ใช่ cause)", "sys": "general"}, {"topic": "Forensic medicine", "q": "A 25-year-old man sustains a gunshot wound to the thigh, does not seek care, and is found dead 3 days later. Autopsy: exsanguination from ruptured femoral artery. Which best describes the manner of death?", "choices": ["Natural", "Accident", "Homicide", "Suicide", "Undetermined"], "ans": 2, "exp": "เสียชีวิตจากบาดแผลกระสุนปืนที่ผู้อื่นกระทำ (แม้ตายช้าไป 3 วัน) = homicide (manner of death ตัดสินจากเหตุที่ทำให้เกิดการบาดเจ็บ)", "sys": "general"}, {"topic": "Forensic medicine", "q": "A man found dead in a running car inside a closed garage after a severe financial argument; his wife is distressed but conscious outside. Autopsy shows bright red lividity and carboxyhemoglobin 65%. Most likely manner of death?", "choices": ["Natural", "Accident", "Homicide", "Suicide", "Undetermined"], "ans": 3, "exp": "CO poisoning (bright red lividity + COHb 65%) จากการติดเครื่องยนต์ในโรงรถปิด + มีเจตนา (พูดจะจบชีวิต) = suicide", "sys": "general"}, {"topic": "Forensic medicine", "q": "A single-car collision at 18:00; the driver is arrested for suspected DUI. At 22:00 a breathalyzer shows BAC 40 mg/dL. Elimination rate 15 mg/dL/hour. Estimated BAC at the time of the accident (18:00)?", "choices": ["60 mg/dL", "80 mg/dL", "120 mg/dL", "140 mg/dL", "100 mg/dL"], "ans": 4, "exp": "back-extrapolation: 40 + (15 mg/dL/ชม. x 4 ชม. จาก 18:00 ถึง 22:00) = 40 + 60 = 100 mg/dL", "sys": "general"}, {"topic": "Forensic medicine", "q": "A man dies after a wall collapsed on his chest and abdomen during a storm. At autopsy, which finding is most specific for traumatic asphyxia?", "choices": ["Intense purple-red discoloration and petechiae of the face, neck, and upper chest", "Multiple rib fractures", "Laceration of the liver and spleen", "Pulmonary edema", "Fat emboli in the lungs"], "ans": 0, "exp": "traumatic asphyxia (แรงกดทรวงอก/ท้อง) -> เลือดคั่งย้อนกลับทำให้ใบหน้า คอ อกส่วนบน มีสีม่วงแดง + petechiae (masque ecchymotique) เป็นลักษณะจำเพาะ", "sys": "general"}, {"topic": "Forensic medicine", "q": "During a fight, a man stabs another; the victim does not seek care and dies several days later from a severe wound infection. The assailant claims he only intended to injure, not kill. Most appropriate charge?", "choices": ["Murder premeditated", "Assault causing bodily harm that results in death", "Murder without premeditation", "Negligent homicide", "Justifiable homicide"], "ans": 1, "exp": "เจตนาทำร้าย (ไม่เจตนาฆ่า) แต่เป็นเหตุให้ผู้อื่นถึงแก่ความตาย = ทำร้ายร่างกายจนเป็นเหตุให้ผู้อื่นถึงแก่ความตาย (assault causing bodily harm resulting in death)", "sys": "general"}, {"topic": "Community/EBM", "q": "A new drug for secondary prevention of MI shows a statistically significant reduction in the primary endpoint in an RCT. How is the Number Needed to Treat (NNT) calculated?", "choices": ["The inverse of the Relative Risk Reduction (1 / RRR)", "The difference in event rates between the control and treatment groups", "The inverse of the Absolute Risk Reduction (1 / ARR)", "The ratio of the risk in the treatment group to the risk in the control group", "The number of patients who benefited from the treatment in the trial"], "ans": 2, "exp": "NNT = 1 / ARR (absolute risk reduction). (RRR ใช้คำนวณสัดส่วน ไม่ใช่ NNT; ARR เองคือผลต่างของ event rate)", "sys": "general"}, {"topic": "Medical ethics", "q": "A 32-year-old woman with multiple bruises in various stages of healing on protected areas, nervous and avoiding eye contact; her husband insists she fell down the stairs, and she is reluctant to speak in his presence. Most appropriate initial management?", "choices": ["Refer the patient to a multidisciplinary domestic violence team", "Perform a pelvic or internal examination", "Treat the bruises based on medical condition alone", "Ask the husband to leave the room to interview the patient privately", "Document the findings and discharge the patient with follow-up instructions"], "ans": 3, "exp": "สงสัยความรุนแรงในครอบครัว -> ขั้นแรกต้องแยกสัมภาษณ์ผู้ป่วยเป็นการส่วนตัว (ขอให้สามีออกจากห้อง) เพื่อให้ผู้ป่วยเล่าได้อย่างปลอดภัย", "sys": "general"}, {"topic": "Medical ethics", "q": "An unconscious, unidentified man is brought to the ED after a motorcycle accident and needs immediate life-saving surgery, with no time to verify identity or insurance. Under which Thai public health policy is the emergency care cost covered?", "choices": ["Social Security Scheme", "Civil Servant Medical Benefit Scheme", "Medical Welfare Scheme", "National Health Security Act", "Universal Coverage for Emergency Patients"], "ans": 4, "exp": "ผู้ป่วยฉุกเฉินวิกฤตที่ไม่ทราบตัวตน/สิทธิ -> ครอบคลุมด้วยนโยบาย Universal Coverage for Emergency Patients (UCEP, เจ็บป่วยฉุกเฉินวิกฤตรักษาได้ทุกที่)", "sys": "general"}, {"topic": "Medical ethics", "q": "A junior doctor on a palliative home-visit team sees a 75-year-old man with terminal metastatic lung cancer, significant pain and dyspnea despite maximal therapy, who says 'I am tired of suffering. Please just let me die.' Most appropriate initial response?", "choices": ["'Let's discuss what letting you die means to you and how we can better manage your symptoms.'", "'I will increase your morphine dose to a level that may hasten death.'", "'I cannot honor that request; it is against the law.'", "Refer him immediately to a psychiatrist for evaluation of depression", "Inform him that you will note his request and proceed with the current care plan without changes"], "ans": 0, "exp": "ตอบสนองด้วยการรับฟังและสำรวจความหมาย/ความทุกข์ของผู้ป่วย ('ลองคุยกันว่าที่บอกว่าอยากให้จากไปหมายถึงอะไร และเราจะช่วยจัดการอาการให้ดีขึ้นได้อย่างไร') เป็น patient-centered communication ที่เหมาะสมที่สุด", "sys": "general"}, {"topic": "Medical ethics", "q": "A drunk driver causes a collision injuring the other driver, who needs extensive hospitalization. Per standard motor insurance law, which party is primarily responsible for the initial medical costs of the injured victim?", "choices": ["The driver at fault's voluntary health insurance", "The compulsory motor insurance of the vehicle at fault", "The injured party's own personal savings", "A government-funded universal coverage scheme (UCEP) for emergency care only", "The driver at fault's criminal liability insurance"], "ans": 1, "exp": "ค่ารักษาเบื้องต้นของผู้บาดเจ็บครอบคลุมโดย 'ประกันภัยรถภาคบังคับ (พ.ร.บ.)' ของรถคันที่ก่อเหตุ (compulsory motor insurance)", "sys": "general"}, {"topic": "Forensic medicine", "q": "A 32-year-old male autopsy after a fatal shooting. On the clothing there is a bullet hole with no gunpowder residue or soot stains around the entry defect. What does this indicate about firing distance?", "choices": ["Contact wound", "Close range wound", "Intermediate or distant range wound", "Graze wound", "Ricochet wound"], "ans": 2, "exp": "ไม่มีเขม่า (soot) หรือ gunpowder residue รอบรูกระสุน = ยิงจากระยะไกล/ระยะปานกลาง (intermediate or distant range). ระยะจ่อ/ใกล้จะมี soot/เขม่า; ระยะ intermediate มี stippling/tattooing", "sys": "general"}]}, {"id": "nl2-2026-jan", "title": "NL 2 ปี 2026 มกราคม (VICHAKARN_SMST)", "subject": "past", "questions": [{"topic": "Internal medicine", "q": "A 26-year-old woman with recurrent, disabling, severe throbbing headaches strictly on the right side lasting 12-24 hours, with profound nausea and worsening with bright lights and loud noises. Normal neuro exam. Most likely diagnosis?", "choices": ["Migraine headache", "Tension-type headache", "Cluster headache", "Trigeminal neuralgia", "Giant cell arteritis"], "ans": 0, "exp": "ปวดข้างเดียวตุบ ๆ รุนแรง + คลื่นไส้ + กลัวแสง/เสียง = migraine headache", "sys": "VI"}, {"topic": "Internal medicine", "q": "A 60-year-old man with a slowly enlarging spot on the upper back over a year, not itchy/bleeding. A 1.5 cm sharply demarcated, brownish, slightly raised plaque with a waxy, verrucous, 'stuck-on' appearance. Most likely diagnosis?", "choices": ["Solar lentigo", "Seborrheic keratosis", "Malignant melanoma", "Basal cell carcinoma", "Actinic keratosis"], "ans": 1, "exp": "ก้อนแบนสีน้ำตาลผิวขรุขระคล้ายขี้ผึ้ง ดู 'stuck-on' (แปะติด) = seborrheic keratosis", "sys": "II"}, {"topic": "Internal medicine", "q": "A 35-year-old man with abdominal cramping, tenesmus, and frequent foul-smelling bloody diarrhea after backpacking in rural Southeast Asia. Stool microscopy shows motile trophozoites containing engulfed red blood cells. Most appropriate primary treatment?", "choices": ["Oral ciprofloxacin", "Intravenous ceftriaxone", "Oral metronidazole", "Oral albendazole", "Oral vancomycin"], "ans": 2, "exp": "trophozoite ที่กินเม็ดเลือดแดง = Entamoeba histolytica (amebic dysentery) -> รักษาด้วย metronidazole (ตามด้วยยากำจัด cyst)", "sys": "I"}, {"topic": "Internal medicine", "q": "A 28-year-old woman of Southeast Asian descent with chronic fatigue and scleral icterus. Microcytic hypochromic anemia with normal ferritin, smear shows anisopoikilocytosis, target cells, basophilic stippling. Brilliant cresyl blue supravital stain shows 'golf ball' inclusions. Most likely diagnosis?", "choices": ["Iron deficiency anemia", "Autoimmune hemolytic anemia", "Hereditary spherocytosis", "Hemoglobin H disease", "Megaloblastic anemia"], "ans": 3, "exp": "microcytic + ferritin ปกติ + target cell + HbH inclusion ('golf ball' จาก brilliant cresyl blue) = hemoglobin H disease (alpha-thalassemia)", "sys": "III"}, {"topic": "Internal medicine", "q": "A 48-year-old man with BMI 34 and retrosternal burning, worst after heavy dinners and when lying down. No dysphagia/odynophagia/weight loss/melena. Most appropriate initial step?", "choices": ["Immediate esophagogastroduodenoscopy", "24-hour ambulatory esophageal pH monitoring", "Barium swallow study", "Referral for laparoscopic Nissen fundoplication", "Lifestyle modifications and an empiric trial of proton pump inhibitors (PPIs)"], "ans": 4, "exp": "GERD ที่ไม่มี alarm feature -> เริ่มด้วยปรับพฤติกรรม + ทดลองให้ PPI (empiric); EGD สงวนไว้เมื่อมี alarm feature", "sys": "XI"}, {"topic": "Internal medicine", "q": "A 32-year-old man with poorly controlled HIV (CD4 120) with 3 weeks of progressive dyspnea on exertion, dry cough, SpO2 88%. CXR shows bilateral symmetric fine reticular perihilar interstitial opacities. Most appropriate confirmatory test?", "choices": ["Immunofluorescence assay of induced sputum for Pneumocystis jirovecii", "Sputum acid-fast bacilli smear and culture", "Polymerase chain reaction for Mycoplasma pneumoniae", "Blood cultures for Streptococcus pneumoniae", "Urine antigen test for Legionella pneumophila"], "ans": 0, "exp": "HIV CD4 ต่ำ + interstitial infiltrate + hypoxia = Pneumocystis jirovecii pneumonia (PCP) -> ยืนยันด้วย immunofluorescence/stain ของ induced sputum", "sys": "I"}, {"topic": "Internal medicine", "q": "A 29-year-old woman receiving packed red blood cells develops, 15 minutes after starting, high fever, chills, severe low back pain, and impending doom. Tachycardia, hypotension, and dark reddish-brown urine. Most likely diagnosis?", "choices": ["Transfusion-related acute lung injury", "Acute hemolytic transfusion reaction", "Febrile non-hemolytic transfusion reaction", "Transfusion-associated circulatory overload", "Delayed hemolytic transfusion reaction"], "ans": 1, "exp": "ไข้ + ปวดหลัง + ความดันตก + ปัสสาวะสีแดงเข้ม (hemoglobinuria) ทันทีหลังให้เลือด = acute hemolytic transfusion reaction (ABO incompatibility)", "sys": "III"}, {"topic": "Internal medicine", "q": "A 68-year-old farmer with a generalized tonic-clonic seizure, no prior history. Non-contrast CT reveals multiple small, scattered, calcified nodular lesions throughout the cerebral cortex and basal ganglia, no edema/mass effect. Most likely underlying etiology?", "choices": ["Primary central nervous system lymphoma", "Reactivation of Toxoplasma gondii", "Prior infection with Taenia solium (Neurocysticercosis)", "Metastatic lung carcinoma", "Tuberculous meningitis"], "ans": 2, "exp": "หลาย calcified nodule กระจายในสมอง (เก่า/สงบ) + ชัก = neurocysticercosis (การติดเชื้อพยาธิตืดหมู Taenia solium เดิม)", "sys": "II"}, {"topic": "Internal medicine", "q": "A 35-year-old woman with sudden high fever (39.5), severe headache, profound myalgia, then intense pain and swelling in the small joints of hands and wrists, with a diffuse maculopapular rash, after travel to a rural mosquito-endemic region. Most likely diagnosis?", "choices": ["Dengue fever", "Malaria", "Typhoid fever", "Chikungunya", "Zika virus infection"], "ans": 3, "exp": "ไข้ + ปวด/บวมข้อเล็กรุนแรง + ผื่น หลังไปพื้นที่ยุงชุก = chikungunya (เด่นเรื่องปวดข้อมาก)", "sys": "I"}, {"topic": "Internal medicine", "q": "A 20-year-old with a mildly itchy rash beginning 10 days ago as a single 4 cm oval, salmon-colored patch with a scaly border on the abdomen, then a widespread eruption of smaller scaly plaques on the trunk following cleavage lines ('Christmas tree'). Most likely diagnosis?", "choices": ["Tinea corporis", "Secondary syphilis", "Psoriasis", "Atopic dermatitis", "Pityriasis rosea"], "ans": 4, "exp": "herald patch (ปื้นเดี่ยวนำมาก่อน) + ผื่นตามแนว cleavage line รูป 'Christmas tree' = pityriasis rosea", "sys": "XII"}, {"topic": "Internal medicine", "q": "A 45-year-old woman with new jaundice, dark urine, and RUQ discomfort. No alcohol, negative viral hepatitis panel. She started an internet-purchased herbal weight-loss supplement 3 weeks ago. Which lab is most critical to order initially?", "choices": ["Liver function tests", "Fasting lipid profile", "Serum creatinine and blood urea nitrogen", "Thyroid-stimulating hormone", "Complete blood count with differential"], "ans": 0, "exp": "สงสัย drug/herb-induced liver injury (ดีซ่านหลังเริ่มสมุนไพร) -> ตรวจ liver function tests ประเมินตับ", "sys": "IV"}, {"topic": "Internal medicine", "q": "A 70-year-old farmer with a cheek lesion slowly growing over a year, occasionally bleeding. A 1.2 cm pearly, translucent nodule with rolled borders and arborizing telangiectasias. Basal cell carcinoma suspected. Most appropriate next step?", "choices": ["Prescribe topical 1% hydrocortisone cream", "Perform a punch biopsy of the lesion", "Reassure the patient and schedule a 6-month follow-up", "Perform immediate wide local excision with 2 cm margins", "Swab the lesion for bacterial and fungal cultures"], "ans": 1, "exp": "สงสัย basal cell carcinoma -> ยืนยันด้วยการตัดชิ้นเนื้อ (punch biopsy) ก่อนวางแผนรักษา (ไม่ตัดกว้าง 2 ซม.แบบ melanoma)", "sys": "II"}, {"topic": "Internal medicine", "q": "A 58-year-old obese woman with poorly controlled T2DM has a severe itchy burning red rash under both breasts worsening over 2 weeks. Well-demarcated brightly erythematous plaques with central maceration and satellite papules/pustules in the inframammary folds. KOH prep. Most likely causative organism?", "choices": ["Staphylococcus aureus", "Trichophyton rubrum", "Candida albicans", "Streptococcus pyogenes", "Malassezia furfur"], "ans": 2, "exp": "ผื่นแดงในซอกใต้ราวนม + satellite papules/pustules ในผู้ป่วยเบาหวานอ้วน = candidal intertrigo -> Candida albicans. *อ้างอิงภาพ*", "img": "https://cdn.jsdelivr.net/gh/MercenzK/Web-quiz-images@main/NL2-2026-Jan-Q13.png", "sys": "XII"}, {"topic": "Internal medicine", "q": "A 55-year-old man with hypertension and stable angina on amlodipine and aspirin, asymptomatic. Total cholesterol 240, LDL 120, HDL 40, triglycerides 150. Normal liver/kidney. Most appropriate lipid-lowering medication?", "choices": ["Gemfibrozil", "Ezetimibe", "Cholestyramine", "Atorvastatin", "Niacin"], "ans": 3, "exp": "มีโรคหลอดเลือดหัวใจ (stable angina) = secondary prevention -> ให้ high-intensity statin (atorvastatin)", "sys": "IX"}, {"topic": "Internal medicine", "q": "A woman is a confirmed obligate carrier of Hemophilia A (X-linked recessive); her male partner is unaffected with no family history. If they conceive naturally, probability the child is a male born with Hemophilia A?", "choices": ["0%", "50%", "75%", "100%", "25%"], "ans": 4, "exp": "แม่พาหะ (XhX) x พ่อปกติ (XY) -> ลูก 4 แบบเท่า ๆ กัน: หญิงพาหะ, หญิงปกติ, ชายเป็นโรค (XhY), ชายปกติ -> โอกาสเป็น 'ชายที่เป็นโรค' = 1/4 = 25%", "sys": "III"}, {"topic": "Internal medicine", "q": "A 60-year-old man with gradual bilateral lower extremity numbness/tingling over 2 years, glove-and-stocking sensorimotor axonal polyneuropathy on NCS, HbA1c 8.5% (diabetic peripheral neuropathy). Which investigation is generally UNNECESSARY for this classic chronic presentation?", "choices": ["Lumbar puncture", "Hemoglobin A1c level", "Serum vitamin B12 level", "Thyroid-stimulating hormone (TSH) level", "Fasting lipid panel"], "ans": 0, "exp": "diabetic peripheral neuropathy แบบคลาสสิก -> lumbar puncture ไม่จำเป็น (ใช้กับโรค demyelinating/GBS ไม่ใช่ axonal จากเบาหวาน)", "sys": "IV"}, {"topic": "Internal medicine", "q": "A 52-year-old man with severe chronic alcohol use, found confused. Wide-based unsteady gait (ataxia), horizontal nystagmus, bilateral lateral rectus palsy, disoriented. Deficiency of which vitamin is the primary cause?", "choices": ["Niacin", "Thiamine", "Pyridoxine", "Folate", "Cobalamin"], "ans": 1, "exp": "triad: confusion + ataxia + ophthalmoplegia/nystagmus = Wernicke encephalopathy จากการขาด thiamine (vitamin B1)", "sys": "VI"}, {"topic": "Internal medicine", "q": "A 50-year-old woman with BP ~155/95 on three clinic visits, asymptomatic, normal BMI, no family history. She reports pharmacy-machine readings are 'always normal.' Normal ECG. Best next step to confirm diagnosis?", "choices": ["Immediately start a low-dose thiazide diuretic", "Prescribe an ACE inhibitor and a calcium channel blocker", "Initiate Home Blood Pressure Monitoring or Ambulatory BP Monitoring", "Order an ultrasound of the renal arteries", "Reassure the patient and schedule a follow-up in one year"], "ans": 2, "exp": "สงสัย white coat hypertension (ความดันที่คลินิกสูงแต่ที่อื่นปกติ) -> ยืนยันด้วย home BP monitoring หรือ ambulatory BP monitoring ก่อนเริ่มยา", "sys": "IX"}, {"topic": "Internal medicine", "q": "A 20-year-old with severe acute gastroenteritis (watery diarrhea and vomiting 12 hours). Initial BP 90/60, HR 110. After 1 L 0.9% NSS bolus: BP 105/70, HR 95. Ongoing diarrhea, cannot tolerate oral intake due to nausea. Most appropriate next step in fluid management?", "choices": ["Discontinue all intravenous fluids and force oral rehydration salts", "Switch to 5% Dextrose in water for nutritional calories", "Give another rapid 1 L bolus of 0.9% NSS", "Continue the 0.9% Normal Saline infusion at an appropriate maintenance rate", "Start 3% hypertonic saline"], "ans": 3, "exp": "ผู้ป่วยตอบสนองต่อ fluid ดีขึ้นแต่ยังเสียน้ำต่อเนื่องและกินไม่ได้ -> ให้ 0.9% NSS ต่อในอัตรา maintenance + ชดเชย ongoing losses (ยังไม่ต้อง bolus ซ้ำ)", "sys": "XI"}, {"topic": "Internal medicine", "q": "A 32-year-old man with high fever, severe myalgia (especially calves), headache, and conjunctival suffusion for 5 days after backpacking in rural Cambodia (waded barefoot through flooded rice paddies). Faint maculopapular rash, mild scleral icterus, mild thrombocytopenia, elevated liver enzymes. Most likely diagnosis?", "choices": ["Malaria", "Dengue fever", "Typhoid fever", "Schistosomiasis", "Leptospirosis"], "ans": 4, "exp": "conjunctival suffusion + ปวดน่องมาก + ดีซ่าน + ลุยน้ำท่วมนา = leptospirosis", "sys": "I"}, {"topic": "Internal medicine", "q": "A 38-year-old man with 3 weeks of low-grade fever, night sweats, progressive headache, lethargy, confusion, nuchal rigidity. CSF: elevated opening pressure, elevated protein, severely decreased glucose, WBC 350 (lymphocyte-predominant), and a fine web-like pellicle forms on standing. Most appropriate immediate specific therapy?", "choices": ["A regimen consisting of isoniazid, rifampin, pyrazinamide, and ethambutol", "Intravenous ceftriaxone, vancomycin, and ampicillin", "High-dose intravenous acyclovir", "Liposomal amphotericin B and flucytosine", "Oral fluconazole and supportive care"], "ans": 0, "exp": "CSF lymphocyte เด่น + น้ำตาลต่ำมาก + โปรตีนสูง + spider-web pellicle ดำเนินกึ่งเฉียบพลัน = tuberculous meningitis -> เริ่ม anti-TB (IRZE) + steroid", "sys": "VI"}, {"topic": "Internal medicine", "q": "A 40-year-old man with insidious fatigue, night sweats, abdominal fullness and early satiety over months. Massive splenomegaly 10 cm below left costal margin. WBC 105,000; smear shows a full continuous spectrum of granulocytes from myeloblasts to mature neutrophils. Most likely diagnosis?", "choices": ["Acute lymphoblastic leukemia", "Chronic myeloid leukemia", "Chronic lymphocytic leukemia", "Acute myeloid leukemia", "Leukemoid reaction secondary to an occult infection"], "ans": 1, "exp": "ม้ามโตมาก + WBC สูงมาก + granulocyte ครบทุกระยะ (myeloblast ถึง neutrophil) = chronic myeloid leukemia (CML)", "sys": "II"}, {"topic": "Internal medicine", "q": "A 24-year-old woman with painful, red bumps on the front of her lower legs over a week, plus mild fever, fatigue, and ankle joint pain. Severe sore throat 2 weeks prior. Multiple bilateral warm, tender, erythematous subcutaneous nodules on the anterior tibia (shown), no ulceration. Most likely diagnosis?", "choices": ["Cellulitis", "Erythema induratum", "Erythema nodosum", "Erythema multiforme", "Pyoderma gangrenosum"], "ans": 2, "exp": "ตุ่มก้อนแดงเจ็บที่หน้าแข้งทั้งสองข้าง หลังเจ็บคอ (post-streptococcal) = erythema nodosum. *อ้างอิงภาพ*", "img": "https://cdn.jsdelivr.net/gh/MercenzK/Web-quiz-images@main/NL2-2026-Jan-Q23.png", "sys": "X"}, {"topic": "Internal medicine", "q": "A 55-year-old man with sudden excruciating pain, swelling, and redness in the right knee waking him from sleep, no trauma, after a barbecue with grilled meats and beer. Erythematous, warm, exquisitely tender knee. Arthrocentesis: cloudy synovial fluid; polarized microscopy shown. No PUD or renal impairment. Most appropriate initial pharmacotherapy?", "choices": ["Initiate immediate therapy with oral allopurinol", "Administer intravenous ceftriaxone and consult orthopedics for a joint washout", "Begin daily maintenance therapy with probenecid", "Prescribe a short, high-dose course of oral indomethacin", "Administer intra-articular hyaluronic acid injections"], "ans": 3, "exp": "acute gout (ผลึกเข็ม negative birefringence) -> รักษาการอักเสบเฉียบพลันด้วย NSAID (indomethacin) ในผู้ไม่มี PUD/ไตเสื่อม. allopurinol/probenecid ไม่เริ่มในระยะเฉียบพลัน. *อ้างอิงภาพ*", "img": "https://cdn.jsdelivr.net/gh/MercenzK/Web-quiz-images@main/NL2-2026-Jan-Q24.png", "sys": "XII"}, {"topic": "Internal medicine", "q": "A 72-year-old farmer with a painless flat dark spot on the right cheek for years, recently growing larger and darker in the center. Significant sun exposure. An asymmetric 1.5 cm pigmented macule with irregular borders and variegated colors (tan to dark brown/black), shown. Most likely diagnosis?", "choices": ["Pigmented basal cell carcinoma", "Seborrheic keratosis", "Solar lentigo", "Actinic keratosis", "Melanoma"], "ans": 4, "exp": "ปื้นสีเข้ม asymmetry + ขอบไม่เรียบ + หลายสี + โตขึ้น (ABCDE) บนผิวโดนแดด = melanoma (lentigo maligna melanoma). *อ้างอิงภาพ*", "img": "https://cdn.jsdelivr.net/gh/MercenzK/Web-quiz-images@main/NL2-2026-Jan-Q25.png", "sys": "II"}, {"topic": "Psychiatry", "q": "A 10-year-old girl with ALL on intensive chemotherapy. Her parents frequently argue in the hospital room; the mother complains the father avoids visiting, the father is overwhelmed by medical bills and feels helpless, and they discuss separation. This is most accurately recognized as a psychosocial complication related to?", "choices": ["The psychological stress and burden of managing a pediatric chronic disease", "An acute primary psychotic breakdown in the parents", "Undiagnosed Munchausen syndrome by proxy in the mother", "A normal, unaffected grieving process of a terminal illness", "Medication-induced behavioral changes in the child"], "ans": 0, "exp": "ความขัดแย้งในครอบครัวจากภาระ/ความเครียดในการดูแลเด็กป่วยเรื้อรัง = psychosocial complication ของการจัดการโรคเรื้อรังในเด็ก", "sys": "V"}, {"topic": "Psychiatry", "q": "A 21-year-old at an EDM party took an 'unknown pill,' now extremely agitated, sweating, aggressive, paranoid ('shadow people trying to steal my organs'). HR 128, BP 160/95, widely dilated pupils. No prior psychiatric history. Most likely diagnosis?", "choices": ["Schizophrenia", "Substance-induced psychotic disorder", "Bipolar I disorder, manic episode", "Panic disorder", "Generalized anxiety disorder"], "ans": 1, "exp": "อาการโรคจิตเฉียบพลัน + sympathetic (tachycardia, HT, รูม่านตาขยาย) หลังใช้สารเสพติด = substance-induced psychotic disorder", "sys": "V"}, {"topic": "Psychiatry", "q": "A 7-year-old girl with chronic stomachaches exclusively on weekday mornings, cries when dropped at school, begs the mother not to leave for fear the mother might get in an accident and never return. Symptoms resolve on weekends. Most likely diagnosis?", "choices": ["Generalized anxiety disorder", "Social anxiety disorder", "Separation anxiety disorder", "Oppositional defiant disorder", "Specific phobia"], "ans": 2, "exp": "กังวล/กลัวการแยกจากผู้ปกครอง (กลัวแม่เป็นอันตราย) + อาการทางกายก่อนไปโรงเรียน = separation anxiety disorder", "sys": "V"}, {"topic": "Psychiatry", "q": "A 24-year-old woman robbed at knifepoint 2 weeks ago, with sudden unprovoked episodes of racing heart, intense shortness of breath, trembling, and overwhelming fear of dying, peaking within 10 minutes and leaving her exhausted. She now avoids going outside. Most accurate description of these episodes?", "choices": ["Generalized anxiety disorder", "Specific phobia", "Malingering", "Panic attacks", "Somatic symptom disorder"], "ans": 3, "exp": "อาการเฉียบพลันถึงจุดสูงสุดใน 10 นาที (ใจสั่น หายใจไม่อิ่ม กลัวตาย) = panic attacks", "sys": "V"}, {"topic": "Psychiatry", "q": "A 48-year-old man admitted for a femur fracture (undisclosed daily heavy alcohol use). On day 3 he becomes acutely confused, agitated, diaphoretic, and hallucinates ('spiders on the walls'). HR 135, BP 170/105, low-grade fever. Most likely diagnosis?", "choices": ["Wernicke encephalopathy", "Hepatic encephalopathy", "Opioid withdrawal syndrome", "Acute schizophrenia episode", "Delirium tremens"], "ans": 4, "exp": "สับสน + agitation + ประสาทหลอน (เห็นแมงมุม) + autonomic hyperactivity วันที่ 3 ของการขาดสุรา = delirium tremens", "sys": "V"}, {"topic": "Psychiatry", "q": "A 35-year-old physician with an overwhelming, persistent fear of contamination who spends exactly 45 minutes washing hands and wears 20 layered sterile gowns before procedures. He recognizes this is irrational and it causes delays, but resisting the ritual causes intolerable anxiety. Most likely diagnosis?", "choices": ["Obsessive-compulsive disorder", "Specific phobia", "Generalized anxiety disorder", "Schizophrenia", "Illness anxiety disorder"], "ans": 0, "exp": "ความคิดย้ำ (กลัวปนเปื้อน) + พฤติกรรมย้ำทำ (ล้างมือ/ใส่เสื้อกาวน์ซ้ำ ๆ) ที่รู้ว่าไม่สมเหตุผลแต่ต้านไม่ได้ = obsessive-compulsive disorder", "sys": "V"}, {"topic": "Psychiatry", "q": "A 42-year-old woman, 2 hours after walking in on her husband with another person, screamed, collapsed, and developed sudden bilateral leg paralysis. Normal neuro exam, DTRs, and neuroimaging. She appears surprisingly unconcerned (la belle indifference). Most likely diagnosis?", "choices": ["Major depressive disorder", "Conversion disorder", "Acute stress disorder", "Factitious disorder", "Panic disorder"], "ans": 1, "exp": "อ่อนแรงเฉียบพลันหลังเหตุการณ์สะเทือนใจ โดยตรวจร่างกาย/imaging ปกติ + la belle indifference = conversion disorder (functional neurological symptom disorder)", "sys": "V"}, {"topic": "Pediatrics", "q": "A full-term male infant with severe respiratory distress, cyanosis, and grunting immediately after birth. Scaphoid (sunken) abdomen, markedly decreased breath sounds over the left hemithorax, heart sounds shifted to the right. Most likely diagnosis?", "choices": ["Tension pneumothorax", "Transient tachypnea of the newborn", "Congenital diaphragmatic hernia", "Respiratory distress syndrome", "Congenital cystic adenomatoid malformation"], "ans": 2, "exp": "scaphoid abdomen + เสียงหายใจซ้ายลด + หัวใจเลื่อนไปขวา + distress ทันทีหลังคลอด = congenital diaphragmatic hernia", "sys": "XVI"}, {"topic": "Pediatrics", "q": "A 4-year-old swallowed a 10-baht coin 30 minutes ago, now playing comfortably, speaking normally, swallowing saliva without difficulty, no stridor/cough/distress, stable vitals. Most appropriate initial step?", "choices": ["Immediate rigid bronchoscopy", "Immediate flexible upper endoscopy", "Reassure the mother and discharge home immediately", "Obtain a radiograph of the chest and abdomen", "Administer oral laxatives to hasten transit"], "ans": 3, "exp": "กลืนเหรียญโดยไม่มีอาการทางเดินหายใจ/กลืนลำบาก -> ถ่าย radiograph ทรวงอกและช่องท้อง เพื่อระบุตำแหน่งเหรียญก่อนตัดสินใจ", "sys": "X"}, {"topic": "Pediatrics", "q": "A previously healthy unvaccinated 5-year-old with low-grade fever, malaise, and a highly pruritic rash beginning on the trunk then spreading to the face and limbs, with macules, papules, vesicles on an erythematous base, and crusted scabs all simultaneously. Most appropriate management?", "choices": ["Prescribe oral acyclovir", "Admit to the hospital for intravenous acyclovir", "Prescribe a topical corticosteroid cream", "Prescribe oral amoxicillin", "Provide supportive care with antipyretics and antipruritics"], "ans": 4, "exp": "varicella (ผื่นหลายระยะพร้อมกัน) ในเด็กแข็งแรง -> รักษาประคับประคอง (ลดไข้ ลดคัน); acyclovir สงวนไว้ผู้เสี่ยงสูง/ผู้ใหญ่/ภูมิคุ้มกันต่ำ", "sys": "I"}, {"topic": "Pediatrics", "q": "A 12-month-old boy with a relapsing rash at both cheeks for 1 month. Mother has allergic rhinitis. Ill-defined erythematous plaque with excoriation, scale, and yellow crust at both cheeks. Most likely diagnosis?", "choices": ["Atopic dermatitis", "Tinea faciei", "Contact dermatitis", "Impetigo nervosa", "Seborrheic dermatitis"], "ans": 0, "exp": "ผื่นเรื้อรังที่แก้มทั้งสองข้างในทารก + ประวัติภูมิแพ้ในครอบครัว = atopic dermatitis (infantile)", "sys": "X"}, {"topic": "Pediatrics", "q": "A 6-year-old girl with a painless 2 cm firm, non-tender, midline neck mass just below the hyoid that moves upward with swallowing and tongue protrusion. Normal thyroid hormones. Before excision of the suspected thyroglossal duct cyst, which imaging best confirms normally located functional thyroid tissue?", "choices": ["Computed tomography (CT) of the neck without contrast", "Radionuclide thyroid scan", "Magnetic resonance imaging (MRI) of the neck", "Lateral neck radiograph", "Positron emission tomography (PET) scan"], "ans": 1, "exp": "thyroglossal duct cyst -> ก่อนผ่าตัดต้องยืนยันว่ามีเนื้อไทรอยด์ที่ทำงานอยู่ตำแหน่งปกติด้วย radionuclide thyroid scan (ประเมิน functional thyroid tissue; ป้องกันการตัดต่อมไทรอยด์เดียวที่มีออกไป)", "sys": "II"}, {"topic": "Pediatrics", "q": "A 3-week-old previously healthy full-term male suddenly begins vomiting dark green bilious fluid, appears lethargic, with a distended abdomen. Plain film shows a 'single bubble' (dilated stomach) with paucity of distal gas. Most likely diagnosis?", "choices": ["Hypertrophic pyloric stenosis", "Duodenal atresia", "Midgut volvulus", "Hirschsprung disease", "Intussusception"], "ans": 2, "exp": "อาเจียนน้ำดี (bilious) เฉียบพลันในทารกที่เคยปกติ = midgut volvulus (malrotation) จนกว่าจะพิสูจน์เป็นอื่น = ภาวะฉุกเฉินทางศัลยกรรม (duodenal atresia จะเป็น double bubble ตั้งแต่แรกเกิด)", "sys": "XVI"}, {"topic": "Pediatrics", "q": "A 4-year-old uncircumcised boy whose parents cannot fully retract his foreskin. No dysuria/balanitis, urinalysis negative, non-scarred tight prepuce (physiologic phimosis). Most appropriate management?", "choices": ["Perform immediate surgical circumcision", "Prescribe a 14-day course of oral antibiotics", "Forcefully retract the foreskin in the clinic to stretch the tissue", "Reassure the parents and advise gentle retraction with routine hygiene", "Refer to pediatric urology for a meatotomy"], "ans": 3, "exp": "physiologic phimosis ในเด็กเล็ก -> reassure + แนะนำรูดเบา ๆ และดูแลสุขอนามัย (หายเองเมื่อโตขึ้น; ห้ามรูดแรง)", "sys": "XIV"}, {"topic": "Pediatrics", "q": "A 6-year-old with 3 days of high fever, severe sore throat, and difficulty swallowing, hot potato voice. Toxic, drooling, leaning forward, significant trismus, unilateral bulging of the soft palate. Most likely diagnosis?", "choices": ["Viral pharyngitis", "Acute epiglottitis", "Retropharyngeal abscess", "Infectious mononucleosis", "Peritonsillar abscess"], "ans": 4, "exp": "hot potato voice + trismus + soft palate bulge ข้างเดียว = peritonsillar abscess", "sys": "I"}, {"topic": "Pediatrics", "q": "A 1-month-old with chronic constipation and abdominal distension, did not pass meconium within 48 hours. Explosive passage of stool after digital rectal exam. Gold standard investigation?", "choices": ["Rectal biopsy", "Barium enema", "Digital rectal examination", "Abdominal ultrasound", "Anorectal manometry"], "ans": 0, "exp": "Hirschsprung disease (ถ่ายขี้เทาช้า + explosive stool) -> gold standard คือ rectal biopsy (ไม่มี ganglion cells)", "sys": "XVI"}, {"topic": "Pediatrics", "q": "A 2-week-old female whose mother (poor prenatal care) had a generalized maculopapular rash and mild fever in the first trimester. The infant has bilateral leukocoria (cataracts), fails to respond to loud noises, and has a continuous machine-like murmur at the left infraclavicular area. Most likely diagnosis?", "choices": ["Congenital cytomegalovirus infection", "Congenital rubella syndrome", "Congenital toxoplasmosis", "Congenital syphilis", "Congenital Zika syndrome"], "ans": 1, "exp": "triad ของ congenital rubella: ต้อกระจก (cataract/leukocoria) + หูหนวก + โรคหัวใจ (PDA, machine-like murmur) หลังแม่เป็นผื่น+ไข้ไตรมาสแรก", "sys": "XV"}, {"topic": "Pediatrics", "q": "A 4-week-old male with sudden green bilious vomiting over 6 hours, lethargic and mildly dehydrated, distended tender abdomen. Upper GI contrast series shows a 'corkscrew' appearance of the duodenum. Most appropriate next step?", "choices": ["Reassure the parents and switch to a soy-based formula", "Prescribe oral antiemetics and discharge home", "Immediate surgical intervention (Ladd procedure)", "Administer a glycerin suppository for suspected constipation", "Schedule an outpatient gastroenterology consultation next week"], "ans": 2, "exp": "midgut volvulus (malrotation) จาก 'corkscrew' duodenum = ภาวะฉุกเฉินทางศัลยกรรม -> ผ่าตัด Ladd procedure ทันที", "sys": "XI"}, {"topic": "Pediatrics", "q": "A 15-year-old with primary amenorrhea, height below 3rd percentile, webbed neck, broad chest with widely spaced nipples, low posterior hairline, and streak ovaries. Most likely karyotype?", "choices": ["46,XX", "47,XXY", "47,XY,+21", "45,X", "47,XXX"], "ans": 3, "exp": "Turner syndrome (เตี้ย คอมีพังผืด อกกว้าง streak ovaries) = karyotype 45,X", "sys": "XVII"}, {"topic": "Surgery", "q": "A 45-year-old man with a painless, slow-growing lump on the upper back for a year that occasionally produces foul-smelling cheesy material. A 2.5 cm firm, mobile subcutaneous nodule with a central dark comedo-like punctum, no erythema. Most likely diagnosis?", "choices": ["Lipoma", "Dermatofibroma", "Sebaceous hyperplasia", "Squamous cell carcinoma", "Epidermal inclusion cyst"], "ans": 4, "exp": "ก้อนใต้ผิวหนังมี central punctum + สารคล้ายเนยเหม็น = epidermal inclusion cyst", "sys": "II"}, {"topic": "Surgery", "q": "A 55-year-old man with intense anal pain and a prolapsed rectal mass, with intermittent bleeding for years, now permanently prolapsed and irreducible. Large, exquisitely tender, thrombosed hemorrhoidal cushions permanently prolapsed and irreducible. Most appropriate definitive management?", "choices": ["Surgical hemorrhoidectomy", "Dietary fiber modification and warm sitz baths", "Rubber band ligation", "Injection sclerotherapy", "Application of topical hydrocortisone cream"], "ans": 0, "exp": "grade IV hemorrhoids (prolapse ถาวร reduce ไม่ได้ + thrombosed) -> รักษาถาวรด้วย surgical hemorrhoidectomy", "sys": "XI"}, {"topic": "Surgery", "q": "A 45-year-old woman with severe constant RUQ pain for 12 hours radiating to the right scapula, with nausea, vomiting, and fever 38.5. Palpation of the RUQ during deep inspiration halts her breathing (Murphy's sign). Normal liver enzymes and bilirubin. Most likely diagnosis?", "choices": ["Acute pancreatitis", "Acute cholecystitis", "Acute ascending cholangitis", "Peptic ulcer perforation", "Choledocholithiasis"], "ans": 1, "exp": "ปวด RUQ + ไข้ + Murphy's sign บวก + LFT/bilirubin ปกติ = acute cholecystitis", "sys": "XI"}, {"topic": "Surgery", "q": "A 62-year-old woman 2 weeks after right total knee arthroplasty with new aching right lower leg pain worsening over 48 hours. Right calf swollen, erythematous, and warm; dorsiflexion elicits deep calf pain. Most likely diagnosis?", "choices": ["Postoperative cellulitis", "Ruptured Baker's cyst", "Deep vein thrombosis (DVT)", "Acute compartment syndrome", "Popliteal artery aneurysm"], "ans": 2, "exp": "หลังผ่าตัดเข่า + น่องบวมแดงร้อนข้างเดียว + ปวดเมื่อ dorsiflexion (Homans) = deep vein thrombosis", "sys": "IX"}, {"topic": "Surgery", "q": "A 55-year-old with a massive small bowel resection (short bowel syndrome, <60 cm viable small intestine), high-output stoma; enteral feeding causes severe diarrhea. Most appropriate primary long-term nutritional support?", "choices": ["Continuous nasogastric tube feeding with an elemental formula", "Clear liquid oral diet supplemented with multivitamins", "Intravenous hydration with 5% Dextrose in 0.45% Normal Saline", "Total parenteral nutrition (TPN)", "Percutaneous endoscopic gastrostomy (PEG) tube feeding"], "ans": 3, "exp": "short bowel syndrome ที่ลำไส้เหลือน้อยมากและทน enteral ไม่ได้ -> ให้ total parenteral nutrition (TPN) ระหว่างรอลำไส้ปรับตัว", "sys": "XI"}, {"topic": "Surgery", "q": "A 35-year-old with severe, sharp, 'tearing' anal pain during defecation lasting about an hour, with bright red blood on the paper, recent constipation and straining. A small, superficial, longitudinal tear in the posterior midline of the anoderm. Most appropriate initial management?", "choices": ["Immediate surgical fistulotomy", "Lateral internal sphincterotomy", "Topical application of a high-potency corticosteroid cream", "A seven-day course of oral ciprofloxacin and metronidazole", "Prescription of stool softeners, a high-fiber diet, and sitz baths"], "ans": 4, "exp": "anal fissure (แผลฉีกแนวยาว posterior midline เจ็บตอนถ่าย) -> รักษาเบื้องต้นด้วยยาทำให้อุจจาระนุ่ม + อาหารกากใย + sitz bath", "sys": "XI"}, {"topic": "Obstetrics & Gynecology", "q": "A 32-year-old G1P0 at 37 weeks with severe unrelenting headache and blurred vision for 4 hours. BP 185/115, 3+ proteinuria, reassuring FHR. IV magnesium sulfate started. Most appropriate next step?", "choices": ["Administer intravenous labetalol and prepare for delivery", "Expectant management until 39 weeks of gestation", "Administer oral methyldopa and discharge home", "Perform an immediate cesarean delivery without blood pressure stabilization", "Administer intramuscular betamethasone"], "ans": 0, "exp": "severe preeclampsia ที่ 37 สัปดาห์ + อาการรุนแรง -> ให้ยาลดความดัน (IV labetalol) + วางแผนคลอด (ที่ >=37 สัปดาห์ควรคลอด)", "sys": "XV"}, {"topic": "Obstetrics & Gynecology", "q": "A 26-year-old primigravida at 10 weeks for her first prenatal visit. Which vaccine is a live attenuated virus and strictly contraindicated during pregnancy?", "choices": ["Inactivated influenza vaccine", "Measles, mumps, and rubella (MMR) vaccine", "Tetanus, diphtheria, and acellular pertussis (Tdap) vaccine", "Recombinant Hepatitis B vaccine", "COVID-19 mRNA vaccine"], "ans": 1, "exp": "MMR เป็นวัคซีนเชื้อเป็นอ่อนฤทธิ์ (live attenuated) -> ห้ามใช้ในหญิงตั้งครรภ์", "sys": "XV"}, {"topic": "Obstetrics & Gynecology", "q": "A 26-year-old, 4 weeks postpartum, with lactational mastitis on oral dicloxacillin, breastfeeding. Most appropriate recommendation regarding breastfeeding?", "choices": ["Discontinue breastfeeding completely and transition to infant formula", "Breastfeed from the unaffected breast and pump and discard milk from the affected breast", "Continue breastfeeding from both breasts, including the affected side", "Wait until the antibiotic course is completed before resuming breastfeeding", "Switch exclusively to pumping and bottle-feeding from both breasts indefinitely"], "ans": 2, "exp": "lactational mastitis -> ให้นมต่อได้ทั้งสองข้างรวมข้างที่อักเสบ (การระบายน้ำนมช่วยให้หายเร็ว และปลอดภัยต่อทารก)", "sys": "XV"}, {"topic": "Obstetrics & Gynecology", "q": "An 18-year-old primigravida at 8 weeks (by LMP), mild breast tenderness, no bleeding/pain. TVUS shows an intrauterine gestational sac (mean sac diameter 15 mm) but no fetal pole or yolk sac. Most appropriate next step?", "choices": ["Prescribe oral misoprostol to induce medical management of early pregnancy loss", "Schedule an immediate surgical dilation and curettage (D&C)", "Administer intramuscular methotrexate for suspected ectopic pregnancy", "Reassure the patient and schedule a repeat ultrasound in 7 to 14 days", "Order an immediate pelvic MRI to confirm the ultrasound findings"], "ans": 3, "exp": "MSD 15 มม. ยังไม่เห็น yolk sac/fetal pole = ยังไม่วินิจฉัยแท้ง (เกณฑ์ต้อง MSD >=25 มม.ไม่มี embryo) -> นัด ultrasound ซ้ำใน 7-14 วัน", "sys": "XV"}, {"topic": "Obstetrics & Gynecology", "q": "A 45-year-old multiparous woman with postcoital spotting for 3 months. A 1.5 cm smooth, reddish-purple, teardrop-shaped fleshy lesion protruding from the external cervical os, bleeding on contact. Urine pregnancy test negative. Most appropriate next step?", "choices": ["Cervical punch biopsy", "Routine Pap smear", "Transvaginal ultrasound", "Prescribe oral contraceptive pills for bleeding control", "Outpatient polypectomy"], "ans": 4, "exp": "cervical polyp (ก้อนสีแดงม่วงรูปหยดน้ำยื่นจากปากมดลูก เลือดออกเมื่อสัมผัส) -> ทำ outpatient polypectomy และส่งชิ้นเนื้อตรวจ", "sys": "XV"}, {"topic": "Obstetrics & Gynecology", "q": "A 45-year-old asymptomatic woman with a screening mammogram showing a 1 cm well-circumscribed oval mass with benign-appearing macrocalcifications, BIRADS Category 3 (probably benign). Most appropriate next step?", "choices": ["Repeat targeted imaging/mammogram in 6 months", "Return to routine screening in 1 year", "Immediate ultrasound-guided core needle biopsy", "Excisional lumpectomy", "Prophylactic bilateral mastectomy"], "ans": 0, "exp": "BIRADS 3 (probably benign) -> ติดตามภาพซ้ำระยะสั้น (repeat mammogram ใน 6 เดือน)", "sys": "II"}, {"topic": "Obstetrics & Gynecology", "q": "A 28-year-old G1P0 at 40 weeks in active labor on oxytocin. EFM: baseline 140, moderate variability, recurrent gradual decreases in FHR consistently beginning after the peak of contraction and not returning to baseline until after the contraction ends. Most likely underlying pathophysiology?", "choices": ["Fetal head compression", "Uteroplacental insufficiency", "Umbilical cord compression", "Normal fetal sleep cycle", "Maternal fever/infection"], "ans": 1, "exp": "late deceleration (nadir ตามหลัง peak ของ contraction ค่อย ๆ ลง) = uteroplacental insufficiency", "sys": "XV"}, {"topic": "Obstetrics & Gynecology", "q": "A 30-year-old with a painful swollen mass on the right labia majora for 4 days, recurrent (simple I&D 6 months ago). A 5 cm tender, fluctuant, erythematous mass at the 4 o'clock position of the introitus. Given recurrence, most appropriate surgical management?", "choices": ["Needle aspiration of the cyst", "Prescription of oral antibiotics alone", "Marsupialization of the cyst", "Repeat simple incision and drainage (I&D)", "Total excision of the Bartholin gland"], "ans": 2, "exp": "Bartholin abscess ที่กลับเป็นซ้ำ -> marsupialization (สร้างช่องเปิดถาวรป้องกันการกลับเป็นซ้ำ); การตัดต่อมทั้งหมดสงวนไว้กรณีเป็นซ้ำหลายครั้ง/ล้มเหลว", "sys": "II"}, {"topic": "Obstetrics & Gynecology", "q": "A 70-year-old multiparous woman with pelvic pressure and a vaginal 'bulge' after standing. The cervix descends to the hymenal ring on Valsalva (Stage 2 uterine prolapse). Severe cardiovascular comorbidities (high surgical risk), declines surgery. Most appropriate conservative management?", "choices": ["Recommend immediate vaginal hysterectomy despite the surgical risks", "Prescribe high-dose systemic oral estrogen therapy", "Advise absolute, continuous bed rest", "Fit the patient with a vaginal ring pessary", "Perform an anterior colporrhaphy"], "ans": 3, "exp": "uterine prolapse ในผู้ป่วยเสี่ยงผ่าตัดสูง/ปฏิเสธผ่าตัด -> ใส่ vaginal ring pessary (การรักษาแบบอนุรักษ์)", "sys": "IX"}, {"topic": "Obstetrics & Gynecology", "q": "A 14-year-old with cyclical severe lower abdominal pain monthly for 4 months, never menstruated, Tanner IV. Pelvic exam shows a bulging, bluish, translucent membrane at the introitus. Most appropriate definitive management?", "choices": ["Prescription of combined oral contraceptive pills to suppress menstruation", "Simple needle aspiration to drain the trapped menstrual blood", "Total abdominal hysterectomy and bilateral salpingo-oophorectomy", "Dilation and curettage of the uterus", "Cruciate incision of the hymen"], "ans": 4, "exp": "imperforate hymen + hematocolpos -> รักษาถาวรด้วยการผ่าเปิดเยื่อพรหมจารีแบบกากบาท (cruciate incision/hymenotomy)", "sys": "XI"}, {"topic": "Emergency medicine", "q": "A 68-year-old with atrial fibrillation and DVT (on a daily 'blood thinner') after a high-speed MVC, hypotensive, tachycardic, FAST shows massive intra-abdominal hemorrhage. INR 5.2, preparing for emergency laparotomy. Besides IV vitamin K, which blood product to give immediately to rapidly reverse coagulopathy?", "choices": ["Fresh frozen plasma", "Packed red blood cells", "Cryoprecipitate", "Platelet concentrate", "Intravenous immunoglobulin"], "ans": 0, "exp": "warfarin coagulopathy (INR 5.2) ที่มีเลือดออกรุนแรง -> reverse เร็วด้วย fresh frozen plasma (หรือ PCC) ร่วมกับ vitamin K", "sys": "emergency"}, {"topic": "Emergency medicine", "q": "A 22-year-old with a stab wound to the right chest, acute respiratory distress, tachypneic, hypoxic. A 3 cm laceration on the right anterior chest wall with a sucking, bubbling sound on inspiration and frothy blood at the margins. Most appropriate immediate intervention?", "choices": ["Perform an immediate emergency thoracotomy", "Apply a sterile dressing securely taped on exactly three sides", "Perform a needle thoracostomy in the 2nd intercostal space", "Apply a completely occlusive dressing taped securely on all four sides", "Intubate the patient and start positive pressure ventilation immediately"], "ans": 1, "exp": "open pneumothorax (sucking chest wound) -> ปิดแผลด้วย three-sided dressing (ให้ลมออกได้แต่ไม่เข้า ป้องกัน tension) แล้วจึงใส่ ICD", "sys": "emergency"}, {"topic": "Emergency medicine", "q": "A 75-year-old with severe palpitations, chest pain, feeling faint, lethargic, cool and clammy. BP 80/50, HR 170. Monitor shows narrow-complex tachycardia, grossly irregular rhythm, absent P waves (unstable AF with RVR). Most appropriate immediate next step?", "choices": ["Administer a bolus of intravenous amiodarone", "Perform carotid sinus massage", "Perform immediate synchronized electrical cardioversion", "Administer intravenous adenosine rapidly", "Perform immediate unsynchronized defibrillation"], "ans": 2, "exp": "AF with RVR ที่ไม่คงที่ (ความดันตก ซึม) -> synchronized cardioversion ทันที", "sys": "emergency"}, {"topic": "Emergency medicine", "q": "A 58-year-old with HT and smoking, crushing substernal chest pain for 90 minutes. ECG: 3 mm ST elevations in V1-V4 (anterior STEMI). Nearest PCI facility is over 3 hours away due to weather. Most appropriate immediate pharmacological intervention?", "choices": ["Administer sublingual nitroglycerin and observe", "Administer intravenous labetalol", "Administer high-dose oral ibuprofen", "Administer a fibrinolytic/thrombolytic drug (e.g., Tenecteplase)", "Wait for the weather to clear and transfer for PCI"], "ans": 3, "exp": "anterior STEMI + ทำ primary PCI ไม่ทันในเวลา (>120 นาที) -> ให้ fibrinolytic (tenecteplase) ทันที", "sys": "emergency"}, {"topic": "Emergency medicine", "q": "A 28-year-old after a high-speed motorcycle collision with moderate diffuse abdominal pain. Stable vitals (BP 125/80, HR 88). FAST negative for free fluid, but exam shows abdominal tenderness with mild guarding. Most appropriate next step to evaluate the abdomen?", "choices": ["Diagnostic peritoneal lavage", "Immediate exploratory laparotomy", "Discharge the patient with pain medications", "Serial abdominal x-rays", "Computed tomography scan of the abdomen and pelvis with IV contrast"], "ans": 4, "exp": "ผู้ป่วยบาดเจ็บที่ stable + FAST ลบแต่ยังมี tenderness/guarding -> ทำ CT abdomen/pelvis with contrast ประเมินการบาดเจ็บอวัยวะภายใน", "sys": "emergency"}, {"topic": "Emergency medicine", "q": "A 22-year-old tourist swimming in the Andaman Sea felt a sudden excruciating burning wrapped around her legs. Severe pain but hemodynamically stable; lower extremity findings shown (jellyfish sting). To prevent further envenomation, most appropriate immediate first-aid?", "choices": ["Continuously flush the lesions with 4-6% acetic acid for at least 30 seconds", "Vigorously rub the area with a towel to remove tentacle remnants", "Rinse the affected limb copiously with bottled fresh drinking water", "Immerse the leg in ice-cold water to reduce swelling and pain", "Urinate on the affected area to neutralize the marine toxins"], "ans": 0, "exp": "jellyfish/box jellyfish sting -> ราดด้วยน้ำส้มสายชู (acetic acid 4-6%) เพื่อยับยั้ง nematocyst ไม่ให้ปล่อยพิษเพิ่ม (ห้ามล้างน้ำจืด/ถู). *อ้างอิงภาพ*", "img": "https://cdn.jsdelivr.net/gh/MercenzK/Web-quiz-images@main/NL2-2026-Jan-Q66.png", "sys": "emergency"}, {"topic": "Community/EBM", "q": "A public health physician finds a high prevalence of childhood obesity (BMI >95th percentile) among elementary school children. As a primary community-based intervention at schools, most appropriate recommendation?", "choices": ["Prescribe anti-obesity medications for all children above the 90th percentile", "Implement a mandatory, structured daily physical exercise program", "Refer all obese children for bariatric surgery evaluation", "Restrict the daily caloric intake of all students to 1,000 kcal/day", "Isolate obese children into specialized, intensive physical education classes"], "ans": 1, "exp": "มาตรการ primary prevention ระดับชุมชนที่เหมาะสม = จัดโปรแกรมออกกำลังกายประจำวันสำหรับนักเรียนทุกคน (ครอบคลุมทั้งประชากร)", "sys": "general"}, {"topic": "Community/EBM", "q": "A 55-year-old man for a routine annual visit, asymptomatic, no risk factors, unremarkable family history, asks about PSA testing for prostate cancer. Most appropriate recommendation regarding PSA screening?", "choices": ["Recommend routine screening with a PSA test and digital rectal exam today", "Advise against PSA screening as it is not recommended for any age group", "Discuss the potential benefits and harms of PSA screening to make a shared decision", "Order a PSA test only if he develops lower urinary tract symptoms", "Perform a prostate biopsy as a baseline"], "ans": 2, "exp": "PSA screening -> ใช้การตัดสินใจร่วม (shared decision-making) อธิบายข้อดี-ข้อเสียให้ผู้ป่วยเลือก (ไม่แนะนำคัดกรองเป็น routine ทุกคน)", "sys": "general"}, {"topic": "Community/EBM", "q": "A 30-year-old man with a deep, actively bleeding, heavily contaminated puncture wound on his calf from a stray dog bite 30 minutes ago. Childhood vaccinations complete; last tetanus booster exactly 8 years ago. Rabies PEP started. Most appropriate tetanus prophylaxis today?", "choices": ["Administer a 3-dose primary course of Td toxoid plus Tetanus Immune Globulin", "Administer Tetanus Immune Globulin only", "Do not administer any tetanus prophylaxis as he is still immune", "Administer a single dose of Tetanus-diphtheria toxoid only", "Administer oral antibiotics and re-evaluate tetanus status in 48 hours"], "ans": 3, "exp": "แผลสกปรก + เคยฉีดครบชุดแต่เข็มสุดท้าย >5 ปี -> ให้ Td booster เข็มเดียว (ไม่ต้องให้ TIG เพราะเคยได้ภูมิครบแล้ว)", "sys": "general"}, {"topic": "Community/EBM", "q": "A 45-year-old woman with chest tightness, wheezing, and dyspnea, working in a cotton textile plant with heavy raw cotton dust exposure for 15 years. Symptoms are worst on Mondays (first day back) and improve as the week progresses. Most likely occupational lung disease?", "choices": ["Asbestosis", "Silicosis", "Allergic rhinitis", "Hypersensitivity pneumonitis", "Byssinosis"], "ans": 4, "exp": "อาการทางเดินหายใจแย่ที่สุดวันจันทร์ (วันแรกกลับมาทำงาน) จากฝุ่นฝ้าย = byssinosis ('Monday fever')", "sys": "general"}, {"topic": "Otolaryngology", "q": "A 55-year-old woman with sudden severe spinning episodes when rolling over in bed or tilting her head back, lasting 20-30 seconds with severe nausea. No hearing loss/tinnitus/focal deficits. Dix-Hallpike elicits brief latency then upbeat torsional nystagmus. Most likely diagnosis?", "choices": ["Benign paroxysmal positional vertigo (BPPV)", "Meniere's disease", "Vestibular neuritis", "Labyrinthitis", "Vestibular schwannoma"], "ans": 0, "exp": "เวียนศีรษะสั้น ๆ (20-30 วินาที) สัมพันธ์กับการเปลี่ยนท่าศีรษะ + Dix-Hallpike บวก (latency + upbeat torsional nystagmus) = BPPV", "sys": "VIII"}, {"topic": "Otolaryngology", "q": "A 42-year-old woman with intense itching, fullness, and mild hearing loss in the left ear for 2 weeks, after a tropical beach vacation and using leftover antibiotic ear drops (symptoms worsened). Otoscopy shown. Most appropriate next step?", "choices": ["Admit the patient for intravenous vancomycin and ceftriaxone", "Perform thorough aural microsuction and prescribe topical clotrimazole drops", "Switch the patient to topical ciprofloxacin-dexamethasone drops", "Schedule the patient for immediate tympanostomy tube placement", "Prescribe oral fluconazole alone and advise the patient to keep the ear dry"], "ans": 1, "exp": "otomycosis (เชื้อราในช่องหู, คันมาก + แย่ลงหลังใช้ยาปฏิชีวนะหยอด) -> ทำความสะอาดช่องหู (aural microsuction) + ยาหยอดฆ่าเชื้อรา (clotrimazole). *อ้างอิงภาพ*", "img": "https://cdn.jsdelivr.net/gh/MercenzK/Web-quiz-images@main/NL2-2026-Jan-Q72.png", "sys": "VIII"}, {"topic": "Orthopedics", "q": "A 72-year-old man with 6 months of bilateral low back pain radiating to buttocks and thighs, with leg pain/cramping after walking a few blocks, relieved immediately by leaning forward over a shopping cart (neurogenic claudication). Which activity most likely exacerbates his symptoms?", "choices": ["Stationary cycling", "Uphill walking", "Downhill walking", "Water aerobics", "Seated rowing"], "ans": 2, "exp": "lumbar spinal stenosis อาการแย่เมื่อหลังแอ่น (extension) และดีขึ้นเมื่อก้ม (flexion) -> เดินลงเนิน (downhill walking = extension) ทำให้แย่ลง; เดินขึ้นเนิน/ปั่นจักรยาน (flexion) ดีขึ้น", "sys": "XIII"}, {"topic": "Orthopedics", "q": "A 48-year-old man with persistent pain on the inner aspect of the left elbow, worse when playing golf or carrying heavy bags. Point tenderness over the medial epicondyle, pain exacerbated by resisted wrist flexion and forearm pronation. Most likely diagnosis?", "choices": ["Lateral epicondylitis", "Olecranon bursitis", "Cubital tunnel syndrome", "Medial epicondylitis", "Biceps tendon rupture"], "ans": 3, "exp": "ปวด medial epicondyle + แย่ลงเมื่อ wrist flexion/pronation ต้านแรง = medial epicondylitis (golfer's elbow)", "sys": "XIII"}, {"topic": "Orthopedics", "q": "A 42-year-old data entry clerk with aching pain, numbness, and tingling in the right hand/wrist, worst at night waking her, affecting the thumb, index, and middle fingers, relieved by shaking. Tapping the volar wrist produces electric shocks into the fingers, with weak thumb abduction. Which nerve is compressed?", "choices": ["Ulnar nerve", "Radial nerve", "Musculocutaneous nerve", "Axillary nerve", "Median nerve"], "ans": 4, "exp": "carpal tunnel syndrome (ชานิ้วโป้ง-ชี้-กลาง เด่นกลางคืน + Tinel บวก + อ่อนแรง thumb abduction) = การกดทับ median nerve", "sys": "XIII"}, {"topic": "Orthopedics", "q": "A 32-year-old construction worker with a closed mid-shaft tibial fracture treated with a circumferential cast this morning, returns 8 hours later with excruciating 'bursting' leg pain not relieved by oxycodone. Toes slightly pale, screams on passive dorsiflexion of the toes. Dorsalis pedis pulses palpable. Most likely diagnosis?", "choices": ["Acute compartment syndrome", "Deep vein thrombosis (DVT)", "Acute osteomyelitis", "Normal post-fracture pain", "Complex regional pain syndrome"], "ans": 0, "exp": "ปวดรุนแรงเกินกว่าที่ควร (out of proportion) + ปวดมากเมื่อ passive stretch + เฝือกแน่น (ชีพจรยังคลำได้) = acute compartment syndrome", "sys": "XIII"}, {"topic": "Orthopedics", "q": "A 55-year-old man with severe intractable lower back pain radiating down both legs, over 12 hours developing saddle anesthesia and inability to urinate despite a full bladder, with decreased anal sphincter tone. MRI shows a massive L4-L5 central disc herniation compressing nerve roots. Most appropriate definitive management?", "choices": ["Lumbar epidural corticosteroid injection", "Urgent surgical decompression (e.g., laminectomy/discectomy)", "Strict bed rest and high-dose oral NSAIDs", "Aggressive physical therapy and traction", "Oral pregabalin and outpatient follow-up in 2 weeks"], "ans": 1, "exp": "cauda equina syndrome (saddle anesthesia + urinary retention + หูรูดหลวม + central disc herniation) = ภาวะฉุกเฉิน -> ผ่าตัดคลายกดประสาทด่วน (decompression)", "sys": "XIII"}, {"topic": "Ophthalmology", "q": "A 50-year-old construction worker with a small, slightly yellowish bump on the white part of the right eye, no pain/vision changes/discharge/photophobia, mild dryness after outdoor work. Finding shown, no corneal involvement. Most appropriate next step?", "choices": ["Immediate surgical excision of the lesion", "Prescription of prophylactic topical antibiotic drops", "Reassurance, use of artificial tears, and wearing UV-blocking sunglasses", "Initiation of high-dose topical corticosteroid drops", "Urgent referral to an ocular oncologist for biopsy"], "ans": 2, "exp": "pinguecula (ตุ่มเหลืองบนตาขาว ไม่ลามถึงกระจกตา) -> รักษาแบบอนุรักษ์: reassurance + น้ำตาเทียม + แว่นกันแดด UV. *อ้างอิงภาพ*", "img": "https://cdn.jsdelivr.net/gh/MercenzK/Web-quiz-images@main/NL2-2026-Jan-Q78.png", "sys": "VII"}, {"topic": "Forensic medicine", "q": "A 45-year-old man found dead floating in a pond. To determine antemortem drowning, which autopsy finding provides the strongest evidence he was alive and actively breathing while submerged?", "choices": ["A large volume of water present in the stomach and duodenum", "Pale and wrinkled skin on the palms and soles (washerwoman's hands)", "Deep rigor mortis in the bilateral upper and lower extremities", "Pink frothy fluid in the airways and mud/diatoms deep in the bronchioles", "Postmortem lividity that is fixed on the anterior aspect of the body"], "ans": 3, "exp": "หลักฐาน antemortem drowning ที่ชัดสุด = ฟอง (frothy fluid) ในทางเดินหายใจ + โคลน/diatom ลึกในหลอดลมฝอย (แสดงว่ายังหายใจสูดน้ำเข้าไป). washerwoman's hands/lividity เกิดหลังตายก็ได้", "sys": "general"}, {"topic": "Forensic medicine", "q": "A police officer's stray bullet accidentally kills an innocent bystander during a raid (death resulting from an official on duty). Per the Thai Criminal Procedure Code, an on-site medicolegal death investigation is required. Which officials must be present?", "choices": ["The local physician and the investigating police officer only", "The investigating police officer and the forensic science team", "The local physician, the investigating police officer, and the victim's family", "A central forensic pathologist, the investigating police officer, and the national police chief", "The local physician, investigating police officer, public prosecutor, and local administrative official"], "ans": 4, "exp": "การตายจากการกระทำของเจ้าพนักงานขณะปฏิบัติหน้าที่ -> ต้องมี 4 ฝ่ายร่วมชันสูตร: แพทย์ + พนักงานสอบสวน + พนักงานอัยการ + ฝ่ายปกครอง (นายอำเภอ/ปลัดอำเภอ)", "sys": "general"}, {"topic": "Forensic medicine", "q": "A 30-year-old with an open comminuted femur fracture from a motorcycle accident, underwent multiple surgeries, then developed a deep wound infection progressing to SIRS, and died of multisystem organ failure from overwhelming infection 3 weeks later. What is the immediate cause of death on the certificate?", "choices": ["Septicemia", "Motorcycle accident", "Open fracture of the right femur", "Cardiopulmonary arrest", "Deep vein thrombosis"], "ans": 0, "exp": "immediate cause of death = ภาวะสุดท้ายที่นำสู่การตายโดยตรง = septicemia (นำสู่ MOF); motorcycle accident เป็น underlying cause. ('cardiopulmonary arrest' เป็น mode of death ไม่ควรลง)", "sys": "general"}, {"topic": "Forensic medicine", "q": "A 25-year-old assaulted, with a deep facial laceration causing permanent disfigurement and a deep RUQ stab wound causing a severe liver laceration with massive hemorrhage (fatal without immediate surgery). How should the injury severity be classified under Thai criminal law?", "choices": ["Minor injury requiring less than 7 days of recovery", "Grievous bodily harm (severe injury) as it involves permanent facial disfigurement and a life-threatening condition if untreated", "Standard physical injury requiring exactly 14 days of recovery", "A non-fatal injury with a standard 30-day recovery period", "Psychological trauma with minor physical components"], "ans": 1, "exp": "แผลที่ทำให้เสียโฉมถาวรที่ใบหน้า + บาดเจ็บที่เป็นอันตรายถึงชีวิตถ้าไม่รักษา = อันตรายสาหัส (grievous bodily harm) ตามกฎหมายอาญา", "sys": "general"}, {"topic": "Community/EBM", "q": "Epidemiologists studying a rare autoimmune disease identify 50 already-diagnosed patients and 100 healthy age/sex-matched individuals, then review past exposure to an artificial sweetener in both groups. Which study design?", "choices": ["Case series", "Prospective cohort study", "Case-control study", "Cross-sectional study", "Randomized controlled trial"], "ans": 2, "exp": "เริ่มจากผู้ที่เป็นโรค (case) + กลุ่มควบคุม (control) แล้วย้อนดูการสัมผัสในอดีต = case-control study (เหมาะกับโรคที่พบยาก)", "sys": "general"}, {"topic": "Community/EBM", "q": "An observational study comparing myocardial infarction between daily low-dose aspirin users and non-users found fewer heart attacks in the aspirin group, but that group also exercised more and smoked less. The effect of the smoking discrepancy is an example of?", "choices": ["Recall bias", "Selection bias", "Measurement bias", "Confounding bias", "Hawthorne effect"], "ans": 3, "exp": "การสูบบุหรี่ (ปัจจัยที่สัมพันธ์กับทั้งการใช้ยาและการเกิด MI) บิดเบือนผลลัพธ์ = confounding bias", "sys": "general"}, {"topic": "Medical ethics", "q": "A 9-year-old unconscious (GCS 6) after a pedestrian-MVA, CT shows a massive acute epidural hematoma with midline shift, requiring emergency craniotomy to prevent herniation/death. Parents unreachable. Most appropriate next step regarding consent?", "choices": ["Wait until the parents can be successfully contacted to obtain informed consent", "Obtain a fingerprint from the child as a form of assented consent", "Consult the hospital ethics committee for approval before proceeding", "Request consent from a distant relative via a telephone call", "Proceed with the emergency craniotomy immediately without waiting for consent"], "ans": 4, "exp": "ภาวะฉุกเฉินคุกคามชีวิตในผู้เยาว์ที่ผู้ปกครองติดต่อไม่ได้ -> ดำเนินการผ่าตัดช่วยชีวิตทันทีภายใต้ implied/emergency consent", "sys": "general"}, {"topic": "Medical ethics", "q": "A 78-year-old with terminal HCC found pulseless and apneic. As paramedics prepare CPR, the family presents a legally binding advance directive (living will) stating he does not want CPR or intubation. How should the team proceed?", "choices": ["Withhold CPR in accordance with the patient's advance directive", "Initiate CPR immediately, as this is an acute emergency", "Contact the hospital director for approval before withholding care", "Administer intravenous epinephrine but withhold chest compressions", "Ask the family to make a new decision on the spot, ignoring the document"], "ans": 0, "exp": "ผู้ป่วยมี advance directive (living will) ที่ทำขณะมีสติสมบูรณ์ ระบุไม่ต้องการ CPR -> เคารพเจตนา งดการกู้ชีพ (withhold CPR)", "sys": "general"}, {"topic": "Medical ethics", "q": "A 35-year-old conscious, alert man after an MVC receiving wound care for minor lacerations. A police officer requests you draw blood to test blood alcohol concentration. Under what circumstances is the blood draw legally permissible?", "choices": ["You can draw the blood immediately upon the police officer's verbal request", "You can draw the blood only if the patient provides informed consent and the police present an official written request", "You must draw the blood regardless of patient consent because it is a legal mandate", "You can draw the blood secretly while taking routine lab samples to avoid conflict", "You should refuse the police entirely, as doctors cannot assist in criminal investigations"], "ans": 1, "exp": "ผู้ป่วยรู้สึกตัวดี -> เจาะเลือดตรวจแอลกอฮอล์ได้ต่อเมื่อผู้ป่วยยินยอม (informed consent) และมีหนังสือร้องขออย่างเป็นทางการจากตำรวจ", "sys": "general"}]}, {"id": "ped-1", "title": "กุมารเวชศาสตร์ ชุดที่ 1 — Neonatology & Newborn", "subject": "ped", "questions": [{"topic": "Neonatal Resuscitation", "q": "A term newborn is delivered by vaginal delivery with clear amniotic fluid. At initial assessment the baby has poor tone, is apneic, and has not responded to warming, drying, and stimulation. The heart rate is 80/min. What is the most appropriate next step?", "choices": ["Begin positive-pressure ventilation with blended oxygen", "Start chest compressions with coordinated ventilation now", "Give intravenous epinephrine through an umbilical catheter", "Administer intratracheal surfactant via endotracheal tube", "Provide free-flow oxygen by mask without assisted breaths"], "ans": 0, "exp": "ทารกไม่หายใจ (apnea) และ HR < 100/min หลัง initial steps → ขั้นตอนถัดไปตาม NRP คือ positive-pressure ventilation (PPV) ทันที เพราะ ventilation คือหัวใจสำคัญที่สุดของการกู้ชีพทารกแรกเกิด. Chest compression เริ่มเมื่อ HR < 60/min หลัง PPV ที่ effective แล้ว 30 วินาที. Epinephrine ใช้เมื่อ HR ยัง < 60 หลัง compression+PPV. Free-flow O2 ใช้กรณีหายใจเองแต่เขียว ไม่พอสำหรับ apnea"}, {"topic": "Neonatal Resuscitation", "q": "During resuscitation of a term newborn, effective positive-pressure ventilation has been provided for 30 seconds. The heart rate is now 50/min. What is the most appropriate next step?", "choices": ["Increase the oxygen concentration to 100% and continue PPV alone", "Start chest compressions coordinated with ventilation at 3:1 ratio", "Give a normal saline bolus 10 mL/kg", "Administer intravenous epinephrine", "Intubate and give surfactant"], "ans": 1, "exp": "หลัง PPV ที่ได้ผล 30 วินาทีแล้ว HR ยัง < 60/min → เริ่ม chest compression ประสานกับ ventilation อัตราส่วน 3:1 (90 compressions + 30 breaths ต่อนาที) พร้อมเพิ่ม O2 เป็น 100%. Epinephrine เป็นขั้นถัดไปถ้า HR ยัง < 60 หลัง compression ร่วม PPV อีก 60 วินาที"}, {"topic": "Neonatal Resuscitation", "q": "A newborn is delivered through meconium-stained amniotic fluid. Immediately after birth the baby is apneic and floppy with poor respiratory effort. According to current guidelines, what is the most appropriate initial management?", "choices": ["Perform routine endotracheal intubation and suction before any ventilation", "Suction the stomach to prevent aspiration before stimulation", "Warm, position, and begin PPV without routine endotracheal suctioning", "Give chest compressions immediately", "Delay resuscitation until the baby cries"], "ans": 2, "exp": "แนวทางปัจจุบัน (NRP) ไม่แนะนำ routine endotracheal suctioning ในทารก non-vigorous ที่มี meconium แล้ว เพราะไม่ลด meconium aspiration syndrome และทำให้เสียเวลา ventilation. ให้ warm/position/clear airway ถ้าจำเป็นแล้วเริ่ม PPV เลย เพราะ ventilation สำคัญที่สุด"}, {"topic": "APGAR Score", "q": "A newborn at 1 minute of life has a heart rate of 130/min, cries vigorously, actively moves all limbs, grimaces and coughs on suctioning, but has bluish hands and feet with a pink body. What is the APGAR score?", "choices": ["10", "8", "7", "9", "6"], "ans": 3, "exp": "APGAR: HR >100 = 2, respiratory effort (crying) = 2, tone (active) = 2, reflex/grimace (cough) = 2, color = 1 (acrocyanosis = body pink, extremities blue). รวม = 9. Acrocyanosis เป็นเรื่องปกติในนาทีแรกจึงได้ color เพียง 1 คะแนน"}, {"topic": "Prematurity - RDS", "q": "A preterm infant born at 29 weeks develops tachypnea, nasal flaring, grunting, and subcostal retractions within the first hours of life. Chest radiograph shows diffuse ground-glass (reticulogranular) opacities with air bronchograms and low lung volumes. What is the most appropriate specific treatment?", "choices": ["Broad-spectrum antibiotics only", "Inhaled nitric oxide", "Systemic corticosteroids", "Emergency exchange transfusion", "Intratracheal surfactant replacement"], "ans": 4, "exp": "ภาพ ground-glass + air bronchograms + volume ต่ำ ในทารก preterm = Respiratory Distress Syndrome (RDS) จาก surfactant deficiency. การรักษาจำเพาะคือ exogenous surfactant ร่วมกับ respiratory support (CPAP/ventilation). Antenatal corticosteroids ให้แม่ก่อนคลอดเพื่อป้องกัน ไม่ใช่ systemic steroid ในทารก"}, {"topic": "Prematurity - RDS", "q": "A woman is in preterm labor at 30 weeks of gestation. Delivery is expected within 48 hours. Which intervention given to the mother most effectively reduces the risk of neonatal respiratory distress syndrome in the infant?", "choices": ["Antenatal betamethasone", "Maternal broad-spectrum antibiotics", "Maternal magnesium sulfate", "Maternal high-dose vitamin C", "Maternal oxygen supplementation"], "ans": 0, "exp": "Antenatal corticosteroid (betamethasone/dexamethasone) ให้แม่ที่เสี่ยงคลอดก่อน 34 สัปดาห์ ช่วยเร่ง fetal lung maturity ลด RDS, IVH และ mortality. MgSO4 ให้เพื่อ neuroprotection (ลด cerebral palsy) ไม่ได้ลด RDS โดยตรง"}, {"topic": "Neonatal Jaundice", "q": "A term breastfed newborn is noted to be jaundiced on day 3 of life. The baby is feeding well, active, and afebrile. Total serum bilirubin is 12 mg/dL, almost entirely unconjugated. There is no hepatosplenomegaly and the blood groups are compatible. What is the most likely cause?", "choices": ["Biliary atresia", "Physiologic jaundice", "Neonatal sepsis", "Rh hemolytic disease", "Crigler-Najjar syndrome type I"], "ans": 1, "exp": "Jaundice ที่เริ่มวันที่ 2-3, bilirubin ไม่สูงมาก, unconjugated, ทารก well และไม่มี hemolysis = physiologic jaundice จาก immature UGT enzyme + RBC turnover สูง. Biliary atresia จะเป็น conjugated hyperbilirubinemia. Jaundice ที่เกิดใน 24 ชั่วโมงแรกถือว่า pathologic เสมอ"}, {"topic": "Neonatal Jaundice", "q": "A newborn develops visible jaundice within the first 18 hours of life. Total serum bilirubin is rising rapidly. The mother is blood group O Rh-positive and the infant is group A Rh-positive. The direct Coombs test is positive. What is the most likely diagnosis?", "choices": ["Physiologic jaundice of the healthy term newborn", "Breast milk jaundice appearing in the second week", "ABO hemolytic disease from maternal anti-A antibodies", "Rh isoimmunization in a sensitized Rh-negative mother", "Gilbert syndrome with mildly reduced conjugation"], "ans": 2, "exp": "Jaundice ภายใน 24 ชม.แรก + แม่ O, ลูก A + direct Coombs positive = ABO incompatibility (anti-A/anti-B IgG จากแม่ผ่านรก). Rh isoimmunization เกิดเมื่อแม่ Rh-negative ลูก Rh-positive (ที่นี่แม่ Rh-positive จึงตัดออก). Jaundice ก่อน 24 ชม.เป็น pathologic เสมอ"}, {"topic": "Neonatal Jaundice", "q": "A 5-day-old exclusively breastfed term infant is brought in with deepening jaundice. Total serum bilirubin is 20 mg/dL (unconjugated). The infant is alert, feeding, and has normal stool color. Phototherapy is started. Which additional statement about breast milk jaundice is correct?", "choices": ["It always requires cessation of breastfeeding permanently", "It presents with conjugated hyperbilirubinemia", "It is caused by inadequate milk intake in the first days", "It typically peaks in the second week and can persist for several weeks", "It is associated with pale stools and dark urine"], "ans": 3, "exp": "Breast milk jaundice: unconjugated bilirubin สูงต่อเนื่อง peak สัปดาห์ที่ 2 อาจอยู่ได้หลายสัปดาห์ จากสารใน breast milk ที่เพิ่ม enterohepatic circulation. ต่างจาก breastfeeding (failure) jaundice ที่เกิดเร็ว (วันที่ 2-4) จากได้นมไม่พอ. ไม่จำเป็นต้องหยุดนมแม่ถาวร. Conjugated + pale stool = biliary atresia ต้องแยก"}, {"topic": "Neonatal Jaundice", "q": "A term newborn on day 4 has a total serum bilirubin approaching the exchange transfusion threshold despite intensive phototherapy, and shows lethargy, poor feeding, and hypertonia with retrocollis. What is the most feared complication being prevented?", "choices": ["Necrotizing enterocolitis", "Retinopathy of prematurity", "Intraventricular hemorrhage", "Bronchopulmonary dysplasia", "Kernicterus (bilirubin encephalopathy)"], "ans": 4, "exp": "Unconjugated bilirubin ที่สูงมากผ่าน blood-brain barrier ไปสะสมที่ basal ganglia → acute bilirubin encephalopathy (lethargy, poor feeding, hypertonia, retrocollis/opisthotonus) และถ้าเรื้อรังคือ kernicterus (choreoathetoid CP, hearing loss, gaze palsy). Exchange transfusion ใช้เมื่อ phototherapy ไม่พอเพื่อป้องกันภาวะนี้"}, {"topic": "Neonatal Sepsis", "q": "A term infant born to a mother with prolonged rupture of membranes (>18 hours) and intrapartum fever develops temperature instability, poor feeding, lethargy, and tachypnea at 12 hours of age. What is the most appropriate initial management?", "choices": ["Blood cultures then empiric ampicillin plus gentamicin", "Oral amoxicillin with discharge and next-day follow-up", "Careful observation without antibiotics for 48 hours", "Intravenous acyclovir alone without antibacterial cover", "Double-volume exchange transfusion to clear the pathogen"], "ans": 0, "exp": "อาการ sepsis ในทารก + risk factors (PROM >18 ชม., maternal fever/chorioamnionitis) → early-onset sepsis (มัก GBS, E. coli). ต้องเก็บ blood culture (และพิจารณา LP) แล้วเริ่ม empiric ampicillin + gentamicin ทันที ห้ามรอ. Ampicillin ครอบคลุม GBS/Listeria, gentamicin ครอบคลุม gram-negative"}, {"topic": "Neonatal Sepsis - GBS", "q": "A pregnant woman screened positive for group B Streptococcus (GBS) colonization at 36 weeks. To prevent early-onset neonatal GBS disease, which intervention is most effective?", "choices": ["Oral antibiotics to the mother at the time of the positive screen", "Intrapartum intravenous penicillin to the mother", "Vaginal antiseptic wash at delivery only", "Antibiotics to the newborn after birth without maternal treatment", "Cesarean delivery for all colonized women"], "ans": 1, "exp": "การป้องกัน early-onset GBS disease ที่ได้ผลคือ intrapartum antibiotic prophylaxis (IAP) ด้วย IV penicillin/ampicillin ให้แม่ระหว่างเจ็บครรภ์คลอด (อย่างน้อย 4 ชม.ก่อนคลอด). การให้ยา oral ตอน screen positive ไม่ช่วยเพราะ recolonize ได้ และไม่ต้องผ่าตัดคลอดในทุกราย"}, {"topic": "TORCH Infection", "q": "A newborn presents with microcephaly, periventricular calcifications on cranial imaging, sensorineural hearing loss, and hepatosplenomegaly with petechiae. Which congenital infection is most likely?", "choices": ["Congenital rubella", "Congenital toxoplasmosis", "Cytomegalovirus", "Congenital syphilis", "Neonatal herpes simplex"], "ans": 2, "exp": "Congenital CMV: microcephaly + periventricular calcification + sensorineural hearing loss (สาเหตุ non-genetic ที่พบบ่อยที่สุดของ SNHL) + hepatosplenomegaly + petechiae ('blueberry muffin'). Toxoplasmosis จะเป็น diffuse intracranial calcification + chorioretinitis + hydrocephalus. Rubella เด่นที่ cataract + PDA + deafness"}, {"topic": "TORCH Infection", "q": "A newborn is found to have congenital cataracts, sensorineural deafness, and a patent ductus arteriosus. The mother had a febrile illness with rash in the first trimester. What is the most likely diagnosis?", "choices": ["Congenital cytomegalovirus", "Congenital toxoplasmosis", "Congenital varicella", "Congenital rubella syndrome", "Congenital Zika syndrome"], "ans": 3, "exp": "Triad ของ congenital rubella = cataracts (+/- glaucoma), sensorineural deafness, และ congenital heart disease (โดยเฉพาะ PDA และ peripheral pulmonary artery stenosis). ประวัติแม่มีไข้ออกผื่นใน trimester แรกสนับสนุน. การฉีดวัคซีน MMR ช่วยป้องกันได้"}, {"topic": "Infant of Diabetic Mother", "q": "A large-for-gestational-age term infant born to a mother with poorly controlled gestational diabetes becomes jittery and lethargic at 2 hours of age. Point-of-care glucose is 25 mg/dL. What is the most appropriate immediate management?", "choices": ["Reassurance; this glucose level is normal for a newborn", "Oral glucose gel only and recheck in 6 hours", "Start intravenous insulin", "Immediate exchange transfusion", "Intravenous dextrose bolus"], "ans": 4, "exp": "IDM มี fetal hyperinsulinism → neonatal hypoglycemia. ทารกมีอาการ (jittery, lethargic) + glucose 25 mg/dL = symptomatic hypoglycemia ต้องรีบให้ IV dextrose bolus (2 mL/kg ของ D10W) ตามด้วย continuous infusion. Symptomatic หรือ glucose ต่ำมากไม่รักษาด้วย oral gel อย่างเดียว. อย่าให้ insulin"}, {"topic": "Infant of Diabetic Mother", "q": "Besides hypoglycemia, which additional complication is most characteristically increased in an infant of a diabetic mother?", "choices": ["Hypocalcemia and polycythemia", "Congenital hypothyroidism", "Biliary atresia", "Duchenne muscular dystrophy", "Cystic fibrosis"], "ans": 0, "exp": "IDM สัมพันธ์กับ macrosomia, hypoglycemia, hypocalcemia/hypomagnesemia, polycythemia (จาก chronic fetal hypoxia กระตุ้น EPO) และ hyperbilirubinemia, RDS, และ congenital anomalies (เช่น caudal regression, VSD). Hypocalcemia + polycythemia จึงเป็นคู่ที่ถูกต้อง"}, {"topic": "Birth Injury", "q": "A newborn delivered after prolonged labor has a soft scalp swelling that crosses the suture lines and is present at birth, associated with overlying bruising. It resolves over a few days. What is this finding?", "choices": ["Cephalohematoma", "Caput succedaneum", "Subgaleal hemorrhage", "Encephalocele", "Cranial meningocele"], "ans": 1, "exp": "Caput succedaneum = edema ของ subcutaneous scalp ข้าม suture line ได้ มีตั้งแต่แรกเกิด หายเองใน 2-3 วัน. Cephalohematoma = subperiosteal bleed ไม่ข้าม suture line เกิดชัดหลังคลอดไม่กี่ชม. Subgaleal hemorrhage อันตราย เลือดออกใน potential space ใหญ่ ทำให้ shock ได้"}, {"topic": "Birth Injury", "q": "A macrosomic infant born with shoulder dystocia is noted to hold the right arm adducted and internally rotated with the forearm pronated and wrist flexed ('waiter's tip' posture), but the grasp reflex is intact. Which nerve roots are most likely injured?", "choices": ["C8-T1 (Klumpke palsy)", "Entire brachial plexus", "C5-C6 (Erb-Duchenne palsy)", "Radial nerve only", "Phrenic nerve"], "ans": 2, "exp": "'Waiter's tip' (arm adducted, internally rotated, forearm pronated, wrist flexed) โดยยัง grasp ได้ = Erb-Duchenne palsy จาก C5-C6 injury หลัง shoulder dystocia. Klumpke (C8-T1) จะเสีย intrinsic hand muscle → 'claw hand' และ grasp เสีย อาจมี Horner syndrome. ส่วนใหญ่หายเองด้วย physiotherapy"}, {"topic": "Hypoxic-Ischemic Encephalopathy", "q": "A term infant born after a sentinel event (placental abruption) has APGAR scores of 2 and 4, cord pH 6.9, and by 4 hours of age shows reduced consciousness, hypotonia, and seizures. What intervention started within 6 hours improves neurodevelopmental outcome?", "choices": ["High-dose corticosteroids", "Prophylactic phenobarbital for all", "Hyperoxic ventilation with 100% oxygen", "Therapeutic hypothermia", "Routine mannitol infusion"], "ans": 3, "exp": "Moderate-to-severe HIE ในทารก ≥36 สัปดาห์ → therapeutic hypothermia (cooling ถึง 33.5°C นาน 72 ชม.) เริ่มภายใน 6 ชม.แรก ลด death และ major disability. Hyperoxia กลับเพิ่ม oxidative injury ควรเลี่ยง. Cooling เป็น standard of care"}, {"topic": "Congenital Anomaly - TEF", "q": "A newborn has excessive drooling and chokes with the first feeding, developing coughing and cyanosis. A nasogastric tube cannot be passed into the stomach and coils in the upper chest on radiograph. What is the most likely diagnosis?", "choices": ["Congenital diaphragmatic hernia with bowel in the chest", "Bilateral choanal atresia causing nasal airway obstruction", "Duodenal atresia producing a double-bubble on radiograph", "Hypertrophic pyloric stenosis with projectile vomiting", "Esophageal atresia with a tracheoesophageal fistula"], "ans": 4, "exp": "Drooling + choking กับ feeding แรก + NG tube ผ่านไม่ได้และขดในทรวงอกส่วนบน = esophageal atresia (มักร่วมกับ distal TEF). อาจสัมพันธ์กับ VACTERL association. Duodenal atresia จะ NG ผ่านลงกระเพาะได้และมี 'double bubble'. รักษาโดยผ่าตัด"}, {"topic": "Congenital Anomaly - CDH", "q": "A term newborn develops severe respiratory distress and cyanosis immediately after birth. The abdomen appears scaphoid, breath sounds are decreased on the left with the cardiac apex shifted to the right, and bowel loops are seen in the left hemithorax on chest radiograph. What is the diagnosis?", "choices": ["Congenital diaphragmatic hernia", "Transient tachypnea of the newborn", "Meconium aspiration syndrome", "Pneumothorax from birth trauma", "Respiratory distress syndrome"], "ans": 0, "exp": "Scaphoid abdomen + respiratory distress + bowel loops ในทรวงอก + mediastinal shift = congenital diaphragmatic hernia (พบบ่อยด้าน left, Bochdalek). ต้อง intubate ทันที (ห้าม bag-mask ventilation เพราะลมเข้ากระเพาะ ดันปอดมากขึ้น), ใส่ NG decompression, แล้วผ่าตัดหลัง stabilize. ปัญหาหลักคือ pulmonary hypoplasia + PPHN"}, {"topic": "Newborn Screening", "q": "A newborn screening program in Thailand routinely tests for congenital hypothyroidism. Why is early detection and treatment before 2-3 weeks of age critical?", "choices": ["To prevent immediate life-threatening cardiac arrhythmia", "To prevent irreversible intellectual disability", "To prevent neonatal hypoglycemic seizures", "To prevent hemolytic anemia", "To prevent congenital cataracts"], "ans": 1, "exp": "Congenital hypothyroidism มักไม่มีอาการชัดตอนแรกเกิด แต่ thyroid hormone จำเป็นต่อ brain development. การเริ่ม levothyroxine เร็ว (ก่อน 2-3 สัปดาห์) ป้องกัน intellectual disability ที่ irreversible จึงเป็นเหตุผลของ universal newborn screening (TSH/T4)"}, {"topic": "Necrotizing Enterocolitis", "q": "A preterm infant born at 28 weeks, now on day 10 of life and being advanced on enteral feeds, develops abdominal distension, bloody stools, feeding intolerance, and lethargy. Abdominal radiograph shows pneumatosis intestinalis. What is the most likely diagnosis?", "choices": ["Hirschsprung disease", "Malrotation with volvulus", "Necrotizing enterocolitis", "Milk protein allergy", "Anal fissure"], "ans": 2, "exp": "Preterm + enteral feeding + abdominal distension + bloody stool + pneumatosis intestinalis (ลมในผนังลำไส้) = necrotizing enterocolitis (NEC). รักษาเบื้องต้น: NPO, NG decompression, IV fluids, broad-spectrum antibiotics; ผ่าตัดเมื่อมี perforation (pneumoperitoneum). Prematurity เป็น risk factor สำคัญที่สุด"}, {"topic": "Vitamin K Deficiency Bleeding", "q": "A 4-day-old exclusively breastfed infant who did not receive vitamin K at birth (home delivery) presents with bleeding from the umbilical stump, bruising, and blood in the stool. Coagulation studies show prolonged PT and aPTT with normal platelet count. What is the most appropriate treatment?", "choices": ["Platelet transfusion", "Oral iron supplementation", "Fresh frozen plasma as the definitive long-term therapy", "Parenteral vitamin K", "Desmopressin (DDAVP)"], "ans": 3, "exp": "Vitamin K deficiency bleeding (VKDB / hemorrhagic disease of newborn): prolonged PT/aPTT, platelet ปกติ ในทารก breastfed ที่ไม่ได้ vitamin K. รักษาด้วย parenteral vitamin K (FFP ใช้เสริมกรณีเลือดออกรุนแรง/ต้องการ correct เร็ว แต่ไม่ใช่ definitive). ป้องกันด้วย IM vitamin K ทุกรายแรกเกิด"}, {"topic": "Transient Tachypnea", "q": "A term infant born by elective cesarean section without labor develops tachypnea (RR 80/min) with mild grunting shortly after birth. Chest radiograph shows prominent perihilar streaking and fluid in the interlobar fissures. Symptoms resolve within 24-48 hours with supportive care. What is the most likely diagnosis?", "choices": ["Respiratory distress syndrome", "Meconium aspiration syndrome", "Congenital pneumonia", "Persistent pulmonary hypertension", "Transient tachypnea of the newborn"], "ans": 4, "exp": "Transient tachypnea of the newborn (TTN) จาก delayed clearance ของ fetal lung fluid พบบ่อยหลัง elective C/S ไม่มี labor. ภาพเอกซเรย์: perihilar streaking, fluid in fissures, mild hyperinflation. หายเองใน 24-72 ชม.ด้วย supportive care (O2). RDS จะแย่ลงและมี ground-glass"}, {"topic": "Meconium Aspiration", "q": "A post-term infant (42 weeks) delivered through thick meconium-stained fluid develops severe respiratory distress and cyanosis. Chest radiograph shows patchy infiltrates with hyperinflation and areas of atelectasis. What is the most likely diagnosis?", "choices": ["Meconium aspiration syndrome", "Transient tachypnea of the newborn", "Respiratory distress syndrome", "Diaphragmatic hernia", "Choanal atresia"], "ans": 0, "exp": "Post-term + thick meconium + respiratory distress + patchy infiltrate/hyperinflation = meconium aspiration syndrome (MAS). Meconium อุด airway (ball-valve → air trapping) และทำให้ chemical pneumonitis + surfactant inactivation, เสี่ยง PPHN และ pneumothorax. รักษา supportive +/- surfactant/iNO"}, {"topic": "PPHN", "q": "A term infant with meconium aspiration has severe hypoxemia. Pre-ductal oxygen saturation (right hand) is 95% while post-ductal saturation (foot) is 80%, a difference that persists despite high inspired oxygen. Echocardiography shows right-to-left shunting at the ductus. What is the diagnosis?", "choices": ["Cyanotic congenital heart disease with fixed shunt", "Persistent pulmonary hypertension of the newborn", "Severe anemia", "Methemoglobinemia", "Sepsis without cardiopulmonary involvement"], "ans": 1, "exp": "Pre-post ductal saturation gradient >10% + right-to-left shunt ที่ ductus = PPHN (pulmonary vascular resistance สูงค้าง). พบร่วมกับ MAS, sepsis, CDH. รักษา: optimize oxygenation/ventilation, inhaled nitric oxide (pulmonary vasodilator), เลี่ยง acidosis/hypothermia"}, {"topic": "Apnea of Prematurity", "q": "A preterm infant born at 30 weeks has recurrent episodes of cessation of breathing lasting >20 seconds accompanied by bradycardia and desaturation, occurring in the absence of sepsis or other identifiable cause. Which medication is first-line treatment?", "choices": ["Phenobarbital", "Dexamethasone", "Caffeine citrate", "Indomethacin", "Digoxin"], "ans": 2, "exp": "Apnea of prematurity จาก immature respiratory control center. First-line pharmacologic treatment คือ methylxanthine โดยเฉพาะ caffeine citrate ซึ่งกระตุ้น respiratory drive และช่วยลด BPD และ improve neurodevelopmental outcome เมื่อเทียบกับ theophylline"}, {"topic": "Retinopathy of Prematurity", "q": "A former 27-week preterm infant who received prolonged supplemental oxygen is scheduled for screening eye examination. Which condition, related to abnormal retinal neovascularization, is being screened for to prevent blindness?", "choices": ["Congenital cataract", "Retinoblastoma", "Congenital glaucoma", "Retinopathy of prematurity", "Optic nerve hypoplasia"], "ans": 3, "exp": "Retinopathy of prematurity (ROP): abnormal retinal vascular proliferation ในทารก preterm/low birth weight ที่ได้ O2 นาน. เสี่ยง retinal detachment และตาบอด. ต้อง screen ตามเกณฑ์ (GA ≤30 wk หรือ BW ≤1500 g) รักษาด้วย laser หรือ anti-VEGF เมื่อถึง threshold"}, {"topic": "Intraventricular Hemorrhage", "q": "A 26-week preterm infant on day 3 of life suddenly develops a bulging fontanelle, falling hematocrit, seizures, and hemodynamic instability. Cranial ultrasound is the key diagnostic tool. Bleeding from which structure most commonly causes this in preterm infants?", "choices": ["Middle cerebral artery aneurysm", "Choroid plexus papilloma", "Bridging veins from trauma", "Arteriovenous malformation", "Germinal matrix"], "ans": 4, "exp": "Intraventricular hemorrhage (IVH) ในทารก preterm มักมาจาก germinal matrix ซึ่งมีหลอดเลือดเปราะบาง (มีมากก่อน 32-34 สัปดาห์). เสี่ยงสูงในสัปดาห์แรกของชีวิต. Cranial ultrasound เป็นเครื่องมือ screen/diagnose. ป้องกันด้วย antenatal steroid และ minimal handling"}, {"topic": "PDA in Preterm", "q": "A preterm infant on day 5 develops a continuous 'machinery' murmur at the left upper sternal border, bounding pulses, a widened pulse pressure, and worsening respiratory status. Echocardiography confirms a hemodynamically significant patent ductus arteriosus. Which pharmacologic option promotes ductal closure?", "choices": ["Indomethacin or ibuprofen", "Prostaglandin E1 infusion", "Digoxin", "Inhaled nitric oxide", "Furosemide as the definitive closure agent"], "ans": 0, "exp": "PDA ในทารก preterm: COX inhibitor (indomethacin/ibuprofen) ยับยั้ง prostaglandin ทำให้ ductus ปิด. ตรงข้ามกับ duct-dependent CHD ที่ต้องใช้ prostaglandin E1 เปิด ductus ค้างไว้. ถ้ายาไม่ได้ผลและ significant → surgical/device ligation"}, {"topic": "Bronchopulmonary Dysplasia", "q": "A former 25-week preterm infant remains oxygen-dependent at 36 weeks postmenstrual age after prolonged mechanical ventilation. Chest radiograph shows cystic changes and hyperinflation. What is the most likely diagnosis?", "choices": ["Recurrent pneumonia", "Bronchopulmonary dysplasia", "Cystic fibrosis", "Congenital lobar emphysema", "Pulmonary sequestration"], "ans": 1, "exp": "Bronchopulmonary dysplasia (BPD/chronic lung disease) = ต้องการ O2 ที่ 36 weeks PMA ในทารก preterm ที่ผ่าน ventilation/oxygen นาน จาก lung injury + arrested alveolar development. ป้องกัน: gentle ventilation, caffeine, vitamin A; หลีกเลี่ยง volutrauma/oxygen toxicity"}, {"topic": "Neonatal Polycythemia", "q": "A term infant appears plethoric (ruddy) and is lethargic with poor feeding. Venous hematocrit is 72%. What is the most appropriate management of symptomatic neonatal polycythemia?", "choices": ["Whole blood transfusion", "Immediate splenectomy", "Partial exchange transfusion with normal saline", "High-dose diuretics", "Therapeutic phlebotomy without volume replacement"], "ans": 2, "exp": "Polycythemia (venous Hct ≥65%) ที่มีอาการ (lethargy, poor feeding, hypoglycemia, respiratory distress) รักษาด้วย partial exchange transfusion โดยเอาเลือดออกและแทนที่ด้วย normal saline เพื่อลด Hct/viscosity. Phlebotomy อย่างเดียวโดยไม่ทดแทน volume ทำให้ hypovolemia"}, {"topic": "Neonatal Hypocalcemia", "q": "A preterm infant on day 2 develops jitteriness and a seizure. Serum total calcium is 6.5 mg/dL (ionized also low). Early neonatal hypocalcemia in this setting is most commonly associated with which risk factor?", "choices": ["Congenital hypothyroidism", "Breast milk jaundice", "Group B Streptococcus colonization", "Prematurity", "Delayed cord clamping"], "ans": 3, "exp": "Early neonatal hypocalcemia (<72 ชม.) พบใน prematurity, infant of diabetic mother, birth asphyxia (จาก abrupt loss ของ maternal calcium supply + immature PTH response). อาการ: jitteriness, seizure. รักษาด้วย IV calcium gluconate เมื่อมีอาการ. Late hypocalcemia (>72 ชม.) นึกถึง high-phosphate feeding, hypoparathyroidism (DiGeorge)"}, {"topic": "Galactosemia", "q": "A newborn started on breast/formula milk develops vomiting, jaundice, hepatomegaly, and poor feeding in the first week, and then Escherichia coli sepsis. Reducing substances are present in the urine. What is the most appropriate dietary management?", "choices": ["Continue breastfeeding as normal", "Switch to a high-protein cow's milk formula", "Start a ketogenic diet", "Restrict all fat intake", "Eliminate galactose/lactose"], "ans": 4, "exp": "Galactosemia (classic, GALT deficiency): vomiting, jaundice, hepatomegaly, cataract, และเสี่ยง E. coli sepsis หลังได้ galactose (lactose ในนม). Urine reducing substance positive แต่ glucose oxidase negative. รักษาโดยตัด galactose/lactose ใช้ soy-based formula. ตรวจพบได้ใน newborn screening"}, {"topic": "Phenylketonuria", "q": "An infant with a positive newborn screen for elevated phenylalanine, if untreated, is at risk for intellectual disability, seizures, a musty body odor, and hypopigmentation. What is the cornerstone of management?", "choices": ["Dietary phenylalanine restriction", "Lifelong phenobarbital", "Galactose-free diet", "High-protein diet to overcome the deficiency", "Copper chelation therapy"], "ans": 0, "exp": "Phenylketonuria (PKU): phenylalanine hydroxylase deficiency → phenylalanine สะสม ทำลายสมอง. คุณลักษณะ: intellectual disability, seizure, musty odor, fair skin/hair (hypopigmentation จาก tyrosine ต่ำ). รักษาด้วย low-phenylalanine diet ตั้งแต่แรกเกิด (ต้องหลีกเลี่ยง aspartame). พบได้จาก newborn screening"}, {"topic": "Gastroschisis vs Omphalocele", "q": "A newborn is born with bowel loops protruding through a defect to the RIGHT of the umbilical cord, with no covering membrane. The liver is not involved and there are usually no other anomalies. What is the diagnosis?", "choices": ["Omphalocele", "Gastroschisis", "Umbilical hernia", "Patent urachus", "Prune-belly syndrome"], "ans": 1, "exp": "Gastroschisis: defect ด้านขวาของสายสะดือ ไม่มีเยื่อหุ้ม (bowel สัมผัสน้ำคร่ำโดยตรง), มักไม่สัมพันธ์กับ anomalies อื่น. Omphalocele: herniation ผ่าน umbilical ring มีเยื่อ (peritoneum/amnion) หุ้ม สัมพันธ์กับ chromosomal/other anomalies บ่อย. ทั้งคู่ต้องคลุม bowel, NG decompression, IV fluid แล้วผ่าตัด"}, {"topic": "Duodenal Atresia", "q": "A newborn with Down syndrome develops bilious vomiting in the first day of life. Abdominal radiograph shows a 'double bubble' sign with no distal gas. What is the most likely diagnosis?", "choices": ["Necrotizing enterocolitis", "Hypertrophic pyloric stenosis", "Duodenal atresia", "Meconium ileus", "Hirschsprung disease"], "ans": 2, "exp": "Double bubble sign (air ในกระเพาะ + duodenal cap) โดยไม่มี distal gas + bilious vomiting = duodenal atresia สัมพันธ์กับ Down syndrome (trisomy 21) บ่อย. Pyloric stenosis จะ non-bilious vomiting ที่ 3-6 สัปดาห์และมี distal gas. รักษาด้วยผ่าตัด (duodenoduodenostomy)"}, {"topic": "Imperforate Anus", "q": "During the routine newborn examination, an infant is found to have no anal opening. Which associated group of anomalies should be evaluated?", "choices": ["CHARGE syndrome only", "Beckwith-Wiedemann syndrome", "Marfan syndrome", "VACTERL association", "Osteogenesis imperfecta"], "ans": 3, "exp": "Imperforate anus (anorectal malformation) เป็นส่วนหนึ่งของ VACTERL association (Vertebral, Anal atresia, Cardiac, TE fistula, Renal, Limb). ตรวจพบ 1 อย่างต้องหาส่วนอื่น เช่น echocardiogram, renal ultrasound, spine imaging. รักษาโดยผ่าตัด (colostomy แล้ว definitive repair)"}, {"topic": "Developmental Dysplasia of Hip", "q": "During newborn examination, a hip is noted to be dislocatable with a palpable 'clunk' when the flexed, abducted hip is pushed posteriorly and reduced with abduction. Which is the most appropriate initial imaging in an infant under 6 months?", "choices": ["Plain hip radiograph", "CT scan of the pelvis", "MRI under anesthesia", "Bone scintigraphy", "Hip ultrasonography"], "ans": 4, "exp": "Developmental dysplasia of hip (DDH): Barlow (dislocatable) และ Ortolani (reducible 'clunk') positive. ในทารก <6 เดือน femoral head ยังเป็น cartilage → ใช้ hip ultrasound เป็น imaging หลัก. หลัง 4-6 เดือนเมื่อ ossification center ปรากฏจึงใช้ plain film. รักษาเริ่มด้วย Pavlik harness"}, {"topic": "Congenital Syphilis", "q": "A newborn presents with a maculopapular rash including the palms and soles, snuffles (rhinitis), hepatosplenomegaly, and radiographs showing metaphyseal lucencies (periostitis). The mother had inadequately treated syphilis. What is the treatment for the infant?", "choices": ["Parenteral penicillin G", "Oral azithromycin", "Intravenous acyclovir", "Oral doxycycline", "Intramuscular ceftriaxone as first-line"], "ans": 0, "exp": "Congenital syphilis: rash ที่ palms/soles, snuffles, hepatosplenomegaly, periostitis/metaphyseal changes, +/- HSM, jaundice. รักษาด้วย parenteral (IV/IM) penicillin G. Doxycycline ห้ามในทารก (teeth staining). ป้องกันด้วยการ screen และรักษา syphilis ในหญิงตั้งครรภ์"}, {"topic": "Neonatal HSV", "q": "A 10-day-old infant, born vaginally to a mother with a primary genital herpes outbreak near delivery, presents with vesicular skin lesions, lethargy, poor feeding, and seizures. What is the most appropriate treatment?", "choices": ["Intravenous ceftriaxone alone", "Intravenous acyclovir", "Oral valacyclovir", "Supportive care only", "Intravenous immunoglobulin as monotherapy"], "ans": 1, "exp": "Neonatal HSV (skin-eye-mouth, CNS, หรือ disseminated) จาก perinatal transmission โดยเฉพาะเมื่อแม่มี primary outbreak ตอนคลอด. อาการ CNS: seizure, lethargy. รักษาด้วย high-dose IV acyclovir (ต่อด้วย oral suppression). พิจารณา C/S ถ้าแม่มี active lesions ตอนเจ็บครรภ์"}, {"topic": "Ophthalmia Neonatorum", "q": "A newborn develops profuse purulent conjunctival discharge with marked eyelid swelling on day 3 of life. Gram stain of the discharge shows gram-negative intracellular diplococci. What is the most appropriate treatment?", "choices": ["Topical erythromycin ointment only", "Oral acyclovir", "Single-dose parenteral ceftriaxone", "Topical corticosteroid drops", "Observation, as it is self-limited"], "ans": 2, "exp": "Gonococcal ophthalmia neonatorum: hyperacute purulent conjunctivitis วันที่ 2-5, gram-negative intracellular diplococci = Neisseria gonorrhoeae. รักษาด้วย systemic ceftriaxone (single dose) + saline irrigation เพราะเสี่ยง corneal perforation. Chlamydial conjunctivitis (วันที่ 5-14) รักษาด้วย oral erythromycin. ป้องกันด้วย erythromycin eye ointment แรกเกิด"}, {"topic": "Duct-Dependent CHD", "q": "A newborn who was well at birth develops profound cyanosis and shock on day 3 as the ductus arteriosus closes. A duct-dependent congenital heart lesion is suspected. Which medication should be started immediately to stabilize the infant?", "choices": ["Indomethacin infusion to promote ductal closure", "Propranolol to control the ventricular heart rate", "Furosemide to offload pulmonary fluid overload", "Prostaglandin E1 infusion to maintain ductal patency", "Adenosine push to terminate a re-entrant tachycardia"], "ans": 3, "exp": "Duct-dependent lesions (เช่น transposition, pulmonary atresia, HLHS, critical coarctation) อาศัย PDA เพื่อ systemic หรือ pulmonary flow. เมื่อ ductus ปิด (วันที่ 2-7) เกิด cyanosis/shock. ให้ prostaglandin E1 (alprostadil) เปิด ductus ค้างไว้เพื่อ stabilize ก่อนรักษาจำเพาะ. Indomethacin ทำตรงข้าม (ปิด ductus)"}, {"topic": "Meconium Ileus", "q": "A newborn fails to pass meconium in the first 48 hours and develops abdominal distension and bilious vomiting. Contrast enema shows a microcolon with inspissated meconium in the terminal ileum. This presentation is most strongly associated with which underlying disease?", "choices": ["Down syndrome", "Congenital hypothyroidism", "Hirschsprung disease", "Galactosemia", "Cystic fibrosis"], "ans": 4, "exp": "Meconium ileus (obstruction จาก thick inspissated meconium ที่ terminal ileum, microcolon) เป็น neonatal presentation ที่ classic ของ cystic fibrosis (>90% ของ meconium ileus มี CF). ควรส่งตรวจ sweat chloride/genetic. Hirschsprung ก็ทำให้ delayed meconium ได้แต่ pattern ต่างกัน (transition zone)"}, {"topic": "Delayed Cord Clamping", "q": "For a vigorous term or preterm newborn who does not require immediate resuscitation, delayed umbilical cord clamping (for at least 30-60 seconds) provides which principal benefit?", "choices": ["Improved iron stores and reduced anemia", "Reduced risk of neonatal jaundice", "Lower risk of polycythemia", "Prevention of respiratory distress syndrome", "Prevention of hypoglycemia"], "ans": 0, "exp": "Delayed cord clamping (≥30-60 วินาที) เพิ่ม placental transfusion → เพิ่ม iron stores, ลด anemia (และใน preterm ลด IVH, NEC, need for transfusion). ข้อควรระวังคืออาจเพิ่ม jaundice/polycythemia เล็กน้อย จึงต้องเฝ้าระวัง แต่ประโยชน์เรื่อง iron/anemia เป็นข้อดีหลัก"}, {"topic": "Neonatal Hypothermia", "q": "A low-birth-weight newborn in a delivery room becomes hypothermic. Which mechanism is the predominant route of heat loss when a wet newborn is left uncovered immediately after birth?", "choices": ["Conduction", "Evaporation", "Radiation", "Convection", "Metabolic heat production"], "ans": 1, "exp": "ทารกแรกเกิดเปียกน้ำคร่ำ heat loss หลักคือ evaporation จากผิวหนังที่เปียก. การเช็ดตัวให้แห้งทันที + ห่อผ้าอุ่น + warmer/skin-to-skin ลดการสูญเสียความร้อน. ทารกเสี่ยง hypothermia เพราะ surface area สูงต่อ mass, brown fat จำกัด, ไม่สั่น (non-shivering thermogenesis)"}, {"topic": "Rh Isoimmunization", "q": "A woman who is blood group O Rh-negative is pregnant with her second child; the father is Rh-positive. Which intervention prevents hemolytic disease of the fetus and newborn from Rh(D) sensitization?", "choices": ["Anti-D immunoglobulin to the newborn after birth", "Maternal corticosteroids in the third trimester", "Anti-D immunoglobulin to the mother at 28 weeks and after delivery", "Exchange transfusion of the mother", "Intramuscular vitamin K to the mother"], "ans": 2, "exp": "การป้องกัน Rh isoimmunization: ให้ anti-D immunoglobulin (RhoGAM) แก่แม่ Rh-negative ที่ 28 สัปดาห์ และภายใน 72 ชม.หลังคลอดถ้าลูก Rh-positive (รวมถึงหลัง sensitizing events เช่น แท้ง, amniocentesis, bleeding). ป้องกันไม่ให้แม่สร้าง anti-D ที่จะทำลาย RBC ของ fetus ในครรภ์ถัดไป"}, {"topic": "Hydrops Fetalis", "q": "A fetus of an Rh-sensitized mother is found to have severe anemia with generalized edema, pleural effusion, ascites, and pericardial effusion. What is this condition called?", "choices": ["Congenital nephrotic syndrome", "Neonatal hypothyroidism", "Meconium peritonitis", "Immune hydrops fetalis", "Congenital chylothorax"], "ans": 3, "exp": "Hydrops fetalis = fluid สะสมใน ≥2 compartments (edema, ascites, pleural/pericardial effusion). Immune hydrops จาก severe hemolytic anemia (เช่น Rh disease) → high-output heart failure. Non-immune hydrops มีสาเหตุอื่น (thalassemia, TORCH, chromosomal, cardiac). รักษาที่ต้นเหตุ +/- intrauterine transfusion"}, {"topic": "G6PD Deficiency", "q": "A male term newborn develops significant jaundice on day 2 with total bilirubin rising quickly. He is of Southeast Asian descent with a family history of favism. The blood smear shows bite cells and Heinz bodies. What is the most likely underlying cause?", "choices": ["Hereditary spherocytosis with a negative Coombs test", "ABO incompatibility from maternal IgG antibodies", "Beta-thalassemia major with ineffective erythropoiesis", "Autoimmune hemolytic anemia with warm antibodies", "Glucose-6-phosphate dehydrogenase (G6PD) deficiency"], "ans": 4, "exp": "G6PD deficiency (X-linked, พบบ่อยในเพศชายเอเชีย/แถบทะเลเมดิเตอร์เรเนียน) ทำให้ neonatal hemolysis + jaundice, smear เห็น bite cells/Heinz bodies. เป็นสาเหตุสำคัญของ severe neonatal hyperbilirubinemia/kernicterus ในไทย. หลีกเลี่ยง oxidant (naphthalene, บาง sulfa, fava bean)"}, {"topic": "Erythema Toxicum", "q": "A healthy 2-day-old term newborn has scattered erythematous macules with central yellow-white papules/pustules on the trunk. The infant is well and afebrile, and a smear of a pustule shows eosinophils. What is the diagnosis?", "choices": ["Erythema toxicum neonatorum", "Neonatal herpes simplex infection", "Staphylococcal pustulosis", "Congenital syphilis", "Neonatal varicella"], "ans": 0, "exp": "Erythema toxicum neonatorum: benign, self-limited rash (erythematous macule + central papule/pustule) ในทารกที่สุขภาพดี วันที่ 1-3, smear เห็น eosinophils. ไม่ต้องรักษา. ต่างจาก neonatal HSV (vesicle, smear เห็น multinucleated giant cell, ทารกป่วย) ที่เป็นภาวะร้ายแรง"}, {"topic": "Neonatal Abstinence Syndrome", "q": "A newborn born to a mother using opioids during pregnancy develops irritability, high-pitched cry, tremors, poor feeding, sweating, sneezing, and loose stools on day 2. What is the most appropriate first-line approach for mild symptoms?", "choices": ["Immediate high-dose intravenous naloxone", "Supportive non-pharmacologic care", "Phenobarbital as the first drug for all cases", "Discharge home without observation", "Complete cessation of feeding"], "ans": 1, "exp": "Neonatal abstinence syndrome (NAS) จาก opioid withdrawal: irritability, tremor, high-pitched cry, feeding/GI symptoms. First-line คือ non-pharmacologic (swaddle, minimal stimulation, frequent small feeds, skin-to-skin). ให้ pharmacologic (morphine/methadone) เมื่อ score สูง. ห้ามให้ naloxone (กระตุ้น acute withdrawal/seizure)"}, {"topic": "Choanal Atresia", "q": "A newborn turns cyanotic when quiet or feeding but becomes pink when crying. A catheter cannot be passed through either nostril into the pharynx. What is the diagnosis?", "choices": ["Laryngomalacia", "Vocal cord paralysis", "Bilateral choanal atresia", "Pierre Robin sequence", "Tracheoesophageal fistula"], "ans": 2, "exp": "Choanal atresia: newborns เป็น obligate nasal breather → cyanosis ตอนสงบ/กินนม (จมูกตัน) แต่ pink ตอนร้อง (หายใจทางปาก) = 'paradoxical cyanosis'. Diagnosis: ใส่ catheter ผ่านจมูกไม่ได้, ยืนยันด้วย CT. รักษา: oral airway ชั่วคราวแล้วผ่าตัด. สัมพันธ์กับ CHARGE association"}, {"topic": "Omphalitis", "q": "A 5-day-old newborn develops periumbilical erythema, induration, tenderness, and purulent discharge from the umbilical stump, with fever. What is the most appropriate management?", "choices": ["Topical antibiotic ointment and discharge", "Oral amoxicillin as an outpatient", "Reassurance; this is normal cord separation", "Admit and start parenteral broad-spectrum antibiotics", "Apply alcohol to the cord only"], "ans": 3, "exp": "Omphalitis (periumbilical cellulitis + discharge + fever) เป็นภาวะร้ายแรงในทารก เสี่ยงลุกลามเป็น necrotizing fasciitis, sepsis, portal vein thrombosis. ต้อง admit + IV broad-spectrum antibiotics (ครอบคลุม S. aureus, GAS, gram-negative). ไม่ใช่แค่ topical/oral"}, {"topic": "Congenital Toxoplasmosis", "q": "A newborn is found to have hydrocephalus, diffuse intracranial calcifications, and chorioretinitis. The mother acquired a primary infection during pregnancy from undercooked meat/cat feces exposure. Which congenital infection is most likely?", "choices": ["Congenital cytomegalovirus", "Congenital rubella", "Congenital syphilis", "Neonatal HSV", "Congenital toxoplasmosis"], "ans": 4, "exp": "Classic triad ของ congenital toxoplasmosis = hydrocephalus + diffuse intracranial calcification + chorioretinitis. ต่างจาก CMV (periventricular calcification, microcephaly, SNHL). แหล่งติด: undercooked meat, cat feces. รักษาทารกด้วย pyrimethamine + sulfadiazine + folinic acid"}, {"topic": "Physiologic Weight Loss", "q": "The parents of a 4-day-old breastfed term newborn are worried because the baby has lost weight since birth. The baby is otherwise feeding, urinating, and active. Up to what percentage of birth weight loss is generally considered acceptable in the first week?", "choices": ["Up to about 7-10%, with return to birth weight by 10-14 days", "Up to 25%, with return by 4 weeks", "Any weight loss is abnormal and requires admission", "Up to 15%, with return by 3 weeks", "Weight loss only matters if the baby is formula-fed"], "ans": 0, "exp": "ทารกแรกเกิดปกติน้ำหนักลดได้ ~7-10% ใน 3-5 วันแรก (จาก fluid shift/นมยังไม่มามาก) และกลับสู่ birth weight ภายใน 10-14 วัน. น้ำหนักลด >10% หรือไม่กลับตามเกณฑ์ ต้องประเมิน feeding/dehydration. Output ปัสสาวะ/อุจจาระที่ดีเป็นสัญญาณว่าได้นมพอ"}, {"topic": "Neonatal Seizure", "q": "A term newborn on day 2 has repetitive focal clonic jerking of one arm with associated eye deviation. After correcting glucose and electrolytes and treating any infection, which anticonvulsant is the traditional first-line agent for neonatal seizures?", "choices": ["Valproic acid", "Phenobarbital", "Carbamazepine", "Ethosuximide", "Diazepam infusion for maintenance"], "ans": 1, "exp": "Neonatal seizure: ต้องหาสาเหตุก่อน (hypoglycemia, hypocalcemia, hyponatremia, HIE, infection/meningitis, IVH, IEM) และแก้ metabolic causes. First-line anticonvulsant แบบดั้งเดิมคือ phenobarbital (IV). Levetiracetam กำลังถูกใช้มากขึ้น. Valproate เลี่ยงในทารกเล็ก (hepatotoxicity)"}, {"topic": "Subgaleal Hemorrhage", "q": "A newborn delivered with vacuum assistance develops a diffuse, fluctuant, boggy scalp swelling that crosses suture lines and increases over hours, with a falling hematocrit and signs of hypovolemia. What is the diagnosis?", "choices": ["Cephalohematoma", "Caput succedaneum", "Subgaleal hemorrhage", "Subdural hematoma", "Epidural hematoma"], "ans": 2, "exp": "Subgaleal hemorrhage: เลือดออกใน loose areolar tissue ระหว่าง galea กับ periosteum เป็น potential space ใหญ่ → เก็บเลือดได้มากจน hypovolemic shock/anemia. สัมพันธ์กับ vacuum/forceps. Boggy swelling ข้าม suture, ขยายตัว, อันตราย ต้องเฝ้าระวัง volume/transfusion. ต่างจาก cephalohematoma ที่จำกัดในกระดูกชิ้นเดียว"}, {"topic": "Cleft Palate Feeding", "q": "A newborn with an isolated cleft palate has difficulty generating suction and feeding. What is the most appropriate feeding recommendation?", "choices": ["Nil by mouth with tube feeds until repair at one year", "Total parenteral nutrition until surgical correction", "A standard rigid nipple with thickened formula feeds", "Use a specialized cleft/squeeze bottle for feeding", "Permanent nasogastric tube feeding to avoid aspiration"], "ans": 3, "exp": "ทารก cleft palate สร้าง suction ไม่ได้ → ใช้ specialized bottle (squeeze/cleft bottle) ที่ช่วยบีบนมเข้าปาก, จัดท่า upright, ป้องกันสำลัก. ยังกินทางปากได้ ไม่จำเป็นต้อง NPO/IV. ผ่าตัด palate ~9-12 เดือน (lip ~3 เดือน, rule of 10s)"}, {"topic": "Clubfoot", "q": "A newborn is noted to have a foot that is rigidly plantarflexed, inverted, and adducted, and cannot be passively brought to a neutral position. What is the most appropriate initial management of congenital talipes equinovarus?", "choices": ["Immediate surgical release in the neonatal period", "Observation as it always self-corrects", "Botulinum toxin injection", "Long-term bracing without casting", "Serial casting started early"], "ans": 4, "exp": "Congenital talipes equinovarus (clubfoot): เท้า equinus + varus + adductus, rigid (ต่างจาก positional ที่ correct ได้). รักษาเริ่มต้นด้วย Ponseti serial casting ตั้งแต่แรกๆ ตามด้วย Achilles tenotomy และ bracing. Surgery เก็บไว้กรณีดื้อต่อ casting"}, {"topic": "Sacral Dimple", "q": "During newborn examination, a deep sacral dimple is found with a tuft of hair and its base cannot be visualized, located high above the anus. What is the most appropriate next step?", "choices": ["Spinal ultrasound to evaluate for occult dysraphism", "Reassurance that all sacral dimples are entirely benign", "Immediate neurosurgical exploration of the spinal canal", "A plain skull radiograph to look for a bony defect", "Prophylactic antibiotics to prevent local infection"], "ans": 0, "exp": "Sacral dimple ที่ 'atypical' (ลึก, มองไม่เห็นก้น, มี hair tuft, ห่างจาก anus >2.5 ซม., มี associated markers) เสี่ยง occult spinal dysraphism (tethered cord) → ประเมินด้วย spinal ultrasound (ทารก <6 เดือน) หรือ MRI. Simple shallow midline dimple ใกล้ anus ที่เห็นก้น เป็น benign ไม่ต้องตรวจเพิ่ม"}, {"topic": "Late-Onset Sepsis", "q": "A preterm infant in the NICU with a central venous catheter, well for the first weeks, suddenly develops temperature instability, apnea, feeding intolerance, and lethargy on day 14. Blood culture grows coagulase-negative staphylococci. What is the most likely diagnosis?", "choices": ["Early-onset GBS sepsis", "Late-onset neonatal sepsis", "Necrotizing enterocolitis", "Physiologic apnea of prematurity", "Congenital CMV"], "ans": 1, "exp": "Late-onset sepsis (>72 ชม. ถึง 7 วัน+) ในทารก NICU มักสัมพันธ์กับ central line/nosocomial, เชื้อบ่อยคือ coagulase-negative staphylococci (CoNS), S. aureus, gram-negative, Candida. รักษา empiric vancomycin + gram-negative coverage และพิจารณา line removal. ต่างจาก early-onset (GBS, E. coli, จากแม่)"}, {"topic": "Congenital Hypothyroidism Cause", "q": "A newborn screen returns a high TSH. The infant is confirmed to have primary congenital hypothyroidism. What is the most common underlying cause worldwide in areas without iodine deficiency?", "choices": ["Pituitary tumor", "Maternal Graves disease", "Thyroid dysgenesis", "Iodine excess", "Thyroid hormone receptor mutation"], "ans": 2, "exp": "ในพื้นที่ที่ไม่ขาด iodine, สาเหตุที่พบบ่อยที่สุดของ primary congenital hypothyroidism คือ thyroid dysgenesis (agenesis, ectopic, hypoplasia) รองลงมาคือ dyshormonogenesis. ในพื้นที่ขาด iodine, iodine deficiency เป็นสาเหตุหลัก. รักษาด้วย levothyroxine เริ่มเร็วเพื่อป้องกัน intellectual disability"}, {"topic": "Neonatal Alloimmune Thrombocytopenia", "q": "An otherwise well term newborn is noted to have widespread petechiae and a platelet count of 20,000/µL on the first day. The mother's platelet count is normal. The mechanism is analogous to Rh disease but involves platelet antigens. What is the diagnosis?", "choices": ["Disseminated intravascular coagulation", "Immune thrombocytopenic purpura from maternal ITP", "Congenital leukemia", "Neonatal alloimmune thrombocytopenia", "Wiskott-Aldrich syndrome"], "ans": 3, "exp": "Neonatal alloimmune thrombocytopenia (NAIT): แม่สร้าง antibody ต่อ paternal platelet antigen (เช่น HPA-1a) ที่ทารกมี → destroy platelet ทารก. แม่ platelet ปกติ (ต่างจาก maternal ITP ที่แม่เกล็ดต่ำ). เสี่ยง intracranial hemorrhage. รักษา: matched/washed platelet, IVIG"}, {"topic": "Pierre Robin Sequence", "q": "A newborn has micrognathia (small jaw), glossoptosis (posteriorly displaced tongue), and a U-shaped cleft palate, resulting in upper airway obstruction. What is the priority in initial management?", "choices": ["Immediate mandibular distraction surgery in the newborn", "Supine positioning with a pillow to assist with feeding", "Routine endotracheal intubation for every affected infant", "Elective tracheostomy for every infant at presentation", "Prone/lateral positioning to relieve airway obstruction"], "ans": 4, "exp": "Pierre Robin sequence: micrognathia + glossoptosis + cleft palate → airway obstruction. Priority คือ airway: จัดท่า prone/lateral ให้ลิ้นตกไปด้านหน้า (supine ทำให้แย่ลง). กรณีรุนแรงใช้ nasopharyngeal airway, mandibular distraction, หรือ tracheostomy. ต้องระวัง feeding และ aspiration"}, {"topic": "Neonatal Conjunctivitis - Chlamydia", "q": "A 10-day-old infant develops mucopurulent conjunctivitis with eyelid swelling. Gram stain shows no gonococci, and chlamydial testing is positive. What is the appropriate treatment?", "choices": ["Oral erythromycin", "Topical erythromycin ointment alone", "Single-dose ceftriaxone", "Topical corticosteroids", "Observation only"], "ans": 0, "exp": "Chlamydial ophthalmia neonatorum เกิดวันที่ 5-14, ต้องรักษาด้วย systemic (oral) erythromycin เพราะ topical ไม่กำจัด nasopharyngeal carriage และเสี่ยง chlamydial pneumonia ตามมา. Gonococcal (วันที่ 2-5, hyperacute) รักษาด้วย systemic ceftriaxone. หมายเหตุ oral erythromycin ในทารกเสี่ยง pyloric stenosis เล็กน้อย ต้องแจ้งผู้ปกครอง"}, {"topic": "Neonatal Tetanus", "q": "In a resource-limited setting, a 7-day-old infant born at home (unclean cord practice, unvaccinated mother) develops difficulty feeding, generalized stiffness, trismus, and spasms. What is the key preventive measure?", "choices": ["Routine newborn BCG vaccination given soon after birth", "Maternal tetanus toxoid plus clean umbilical cord care", "Exclusive breastfeeding from the first day of life", "High-dose vitamin A supplementation for the newborn", "Prophylactic broad-spectrum antibiotics for every baby"], "ans": 1, "exp": "Neonatal tetanus จาก Clostridium tetani เข้าทาง unclean umbilical cord ในทารกที่แม่ไม่ได้รับ tetanus toxoid. อาการวันที่ 3-14: poor feeding, trismus, rigidity, spasms. ป้องกันด้วย maternal tetanus toxoid (antenatal) + clean delivery/cord care. รักษา: tetanus immunoglobulin, metronidazole, ควบคุม spasm, supportive"}, {"topic": "Neonatal Hypoglycemia Screening", "q": "Which newborn is at highest risk for hypoglycemia and should have routine glucose monitoring in the first hours of life?", "choices": ["A term appropriate-for-gestational-age infant feeding well", "A 3-day-old thriving breastfed infant", "A large-for-gestational-age infant of a diabetic mother", "A term infant with physiologic jaundice", "A healthy infant after uncomplicated vaginal delivery"], "ans": 2, "exp": "กลุ่มเสี่ยง neonatal hypoglycemia ที่ต้อง screen glucose: infant of diabetic mother, LGA, SGA/IUGR, preterm/late-preterm, perinatal stress/asphyxia. IDM/LGA มี hyperinsulinism. ทารก term AGA ที่กินได้ดีไม่ต้อง routine screen. อาการ hypoglycemia: jitteriness, lethargy, poor feeding, seizure, apnea"}, {"topic": "Caput vs Cephalohematoma", "q": "A newborn has a scalp swelling first noticed several hours after birth that is firm, does NOT cross the suture lines, and is associated with a later rise in bilirubin as it resorbs. What is the diagnosis?", "choices": ["Caput succedaneum", "Subgaleal hemorrhage", "Cranial meningocele", "Cephalohematoma", "Craniosynostosis"], "ans": 3, "exp": "Cephalohematoma: subperiosteal bleed จำกัดในกระดูกชิ้นเดียว จึง 'ไม่ข้าม suture line', ปรากฏหลังคลอดไม่กี่ชั่วโมง, ค่อยๆ หายในสัปดาห์-เดือน และการ resorb ของเลือดเพิ่ม bilirubin (jaundice). Caput succedaneum ข้าม suture, มีตั้งแต่แรกเกิด, หายเร็วใน 2-3 วัน"}, {"topic": "Neonatal Anemia - Hemolytic", "q": "A newborn with jaundice, pallor, splenomegaly, and a family history of gallstones and splenectomy has a blood smear showing numerous spherocytes and a negative direct Coombs test. What is the most likely diagnosis?", "choices": ["ABO hemolytic disease", "G6PD deficiency", "Autoimmune hemolytic anemia", "Iron deficiency anemia", "Hereditary spherocytosis"], "ans": 4, "exp": "Hereditary spherocytosis: hemolytic anemia + jaundice + splenomegaly, smear เห็น spherocytes, direct Coombs 'negative' (ต่างจาก ABO/immune ที่ Coombs positive), ประวัติครอบครัว (autosomal dominant), gallstones. ยืนยันด้วย osmotic fragility/EMA binding. รักษา: folate, phototherapy, พิจารณา splenectomy ในรายรุนแรง"}, {"topic": "Breastfeeding Benefits", "q": "A mother asks about benefits of exclusive breastfeeding for her newborn. Which statement is correct regarding recommendations?", "choices": ["Exclusive breastfeeding is recommended for about the first 6 months of life", "Cow's milk should be introduced at 2 months", "Water supplementation is required between feeds from birth", "Solid foods should begin at 2 months of age", "Breast milk provides sufficient vitamin D without any consideration"], "ans": 0, "exp": "แนะนำ exclusive breastfeeding ~6 เดือนแรก แล้วเริ่ม complementary food ควบคู่นมแม่ต่อถึง 2 ปีหรือมากกว่า. ไม่ให้นมวัว (<1 ปี), ไม่ต้องเสริมน้ำในทารกที่กินนมแม่ล้วน. นมแม่มี vitamin D ต่ำ จึงแนะนำเสริม vitamin D ในทารกที่กินนมแม่ล้วน (จุดที่ต้องระวัง)"}, {"topic": "Biliary Atresia", "q": "A 5-week-old infant has persistent jaundice with pale/acholic stools and dark urine. Total bilirubin is 10 mg/dL with a direct (conjugated) fraction of 6 mg/dL. The liver is firm. Why is prompt diagnosis critical?", "choices": ["It resolves on its own once breastfeeding is stopped", "Kasai portoenterostomy is best done before eight weeks", "Intensive phototherapy will cure it if started early", "It needs only ursodeoxycholic acid without surgery", "It is a benign variant of ordinary physiologic jaundice"], "ans": 1, "exp": "Conjugated (direct) hyperbilirubinemia + acholic stool + dark urine = biliary atresia จนกว่าจะพิสูจน์เป็นอย่างอื่น (conjugated hyperbilirubinemia เป็น pathologic เสมอ). ต้องรีบวินิจฉัย เพราะ Kasai portoenterostomy ได้ผลดีที่สุดเมื่อทำก่อน 8 สัปดาห์; ล่าช้าจะเกิด cirrhosis และต้อง liver transplant. Direct bili สูง 'ห้าม' รักษาด้วย phototherapy อย่างเดียว"}, {"topic": "Malrotation with Volvulus", "q": "A previously well 3-day-old newborn suddenly develops bilious vomiting, abdominal distension, and bloody stools with signs of shock. Upper GI contrast study shows an abnormal position of the duodenojejunal junction. What is the most appropriate action?", "choices": ["Observation and rehydration only", "Barium enema and discharge", "Emergency surgery for midgut volvulus", "Start proton pump inhibitor", "Reassurance; bilious vomiting is normal in newborns"], "ans": 2, "exp": "Bilious vomiting ในทารกแรกเกิด = malrotation with midgut volvulus จนกว่าจะพิสูจน์เป็นอื่น (surgical emergency!). Volvulus บิดรอบ SMA → ischemia ของ midgut. Upper GI (gold standard) เห็น abnormal DJ junction/corkscrew. ต้องผ่าตัด Ladd procedure ด่วน เพื่อรักษาลำไส้"}, {"topic": "Hirschsprung Disease", "q": "A term newborn fails to pass meconium within the first 48 hours and develops abdominal distension and bilious vomiting. A contrast enema shows a narrowed distal segment with proximal dilatation (transition zone). What is the diagnostic test of choice?", "choices": ["Abdominal ultrasound to assess bowel wall thickness", "Serum electrolytes to detect a metabolic disturbance", "Stool culture to identify an infective enterocolitis", "Rectal suction biopsy showing absent ganglion cells", "Sweat chloride test to screen for cystic fibrosis"], "ans": 3, "exp": "Delayed passage of meconium (>48 ชม.) + distension + transition zone = Hirschsprung disease (aganglionosis ของ distal colon จาก failure ของ neural crest migration). Gold standard วินิจฉัยคือ rectal suction biopsy พบ 'absent ganglion cells' + hypertrophied nerve. สัมพันธ์กับ Down syndrome. รักษาผ่าตัดดึง ganglionic bowel ลงมา; ระวัง enterocolitis"}, {"topic": "Congenital Adrenal Hyperplasia", "q": "A 2-week-old infant presents with vomiting, poor feeding, dehydration, and shock. Labs show hyponatremia, hyperkalemia, and hypoglycemia. A female infant may have ambiguous genitalia. What is the most likely diagnosis?", "choices": ["Hypertrophic pyloric stenosis with metabolic alkalosis", "Congenital hypothyroidism with prolonged jaundice", "Classic galactosemia with vomiting and Escherichia coli sepsis", "A urea cycle defect with symptomatic hyperammonemia", "Congenital adrenal hyperplasia with a salt-wasting crisis"], "ans": 4, "exp": "Salt-wasting CAH (21-hydroxylase deficiency): cortisol + aldosterone ต่ำ → hyponatremia, hyperkalemia, hypoglycemia, shock ในสัปดาห์ที่ 1-3; เพศหญิงมี virilization/ambiguous genitalia, เพศชายอวัยวะปกติ (จึงมักมาด้วย crisis). รักษา: IV normal saline + dextrose, hydrocortisone (+ fludrocortisone). ตรวจ 17-OHP สูง"}, {"topic": "Urea Cycle Defect", "q": "A term infant, well at birth, becomes lethargic with poor feeding, vomiting, and tachypnea on day 3 after starting protein feeds, progressing to coma. Blood gas shows respiratory alkalosis and a markedly elevated ammonia level with normal glucose. What class of disorder is most likely?", "choices": ["Urea cycle defect", "Congenital hypothyroidism", "Neonatal sepsis with lactic acidosis", "Galactosemia", "Glycogen storage disease"], "ans": 0, "exp": "Urea cycle defect: หลังได้ protein feed ทารกมี hyperammonemia → lethargy, vomiting, tachypnea (ammonia กระตุ้นหายใจ → respiratory alkalosis), coma. Glucose ปกติ, no acidosis (ต่างจาก organic acidemia ที่มี metabolic acidosis + ketosis). รักษา: หยุด protein, IV glucose, nitrogen scavengers, hemodialysis"}, {"topic": "Neonatal Hepatitis B Prevention", "q": "A newborn is delivered to a mother who is hepatitis B surface antigen (HBsAg) positive. What is the recommended intervention to prevent perinatal transmission?", "choices": ["Hepatitis B vaccine given only at two months of age", "Hepatitis B immunoglobulin plus vaccine within 12 hours", "Complete avoidance of breastfeeding to block transmission", "Cesarean delivery alone as sufficient to prevent spread", "No intervention as long as the mother is asymptomatic"], "ans": 1, "exp": "ทารกที่แม่ HBsAg positive: ให้ HBIG + hepatitis B vaccine ภายใน 12 ชม.หลังคลอด (คนละตำแหน่ง) แล้วให้ vaccine series ต่อ ป้องกัน perinatal transmission ได้ >90%. Breastfeeding ทำได้เมื่อได้ prophylaxis. C/S ไม่ป้องกันเพียงพอ"}, {"topic": "Neonatal HIV Prevention", "q": "To reduce mother-to-child transmission of HIV, which combination of interventions is most effective?", "choices": ["Infant antiretroviral prophylaxis started at six weeks", "Exclusive breastfeeding without any antiretroviral drugs", "Maternal antiretroviral therapy plus infant prophylaxis", "A single dose of antibiotics given at the time of birth", "Immunoglobulin given to the newborn as the only measure"], "ans": 2, "exp": "การป้องกัน MTCT ของ HIV: maternal ART ตลอดการตั้งครรภ์ (กด viral load) + intrapartum management + infant ARV prophylaxis (zidovudine +/- others) + การเลือกวิธี feeding ที่ปลอดภัย. ร่วมกันลด transmission เหลือ <1-2%"}, {"topic": "Oral Thrush", "q": "A 3-week-old breastfed infant has white plaques on the buccal mucosa and tongue that do not wipe off easily and leave an erythematous base when scraped. The infant is otherwise well. What is the treatment?", "choices": ["Oral acyclovir", "Systemic amphotericin B", "Topical corticosteroid", "Oral nystatin suspension", "No treatment; wipe with a wet cloth"], "ans": 3, "exp": "Oral candidiasis (thrush): white plaques ที่ขูดออกยากและมี erythematous base = Candida albicans, พบบ่อยในทารก. รักษาด้วย topical oral nystatin (หรือ miconazole gel). ต่างจาก milk residue ที่เช็ดออกง่าย. รักษาหัวนมแม่ด้วยถ้ามี candidal infection เพื่อป้องกันการติดซ้ำ"}, {"topic": "Cryptorchidism", "q": "A 6-month-old male infant has a right testis that is not palpable in the scrotum but is felt in the inguinal canal and cannot be brought down. What is the appropriate management of undescended testis if it has not descended by this age?", "choices": ["Observation indefinitely", "Hormonal therapy is always curative and definitive", "Immediate orchiectomy", "No intervention is ever needed", "Refer for orchidopexy, typically by 12-18 months"], "ans": 4, "exp": "Cryptorchidism: testis ส่วนใหญ่ลงเองใน 3-6 เดือนแรก; ถ้ายังไม่ลงหลัง 6 เดือน (corrected age) ควรส่งทำ orchidopexy ภายใน 12-18 เดือน เพื่อลดความเสี่ยง infertility และ testicular malignancy และ torsion. Undescended testis เพิ่มความเสี่ยงมะเร็งแม้ทำ orchidopexy แล้ว (แต่ช่วยให้ตรวจคลำได้)"}, {"topic": "Hypospadias", "q": "A newborn boy is found to have the urethral meatus on the ventral surface of the penis with a ventral curvature (chordee). What advice should be given to the parents regarding routine care?", "choices": ["Do not perform circumcision", "Perform circumcision as usual before discharge", "Immediate surgery in the neonatal period", "No follow-up is required", "Catheterize permanently until surgery"], "ans": 0, "exp": "Hypospadias: urethral meatus อยู่ ventral, +/- chordee. 'ห้าม circumcision' เพราะ foreskin จำเป็นสำหรับ surgical repair (urethroplasty) ที่ทำภายหลัง ~6-18 เดือน. ถ้ามี hypospadias + undescended testis ต้องประเมิน disorder of sex development"}, {"topic": "Facial Nerve Palsy", "q": "A newborn delivered by forceps has asymmetric crying: one side of the mouth droops and that eye does not close fully, but the forehead is also involved on the affected side. The rest of the exam is normal. What is the most likely cause?", "choices": ["Central facial palsy from a perinatal cerebral stroke", "Peripheral facial nerve injury from forceps compression", "Erb palsy from upper brachial plexus (C5-C6) injury", "Congenital myasthenia from neuromuscular transmission failure", "Mobius syndrome from bilateral cranial nerve agenesis"], "ans": 1, "exp": "Traumatic peripheral facial nerve palsy จาก forceps/compression: อ่อนแรงครึ่งหน้าข้างเดียว 'รวมหน้าผาก' (peripheral pattern), ตาปิดไม่สนิท, มุมปากตก เห็นชัดตอนร้อง. ส่วนใหญ่หายเองในสัปดาห์-เดือน. ดูแลตา (lubricant) ป้องกัน exposure keratitis. Mobius = bilateral + congenital"}, {"topic": "Clavicle Fracture", "q": "A macrosomic newborn born with shoulder dystocia has decreased movement of one arm and an asymmetric Moro reflex. There is crepitus and tenderness over the clavicle, but the grasp and biceps function are intact. What is the most likely diagnosis?", "choices": ["Erb palsy", "Klumpke palsy", "Clavicle fracture", "Septic arthritis of the shoulder", "Osteogenesis imperfecta"], "ans": 2, "exp": "Clavicle fracture เป็น birth injury ที่พบบ่อยที่สุด สัมพันธ์กับ macrosomia/shoulder dystocia: crepitus/tenderness เหนือ clavicle, decreased arm movement, asymmetric Moro แต่ neurologic function (grasp, biceps) ปกติ (ต่างจาก brachial plexus injury). รักษา conservative (gentle handling); หายเองดี มี callus"}, {"topic": "Small for Gestational Age", "q": "A term infant is born with a birth weight below the 10th percentile for gestational age with asymmetric growth restriction (relatively spared head circumference). Which maternal/placental factor most likely explains this pattern?", "choices": ["A first-trimester chromosomal abnormality", "Congenital TORCH infection in early pregnancy", "Constitutional (familial) small size", "Uteroplacental insufficiency in late pregnancy", "Gestational diabetes"], "ans": 3, "exp": "Asymmetric IUGR/SGA (head spared, weight ลดมาก) มักจาก uteroplacental insufficiency ในช่วงหลังของการตั้งครรภ์ (เช่น preeclampsia/HT) → brain-sparing. Symmetric IUGR (ทุกส่วนเล็กเท่ากัน) เกิดจาก insult ตั้งแต่ early pregnancy (chromosomal, TORCH). SGA เสี่ยง hypoglycemia, polycythemia, hypothermia"}, {"topic": "Post-term Complications", "q": "An infant born at 42+ weeks of gestation has dry, peeling, cracked skin, long nails, decreased subcutaneous fat, and meconium-stained skin. What complication is this post-term infant at increased risk for?", "choices": ["Respiratory distress syndrome from surfactant deficiency", "Congenital hypothyroidism", "Necrotizing enterocolitis", "Retinopathy of prematurity", "Meconium aspiration and hypoglycemia"], "ans": 4, "exp": "Post-term (post-maturity) infant: dysmaturity (peeling skin, long nails, ลด subcutaneous fat), meconium staining. เสี่ยง meconium aspiration, hypoglycemia (glycogen store หมด), polycythemia, และ perinatal asphyxia จาก placental insufficiency. RDS/ROP เป็นปัญหาของ preterm ตรงข้ามกัน"}, {"topic": "Erb Palsy Management", "q": "A newborn with Erb-Duchenne palsy (C5-C6) from birth is being managed. What is the most appropriate initial management for most cases?", "choices": ["Gentle physiotherapy with observation for recovery", "Immediate nerve grafting surgery in the neonatal period", "Complete immobilization of the affected arm for six months", "High-dose corticosteroids to reduce nerve inflammation", "Surgical amputation if there is no movement at birth"], "ans": 0, "exp": "Erb palsy ส่วนใหญ่ (neurapraxia) ฟื้นเองได้ภายในไม่กี่สัปดาห์-เดือน. Initial management คือ gentle physiotherapy/ROM exercises (เริ่มหลัง 1-2 สัปดาห์) เพื่อป้องกัน contracture และเฝ้าดูการฟื้นตัว. Surgery (nerve reconstruction) พิจารณาเมื่อไม่ฟื้นภายใน 3-6 เดือน"}, {"topic": "Neonatal Pneumonia", "q": "A term infant born after prolonged rupture of membranes develops respiratory distress with grunting and requires oxygen at 6 hours. Chest radiograph shows bilateral patchy infiltrates. Blood culture is pending. What is the most appropriate management?", "choices": ["Exogenous surfactant alone without antibacterial cover", "Empiric ampicillin plus gentamicin and respiratory support", "Nebulized racemic epinephrine to relieve the distress", "Careful observation without antibiotics for 48 hours", "Oral antibiotics with early discharge and follow-up"], "ans": 1, "exp": "Congenital/early-onset neonatal pneumonia (มัก GBS, gram-negative) สัมพันธ์กับ PROM/chorioamnionitis: respiratory distress + patchy infiltrate. รักษาเหมือน early-onset sepsis: blood culture แล้ว empiric ampicillin + gentamicin + respiratory support. อาการอาจแยกจาก RDS/TTN ยาก จึงมักครอบคลุมเชื้อไว้ก่อน"}, {"topic": "Single Umbilical Artery", "q": "On examining the umbilical cord of a newborn, only two vessels are found (one artery and one vein) instead of the usual three. What is the appropriate consideration?", "choices": ["Immediate surgical exploration of the umbilical vessels", "Reassurance that the finding has no clinical significance", "Examination and renal ultrasound for associated anomalies", "Prophylactic antibiotics to prevent umbilical infection", "Exchange transfusion to correct a presumed hematologic problem"], "ans": 2, "exp": "Single umbilical artery (2-vessel cord) อาจสัมพันธ์กับ congenital anomalies โดยเฉพาะ renal/genitourinary และบางครั้ง cardiac/chromosomal. แนะนำตรวจร่างกายละเอียด และพิจารณา renal ultrasound. ถ้าไม่มี anomaly อื่น prognosis ดี"}, {"topic": "Neonatal Listeriosis", "q": "A newborn born to a mother who ate unpasteurized cheese and had a flu-like illness presents with early-onset sepsis, respiratory distress, and a disseminated granulomatous rash. Which organism should empiric therapy specifically cover?", "choices": ["Pseudomonas aeruginosa", "Mycobacterium tuberculosis", "Candida albicans", "Listeria monocytogenes", "Bordetella pertussis"], "ans": 3, "exp": "Congenital listeriosis (granulomatosis infantiseptica): early-onset sepsis + disseminated granulomas/rash, จากแม่กิน unpasteurized dairy/deli. Listeria monocytogenes ถูกครอบคลุมด้วย 'ampicillin' (ซึ่งเป็นเหตุผลหนึ่งที่ empiric neonatal sepsis ใช้ ampicillin + gentamicin; cephalosporins ไม่ครอบคลุม Listeria)"}, {"topic": "Prematurity Classification", "q": "A neonate is born at 33 weeks of gestation. According to the World Health Organization classification by gestational age, this infant is categorized as which of the following?", "choices": ["Extremely preterm (less than 28 weeks of gestation)", "Very preterm (28 to under 32 weeks of gestation)", "Term gestation (37 to 42 completed weeks)", "Post-term gestation (42 weeks or more)", "Moderate to late preterm (32 to under 37 weeks)"], "ans": 4, "exp": "WHO classification by GA: extremely preterm (<28 wk), very preterm (28 ถึง <32 wk), moderate to late preterm (32 ถึง <37 wk). ทารก 33 สัปดาห์จึงเป็น 'moderate to late preterm'. Term = 37-42 wk, post-term ≥42 wk. Late preterm (34-36+6) ก็ยังเสี่ยง feeding, jaundice, respiratory, hypothermia"}, {"topic": "Umbilical Granuloma", "q": "After the umbilical cord separates, a newborn is noted to have a small, moist, pink-red pedunculated nodule at the umbilicus with scant serous discharge but no surrounding cellulitis or feculent/urinary drainage. What is the appropriate management?", "choices": ["Application of silver nitrate to the granuloma", "Urgent surgical exploration for a patent urachus", "Broad-spectrum intravenous antibiotics", "Exchange transfusion", "No follow-up needed; it is malignant tissue"], "ans": 0, "exp": "Umbilical granuloma: เนื้อ granulation สีชมพูแดงชื้นที่สะดือหลัง cord หลุด ไม่มี cellulitis. รักษาด้วย silver nitrate cautery (หรือ salt application). ต้องแยกจาก umbilical polyp (omphalomesenteric/urachal remnant), feculent discharge (patent vitelline duct), หรือ urine (patent urachus) ที่ต้องผ่าตัด และ omphalitis (cellulitis) ที่ต้อง IV antibiotics"}, {"topic": "Neonatal Tetralogy Cyanosis", "q": "A newborn has a cyanotic congenital heart lesion. The hyperoxia test is performed: after giving 100% oxygen, the arterial PaO2 remains low (fails to rise substantially). What does this finding suggest?", "choices": ["Primary parenchymal lung disease as the sole cause", "Cyanotic congenital heart disease with right-to-left shunt", "Methemoglobinemia from an oxidizing agent exposure", "Entirely normal transitional newborn physiology", "Severe anemia reducing oxygen-carrying capacity"], "ans": 1, "exp": "Hyperoxia test: ให้ 100% O2 แล้ววัด PaO2. ถ้า PaO2 ไม่ขึ้น (ยังต่ำ, มัก <100-150) แสดงว่า cyanosis จาก right-to-left shunt ของ 'cyanotic CHD' (เลือดข้าม lung ไป). ถ้า PaO2 ขึ้นดี = pulmonary/parenchymal cause. ช่วยแยกสาเหตุ cyanosis ในทารก"}, {"topic": "SGA Hypoglycemia Prevention", "q": "A small-for-gestational-age term newborn is at risk for hypoglycemia. Which is the most appropriate strategy in the first hours of life for an asymptomatic at-risk infant?", "choices": ["Withhold all feeds for 12 hours", "Prophylactic intravenous insulin", "Early and frequent feeding with routine glucose monitoring", "Immediate exchange transfusion", "High-dose oral glucose bolus every hour regardless of levels"], "ans": 2, "exp": "ทารก SGA/at-risk ที่ยังไม่มีอาการ: ป้องกัน hypoglycemia ด้วย early feeding (ภายใน 1 ชม.) frequent feeds + routine glucose monitoring ตาม protocol. ถ้า glucose ต่ำแม้ feeding หรือมีอาการ → IV dextrose. ไม่ให้ insulin, ไม่งดนม"}, {"topic": "Congenital Varicella", "q": "A newborn whose mother developed a chickenpox rash 3 days before delivery is at highest risk for severe neonatal varicella. What is the recommended intervention for the infant?", "choices": ["Immediate measles-mumps-rubella vaccination of the infant", "A course of oral prednisolone to blunt the infection", "No intervention regardless of the timing of exposure", "Varicella-zoster immunoglobulin with acyclovir if disease develops", "Exchange transfusion to remove circulating virus"], "ans": 3, "exp": "ถ้าแม่เป็น varicella ในช่วง 5 วันก่อน ถึง 2 วันหลังคลอด ทารกเสี่ยง severe neonatal varicella (ยังไม่ได้ maternal antibody ทัน). ให้ VZIG แก่ทารกเพื่อป้องกัน/ลดความรุนแรง และให้ IV acyclovir ถ้าเกิดโรค. ต่างจาก congenital varicella syndrome (limb hypoplasia, scarring) ที่เกิดจากติดเชื้อช่วงต้นครรภ์"}, {"topic": "Phototherapy Mechanism", "q": "Phototherapy is started for a jaundiced term newborn with unconjugated hyperbilirubinemia. By what mechanism does phototherapy lower the bilirubin level?", "choices": ["It increases hepatic conjugation enzyme synthesis", "It destroys red blood cells to reduce production", "It binds bilirubin in the gut to block absorption", "It stimulates renal tubular secretion of unconjugated bilirubin", "It converts bilirubin to water-soluble isomers that are excreted without conjugation"], "ans": 4, "exp": "Phototherapy (blue light ~460 nm) เปลี่ยน unconjugated bilirubin ที่ผิวหนังเป็น water-soluble photoisomers (structural isomer 'lumirubin' + configurational isomer) ที่ขับออกทาง bile/urine ได้โดยไม่ต้องผ่าน hepatic conjugation. ใช้กับ unconjugated hyperbilirubinemia; 'ห้าม' ใช้เดี่ยวใน conjugated (direct) hyperbilirubinemia เพราะเกิด 'bronze baby'"}, {"topic": "Neonatal Conjunctivitis Prophylaxis", "q": "Which agent is commonly applied to the eyes of all newborns shortly after birth to prevent gonococcal ophthalmia neonatorum?", "choices": ["Erythromycin eye ointment", "Topical acyclovir", "Silver nitrate at high concentration for HSV", "Topical gentamicin", "Topical corticosteroid"], "ans": 0, "exp": "Ocular prophylaxis แรกเกิดด้วย erythromycin 0.5% eye ointment (แทน silver nitrate เดิมที่ทำให้ chemical conjunctivitis) ป้องกัน gonococcal ophthalmia neonatorum. ไม่ป้องกัน chlamydial conjunctivitis ได้ดี. การป้องกันที่ดีที่สุดคือ antenatal screening/treatment ของแม่"}, {"topic": "Neonatal RDS vs TTN", "q": "Two newborns both have early tachypnea. Infant A was born at 30 weeks and worsens over hours needing surfactant; infant B was born at 39 weeks by elective cesarean and improves by 24-48 hours. Which statement best distinguishes their conditions?", "choices": ["Both are caused by surfactant deficiency", "RDS results from surfactant deficiency and tends to worsen", "TTN typically requires surfactant and mechanical ventilation", "RDS is more common in post-term infants", "TTN characteristically shows a ground-glass pattern with air bronchograms"], "ans": 1, "exp": "RDS: preterm, surfactant deficiency, worsens over first hours, CXR ground-glass + air bronchograms, ต้องการ surfactant/support. TTN: term (มัก elective C/S), retained fetal lung fluid, self-limited หายใน 24-72 ชม., CXR perihilar streaking/fluid in fissure. Gestational age และ course ช่วยแยก"}, {"topic": "Breastfeeding Failure Jaundice", "q": "A 3-day-old exclusively breastfed newborn has jaundice, has lost 11% of birth weight, has fewer than 3 wet diapers per day, and appears mildly dehydrated. Total bilirubin is elevated and unconjugated. What is the most appropriate management?", "choices": ["Permanently switch to formula and stop all breast milk", "Restrict the infant's fluid intake to lower bilirubin", "Support effective breastfeeding and phototherapy per nomogram", "Start ursodeoxycholic acid to promote bile flow", "Reassure and take no action despite the weight loss"], "ans": 2, "exp": "Breastfeeding (failure) jaundice เกิดเร็ว (วันที่ 2-4) จากได้นมไม่พอ → dehydration + ลด enterohepatic clearance ของ bilirubin. รักษาโดยเพิ่ม 'effective' breastfeeding (lactation support, feed บ่อยขึ้น), ประเมิน/แก้ hydration, และ phototherapy ตาม bilirubin nomogram ถ้าถึงเกณฑ์. ไม่ใช่การหยุดนมแม่ถาวรหรือจำกัดน้ำ"}, {"topic": "Maple Syrup Urine Disease", "q": "A term newborn, well at birth, develops poor feeding, lethargy, and abnormal tone/opisthotonus in the first week, and the urine has a sweet, caramel/maple-syrup odor. Which metabolic disorder is most likely?", "choices": ["Phenylketonuria", "Galactosemia", "Congenital hypothyroidism", "Maple syrup urine disease", "Biotinidase deficiency"], "ans": 3, "exp": "Maple syrup urine disease (MSUD): defect ใน branched-chain alpha-ketoacid dehydrogenase → สะสม leucine/isoleucine/valine, ปัสสาวะกลิ่นน้ำเชื่อม (maple syrup). อาการในสัปดาห์แรก: poor feeding, lethargy, opisthotonus, encephalopathy. รักษา: จำกัด branched-chain amino acids, dialysis ในภาวะวิกฤต. ตรวจพบได้จาก expanded newborn screening"}, {"topic": "Down Syndrome Recognition", "q": "A newborn has hypotonia, upslanting palpebral fissures, a flat nasal bridge, a single transverse palmar crease, a sandal gap between the first and second toes, and a systolic murmur. Which is the most appropriate next step?", "choices": ["Reassurance that these are normal newborn variants", "Empiric levothyroxine without any confirmatory testing", "Immediate surgical intervention for the dysmorphic features", "Exchange transfusion to treat a presumed hemolytic process", "Chromosome analysis and echocardiography for heart disease"], "ans": 4, "exp": "ลักษณะ dysmorphic (hypotonia, upslanting palpebral fissures, flat nasal bridge, single palmar crease, sandal gap) + murmur = สงสัย Down syndrome (trisomy 21). ยืนยันด้วย karyotype และประเมิน congenital heart disease (พบ ~40-50%, เช่น AVSD, VSD) ด้วย echocardiogram. Down สัมพันธ์กับ duodenal atresia, Hirschsprung, hypothyroidism, leukemia ด้วย"}]}, {"id": "ped-2", "title": "กุมารเวชศาสตร์ ชุดที่ 2 — Growth/Development/Nutrition/Genetics/Vaccines", "subject": "ped", "questions": [{"topic": "Developmental Milestones", "q": "A mother brings her 6-month-old infant for a well-child visit. Which of the following is the expected gross motor milestone for a typically developing 6-month-old?", "choices": ["Sits without support and rolls over", "Walks independently", "Runs and climbs stairs", "Pincer grasp of small objects", "Speaks in two-word phrases"], "ans": 0, "exp": "6 เดือน: นั่งได้เอง (หรือเกือบเอง), พลิกคว่ำพลิกหงาย, เอื้อมคว้าของ, ส่งของมือหนึ่งไปอีกมือ, babble. Walk independently ~12 เดือน, pincer grasp ~9-12 เดือน, two-word phrases ~24 เดือน. การรู้ milestones ช่วย screen developmental delay"}, {"topic": "Developmental Milestones", "q": "At which age does a typically developing child usually begin to walk independently (take a few steps alone)?", "choices": ["6 months", "12 months", "9 months", "18 months", "24 months"], "ans": 1, "exp": "เดินได้เอง (independent walking) โดยเฉลี่ย ~12 เดือน (ช่วงปกติ 9-15 เดือน). ถ้ายังไม่เดินเมื่ออายุ 18 เดือนถือว่าผิดปกติ ต้องประเมิน. milestones อื่น: cruise ~9-11 เดือน, run ~18 เดือน, ขึ้นบันได ~2 ปี"}, {"topic": "Developmental Milestones", "q": "A 2-year-old child is brought for evaluation. Which language milestone is expected at 24 months of age?", "choices": ["Speaks in full grammatical sentences of five to six words", "Says only 'mama' and 'dada' without specific meaning", "Uses two-word phrases with a vocabulary near fifty words", "Names all of the primary colors correctly on request", "Tells a coherent multi-sentence story about an event"], "ans": 2, "exp": "24 เดือน: พูดวลี 2 คำ (two-word phrases), vocabulary ~50 คำ, ทำตามคำสั่ง 2 ขั้น, ชี้ส่วนของร่างกาย. คำเดี่ยวแรก ~12 เดือน. Red flag: ไม่มีคำเดี่ยวที่ 16 เดือน หรือไม่มี two-word phrases ที่ 24 เดือน → ประเมิน hearing และ developmental/autism"}, {"topic": "Developmental Delay", "q": "A 10-month-old infant cannot sit without support, does not reach for objects, and has persistent fisting of the hands. What is the most appropriate next step?", "choices": ["Reassure; this is within normal limits", "Recheck in 1 year without intervention", "Start empiric physiotherapy without evaluation and no diagnosis", "Refer for developmental evaluation and assess for cerebral palsy", "Order a brain MRI as the only action"], "ans": 3, "exp": "ที่ 10 เดือนควรนั่งเองได้และเอื้อมคว้าของ. ไม่สามารถนั่ง + persistent fisting (ปกติ fisting หายไปที่ 3-4 เดือน) + ไม่เอื้อมของ = motor delay + abnormal tone → red flags ของ cerebral palsy/neuromuscular. ต้องส่งประเมิน developmental และหาสาเหตุ (รวม early intervention)"}, {"topic": "Primitive Reflexes", "q": "The Moro reflex is normally present at birth. Persistence of the Moro reflex beyond which age is considered abnormal and may indicate a neurologic problem?", "choices": ["2 weeks", "12 months", "18 months", "24 months", "6 months"], "ans": 4, "exp": "Moro reflex ปกติมีแรกเกิดและหายไปประมาณ 5-6 เดือน. การคงอยู่ >6 เดือน (persistent primitive reflex) ผิดปกติ บ่งชี้ CNS problem (เช่น cerebral palsy). Primitive reflexes อื่น: palmar grasp หาย ~5-6 เดือน, ATNR หาย ~4-6 เดือน. Parachute reflex ปรากฏ ~9 เดือน"}, {"topic": "Growth - Failure to Thrive", "q": "A 9-month-old infant's weight has fallen from the 50th percentile to below the 3rd percentile over several months, while length and head circumference are relatively preserved. The child appears thin. What is the most common cause of failure to thrive in this age group?", "choices": ["Inadequate caloric intake", "Growth hormone deficiency", "Congenital hypothyroidism", "Chromosomal abnormality", "Chronic kidney disease"], "ans": 0, "exp": "Failure to thrive (FTT) ที่ weight ตกก่อน length/head circumference (ลำดับ weight → length → head) มักเป็น 'inadequate caloric intake' (non-organic/feeding issues พบบ่อยที่สุด). สาเหตุ organic (malabsorption, chronic disease) พบน้อยกว่า. ประเมิน feeding history, psychosocial, และ growth pattern เป็นหลัก"}, {"topic": "Growth Parameters", "q": "A healthy term infant is expected to double the birth weight by approximately what age?", "choices": ["1 month", "4-6 months", "2 months", "12 months", "18 months"], "ans": 1, "exp": "Rule of thumb การเจริญเติบโต: น้ำหนักเพิ่มเป็น 2 เท่าของแรกเกิด ~4-6 เดือน, 3 เท่า ~12 เดือน, 4 เท่า ~2 ปี. ความยาวเพิ่ม ~50% ที่ 12 เดือน. Head circumference เพิ่ม ~1 ซม./เดือนในปีแรก. ใช้ประเมิน growth ปกติ"}, {"topic": "Short Stature", "q": "A 4-year-old boy is significantly shorter than peers. His growth velocity is normal, his bone age equals his chronological age, and his predicted adult height is consistent with his mid-parental (target) height. His father was also a short adult. What is the most likely diagnosis?", "choices": ["Growth hormone deficiency", "Constitutional delay of growth and puberty", "Familial short stature", "Hypothyroidism", "Turner syndrome"], "ans": 2, "exp": "Familial short stature: เตี้ยแต่ growth velocity ปกติ, bone age = chronological age, predicted height ตรงกับ target (mid-parental) height, มีประวัติครอบครัวเตี้ย. ต่างจาก constitutional delay (bone age 'ล่าช้า' กว่า chronological, puberty มาช้า, สุดท้ายสูงปกติ) และจาก pathologic (GH deficiency, hypothyroid) ที่ growth velocity 'ลดลง'"}, {"topic": "Short Stature", "q": "A 3-year-old girl has short stature with a low growth velocity, a webbed neck, widely spaced nipples, and lymphedema of the hands and feet noted in infancy. What is the most likely diagnosis?", "choices": ["Down syndrome", "Familial short stature", "Growth hormone deficiency", "Turner syndrome", "Noonan syndrome"], "ans": 3, "exp": "Turner syndrome (45,X): short stature, webbed neck, widely spaced nipples/shield chest, lymphedema แรกเกิด, cubitus valgus, gonadal dysgenesis (primary amenorrhea), coarctation/bicuspid aortic valve, horseshoe kidney. ยืนยันด้วย karyotype. รักษา: GH (เพิ่มความสูง) + estrogen (puberty). Noonan คล้ายแต่ karyotype ปกติและมี pulmonary stenosis"}, {"topic": "Precocious Puberty", "q": "A 6-year-old girl develops breast budding and pubic hair with accelerated growth and an advanced bone age. Which finding would point to central (GnRH-dependent) precocious puberty?", "choices": ["Suppressed LH and FSH", "A unilateral adrenal mass", "Isolated pubic hair with no other signs", "Normal bone age", "Elevated LH response to GnRH stimulation"], "ans": 4, "exp": "Central (GnRH-dependent) precocious puberty: HPG axis ทำงานก่อนวัย → pubertal LH response ต่อ GnRH stimulation (LH สูง), bone age advanced, มักไม่พบสาเหตุในเด็กหญิง (idiopathic) แต่ต้อง MRI brain แยก CNS lesion. Peripheral (GnRH-independent) จะ LH/FSH suppressed จาก autonomous sex steroid (adrenal/gonadal/exogenous)"}, {"topic": "Delayed Puberty", "q": "A 14-year-old boy has no signs of puberty (testicular volume <4 mL). He is otherwise healthy with a family history of 'late bloomers,' and his bone age is delayed relative to chronological age. What is the most likely diagnosis?", "choices": ["Constitutional delay of growth and puberty", "Klinefelter syndrome with small firm testes", "Kallmann syndrome with anosmia and low gonadotropins", "Panhypopituitarism from a pituitary lesion", "Testicular failure following chemotherapy exposure"], "ans": 0, "exp": "Constitutional delay of growth and puberty (CDGP): เด็ก (มักชาย) เข้าสู่ puberty ช้า, bone age delayed, มีประวัติครอบครัว 'late bloomer', สุดท้าย puberty และความสูงปกติ. เป็นสาเหตุที่พบบ่อยที่สุดของ delayed puberty. ต่างจาก Kallmann (hypogonadotropic + anosmia) และ Klinefelter (small firm testes, 47,XXY)"}, {"topic": "Malnutrition - Kwashiorkor", "q": "A 2-year-old child from a food-insecure setting presents with generalized edema, a distended abdomen, sparse depigmented hair, skin desquamation, and hepatomegaly, but is not severely wasted. What is the diagnosis?", "choices": ["Marasmus", "Kwashiorkor", "Nephrotic syndrome", "Beriberi", "Scurvy"], "ans": 1, "exp": "Kwashiorkor: severe protein malnutrition ทั้งๆ ที่ energy อาจพอ → edema (จาก hypoalbuminemia), hepatomegaly (fatty liver), skin/hair changes (flaky paint dermatosis, depigmented hair), apathy. ต่างจาก marasmus (severe wasting ทั้ง energy+protein, 'skin and bones', ไม่มี edema). Refeeding ต้องระวัง refeeding syndrome"}, {"topic": "Malnutrition - Marasmus", "q": "A 1-year-old child presents with severe wasting, loss of subcutaneous fat and muscle, a wizened 'old man' facies, and weight far below expected, without edema. What is the diagnosis?", "choices": ["Kwashiorkor", "Marasmic-kwashiorkor", "Marasmus", "Congenital hypothyroidism", "Cystic fibrosis"], "ans": 2, "exp": "Marasmus: severe deficiency ทั้ง energy และ protein → total body wasting, loss ของ subcutaneous fat/muscle, 'old man' face, ไม่มี edema (ต่างจาก kwashiorkor). Weight-for-height ต่ำมาก. รักษา: gradual refeeding ระวัง hypoglycemia, hypothermia, infection, refeeding syndrome"}, {"topic": "Vitamin A Deficiency", "q": "A child in a developing region presents with night blindness, dry conjunctiva with Bitot spots, and corneal xerosis. Which vitamin deficiency is responsible?", "choices": ["Vitamin D", "Vitamin C", "Vitamin B1 (thiamine)", "Vitamin A", "Vitamin K"], "ans": 3, "exp": "Vitamin A deficiency: night blindness (nyctalopia) เป็นอาการแรก, ตามด้วย xerophthalmia (conjunctival xerosis, Bitot spots, corneal xerosis/keratomalacia → ตาบอด), และเพิ่มความเสี่ยง/ความรุนแรงของ measles และ infection. รักษา/ป้องกันด้วย vitamin A supplementation (โดยเฉพาะร่วมกับ measles)"}, {"topic": "Vitamin D Deficiency - Rickets", "q": "A 14-month-old exclusively breastfed toddler with little sun exposure has bowing of the legs, widening of the wrists, a rachitic rosary, and delayed closure of the fontanelle. X-rays show cupping and fraying of the metaphyses. Which lab pattern is expected?", "choices": ["High calcium, high phosphate, and low alkaline phosphatase", "Entirely normal calcium, phosphate, and vitamin D studies", "Low calcium with high phosphate and a suppressed PTH", "A markedly elevated 25-hydroxy vitamin D level", "Low calcium, low phosphate, high ALP, low vitamin D"], "ans": 4, "exp": "Nutritional rickets จาก vitamin D deficiency: bowing legs, wrist widening, rachitic rosary, frontal bossing, metaphyseal cupping/fraying. Labs: 25-OH vitamin D ต่ำ, phosphate ต่ำ, alkaline phosphatase สูง, PTH สูง (secondary hyperparathyroidism), calcium ต่ำ/ปกติ. ป้องกันด้วย vitamin D supplement ในทารกกินนมแม่ล้วน"}, {"topic": "Vitamin C Deficiency - Scurvy", "q": "A toddler with a very restricted diet presents with irritability, bleeding swollen gums, perifollicular hemorrhages, poor wound healing, and pain on movement of the legs from subperiosteal hemorrhage. Which deficiency is this?", "choices": ["Vitamin C (ascorbic acid) deficiency causing scurvy", "Vitamin A deficiency causing night blindness", "Vitamin B12 deficiency causing megaloblastic anemia", "Vitamin D deficiency causing nutritional rickets", "Folate deficiency causing megaloblastic anemia"], "ans": 0, "exp": "Scurvy (vitamin C deficiency): impaired collagen synthesis → bleeding gums, perifollicular hemorrhage, corkscrew hairs, poor wound healing, subperiosteal hemorrhage (ปวดขา 'pseudoparalysis'), anemia. รักษาด้วย vitamin C supplementation. พบในเด็กที่กินอาหารจำกัดมาก (เช่น autism/selective eating)"}, {"topic": "Iron Deficiency Anemia", "q": "A 15-month-old toddler who drinks large volumes of cow's milk (>700 mL/day) and eats few solids has pallor and mild fatigue. CBC shows microcytic hypochromic anemia with low ferritin. What is the most appropriate management?", "choices": ["Packed red blood cell transfusion for the anemia", "Oral iron therapy and reduction of cow's milk intake", "Intramuscular vitamin B12 replacement injections", "Increasing cow's milk intake to improve nutrition", "Bone marrow biopsy to evaluate for marrow failure"], "ans": 1, "exp": "Iron deficiency anemia ในเด็กวัยเตาะแตะ มักจากดื่มนมวัวมากเกิน (>500-700 mL/day; นมวัว iron ต่ำ + ทำให้ occult GI blood loss + อิ่มจนกินอาหารอื่นน้อย). Microcytic hypochromic + ferritin ต่ำ. รักษา: oral iron + ลดนมวัว + เพิ่มอาหาร iron-rich. ป้องกันได้ จึงเป็น high-yield"}, {"topic": "Immunization Schedule - BCG", "q": "In Thailand's Expanded Program on Immunization (EPI), which vaccine is routinely given to newborns at birth to protect against severe forms of tuberculosis?", "choices": ["MMR vaccine", "DTP vaccine", "BCG vaccine", "Rotavirus vaccine", "Varicella vaccine"], "ans": 2, "exp": "BCG (Bacille Calmette-Guerin) ให้แรกเกิดในโปรแกรม EPI ของไทย ป้องกัน severe TB (miliary TB, TB meningitis) ในเด็ก. Hepatitis B dose แรกก็ให้แรกเกิด. MMR ให้ ~9-12 เดือน, DTP เริ่ม 2 เดือน. เป็น live vaccine จึงเลี่ยงในผู้มี severe immunodeficiency"}, {"topic": "Immunization - Live Vaccine Contraindication", "q": "A 12-month-old child with a known severe combined immunodeficiency (SCID) is due for routine vaccines. Which vaccine is contraindicated?", "choices": ["Inactivated hepatitis B vaccine", "Diphtheria-tetanus toxoid", "Inactivated polio vaccine (IPV)", "MMR (live attenuated vaccine)", "Pneumococcal conjugate vaccine"], "ans": 3, "exp": "Live attenuated vaccines (MMR, BCG, oral polio, varicella, rotavirus, live influenza) 'ห้าม' ในผู้ที่มี severe immunodeficiency (SCID, ผู้ได้ immunosuppression สูง) เพราะเสี่ยง disseminated vaccine-strain disease. Inactivated/subunit vaccines (hepatitis B, DTP, IPV, PCV) ปลอดภัย (แต่ response อาจลด). Live vaccine ก็เลี่ยงในหญิงตั้งครรภ์"}, {"topic": "Immunization - Egg Allergy", "q": "The parents of a child with a mild egg allergy are worried about vaccines. Regarding routine vaccination, which statement is correct?", "choices": ["MMR is absolutely contraindicated in any egg allergy", "All vaccines must be avoided in egg allergy", "Egg-allergic children can never receive influenza vaccine", "Egg allergy requires lifelong vaccine deferral", "MMR vaccine can be given routinely even to egg-allergic children"], "ans": 4, "exp": "MMR ปลูกใน chick fibroblast culture (ไม่ใช่ไข่) จึงให้ได้ตามปกติแม้แพ้ไข่ (ไม่ contraindicated). Influenza vaccine ปัจจุบันก็ให้ได้ในผู้แพ้ไข่ (อาจสังเกตอาการ). Contraindication จริงของ vaccine คือ anaphylaxis ต่อ vaccine component/dose ก่อนหน้า, ไม่ใช่ egg allergy ทั่วไป"}, {"topic": "Vaccine Timing - MMR", "q": "According to typical schedules (including Thailand), at what age is the first dose of measles-containing vaccine (MMR) usually given?", "choices": ["9-12 months", "At birth", "2 months", "4 years only", "6 weeks"], "ans": 0, "exp": "MMR dose แรกให้ ~9-12 เดือน (ไทยให้ ~9-12 เดือน และ booster ~2.5 ปี หรือช่วงเข้าเรียน). ให้ตอนนี้เพราะ maternal antibody ลดลงพอที่วัคซีนจะกระตุ้นภูมิได้. ในสถานการณ์ระบาดอาจให้เร็วขึ้น (6-9 เดือน) แต่ต้อง revaccinate ตามตาราง"}, {"topic": "Down Syndrome Complications", "q": "A child with trisomy 21 (Down syndrome) is being followed. Which associated condition should be screened for given its increased incidence in this population?", "choices": ["Cystic fibrosis with pancreatic insufficiency", "Congenital heart disease, hypothyroidism, and leukemia", "Duchenne muscular dystrophy with an elevated CK", "Sickle cell disease with vaso-occlusive crises", "Marfan syndrome with aortic root dilatation"], "ans": 1, "exp": "Down syndrome สัมพันธ์กับหลายภาวะที่ต้อง screen: congenital heart disease (AVSD/VSD, ~40-50%), hypothyroidism, leukemia (ALL/AML), duodenal atresia, Hirschsprung, atlantoaxial instability, hearing/vision problems, และ early Alzheimer. ต้องมี screening protocol ต่อเนื่อง"}, {"topic": "Fragile X Syndrome", "q": "A boy presents with intellectual disability, a long face with a prominent jaw and large ears, macroorchidism (large testes) after puberty, and autistic behaviors. What is the most likely diagnosis?", "choices": ["Down syndrome", "Klinefelter syndrome", "Fragile X syndrome", "Prader-Willi syndrome", "Williams syndrome"], "ans": 2, "exp": "Fragile X syndrome (CGG repeat expansion ใน FMR1 gene, X-linked): สาเหตุ inherited intellectual disability ที่พบบ่อยที่สุด. ลักษณะ: long face, prominent jaw/forehead, large ears, macroorchidism (หลัง puberty), autism/ADHD, hyperextensible joints. ตรวจ DNA (FMR1)"}, {"topic": "Prader-Willi Syndrome", "q": "An infant initially presented with severe hypotonia and poor feeding requiring tube feeding. By early childhood he develops hyperphagia with rapid weight gain/obesity, short stature, small hands and feet, and hypogonadism. Which mechanism is responsible?", "choices": ["Loss of maternally expressed genes on chromosome 15q", "Trisomy 21 from meiotic nondisjunction of chromosome 21", "45,X monosomy affecting a single X chromosome", "Loss of paternally expressed genes on chromosome 15q", "Fragile X CGG trinucleotide repeat expansion"], "ans": 3, "exp": "Prader-Willi syndrome: ขาด paternal 15q11-13 (deletion จากพ่อ หรือ maternal uniparental disomy) — imprinting disorder. Phase แรก hypotonia + poor feeding (FTT) แล้วเปลี่ยนเป็น hyperphagia → obesity, short stature, small hands/feet, hypogonadism, intellectual disability. ตรงข้าม imprinting คือ Angelman (ขาด maternal 15q)"}, {"topic": "Angelman Syndrome", "q": "A child has severe intellectual disability, absent speech, ataxic 'puppet-like' movements, frequent inappropriate laughter with a happy demeanor, and seizures. This results from loss of maternally expressed genes on chromosome 15q. What is the diagnosis?", "choices": ["Prader-Willi syndrome", "Rett syndrome", "Williams syndrome", "Fragile X syndrome", "Angelman syndrome"], "ans": 4, "exp": "Angelman syndrome ('happy puppet'): ขาด maternal 15q11-13 (deletion/paternal UPD) — imprinting คู่กับ Prader-Willi. ลักษณะ: severe ID, ไม่มี speech, ataxia/jerky movements, inappropriate laughter, seizures, microcephaly. เทียบ imprinting: paternal loss = Prader-Willi, maternal loss = Angelman"}, {"topic": "Williams Syndrome", "q": "A child has an outgoing, overly friendly 'cocktail party' personality, mild intellectual disability, elfin facial features, and supravalvular aortic stenosis. Hypercalcemia may be present. What is the diagnosis?", "choices": ["Williams syndrome", "Down syndrome", "Noonan syndrome", "DiGeorge syndrome", "Turner syndrome"], "ans": 0, "exp": "Williams syndrome (microdeletion 7q11.23 รวม elastin gene): elfin facies, overly friendly/loquacious personality, mild ID, supravalvular aortic stenosis (จาก elastin), idiopathic hypercalcemia. ตรวจด้วย FISH/microarray. เฝ้าระวัง cardiovascular และ calcium"}, {"topic": "DiGeorge Syndrome", "q": "An infant presents with neonatal hypocalcemic seizures, a conotruncal cardiac defect (e.g., truncus arteriosus), recurrent infections from T-cell deficiency, and dysmorphic facies. Which is the underlying defect?", "choices": ["Trisomy 21 causing an atrioventricular septal defect", "22q11.2 microdeletion with thymic and parathyroid hypoplasia", "45,X monosomy with short stature and a webbed neck", "Maternal deletion of chromosome 15q causing Angelman", "Elastin gene deletion on chromosome 7 causing Williams"], "ans": 1, "exp": "DiGeorge/22q11.2 deletion syndrome: CATCH-22 = Cardiac (conotruncal: TOF, truncus, interrupted aortic arch), Abnormal facies, Thymic hypoplasia (T-cell deficiency/infection), Cleft palate, Hypocalcemia (parathyroid hypoplasia). Hypocalcemic seizure ในทารกที่มี cardiac defect ควรนึกถึง. ตรวจ FISH 22q11"}, {"topic": "Achondroplasia", "q": "A child has disproportionate short stature with rhizomelic (proximal) limb shortening, a large head with frontal bossing and midface hypoplasia, and trident hands, with normal intelligence. Inheritance is autosomal dominant (often de novo). What gene is involved?", "choices": ["Fibrillin-1 (FBN1) defect causing connective tissue disease", "Dystrophin deficiency causing progressive myopathy", "FGFR3 (fibroblast growth factor receptor 3) mutation", "Type I collagen (COL1A1) defect causing brittle bones", "NF1 tumor suppressor mutation causing neurofibromas"], "ans": 2, "exp": "Achondroplasia: สาเหตุที่พบบ่อยที่สุดของ disproportionate short-limb dwarfism, autosomal dominant จาก gain-of-function mutation ใน FGFR3 (มัก de novo, สัมพันธ์กับ advanced paternal age). ลักษณะ: rhizomelic shortening, macrocephaly/frontal bossing, midface hypoplasia, trident hand; สติปัญญาปกติ. เฝ้าระวัง foramen magnum stenosis"}, {"topic": "Marfan Syndrome", "q": "A tall adolescent has long thin extremities, arachnodactyly, joint hypermobility, a high-arched palate, pectus deformity, lens dislocation (ectopia lentis), and aortic root dilatation. Which protein is defective?", "choices": ["Type III collagen of blood vessels and hollow organs", "Dystrophin of the skeletal muscle cytoskeleton", "FGFR3 receptor regulating endochondral bone growth", "Fibrillin-1 (FBN1) glycoprotein of connective tissue", "Elastin providing recoil to arteries and skin"], "ans": 3, "exp": "Marfan syndrome: autosomal dominant, defect ใน fibrillin-1 (FBN1). ลักษณะ: tall, arachnodactyly, joint hypermobility, ectopia lentis (superotemporal lens dislocation), aortic root dilatation/dissection (สาเหตุการเสียชีวิตหลัก), MVP. ต้อง echocardiogram เฝ้าระวัง aorta, beta-blocker/ARB ลด aortic dilatation"}, {"topic": "Neurofibromatosis Type 1", "q": "A child has six café-au-lait macules larger than 5 mm, axillary freckling, and a family history of similar findings. Iris hamartomas (Lisch nodules) are seen on slit-lamp exam. What is the diagnosis?", "choices": ["Tuberous sclerosis", "Sturge-Weber syndrome", "McCune-Albright syndrome", "Neurofibromatosis type 2", "Neurofibromatosis type 1"], "ans": 4, "exp": "Neurofibromatosis type 1 (autosomal dominant, NF1 gene): ≥6 café-au-lait macules, axillary/inguinal freckling, neurofibromas, Lisch nodules (iris hamartoma), optic glioma, bony lesions, first-degree relative. เฝ้าระวัง learning disability, scoliosis, hypertension (pheochromocytoma/renal artery). ต่างจาก NF2 (bilateral acoustic neuroma)"}, {"topic": "Tuberous Sclerosis", "q": "An infant with seizures (infantile spasms) has hypopigmented 'ash leaf' macules and later develops facial angiofibromas and a 'shagreen patch.' Brain imaging shows cortical tubers. What is the diagnosis?", "choices": ["Tuberous sclerosis complex", "Neurofibromatosis type 1", "Sturge-Weber syndrome", "Incontinentia pigmenti", "Ataxia-telangiectasia"], "ans": 0, "exp": "Tuberous sclerosis complex (autosomal dominant, TSC1/TSC2): ash-leaf macules (hypopigmented, เห็นด้วย Wood lamp), facial angiofibroma (adenoma sebaceum), shagreen patch, cortical tubers/subependymal nodules, seizures (infantile spasms), cardiac rhabdomyoma, renal angiomyolipoma. Genetic + multidisciplinary surveillance"}, {"topic": "Cow's Milk Protein Allergy", "q": "A 2-month-old formula-fed infant has blood-streaked, mucousy stools, eczema, and irritability but is otherwise thriving. Symptoms resolve when the mother eliminates dairy (if breastfeeding) or the infant is switched to an extensively hydrolyzed formula. What is the diagnosis?", "choices": ["Necrotizing enterocolitis", "Cow's milk protein allergy", "Anal fissure only", "Lactose intolerance", "Hirschsprung disease"], "ans": 1, "exp": "Cow's milk protein allergy (CMPA): non-IgE mediated proctocolitis พบบ่อย — blood/mucus in stool, eczema, fussiness ในทารกที่ยัง thriving. รักษา: หญิงให้นมแม่ตัด dairy/soy จากอาหาร, formula-fed เปลี่ยนเป็น extensively hydrolyzed (หรือ amino acid) formula. ต่างจาก lactose intolerance (enzyme deficiency, ไม่ใช่ allergy, ไม่มีเลือด). ส่วนใหญ่หายเมื่อโตขึ้น"}, {"topic": "Complementary Feeding", "q": "Parents ask when to introduce complementary (solid) foods to their exclusively breastfed infant. What is the recommended age to begin complementary foods while continuing breastfeeding?", "choices": ["At 2 months of age", "At 3 months of age", "Around 6 months of age", "At 12 months of age", "Only after 18 months"], "ans": 2, "exp": "แนะนำเริ่ม complementary food ~6 เดือน (เมื่อ developmental readiness: นั่งได้, head control, สนใจอาหาร) พร้อมนมแม่ต่อ. เริ่มเร็วเกิน (<4 เดือน) เสี่ยง aspiration/allergy/displace milk; ช้าเกินเสี่ยงขาด iron/zinc และ feeding difficulty. เริ่ม iron-rich foods, หลีกเลี่ยง honey (<1 ปี, botulism) และนมวัวเป็น main drink (<1 ปี)"}, {"topic": "Infantile Colic", "q": "A healthy, thriving 4-week-old cries inconsolably for more than 3 hours a day, more than 3 days a week, worse in the evenings. Physical exam and growth are normal. What is the most appropriate management?", "choices": ["Start a proton pump inhibitor", "Switch to intravenous fluids", "Immediate abdominal surgery", "Reassurance and parental support", "Begin phenobarbital"], "ans": 3, "exp": "Infantile colic ('rule of 3s': ร้อง >3 ชม./วัน, >3 วัน/สัปดาห์, >3 สัปดาห์) ในทารกที่สุขภาพดีและ growth ปกติ, เป็น diagnosis of exclusion. รักษาหลักคือ reassurance + parental support + soothing techniques; หายเองมัก 3-4 เดือน. ต้องแยก organic causes (hernia, corneal abrasion, CMPA) ก่อน"}, {"topic": "Childhood Obesity", "q": "A 10-year-old child has a BMI at the 97th percentile for age and sex. Which is the most appropriate first-line management?", "choices": ["Bariatric (weight-loss) surgery as the first option", "Immediate weight-loss pharmacotherapy for every child", "Severe caloric restriction with a near-starvation diet", "No intervention until the child reaches adulthood", "Family-based lifestyle intervention with diet and activity"], "ans": 4, "exp": "Childhood obesity (BMI ≥95th percentile). First-line คือ family-based lifestyle intervention: healthy diet, เพิ่ม physical activity (≥60 นาที/วัน), ลด screen time และ sugary drinks. ประเมิน comorbidities (T2DM, dyslipidemia, NAFLD, OSA, hypertension). Pharmacotherapy/surgery สงวนไว้กรณี severe/complicated ในวัยรุ่น"}, {"topic": "Rotavirus Vaccine", "q": "The rotavirus vaccine is an oral live vaccine given in infancy. Which historical adverse event requires attention to the timing/age limits of administration?", "choices": ["Intussusception", "Necrotizing enterocolitis", "Febrile seizures", "Anaphylaxis to egg", "Guillain-Barre syndrome"], "ans": 0, "exp": "Rotavirus vaccine (oral, live) มีความเสี่ยง 'intussusception' เพิ่มเล็กน้อย จึงกำหนดอายุเริ่ม (dose แรกก่อน 15 สัปดาห์) และให้เสร็จก่อน 8 เดือน และ contraindicated ในเด็กที่มีประวัติ intussusception หรือ uncorrected intestinal malformation. ประโยชน์ป้องกัน severe rotavirus gastroenteritis สูงกว่าความเสี่ยง"}, {"topic": "HPV Vaccine", "q": "The HPV vaccine is recommended for adolescents. What is the primary purpose of vaccinating boys and girls before sexual debut?", "choices": ["To prevent hepatitis B infection", "To prevent HPV-related cancers and genital warts", "To treat existing HPV infection", "To prevent herpes simplex infection", "To replace cervical cancer screening entirely"], "ans": 1, "exp": "HPV vaccine ให้ในวัยรุ่น (แนะนำ ~9-14 ปี, ก่อน sexual debut เพื่อ efficacy สูงสุด) ป้องกัน HPV-related cancers (cervical, vulvar, vaginal, anal, penile, oropharyngeal) และ genital warts. เป็น prophylactic (ไม่รักษาการติดเชื้อเดิม). ยังต้อง screen cervical cancer ต่อ"}, {"topic": "Catch-up Immunization", "q": "A healthy 18-month-old child recently immigrated and has no immunization records and no evidence of prior vaccination. What is the most appropriate approach?", "choices": ["Give no vaccines because records are missing", "Wait until age 5 to start vaccines", "Begin a catch-up immunization schedule appropriate for age", "Give only a single MMR and nothing else", "Perform antibody titers for every vaccine before giving any"], "ans": 2, "exp": "เด็กที่ไม่มีหลักฐานการฉีดวัคซีน ถือว่า 'unvaccinated' และเริ่ม catch-up schedule ตามอายุ (ให้หลายชนิดพร้อมกันได้อย่างปลอดภัย). ไม่จำเป็นต้องเริ่มใหม่ทั้งหมดถ้ามีบางเข็ม ('ทุกเข็มที่ให้ไปนับได้'). Serologic testing ทำเฉพาะบางกรณี ไม่ใช่ก่อนทุกวัคซีน"}, {"topic": "Head Circumference - Macrocephaly", "q": "A 4-month-old infant has a head circumference crossing upward across percentiles, a bulging anterior fontanelle, 'sunset' eyes, and a rapidly enlarging head. What is the most appropriate next step?", "choices": ["Reassurance; this is familial macrocephaly", "Start iron supplementation", "Recheck head circumference in 6 months only", "Neuroimaging to evaluate for hydrocephalus", "Begin physiotherapy"], "ans": 3, "exp": "Rapidly increasing head circumference + bulging fontanelle + sunset eyes (จาก increased ICP) = hydrocephalus จนกว่าจะพิสูจน์เป็นอื่น → neuroimaging ด่วน (cranial US ถ้า fontanelle ยังเปิด, หรือ CT/MRI). Benign familial macrocephaly จะโตขนานเส้น percentile และ development ปกติ ไม่มีสัญญาณ ICP สูง"}, {"topic": "Autism Spectrum Screening", "q": "A 20-month-old child does not point to show interest, does not respond to his name, avoids eye contact, has no single words, and lines up toys repetitively. What is the most appropriate action?", "choices": ["Reassure the parents that boys simply talk later", "Recheck the child's development again at five years", "Start stimulant medication to improve attention", "Advise more screen-based programs to aid learning", "Refer for autism/developmental evaluation and hearing test"], "ans": 4, "exp": "Red flags ของ autism spectrum disorder: ไม่ตอบชื่อ, ไม่ชี้บอก (joint attention), หลบตา, ไม่มีคำพูด, พฤติกรรมซ้ำ (line up toys). ต้องส่งประเมิน developmental/autism และตรวจ hearing (แยก hearing loss). Early intervention ปรับ prognosis. M-CHAT ใช้ screen ที่ 18 และ 24 เดือน"}, {"topic": "Speech Delay - Hearing", "q": "A 2-year-old has no meaningful words and does not follow simple commands. There is a history of recurrent otitis media. What is the most important first investigation?", "choices": ["Formal hearing assessment", "Brain MRI", "Karyotype", "Serum lead level only", "Thyroid function only"], "ans": 0, "exp": "Speech/language delay: การตรวจที่สำคัญที่สุดก่อนคือ 'hearing assessment' เพราะ hearing loss (รวม conductive จาก recurrent OM with effusion) เป็นสาเหตุที่พบบ่อยและแก้ไขได้ของ speech delay. หลังจากนั้นจึงประเมิน developmental/autism และสาเหตุอื่น"}, {"topic": "Mid-Parental Height", "q": "A boy's parents want to estimate his genetic target height. His father is 175 cm and his mother is 160 cm. Using the mid-parental height method for a boy, what is his approximate target height?", "choices": ["About 160 cm", "About 174 cm", "About 185 cm", "About 167 cm", "About 150 cm"], "ans": 1, "exp": "Mid-parental (target) height เด็กชาย = [(father + mother) / 2] + 6.5 ซม. = [(175 + 160)/2] + 6.5 = 167.5 + 6.5 = 174 ซม. (เด็กหญิงลบ 6.5). ช่วง +/- 8.5 ซม. ใช้เทียบกับ predicted height เพื่อประเมินว่า short stature เข้ากับพันธุกรรมหรือไม่"}, {"topic": "Constitutional Growth Delay", "q": "A 13-year-old boy is shorter than peers with delayed puberty. His bone age is 11 years (delayed), growth velocity is normal for bone age, and there is a family history of delayed puberty. What is the expected outcome?", "choices": ["Permanent short stature that requires growth hormone", "A progressive decline across the height percentiles", "Normal final adult height with later-than-average puberty", "Infertility that becomes apparent in adulthood", "Precocious puberty with an advanced bone age"], "ans": 2, "exp": "Constitutional delay of growth and puberty: bone age 'ล่าช้า' (=potential ยังเหลือ), growth velocity ปกติเมื่อเทียบ bone age, ประวัติครอบครัว. Puberty และ growth spurt มาช้ากว่าเพื่อน แต่ 'final adult height ปกติ'. เป็น variant of normal, มักไม่ต้องรักษา (อาจให้ short course testosterone เพื่อ psychosocial)"}, {"topic": "Zinc Deficiency", "q": "An infant develops a periorificial and acral (around mouth, eyes, and on hands/feet) erosive dermatitis, diarrhea, and alopecia, especially after weaning from breast milk. Which deficiency (or the inherited disorder acrodermatitis enteropathica) is responsible?", "choices": ["Vitamin C deficiency", "Niacin deficiency", "Biotin deficiency", "Zinc deficiency", "Vitamin A deficiency"], "ans": 3, "exp": "Zinc deficiency (acquired หรือ acrodermatitis enteropathica ที่ inherited): classic triad = periorificial/acral dermatitis, diarrhea, alopecia. อาจปรากฏหลังหย่านม (breast milk zinc bioavailability สูง). รักษาด้วย zinc supplementation ตอบสนองรวดเร็ว. Zinc ยังสำคัญต่อ growth และ immune function"}, {"topic": "Fluoride and Dental Health", "q": "Regarding prevention of dental caries in young children, which recommendation is appropriate?", "choices": ["Complete avoidance of any fluoride in young children", "A large ribbon of fluoride toothpaste used from birth", "High-dose systemic fluoride tablets for all infants", "Deferring all dental care until permanent teeth erupt", "A rice-grain amount of fluoride toothpaste under age three"], "ans": 4, "exp": "การป้องกัน dental caries: แปรงฟันด้วย fluoride toothpaste ปริมาณ 'smear/rice-grain' (<3 ปี) และ 'pea-size' (3-6 ปี), เริ่มดูแลตั้งแต่ฟันซี่แรกขึ้น, first dental visit ~1 ปี, หลีกเลี่ยง bottle ตอนนอน (nursing bottle caries). Fluoride มากเกินเสี่ยง fluorosis จึงต้องพอเหมาะ"}, {"topic": "Trisomy 18", "q": "A newborn has intrauterine growth restriction, a prominent occiput, micrognathia, clenched hands with overlapping fingers, rocker-bottom feet, and a ventricular septal defect. Most affected infants die within the first year. What is the diagnosis?", "choices": ["Edwards syndrome", "Patau syndrome (trisomy 13)", "Down syndrome (trisomy 21)", "Turner syndrome", "Klinefelter syndrome"], "ans": 0, "exp": "Trisomy 18 (Edwards): IUGR, prominent occiput, micrognathia, clenched hands with overlapping fingers, rocker-bottom feet, congenital heart disease (VSD), มี survival ต่ำ (ส่วนใหญ่เสียชีวิตในปีแรก). Trisomy 13 (Patau) เด่นที่ midline defects (holoprosencephaly, cleft lip/palate, polydactyly)"}, {"topic": "Trisomy 13", "q": "A newborn has holoprosencephaly, cleft lip and palate, microphthalmia, postaxial polydactyly, cutis aplasia of the scalp, and severe congenital heart disease. What is the most likely diagnosis?", "choices": ["Edwards syndrome (trisomy 18)", "Patau syndrome", "Down syndrome", "Cri-du-chat syndrome", "Beckwith-Wiedemann syndrome"], "ans": 1, "exp": "Trisomy 13 (Patau): midline defects — holoprosencephaly, cleft lip/palate, microphthalmia/cyclopia, polydactyly (postaxial), cutis aplasia, severe CHD. Prognosis เลวมาก (ส่วนใหญ่เสียชีวิตในสัปดาห์-เดือนแรก). ตัวเลขจำง่าย: 13 = polydactyly (นิ้วเกิน)"}, {"topic": "Klinefelter Syndrome", "q": "A tall adolescent boy has small firm testes, gynecomastia, sparse body hair, and learning difficulties. Karyotype shows 47,XXY. What is the expected reproductive consequence?", "choices": ["Precocious puberty with early testicular enlargement", "Entirely normal fertility and testosterone production", "Infertility from primary (hypergonadotropic) testicular failure", "Female-appearing external genitalia at birth", "Primary adrenal insufficiency with salt wasting"], "ans": 2, "exp": "Klinefelter syndrome (47,XXY): tall, long limbs, small firm testes, gynecomastia, sparse hair, infertility (primary testicular failure → testosterone ต่ำ, LH/FSH สูง = hypergonadotropic hypogonadism), learning/behavioral issues. สาเหตุ male hypogonadism/infertility ที่พบบ่อย. รักษา testosterone replacement"}, {"topic": "Beckwith-Wiedemann", "q": "A large-for-gestational-age newborn has macroglossia, an omphalocele, hemihypertrophy, and neonatal hypoglycemia. There is an increased risk of embryonal tumors. What is the diagnosis?", "choices": ["Down syndrome", "Prader-Willi syndrome", "Marfan syndrome", "Beckwith-Wiedemann syndrome", "Congenital hypothyroidism"], "ans": 3, "exp": "Beckwith-Wiedemann syndrome (overgrowth, imprinting 11p15): macroglossia, macrosomia, omphalocele/abdominal wall defect, hemihypertrophy, neonatal hypoglycemia (hyperinsulinism). เพิ่มความเสี่ยง embryonal tumors (Wilms tumor, hepatoblastoma) → ต้อง surveillance ด้วย abdominal ultrasound + AFP"}, {"topic": "Osteogenesis Imperfecta", "q": "A child has recurrent fractures with minimal trauma, blue sclerae, hearing loss, and mildly short stature. There is a family history. Which structural protein is defective?", "choices": ["Fibrillin-1", "Dystrophin", "Elastin", "Type IV collagen", "Type I collagen"], "ans": 4, "exp": "Osteogenesis imperfecta ('brittle bone disease'): defect ใน type I collagen (มัก autosomal dominant) → recurrent fractures, blue sclerae, hearing loss (otosclerosis), dentinogenesis imperfecta, joint laxity. Differential ที่สำคัญคือ child abuse (ต้องแยก). รักษา: bisphosphonate, PT, orthopedic care"}, {"topic": "Duchenne Muscular Dystrophy", "q": "A 4-year-old boy has difficulty running and climbing stairs, a waddling gait, and uses his hands to 'climb up' his legs when rising from the floor (Gowers sign). He has enlarged calves and a markedly elevated creatine kinase. What is the inheritance pattern?", "choices": ["X-linked recessive", "Autosomal dominant", "Autosomal recessive", "Mitochondrial", "Trisomy"], "ans": 0, "exp": "Duchenne muscular dystrophy: X-linked recessive, absent dystrophin. เด็กชาย 3-5 ปี: proximal muscle weakness, Gowers sign, calf pseudohypertrophy, waddling gait, CK สูงมาก. ยืนยันด้วย genetic testing/muscle biopsy. Progressive → wheelchair, cardiomyopathy, respiratory failure. Becker MD คือ dystrophin ที่ลดลง (milder)"}, {"topic": "Neural Tube Defect Prevention", "q": "A woman is planning pregnancy. Which intervention most effectively reduces the risk of fetal neural tube defects such as spina bifida?", "choices": ["Vitamin A supplementation throughout the pregnancy", "Periconceptional folic acid supplementation for the mother", "Iron supplementation to prevent maternal anemia", "Calcium supplementation to support fetal bone", "Vitamin C supplementation for maternal immunity"], "ans": 1, "exp": "Periconceptional folic acid (เริ่มก่อนตั้งครรภ์ 1 เดือนถึง first trimester) ลด neural tube defects (spina bifida, anencephaly). ขนาด 400 mcg/day ทั่วไป, 4 mg/day ถ้ามีประวัติ NTD ในครรภ์ก่อน. Vitamin A 'มากเกิน' กลับ teratogenic. เป็นมาตรการ preventive สำคัญ"}, {"topic": "Vitamin B12 Deficiency", "q": "A 9-month-old exclusively breastfed infant of a strict vegan mother presents with pallor, developmental regression, hypotonia, and a macrocytic anemia. Which deficiency is most likely?", "choices": ["Iron deficiency", "Vitamin C deficiency", "Vitamin B12 deficiency", "Folate deficiency from dietary excess", "Vitamin K deficiency"], "ans": 2, "exp": "ทารกที่กินนมแม่ล้วนจากแม่ vegan (B12 ในนมแม่ต่ำ) เสี่ยง vitamin B12 deficiency: macrocytic (megaloblastic) anemia, developmental regression, hypotonia, irritability. รักษาด้วย B12 supplementation (แม่+ทารก). Iron deficiency ทำให้ microcytic (แยกได้จาก MCV). ต้องแนะนำ B12 ในแม่ vegan"}, {"topic": "Iodine Deficiency", "q": "In an iodine-deficient region, a child has goiter, short stature, intellectual disability, and delayed development. Severe congenital iodine deficiency causes which classic condition?", "choices": ["Kwashiorkor from severe dietary protein deficiency", "Nutritional rickets from vitamin D deficiency", "Scurvy from prolonged vitamin C deficiency", "Endemic cretinism from congenital iodine deficiency", "Beriberi from thiamine (vitamin B1) deficiency"], "ans": 3, "exp": "Iodine deficiency: สาเหตุที่ป้องกันได้ที่พบบ่อยที่สุดของ intellectual disability ทั่วโลก. Severe deficiency ในครรภ์ → endemic cretinism (intellectual disability, deaf-mutism, spasticity, short stature, goiter). ป้องกันด้วย iodized salt และ iodine ในหญิงตั้งครรภ์. Newborn screening TSH ช่วยตรวจจับ"}, {"topic": "Infant Botulism", "q": "A previously healthy 4-month-old develops constipation, poor feeding, a weak cry, ptosis, and descending flaccid paralysis with hypotonia ('floppy baby'). The parents recently gave the infant honey. What is the diagnosis?", "choices": ["Spinal muscular atrophy", "Guillain-Barre syndrome", "Myasthenia gravis", "Hypothyroidism", "Infant botulism"], "ans": 4, "exp": "Infant botulism: Clostridium botulinum spores (จาก honey/soil) colonize ลำไส้ทารก ปล่อย toxin → constipation แล้ว descending symmetric flaccid paralysis, ptosis, poor feeding, weak cry, hypotonia. รักษาด้วย human botulism immunoglobulin (BabyBIG) + supportive. 'ห้ามให้ honey แก่ทารก <1 ปี'. ไม่ใช้ aminoglycoside (เสริม neuromuscular blockade)"}, {"topic": "Tooth Eruption", "q": "Parents ask when their baby's first primary (deciduous) tooth should appear. What is the typical age of eruption of the first tooth?", "choices": ["About 6-10 months, usually the lower central incisor", "Present already at the time of birth as natal teeth", "At around two months of age as the first tooth", "Not until about eighteen months of age", "Delayed until roughly three years of age"], "ans": 0, "exp": "ฟันน้ำนมซี่แรก (มัก lower central incisor) ขึ้น ~6-10 เดือน; ฟันน้ำนมครบ 20 ซี่ ~2.5-3 ปี. Delayed eruption (>12-18 เดือนยังไม่มีฟัน) อาจสัมพันธ์กับ hypothyroidism, rickets, genetic. Natal teeth (ฟันแรกเกิด) พบน้อยและอาจต้องพิจารณาถอนถ้าหลุดง่าย/รบกวน feeding"}, {"topic": "Fontanelle Closure", "q": "During a well-child visit, the physician assesses the anterior fontanelle. At what age does the anterior fontanelle normally close?", "choices": ["By 2 months", "9-18 months", "By 6 months", "By 3 years", "At birth"], "ans": 1, "exp": "Anterior fontanelle ปิด ~9-18 เดือน (posterior fontanelle ปิด ~2 เดือน). ปิดเร็ว (craniosynostosis, microcephaly) หรือปิดช้า/ใหญ่ (hypothyroidism, rickets, hydrocephalus, Down) เป็นเบาะแส. Bulging = increased ICP, sunken = dehydration"}, {"topic": "Stranger Anxiety", "q": "A 9-month-old infant cries and clings to the mother when approached by an unfamiliar person at a clinic visit. The parents are concerned. What is the most appropriate interpretation?", "choices": ["An early warning sign of autism spectrum disorder", "An anxiety disorder that requires specific treatment", "Normal stranger anxiety, an expected social milestone", "Evidence of an abnormal or insecure attachment", "An indication of underlying hearing impairment"], "ans": 2, "exp": "Stranger anxiety เป็น normal developmental milestone ปรากฏ ~6-9 เดือน (สัมพันธ์กับ attachment และ object permanence). Separation anxiety ปรากฏ ~9-18 เดือน. เป็นสัญญาณ development ปกติ ไม่ใช่พยาธิสภาพ. การไม่มี social engagement เลยต่างหากที่น่ากังวล"}, {"topic": "Object Permanence", "q": "A 9-month-old infant will look for a toy that has been hidden under a cloth, demonstrating a key cognitive milestone. What is this milestone called?", "choices": ["Theory of mind", "Conservation", "Symbolic play", "Object permanence", "Abstract reasoning"], "ans": 3, "exp": "Object permanence (การเข้าใจว่าสิ่งของยังคงอยู่แม้มองไม่เห็น) พัฒนา ~8-9 เดือน (Piaget's sensorimotor stage) และสัมพันธ์กับ stranger/separation anxiety. Conservation และ abstract reasoning เป็น cognitive milestones ในเด็กโตกว่า"}, {"topic": "Toilet Training", "q": "Parents ask when to start toilet training. Which is the most appropriate advice regarding readiness?", "choices": ["Start rigid scheduled training as early as six months", "Never attempt any toilet training before five years", "Punish the child for accidents to speed up learning", "Expect toilet training to be complete by twelve months", "Begin at readiness signs, usually around 18-30 months"], "ans": 4, "exp": "Toilet training ควรเริ่มเมื่อเด็กมี 'readiness' (มัก ~18-30 เดือน): เดินได้, สื่อสารความต้องการ, สนใจ, สามารถถอด/ใส่กางเกง, แห้งได้นานขึ้น. ใช้ positive reinforcement, ไม่ลงโทษ accidents. เริ่มเร็ว/บังคับเกินไปทำให้ยากขึ้น. Nighttime dryness มาทีหลัง daytime"}, {"topic": "Tanner Staging", "q": "In girls, which physical change usually marks the earliest sign of puberty (Tanner stage 2)?", "choices": ["Breast budding", "Menarche (first menstruation)", "Peak height velocity", "Axillary hair", "Adult breast contour"], "ans": 0, "exp": "ในเด็กหญิง สัญญาณแรกของ puberty คือ breast budding (thelarche, Tanner 2) ~8-13 ปี, ตามด้วย pubic hair, growth spurt, และ menarche (ประมาณ 2-2.5 ปีหลัง thelarche). ในเด็กชาย สัญญาณแรกคือ testicular enlargement (≥4 mL). Precocious = thelarche <8 ปี (หญิง), testicular enlargement <9 ปี (ชาย)"}, {"topic": "Growth Hormone Deficiency", "q": "A 5-year-old has poor linear growth with a low growth velocity, increased subcutaneous fat, a youthful 'cherubic' face, and a delayed bone age, but normal body proportions. Which diagnosis should be evaluated?", "choices": ["Familial short stature", "Growth hormone deficiency", "Achondroplasia", "Precocious puberty", "Constitutional tall stature"], "ans": 1, "exp": "Growth hormone deficiency: growth velocity 'ลดลง' ทำให้ height percentile ตกข้ามเส้น, increased fat, immature/cherubic facies, delayed bone age, body proportion ปกติ. ประเมินด้วย IGF-1/IGFBP-3 และ GH stimulation test, MRI pituitary. รักษาด้วย recombinant GH. ต่างจาก familial SS (velocity ปกติ)"}, {"topic": "Breast Milk vs Formula", "q": "A mother asks about the advantages of breast milk over formula. Which statement is correct?", "choices": ["Formula contains maternal antibodies like breast milk", "Breast milk has more iron in absolute quantity but poorly absorbed", "Breast milk provides IgA antibodies and reduces infections", "Breast milk provides adequate vitamin D without supplementation", "Formula-fed infants have lower rates of respiratory infection"], "ans": 2, "exp": "นมแม่มี secretory IgA, lactoferrin, lysozyme, WBC และ growth factors → ลด infection (GI, respiratory, OM), ลด NEC, allergy, obesity, SIDS. Iron ในนมแม่ปริมาณต่ำแต่ 'ดูดซึมดี'. ข้อจำกัด: vitamin D และ vitamin K ต่ำ จึงต้องเสริม. Formula ไม่มี maternal antibody"}, {"topic": "Breastfeeding Contraindication", "q": "In which situation is breastfeeding generally contraindicated?", "choices": ["Maternal mastitis", "Common cold in the mother", "Physiologic newborn jaundice", "Infant with galactosemia", "Maternal type 2 diabetes"], "ans": 3, "exp": "Galactosemia ในทารกเป็นข้อห้าม breastfeeding ที่ชัดเจน (นมแม่มี lactose/galactose ที่ทารกเผาผลาญไม่ได้ → toxic). ข้อห้ามอื่น เช่น มารดา HIV (ในบริบทที่มี safe formula), active untreated TB (แยกชั่วคราว), บาง chemotherapy/drugs. Mastitis, common cold, jaundice, DM 'ไม่ใช่' ข้อห้าม — ยังให้นมแม่ต่อได้"}, {"topic": "Failure to Thrive - Evaluation", "q": "A 12-month-old with failure to thrive is being evaluated. After a detailed diet and psychosocial history, what is generally the most useful initial approach?", "choices": ["Immediately order an extensive panel of invasive tests", "Admit the child for exploratory abdominal surgery", "Start appetite-stimulant medication before anything else", "Begin parenteral nutrition as the initial intervention", "Observe feeding and give nutritional support with follow-up"], "ans": 4, "exp": "FTT ส่วนใหญ่เป็น non-organic (inadequate intake/feeding-psychosocial). แนวทางที่คุ้มค่าที่สุดคือ ประเมิน feeding (สังเกตการให้นม/อาหาร), diet + psychosocial history, ให้ nutritional/feeding support และติดตาม growth ใกล้ชิด. Lab/invasive testing ทำแบบ targeted เมื่อมีเบาะแส organic ไม่ใช่ shotgun"}, {"topic": "Vaccine Spacing - Live Vaccines", "q": "A child received the MMR vaccine today but also needs the varicella vaccine, which was not given at the same visit. If not given together, what is the minimum interval before giving the second live vaccine?", "choices": ["4 weeks", "1 day", "1 week", "6 months", "1 year"], "ans": 0, "exp": "Live parenteral vaccines (MMR, varicella) ถ้าไม่ได้ให้ 'วันเดียวกัน' ต้องเว้นระยะอย่างน้อย 4 สัปดาห์ (เพื่อไม่ให้ interferon จากตัวแรกลด immune response ของตัวที่สอง). ถ้าให้พร้อมกันในวันเดียวได้ปกติ. Inactivated vaccines ไม่มีข้อจำกัดการเว้นระยะกับวัคซีนอื่น"}, {"topic": "Pertussis Vaccine", "q": "An unimmunized 2-month-old is due for vaccines. Which vaccine protects against pertussis (whooping cough), a serious cause of apnea and death in young infants?", "choices": ["MMR (measles-mumps-rubella) live attenuated vaccine", "DTaP (diphtheria-tetanus-acellular pertussis) vaccine", "BCG vaccine given to protect against tuberculosis", "Hepatitis A vaccine against fecal-oral hepatitis", "Oral rotavirus vaccine against infantile gastroenteritis"], "ans": 1, "exp": "DTaP ให้ป้องกัน pertussis (ร่วมกับ diphtheria, tetanus) เริ่ม 2 เดือน. Pertussis รุนแรงในทารกเล็ก (apnea, whooping cough, death). กลยุทธ์ 'cocooning' + maternal Tdap ระหว่างตั้งครรภ์ ช่วยป้องกันทารกที่ยังฉีดไม่ครบ. Tdap ใช้ใน adolescent/adult booster"}, {"topic": "Hib Vaccine", "q": "Widespread use of a conjugate vaccine has dramatically reduced which former leading cause of bacterial meningitis and epiglottitis in young children?", "choices": ["Neisseria meningitidis only", "Streptococcus pyogenes", "Haemophilus influenzae type b", "Escherichia coli", "Staphylococcus aureus"], "ans": 2, "exp": "Hib conjugate vaccine ลด invasive Haemophilus influenzae type b disease (meningitis, epiglottitis, septic arthritis, pneumonia) อย่างมาก. เริ่มฉีด 2 เดือน. ก่อนมีวัคซีน Hib เป็นสาเหตุอันดับต้นของ bacterial meningitis ในเด็กเล็ก. Conjugation กับ protein ช่วยให้ทารก <2 ปีสร้างภูมิต่อ polysaccharide ได้"}, {"topic": "Pneumococcal Vaccine", "q": "The pneumococcal conjugate vaccine (PCV) is part of routine infant immunization. It primarily protects against invasive disease caused by which organism?", "choices": ["Haemophilus influenzae type b", "Neisseria meningitidis", "Group B Streptococcus", "Streptococcus pneumoniae", "Mycobacterium tuberculosis"], "ans": 3, "exp": "PCV ป้องกัน invasive pneumococcal disease (meningitis, bacteremia, pneumonia) และลด otitis media จาก Streptococcus pneumoniae. Conjugate vaccine (PCV) ใช้ในเด็ก <2 ปีได้ (ต่างจาก polysaccharide PPSV23 ที่ใช้ในกลุ่มเสี่ยงอายุมากกว่า). ลด nasopharyngeal carriage และมี herd immunity"}, {"topic": "Influenza Vaccine Age", "q": "From what minimum age is the annual inactivated influenza vaccine recommended for routine use in children?", "choices": ["At birth", "2 years", "5 years", "12 years", "6 months"], "ans": 4, "exp": "Inactivated influenza vaccine แนะนำให้ 'ทุกปี' เริ่มตั้งแต่อายุ 6 เดือนขึ้นไป (dose แรกในเด็กเล็กที่ไม่เคยฉีดต้องให้ 2 เข็มห่าง 4 สัปดาห์). ทารก <6 เดือนป้องกันโดยฉีดแม่ระหว่างตั้งครรภ์และ cocooning. กลุ่มเสี่ยง (asthma, heart disease) ควรได้รับทุกปี"}, {"topic": "MMR Second Dose", "q": "A child received the first MMR at 12 months. The second (booster) dose of MMR is typically recommended at what age in many schedules?", "choices": ["At about 4-6 years, around the time of school entry", "At thirteen months, shortly after the first dose", "At nine months of age, earlier than usual", "At two months of age with the primary series", "Not until about ten years of age"], "ans": 0, "exp": "MMR ให้ 2 dose: dose แรก ~9-12 เดือน, dose ที่สอง ~2.5 ปี หรือช่วงเข้าเรียน (4-6 ปี ในหลาย schedule). Dose สองไม่ใช่เพราะภูมิตกแต่เพื่อ 'catch' คนที่ไม่ตอบสนอง dose แรก (~5%). ในช่วงระบาดสามารถให้เร็วขึ้นได้ตามคำแนะนำ"}, {"topic": "Japanese Encephalitis Vaccine", "q": "In Thailand and much of Asia, routine childhood immunization includes a vaccine against a mosquito-borne flavivirus that causes encephalitis, associated with rice-farming areas and pigs. Which vaccine is this?", "choices": ["Yellow fever vaccine", "Japanese encephalitis vaccine", "Dengue vaccine (for all infants)", "Rabies vaccine", "Tick-borne encephalitis vaccine"], "ans": 1, "exp": "Japanese encephalitis (JE) เป็น flavivirus นำโดยยุง Culex สัมพันธ์กับนาข้าว/หมู เป็นสาเหตุสำคัญของ viral encephalitis ในเอเชีย. JE vaccine อยู่ในโปรแกรม EPI ของไทย. ต่างจาก dengue vaccine ที่มีข้อจำกัด (แนะนำเฉพาะผู้เคยติดเชื้อ dengue มาก่อน ไม่ใช่ทุกคน)"}, {"topic": "Social Smile", "q": "At which age does a typically developing infant begin to smile responsively (social smile) in reaction to a caregiver?", "choices": ["At birth", "6 months", "About 2 months", "9 months", "12 months"], "ans": 2, "exp": "Social smile (ยิ้มตอบสนอง) ปรากฏ ~6-8 สัปดาห์ (~2 เดือน) เป็น social-emotional milestone แรกๆ. ก่อนหน้านั้นเป็น reflex smile. การไม่มี social smile ที่ 3 เดือนเป็น red flag ที่ต้องประเมิน vision และ development"}, {"topic": "Head Control", "q": "At which age should a typically developing infant have good head control (no significant head lag when pulled to sit)?", "choices": ["1 month", "9 months", "12 months", "About 4 months", "18 months"], "ans": 3, "exp": "Head control (ไม่มี significant head lag เมื่อดึงขึ้นนั่ง) พัฒนา ~4 เดือน. Head lag ที่คงอยู่หลัง 4-6 เดือนเป็น red flag ของ hypotonia/motor delay (เช่น cerebral palsy, spinal muscular atrophy) ต้องประเมิน tone และ development"}, {"topic": "Pincer Grasp", "q": "At which age does a typically developing infant develop a mature pincer grasp (picking up a small object between the thumb and index finger)?", "choices": ["3 months", "6 months", "18 months", "24 months", "9-12 months"], "ans": 4, "exp": "Pincer grasp (หยิบของเล็กด้วยนิ้วโป้ง-ชี้) พัฒนา ~9-12 เดือน (ก่อนหน้าเป็น raking/palmar grasp ~6 เดือน). Fine motor milestones สำคัญต่อการประเมินและสัมพันธ์กับการเริ่ม finger feeding. Handedness ที่ชัดก่อน 1 ปีถือว่าผิดปกติ (อาจบ่งชี้ hemiparesis)"}, {"topic": "Drawing Milestones", "q": "A pediatrician assesses fine motor and cognitive development by asking a child to copy shapes. At approximately what age can a typical child copy a circle?", "choices": ["3 years", "1 year", "18 months", "6 years", "9 months"], "ans": 0, "exp": "Milestones การวาด/ลอกรูป: วาดเส้น (scribble) ~15-18 เดือน, ลอกวงกลม (circle) ~3 ปี, ลอกกากบาท (cross) ~3.5-4 ปี, ลอกสี่เหลี่ยม (square) ~4-5 ปี, ลอกสามเหลี่ยม (triangle) ~5 ปี. ใช้ประเมิน visuomotor/cognitive development"}, {"topic": "Gross Motor - 3 years", "q": "A pediatrician evaluates a 3-year-old's gross motor development. Which skill is typically achieved by a 3-year-old?", "choices": ["Hops on one foot for several seconds without support", "Rides a tricycle and climbs stairs alternating feet", "Skips smoothly alternating feet across the room", "Walks upstairs placing two feet on each single step", "Runs for the very first time without falling"], "ans": 1, "exp": "3 ปี: ขี่ tricycle, ขึ้นบันไดสลับเท้า, กระโดดสองเท้า, ยืนขาเดียวสั้นๆ. 4 ปี: hop on one foot, ลงบันไดสลับเท้า. 5 ปี: skip, กระโดดข้าม. ใช้เทียบ gross motor milestones ในเด็กก่อนวัยเรียน"}, {"topic": "Cri-du-chat Syndrome", "q": "A newborn has a high-pitched, cat-like cry, microcephaly, hypertelorism, and intellectual disability. This is caused by a deletion on the short arm of chromosome 5. What is the diagnosis?", "choices": ["Down syndrome", "Angelman syndrome", "Cri-du-chat syndrome", "Williams syndrome", "Prader-Willi syndrome"], "ans": 2, "exp": "Cri-du-chat syndrome: deletion ของ chromosome 5p (5p-). ลักษณะเด่น: high-pitched 'cat-like' cry (จาก laryngeal abnormality), microcephaly, hypertelorism, round face, intellectual disability, hypotonia. วินิจฉัยด้วย karyotype/microarray"}, {"topic": "Rett Syndrome", "q": "A girl developed normally until 6-18 months, then showed developmental regression with loss of purposeful hand use, stereotypic hand-wringing movements, deceleration of head growth, and loss of language. What is the most likely diagnosis?", "choices": ["Autism spectrum disorder (idiopathic)", "Angelman syndrome", "Fragile X syndrome", "Rett syndrome", "Cerebral palsy"], "ans": 3, "exp": "Rett syndrome (MECP2 mutation, X-linked, เกือบทั้งหมดในเพศหญิง): พัฒนาปกติช่วงแรกแล้ว 'regression' ~6-18 เดือน — สูญเสีย purposeful hand use, stereotypic hand-wringing, acquired microcephaly (head growth deceleration), loss of language, gait abnormality. ต่างจาก autism ที่ไม่มี hand-wringing stereotypy/regression pattern แบบนี้"}, {"topic": "Beriberi - Thiamine", "q": "An infant exclusively breastfed by a thiamine-deficient mother (polished rice diet) develops heart failure, hoarseness/aphonia, and edema. Which deficiency is responsible?", "choices": ["Vitamin C deficiency", "Vitamin A deficiency", "Niacin deficiency", "Vitamin K deficiency", "Thiamine deficiency"], "ans": 4, "exp": "Infantile beriberi จาก thiamine (B1) deficiency พบในทารกที่แม่กิน polished rice diet (ขาด B1): wet beriberi (high-output heart failure, edema), aphonia/hoarse cry, และ neurologic. รักษาด้วย thiamine ทันที (ตอบสนองเร็ว). ยังพบได้ในบางพื้นที่ของไทย/เอเชีย"}, {"topic": "Pellagra - Niacin", "q": "A child with a maize-based diet develops the classic triad of dermatitis (photosensitive), diarrhea, and dementia. Which vitamin deficiency causes this?", "choices": ["Niacin deficiency", "Thiamine deficiency", "Vitamin C deficiency", "Folate deficiency", "Vitamin B12 deficiency"], "ans": 0, "exp": "Pellagra จาก niacin (B3) deficiency: '3 Ds' = Dermatitis (photosensitive, Casal necklace), Diarrhea, Dementia (+ ที่ 4 = Death ถ้าไม่รักษา). พบในอาหารพึ่ง maize (corn) ที่ niacin/tryptophan ต่ำ. รักษาด้วย niacin. Hartnup disease ก็ทำให้ pellagra-like ได้"}, {"topic": "Denver Developmental Screening", "q": "A tool used to screen for developmental delay across gross motor, fine motor, language, and personal-social domains in children up to 6 years is the Denver Developmental Screening Test. What is the correct use of such a screening test?", "choices": ["It provides a definitive diagnosis of intellectual disability", "It screens for delay and flags children needing evaluation", "It measures the child's intelligence quotient precisely", "It fully replaces a formal developmental assessment", "It is only valid for use after six years of age"], "ans": 1, "exp": "Denver Developmental Screening Test (DDST) เป็น 'screening tool' ประเมิน 4 domains (gross motor, fine motor, language, personal-social) ในเด็กจนถึง 6 ปี. ผลผิดปกติบ่งชี้ว่าต้อง 'ประเมินวินิจฉัยเพิ่ม' ไม่ใช่การวินิจฉัยหรือวัด IQ. Screening tools ช่วยตรวจจับ delay เพื่อ early intervention"}, {"topic": "Handedness", "q": "A 10-month-old infant shows a strong, consistent preference for using the right hand and rarely uses the left. What does established hand dominance before 12 months of age suggest?", "choices": ["Entirely normal and expected at this age", "An indication of advanced motor development", "Abnormal, suggesting weakness of the non-preferred side", "A finding that confirms autism spectrum disorder", "A reliable sign of above-average intelligence"], "ans": 2, "exp": "Hand dominance โดยปกติชัดเจนหลัง 1-2 ปี. Established handedness 'ก่อน 12 เดือน' ถือว่าผิดปกติ เพราะอาจสะท้อน weakness/ไม่ใช้แขนอีกข้าง (เช่น hemiplegic cerebral palsy, brachial plexus injury) → ต้องประเมิน motor/neurologic"}, {"topic": "SIDS Prevention", "q": "During anticipatory guidance, which recommendation most effectively reduces the risk of sudden infant death syndrome (SIDS)?", "choices": ["Place the infant prone (on the stomach) to sleep", "Use soft pillows and blankets in the crib", "Have the infant sleep in the parents' bed (bed-sharing)", "Place the infant on the back to sleep on a firm surface without soft bedding", "Keep the room very warm and overbundle the infant"], "ans": 3, "exp": "SIDS prevention ('Safe to Sleep'): นอนหงาย (back to sleep) บนที่นอนแข็ง, ไม่มี soft bedding/pillow/toys, room-sharing แต่ไม่ bed-sharing, หลีกเลี่ยงบุหรี่และ overheating, พิจารณา pacifier. Prone/side sleeping เพิ่มความเสี่ยง SIDS อย่างชัดเจน"}, {"topic": "Amblyopia Screening", "q": "A 4-year-old is found on vision screening to have reduced visual acuity in one eye and a constant inward deviation (esotropia). Untreated, this can cause permanent vision loss in the deviating eye. What is this condition and its principle of treatment?", "choices": ["Congenital cataract; treat with corrective glasses only", "Bacterial conjunctivitis; treat with topical antibiotics", "Retinoblastoma; treat with systemic chemotherapy", "Congenital color blindness; no treatment is required", "Amblyopia; patch the better eye to strengthen the weaker"], "ans": 4, "exp": "Amblyopia ('lazy eye') = การมองเห็นลดลงจากสมองไม่พัฒนา visual pathway ของตาข้างที่ input ไม่ดี (จาก strabismus, refractive error, หรือ deprivation เช่น cataract). รักษาโดยแก้สาเหตุ + patching/penalization ตาข้างที่ดีเพื่อบังคับใช้ตาข้างที่อ่อน. ต้องรักษาในช่วง critical period (ก่อน ~7-8 ปี) มิฉะนั้น vision loss ถาวร"}, {"topic": "Newborn Hearing Screening", "q": "Universal newborn hearing screening is recommended. Why is early identification of congenital hearing loss important?", "choices": ["Early intervention improves language and cognition", "Untreated hearing loss resolves on its own with time", "Hearing loss only matters after five years of age", "Early detection mainly prevents future ear infections", "Hearing status has no effect on speech development"], "ans": 0, "exp": "Universal newborn hearing screening (OAE/ABR): congenital hearing loss พบได้และมองไม่เห็น. Early identification + intervention (hearing aid, cochlear implant, speech therapy) ภายในไม่กี่เดือนแรก ช่วยพัฒนา language/cognitive/psychosocial ได้ดีกว่ามาก (critical period). Delay ทำให้ speech-language delay ถาวร"}, {"topic": "Lead Poisoning", "q": "A toddler living in an old house with peeling paint has irritability, abdominal pain, constipation, developmental regression, and microcytic anemia with basophilic stippling. What is the most likely diagnosis?", "choices": ["Iron deficiency anemia alone", "Lead poisoning", "Thalassemia", "Vitamin B12 deficiency", "Copper deficiency"], "ans": 1, "exp": "Lead poisoning (จาก old paint, contaminated soil/toys): neurodevelopmental effects (irritability, cognitive decline/regression), abdominal pain/constipation, microcytic anemia with basophilic stippling, และ severe cases → encephalopathy. ตรวจ blood lead level. รักษา: remove source + chelation (succimer/EDTA/dimercaprol) ในรายที่สูง. ป้องกันคือหัวใจสำคัญ"}, {"topic": "Anticipatory Guidance - Injury", "q": "During a well-child visit for a 9-month-old, which anticipatory guidance is most appropriate for injury prevention at this developmental stage?", "choices": ["Let the infant play with small coins for fine motor skills", "Switch to a forward-facing car seat right away", "Childproof the home: cover outlets and gate the stairs", "Allow the infant to sleep with soft pillows and blankets", "Offer whole nuts and hard candy as convenient snacks"], "ans": 2, "exp": "ที่ 9 เดือน ทารกเริ่มคลาน/เคลื่อนที่ → anticipatory guidance เน้น childproofing: ปิดปลั๊ก, gate บันได, ล็อกตู้/สารเคมี, เก็บของชิ้นเล็ก (choking), ระวังจมน้ำ. ยังใช้ rear-facing car seat, ห้าม small/hard food (choking), ไม่ให้ pillow/blanket ในเปล (SIDS). Anticipatory guidance ปรับตาม developmental stage"}, {"topic": "Kwashiorkor Refeeding", "q": "A severely malnourished child with kwashiorkor is admitted. During initial nutritional rehabilitation, which complication must be anticipated and prevented by starting feeds cautiously?", "choices": ["Hypertensive crisis", "Hyperphosphatemia", "Polycythemia", "Refeeding syndrome", "Immediate obesity"], "ans": 3, "exp": "Refeeding syndrome: เมื่อเริ่มให้อาหาร (โดยเฉพาะ carbohydrate) ในผู้ขาดสารอาหารรุนแรง insulin surge ดึง phosphate/potassium/magnesium เข้าเซลล์ → hypophosphatemia, hypokalemia, hypomagnesemia, fluid overload, arrhythmia. ป้องกันโดยเริ่ม feed ช้าๆ (low calorie) เพิ่มทีละน้อย + monitor/replace electrolytes + thiamine. WHO มี F-75/F-100 protocol"}, {"topic": "Physiologic Anemia of Infancy", "q": "A healthy, thriving 2-month-old term infant has a hemoglobin of 10 g/dL on a routine check. The infant is asymptomatic. What is the most likely explanation?", "choices": ["Iron deficiency anemia", "Occult blood loss", "Thalassemia major", "Hemolytic anemia", "Physiologic anemia of infancy"], "ans": 4, "exp": "Physiologic anemia of infancy: หลังคลอด erythropoiesis ลดลง (จาก oxygenation ดีขึ้น, EPO ลด) + fetal RBC lifespan สั้น → Hb ลดถึง nadir ~9-11 g/dL ที่ ~8-12 สัปดาห์ (term). เป็น normal, asymptomatic, ไม่ต้องรักษา (ไม่ตอบสนอง iron). Preterm มี nadir ต่ำและเร็วกว่า"}, {"topic": "Vegan Diet Counseling", "q": "The parents of a toddler follow a strict vegan diet for the child. Which nutrients most require attention/supplementation to prevent deficiency?", "choices": ["Vitamin B12, iron, vitamin D, and adequate protein", "Only vitamin C and folate need any attention", "Mainly sodium and chloride require supplementation", "Vitamin A and beta-carotene are the key concern", "No supplementation is ever needed on a vegan diet"], "ans": 0, "exp": "Vegan diet ในเด็กต้องวางแผนอย่างระวัง: เสี่ยงขาด vitamin B12 (พบเฉพาะใน animal products), iron (non-heme ดูดซึมน้อย), vitamin D, calcium, zinc, omega-3, และต้องพอเพียง protein/calorie สำหรับ growth. แนะนำ B12 supplementation และติดตาม growth. ไม่วางแผนดีเสี่ยง developmental/growth impairment"}, {"topic": "Well-Child Visit Screening", "q": "At what age is a child most commonly screened for iron deficiency anemia and (in at-risk populations) lead exposure during routine well-child care?", "choices": ["At birth", "Around 9-12 months", "At 2 weeks", "At 5 years only", "Never routinely"], "ans": 1, "exp": "การ screen iron deficiency anemia (และ lead ในกลุ่มเสี่ยง) มักทำ ~9-12 เดือน ซึ่งเป็นช่วงที่ iron stores จากแม่หมดและเด็กเสี่ยงขาดธาตุเหล็กจากอาหาร (โดยเฉพาะดื่มนมวัวมาก). Well-child visits รวม growth/development, immunization, screening, และ anticipatory guidance ตามอายุ"}, {"topic": "Marasmus vs Kwashiorkor Edema", "q": "Which single clinical feature most reliably distinguishes kwashiorkor from marasmus?", "choices": ["Severe muscle wasting, only in kwashiorkor", "Normal weight in marasmus", "Presence of bilateral pitting edema in kwashiorkor", "Hepatomegaly, only in marasmus", "Edema present in marasmus but not kwashiorkor"], "ans": 2, "exp": "จุดแยกสำคัญ: 'edema' (bilateral pitting, จาก hypoalbuminemia) พบใน kwashiorkor แต่ 'ไม่พบ' ใน marasmus. Marasmus เด่นที่ severe wasting/ผอมหนังหุ้มกระดูก. Kwashiorkor มี edema + hepatomegaly + skin/hair changes ทั้งๆ ที่อาจไม่ผอมมาก. Marasmic-kwashiorkor มีทั้งสอง"}, {"topic": "Growth Chart Interpretation", "q": "A child's weight and height have consistently tracked along the 15th percentile since infancy, with a normal growth velocity and normal development. What is the most appropriate interpretation?", "choices": ["Failure to thrive that requires hospital admission", "Growth hormone deficiency needing hormone therapy", "Malnutrition requiring intensive nutritional rehabilitation", "Normal growth; steady tracking on a percentile is reassuring", "An underlying chromosomal abnormality affecting growth"], "ans": 3, "exp": "การเจริญเติบโตที่ 'tracking' ตามเส้น percentile เดิมสม่ำเสมอ (แม้เป็น percentile ต่ำ) พร้อม growth velocity ปกติและ development ปกติ = normal growth (constitutional). สิ่งที่น่ากังวลคือการ 'crossing percentiles ลง' (declining velocity) หรือ development delay ไม่ใช่ค่า absolute percentile ที่คงที่"}, {"topic": "Congenital Hypothyroidism Presentation", "q": "A 3-week-old infant (whose newborn screen was inadvertently missed) presents with prolonged jaundice, constipation, poor feeding, lethargy, a large tongue, an umbilical hernia, and a hoarse cry. What is the most likely diagnosis?", "choices": ["Down syndrome without thyroid disease", "Biliary atresia", "Hirschsprung disease", "Neonatal sepsis", "Congenital hypothyroidism"], "ans": 4, "exp": "Congenital hypothyroidism (ถ้าพลาด newborn screening): prolonged jaundice, constipation, poor feeding, lethargy, macroglossia, umbilical hernia, hoarse cry, hypotonia, large fontanelle. รักษาด้วย levothyroxine โดยเร็วป้องกัน intellectual disability. Newborn screening (TSH) ตรวจจับก่อนมีอาการ จึงสำคัญมาก"}, {"topic": "Puberty Sequence - Boys", "q": "In boys, which of the following is the first physical sign of the onset of puberty?", "choices": ["Testicular enlargement", "Growth of facial hair", "Deepening of the voice", "Peak height velocity", "Appearance of pubic hair"], "ans": 0, "exp": "ในเด็กชาย สัญญาณแรกของ puberty คือ 'testicular enlargement' (volume ≥4 mL, ~9-14 ปี) ตามด้วย pubic hair, penile growth, growth spurt (มาช้ากว่าหญิง, peak ที่ Tanner 3-4), facial hair, voice change. Testicular enlargement <9 ปี = precocious puberty ในเด็กชาย"}, {"topic": "Separation Anxiety", "q": "A 15-month-old cries and becomes distressed whenever the mother leaves the room but is consolable and plays normally when she returns. The parents ask if this is a problem. What is the most appropriate interpretation?", "choices": ["A pathological anxiety disorder requiring treatment", "Normal separation anxiety, an expected developmental phase", "A sign of insecure attachment needing family therapy", "Evidence of a global developmental delay", "An early symptom of autism spectrum disorder"], "ans": 1, "exp": "Separation anxiety เป็น normal developmental phase ปรากฏ ~9 เดือน, peak ~12-18 เดือน, ค่อยๆ ลดลงเมื่ออายุ 2-3 ปี. สะท้อน secure attachment และ object permanence. Separation anxiety 'disorder' คือเมื่อมากเกิน/นานเกิน/รบกวนการทำงานในเด็กโต ซึ่งต่างจากภาวะปกตินี้"}, {"topic": "Obesity Comorbidity", "q": "An obese 12-year-old has velvety hyperpigmentation of the skin folds of the neck and axillae (acanthosis nigricans). What does this finding most likely indicate?", "choices": ["Addison disease", "Vitamin B12 deficiency", "Insulin resistance", "Hyperthyroidism", "Cushing syndrome exclusively"], "ans": 2, "exp": "Acanthosis nigricans (velvety hyperpigmentation ที่คอ/รักแร้/ขาหนีบ) ในเด็กอ้วนบ่งชี้ insulin resistance และเพิ่มความเสี่ยง type 2 diabetes. ควร screen HbA1c/fasting glucose และ metabolic comorbidities (dyslipidemia, NAFLD, hypertension, OSA). เป็น marker ที่เห็นได้จากการตรวจร่างกาย"}, {"topic": "Folate Deficiency", "q": "A child with poor dietary intake or increased demand (e.g., chronic hemolysis) develops a macrocytic (megaloblastic) anemia, but WITHOUT neurologic deficits. Which deficiency is most consistent with this picture?", "choices": ["Vitamin B12 deficiency", "Iron deficiency", "Vitamin K deficiency", "Folate deficiency", "Thiamine deficiency"], "ans": 3, "exp": "Folate deficiency: macrocytic (megaloblastic) anemia 'โดยไม่มี' neurologic deficits (ต่างจาก B12 deficiency ที่มี neuro เช่น subacute combined degeneration). พบเมื่อ intake ต่ำหรือ demand สูง (chronic hemolysis เช่น thalassemia/HS, malabsorption, บางยา). รักษาด้วย folate. ระวัง: ให้ folate เดี่ยวในภาวะ B12 ต่ำอาจบด anemia แต่ neuro แย่ลง"}, {"topic": "Parachute Reflex", "q": "A protective postural reflex that appears around 9 months and persists for life, in which an infant extends the arms when suddenly moved head-first toward a surface, is which reflex?", "choices": ["Moro reflex", "Asymmetric tonic neck reflex", "Rooting reflex", "Palmar grasp reflex", "Parachute reflex"], "ans": 4, "exp": "Parachute reflex เป็น 'protective/postural' reflex ปรากฏ ~9 เดือน และคงอยู่ตลอดชีวิต — เหยียดแขนออกเพื่อป้องกันเมื่อถูกเคลื่อนศีรษะลงหาพื้น. ต่างจาก primitive reflexes (Moro, ATNR, grasp, rooting) ที่มีแรกเกิดและ 'หายไป'. การไม่ปรากฏ parachute เมื่อควรมีบ่งชี้ neurologic problem"}]}, {"id": "ped-3", "title": "กุมารเวชศาสตร์ ชุดที่ 3 — Infectious Disease & Respiratory", "subject": "ped", "questions": [{"topic": "Measles", "q": "A 3-year-old unimmunized child has 4 days of high fever, cough, coryza, and conjunctivitis, followed by a maculopapular rash that began on the face and spread downward. Small white spots on an erythematous base are seen on the buccal mucosa. What is the diagnosis?", "choices": ["Measles (rubeola)", "Rubella", "Roseola infantum", "Scarlet fever", "Erythema infectiosum"], "ans": 0, "exp": "Measles: prodrome '3 Cs' (Cough, Coryza, Conjunctivitis) + high fever, Koplik spots (จุดขาวบน buccal mucosa, pathognomonic) ตามด้วย maculopapular rash เริ่มที่หน้า/หลังหูแล้วลามลง (cephalocaudal). เสี่ยง pneumonia, encephalitis, SSPE. รักษา supportive + vitamin A. ป้องกันด้วย MMR"}, {"topic": "Measles Complication", "q": "A child with measles develops worsening respiratory distress several days into the illness. Which is the most common cause of measles-associated death in children?", "choices": ["Myocarditis with acute cardiac decompensation", "Pneumonia, either viral or secondary bacterial", "Acute post-infectious glomerulonephritis", "Acute appendicitis with abdominal pain", "Hematogenous osteomyelitis of a long bone"], "ans": 1, "exp": "Pneumonia (ทั้ง measles giant cell pneumonia และ secondary bacterial) เป็นสาเหตุการเสียชีวิตที่พบบ่อยที่สุดของ measles. ภาวะแทรกซ้อนอื่น: otitis media (พบบ่อยสุดโดยรวม), croup, acute encephalitis, และ subacute sclerosing panencephalitis (SSPE, หลายปีต่อมา). Vitamin A ลด morbidity/mortality"}, {"topic": "Rubella", "q": "A child has a mild, low-grade fever with a pink maculopapular rash starting on the face and spreading to the trunk, accompanied by tender, enlarged posterior auricular and suboccipital lymph nodes. The illness is mild and resolves in a few days. What is the diagnosis?", "choices": ["Measles with cough, coryza, and Koplik spots", "Roseola infantum with fever then a rash", "Rubella (German measles) with posterior nodes", "Scarlet fever with a sandpaper-like rash", "Meningococcemia with a petechial rash"], "ans": 2, "exp": "Rubella: mild illness, pink maculopapular rash เริ่มที่หน้าลามลง (คล้าย measles แต่เบากว่า ไม่มี Koplik/3 Cs รุนแรง), เด่นที่ 'tender posterior auricular + suboccipital lymphadenopathy'. อันตรายหลักคือ congenital rubella ในหญิงตั้งครรภ์. ป้องกันด้วย MMR"}, {"topic": "Roseola", "q": "A 10-month-old has 3 days of high fever (up to 40°C) but otherwise looks well. When the fever breaks, a rose-pink maculopapular rash appears on the trunk and spreads outward. The child had a febrile seizure during the fever. What is the most likely cause?", "choices": ["Measles virus", "Parvovirus B19", "Group A Streptococcus", "Human herpesvirus 6", "Rubella virus"], "ans": 3, "exp": "Roseola infantum (exanthem subitum, HHV-6/7): ไข้สูง 3-5 วันในทารกที่ดูสบายดี แล้วไข้ลด 'ตามด้วย' rose-pink rash ที่ลำตัว. สัมพันธ์กับ febrile seizure (จากไข้สูง). Self-limited, supportive. ลำดับ 'ไข้ลดแล้วผื่นขึ้น' เป็นเบาะแสสำคัญ"}, {"topic": "Erythema Infectiosum", "q": "A 6-year-old develops bright red erythema of both cheeks ('slapped cheek') followed by a lacy reticular rash on the extremities. He had mild cold symptoms before the rash. What is the causative agent?", "choices": ["Human herpesvirus 6", "Measles virus", "Coxsackievirus", "Group A Streptococcus", "Parvovirus B19"], "ans": 4, "exp": "Erythema infectiosum ('fifth disease', parvovirus B19): 'slapped cheek' facial erythema ตามด้วย lacy/reticular rash ที่แขนขา. เมื่อผื่นขึ้นมักไม่ติดต่อแล้ว. เสี่ยงในกลุ่มพิเศษ: aplastic crisis ในผู้มี hemolytic anemia (เช่น thalassemia, sickle cell), hydrops fetalis ในหญิงตั้งครรภ์, arthropathy ในผู้ใหญ่"}, {"topic": "Hand-Foot-Mouth Disease", "q": "A 2-year-old has fever, painful oral ulcers/vesicles, and vesicular lesions on the palms, soles, and buttocks. Several children at daycare are similarly affected. What is the most likely causative agent?", "choices": ["Coxsackievirus A", "Herpes simplex virus", "Varicella-zoster virus", "Measles virus", "Parvovirus B19"], "ans": 0, "exp": "Hand-foot-mouth disease (Coxsackievirus A16, enterovirus 71): fever + oral ulcers/vesicles + vesicles ที่ฝ่ามือ ฝ่าเท้า และก้น, ระบาดใน daycare. Self-limited, supportive (hydration, pain control). Enterovirus 71 อาจทำให้ neurologic complication รุนแรง. ต่างจาก herpangina (ulcers เฉพาะ posterior pharynx)"}, {"topic": "Chickenpox", "q": "A child develops fever and a pruritic rash with lesions in different stages simultaneously: macules, papules, vesicles ('dew drop on a rose petal'), and crusts. What is the diagnosis and the mainstay of management in a healthy child?", "choices": ["Smallpox requiring immediate isolation and vaccination", "Varicella (chickenpox) treated with supportive care", "Measles managed with vitamin A supplementation", "Hand-foot-mouth disease treated with antivirals", "Bullous impetigo treated with topical antibiotics"], "ans": 1, "exp": "Varicella (VZV): ผื่นคันหลาย stages พร้อมกัน (macule→papule→vesicle 'dew drop on rose petal'→crust), เริ่มลำตัวลามออก. เด็กสุขภาพดีรักษา supportive (calamine, antihistamine, ตัดเล็บกันเกา/secondary bacterial infection). Acyclovir พิจารณาในกลุ่มเสี่ยง (immunocompromised, adolescent/adult, neonate). ป้องกันด้วย varicella vaccine. หลีกเลี่ยง aspirin (Reye)"}, {"topic": "Scarlet Fever", "q": "A 7-year-old with a sore throat develops a diffuse erythematous 'sandpaper' rash that blanches, along with a strawberry tongue, circumoral pallor, and accentuation of the rash in skin folds (Pastia lines). What is the cause and treatment?", "choices": ["Staphylococcus aureus; vancomycin", "Measles virus; supportive care", "Group A Streptococcus", "Parvovirus B19; supportive care", "Kawasaki disease; IVIG"], "ans": 2, "exp": "Scarlet fever จาก Group A Streptococcus (erythrogenic toxin): sandpaper rash, strawberry tongue, circumoral pallor, Pastia lines (accentuation ใน skin folds), pharyngitis. รักษาด้วย penicillin/amoxicillin เพื่อรักษา strep pharyngitis และป้องกัน rheumatic fever. Desquamation ตามมาภายหลัง"}, {"topic": "Croup", "q": "A 2-year-old has a 2-day history of coryza followed by a barking (seal-like) cough, hoarseness, and inspiratory stridor that worsens at night. He is not drooling and does not appear toxic. What is the diagnosis and typical cause?", "choices": ["Epiglottitis, Haemophilus influenzae type b", "Bacterial tracheitis, Staphylococcus aureus", "Foreign body aspiration", "Croup, usually parainfluenza virus", "Retropharyngeal abscess"], "ans": 3, "exp": "Croup (viral laryngotracheobronchitis, มัก parainfluenza): barking/seal-like cough, hoarseness, inspiratory stridor, worse ตอนกลางคืน, low-grade fever, ไม่ toxic/ไม่ drool. CXR อาจเห็น 'steeple sign'. รักษา: corticosteroid (dexamethasone) ทุกราย + nebulized epinephrine ถ้า stridor at rest. ต่างจาก epiglottitis (toxic, drooling, tripod)"}, {"topic": "Epiglottitis", "q": "A 4-year-old, incompletely immunized, develops sudden high fever, severe sore throat, drooling, muffled 'hot potato' voice, and sits leaning forward (tripod position) with respiratory distress but no barking cough. What is the priority in management?", "choices": ["Immediately examine the throat with a tongue depressor", "Send home with oral antibiotics", "Nebulized bronchodilators", "Force the child to lie supine for examination", "Secure the airway in a controlled setting"], "ans": 4, "exp": "Epiglottitis (classic Haemophilus influenzae type b, ลดลงมากหลังวัคซีน Hib): sudden high fever, drooling, dysphagia, muffled voice, tripod/sniffing position, toxic, 'ไม่มี barking cough'. Priority คือ 'secure airway' ในห้องผ่าตัด/ควบคุม, 'ห้ามกระตุ้น' หรือใช้ tongue depressor ตรวจคอ (อาจ laryngospasm/obstruction). แล้วให้ ceftriaxone. Thumbprint sign บน lateral neck X-ray"}, {"topic": "Bronchiolitis", "q": "A 6-month-old infant in the rainy season has 2 days of coryza followed by wheezing, tachypnea, retractions, and diffuse crackles/wheezes. What is the most common causative organism?", "choices": ["Respiratory syncytial virus", "Streptococcus pneumoniae", "Mycoplasma pneumoniae", "Haemophilus influenzae", "Bordetella pertussis"], "ans": 0, "exp": "Bronchiolitis: การติดเชื้อ lower airway ในทารก <2 ปี, มัก RSV (ฤดูฝน/หนาว): coryza → wheeze, tachypnea, retraction, crackles. รักษา 'supportive' (oxygen, hydration, suction) เป็นหลัก; bronchodilator/steroid ไม่ช่วยประจำ. เสี่ยง apnea ในทารกเล็ก. Palivizumab ป้องกันในกลุ่มเสี่ยงสูง (preterm, CHD)"}, {"topic": "Pertussis", "q": "A 3-month-old, incompletely immunized, has paroxysms of severe coughing followed by an inspiratory 'whoop,' post-tussive vomiting, and episodes of apnea/cyanosis. Lymphocytosis is present. What is the treatment?", "choices": ["Amoxicillin", "Macrolide (e.g., azithromycin)", "Supportive care only, no antibiotics", "Oseltamivir", "Corticosteroids as first-line"], "ans": 1, "exp": "Pertussis (Bordetella pertussis): paroxysmal cough + inspiratory whoop + post-tussive vomiting + apnea (ในทารก), marked lymphocytosis. รักษาด้วย macrolide (azithromycin) — ลดการแพร่เชื้อ (ช่วยอาการมากถ้าให้ระยะ catarrhal). ให้ prophylaxis แก่ close contacts. ป้องกันด้วย DTaP + maternal Tdap. ทารกเล็กเสี่ยงเสียชีวิต"}, {"topic": "Pediatric Pneumonia - Bacterial", "q": "A 4-year-old has high fever, tachypnea, productive cough, and focal crackles with bronchial breath sounds over the right lower lung. Chest radiograph shows lobar consolidation. What is the most likely organism and first-line treatment?", "choices": ["Respiratory syncytial virus; supportive care", "Mycoplasma pneumoniae; azithromycin", "Streptococcus pneumoniae", "Staphylococcus aureus; vancomycin", "Bordetella pertussis; macrolide"], "ans": 2, "exp": "Lobar consolidation + high fever + focal findings ในเด็กเล็กบ่งชี้ 'typical' bacterial pneumonia, สาเหตุที่พบบ่อยที่สุดคือ Streptococcus pneumoniae. First-line outpatient คือ high-dose amoxicillin. ต่างจาก atypical (Mycoplasma) ในเด็กโต/วัยรุ่นที่ค่อยเป็นค่อยไป diffuse. รุนแรง → admit + IV ampicillin"}, {"topic": "Atypical Pneumonia", "q": "A 12-year-old has a 2-week history of gradually worsening dry cough, low-grade fever, malaise, and headache. Chest exam findings are subtle but the radiograph shows diffuse interstitial infiltrates ('walking pneumonia'). What is the likely cause and treatment?", "choices": ["Streptococcus pneumoniae; amoxicillin", "Respiratory syncytial virus; supportive care", "Staphylococcus aureus; vancomycin", "Mycoplasma pneumoniae", "Pneumocystis jirovecii; cotrimoxazole"], "ans": 3, "exp": "Atypical/'walking' pneumonia ในเด็กโต/วัยรุ่น มัก Mycoplasma pneumoniae: gradual onset, dry cough, malaise, headache, findings น้อยเทียบกับ CXR (diffuse interstitial). อาจมี extrapulmonary (hemolytic anemia จาก cold agglutinin, rash). รักษาด้วย macrolide (azithromycin) เพราะไม่มี cell wall (beta-lactam ไม่ได้ผล)"}, {"topic": "Asthma - Acute", "q": "A 6-year-old known asthmatic presents with acute wheezing, tachypnea, and use of accessory muscles after exposure to a trigger. What is the most appropriate first-line acute treatment?", "choices": ["Oral antibiotics directed at a respiratory infection", "Inhaled corticosteroid used alone as a rescue agent", "Chest physiotherapy alone to clear the airways", "Immediate intubation and ventilation for every child", "Inhaled short-acting beta-agonist plus systemic steroid"], "ans": 4, "exp": "Acute asthma exacerbation: first-line คือ inhaled short-acting beta-agonist (SABA, salbutamol) ซ้ำ + systemic corticosteroid (เร่งการหาย/ลด relapse) + oxygen ตามต้องการ; เพิ่ม ipratropium ในรายรุนแรง. Antibiotics ไม่จำเป็นถ้าไม่มี bacterial infection. ICS เป็น controller ไม่ใช่ rescue"}, {"topic": "Asthma - Chronic Control", "q": "A 7-year-old has daytime asthma symptoms several times a week and nighttime awakenings, using his reliever inhaler frequently. What is the most appropriate step-up controller therapy?", "choices": ["Add a daily low-dose inhaled corticosteroid", "Use only as-needed short-acting beta-agonist", "Start long-term oral corticosteroids", "Prescribe antibiotics prophylactically", "Add a long-acting beta-agonist as monotherapy"], "ans": 0, "exp": "Asthma ที่ควบคุมไม่ได้ (symptoms หลายครั้ง/สัปดาห์, nocturnal, ใช้ reliever บ่อย) ควร step-up ด้วย 'daily low-dose inhaled corticosteroid' (controller หลักในเด็ก). LABA ห้ามใช้ monotherapy (ต้องคู่กับ ICS) และในเด็กเล็กมักเพิ่ม ICS ก่อน. Oral steroid ระยะยาวเลี่ยง (side effects)"}, {"topic": "Foreign Body Aspiration", "q": "A previously well 18-month-old suddenly develops coughing, choking, and wheezing while eating peanuts, with decreased breath sounds and localized wheeze on the right. What is the most likely diagnosis?", "choices": ["Acute asthma exacerbation from an allergen trigger", "Foreign body aspiration into a main bronchus", "Viral bronchiolitis from respiratory syncytial virus", "Croup (laryngotracheobronchitis) from parainfluenza", "Lobar bacterial pneumonia from pneumococcus"], "ans": 1, "exp": "Foreign body aspiration: sudden choking/cough/wheeze ในเด็กวัยเตาะแตะ (มัก peanuts/small objects), unilateral decreased breath sounds/localized wheeze (มัก right main bronchus). CXR อาจเห็น hyperinflation/air trapping ข้างที่อุด (หรือปกติ). วินิจฉัย+รักษาด้วย bronchoscopy. Sudden onset ในเด็กที่เคยปกติเป็นเบาะแสสำคัญ"}, {"topic": "Pediatric TB", "q": "An 8-year-old with chronic cough, weight loss, and night sweats has a household contact with active pulmonary tuberculosis. A tuberculin skin test is positive and chest radiograph shows hilar lymphadenopathy. What is the appropriate management of active TB?", "choices": ["Isoniazid monotherapy", "A short course of amoxicillin", "Multidrug antituberculous therapy", "Observation only", "Corticosteroids alone"], "ans": 2, "exp": "Pediatric active TB: chronic cough/weight loss/night sweats + TB contact + positive TST + hilar lymphadenopathy. รักษาด้วย multidrug regimen (2 เดือน HRZE ตามด้วย 4 เดือน HR) เหมือนผู้ใหญ่แต่ปรับ dose. Latent TB (positive test, no disease) รักษาด้วย isoniazid (หรือ regimen สั้น) monotherapy. BCG ป้องกัน severe TB"}, {"topic": "Acute Otitis Media", "q": "A 2-year-old with a recent upper respiratory infection develops ear pain, fever, and irritability. Otoscopy shows a bulging, erythematous tympanic membrane with impaired mobility. What is the first-line antibiotic (if treatment is indicated)?", "choices": ["Azithromycin", "Ciprofloxacin", "Vancomycin", "High-dose amoxicillin", "Topical antibiotic drops"], "ans": 3, "exp": "Acute otitis media (bulging erythematous TM + effusion + acute symptoms), เชื้อบ่อย: S. pneumoniae, H. influenzae, M. catarrhalis. First-line antibiotic คือ 'high-dose amoxicillin' (amoxicillin-clavulanate ถ้าเคยได้ยา/ไม่ตอบสนอง). ในเด็กโตอาการไม่รุนแรงอาจ observe 48-72 ชม. เพราะหลายรายหายเอง"}, {"topic": "Streptococcal Pharyngitis", "q": "A 6-year-old has fever, sore throat, tonsillar exudates, tender anterior cervical lymphadenopathy, and NO cough or coryza. What is the appropriate management?", "choices": ["Treat every sore throat empirically with azithromycin", "Give antiviral therapy for the presumed viral cause", "Do no testing since all pharyngitis is viral", "Proceed directly to tonsillectomy for the infection", "Confirm with a rapid strep test, then give penicillin"], "ans": 4, "exp": "Group A Strep pharyngitis (Centor/McIsaac: fever, tonsillar exudate, tender anterior cervical nodes, 'no cough'): ยืนยันด้วย rapid antigen test/throat culture ในเด็ก (เพราะแยกจาก viral ยาก) แล้วรักษาด้วย penicillin/amoxicillin เพื่อลดอาการ, ป้องกัน suppurative complications และ rheumatic fever. เด็ก <3 ปีพบ strep pharyngitis น้อย"}, {"topic": "Fever Without Source", "q": "A well-appearing, fully immunized 2-year-old has a fever of 39°C for 1 day without localizing signs, and looks non-toxic. What is the most appropriate approach?", "choices": ["Careful clinical assessment with symptomatic care and follow-up", "Immediate lumbar puncture for every febrile child", "Empiric broad-spectrum intravenous antibiotics for all", "Hospital admission of every child regardless of appearance", "A CT scan of the head to exclude a serious cause"], "ans": 0, "exp": "เด็กโต (well-appearing, fully immunized) ที่มี fever without localizing source และดู non-toxic ส่วนใหญ่เป็น self-limited viral. แนวทางคือ ประเมิน clinical อย่างระวัง, symptomatic care, safety-net/follow-up, ไม่จำเป็นต้อง extensive workup. เกณฑ์ต่างออกไปในทารกเล็ก (โดยเฉพาะ <3 เดือน) ที่ต้องประเมิน serious bacterial infection เข้มข้น"}, {"topic": "Neonatal/Infant Fever <3 months", "q": "A 3-week-old previously well infant presents with a rectal temperature of 38.5°C and no obvious source. What is the most appropriate management?", "choices": ["Reassurance and discharge with paracetamol", "Full sepsis workup and empiric antibiotics", "Oral antibiotics as an outpatient", "Observation at home for 48 hours", "Antipyretics alone and recheck in a week"], "ans": 1, "exp": "ทารก <28 วัน (และมัก <60-90 วัน) ที่มีไข้ ≥38°C ต้องประเมินอย่างจริงจังเพราะเสี่ยง serious bacterial infection (UTI, bacteremia, meningitis) และอาการไม่จำเพาะ. แนวทาง: full sepsis workup (blood, urine, CSF) + empiric IV antibiotics (เช่น ampicillin + gentamicin/cefotaxime) + admit. ต่างจากเด็กโตอย่างสิ้นเชิง"}, {"topic": "Impetigo", "q": "A 5-year-old has honey-colored crusted lesions around the nose and mouth that are spreading, without systemic symptoms. What is the diagnosis and treatment for localized disease?", "choices": ["Herpes simplex; oral acyclovir", "Eczema herpeticum; IV acyclovir", "Impetigo; topical mupirocin", "Tinea; topical antifungal", "Cellulitis; IV antibiotics"], "ans": 2, "exp": "Impetigo (Staphylococcus aureus, Group A Strep): honey-colored crusts, มักรอบจมูก/ปาก, ติดต่อได้. Localized รักษาด้วย topical mupirocin; แพร่กระจาย/รุนแรงใช้ oral antibiotics (cephalexin/dicloxacillin). Non-bullous พบบ่อยสุด. ภาวะแทรกซ้อน: post-streptococcal glomerulonephritis (ไม่ใช่ rheumatic fever จาก skin infection)"}, {"topic": "Dengue Fever", "q": "A 9-year-old in Thailand has 3 days of high fever, severe headache, retro-orbital pain, myalgia, and a positive tourniquet test. CBC shows leukopenia and thrombocytopenia. What is the most likely diagnosis?", "choices": ["Typhoid fever", "Malaria", "Leptospirosis", "Dengue fever", "Measles"], "ans": 3, "exp": "Dengue fever: ไข้สูงเฉียบพลัน, retro-orbital pain, myalgia/arthralgia ('breakbone fever'), positive tourniquet test, leukopenia + thrombocytopenia. พบบ่อยในไทย (Aedes aegypti). ต้องเฝ้าระวังเข้าสู่ 'critical/leakage phase' ช่วงไข้ลด (วันที่ 3-7). รักษา supportive; หลีกเลี่ยง NSAIDs/aspirin (เลือดออก)"}, {"topic": "Dengue Warning Signs", "q": "A child with dengue is entering the critical phase around the time of defervescence. Which finding is a warning sign of severe dengue (plasma leakage) requiring close monitoring/admission?", "choices": ["Return of appetite with complete resolution of the fever", "A single isolated episode of loose stool", "A mild headache that improves fully with rest", "Reappearance of only a convalescent recovery rash", "Persistent vomiting with a rising hematocrit and low platelets"], "ans": 4, "exp": "Dengue warning signs (บ่งชี้เสี่ยง severe dengue/plasma leakage): abdominal pain/tenderness, persistent vomiting, clinical fluid accumulation (ascites/effusion), mucosal bleeding, lethargy/restlessness, hepatomegaly >2 ซม., และ 'rising hematocrit ร่วมกับ platelet ตกเร็ว'. เกิดช่วงไข้ลง (critical phase) → ต้อง admit + monitor + IV fluid ตามแนวทาง"}, {"topic": "Dengue Shock Syndrome", "q": "A child with dengue on day 5 (fever now resolved) develops cold clammy extremities, narrow pulse pressure (≤20 mmHg), tachycardia, and restlessness. What is the priority management?", "choices": ["Prompt isotonic intravenous fluid resuscitation for shock", "Platelet transfusion given regardless of any bleeding", "Broad-spectrum antibiotics for a presumed infection", "Oral rehydration solution given by mouth alone", "Systemic corticosteroids used as the first-line therapy"], "ans": 0, "exp": "Dengue shock syndrome (DSS): plasma leakage → hypovolemic shock ในช่วง critical phase (ไข้ลด): narrow pulse pressure (≤20), cold clammy skin, tachycardia, capillary refill นาน. Priority คือ isotonic IV fluid resuscitation (crystalloid, +/- colloid) ตามแนวทาง WHO/กระทรวง. Platelet transfusion ให้เฉพาะเมื่อมี bleeding สำคัญ ไม่ให้ตามตัวเลข. ไม่ใช้ steroid"}, {"topic": "Kawasaki Disease", "q": "A 3-year-old has fever for 6 days plus bilateral non-exudative conjunctivitis, cracked red lips with a strawberry tongue, a polymorphous rash, erythema of the palms and soles, and a single enlarged cervical lymph node. What is the most important complication to prevent?", "choices": ["Glomerulonephritis", "Coronary artery aneurysm", "Rheumatic heart disease", "Hepatic failure", "Osteomyelitis"], "ans": 1, "exp": "Kawasaki disease (medium-vessel vasculitis): fever ≥5 วัน + ≥4 ของ (bilateral non-exudative conjunctivitis, oral changes/strawberry tongue, polymorphous rash, extremity changes, cervical lymphadenopathy ≥1.5 ซม.). ภาวะแทรกซ้อนสำคัญคือ 'coronary artery aneurysm'. รักษาด้วย IVIG + aspirin ภายใน 10 วันเพื่อลดความเสี่ยง coronary. ต้อง echocardiogram"}, {"topic": "Bacterial Meningitis - Infant", "q": "A 4-month-old has fever, lethargy, poor feeding, a bulging fontanelle, and a high-pitched cry. Lumbar puncture shows elevated opening pressure, high protein, low glucose, and neutrophilic pleocytosis. What is the appropriate empiric therapy?", "choices": ["Oral amoxicillin as outpatient antibacterial therapy", "Intravenous acyclovir alone without antibacterial cover", "Third-generation cephalosporin plus vancomycin", "Supportive care without any antibiotic treatment", "Empiric antifungal therapy for a presumed fungal cause"], "ans": 2, "exp": "Bacterial meningitis ในทารก/เด็ก (>1-3 เดือน): เชื้อบ่อย S. pneumoniae, N. meningitidis (Hib ลดลงหลังวัคซีน). CSF: neutrophilic pleocytosis, protein สูง, glucose ต่ำ. Empiric: third-gen cephalosporin (ceftriaxone/cefotaxime) + vancomycin (ครอบคลุม resistant pneumococcus); เพิ่ม dexamethasone (โดยเฉพาะ Hib). ทารก <1 เดือนต้องคลุม GBS/Listeria/E.coli (ampicillin + cefotaxime)"}, {"topic": "Viral Meningitis", "q": "A 7-year-old has fever, headache, neck stiffness, and photophobia but appears relatively well and alert. CSF shows lymphocytic pleocytosis with normal glucose and mildly elevated protein; Gram stain is negative. What is the most likely cause?", "choices": ["Pneumococcal meningitis", "Tuberculous meningitis", "Cryptococcal meningitis", "Enteroviral meningitis", "Meningococcal meningitis"], "ans": 3, "exp": "Viral (aseptic) meningitis, มัก enterovirus: meningeal signs แต่ผู้ป่วยดูดีกว่า bacterial. CSF: lymphocytic pleocytosis, glucose 'ปกติ', protein สูงเล็กน้อย, Gram stain negative. รักษา supportive (self-limited). ต่างจาก bacterial (neutrophil, glucose ต่ำ) และ TB meningitis (lymphocyte, glucose ต่ำมาก, protein สูงมาก)"}, {"topic": "Pediatric UTI", "q": "A 2-year-old girl has fever without an obvious source, irritability, and decreased appetite. Urinalysis shows pyuria and positive leukocyte esterase and nitrites. What is the most appropriate next step after starting treatment?", "choices": ["No treatment, since childhood UTIs are self-limited", "Immediate cystoscopy to inspect the bladder", "Topical antibiotics applied to the perineum", "Repeat the urine test in a month before treating", "Antibiotics and imaging to find an underlying abnormality"], "ans": 4, "exp": "Pediatric UTI: เด็กเล็กมักมาด้วยไข้ไม่มี source, irritability, poor feeding; urinalysis เห็น pyuria + nitrite/LE, ยืนยันด้วย urine culture (proper collection). รักษาด้วย antibiotics. หลัง febrile UTI (โดยเฉพาะเด็กเล็ก/ผิดปกติ) พิจารณา renal ultrasound +/- VCUG หา vesicoureteral reflux/anomaly. E. coli พบบ่อยที่สุด"}, {"topic": "Acute Gastroenteritis - Dehydration", "q": "A 1-year-old with acute watery diarrhea and vomiting is mildly to moderately dehydrated but able to drink. What is the most appropriate first-line management?", "choices": ["Oral rehydration solution", "Intravenous fluids for all cases", "Antidiarrheal agents (loperamide)", "Broad-spectrum antibiotics", "Withhold all fluids to 'rest the gut'"], "ans": 0, "exp": "Acute gastroenteritis (มัก rotavirus/norovirus): first-line สำหรับ mild-moderate dehydration คือ 'oral rehydration solution (ORS)' + continue feeding. IV fluids สงวนไว้สำหรับ severe dehydration/shock หรือกิน ORS ไม่ได้. 'ไม่' ให้ antidiarrheal (loperamide) ในเด็ก และ antibiotics เฉพาะบางเชื้อ (เช่น dysentery/cholera). Zinc supplementation ช่วยลดระยะและความรุนแรง"}, {"topic": "Severe Dehydration", "q": "A 10-month-old with profuse diarrhea is lethargic, has sunken eyes, a very slow skin pinch, cold extremities, and weak pulses. What is the most appropriate immediate management?", "choices": ["Oral rehydration solution by cup", "Rapid intravenous isotonic fluid bolus", "Small sips of water only", "Antiemetics and observation", "Oral antibiotics and discharge"], "ans": 1, "exp": "Severe dehydration/hypovolemic shock (lethargy, sunken eyes, skin pinch กลับช้ามาก, cold extremities, weak pulse): ต้อง IV isotonic fluid bolus (normal saline/Ringer's lactate) ทันทีเพื่อ resuscitate, แล้วค่อยชดเชย deficit + maintenance. ORS ใช้ไม่ได้ในภาวะ shock/ซึม (เสี่ยงสำลัก). ประเมิน electrolytes"}, {"topic": "Typhoid Fever", "q": "An 8-year-old has a week of stepwise rising fever, abdominal pain, headache, relative bradycardia, hepatosplenomegaly, and rose spots on the trunk. Blood culture grows a gram-negative rod. What is the most likely diagnosis?", "choices": ["Dengue fever", "Malaria", "Typhoid fever", "Leptospirosis", "Scrub typhus"], "ans": 2, "exp": "Typhoid (enteric) fever: Salmonella Typhi, ติดจาก contaminated food/water. อาการ: stepladder fever, abdominal pain, relative bradycardia (Faget sign), hepatosplenomegaly, rose spots. Complication: intestinal perforation/hemorrhage (สัปดาห์ที่ 3). Blood culture คือ gold standard ช่วงแรก. รักษาด้วย ceftriaxone/azithromycin (ระวัง resistance)"}, {"topic": "Malaria", "q": "A child returning from a forested border area of Thailand has cyclical high fever with chills and rigors, sweating, headache, and splenomegaly. A blood smear is the key test. Which is the most appropriate diagnostic step?", "choices": ["Blood culture alone to detect a bacterial cause", "Stool examination to look for enteric pathogens", "A chest radiograph to assess for pneumonia", "Thick and thin blood smears to identify the parasite", "A tuberculin skin test to screen for tuberculosis"], "ans": 3, "exp": "Malaria (Plasmodium; ในไทยพบ P. falciparum และ P. vivax แถบชายแดน/ป่า): cyclical fever + chills/rigors + sweating + splenomegaly + anemia. วินิจฉัยด้วย thick/thin blood smear (identify species + parasitemia) หรือ rapid diagnostic test. P. falciparum อาจรุนแรง (cerebral malaria, severe anemia). รักษาตาม species (artemisinin-based สำหรับ falciparum; primaquine เพิ่มสำหรับ vivax hypnozoites หลังเช็ค G6PD)"}, {"topic": "Mumps", "q": "An unimmunized 8-year-old develops fever and bilateral tender swelling of the parotid glands with earache worsened by chewing. What is a recognized complication, especially in post-pubertal males?", "choices": ["Coronary aneurysm", "Glomerulonephritis", "Rheumatic fever", "Hemolytic uremic syndrome", "Orchitis"], "ans": 4, "exp": "Mumps (paramyxovirus): parotitis (บวม tender, earache, เจ็บเวลาเคี้ยว). Complications: orchitis (post-pubertal males, เสี่ยง infertility ถ้า bilateral), aseptic meningitis, oophoritis, pancreatitis, sensorineural hearing loss. Self-limited, supportive. ป้องกันด้วย MMR"}, {"topic": "Diphtheria", "q": "An unimmunized child has fever, severe sore throat, and a gray adherent pseudomembrane over the tonsils and pharynx that bleeds when scraped, with marked cervical swelling ('bull neck'). What is the treatment principle?", "choices": ["Diphtheria antitoxin plus antibiotics", "Supportive care only", "Antivirals", "Surgical removal of the membrane only", "High-dose corticosteroids as sole therapy"], "ans": 0, "exp": "Diphtheria (Corynebacterium diphtheriae): gray adherent pseudomembrane ที่ bleed เมื่อขูด, bull neck, toxin-mediated myocarditis/neuropathy. รักษาด้วย 'diphtheria antitoxin' (neutralize toxin, ให้เร็ว) + antibiotics (penicillin/erythromycin) + airway management + isolation. ป้องกันด้วย DTaP. ห้ามขูด membrane (bleeding/obstruction)"}, {"topic": "Rabies Post-exposure", "q": "A child is bitten by a stray dog that then runs away and cannot be observed, in a rabies-endemic area. The wound is on the hand. What is the most appropriate management?", "choices": ["Thorough wound washing alone as sufficient treatment", "Wound washing plus rabies vaccine and immunoglobulin", "Rabies vaccine only, without any immunoglobulin", "Observation of the child for symptoms before treating", "A course of oral antibiotics as the only measure"], "ans": 1, "exp": "Rabies post-exposure prophylaxis (category III: bite/broken skin): (1) ล้างแผลด้วยสบู่/น้ำมากๆ นาน ≥15 นาที, (2) rabies vaccine series, (3) rabies immunoglobulin (RIG) แทรกรอบแผล (สำหรับผู้ไม่เคยได้วัคซีนมาก่อน). Rabies เป็น fatal เกือบ 100% เมื่อมีอาการ → ต้อง prophylaxis ทันทีในพื้นที่ endemic. อาจให้ tetanus prophylaxis + antibiotics ด้วย"}, {"topic": "Infectious Mononucleosis", "q": "A 15-year-old has fever, severe exudative pharyngitis, marked cervical (and posterior) lymphadenopathy, splenomegaly, and fatigue. He develops a rash after receiving amoxicillin. Atypical lymphocytes are seen. What is the diagnosis?", "choices": ["Streptococcal pharyngitis", "Diphtheria", "Infectious mononucleosis", "Kawasaki disease", "Acute HIV infection"], "ans": 2, "exp": "Infectious mononucleosis (EBV): exudative pharyngitis + posterior cervical lymphadenopathy + splenomegaly + fatigue + atypical lymphocytes, positive heterophile (Monospot). Ampicillin/amoxicillin ทำให้เกิด morbilliform rash (คลาสสิก). หลีกเลี่ยง contact sports (เสี่ยง splenic rupture). Supportive; steroid เฉพาะกรณี airway obstruction"}, {"topic": "Influenza", "q": "During flu season, a child has abrupt onset of high fever, myalgia, headache, cough, and sore throat. Which antiviral, if started early (within 48 hours), can shorten the illness?", "choices": ["Acyclovir", "Amoxicillin", "Azithromycin", "Oseltamivir", "Ribavirin"], "ans": 3, "exp": "Influenza: abrupt fever, myalgia, headache, respiratory symptoms. Oseltamivir (neuraminidase inhibitor) ได้ผลดีที่สุดถ้าเริ่มภายใน 48 ชม., แนะนำในกลุ่มเสี่ยง/รุนแรง. ส่วนใหญ่ในเด็กสุขภาพดีเป็น self-limited (supportive). หลีกเลี่ยง aspirin (Reye). ป้องกันด้วย annual influenza vaccine (≥6 เดือน). ระวัง secondary bacterial pneumonia"}, {"topic": "MIS-C", "q": "Several weeks after a SARS-CoV-2 infection, a previously healthy child develops persistent fever, rash, conjunctivitis, abdominal pain, and shock with elevated inflammatory markers and cardiac dysfunction. What is the most likely diagnosis?", "choices": ["A simple self-limited viral exanthem illness", "Acute appendicitis with peritoneal irritation", "Nephrotic syndrome with heavy proteinuria", "Henoch-Schonlein purpura with palpable purpura", "Multisystem inflammatory syndrome in children (MIS-C)"], "ans": 4, "exp": "MIS-C (multisystem inflammatory syndrome in children) เกิดหลังติด SARS-CoV-2 หลายสัปดาห์: persistent fever + multisystem involvement (mucocutaneous คล้าย Kawasaki, GI, cardiac dysfunction/shock, coagulopathy) + markedly elevated inflammatory markers. รักษาด้วย IVIG +/- corticosteroids และ supportive/cardiac care. ต้องแยกจาก sepsis และ Kawasaki"}, {"topic": "Osteomyelitis", "q": "A 9-year-old has fever and refuses to bear weight, with point tenderness, warmth, and swelling over the metaphysis of the distal femur. Blood cultures and MRI are pending. What is the most common causative organism?", "choices": ["Staphylococcus aureus", "Escherichia coli", "Streptococcus pneumoniae", "Pseudomonas aeruginosa", "Neisseria gonorrhoeae"], "ans": 0, "exp": "Acute hematogenous osteomyelitis ในเด็ก มักเกิดที่ metaphysis ของ long bones (rich blood supply): fever, localized bone pain/tenderness, refusal to bear weight. เชื้อที่พบบ่อยที่สุดคือ 'Staphylococcus aureus'. วินิจฉัยด้วย MRI (เร็วสุด), blood culture, ESR/CRP สูง. รักษาด้วย IV antibiotics (+/- surgical drainage). ในทารกอาจลาม joint"}, {"topic": "Septic Arthritis", "q": "A 3-year-old with fever holds the hip flexed, abducted, and externally rotated and refuses to move it, with severe pain on any passive motion. Joint aspiration is planned. What is the most appropriate management?", "choices": ["Oral anti-inflammatory drugs with watchful observation", "Urgent joint aspiration/drainage plus intravenous antibiotics", "Physiotherapy alone to preserve the joint range", "Simple immobilization without any joint aspiration", "Topical analgesics applied over the affected joint"], "ans": 1, "exp": "Septic arthritis เป็น emergency: fever + joint held in position of comfort (hip: flexed/abducted/externally rotated) + severe pain on passive movement + refusal to move. ต้อง urgent joint aspiration (diagnostic + therapeutic) + IV antibiotics (ครอบคลุม S. aureus) +/- surgical drainage เพื่อป้องกัน joint destruction/AVN. แยกจาก transient synovitis (afebrile, ดูดีกว่า, Kocher criteria)"}, {"topic": "Orbital Cellulitis", "q": "A child with recent sinusitis develops eyelid swelling, redness, and now painful eye movement (ophthalmoplegia), proptosis, and reduced visual acuity. What is the diagnosis and the appropriate management?", "choices": ["Preseptal cellulitis; oral antibiotics at home", "Allergic conjunctivitis; antihistamines", "Orbital cellulitis", "Chalazion; warm compresses", "Viral conjunctivitis; supportive care"], "ans": 2, "exp": "Orbital (post-septal) cellulitis (มักลามจาก ethmoid sinusitis): eyelid swelling + 'painful/limited eye movement, proptosis, decreased vision' (แยกจาก preseptal ที่ไม่มีอาการเหล่านี้). เป็น emergency → admit, CT orbit/sinus, IV broad-spectrum antibiotics, +/- surgical drainage. เสี่ยง vision loss, cavernous sinus thrombosis, intracranial spread"}, {"topic": "Retropharyngeal Abscess", "q": "A 3-year-old has fever, neck stiffness, drooling, muffled voice, and refuses to extend the neck after a recent pharyngitis. Lateral neck radiograph shows widened prevertebral soft tissue. What is the diagnosis?", "choices": ["Epiglottitis with a swollen cherry-red epiglottis", "Croup with a barking cough and inspiratory stridor", "Bacterial meningitis with neck stiffness", "Retropharyngeal abscess in the deep neck space", "Peritonsillar abscess with uvular deviation"], "ans": 3, "exp": "Retropharyngeal abscess (เด็ก 2-4 ปี, lymph nodes ใน retropharyngeal space): fever, neck stiffness/torticollis, drooling, muffled voice, refusal to move neck, +/- stridor. Lateral neck X-ray เห็น widened prevertebral soft tissue; ยืนยัน CT. รักษาด้วย IV antibiotics +/- surgical drainage. เสี่ยง airway obstruction และ mediastinitis"}, {"topic": "Scabies", "q": "An infant has intense pruritus worse at night, with burrows and vesicles/pustules on the palms, soles, and web spaces, and other family members are itchy. What is the treatment?", "choices": ["Oral antihistamine alone", "Topical corticosteroid alone", "Oral antibiotics", "Topical antifungal", "Topical permethrin"], "ans": 4, "exp": "Scabies (Sarcoptes scabiei): intense pruritus (worse at night), burrows, พบที่ web spaces, wrists, และในทารกที่ palms/soles/head. ติดต่อในครอบครัว. รักษาด้วย topical permethrin 5% (ในทารกอาจรวมศีรษะ), รักษาทุกคนในบ้าน + ซักผ้า/เครื่องนอนน้ำร้อน. Oral ivermectin ใช้กรณี crusted/ดื้อ. อาการคันอาจอยู่ต่อหลายสัปดาห์หลังรักษา"}, {"topic": "Tinea Capitis", "q": "A 6-year-old has a scaly patch of hair loss on the scalp with broken hairs ('black dots') and an enlarged occipital lymph node. What is the appropriate treatment?", "choices": ["Oral antifungal", "Topical antifungal cream alone", "Topical corticosteroid", "Oral antibiotics", "Selenium sulfide shampoo alone"], "ans": 0, "exp": "Tinea capitis (dermatophyte, เช่น Trichophyton/Microsporum): scaly alopecic patch, broken hairs/black dots, occipital lymphadenopathy, อาจเกิด 'kerion' (boggy inflammatory mass). ต้อง 'oral' antifungal (griseofulvin/terbinafine) เพราะ topical เข้า hair follicle ไม่พอ; adjunct antifungal shampoo ลดการแพร่. ต่างจาก tinea corporis (topical เพียงพอ)"}, {"topic": "Herpetic Gingivostomatitis", "q": "A 2-year-old has high fever, irritability, refusal to eat, and painful vesicles and ulcers on the gums, tongue, and lips with bleeding, tender gums. What is the causative agent?", "choices": ["Coxsackievirus", "Herpes simplex virus type 1", "Candida albicans", "Group A Streptococcus", "Measles virus"], "ans": 1, "exp": "Primary herpetic gingivostomatitis (HSV-1): fever + painful vesicles/ulcers ของ 'anterior' mouth, gingiva, lips, tongue + tender/bleeding gums + refusal to eat (เสี่ยง dehydration). รักษา supportive (hydration, analgesia); acyclovir ถ้าเริ่มเร็ว/รุนแรง/immunocompromised. ต่างจาก herpangina (Coxsackie, ulcers ที่ posterior pharynx) และ oral thrush (Candida, white plaques)"}, {"topic": "Meningococcemia", "q": "An adolescent rapidly develops high fever, hypotension, and a non-blanching petechial/purpuric rash that is spreading, along with signs of shock. What is the priority action?", "choices": ["Awaiting blood culture results before any antibiotics", "Oral antibiotics with routine outpatient follow-up", "Immediate parenteral antibiotics and fluid resuscitation", "Antihistamines directed at the spreading rash", "Topical corticosteroids applied to the skin lesions"], "ans": 2, "exp": "Meningococcemia (Neisseria meningitidis): fulminant sepsis + non-blanching petechial/purpuric rash + shock (purpura fulminans, DIC, Waterhouse-Friderichsen). เป็น emergency — ให้ parenteral antibiotics (ceftriaxone) 'ทันที' + aggressive fluid resuscitation, 'ไม่รอ' culture. ให้ chemoprophylaxis (rifampicin/ciprofloxacin/ceftriaxone) แก่ close contacts. ป้องกันด้วย meningococcal vaccine"}, {"topic": "Staph Scalded Skin Syndrome", "q": "A toddler has fever, diffuse erythema, and superficial blistering with skin peeling in sheets; gentle lateral pressure causes the skin to slough (Nikolsky sign). The mucous membranes are spared. What is the cause?", "choices": ["Stevens-Johnson syndrome", "Scarlet fever", "Toxic epidermal necrolysis from drugs", "Staphylococcal scalded skin syndrome", "Bullous impetigo localized only"], "ans": 3, "exp": "Staphylococcal scalded skin syndrome (SSSS): exfoliative toxin ของ S. aureus ทำให้ superficial epidermal splitting → diffuse erythema, peeling in sheets, positive Nikolsky sign, 'mucous membranes spared' (ต่างจาก SJS/TEN ที่มี mucosal + drug-related, deeper). พบในเด็กเล็ก. รักษาด้วย anti-staph antibiotics + supportive/fluid/skin care"}, {"topic": "Toxic Shock Syndrome", "q": "A child develops high fever, hypotension, a diffuse macular erythroderma (sunburn-like rash), vomiting/diarrhea, and multi-organ involvement, later followed by desquamation of the palms and soles. What is the mechanism?", "choices": ["An IgE-mediated systemic anaphylactic reaction", "A benign self-limited viral exanthem", "An autoimmune small-vessel vasculitis", "An inherited terminal complement deficiency", "Superantigen toxin produced by Staphylococcus aureus"], "ans": 4, "exp": "Toxic shock syndrome (TSS): superantigen (TSST-1 ของ S. aureus, หรือ group A Strep exotoxin) กระตุ้น massive cytokine → fever, hypotension, diffuse erythroderma, multi-organ dysfunction, ตามด้วย desquamation (palms/soles). รักษา: source control (remove tampon/drain), IV fluids, antibiotics (clindamycin ลด toxin + beta-lactam), +/- IVIG"}, {"topic": "Pediatric HIV", "q": "An infant born to an HIV-positive mother is being followed. Which prophylaxis is recommended to prevent Pneumocystis jirovecii pneumonia in HIV-exposed/infected infants?", "choices": ["Cotrimoxazole", "Isoniazid", "Fluconazole", "Azithromycin", "Acyclovir"], "ans": 0, "exp": "HIV-exposed/infected infants เริ่ม 'cotrimoxazole' prophylaxis (~4-6 สัปดาห์) ป้องกัน Pneumocystis jirovecii pneumonia (PCP) จนกว่าจะยืนยันสถานะ/immune status ดีขึ้น. ร่วมกับ maternal ART + infant ARV prophylaxis เพื่อลด transmission และ early ART ถ้าติดเชื้อ. PCP เป็น AIDS-defining ที่รุนแรงในทารก"}, {"topic": "Cystic Fibrosis", "q": "A child has recurrent pneumonia, chronic productive cough, failure to thrive, greasy foul-smelling stools (steatorrhea), and clubbing. A sweat chloride test is elevated. What is the pathophysiology?", "choices": ["Isolated ciliary dysfunction impairing mucus clearance", "Defective CFTR chloride channel causing thick secretions", "A primary antibody (immunoglobulin) deficiency", "Alpha-1 antitrypsin deficiency damaging the lungs", "A surfactant protein deficiency of the alveoli"], "ans": 1, "exp": "Cystic fibrosis (autosomal recessive, CFTR mutation): defective chloride channel → thick secretions → recurrent pulmonary infections (Pseudomonas, S. aureus), bronchiectasis, pancreatic insufficiency (steatorrhea, FTT, fat-soluble vitamin deficiency), meconium ileus, infertility. วินิจฉัยด้วย sweat chloride สูง + genetics. รักษา: airway clearance, antibiotics, pancreatic enzyme replacement, CFTR modulators"}, {"topic": "Parapneumonic Effusion/Empyema", "q": "A child with bacterial pneumonia remains febrile with worsening respiratory distress. Examination shows dullness to percussion and decreased breath sounds at the base; imaging confirms a significant pleural effusion. What is the appropriate next step?", "choices": ["Continue the same oral antibiotics only", "Chest physiotherapy alone", "Pleural fluid drainage plus antibiotics", "Bronchodilators", "Immediate lobectomy"], "ans": 2, "exp": "Parapneumonic effusion/empyema: pneumonia ที่ persistent fever + effusion (dullness, decreased breath sounds). ต้อง drainage (thoracocentesis/chest tube, +/- fibrinolytics หรือ VATS ถ้า loculated/empyema) + IV antibiotics ครอบคลุมเชื้อ (S. pneumoniae, S. aureus). Empyema (pus) ต้อง drainage เสมอ"}, {"topic": "Allergic Rhinitis", "q": "A child has recurrent sneezing, clear rhinorrhea, nasal itching and congestion, with pale boggy nasal mucosa, allergic shiners, and a transverse nasal crease. Symptoms worsen with dust/pollen. What is the first-line treatment for persistent symptoms?", "choices": ["Oral antibiotics", "Systemic corticosteroids long-term", "Decongestant nasal spray used continuously", "Intranasal corticosteroid", "Antitussive syrup"], "ans": 3, "exp": "Allergic rhinitis: sneezing, clear rhinorrhea, nasal itch/congestion, pale boggy mucosa, allergic shiners, nasal salute/crease, สัมพันธ์กับ allergens. First-line สำหรับ persistent/moderate-severe คือ 'intranasal corticosteroid' (+/- oral/intranasal antihistamine). Avoidance ของ allergen สำคัญ. Topical decongestant นานเกินเสี่ยง rhinitis medicamentosa. สัมพันธ์กับ asthma/eczema (atopic march)"}, {"topic": "Bacterial Sinusitis", "q": "A child has persistent nasal discharge and cough lasting more than 10 days without improvement, or worsening after initial improvement, with facial pain. What is the most appropriate management of acute bacterial sinusitis?", "choices": ["Azithromycin used alone as the first-line drug", "Oral antihistamines directed at the symptoms", "Immediate endoscopic sinus surgery for drainage", "Antiviral therapy for a presumed viral cause", "High-dose amoxicillin or amoxicillin-clavulanate"], "ans": 4, "exp": "Acute bacterial rhinosinusitis ในเด็ก วินิจฉัยเมื่อ symptoms 'persistent >10 วัน' โดยไม่ดีขึ้น, 'worsening/double-sickening', หรือ severe onset. เชื้อคล้าย AOM (S. pneumoniae, H. influenzae, M. catarrhalis). รักษาด้วย amoxicillin +/- clavulanate. เฝ้าระวัง complications (orbital/intracranial). ส่วนใหญ่ URI <10 วันเป็น viral ไม่ต้อง antibiotics"}, {"topic": "Acute Mastoiditis", "q": "A child with a recent or ongoing acute otitis media develops fever, postauricular swelling, redness, tenderness, and a protruding ear (auricle pushed forward). What is the diagnosis?", "choices": ["Acute mastoiditis", "Otitis externa", "Preauricular lymphadenitis", "Parotitis", "Cellulitis of the cheek"], "ans": 0, "exp": "Acute mastoiditis (complication ของ AOM): postauricular swelling/erythema/tenderness + protruding auricle (หูกาง) + fever. เป็น complication ที่ต้อง admit, IV antibiotics, imaging (CT), +/- myringotomy/mastoidectomy. เสี่ยงลาม intracranial. ต่างจาก otitis externa (ปวดเมื่อดึงใบหู, ไม่ดันหูกาง)"}, {"topic": "Peritonsillar Abscess", "q": "An adolescent with worsening sore throat has severe unilateral throat pain, trismus, a muffled 'hot potato' voice, and uvular deviation to the opposite side with a bulging tonsil. What is the diagnosis?", "choices": ["Retropharyngeal abscess", "Peritonsillar abscess", "Epiglottitis", "Infectious mononucleosis", "Diphtheria"], "ans": 1, "exp": "Peritonsillar abscess (quinsy): unilateral severe sore throat, trismus, muffled voice, drooling, และ 'uvular deviation ไปด้านตรงข้าม' + bulging peritonsillar area. พบในวัยรุ่น/ผู้ใหญ่ (ต่างจาก retropharyngeal ในเด็กเล็ก). รักษาด้วย needle aspiration/incision & drainage + antibiotics"}, {"topic": "Laryngomalacia", "q": "A 6-week-old, otherwise thriving, has intermittent inspiratory stridor that worsens when supine, feeding, or agitated and improves when prone. There is no distress and growth is normal. What is the most likely diagnosis?", "choices": ["Vocal cord paralysis", "Subglottic stenosis", "Laryngomalacia", "Vascular ring", "Croup"], "ans": 2, "exp": "Laryngomalacia: สาเหตุที่พบบ่อยที่สุดของ chronic stridor ในทารก — floppy supraglottic structures collapse ขณะหายใจเข้า → inspiratory stridor แย่ลงเมื่อ supine/feeding/crying, ดีขึ้น prone. ทารก thriving, ไม่ distress. ส่วนใหญ่หายเองภายใน 12-18 เดือน. Severe (FTT, apnea, cyanosis) พิจารณา supraglottoplasty"}, {"topic": "Adenotonsillar Hypertrophy / OSA", "q": "A 5-year-old snores loudly with witnessed apneic pauses, mouth breathing, restless sleep, and daytime behavioral problems. Examination shows enlarged tonsils. What is the most likely cause and treatment?", "choices": ["Central sleep apnea managed with supplemental oxygen", "Poorly controlled asthma treated with inhaled steroids", "Allergic rhinitis treated with antihistamines alone", "Obstructive sleep apnea from adenotonsillar hypertrophy", "Narcolepsy treated with daytime stimulant medication"], "ans": 3, "exp": "Adenotonsillar hypertrophy เป็นสาเหตุที่พบบ่อยที่สุดของ obstructive sleep apnea (OSA) ในเด็ก: snoring, witnessed apnea, mouth breathing, restless sleep, daytime hyperactivity/behavioral/learning problems, +/- failure to thrive. รักษาหลักคือ adenotonsillectomy. ยืนยันด้วย polysomnography ในรายที่ไม่ชัด. ถ้าไม่รักษาเสี่ยง cor pulmonale"}, {"topic": "Pinworm", "q": "A 6-year-old has intense perianal itching, especially at night, disturbing sleep. Application of clear tape to the perianal area in the morning reveals eggs. What is the treatment?", "choices": ["Metronidazole", "Praziquantel", "Ivermectin only", "Topical corticosteroid", "Albendazole or mebendazole"], "ans": 4, "exp": "Enterobius vermicularis (pinworm): perianal itching ตอนกลางคืน (female worm วางไข่รอบ anus). วินิจฉัยด้วย 'scotch tape test' (เห็นไข่). รักษาด้วย albendazole/mebendazole และ 'repeat dose ใน 2 สัปดาห์' + รักษาทั้งครอบครัว + สุขอนามัย (ล้างมือ, ตัดเล็บ, ซักผ้า). พบบ่อยที่สุดใน helminth ของเด็กในเขตอบอุ่น/สุขอนามัย"}, {"topic": "Ascariasis", "q": "A child from a rural area with poor sanitation passes a large round worm in the stool and has had a cough with transient pulmonary infiltrates earlier, and now vague abdominal pain. What is the causative organism?", "choices": ["Ascaris lumbricoides", "Enterobius vermicularis", "Taenia solium", "Giardia lamblia", "Ancylostoma duodenale"], "ans": 0, "exp": "Ascaris lumbricoides (soil-transmitted helminth): ไข่จาก contaminated soil/food, larvae migrate ผ่านปอด (Loffler syndrome: cough + transient eosinophilic pulmonary infiltrates) แล้วโตในลำไส้ (abdominal pain, obstruction, biliary/pancreatic). รักษาด้วย albendazole/mebendazole. ป้องกันด้วยสุขอนามัย/mass deworming"}, {"topic": "Giardiasis", "q": "A child returns from camping with 2 weeks of foul-smelling, greasy, non-bloody diarrhea, bloating, flatulence, and weight loss after drinking untreated stream water. What is the cause and treatment?", "choices": ["Shigella; ceftriaxone", "Giardia lamblia; metronidazole", "Rotavirus; supportive care", "Entamoeba histolytica; paromomycin only", "Vibrio cholerae; doxycycline"], "ans": 1, "exp": "Giardiasis (Giardia lamblia/duodenalis): จาก contaminated water (camping/stream), causes prolonged 'malabsorptive' diarrhea — foul greasy stool, bloating, flatulence, weight loss, 'no blood'. วินิจฉัยด้วย stool antigen/microscopy. รักษาด้วย metronidazole (หรือ tinidazole/nitazoxanide). ต่างจาก amoebic dysentery (bloody stool, invasive)"}, {"topic": "Amebic Dysentery", "q": "A child has bloody, mucoid diarrhea with abdominal pain and tenesmus. Stool microscopy shows trophozoites with ingested red blood cells. What is the treatment?", "choices": ["Supportive rehydration care without antiparasitics", "Albendazole directed against a helminth infection", "Metronidazole followed by a luminal agent for cysts", "Ceftriaxone alone for a presumed bacterial dysentery", "Praziquantel directed against a fluke infection"], "ans": 2, "exp": "Amebiasis (Entamoeba histolytica): invasive colitis → bloody mucoid diarrhea, tenesmus; trophozoites with ingested RBCs ใน stool. เสี่ยง amebic liver abscess. รักษาด้วย metronidazole (tissue) 'ตามด้วย luminal agent' (paromomycin/diloxanide) เพื่อกำจัด cyst ในลำไส้ (ป้องกัน relapse/แพร่). ป้องกันด้วยสุขอนามัย"}, {"topic": "Shigellosis", "q": "A young child has fever, crampy abdominal pain, and frequent small-volume bloody, mucoid stools (dysentery), and has a febrile seizure. What is the most likely bacterial cause?", "choices": ["Rotavirus", "Vibrio cholerae", "Giardia lamblia", "Shigella", "Enterotoxigenic E. coli"], "ans": 3, "exp": "Shigella dysentery: fever, crampy abdominal pain, tenesmus, small-volume 'bloody mucoid' stool; อาจมี febrile/afebrile seizure และ neurologic (จาก Shiga toxin/other). วินิจฉัยด้วย stool culture. รักษา rehydration + antibiotics (azithromycin/ceftriaxone) ในรายรุนแรง/dysentery. Shiga toxin-producing E. coli (STEC) เสี่ยง HUS (หลีกเลี่ยง antibiotics ใน STEC)"}, {"topic": "Cholera", "q": "During an outbreak, a child develops profuse, painless watery diarrhea described as 'rice-water stools' leading to rapid, severe dehydration. What is the priority management?", "choices": ["Antimotility drugs such as loperamide as first-line", "Withholding all fluids to reduce the stool output", "Antiviral therapy directed at the enteric virus", "Systemic corticosteroids to reduce gut inflammation", "Aggressive rehydration with careful electrolyte replacement"], "ans": 4, "exp": "Cholera (Vibrio cholerae): profuse painless 'rice-water' diarrhea → rapid severe dehydration/hypovolemic shock และ electrolyte loss. Priority คือ 'aggressive rehydration' (ORS สำหรับ mild-moderate, IV Ringer's สำหรับ severe) — ช่วยชีวิตได้. Antibiotics (doxycycline/azithromycin) ลดระยะและ volume ในรายรุนแรง. Zinc ในเด็ก. Public health/water sanitation สำคัญ"}, {"topic": "Hepatitis A", "q": "Several children at a school develop fever, malaise, anorexia, nausea, jaundice, and dark urine after eating contaminated food. Liver enzymes are markedly elevated. The illness is self-limited without chronic infection. What is the causative agent?", "choices": ["Hepatitis A virus", "Hepatitis B virus", "Hepatitis C virus", "Epstein-Barr virus", "Cytomegalovirus"], "ans": 0, "exp": "Hepatitis A: fecal-oral (contaminated food/water), acute self-limited hepatitis (fever, anorexia, nausea, jaundice, dark urine, elevated transaminases), 'ไม่มี chronic' infection/carrier. พบระบาดในเด็ก (มัก mild/anicteric). ป้องกันด้วยสุขอนามัยและ hepatitis A vaccine. Supportive care"}, {"topic": "Leptospirosis", "q": "A teenager who waded through floodwater develops high fever, severe myalgia (especially calves), conjunctival suffusion, headache, and jaundice with acute kidney injury (Weil disease). What is the causative organism and treatment?", "choices": ["Dengue virus; supportive care", "Leptospira; penicillin or doxycycline", "Salmonella Typhi; ceftriaxone", "Plasmodium falciparum; artemisinin", "Rickettsia; azithromycin"], "ans": 1, "exp": "Leptospirosis (Leptospira, ติดจากน้ำ/ดินปนเปื้อนปัสสาวะสัตว์ เช่น หนู — พบหลังน้ำท่วมในไทย): fever, severe myalgia (โดยเฉพาะ calves), 'conjunctival suffusion', headache; severe (Weil disease) = jaundice + AKI + bleeding. รักษาด้วย penicillin หรือ doxycycline. ป้องกันหลีกเลี่ยงน้ำปนเปื้อน. Differential กับ dengue/scrub typhus ในไทย"}, {"topic": "Scrub Typhus", "q": "A child in a rural area of Thailand has fever, headache, myalgia, generalized lymphadenopathy, and a painless ulcer with a black crust (eschar) at the site of a mite bite. What is the treatment?", "choices": ["Ceftriaxone", "Amoxicillin", "Doxycycline (or azithromycin)", "Artemisinin combination therapy", "Metronidazole"], "ans": 2, "exp": "Scrub typhus (Orientia tsutsugamushi, ติดจาก chigger/mite bite): fever, headache, myalgia, lymphadenopathy, และ 'eschar' (แผลสะเก็ดดำ ที่จุดถูกกัด — เบาะแสสำคัญ), +/- rash. พบในไทย/เอเชีย. รักษาด้วย doxycycline (หรือ azithromycin ในเด็กเล็ก/ตั้งครรภ์). ตอบสนองเร็ว. Differential ของ acute undifferentiated febrile illness ในไทย"}, {"topic": "Chikungunya", "q": "A child in a dengue-endemic area has acute fever with prominent, severe symmetric polyarthralgia/arthritis and a maculopapular rash, transmitted by the same Aedes mosquito. What is the most likely diagnosis?", "choices": ["Dengue hemorrhagic fever", "Zika virus infection", "Malaria", "Chikungunya", "Rheumatic fever"], "ans": 3, "exp": "Chikungunya (alphavirus, Aedes mosquito): fever + 'prominent severe polyarthralgia/arthritis' (มักเด่นกว่า dengue) + maculopapular rash; joint pain อาจอยู่นานเป็นสัปดาห์-เดือน. Supportive care. ต่างจาก dengue (bleeding/plasma leakage) และ Zika (mild, congenital microcephaly, conjunctivitis). ทั้งสามนำโดย Aedes"}, {"topic": "Otitis Externa", "q": "A child who swims frequently develops ear pain that worsens when the tragus is pushed or the auricle is pulled, with a swollen, erythematous external ear canal and discharge, but a normal-appearing tympanic membrane. What is the treatment?", "choices": ["Oral amoxicillin for a middle-ear infection", "Systemic antifungal therapy for the ear canal", "Myringotomy to drain the middle-ear space", "Observation alone without any active treatment", "Topical antibiotic ear drops applied to the canal"], "ans": 4, "exp": "Otitis externa ('swimmer's ear'): pain on tragal pressure/auricle traction, canal swelling/erythema/discharge, TM ปกติ. เชื้อบ่อย Pseudomonas, S. aureus. รักษาด้วย 'topical' antibiotic +/- steroid ear drops + keep ear dry. ต่างจาก AOM (TM bulging, pain ไม่ขึ้นกับการดึงหู). Malignant otitis externa (diabetic/immunocompromised) รุนแรงต้อง systemic"}, {"topic": "Tuberculous Meningitis", "q": "A young child with a TB contact has 2 weeks of gradually worsening fever, lethargy, and vomiting, then develops cranial nerve palsies and decreased consciousness. CSF shows lymphocytic pleocytosis, very high protein, and very low glucose. What is the diagnosis?", "choices": ["Tuberculous meningitis", "Acute bacterial (pneumococcal) meningitis", "Viral (enteroviral) meningitis", "Cerebral malaria", "Guillain-Barre syndrome"], "ans": 0, "exp": "Tuberculous meningitis: subacute onset (สัปดาห์), basal meningitis → cranial nerve palsies, hydrocephalus, decreased consciousness. CSF: 'lymphocytic' pleocytosis, protein สูงมาก, glucose ต่ำมาก (คล้าย TB pattern). รักษาด้วย anti-TB (4 ยา) + corticosteroid (ลด mortality/neuro sequelae). Delay ในการรักษาเพิ่ม disability — ต้องรักษาเชิง empiric ถ้าสงสัย"}, {"topic": "Cerebral Malaria", "q": "A child with Plasmodium falciparum malaria develops impaired consciousness, seizures, and coma with a high parasitemia. What is the appropriate treatment for severe/cerebral malaria?", "choices": ["Oral chloroquine", "Intravenous artesunate", "Oral artemether-lumefantrine as first choice", "Doxycycline monotherapy", "Supportive care without antimalarials"], "ans": 1, "exp": "Severe/cerebral malaria (P. falciparum): impaired consciousness, seizures, coma, +/- severe anemia, hypoglycemia, high parasitemia. รักษาด้วย 'IV artesunate' (superior to quinine) + supportive care (จัดการ hypoglycemia, seizures, anemia). Cerebral malaria มี mortality สูง. Uncomplicated malaria ใช้ oral ACT. ต้องเช็ค G6PD ก่อน primaquine (vivax)"}, {"topic": "Pediatric Septic Shock", "q": "A child with fever, tachycardia, prolonged capillary refill, altered mental status, and hypotension is diagnosed with septic shock. What is the priority within the first hour?", "choices": ["Awaiting culture results before giving any antibiotics", "Oral rehydration with continued outpatient observation", "Rapid fluid boluses with early antibiotics and cultures", "Starting vasopressors before giving any intravenous fluid", "Systemic corticosteroids as the first-line therapy for all"], "ans": 2, "exp": "Pediatric septic shock: recognize early (tachycardia, prolonged cap refill, altered mental status, +/- hypotension — เด็ก compensate นานก่อน BP ตก). Priority ชั่วโมงแรก: obtain cultures, ให้ broad-spectrum antibiotics 'เร็ว', และ isotonic fluid boluses (ประเมินซ้ำ, ระวัง fluid overload); เพิ่ม vasopressors (epinephrine/norepinephrine) ถ้า fluid-refractory. ตาม Surviving Sepsis guidelines"}, {"topic": "Meningococcal Prophylaxis", "q": "A child is diagnosed with meningococcal meningitis. What should be done for close household contacts?", "choices": ["No action is needed", "Full treatment doses of IV antibiotics for 7 days", "Only vaccination, no antibiotics", "Chemoprophylaxis", "Observation for symptoms without prophylaxis"], "ans": 3, "exp": "Close contacts ของ meningococcal disease (household, daycare, ผู้สัมผัส secretions) ควรได้ 'chemoprophylaxis' โดยเร็ว: rifampicin, ciprofloxacin, หรือ ceftriaxone เพื่อกำจัด nasopharyngeal carriage และป้องกัน secondary case. Meningococcal vaccine ใช้ควบคุม outbreak/กลุ่มเสี่ยง. Hib exposure ก็มี rifampicin prophylaxis ในบางกรณี"}, {"topic": "Reye Syndrome", "q": "A child recovering from influenza or varicella who was given aspirin develops vomiting, lethargy progressing to encephalopathy, with elevated liver enzymes and hyperammonemia but minimal jaundice. What is the diagnosis?", "choices": ["Viral hepatitis A", "Bacterial meningitis", "Diabetic ketoacidosis", "Wilson disease", "Reye syndrome"], "ans": 4, "exp": "Reye syndrome: acute encephalopathy + fatty liver (hepatic dysfunction, hyperammonemia, elevated transaminases, 'minimal jaundice') หลัง viral illness (influenza, varicella) ที่ได้ 'aspirin'. จึง 'ห้ามให้ aspirin ในเด็ก' ที่มีไข้/ไวรัส (ยกเว้นข้อบ่งชี้เฉพาะ เช่น Kawasaki). รักษา supportive/ICU, จัดการ increased ICP และ metabolic"}, {"topic": "Bacterial Tracheitis", "q": "A child with a preceding viral URI acutely deteriorates with high fever, toxic appearance, stridor, and a brassy cough that does not respond to croup treatment (nebulized epinephrine). What is the most likely diagnosis?", "choices": ["Bacterial tracheitis", "Viral croup", "Epiglottitis", "Asthma", "Foreign body aspiration"], "ans": 0, "exp": "Bacterial tracheitis (มัก S. aureus, secondary to viral croup): toxic, high fever, stridor + brassy cough, 'ไม่ตอบสนอง' croup treatment (nebulized epinephrine/steroid). เป็น potentially life-threatening airway emergency → airway management, IV antibiotics, +/- bronchoscopy. อยู่ระหว่าง croup (viral, ตอบสนองยา) กับ epiglottitis (drooling, tripod)"}, {"topic": "Croup Severity Management", "q": "A child with croup has stridor at rest and moderate retractions but is not cyanotic. In addition to a single dose of corticosteroid, what is the most appropriate treatment for stridor at rest?", "choices": ["Nebulized salbutamol", "Nebulized epinephrine", "Oral antibiotics", "Chest physiotherapy", "Immediate intubation"], "ans": 1, "exp": "Croup ที่มี 'stridor at rest'/moderate-severe: ให้ corticosteroid (dexamethasone) 'ทุกราย' + 'nebulized epinephrine' สำหรับ stridor at rest (ออกฤทธิ์เร็ว, ต้องสังเกต ≥2-3 ชม.เพราะ rebound). Mild croup (barky cough, no stridor at rest) ให้ steroid + supportive. Intubation เฉพาะรายที่ล้มเหลว/impending failure"}, {"topic": "RSV Prophylaxis", "q": "A former premature infant with chronic lung disease is at high risk for severe RSV bronchiolitis. Which agent can be given as monthly injections during RSV season for prevention in high-risk infants?", "choices": ["Oral ribavirin", "RSV live vaccine", "Palivizumab (monoclonal antibody)", "Oseltamivir", "Intravenous immunoglobulin monthly"], "ans": 2, "exp": "Palivizumab (anti-RSV monoclonal antibody) ให้เป็น monthly injection ในฤดู RSV แก่ทารกกลุ่มเสี่ยงสูง (preterm, chronic lung disease, hemodynamically significant congenital heart disease) เพื่อ 'prevent' severe RSV bronchiolitis. เป็น passive immunoprophylaxis (ไม่ใช่ vaccine/ไม่ใช้รักษา). Bronchiolitis ที่เป็นแล้วรักษา supportive"}, {"topic": "Primary Ciliary Dyskinesia", "q": "A child has recurrent sinopulmonary infections, chronic wet cough with bronchiectasis, chronic otitis media, and situs inversus (dextrocardia). Neonatal respiratory distress was noted. What is the diagnosis?", "choices": ["Cystic fibrosis", "Selective IgA deficiency", "Asthma", "Primary ciliary dyskinesia", "Alpha-1 antitrypsin deficiency"], "ans": 3, "exp": "Primary ciliary dyskinesia (PCD): defective ciliary function → recurrent sinusitis/otitis, chronic wet cough/bronchiectasis, neonatal respiratory distress, และ ~50% มี 'situs inversus' (Kartagener triad = situs inversus + chronic sinusitis + bronchiectasis), infertility. ต่างจาก CF (sweat chloride, pancreatic insufficiency). วินิจฉัยด้วย nasal NO, ciliary studies, genetics"}, {"topic": "Bronchiectasis", "q": "A child has a chronic daily productive ('wet') cough with copious purulent sputum, recurrent chest infections, and clubbing. High-resolution CT shows dilated, thick-walled bronchi. What is the diagnosis?", "choices": ["Asthma", "Bronchiolitis", "Viral pneumonia", "Pulmonary embolism", "Bronchiectasis"], "ans": 4, "exp": "Bronchiectasis: permanent bronchial dilatation จาก recurrent infection/inflammation → chronic productive cough, purulent sputum, recurrent infections, clubbing; HRCT เห็น dilated thick-walled bronchi ('signet ring'). ในเด็กต้องหาสาเหตุ underlying (CF, PCD, immunodeficiency, foreign body, post-infectious เช่น หลัง measles/pertussis/TB). รักษา airway clearance + antibiotics + treat cause"}, {"topic": "Aspiration Pneumonia", "q": "A child with cerebral palsy and swallowing dysfunction has recurrent pneumonias, typically involving the right lower lobe, with coughing during feeds. What is the underlying mechanism?", "choices": ["Aspiration of oral/gastric contents from poor swallowing", "An underlying primary immunodeficiency disorder", "An unrecognized congenital heart malformation", "A retained inhaled foreign body in the airway", "Undiagnosed cystic fibrosis with thick secretions"], "ans": 0, "exp": "Aspiration pneumonia: เด็กที่มี neurologic impairment (cerebral palsy) + dysphagia/GERD → aspirate contents, มัก 'right lower/middle lobe' (จาก anatomy). Recurrent pneumonia + coughing/choking with feeds เป็นเบาะแส. รักษา + ประเมิน swallowing (VFSS), ปรับ feeding (thickened, tube feeding), จัดการ GERD เพื่อป้องกันซ้ำ"}, {"topic": "Staphylococcal Pneumonia", "q": "An infant with severe pneumonia rapidly deteriorates; chest imaging shows pneumatoceles, an empyema, and evidence of pneumothorax. Which organism is most classically associated with this necrotizing, complicated course?", "choices": ["Respiratory syncytial virus", "Staphylococcus aureus", "Mycoplasma pneumoniae", "Streptococcus pneumoniae only", "Bordetella pertussis"], "ans": 1, "exp": "Staphylococcus aureus pneumonia (โดยเฉพาะในทารก, post-influenza, หรือ hematogenous): course รุนแรง necrotizing — pneumatoceles, empyema, pneumothorax, effusion, abscess. รักษาด้วย anti-staph antibiotics (พิจารณา MRSA coverage: vancomycin/clindamycin) + drainage ของ empyema. ดำเนินโรคเร็ว/รุนแรงกว่า pneumococcal ทั่วไป"}, {"topic": "Bacterial vs Viral Conjunctivitis", "q": "A child has a red eye with thick purulent discharge causing the eyelids to stick together in the morning, without significant itching. What is the most likely type and treatment?", "choices": ["Allergic conjunctivitis; antihistamine drops", "Viral conjunctivitis; supportive care only", "Bacterial conjunctivitis", "Chemical conjunctivitis; irrigation", "Orbital cellulitis; IV antibiotics"], "ans": 2, "exp": "Bacterial conjunctivitis: purulent/mucopurulent discharge, eyelids ติดกันตอนเช้า, ไม่คันเด่น. รักษาด้วย topical antibiotics + สุขอนามัย. Viral (มัก adenovirus): watery discharge, มักคู่ URI, ติดต่อง่าย, supportive. Allergic: itching เด่น + watery + bilateral + atopy, รักษาด้วย antihistamine/mast-cell stabilizer. Neonatal conjunctivitis ต้องแยก gonococcal/chlamydial"}, {"topic": "Molluscum Contagiosum", "q": "A child has multiple small, firm, dome-shaped, flesh-colored papules with central umbilication on the trunk and extremities. They are asymptomatic. What is the cause and typical course?", "choices": ["Human papillomavirus; requires cryotherapy always", "Herpes simplex virus; oral antivirals", "Bacterial folliculitis; oral antibiotics", "Poxvirus (molluscum contagiosum); usually self-limited", "Scabies; permethrin"], "ans": 3, "exp": "Molluscum contagiosum (poxvirus): dome-shaped, flesh-colored papules with 'central umbilication', ติดต่อโดยสัมผัส, พบบ่อยในเด็ก. ส่วนใหญ่ 'self-limited' (หายเองในเดือน-ปี). รักษาเฉพาะเมื่อรบกวน/แพร่กระจาย (curettage, cryotherapy, cantharidin). แพร่ในผู้ atopic/immunocompromised มากกว่า"}, {"topic": "Warts", "q": "A school-aged child has rough, hyperkeratotic papules on the fingers and hands. What is the causative agent?", "choices": ["Poxvirus", "Herpes simplex virus", "Coxsackievirus", "Dermatophyte fungus", "Human papillomavirus"], "ans": 4, "exp": "Common warts (verruca vulgaris): rough hyperkeratotic papules จาก human papillomavirus (HPV), พบที่มือ/นิ้ว, ติดต่อโดยสัมผัส. ส่วนใหญ่หายเองในเด็ก (เดือน-ปี). รักษา (ถ้าต้องการ): salicylic acid, cryotherapy. Plantar warts ที่ฝ่าเท้า, ต่างจาก molluscum (umbilicated, poxvirus)"}, {"topic": "Cat Scratch Disease", "q": "A child develops a tender, enlarged regional lymph node (e.g., axillary) 1-2 weeks after being scratched by a kitten, with a small papule at the scratch site and low-grade fever. What is the causative organism?", "choices": ["Bartonella henselae", "Staphylococcus aureus", "Mycobacterium tuberculosis", "Toxoplasma gondii", "Francisella tularensis"], "ans": 0, "exp": "Cat scratch disease (Bartonella henselae): regional 'tender lymphadenopathy' 1-2 สัปดาห์หลังถูกแมว (โดยเฉพาะลูกแมว) ข่วน/กัด + papule ที่จุดข่วน + low-grade fever. ส่วนใหญ่ self-limited; azithromycin ในรายที่มีอาการ/lymph node ใหญ่. Differential ของ subacute regional lymphadenopathy ในเด็ก"}, {"topic": "Tonsillectomy Indications", "q": "A child has had 7 documented episodes of throat infection in the past year with fever and cervical adenopathy, missing significant school. What is a recognized indication for tonsillectomy?", "choices": ["A single isolated episode of acute tonsillitis", "Recurrent throat infections meeting frequency criteria", "Asymptomatic enlargement of the tonsils alone", "Any ordinary sore throat lasting a single day", "The presence of a transient strawberry tongue"], "ans": 1, "exp": "ข้อบ่งชี้ tonsillectomy: recurrent throat infection ที่เข้าเกณฑ์ (เช่น ≥7 ครั้ง/ปี, ≥5 ครั้ง/ปี ต่อเนื่อง 2 ปี, ≥3 ครั้ง/ปี ต่อเนื่อง 3 ปี — Paradise criteria) หรือ 'obstructive sleep apnea/adenotonsillar hypertrophy', peritonsillar abscess ซ้ำ, suspected malignancy. Single/mild episodes ไม่ใช่ข้อบ่งชี้"}, {"topic": "Epistaxis", "q": "A child has a nosebleed from the anterior nasal septum. What is the most appropriate first-aid measure?", "choices": ["Tilt the head backward and swallow the draining blood", "Lie flat and apply ice only to the forehead", "Lean forward and pinch the soft nose for ten minutes", "Pack the nose immediately without applying pressure", "Blow the nose forcefully to clear out the clots"], "ans": 2, "exp": "Anterior epistaxis (มักจาก Little's area/Kiesselbach plexus): first-aid คือ นั่งโน้มตัวไปข้างหน้า (ป้องกันกลืนเลือด/สำลัก) และบีบ soft part ของจมูกต่อเนื่อง ~10 นาที. เอนศีรษะไปข้างหลังผิด. ถ้าไม่หยุด → topical vasoconstrictor, cautery, packing. Recurrent/severe หาสาเหตุ (nose picking, dryness, coagulopathy)"}, {"topic": "Cholesteatoma", "q": "A child with chronic ear discharge that is foul-smelling and unresponsive to antibiotics, with progressive hearing loss and a retraction pocket/white debris in the attic on otoscopy, may have which serious complication of chronic otitis media?", "choices": ["Otitis externa", "Simple wax impaction", "Acute otitis media", "Cholesteatoma", "Allergic otitis"], "ans": 3, "exp": "Cholesteatoma: keratinizing squamous epithelium สะสมใน middle ear (มักจาก chronic OM/retraction pocket) → foul-smelling discharge เรื้อรังที่ดื้อ antibiotics, progressive conductive hearing loss, white debris/attic retraction. Locally destructive (ossicles, bone) → complications (facial palsy, labyrinthitis, intracranial). รักษาด้วย surgery (mastoidectomy/tympanoplasty)"}, {"topic": "Tetanus Wound Prophylaxis", "q": "A child with an unknown or incomplete tetanus immunization history sustains a deep, contaminated puncture wound. What is the most appropriate prophylaxis?", "choices": ["Tetanus toxoid only regardless of wound type", "No prophylaxis is needed", "Oral antibiotics alone", "Immunoglobulin only, no vaccine", "Tetanus toxoid vaccine plus tetanus immunoglobulin"], "ans": 4, "exp": "Tetanus-prone wound (deep/contaminated/puncture) + incomplete/unknown immunization: ให้ทั้ง 'tetanus toxoid vaccine' และ 'tetanus immunoglobulin (TIG)'. ถ้า immunization ครบและ wound clean อาจแค่ booster ตาม interval. Wound care/debridement สำคัญ. เด็กที่ฉีดครบตามเกณฑ์และ clean minor wound มักไม่ต้อง TIG"}, {"topic": "Measles Post-exposure", "q": "An unimmunized, immunocompetent child is exposed to a confirmed case of measles 2 days ago. What is the most appropriate post-exposure prophylaxis?", "choices": ["MMR vaccine given within 72 hours of the exposure", "No specific action needed after the exposure", "A course of antibiotics following the exposure", "Vitamin A supplementation alone without vaccine", "Waiting for symptoms to develop before acting"], "ans": 0, "exp": "Measles post-exposure prophylaxis: MMR vaccine ภายใน 72 ชม.หลังสัมผัส (สำหรับผู้ที่ให้วัคซีนได้และ immunocompetent) อาจป้องกัน/ลดความรุนแรง. Immunoglobulin (IG) ภายใน 6 วัน สำหรับกลุ่มที่ให้วัคซีนไม่ได้ (ทารก <6-12 เดือน, ตั้งครรภ์, immunocompromised). Measles ติดต่อได้สูงมาก (airborne)"}, {"topic": "Herpangina", "q": "A young child has sudden fever and refuses to eat because of painful small vesicles and ulcers on the soft palate, uvula, and tonsillar pillars (posterior oropharynx) only, without lesions on the hands or feet. What is the cause?", "choices": ["Herpes simplex virus", "Coxsackievirus", "Candida albicans", "Group A Streptococcus", "Adenovirus"], "ans": 1, "exp": "Herpangina (Coxsackievirus/enterovirus): fever + painful vesicles/ulcers ที่ 'posterior' oropharynx (soft palate, uvula, tonsillar pillars) เท่านั้น. ต่างจาก herpetic gingivostomatitis (HSV, anterior mouth/gingiva) และ hand-foot-mouth (เพิ่ม vesicles ที่มือเท้าก้น). Self-limited, supportive (hydration/analgesia)"}, {"topic": "Pediatric COVID-19", "q": "Compared with adults, how does acute SARS-CoV-2 infection (COVID-19) typically present in most children?", "choices": ["Most children develop severe pneumonia requiring ICU", "Children never transmit the virus", "Most children have mild or asymptomatic disease", "Children universally develop MIS-C", "COVID-19 does not occur in children"], "ans": 2, "exp": "COVID-19 ในเด็กส่วนใหญ่ 'mild หรือ asymptomatic' (แม้ติดและแพร่เชื้อได้). ส่วนน้อยมีอาการรุนแรง โดยเฉพาะกลุ่มเสี่ยง (comorbidity). ภาวะแทรกซ้อนที่พบเฉพาะคือ MIS-C หลังติดหลายสัปดาห์ (พบน้อยแต่รุนแรง). รักษา supportive; กลุ่มเสี่ยงพิจารณา antiviral ตามแนวทาง"}, {"topic": "Sinusitis Complication - Pott Puffy Tumor", "q": "An adolescent with frontal sinusitis develops a tender, doughy, swelling over the forehead, headache, and fever, indicating spread of infection to the frontal bone. What is this complication?", "choices": ["Orbital cellulitis", "Cavernous sinus thrombosis", "Simple frontal headache", "Pott puffy tumor", "Meningitis without bone involvement"], "ans": 3, "exp": "Pott puffy tumor: complication ของ frontal sinusitis → frontal bone osteomyelitis + subperiosteal abscess → 'doughy' forehead swelling, fever, headache. เสี่ยงลาม intracranial (epidural/subdural empyema, meningitis). ต้อง imaging (CT/MRI), IV antibiotics, และมัก surgical drainage. เป็น complication ที่พบในวัยรุ่น"}, {"topic": "Kawasaki - Incomplete", "q": "A 5-month-old infant has prolonged fever for 7 days with only 2 classic clinical criteria but has elevated inflammatory markers. Why is heightened suspicion for incomplete Kawasaki disease important, especially in infants?", "choices": ["Infants essentially never develop coronary complications", "The illness always resolves fully without any treatment", "Incomplete Kawasaki disease does not need echocardiography", "Antibiotics are curative for the underlying process", "Infants risk coronary aneurysms and may not meet criteria"], "ans": 4, "exp": "Incomplete (atypical) Kawasaki disease: prolonged fever + criteria ไม่ครบ แต่มี lab evidence ของ inflammation. 'ทารก <6 เดือน' มักนำเสนอ incomplete และ 'เสี่ยง coronary artery aneurysm สูงกว่า' จึงต้องสงสัยและทำ echocardiogram + พิจารณารักษา (IVIG) แม้ criteria ไม่ครบ. การรักษาช้าเพิ่มความเสี่ยง coronary"}, {"topic": "Chronic URI vs Bacterial", "q": "A 3-year-old has had clear runny nose, congestion, and cough for 5 days during the cool season, with low-grade fever and is otherwise active. What is the most appropriate management?", "choices": ["Supportive care for a self-limited viral infection", "Immediate broad-spectrum antibiotics for the illness", "A chest radiograph and admission to the hospital", "Antitussive syrup containing codeine for the cough", "Systemic corticosteroids to reduce airway inflammation"], "ans": 0, "exp": "Viral URI (common cold): clear rhinorrhea, congestion, cough, low-grade fever, ผู้ป่วยยัง active, ระยะ <10 วัน. รักษา 'supportive' (fluids, saline nasal, antipyretic), 'ไม่ให้ antibiotics' (viral). Antibiotics พิจารณาเมื่อเข้าเกณฑ์ bacterial sinusitis (>10 วัน/worsening/severe) หรือ AOM/pneumonia. หลีกเลี่ยง codeine/OTC cough meds ในเด็กเล็ก"}, {"topic": "Hookworm", "q": "A school-aged child from a rural area who often walks barefoot has iron deficiency anemia, fatigue, and an itchy rash on the feet ('ground itch'). Stool examination shows characteristic ova. Which organism is most likely?", "choices": ["Enterobius vermicularis", "Hookworm (Necator/Ancylostoma)", "Giardia lamblia", "Ascaris lumbricoides", "Taenia saginata"], "ans": 1, "exp": "Hookworm (Necator americanus/Ancylostoma): larvae ไชผ่านผิวหนัง (เดินเท้าเปล่า, 'ground itch') → ปอด → ลำไส้ ดูดเลือด → 'iron deficiency anemia' + hypoproteinemia. วินิจฉัยด้วย stool ova. รักษาด้วย albendazole/mebendazole + เสริม iron. ป้องกัน: ใส่รองเท้า, สุขาภิบาล. เป็นสาเหตุสำคัญของ anemia ในเด็กเขตร้อน"}, {"topic": "Melioidosis", "q": "A child in northeastern Thailand, especially with exposure to soil/water during the rainy season, develops fever with pneumonia and/or abscesses (e.g., parotid). Which organism should be considered?", "choices": ["Streptococcus pneumoniae", "Mycobacterium tuberculosis", "Burkholderia pseudomallei", "Staphylococcus aureus only", "Leptospira"], "ans": 2, "exp": "Melioidosis (Burkholderia pseudomallei): endemic ในภาคอีสานของไทย, ติดจาก soil/water (rainy season), พบมากในผู้มี diabetes. อาการหลากหลาย: pneumonia, abscesses (parotid abscess เด่นในเด็กไทย), sepsis. รักษา: intensive phase ceftazidime/meropenem แล้ว eradication phase cotrimoxazole นานหลายเดือน (relapse ได้). ต้องนึกถึงใน febrile illness ในพื้นที่ endemic"}, {"topic": "Neonatal/Pediatric Conjunctivitis Timing", "q": "A 3-year-old develops acute unilateral red eye with watery discharge, a preauricular lymph node, and a recent cold; several classmates are affected. What is the most likely cause and management?", "choices": ["Bacterial conjunctivitis; oral antibiotics", "Allergic conjunctivitis; oral steroids", "Gonococcal conjunctivitis; ceftriaxone", "Viral conjunctivitis", "Foreign body; surgical removal"], "ans": 3, "exp": "Viral conjunctivitis (มัก adenovirus): watery discharge, preauricular lymphadenopathy, คู่กับ URI, ระบาดในโรงเรียน (ติดต่อง่ายมาก). รักษา 'supportive' + สุขอนามัยเข้มงวด (ล้างมือ, ไม่ใช้ของร่วม). Highly contagious — แยกจากโรงเรียนช่วงมีอาการ. ไม่ต้อง antibiotics เว้นแต่ superinfection"}, {"topic": "Diphtheria/Croup Airway", "q": "A child with severe upper airway obstruction from an infectious cause is in impending respiratory failure with cyanosis and decreasing air entry despite medical therapy. What is the priority?", "choices": ["Give oral fluids while awaiting further assessment", "Administer a high-dose antihistamine for the swelling", "Discharge the child home with outpatient follow-up", "Delay airway management until imaging is completed", "Establish a definitive airway in a controlled setting"], "ans": 4, "exp": "ในภาวะ upper airway obstruction ที่มี impending respiratory failure (cyanosis, decreasing air entry, exhaustion) — ไม่ว่าจาก croup รุนแรง, epiglottitis, bacterial tracheitis, diphtheria — priority คือ 'secure definitive airway' (intubation โดยผู้เชี่ยวชาญในห้องควบคุม, เตรียม surgical airway) ก่อน investigation อื่น. Airway มาก่อนเสมอ (ABC)"}]}, {"id": "ped-4", "title": "กุมารเวชศาสตร์ ชุดที่ 4 — Cardio/GI/Nephro/Heme-Onc", "subject": "ped", "questions": [{"topic": "Congenital Heart - VSD", "q": "A 6-week-old infant is found to have a harsh holosystolic murmur at the left lower sternal border during a routine visit. The infant has been feeding slowly with diaphoresis and poor weight gain. What is the most likely diagnosis?", "choices": ["Ventricular septal defect", "Atrial septal defect", "Tetralogy of Fallot", "Transposition of the great arteries", "Patent ductus arteriosus"], "ans": 0, "exp": "Ventricular septal defect (VSD): acyanotic left-to-right shunt ที่พบบ่อยที่สุด — harsh holosystolic murmur ที่ left lower sternal border. Large VSD → heart failure ในทารก (poor feeding, diaphoresis, FTT, tachypnea) ราวสัปดาห์ที่ 4-8 เมื่อ PVR ลด. Small VSD ส่วนใหญ่ปิดเอง. รักษา HF + surgical closure ถ้า large/symptomatic"}, {"topic": "Congenital Heart - ASD", "q": "A 4-year-old is noted to have a wide, fixed splitting of the second heart sound and a systolic ejection murmur at the left upper sternal border. She is usually asymptomatic. What is the most likely diagnosis?", "choices": ["Ventricular septal defect", "Atrial septal defect", "Aortic stenosis", "Mitral regurgitation", "Pulmonary atresia"], "ans": 1, "exp": "Atrial septal defect (ASD): มัก asymptomatic ในเด็ก, ตรวจพบ 'wide fixed splitting of S2' (สำคัญ) + systolic ejection murmur ที่ left upper sternal border (จาก increased flow ผ่าน pulmonary valve). Left-to-right shunt. อาจ present ในผู้ใหญ่ด้วย arrhythmia/pulmonary hypertension. รักษา: device/surgical closure ถ้า significant"}, {"topic": "Congenital Heart - TOF", "q": "A 1-year-old has episodes of sudden cyanosis and irritability, relieved by squatting. Examination shows a systolic ejection murmur, and chest X-ray reveals a 'boot-shaped' heart. What is the diagnosis?", "choices": ["Ventricular septal defect", "Atrial septal defect", "Tetralogy of Fallot", "Transposition of the great arteries", "Coarctation of the aorta"], "ans": 2, "exp": "Tetralogy of Fallot (cyanotic CHD ที่พบบ่อยที่สุดหลังวัยทารก): VSD, overriding aorta, RV outflow obstruction (pulmonary stenosis), RVH. 'Tet spells' (hypercyanotic) บรรเทาด้วย squatting (เพิ่ม SVR ลด right-to-left shunt). CXR 'boot-shaped heart'. รักษา tet spell: knee-chest position, oxygen, morphine, fluids, +/- beta-blocker/phenylephrine; surgical repair"}, {"topic": "Congenital Heart - TGA", "q": "A newborn becomes severely cyanotic within the first day of life; cyanosis does not improve with oxygen. Chest X-ray shows an 'egg on a string' appearance with a narrow mediastinum. What is the diagnosis and initial stabilizing treatment?", "choices": ["Tetralogy of Fallot; beta-blocker", "Ventricular septal defect; diuretics", "Atrial septal defect; observation", "Transposition of the great arteries", "Coarctation; surgery without medication"], "ans": 3, "exp": "Transposition of the great arteries (TGA): cyanosis รุนแรงในวันแรก (parallel circulations), ไม่ตอบสนอง O2 (hyperoxia test fail), CXR 'egg on a string'. Initial: prostaglandin E1 เปิด ductus + balloon atrial septostomy เพื่อ mixing, แล้ว arterial switch operation. เป็น cyanotic CHD ที่ present เร็วที่สุด (แรกเกิด)"}, {"topic": "Congenital Heart - PDA", "q": "A preterm infant has a continuous 'machinery' murmur below the left clavicle, bounding peripheral pulses, and a wide pulse pressure. What is the diagnosis?", "choices": ["Ventricular septal defect", "Aortic stenosis", "Coarctation of the aorta", "Tetralogy of Fallot", "Patent ductus arteriosus"], "ans": 4, "exp": "Patent ductus arteriosus (PDA): continuous 'machinery' murmur ใต้ clavicle ซ้าย + bounding pulses + wide pulse pressure (จาก aortic runoff). พบบ่อยใน preterm. รักษา: COX inhibitor (indomethacin/ibuprofen) ในทารก preterm, หรือ device/surgical closure. Left-to-right shunt (acyanotic)"}, {"topic": "Coarctation of Aorta", "q": "A child is found to have hypertension in the arms with weak, delayed femoral pulses (radio-femoral delay) and lower blood pressure in the legs. What is the most likely diagnosis?", "choices": ["Coarctation of the aorta", "Essential hypertension", "Renal artery stenosis", "Patent ductus arteriosus", "Aortic regurgitation"], "ans": 0, "exp": "Coarctation of the aorta: narrowing ของ aorta (มัก juxtaductal) → upper extremity hypertension + 'radio-femoral delay'/weak femoral pulses + BP แขน > ขา. สัมพันธ์กับ Turner syndrome และ bicuspid aortic valve. CXR อาจเห็น rib notching (เด็กโต). Neonatal critical coarctation = duct-dependent (ให้ PGE1). รักษา: surgical/balloon repair"}, {"topic": "Innocent Murmur", "q": "A healthy 5-year-old has a soft (grade 2), vibratory, musical systolic murmur at the left lower sternal border that decreases when standing. There are no other symptoms, normal pulses, and normal growth. What is the most appropriate action?", "choices": ["Urgent cardiac surgery", "Reassurance; this is an innocent murmur", "Start diuretics", "Immediate cardiac catheterization", "Restrict all physical activity"], "ans": 1, "exp": "Innocent (Still's) murmur: soft, systolic, vibratory/musical, ที่ LLSB, 'เปลี่ยนตามท่า' (ลดเมื่อยืน), ในเด็กสุขภาพดี growth/pulse ปกติ, ไม่มีอาการ. เป็น benign พบบ่อย. Reassurance ไม่ต้อง workup. Red flags ที่บ่งชี้ pathologic: diastolic, holosystolic, harsh, thrill, symptoms, abnormal S2/pulses → ส่ง echocardiogram"}, {"topic": "Acute Rheumatic Fever", "q": "A 9-year-old, 3 weeks after a sore throat, develops fever, migratory polyarthritis of large joints, a new heart murmur, and subcutaneous nodules. Which criteria are used for diagnosis?", "choices": ["Duke criteria", "Light criteria", "Jones criteria", "Centor criteria", "Ranson criteria"], "ans": 2, "exp": "Acute rheumatic fever (immune reaction หลัง Group A Strep pharyngitis): วินิจฉัยด้วย 'Jones criteria' — evidence ของ preceding strep + 2 major หรือ 1 major + 2 minor. Major (JONES): Joints (migratory polyarthritis), carditis (O = heart), Nodules, Erythema marginatum, Sydenham chorea. Carditis (valvulitis, มัก mitral) เป็นภาวะที่ทำให้ long-term morbidity. รักษา + secondary prophylaxis penicillin"}, {"topic": "Rheumatic Fever Prophylaxis", "q": "A child recovers from acute rheumatic fever with carditis. What is the recommended secondary prevention?", "choices": ["A single course of antibiotics only", "No further treatment", "Lifelong aspirin only", "Long-term penicillin prophylaxis", "Antiviral prophylaxis"], "ans": 3, "exp": "หลัง acute rheumatic fever ต้องให้ 'secondary prophylaxis' ด้วย benzathine penicillin G IM ทุก 3-4 สัปดาห์ (หรือ oral penicillin) เพื่อป้องกัน recurrent strep infection และ recurrent ARF/worsening carditis. ระยะเวลาขึ้นกับว่ามี carditis/valve disease (นานหลายปีถึงตลอดชีวิตในรายที่มี rheumatic heart disease)"}, {"topic": "Kawasaki Cardiac Follow-up", "q": "A child treated for Kawasaki disease needs cardiac surveillance. Which imaging is essential to detect the main cardiac complication?", "choices": ["A chest radiograph alone to assess heart size", "An electrocardiogram alone to detect arrhythmia", "Cardiac MRI used as the only imaging modality", "No cardiac imaging is needed in these children", "Echocardiography to evaluate the coronary arteries"], "ans": 4, "exp": "Kawasaki disease ต้อง 'echocardiography' (baseline + follow-up ~2 และ 6 สัปดาห์) เพื่อประเมิน coronary artery aneurysm ซึ่งเป็นภาวะแทรกซ้อนหลัก. IVIG + aspirin ลดความเสี่ยง. ผู้ที่มี coronary aneurysm ต้อง long-term antiplatelet/anticoagulation และ cardiology follow-up"}, {"topic": "Pyloric Stenosis", "q": "A 4-week-old firstborn boy has progressive non-bilious projectile vomiting after feeds and remains hungry. A firm 'olive-shaped' mass is palpable in the epigastrium. What acid-base/electrolyte disturbance is expected?", "choices": ["Hypochloremic, hypokalemic metabolic alkalosis", "High anion gap metabolic acidosis", "Hyperchloremic metabolic acidosis", "Respiratory alkalosis", "Hyperkalemic metabolic acidosis"], "ans": 0, "exp": "Hypertrophic pyloric stenosis: ทารกชาย 3-6 สัปดาห์, non-bilious 'projectile' vomiting, ยังหิว, palpable 'olive' + visible peristalsis. การอาเจียนเสีย HCl → 'hypochloremic hypokalemic metabolic alkalosis' (+/- paradoxical aciduria). วินิจฉัยด้วย ultrasound. รักษา: 'แก้ fluid/electrolyte ก่อน' แล้วผ่าตัด pyloromyotomy (ไม่ใช่ surgical emergency)"}, {"topic": "Intussusception", "q": "A 9-month-old has sudden episodes of intermittent severe crampy abdominal pain with drawing up of the legs, vomiting, and passage of 'currant jelly' stools. A sausage-shaped mass is palpable in the right abdomen. What is the diagnosis and first-line management?", "choices": ["Malrotation with volvulus; immediate laparotomy", "Intussusception; air or contrast enema reduction", "Pyloric stenosis; pyloromyotomy", "Gastroenteritis; oral rehydration", "Appendicitis; appendectomy"], "ans": 1, "exp": "Intussusception (มัก ileocolic, อายุ 3 เดือน-3 ปี): colicky intermittent pain (ดึงขาเข้า), vomiting, 'currant jelly stool' (เลือด+mucus, late), sausage-shaped mass. วินิจฉัยด้วย ultrasound ('target/donut sign'). รักษา: 'air/contrast enema reduction' (diagnostic+therapeutic) ถ้าไม่มี peritonitis/perforation; surgery ถ้า enema ล้มเหลว/complication. Lead point พบมากขึ้นในเด็กโต"}, {"topic": "Biliary Atresia vs Physiologic", "q": "A 6-week-old has persistent jaundice, pale (acholic) stools, dark urine, and hepatomegaly. Direct bilirubin is elevated. What is the most critical next step?", "choices": ["Reassurance; this is physiologic jaundice", "Start phototherapy", "Urgent evaluation for biliary atresia", "Increase feeding frequency and recheck in a month", "Give ursodeoxycholic acid and observe for 6 weeks"], "ans": 2, "exp": "Conjugated (direct) hyperbilirubinemia + acholic stool + dark urine + hepatomegaly = biliary atresia จนกว่าจะพิสูจน์เป็นอื่น. เป็น 'cholestasis' ที่ต้องรีบวินิจฉัย เพราะ Kasai portoenterostomy ได้ผลดีที่สุดก่อน 8 สัปดาห์ (delay → cirrhosis → liver transplant). 'ห้าม' ใช้ phototherapy กับ direct hyperbilirubinemia. Conjugated jaundice เป็น pathologic เสมอ"}, {"topic": "Nephrotic Syndrome", "q": "A 3-year-old presents with periorbital and generalized edema, and investigations show heavy proteinuria, hypoalbuminemia, and hyperlipidemia with normal blood pressure and no hematuria. What is the most likely diagnosis and initial treatment?", "choices": ["Post-streptococcal glomerulonephritis; antibiotics", "IgA nephropathy; ACE inhibitor", "Henoch-Schonlein nephritis; observation", "Minimal change disease", "Alport syndrome; dialysis"], "ans": 3, "exp": "Nephrotic syndrome ในเด็ก: edema (periorbital/generalized), heavy proteinuria, hypoalbuminemia, hyperlipidemia. สาเหตุที่พบบ่อยที่สุดในเด็ก (~90%) คือ 'minimal change disease' — ตอบสนองดีต่อ corticosteroids (empiric ไม่ต้อง biopsy ในเด็กเล็กที่ typical). เสี่ยง infection (SBP, pneumococcal), thrombosis. ต่างจาก nephritic (hematuria, HT, RBC casts)"}, {"topic": "Post-Streptococcal GN", "q": "A 7-year-old, 2 weeks after a skin infection (impetigo), presents with tea-colored (cola) urine, periorbital edema, hypertension, and reduced urine output. Complement C3 is low. What is the diagnosis?", "choices": ["Minimal change nephrotic syndrome", "IgA nephropathy", "Hemolytic uremic syndrome", "Alport syndrome", "Post-streptococcal glomerulonephritis"], "ans": 4, "exp": "Post-streptococcal glomerulonephritis (PSGN): nephritic syndrome 1-2 สัปดาห์หลัง strep pharyngitis, หรือ 3-6 สัปดาห์หลัง skin infection (impetigo) — tea/cola-colored urine (hematuria), edema, hypertension, oliguria, 'low C3' (กลับปกติใน 6-8 สัปดาห์). รักษา supportive (salt/water restriction, antihypertensives, จัดการ fluid overload). ส่วนใหญ่หายเองในเด็ก. Evidence: ASO/anti-DNase B"}, {"topic": "IgA Nephropathy", "q": "An older child develops gross hematuria that occurs concurrently with (within 1-2 days of) an upper respiratory infection, recurring with subsequent infections, with normal complement levels. What is the most likely diagnosis?", "choices": ["IgA nephropathy", "Post-streptococcal glomerulonephritis", "Minimal change disease", "Hemolytic uremic syndrome", "Thin basement membrane disease"], "ans": 0, "exp": "IgA nephropathy (Berger disease): gross hematuria 'พร้อมกับ' URI (synpharyngitic, ภายใน 1-2 วัน) และ recurrent, 'complement ปกติ'. ต่างจาก PSGN ที่ hematuria เกิด 1-2 สัปดาห์ 'หลัง' strep และ 'C3 ต่ำ'. IgA nephropathy เป็น glomerulonephritis ที่พบบ่อยที่สุดทั่วโลก; บางรายดำเนินสู่ CKD. HSP nephritis เป็น systemic form"}, {"topic": "Hemolytic Uremic Syndrome", "q": "A 3-year-old, several days after an episode of bloody diarrhea, develops pallor, decreased urine output, petechiae, and edema. Labs show microangiopathic hemolytic anemia with schistocytes, thrombocytopenia, and acute kidney injury. What is the most likely trigger?", "choices": ["Streptococcus pyogenes causing a skin infection", "Shiga toxin-producing Escherichia coli (O157:H7)", "Rotavirus causing acute watery gastroenteritis", "Salmonella Typhi causing enteric fever", "Respiratory syncytial virus causing bronchiolitis"], "ans": 1, "exp": "Typical hemolytic uremic syndrome (HUS): triad = microangiopathic hemolytic anemia (schistocytes) + thrombocytopenia + acute kidney injury, มัก 'หลัง bloody diarrhea' จาก Shiga toxin-producing E. coli (O157:H7, จาก undercooked beef/contaminated). รักษา supportive (fluid/electrolyte, +/- dialysis); 'หลีกเลี่ยง antibiotics' ใน STEC (อาจเพิ่ม toxin release). สาเหตุ AKI ที่พบบ่อยในเด็กเล็ก"}, {"topic": "Henoch-Schonlein Purpura", "q": "A 6-year-old develops palpable purpura on the buttocks and lower extremities, colicky abdominal pain, and arthralgia of the ankles and knees, with normal platelet count. Urinalysis shows microscopic hematuria. What is the diagnosis?", "choices": ["Immune thrombocytopenic purpura", "Hemolytic uremic syndrome", "Henoch-Schonlein purpura", "Meningococcemia", "Acute leukemia"], "ans": 2, "exp": "Henoch-Schonlein purpura (IgA vasculitis): tetrad = palpable purpura (extensor/lower limbs & buttocks, 'normal platelet'), arthritis/arthralgia, abdominal pain (เสี่ยง intussusception), และ renal involvement (IgA nephritis, hematuria/proteinuria). มักหลัง URI. รักษาส่วนใหญ่ supportive; steroid สำหรับ severe GI/renal. ติดตาม urinalysis/BP เพราะ nephritis อาจตามมา"}, {"topic": "Vesicoureteral Reflux", "q": "An infant with a first febrile urinary tract infection undergoes evaluation. Renal ultrasound and voiding cystourethrogram are considered to detect which condition that predisposes to recurrent pyelonephritis and renal scarring?", "choices": ["Wilms tumor", "Polycystic kidney disease", "Renal artery stenosis", "Vesicoureteral reflux", "Nephrolithiasis"], "ans": 3, "exp": "Vesicoureteral reflux (VUR): retrograde flow ของ urine จาก bladder ขึ้น ureter/kidney → เสี่ยง recurrent pyelonephritis และ renal scarring (reflux nephropathy → HT/CKD). ประเมินหลัง febrile UTI ในเด็กเล็ก/atypical ด้วย renal ultrasound +/- VCUG (diagnose+grade). รักษา: prophylactic antibiotics หรือ surgery ตาม grade/recurrence"}, {"topic": "Wilms Tumor", "q": "A 3-year-old is found to have a smooth, non-tender abdominal mass that does not cross the midline, discovered by a parent during bathing. The child has mild hypertension and hematuria. What is the most likely diagnosis?", "choices": ["Neuroblastoma arising from sympathetic tissue", "Hepatoblastoma arising from the liver", "Polycystic kidney disease with enlarged kidneys", "Splenomegaly from a hematologic disorder", "Wilms tumor (nephroblastoma) of the kidney"], "ans": 4, "exp": "Wilms tumor (nephroblastoma): abdominal mass ในเด็ก ~2-5 ปี, 'unilateral, smooth, ไม่ข้าม midline', +/- hypertension, hematuria. สัมพันธ์กับ WAGR, Beckwith-Wiedemann, hemihypertrophy. 'ห้ามคลำท้องแรงซ้ำ' (เสี่ยง rupture). วินิจฉัยด้วย imaging; รักษา nephrectomy + chemo +/- radiation. Prognosis ดี. ต่างจาก neuroblastoma (ข้าม midline, calcification, catecholamines)"}, {"topic": "Neuroblastoma", "q": "A 2-year-old has an irregular abdominal mass that crosses the midline, weight loss, and periorbital ecchymoses ('raccoon eyes') from metastasis. Urine catecholamine metabolites (VMA/HVA) are elevated. What is the diagnosis?", "choices": ["Neuroblastoma", "Wilms tumor", "Hepatoblastoma", "Rhabdomyosarcoma", "Lymphoma"], "ans": 0, "exp": "Neuroblastoma (จาก neural crest/adrenal medulla/sympathetic chain): abdominal mass ที่ 'ข้าม midline', irregular, systemic symptoms, metastasis (periorbital ecchymoses 'raccoon eyes', bone), elevated urine VMA/HVA (catecholamines). พบในเด็กเล็ก (<5 ปี). Imaging เห็น calcification. 'Opsoclonus-myoclonus' เป็น paraneoplastic. ต่างจาก Wilms (ไม่ข้าม midline)"}, {"topic": "Iron Deficiency vs Thalassemia", "q": "A Thai child has microcytic anemia. Which finding favors thalassemia trait over iron deficiency anemia?", "choices": ["A low red cell count together with a low ferritin", "Normal RBC count and ferritin with abnormal electrophoresis", "Resolution of the microcytosis after iron therapy", "A raised red cell distribution width with low iron", "A history of pica and clear dietary iron deficiency"], "ans": 1, "exp": "Thalassemia trait vs iron deficiency (ทั้งคู่ microcytic): thalassemia มัก 'RBC count ปกติ/สูง', RDW ปกติ, ferritin ปกติ, Mentzer index (MCV/RBC) <13, และ hemoglobin electrophoresis ผิดปกติ (เช่น HbA2 สูงใน beta-thal trait). Iron deficiency: RBC ต่ำ, RDW สูง, ferritin ต่ำ, ตอบสนอง iron. สำคัญในไทยเพราะ thalassemia ชุก — อย่าให้ iron เกินโดยไม่จำเป็น"}, {"topic": "Beta-Thalassemia Major", "q": "A Thai child presents at 6-12 months with progressive pallor, poor growth, hepatosplenomegaly, and frontal bossing with maxillary overgrowth. Hemoglobin electrophoresis shows markedly elevated HbF. What is the mainstay of management?", "choices": ["Oral iron supplementation to correct the anemia", "Systemic corticosteroids to reduce hemolysis", "Regular blood transfusions together with iron chelation", "Splenectomy performed as first-line at diagnosis", "Observation alone without any active treatment"], "ans": 2, "exp": "Beta-thalassemia major (Cooley anemia): severe anemia เริ่มแสดง 6-12 เดือน (เมื่อ HbF→HbA switch ล้มเหลว), hepatosplenomegaly, 'chipmunk facies'/frontal bossing (จาก marrow expansion), growth failure. รักษาด้วย 'regular transfusion' + 'iron chelation' (ป้องกัน iron overload → cardiac/liver/endocrine). Curative คือ hematopoietic stem cell transplant. พบชุกในไทย — ให้ genetic counseling/prenatal"}, {"topic": "Hb H Disease", "q": "A child with alpha-thalassemia caused by deletion of three alpha-globin genes has moderate chronic hemolytic anemia with hemoglobin H inclusions on special stain. Which complication should be considered during oxidative stress or infection?", "choices": ["Iron deficiency", "Vitamin B12 deficiency", "Polycythemia", "Acute hemolytic exacerbation", "Neutropenia as the main problem"], "ans": 3, "exp": "Hb H disease (alpha-thalassemia, 3-gene deletion): chronic hemolytic anemia ระดับปานกลาง, HbH inclusions (beta-tetramers, unstable). เสี่ยง acute hemolytic crisis เมื่อมี oxidative stress/infection/บางยา. รักษา supportive, folate, หลีกเลี่ยง oxidants, transfusion เมื่อจำเป็น. 4-gene deletion = Hb Bart's hydrops fetalis (fatal in utero) — สำคัญมากในไทย"}, {"topic": "Immune Thrombocytopenic Purpura", "q": "A previously healthy 4-year-old develops sudden petechiae, bruising, and epistaxis about 1-2 weeks after a viral illness. The platelet count is very low but the white cell count, hemoglobin, and exam (no hepatosplenomegaly) are otherwise normal. What is the diagnosis?", "choices": ["Acute leukemia", "Hemolytic uremic syndrome", "Disseminated intravascular coagulation", "Aplastic anemia", "Immune thrombocytopenic purpura"], "ans": 4, "exp": "Immune (idiopathic) thrombocytopenic purpura (ITP): isolated thrombocytopenia หลัง viral illness ในเด็ก, petechiae/bruising/mucosal bleeding, 'no hepatosplenomegaly/lymphadenopathy', CBC อื่นปกติ (แยกจาก leukemia). ส่วนใหญ่ self-limited. รักษา: observation ถ้า bleeding เล็กน้อย; IVIG/anti-D/steroid ถ้า severe bleeding. หลีกเลี่ยง contact sports/NSAIDs"}, {"topic": "Hemophilia A", "q": "A male infant develops prolonged bleeding after circumcision and later has hemarthroses (bleeding into joints) and deep muscle hematomas. Labs show a prolonged aPTT with normal PT and platelet count. Which factor is deficient?", "choices": ["Factor VIII", "Factor IX", "Von Willebrand factor", "Factor VII", "Platelet function"], "ans": 0, "exp": "Hemophilia A (X-linked recessive, factor VIII deficiency): prolonged aPTT, normal PT/platelet, deep bleeding — hemarthrosis, muscle hematoma, prolonged bleeding post-procedure. รักษาด้วย factor VIII replacement (+/- desmopressin ใน mild). Hemophilia B = factor IX deficiency (คล้ายกัน). ต่างจาก von Willebrand (mucocutaneous bleeding, platelet-type)"}, {"topic": "Von Willebrand Disease", "q": "An adolescent girl has a lifelong history of easy bruising, frequent epistaxis, heavy menstrual bleeding, and prolonged bleeding after dental procedures, with a family history. Platelet count is normal. What is the most likely diagnosis?", "choices": ["Hemophilia A", "Von Willebrand disease", "Immune thrombocytopenic purpura", "Vitamin K deficiency", "Glanzmann thrombasthenia"], "ans": 1, "exp": "Von Willebrand disease (สาเหตุ inherited bleeding disorder ที่พบบ่อยที่สุด, มัก autosomal dominant): 'mucocutaneous' bleeding — easy bruising, epistaxis, menorrhagia, bleeding หลังหัตถการ. Platelet count ปกติแต่ function ผิด (vWF ลด/ผิด). รักษาด้วย desmopressin (DDAVP, ปล่อย vWF) หรือ vWF/factor VIII concentrate. ต่างจาก hemophilia (deep bleeding, X-linked ในชาย)"}, {"topic": "Sickle Cell - Vaso-occlusive", "q": "A child with known sickle cell disease presents with acute severe bone pain in the extremities and back precipitated by cold and dehydration. What is the priority management of a vaso-occlusive crisis?", "choices": ["Immediate splenectomy", "High-dose iron therapy", "Hydration, analgesia, and oxygen", "Platelet transfusion", "Withhold fluids"], "ans": 2, "exp": "Sickle cell vaso-occlusive crisis: acute pain จาก microvascular occlusion โดย sickled RBCs, กระตุ้นด้วย cold, dehydration, infection, hypoxia. รักษา: hydration + analgesia (opioids ตามความรุนแรง) + oxygen ถ้า hypoxic + treat trigger. เฝ้าระวัง acute chest syndrome, splenic sequestration, stroke, aplastic crisis (parvovirus B19). Hydroxyurea ลดความถี่ crisis. (พบน้อยในไทยเทียบ thalassemia)"}, {"topic": "Acute Lymphoblastic Leukemia", "q": "A 4-year-old has weeks of pallor, fatigue, fever, bone pain, easy bruising, lymphadenopathy, and hepatosplenomegaly. CBC shows anemia, thrombocytopenia, and abnormal circulating blast cells. What is the most likely diagnosis?", "choices": ["Immune thrombocytopenic purpura", "Aplastic anemia", "Infectious mononucleosis", "Acute lymphoblastic leukemia", "Iron deficiency anemia"], "ans": 3, "exp": "Acute lymphoblastic leukemia (ALL): มะเร็งที่พบบ่อยที่สุดในเด็ก. Bone marrow ถูกแทนที่ → anemia (pallor/fatigue), thrombocytopenia (bruising/bleeding), neutropenia (fever/infection), + bone pain, lymphadenopathy, hepatosplenomegaly, blasts ใน peripheral smear. วินิจฉัยด้วย bone marrow (>20-25% blasts). รักษา chemotherapy; prognosis ดีในเด็ก. Peak 2-5 ปี"}, {"topic": "Acute Promyelocytic Leukemia", "q": "An adolescent with acute myeloid leukemia (M3 subtype) presents with bleeding and disseminated intravascular coagulation. This subtype is associated with the t(15;17) translocation and responds to a specific differentiating agent. What is that agent?", "choices": ["Vincristine used alone as the single agent", "Imatinib targeting a tyrosine kinase fusion", "Rituximab targeting a B-cell surface antigen", "Methotrexate used alone as the single agent", "All-trans retinoic acid to induce cell differentiation"], "ans": 4, "exp": "Acute promyelocytic leukemia (APL, AML-M3): t(15;17) PML-RARA, มักมาด้วย 'DIC/bleeding'. รักษาด้วย 'all-trans retinoic acid (ATRA)' (+/- arsenic trioxide) ซึ่งกระตุ้น differentiation ของ promyelocytes — เป็น AML subtype ที่ prognosis ดีที่สุดถ้ารักษาเร็ว. ต้องระวัง differentiation syndrome และแก้ coagulopathy"}, {"topic": "Hodgkin Lymphoma", "q": "An adolescent has painless, firm, rubbery cervical lymphadenopathy for weeks, with fever, night sweats, and weight loss (B symptoms). Lymph node biopsy shows Reed-Sternberg cells. What is the diagnosis?", "choices": ["Hodgkin lymphoma", "Reactive lymphadenitis", "Acute lymphoblastic leukemia", "Cat scratch disease", "Tuberculous lymphadenitis"], "ans": 0, "exp": "Hodgkin lymphoma: painless firm 'rubbery' lymphadenopathy (มัก cervical/supraclavicular), B symptoms (fever, night sweats, weight loss), +/- mediastinal mass. Biopsy พบ 'Reed-Sternberg cells' (pathognomonic). พบในวัยรุ่น/young adults. รักษา chemotherapy +/- radiation; prognosis ดี. Persistent, non-tender, supraclavicular nodes เป็น red flag ต้อง biopsy"}, {"topic": "Burkitt Lymphoma", "q": "A child presents with a rapidly enlarging abdominal (or jaw) mass, and biopsy shows a 'starry sky' appearance of a highly proliferative B-cell lymphoma associated with the c-MYC translocation. On starting chemotherapy, which acute metabolic emergency must be anticipated?", "choices": ["Diabetic ketoacidosis", "Tumor lysis syndrome", "Adrenal crisis", "Refeeding syndrome", "Thyroid storm"], "ans": 1, "exp": "Burkitt lymphoma: highly aggressive B-cell NHL, c-MYC (t(8;14)), 'starry sky' histology; abdominal (sporadic) หรือ jaw (endemic, EBV-related) mass, โตเร็วมาก. เมื่อเริ่ม chemo เซลล์แตกเร็ว → 'tumor lysis syndrome': hyperkalemia, hyperphosphatemia, hyperuricemia, hypocalcemia, AKI. ป้องกัน: hydration + allopurinol/rasburicase + monitor electrolytes"}, {"topic": "Retinoblastoma", "q": "A parent notices a white reflection in the pupil (leukocoria) instead of the normal red reflex in their 18-month-old's photographs, along with a new squint. What is the most likely diagnosis?", "choices": ["Congenital cataract", "Strabismus without pathology", "Retinoblastoma", "Vitreous hemorrhage", "Optic glioma"], "ans": 2, "exp": "Retinoblastoma: มะเร็งจอตาในเด็กเล็ก (<3-5 ปี), classic sign = 'leukocoria' (white pupillary reflex แทน red reflex, เห็นในรูปถ่าย) +/- strabismus. Hereditary form (RB1) bilateral/multifocal + เสี่ยงมะเร็งอื่น. ต้องรีบส่ง ophthalmology (life- and eye-saving). การตรวจ red reflex ใน well-child เป็น screen สำคัญ (แยก cataract ด้วย)"}, {"topic": "Infant GERD", "q": "A thriving 2-month-old has frequent effortless regurgitation after feeds but is otherwise well, growing normally, and feeding eagerly ('happy spitter'). What is the most appropriate management?", "choices": ["Start a proton pump inhibitor", "Perform fundoplication surgery", "Switch to intravenous nutrition", "Reassurance and conservative measures", "Extensive imaging workup"], "ans": 3, "exp": "Physiologic infant gastroesophageal reflux ('happy spitter'): regurgitation ที่ effortless ในทารกที่ thriving และ feeding ดี — เป็น normal, ดีขึ้นเมื่ออายุ ~12 เดือน. รักษาด้วย reassurance + conservative (feed เล็กบ่อย, จัดท่าตั้งตรงหลังนม, thickened feed). GERD 'disease' (poor growth, irritability, feeding refusal, respiratory) จึงพิจารณา acid suppression/evaluation"}, {"topic": "Appendicitis", "q": "An 8-year-old has periumbilical pain that migrated to the right lower quadrant, anorexia, low-grade fever, and vomiting, with tenderness and guarding at McBurney point and pain on the right with rebound. What is the most appropriate management?", "choices": ["Oral antibiotics at home", "Observation without intervention", "Laxatives", "Antacids", "Surgical appendectomy"], "ans": 4, "exp": "Acute appendicitis: classic migratory pain (periumbilical → RLQ), anorexia, fever, RLQ tenderness/guarding/rebound at McBurney point, +/- Rovsing/psoas signs. เป็น surgical emergency ในเด็ก (เสี่ยง perforation เร็วกว่าผู้ใหญ่). รักษา: appendectomy + IV fluids + antibiotics. Ultrasound/CT ช่วยในรายไม่ชัด. Perforated → peritonitis"}, {"topic": "Functional Constipation", "q": "A 3-year-old has hard, infrequent stools, painful defecation with stool withholding behavior, and occasional overflow soiling, but is otherwise well with a normal exam and normal growth. Symptoms began around toilet training. What is the diagnosis?", "choices": ["Functional constipation", "Hirschsprung disease", "Hypothyroidism", "Celiac disease", "Spinal cord lesion"], "ans": 0, "exp": "Functional constipation: พบบ่อยที่สุด, มัก trigger จาก painful defecation/toilet training → withholding → hard stool → cycle + overflow soiling (encopresis). ตรวจร่างกาย/growth ปกติ. ต่างจาก Hirschsprung (เริ่มแรกเกิด, delayed meconium, empty rectum, FTT). รักษา: disimpaction + maintenance osmotic laxative (PEG) + behavioral + dietary fiber/fluids"}, {"topic": "Celiac Disease", "q": "A toddler develops chronic diarrhea, abdominal distension, poor weight gain, and irritability after wheat-based cereals were introduced. Anti-tissue transglutaminase (anti-tTG) IgA antibodies are positive. What is the treatment?", "choices": ["Lactose-free diet only", "Lifelong gluten-free diet", "Pancreatic enzyme replacement", "Corticosteroids", "Low-fat diet"], "ans": 1, "exp": "Celiac disease (gluten-sensitive enteropathy): immune reaction ต่อ gluten (wheat, barley, rye) → villous atrophy → malabsorption (chronic diarrhea, distension, FTT, irritability, +/- dermatitis herpetiformis). Screen: anti-tTG IgA (+ total IgA); ยืนยันด้วย duodenal biopsy. รักษาด้วย 'lifelong gluten-free diet'. สัมพันธ์กับ T1DM, Down, Turner"}, {"topic": "Meckel Diverticulum", "q": "A 2-year-old presents with painless, large-volume rectal bleeding (brick-red/maroon stools) without other symptoms. A technetium-99m pertechnetate ('Meckel') scan is positive. What is the underlying lesion?", "choices": ["An anal fissure causing painful streaky bleeding", "Intussusception producing currant-jelly stools", "Meckel diverticulum with acid-secreting gastric mucosa", "A juvenile polyp causing painless intermittent bleeding", "Inflammatory bowel disease with chronic diarrhea"], "ans": 2, "exp": "Meckel diverticulum ('rule of 2s': 2% ประชากร, ~2 ฟุตจาก ileocecal valve, ~2 นิ้ว, มัก symptomatic <2 ปี): สาเหตุที่พบบ่อยของ painless significant lower GI bleeding ในเด็กเล็ก จาก 'ectopic gastric mucosa' ที่หลั่งกรด → ulcer/bleeding. วินิจฉัยด้วย Meckel scan (Tc-99m pertechnetate). รักษาผ่าตัด. อาจทำให้ intussusception/obstruction ได้ด้วย"}, {"topic": "Button Battery Ingestion", "q": "A toddler is brought in after swallowing a coin-shaped object. Radiograph shows a disc in the esophagus with a 'double ring/halo' sign. What is the appropriate management?", "choices": ["Observation and let it pass", "Induce vomiting", "Oral laxatives and discharge", "Emergent endoscopic removal", "Repeat X-ray in 1 week"], "ans": 3, "exp": "Button (disc) battery ใน esophagus = emergency: 'double ring/halo' sign บน X-ray. สร้าง caustic/electrical injury ภายในชั่วโมง → esophageal perforation, fistula, stricture. ต้อง 'emergent endoscopic removal'. (honey อาจให้ระหว่างรอในบางแนวทางเพื่อลด injury). ต่างจากเหรียญธรรมดาที่อาจ observe ได้ถ้าไม่มีอาการและอยู่ต่ำกว่า esophagus"}, {"topic": "Caustic Ingestion", "q": "A 2-year-old swallows a household drain cleaner (alkali). He has drooling, oral burns, and pain. What is an appropriate initial management step?", "choices": ["Induce vomiting immediately", "Give an acid to neutralize the alkali", "Give large volumes of water to dilute, then discharge", "Perform immediate gastric lavage", "Do NOT induce vomiting or give neutralizing agents"], "ans": 4, "exp": "Caustic (alkali) ingestion: alkali ทำให้ liquefactive necrosis (deep, esophageal injury/perforation, later stricture). Management: 'ห้าม induce vomiting' (re-expose esophagus), 'ห้าม neutralize' (exothermic), ห้าม gastric lavage/charcoal. ประเมิน airway (อาจ edema), NPO, IV fluids, และ endoscopy เพื่อ grade injury. เฝ้าระวัง stricture ระยะยาว"}, {"topic": "Coin Ingestion", "q": "A 3-year-old swallowed a coin that is now seen on X-ray in the stomach. The child is asymptomatic, eating and drinking normally. What is the most appropriate management?", "choices": ["Observation with follow-up", "Immediate endoscopy for all", "Induce vomiting", "Emergency laparotomy", "Give strong laxatives urgently"], "ans": 0, "exp": "Coin ที่ผ่านลงถึง 'stomach' และเด็ก asymptomatic ส่วนใหญ่ผ่านออกเองได้ → observe (ตรวจอุจจาระ/repeat imaging ถ้าไม่ผ่านใน weeks). Endoscopy ถ้าอยู่ที่ 'esophagus' + symptomatic, หรือค้างนาน, หรือเป็น button battery/magnet (ซึ่งอันตราย). Multiple magnets ต้อง removal (เสี่ยง bowel necrosis/perforation)"}, {"topic": "Testicular Torsion", "q": "A 14-year-old has sudden severe unilateral scrotal pain, nausea, a high-riding testis with a horizontal lie, and an absent cremasteric reflex. What is the priority management?", "choices": ["Antibiotics with routine outpatient urology follow-up", "Emergency surgical exploration and detorsion within hours", "Scrotal support with non-steroidal analgesics", "Overnight observation with reassessment in the morning", "Warm compresses applied to the affected scrotum"], "ans": 1, "exp": "Testicular torsion: sudden severe scrotal pain, nausea/vomiting, high-riding testis, horizontal lie, 'absent cremasteric reflex', negative Prehn sign. เป็น surgical emergency — testicular salvage สูงถ้า detorsion ภายใน ~6 ชม. อย่ารอ imaging ถ้า classic. ต่างจาก epididymitis (gradual, fever, cremasteric intact, relief on elevation) และ torsion of appendix testis ('blue dot')"}, {"topic": "Inguinal Hernia", "q": "An infant has an intermittent bulge in the groin that extends toward the scrotum, more prominent with crying, and reducible. It represents a persistent processus vaginalis. What is the appropriate management?", "choices": ["Observation, since it always resolves on its own", "Application of a truss to hold the hernia in", "Elective surgical repair given the risk of incarceration", "No treatment is ever required for this hernia", "A course of antibiotics directed at the swelling"], "ans": 2, "exp": "Pediatric 'indirect' inguinal hernia (patent processus vaginalis): reducible groin bulge → scrotum, prominent เมื่อ crying/straining. ต่างจาก hydrocele (transilluminates, ไม่ลงถึง internal ring). แนะนำ 'surgical repair' เพราะเสี่ยง incarceration/strangulation (โดยเฉพาะทารก). Incarcerated + irreducible/ill = emergency. (Umbilical hernia ต่างกัน — มักปิดเอง)"}, {"topic": "Umbilical Hernia", "q": "A healthy 1-year-old has a soft, easily reducible umbilical bulge that protrudes with crying. What is the most appropriate management?", "choices": ["Immediate surgical repair in the neonatal period", "Taping or binding the abdomen to close the defect", "Urgent referral because of a high incarceration risk", "Observation, since most close by four to five years", "A course of antibiotics directed at the umbilicus"], "ans": 3, "exp": "Umbilical hernia: พบบ่อย, soft reducible bulge, protrude เมื่อ crying. ส่วนใหญ่ 'ปิดเองภายใน 4-5 ปี' → observe. Surgical repair พิจารณาถ้ายังไม่ปิดหลัง 4-5 ปี, ใหญ่มาก, หรือ incarceration (พบน้อย). ต่างจาก inguinal hernia ที่แนะนำผ่าตัดเสมอ. Taping ไม่ช่วย"}, {"topic": "Supraventricular Tachycardia", "q": "A 2-month-old infant presents with poor feeding, irritability, and pallor. The heart rate is 280/min and narrow-complex on ECG, with no beat-to-beat variability. The infant is alert with adequate perfusion. What is the first-line treatment for stable SVT?", "choices": ["Immediate synchronized cardioversion", "Oral beta-blocker only", "Digoxin loading over 24 hours before anything else", "Observation", "Vagal maneuvers"], "ans": 4, "exp": "Supraventricular tachycardia (SVT) ในทารก: HR สูงมาก (~220-300), narrow QRS, ไม่มี beat-to-beat variability (ต่างจาก sinus tachy). ถ้า 'stable': vagal maneuvers (ice to face ในทารก) แล้ว 'IV adenosine' (rapid push). ถ้า 'unstable' (shock/HF): synchronized cardioversion. ป้องกัน recurrence ด้วย beta-blocker/etc. WPW เป็นสาเหตุที่พบ"}, {"topic": "Myocarditis", "q": "A previously healthy child develops tachycardia, tachypnea, and signs of heart failure (hepatomegaly, gallop) following a viral illness. ECG shows low-voltage QRS and troponin is elevated. Echocardiography shows a dilated, poorly contracting ventricle. What is the diagnosis?", "choices": ["Viral myocarditis", "Acute rheumatic fever", "Pericarditis", "Kawasaki disease", "Innocent murmur"], "ans": 0, "exp": "Myocarditis (มัก viral, เช่น coxsackie/enterovirus, adenovirus): เด็กเคยสุขภาพดี → heart failure หลัง viral prodrome, tachycardia ไม่สมเหตุผลกับไข้, gallop, hepatomegaly, elevated troponin, low-voltage ECG, dilated hypocontractile ventricle บน echo. รักษา supportive HF (+/- inotropes, IVIG, mechanical support ในรายรุนแรง). อาจดำเนินสู่ dilated cardiomyopathy"}, {"topic": "Pericarditis", "q": "A child has sharp chest pain that is worse when lying flat and improves when sitting forward, a pericardial friction rub, and ECG showing diffuse ST-segment elevation. What is the diagnosis?", "choices": ["Myocardial infarction", "Acute pericarditis", "Costochondritis", "Pneumothorax", "Gastroesophageal reflux"], "ans": 1, "exp": "Acute pericarditis: pleuritic/positional chest pain (worse supine, ดีขึ้นเมื่อโน้มตัวไปหน้า), pericardial friction rub, diffuse ST elevation + PR depression บน ECG. สาเหตุมัก viral/idiopathic ในเด็ก. เฝ้าระวัง pericardial effusion → cardiac tamponade (Beck triad: hypotension, distended neck veins, muffled heart sounds). รักษา NSAIDs +/- colchicine, treat cause"}, {"topic": "Infective Endocarditis Prophylaxis", "q": "A child with a high-risk cardiac condition (e.g., prosthetic valve or unrepaired cyanotic congenital heart disease) is undergoing a dental procedure involving gingival manipulation. What is recommended?", "choices": ["No prophylaxis under any circumstances", "Prophylaxis for all children regardless of cardiac status", "Antibiotic prophylaxis before the procedure", "Antiviral prophylaxis", "Prophylaxis only after the procedure"], "ans": 2, "exp": "Infective endocarditis prophylaxis (amoxicillin ก่อน dental procedure ที่มี gingival/periapical manipulation) แนะนำเฉพาะผู้มี 'highest-risk' cardiac conditions: prosthetic valve/material, previous IE, unrepaired cyanotic CHD หรือ repaired ที่มี residual defect, cardiac transplant with valvulopathy. เด็กทั่วไป/lesion เสี่ยงต่ำไม่ต้อง. แนวทางลดการใช้ prophylaxis ลงจากอดีต"}, {"topic": "Pediatric Chest Pain", "q": "A 13-year-old has intermittent sharp chest pain reproducible by palpation over the costochondral junctions, worse with deep breathing, with a normal cardiac exam and no exertional symptoms. What is the most likely cause?", "choices": ["Myocardial ischemia", "Pulmonary embolism", "Aortic dissection", "Costochondritis", "Pericarditis"], "ans": 3, "exp": "Pediatric chest pain ส่วนใหญ่ 'ไม่ใช่ cardiac' — สาเหตุที่พบบ่อยคือ musculoskeletal (costochondritis: reproducible ด้วยการกด costochondral junction, worse ด้วยหายใจลึก/movement), respiratory, GI, psychogenic. Red flags ที่บ่งชี้ cardiac: exertional pain/syncope, palpitations, family history sudden death, abnormal exam → ต้อง workup (ECG/echo)"}, {"topic": "Pediatric Syncope", "q": "An adolescent faints briefly after standing in a hot assembly, preceded by lightheadedness, nausea, and visual dimming, and recovers quickly. Exam and ECG are normal. What is the most likely cause?", "choices": ["Ventricular arrhythmia", "Structural heart disease", "Seizure disorder", "Pulmonary embolism", "Vasovagal syncope"], "ans": 4, "exp": "Vasovagal syncope: สาเหตุที่พบบ่อยที่สุดของ syncope ในเด็ก/วัยรุ่น — trigger (prolonged standing, heat, pain, emotion), prodrome (lightheaded, nausea, visual dimming), recovery เร็ว, exam/ECG ปกติ. Benign. Red flags ที่ต้อง workup: syncope 'ขณะออกกำลัง', ไม่มี prodrome, palpitations, family history sudden death, abnormal ECG (long QT, HCM) → cardiac cause"}, {"topic": "Pediatric Hypertension", "q": "A 6-year-old is found to have persistently elevated blood pressure. Compared with adults, what is true about hypertension in young children?", "choices": ["Secondary causes are more likely and should be investigated", "It is almost always essential (primary) hypertension", "It never requires evaluation", "It is always caused by pheochromocytoma", "Blood pressure norms are the same as adults"], "ans": 0, "exp": "ในเด็กเล็ก hypertension มักเป็น 'secondary' — สาเหตุที่พบบ่อยที่สุดคือ renal (renal parenchymal disease, renal artery stenosis), ตามด้วย coarctation, endocrine (CAH, pheochromocytoma, hyperthyroid), และยา. ยิ่งอายุน้อย/BP สูง ยิ่งต้องหาสาเหตุ. BP เทียบกับ percentile ตามอายุ/เพศ/ส่วนสูง. วัยรุ่นที่อ้วนเริ่มพบ primary HT มากขึ้น"}, {"topic": "Heart Failure in Infancy", "q": "A 2-month-old with a large VSD presents with tachypnea, diaphoresis and fatigue during feeds, poor weight gain, and hepatomegaly. Which is the most characteristic sign of heart failure in an infant?", "choices": ["Dependent ankle edema as seen in adult heart failure", "Feeding difficulty with diaphoresis and poor weight gain", "Orthopnea that the patient is able to describe", "Exertional chest pain brought on by activity", "An isolated nocturnal cough without other signs"], "ans": 1, "exp": "Heart failure ในทารกแสดงต่างจากผู้ใหญ่: 'feeding เป็น exertion' → tachypnea, diaphoresis (เหงื่อออกหน้าผาก), fatigue ขณะดูดนม, poor weight gain (FTT), tachycardia, hepatomegaly, +/- respiratory distress. Ankle edema/orthopnea ไม่ค่อยเห็นในทารก. มัก secondary ต่อ large left-to-right shunt (VSD) เมื่อ PVR ลด (~สัปดาห์ 4-8)"}, {"topic": "Renal Tubular Acidosis", "q": "A child has failure to thrive, polyuria, and a normal anion gap (hyperchloremic) metabolic acidosis with an inappropriately alkaline urine (urine pH > 5.5) and hypokalemia. What is the diagnosis?", "choices": ["Diabetic ketoacidosis with a high anion gap", "Lactic acidosis from tissue hypoperfusion", "Distal (type 1) renal tubular acidosis", "Pyloric stenosis with metabolic alkalosis", "Bartter syndrome with hypokalemic alkalosis"], "ans": 2, "exp": "Distal (type 1) RTA: normal anion gap (hyperchloremic) metabolic acidosis + inability to acidify urine ('urine pH >5.5' แม้ acidosis) + hypokalemia, nephrocalcinosis/stones, FTT. Type 2 (proximal) มี bicarbonate wasting (Fanconi). Type 4 = hyperkalemic (aldosterone problem). รักษาด้วย alkali (bicarbonate/citrate) + potassium. RTA เป็นสาเหตุของ FTT + acidosis ในเด็ก"}, {"topic": "Acute Kidney Injury", "q": "A child with severe gastroenteritis and dehydration develops oliguria and a rising creatinine that improves rapidly with fluid resuscitation. What type of acute kidney injury is this?", "choices": ["Intrinsic renal AKI (acute tubular necrosis, established)", "Postrenal AKI (obstruction)", "Chronic kidney disease", "Prerenal AKI", "Glomerulonephritis"], "ans": 3, "exp": "Prerenal AKI: จาก decreased renal perfusion (volume depletion เช่น gastroenteritis/dehydration, shock) — kidney ยังปกติ, ตอบสนองดีต่อ fluid resuscitation (creatinine กลับลง). ถ้า hypoperfusion นาน → acute tubular necrosis (intrinsic, ไม่ตอบสนอง fluid). Postrenal = obstruction. การให้ fluid ทันเวลาช่วยป้องกัน progression"}, {"topic": "Approach to Hematuria", "q": "A child has asymptomatic microscopic hematuria found incidentally, with normal blood pressure, no proteinuria, normal renal function, and a family history of hematuria. What is the most appropriate initial approach?", "choices": ["Proceed immediately to a diagnostic renal biopsy", "Start corticosteroids for a presumed glomerular disease", "Begin dialysis for a presumed renal failure", "Ignore it, since hematuria is never significant", "Evaluate the family and check relatives' urinalysis"], "ans": 4, "exp": "Isolated asymptomatic microscopic hematuria (normal BP/renal function, no proteinuria) + family history → นึกถึง 'thin basement membrane disease (benign familial hematuria)' หรือ early Alport. แนวทาง: ยืนยัน hematuria ซ้ำ, ตรวจ family, ประเมิน proteinuria/BP/renal function, +/- audiometry (Alport). Red flags (proteinuria, HT, ↓GFR, gross hematuria) จึงต้อง workup เข้มขึ้น. ไม่รีบ biopsy ในราย isolated"}, {"topic": "Orthostatic Proteinuria", "q": "An asymptomatic adolescent is found to have proteinuria on a daytime sample, but a first-morning urine sample shows no proteinuria. Renal function and blood pressure are normal. What is the most likely diagnosis?", "choices": ["Orthostatic proteinuria", "Nephrotic syndrome", "Glomerulonephritis", "Diabetic nephropathy", "Multiple myeloma"], "ans": 0, "exp": "Orthostatic (postural) proteinuria: proteinuria เฉพาะช่วงตั้งตรง/กลางวัน แต่ 'first-morning sample ปกติ' (แสดงว่าไม่มี proteinuria ตอนนอนราบ). พบบ่อยในวัยรุ่น, benign, ไม่มี HT/renal dysfunction. วินิจฉัยด้วยการเทียบ first-morning vs daytime urine. ไม่ต้องรักษา, prognosis ดี. แยกจาก persistent/fixed proteinuria ที่ต้อง workup"}, {"topic": "Autosomal Recessive PKD", "q": "A neonate has bilaterally enlarged palpable kidneys, oligohydramnios with pulmonary hypoplasia (Potter sequence), and hepatic fibrosis. What is the most likely diagnosis?", "choices": ["Wilms tumor", "Autosomal recessive polycystic kidney disease", "Multicystic dysplastic kidney (unilateral)", "Autosomal dominant polycystic kidney disease presenting in the neonate", "Hydronephrosis"], "ans": 1, "exp": "Autosomal recessive PKD (ARPKD): bilaterally enlarged kidneys ในทารก, oligohydramnios → pulmonary hypoplasia + Potter sequence (severe cases fatal), และ 'congenital hepatic fibrosis' (portal hypertension). ต่างจาก ADPKD (present ผู้ใหญ่, berry aneurysm, liver cysts). Wilms เป็น unilateral solid mass. ประเมิน renal function/respiratory/liver"}, {"topic": "Nephrolithiasis - Hypercalciuria", "q": "A child presents with gross hematuria and colicky flank pain, and a small kidney stone is identified. The most common metabolic abnormality predisposing to pediatric stones is which of the following?", "choices": ["Hyperkalemia from impaired potassium excretion", "Hypernatremia from a free-water deficit", "Idiopathic hypercalciuria raising stone risk", "Hypoalbuminemia from urinary protein loss", "Hyperbilirubinemia from red-cell breakdown"], "ans": 2, "exp": "Pediatric nephrolithiasis: hematuria + colicky flank pain. Metabolic abnormality ที่พบบ่อยที่สุดคือ 'idiopathic hypercalciuria'. ต้องประเมิน metabolic (24-hr urine calcium/oxalate/citrate/cystine), imaging (ultrasound/CT). รักษา: hydration, ปรับอาหาร (ลด sodium, adequate calcium), treat underlying (RTA, hypercalciuria). Stones ในเด็กมักมี underlying cause"}, {"topic": "Phimosis / Paraphimosis", "q": "An uncircumcised boy has the foreskin retracted behind the glans and it cannot be returned to its normal position, causing a painful swollen glans. What is this urologic emergency?", "choices": ["Phimosis", "Balanitis", "Testicular torsion", "Paraphimosis", "Hydrocele"], "ans": 3, "exp": "Paraphimosis: foreskin ที่ retract ไปหลัง glans แล้ว 'ดึงกลับไม่ได้' → constriction ring → glans บวม/เจ็บ, เสี่ยง ischemia = 'emergency' ต้อง manual reduction (compression) หรือ dorsal slit. ต่างจาก phimosis (foreskin ตึง retract ไม่ได้ — ปกติในเด็กเล็ก physiologic, ไม่ใช่ emergency). Balanitis = inflammation/infection ของ glans"}, {"topic": "Febrile Neutropenia", "q": "A child on chemotherapy for leukemia develops a fever of 38.5°C with an absolute neutrophil count of 300/µL. What is the most appropriate immediate management?", "choices": ["Oral antibiotics as an outpatient", "Antipyretics and observation at home", "Wait for culture results before antibiotics", "Granulocyte transfusion as first-line", "Blood cultures and prompt empiric broad-spectrum IV antibiotics"], "ans": 4, "exp": "Febrile neutropenia (fever + ANC <500) เป็น oncologic emergency: เสี่ยง overwhelming bacterial sepsis (รวม Pseudomonas). ต้อง blood cultures แล้วเริ่ม 'empiric broad-spectrum IV antibiotics ทันที' (เช่น antipseudomonal beta-lactam: cefepime/piperacillin-tazobactam) 'ไม่รอ' culture. ประเมิน source, พิจารณาเพิ่ม coverage ตาม risk. ห้ามชะลอ antibiotics"}, {"topic": "Aplastic Anemia", "q": "A child presents with fatigue, recurrent infections, and bleeding. CBC shows pancytopenia (anemia, leukopenia, thrombocytopenia) with a low reticulocyte count, and bone marrow is hypocellular ('empty'). What is the diagnosis?", "choices": ["Aplastic anemia", "Acute leukemia", "Iron deficiency anemia", "Immune thrombocytopenic purpura", "Hemolytic anemia"], "ans": 0, "exp": "Aplastic anemia: pancytopenia + reticulocytopenia + 'hypocellular bone marrow' (bone marrow failure). สาเหตุ: idiopathic/autoimmune, drugs/toxins, viral (hepatitis, parvovirus), inherited (Fanconi anemia). ต่างจาก leukemia (marrow เต็มด้วย blasts). รักษา: supportive (transfusion, treat infection), immunosuppression, หรือ HSCT (curative). Fanconi = inherited + congenital anomalies"}, {"topic": "Disseminated Intravascular Coagulation", "q": "A critically ill child with sepsis develops diffuse bleeding from IV sites and mucosa. Labs show thrombocytopenia, prolonged PT and aPTT, low fibrinogen, and elevated D-dimer with schistocytes. What is the diagnosis?", "choices": ["Immune thrombocytopenic purpura after a virus", "Disseminated intravascular coagulation from sepsis", "Hemophilia A from a factor VIII deficiency", "Von Willebrand disease with mucosal bleeding", "Vitamin K deficiency prolonging the clotting times"], "ans": 1, "exp": "Disseminated intravascular coagulation (DIC): consumptive coagulopathy จาก severe illness (sepsis, trauma, malignancy) → thrombocytopenia, prolonged PT/aPTT, 'low fibrinogen', high D-dimer, schistocytes, bleeding +/- microthrombi. รักษา 'ที่ต้นเหตุ' (เช่น sepsis) + supportive (platelets, FFP, cryoprecipitate ตาม bleeding). ต่างจาก ITP (isolated thrombocytopenia, normal coags)"}, {"topic": "Transfusion Reaction", "q": "During a blood transfusion, a child develops fever, flank pain, hypotension, and dark (hemoglobinuric) urine. What type of transfusion reaction is this?", "choices": ["Febrile non-hemolytic reaction", "Mild allergic (urticarial) reaction", "Acute hemolytic transfusion reaction", "Transfusion-associated circulatory overload", "Delayed hemolytic reaction"], "ans": 2, "exp": "Acute hemolytic transfusion reaction (มัก ABO incompatibility/clerical error): fever, flank/back pain, hypotension, hemoglobinuria (dark urine), +/- DIC, renal failure. ต้อง 'หยุด transfusion ทันที' + IV fluids + supportive + recheck identification. ต่างจาก febrile non-hemolytic (fever เพียงอย่างเดียว, common, benign) และ allergic (urticaria)"}, {"topic": "G6PD Hemolysis", "q": "A boy with known G6PD deficiency develops acute pallor, jaundice, and dark urine after eating fava beans (or taking an oxidant drug). The blood smear shows bite cells and Heinz bodies. What is the management principle?", "choices": ["Lifelong corticosteroids to suppress the hemolysis", "Iron supplementation to correct the anemia", "Splenectomy performed in all affected patients", "Supportive care with strict avoidance of oxidant triggers", "Regular scheduled exchange transfusions"], "ans": 3, "exp": "G6PD deficiency (X-linked): episodic acute hemolysis หลัง oxidative stress — fava beans, drugs (บาง sulfonamides, primaquine, nitrofurantoin, naphthalene), infection. Smear: bite cells, Heinz bodies. รักษา 'supportive' + 'หลีกเลี่ยง triggers'; transfusion ในรายรุนแรง. ให้ความรู้ผู้ป่วย/ครอบครัวเรื่องยาและอาหารที่ห้าม. พบชุกในเอเชีย/ไทย"}, {"topic": "Lactose Intolerance", "q": "An older child develops abdominal bloating, cramps, flatulence, and non-bloody watery diarrhea after consuming milk or dairy, often following a bout of viral gastroenteritis. Symptoms resolve when dairy is removed. What is the mechanism?", "choices": ["An IgE-mediated allergy to cow's-milk protein", "Celiac disease with gluten-induced villous atrophy", "A bacterial enteric infection of the gut", "Pancreatic insufficiency impairing digestion", "Lactase deficiency causing malabsorption of lactose"], "ans": 4, "exp": "Lactose intolerance: lactase deficiency (primary/genetic ที่พบมากในเอเชีย, หรือ secondary หลัง gastroenteritis) → lactose ไม่ย่อย → osmotic diarrhea + gas/bloating/cramps 'ไม่มีเลือด'. ต่างจาก cow's milk 'allergy' (immune-mediated, อาจมีเลือด/eczema, ในทารก). วินิจฉัยจากประวัติ/hydrogen breath test. รักษา: ลด lactose หรือใช้ lactase. Secondary มักหายเมื่อ mucosa ฟื้น"}, {"topic": "Toddler's Diarrhea", "q": "A thriving, well-appearing 2-year-old passes several loose stools daily, often containing undigested food particles, but has normal growth and no signs of malabsorption or dehydration. The child drinks large amounts of fruit juice. What is the diagnosis?", "choices": ["Toddler's diarrhea", "Celiac disease", "Inflammatory bowel disease", "Cystic fibrosis", "Giardiasis"], "ans": 0, "exp": "Toddler's diarrhea (chronic nonspecific diarrhea): เด็ก 1-3 ปีที่ 'thriving' และ growth ปกติ, loose stools +/- undigested food, ไม่มี malabsorption/dehydration. สัมพันธ์กับ excessive fluid/juice (sorbitol/fructose) และ low fat. รักษา: '4 F's' — ปรับ fluid (ลด juice), เพิ่ม fat & fiber, ลด fructose. Benign, self-limited. ไม่ต้อง extensive workup ถ้า thriving"}, {"topic": "Inflammatory Bowel Disease", "q": "An adolescent has months of crampy abdominal pain, chronic diarrhea (sometimes bloody), weight loss, growth failure, and perianal skin tags/fistulae, with oral ulcers and elevated inflammatory markers. What is the most likely diagnosis?", "choices": ["Irritable bowel syndrome", "Crohn disease", "Functional constipation", "Toddler's diarrhea", "Celiac disease"], "ans": 1, "exp": "Inflammatory bowel disease (Crohn disease): chronic abdominal pain, diarrhea (+/- blood), weight loss, 'growth failure/delayed puberty' (สำคัญในเด็ก), perianal disease (skin tags, fistula), extraintestinal (oral ulcers, arthritis, uveitis), elevated ESR/CRP/calprotectin. Crohn = transmural, skip lesions, mouth-to-anus. Ulcerative colitis = continuous colonic, bloody diarrhea. วินิจฉัย endoscopy + biopsy"}, {"topic": "Anal Fissure", "q": "A 1-year-old with a history of hard stools has bright red blood streaking the outside of the stool and on the toilet paper, with pain on defecation. Examination reveals a small tear at the anal margin. What is the most likely cause?", "choices": ["Meckel diverticulum", "Intussusception", "Anal fissure", "Inflammatory bowel disease", "Juvenile polyp"], "ans": 2, "exp": "Anal fissure: สาเหตุที่พบบ่อยที่สุดของ 'painful' rectal bleeding (bright red, streaking stool surface/toilet paper) ในเด็กเล็ก, สัมพันธ์กับ constipation/hard stool. เห็น tear ที่ anal margin. รักษา: จัดการ constipation (stool softener, fiber, fluids), sitz bath. ต่างจาก Meckel (painless, large-volume) และ juvenile polyp (painless, intermittent)"}, {"topic": "Rectal Prolapse", "q": "A young child strains during defecation and a red, tubular mass of rectal mucosa protrudes from the anus, then reduces. Recurrent rectal prolapse in a child should prompt testing for which underlying disease?", "choices": ["Diabetes mellitus", "Hypothyroidism", "Sickle cell disease", "Cystic fibrosis", "Wilson disease"], "ans": 3, "exp": "Rectal prolapse ในเด็ก มักสัมพันธ์กับ constipation/straining และส่วนใหญ่ self-limited. แต่ 'recurrent' rectal prolapse ควร screen 'cystic fibrosis' (จาก malnutrition/steatorrhea/cough increasing intra-abdominal pressure) ด้วย sweat chloride. สาเหตุอื่น: parasites, malnutrition. รักษา manual reduction + treat underlying (constipation/CF)"}, {"topic": "Encopresis", "q": "A 6-year-old who is toilet trained has involuntary soiling of the underwear with soft stool, on a background of chronic constipation with a large fecal mass in the rectum. What is the mechanism?", "choices": ["Primary neurologic bladder-bowel disorder", "Deliberate behavioral defiance", "Infectious diarrhea", "Spinal cord tumor", "Overflow incontinence around retained stool"], "ans": 4, "exp": "Functional encopresis: มักเป็น 'overflow' soiling — chronic constipation → fecal impaction → liquid stool ไหลผ่านรอบก้อน (involuntary, ไม่ใช่การจงใจ). รักษา: disimpaction + maintenance laxative (PEG) + behavioral toilet program + education (ลด blame). ต้องแยก organic (Hirschsprung, spinal) แต่ functional พบบ่อยสุด"}, {"topic": "Cyclic Vomiting Syndrome", "q": "A child has recurrent, stereotyped episodes of intense vomiting lasting hours to days, separated by completely symptom-free intervals, with a family history of migraine. Workup between episodes is normal. What is the diagnosis?", "choices": ["Cyclic vomiting syndrome", "Gastroesophageal reflux disease", "Increased intracranial pressure", "Pyloric stenosis", "Diabetic ketoacidosis"], "ans": 0, "exp": "Cyclic vomiting syndrome: recurrent 'stereotyped' vomiting episodes (เหมือนเดิมทุกครั้ง) สลับกับช่วงปกติสมบูรณ์, สัมพันธ์กับ personal/family history of migraine. เป็น diagnosis of exclusion (ต้องแยก metabolic, GI obstruction, increased ICP — โดยเฉพาะ vomiting ตอนเช้า/neuro signs). รักษา: หลีกเลี่ยง triggers, abortive (antiemetic/triptan), prophylaxis (cyproheptadine/amitriptyline)"}, {"topic": "Wilson Disease", "q": "A 12-year-old has worsening school performance, tremor, dysarthria, and new liver disease (elevated transaminases). Slit-lamp exam reveals Kayser-Fleischer rings. Serum ceruloplasmin is low. What is the diagnosis?", "choices": ["Autoimmune hepatitis", "Wilson disease", "Hemochromatosis", "Alpha-1 antitrypsin deficiency", "Viral hepatitis"], "ans": 1, "exp": "Wilson disease (autosomal recessive, ATP7B): copper สะสมใน liver, brain, cornea. เด็ก/วัยรุ่นมักมาด้วย 'hepatic' (hepatitis, cirrhosis, acute liver failure), ผู้โตขึ้นมี 'neuropsychiatric' (tremor, dysarthria, behavioral/school decline) + Kayser-Fleischer rings. Ceruloplasmin ต่ำ, urine copper สูง. รักษา: chelation (penicillamine/trientine) + zinc, low-copper diet. เป็น treatable cause ของ liver + neuro disease"}, {"topic": "Chronic Hepatitis B", "q": "A child who acquired hepatitis B perinatally is typically asymptomatic but at risk for which long-term complication?", "choices": ["Immediate fulminant hepatic failure in every case", "Spontaneous complete viral clearance in all children", "Chronic infection leading to cirrhosis and liver cancer", "Isolated nephrotic syndrome without liver disease", "No meaningful long-term risk from the infection"], "ans": 2, "exp": "Hepatitis B ที่ติดตั้งแต่ 'perinatal/early childhood' มีโอกาสสูงมากที่จะกลายเป็น 'chronic' (>90% ในทารก vs <5% ในผู้ใหญ่) และมัก asymptomatic แต่เสี่ยง cirrhosis และ hepatocellular carcinoma ระยะยาว. จึงเน้นป้องกัน perinatal transmission (HBIG + vaccine แรกเกิด) และ universal vaccination. ต้อง monitor + antiviral ในบางราย"}, {"topic": "Acute Liver Failure", "q": "A child develops jaundice, coagulopathy (elevated INR not corrected by vitamin K), and hepatic encephalopathy over days. Which is a common cause of pediatric acute liver failure that must be identified urgently?", "choices": ["Iron deficiency anemia", "Simple gastroenteritis", "Physiologic jaundice", "Acetaminophen overdose", "Constipation"], "ans": 3, "exp": "Pediatric acute liver failure: jaundice + coagulopathy (INR สูง ไม่แก้ด้วย vitamin K) + encephalopathy. สาเหตุสำคัญที่ต้องรีบระบุ: 'acetaminophen overdose' (มี antidote N-acetylcysteine), viral hepatitis, metabolic (Wilson, metabolic disease ในทารก), autoimmune, drugs, ischemia. รักษา supportive/ICU + treat cause; อาจต้อง liver transplant. Acetaminophen level + NAC สำคัญ"}, {"topic": "Hepatoblastoma", "q": "A 2-year-old has an enlarging right upper quadrant abdominal mass and a markedly elevated serum alpha-fetoprotein (AFP). What is the most likely malignancy?", "choices": ["Wilms tumor", "Neuroblastoma", "Hodgkin lymphoma", "Rhabdomyosarcoma", "Hepatoblastoma"], "ans": 4, "exp": "Hepatoblastoma: มะเร็งตับที่พบบ่อยที่สุดในเด็กเล็ก (<3 ปี): RUQ abdominal mass + 'markedly elevated AFP' (tumor marker). สัมพันธ์กับ Beckwith-Wiedemann, prematurity, familial adenomatous polyposis. รักษา: chemotherapy + surgical resection. AFP ใช้ติดตาม response. ต่างจาก Wilms (renal) และ neuroblastoma (catecholamines, ข้าม midline)"}, {"topic": "Rhabdomyosarcoma", "q": "A young child develops a rapidly growing mass; a common site is the head/neck or genitourinary tract, and a vaginal lesion may protrude as a 'bunch of grapes' (sarcoma botryoides). What is the diagnosis?", "choices": ["Rhabdomyosarcoma", "Neuroblastoma", "Wilms tumor", "Ewing sarcoma", "Retinoblastoma"], "ans": 0, "exp": "Rhabdomyosarcoma: soft tissue sarcoma ที่พบบ่อยที่สุดในเด็ก (จาก skeletal muscle precursors). Sites: head/neck (รวม orbit → proptosis, parameningeal), genitourinary (bladder, vagina — 'sarcoma botryoides' คล้ายพวงองุ่น). รักษา multimodal (surgery + chemo +/- radiation). Embryonal type prognosis ดีกว่า alveolar"}, {"topic": "Langerhans Cell Histiocytosis", "q": "A child has lytic bone lesions (e.g., skull), a chronic seborrheic-like scalp rash, and, in some cases, diabetes insipidus. Biopsy shows CD1a-positive histiocytes with Birbeck granules. What is the diagnosis?", "choices": ["Acute leukemia infiltrating the bone marrow", "Langerhans cell histiocytosis with CD1a-positive cells", "Metastatic neuroblastoma involving the bones", "Hematogenous osteomyelitis of the skull", "Ewing sarcoma arising in the flat bones"], "ans": 1, "exp": "Langerhans cell histiocytosis (LCH): clonal proliferation ของ Langerhans cells (CD1a+, S100+, Birbeck granules). Presentations หลากหลาย: lytic bone lesions (skull), skin rash (seborrheic/eczematous), diabetes insipidus (pituitary infiltration), lymphadenopathy, hepatosplenomegaly. Range จาก single-system (ดี) ถึง multisystem. รักษาตาม extent (observation ถึง chemotherapy)"}, {"topic": "Fanconi Anemia", "q": "A child with short stature, abnormal thumbs/radii, café-au-lait spots, and progressive bone marrow failure (pancytopenia) has increased chromosomal breakage on testing. What is the diagnosis?", "choices": ["Acquired aplastic anemia", "Diamond-Blackfan anemia", "Fanconi anemia", "Immune thrombocytopenic purpura", "Iron deficiency anemia"], "ans": 2, "exp": "Fanconi anemia: inherited bone marrow failure + congenital anomalies (short stature, abnormal thumbs/radii, café-au-lait, renal/cardiac anomalies) + increased 'chromosomal breakage' (DNA repair defect) + เสี่ยง malignancy (AML, solid tumors). ต่างจาก acquired aplastic anemia (ไม่มี congenital anomaly). Diamond-Blackfan = pure red cell aplasia. รักษา: androgens/HSCT"}, {"topic": "Diamond-Blackfan Anemia", "q": "A 3-month-old presents with severe macrocytic anemia, a very low reticulocyte count, and normal platelets/white cells. Some have thumb anomalies and short stature. Bone marrow shows absent red cell precursors only. What is the diagnosis?", "choices": ["Transient erythroblastopenia of childhood", "Iron deficiency anemia", "Fanconi anemia", "Diamond-Blackfan anemia", "Beta-thalassemia major"], "ans": 3, "exp": "Diamond-Blackfan anemia: congenital pure red cell aplasia — severe macrocytic anemia + reticulocytopenia + 'absent erythroid precursors' (WBC/platelet ปกติ), present ในทารก (<1 ปี), +/- congenital anomalies (thumb, craniofacial, short stature). ต่างจาก transient erythroblastopenia of childhood (TEC: normocytic, เด็กโต ~1-4 ปี, หลัง viral, หายเอง). รักษา: corticosteroids, transfusion, HSCT"}, {"topic": "Methemoglobinemia", "q": "An infant presents with cyanosis that does not improve with oxygen, and the blood appears chocolate-brown. Pulse oximetry reads around 85% and does not correlate with the PaO2. What is the diagnosis?", "choices": ["Cyanotic congenital heart disease", "Severe pneumonia", "Carbon monoxide poisoning", "Polycythemia", "Methemoglobinemia"], "ans": 4, "exp": "Methemoglobinemia: hemoglobin iron ถูก oxidize เป็น Fe3+ ไม่จับ O2 → cyanosis 'ไม่ตอบสนอง O2', 'chocolate-brown blood', pulse ox ~85% (ไม่สัมพันธ์ PaO2 ที่ปกติ), saturation gap. สาเหตุ: oxidant drugs/chemicals (topical anesthetics, nitrates/well water ในทารก), congenital (cytochrome b5 reductase), dapsone. รักษาด้วย 'methylene blue' (ระวังในผู้ G6PD deficiency) + remove agent"}, {"topic": "Splenic Sequestration", "q": "A young child with sickle cell disease (or severe thalassemia) suddenly develops pallor, lethargy, a rapidly enlarging spleen, and a sharp drop in hemoglobin with signs of hypovolemic shock. What is the emergency?", "choices": ["Acute splenic sequestration with a falling hemoglobin", "An aplastic crisis triggered by parvovirus B19", "A vaso-occlusive crisis causing severe bone pain", "A hyperhemolytic crisis with brisk red-cell breakdown", "Chronic transfusional iron overload of the organs"], "ans": 0, "exp": "Acute splenic sequestration: เลือดสะสมค้างใน spleen อย่างรวดเร็ว → rapidly enlarging spleen + acute drop in Hb + hypovolemic shock ในเด็กเล็กที่มี sickle cell/thalassemia. เป็น 'emergency' — ต้อง fluid resuscitation + transfusion. Recurrent → พิจารณา splenectomy. ต่างจาก aplastic crisis (parvovirus B19, reticulocyte ต่ำ, spleen ไม่โต)"}, {"topic": "Asplenia Vaccination", "q": "A child who has undergone splenectomy (or has functional asplenia from sickle cell disease) requires special prevention against which type of infection?", "choices": ["Viral upper respiratory infections", "Encapsulated bacteria", "Fungal infections", "Parasitic infections", "Non-typhoidal Salmonella only"], "ans": 1, "exp": "Asplenic/hyposplenic patients เสี่ยง overwhelming sepsis จาก 'encapsulated bacteria' (Streptococcus pneumoniae, Haemophilus influenzae type b, Neisseria meningitidis) เพราะ spleen สำคัญต่อการกำจัด encapsulated organisms. ป้องกันด้วย vaccinations (pneumococcal, Hib, meningococcal), penicillin prophylaxis (โดยเฉพาะเด็กเล็ก/sickle cell), และรีบรักษาไข้ทันที (emergency)"}, {"topic": "Alport Syndrome", "q": "A boy has persistent hematuria progressing to proteinuria and declining renal function, along with progressive sensorineural hearing loss and eye abnormalities. There is an X-linked family history of kidney failure. What is the diagnosis?", "choices": ["Thin basement membrane disease", "Post-streptococcal glomerulonephritis", "Alport syndrome", "IgA nephropathy", "Minimal change disease"], "ans": 2, "exp": "Alport syndrome: defect ใน type IV collagen (มัก X-linked) → progressive glomerulonephritis (hematuria → proteinuria → ESRD), 'sensorineural hearing loss', และ ocular abnormalities (anterior lenticonus). Family history ของ renal failure + deafness. ต่างจาก thin basement membrane disease (benign familial hematuria, ไม่ progress). วินิจฉัย genetics/biopsy"}, {"topic": "Steroid-Sensitive Nephrotic Relapse", "q": "A child with minimal change nephrotic syndrome initially responded to steroids but now has frequent relapses or becomes steroid-dependent. What is a reasonable next step to reduce steroid exposure?", "choices": ["Stop all treatment permanently", "Immediate kidney transplant", "Lifelong high-dose steroids only", "Steroid-sparing agents", "Dialysis"], "ans": 3, "exp": "Frequently-relapsing/steroid-dependent nephrotic syndrome: แม้ตอบสนอง steroid แต่ relapse บ่อย → ใช้ 'steroid-sparing agents' (levamisole, cyclophosphamide, calcineurin inhibitors เช่น cyclosporine/tacrolimus, MMF, rituximab) เพื่อลด steroid toxicity (growth, cushingoid, bone). Minimal change ส่วนใหญ่ยัง prognosis ดี (ไม่นำสู่ ESRD). Steroid-'resistant' ต้อง biopsy (FSGS)"}, {"topic": "Congenital Nephrotic Syndrome", "q": "A newborn/young infant (first 3 months) presents with massive proteinuria, severe edema, and hypoalbuminemia, with a large placenta at birth. This does not respond to steroids. What is the most likely category?", "choices": ["Minimal change disease", "Post-streptococcal glomerulonephritis", "Orthostatic proteinuria", "Transient proteinuria of fever", "Congenital nephrotic syndrome"], "ans": 4, "exp": "Congenital nephrotic syndrome (present <3 เดือน): massive proteinuria, edema, hypoalbuminemia; Finnish type (NPHS1/nephrin mutation) มี large placenta. 'ไม่ตอบสนอง steroid' (genetic/structural, ไม่ใช่ immune). รักษา: albumin, nutrition, จัดการ thrombosis/infection, ACE inhibitor/indomethacin, สุดท้าย nephrectomy + dialysis + transplant. ต่างจาก minimal change (เด็กโต, steroid-sensitive)"}, {"topic": "Hypertrophic Cardiomyopathy", "q": "A 15-year-old athlete collapses suddenly during exercise. He had a family history of sudden cardiac death and a prior systolic murmur that increased with standing/Valsalva. What is the most likely underlying condition?", "choices": ["Hypertrophic cardiomyopathy", "Innocent flow murmur", "Mitral valve prolapse without consequence", "Costochondritis", "Vasovagal syncope"], "ans": 0, "exp": "Hypertrophic cardiomyopathy (HCM): สาเหตุที่พบบ่อยของ 'sudden cardiac death ในนักกีฬาวัยรุ่น'. Autosomal dominant (sarcomere mutation) → LV outflow obstruction; murmur 'เพิ่มขึ้น' เมื่อ preload ลด (standing/Valsalva) และลดลงเมื่อ squatting (ตรงข้าม innocent murmur). Family history sudden death. ต้อง ECG/echo, จำกัด competitive sports, พิจารณา ICD. Exertional syncope = red flag"}, {"topic": "Long QT Syndrome", "q": "An adolescent has recurrent syncope during exercise or emotional stress, and a sibling died suddenly at a young age. ECG shows a prolonged corrected QT interval. What is the risk?", "choices": ["Supraventricular tachycardia only", "Ventricular arrhythmia and sudden death", "Benign palpitations with no risk", "Heart block from birth only", "Atrial fibrillation only"], "ans": 1, "exp": "Long QT syndrome (congenital, ion channel mutations): prolonged QTc → เสี่ยง 'torsades de pointes' → syncope/sudden death, มัก trigger ด้วย exertion/emotion/startle (หรือ swimming/auditory ตาม subtype). Family history sudden death. รักษา: beta-blockers, หลีกเลี่ยง QT-prolonging drugs และ electrolyte abnormalities, พิจารณา ICD. Exertional syncope + family history = red flag ต้อง ECG"}, {"topic": "AVSD in Down Syndrome", "q": "An infant with Down syndrome has signs of heart failure, and echocardiography reveals a common atrioventricular canal defect. Which congenital heart lesion is most classically associated with trisomy 21?", "choices": ["Tetralogy of Fallot", "Transposition of the great arteries", "Atrioventricular septal defect", "Coarctation of the aorta", "Ebstein anomaly"], "ans": 2, "exp": "Atrioventricular septal defect (AVSD/AV canal defect) เป็น congenital heart lesion ที่ 'classic' สัมพันธ์กับ Down syndrome (trisomy 21). ทารก Down ทุกรายควรทำ echocardiogram. AVSD → left-to-right shunt + AV valve regurgitation → heart failure + pulmonary hypertension → ต้องผ่าตัดซ่อม. VSD ก็พบบ่อยใน Down เช่นกัน"}, {"topic": "Pulmonary Stenosis", "q": "A child is found to have a systolic ejection murmur at the left upper sternal border that radiates to the back, with an ejection click. Echocardiography confirms narrowing at the pulmonary valve. What is the most appropriate treatment for significant stenosis?", "choices": ["Beta-blocker only", "Diuretics as definitive therapy", "No treatment ever needed", "Balloon valvuloplasty", "Immediate valve replacement in all"], "ans": 3, "exp": "Pulmonary valve stenosis: systolic ejection murmur ที่ LUSB radiate ไปหลัง + ejection click (ลดลงเมื่อหายใจเข้า). Mild มัก observe. Moderate-severe (gradient สูง/RV strain) รักษาด้วย 'balloon valvuloplasty' (first-line, ได้ผลดี). สัมพันธ์กับ Noonan syndrome. Critical pulmonary stenosis ในทารกอาจ duct-dependent (PGE1)"}, {"topic": "Aortic Stenosis", "q": "A child has a harsh systolic ejection murmur at the right upper sternal border radiating to the carotids, with a possible ejection click. Severe cases may cause exertional syncope or chest pain. What is a recognized association?", "choices": ["Trisomy 21", "Kawasaki disease", "Rheumatic mitral stenosis in infancy", "Coxsackie myocarditis", "Bicuspid aortic valve"], "ans": 4, "exp": "Congenital aortic (valvular) stenosis: harsh systolic ejection murmur ที่ RUSB radiate ไป carotids + ejection click, +/- thrill. มัก associated กับ 'bicuspid aortic valve' (พบบ่อย, สัมพันธ์กับ coarctation/Turner). Severe → exertional syncope, chest pain, sudden death → จำกัด activity, balloon/surgical valvotomy. Critical neonatal AS = duct-dependent (PGE1)"}, {"topic": "Iron Overload in Thalassemia", "q": "A child with transfusion-dependent thalassemia major, after years of regular transfusions, is at risk for iron overload affecting the heart, liver, and endocrine glands. What is the appropriate management?", "choices": ["Iron chelation therapy", "Additional iron supplementation", "High-dose vitamin C alone", "Regular phlebotomy", "No intervention needed"], "ans": 0, "exp": "Transfusion-dependent thalassemia → iron overload (แต่ละหน่วยเลือดมี iron, ร่างกายขับไม่ได้) → cardiac (cardiomyopathy/arrhythmia — สาเหตุตายหลัก), liver (cirrhosis), endocrine (diabetes, hypogonadism, hypothyroid, growth failure). รักษาด้วย 'iron chelation' (deferoxamine SC/IV, oral deferasirox/deferiprone), monitor ferritin + cardiac/liver iron (MRI T2*). Phlebotomy ใช้ไม่ได้ (anemic)"}, {"topic": "Ewing Sarcoma", "q": "An adolescent has progressive pain and swelling of the diaphysis of a long bone (or pelvis), with systemic symptoms (fever, weight loss). X-ray shows a lytic lesion with an 'onion-skin' periosteal reaction. What is the likely diagnosis?", "choices": ["Osteosarcoma", "Ewing sarcoma", "Osteomyelitis", "Osteoid osteoma", "Giant cell tumor"], "ans": 1, "exp": "Ewing sarcoma: malignant bone tumor ในเด็ก/วัยรุ่น, มักที่ 'diaphysis' ของ long bones หรือ pelvis/flat bones, +/- systemic symptoms (fever, weight loss — เลียนแบบ infection). X-ray: lytic + 'onion-skin' (lamellated) periosteal reaction. t(11;22). รักษา chemo + surgery/radiation. ต่างจาก osteosarcoma (metaphysis, 'sunburst'/Codman triangle)"}, {"topic": "Osteosarcoma", "q": "A 14-year-old has pain and swelling around the knee (distal femur). X-ray shows a destructive metaphyseal lesion with a 'sunburst' pattern and Codman triangle. What is the most likely diagnosis?", "choices": ["Ewing sarcoma", "Osteomyelitis", "Osteosarcoma", "Chondrosarcoma", "Osteoid osteoma"], "ans": 2, "exp": "Osteosarcoma: malignant bone tumor ที่พบบ่อยที่สุดในวัยรุ่น (ช่วง growth spurt), มักที่ 'metaphysis' ของ long bones รอบเข่า (distal femur/proximal tibia). X-ray: 'sunburst' periosteal reaction + Codman triangle. Metastasis ไปปอด. รักษา: neoadjuvant chemo + limb-sparing surgery/resection. ต่างจาก Ewing (diaphysis, onion-skin)"}, {"topic": "Juvenile Polyp", "q": "A 4-year-old has intermittent, painless, small-volume bright red rectal bleeding and passes a polyp. Colonoscopy shows a solitary pedunculated hamartomatous polyp. What is the diagnosis?", "choices": ["Colorectal carcinoma", "Meckel diverticulum", "Anal fissure", "Juvenile polyp", "Inflammatory bowel disease"], "ans": 3, "exp": "Juvenile polyp: สาเหตุที่พบบ่อยของ 'painless' rectal bleeding ในเด็กก่อนวัยเรียน — solitary pedunculated hamartomatous polyp, มัก recto-sigmoid, อาจ prolapse/หลุดเอง. Benign (isolated), รักษาด้วย polypectomy. ต่างจาก multiple polyps/polyposis syndromes (FAP, Peutz-Jeghers) ที่มี cancer risk และต้อง surveillance"}, {"topic": "Hemophilia Joint Care", "q": "A boy with severe hemophilia A has recurrent hemarthroses of the knee. Beyond acute factor replacement, what is the key long-term strategy to prevent chronic joint damage (hemophilic arthropathy)?", "choices": ["Chronic NSAIDs and aspirin", "Intramuscular injections for pain", "Complete permanent immobilization", "Repeated joint aspiration only", "Prophylactic regular factor replacement"], "ans": 4, "exp": "Severe hemophilia + recurrent hemarthrosis → chronic 'hemophilic arthropathy' (joint destruction). กลยุทธ์ระยะยาวคือ 'prophylactic factor replacement' (ให้ factor สม่ำเสมอเพื่อป้องกัน bleed) + physiotherapy. หลีกเลี่ยง 'aspirin/NSAIDs' (เพิ่ม bleeding) และ IM injections. Emicizumab (ในบางกรณี) ลด bleeding. Acute bleed: factor replacement + RICE"}, {"topic": "Transient Erythroblastopenia of Childhood", "q": "A previously healthy 2-year-old develops gradual pallor and is found to have normocytic anemia with a low reticulocyte count following a viral illness, but is otherwise well and recovers spontaneously over weeks. What is the diagnosis?", "choices": ["Transient erythroblastopenia of childhood after a virus", "Diamond-Blackfan congenital pure red-cell aplasia", "Iron deficiency anemia from inadequate intake", "Acute leukemia infiltrating the bone marrow", "A hemolytic anemia with brisk red-cell destruction"], "ans": 0, "exp": "Transient erythroblastopenia of childhood (TEC): temporary red cell aplasia หลัง viral illness ในเด็กวัย ~1-4 ปี (โตกว่า Diamond-Blackfan) — normocytic anemia + reticulocytopenia, ผู้ป่วยดูดี, 'หายเองภายในสัปดาห์-เดือน' โดยไม่ต้องรักษา (+/- transfusion ถ้า severe). ต่างจาก Diamond-Blackfan (congenital, macrocytic, ทารก, +/- anomalies)"}, {"topic": "Sickle Cell - Aplastic Crisis", "q": "A child with a chronic hemolytic anemia (sickle cell or hereditary spherocytosis) develops a sudden, profound worsening of anemia with a very low reticulocyte count after a viral illness. Which virus is the classic trigger?", "choices": ["Rotavirus", "Parvovirus B19", "Respiratory syncytial virus", "Hepatitis A virus", "Adenovirus"], "ans": 1, "exp": "Aplastic crisis ในผู้มี chronic hemolytic anemia (sickle cell, hereditary spherocytosis, thalassemia): 'parvovirus B19' ติดเชื้อ erythroid precursors → หยุดสร้าง RBC ชั่วคราว → Hb ตกฮวบ + 'reticulocytopenia'. ในคนที่ RBC lifespan สั้นอยู่แล้วจึงเกิด severe anemia. รักษา: transfusion support (self-limited ~1-2 สัปดาห์). ต่างจาก splenic sequestration (reticulocyte สูง, spleen โต)"}, {"topic": "Bronchiolitis-associated Wheeze vs Asthma", "q": "A 2-year-old with recurrent episodes of wheezing triggered by viral colds, a personal history of eczema, and a family history of asthma is more likely to have which condition rather than simple viral bronchiolitis?", "choices": ["Cystic fibrosis", "Foreign body aspiration", "Asthma (recurrent wheeze with atopy)", "Congenital heart disease", "Gastroesophageal reflux"], "ans": 2, "exp": "Recurrent wheeze (≥3 episodes) + atopy (eczema, allergic rhinitis) + family history of asthma → เข้าได้กับ 'asthma' มากกว่า single-episode bronchiolitis (ซึ่งเป็น first wheeze ในทารก มัก RSV). ใช้ modified Asthma Predictive Index ประเมิน. Recurrent wheeze ที่มี atopy ตอบสนอง inhaled corticosteroid/bronchodilator ต่างจาก bronchiolitis (supportive)"}, {"topic": "Growth Failure in Chronic Disease", "q": "A child with poorly controlled chronic kidney disease has short stature and poor growth despite adequate calorie intake. Which factors contribute to growth failure in CKD?", "choices": ["Excess growth hormone driving overgrowth", "Hyperthyroidism accelerating the metabolism", "Precocious puberty advancing the bone age", "Acidosis, renal bone disease, anemia, and GH resistance", "Chronic vitamin A toxicity affecting growth"], "ans": 3, "exp": "Growth failure ใน chronic kidney disease เกิดจากหลายปัจจัย: metabolic acidosis, renal osteodystrophy (secondary hyperparathyroidism, vitamin D/calcium/phosphate imbalance), anemia (EPO deficiency), malnutrition, และ growth hormone resistance. การจัดการ: แก้ acidosis, mineral/bone disease, anemia, nutrition และอาจให้ recombinant GH. Chronic disease หลายอย่างทำให้ growth failure"}, {"topic": "Chronic Kidney Disease", "q": "A child with bilateral renal dysplasia has progressively rising creatinine, anemia, poor growth, and bone abnormalities over years. Which is a key management principle in pediatric CKD?", "choices": ["Severely restrict all fluids from the time of diagnosis", "Avoid any dietary modification whatsoever", "Proceed to transplantation without medical management", "Give high-dose vitamin A supplementation", "Manage growth, anemia, bone disease, and blood pressure"], "ans": 4, "exp": "Pediatric CKD (มักจาก congenital anomalies/CAKUT, reflux nephropathy, hereditary): management เน้น slow progression และจัดการภาวะแทรกซ้อน — control BP (ACE inhibitor/ARB, ลด proteinuria), แก้ anemia (EPO/iron), CKD-mineral bone disease (phosphate binder, vitamin D), acidosis, optimize growth/nutrition (+/- GH). Renal replacement (dialysis/transplant) เมื่อ ESRD. Transplant เป็น optimal สำหรับเด็ก"}]}, {"id": "ped-5", "title": "กุมารเวชศาสตร์ ชุดที่ 5 — Neuro/Endocrine/Emergency/Behavioral", "subject": "ped", "questions": [{"topic": "Febrile Seizure - Simple", "q": "An 18-month-old has a single generalized tonic-clonic seizure lasting 2 minutes during a febrile illness (39.5°C from otitis media), returns to normal quickly, and has a normal neurologic exam. What is the most appropriate management?", "choices": ["Identify and treat the source of fever", "Perform an EEG and brain MRI on all", "Start long-term anticonvulsant prophylaxis", "Perform a lumbar puncture on every child", "Admit for prolonged EEG monitoring"], "ans": 0, "exp": "Simple febrile seizure (6 เดือน-5 ปี, generalized, <15 นาที, ครั้งเดียวใน 24 ชม., neuro ปกติ): benign. Management เน้นหา/รักษาสาเหตุไข้ + reassurance. 'ไม่ต้อง' routine EEG/neuroimaging/LP (พิจารณา LP ถ้าสงสัย meningitis หรือเด็กเล็ก/ไม่ได้วัคซีน). ไม่ให้ prophylactic anticonvulsant (ความเสี่ยง > ประโยชน์). Antipyretics ไม่ป้องกัน recurrence"}, {"topic": "Febrile Seizure - Complex", "q": "A 2-year-old has a febrile seizure that is focal (one-sided), lasts 25 minutes, and recurs within the same 24-hour period. How is this classified and what does it imply?", "choices": ["Simple febrile seizure; no concern", "Complex febrile seizure", "Definite epilepsy", "Breath-holding spell", "Absence seizure"], "ans": 1, "exp": "Complex febrile seizure = มีลักษณะใดลักษณะหนึ่ง: focal, prolonged (>15 นาที), หรือ recurrent ภายใน 24 ชม. เพิ่มความเสี่ยง epilepsy เล็กน้อยและอาจต้อง evaluation เพิ่ม (พิจารณา EEG/imaging/LP ตามบริบท). Simple febrile seizure prognosis ดีมาก. Febrile status epilepticus ต้องจัดการ seizure ทันที"}, {"topic": "Absence Seizure", "q": "A 7-year-old is noted by teachers to have frequent brief 'staring spells' with eyelid fluttering lasting a few seconds, with no postictal confusion, occurring many times a day and provoked by hyperventilation. EEG shows 3-Hz spike-and-wave. What is the treatment?", "choices": ["Carbamazepine", "Phenytoin", "Ethosuximide", "Vagal nerve stimulator first-line", "No treatment is ever needed"], "ans": 2, "exp": "Childhood absence epilepsy: brief staring spells (วินาที) + eyelid flutter, ไม่มี postictal, provoked by hyperventilation, EEG '3-Hz generalized spike-and-wave'. รักษาด้วย 'ethosuximide' (first-line สำหรับ absence เดี่ยว) หรือ valproate (ถ้ามี GTC ร่วม). 'หลีกเลี่ยง carbamazepine/phenytoin' (อาจ worsen absence). ส่วนใหญ่ remit ในวัยรุ่น"}, {"topic": "Infantile Spasms", "q": "A 6-month-old has clusters of sudden flexion ('jackknife') spasms of the trunk and limbs, especially on awakening, with developmental regression. EEG shows hypsarrhythmia. What is the diagnosis?", "choices": ["Benign myoclonus", "Absence epilepsy", "Breath-holding spells", "Infantile spasms", "Febrile seizures"], "ans": 3, "exp": "Infantile spasms (West syndrome): clusters ของ flexor/extensor spasms ('jackknife/salaam') ในทารก ~3-12 เดือน + developmental regression + EEG 'hypsarrhythmia'. สาเหตุหลากหลาย (tuberous sclerosis, HIE, metabolic). รักษาด้วย ACTH/corticosteroids หรือ vigabatrin (โดยเฉพาะ tuberous sclerosis). การรักษาเร็วสำคัญต่อ developmental outcome. เป็น epileptic encephalopathy"}, {"topic": "Status Epilepticus", "q": "A child has a generalized tonic-clonic seizure that has continued for more than 5 minutes without stopping. What is the first-line pharmacologic treatment?", "choices": ["Oral phenytoin", "IV phenobarbital as the very first drug", "Wait 30 minutes before any treatment", "IV dextrose only", "A benzodiazepine"], "ans": 4, "exp": "Status epilepticus (seizure ≥5 นาที หรือ seizures ต่อเนื่องไม่ฟื้น): first-line คือ 'benzodiazepine' (IV lorazepam/diazepam, หรือ IM/buccal/intranasal midazolam ถ้าไม่มี IV). ตรวจ/แก้ glucose. ถ้าไม่หยุด → second-line (levetiracetam/fosphenytoin/valproate), แล้ว anesthetic agents. ABC + monitor. Prolonged seizure → neuronal injury"}, {"topic": "Breath-Holding Spell", "q": "A healthy 18-month-old, when upset or frightened, cries then holds his breath, turns blue (or pale), and briefly loses consciousness with some limb stiffening, then recovers fully within a minute. Exam and development are normal. What is the diagnosis?", "choices": ["Breath-holding spell", "Epileptic seizure", "Cardiac arrhythmia", "Vasovagal syncope in an adult pattern", "Hypoglycemia"], "ans": 0, "exp": "Breath-holding spells: benign, ในเด็ก 6 เดือน-5 ปี, trigger ด้วย crying (anger/pain/fright/frustration) → apnea → cyanotic (or pallid) → brief LOC +/- stiffening → ฟื้นเร็ว. Development ปกติ. Benign, หายเองเมื่อโต. ตรวจ 'iron deficiency' (สัมพันธ์และรักษาช่วยลด spell). Reassurance; ไม่ใช่ epilepsy. Pallid type สัมพันธ์กับ vagal-mediated"}, {"topic": "Cerebral Palsy", "q": "A 2-year-old former premature infant has a non-progressive motor disorder with spasticity, increased tone, scissoring of the legs, hyperreflexia, and delayed motor milestones, but no loss of previously acquired skills. What is the diagnosis?", "choices": ["Muscular dystrophy", "Cerebral palsy", "A progressive neurodegenerative disease", "Spinal muscular atrophy", "Guillain-Barre syndrome"], "ans": 1, "exp": "Cerebral palsy: 'non-progressive' motor/posture disorder จาก injury ต่อ developing brain (prematurity, HIE, kernicterus, infection). Spastic type (พบบ่อยสุด): hypertonia, hyperreflexia, scissoring, delayed motor milestones, persistent primitive reflexes. 'Non-progressive' (ไม่มี regression — แยกจาก neurodegenerative). สัมพันธ์กับ epilepsy, intellectual disability, feeding/vision problems. รักษา multidisciplinary (PT/OT, spasticity management)"}, {"topic": "Duchenne - Motor Regression", "q": "A 4-year-old boy with previously normal development now has difficulty climbing stairs, frequent falls, calf hypertrophy, and a positive Gowers sign, with a very high creatine kinase. Which investigation confirms the diagnosis?", "choices": ["A brain MRI to look for a central nervous system lesion", "A nerve conduction study to assess peripheral nerves", "Genetic testing for a dystrophin (DMD) gene mutation", "Thyroid function tests to exclude hypothyroidism", "A lumbar puncture to examine the cerebrospinal fluid"], "ans": 2, "exp": "Duchenne muscular dystrophy: proximal weakness (climbing stairs/getting up), Gowers sign, calf pseudohypertrophy, waddling gait, markedly elevated CK. ยืนยันด้วย 'genetic testing (dystrophin/DMD gene)' หรือ muscle biopsy (absent dystrophin). X-linked recessive. Progressive → wheelchair, cardiomyopathy, respiratory. Corticosteroids ชะลอ progression"}, {"topic": "Type 1 Diabetes - New Onset", "q": "A 9-year-old has a few weeks of polyuria, polydipsia, weight loss, and fatigue. Random glucose is 320 mg/dL with glucosuria and ketonuria but no acidosis or vomiting. What is the diagnosis and initial management?", "choices": ["Type 2 diabetes; start metformin", "Diabetes insipidus; desmopressin", "Urinary tract infection; antibiotics", "New-onset type 1 diabetes mellitus", "Psychogenic polydipsia; fluid restriction"], "ans": 3, "exp": "New-onset type 1 diabetes mellitus (autoimmune beta-cell destruction): polyuria, polydipsia, weight loss, hyperglycemia + glucosuria/ketonuria. เด็กส่วนใหญ่เป็น type 1 (insulin-dependent). รักษาด้วย 'insulin' (basal-bolus) + diabetes education, monitoring, nutrition. ถ้ามี acidosis/vomiting = DKA (emergency). ต่างจาก T2DM (obese, acanthosis, metformin)"}, {"topic": "Diabetic Ketoacidosis", "q": "A child with type 1 diabetes presents with vomiting, abdominal pain, deep rapid (Kussmaul) breathing, dehydration, glucose 450 mg/dL, ketosis, and a high anion gap metabolic acidosis. What is the priority in initial management?", "choices": ["Immediate high-dose IV insulin bolus before any fluids", "Oral hydration and outpatient management", "Rapid correction with bicarbonate for all", "Fluid restriction", "Intravenous fluid resuscitation"], "ans": 4, "exp": "Diabetic ketoacidosis (DKA): hyperglycemia + ketosis + high anion gap metabolic acidosis + dehydration, Kussmaul breathing. Management: 'fluids ก่อน' (careful, ระวัง cerebral edema — ภาวะแทรกซ้อนที่ร้ายแรงในเด็ก), แล้ว 'insulin infusion', ติดตาม/ทดแทน 'potassium' (total body K ต่ำแม้ serum ปกติ/สูง). หลีกเลี่ยง bicarbonate routine และแก้ glucose ช้าๆ. หา precipitant (infection, missed insulin)"}, {"topic": "Congenital Hypothyroidism - Screening", "q": "Why does newborn screening for congenital hypothyroidism (measuring TSH/T4) allow prevention of the most serious outcome?", "choices": ["Early thyroxine prevents irreversible intellectual disability", "It prevents an immediate life-threatening cardiac arrest", "It prevents neonatal seizures caused by hypocalcemia", "It prevents a hemolytic anemia of the newborn", "It cures the underlying thyroid gland dysgenesis"], "ans": 0, "exp": "Congenital hypothyroidism มักไม่มีอาการชัดตอนแรกเกิด แต่ thyroid hormone จำเป็นต่อ CNS development. Newborn screening (TSH/T4) + เริ่ม levothyroxine เร็ว (ก่อน 2-3 สัปดาห์) ป้องกัน 'irreversible intellectual disability' (cretinism). เป็นเหตุผลของ universal screening. ยาไม่ได้รักษา thyroid แต่ทดแทน hormone"}, {"topic": "Acquired Hypothyroidism", "q": "A 10-year-old girl has declining growth velocity, weight gain, constipation, cold intolerance, fatigue, and delayed bone age. TSH is elevated and free T4 is low, with positive anti-thyroid antibodies. What is the most likely cause?", "choices": ["Graves disease", "Hashimoto thyroiditis", "Congenital hypothyroidism", "Iodine excess", "Pituitary tumor"], "ans": 1, "exp": "Acquired hypothyroidism ในเด็ก สาเหตุที่พบบ่อยที่สุดคือ 'Hashimoto (chronic autoimmune) thyroiditis': growth deceleration (เบาะแสสำคัญในเด็ก), weight gain, constipation, cold intolerance, fatigue, delayed bone age/puberty, goiter. High TSH + low free T4 + positive anti-TPO/anti-thyroglobulin antibodies. รักษาด้วย levothyroxine"}, {"topic": "Hyperthyroidism - Graves", "q": "An adolescent has weight loss despite good appetite, palpitations, heat intolerance, tremor, a diffuse goiter with a bruit, and exophthalmos. What is the most likely diagnosis?", "choices": ["Hashimoto thyroiditis", "Toxic adenoma", "Graves disease", "Subacute thyroiditis", "Thyroid cancer"], "ans": 2, "exp": "Graves disease (autoimmune, TSH receptor antibodies): สาเหตุ hyperthyroidism ที่พบบ่อยที่สุดในเด็ก/วัยรุ่น — weight loss + increased appetite, palpitations/tachycardia, heat intolerance, tremor, 'diffuse goiter with bruit', และ 'exophthalmos/ophthalmopathy' (จำเพาะ Graves). Low TSH, high T4/T3, positive TRAb. รักษา: antithyroid (methimazole; ไม่ใช้ PTU ในเด็กยกเว้นบางกรณี), +/- radioiodine/surgery"}, {"topic": "Precocious Puberty Workup", "q": "An 8-year-old girl with breast development and pubic hair and accelerated growth is found to have central precocious puberty. Which investigation is important to exclude an intracranial cause?", "choices": ["Abdominal ultrasound only", "Bone marrow biopsy", "Chest radiograph", "Brain MRI", "Echocardiography"], "ans": 3, "exp": "Central (GnRH-dependent) precocious puberty: activation ของ HPG axis ก่อนวัย (หญิง <8 ปี, ชาย <9 ปี), pubertal LH response, advanced bone age. ในเด็กหญิงส่วนใหญ่ idiopathic แต่ต้อง 'brain MRI' เพื่อ exclude CNS lesion (hamartoma, tumor, hydrocephalus) โดยเฉพาะในเด็กชาย/อายุน้อยมาก. รักษาด้วย GnRH agonist. Peripheral causes มี LH suppressed"}, {"topic": "Rickets - Vitamin D", "q": "A toddler with limited sun exposure and exclusive prolonged breastfeeding without supplementation has bowed legs and delayed walking. Which preventive measure would have avoided this?", "choices": ["Iron supplementation to prevent a nutritional anemia", "Dietary calcium restriction during infancy", "Vitamin A supplementation for the young infant", "Complete avoidance of any sun exposure", "Vitamin D supplementation for the breastfed infant"], "ans": 4, "exp": "Nutritional rickets จาก vitamin D deficiency (breastfed ล้วนโดยไม่เสริม + sun exposure น้อย): bowing legs, delayed motor, metaphyseal changes, high ALP. ป้องกันด้วย 'vitamin D supplementation' ในทารกที่กินนมแม่ล้วน (นมแม่ vitamin D ต่ำ). รักษาด้วย vitamin D + calcium. เป็น preventable disease"}, {"topic": "Congenital Adrenal Hyperplasia - Ambiguous", "q": "A newborn with a 46,XX karyotype has ambiguous (virilized) external genitalia. The most common cause is an enzyme deficiency that also risks a salt-wasting crisis. Which enzyme is deficient?", "choices": ["21-hydroxylase", "11-beta-hydroxylase", "17-alpha-hydroxylase", "5-alpha-reductase", "Aromatase"], "ans": 0, "exp": "Congenital adrenal hyperplasia ที่พบบ่อยที่สุดคือ '21-hydroxylase deficiency': cortisol/aldosterone ต่ำ + androgen สูง → virilization ของ 46,XX (ambiguous genitalia) และเสี่ยง 'salt-wasting crisis' (hyponatremia, hyperkalemia, shock) ในสัปดาห์แรก. Elevated 17-OHP. รักษา: glucocorticoid +/- mineralocorticoid; จัดการ crisis ด้วย saline/dextrose/hydrocortisone. Newborn screening ตรวจได้"}, {"topic": "Child Physical Abuse", "q": "A 4-month-old infant presents with a spiral fracture of the femur, bruises of varying ages, and a history that is inconsistent and keeps changing. The injury pattern does not match the stated mechanism. What is the most appropriate action?", "choices": ["Discharge with reassurance", "Evaluate for non-accidental injury and report to child protection", "Apply a cast and follow up in clinic without further concern", "Assume osteogenesis imperfecta and take no protective action", "Only treat the fracture"], "ans": 1, "exp": "Red flags ของ child physical abuse: injuries ไม่เข้ากับ mechanism/developmental stage (spiral/femur fracture ในทารกที่ยังเดินไม่ได้), bruises หลาย ages, changing/inconsistent history, delayed presentation. ต้องประเมิน non-accidental injury (skeletal survey, fundoscopy, coagulation/imaging เพื่อแยก OI/bleeding), ดูแลความปลอดภัย และ 'report' ตามกฎหมาย. Retinal hemorrhage + subdural = abusive head trauma"}, {"topic": "Abusive Head Trauma", "q": "A previously well 3-month-old presents with lethargy, seizures, and apnea without a history of trauma. Exam reveals retinal hemorrhages and imaging shows subdural hematomas of different ages, with no external signs of injury. What should be strongly suspected?", "choices": ["Benign external hydrocephalus", "Meningitis", "Abusive head trauma", "Metabolic disorder", "Simple febrile seizure"], "ans": 2, "exp": "Abusive head trauma (shaken baby syndrome): triad = subdural hematoma (often ต่าง ages), retinal hemorrhages, และ encephalopathy (lethargy, seizure, apnea) โดยไม่มีประวัติ trauma ที่สมเหตุผล. เป็น inflicted injury ที่ร้ายแรง. ต้องประเมินครบ (imaging, ophthalmology, skeletal survey), ดูแลความปลอดภัย และรายงาน child protection. เป็นสาเหตุสำคัญของ death/disability จาก abuse"}, {"topic": "Acute Poisoning - Paracetamol", "q": "A teenager presents 4 hours after ingesting a large amount of paracetamol (acetaminophen) tablets. She is currently asymptomatic. What is the appropriate management?", "choices": ["Reassure and discharge because she is asymptomatic now", "Induce vomiting with ipecac to empty the stomach", "Give activated charcoal alone and then discharge", "Measure the paracetamol level and give N-acetylcysteine", "Wait for signs of liver failure before starting treatment"], "ans": 3, "exp": "Paracetamol (acetaminophen) overdose: มัก asymptomatic ในระยะแรก (24 ชม.) แต่เสี่ยง hepatotoxicity ตามมา. Measure 'paracetamol level' ที่ ≥4 ชม.หลังกิน แล้วเทียบ 'Rumack-Matthew nomogram' → ให้ 'N-acetylcysteine' (antidote, ป้องกัน hepatic injury, ได้ผลดีถ้าให้ <8-10 ชม.). อย่ารอให้เกิด liver failure. Activated charcoal ถ้ามาเร็ว (<1-2 ชม.)"}, {"topic": "Acute Poisoning - Organophosphate", "q": "A child from a farm presents with excessive salivation, lacrimation, urination, defecation, miosis, bradycardia, muscle fasciculations, and difficulty breathing after pesticide exposure. What is the antidote?", "choices": ["Naloxone to reverse opioid respiratory depression", "Flumazenil to reverse benzodiazepine sedation", "N-acetylcysteine for paracetamol hepatotoxicity", "Deferoxamine to chelate a toxic iron ingestion", "Atropine together with pralidoxime for the toxidrome"], "ans": 4, "exp": "Organophosphate (pesticide) poisoning: acetylcholinesterase inhibition → cholinergic crisis 'SLUDGE/DUMBELS' (salivation, lacrimation, urination, defecation, GI, emesis; miosis, bradycardia, bronchorrhea, fasciculations, weakness). รักษา: decontamination + 'atropine' (antagonize muscarinic — titrate to secretions) + 'pralidoxime' (reactivate cholinesterase, ช่วย nicotinic/muscle) + airway support. พบในเกษตรกรรม/ไทย"}, {"topic": "Iron Poisoning", "q": "A toddler ingests a bottle of adult iron (ferrous sulfate) tablets. After initial vomiting and abdominal pain (some with hematemesis), which antidote is used for severe iron poisoning?", "choices": ["Deferoxamine", "N-acetylcysteine", "Atropine", "Naloxone", "Activated charcoal (which binds iron effectively)"], "ans": 0, "exp": "Iron poisoning: stages — GI toxicity (vomiting, hematemesis, abdominal pain), latent, shock/metabolic acidosis, hepatic failure, late stricture. 'Activated charcoal ไม่จับ iron'. Severe/symptomatic → 'deferoxamine' (iron chelation). ประเมิน serum iron, abdominal X-ray (radio-opaque tablets), supportive/fluids. เป็นสาเหตุสำคัญของ pediatric poisoning fatality — เก็บยาให้พ้นมือเด็ก"}, {"topic": "Anaphylaxis", "q": "A child develops hives, facial/lip swelling, wheezing, vomiting, and hypotension within minutes of eating peanuts. What is the first-line treatment?", "choices": ["Intravenous antihistamine alone", "Intramuscular adrenaline", "Oral corticosteroid alone", "Nebulized salbutamol only", "Observation and reassurance"], "ans": 1, "exp": "Anaphylaxis (multi-system: skin + respiratory/CV/GI ภายในนาที-ชั่วโมงหลัง allergen): first-line และ life-saving คือ 'IM adrenaline (epinephrine)' ที่ต้นขา (repeat q5-15 นาทีตามต้องการ) + จัดท่านอน + O2/fluids. Antihistamine/steroid เป็น 'adjunct' ไม่ใช่ first-line. สังเกต biphasic reaction. สั่ง epinephrine auto-injector + หลีกเลี่ยง allergen"}, {"topic": "Food Allergy", "q": "A young child develops urticaria and vomiting within 30 minutes of eating egg, reproducibly. Skin prick and specific IgE tests are positive. What is the cornerstone of management?", "choices": ["Daily antihistamines to allow continued egg consumption", "Unsupervised food desensitization carried out at home", "Strict allergen avoidance with an adrenaline auto-injector", "Daily oral corticosteroids to suppress reactions", "No particular precautions are necessary at all"], "ans": 2, "exp": "IgE-mediated food allergy (egg, milk, peanut, seafood): rapid urticaria/angioedema/vomiting/anaphylaxis. Management: 'strict allergen avoidance' + emergency plan ด้วย 'adrenaline auto-injector' + antihistamine สำหรับ mild. อ่านฉลากอาหาร, educate. Oral immunotherapy ทำภายใต้ผู้เชี่ยวชาญเท่านั้น. Milk/egg allergy หลายรายหายเมื่อโต; peanut/seafood มัก persistent"}, {"topic": "Atopic Dermatitis", "q": "An infant has chronic, intensely itchy, dry, erythematous, scaly lesions on the cheeks and extensor surfaces, later involving flexural areas, with a family history of asthma and allergic rhinitis. What is the mainstay of management?", "choices": ["Systemic antibiotics prescribed for every affected child", "Long-term oral corticosteroids to control the disease", "Complete avoidance of bathing to protect the skin", "Regular emollients with topical steroids for flares", "Topical antifungal creams applied to the lesions"], "ans": 3, "exp": "Atopic dermatitis (eczema): chronic pruritic, dry, erythematous/scaly lesions — infant (cheeks/extensor) → เด็กโต (flexural), ส่วนหนึ่งของ 'atopic march' (eczema → asthma → allergic rhinitis). Mainstay: 'liberal emollients/moisturizers' + topical corticosteroids (หรือ calcineurin inhibitors) สำหรับ flares + หลีกเลี่ยง triggers + จัดการ pruritus. Secondary infection (S. aureus, eczema herpeticum) ต้องรักษา"}, {"topic": "Migraine", "q": "A 12-year-old has recurrent episodes of throbbing, often unilateral headache with nausea, photophobia, and phonophobia, relieved by sleep, sometimes preceded by visual aura. There is a family history. Exam is normal between episodes. What is the diagnosis?", "choices": ["Brain tumor", "Tension-type headache", "Idiopathic intracranial hypertension", "Meningitis", "Migraine"], "ans": 4, "exp": "Pediatric migraine: recurrent throbbing headache (อาจ bilateral ในเด็ก), nausea/vomiting, photophobia/phonophobia, relieved by sleep, +/- aura, family history, normal exam. รักษา: acute (NSAIDs, triptans, hydration, rest) + trigger avoidance; prophylaxis ถ้าบ่อย (topiramate, propranolol, amitriptyline). Red flags ที่บ่งชี้ secondary (tumor): morning headache/vomiting, worse ตอนนอน, neuro signs, ตื่นกลางคืน"}, {"topic": "Brain Tumor Red Flags", "q": "A 7-year-old has morning headaches with vomiting, worsening over weeks, plus new ataxia, and papilledema on exam. What is the most appropriate next step?", "choices": ["Neuroimaging to evaluate for a posterior fossa tumor", "Reassurance with simple oral analgesics for the pain", "Starting long-term migraine prophylactic medication", "Psychological counseling alone without imaging", "Lumbar puncture performed first, before any imaging"], "ans": 0, "exp": "Red flags ของ raised ICP/brain tumor ในเด็ก: 'morning' headache + vomiting, progressive/worsening, ตื่นกลางดึกจากปวดหัว, neuro signs (ataxia, cranial nerve palsy), papilledema, personality/growth change. Posterior fossa tumors (medulloblastoma, astrocytoma, ependymoma) พบบ่อยในเด็ก → cerebellar signs + hydrocephalus. ต้อง 'neuroimaging'. 'ห้าม LP ก่อน imaging' ถ้าสงสัย raised ICP (เสี่ยง herniation)"}, {"topic": "Hydrocephalus", "q": "An infant has a rapidly increasing head circumference, bulging fontanelle, 'sunset sign' of the eyes, and prominent scalp veins. Imaging shows dilated ventricles. What is the definitive treatment for obstructive hydrocephalus?", "choices": ["Diuretics as definitive therapy", "Ventriculoperitoneal shunt", "Repeated lumbar punctures indefinitely", "Observation only", "Corticosteroids"], "ans": 1, "exp": "Hydrocephalus: CSF สะสม → ventricular dilatation + raised ICP. ในทารก (fontanelle เปิด): macrocephaly, bulging fontanelle, sunset eyes, scalp vein prominence, irritability/vomiting. Definitive treatment คือ CSF diversion — 'ventriculoperitoneal (VP) shunt' หรือ endoscopic third ventriculostomy (สำหรับ obstructive). หาสาเหตุ (aqueductal stenosis, tumor, post-hemorrhage/infection). Diuretics ไม่ใช่ definitive"}, {"topic": "Neural Tube Defect - Spina Bifida", "q": "A newborn is born with a midline lumbosacral sac containing neural tissue, with lower limb weakness and neurogenic bladder. What is this open neural tube defect and how could it have been reduced?", "choices": ["Simple sacral dimple; no prevention possible", "Meningocele without neural involvement; caused by trauma", "Myelomeningocele; periconceptional maternal folic acid reduces the risk", "Encephalocele; caused by hypoxia", "Diastematomyelia; caused by infection"], "ans": 2, "exp": "Myelomeningocele (open spina bifida): herniation ของ meninges + neural tissue → motor/sensory deficits, neurogenic bladder/bowel, +/- hydrocephalus (Chiari II). ป้องกันด้วย 'periconceptional folic acid'. Management: cover defect, ผ่าตัดปิด (หรือ fetal surgery), จัดการ hydrocephalus/bladder, multidisciplinary. ต่างจาก meningocele (ไม่มี neural tissue) และ spina bifida occulta (hidden, sacral dimple/hair tuft)"}, {"topic": "Guillain-Barre Syndrome", "q": "A child develops progressive, symmetric ascending weakness starting in the legs with loss of deep tendon reflexes, about 2 weeks after a diarrheal or respiratory illness. CSF shows elevated protein with normal cell count. What is the diagnosis?", "choices": ["Poliomyelitis", "Transverse myelitis", "Botulism", "Guillain-Barre syndrome", "Myasthenia gravis"], "ans": 3, "exp": "Guillain-Barre syndrome (acute inflammatory demyelinating polyneuropathy): 'ascending' symmetric weakness + areflexia หลัง infection (Campylobacter, viral). CSF: 'albuminocytologic dissociation' (protein สูง, cell ปกติ). เฝ้าระวัง 'respiratory failure' (monitor vital capacity) และ autonomic instability. รักษาด้วย IVIG หรือ plasmapheresis + supportive. ต่างจาก botulism (descending) และ tick paralysis"}, {"topic": "HSV Encephalitis", "q": "A child has fever, altered mental status, focal seizures, and behavioral changes. MRI shows temporal lobe involvement and CSF shows lymphocytic pleocytosis. What is the most important treatment to start empirically?", "choices": ["Ceftriaxone alone", "Oseltamivir", "Supportive care while awaiting PCR", "Corticosteroids alone", "Intravenous acyclovir"], "ans": 4, "exp": "Herpes simplex encephalitis: fever + encephalopathy + focal (temporal) signs/seizures + behavioral change; MRI 'temporal lobe' involvement; CSF lymphocytic pleocytosis, HSV PCR positive. ต้องเริ่ม 'IV acyclovir' empirically ทันทีเมื่อสงสัย (ก่อนผล PCR) เพราะ delay เพิ่ม mortality/morbidity. เป็น treatable cause ของ encephalitis ที่ต้องคิดถึงเสมอ"}, {"topic": "Ataxia - Acute Cerebellar", "q": "A 3-year-old, about 1-2 weeks after having chickenpox, develops sudden difficulty walking with a wide-based unsteady gait and truncal instability, but is alert and afebrile with no other neurologic deficit. What is the most likely diagnosis?", "choices": ["Acute post-infectious cerebellar ataxia", "Posterior fossa brain tumor", "Guillain-Barre syndrome", "Bacterial meningitis", "Ingestion/intoxication"], "ans": 0, "exp": "Acute post-infectious cerebellar ataxia: สาเหตุที่พบบ่อยที่สุดของ acute ataxia ในเด็กเล็ก, มักหลัง varicella หรือ viral infection (1-3 สัปดาห์) — sudden gait/truncal ataxia, alert, ไม่มี neuro deficit อื่น. Benign, self-limited (สัปดาห์-เดือน). ต้องแยกจาก posterior fossa tumor (progressive + raised ICP), intoxication (drugs/alcohol), GBS, opsoclonus-myoclonus (neuroblastoma)"}, {"topic": "Tourette Syndrome", "q": "A 9-year-old boy has multiple motor tics (blinking, head jerking) and vocal tics (throat clearing, grunting) that have persisted for over a year, waxing and waning, and are worse with stress. What is the diagnosis?", "choices": ["Absence seizures", "Tourette syndrome", "Obsessive-compulsive disorder alone", "Myoclonic epilepsy", "Chorea"], "ans": 1, "exp": "Tourette syndrome: 'multiple motor + ≥1 vocal tics' >1 ปี, onset ก่อน 18 ปี, waxing/waning, worse ด้วย stress, suppressible ชั่วคราว. สัมพันธ์กับ ADHD และ OCD. รักษาเมื่อ tics รบกวน: behavioral therapy (habit reversal), +/- alpha-agonists (clonidine/guanfacine) หรือ antipsychotics. ต่างจาก seizure (ไม่ suppressible, มี EEG change)"}, {"topic": "ADHD", "q": "An 8-year-old has persistent inattention, hyperactivity, and impulsivity present in both school and home for over 6 months, impairing function, and not explained by another disorder. What is a recognized first-line treatment for school-aged children?", "choices": ["Antipsychotics", "Benzodiazepines", "Stimulant medication with behavioral therapy", "Restriction of all screen time as sole treatment", "No treatment is effective"], "ans": 2, "exp": "Attention-deficit/hyperactivity disorder (ADHD): inattention +/- hyperactivity-impulsivity, ≥6 เดือน, 'หลาย settings' (บ้าน+โรงเรียน), เริ่มก่อน 12 ปี, impair function. รักษาในเด็กวัยเรียน: 'stimulants' (methylphenidate/amphetamine) มีประสิทธิภาพสูง + behavioral therapy/school support. เด็กก่อนวัยเรียนเริ่มด้วย behavioral therapy. Non-stimulant (atomoxetine) เป็น alternative"}, {"topic": "Nocturnal Enuresis", "q": "A healthy 6-year-old wets the bed at night but has never been consistently dry at night, with normal daytime voiding and a normal exam. What is the most appropriate initial approach?", "choices": ["Immediate desmopressin for all", "Urologic surgery", "Punishment for wet nights", "Reassurance and behavioral measures", "Extensive imaging workup"], "ans": 3, "exp": "Primary monosymptomatic nocturnal enuresis (ไม่เคยแห้งกลางคืน, daytime ปกติ, exam ปกติ): common, mostly matures/resolves. Initial: reassurance + behavioral (fluid restriction ตอนเย็น, void ก่อนนอน, positive reinforcement, 'enuresis alarm' — first-line ที่ได้ผลถาวรสุด). Desmopressin ช่วยชั่วคราว (เช่น ค้างคืน/แคมป์). หลีกเลี่ยงการลงโทษ. Secondary/daytime symptoms ต้อง workup (UTI, DM, constipation)"}, {"topic": "Adolescent Depression / Suicide", "q": "A 15-year-old presents with 2 months of depressed mood, anhedonia, sleep and appetite changes, and hopelessness, and admits to thoughts of self-harm. What is the most important immediate assessment?", "choices": ["Prescribe an antidepressant and discharge without further assessment", "Reassure that it is a normal teenage phase", "Recommend more exercise only", "Avoid discussing suicide to prevent giving ideas", "Assess suicide risk/safety directly and ensure safety"], "ans": 4, "exp": "Adolescent depression with self-harm thoughts: การประเมินที่สำคัญที่สุดทันทีคือ 'ประเมิน suicide risk/safety โดยตรง' (ถามเรื่อง suicidal ideation ไม่เพิ่มความเสี่ยง — เป็น myth) และจัดการความปลอดภัย (remove means, supervision, referral). แล้วจึงวางแผนรักษา (psychotherapy เช่น CBT +/- SSRI ที่ต้อง monitor). ครอบครัวและ mental health support สำคัญ (สื่อสารด้วยความห่วงใย). *หัวข้อนี้เป็นเรื่องละเอียดอ่อน หากมีความเสี่ยงจริง ควรปรึกษาผู้เชี่ยวชาญ/สายด่วนสุขภาพจิต"}, {"topic": "Anorexia Nervosa", "q": "A 15-year-old girl has significant weight loss with a low BMI, intense fear of gaining weight, a distorted body image, restrictive eating and excessive exercise, and amenorrhea, with bradycardia and hypotension. What is the diagnosis?", "choices": ["Anorexia nervosa", "Bulimia nervosa", "Hyperthyroidism", "Inflammatory bowel disease", "Type 1 diabetes"], "ans": 0, "exp": "Anorexia nervosa: restriction → significantly low body weight, intense fear ของการอ้วน, distorted body image. Medical complications: bradycardia, hypotension, hypothermia, amenorrhea, electrolyte disturbance, osteoporosis. เฝ้าระวัง 'refeeding syndrome' ระหว่างฟื้นฟู. รักษา multidisciplinary (medical stabilization, nutrition, psychotherapy/family-based). *เป็นภาวะที่มี mortality สูง ควรดูแลโดยทีมเฉพาะทาง"}, {"topic": "Adolescent Confidentiality", "q": "A 16-year-old requests contraception and asks that her parents not be informed. Regarding confidential care for adolescents, what is generally the appropriate approach?", "choices": ["Always informing the parents of everything without exception", "Confidential care with encouragement of family communication", "Refusing to discuss any sensitive topics with a minor", "Never involving the parents under any circumstances", "Reporting the adolescent to the relevant authorities"], "ans": 1, "exp": "Adolescent care: การให้ 'confidential care' สำหรับ sensitive issues (contraception, sexual health, mental health, substance use) ช่วยให้วัยรุ่นเข้าถึงบริการ, พร้อมส่งเสริมการสื่อสารกับครอบครัว. ข้อจำกัด: safety concerns (suicidal/homicidal, abuse) ต้อง break confidentiality เพื่อความปลอดภัย. ใช้ HEEADSSS assessment. กฎหมาย/บริบทท้องถิ่นกำหนดขอบเขต. สร้าง trust และ non-judgmental"}, {"topic": "SCID", "q": "An infant presents with recurrent severe infections (including opportunistic/fungal), chronic diarrhea, failure to thrive, and absent tonsils/lymph nodes, starting in the first months of life. Lymphopenia is present. What is the diagnosis?", "choices": ["Selective IgA deficiency", "Chronic granulomatous disease", "Severe combined immunodeficiency", "Physiologic hypogammaglobulinemia of infancy", "Cystic fibrosis"], "ans": 2, "exp": "Severe combined immunodeficiency (SCID): defect ทั้ง T และ B cell function → recurrent severe/opportunistic infections (PCP, candida, viral), chronic diarrhea, FTT ตั้งแต่เดือนแรกๆ, absent lymphoid tissue, lymphopenia. 'ห้าม live vaccines และต้อง irradiated/CMV-negative blood'. เป็น pediatric emergency — HSCT curative. Newborn screening (TREC) ตรวจได้. 'Bubble boy'"}, {"topic": "X-linked Agammaglobulinemia", "q": "A boy develops recurrent bacterial infections (otitis, sinusitis, pneumonia with encapsulated organisms) after about 6 months of age, with very low immunoglobulins and absent B cells but normal T cells. What is the diagnosis?", "choices": ["Severe combined immunodeficiency", "DiGeorge syndrome", "Chronic granulomatous disease", "X-linked agammaglobulinemia", "Complement deficiency"], "ans": 3, "exp": "X-linked (Bruton) agammaglobulinemia (BTK mutation): B-cell maturation ล้มเหลว → 'absent B cells', low all immunoglobulins, but T cells ปกติ. Recurrent 'encapsulated' bacterial infections (S. pneumoniae, H. influenzae) เริ่มหลัง ~6 เดือน (เมื่อ maternal IgG หมด). รักษาด้วย IVIG replacement + prompt antibiotics. เพศชาย. ต่างจาก SCID (T+B affected, opportunistic, เร็วกว่า)"}, {"topic": "Chronic Granulomatous Disease", "q": "A child has recurrent infections with catalase-positive organisms (e.g., Staphylococcus aureus, Serratia, Aspergillus) forming abscesses and granulomas. The neutrophil oxidative burst (DHR/NBT) test is abnormal. What is the diagnosis?", "choices": ["Chediak-Higashi syndrome", "Leukocyte adhesion deficiency", "Severe combined immunodeficiency", "Complement C5 deficiency", "Chronic granulomatous disease"], "ans": 4, "exp": "Chronic granulomatous disease (CGD): defect ใน NADPH oxidase → neutrophils phagocytose ได้แต่ 'kill ไม่ได้' → recurrent infections โดย 'catalase-positive' organisms (S. aureus, Serratia, Burkholderia, Nocardia, Aspergillus), abscesses/granulomas. วินิจฉัยด้วย DHR/NBT test (abnormal oxidative burst). รักษา: prophylaxis (cotrimoxazole + antifungal + IFN-gamma), HSCT curative"}, {"topic": "Ketotic Hypoglycemia", "q": "A thin 2-year-old, after an overnight fast or intercurrent illness with poor intake, develops early morning lethargy, pallor, and a seizure; glucose is low with ketonuria, and the child recovers with glucose. This resolves with age. What is the most likely diagnosis?", "choices": ["Ketotic hypoglycemia of childhood", "Congenital hyperinsulinism", "Type 1 diabetes", "Adrenal insufficiency", "Glycogen storage disease type I"], "ans": 0, "exp": "Ketotic hypoglycemia: สาเหตุที่พบบ่อยที่สุดของ hypoglycemia ในเด็กเล็ก (1-5 ปี) — เกิดเมื่อ fasting/illness (limited glycogen/gluconeogenic substrate), hypoglycemia + 'ketosis' (appropriate ketone response). รักษา/ป้องกัน: หลีกเลี่ยง prolonged fasting, ให้ carbohydrate ระหว่างป่วย. หายเมื่อโตขึ้น. ต่างจาก hyperinsulinism (ketone ต่ำ, insulin สูง) — ต้องแยก"}, {"topic": "Congenital Hyperinsulinism", "q": "A neonate/infant has recurrent severe hypoglycemia requiring high glucose infusion rates, with inappropriately LOW ketones and detectable insulin during hypoglycemia. What is the mechanism?", "choices": ["Ketotic hypoglycemia", "Congenital hyperinsulinism", "Growth hormone deficiency", "Glycogen storage disease", "Galactosemia"], "ans": 1, "exp": "Congenital hyperinsulinism: dysregulated insulin secretion → recurrent severe hypoglycemia, ต้องการ 'high glucose infusion rate', 'low ketones/free fatty acids' (insulin ยับยั้ง ketogenesis/lipolysis), detectable insulin ขณะ hypoglycemia. รักษา: frequent feeds, diazoxide, octreotide, +/- surgery (focal lesion). ต่างจาก ketotic hypoglycemia (ketone สูง). ต้องรักษาเร็วป้องกัน brain injury"}, {"topic": "Adrenal Insufficiency / Crisis", "q": "A child with known adrenal insufficiency develops vomiting, weakness, and hypotension during an intercurrent febrile illness. Labs show hyponatremia, hyperkalemia, and hypoglycemia. What is the immediate treatment?", "choices": ["An insulin infusion to lower the blood glucose", "Potassium supplementation to correct the levels", "Intravenous hydrocortisone together with fluid resuscitation", "Oral prednisolone with discharge home", "Fluid restriction to manage the hyponatremia"], "ans": 2, "exp": "Adrenal (Addisonian) crisis: cortisol deficiency + stress (illness) → vomiting, weakness, shock, hyponatremia, hyperkalemia, hypoglycemia. Immediate: 'IV hydrocortisone (stress dose)' + IV normal saline + dextrose (แก้ hypoglycemia). แก้ hyperkalemia จะดีขึ้นตาม. ผู้ป่วย chronic ต้อง 'stress dosing' ระหว่างป่วย/ผ่าตัด + emergency plan. สาเหตุ: autoimmune, CAH, adrenoleukodystrophy, withdrawal ของ steroid"}, {"topic": "Cushing Syndrome", "q": "A child has weight gain with central obesity, growth failure (declining height velocity with rising weight), a round 'moon' face, purple striae, hypertension, and hirsutism. What is the most common cause in children?", "choices": ["Adrenal carcinoma", "Pituitary adenoma (Cushing disease) only", "Ectopic ACTH", "Exogenous corticosteroid use", "Congenital adrenal hyperplasia"], "ans": 3, "exp": "Cushing syndrome ในเด็ก: การรวมกันของ 'weight gain + growth failure' (short and fat) เป็นเบาะแสสำคัญ (ต่างจาก obesity ทั่วไปที่สูงปกติ/เร็ว), moon face, striae, HT, hirsutism. สาเหตุที่พบบ่อยที่สุดคือ 'exogenous/iatrogenic corticosteroids'. Endogenous: Cushing disease (pituitary ACTH), adrenal tumor. ประเมิน cortisol (24-hr urine, dexamethasone suppression)"}, {"topic": "Central Diabetes Insipidus", "q": "A child develops polyuria and polydipsia with dilute urine (low specific gravity) and a tendency to hypernatremia. A water deprivation test shows the urine concentrates after administration of desmopressin. What is the diagnosis?", "choices": ["Nephrogenic diabetes insipidus", "Type 1 diabetes mellitus", "Primary polydipsia", "SIADH", "Central diabetes insipidus"], "ans": 4, "exp": "Central diabetes insipidus: ADH (vasopressin) deficiency → polyuria (dilute urine) + polydipsia + เสี่ยง hypernatremia. Water deprivation test: urine ไม่ concentrate จน 'ให้ desmopressin แล้ว concentrate' (แยกจาก nephrogenic DI ที่ไม่ตอบสนอง desmopressin). สาเหตุ: tumor (craniopharyngioma), trauma, surgery, infiltration (LCH). รักษาด้วย desmopressin. ต่างจาก DM (glucose) และ SIADH (concentrated urine, hyponatremia)"}, {"topic": "SIADH", "q": "A child with bacterial meningitis develops hyponatremia with concentrated urine (high urine osmolality and sodium), low serum osmolality, and euvolemia without edema. What is the diagnosis and initial management?", "choices": ["SIADH; fluid restriction", "Diabetes insipidus; desmopressin", "Dehydration; aggressive fluids", "Adrenal insufficiency; hydrocortisone", "Cerebral salt wasting; fluid restriction"], "ans": 0, "exp": "SIADH (syndrome of inappropriate ADH): พบใน CNS disease (meningitis, trauma), pulmonary disease, drugs → water retention → hyponatremia + 'inappropriately concentrated urine' (urine osm/Na สูง) + low serum osm + euvolemia. รักษา: 'fluid restriction' (hypertonic saline ถ้า severe/seizing). ต่างจาก cerebral salt wasting (hypovolemic, ต้องให้ salt/fluid) — การประเมิน volume status สำคัญ"}, {"topic": "Hypocalcemia - Tetany", "q": "A child presents with carpopedal spasm, perioral numbness, and a positive Chvostek and Trousseau sign, with a seizure. Serum calcium is low. What is the immediate treatment for symptomatic hypocalcemia?", "choices": ["Oral vitamin D alone", "Intravenous calcium gluconate", "Intravenous magnesium only", "Phosphate supplementation", "Observation"], "ans": 1, "exp": "Symptomatic hypocalcemia (tetany): carpopedal spasm, perioral/peripheral paresthesia, Chvostek/Trousseau signs, laryngospasm, seizure. 'IV calcium gluconate' สำหรับ symptomatic/severe (with cardiac monitoring). หาสาเหตุ: hypoparathyroidism (DiGeorge), vitamin D deficiency, hypomagnesemia (ต้องแก้ Mg ด้วยถ้าต่ำ), renal disease. Long-term: calcium + vitamin D ตามสาเหตุ"}, {"topic": "Spinal Muscular Atrophy", "q": "A 3-month-old has severe hypotonia ('floppy baby'), symmetric proximal weakness, absent deep tendon reflexes, tongue fasciculations, and preserved alertness/social interaction, with a normal sensory exam. What is the most likely diagnosis?", "choices": ["Cerebral palsy", "Guillain-Barre syndrome", "Spinal muscular atrophy", "Duchenne muscular dystrophy", "Myasthenia gravis"], "ans": 2, "exp": "Spinal muscular atrophy type 1 (Werdnig-Hoffmann, SMN1 deletion, autosomal recessive): progressive 'lower motor neuron' degeneration → severe hypotonia/floppy, proximal weakness, areflexia, tongue fasciculations, 'bright alert face' (cognition ปกติ), bell-shaped chest/paradoxical breathing. Sensory ปกติ. เดิม fatal ในทารก แต่ปัจจุบันมี disease-modifying therapy (nusinersen, gene therapy). Newborn screening"}, {"topic": "Juvenile Myasthenia Gravis", "q": "An adolescent has fluctuating weakness that worsens with activity and improves with rest, with ptosis and diplopia worse in the evening, and difficulty chewing/swallowing. What is the underlying mechanism?", "choices": ["Demyelination of the peripheral motor and sensory nerves", "Degeneration of the anterior horn motor neurons", "Deficiency of dystrophin in the muscle membrane", "Autoantibodies against the acetylcholine receptor at the junction", "Injury to the upper motor neurons of the brain"], "ans": 3, "exp": "Juvenile myasthenia gravis: autoantibodies ต่อ 'acetylcholine receptor' (postsynaptic NMJ) → 'fatigable' weakness (worse ด้วย activity/ตอนเย็น, ดีขึ้นด้วย rest), ptosis, diplopia, bulbar/proximal weakness. วินิจฉัย: anti-AChR antibody, repetitive nerve stimulation, edrophonium test. รักษา: acetylcholinesterase inhibitor (pyridostigmine), immunosuppression, thymectomy. เฝ้าระวัง myasthenic crisis (respiratory)"}, {"topic": "Sydenham Chorea", "q": "A child, weeks to months after a streptococcal infection, develops involuntary, non-rhythmic, purposeless movements of the limbs and face, emotional lability, and muscle weakness. What is this a manifestation of?", "choices": ["Tourette syndrome", "Cerebral palsy", "Wilson disease", "Huntington disease", "Acute rheumatic fever"], "ans": 4, "exp": "Sydenham chorea (St. Vitus dance): late neurologic manifestation ของ 'acute rheumatic fever' (major Jones criterion), เกิดสัปดาห์-เดือนหลัง strep — chorea (involuntary, non-rhythmic movements), emotional lability, hypotonia/weakness ('milkmaid grip'). Self-limited (สัปดาห์-เดือน). ต้องให้ secondary penicillin prophylaxis เหมือน ARF อื่น. อาจสัมพันธ์ carditis"}, {"topic": "Burns - Fluid Resuscitation", "q": "A child sustains partial and full-thickness burns over an estimated 30% of total body surface area. What is the principle of initial fluid management?", "choices": ["Calculate resuscitation from burn area and weight, plus maintenance", "Restrict fluids in order to avoid tissue edema", "Give a single small bolus and then simply observe", "Give only oral fluids regardless of the burn size", "Use diuretics to prevent any fluid overload"], "ans": 0, "exp": "Major burns (>10-15% TBSA ในเด็ก) → large fluid losses → ต้อง IV fluid resuscitation คำนวณจาก %TBSA + weight (Parkland: 4 mL x kg x %TBSA ของ Ringer's lactate, ครึ่งแรกใน 8 ชม.แรก) 'บวก maintenance fluid ในเด็ก' (ต่างจากผู้ใหญ่). Titrate ตาม urine output. ประเมิน airway (inhalation injury), analgesia, wound care. ในเด็กใช้ %TBSA chart ที่ปรับตามสัดส่วนศีรษะ/ขาที่ต่างจากผู้ใหญ่"}, {"topic": "Drowning", "q": "A child is rescued from a swimming pool after a submersion event and is apneic. What is the single most important initial intervention in drowning resuscitation?", "choices": ["Abdominal thrusts to expel water first", "Rescue breaths/ventilation as the priority", "Chest compressions only", "Warming before any ventilation", "Withhold CPR until hospital arrival"], "ans": 1, "exp": "Drowning: hypoxia เป็นปัญหาหลัก → priority คือ 'ventilation/rescue breaths' (airway-breathing) เริ่มเร็วที่สุด (แม้ตอนอยู่ในน้ำถ้าปลอดภัย), แล้ว CPR ตามมาตรฐาน. 'ไม่' เสียเวลาพยายามเอาน้ำออก/abdominal thrust (ไม่ช่วยและ delay). เฝ้าระวัง delayed respiratory deterioration, hypothermia, และ observe. Prevention (supervision, fencing) สำคัญที่สุด"}, {"topic": "Snakebite", "q": "A child in rural Thailand is bitten by a snake and develops progressive local swelling, bleeding from the bite site, prolonged clotting (coagulopathy), and hematuria. Which management is appropriate?", "choices": ["Apply a tight arterial tourniquet and incise the wound", "Attempt to suck the venom out of the bite site", "Immobilize the limb and give antivenom for envenomation", "Apply ice and aggressively elevate the limb", "Give antivenom to everyone bitten regardless of signs"], "ans": 2, "exp": "Snakebite (ไทย: hematotoxic — Russell's viper, green pit viper, Malayan pit viper → bleeding/coagulopathy; neurotoxic — cobra, krait → paralysis): first aid = ทำให้สงบ, immobilize limb, pressure immobilization (บาง neurotoxic), รีบส่ง รพ. 'หลีกเลี่ยง' tourniquet แน่น/กรีด/ดูดพิษ/ice (harmful). ให้ 'antivenom' เมื่อมี systemic envenomation (coagulopathy, neurotoxicity, significant local). Monitor 20-min whole blood clotting test สำหรับ hematotoxic"}, {"topic": "Opioid Overdose", "q": "An adolescent is found with pinpoint pupils, respiratory depression (slow shallow breathing), and decreased consciousness after suspected opioid use. What is the antidote?", "choices": ["Flumazenil", "Atropine", "N-acetylcysteine", "Naloxone", "Physostigmine"], "ans": 3, "exp": "Opioid toxidrome: 'pinpoint pupils (miosis) + respiratory depression + CNS depression'. Antidote คือ 'naloxone' (opioid antagonist, ให้ IV/IM/intranasal, titrate to respiration). สำคัญคือ support ventilation (airway/breathing). ระวัง re-sedation (naloxone half-life สั้นกว่า opioid บางชนิด) → observe/repeat. Flumazenil = benzodiazepine antidote (ใช้ระวัง)"}, {"topic": "Salicylate Poisoning", "q": "A child who ingested aspirin presents with tachypnea/hyperventilation, tinnitus, vomiting, fever, and a mixed respiratory alkalosis with high anion gap metabolic acidosis. What is a key treatment?", "choices": ["Naloxone to reverse an opioid intoxication", "N-acetylcysteine for paracetamol poisoning", "Atropine with pralidoxime for organophosphates", "Deferoxamine to chelate a toxic iron overdose", "Urine alkalinization using intravenous sodium bicarbonate"], "ans": 4, "exp": "Salicylate (aspirin) poisoning: stimulate respiratory center (respiratory alkalosis) + uncouple oxidative phosphorylation (high anion gap metabolic acidosis) → 'mixed acid-base', tinnitus, hyperthermia, vomiting. รักษา: 'urine alkalinization ด้วย sodium bicarbonate' (เพิ่ม excretion + ลด CNS penetration), fluids, glucose, hemodialysis ในรายรุนแรง. (Aspirin หลีกเลี่ยงในเด็ก — Reye syndrome ด้วย)"}, {"topic": "Carbon Monoxide Poisoning", "q": "A family presents with headache, nausea, dizziness, and confusion after using a charcoal heater in an enclosed room. Pulse oximetry reads normal despite symptoms. What is the treatment?", "choices": ["High-flow 100% oxygen", "Naloxone", "Activated charcoal", "Methylene blue", "Deferoxamine"], "ans": 0, "exp": "Carbon monoxide poisoning: CO จับ hemoglobin (carboxyhemoglobin) แน่นกว่า O2 → tissue hypoxia. อาการ: headache, nausea, dizziness, confusion, +/- coma; 'pulse ox อาจปกติ' (วัด COHb ไม่ได้ — ต้อง co-oximetry). แหล่ง: charcoal/generator ในที่อับ, ไฟไหม้. รักษา: 'high-flow 100% oxygen' (เร่ง CO elimination), hyperbaric O2 ถ้า severe (LOC, neuro, cardiac, pregnancy). Cherry-red เป็น late/unreliable sign"}, {"topic": "Pediatric Head Injury / Concussion", "q": "A child falls and hits his head, briefly loses consciousness, and now has a headache and vomited twice but has a normal neurologic exam (GCS 15). What guides the decision about neuroimaging?", "choices": ["Imaging every child who sustains any head bump", "Clinical decision rules based on brain-injury risk factors", "Never obtaining neuroimaging in injured children", "A skull radiograph used as the definitive test", "An MRI of the brain for every minor head injury"], "ans": 1, "exp": "Pediatric minor head injury: ใช้ 'clinical decision rules (PECARN)' ประเมินความเสี่ยงของ clinically important traumatic brain injury (พิจารณาจาก GCS, mental status, LOC, mechanism, vomiting, severe headache, signs of skull fracture) เพื่อตัดสินใจ CT (หลีกเลี่ยง radiation ที่ไม่จำเป็น). Concussion = functional injury, จัดการด้วย rest + gradual return. Red flags (worsening, focal signs) → CT/admit"}, {"topic": "Dehydration Assessment", "q": "A child with gastroenteritis has sunken eyes, decreased skin turgor, dry mucous membranes, tachycardia, and delayed capillary refill but is still responsive. Approximately what degree of dehydration does this represent?", "choices": ["No dehydration", "Mild dehydration only", "Moderate to severe dehydration", "Fluid overload", "Isolated hypernatremia without dehydration"], "ans": 2, "exp": "Clinical signs ของ 'moderate-to-severe' dehydration: sunken eyes, decreased skin turgor, dry mucous membranes, tachycardia, delayed capillary refill, decreased urine output, +/- lethargy/hypotension (severe). ประเมิน %fluid deficit ชี้แนวทาง (ORS สำหรับ mild-moderate; IV สำหรับ severe/shock). Weight change เป็น measure ที่แม่นยำ. ในทารกดู fontanelle ด้วย"}, {"topic": "Oppositional Defiant Disorder", "q": "A 7-year-old has a persistent pattern (>6 months) of angry/irritable mood, argumentative and defiant behavior toward authority figures, and vindictiveness, causing problems at home and school, but without serious violation of others' rights or the law. What is the diagnosis?", "choices": ["Conduct disorder", "ADHD alone", "Autism spectrum disorder", "Oppositional defiant disorder", "Normal childhood behavior"], "ans": 3, "exp": "Oppositional defiant disorder (ODD): pattern เรื้อรัง (≥6 เดือน) ของ angry/irritable mood, argumentative/defiant behavior, vindictiveness ต่อ authority, impair function. 'ไม่ละเมิดสิทธิผู้อื่น/กฎหมายรุนแรง' (ต่างจาก conduct disorder). มักร่วมกับ ADHD. รักษา: parent management training, behavioral therapy, จัดการ comorbidity"}, {"topic": "Conduct Disorder", "q": "A 14-year-old repeatedly violates the rights of others and major social norms: aggression toward people/animals, destruction of property, deceitfulness/theft, and serious rule violations. What is the diagnosis?", "choices": ["Oppositional defiant disorder", "Bipolar disorder", "Intermittent explosive disorder", "Normal adolescent rebellion", "Conduct disorder"], "ans": 4, "exp": "Conduct disorder: repetitive pattern ของการ 'ละเมิดสิทธิผู้อื่นและ norms' — aggression to people/animals, destruction of property, deceitfulness/theft, serious rule violations (truancy, running away). รุนแรงกว่า ODD. เสี่ยงพัฒนาเป็น antisocial personality disorder. รักษา: multimodal (family/behavioral therapy, จัดการ comorbidity, psychosocial support)"}, {"topic": "Juvenile Idiopathic Arthritis", "q": "A 3-year-old girl has had swelling, warmth, and morning stiffness of the knee for more than 6 weeks without infection or trauma, plus a positive ANA. Slit-lamp exam is recommended to screen for a silent complication. What is that complication?", "choices": ["Chronic anterior uveitis threatening the vision", "A coronary artery aneurysm of the heart", "An immune-complex glomerulonephritis of the kidney", "An interstitial lung disease of the lungs", "An aortic dissection of the great vessel"], "ans": 0, "exp": "Juvenile idiopathic arthritis (JIA): arthritis ≥6 สัปดาห์, เริ่มก่อน 16 ปี. Oligoarticular JIA (ANA-positive, young girls) เสี่ยง 'chronic anterior uveitis' ที่ 'silent' (asymptomatic แต่ทำให้ตาบอด) → ต้อง regular slit-lamp screening. รักษา: NSAIDs, intra-articular/systemic steroids, methotrexate, biologics. Systemic JIA (Still) มี fever + rash + arthritis. ต่างจาก septic arthritis (acute, ill)"}, {"topic": "Juvenile Dermatomyositis", "q": "A 6-year-old has symmetric proximal muscle weakness (difficulty climbing stairs), a heliotrope rash on the eyelids, and Gottron papules over the knuckles, with elevated muscle enzymes (CK). What is the diagnosis?", "choices": ["Duchenne muscular dystrophy", "Juvenile dermatomyositis", "Systemic lupus erythematosus", "Juvenile idiopathic arthritis", "Polymyositis without skin involvement"], "ans": 1, "exp": "Juvenile dermatomyositis: autoimmune inflammatory myopathy — symmetric 'proximal muscle weakness' + characteristic skin findings ('heliotrope rash' รอบตา, 'Gottron papules' ที่ข้อนิ้ว), elevated muscle enzymes (CK, aldolase), +/- calcinosis, vasculopathy. รักษาด้วย corticosteroids + steroid-sparing (methotrexate/IVIG). ต่างจาก DMD (genetic, ชาย, ไม่มี rash)"}, {"topic": "Pediatric SLE", "q": "An adolescent girl has a malar (butterfly) rash, photosensitivity, oral ulcers, arthritis, and renal involvement, with positive ANA and anti-dsDNA and low complement. What is the diagnosis?", "choices": ["Juvenile idiopathic arthritis", "Dermatomyositis", "Systemic lupus erythematosus", "Henoch-Schonlein purpura", "Acute rheumatic fever"], "ans": 2, "exp": "Pediatric systemic lupus erythematosus (SLE): multisystem autoimmune — malar rash, photosensitivity, oral ulcers, arthritis, serositis, 'lupus nephritis' (สำคัญในเด็ก, รุนแรงกว่าผู้ใหญ่), cytopenias, neuropsychiatric. Labs: ANA (sensitive), anti-dsDNA/anti-Sm (specific), low C3/C4 (active). พบมากในหญิงวัยรุ่น. รักษา: hydroxychloroquine + corticosteroids + immunosuppressants ตาม organ involvement"}, {"topic": "Selective IgA Deficiency", "q": "A generally healthy child has recurrent mild sinopulmonary and GI infections, and had an anaphylactic-type reaction to a blood transfusion. Immunoglobulin studies show very low IgA with normal IgG and IgM. What is the diagnosis?", "choices": ["X-linked agammaglobulinemia", "Severe combined immunodeficiency", "Common variable immunodeficiency only", "Selective IgA deficiency", "Chronic granulomatous disease"], "ans": 3, "exp": "Selective IgA deficiency: primary immunodeficiency ที่พบบ่อยที่สุด, ส่วนใหญ่ 'asymptomatic'; บางรายมี recurrent mucosal (sino-pulmonary, GI) infections, atopy, autoimmune. เสี่ยง 'anaphylaxis ต่อ blood products' ที่มี IgA (ต้องใช้ washed/IgA-deficient products). IgA ต่ำ, IgG/IgM ปกติ. ไม่มี specific treatment (จัดการ infection). สัมพันธ์กับ celiac disease"}, {"topic": "Kawasaki vs Systemic JIA", "q": "A child has daily spiking (quotidian) high fevers, a salmon-pink evanescent rash that appears with fever, arthritis, hepatosplenomegaly, and very high inflammatory markers/ferritin, persisting for weeks. What is the most likely diagnosis?", "choices": ["Kawasaki disease with mucocutaneous features", "Acute rheumatic fever after a streptococcal infection", "Acute leukemia infiltrating the bone marrow", "Familial Mediterranean fever with periodic attacks", "Systemic juvenile idiopathic arthritis (Still disease)"], "ans": 4, "exp": "Systemic JIA (Still disease): 'quotidian' spiking fevers, evanescent 'salmon-pink' rash (มากับไข้), arthritis, hepatosplenomegaly/lymphadenopathy, serositis, markedly elevated inflammatory markers + ferritin. เสี่ยง macrophage activation syndrome (MAS). ต่างจาก Kawasaki (fever ≥5 วัน + mucocutaneous criteria, coronary risk, ตอบสนอง IVIG, มักหายใน ~2 สัปดาห์). ต้อง exclude infection/malignancy"}, {"topic": "Maintenance Fluids", "q": "Using the Holliday-Segar method, what is the approximate daily maintenance fluid requirement for a 20 kg child?", "choices": ["1500 mL/day", "2000 mL/day", "1000 mL/day", "500 mL/day", "3000 mL/day"], "ans": 0, "exp": "Holliday-Segar maintenance fluid: 100 mL/kg สำหรับ 10 kg แรก + 50 mL/kg สำหรับ 10 kg ถัดไป + 20 mL/kg สำหรับ kg ที่เหลือ. เด็ก 20 kg = (10x100) + (10x50) = 1000 + 500 = '1500 mL/day' (~62 mL/hr, กฎ '4-2-1' rate). ใช้เป็น baseline แล้วปรับตาม deficit/ongoing losses. เลือก isotonic fluid + dextrose ในเด็กเพื่อลด hyponatremia"}, {"topic": "Hypernatremic Dehydration", "q": "An infant with gastroenteritis has severe dehydration and a serum sodium of 165 mEq/L. During correction, why must the sodium be lowered slowly?", "choices": ["Rapid correction causes central pontine myelinolysis", "Rapid correction risks cerebral edema and seizures", "Rapid correction causes hyperkalemia", "It does not matter how fast sodium is corrected", "Slow correction causes kernicterus"], "ans": 1, "exp": "Hypernatremic dehydration (Na >150): brain adapts โดยสร้าง idiogenic osmoles. ถ้า 'ลด sodium เร็วเกินไป' → water เข้าเซลล์สมอง → 'cerebral edema, seizures'. จึงต้องแก้ช้าๆ (ลด Na ไม่เกิน ~0.5 mEq/L/hr หรือ ~10-12/วัน) ด้วย fluid replacement over 48 ชม. (Central pontine myelinolysis สัมพันธ์กับการแก้ 'hyponatremia' เร็วเกิน — ตรงข้ามกัน)"}, {"topic": "Hyperkalemia Management", "q": "A child with acute kidney injury has a potassium of 7.5 mEq/L with peaked T waves and a widening QRS on ECG. What is the first drug to give to stabilize the myocardium?", "choices": ["Insulin and glucose", "Sodium bicarbonate", "Intravenous calcium gluconate", "Salbutamol nebulizer", "Oral potassium binder"], "ans": 2, "exp": "Severe hyperkalemia with ECG changes (peaked T, wide QRS, เสี่ยง arrhythmia): ให้ 'IV calcium gluconate ก่อน' เพื่อ 'stabilize myocardium' (ไม่ลด K แต่ป้องกัน arrhythmia). แล้วจึง shift K เข้าเซลล์ (insulin+glucose, salbutamol, bicarbonate) และ remove K (diuretics, potassium binders, dialysis). Calcium เป็นขั้นแรกในภาวะฉุกเฉินที่มี ECG changes"}, {"topic": "DKA Cerebral Edema", "q": "A child being treated for diabetic ketoacidosis suddenly develops headache, decreasing consciousness, bradycardia, and hypertension several hours into therapy. What is the most serious complication being manifested?", "choices": ["Hypoglycemia", "Hypokalemia", "Pulmonary embolism", "Cerebral edema", "Aspiration pneumonia"], "ans": 3, "exp": "Cerebral edema เป็นภาวะแทรกซ้อนที่ร้ายแรงที่สุดของ pediatric DKA (สาเหตุ death/disability หลัก): headache, decreasing consciousness, bradycardia + hypertension (Cushing response), pupillary changes — มักเกิด 4-12 ชม.หลังเริ่มรักษา. ป้องกันด้วยการแก้ fluid/glucose 'ช้าๆ'. รักษา: hypertonic saline หรือ mannitol + ลด IV fluid rate + airway. ต้องตระหนักและ recognize เร็ว"}, {"topic": "Thyroid Storm", "q": "An adolescent with untreated Graves disease develops high fever, severe tachycardia/arrhythmia, agitation/delirium, vomiting, and heart failure during an intercurrent illness. What is this life-threatening condition?", "choices": ["Adrenal crisis", "Diabetic ketoacidosis", "Malignant hyperthermia", "Serotonin syndrome", "Thyroid storm"], "ans": 4, "exp": "Thyroid storm: decompensated thyrotoxicosis (มัก precipitate ด้วย infection/surgery/stopping meds) — hyperpyrexia, severe tachycardia/arrhythmia/HF, CNS (agitation, delirium, coma), GI (vomiting, diarrhea). Emergency: 'beta-blocker' (propranolol), thionamide (PTU/methimazole), iodine (หลัง thionamide), corticosteroid, supportive/cooling, treat precipitant. Mortality สูงถ้าไม่รักษา"}, {"topic": "Pubertal Gynecomastia", "q": "A 13-year-old boy in mid-puberty has mild, tender, bilateral breast tissue enlargement. He is otherwise healthy with normal genital development. What is the most appropriate management?", "choices": ["Reassurance, since pubertal gynecomastia usually resolves", "Immediate breast reduction surgery for the tissue", "Testosterone therapy given to every affected boy", "An extensive tumor workup performed in every case", "Routine long-term estrogen-blocking medication"], "ans": 0, "exp": "Pubertal gynecomastia: benign, common ในเด็กชายกลาง puberty (transient imbalance ของ estrogen/androgen), mild tender breast tissue, ส่วนใหญ่ 'หายเองภายใน 1-2 ปี'. รักษาด้วย reassurance. Workup เมื่อ atypical: prepubertal, rapid/large/persistent, features ของ syndrome (Klinefelter), medications, หรือ signs ของ tumor/endocrine disorder"}, {"topic": "Type 2 Diabetes in Adolescents", "q": "An obese 14-year-old with acanthosis nigricans and a family history of diabetes is found to have hyperglycemia without significant ketosis. What is the first-line pharmacologic treatment (along with lifestyle changes)?", "choices": ["Insulin only, lifelong", "Metformin", "Sulfonylurea as first-line", "No medication is ever indicated", "GLP-1 agonist as sole first-line for all"], "ans": 1, "exp": "Type 2 diabetes ในวัยรุ่น (เพิ่มขึ้นตามความชุกของ obesity): insulin resistance — obese + acanthosis nigricans + family history, hyperglycemia มัก 'ไม่มี ketosis' รุนแรง. First-line: 'lifestyle modification + metformin'. Insulin ใช้ถ้า presentation รุนแรง/ketosis/สูงมาก. ต่างจาก T1DM (autoimmune, lean, insulin-dependent, ketosis). Screen comorbidities"}, {"topic": "Bell Palsy", "q": "A child develops acute unilateral facial weakness involving the forehead (cannot wrinkle it or close the eye fully) with drooping of the mouth, without other neurologic deficits, often following a viral illness. What is the diagnosis?", "choices": ["A stroke producing a central facial nerve palsy", "Guillain-Barre syndrome with ascending weakness", "Bell palsy, an idiopathic peripheral facial nerve palsy", "A brain tumor compressing the facial nerve", "Myasthenia gravis with fatigable facial weakness"], "ans": 2, "exp": "Bell palsy: acute idiopathic 'peripheral' (lower motor neuron) facial nerve palsy → weakness ของครึ่งหน้า 'รวมหน้าผาก' (แยกจาก central/UMN ที่ forehead spared). อาจหลัง viral. ดูแลตา (lubrication, ป้องกัน exposure keratitis); corticosteroids ในบางราย. ส่วนใหญ่หายดี. ต้องแยก Lyme, otitis media, tumor, hypertension (ในเด็ก) ถ้า bilateral/atypical"}, {"topic": "Transverse Myelitis", "q": "A child develops, over hours to days, bilateral leg weakness, a sensory level on the trunk, and bladder dysfunction after a viral illness. MRI shows a T2-hyperintense spinal cord lesion. What is the diagnosis?", "choices": ["Guillain-Barre syndrome", "Bell palsy", "Cerebral palsy", "Transverse myelitis", "Muscular dystrophy"], "ans": 3, "exp": "Transverse myelitis: acute inflammation ของ spinal cord → bilateral weakness, 'sensory level', autonomic (bladder/bowel) dysfunction, post-infectious/autoimmune. MRI: cord lesion (T2 hyperintense). ต่างจาก GBS (peripheral, ascending, no sensory level, areflexia, no bladder ตอนแรก). รักษา: high-dose IV corticosteroids +/- plasmapheresis. ต้องแยก compressive cause (emergency imaging)"}, {"topic": "Night Terrors", "q": "The parents of a 4-year-old report that about 2 hours after falling asleep, he suddenly sits up screaming, appears terrified and sweaty, is inconsolable and unresponsive, and has no memory of it the next morning. What is the most appropriate advice?", "choices": ["Starting a sedative medication every single night", "Referral for evaluation for epilepsy surgery", "Fully waking the child during each nightly episode", "A mandatory extensive psychiatric evaluation", "Reassurance, since night terrors are benign and self-limited"], "ans": 4, "exp": "Night terrors (sleep terrors): parasomnia จาก 'non-REM' sleep (early night), เด็กนั่งขึ้นกรีดร้อง, ตื่นตระหนก, autonomic (sweating, tachycardia), 'inconsolable + ไม่ตื่นเต็มที่ + จำไม่ได้'. Benign, หายเมื่อโต. รักษา: reassurance, sleep hygiene, ความปลอดภัย, ไม่ปลุกให้ตื่นเต็มที่. ต่างจาก 'nightmares' (REM, late night, ตื่นเต็มที่ + จำได้ + consolable)"}, {"topic": "Nightmares vs Parasomnia", "q": "A 5-year-old wakes in the later part of the night frightened after a bad dream, is fully alert, can describe the dream, and is comforted by a parent. What is this?", "choices": ["Nightmares, a frightening REM-sleep phenomenon", "Night terrors arising from non-REM deep sleep", "Nocturnal seizures occurring during sleep", "Sleepwalking arising from non-REM deep sleep", "Obstructive sleep apnea disrupting the sleep"], "ans": 0, "exp": "Nightmares: frightening dreams ใน 'REM sleep' (later half ของคืน), เด็ก 'ตื่นเต็มที่, จำเนื้อหาได้, และ consolable'. Benign, common. รักษา: reassurance, sleep hygiene, จัดการ stressor. ต่างจาก night terrors (non-REM, early, inconsolable, amnesia). Frequent distressing nightmares อาจสัมพันธ์กับ stress/anxiety/PTSD"}, {"topic": "Sleepwalking", "q": "A 7-year-old is found walking around the house with a blank stare during the first third of the night, is difficult to awaken, and has no memory of it. What is the appropriate management?", "choices": ["Wake the child every night preemptively for months", "Ensure environmental safety and reassure", "Start antiepileptic medication", "Refer for immediate neurosurgery", "Restrict all daytime naps permanently"], "ans": 1, "exp": "Sleepwalking (somnambulism): non-REM parasomnia (early night) — เด็กลุกเดิน, blank stare, ปลุกยาก, จำไม่ได้. Benign, พบบ่อย, หายเมื่อโต. Management: 'ความปลอดภัยของสิ่งแวดล้อม' (ล็อกประตู/หน้าต่าง, กันบันได), sleep hygiene, adequate sleep (sleep deprivation กระตุ้น). ไม่ต้องปลุกให้ตื่น. รุนแรง/บ่อยพิจารณา scheduled awakening"}, {"topic": "Temper Tantrums", "q": "A healthy 2-year-old has frequent temper tantrums (crying, screaming, falling to the floor) when frustrated or told 'no,' with normal development otherwise. What is the most appropriate guidance?", "choices": ["Starting behavioral medication to control the tantrums", "Referral for inpatient psychiatric admission", "Reassurance, since tantrums are normal, with calm responses", "Using physical punishment to stop the tantrums", "An extensive medical workup for the behavior"], "ans": 2, "exp": "Temper tantrums เป็น 'normal' developmental behavior ในเด็กวัยเตาะแตะ (1-3 ปี) จาก limited emotional regulation/language + desire for autonomy. Management: consistency, calm response, ignore attention-seeking behavior, positive reinforcement, ensure safety, หลีกเลี่ยง triggers (hunger/tired). Red flags (self-injury, prolonged/frequent, aggression, developmental concern) จึงต้องประเมินเพิ่ม"}, {"topic": "Adolescent Risk Screening", "q": "When interviewing an adolescent, a structured psychosocial assessment (Home, Education, Activities, Drugs, Sexuality, Suicide/depression, Safety) is used to identify risk. What is this assessment called?", "choices": ["APGAR score", "Glasgow Coma Scale", "CAGE questionnaire", "HEEADSSS assessment", "Denver test"], "ans": 3, "exp": "HEEADSSS assessment (Home, Education/employment, Eating, Activities, Drugs, Sexuality, Suicide/depression, Safety) เป็น structured psychosocial interview สำหรับวัยรุ่น — ช่วยประเมิน risk behaviors ในบรรยากาศ confidential/non-judgmental. เริ่มจากคำถามที่ threatening น้อยไปมาก. เป็นเครื่องมือสำคัญของ adolescent medicine (ควบคู่ confidentiality)"}, {"topic": "Vaping / E-cigarettes", "q": "An adolescent presents with cough, dyspnea, chest pain, and diffuse lung infiltrates after heavy use of e-cigarettes/vaping. This is recognized as which entity?", "choices": ["Community-acquired bacterial pneumonia of the lung", "An asthma exacerbation from an airway trigger", "A pulmonary embolism obstructing the circulation", "Pulmonary tuberculosis with chronic infection", "E-cigarette or vaping product use-associated lung injury"], "ans": 4, "exp": "EVALI (e-cigarette/vaping associated lung injury): acute/subacute respiratory (cough, dyspnea, chest pain) + GI + constitutional symptoms + diffuse lung infiltrates ในผู้ใช้ vaping (สัมพันธ์กับ THC/vitamin E acetate). เป็น diagnosis of exclusion (แยก infection). รักษา: หยุด vaping, supportive, +/- corticosteroids. Vaping ในวัยรุ่นเพิ่มขึ้น — ควร screen และให้คำแนะนำ"}, {"topic": "Intellectual Disability", "q": "A child has significant deficits in both intellectual functioning (IQ well below average) and adaptive functioning (daily living skills), with onset during the developmental period. What is the appropriate approach?", "choices": ["Identify the cause and provide early multidisciplinary support", "Accept that no intervention changes the outcome", "Place all such children in long-term institutions", "Treat the child solely with medication", "Delay any evaluation until the child reaches school age"], "ans": 0, "exp": "Intellectual disability: deficits ทั้ง 'intellectual' (IQ) และ 'adaptive functioning' ที่เริ่มในช่วง developmental period. ประเมินหาสาเหตุ (genetic เช่น Down/Fragile X, metabolic, TORCH, perinatal, environmental) เมื่อทำได้ + early intervention/special education + multidisciplinary support + จัดการ comorbidities (epilepsy, behavior, sensory). Early intervention ปรับ outcome ได้"}, {"topic": "Infant Choking - BLS", "q": "A 10-month-old infant suddenly chokes on a piece of food and cannot cry, cough, or breathe (severe airway obstruction) but is still conscious. What is the correct maneuver?", "choices": ["Abdominal thrusts (Heimlich maneuver)", "Alternating 5 back blows and 5 chest thrusts", "Blind finger sweep of the mouth", "Lay the infant flat and wait", "Give water to wash it down"], "ans": 1, "exp": "Infant (<1 ปี) choking with 'severe' obstruction but conscious: '5 back blows + 5 chest thrusts' สลับกัน (ไม่ใช้ abdominal thrusts/Heimlich ในทารก — เสี่ยง organ injury). ถ้าหมดสติ → เริ่ม CPR + look ในปากก่อนช่วยหายใจ (ไม่ blind finger sweep). ถ้ายัง cough/cry ได้ (mild) → กระตุ้นให้ไอ, ไม่รบกวน. ในเด็ก >1 ปี ใช้ abdominal thrusts"}, {"topic": "PALS - Bradycardia", "q": "An infant has a heart rate of 50/min with poor perfusion, hypotension, and altered consciousness despite effective oxygenation and ventilation. According to pediatric advanced life support, what is the next step?", "choices": ["Immediate synchronized cardioversion", "Give adenosine", "Start chest compressions", "Observe and reassess in 10 minutes", "Defibrillate"], "ans": 2, "exp": "ใน PALS, 'bradycardia' ที่มี poor perfusion (HR <60 ในทารก/เด็ก) 'despite adequate oxygenation/ventilation' → เริ่ม 'chest compressions' + epinephrine (bradycardia ในเด็กมักจาก hypoxia — จึงเน้น airway/breathing ก่อน แล้ว compression ถ้า HR <60 + poor perfusion). Atropine สำหรับ vagal/AV block. ต่างจากผู้ใหญ่ที่ bradycardia มัก cardiac primary"}, {"topic": "Acute Urticaria", "q": "A child develops widespread transient, intensely itchy raised wheals that individually last less than 24 hours and migrate, following a viral infection. There is no anaphylaxis. What is the first-line treatment?", "choices": ["Systemic corticosteroids for all", "Intramuscular adrenaline", "Topical antifungal", "Non-sedating oral antihistamine", "Oral antibiotics"], "ans": 3, "exp": "Acute urticaria: transient migratory 'wheals' (individual lesions <24 ชม.), pruritic, มักหลัง viral infection (สาเหตุที่พบบ่อยในเด็ก), หรือ food/drug/allergen. First-line: 'non-sedating H1 antihistamine' (cetirizine/loratadine). Short corticosteroid ในรายรุนแรง. ถ้ามี systemic features (respiratory/CV) = anaphylaxis → adrenaline. Angioedema ร่วมต้องเฝ้าระวัง airway"}, {"topic": "Hereditary Angioedema", "q": "A child has recurrent episodes of non-pruritic, non-pitting swelling of the face, extremities, and bowel (causing abdominal pain), WITHOUT urticaria, poorly responsive to antihistamines, with a family history. C4 is low. What is the diagnosis?", "choices": ["Allergic angioedema", "Anaphylaxis", "Chronic urticaria", "Contact dermatitis", "Hereditary angioedema"], "ans": 4, "exp": "Hereditary angioedema (C1 esterase inhibitor deficiency, autosomal dominant): recurrent 'angioedema WITHOUT urticaria/itch', involving face/extremities/airway/bowel (abdominal pain), 'ไม่ตอบสนอง antihistamine/epinephrine/steroid' (bradykinin-mediated), family history, 'low C4'. เสี่ยง 'laryngeal edema' (fatal). รักษา acute: C1 inhibitor concentrate, bradykinin antagonist (icatibant); prophylaxis. ต่างจาก allergic angioedema"}, {"topic": "Terminal Complement Deficiency", "q": "A teenager has had recurrent episodes of Neisseria meningitidis infection (meningococcemia/meningitis). Which underlying immune defect should be evaluated?", "choices": ["Terminal complement deficiency", "T-cell deficiency", "IgA deficiency", "Neutrophil oxidative burst defect", "B-cell deficiency"], "ans": 0, "exp": "Recurrent 'Neisseria' infections (meningococcal, gonococcal) → นึกถึง 'terminal complement deficiency (C5-C9/membrane attack complex)' ซึ่งจำเป็นต่อการ lyse Neisseria. ประเมินด้วย CH50 (low/absent). ต้อง meningococcal vaccination + prompt treatment ของ infection. Properdin deficiency (X-linked) ก็เพิ่มความเสี่ยง fulminant meningococcemia"}, {"topic": "Wiskott-Aldrich Syndrome", "q": "A boy has the triad of eczema, recurrent infections, and thrombocytopenia with small platelets, and an X-linked inheritance pattern. What is the diagnosis?", "choices": ["Ataxia-telangiectasia", "Wiskott-Aldrich syndrome", "Chronic granulomatous disease", "Hyper-IgE (Job) syndrome", "X-linked agammaglobulinemia"], "ans": 1, "exp": "Wiskott-Aldrich syndrome (X-linked, WAS gene): triad = 'eczema + recurrent infections (immunodeficiency) + thrombocytopenia with SMALL platelets'. เสี่ยง bleeding, infections (encapsulated), autoimmune, และ malignancy (lymphoma). รักษา: supportive, IVIG, HSCT curative. Small platelet size เป็นเบาะแสสำคัญ (ต่างจาก ITP ที่ platelet ปกติ/ใหญ่)"}, {"topic": "Ataxia-Telangiectasia", "q": "A child develops progressive cerebellar ataxia in early childhood, later oculocutaneous telangiectasias, recurrent sinopulmonary infections, and an increased risk of malignancy, with elevated alpha-fetoprotein. What is the diagnosis?", "choices": ["Friedreich ataxia", "Wiskott-Aldrich syndrome", "Ataxia-telangiectasia", "Tuberous sclerosis", "Acute cerebellar ataxia"], "ans": 2, "exp": "Ataxia-telangiectasia (ATM gene, DNA repair defect, autosomal recessive): 'progressive cerebellar ataxia' (early childhood) + 'oculocutaneous telangiectasias' + immunodeficiency (recurrent sinopulmonary infection, low IgA) + radiation sensitivity + increased malignancy (lymphoma/leukemia), elevated AFP. หลีกเลี่ยง radiation. Multidisciplinary supportive care"}, {"topic": "Hyper-IgE Syndrome", "q": "A child has recurrent 'cold' (non-inflamed) skin abscesses (Staphylococcus), recurrent pneumonias with pneumatoceles, severe eczema, retained primary teeth, and a characteristic coarse facial appearance, with markedly elevated IgE. What is the diagnosis?", "choices": ["Chronic granulomatous disease", "Atopic dermatitis alone", "Wiskott-Aldrich syndrome", "Hyper-IgE syndrome", "Cystic fibrosis"], "ans": 3, "exp": "Hyper-IgE (Job) syndrome: recurrent 'cold' staphylococcal skin abscesses (ไม่มี inflammation ตามปกติ), recurrent pneumonia with pneumatoceles, severe eczema, 'retained primary teeth', coarse facies, bone fractures, และ 'markedly elevated IgE'. รักษา: prophylactic anti-staph antibiotics + antifungal, skin care. เป็น primary immunodeficiency ที่มีลักษณะเฉพาะ (STAT3 mutation)"}, {"topic": "Heat Stroke", "q": "A child collapses during sports on a hot day with a core temperature over 40°C, hot dry (or sweaty) skin, and altered mental status (confusion, seizures). What is the priority management?", "choices": ["Antipyretics (paracetamol) as the main treatment", "Antibiotics", "Warm the patient", "Fluid restriction", "Rapid active cooling and supportive care"], "ans": 4, "exp": "Heat stroke: core temp >40°C + CNS dysfunction (confusion, seizure, coma) จาก thermoregulatory failure (exertional in athletes, หรือ environmental). Priority: 'rapid active cooling' (cold water immersion/evaporative + ice packs) + support ABC + IV fluids + จัดการ complications (rhabdomyolysis, DIC, organ failure). 'Antipyretics ไม่ช่วย' (mechanism ต่าง fever). Prevention: hydration, acclimatization"}, {"topic": "Electrical Injury", "q": "A child bites through an electrical cord and sustains an oral commissure burn. Beyond the immediate injury, what delayed complication should caregivers be warned about?", "choices": ["Delayed labial-artery bleeding as the eschar separates", "A sudden cardiac arrest occurring weeks later", "Only a gradual discoloration of the nearby teeth", "No complications occur after this type of burn", "A permanent loss of color vision in both eyes"], "ans": 0, "exp": "Oral commissure electrical burn (เด็กกัดสายไฟ): full-thickness burn ที่มุมปาก. ภาวะแทรกซ้อน delayed สำคัญคือ 'bleeding จาก labial artery' เมื่อ eschar หลุด (~5-14 วัน) — ต้องเตือนผู้ปกครองให้เฝ้าระวังและรู้วิธีกดห้ามเลือด. High-voltage electrical injury ทั่วไปเสี่ยง cardiac arrhythmia, deep tissue/rhabdomyolysis, compartment syndrome — ต้อง monitor"}, {"topic": "Hypothermia", "q": "A child rescued from cold water has a core temperature of 30°C, is bradycardic, and appears lifeless with barely detectable vital signs. What principle guides resuscitation?", "choices": ["Declare death immediately based on the cold exam", "Continue resuscitation and rewarming", "Rapidly rewarm the extremities first only", "Withhold CPR because of the low heart rate", "Give cold IV fluids"], "ans": 1, "exp": "Severe hypothermia: metabolism ลด → ผู้ป่วยอาจดูเหมือนเสียชีวิตแต่ยังฟื้นได้ (โดยเฉพาะเด็ก/drowning cold water) → หลักการ 'not dead until warm and dead' — ทำ CPR + active rewarming ต่อจนอุ่น. จัดการนุ่มนวล (เสี่ยง arrhythmia), rewarm core (warm IV fluids, warm air). ประเมินซ้ำเมื่ออุณหภูมิสูงขึ้น. Bradycardia จาก hypothermia อาจ appropriate"}, {"topic": "Poisoning - Decontamination", "q": "A child presents 30 minutes after ingesting a toxic dose of a medication (that binds to charcoal), is awake with an intact airway. Which gastrointestinal decontamination method is most appropriate?", "choices": ["Syrup of ipecac to induce vomiting", "Gastric lavage for all ingestions", "Activated charcoal", "Whole bowel irrigation for every case", "No decontamination is ever useful"], "ans": 2, "exp": "GI decontamination ในพิษเฉียบพลัน: 'activated charcoal' (ให้ภายใน ~1 ชม., ผู้ป่วยตื่น/airway ปลอดภัย, สารดูดซับ charcoad ได้) เป็น method ที่ใช้บ่อยที่สุด. 'ไม่แนะนำ ipecac' (ไม่มีประโยชน์, เสี่ยง aspiration). Gastric lavage เฉพาะกรณีจำกัด. Whole bowel irrigation สำหรับ iron/lithium/sustained-release/body packers. Charcoal 'ไม่จับ' iron, lithium, alcohols, hydrocarbons"}, {"topic": "Microcephaly", "q": "A newborn has a head circumference well below the 3rd percentile (more than 3 standard deviations below the mean). Which is an important consideration in the differential?", "choices": ["A normal head-size variant requiring no thought", "A finding that is always due to craniosynostosis", "A change that is always benign and familial", "Congenital infection, genetic syndromes, or brain malformation", "A finding caused exclusively by prematurity"], "ans": 3, "exp": "Microcephaly (head circumference <3rd percentile / <-3 SD): บ่งชี้ปัญหาการเจริญของสมอง. Differential: congenital infections (Zika — สัมพันธ์ congenital microcephaly, CMV, toxoplasma, rubella), genetic/chromosomal syndromes, brain malformation, HIE, metabolic, maternal (alcohol/PKU). ประเมิน: history, exam, neuroimaging, infection workup, genetics. สัมพันธ์กับ developmental delay. ต่างจาก craniosynostosis (skull shape ผิด, sutures ปิดก่อนเวลา)"}, {"topic": "Substance Use - Adolescent", "q": "During a confidential adolescent visit, a screening tool identifies concerning alcohol/drug use. What is the recommended framework used for adolescent substance use screening and management?", "choices": ["Immediate mandatory hospitalization of the adolescent", "Informing the school and the police as the first step", "Ignoring the finding in order to maintain trust", "Prescribing benzodiazepines to manage the use", "Screening, Brief Intervention, and Referral to Treatment"], "ans": 4, "exp": "Adolescent substance use: ใช้ validated screening (เช่น CRAFFT) ภายใน 'SBIRT' framework (Screening, Brief Intervention, Referral to Treatment) — ประเมิน risk, ให้ brief motivational counseling, และ refer สำหรับ treatment ตามความรุนแรง, ในบรรยากาศ confidential/non-judgmental (ภายในขอบเขต safety). ส่งเสริมการเปลี่ยนพฤติกรรม. *เป็นหัวข้อละเอียดอ่อน ควรดูแลด้วยความเข้าใจ"}, {"topic": "Bacterial Meningitis - Hearing", "q": "A child recovering from bacterial meningitis (e.g., pneumococcal) requires follow-up testing before discharge because of a common permanent sequela. Which test is important?", "choices": ["Audiologic evaluation", "Echocardiography", "Renal ultrasound", "Bone density scan", "Pulmonary function test"], "ans": 0, "exp": "Sensorineural hearing loss เป็น sequela ที่พบบ่อยที่สุดของ bacterial meningitis (โดยเฉพาะ pneumococcal) → ต้อง 'audiologic evaluation' หลังหาย (ก่อน/ไม่นานหลัง discharge) เพื่อ early detection และ intervention (hearing aid/cochlear implant) ป้องกัน speech/language delay. Adjunctive dexamethasone (โดยเฉพาะ Hib) ช่วยลด hearing loss. Sequelae อื่น: seizures, cognitive/motor deficits"}, {"topic": "Craniosynostosis", "q": "An infant has an abnormally shaped head with a palpable bony ridge along a suture and a head circumference that is not enlarging appropriately, due to premature fusion of a cranial suture. What is the concern and management?", "choices": ["Benign positional plagiocephaly needing only repositioning", "Craniosynostosis, which may need surgical correction", "Hydrocephalus requiring a ventriculoperitoneal shunt", "Normal head molding that requires no intervention", "Nutritional rickets treated with vitamin D"], "ans": 1, "exp": "Craniosynostosis: premature fusion ของ cranial suture → abnormal head shape + palpable ridge along suture + restricted growth ในทิศทางนั้น. Single-suture มักเป็น cosmetic แต่ multiple-suture เสี่ยง raised ICP และ restrict brain growth → ผ่าตัด. ต่างจาก 'positional plagiocephaly' (จากนอนท่าเดิม, sutures ปกติ, ปรับด้วย repositioning/helmet). วินิจฉัยด้วย exam + CT"}, {"topic": "Failure to Pass Meconium - Older", "q": "A child with lifelong severe constipation since birth, abdominal distension, and poor growth is found on rectal exam to have a tight anal canal with explosive release of stool and gas. A rectal biopsy is diagnostic. What condition, if missed in the newborn period, can present later?", "choices": ["Functional constipation", "Hypothyroidism", "Hirschsprung disease", "Anal fissure", "Celiac disease"], "ans": 2, "exp": "Hirschsprung disease (aganglionosis): อาจ present later ในเด็กที่มี severe constipation 'ตั้งแต่แรกเกิด' + distension + FTT, rectal exam พบ tight canal + 'explosive' stool release. Short-segment อาจไม่ถูกวินิจฉัยตอนแรกเกิด. Gold standard = rectal biopsy (absent ganglion cells). เสี่ยง enterocolitis. ต่างจาก functional constipation (เริ่มหลัง toilet training, stool in rectum, thriving)"}, {"topic": "Reflex Anoxic / Vasovagal Syncope Exercise", "q": "An adolescent athlete experiences syncope DURING exertion (not after stopping). Why is exertional syncope a red flag compared with typical vasovagal syncope?", "choices": ["It is always benign and requires no evaluation at all", "It reliably indicates simple dehydration only", "It represents an atypical form of seizure", "It may indicate serious cardiac disease needing evaluation", "It is a phenomenon that only occurs in girls"], "ans": 3, "exp": "'Exertional syncope' (เป็นลม 'ขณะ' ออกกำลัง) เป็น red flag สำคัญ — อาจบ่งชี้ serious cardiac cause: hypertrophic cardiomyopathy, arrhythmia (long QT, CPVT), anomalous coronary, aortic stenosis → เสี่ยง sudden cardiac death. ต้อง 'cardiac evaluation' (ECG, echo, +/- family history/genetic). ต่างจาก vasovagal syncope ทั่วไป (เกิด 'หลัง' ยืนนาน/หลังหยุดออกกำลัง, มี prodrome, benign)"}, {"topic": "Osteomyelitis vs Ewing Systemic", "q": "A child has bone pain, fever, and elevated inflammatory markers. Which feature would favor acute osteomyelitis over a bone tumor as the cause?", "choices": ["Weeks of gradually enlarging painless mass", "An 'onion-skin' periosteal reaction on X-ray with a diaphyseal mass", "Systemic weight loss with a lytic lesion and soft tissue mass", "Absence of any inflammatory markers", "Acute onset with fever, focal metaphyseal tenderness, and rapid response to antibiotics"], "ans": 4, "exp": "Acute osteomyelitis: acute onset fever + focal metaphyseal bone tenderness + elevated ESR/CRP + มัก respond ต่อ antibiotics (+/- drainage). Bone tumors (Ewing/osteosarcoma) มัก subacute-chronic, progressive mass/pain, systemic (weight loss), และ X-ray features (onion-skin/sunburst, soft tissue mass). ในบางครั้งแยกยาก (Ewing เลียนแบบ infection) — ต้อง imaging/biopsy ถ้าไม่ตอบสนอง. Clinical course ช่วยแยก"}]}, {"id": "er-1", "title": "เวชศาสตร์ฉุกเฉิน ชุดที่ 1 — Resuscitation & Cardiopulmonary", "subject": "emergency", "questions": [{"topic": "BLS / CPR", "q": "A 55-year-old man suddenly collapses in the emergency department. He is unresponsive, not breathing normally, and has no palpable central pulse after a 10-second check. What is the most appropriate immediate action?", "choices": ["Begin chest compressions at 100-120 per minute, depth 5-6 cm", "Deliver two rescue breaths before starting any compressions", "Perform a rapid abdominal thrust to clear the airway first", "Give a precordial thump and reassess the carotid pulse", "Withhold compressions until the monitor rhythm is available"], "ans": 0, "exp": "Cardiac arrest ที่ยืนยันแล้ว (unresponsive + no normal breathing + no pulse) → เริ่ม 'high-quality chest compressions' ทันที (100-120/min, ลึก 5-6 cm, recoil เต็มที่, ลด interruption). C-A-B: compression มาก่อน. Precordial thump/abdominal thrust ไม่ใช่ขั้นตอนของ arrest ทั่วไป"}, {"topic": "Defibrillation", "q": "During resuscitation of an adult in cardiac arrest, the monitor shows ventricular fibrillation. A defibrillator is ready. What is the most appropriate next step?", "choices": ["Give intravenous amiodarone before any defibrillation attempt", "Deliver an immediate unsynchronized shock and resume compressions", "Perform synchronized cardioversion timed to the R wave", "Administer intravenous epinephrine and delay the shock", "Continue compressions alone until the rhythm self-resolves"], "ans": 1, "exp": "VF/pulseless VT เป็น 'shockable rhythm' → defibrillate ทันที (unsynchronized) แล้ว resume CPR 2 นาที. Synchronized cardioversion ใช้กับ 'perfusing' tachyarrhythmia ที่มี R wave. Epinephrine/amiodarone ให้ควบคู่แต่ไม่ทำให้ delay การ shock ใน shockable rhythm"}, {"topic": "ACLS - Shockable", "q": "An adult in cardiac arrest remains in ventricular fibrillation after two shocks and ongoing CPR. Which drug regimen is most appropriate at this point?", "choices": ["Atropine 1 mg repeated every 3 minutes until rhythm returns", "Adenosine rapid push to terminate the ventricular fibrillation", "Epinephrine every 3-5 minutes", "Sodium bicarbonate empirically after the first defibrillation", "Calcium gluconate as the first-line antiarrhythmic in arrest"], "ans": 2, "exp": "VF/pVT ที่ยังไม่ตอบสนอง: ให้ epinephrine 1 mg IV q3-5 นาที + antiarrhythmic 'amiodarone' (300 mg แล้ว 150 mg) หรือ lidocaine สำหรับ refractory VF. Atropine ไม่ใช้ใน VF, adenosine ใช้ SVT, calcium/bicarb เฉพาะข้อบ่งชี้ (hyperK, TCA overdose)"}, {"topic": "ACLS - Non-shockable", "q": "A patient in cardiac arrest has an organized rhythm on the monitor at 40/min but no palpable pulse. What is the correct management?", "choices": ["Deliver an immediate unsynchronized defibrillation shock", "Perform synchronized cardioversion for the bradycardic rhythm", "Administer atropine and stop compressions to reassess", "Continue CPR, give epinephrine, and search for reversible causes", "Insert a transvenous pacemaker before resuming compressions"], "ans": 3, "exp": "Pulseless electrical activity (PEA): organized rhythm แต่ไม่มี pulse = non-shockable → CPR ต่อ + epinephrine q3-5 นาที + หาและแก้ 'reversible causes' (H's & T's: hypoxia, hypovolemia, H+, hypo/hyperkalemia, hypothermia, tension pneumothorax, tamponade, toxins, thrombosis). ห้าม shock/cardiovert PEA"}, {"topic": "Reversible causes", "q": "A young man in pulseless electrical activity arrest was pulled from a road traffic accident with distended neck veins, tracheal deviation, and absent breath sounds on the right. What reversible cause should be treated immediately?", "choices": ["Cardiac tamponade, treated by urgent pericardiocentesis drainage", "Massive pulmonary embolism, treated by systemic thrombolysis", "Severe hyperkalemia, treated by intravenous calcium gluconate", "Hypovolemic shock, treated by rapid crystalloid fluid bolus", "Tension pneumothorax, treated by immediate chest decompression"], "ans": 4, "exp": "PEA + tracheal deviation + distended neck veins + absent unilateral breath sounds หลัง trauma = 'tension pneumothorax' → needle/finger decompression ทันที แล้ว chest tube. เป็นหนึ่งใน H's & T's ที่แก้ได้เร็ว. Tamponade ก็ทำให้ distended neck veins แต่ pattern ปอด/trachea ชี้ tension ptx"}, {"topic": "Post-ROSC care", "q": "A patient achieves return of spontaneous circulation after cardiac arrest but remains comatose. What is a key component of post-cardiac-arrest care?", "choices": ["Targeted temperature management and treating the underlying cause", "Immediate extubation once a pulse and blood pressure return", "Routine high-dose corticosteroids to protect the brain tissue", "Maintaining oxygen saturation deliberately near one hundred percent", "Withholding coronary angiography regardless of the ECG findings"], "ans": 0, "exp": "Post-ROSC: targeted temperature management (TTM) ในผู้ที่ยัง comatose, หา/รักษาสาเหตุ (coronary angiography ถ้าสงสัย ACS/STEMI), optimize hemodynamics + ventilation (หลีกเลี่ยง hyperoxia — เป้า SpO2 92-98%, และหลีกเลี่ยง hypocapnia). ไม่ใช่ routine steroid"}, {"topic": "PALS - Bradycardia", "q": "An infant has a heart rate of 50/min with poor perfusion, weak pulses, and altered mental status despite effective oxygenation and ventilation. What is the next step?", "choices": ["Deliver synchronized cardioversion at a low energy dose", "Start chest compressions and give epinephrine", "Administer a rapid dose of intravenous adenosine", "Give a normal saline bolus and simply observe", "Apply immediate transcutaneous pacing as first-line"], "ans": 1, "exp": "PALS: bradycardia (HR <60) + poor perfusion 'ทั้งที่' oxygenation/ventilation ดีแล้ว → เริ่ม 'chest compressions' + epinephrine. Bradycardia ในเด็กมักจาก hypoxia จึงเน้น airway/breathing ก่อน. Atropine ใช้กรณี vagal/AV block. Cardioversion/adenosine ใช้ tachyarrhythmia"}, {"topic": "PALS - SVT", "q": "A 6-month-old is alert with adequate perfusion but has a narrow-complex tachycardia of 280/min with no beat-to-beat variability. What is the most appropriate first-line treatment?", "choices": ["Immediate synchronized cardioversion at two joules per kilogram", "Intravenous amiodarone infusion over twenty minutes", "Vagal maneuvers such as applying ice to the face", "A rapid normal saline bolus of twenty milliliters per kilogram", "Oral beta-blocker started at a standard maintenance dose"], "ans": 2, "exp": "Stable SVT ในทารก: เริ่ม vagal maneuvers (ice to face) → IV adenosine ถ้าไม่ได้ผล. Synchronized cardioversion เก็บไว้สำหรับ 'unstable' SVT. HR ~280 + no beat-to-beat variability แยกจาก sinus tachycardia (ซึ่ง <220 ในทารกและมี variability/สาเหตุชัด)"}, {"topic": "Choking - adult", "q": "A conscious adult suddenly cannot speak, cough, or breathe while eating and clutches the throat with both hands. What is the correct immediate management?", "choices": ["Deliver five back blows only and then stop to reassess", "Begin chest compressions immediately despite being conscious", "Perform a blind finger sweep of the mouth to remove food", "Perform abdominal thrusts until relief", "Encourage forceful coughing and take no further action"], "ans": 3, "exp": "Severe airway obstruction (ไอ/พูด/หายใจไม่ได้) ในผู้ใหญ่ conscious → abdominal thrusts (Heimlich) ซ้ำจนหลุดหรือหมดสติ. ถ้าหมดสติ → เริ่ม CPR. 'ไม่' blind finger sweep. ในทารกใช้ back blows + chest thrusts. Mild obstruction (ยังไอได้) → กระตุ้นให้ไอ"}, {"topic": "Acute pulmonary edema", "q": "A patient with known heart failure presents with severe dyspnea, pink frothy sputum, diffuse crackles, and oxygen saturation of 84%. Blood pressure is 180/110 mmHg. What is the most appropriate initial management?", "choices": ["Rapid large-volume crystalloid infusion and head-down positioning", "Immediate synchronized cardioversion regardless of the rhythm", "Nebulized bronchodilators alone with observation for response", "Broad-spectrum antibiotics as the first priority for the crackles", "Oxygen/non-invasive ventilation, IV nitrate, and IV furosemide"], "ans": 4, "exp": "Acute cardiogenic pulmonary edema (SCAPE) ที่ BP สูง: sit up + oxygen/NIV (CPAP/BiPAP), IV vasodilator (nitroglycerin ลด preload/afterload), IV loop diuretic (furosemide), หา precipitant. หลีกเลี่ยงการให้ fluid load. Antibiotic เฉพาะเมื่อมี infection"}, {"topic": "Anaphylaxis", "q": "A patient develops urticaria, lip swelling, wheeze, and hypotension minutes after a bee sting. What is the single most important first-line treatment?", "choices": ["Intramuscular adrenaline into the anterolateral thigh", "Intravenous diphenhydramine given slowly as first-line", "Nebulized salbutamol as the initial definitive therapy", "Intravenous hydrocortisone administered before anything else", "Oral antihistamine with observation for symptom progression"], "ans": 0, "exp": "Anaphylaxis (multisystem หลัง allergen): first-line และ life-saving คือ 'IM adrenaline' ที่ต้นขาด้านหน้า-นอก (ซ้ำได้ q5-15 นาที) + O2/fluid + จัดท่านอน. Antihistamine/steroid/bronchodilator เป็น adjunct ไม่ใช่ first-line. สังเกต biphasic reaction"}, {"topic": "Shock classification", "q": "A trauma patient has cold clammy extremities, tachycardia, narrow pulse pressure, and flat neck veins after major blood loss. Which type of shock is this?", "choices": ["Cardiogenic shock from pump failure", "Hypovolemic shock", "Obstructive shock from tension physiology", "Distributive shock from vasodilation", "Neurogenic shock from spinal injury"], "ans": 1, "exp": "Hemorrhagic (hypovolemic) shock: blood loss → cold/clammy skin, tachycardia, narrow pulse pressure, 'flat' neck veins. Cardiogenic/obstructive มัก distended neck veins. Distributive (septic/anaphylactic) มัก warm early + wide pulse pressure. Neurogenic: hypotension + bradycardia + warm skin"}, {"topic": "Cardiogenic shock", "q": "A patient 2 days after an anterior myocardial infarction has hypotension, cold extremities, pulmonary edema, and elevated jugular venous pressure. What is the underlying type of shock?", "choices": ["Hypovolemic shock from occult gastrointestinal bleeding", "Septic shock from a hospital-acquired infection source", "Cardiogenic shock from left ventricular pump failure", "Anaphylactic shock from a recently administered drug", "Neurogenic shock from an undiagnosed spinal injury"], "ans": 2, "exp": "Cardiogenic shock: post-MI pump failure → hypotension + signs of hypoperfusion + 'pulmonary congestion' + elevated JVP (สูงทั้ง preload). รักษา: revascularization, inotrope/vasopressor, mechanical support; หลีกเลี่ยง fluid overload. ต่างจาก hypovolemic ที่ JVP ต่ำ"}, {"topic": "Obstructive shock - tamponade", "q": "A patient with hypotension has muffled heart sounds, distended neck veins, and pulsus paradoxus after a stab wound to the chest. What is the diagnosis and management?", "choices": ["Tension pneumothorax; immediate needle chest decompression", "Massive hemothorax; large-bore chest tube and thoracotomy", "Myocardial contusion; observation with cardiac monitoring only", "Cardiac tamponade; urgent pericardiocentesis or surgical drainage", "Aortic dissection; blood-pressure control with intravenous drugs"], "ans": 3, "exp": "Cardiac tamponade (Beck triad: hypotension, muffled heart sounds, distended neck veins + pulsus paradoxus) หลัง penetrating chest trauma → 'obstructive shock' ต้อง drainage ด่วน (pericardiocentesis หรือ surgical/thoracotomy). แยกจาก tension pneumothorax (tracheal deviation, absent breath sounds)"}, {"topic": "Sepsis bundle", "q": "A febrile patient has hypotension unresponsive to fluids, tachycardia, and lactate of 4 mmol/L from a urinary source. What are the key early interventions?", "choices": ["Await culture results before starting any antimicrobial therapy", "Low-dose corticosteroids as the single most important first step", "Restrict all intravenous fluids to avoid pulmonary congestion", "Start vasopressors before giving any intravenous fluid at all", "Blood cultures, early broad-spectrum antibiotics, fluids, and vasopressor"], "ans": 4, "exp": "Septic shock (Hour-1 bundle): เจาะ blood culture + lactate, ให้ 'broad-spectrum antibiotics เร็ว', crystalloid 30 mL/kg, และ vasopressor (norepinephrine) ถ้า fluid-refractory เพื่อ MAP ≥65. Source control. ไม่รอ culture; ไม่งด fluid"}, {"topic": "Unstable tachycardia", "q": "A patient has a wide-complex tachycardia at 180/min with hypotension, chest pain, and altered mental status. What is the most appropriate immediate treatment?", "choices": ["Synchronized cardioversion after brief sedation if possible", "Intravenous adenosine rapid push as the first maneuver", "Oral beta-blocker with reassessment in thirty minutes", "Unsynchronized defibrillation regardless of the pulse status", "Observation on telemetry while awaiting cardiology review"], "ans": 0, "exp": "Unstable tachyarrhythmia (มี hypotension/chest pain/altered mental status/shock) → 'synchronized cardioversion' ทันที (± sedation). Adenosine อาจลองใน 'regular narrow-complex' ถ้าไม่ delay. ห้าม unsynchronized shock ในผู้มี pulse (เสี่ยง R-on-T → VF)"}, {"topic": "Symptomatic bradycardia", "q": "A patient has a heart rate of 38/min with hypotension, dizziness, and cool skin. What is the first-line pharmacologic treatment?", "choices": ["Intravenous adenosine to reset the sinus node function", "Intravenous atropine, with pacing if it is ineffective", "A beta-blocker infusion to stabilize the cardiac rhythm", "Synchronized cardioversion at an escalating energy dose", "Intravenous amiodarone loading over the first hour"], "ans": 1, "exp": "Symptomatic bradycardia: first-line 'atropine' 1 mg IV (ซ้ำได้ถึง 3 mg); ถ้าไม่ได้ผล → transcutaneous pacing และ/หรือ dopamine/epinephrine infusion. Adenosine/cardioversion/amiodarone ใช้ tachyarrhythmia. หาสาเหตุ (MI, hyperK, ยา, hypothyroid)"}, {"topic": "Airway - RSI", "q": "A patient with a decreased level of consciousness and no gag reflex is unable to protect the airway. Which intervention definitively secures the airway?", "choices": ["High-flow oxygen delivered through a non-rebreather mask", "Insertion of a nasopharyngeal airway with suctioning", "Endotracheal intubation, often via rapid sequence induction", "Continuous positive airway pressure by a tight face mask", "Placement of the patient in the lateral recovery position"], "ans": 2, "exp": "ผู้ป่วยที่ 'ป้องกัน airway ไม่ได้' (low GCS, no gag, apnea, obstruction) → definitive airway = 'endotracheal intubation' (มัก rapid sequence induction). NPA/oxygen/CPAP เป็น temporizing. Indication intubate: failure to oxygenate/ventilate/protect airway, หรือ anticipated course"}, {"topic": "Capnography", "q": "During CPR, waveform capnography suddenly shows an abrupt sustained rise in end-tidal CO2 from 12 to 40 mmHg. What does this most likely indicate?", "choices": ["Displacement of the endotracheal tube into the esophagus", "Development of a tension pneumothorax", "Onset of severe metabolic acidosis", "Return of spontaneous circulation", "Complete airway obstruction by secretions"], "ans": 3, "exp": "การเพิ่มขึ้นเฉียบพลันและต่อเนื่องของ EtCO2 ระหว่าง CPR (เช่น 10-15 → >35-40) บ่งชี้ 'ROSC' (cardiac output กลับมา → CO2 ถูกส่งไปปอดมากขึ้น). EtCO2 ที่ต่ำมาก (<10) บ่งชี้ CPR คุณภาพต่ำ/prognosis แย่. EtCO2 ตกเป็นศูนย์ทันที = tube หลุด/esophageal"}, {"topic": "Respiratory failure - NIV", "q": "A patient with a COPD exacerbation has severe dyspnea, respiratory acidosis (pH 7.28, PaCO2 65), and is alert enough to cooperate. What is the appropriate ventilatory support?", "choices": ["Immediate endotracheal intubation and mechanical ventilation", "High-flow humidified oxygen alone without pressure support", "Chest physiotherapy and incentive spirometry as first-line", "A helium-oxygen mixture as the definitive ventilatory therapy", "Non-invasive positive pressure ventilation"], "ans": 4, "exp": "COPD exacerbation ที่มี hypercapnic respiratory acidosis (pH <7.35) แต่ผู้ป่วยยัง alert/cooperate และ airway ปลอดภัย → 'NIV (BiPAP)' ลด work of breathing, ลดการ intubate และ mortality. Intubation เมื่อ NIV ล้มเหลว/contraindicated (ซึม, airway protection ไม่ได้, unstable)"}, {"topic": "Acute asthma - ER", "q": "A patient with a severe asthma attack has marked wheeze, accessory muscle use, and inability to speak full sentences. What is the appropriate initial emergency treatment?", "choices": ["Nebulized salbutamol/ipratropium, systemic steroid, and oxygen", "Oral antibiotics and a chest radiograph before any bronchodilator", "Immediate intubation for every patient with a severe attack", "Intravenous beta-blocker to reduce the heart rate first", "A sedative to relieve the anxiety associated with dyspnea"], "ans": 0, "exp": "Severe asthma exacerbation: repeated inhaled/nebulized SABA + ipratropium + systemic corticosteroid + controlled O2 (SpO2 93-95%); เพิ่ม IV magnesium sulfate ในรายรุนแรง. Intubation เฉพาะ impending respiratory failure. หลีกเลี่ยง sedative/beta-blocker/non-indicated antibiotic"}, {"topic": "Tension pneumothorax", "q": "A ventilated patient acutely develops hypotension, high airway pressures, absent breath sounds on one side, and tracheal deviation to the opposite side. What is the immediate management?", "choices": ["Urgent chest radiograph before any intervention is performed", "Immediate needle or finger thoracostomy", "Increase the ventilator tidal volume to overcome the resistance", "Rapid intravenous fluid bolus and vasopressor infusion", "Bronchoscopy to relieve a presumed mucus plug obstruction"], "ans": 1, "exp": "Tension pneumothorax เป็น 'clinical diagnosis' (ไม่รอ CXR): hypotension + absent breath sounds + tracheal deviation + distended neck veins, worse ด้วย positive-pressure ventilation → decompress ทันที (needle/finger thoracostomy ที่ 2nd ICS MCL หรือ 4th-5th ICS AAL) แล้วใส่ chest tube"}, {"topic": "Aortic dissection", "q": "A hypertensive man has sudden severe tearing chest pain radiating to the back, a blood-pressure difference between the two arms, and a widened mediastinum on chest radiograph. What is the diagnosis?", "choices": ["ST-elevation myocardial infarction", "Massive pulmonary embolism", "Acute aortic dissection", "Tension pneumothorax", "Esophageal rupture (Boerhaave)"], "ans": 2, "exp": "Acute aortic dissection: sudden 'tearing' chest/back pain, inter-arm BP/pulse difference, widened mediastinum, ± aortic regurgitation/tamponade. วินิจฉัยด้วย CT angiography. รักษา: ลด BP + heart rate (IV beta-blocker เช่น esmolol/labetalol ก่อน vasodilator); type A → surgery, type B → medical/endovascular"}, {"topic": "Massive PE", "q": "A patient with sudden dyspnea and pleuritic chest pain becomes hypotensive with a heart rate of 130/min; echocardiography shows right ventricular strain. What is the appropriate treatment for high-risk pulmonary embolism?", "choices": ["Anticoagulation withheld until a CT scan is fully reported", "Intravenous beta-blocker to control the sinus tachycardia", "A large fluid bolus followed by immediate discharge planning", "Systemic thrombolysis plus anticoagulation", "Inhaled bronchodilators as the primary definitive therapy"], "ans": 3, "exp": "High-risk (massive) PE = hemodynamic instability (hypotension/shock) + RV strain → 'systemic thrombolysis' (หรือ catheter/surgical embolectomy ถ้า contraindicated) + anticoagulation. Non-high-risk PE รักษาด้วย anticoagulation. เริ่ม anticoagulation ได้ตั้งแต่สงสัยสูงถ้า bleeding risk ต่ำ"}, {"topic": "Syncope red flags", "q": "A 68-year-old man had syncope during exertion. He has a systolic ejection murmur and a family history of sudden cardiac death. What is the most appropriate approach?", "choices": ["Reassurance and discharge because syncope is usually benign", "Prescription of a beta-blocker without further investigation", "Tilt-table testing as the single most important next step", "Empiric antiepileptic therapy for a presumed seizure disorder", "Cardiac evaluation for a cardiac cause"], "ans": 4, "exp": "Exertional syncope + murmur + family history sudden death = red flags ของ 'cardiac' syncope (aortic stenosis, HCM, arrhythmia/long QT) → ต้อง ECG + echocardiography และประเมินความเสี่ยง. ต่างจาก vasovagal (มี prodrome, trigger, recovery เร็ว, benign) ที่ไม่ต้อง workup มาก"}, {"topic": "STEMI - reperfusion", "q": "A man has 40 minutes of crushing chest pain and ECG shows 2 mm ST elevation in leads V2-V4 at a hospital with a catheterization laboratory. What is the best reperfusion strategy?", "choices": ["Primary percutaneous coronary intervention within 90 minutes", "Fibrinolytic therapy given only after troponin confirmation", "Oral antiplatelet therapy alone with outpatient follow-up", "Elective angiography scheduled within the next few days", "High-flow oxygen and observation until the pain resolves"], "ans": 0, "exp": "Anterior STEMI ที่โรงพยาบาลทำ PCI ได้ → 'primary PCI ภายใน 90 นาที' (ดีกว่า fibrinolytic เมื่อทำได้ทัน). ถ้า PCI ไม่ทันใน 120 นาที → fibrinolytic ภายใน 30 นาที. ให้ ASA + P2Y12 + anticoagulant + statin; ไม่รอ troponin ในการตัดสิน reperfusion"}, {"topic": "NSTEMI", "q": "A patient with chest pain has ST depression and elevated troponin but no ST elevation, and is hemodynamically stable. What is the appropriate management?", "choices": ["Immediate fibrinolytic therapy identical to STEMI treatment", "Dual antiplatelet, anticoagulation, and risk-based early invasive care", "Discharge home once a single troponin returns to normal", "Beta-blocker alone with no antiplatelet or anticoagulant", "Emergency pericardiocentesis to relieve the chest pain"], "ans": 1, "exp": "NSTE-ACS (NSTEMI): ST depression/T inversion + troponin สูง, no ST elevation → medical therapy (ASA + P2Y12 + anticoagulant + anti-ischemic) + risk-stratify (GRACE/TIMI) → early invasive (angiography) ในผู้เสี่ยงสูง. 'ไม่ให้ fibrinolytic' ใน NSTE-ACS (ไม่มีประโยชน์)"}, {"topic": "Torsades de pointes", "q": "A patient with a prolonged QT interval develops a polymorphic ventricular tachycardia with a twisting-around-the-baseline pattern but has a pulse. What is the specific treatment?", "choices": ["Intravenous adenosine rapid push", "Oral amiodarone loading dose", "Intravenous magnesium sulfate", "Intravenous calcium gluconate", "Intravenous digoxin loading dose"], "ans": 2, "exp": "Torsades de pointes (polymorphic VT with long QT): specific treatment = 'IV magnesium sulfate'; แก้ electrolyte (K, Mg), หยุดยา QT-prolonging, overdrive pacing/isoproterenol ถ้า recurrent. Pulseless torsades → defibrillate. Amiodarone/procainamide หลีกเลี่ยง (ยืด QT)"}, {"topic": "SVT - stable", "q": "A young adult has a regular narrow-complex tachycardia at 190/min, is alert, and has stable blood pressure. After vagal maneuvers fail, what is the next step?", "choices": ["Immediate synchronized cardioversion under sedation", "Intravenous amiodarone infusion over one hour", "Oral digoxin with reassessment the next day", "Intravenous adenosine by rapid push", "Unsynchronized defibrillation at maximum energy"], "ans": 3, "exp": "Stable SVT (regular narrow-complex): vagal maneuvers → 'IV adenosine' (rapid push 6 mg แล้ว 12 mg); ถ้าไม่ได้ผล/recurrent ใช้ CCB/beta-blocker. Cardioversion เก็บไว้สำหรับ unstable. Adenosine half-life สั้นมาก จึงต้อง push เร็วตามด้วย flush"}, {"topic": "Hyperkalemic arrest", "q": "A hemodialysis patient in cardiac arrest has a widened QRS progressing to a sine-wave pattern before the arrest, and potassium is 8.5 mmol/L. Besides CPR, what is the priority drug?", "choices": ["Immediate high-dose intravenous insulin without any glucose", "Rapid infusion of a large volume of potassium-containing fluid", "Intravenous adenosine to convert the widened-complex rhythm", "Empiric intravenous amiodarone as the first-line antiarrhythmic", "Intravenous calcium to stabilize the myocardium"], "ans": 4, "exp": "Hyperkalemia เป็น reversible cause ของ arrest (dialysis patient, wide QRS/sine wave): ให้ 'IV calcium' เพื่อ stabilize myocardium ทันที + insulin/glucose, salbutamol, bicarbonate (shift) + dialysis (remove). Calcium เป็นลำดับแรกในภาวะฉุกเฉินที่มี ECG changes"}, {"topic": "Maternal cardiac arrest", "q": "A woman at 34 weeks of gestation goes into cardiac arrest. Along with high-quality CPR, which additional maneuver improves resuscitation?", "choices": ["Manual left uterine displacement to relieve aortocaval compression", "Immediate delivery only after 30 minutes of failed resuscitation", "Placing the patient fully supine with legs elevated high", "Withholding defibrillation because of the pregnancy", "Routine tocolytics to relax the uterus during compressions"], "ans": 0, "exp": "Maternal arrest (>20 wk): ทำ 'manual left uterine displacement' (หรือเอียงตัว) เพื่อลด aortocaval compression จาก gravid uterus; defibrillation/ยาให้ปกติ. พิจารณา 'perimortem cesarean delivery' ภายใน ~5 นาทีถ้า ROSC ไม่กลับ (ช่วยทั้งแม่และทารก). ไม่วางท่า supine ราบ"}, {"topic": "Accidental hypothermia arrest", "q": "A patient rescued from cold water is in cardiac arrest with a core temperature of 28°C. What principle guides resuscitation?", "choices": ["Declare death immediately based on the cold, fixed pupils", "Continue CPR and rewarm", "Give repeated adrenaline at the normal short intervals", "Rapidly rewarm only the limbs before starting compressions", "Defibrillate repeatedly regardless of the core temperature"], "ans": 1, "exp": "Severe hypothermic arrest: prognosis อาจดีแม้ดูเหมือนเสียชีวิต → 'not dead until warm and dead' — ทำ CPR + active core rewarming ต่อ. ในอุณหภูมิต่ำมาก (<30°C) ลด/เว้นการให้ยาและจำกัด defibrillation จนอุ่นขึ้น (heart ตอบสนองยา/shock ไม่ดีตอนเย็นมาก). จัดการนุ่มนวลกัน VF"}, {"topic": "Beta-blocker overdose", "q": "A patient with bradycardia and hypotension refractory to atropine after a beta-blocker overdose is not improving. Which antidote is most specific?", "choices": ["Intravenous adenosine to reset the sinus node", "Intravenous magnesium sulfate as first-line therapy", "High-dose glucagon", "A rapid crystalloid bolus as the definitive treatment", "Intravenous amiodarone to stabilize the heart rhythm"], "ans": 2, "exp": "Beta-blocker (และ CCB) overdose ที่ refractory bradycardia/hypotension: 'glucagon' (เพิ่ม cAMP ข้าม beta-receptor) + high-dose insulin-euglycemia therapy, calcium (โดยเฉพาะ CCB), vasopressors, pacing, lipid emulsion ในรายรุนแรง. Atropine มักไม่พอ"}, {"topic": "Digoxin toxicity", "q": "A patient on digoxin presents with nausea, confusion, yellow-tinged vision, bradycardia, and hyperkalemia. Which is the specific antidote for life-threatening toxicity?", "choices": ["Intravenous calcium to correct the hyperkalemia", "Oral activated charcoal as the only intervention", "Intravenous adenosine to control the bradycardia", "Digoxin-specific antibody fragments", "High-dose intravenous magnesium as the antidote"], "ans": 3, "exp": "Digoxin toxicity (GI + visual 'yellow-green halos' + arrhythmia + hyperkalemia ซึ่งบ่ง severity): antidote คือ 'digoxin-specific Fab antibody' ในรายรุนแรง/life-threatening arrhythmia/hyperkalemia. 'หลีกเลี่ยง IV calcium' ใน digoxin toxicity (ทฤษฎี stone heart). แก้ electrolyte, atropine สำหรับ bradycardia"}, {"topic": "Hypertensive emergency", "q": "A patient has blood pressure 220/130 mmHg with acute headache, confusion, and papilledema (hypertensive encephalopathy). What is the appropriate management?", "choices": ["Rapid normalization of blood pressure to normal within minutes", "Sublingual short-acting nifedipine to drop the pressure quickly", "Oral antihypertensives with discharge and next-week follow-up", "No treatment because the patient is chronically hypertensive", "Controlled IV antihypertensive, lowering BP gradually"], "ans": 4, "exp": "Hypertensive emergency (severe HT + acute end-organ damage เช่น encephalopathy): ลด BP แบบ 'ควบคุม' ด้วย IV titratable agent (labetalol, nicardipine, nitroprusside) ~10-25% ในชั่วโมงแรก แล้วค่อยๆ ลด (เร็วเกินเสี่ยง ischemia). หลีกเลี่ยง sublingual nifedipine (ลดเร็วเกินคุม). ข้อยกเว้น: aortic dissection/stroke มีเป้าเฉพาะ"}, {"topic": "Termination of resuscitation", "q": "During prolonged out-of-hospital arrest, which finding is most associated with poor outcome and informs decisions about continuing resuscitation?", "choices": ["Persistently very low end-tidal CO2 after 20 minutes of good CPR", "An initial shockable rhythm that responded to early defibrillation", "A witnessed arrest with immediate bystander CPR provided", "Return of spontaneous circulation achieved during transport", "A short downtime before advanced life support arrived on scene"], "ans": 0, "exp": "EtCO2 ที่ต่ำมากค้าง (<10 mmHg) หลัง CPR คุณภาพดี ~20 นาที + intubated สัมพันธ์กับ prognosis ที่แย่มาก และใช้ประกอบการตัดสินใจร่วมกับปัจจัยอื่น. ปัจจัยพยากรณ์ดี: witnessed arrest, bystander CPR, shockable rhythm, ROSC ระหว่างช่วย"}, {"topic": "Foreign body - infant", "q": "A 9-month-old suddenly chokes and cannot cry or breathe while conscious. What is the correct maneuver?", "choices": ["Standing abdominal thrusts (the Heimlich maneuver)", "Five back blows alternating with five chest thrusts", "A blind finger sweep to remove the obstructing object", "Immediate chest compressions while the infant is conscious", "Positioning upright and simply waiting for spontaneous relief"], "ans": 1, "exp": "Severe airway obstruction ในทารก (<1 ปี) ที่ยัง conscious: '5 back blows + 5 chest thrusts' สลับกัน (ไม่ใช้ abdominal thrusts ในทารก — เสี่ยง organ injury). ถ้าหมดสติ → เริ่ม CPR + มองในปากก่อนช่วยหายใจ (ไม่ blind sweep)"}, {"topic": "Oxygen delivery", "q": "A hypoxemic patient needs a high inspired oxygen concentration during acute resuscitation. Which device delivers the highest FiO2 for a spontaneously breathing patient?", "choices": ["Standard nasal cannula at two liters per minute", "Simple face mask at a low flow rate", "Non-rebreather mask with a reservoir bag", "Venturi mask set to the 24 percent setting", "Nasal cannula humidified at one liter per minute"], "ans": 2, "exp": "สำหรับผู้ป่วยหายใจเองที่ต้องการ FiO2 สูง: 'non-rebreather mask with reservoir' ให้ได้สูงสุด (~60-90%). Nasal cannula/simple mask/Venturi ให้ FiO2 ต่ำกว่าและควบคุมได้ (Venturi เหมาะเมื่อต้องคุม FiO2 แน่นอนเช่น COPD). High-flow nasal cannula ก็ให้สูงได้แต่ไม่อยู่ในตัวเลือก"}, {"topic": "Cardiac tamponade - workup", "q": "A patient with pericardial effusion develops rising heart rate, falling blood pressure, and pulsus paradoxus. Which bedside investigation best confirms tamponade physiology?", "choices": ["A 12-lead ECG showing diffuse ST elevation and PR depression", "A chest radiograph showing an enlarged cardiac silhouette", "Serum troponin measurement to detect myocardial injury", "Bedside echocardiography showing diastolic chamber collapse", "Central venous pressure trend measured over several hours"], "ans": 3, "exp": "Cardiac tamponade: 'bedside echocardiography' เป็น investigation ที่ยืนยันได้เร็ว — เห็น pericardial effusion + diastolic collapse ของ RA/RV + IVC plethora. Clinical: Beck triad + pulsus paradoxus. รักษา: pericardiocentesis. ECG/CXR ช่วยสนับสนุนแต่ไม่ยืนยัน physiology"}, {"topic": "Massive hemoptysis", "q": "A patient coughs up more than 500 mL of blood in 24 hours and is becoming hypoxemic. What is the priority in management?", "choices": ["Immediately give a large dose of an oral antitussive agent", "Start systemic thrombolysis to dissolve airway clots", "Perform urgent full anticoagulation to prevent embolism", "Discharge with outpatient bronchoscopy in a few days", "Protect the airway and position the bleeding lung dependent"], "ans": 4, "exp": "Massive hemoptysis เป็น emergency — คนตายจาก 'asphyxiation' ไม่ใช่ exsanguination. Priority: airway protection + วางผู้ป่วยให้ปอดข้างที่เลือดออกอยู่ 'ด้านล่าง' (กันเลือดไหลข้ามไปปอดดี), O2, resuscitate, แล้ว localize (bronchoscopy/CT) + control (bronchial artery embolization/surgery). ห้าม anticoagulant/thrombolytic"}, {"topic": "Spontaneous pneumothorax", "q": "A tall thin young man has sudden pleuritic chest pain and dyspnea; examination shows decreased breath sounds and hyperresonance on one side, and he is stable. What is the diagnosis?", "choices": ["Primary spontaneous pneumothorax", "Acute myocardial infarction", "Community-acquired pneumonia", "Pulmonary thromboembolism", "Acute pericarditis with effusion"], "ans": 0, "exp": "Primary spontaneous pneumothorax: ชายรูปร่างสูงผอม, sudden pleuritic pain + dyspnea, decreased breath sounds + hyperresonance ข้างเดียว. รักษาตามขนาด/อาการ: observation/aspiration/chest tube. ถ้ามี hypotension + tracheal deviation = tension → decompress ทันที"}, {"topic": "ARDS", "q": "A patient with sepsis develops acute severe hypoxemia with bilateral infiltrates not explained by heart failure, and a low PaO2/FiO2 ratio. What is a key ventilator strategy?", "choices": ["High tidal volume ventilation to fully recruit the lungs", "Low tidal volume lung-protective ventilation", "Routine early tracheostomy in the first 24 hours", "Permissive hyperoxia targeting a PaO2 above 150", "Withholding PEEP to reduce the airway pressures"], "ans": 1, "exp": "Acute respiratory distress syndrome (ARDS): acute hypoxemia + bilateral infiltrates ไม่ใช่จาก cardiogenic + low P/F ratio (Berlin criteria). Ventilator: 'low tidal volume (~6 mL/kg predicted body weight) lung-protective' + adequate PEEP + plateau pressure <30, prone positioning ในรายรุนแรง. รักษาสาเหตุ (sepsis)"}, {"topic": "Right ventricular MI", "q": "A patient with an inferior STEMI develops hypotension after receiving nitroglycerin. ECG right-sided leads show ST elevation in V4R. What is the appropriate management?", "choices": ["A large dose of intravenous nitrate to relieve the pain", "Immediate diuresis with high-dose intravenous furosemide", "Cautious intravenous fluid loading and avoiding nitrates", "Beta-blocker infusion to slow the compensatory tachycardia", "Routine morphine boluses to reduce the myocardial demand"], "ans": 2, "exp": "Right ventricular infarction (inferior STEMI + ST elevation V4R): RV preload-dependent → 'ให้ fluid' และ 'หลีกเลี่ยง nitrate/diuretic/morphine' (ลด preload → hypotension รุนแรง). Reperfusion + inotrope ถ้าจำเป็น. Nitroglycerin ทำให้ hypotension ใน RV MI เป็นเบาะแสสำคัญ"}, {"topic": "Cricothyrotomy", "q": "In a 'cannot intubate, cannot oxygenate' emergency with a completely obstructed upper airway, what is the definitive rescue procedure in an adult?", "choices": ["Repeated attempts at oral endotracheal intubation", "Insertion of a nasopharyngeal airway with suction", "Bag-mask ventilation continued until help arrives", "Surgical cricothyroidotomy to establish an emergency airway", "High-flow nasal oxygen while awaiting spontaneous breathing"], "ans": 3, "exp": "'Cannot intubate, cannot oxygenate' (CICO) ในผู้ใหญ่ที่ upper airway อุดสนิท → emergency 'surgical cricothyroidotomy' (front-of-neck access) เป็น definitive rescue. ในเด็กเล็กใช้ needle cricothyrotomy + jet ventilation. ต้องทำเร็วเพื่อป้องกัน hypoxic brain injury"}, {"topic": "Acute limb ischemia", "q": "A patient with atrial fibrillation develops a sudden cold, pale, pulseless, painful leg with paresthesia. What is the appropriate emergency management?", "choices": ["Elevation of the limb with ice packs and observation", "Immediate below-knee amputation without imaging", "Warm compresses and outpatient vascular clinic referral", "Compression bandaging to reduce the limb swelling", "Systemic heparin and urgent vascular revascularization"], "ans": 4, "exp": "Acute limb ischemia (มัก embolism จาก AF): 6 P's (pain, pallor, pulseless, paresthesia, paralysis, poikilothermia) → emergency 'anticoagulate (heparin)' + urgent revascularization (embolectomy/thrombolysis) เพื่อ salvage limb. Motor/sensory loss = advanced (threatened limb). ห้ามยกสูง/ประคบเย็น"}, {"topic": "Flash pulmonary edema cause", "q": "A patient with recurrent sudden ('flash') pulmonary edema and severe hypertension is found to have an abdominal bruit. Which underlying cause should be considered?", "choices": ["Bilateral renal artery stenosis", "Primary hypothyroidism", "Chronic obstructive pulmonary disease", "Iron deficiency anemia", "Benign essential tremor"], "ans": 0, "exp": "Recurrent 'flash' pulmonary edema + severe/resistant hypertension + abdominal bruit → นึกถึง 'bilateral renal artery stenosis' (Pickering syndrome). Acute management เหมือน pulmonary edema (NIV, nitrate, diuretic) แต่ต้องหา/แก้สาเหตุ. ACEI/ARB ระวังใน bilateral RAS (เสี่ยง AKI)"}, {"topic": "Bystander CPR", "q": "A bystander witnesses an adult collapse and is untrained in rescue breathing. What should the emergency dispatcher advise?", "choices": ["Rescue breaths first, then start chest compressions", "Compression-only CPR at 100-120 per minute", "Wait for the ambulance rather than attempting any CPR", "Check the blood pressure before beginning compressions", "Give abdominal thrusts in case of airway obstruction"], "ans": 1, "exp": "สำหรับ bystander ที่ไม่ได้ฝึก rescue breathing → 'compression-only (hands-only) CPR' ต่อเนื่องจนกว่าความช่วยเหลือมาถึง — ง่าย ทำได้จริง และเพิ่ม survival. Trained rescuer ทำ 30:2. เริ่มทันทีเมื่อ unresponsive + ไม่หายใจปกติ (agonal gasp = arrest)"}, {"topic": "Opioid-associated arrest", "q": "An unresponsive person with pinpoint pupils and very slow shallow breathing is found with drug paraphernalia; a pulse is present. What is the priority intervention?", "choices": ["Immediate chest compressions despite the pulse", "A rapid intravenous crystalloid fluid bolus", "Support ventilation and give naloxone", "Intravenous flumazenil to reverse the sedation", "Oral activated charcoal to bind the drug"], "ans": 2, "exp": "Opioid toxidrome (pinpoint pupils + respiratory depression + CNS depression) with pulse → priority คือ support 'ventilation' (airway/breathing) + 'naloxone'. ถ้า 'ไม่มี pulse' → เริ่ม CPR ตามปกติ. ระวัง re-sedation (naloxone half-life สั้น). Flumazenil = benzodiazepine antidote"}, {"topic": "Wide-complex tachycardia", "q": "A 70-year-old with prior myocardial infarction has a regular wide-complex tachycardia at 160/min and is stable. Which is the safest assumption and treatment?", "choices": ["Assume SVT with aberrancy and give a calcium channel blocker", "Give intravenous verapamil empirically to slow conduction", "Withhold all therapy and observe on telemetry only", "Treat as ventricular tachycardia", "Immediately defibrillate the patient with an unsynchronized shock"], "ans": 3, "exp": "Wide-complex tachycardia ในผู้สูงอายุที่มีประวัติ structural heart disease/MI → assume 'VT' จนกว่าจะพิสูจน์เป็นอื่น (ปลอดภัยกว่า). Stable VT: antiarrhythmic (amiodarone/procainamide) หรือ elective cardioversion; unstable → synchronized cardioversion. 'หลีกเลี่ยง verapamil' (อันตรายถ้าเป็น VT)"}, {"topic": "WPW with AF", "q": "A patient with Wolff-Parkinson-White syndrome develops atrial fibrillation with a very rapid, irregular wide-complex rhythm. Which drug must be avoided?", "choices": ["Procainamide given by slow intravenous infusion", "Synchronized electrical cardioversion if unstable", "Ibutilide used to chemically cardiovert the rhythm", "Immediate defibrillation if the patient deteriorates to arrest", "AV nodal blockers such as adenosine, verapamil, or digoxin"], "ans": 4, "exp": "WPW + AF (rapid irregular wide-complex): 'ห้ามใช้ AV nodal blockers' (adenosine, verapamil, diltiazem, digoxin, beta-blocker) เพราะจะดันการนำผ่าน accessory pathway → เร่ง ventricular rate → VF. ใช้ procainamide/ibutilide หรือ cardioversion (unstable). ถ้า arrest → defibrillate"}, {"topic": "Third-degree AV block", "q": "An elderly patient has syncope with a heart rate of 35/min; ECG shows complete dissociation between P waves and QRS complexes. What is the definitive treatment?", "choices": ["Transcutaneous pacing then a permanent pacemaker", "Intravenous adenosine to restore AV conduction", "Synchronized cardioversion at a low energy level", "A beta-blocker to regularize the ventricular rhythm", "Observation alone because it usually resolves quickly"], "ans": 0, "exp": "Complete (third-degree) AV block: P และ QRS แยกจากกัน, symptomatic bradycardia → atropine มักไม่ได้ผล (block อยู่ใต้ AV node) → 'transcutaneous/transvenous pacing' เป็น bridge แล้ว 'permanent pacemaker' เป็น definitive. หา reversible causes (MI, ยา, hyperK)"}, {"topic": "Norepinephrine", "q": "In septic shock that remains hypotensive despite adequate fluid resuscitation, which vasopressor is recommended first-line?", "choices": ["Dopamine", "Norepinephrine", "Phenylephrine", "Dobutamine", "Isoproterenol"], "ans": 1, "exp": "Septic shock ที่ fluid-refractory: vasopressor first-line = 'norepinephrine' (เป้า MAP ≥65). เพิ่ม vasopressin/epinephrine ถ้าไม่พอ. Dobutamine เพิ่มเมื่อมี myocardial dysfunction/persistent hypoperfusion. Dopamine เพิ่ม arrhythmia. (Surviving Sepsis)"}, {"topic": "Pericarditis", "q": "A young man has sharp pleuritic chest pain that is worse lying flat and better sitting forward, with a friction rub and diffuse ST elevation with PR depression. What is the diagnosis and first-line treatment?", "choices": ["Acute STEMI; emergency coronary reperfusion", "Aortic dissection; blood-pressure and rate control", "Acute pericarditis; NSAIDs plus colchicine", "Pulmonary embolism; systemic anticoagulation", "Costochondritis; simple reassurance and analgesia"], "ans": 2, "exp": "Acute pericarditis: positional pleuritic pain (แย่ตอนนอนราบ ดีขึ้นเมื่อโน้มไปหน้า), friction rub, 'diffuse' ST elevation + PR depression (ต่างจาก STEMI ที่ localized + reciprocal). สาเหตุมัก viral/idiopathic. รักษา NSAID + colchicine. เฝ้าระวัง effusion/tamponade"}, {"topic": "Commotio cordis", "q": "A teenage baseball player collapses immediately after being struck in the chest by a ball and is found in ventricular fibrillation. What is the most important immediate intervention?", "choices": ["Immediate pericardiocentesis for tamponade", "Needle decompression for tension pneumothorax", "Intravenous beta-blocker to stabilize the rhythm", "Prompt defibrillation with CPR", "Corticosteroids for myocardial inflammation"], "ans": 3, "exp": "Commotio cordis: blunt chest impact ในช่วง vulnerable ของ T wave → VF ในหัวใจปกติ. Immediate 'defibrillation + CPR' คือ key (survival ขึ้นกับ early defibrillation). ไม่ใช่ structural injury — จึงไม่ใช่ tamponade/pneumothorax เป็นหลัก"}, {"topic": "Intraosseous access", "q": "During resuscitation of a child in shock, two attempts at peripheral intravenous access fail. What is the recommended next route for fluids and drugs?", "choices": ["Repeated peripheral IV attempts for another ten minutes", "Subcutaneous fluid administration", "Oral rehydration through a nasogastric tube", "Wait for a central line to be placed electively", "Intraosseous access"], "ans": 4, "exp": "เมื่อ IV access ล้มเหลวในภาวะฉุกเฉิน (เด็กหรือผู้ใหญ่) → 'intraosseous (IO) access' เป็นทางเลือกที่รวดเร็วและเชื่อถือได้ ให้ fluid/ยา/เลือดได้ทุกชนิด. เป็นมาตรฐานใน PALS/ACLS เมื่อ IV ยาก. ไม่รอ central line ในภาวะวิกฤต"}, {"topic": "Papillary muscle rupture", "q": "Several days after an inferior myocardial infarction, a patient develops sudden pulmonary edema, hypotension, and a new loud holosystolic murmur. What is the most likely complication?", "choices": ["Acute mitral regurgitation from papillary muscle rupture", "Ventricular free-wall rupture with immediate tamponade", "Reinfarction of the anterior myocardial wall", "Acute pericarditis in the post-infarction period", "Left ventricular aneurysm formation over the scar"], "ans": 0, "exp": "Post-MI mechanical complication (~3-7 วัน): acute mitral regurgitation จาก 'papillary muscle rupture' → sudden pulmonary edema + new holosystolic murmur + cardiogenic shock. ต้อง echocardiogram + emergency surgery (± mechanical support). ต่างจาก VSD (murmur + thrill), free-wall rupture (tamponade/PEA)"}, {"topic": "Adenosine caution", "q": "Before giving adenosine for supraventricular tachycardia, in which patient should it be used with particular caution or avoided?", "choices": ["A young patient with a structurally normal heart", "A patient with severe reactive airway disease", "A patient who has stable blood pressure and is alert", "A patient in whom vagal maneuvers were already tried", "A patient with a regular narrow-complex tachycardia"], "ans": 1, "exp": "Adenosine อาจกระตุ้น 'bronchospasm' → ใช้ระวัง/หลีกเลี่ยงใน severe asthma/reactive airway disease. ผู้ป่วยควรได้รับคำเตือนถึงความรู้สึกไม่สบายชั่วครู่ (flushing, chest tightness, impending doom) เพราะ half-life สั้นมาก. หลีกเลี่ยงร่วมกับ dipyridamole/heart transplant (เพิ่มฤทธิ์)"}, {"topic": "Cardiogenic shock support", "q": "A patient in refractory cardiogenic shock after massive myocardial infarction is not responding to inotropes and vasopressors. What advanced option may be considered?", "choices": ["High-dose diuretics to offload the failing ventricle", "Immediate systemic thrombolysis regardless of the cause", "Mechanical circulatory support", "Beta-blocker infusion to reduce the myocardial workload", "Large-volume fluid resuscitation to raise the pressure"], "ans": 2, "exp": "Refractory cardiogenic shock: พิจารณา 'mechanical circulatory support' (intra-aortic balloon pump, Impella, VA-ECMO) เป็น bridge ร่วมกับ revascularization. Beta-blocker/large fluid load อันตรายในภาวะนี้. Diuretic ช่วย congestion แต่ไม่แก้ shock"}, {"topic": "Electrical storm", "q": "A patient with an implantable defibrillator has three or more episodes of ventricular tachycardia within 24 hours. Besides antiarrhythmics, which additional therapy is often helpful?", "choices": ["Withdrawal of all antiarrhythmic drugs immediately", "High-dose inhaled beta-agonists to support the heart", "Routine emergency pericardiocentesis for all cases", "Beta-blockade and sedation", "Aggressive intravenous fluid loading to raise output"], "ans": 3, "exp": "Electrical storm (≥3 VT/VF ใน 24 ชม.): จัดการด้วย antiarrhythmic (amiodarone) + 'beta-blockade' (sympathetic drive สำคัญ) + sedation, แก้ triggers (ischemia, electrolyte), device reprogramming; ราย refractory พิจารณา deep sedation/ablation. Beta-blocker เป็นเสาหลักที่มักถูกลืม"}, {"topic": "Second-degree AV block Mobitz II", "q": "An asymptomatic patient has intermittent non-conducted P waves with a constant PR interval on the conducted beats (Mobitz type II). What is the concern and management?", "choices": ["A benign finding that never requires any intervention", "Immediate synchronized cardioversion to restore conduction", "Adenosine to improve atrioventricular nodal conduction", "Reassurance identical to that for Mobitz type I block", "High risk of progression to complete block"], "ans": 4, "exp": "Mobitz II (constant PR + dropped beats, block ที่ His-Purkinje) เสี่ยงลุกลามเป็น complete heart block เฉียบพลัน → มัก indication ของ 'pacemaker' (ต่างจาก Mobitz I/Wenckebach ที่ PR ยาวขึ้นเรื่อยๆ, block ที่ AV node, มัก benign). ประเมิน reversible causes"}, {"topic": "PE risk stratification", "q": "A hemodynamically stable patient with confirmed pulmonary embolism has right ventricular dysfunction on echocardiography and elevated troponin. How is this classified?", "choices": ["Intermediate risk pulmonary embolism", "Low-risk pulmonary embolism suitable for discharge", "High-risk (massive) pulmonary embolism with shock", "Chronic thromboembolic pulmonary hypertension", "A pulmonary embolism that has fully resolved"], "ans": 0, "exp": "PE ที่ 'stable' (ไม่มี hypotension) แต่มี RV dysfunction + biomarker (troponin/BNP) สูง = 'intermediate/submassive' risk → anticoagulation + close monitoring; พิจารณา reperfusion ถ้า deteriorate. High-risk = hemodynamic instability (systemic thrombolysis). Low-risk = ไม่มี RV strain/biomarker (อาจ outpatient)"}, {"topic": "Dobutamine indication", "q": "A patient with cardiogenic pulmonary edema has low cardiac output and poor perfusion but a borderline blood pressure. Which agent primarily improves contractility and cardiac output?", "choices": ["Phenylephrine", "Dobutamine", "Furosemide", "Norepinephrine", "Adenosine"], "ans": 1, "exp": "Dobutamine (beta-1 agonist, inotrope) เพิ่ม contractility/cardiac output ในภาวะ low-output heart failure/cardiogenic shock ที่ perfusion แย่. ถ้า BP ต่ำมากอาจต้องคู่กับ vasopressor (norepinephrine). Phenylephrine เป็น pure vasoconstrictor (ไม่เพิ่ม contractility). Furosemide จัดการ congestion"}, {"topic": "Agonal breathing", "q": "A collapsed patient is unresponsive with occasional irregular gasping breaths and no definite pulse. How should this be interpreted?", "choices": ["Normal breathing that rules out cardiac arrest", "A seizure that requires benzodiazepine treatment", "Agonal gasps indicating cardiac arrest", "Simple fainting that will resolve spontaneously", "Hyperventilation requiring rebreathing into a bag"], "ans": 2, "exp": "Agonal breathing (gasping) หลัง collapse = สัญญาณของ 'cardiac arrest' ไม่ใช่การหายใจปกติ → เริ่ม CPR ทันที. เป็นสาเหตุที่ arrest ถูกมองข้ามบ่อย. ถ้า unresponsive + ไม่หายใจปกติ (รวม agonal) → treat as arrest"}, {"topic": "Brugada / channelopathy", "q": "A young man with a family history of sudden death has syncope; ECG shows coved ST elevation in V1-V2 (type 1 Brugada pattern). What is the definitive management to prevent sudden death?", "choices": ["Lifelong beta-blocker therapy as the definitive treatment", "Radiofrequency ablation of the sinoatrial node", "A permanent pacemaker for the bradycardic episodes", "Implantable cardioverter-defibrillator in appropriate patients", "Long-term oral anticoagulation to prevent embolism"], "ans": 3, "exp": "Brugada syndrome (sodium channelopathy, coved type-1 ST elevation V1-V2) เสี่ยง VF/sudden death — โดยเฉพาะผู้มี syncope/aborted arrest/family history → 'ICD' เป็น definitive. หลีกเลี่ยงไข้สูง/ยาบางชนิด (ตาม brugadadrugs). ระวังในชายไทย/เอเชีย ('Lai Tai' sudden unexplained nocturnal death)"}, {"topic": "Neurogenic shock", "q": "A patient with a high cervical spinal cord injury has hypotension with paradoxical bradycardia and warm, dry skin. What is the underlying mechanism?", "choices": ["Massive blood loss causing compensatory vasoconstriction", "Cardiac pump failure causing pulmonary congestion", "Systemic infection causing distributive vasodilation", "Tension physiology obstructing venous return to the heart", "Loss of sympathetic tone causing vasodilation and bradycardia"], "ans": 4, "exp": "Neurogenic shock (high spinal cord injury): loss of sympathetic outflow → vasodilation (warm skin) + hypotension + 'bradycardia' (unopposed vagal, ต่างจาก shock อื่นที่ tachycardia). รักษา: fluid + vasopressor (norepinephrine/phenylephrine) + atropine สำหรับ bradycardia; ต้องแยก/ตัด hemorrhagic shock ร่วมด้วยใน trauma"}, {"topic": "Acute chest syndrome", "q": "A patient with sickle cell disease develops fever, chest pain, hypoxia, and a new pulmonary infiltrate. What is this emergency and its management?", "choices": ["Acute chest syndrome", "Simple community pneumonia; oral antibiotics and discharge", "Pulmonary embolism; anticoagulation as the sole therapy", "Acute pericarditis; NSAIDs and colchicine treatment", "Asthma exacerbation; bronchodilators and steroids only"], "ans": 0, "exp": "Acute chest syndrome (sickle cell): fever + respiratory symptoms + new infiltrate → emergency: O2, antibiotics (ครอบคลุม atypical), analgesia, hydration, และ 'transfusion' (simple/exchange) ในรายรุนแรง. เป็นสาเหตุการเสียชีวิตสำคัญของ sickle cell (พบน้อยในไทยเทียบ thalassemia)"}, {"topic": "Hypertensive emergency in pregnancy", "q": "A woman at 36 weeks with severe preeclampsia has blood pressure 170/115 mmHg and a seizure. Besides controlling blood pressure, what is the priority drug?", "choices": ["Intravenous phenytoin as the first-line anticonvulsant", "Magnesium sulfate to control and prevent seizures", "A benzodiazepine infusion as definitive seizure control", "Immediate high-dose diuretic to lower the pressure", "Ergometrine to reduce the risk of postpartum bleeding"], "ans": 1, "exp": "Eclampsia (severe preeclampsia + seizure): 'magnesium sulfate' เป็น first-line ควบคุม/ป้องกัน seizure (เหนือกว่า phenytoin/benzodiazepine) + antihypertensive (labetalol/hydralazine/nifedipine) + stabilize แล้ว 'delivery' เป็นการรักษาที่แท้จริง. เฝ้าระวัง Mg toxicity (loss of reflexes, respiratory depression → calcium gluconate)"}, {"topic": "Free-wall rupture", "q": "Several days after a large myocardial infarction, a patient suddenly develops pulseless electrical activity with distended neck veins and rapid deterioration. What complication is most likely?", "choices": ["Acute mitral regurgitation from papillary rupture", "Ventricular septal rupture with a left-to-right shunt", "Ventricular free-wall rupture causing cardiac tamponade", "Recurrent occlusion causing extension of the infarct", "Pericarditis producing a small reactive effusion"], "ans": 2, "exp": "Ventricular free-wall rupture (post-MI, ~3-7 วัน): sudden hemopericardium → tamponade → PEA/sudden death, distended neck veins. มัก fatal; emergency pericardiocentesis + surgery ถ้าทัน. ต่างจาก papillary rupture (acute MR/pulmonary edema) และ VSD (shunt murmur)"}, {"topic": "New-onset AF - unstable", "q": "A patient with new atrial fibrillation at 160/min develops hypotension, chest pain, and pulmonary edema. What is the most appropriate immediate treatment?", "choices": ["Oral rate-control with a beta-blocker", "Intravenous adenosine rapid push", "Unsynchronized defibrillation shock", "Synchronized cardioversion", "Digoxin loading over 24 hours"], "ans": 3, "exp": "Unstable atrial fibrillation (hypotension, ischemic chest pain, pulmonary edema, shock) → 'synchronized cardioversion' ทันที. Stable AF → rate control (beta-blocker/CCB) ± anticoagulation ตาม CHA2DS2-VASc. Adenosine ไม่ terminate AF (แต่ช่วยเผย rhythm ใน SVT อื่น)"}, {"topic": "Ventilation with advanced airway", "q": "After an advanced airway is placed during adult CPR, how should ventilations be delivered?", "choices": ["Continue the 30:2 ratio pausing for each breath", "Hyperventilate at 20 breaths per minute to raise oxygen", "One breath every 2 seconds synchronized with compressions", "Withhold ventilation entirely and give compressions only", "One breath every 6 seconds without pausing compressions"], "ans": 4, "exp": "หลังใส่ advanced airway ระหว่าง CPR: ให้ ventilation 'ต่อเนื่อง 1 ครั้งทุก 6 วินาที (10/min)' โดย 'ไม่หยุด' chest compressions (compressions ต่อเนื่อง). หลีกเลี่ยง hyperventilation (เพิ่ม intrathoracic pressure → ลด venous return/cardiac output)"}, {"topic": "Refractory VF", "q": "An adult remains in ventricular fibrillation after several shocks, epinephrine, and amiodarone. Which additional strategy may be considered for refractory VF?", "choices": ["Consider changing pad position or double sequential defibrillation", "Stop all defibrillation and give compressions only", "Switch immediately to synchronized cardioversion", "Give repeated intravenous calcium as an antiarrhythmic", "Administer atropine to convert the rhythm"], "ans": 0, "exp": "Refractory VF: optimize CPR quality, ให้ antiarrhythmic (amiodarone/lidocaine), หา reversible causes; พิจารณา 'เปลี่ยนตำแหน่ง pad (anterior-posterior)' หรือ double sequential external defibrillation, และ ECPR ในศูนย์ที่ทำได้. ยังคง shock (shockable rhythm) — ไม่เปลี่ยนเป็น cardioversion/atropine"}, {"topic": "Cardiac standstill on ultrasound", "q": "During resuscitation of PEA arrest, point-of-care echocardiography shows no cardiac motion (cardiac standstill) after adequate resuscitation. What does this finding suggest?", "choices": ["It confirms a shockable rhythm requiring defibrillation", "It is associated with very poor likelihood of survival", "It indicates tension pneumothorax as the cause", "It reliably confirms the patient is in fine VF", "It means resuscitation should be prolonged indefinitely"], "ans": 1, "exp": "Point-of-care ultrasound ที่พบ 'cardiac standstill' (no cardiac motion) ใน PEA/asystolic arrest หลังกู้ชีพเต็มที่ สัมพันธ์กับ 'survival ต่ำมาก' และใช้ประกอบการตัดสินใจ (ร่วมกับปัจจัยอื่น). Ultrasound ยังช่วยหา reversible causes (tamponade, RV strain จาก PE, hypovolemia)"}, {"topic": "Smoke inhalation / cyanide", "q": "A patient rescued from an enclosed house fire has soot in the airway, altered mental status, and a high lactate with a normal oxygen saturation. Besides oxygen, which antidote should be considered for cyanide toxicity?", "choices": ["Naloxone", "Atropine and pralidoxime", "Hydroxocobalamin", "N-acetylcysteine", "Deferoxamine"], "ans": 2, "exp": "Enclosed-space fire: ระวัง 'cyanide toxicity' (จาก combustion) — altered mental status + severe lactic acidosis + normal SpO2. Antidote = 'hydroxocobalamin' (± sodium thiosulfate). ร่วมกับ CO poisoning (ให้ 100% O2). ประเมิน airway burn/inhalation injury (อาจต้อง intubate เร็ว)"}, {"topic": "Pediatric fluid resuscitation", "q": "A child in hypovolemic (or septic) shock needs fluid resuscitation. What is the appropriate initial isotonic fluid bolus?", "choices": ["5 mL/kg of isotonic crystalloid given very slowly", "60 mL/kg given as a single rapid infusion", "Maintenance fluids only, without any bolus", "20 mL/kg of isotonic crystalloid, reassessed after each bolus", "A colloid bolus of 20 mL/kg as the required first choice"], "ans": 3, "exp": "Pediatric shock resuscitation: isotonic crystalloid (NSS/LR) 'bolus 20 mL/kg' แล้วประเมินซ้ำ (repeat ตามการตอบสนอง, ระวัง fluid overload โดยเฉพาะ cardiogenic/severe malnutrition/DKA). Cardiogenic → bolus เล็กลง/ระวัง. PALS"}, {"topic": "Compression fraction", "q": "To maximize survival during CPR, teams aim to minimize interruptions in chest compressions. Which metric reflects this goal?", "choices": ["A high number of defibrillation shocks per minute", "Frequent pulse checks between every compression cycle", "Prolonged pauses to secure a definitive airway early", "A slow compression rate below 80 per minute", "A high chest compression fraction"], "ans": 4, "exp": "Chest compression fraction (สัดส่วนเวลาที่กำลังกด อย่างน้อย >60-80%) สะท้อนคุณภาพ CPR — ยิ่งลด interruptions (pulse check, ventilation, intubation) ยิ่ง perfusion ดีขึ้นและ survival เพิ่ม. Metrics คุณภาพอื่น: rate 100-120, depth 5-6 cm, full recoil"}, {"topic": "Fulminant myocarditis", "q": "A previously healthy young adult develops rapidly progressive heart failure and cardiogenic shock days after a viral illness, with elevated troponin and a dilated hypokinetic ventricle. What is the diagnosis?", "choices": ["Fulminant myocarditis", "Acute myocardial infarction from coronary occlusion", "Acute pericarditis with a small effusion", "Hypertrophic obstructive cardiomyopathy", "Rheumatic mitral valve disease"], "ans": 0, "exp": "Fulminant myocarditis (มัก viral): heart failure/cardiogenic shock เฉียบพลันในคนหนุ่มสาวที่เคยแข็งแรง หลัง viral prodrome, troponin สูง, low-voltage ECG, dilated hypocontractile ventricle. รักษา supportive/inotrope + mechanical support (ECMO) ในราย refractory; อาจฟื้นตัวดีถ้าประคับประคองผ่านช่วงวิกฤต"}, {"topic": "Flail chest", "q": "A trauma patient has paradoxical movement of a chest wall segment (moving inward on inspiration) with multiple adjacent rib fractures and hypoxia. What is the diagnosis and key management concern?", "choices": ["Simple rib fracture; discharge with oral analgesia", "Flail chest; analgesia and support for the underlying pulmonary contusion", "Tension pneumothorax; immediate needle decompression", "Massive hemothorax; immediate thoracotomy for bleeding", "Cardiac tamponade; urgent pericardiocentesis drainage"], "ans": 1, "exp": "Flail chest (≥2 ribs fractured ใน ≥2 ตำแหน่ง) → paradoxical chest wall movement; morbidity หลักมาจาก 'underlying pulmonary contusion' + pain → hypoventilation/hypoxia. รักษา: analgesia (รวม regional), pulmonary toilet, O2/ventilatory support ตามต้องการ; surgical fixation ในบางราย"}, {"topic": "Massive transfusion", "q": "A trauma patient in hemorrhagic shock requires ongoing large-volume transfusion. What is the recommended balanced resuscitation approach?", "choices": ["Give only packed red blood cells and avoid plasma entirely", "Use large volumes of crystalloid instead of blood products", "Transfuse red cells, plasma, and platelets in about a 1:1:1 ratio", "Withhold transfusion until the hemoglobin falls below 5 g/dL", "Give platelets alone since coagulopathy is the main issue"], "ans": 2, "exp": "Massive hemorrhage: 'balanced/hemostatic resuscitation' ด้วย PRBC : FFP : platelet ~1:1:1 (จำลอง whole blood), จำกัด crystalloid (กัน dilutional coagulopathy), permissive hypotension ก่อน hemorrhage control, ให้ tranexamic acid ภายใน 3 ชม., ป้องกัน lethal triad (hypothermia, acidosis, coagulopathy)"}, {"topic": "Tranexamic acid", "q": "In a trauma patient with significant hemorrhage presenting within 3 hours of injury, which drug reduces mortality from bleeding?", "choices": ["Recombinant factor VIIa for all patients", "Prophylactic broad-spectrum antibiotics", "High-dose corticosteroids", "Tranexamic acid", "Intravenous vitamin K"], "ans": 3, "exp": "Tranexamic acid (antifibrinolytic) ให้ภายใน 3 ชม.หลัง trauma ที่มี/เสี่ยง significant bleeding ลด mortality (CRASH-2). ให้ช้ากว่า 3 ชม.อาจเพิ่มอันตราย. ใช้ใน postpartum hemorrhage ด้วย"}, {"topic": "Permissive hypotension", "q": "In a bleeding trauma patient without head injury before surgical hemorrhage control, what blood-pressure strategy is generally recommended?", "choices": ["Aggressive fluid loading to normalize blood pressure quickly", "Targeting a systolic pressure above 160 mmHg immediately", "Withholding all fluids and blood products until the operating room", "Using vasopressors alone to raise pressure to normal levels", "Permissive hypotension until bleeding is controlled"], "ans": 4, "exp": "Permissive hypotension (hypotensive resuscitation): ก่อน definitive hemorrhage control ในผู้ป่วยที่ไม่มี traumatic brain injury → คุม BP ให้พอมี perfusion (เช่น SBP ~80-90 / palpable radial pulse) แทนการดันให้ปกติ ซึ่งเพิ่ม rebleeding/dilution. ข้อยกเว้น: TBI ต้องรักษา perfusion สมอง"}, {"topic": "Cardioversion energy - AF", "q": "A patient requires synchronized cardioversion for unstable atrial fibrillation. What is a key technical point compared with defibrillation?", "choices": ["The shock is synchronized to the R wave to avoid the vulnerable period", "The highest possible energy is always used regardless of rhythm", "Pads must never be placed in the anterior-posterior position", "The synchronize function is turned off for atrial fibrillation", "Sedation is contraindicated before elective cardioversion"], "ans": 0, "exp": "Synchronized cardioversion: เครื่องปล่อย shock ตรงกับ 'R wave' เพื่อหลีกเลี่ยง T wave (vulnerable period) ที่อาจกระตุ้น VF. ใช้กับ perfusing tachyarrhythmia (unstable AF/flutter/SVT/VT with pulse) + sedation. ต่างจาก defibrillation (unsynchronized) สำหรับ VF/pulseless VT"}, {"topic": "Kussmaul sign", "q": "A patient with constrictive/tamponade physiology shows a paradoxical rise in jugular venous pressure during inspiration. What is this sign called?", "choices": ["Pulsus paradoxus", "Kussmaul sign", "Corrigan pulse", "Kussmaul breathing", "Levine sign"], "ans": 1, "exp": "Kussmaul sign = JVP 'สูงขึ้น' ตอนหายใจเข้า (แทนที่จะลด) พบใน constrictive pericarditis, severe right heart failure, tamponade บางกรณี, RV infarction. อย่าสับสนกับ 'pulsus paradoxus' (BP ลด >10 mmHg ตอนหายใจเข้า, พบใน tamponade/severe asthma) และ Kussmaul 'breathing' (deep breathing ใน metabolic acidosis)"}, {"topic": "Status asthmaticus ventilation", "q": "A patient with near-fatal asthma is intubated. Which ventilator strategy reduces the risk of dynamic hyperinflation (breath stacking) and barotrauma?", "choices": ["High respiratory rate to rapidly correct the carbon dioxide", "High tidal volumes to overcome the airway resistance", "Low respiratory rate with prolonged expiratory time", "Minimal expiratory time to maximize the minute ventilation", "Zero PEEP with maximal inspiratory pressures"], "ans": 2, "exp": "Intubated severe asthma: risk 'dynamic hyperinflation/auto-PEEP' → hypotension/barotrauma. Strategy: low RR + 'prolonged expiratory time' (I:E สูง), low tidal volume, ยอมให้ CO2 คั่ง ('permissive hypercapnia'), continue bronchodilator/steroid. ถ้า sudden hypotension หลัง intubate → ปลด vent ให้ปอดคลายลม + ประเมิน pneumothorax"}, {"topic": "Vasopressin in arrest", "q": "Which statement about epinephrine in adult cardiac arrest is correct?", "choices": ["Epinephrine is only given once at the very end of resuscitation", "High-dose epinephrine routinely improves neurologic survival", "Epinephrine is contraindicated in shockable rhythms", "Epinephrine 1 mg IV is given every 3-5 minutes during arrest", "Epinephrine should be given as a continuous drip during CPR"], "ans": 3, "exp": "Epinephrine 1 mg IV/IO 'ทุก 3-5 นาที' ระหว่าง arrest (ให้เร็วใน non-shockable; หลัง shock ที่ 2 ใน shockable). High-dose epinephrine ไม่ช่วย outcome. Vasopressin ถูกถอดออกจาก algorithm หลัก (ไม่เพิ่มประโยชน์เหนือ epinephrine)"}, {"topic": "Oxygen target", "q": "In an acutely ill patient who is not critically hypoxemic, what is an appropriate oxygen saturation target to avoid harm from hyperoxia?", "choices": ["Always 100% regardless of the underlying condition", "Below 85% to stimulate the respiratory drive", "Exactly 90% for every patient in all situations", "Oxygen is unnecessary unless the patient is cyanotic", "About 94-98%"], "ans": 4, "exp": "เป้า oxygen saturation ~94-98% ในผู้ป่วยทั่วไป (หลีกเลี่ยง hyperoxia ที่อาจเพิ่ม oxidative injury/mortality เช่นหลัง MI/ROSC/stroke), และ '88-92%' ในกลุ่มเสี่ยง hypercapnic respiratory failure (COPD). ให้ O2 ตาม target ไม่ใช่ให้สูงสุดเสมอ"}, {"topic": "Acute severe aortic regurgitation", "q": "A patient with aortic dissection or endocarditis develops sudden severe dyspnea and pulmonary edema with a soft early diastolic murmur and hypotension. What is the underlying acute problem?", "choices": ["Acute severe aortic regurgitation", "Acute mitral stenosis from thrombus", "Chronic compensated aortic stenosis", "Isolated right ventricular failure", "Ventricular septal rupture"], "ans": 0, "exp": "Acute severe aortic regurgitation (จาก dissection/endocarditis): LV ยังไม่ dilate ทัน → sudden pulmonary edema + hypotension + soft/short diastolic murmur (แตกต่างจาก chronic AR ที่ทน). เป็น surgical emergency (valve repair/replacement); vasodilator/inotrope เป็น bridge, 'หลีกเลี่ยง' IABP และ beta-blocker เดี่ยว (ยับยั้ง compensatory tachycardia)"}, {"topic": "Sudden cardiac death screening", "q": "A young athlete has exertional syncope and a systolic murmur that increases with the Valsalva maneuver and decreases with squatting. What is the most likely cause of potential sudden death?", "choices": ["Innocent flow murmur", "Hypertrophic cardiomyopathy", "Mitral valve prolapse without consequence", "Simple vasovagal syncope", "Acute rheumatic carditis"], "ans": 1, "exp": "Hypertrophic cardiomyopathy (HCM): สาเหตุ sudden cardiac death ในนักกีฬาวัยรุ่นที่พบบ่อย. Murmur 'เพิ่มขึ้น' เมื่อ preload ลด (Valsalva/standing) และ 'ลดลง' เมื่อ squatting (ตรงข้าม innocent murmur/AS). Exertional syncope + family history sudden death = red flag → echo, จำกัด competitive sport, พิจารณา ICD"}, {"topic": "Pediatric defibrillation dose", "q": "A child in ventricular fibrillation requires defibrillation. What is the recommended initial energy dose?", "choices": ["A fixed 200 J for all children regardless of weight", "0.5 J/kg as the standard first shock energy", "2 J/kg for the first shock", "Synchronized shock at 1 J/kg for ventricular fibrillation", "10 J/kg as the initial defibrillation dose"], "ans": 2, "exp": "Pediatric VF/pulseless VT: initial defibrillation '2 J/kg' (unsynchronized), เพิ่มเป็น 4 J/kg และมากขึ้น (สูงสุด ~10 J/kg หรือ adult dose) สำหรับ shock ถัดไป. Synchronized cardioversion ใช้ 0.5-1 J/kg (perfusing tachyarrhythmia)"}, {"topic": "Beck triad", "q": "Which triad of clinical signs is classically associated with cardiac tamponade?", "choices": ["Hypertension, bradycardia, and irregular respiration", "Fever, rash, and hypotension with desquamation", "Jaundice, acute kidney injury, and myalgia", "Hypotension, muffled heart sounds, and distended neck veins", "Chest pain, ST elevation, and reciprocal ST depression"], "ans": 3, "exp": "Beck triad ของ cardiac tamponade = hypotension + muffled heart sounds + distended neck veins (raised JVP), ± pulsus paradoxus. Cushing triad (hypertension + bradycardia + irregular respiration) = raised ICP. Toxic shock = fever + rash + hypotension + desquamation"}, {"topic": "Cardiac tamponade drainage", "q": "A hypotensive patient with confirmed cardiac tamponade is rapidly deteriorating. What is the definitive emergency treatment?", "choices": ["A large intravenous crystalloid bolus as the only measure", "Immediate synchronized cardioversion of the rhythm", "High-dose diuretics to reduce the pericardial fluid", "Systemic thrombolysis to dissolve the effusion", "Pericardiocentesis"], "ans": 4, "exp": "Cardiac tamponade ที่ unstable → 'pericardiocentesis' (echo-guided) หรือ surgical drainage เป็น definitive. IV fluid เป็น temporizing (เพิ่ม preload) ระหว่างรอ drainage. Diuretic 'ห้าม' (ลด preload → แย่ลง). ใน traumatic tamponade มัก surgery (thoracotomy)"}, {"topic": "Return breathing rate - child CPR", "q": "For a child in cardiac arrest with two rescuers and no advanced airway, what compression-to-ventilation ratio is used?", "choices": ["15:2 (two-rescuer pediatric CPR)", "30:2 identical to single-rescuer adult CPR", "5:1 as the standard pediatric ratio", "Continuous compressions with no ventilations at all", "10:2 for all pediatric resuscitation scenarios"], "ans": 0, "exp": "Pediatric CPR: 'two-rescuer' ใช้ 15:2; 'single-rescuer' ใช้ 30:2 (เหมือนผู้ใหญ่). หลังใส่ advanced airway → compressions ต่อเนื่อง + ventilation ~1 ครั้งทุก 2-3 วินาที (20-30/min) ในเด็ก. Compression depth ~1/3 ของ AP diameter"}, {"topic": "Hypoglycemia as arrest cause", "q": "In any collapsed or arresting patient with altered consciousness, which rapidly reversible metabolic cause must be checked and corrected immediately?", "choices": ["Mild dehydration from reduced oral intake", "Hypoglycemia", "Chronic anemia developing over months", "Longstanding well-controlled hypothyroidism", "A stable chronic electrolyte abnormality"], "ans": 1, "exp": "Hypoglycemia เป็นสาเหตุ reversible ที่ต้องตรวจ 'blood glucose' และแก้ทันที (IV dextrose) ในผู้ป่วยหมดสติ/ชัก/arrest ทุกราย — 'don't ever forget glucose'. เป็นส่วนหนึ่งของการประเมิน altered consciousness/H's & T's"}, {"topic": "Post-ROSC hypotension", "q": "After return of spontaneous circulation, a patient has a mean arterial pressure of 55 mmHg. What is the appropriate management?", "choices": ["Allow permissive hypotension to rest the heart after arrest", "Immediately give a beta-blocker to control the heart rate", "Treat hypotension with fluids and vasopressors to maintain perfusion", "Withhold all vasoactive drugs during the post-arrest period", "Induce deliberate hyperventilation to protect the brain"], "ans": 2, "exp": "Post-ROSC hypotension (MAP ต่ำ) ทำให้ secondary organ/brain injury → รักษาด้วย fluid + vasopressor/inotrope เพื่อ maintain MAP (มัก ≥65) และ perfusion. หลีกเลี่ยง hypocapnia (hyperventilation → cerebral vasoconstriction) และ hyperoxia. หา/รักษาสาเหตุ arrest"}, {"topic": "Septic shock - pediatric", "q": "A child with fever, tachycardia, prolonged capillary refill, and altered mental status is in septic shock. What are the priorities in the first hour?", "choices": ["Await culture results before starting any antimicrobial therapy", "Oral rehydration and discharge with next-day follow-up", "Vasopressors before any fluid resuscitation is attempted", "Cultures, early antibiotics, fluid boluses, and vasopressor if refractory", "Corticosteroids as the single most important first-line therapy"], "ans": 3, "exp": "Pediatric septic shock (recognize early — เด็ก compensate นานก่อน BP ตก): first hour ให้ obtain cultures, 'broad-spectrum antibiotics เร็ว', isotonic fluid boluses 20 mL/kg (ประเมินซ้ำ, ระวัง overload), และ vasopressor (epinephrine/norepinephrine) ถ้า fluid-refractory. Surviving Sepsis pediatric"}, {"topic": "Warm vs cold shock (peds)", "q": "A child in septic shock has bounding pulses, warm extremities, and a wide pulse pressure ('warm shock'). Which vasoactive agent is typically preferred?", "choices": ["Dobutamine as the sole agent for warm shock", "A large dose of intravenous furosemide", "Nitroglycerin to further reduce afterload", "Adenosine to slow the heart rate", "Norepinephrine"], "ans": 4, "exp": "Pediatric septic shock: 'warm shock' (vasodilated, warm extremities, bounding pulse, wide pulse pressure) → vasopressor 'norepinephrine'; 'cold shock' (vasoconstricted, cool, poor perfusion) → epinephrine เป็นทางเลือก. ปรับตาม clinical/hemodynamics"}, {"topic": "Cardiac contusion", "q": "A patient with blunt chest trauma (steering wheel injury) has sinus tachycardia, new arrhythmias, and mildly elevated troponin with a normal coronary risk profile. What is the likely diagnosis?", "choices": ["Blunt cardiac contusion", "Acute coronary occlusion from atherosclerosis", "Acute viral pericarditis unrelated to trauma", "Aortic dissection extending to the coronaries", "Congenital long QT syndrome unmasked by stress"], "ans": 0, "exp": "Blunt cardiac injury/myocardial contusion (blunt chest trauma): arrhythmia (sinus tach, ectopy, RBBB), ± mild troponin rise, ECG changes. รักษา: cardiac monitoring, จัดการ arrhythmia, ประเมิน associated injury (echocardiogram ถ้า unstable). ส่วนใหญ่ supportive; เฝ้าระวัง significant arrhythmia/pump dysfunction"}, {"topic": "High-altitude / hypoxic drive myth", "q": "Which statement about giving oxygen to a hypoxemic COPD patient in an emergency is correct?", "choices": ["Withhold all oxygen to preserve the hypoxic respiratory drive", "Never withhold needed oxygen", "Always deliver 100% oxygen regardless of the saturation", "Oxygen is contraindicated in any COPD patient entirely", "Give oxygen only if the patient becomes fully unconscious"], "ans": 1, "exp": "ในผู้ป่วย COPD ที่ hypoxemic: 'อย่าอดออกซิเจนที่จำเป็น' — ให้ O2 titrate ไปที่เป้า 88-92% (หลีกเลี่ยงทั้ง hypoxia และ hyperoxia ที่อาจทำให้ CO2 คั่ง). Hypoxia ฆ่าเร็วกว่า hypercapnia. Monitor และปรับตาม blood gas; ถ้า CO2 คั่ง/ซึม พิจารณา NIV"}, {"topic": "Pulseless VT", "q": "A monitored patient loses consciousness and the rhythm shows a regular wide-complex tachycardia with no palpable pulse. How should this be treated?", "choices": ["With synchronized cardioversion timed to the QRS complex", "With intravenous adenosine given by rapid push", "As a shockable rhythm with immediate defibrillation and CPR", "With observation because it may terminate spontaneously", "With intravenous atropine to increase the heart rate"], "ans": 2, "exp": "Pulseless ventricular tachycardia จัดเป็น 'shockable rhythm' เหมือน VF → defibrillate (unsynchronized) ทันที + CPR + epinephrine + amiodarone. Synchronized cardioversion ใช้กับ VT ที่ 'ยังมี pulse' (unstable). ไม่มี pulse = treat like VF"}, {"topic": "AED in children", "q": "An AED is needed for a 3-year-old in cardiac arrest. What is the appropriate use of the device?", "choices": ["Never use an AED in any child under eight years old", "Use only manual defibrillation and never an AED", "Place both adult pads on the anterior chest touching each other", "Use pediatric attenuator pads/settings if available, otherwise adult pads", "Withhold defibrillation entirely until a physician arrives"], "ans": 3, "exp": "AED ในเด็ก: ใช้ 'pediatric dose attenuator pads/settings' ถ้ามี (สำหรับ <8 ปี/<25 kg); ถ้าไม่มี ใช้ adult AED/pads ได้ (ดีกว่าไม่ defibrillate). วาง pad ไม่ให้สัมผัสกัน (อาจใช้ anterior-posterior ในเด็กเล็ก). Early defibrillation สำคัญต่อ survival ใน shockable rhythm"}, {"topic": "Acute mitral stenosis decompensation", "q": "A pregnant woman with known rheumatic mitral stenosis develops acute pulmonary edema when she goes into rapid atrial fibrillation. Besides oxygen and diuresis, what is a key treatment?", "choices": ["Aggressive fluid loading to increase cardiac output", "A pure arterial vasodilator to reduce afterload", "A positive inotrope to increase the heart rate", "Immediate thrombolysis for the pulmonary edema", "Rate control to lengthen diastolic filling time"], "ans": 4, "exp": "Mitral stenosis: cardiac output พึ่ง diastolic filling time — 'rate control' (beta-blocker) สำคัญเพราะ tachycardia/AF ลด filling → pulmonary edema. การตั้งครรภ์ (เพิ่ม volume/HR) มัก unmask MS. หลีกเลี่ยง fluid overload และยาที่เพิ่ม HR; anticoagulate ถ้า AF. Definitive: balloon/surgical valvotomy"}]}, {"id": "er-2", "title": "เวชศาสตร์ฉุกเฉิน ชุดที่ 2 — Trauma/Burns/Environmental", "subject": "emergency", "questions": [{"topic": "ATLS - Primary survey", "q": "A patient arrives after a high-speed motor vehicle collision. According to trauma primary survey principles, what is assessed and managed first?", "choices": ["Airway with cervical spine protection", "Circulation with control of external hemorrhage", "Disability using the Glasgow Coma Scale", "Exposure with prevention of hypothermia", "A detailed head-to-toe secondary survey"], "ans": 0, "exp": "ATLS primary survey ตามลำดับ 'ABCDE': Airway (+ C-spine protection) มาก่อนเสมอ → Breathing → Circulation (control hemorrhage, 2 large-bore IV) → Disability (GCS, pupils) → Exposure/Environment (ถอดเสื้อผ้า + ป้องกัน hypothermia). แก้ปัญหาที่คุกคามชีวิตทันทีที่พบในแต่ละขั้น"}, {"topic": "Massive hemothorax", "q": "A trauma patient has dullness to percussion and absent breath sounds on the right; a chest tube immediately drains 1600 mL of blood with continued bleeding. What is the appropriate management?", "choices": ["Needle decompression at the second intercostal space", "Chest tube drainage and urgent thoracotomy for ongoing bleeding", "Observation with a repeat chest radiograph in six hours", "Immediate pericardiocentesis to relieve the pressure", "Non-invasive ventilation to re-expand the collapsed lung"], "ans": 1, "exp": "Massive hemothorax: chest tube ระบายเลือด; indication ผ่าตัด (thoracotomy) = ออกทันที >1500 mL หรือ >200 mL/hr ต่อเนื่อง 2-4 ชม. หรือ hemodynamic instability. ต้อง resuscitate ควบคู่. ต่างจาก tension pneumothorax (needle decompression) และ tamponade (pericardiocentesis)"}, {"topic": "Pelvic fracture hemorrhage", "q": "A patient with an unstable pelvic fracture from a crush injury is hypotensive with a widened pelvis. What is an appropriate early intervention to control bleeding?", "choices": ["Log-roll repeatedly to fully assess the pelvic instability", "Apply skeletal traction to the pelvis at the bedside", "Apply a pelvic binder to reduce pelvic volume and tamponade bleeding", "Delay all intervention until a CT scan is completed", "Immediately internally fix the pelvis in the resuscitation bay"], "ans": 2, "exp": "Unstable pelvic fracture + hemorrhage: apply 'pelvic binder' (ลด pelvic volume → tamponade venous/bony bleeding) + balanced resuscitation. ควบคุมต่อด้วย angioembolization (arterial) หรือ preperitoneal packing/external fixation. หลีกเลี่ยงการ manipulate/log-roll ซ้ำ (เพิ่มเลือดออก)"}, {"topic": "FAST examination", "q": "A hypotensive blunt trauma patient undergoes a bedside ultrasound (FAST). What is the primary purpose of this examination?", "choices": ["Diagnose long-bone fractures of the extremities", "Assess the coronary arteries for occlusion", "Measure the intracranial pressure noninvasively", "Detect free intraperitoneal fluid indicating hemorrhage", "Evaluate the airway for foreign body obstruction"], "ans": 3, "exp": "FAST (Focused Assessment with Sonography for Trauma) มองหา 'free fluid' (เลือด) ใน peritoneum (perihepatic, perisplenic, pelvis) และ pericardium ในผู้ป่วย trauma โดยเฉพาะ hemodynamically unstable → positive + unstable = ไป OR. ไม่ประเมิน fracture/airway/coronary"}, {"topic": "Head injury - epidural", "q": "A young man struck on the temple briefly lost consciousness, recovered ('lucid interval'), then deteriorated with a fixed dilated pupil. CT shows a lens-shaped (biconvex) hyperdensity. What is the diagnosis?", "choices": ["Acute subdural hematoma", "Diffuse axonal injury", "Subarachnoid hemorrhage", "Chronic subdural hematoma", "Epidural hematoma"], "ans": 4, "exp": "Epidural hematoma (มัก middle meningeal artery tear หลัง temporal bone fracture): 'lucid interval' แล้ว rapid deterioration + ipsilateral fixed dilated pupil (uncal herniation) + CT 'biconvex/lens-shaped' ไม่ข้าม suture. เป็น neurosurgical emergency (craniotomy). Subdural = crescent-shaped, ข้าม suture"}, {"topic": "Raised ICP management", "q": "A head-injured patient shows signs of impending brain herniation (unilateral dilated pupil, deteriorating consciousness) while awaiting neurosurgery. What is an appropriate temporizing measure?", "choices": ["Hyperosmolar therapy and head elevation", "Aggressive fluid restriction with induced dehydration", "Prophylactic prolonged hyperventilation to PaCO2 of 20", "Immediate lumbar puncture to relieve the pressure", "Systemic thrombolysis to improve cerebral blood flow"], "ans": 0, "exp": "Impending herniation (raised ICP): temporizing — head elevation 30°, 'hyperosmolar therapy' (mannitol/hypertonic saline), optimize oxygenation/BP, brief mild hyperventilation (PaCO2 ~30-35) 'เฉพาะช่วง' herniation, แก้สาเหตุ → neurosurgical decompression. 'ห้าม LP' (herniation). หลีกเลี่ยง prolonged/aggressive hyperventilation (ischemia)"}, {"topic": "Cervical spine clearance", "q": "An alert trauma patient with no neck pain, no midline tenderness, no neurologic deficit, no distracting injury, and no intoxication. How should the cervical spine be managed?", "choices": ["Mandatory CT of the cervical spine for every trauma patient", "The cervical spine can be clinically cleared without imaging", "Immediate MRI of the spine before any assessment", "Keep the collar on indefinitely regardless of findings", "Flexion-extension radiographs as the first-line screen"], "ans": 1, "exp": "Clinical decision rules (NEXUS/Canadian C-spine): ผู้ป่วย alert ที่ไม่มี midline tenderness, ไม่มี neuro deficit, ไม่มี distracting injury, ไม่ intoxicated, และไม่ high-risk → 'clear ได้ทางคลินิก' โดยไม่ต้อง imaging. ถ้าเข้าเกณฑ์เสี่ยง → CT cervical spine. ลด imaging ที่ไม่จำเป็น"}, {"topic": "Burn - fluid resuscitation", "q": "An adult has deep partial and full-thickness burns over 40% of total body surface area. Using the Parkland formula, fluid resuscitation is guided by what principle?", "choices": ["Give a single fixed 2-liter bolus and then stop all fluids", "Restrict fluids to avoid edema regardless of burn size", "Calculate crystalloid by %TBSA and weight, half in the first 8 hours, titrate to urine output", "Use colloid alone from the moment of injury", "Replace fluid based only on the patient's thirst"], "ans": 2, "exp": "Parkland formula: 4 mL × kg × %TBSA (partial+full thickness) ของ Ringer's lactate ใน 24 ชม.แรก, 'ครึ่งแรกใน 8 ชม.แรก' (นับจากเวลาที่ไหม้). Titrate ตาม 'urine output' (~0.5 mL/kg/hr ผู้ใหญ่, ~1 ในเด็ก). ประเมิน airway (inhalation injury). Refer major burn"}, {"topic": "Inhalation injury / airway burn", "q": "A patient from a house fire has facial burns, singed nasal hair, soot in the mouth, hoarseness, and stridor. What is the priority?", "choices": ["Watchful waiting with humidified oxygen only", "Delayed intubation once blistering fully develops", "Immediate tracheostomy as the first-line airway", "Early endotracheal intubation before airway edema worsens", "Nebulized bronchodilators as definitive airway management"], "ans": 3, "exp": "สัญญาณ inhalation/airway burn (facial burn, singed nasal hair, soot, hoarseness, stridor) → airway edema จะแย่ลงเร็ว → 'early intubation' ก่อนที่ edema จะทำให้ intubate ไม่ได้. Delay = อันตราย. ประเมิน CO/cyanide ร่วมด้วย"}, {"topic": "Rule of nines", "q": "Estimating burn extent in an adult using the rule of nines, the entire anterior trunk (chest and abdomen) accounts for approximately what percentage of total body surface area?", "choices": ["9%", "36%", "27%", "4.5%", "18%"], "ans": 4, "exp": "Rule of nines (ผู้ใหญ่): head 9%, แต่ละแขน 9%, anterior trunk 18%, posterior trunk 18%, แต่ละขา 18%, perineum 1%. ดังนั้น 'anterior trunk = 18%'. ในเด็กสัดส่วนต่างกัน (head ใหญ่กว่า) — ใช้ Lund-Browder chart เพื่อความแม่นยำ. นับเฉพาะ partial+full thickness"}, {"topic": "Circumferential burn", "q": "A patient with a circumferential full-thickness burn of the limb develops a cold, pulseless, tense extremity. What is the appropriate procedure?", "choices": ["Escharotomy to release the constricting eschar", "Immediate limb amputation to prevent sepsis", "Fasciotomy of all muscle compartments first", "Elevation and ice packs with observation", "Tight compressive dressing to reduce swelling"], "ans": 0, "exp": "Circumferential full-thickness burn → eschar แข็งรัด (tourniquet effect) → compromised perfusion (cold, pulseless, tense) หรือ chest → restrict ventilation → ต้อง 'escharotomy' (กรีดผ่าน eschar) เพื่อคลายการรัด. ต่างจาก fasciotomy (สำหรับ compartment syndrome ลึกกว่า)"}, {"topic": "Drowning resuscitation", "q": "A child is pulled unconscious and apneic from a pool. What is the single most important initial intervention?", "choices": ["Abdominal thrusts to expel swallowed water first", "Rescue breaths/ventilation to correct hypoxia", "Chest compressions only without any ventilation", "Rapid rewarming before providing any breaths", "Withholding CPR until arrival at the hospital"], "ans": 1, "exp": "Drowning: ปัญหาหลักคือ 'hypoxia' → priority คือ ventilation/rescue breaths เริ่มเร็วที่สุด (แม้ตอนอยู่ในน้ำถ้าปลอดภัย) แล้ว CPR ตามมาตรฐาน. 'ไม่' เสียเวลาพยายามเอาน้ำออก/abdominal thrust. เฝ้าระวัง delayed respiratory deterioration และ hypothermia"}, {"topic": "Heat stroke", "q": "A marathon runner collapses on a hot day with a core temperature of 41°C, confusion, and hot skin. What is the priority management?", "choices": ["Antipyretics such as paracetamol as the main therapy", "Broad-spectrum antibiotics for presumed sepsis", "Rapid active cooling and supportive care", "Warming the patient with blankets to prevent shivering", "Fluid restriction to avoid cerebral edema"], "ans": 2, "exp": "Heat stroke: core temp >40°C + CNS dysfunction (confusion/seizure/coma) จาก thermoregulatory failure. Priority = 'rapid active cooling' (cold-water immersion เร็วสุดสำหรับ exertional; evaporative + ice packs) + support ABC + IV fluid + จัดการ complication (rhabdomyolysis, DIC). 'Antipyretics ไม่ช่วย' (กลไกต่าง fever)"}, {"topic": "Hypothermia rewarming", "q": "A patient with moderate hypothermia (core 30°C) is conscious with shivering. What is the appropriate rewarming method?", "choices": ["Rapid immersion of the limbs in very hot water", "Vigorous rubbing of the extremities to generate heat", "Cold intravenous fluids to avoid overheating", "Active external and core rewarming with warm fluids and warm air", "No rewarming until the core reaches normal on its own"], "ans": 3, "exp": "Moderate hypothermia: 'active rewarming' — external (warm blankets/forced warm air) + core (warm humidified O2, warm IV fluids). จัดการนุ่มนวล (เสี่ยง arrhythmia). หลีกเลี่ยงการถูแขนขาแรง/immersion ร้อนเฉพาะที่ (afterdrop, arrhythmia). Severe/arrest → active core rewarming (ECMO/lavage)"}, {"topic": "Electrical injury", "q": "A worker sustains a high-voltage electrical injury. Beyond the surface burns, which serious complications must be evaluated?", "choices": ["Only the visible skin entry and exit wounds", "Isolated superficial epidermal burns without deep injury", "A self-limited condition needing no monitoring", "Purely psychological effects without physical harm", "Cardiac arrhythmia, deep tissue/muscle damage, and rhabdomyolysis"], "ans": 4, "exp": "High-voltage electrical injury: surface burns มัก underestimate — current ผ่านลึก → 'deep tissue/muscle necrosis, rhabdomyolysis (→ AKI), compartment syndrome, และ cardiac arrhythmia'. ต้อง ECG/monitor, ตรวจ CK/myoglobin, IV fluid + urine alkalinization ป้องกัน renal injury, ประเมิน associated trauma (ตกจากที่สูง)"}, {"topic": "Tetanus-prone wound", "q": "A patient with an incomplete/unknown tetanus immunization history sustains a deep, contaminated puncture wound. What prophylaxis is appropriate?", "choices": ["Tetanus toxoid vaccine plus tetanus immunoglobulin", "Tetanus toxoid vaccine only regardless of wound type", "Tetanus immunoglobulin only without any vaccine", "Oral antibiotics alone as sufficient prophylaxis", "No prophylaxis is needed for puncture wounds"], "ans": 0, "exp": "Tetanus-prone wound (deep/contaminated/puncture/necrotic) + immunization ไม่ครบ/ไม่ทราบ → ให้ทั้ง 'tetanus toxoid vaccine + tetanus immunoglobulin (TIG)'. ถ้าฉีดครบและ clean minor wound มักแค่ booster ตาม interval. ทำความสะอาด/debride แผลด้วย"}, {"topic": "Rabies post-exposure", "q": "A child is bitten by a stray dog that escapes, in a rabies-endemic area; the wound is on the hand. What is the appropriate management?", "choices": ["Thorough wound washing alone as sufficient treatment", "Wound washing plus rabies vaccine and rabies immunoglobulin", "Rabies vaccine only without any immunoglobulin", "Observation of the child for symptoms before treating", "A course of oral antibiotics as the only measure"], "ans": 1, "exp": "Rabies category III exposure (bite/broken skin): (1) ล้างแผลด้วยสบู่/น้ำ ≥15 นาที, (2) rabies vaccine series, (3) rabies immunoglobulin (RIG) แทรกรอบแผล (ผู้ไม่เคยฉีดมาก่อน). Rabies fatal เกือบ 100% เมื่อมีอาการ → prophylaxis ทันทีในพื้นที่ endemic. ± tetanus + antibiotic"}, {"topic": "Wound closure timing", "q": "A patient presents 10 hours after a clean laceration on the face. Regarding primary closure, what is the appropriate consideration?", "choices": ["Facial wounds must never be closed after 6 hours", "All wounds older than 6 hours should be left completely open", "The face has good vascularity and can often be closed primarily even later", "Contaminated wounds should always be closed primarily", "Antibiotics are mandatory for all simple clean lacerations"], "ans": 2, "exp": "การปิดแผล: golden period คร่าวๆ ~6-8 ชม. สำหรับ primary closure แต่ 'ใบหน้า/หนังศีรษะ' vascularity ดี ปิด primary ได้แม้เลยเวลา (cosmesis). แผล contaminated/bite/นาน → พิจารณา delayed primary/secondary closure + irrigation/debridement. Antibiotic ไม่จำเป็นในแผล clean simple"}, {"topic": "Compartment syndrome", "q": "A patient with a tibial fracture develops severe pain out of proportion, worse on passive stretch of the toes, with a tense swollen calf. What is the diagnosis and management?", "choices": ["Deep vein thrombosis; therapeutic anticoagulation", "Simple muscle contusion; ice and elevation", "Cellulitis; intravenous antibiotic therapy", "Acute compartment syndrome", "Chronic exertional pain; outpatient physiotherapy"], "ans": 3, "exp": "Acute compartment syndrome: 'pain out of proportion' + pain on passive stretch (อาการแรก/ไวสุด) + tense compartment; paresthesia/pulselessness เป็น late. เป็น emergency → 'fasciotomy' ด่วน (ลด pressure ป้องกัน muscle/nerve necrosis). ห้ามยกสูงเกิน/ประคบเย็นแน่น (ลด perfusion). วัด compartment pressure ในรายไม่ชัด"}, {"topic": "Triage - START", "q": "In a mass-casualty incident using START triage, a victim who is walking and able to follow commands is tagged which color?", "choices": ["Red (immediate, life-threatening)", "Yellow (delayed treatment)", "Black (deceased / expectant)", "Blue (contaminated, needs decontamination)", "Green (minor / walking wounded)"], "ans": 4, "exp": "START triage (mass casualty): 'Green' = walking wounded (minor). Red (immediate) = life-threatening แต่ salvageable (เช่น airway/breathing/circulation problem ที่แก้ได้). Yellow (delayed) = บาดเจ็บแต่รอได้. Black (expectant/deceased) = ไม่หายใจแม้เปิด airway. เป้าหมาย: ช่วยคนมากที่สุดด้วยทรัพยากรจำกัด"}, {"topic": "Blast injury", "q": "A patient injured in an explosion has ruptured tympanic membranes, dyspnea, and hemoptysis. Which type of blast injury directly caused the lung and ear damage?", "choices": ["Primary blast injury", "Secondary blast injury (from flying debris)", "Tertiary blast injury (from being thrown)", "Quaternary blast injury (burns and inhalation)", "Crush injury from structural collapse"], "ans": 0, "exp": "Blast injury: 'primary' = จาก pressure/blast wave ต่ออวัยวะที่มีอากาศ (ear → TM rupture, lung → blast lung/pulmonary contusion, GI). Secondary = shrapnel/debris (penetrating). Tertiary = ถูกเหวี่ยงชน. Quaternary = burns, inhalation, crush. TM rupture เป็น marker ของ significant blast exposure"}, {"topic": "Abdominal trauma - unstable", "q": "A blunt abdominal trauma patient is hypotensive and does not respond to fluids; FAST shows free intraperitoneal fluid. What is the appropriate management?", "choices": ["CT scan of the abdomen before any intervention", "Emergency exploratory laparotomy", "Diagnostic peritoneal lavage then discharge", "Observation with serial abdominal examinations", "Angiographic embolization as the sole treatment"], "ans": 1, "exp": "Blunt abdominal trauma + 'hemodynamically unstable' + positive FAST (free fluid) → 'emergency laparotomy' (ไม่รอ CT). Stable patient + positive FAST → CT เพื่อประเมินและอาจ non-operative management (solid organ injury) หรือ angioembolization. Unstable = ไป OR"}, {"topic": "Open pneumothorax", "q": "A patient has a large open chest wound ('sucking chest wound') with air moving through it and respiratory distress. What is the appropriate initial management?", "choices": ["Completely seal the wound on all four sides immediately", "Pack the wound tightly with gauze to stop the air", "Apply a three-sided occlusive dressing", "Leave the wound fully open and give oxygen only", "Perform immediate pericardiocentesis for the distress"], "ans": 2, "exp": "Open pneumothorax (sucking chest wound): apply 'three-sided occlusive dressing' (ทำหน้าที่เป็น flutter valve — ให้ลมออกได้ตอนหายใจออก ป้องกันลมเข้าตอนหายใจเข้า) เพื่อกัน tension physiology, แล้วใส่ chest tube (ตำแหน่งอื่น) + definitive closure. Sealing 4 ด้านสนิทเสี่ยงเปลี่ยนเป็น tension pneumothorax"}, {"topic": "GCS scoring", "q": "A head-injured patient opens eyes to pain, makes incomprehensible sounds, and withdraws from a painful stimulus. What is the Glasgow Coma Scale score?", "choices": ["6 (E1 V2 M3)", "10 (E2 V3 M5)", "12 (E3 V4 M5)", "8 (E2 V2 M4)", "5 (E1 V1 M3)"], "ans": 3, "exp": "GCS: Eye opening to pain = 2, incomprehensible sounds = 2, withdrawal from pain = 4 → รวม '8'. GCS ≤8 = severe TBI และมักเป็น indication ในการ 'secure airway' (intubate). Best motor response เป็น component ที่ prognostic สำคัญ"}, {"topic": "Basal skull fracture", "q": "A head-trauma patient has periorbital ecchymosis ('raccoon eyes'), bruising behind the ear (Battle sign), and clear fluid dripping from the nose. What does this indicate?", "choices": ["Simple nasal bone fracture with epistaxis", "Frontal sinus fracture without dural injury", "Orbital blow-out fracture with entrapment", "Mandibular fracture with malocclusion", "Basal skull fracture with a CSF leak"], "ans": 4, "exp": "Basal skull fracture signs: 'raccoon eyes' (periorbital ecchymosis), 'Battle sign' (mastoid ecchymosis), CSF rhinorrhea/otorrhea, hemotympanum. CSF leak → เสี่ยง meningitis. 'หลีกเลี่ยง nasogastric/nasotracheal tube' (เสี่ยงเข้ากะโหลก). ประเมินด้วย CT; ส่วนใหญ่ CSF leak หายเอง"}, {"topic": "Traumatic aortic injury", "q": "A patient in a high-speed deceleration crash has a widened mediastinum on chest radiograph, hypotension, and differential blood pressures. What life-threatening injury is suspected?", "choices": ["Traumatic aortic injury", "Simple rib fractures with pain", "Tension pneumothorax on the right", "Isolated sternal fracture", "Uncomplicated pulmonary contusion"], "ans": 0, "exp": "Traumatic aortic injury (deceleration, มักที่ aortic isthmus): 'widened mediastinum' + differential pulses/BP + severe mechanism. วินิจฉัยด้วย CT angiography. รักษา: impulse control (ลด BP/HR, IV beta-blocker) + urgent surgical/endovascular repair. เป็นสาเหตุการตายที่พบบ่อยในที่เกิดเหตุ"}, {"topic": "Pulmonary contusion", "q": "A patient with blunt chest trauma develops progressive hypoxia over hours, with a patchy infiltrate on the injured side that does not follow lobar boundaries. What is the diagnosis?", "choices": ["Lobar bacterial pneumonia", "Pulmonary contusion", "Simple pneumothorax", "Cardiogenic pulmonary edema", "Pulmonary embolism"], "ans": 1, "exp": "Pulmonary contusion (blunt chest trauma): hypoxia ค่อยเป็นค่อยไปในชั่วโมงแรกๆ + patchy non-lobar infiltrate ในบริเวณที่บาดเจ็บ. รักษา: O2/ventilatory support, analgesia, pulmonary toilet, judicious fluid (หลีกเลี่ยง overload). เป็นสาเหตุ morbidity หลักของ flail chest"}, {"topic": "Spinal cord - central cord", "q": "An elderly patient with cervical spondylosis falls, hyperextending the neck, and develops weakness that is worse in the arms/hands than the legs. What is the diagnosis?", "choices": ["Anterior cord syndrome", "Brown-Sequard syndrome", "Central cord syndrome", "Complete cord transection", "Cauda equina syndrome"], "ans": 2, "exp": "Central cord syndrome (พบบ่อยสุดของ incomplete SCI): มัก hyperextension injury ในผู้สูงอายุที่มี cervical spondylosis → weakness 'แขน/มือ > ขา' (upper > lower), variable sensory. Anterior cord = motor + pain/temp loss, proprioception เหลือ. Brown-Sequard = hemisection (ipsilateral motor/proprioception, contralateral pain/temp)"}, {"topic": "Neurogenic vs spinal shock", "q": "In a patient with acute spinal cord injury, the term 'spinal shock' refers to which phenomenon?", "choices": ["Hypotension with bradycardia from lost sympathetic tone", "Hemorrhagic hypotension from associated blood loss", "Septic vasodilation from an infected wound", "Transient loss of reflexes and flaccidity below the injury level", "Cardiogenic pump failure from myocardial contusion"], "ans": 3, "exp": "'Spinal shock' = การสูญเสีย reflex/tone ชั่วคราว (flaccid paralysis, areflexia) ต่ำกว่าระดับบาดเจ็บ ในช่วงแรก (ฟื้นเป็นวัน-สัปดาห์, กลับมา hyperreflexia). ต่างจาก 'neurogenic shock' ซึ่งเป็น 'hemodynamic' (hypotension + bradycardia จาก loss sympathetic tone ใน high cord injury). ต้องแยกกัน"}, {"topic": "Urethral injury", "q": "A pelvic-fracture patient has blood at the urethral meatus, inability to void, and a high-riding prostate on rectal exam. What should NOT be done, and what is the next step?", "choices": ["Immediately force a large Foley catheter to drain the bladder", "Insert a suprapubic catheter before any imaging is done", "Perform emergency cystoscopy through the injured urethra", "Ignore the findings and proceed with abdominal surgery", "Do not insert a urinary catheter"], "ans": 4, "exp": "Urethral injury (blood at meatus, high-riding prostate, unable to void, มักกับ pelvic fracture): 'ห้ามใส่ urethral catheter' (อาจทำ partial → complete tear) → ทำ 'retrograde urethrogram' ก่อน; ถ้ามี injury → suprapubic catheter/urology. Blood at meatus เป็นสัญญาณสำคัญ"}, {"topic": "Renal trauma", "q": "A patient with blunt flank trauma has gross hematuria and is hemodynamically stable. What is the appropriate initial investigation?", "choices": ["CT scan with contrast", "Immediate exploratory laparotomy for all hematuria", "Renal ultrasound as the definitive grading tool", "Retrograde urethrogram to assess the kidney", "No imaging since hematuria is always benign"], "ans": 0, "exp": "Blunt renal trauma + gross hematuria + stable → 'CT with contrast' (with delayed/excretory phase) เพื่อ grade injury และดู collecting system/urinary extravasation. ส่วนใหญ่ (low grade) จัดการ non-operatively. Unstable/expanding hematoma → surgery. Microscopic hematuria + stable + no shock มักไม่ต้อง image"}, {"topic": "Splenic injury", "q": "A patient with left upper quadrant blunt trauma and left shoulder pain (Kehr sign) is hemodynamically stable; CT shows a splenic laceration without active extravasation. What is the preferred management?", "choices": ["Immediate splenectomy regardless of stability", "Non-operative management with close monitoring", "Discharge home with next-week outpatient follow-up", "Systemic anticoagulation to prevent thrombosis", "Angiographic embolization is contraindicated entirely"], "ans": 1, "exp": "Splenic injury ในผู้ป่วย 'stable' (low-grade, no active bleeding) → 'non-operative management' (observation, serial exam/Hct) เป็นมาตรฐาน; angioembolization ในบางราย. Unstable → splenectomy. Kehr sign (referred left shoulder pain) จาก diaphragmatic irritation. หลัง splenectomy ต้อง vaccinate encapsulated organisms"}, {"topic": "Diaphragmatic rupture", "q": "After blunt abdominal trauma, a patient has respiratory distress and bowel sounds heard in the left chest, with a nasogastric tube tip seen in the thorax on radiograph. What is the diagnosis?", "choices": ["Massive left hemothorax", "Tension pneumothorax on the left", "Traumatic diaphragmatic rupture", "Left lower lobe pneumonia", "Boerhaave esophageal rupture"], "ans": 2, "exp": "Traumatic diaphragmatic rupture (มักด้านซ้าย): abdominal contents เลื่อนเข้าทรวงอก → bowel sounds ในอก, respiratory distress, NG tube coiling ในทรวงอกบน CXR. วินิจฉัยด้วย CT; รักษาโดยผ่าตัดซ่อม. อาจ present ล่าช้าเป็น herniation/obstruction"}, {"topic": "Local anesthetic toxicity", "q": "During a large-volume local anesthetic infiltration, a patient develops perioral numbness, tinnitus, seizures, then cardiac arrest. What is the specific rescue treatment?", "choices": ["Intravenous flumazenil to reverse the sedation", "Naloxone to reverse the neurologic effects", "High-dose atropine for the cardiac toxicity", "Intravenous lipid emulsion therapy", "Activated charcoal to bind the local anesthetic"], "ans": 3, "exp": "Local anesthetic systemic toxicity (LAST): CNS (perioral numbness, tinnitus, seizure) → cardiovascular (arrhythmia, arrest, โดยเฉพาะ bupivacaine). Specific antidote = 'IV lipid emulsion (Intralipid) 20%' + supportive/ACLS (modified). ป้องกันด้วยการคำนวณ max dose + aspirate ก่อนฉีด"}, {"topic": "Mangled extremity / amputation", "q": "A patient has a traumatic complete amputation of the hand. To preserve the amputated part for possible replantation, how should it be transported?", "choices": ["Submerge the part directly in ice water without wrapping", "Place the part directly on dry ice to freeze it", "Leave the part exposed to air at room temperature", "Soak the part in an antiseptic solution before transport", "Wrap in saline-moistened gauze, seal in a bag, and place on ice"], "ans": 4, "exp": "Amputated part preservation: ห่อด้วย 'saline-moistened gauze', ใส่ถุงกันน้ำ/sealed bag, แล้ววางบน 'ice' (ไม่ให้สัมผัส ice โดยตรง — กัน frostbite และ 'ห้ามแช่ในน้ำ/ice โดยตรง' หรือ dry ice). รีบส่งศูนย์ replantation. ควบคุมเลือดออกที่ stump ด้วย pressure"}, {"topic": "Frostbite", "q": "A hiker returns with white, hard, insensate fingers after severe cold exposure. What is the appropriate rewarming method?", "choices": ["Rapid rewarming in warm water once refreezing can be avoided", "Vigorous rubbing of the affected fingers with snow", "Slow rewarming next to an open flame or heater", "Immediate surgical debridement of all affected tissue", "Rewarming and then allowing the tissue to refreeze"], "ans": 0, "exp": "Frostbite: rewarm ด้วย 'warm water 37-39°C' rapid rewarming — เฉพาะเมื่อมั่นใจว่าจะไม่ refreeze (refreeze ทำอันตรายมากกว่า). ห้ามถูด้วยหิมะ/ความร้อนแห้ง/ไฟ. Analgesia (เจ็บมากตอน rewarm). ประเมิน demarcation ก่อน debride (รอหลายสัปดาห์ 'frostbite in January, amputate in July')"}, {"topic": "High-altitude illness", "q": "A trekker at high altitude develops severe dyspnea at rest, cough with frothy sputum, and hypoxia. What is the diagnosis and definitive treatment?", "choices": ["Acute mountain sickness; continue ascending slowly", "High-altitude pulmonary edema", "Community-acquired pneumonia; oral antibiotics", "Pulmonary embolism; systemic anticoagulation", "Asthma exacerbation; inhaled bronchodilators only"], "ans": 1, "exp": "High-altitude pulmonary edema (HAPE): dyspnea at rest + cough/frothy sputum + hypoxia at altitude. Definitive = 'immediate descent' + oxygen (± nifedipine, portable hyperbaric). HACE (cerebral edema): ataxia, altered mental status → descent + dexamethasone. AMS (headache/nausea) → หยุดขึ้น/acetazolamide. Descent คือหัวใจ"}, {"topic": "Crush syndrome", "q": "A patient trapped under rubble for hours is freed; you anticipate rhabdomyolysis. What is a key management priority to protect the kidneys?", "choices": ["Fluid restriction to prevent pulmonary edema", "Immediate limb amputation to remove damaged muscle", "Aggressive intravenous fluid and monitor for hyperkalemia", "Oral potassium supplementation for the muscle injury", "Withholding fluids until the urine turns clear"], "ans": 2, "exp": "Crush/rhabdomyolysis: muscle necrosis → myoglobin (AKI), 'hyperkalemia' (life-threatening arrhythmia), hypocalcemia, acidosis. รักษา: 'aggressive IV fluid' (รักษา urine output, ± bicarbonate/mannitol ในบางแนวทาง), monitor+treat hyperkalemia, ECG. ระวัง sudden hyperkalemia เมื่อปลดแรงกด (reperfusion)"}, {"topic": "Chest tube placement", "q": "A chest tube is being placed for a traumatic hemopneumothorax. What is the recommended safe site of insertion?", "choices": ["The 2nd intercostal space in the midclavicular line", "Directly over the lower border of the rib", "The midline over the sternum at the 5th space", "The 'triangle of safety'", "The posterior chest below the 8th rib routinely"], "ans": 3, "exp": "Chest tube (tube thoracostomy) วางที่ 'triangle of safety' — 4th-5th ICS, anterior-to-mid axillary line, 'เหนือขอบบนของ rib' (หลีกเลี่ยง neurovascular bundle ที่ขอบล่าง). Needle decompression (tension ptx) ที่ 2nd ICS MCL หรือ 4th-5th ICS AAL. วางต่ำ/หลังเกินเสี่ยง diaphragm/liver/spleen"}, {"topic": "Blood at meatus - workup order", "q": "In a multi-trauma patient, which injury pattern warrants evaluating the urethra before placing a urinary catheter?", "choices": ["Isolated closed forearm fracture", "Superficial facial laceration", "A simple ankle sprain from a fall", "An uncomplicated nasal bone fracture", "Pelvic fracture with blood at the urethral meatus"], "ans": 4, "exp": "ก่อนใส่ urinary catheter ต้องประเมิน urethra ถ้ามีสัญญาณ urethral injury: 'blood at meatus', high-riding/boggy prostate, perineal/scrotal hematoma, pelvic fracture. → retrograde urethrogram ก่อน. Isolated limb/face injury ไม่เกี่ยวกับ urethra"}, {"topic": "Damage control resuscitation", "q": "In severe trauma with the 'lethal triad', which three components must be aggressively prevented/corrected?", "choices": ["Hypothermia, acidosis, and coagulopathy", "Hypertension, alkalosis, and thrombocytosis", "Hyperglycemia, hypernatremia, and leukocytosis", "Fever, hypoxia, and hyperkalemia", "Bradycardia, hypocapnia, and anemia"], "ans": 0, "exp": "Lethal triad ของ trauma = 'hypothermia + acidosis + coagulopathy' (แต่ละอย่างทำให้อีกอย่างแย่ลง → เลือดออกไม่หยุด). Damage control resuscitation: warm patient, balanced transfusion (1:1:1), limit crystalloid, permissive hypotension, tranexamic acid, rapid hemorrhage control (damage control surgery)"}, {"topic": "Trauma in pregnancy", "q": "A pregnant woman at 30 weeks is stabilized after a car crash. Besides standard trauma care, what positioning and test are important?", "choices": ["Strict supine positioning with the legs elevated high", "Left lateral tilt to relieve aortocaval compression", "Immediate delivery regardless of maternal stability", "Withholding all imaging because of the pregnancy", "Prioritizing the fetus over maternal resuscitation"], "ans": 1, "exp": "Trauma ในหญิงตั้งครรภ์ (>20 wk): 'resuscitate mother first' (ช่วยแม่ = ช่วยลูก), 'left lateral tilt/manual uterine displacement' ลด aortocaval compression, monitor fetus (CTG), ประเมิน 'feto-maternal hemorrhage' (Kleihauer-Betke) และให้ anti-D ถ้าแม่ Rh-negative. อย่าเลี่ยง necessary imaging"}, {"topic": "Dog/cat bite prophylaxis", "q": "A patient has a deep cat bite over the hand. Which antibiotic is recommended for prophylaxis given the likely organism (Pasteurella multocida)?", "choices": ["Oral cephalexin as the drug of choice", "Topical antibiotic ointment alone", "Amoxicillin-clavulanate", "Oral azithromycin as first-line", "No antibiotic is ever needed for bites"], "ans": 2, "exp": "Bite wounds (cat > dog): เชื้อสำคัญ 'Pasteurella multocida' (+ anaerobes, Capnocytophaga) → prophylaxis/treatment ด้วย 'amoxicillin-clavulanate'. Cat bites (puncture ลึก) เสี่ยง infection สูง → ให้ prophylaxis เกือบทุกราย. ± tetanus/rabies. Human bite (Eikenella) ก็ใช้ amox-clav"}, {"topic": "Ocular chemical burn", "q": "A worker splashes an alkaline chemical into the eye. What is the immediate priority?", "choices": ["Patch the eye and refer without any irrigation", "Apply a topical steroid before any irrigation", "Neutralize the alkali with a weak acid solution", "Copious immediate irrigation with water/saline until pH normalizes", "Perform urgent surgery before decontamination"], "ans": 3, "exp": "Ocular chemical burn (โดยเฉพาะ 'alkali' → liquefactive necrosis, ลึก, อันตรายกว่า acid): priority = 'irrigate ทันทีและมากๆ' (water/saline) นานจน pH กลับปกติ (ก่อนทำอย่างอื่น). ห้าม neutralize ด้วยกรด. แล้วประเมิน/refer ophthalmology. 'Time is vision'"}, {"topic": "Globe rupture", "q": "An eye-trauma patient has a teardrop-shaped pupil, decreased vision, and a boggy globe with visible uveal tissue. What is the appropriate emergency management?", "choices": ["Apply a tight pressure patch to control the bleeding", "Irrigate the eye vigorously to clean the wound", "Instill topical anesthetic and probe the wound", "Measure intraocular pressure with tonometry immediately", "Place a rigid eye shield, avoid pressure, and urgent ophthalmology referral"], "ans": 4, "exp": "Globe rupture (teardrop/peaked pupil, ลด vision, uveal prolapse, boggy globe หลัง trauma): 'ห้ามกด/patch แน่น/วัด IOP/probe' (จะดัน content ออก) → วาง 'rigid shield' (ไม่กด), keep NPO, analgesia/antiemetic (กัน Valsalva), antibiotic, tetanus, urgent ophthalmology/surgery"}, {"topic": "Anterior shoulder dislocation", "q": "A patient falls on an outstretched arm and holds the shoulder abducted and externally rotated with a loss of the normal deltoid contour. What is the diagnosis?", "choices": ["Anterior shoulder dislocation", "Posterior shoulder dislocation", "Fractured clavicle", "Acromioclavicular joint separation", "Rotator cuff tear without dislocation"], "ans": 0, "exp": "Anterior shoulder dislocation (พบบ่อยสุด): แขนอยู่ท่า abducted + externally rotated, เสีย deltoid contour (squared-off), humeral head คลำได้ด้านหน้า. ตรวจ axillary nerve (sensation over deltoid) ก่อน/หลัง reduction. X-ray ก่อน/หลัง reduction. Posterior dislocation (มักจาก seizure/electrocution) แขน adducted + internally rotated"}, {"topic": "Posterior hip dislocation", "q": "A front-seat passenger in a head-on collision has a painful hip held flexed, adducted, and internally rotated with a shortened leg. What is the diagnosis and a key complication?", "choices": ["Anterior hip dislocation; risk of femoral nerve palsy", "Posterior hip dislocation", "Femoral neck fracture; risk of nonunion", "Knee dislocation; risk of popliteal artery injury", "Pelvic ring fracture; risk of bladder rupture"], "ans": 1, "exp": "Posterior hip dislocation (dashboard injury): hip 'flexed, adducted, internally rotated' + shortened leg. Emergency reduction (ยิ่งเร็วยิ่งดี) เพราะเสี่ยง 'avascular necrosis' ของ femoral head และ sciatic nerve injury. ตรวจ neurovascular. Anterior dislocation: hip abducted + externally rotated"}, {"topic": "Salter-Harris fracture", "q": "A child with a growth-plate (physeal) injury has a fracture that could affect future bone growth. Why are these injuries important?", "choices": ["Physeal fractures never affect growth in any way", "They only occur in adults with fused growth plates", "Physeal injury can cause growth arrest and limb deformity", "They always heal without any long-term consequence", "They are managed identically to adult shaft fractures"], "ans": 2, "exp": "Salter-Harris (physeal/growth-plate) fractures ในเด็ก อาจทำให้ 'growth arrest/angular deformity/limb length discrepancy' โดยเฉพาะ types สูง (III-V, ผ่าน epiphysis/crush). ต้อง proper reduction + follow-up growth. เด็กกระดูกยืดหยุ่น → greenstick/torus fractures ก็พบบ่อย"}, {"topic": "Knee dislocation - vascular", "q": "A patient with a traumatic knee dislocation that spontaneously reduced needs careful vascular assessment. Which injury must be excluded?", "choices": ["Femoral nerve transection", "Anterior cruciate ligament tear only", "Simple patellar dislocation", "Popliteal artery injury", "Isolated meniscal tear"], "ans": 3, "exp": "Knee dislocation (แม้ reduce เองแล้ว) เสี่ยง 'popliteal artery injury' สูง → ต้องประเมิน vascular อย่างระมัดระวัง (pulses, ABI, ± CT angiography) แม้ pulses ปกติ (intimal injury เกิด delayed thrombosis). Missed → limb loss. ตรวจ peroneal nerve ด้วย (foot drop)"}, {"topic": "Procedural sedation", "q": "Before performing procedural sedation for a fracture reduction in the emergency department, what is a key safety requirement?", "choices": ["Deep general anesthesia with paralysis for every procedure", "No monitoring is needed for short procedures", "The proceduralist alone manages both sedation and the procedure", "Reversal agents must be given routinely before sedation", "Monitoring, resuscitation equipment, and personnel able to manage the airway"], "ans": 4, "exp": "Procedural sedation & analgesia (PSA): ต้องมี 'monitoring' (SpO2, ± capnography, BP, ECG), resuscitation/airway equipment พร้อม, และ 'บุคลากรที่ดูแล sedation แยกจากผู้ทำหัตถการ' และสามารถจัดการ airway ได้. ประเมิน NPO/airway (LEMON). ยาที่ใช้: ketamine, propofol, midazolam/fentanyl"}, {"topic": "Ketamine", "q": "Which sedative agent is particularly useful for procedural sedation because it provides analgesia and tends to preserve airway reflexes and respiratory drive?", "choices": ["Ketamine", "Propofol", "Midazolam", "Thiopental", "Succinylcholine"], "ans": 0, "exp": "Ketamine (dissociative): ให้ทั้ง sedation + 'analgesia', รักษา airway reflexes/respiratory drive และ BP (sympathomimetic) — เหมาะกับเด็ก/หัตถการเจ็บ/hypotensive. ผลข้าง: emergence reaction, hypersalivation, laryngospasm (พบน้อย), เพิ่ม secretions. Propofol กด respiration/BP มากกว่า"}, {"topic": "RSI paralytic", "q": "During rapid sequence intubation, which depolarizing neuromuscular blocker has a rapid onset and short duration but is contraindicated in hyperkalemia, burns >24-48h, and crush injury?", "choices": ["Rocuronium", "Succinylcholine", "Vecuronium", "Atracurium", "Pancuronium"], "ans": 1, "exp": "Succinylcholine (depolarizing NMB): onset เร็ว (~45 วิ) + duration สั้น — เหมาะ RSI แต่ 'contraindicated' ใน hyperkalemia, major burns/crush/denervation (>24-48 ชม. เสี่ยง lethal hyperkalemia), history malignant hyperthermia, บาง myopathy. ทางเลือก: rocuronium (non-depolarizing, reversible ด้วย sugammadex)"}, {"topic": "Button battery ingestion", "q": "A toddler swallowed a coin-shaped object; radiograph shows a disc in the esophagus with a 'double-ring' halo sign. What is the management?", "choices": ["Observation to let the object pass naturally", "Induce vomiting to expel the object", "Emergent endoscopic removal", "Oral laxatives and discharge home", "Repeat the radiograph in one week"], "ans": 2, "exp": "Button battery ใน esophagus = emergency (double-ring/halo sign) — สร้าง caustic/electrical injury ภายในชั่วโมง → perforation/fistula/stricture. ต้อง 'emergent endoscopic removal' (honey อาจให้ระหว่างรอในบางแนวทาง). ต่างจากเหรียญธรรมดาในกระเพาะที่ asymptomatic ซึ่ง observe ได้"}, {"topic": "Foreign body aspiration", "q": "A toddler suddenly coughs, chokes, and wheezes while eating peanuts, with decreased breath sounds on one side. What is the diagnosis and definitive management?", "choices": ["Acute asthma; nebulized bronchodilators only", "Bronchiolitis; supportive care alone", "Bacterial pneumonia; intravenous antibiotics", "Foreign body aspiration", "Croup; nebulized epinephrine and steroid"], "ans": 3, "exp": "Foreign body aspiration (เด็กวัยเตาะแตะ, peanut/small object): sudden choking/cough/wheeze + unilateral decreased breath sounds; CXR อาจเห็น air trapping/hyperinflation ข้างที่อุด. Definitive = 'rigid bronchoscopy' removal. ถ้า complete obstruction + conscious → back blows/chest thrusts (infant) หรือ Heimlich (เด็กโต)"}, {"topic": "Decompression sickness", "q": "A scuba diver develops joint pain, skin mottling, and neurologic symptoms shortly after a rapid ascent. What is the diagnosis and definitive treatment?", "choices": ["Nitrogen narcosis; no treatment is needed", "Simple muscle strain; rest and analgesia", "Middle-ear barotrauma; decongestants only", "Panic attack; reassurance and breathing exercises", "Decompression sickness"], "ans": 4, "exp": "Decompression sickness ('the bends'): nitrogen bubbles หลัง rapid ascent → joint pain, skin (cutis marmorata), neurologic/pulmonary ('the chokes'). รักษา: high-flow O2 + IV fluid + 'recompression (hyperbaric oxygen) therapy' เป็น definitive. Arterial gas embolism ก็ต้อง hyperbaric. หลีกเลี่ยง air travel จนกว่าจะหาย"}, {"topic": "Lightning injury", "q": "In a mass-casualty lightning strike, which triage principle differs from the usual approach?", "choices": ["'Reverse triage' — resuscitate the apparently dead first", "Tag all apneic victims as expectant immediately", "Prioritize the walking wounded over cardiac arrest", "Withhold CPR from all lightning-strike victims", "Standard START triage applies without any change"], "ans": 0, "exp": "Lightning injury: ใช้ 'reverse triage' — ผู้ที่ดูเหมือนเสียชีวิต (respiratory/cardiac arrest จาก transient asystole/apnea) มีโอกาสรอดสูงถ้าได้ CPR/ventilation ทันที เพราะหัวใจอาจกลับเต้นเองแต่ apnea ทำให้ arrest ซ้ำ → ช่วยกลุ่ม 'apparently dead' ก่อน (ตรงข้ามหลัก triage ปกติ). เฝ้าระวัง arrhythmia, burns (Lichtenberg figure)"}, {"topic": "Subungual hematoma", "q": "A patient has severe throbbing pain under the fingernail after crushing it in a door; a hematoma occupies most of the nail bed but the nail and margins are intact. What is the appropriate management?", "choices": ["Immediate complete removal of the entire nail", "Trephination of the nail to relieve pressure", "Amputation of the distal fingertip", "Systemic anticoagulation to resorb the clot", "No intervention despite the severe pain"], "ans": 1, "exp": "Painful subungual hematoma (nail intact) → 'trephination' (เจาะเล็บระบายเลือด) ลด pressure/pain. ถ้า nail หรือ margin เสียหายมาก/สงสัย nail bed laceration ต้องประเมิน/repair. X-ray แยก distal phalanx fracture (tuft fracture — open fracture ถ้า nail bed ฉีก → antibiotic)"}, {"topic": "High-pressure injection injury", "q": "A worker accidentally injects paint under high pressure into a fingertip; the entry wound looks small but the finger is painful. Why is this a surgical emergency?", "choices": ["It is trivial and can be managed with a simple dressing", "The main risk is only a minor cosmetic scar", "Extensive deep tissue spread and necrosis despite a small wound", "It resolves spontaneously without any intervention", "The injected material is always harmless to tissue"], "ans": 2, "exp": "High-pressure injection injury: แผลภายนอกดูเล็กแต่ 'สารกระจายลึกตาม tendon sheath/tissue plane' → inflammation, ischemia, necrosis, compartment syndrome → เป็น 'surgical emergency' (urgent debridement/decompression). Delay = amputation. อย่าประเมินต่ำจากขนาดแผล"}, {"topic": "Open fracture management", "q": "A patient has an open tibial fracture with bone protruding through a contaminated wound. Besides splinting, what are the key early steps?", "choices": ["Immediate closure of the wound over the bone in the ED", "Delay all antibiotics until the operating room", "Vigorous scrubbing of the exposed bone at the bedside", "Early IV antibiotics, tetanus prophylaxis, wound cover, and urgent debridement", "Discharge with oral antibiotics and outpatient surgery"], "ans": 3, "exp": "Open fracture: control bleeding, cover wound (moist sterile), splint, ให้ 'IV antibiotics เร็ว' (cefazolin ± gram-negative/anaerobe coverage ตาม Gustilo grade) + 'tetanus prophylaxis' → urgent 'irrigation & debridement' + fracture stabilization ใน OR. ไม่ปิดแผลใน ED, ไม่ delay antibiotics"}, {"topic": "Compartment pressure", "q": "Which single clinical feature is the earliest and most sensitive for acute compartment syndrome?", "choices": ["Absent distal pulses in the affected limb", "Paralysis of the muscles in the compartment", "Pallor and coolness of the distal extremity", "Complete loss of sensation in the limb", "Pain out of proportion, worsened by passive stretch"], "ans": 4, "exp": "อาการแรก/ไวสุดของ compartment syndrome = 'pain out of proportion' + pain on passive stretch. 'Pulselessness/pallor/paralysis' เป็น 'late' signs (อาจ irreversible แล้ว) — อย่ารอ. ในผู้ป่วยที่ประเมินไม่ได้ (unconscious) ใช้การวัด compartment pressure. รักษา = fasciotomy"}, {"topic": "Needle thoracostomy site", "q": "For emergency needle decompression of a tension pneumothorax in an adult, which site is recommended?", "choices": ["5th intercostal space in the anterior axillary line", "Directly over the sternum at the 3rd interspace", "Below the 8th rib in the posterior axillary line", "The supraclavicular fossa above the clavicle", "The epigastrium just below the xiphoid process"], "ans": 0, "exp": "Needle decompression (tension pneumothorax): แนวทางปัจจุบันแนะนำ '5th ICS anterior/mid-axillary line' (chest wall บางกว่า เข็มถึง pleura ได้ดีกว่าในผู้ใหญ่ตัวใหญ่) หรือ classic '2nd ICS midclavicular line'. ตามด้วย chest tube. วางเข็ม 'เหนือขอบบนของ rib'"}, {"topic": "Traumatic hyphema", "q": "A patient struck in the eye has blood layering in the anterior chamber and pain. What is a key management point?", "choices": ["Apply a tight pressure patch and discharge home", "Elevate the head, limit activity, and monitor for rebleeding and raised IOP", "Irrigate the anterior chamber to remove the blood", "Vigorous eye movement exercises to clear the blood", "Immediate anticoagulation to prevent clot organization"], "ans": 1, "exp": "Traumatic hyphema (blood ใน anterior chamber): head elevation 30-45°, limit activity, shield, analgesia/antiemetic (กัน Valsalva), monitor 'rebleeding' (วันที่ 3-5) และ 'raised IOP' (โดยเฉพาะผู้มี sickle trait). Ophthalmology follow-up. ห้ามกด/anticoagulate; ระวัง associated globe rupture"}, {"topic": "Pediatric trauma differences", "q": "Compared with adults, which physiologic feature makes hypotension a late and ominous sign in an injured child?", "choices": ["Children lose blood pressure immediately with minor blood loss", "Children never develop shock from trauma", "Children maintain blood pressure by vasoconstriction until late", "Blood pressure norms in children are identical to adults", "Tachycardia is always absent in pediatric shock"], "ans": 2, "exp": "เด็ก compensate shock ได้ดี (tachycardia + vasoconstriction รักษา BP) จน blood loss มาก (~30-45%) แล้วจึง 'decompensate อย่างรวดเร็ว' → hypotension เป็น 'late/ominous' sign. จึงเฝ้าระวัง tachycardia/perfusion/mental status. ใช้ weight-based dosing, ระวัง hypothermia (surface area สูง)"}, {"topic": "Non-accidental injury", "q": "A 4-month-old presents with a spiral femur fracture, bruises of varying ages, and an inconsistent history. What must be considered and done?", "choices": ["Discharge home with reassurance and a cast", "Assume osteogenesis imperfecta and take no protective action", "Treat only the fracture and ignore the history", "Evaluate for non-accidental injury and report per protocol", "Delay evaluation until the next routine visit"], "ans": 3, "exp": "Red flags ของ child physical abuse: injury ไม่เข้ากับ mechanism/developmental stage (spiral femur ในทารกที่ยังเดินไม่ได้), bruises หลาย ages, inconsistent history. ต้องประเมิน non-accidental injury (skeletal survey, fundoscopy, coagulation), ดูแลความปลอดภัย และ 'รายงาน' ตามกฎหมาย. (หัวข้อละเอียดอ่อน — ดูแลรอบคอบ)"}, {"topic": "Minor burn care", "q": "A patient has a small superficial partial-thickness burn (blistered, painful, moist). What is appropriate outpatient care?", "choices": ["Apply ice directly to the burn for a prolonged time", "Rupture and debride all blisters aggressively at once", "Apply toothpaste or butter to soothe the area", "Leave it exposed and give prophylactic oral antibiotics", "Cool the burn, clean gently, apply a non-adherent dressing, and give analgesia"], "ans": 4, "exp": "Minor superficial partial-thickness burn: cool ด้วยน้ำอุณหภูมิห้อง (ไม่ใช่ ice โดยตรง — เพิ่ม injury), clean, apply non-adherent/antimicrobial dressing, analgesia, tetanus ตาม status. ไม่ทา toothpaste/butter. Blister management ตามแนวทาง. Prophylactic systemic antibiotic ไม่แนะนำ routine. Refer major/special-area burns"}, {"topic": "Burn referral criteria", "q": "Which burn should be referred to a specialized burn center?", "choices": ["Burns to the face, hands, feet, genitalia, or major joints", "A tiny superficial sunburn on the forearm", "A single small blister on one finger", "First-degree burn of a small skin area", "A minor scald that has already healed"], "ans": 0, "exp": "Burn center referral criteria: partial-thickness >10% TBSA, 'burns to face/hands/feet/genitalia/perineum/major joints', full-thickness burns, electrical/chemical burns, inhalation injury, burns ในเด็ก/ผู้สูงอายุ/comorbidity, circumferential burns. บริเวณ functional/cosmetic สำคัญจึงต้องดูแลเฉพาะทาง"}, {"topic": "Mass casualty - SALT", "q": "In a disaster, the first step of the SALT mass-casualty triage method after ensuring scene safety is what?", "choices": ["Individually assess every victim in the order found", "Global sorting: ask everyone who can walk to move to one area", "Transport all victims to the hospital immediately", "Provide definitive surgical care at the scene", "Wait for all resources before any assessment"], "ans": 1, "exp": "SALT triage (Sort-Assess-Lifesaving interventions-Treatment/Transport): เริ่มด้วย 'global sorting' — สั่งให้คนที่เดินได้ไปพื้นที่หนึ่ง (minor), คนที่ทำตามคำสั่ง/โบกมือได้เป็นลำดับถัดไป, ที่เหลือ (ไม่ขยับ) ประเมินก่อน. เป้าหมาย: จัดลำดับด้วยทรัพยากรจำกัด. คล้าย START แต่เพิ่ม lifesaving interventions"}, {"topic": "Hazmat decontamination", "q": "Patients exposed to a hazardous chemical arrive at the emergency department. What must happen before they enter the main treatment area?", "choices": ["Immediate transfer into the resuscitation room untouched", "Administration of antidotes before any decontamination", "Decontamination of patients", "Routine admission without any decontamination step", "Discharge home to shower and return later"], "ans": 2, "exp": "Hazmat/chemical exposure: ต้อง 'decontaminate' ผู้ป่วย (remove clothing + copious irrigation) 'ก่อน' เข้าพื้นที่รักษาหลัก เพื่อป้องกัน secondary contamination ของบุคลากร/สถานที่; staff ใส่ PPE. Life-saving interventions (airway, antidote สำหรับบางสาร) อาจทำระหว่าง/หลัง decontamination ตามสถานการณ์"}, {"topic": "Heat exhaustion vs heat stroke", "q": "A worker in the heat has fatigue, heavy sweating, headache, and nausea but a normal mental status and a core temperature of 39°C. What is the diagnosis?", "choices": ["Heat stroke", "Malignant hyperthermia", "Neuroleptic malignant syndrome", "Heat exhaustion", "Thyroid storm"], "ans": 3, "exp": "Heat exhaustion: heat illness ที่ core มัก <40°C และ 'mental status ปกติ' (fatigue, sweating, headache, nausea) → rest, cooling, oral/IV rehydration. ต่างจาก 'heat stroke' (core >40°C + 'CNS dysfunction' — confusion/seizure/coma) ที่เป็น emergency ต้อง rapid active cooling"}, {"topic": "Hydrofluoric acid burn", "q": "A worker splashes hydrofluoric acid on the hand, causing severe pain out of proportion to a small-looking burn. Besides irrigation, what is the specific antidote?", "choices": ["Sodium bicarbonate paste", "Silver sulfadiazine cream", "Systemic corticosteroids", "Activated charcoal application", "Topical/local calcium gluconate"], "ans": 4, "exp": "Hydrofluoric acid burn: fluoride ไป chelate calcium/magnesium → severe pain out of proportion + เสี่ยง 'systemic hypocalcemia/hypomagnesemia + hyperkalemia' (arrhythmia) แม้พื้นที่เล็ก. รักษา: irrigation + 'calcium gluconate' (topical gel, intradermal, หรือ intra-arterial) + monitor/correct electrolyte + ECG. เป็น burn ที่อันตรายเกินขนาดแผล"}, {"topic": "Penetrating neck injury", "q": "A patient has a stab wound to the neck with an expanding hematoma, stridor, and hemodynamic instability. What is the appropriate management?", "choices": ["Immediate airway control and surgical exploration", "Local wound probing to assess the depth", "Observation with serial neck examinations", "CT angiography before any airway intervention", "Discharge after simple wound closure"], "ans": 0, "exp": "Penetrating neck injury with 'hard signs' (expanding/pulsatile hematoma, active bleeding, airway compromise/stridor, shock, neuro deficit) → 'secure airway (early)' + 'immediate surgical exploration'. ห้าม probe wound (dislodge clot). Stable + no hard signs → CT angiography + selective management. Airway อาจแย่ลงเร็ว → intubate เร็ว"}, {"topic": "Orbital blow-out fracture", "q": "A patient struck in the eye has diplopia on upward gaze, an inability to elevate the eye, and infraorbital numbness. What is the diagnosis?", "choices": ["Globe rupture with uveal prolapse", "Orbital floor fracture with muscle entrapment", "Traumatic optic neuropathy", "Isolated corneal abrasion", "Acute angle-closure glaucoma"], "ans": 1, "exp": "Orbital floor 'blow-out' fracture: diplopia on upgaze + restricted elevation ('entrapment' ของ inferior rectus) + infraorbital nerve numbness (cheek/upper lip) + enophthalmos. ระวัง 'oculocardiac reflex' (bradycardia จาก entrapment ในเด็ก — white-eyed blowout, surgical urgency). CT orbit; ophthalmology/maxillofacial referral"}, {"topic": "Dental avulsion", "q": "A child has a permanent tooth completely knocked out (avulsed). What is the best immediate action to save the tooth?", "choices": ["Scrub the tooth clean with soap and water first", "Store the tooth dry in a tissue until the next day", "Reimplant it promptly or store it in milk/saliva and see a dentist urgently", "Discard the tooth as it cannot be saved", "Store the tooth in plain tap water for several hours"], "ans": 2, "exp": "Avulsed 'permanent' tooth: reimplant ทันที (จับที่ crown ไม่ใช่ root, ห้ามขัด/ล้างแรง) → ยิ่งเร็วยิ่งดี (survival ลดตามเวลา extra-oral). ถ้า reimplant ไม่ได้ เก็บใน 'milk' (หรือ saliva/Hank's solution, saline) ไม่เก็บแห้ง/น้ำประปา → รีบพบทันตแพทย์. Primary (baby) tooth ไม่ reimplant"}, {"topic": "Simple pneumothorax in trauma", "q": "A stable trauma patient is found to have a small simple pneumothorax and needs positive-pressure ventilation for another injury. What is the concern?", "choices": ["It will always resolve spontaneously during ventilation", "It has no relevance to mechanical ventilation", "It requires immediate thoracotomy before ventilation", "Positive-pressure ventilation may convert it to a tension pneumothorax", "It should be treated with anticoagulation"], "ans": 3, "exp": "Simple pneumothorax + positive-pressure ventilation (mechanical/anesthesia) → เสี่ยงเปลี่ยนเป็น 'tension pneumothorax' → มัก 'ใส่ chest tube ก่อน' ในผู้ที่ต้อง PPV/general anesthesia หรือ air transport. Occult pneumothorax เล็กในผู้ป่วยที่ไม่ต้อง PPV อาจ observe ได้"}, {"topic": "Scrotal / testicular trauma", "q": "A young man has severe scrotal pain and swelling after blunt trauma; ultrasound is needed to exclude which surgical emergency?", "choices": ["Simple epididymal cyst needing no treatment", "A varicocele requiring elective repair", "Chronic hydrocele managed conservatively", "Referred pain from a kidney stone", "Testicular rupture requiring surgical exploration"], "ans": 4, "exp": "Blunt scrotal trauma: ultrasound เพื่อประเมิน 'testicular rupture' (tunica albuginea disruption, heterogeneous testis) หรือ large hematocele → 'surgical exploration/repair' (salvage). ต้องแยก testicular torsion (อาจถูกกระตุ้นด้วย trauma) ซึ่งก็ต้อง explore ด่วน. Early surgery เพิ่มโอกาส salvage"}, {"topic": "Priapism", "q": "A man presents with a painful, rigid erection lasting more than 4 hours without sexual stimulation (ischemic/low-flow priapism). What is the appropriate emergency management?", "choices": ["Aspiration of the corpora and intracavernosal phenylephrine", "Observation for 24 hours before any intervention", "Immediate penile amputation to relieve the pain", "Systemic anticoagulation as the first-line therapy", "Warm compresses and discharge with follow-up"], "ans": 0, "exp": "Ischemic (low-flow) priapism >4 ชม. เป็น emergency (เสี่ยง fibrosis/impotence) → 'corporal aspiration + intracavernosal sympathomimetic (phenylephrine)'; refractory → shunt/surgery. หาสาเหตุ (sickle cell, ยา, injection). High-flow (non-ischemic, painless, post-trauma) จัดการต่างกัน (มัก observe/embolization)"}, {"topic": "Anticoagulated head injury", "q": "An elderly patient on warfarin has a minor head injury with no symptoms. What is the appropriate approach?", "choices": ["Discharge immediately without imaging since he is asymptomatic", "CT head and consider observation, because delayed intracranial bleeding is a risk", "Stop all monitoring because minor trauma is always benign", "Give prophylactic mannitol to every anticoagulated patient", "Reverse anticoagulation routinely even without bleeding"], "ans": 1, "exp": "ผู้สูงอายุ/ผู้ใช้ anticoagulant (warfarin/DOAC) ที่ head injury แม้ 'minor/asymptomatic' → เสี่ยง 'intracranial hemorrhage' (รวม delayed) → ควร 'CT head' + พิจารณา observation. ถ้ามี ICH → รีบ reverse (vitamin K + PCC สำหรับ warfarin; specific reversal สำหรับ DOAC) + neurosurgery. Low threshold to image"}, {"topic": "Nasal foreign body", "q": "A toddler has unilateral foul-smelling purulent nasal discharge for several days. What should be suspected?", "choices": ["Bilateral acute bacterial sinusitis", "Allergic rhinitis with infection", "A retained nasal foreign body", "A congenital choanal atresia", "A nasopharyngeal tumor"], "ans": 2, "exp": "Unilateral foul-smelling purulent nasal discharge ในเด็กเล็ก = 'nasal foreign body' จนกว่าจะพิสูจน์เป็นอื่น → ตรวจและเอาออก. Button battery/magnet ในจมูกเป็น emergency (tissue necrosis). Bilateral discharge มักเป็น URI/sinusitis. Choanal atresia present ตั้งแต่แรกเกิด"}, {"topic": "Corneal abrasion", "q": "A patient has eye pain, foreign-body sensation, and tearing after a scratch; fluorescein staining shows an epithelial defect without infection. What is the management?", "choices": ["A tight double eye patch worn for a week", "Topical corticosteroids as first-line therapy", "Long-term topical anesthetic drops for the pain", "Topical antibiotic, analgesia, and avoiding the eye patch/contact lenses", "Immediate surgical repair of the epithelium"], "ans": 3, "exp": "Corneal abrasion (fluorescein uptake, ไม่มี infiltrate): topical antibiotic prophylaxis, analgesia (oral/topical NSAID), หลีกเลี่ยง contact lens; ไม่ patch (โดยเฉพาะ contact lens wearer — เสี่ยง Pseudomonas). 'ห้ามให้ topical anesthetic กลับบ้าน' (delayed healing/toxicity). ติดตามถ้าไม่ดีขึ้น/สงสัย ulcer"}, {"topic": "Strangulation / hanging", "q": "A near-hanging victim survives with neck swelling and hoarseness. Besides airway assessment, what delayed complication should be anticipated?", "choices": ["Only a minor skin abrasion with no other risk", "Immediate resolution with no monitoring needed", "Isolated psychological effects without physical harm", "A benign course allowing immediate discharge", "Airway edema and possible delayed airway obstruction"], "ans": 4, "exp": "Near-hanging/strangulation: เสี่ยง 'airway edema' ที่แย่ลง (delayed obstruction) → early airway assessment/protection + observe; ประเมิน laryngeal/vascular (carotid dissection) injury, hypoxic brain injury, cervical spine. (เป็นหัวข้อละเอียดอ่อน — ต้องประเมิน suicide risk + mental health support)"}, {"topic": "Seatbelt sign / bowel injury", "q": "A restrained passenger has a transverse abdominal bruise ('seatbelt sign') and a lumbar (Chance) fracture. What associated injury must be excluded?", "choices": ["Hollow viscus injury", "Isolated superficial skin bruising only", "A benign muscular strain of the abdomen", "An uncomplicated single rib fracture", "A simple urinary tract infection"], "ans": 0, "exp": "'Seatbelt sign' (transverse abdominal ecchymosis) + Chance fracture (flexion-distraction lumbar) สัมพันธ์กับ 'hollow viscus/mesenteric injury' (bowel perforation อาจ present ล่าช้า). ต้องประเมินซ้ำ + CT + observation; low threshold for laparotomy ถ้ามี peritonitis. อย่าประเมินต่ำจากภายนอก"}, {"topic": "Blast lung", "q": "An explosion victim without external chest wounds develops hypoxia, hemoptysis, and bilateral infiltrates. What is the mechanism of this primary blast injury?", "choices": ["Penetrating shrapnel damaging the lung directly", "Barotrauma to the alveoli from the pressure wave", "Aspiration of gastric contents during the blast", "Fat embolism from associated long-bone fractures", "Chemical inhalation from the explosive residue"], "ans": 1, "exp": "Blast lung (primary blast injury): pressure wave ต่อ air-filled lung → alveolar barotrauma/hemorrhage → hypoxia, hemoptysis, bilateral infiltrates (คล้าย pulmonary contusion/ARDS), เสี่ยง pneumothorax/air embolism. รักษา supportive (gentle ventilation, ระวัง PPV → air embolism/pneumothorax). อาจไม่มีแผลภายนอก"}, {"topic": "Retrobulbar hemorrhage", "q": "After facial trauma, a patient develops proptosis, severe eye pain, decreased vision, and a very high intraocular pressure (orbital compartment syndrome). What is the sight-saving emergency procedure?", "choices": ["Immediate systemic anticoagulation", "A tight pressure patch over the eye", "Lateral canthotomy and cantholysis", "Topical antibiotic drops and observation", "Delayed elective orbital surgery next week"], "ans": 2, "exp": "Retrobulbar hemorrhage → orbital compartment syndrome (proptosis, ↓vision, ↑IOP, ophthalmoplegia) เป็น 'sight-threatening emergency' — vision loss ภายในชั่วโมง → 'lateral canthotomy and cantholysis' ที่ bedside เพื่อลด orbital pressure ทันที. Time-critical เหมือน compartment syndrome ที่อื่น"}, {"topic": "Fournier gangrene", "q": "A diabetic man has rapidly spreading pain, swelling, crepitus, and skin necrosis of the perineum/scrotum with systemic toxicity. What is the diagnosis and management?", "choices": ["Simple scrotal cellulitis; oral antibiotics at home", "An epididymo-orchitis; scrotal support and NSAIDs", "A strangulated inguinal hernia; elective repair", "Fournier gangrene", "Contact dermatitis; topical corticosteroid cream"], "ans": 3, "exp": "Fournier gangrene = necrotizing fasciitis ของ perineum/genitalia (มักในผู้ป่วยเบาหวาน/immunocompromised): pain out of proportion, crepitus, skin necrosis, systemic toxicity → 'emergency surgical debridement' + broad-spectrum antibiotics + resuscitation. Delay = fatal. คล้าย necrotizing fasciitis ที่อื่น (surgical emergency)"}, {"topic": "Acute mesenteric ischemia", "q": "An elderly patient with atrial fibrillation has sudden severe abdominal pain out of proportion to a soft, minimally tender abdomen, with elevated lactate. What is the diagnosis?", "choices": ["Acute appendicitis with early peritonitis", "Uncomplicated gastroenteritis", "Simple constipation with distension", "Acute pancreatitis of gallstone origin", "Acute mesenteric ischemia"], "ans": 4, "exp": "Acute mesenteric ischemia (มัก embolism จาก AF ไป SMA): 'pain out of proportion' ต่อการตรวจ (soft abdomen ระยะแรก) + elevated lactate + risk factors. วินิจฉัยด้วย CT angiography. เป็น emergency → resuscitation, anticoagulation, revascularization (surgery/endovascular) ± bowel resection. Delay → bowel infarction/death"}, {"topic": "Ruptured AAA", "q": "An elderly man has sudden severe abdominal/back pain, hypotension, and a pulsatile abdominal mass. What is the diagnosis and management?", "choices": ["Ruptured abdominal aortic aneurysm", "Renal colic; analgesia and outpatient urology", "Acute pancreatitis; supportive care and fluids", "Diverticulitis; antibiotics and bowel rest", "Musculoskeletal back pain; rest and analgesia"], "ans": 0, "exp": "Ruptured abdominal aortic aneurysm (AAA): triad = 'sudden abdominal/back pain + hypotension + pulsatile abdominal mass' ในผู้สูงอายุ. เป็น surgical emergency → immediate resuscitation (permissive hypotension) + 'emergency repair' (open/endovascular EVAR). Unstable → OR ทันที (ไม่รอ imaging); stable → CT. Mortality สูง"}, {"topic": "Testicular torsion", "q": "A 14-year-old has sudden severe scrotal pain with a high-riding testis, horizontal lie, and an absent cremasteric reflex. What is the management?", "choices": ["Antibiotics with outpatient urology follow-up", "Emergency surgical exploration and detorsion", "Scrotal elevation and NSAIDs with observation", "Doppler ultrasound before any intervention regardless of delay", "Warm compresses and discharge home overnight"], "ans": 1, "exp": "Testicular torsion: sudden severe pain + high-riding testis + horizontal lie + 'absent cremasteric reflex' + negative Prehn sign. Surgical emergency — salvage สูงถ้า detorsion ภายใน ~6 ชม. → 'emergency exploration' (ไม่ delay เพื่อ imaging ถ้า classic; manual detorsion เป็น temporizing). ต่างจาก epididymitis (gradual, fever, cremasteric intact)"}, {"topic": "Rib fracture in elderly", "q": "An elderly patient with multiple rib fractures is at particular risk of which complication that guides aggressive analgesia and monitoring?", "choices": ["Immediate cardiac arrest from the rib pain", "Rapid healing with no significant risk", "Pneumonia and respiratory failure from splinting/hypoventilation", "Only cosmetic chest wall deformity", "Isolated skin bruising without deeper effects"], "ans": 2, "exp": "Rib fractures ในผู้สูงอายุเพิ่ม morbidity/mortality อย่างมาก — pain → 'splinting/hypoventilation' → atelectasis → 'pneumonia/respiratory failure'. จัดการด้วย 'aggressive multimodal analgesia' (รวม regional/epidural), pulmonary toilet/incentive spirometry, monitoring. ≥3 ribs หรือผู้สูงอายุ → พิจารณา admit"}, {"topic": "Epistaxis - posterior", "q": "A hypertensive elderly patient has heavy nosebleed not controlled by anterior pressure, with blood draining down the throat. What is likely and how is it managed?", "choices": ["Anterior epistaxis; more nasal pinching at home", "A trivial bleed requiring no intervention", "Bleeding from the frontal sinus needing surgery", "Posterior epistaxis", "Hemoptysis from a lung source, not the nose"], "ans": 3, "exp": "Posterior epistaxis (มักผู้สูงอายุ/HT, เลือดไหลลงคอ, คุมด้วย anterior pressure/packing ไม่ได้): ต้อง 'posterior packing' (balloon/gauze) + admit/ENT referral (เสี่ยง airway/aspiration/complications). Anterior epistaxis (Little's area) มักคุมได้ด้วยบีบจมูก 10 นาที ± cautery/anterior packing"}, {"topic": "Acute urinary retention", "q": "An elderly man cannot pass urine and has a painful, distended, palpable bladder. What is the immediate management?", "choices": ["Fluid restriction to reduce the urine production", "Immediate prostate surgery in the emergency department", "Diuretics to force urine past the obstruction", "Observation because it will resolve spontaneously", "Urgent urethral catheterization to drain the bladder"], "ans": 4, "exp": "Acute urinary retention (painful distended bladder, unable to void): immediate 'catheterization' (urethral; suprapubic ถ้าใส่ urethral ไม่ได้/contraindicated) เพื่อ decompress + relief. หา precipitant (BPH, ยา anticholinergic, infection, neurologic). เฝ้าระวัง 'post-obstructive diuresis'. BPH → alpha-blocker; urology follow-up"}, {"topic": "Angioedema airway", "q": "A patient on an ACE inhibitor develops progressive tongue and lip swelling without urticaria, threatening the airway. What is the priority?", "choices": ["Early airway assessment/securing and stopping the ACE inhibitor", "High-dose intramuscular adrenaline as the definitive cure", "Oral antihistamine with discharge home", "Reassurance since it will resolve within minutes", "Immediate tracheostomy for every patient"], "ans": 0, "exp": "ACE inhibitor-induced angioedema (bradykinin-mediated, ไม่มี urticaria/itch) → priority = 'airway' (early assessment, พร้อม intubate/surgical airway เพราะแย่ลงเร็ว) + หยุด ACE inhibitor. มัก 'ไม่ตอบสนอง' adrenaline/antihistamine/steroid (ต่างจาก allergic/histaminergic angioedema/anaphylaxis). Hereditary angioedema (C1-INH) ก็ bradykinin — ใช้ specific therapy"}, {"topic": "Compression-only bystander vs drowning", "q": "For a drowning victim in arrest, why is standard CPR with rescue breaths (rather than compression-only) preferred if the rescuer is able?", "choices": ["Because drowning victims never need chest compressions", "Because hypoxia is the primary cause, so ventilations are essential", "Because compressions worsen the aspirated water", "Because ventilations are contraindicated in drowning", "Because defibrillation always precedes any ventilation"], "ans": 1, "exp": "Drowning arrest เกิดจาก 'hypoxia' เป็นหลัก → 'rescue breaths/ventilation จำเป็น' (standard CPR with breaths ดีกว่า compression-only ถ้าทำได้) และเริ่มด้วย rescue breaths. ต่างจาก cardiac arrest ทั่วไปที่ compression-only เพียงพอสำหรับ bystander ที่ไม่ได้ฝึก"}, {"topic": "Fishhook removal", "q": "A patient has a fishhook embedded in the finger with the barb below the skin. After assessing neurovascular status and tetanus, what is a common removal technique?", "choices": ["Forcefully pull the hook straight out against the barb", "Leave the hook in place permanently", "Advance-and-cut", "Amputate the fingertip to remove the hook", "Apply strong traction with pliers without any technique"], "ans": 2, "exp": "Fishhook (barbed) removal: เทคนิคเช่น 'advance-and-cut' (ดัน barb ทะลุผิว ตัด barb แล้วดึงย้อนออก) หรือ string-yank/needle-cover techniques — เพราะดึงตรงย้อนออกจะติด barb และฉีกเนื้อ. ประเมิน neurovascular, ล้างแผล, tetanus prophylaxis, antibiotic ตามความจำเป็น"}, {"topic": "Geriatric fall workup", "q": "An elderly patient presents after a 'mechanical fall.' Beyond treating injuries, what is an important consideration?", "choices": ["Assume all elderly falls are purely accidental with no workup", "Discharge immediately once fractures are excluded", "Attribute the fall solely to old age without evaluation", "Search for an underlying medical cause", "Restrict all future mobility to prevent any falls"], "ans": 3, "exp": "Elderly fall: อย่ามองว่าเป็น 'mechanical' เสมอ — ต้องหา 'underlying cause' (syncope/arrhythmia, orthostatic hypotension, infection/sepsis, hypoglycemia, stroke/TIA, polypharmacy/sedatives, dehydration) + ประเมิน injury (โดยเฉพาะ head injury ในผู้ใช้ anticoagulant, hip fracture) + fall-risk/functional assessment เพื่อป้องกันซ้ำ"}, {"topic": "Burn depth", "q": "A burn appears white and leathery, is dry, and is insensate to pinprick. What depth of burn is this?", "choices": ["Superficial (first-degree) burn", "Superficial partial-thickness burn", "Simple sunburn without dermal injury", "Epidermal-only erythema", "Full-thickness burn"], "ans": 4, "exp": "Full-thickness (3rd-degree) burn: ทำลาย epidermis + dermis ทั้งหมด → white/leathery/charred, 'dry', 'insensate' (ทำลาย nerve endings). Superficial (1st): red, painful, ไม่มี blister. Superficial partial (2nd): red/moist/blister, เจ็บมาก. Deep burn มัก need grafting; ประเมิน %TBSA เฉพาะ partial+full"}, {"topic": "Nasal septal hematoma", "q": "After nasal trauma, examination shows a bluish, boggy swelling on the nasal septum. Why must this be drained urgently?", "choices": ["Untreated, it can cause septal necrosis and 'saddle nose' deformity", "It always resolves without any intervention", "It only causes a minor cosmetic concern", "It is a normal finding after any nosebleed", "Drainage should be delayed for several weeks"], "ans": 0, "exp": "Septal hematoma (boggy swelling บน septum หลัง trauma) ต้อง 'incise & drain ด่วน' เพราะ hematoma ตัด blood supply → septal cartilage necrosis/abscess → 'saddle nose' deformity และ perforation. ต้องตรวจ septum ในผู้บาดเจ็บจมูกทุกราย"}, {"topic": "Ellis dental fracture", "q": "A patient chips a front tooth and now has pink/red exposed tissue at the fracture site with bleeding from the tooth (pulp exposure). What is the significance?", "choices": ["It is a trivial enamel chip needing no follow-up", "Pulp exposure needs urgent dental referral", "The tooth must always be extracted immediately", "It never causes pain or infection", "It can be safely ignored for months"], "ans": 1, "exp": "Dental crown fracture ที่มี 'pulp exposure' (Ellis III — เห็นเนื้อชมพู/แดง, เลือดออกจากฟัน) เจ็บและเสี่ยง infection/pulp necrosis → 'urgent dental referral' (pulp protection/treatment). Enamel-only (Ellis I) ไม่เร่งด่วน; dentin exposure (Ellis II, เหลือง) ต้อง cover และพบทันตแพทย์"}, {"topic": "Ear foreign body - insect", "q": "A patient has a live insect in the ear canal causing intense buzzing and pain. What is an appropriate first step before removal?", "choices": ["Irrigate with water when a button battery is suspected", "Push the object deeper to dislodge it from behind", "Immobilize/kill the insect with mineral oil or lidocaine", "Leave the live insect in place indefinitely", "Use forceps blindly without visualizing the canal"], "ans": 2, "exp": "Live insect ในหู: หยอด 'mineral oil / lidocaine' เพื่อ immobilize/kill ก่อน (ลดการดิ้น/เจ็บ) แล้วเอาออก (irrigation/instrument ภายใต้การมองเห็น). 'ห้าม irrigate' ถ้าเป็น button battery หรือ organic material ที่พองน้ำ (เช่นถั่ว/เมล็ด). ระวัง TM perforation"}, {"topic": "Marine envenomation - jellyfish", "q": "A swimmer is stung by a jellyfish with painful linear welts. What is a generally appropriate first-aid measure for many species?", "choices": ["Rinse vigorously with fresh water and rub the area", "Apply ice directly and scrub off tentacles with a towel", "Apply a tight arterial tourniquet to the limb", "Rinse with vinegar/sea water and remove tentacles", "Do nothing, as jellyfish stings are always harmless"], "ans": 3, "exp": "Jellyfish sting: remove tentacles (ไม่ถูด้วยมือเปล่า), rinse ด้วย 'sea water/vinegar' (vinegar inactivate nematocysts ในหลาย species เช่น box jellyfish) — 'หลีกเลี่ยง fresh water/ถู/ice' (กระตุ้น nematocyst discharge เพิ่ม). Hot-water immersion (~45°C) ลดปวด. Box jellyfish (Chironex) รุนแรง อาจ arrest → resuscitate + antivenom"}, {"topic": "Penile fracture", "q": "A man hears a 'crack' with sudden pain, detumescence, swelling, and an eggplant-shaped penile deformity during intercourse. What is the diagnosis and management?", "choices": ["Simple bruise; ice and reassurance at home", "Priapism; corporal aspiration and phenylephrine", "Peyronie disease; elective outpatient management", "Urethral stricture; scheduled dilatation", "Penile fracture"], "ans": 4, "exp": "Penile fracture (rupture ของ tunica albuginea, มักขณะ intercourse): 'cracking' sound + pain + rapid detumescence + swelling/hematoma ('eggplant deformity'). เป็น urologic emergency → 'urgent surgical repair'. ประเมิน urethral injury ร่วม (blood at meatus, gross hematuria → retrograde urethrogram)"}]}, {"id": "er-3", "title": "เวชศาสตร์ฉุกเฉิน ชุดที่ 3 — Toxicology & Medical Emergencies", "subject": "emergency", "questions": [{"topic": "Paracetamol overdose", "q": "A teenager presents 4 hours after ingesting a large amount of paracetamol and is currently asymptomatic. What is the appropriate management?", "choices": ["Measure the paracetamol level and treat with N-acetylcysteine per nomogram", "Reassure and discharge because she is asymptomatic now", "Induce vomiting with syrup of ipecac immediately", "Give activated charcoal only and then discharge home", "Wait for signs of liver failure before any treatment"], "ans": 0, "exp": "Paracetamol (acetaminophen) overdose มัก asymptomatic ระยะแรก แต่เสี่ยง hepatotoxicity → วัด 'level ที่ ≥4 ชม.' เทียบ Rumack-Matthew nomogram → ให้ 'N-acetylcysteine' (ดีสุด <8-10 ชม.). Activated charcoal ถ้ามาเร็ว (<1-2 ชม.). อย่ารอ liver failure. NAC เป็น antidote ที่มีประสิทธิภาพสูง"}, {"topic": "Organophosphate poisoning", "q": "A farmer presents with excessive salivation, lacrimation, urination, defecation, miosis, bradycardia, muscle fasciculations, and bronchorrhea after pesticide exposure. What is the antidote?", "choices": ["Naloxone repeated until the pupils dilate", "Atropine plus pralidoxime", "Flumazenil to reverse the cholinergic state", "N-acetylcysteine as the specific antidote", "Physostigmine to reverse the toxidrome"], "ans": 1, "exp": "Organophosphate (cholinergic crisis, SLUDGE/DUMBELS + miosis + bronchorrhea + fasciculations): antidote = 'atropine' (titrate to drying of secretions — เป้าหลัก) + 'pralidoxime' (reactivate cholinesterase, ช่วย nicotinic/muscle) + decontamination + airway support. ไม่ใช้ physostigmine (จะเพิ่ม cholinergic)"}, {"topic": "Salicylate poisoning", "q": "A patient who ingested aspirin has tinnitus, hyperventilation, vomiting, fever, and a mixed respiratory alkalosis with high anion gap metabolic acidosis. What is a key treatment?", "choices": ["Naloxone infusion to reverse the toxidrome", "Atropine and pralidoxime as the antidote", "Urine alkalinization with sodium bicarbonate", "N-acetylcysteine given per the nomogram", "Deferoxamine to chelate the salicylate"], "ans": 2, "exp": "Salicylate (aspirin) poisoning: มี 'mixed acid-base' (respiratory alkalosis + high anion gap metabolic acidosis), tinnitus, hyperthermia. รักษา: 'urine alkalinization ด้วย sodium bicarbonate' (เพิ่ม renal excretion + ลด CNS penetration), fluid, glucose, 'hemodialysis' ในรายรุนแรง (high level, severe acidosis, CNS/renal). ระวัง intubation (ต้องคง minute ventilation สูง)"}, {"topic": "Opioid overdose", "q": "An unresponsive patient has pinpoint pupils and a respiratory rate of 4/min. What is the antidote?", "choices": ["Flumazenil", "Atropine", "Physostigmine", "Naloxone", "Deferoxamine"], "ans": 3, "exp": "Opioid toxidrome (miosis + respiratory depression + CNS depression): antidote = 'naloxone' (titrate to adequate respiration, ไม่ต้องให้ถึงตื่นเต็ม), support ventilation. ระวัง re-sedation (naloxone half-life สั้นกว่า opioid หลายชนิด) → observe/repeat/infusion. Flumazenil = benzodiazepine"}, {"topic": "Tricyclic antidepressant overdose", "q": "A patient with a tricyclic antidepressant overdose has a widened QRS (>100 ms), hypotension, and seizures. What is the specific treatment for the cardiotoxicity?", "choices": ["Intravenous calcium gluconate", "Intravenous magnesium as first-line", "Digoxin-specific antibody fragments", "Intravenous glucagon infusion", "Intravenous sodium bicarbonate"], "ans": 4, "exp": "TCA overdose: anticholinergic + 'sodium channel blockade' (wide QRS, arrhythmia) + alpha-block (hypotension) + seizures. Specific treatment ของ cardiotoxicity = 'IV sodium bicarbonate' (narrow QRS, treat hypotension/arrhythmia) เมื่อ QRS >100 ms หรือ arrhythmia/hypotension. Benzodiazepine สำหรับ seizure. หลีกเลี่ยง class Ia/Ic/III antiarrhythmics"}, {"topic": "Methanol / ethylene glycol", "q": "A patient with a high anion gap metabolic acidosis and an elevated osmolar gap after ingesting antifreeze or bootleg alcohol needs an antidote. What is it?", "choices": ["Fomepizole plus hemodialysis", "Naloxone with supportive care", "N-acetylcysteine per the nomogram", "Atropine and pralidoxime together", "Activated charcoal as the definitive therapy"], "ans": 0, "exp": "Toxic alcohols (methanol → blindness; ethylene glycol → renal failure/oxalate crystals): high anion gap metabolic acidosis + 'elevated osmolar gap'. Antidote = 'fomepizole' (หรือ ethanol) ยับยั้ง alcohol dehydrogenase (บล็อกการสร้าง toxic metabolite) + 'hemodialysis' ในรายรุนแรง + cofactors (folate/thiamine/pyridoxine). Charcoal ไม่จับ alcohols"}, {"topic": "Iron poisoning", "q": "A toddler ingests adult iron tablets and develops vomiting with hematemesis, abdominal pain, then metabolic acidosis. Which antidote is used for severe poisoning?", "choices": ["N-acetylcysteine", "Deferoxamine", "Naloxone", "Atropine", "Fomepizole"], "ans": 1, "exp": "Iron poisoning stages: GI (vomiting/hematemesis) → latent → shock/metabolic acidosis → hepatic failure → late stricture. 'Activated charcoal ไม่จับ iron'. Severe/symptomatic (high level, radio-opaque tablets, acidosis) → 'deferoxamine' (chelation) + supportive/fluid. เป็นสาเหตุ pediatric poisoning fatality — เก็บยาพ้นมือเด็ก"}, {"topic": "Carbon monoxide", "q": "A family presents with headache, nausea, dizziness, and confusion after using a charcoal heater indoors; pulse oximetry reads normal. What is the treatment?", "choices": ["Naloxone with airway support", "Methylene blue given intravenously", "High-flow 100% oxygen", "Deferoxamine to chelate the toxin", "Atropine to reverse the symptoms"], "ans": 2, "exp": "Carbon monoxide poisoning: CO จับ hemoglobin แน่นกว่า O2 → tissue hypoxia; pulse ox 'อาจปกติ' (ต้อง co-oximetry วัด COHb). อาการ: headache, nausea, confusion, coma. รักษา: 'high-flow 100% O2' (เร่ง CO elimination); hyperbaric O2 ถ้า severe (LOC, neuro, cardiac ischemia, pregnancy, high COHb). Cherry-red เป็น late/unreliable"}, {"topic": "Methemoglobinemia", "q": "A patient has cyanosis unresponsive to oxygen, chocolate-brown blood, and a saturation gap after exposure to an oxidizing agent (e.g., topical anesthetic, dapsone). What is the antidote?", "choices": ["Naloxone", "Hydroxocobalamin", "Deferoxamine", "Methylene blue", "Fomepizole"], "ans": 3, "exp": "Methemoglobinemia: Fe3+ ไม่จับ O2 → cyanosis 'ไม่ตอบสนอง O2', 'chocolate-brown blood', pulse ox ~85% (saturation gap). สาเหตุ: oxidizing drugs/chemicals (topical anesthetics, dapsone, nitrates). Antidote = 'methylene blue' (ระวังใน G6PD deficiency) + remove agent. Severe/G6PD → exchange transfusion/ascorbic acid"}, {"topic": "Sympathomimetic toxidrome", "q": "A young man brought in agitated after amphetamine use has hyperthermia, tachycardia, hypertension, mydriasis, and diaphoresis. What is the mainstay of management?", "choices": ["Beta-blocker monotherapy to control the blood pressure", "Physostigmine to reverse the agitation", "Naloxone to reverse the stimulant effect", "Haloperidol as the single first-line agent", "Benzodiazepines, cooling, and supportive care"], "ans": 4, "exp": "Sympathomimetic toxidrome (amphetamine/cocaine): hyperthermia, tachycardia, hypertension, mydriasis, diaphoresis, agitation. Mainstay = 'benzodiazepines' (ลด agitation/sympathetic drive, ป้องกัน seizure) + active cooling + fluid + supportive. 'หลีกเลี่ยง beta-blocker เดี่ยว' ใน cocaine (unopposed alpha → worse hypertension/coronary spasm)"}, {"topic": "Anticholinergic toxidrome", "q": "A patient is 'hot as a hare, red as a beet, dry as a bone, blind as a bat, mad as a hatter' with urinary retention after an overdose. Which toxidrome is this?", "choices": ["Anticholinergic toxidrome", "Cholinergic toxidrome", "Opioid toxidrome", "Sympathomimetic toxidrome", "Sedative-hypnotic toxidrome"], "ans": 0, "exp": "Anticholinergic toxidrome (antihistamine, TCA, atropine, jimsonweed): 'hot (hyperthermia), red (flushed), dry (no sweat/secretions), blind (mydriasis/blurred), mad (delirium)' + urinary retention + tachycardia + ↓bowel sounds. รักษา supportive + benzodiazepine; physostigmine ในบางกรณี (ระวัง). ตรงข้ามกับ cholinergic (wet, miosis)"}, {"topic": "Serotonin syndrome", "q": "A patient on an SSRI who was given tramadol develops agitation, hyperthermia, clonus, hyperreflexia (worse in the legs), and diaphoresis. What is the diagnosis?", "choices": ["Neuroleptic malignant syndrome", "Serotonin syndrome", "Malignant hyperthermia", "Anticholinergic toxidrome", "Thyroid storm"], "ans": 1, "exp": "Serotonin syndrome (serotonergic drug combinations เช่น SSRI + tramadol/MAOI/linezolid): triad = 'neuromuscular hyperactivity' (clonus, hyperreflexia เด่นที่ขา, tremor) + autonomic (hyperthermia, diaphoresis, tachycardia) + altered mental status; onset เร็ว (<24 ชม.). รักษา: หยุดยา, benzodiazepine, cooling, cyproheptadine. ต่างจาก NMS (rigidity, bradyreflexia, ช้ากว่า)"}, {"topic": "Neuroleptic malignant syndrome", "q": "A patient on an antipsychotic develops high fever, 'lead-pipe' muscle rigidity, altered consciousness, autonomic instability, and a markedly elevated creatine kinase over days. What is the diagnosis?", "choices": ["Serotonin syndrome", "Malignant hyperthermia", "Neuroleptic malignant syndrome", "Sympathomimetic toxidrome", "Anticholinergic delirium"], "ans": 2, "exp": "Neuroleptic malignant syndrome (NMS): antipsychotic/dopamine blockade → hyperthermia + 'lead-pipe rigidity' + altered consciousness + autonomic instability + high CK (rhabdomyolysis); onset ช้า (วัน). รักษา: หยุดยา, cooling, supportive, dantrolene/bromocriptine ในรายรุนแรง. ต่างจาก serotonin syndrome (clonus/hyperreflexia, เร็ว)"}, {"topic": "Alcohol withdrawal", "q": "A patient with chronic alcohol use develops tremor, agitation, tachycardia, and a seizure 2 days after stopping drinking. What is the first-line treatment?", "choices": ["Haloperidol as the primary treatment", "Beta-blocker monotherapy for the tremor", "Naloxone to reverse the withdrawal state", "Benzodiazepines", "Phenytoin as first-line for the seizures"], "ans": 3, "exp": "Alcohol withdrawal (tremor → seizure → delirium tremens): first-line = 'benzodiazepines' (symptom-triggered) + 'thiamine ก่อน glucose' (ป้องกัน Wernicke) + electrolyte (Mg). DTs (agitation, autonomic, hallucination, confusion) มี mortality — ต้อง admit/ICU. Benzodiazepine ดีกว่า phenytoin สำหรับ withdrawal seizure"}, {"topic": "Snakebite - hematotoxic", "q": "A patient in Thailand is bitten by a snake and develops progressive local swelling, bleeding from the bite and gums, and prolonged clotting. What is the management principle?", "choices": ["Apply a tight arterial tourniquet and incise the wound", "Suck out the venom from the bite site", "Apply ice and vigorously massage the limb", "Give antivenom to everyone bitten regardless of symptoms", "Immobilize the limb, avoid harmful first aid, and give antivenom for systemic envenomation"], "ans": 4, "exp": "Hematotoxic snakebite (ไทย: Russell's viper, green pit viper, Malayan pit viper → coagulopathy/bleeding, monitor '20-min whole blood clotting test'): first aid = immobilize limb + รีบส่ง; 'หลีกเลี่ยง' tourniquet แน่น/กรีด/ดูด/ice; ให้ 'antivenom' เมื่อมี systemic envenomation (coagulopathy, bleeding, significant local). Support + monitor renal"}, {"topic": "Snakebite - neurotoxic", "q": "A patient bitten by a cobra develops ptosis, difficulty swallowing, and progressive descending weakness with respiratory compromise. What is the priority besides antivenom?", "choices": ["Airway protection and ventilatory support", "Immediate limb amputation to stop the venom", "High-dose corticosteroids as the definitive therapy", "Aggressive urine alkalinization to clear the venom", "A tight arterial tourniquet applied above the bite"], "ans": 0, "exp": "Neurotoxic snakebite (cobra/krait: ptosis, bulbar/descending paralysis, respiratory failure): priority = 'airway/ventilatory support' (respiratory failure ฆ่า) + antivenom; pressure immobilization อาจใช้ในบาง neurotoxic. เฝ้าระวัง progression. Anticholinesterase อาจช่วยในบางชนิด. ห้าม harmful first aid"}, {"topic": "Activated charcoal", "q": "A patient presents within 1 hour of a significant toxic ingestion, is awake with an intact airway, and the toxin binds charcoal. Which decontamination is appropriate?", "choices": ["Syrup of ipecac to induce vomiting", "Single-dose activated charcoal", "Gastric lavage for all ingestions routinely", "Whole bowel irrigation for every case", "Forced diuresis as the primary method"], "ans": 1, "exp": "GI decontamination: 'single-dose activated charcoal' (ภายใน ~1 ชม., ผู้ป่วยตื่น/airway ปลอดภัย, สารดูดซับ charcoal ได้) เป็น method ที่ใช้บ่อยสุด. 'ไม่แนะนำ ipecac' (เสี่ยง aspiration, ไม่มีประโยชน์). Charcoal 'ไม่จับ' iron, lithium, alcohols, hydrocarbons, corrosives. Whole bowel irrigation สำหรับ iron/lithium/sustained-release/body packers"}, {"topic": "Whole bowel irrigation", "q": "For which ingestion is whole bowel irrigation with polyethylene glycol particularly useful?", "choices": ["A small ingestion of activated-charcoal-binding tablets", "Any minor ingestion presenting within one hour", "Sustained-release drugs, iron, lithium, or drug packets", "Corrosive acid or alkali ingestion", "Simple ethanol intoxication"], "ans": 2, "exp": "Whole bowel irrigation (polyethylene glycol) มีประโยชน์ใน: 'sustained/extended-release preparations, iron, lithium' (ไม่จับ charcoal), และ 'body packers' (ห่อยาเสพติด). หลีกเลี่ยงใน bowel obstruction/perforation/ileus, unprotected airway, หรือ corrosive ingestion"}, {"topic": "Cyanide", "q": "A victim of an enclosed-space fire has altered mental status, severe lactic acidosis, and normal oxygen saturation. Which antidote treats the likely cyanide toxicity?", "choices": ["Methylene blue", "Deferoxamine", "Naloxone", "Hydroxocobalamin", "Fomepizole"], "ans": 3, "exp": "Cyanide poisoning (enclosed-space fire, industrial): blocks cellular respiration → severe 'lactic acidosis' + normal SpO2/high venous O2, altered mental status, cardiovascular collapse. Antidote = 'hydroxocobalamin' (± sodium thiosulfate). ร่วมกับ 100% O2 (co-existing CO). ประเมิน airway burn"}, {"topic": "Lithium toxicity", "q": "A patient on lithium with dehydration develops tremor, confusion, ataxia, and myoclonus with a high lithium level. What is the definitive treatment for severe toxicity?", "choices": ["Activated charcoal to bind the lithium", "N-acetylcysteine per the nomogram", "Naloxone with supportive care", "Sodium bicarbonate to alkalinize the urine", "Hemodialysis"], "ans": 4, "exp": "Lithium toxicity (narrow therapeutic index, worsened by dehydration/renal impairment/drugs เช่น NSAID, thiazide, ACEI): neuro (tremor → confusion, ataxia, myoclonus, seizure). รักษา: IV fluid (NSS), หยุด lithium; 'hemodialysis' สำหรับ severe (high level, severe neuro/renal). 'Charcoal ไม่จับ lithium' → whole bowel irrigation สำหรับ sustained-release"}, {"topic": "Scorpion / spider envenomation", "q": "A child stung by a scorpion develops autonomic storm and neuromuscular hyperactivity. Besides supportive care and pain control, what may be needed in severe cases?", "choices": ["Scorpion antivenom", "Immediate limb amputation to stop the venom", "High-dose corticosteroids as the definitive cure", "Urine alkalinization to clear the toxin", "A tight arterial tourniquet on the limb"], "ans": 0, "exp": "Severe scorpion envenomation (โดยเฉพาะเด็ก): autonomic + neuromuscular hyperactivity, อาจ pulmonary edema/cardiac → supportive (airway, benzodiazepine, prazosin ในบางชนิด, analgesia) + 'antivenom' ในรายรุนแรง. Widow spider (Latrodectus): painful cramps → analgesia/benzodiazepine ± antivenom. Recluse (Loxosceles): necrotic ulcer → wound care"}, {"topic": "Paraquat", "q": "A patient ingests paraquat herbicide. Why is high-flow oxygen generally avoided in this poisoning?", "choices": ["Oxygen neutralizes the antidote effect", "Oxygen worsens the free-radical pulmonary fibrosis", "Oxygen causes immediate cardiac arrhythmia", "Oxygen precipitates renal failure directly", "Oxygen has no role and is simply unnecessary"], "ans": 1, "exp": "Paraquat poisoning: สร้าง free radicals → progressive 'pulmonary fibrosis' (สาเหตุการตายหลัก) + multiorgan failure. 'หลีกเลี่ยง supplemental oxygen' (เพิ่ม oxidative/free-radical injury) เว้นแต่ hypoxia รุนแรง. รักษา: early decontamination (charcoal/Fuller's earth), supportive; prognosis แย่มากในปริมาณสูง. Highly lethal"}, {"topic": "Ethanol intoxication vs other", "q": "A patient with altered mental status has an elevated osmolar gap but only a mild or no metabolic acidosis and a fruity/alcohol smell. Which is most consistent?", "choices": ["Methanol poisoning with severe acidosis", "Ethylene glycol with oxalate crystals", "Ethanol intoxication", "Salicylate poisoning", "Organophosphate poisoning"], "ans": 2, "exp": "Ethanol intoxication: elevated 'osmolar gap' 'โดยไม่มี'/มี metabolic acidosis เล็กน้อย (ต่างจาก methanol/ethylene glycol ที่ osmolar gap สูง + severe high anion gap acidosis จาก toxic metabolites). ดูแล supportive + ตรวจ hypoglycemia + thiamine; ตัด co-ingestant/toxic alcohols ในรายที่มี acidosis"}, {"topic": "Diabetic ketoacidosis", "q": "A patient with type 1 diabetes has vomiting, Kussmaul breathing, glucose 480, ketosis, and a high anion gap metabolic acidosis. What is the priority in management?", "choices": ["A large intravenous insulin bolus before any fluids are given", "Rapid correction of glucose to normal within one hour", "Routine bicarbonate for every patient with acidosis", "Intravenous fluids first", "Oral rehydration and discharge with follow-up"], "ans": 3, "exp": "DKA: 'fluid ก่อน' (careful — ระวัง cerebral edema โดยเฉพาะเด็ก) → 'insulin infusion' → ทดแทน 'potassium' (total body K ต่ำแม้ serum ปกติ/สูง; เริ่ม insulin เมื่อ K ≥3.3) + หา precipitant. หลีกเลี่ยง bicarbonate routine, แก้ glucose ช้าๆ, ให้ dextrose เมื่อ glucose ~200 (ยังต้อง insulin ปิด ketosis)"}, {"topic": "Hyperosmolar hyperglycemic state", "q": "An elderly type 2 diabetic has profound dehydration, glucose 900, very high serum osmolality, and altered consciousness but minimal ketosis/acidosis. What is the diagnosis?", "choices": ["Diabetic ketoacidosis with severe ketosis", "Lactic acidosis from metformin", "Hypoglycemic coma from insulin excess", "Alcoholic ketoacidosis", "Hyperosmolar hyperglycemic state"], "ans": 4, "exp": "HHS: type 2 DM, glucose สูงมาก (มัก >600), serum osmolality สูงมาก (>320), profound dehydration, altered consciousness, 'minimal ketosis/acidosis' (มี insulin พอยับยั้ง ketogenesis). รักษา: aggressive IV fluid (deficit มาก), insulin, K replacement, หา precipitant (infection). Mortality สูงกว่า DKA"}, {"topic": "Hypoglycemia", "q": "A patient on a sulfonylurea is found confused, sweaty, and tremulous with a capillary glucose of 40 mg/dL. What is the immediate treatment?", "choices": ["Intravenous dextrose", "Intravenous insulin to stabilize the glucose", "Naloxone to reverse the altered mental status", "Fluid restriction to concentrate the glucose", "Observation because it will resolve on its own"], "ans": 0, "exp": "Symptomatic hypoglycemia: ให้ 'glucose ทันที' — oral (ถ้ากลืนได้/รู้ตัว) หรือ 'IV dextrose' (D50 ในผู้ใหญ่, D10 ในเด็ก) ถ้าซึม/ให้ทางปากไม่ได้; glucagon IM ถ้าไม่มี IV access. Sulfonylurea-induced hypoglycemia 'prolonged/recurrent' → admit + observe (± octreotide). หา/แก้สาเหตุ"}, {"topic": "Thyroid storm", "q": "A patient with untreated Graves disease develops fever 40°C, severe tachyarrhythmia, agitation/delirium, and heart failure during an infection. What is the treatment?", "choices": ["Levothyroxine to restore normal thyroid function", "Beta-blocker, thionamide, iodine, steroid, and supportive care", "Only paracetamol and cooling for the fever", "Immediate radioactive iodine as the emergency therapy", "Fluid restriction and observation alone"], "ans": 1, "exp": "Thyroid storm (decompensated thyrotoxicosis, precipitate ด้วย infection/surgery): hyperpyrexia + tachyarrhythmia/HF + CNS (agitation/coma) + GI. รักษา: 'beta-blocker (propranolol)' + 'thionamide (PTU/methimazole)' + 'iodine (หลัง thionamide)' + 'corticosteroid' + supportive/cooling + treat precipitant. Mortality สูงถ้าไม่รักษา"}, {"topic": "Myxedema coma", "q": "An elderly patient in winter has hypothermia, bradycardia, hypoventilation, hyponatremia, and decreased consciousness with a history of hypothyroidism. What is the treatment?", "choices": ["Immediate antithyroid drugs to lower the metabolism", "Rapid active cooling as the priority", "Intravenous levothyroxine and supportive care", "High-dose beta-blocker to control the heart rate", "Naloxone for the altered consciousness"], "ans": 2, "exp": "Myxedema coma (severe decompensated hypothyroidism, precipitate ด้วย cold/infection): hypothermia, bradycardia, hypoventilation, hyponatremia, altered consciousness. รักษา: 'IV thyroid hormone (levothyroxine ± liothyronine)' + 'stress-dose hydrocortisone' (ก่อน thyroid ในกรณีสงสัย adrenal insufficiency ร่วม) + passive rewarming + supportive (airway, hyponatremia). Emergency, mortality สูง"}, {"topic": "Adrenal crisis", "q": "A patient with known adrenal insufficiency develops vomiting, hypotension, hyponatremia, hyperkalemia, and hypoglycemia during an infection. What is the immediate treatment?", "choices": ["Insulin infusion to lower the potassium", "Fluid restriction to correct the hyponatremia", "Oral prednisolone with discharge home", "Intravenous hydrocortisone plus fluids", "Potassium supplementation for the muscle weakness"], "ans": 3, "exp": "Adrenal (Addisonian) crisis: cortisol deficiency + stress → vomiting, shock, hyponatremia, hyperkalemia, hypoglycemia. Immediate = 'IV hydrocortisone (stress dose)' + 'IV normal saline + dextrose'. Hyperkalemia ดีขึ้นตาม. ผู้ป่วย chronic ต้อง stress dosing ระหว่างป่วย/ผ่าตัด + emergency plan"}, {"topic": "Severe hyperkalemia", "q": "A dialysis patient has potassium 7.2 mmol/L with peaked T waves and a widening QRS. What is the first drug to give?", "choices": ["Insulin with glucose as the first single intervention", "Nebulized salbutamol as the initial priority", "Oral potassium binder as the first-line therapy", "Sodium bicarbonate as the sole treatment", "Intravenous calcium to stabilize the myocardium"], "ans": 4, "exp": "Severe hyperkalemia + ECG changes (peaked T, wide QRS): 'IV calcium ก่อน' (stabilize myocardium ป้องกัน arrhythmia — ไม่ลด K) → shift (insulin+glucose, salbutamol, bicarbonate) → remove (diuretic, binder, dialysis). Calcium เป็นลำดับแรกในภาวะฉุกเฉินที่มี ECG changes"}, {"topic": "Severe symptomatic hyponatremia", "q": "A patient with serum sodium 110 mmol/L has a seizure from acute hyponatremia. What is the appropriate treatment?", "choices": ["Hypertonic saline, correcting sodium slowly to avoid demyelination", "Rapid normalization of sodium within a few hours", "Free water infusion to dilute the concentrated blood", "Fluid restriction alone despite the active seizure", "Loop diuretics as the sole management"], "ans": 0, "exp": "Severe symptomatic hyponatremia (seizure/coma): ให้ 'hypertonic 3% saline' (bolus) เพื่อยก Na พอหยุดอาการ แต่ 'แก้ช้า' โดยรวม (ไม่เกิน ~8-10 mEq/L/วัน) เพื่อป้องกัน 'osmotic demyelination syndrome' (central pontine myelinolysis). หาสาเหตุ (SIADH → fluid restriction เมื่อ chronic/asymptomatic)"}, {"topic": "Hypercalcemic crisis", "q": "A patient with malignancy has calcium 15 mg/dL with confusion, polyuria, and dehydration. What is the initial management?", "choices": ["Fluid restriction to reduce the calcium load", "Aggressive intravenous normal saline", "Immediate hemodialysis for every patient", "Oral calcium binders as the first-line therapy", "Thiazide diuretics to increase calcium excretion"], "ans": 1, "exp": "Hypercalcemic crisis ('stones, bones, groans, psychiatric moans' + polyuria/dehydration, มัก malignancy/hyperparathyroid): 'aggressive IV normal saline' (rehydrate + promote calciuresis) เป็นอันดับแรก → bisphosphonate (ออกฤทธิ์ช้า, ยั่งยืน) + calcitonin (เร็ว, ชั่วคราว) ± steroid/dialysis. 'หลีกเลี่ยง thiazide' (เพิ่ม calcium reabsorption)"}, {"topic": "Hypocalcemia - tetany", "q": "A postoperative thyroidectomy patient develops perioral numbness, carpopedal spasm, and a positive Chvostek sign with a low calcium. What is the treatment?", "choices": ["Oral vitamin D alone as the acute treatment", "Intravenous magnesium as the sole therapy", "Intravenous calcium gluconate for symptomatic hypocalcemia", "Phosphate supplementation to raise the calcium", "Observation because it resolves spontaneously"], "ans": 2, "exp": "Symptomatic hypocalcemia (post-thyroidectomy/parathyroid injury): tetany (perioral/peripheral paresthesia, carpopedal spasm, Chvostek/Trousseau, laryngospasm, seizure) → 'IV calcium gluconate' (with cardiac monitoring). แก้ magnesium ถ้าต่ำร่วม (ทำให้ hypocalcemia ดื้อ). Long-term: calcium + vitamin D"}, {"topic": "DKA cerebral edema", "q": "A child being treated for DKA suddenly develops headache, decreasing consciousness, bradycardia, and hypertension several hours into therapy. What is the complication?", "choices": ["Hypoglycemia from the insulin", "Hypokalemia from the treatment", "Aspiration pneumonia", "Cerebral edema", "Pulmonary embolism"], "ans": 3, "exp": "Cerebral edema เป็นภาวะแทรกซ้อนที่ร้ายแรงที่สุดของ 'pediatric DKA': headache + decreasing consciousness + bradycardia + hypertension (Cushing response), pupillary changes — มัก 4-12 ชม.หลังเริ่มรักษา. ป้องกัน: แก้ fluid/glucose 'ช้าๆ'. รักษา: hypertonic saline/mannitol + ลด IV rate + airway. ต้อง recognize เร็ว"}, {"topic": "Alcoholic ketoacidosis", "q": "A malnourished patient with chronic alcohol use who recently stopped eating and drinking has vomiting, a high anion gap metabolic acidosis with ketones, but near-normal glucose. What is the treatment?", "choices": ["High-dose insulin infusion like for DKA", "Sodium bicarbonate as the primary therapy", "Fomepizole to block alcohol metabolism", "Naloxone with supportive care only", "Intravenous dextrose-containing saline and thiamine"], "ans": 4, "exp": "Alcoholic ketoacidosis: chronic alcohol + starvation/vomiting → ketoacidosis 'โดย glucose ปกติ/ต่ำ'. รักษา: 'IV dextrose + saline' (กระตุ้น insulin, ปิด ketogenesis) + 'thiamine ก่อน glucose' (กัน Wernicke) + แก้ electrolyte (K, Mg, phosphate). ไม่ต้อง insulin (ต่างจาก DKA). ตอบสนองดี"}, {"topic": "Pheochromocytoma crisis", "q": "A patient has episodic severe headache, palpitations, diaphoresis, and paroxysmal severe hypertension. Which drug must be given first if treating the hypertension pharmacologically?", "choices": ["Alpha-blockade before any beta-blockade", "Beta-blockade first to control the heart rate", "A diuretic as the initial single agent", "An ACE inhibitor as the first-line drug", "A calcium channel blocker is absolutely contraindicated"], "ans": 0, "exp": "Pheochromocytoma (catecholamine excess: episodic headache + palpitations + diaphoresis + paroxysmal HT): ถ้าให้ยาต้องให้ 'alpha-blockade ก่อน' (phenoxybenzamine/phentolamine) แล้วจึง beta-blocker — เพราะ 'beta-block ก่อน' → unopposed alpha → hypertensive crisis. Definitive = surgical resection หลัง alpha-blockade adequate"}, {"topic": "Tumor lysis syndrome", "q": "A patient starting chemotherapy for a bulky lymphoma develops hyperkalemia, hyperphosphatemia, hyperuricemia, hypocalcemia, and acute kidney injury. What is the syndrome and prevention?", "choices": ["Refeeding syndrome; slow feeding with phosphate", "Tumor lysis syndrome", "Contrast nephropathy; withhold all fluids", "Adrenal crisis; stress-dose steroids", "Hemolytic uremic syndrome; plasma exchange"], "ans": 1, "exp": "Tumor lysis syndrome (chemo ใน bulky/high-turnover tumor เช่น Burkitt, leukemia): cell lysis → 'hyperkalemia, hyperphosphatemia, hyperuricemia, hypocalcemia, AKI'. ป้องกัน/รักษา: 'aggressive hydration' + 'allopurinol/rasburicase' (ลด uric acid) + monitor/treat electrolytes ± dialysis. เป็น oncologic emergency"}, {"topic": "Wernicke encephalopathy", "q": "A patient with chronic alcohol use develops confusion, ataxia, and ophthalmoplegia. What is the treatment and a key caution?", "choices": ["Give glucose first and thiamine only if symptoms persist", "Naloxone to reverse the confusion", "Give thiamine before glucose to avoid precipitating Wernicke", "Immediate CT and withhold all treatment until results", "Benzodiazepines as the specific treatment"], "ans": 2, "exp": "Wernicke encephalopathy (thiamine deficiency): classic triad = confusion + ataxia + ophthalmoplegia/nystagmus (มักไม่ครบ). ให้ 'thiamine ก่อน glucose' (glucose ก่อนอาจ precipitate/worsen Wernicke). Untreated → Korsakoff (irreversible amnesia/confabulation). พบใน alcoholism, malnutrition, hyperemesis"}, {"topic": "Malignant hyperthermia", "q": "During general anesthesia with a volatile agent and succinylcholine, a patient develops rapidly rising temperature, muscle rigidity, tachycardia, and a rising end-tidal CO2. What is the antidote?", "choices": ["Bromocriptine as the specific antidote", "Cyproheptadine to reverse the rigidity", "Naloxone with supportive cooling", "Dantrolene (plus stopping the triggering agent and cooling)", "Physostigmine to reverse the hyperthermia"], "ans": 3, "exp": "Malignant hyperthermia (genetic, triggered by 'volatile anesthetics + succinylcholine'): hypermetabolic — rising temp/EtCO2, masseter/generalized rigidity, tachycardia, acidosis, hyperkalemia, rhabdomyolysis. รักษา: 'หยุด trigger' + 'dantrolene' + cooling + treat hyperkalemia/acidosis. ต่างจาก NMS (antipsychotic, ช้ากว่า) และ serotonin syndrome"}, {"topic": "Status epilepticus", "q": "A patient has a generalized tonic-clonic seizure that has continued for more than 5 minutes. What is the first-line treatment?", "choices": ["Intravenous phenytoin as the very first agent", "Oral levetiracetam given immediately", "Waiting 30 minutes before any drug treatment", "Intravenous magnesium as first-line for all", "A benzodiazepine"], "ans": 4, "exp": "Status epilepticus (seizure ≥5 นาที หรือ recurrent ไม่ฟื้น): first-line = 'benzodiazepine' (IV lorazepam/diazepam, หรือ IM/buccal/intranasal midazolam ถ้าไม่มี IV). ตรวจ/แก้ glucose. ถ้าไม่หยุด → second-line (levetiracetam/fosphenytoin/valproate) → anesthetic agents. ABC + หา precipitant"}, {"topic": "Acute ischemic stroke", "q": "A patient has sudden right-sided weakness and aphasia; CT shows no hemorrhage and symptoms began 2 hours ago. What is the appropriate treatment for eligible patients?", "choices": ["Intravenous thrombolysis within the time window", "Immediate high-dose aspirin plus thrombolysis together", "Rapid lowering of blood pressure to normal in all cases", "Anticoagulation with heparin as the first-line therapy", "Observation with a repeat scan in 24 hours"], "ans": 0, "exp": "Acute ischemic stroke (CT ตัด hemorrhage, ภายใน window): 'IV thrombolysis' (alteplase/tenecteplase) ภายใน 4.5 ชม.ในผู้เข้าเกณฑ์; mechanical thrombectomy ถึง 24 ชม.ในราย large vessel occlusion ที่คัดเลือก. คุม BP (permissive จนกว่าจะให้ lytic แล้วมีเป้า), glucose; antiplatelet เริ่มหลัง 24 ชม.ถ้าให้ lytic"}, {"topic": "Subarachnoid hemorrhage", "q": "A patient describes a sudden 'worst headache of my life' (thunderclap) reaching maximum intensity in seconds, with neck stiffness. What is the diagnosis and next step?", "choices": ["Migraine; give a triptan and discharge", "Subarachnoid hemorrhage", "Tension headache; simple analgesia and reassurance", "Meningitis; start antibiotics without imaging", "Sinusitis; oral antibiotics and decongestants"], "ans": 1, "exp": "Thunderclap headache ('worst headache', peak ในวินาที) = subarachnoid hemorrhage จนกว่าจะพิสูจน์เป็นอื่น → 'non-contrast CT head' (sensitive มากช่วงแรก); ถ้า CT negative แต่ยังสงสัย → 'LP' (xanthochromia/RBC). มัก aneurysm rupture → neurosurgery/coiling, จัดการ BP, nimodipine (vasospasm), เฝ้าระวัง rebleed"}, {"topic": "Bacterial meningitis", "q": "A patient has fever, severe headache, neck stiffness, and photophobia. Without signs of raised ICP or focal deficit, what is the appropriate sequence?", "choices": ["Delay antibiotics until the LP result is available", "CT head for every patient before any antibiotics", "Blood cultures, immediate empiric antibiotics", "Oral antibiotics and discharge with follow-up", "Antivirals alone while awaiting culture results"], "ans": 2, "exp": "Bacterial meningitis: 'ไม่ delay antibiotics'. ถ้าไม่มีข้อบ่งชี้ CT ก่อน LP (no focal deficit, no papilledema, not immunocompromised, no seizure) → blood culture → LP → empiric antibiotics (ceftriaxone + vancomycin ± ampicillin สำหรับ Listeria) + dexamethasone. ถ้าต้อง CT ก่อน → ให้ antibiotics 'ก่อน' scan (หลัง blood culture)"}, {"topic": "HSV encephalitis", "q": "A patient has fever, confusion, personality change, and focal seizures; MRI shows temporal lobe involvement and CSF shows lymphocytic pleocytosis. What must be started empirically?", "choices": ["Intravenous ceftriaxone alone", "Oseltamivir for presumed influenza", "Supportive care while awaiting PCR", "Intravenous acyclovir", "Corticosteroids as the primary therapy"], "ans": 3, "exp": "Herpes simplex encephalitis: fever + encephalopathy + focal (temporal) signs/seizures, MRI temporal lobe, CSF lymphocytic + HSV PCR. เริ่ม 'IV acyclovir empirically ทันที' เมื่อสงสัย (ก่อนผล PCR) — delay เพิ่ม mortality/morbidity. เป็น treatable cause ของ encephalitis ที่ต้องคิดถึงเสมอ"}, {"topic": "Acute agitation / sedation", "q": "An acutely agitated, violent patient poses a danger to self and staff. After de-escalation fails and to allow assessment, what is an appropriate approach?", "choices": ["Physical restraints alone indefinitely without medication", "Discharge the patient to remove the danger", "Withhold all intervention until the patient calms alone", "High-dose opioids to sedate the patient quickly", "Rapid tranquilization with monitoring"], "ans": 4, "exp": "Acute agitation ที่เป็นอันตราย: เริ่มด้วย de-escalation/verbal; ถ้าไม่ได้ผล → 'rapid tranquilization' (benzodiazepine เช่น lorazepam/midazolam ± antipsychotic เช่น haloperidol/olanzapine) + monitoring (airway, vitals) + evaluate สาเหตุ organic (hypoxia, hypoglycemia, intoxication, sepsis). Restraint เป็น last resort ชั่วคราว + reassess. (ดูแลด้วยความปลอดภัย/เคารพศักดิ์ศรี)"}, {"topic": "Upper GI bleeding - variceal", "q": "A patient with cirrhosis vomits large amounts of fresh blood and is hypotensive. Besides resuscitation, what is appropriate for suspected variceal bleeding?", "choices": ["Vasoactive drug, prophylactic antibiotics, and endoscopy", "Immediate high-dose oral iron and discharge", "Withhold all fluids to avoid raising portal pressure", "Systemic thrombolysis to clear the bleeding", "Beta-blocker infusion as the acute hemostatic therapy"], "ans": 0, "exp": "Variceal UGIB (cirrhosis, hematemesis, shock): resuscitate (restrictive transfusion Hb ~7) + 'vasoactive drug (octreotide/terlipressin)' ลด portal pressure + 'prophylactic antibiotics' (ceftriaxone — ลด infection/mortality) + urgent 'endoscopic band ligation'. Balloon tamponade/TIPS ในราย refractory. Non-variceal (PUD) → PPI + endoscopic therapy"}, {"topic": "Lower GI bleeding", "q": "An elderly patient passes a large volume of fresh red blood per rectum and is hemodynamically unstable. What is the appropriate approach?", "choices": ["Immediate colectomy without any localization", "Resuscitate, exclude a brisk upper GI source", "Reassurance and discharge with outpatient colonoscopy", "Oral iron therapy as the definitive management", "Systemic anticoagulation to prevent clot formation"], "ans": 1, "exp": "Massive lower GI bleeding (hematochezia): resuscitate ก่อน; 'ตัด brisk upper GI source' (ประมาณ 10-15% ของ hematochezia รุนแรงมาจาก upper — NG/upper endoscopy). Localize: colonoscopy (หลัง prep) หรือ CT angiography/tagged RBC scan ใน active bleeding → treatment (endoscopic/embolization/surgery). สาเหตุบ่อย: diverticular, angiodysplasia"}, {"topic": "Acute pancreatitis", "q": "A patient has severe epigastric pain radiating to the back, vomiting, and a lipase more than three times the upper limit of normal. What is the key initial management?", "choices": ["Immediate surgery to remove the pancreas", "Prophylactic antibiotics for every patient", "Aggressive intravenous fluids, analgesia, and early enteral feeding as tolerated", "Prolonged complete fasting for at least a week", "High-dose corticosteroids to reduce inflammation"], "ans": 2, "exp": "Acute pancreatitis (dx ≥2/3: typical pain, lipase >3× ULN, imaging; สาเหตุบ่อย gallstone/alcohol): 'aggressive IV fluid' + analgesia + 'early enteral feeding' เมื่อทน + หาสาเหตุ (US, triglyceride). ERCP ถ้ามี cholangitis/obstruction. 'ไม่' ให้ prophylactic antibiotic routine (เฉพาะ infected necrosis). ประเมินความรุนแรง"}, {"topic": "Ascending cholangitis", "q": "A patient has fever, right upper quadrant pain, and jaundice (Charcot triad), progressing to hypotension and confusion (Reynolds pentad). What is the management?", "choices": ["Elective outpatient ultrasound and follow-up", "Analgesia alone with observation", "Immediate total pancreatectomy", "Antibiotics, resuscitation, and urgent biliary drainage", "Oral antibiotics and discharge home"], "ans": 3, "exp": "Ascending cholangitis: Charcot triad (fever + RUQ pain + jaundice); severe = Reynolds pentad (+ hypotension + confusion) จาก biliary obstruction + infection. รักษา: resuscitation + IV antibiotics + 'urgent biliary decompression/drainage' (ERCP; PTC/surgery ถ้าไม่ได้). เป็น emergency — mortality สูงถ้า delay drainage"}, {"topic": "Disseminated intravascular coagulation", "q": "A septic patient develops diffuse bleeding with thrombocytopenia, prolonged PT/aPTT, low fibrinogen, and high D-dimer. What is the cornerstone of treatment?", "choices": ["High-dose systemic anticoagulation for all patients", "Platelet transfusion alone regardless of the cause", "Withhold all blood products despite active bleeding", "Tranexamic acid as the definitive single therapy", "Treat the underlying cause plus supportive blood products as needed"], "ans": 4, "exp": "DIC (consumptive coagulopathy จาก sepsis/trauma/malignancy/obstetric): thrombocytopenia + prolonged PT/aPTT + 'low fibrinogen' + high D-dimer + bleeding/microthrombi. Cornerstone = 'รักษาสาเหตุ' (เช่น sepsis) + supportive (platelets/FFP/cryoprecipitate ตาม bleeding). Heparin เฉพาะบางกรณี thrombotic-predominant"}, {"topic": "Thrombotic thrombocytopenic purpura", "q": "A patient has microangiopathic hemolytic anemia, thrombocytopenia, fever, neurologic changes, and renal impairment with a normal coagulation profile. What is the treatment?", "choices": ["Urgent plasma exchange", "Platelet transfusion to correct the low count", "Broad-spectrum antibiotics as the primary therapy", "High-dose iron to treat the anemia", "Immediate splenectomy for all patients"], "ans": 0, "exp": "TTP (pentad: MAHA + thrombocytopenia + fever + neuro + renal; ADAMTS13 deficiency): 'normal PT/aPTT' (ต่างจาก DIC). รักษา: 'urgent plasma exchange' (+ steroid ± rituximab/caplacizumab). 'หลีกเลี่ยง platelet transfusion' (อาจ worsen thrombosis) เว้นแต่ life-threatening bleeding. เป็น hematologic emergency"}, {"topic": "Acute hemolytic transfusion reaction", "q": "During a blood transfusion, a patient develops fever, flank pain, hypotension, and dark hemoglobinuric urine. What is the immediate action?", "choices": ["Slow the transfusion and continue with an antihistamine", "Stop the transfusion immediately and give supportive care/fluids", "Give more of the same blood to complete the unit", "Administer a diuretic and continue the transfusion", "Observe without stopping since fever is expected"], "ans": 1, "exp": "Acute hemolytic transfusion reaction (มัก ABO incompatibility/clerical error): fever + flank/back pain + hypotension + hemoglobinuria + DIC/renal failure. 'หยุด transfusion ทันที' + IV fluids/supportive + maintain urine output + recheck identification + notify blood bank. ต่างจาก febrile non-hemolytic (fever อย่างเดียว, benign) และ allergic (urticaria)"}, {"topic": "Febrile neutropenia", "q": "A patient on chemotherapy has a fever of 38.5°C with an absolute neutrophil count of 300/µL. What is the immediate management?", "choices": ["Oral antibiotics as an outpatient", "Antipyretics and observation at home", "Blood cultures and prompt empiric broad-spectrum IV antibiotics", "Await culture results before any antibiotics", "Granulocyte transfusion as the first-line therapy"], "ans": 2, "exp": "Febrile neutropenia (fever + ANC <500) = oncologic emergency (เสี่ยง overwhelming sepsis รวม Pseudomonas). ต้อง blood cultures แล้วเริ่ม 'empiric broad-spectrum IV antibiotics ทันที' (antipseudomonal beta-lactam: cefepime/piperacillin-tazobactam) ไม่รอ culture. เพิ่ม coverage ตาม risk. ห้ามชะลอ"}, {"topic": "Ectopic pregnancy - ruptured", "q": "A woman of reproductive age has amenorrhea, sudden severe lower abdominal pain, hypotension, and a positive pregnancy test with an empty uterus on ultrasound. What is the diagnosis and management?", "choices": ["Threatened miscarriage; observation and bed rest", "Ovarian cyst; simple analgesia and follow-up", "Pelvic inflammatory disease; outpatient antibiotics", "Ruptured ectopic pregnancy", "Normal early pregnancy; reassurance and discharge"], "ans": 3, "exp": "Ruptured ectopic pregnancy: amenorrhea + abdominal pain + positive β-hCG + hemodynamic instability + empty uterus/adnexal mass/free fluid → 'emergency surgery (salpingectomy)' + resuscitation. Stable/small unruptured → methotrexate. เป็นสาเหตุการเสียชีวิตของหญิงตั้งครรภ์ระยะแรก — คิดถึงเสมอในหญิงวัยเจริญพันธุ์ที่ปวดท้อง/shock"}, {"topic": "Postpartum hemorrhage", "q": "After delivery, a woman has heavy vaginal bleeding; the uterus is soft and boggy. What is the first-line management?", "choices": ["Immediate hysterectomy as the first step", "Observation because bleeding after delivery is normal", "Fluid restriction to reduce the bleeding", "Antibiotics as the primary hemostatic therapy", "Uterine massage and uterotonics, plus tranexamic acid"], "ans": 4, "exp": "Postpartum hemorrhage — สาเหตุ 4 T's (Tone/atony พบบ่อยสุด, Trauma, Tissue, Thrombin). Soft boggy uterus = atony → 'uterine massage + uterotonics' (oxytocin → methylergometrine → carboprost/misoprostol) + 'tranexamic acid' + resuscitation; balloon tamponade/surgery ถ้าไม่หยุด. Hysterectomy เป็น last resort"}, {"topic": "Cord prolapse", "q": "During labor, the umbilical cord is felt protruding through the cervix ahead of the presenting part, with fetal bradycardia. What is the immediate management?", "choices": ["Elevate the presenting part off the cord and arrange emergency cesarean", "Push the cord back and continue vaginal delivery", "Await spontaneous vaginal delivery with monitoring", "Apply fundal pressure to expedite delivery", "Reassure and reassess in thirty minutes"], "ans": 0, "exp": "Umbilical cord prolapse (obstetric emergency): cord ถูกกดโดย presenting part → fetal hypoxia/bradycardia. Immediate: 'ยก presenting part ขึ้นจาก cord' (manual elevation/knee-chest หรือ Trendelenburg), หลีกเลี่ยงการจับ/ดัน cord, เตรียม 'emergency cesarean'. Time-critical เพื่อ fetal survival"}, {"topic": "Shoulder dystocia", "q": "After delivery of the fetal head, the anterior shoulder becomes impacted behind the pubic symphysis ('turtle sign'). What is a first-line maneuver?", "choices": ["Fundal pressure to push the baby out", "McRoberts maneuver with suprapubic pressure", "Immediate cesarean after the head has delivered", "Vigorous downward traction on the fetal head alone", "Wait for spontaneous resolution without maneuvers"], "ans": 1, "exp": "Shoulder dystocia (obstetric emergency, 'turtle sign'): first-line = 'McRoberts maneuver' (hyperflex maternal hips) + 'suprapubic pressure' → internal rotation (Rubin/Woods), delivery of posterior arm, etc. 'หลีกเลี่ยง fundal pressure' (ยิ่งอัดไหล่) และ excessive traction (brachial plexus injury). เสี่ยง Erb palsy, fracture, hypoxia"}, {"topic": "Acute liver failure", "q": "A patient develops jaundice, coagulopathy (INR not corrected by vitamin K), and hepatic encephalopathy over days after a paracetamol overdose. What is a key treatment?", "choices": ["High-dose diuretics as the primary therapy", "Routine broad-spectrum antibiotics as the cure", "N-acetylcysteine and supportive intensive care", "Immediate discharge once jaundice appears", "Oral lactulose alone as definitive treatment"], "ans": 2, "exp": "Acute liver failure: jaundice + coagulopathy (INR สูง ไม่แก้ด้วย vitamin K) + encephalopathy. สาเหตุสำคัญ = paracetamol (→ 'N-acetylcysteine' antidote), viral, drug, metabolic. รักษา: ICU supportive, จัดการ encephalopathy/cerebral edema, coagulopathy, glucose; ประเมิน 'liver transplant' (King's College criteria). NAC ช่วยแม้ non-paracetamol ในบางกรณี"}, {"topic": "Acute angle-closure glaucoma", "q": "A patient has a sudden painful red eye with a mid-dilated fixed pupil, halos around lights, nausea, and a hard eyeball with high intraocular pressure. What is the diagnosis?", "choices": ["Acute anterior uveitis", "Bacterial conjunctivitis", "Central retinal artery occlusion", "Acute angle-closure glaucoma", "Corneal foreign body"], "ans": 3, "exp": "Acute angle-closure glaucoma (ophthalmic emergency): severe eye pain + red eye + 'mid-dilated fixed pupil' + halos + nausea/vomiting + hard globe (raised IOP). รักษา: ลด IOP ด่วน (topical + systemic — acetazolamide, timolol, pilocarpine, ± mannitol) + ophthalmology (laser iridotomy). Delay → permanent vision loss"}, {"topic": "Central retinal artery occlusion", "q": "A patient has sudden painless complete vision loss in one eye; fundoscopy shows a pale retina with a cherry-red spot. What is the diagnosis and urgency?", "choices": ["Vitreous hemorrhage; routine follow-up", "Optic neuritis; oral steroids as outpatient", "Cataract; elective surgery", "Simple refractive error; prescribe glasses", "Central retinal artery occlusion"], "ans": 4, "exp": "Central retinal artery occlusion (CRAO): sudden 'painless' monocular vision loss + pale retina + 'cherry-red spot' (fovea). เป็น 'stroke ของตา' — emergency (retinal survival สั้น): ocular massage, ลด IOP, ± thrombolysis ในบางศูนย์/เวลา, และประเมิน stroke workup (carotid, cardiac, GCA ในผู้สูงอายุ). Prognosis มัก poor ถ้า delay"}, {"topic": "Necrotizing fasciitis", "q": "A diabetic patient has rapidly spreading erythema with pain out of proportion, skin bullae, crepitus, and systemic toxicity. What is the diagnosis and management?", "choices": ["Necrotizing fasciitis", "Simple cellulitis; oral antibiotics at home", "Contact dermatitis; topical steroids", "Deep vein thrombosis; anticoagulation", "Erysipelas; observation and elevation"], "ans": 0, "exp": "Necrotizing fasciitis: 'pain out of proportion', rapidly spreading, skin bullae/necrosis, crepitus (gas), systemic toxicity (± diabetes/immunocompromise). เป็น 'surgical emergency' → 'immediate surgical debridement' + broad-spectrum antibiotics (+ clindamycin ลด toxin) + resuscitation. Delay = fatal. อย่ารอ imaging ถ้า clinical ชัด"}, {"topic": "Acute urinary retention with AKI", "q": "An elderly man with obstructive uropathy is in urinary retention with a rising creatinine (post-renal AKI). After catheterization drains a large volume, what must be monitored?", "choices": ["Immediate re-clamping of the catheter permanently", "Post-obstructive diuresis with fluid and electrolyte losses", "Fluid restriction to prevent overload", "Nothing further, as recovery is always uneventful", "Routine dialysis for all such patients"], "ans": 1, "exp": "Post-renal AKI จาก obstruction (retention) → หลัง relieve (catheter) อาจเกิด 'post-obstructive diuresis' (polyuria มาก) → monitor fluid/electrolyte (hypovolemia, hypokalemia, hypomagnesemia) + replace ตามต้องการ. Creatinine มักดีขึ้นหลัง decompress. หา/แก้สาเหตุ obstruction"}, {"topic": "Priapism - sickle", "q": "A boy with sickle cell disease has a prolonged painful erection (priapism). Besides analgesia and hydration, what may be needed for ischemic priapism?", "choices": ["Observation for 24 hours before any action", "Immediate penile amputation", "Aspiration of the corpora and intracavernosal phenylephrine", "Systemic anticoagulation as first-line", "Warm compresses and discharge home"], "ans": 2, "exp": "Ischemic priapism (>4 ชม., painful, rigid) — sickle cell เป็นสาเหตุในเด็ก: emergency (เสี่ยง fibrosis/impotence) → analgesia, hydration, treat sickle crisis; 'corporal aspiration + intracavernosal phenylephrine'; refractory → shunt. High-flow (non-ischemic) จัดการต่างกัน"}, {"topic": "Malaria - severe", "q": "A traveler from a forested area has cyclical fever, then develops impaired consciousness, seizures, and high P. falciparum parasitemia. What is the treatment for severe/cerebral malaria?", "choices": ["Oral chloroquine as first-line", "Doxycycline monotherapy", "Supportive care without antimalarials", "Intravenous artesunate", "Oral artemether-lumefantrine as first choice"], "ans": 3, "exp": "Severe/cerebral malaria (P. falciparum: impaired consciousness, seizures, high parasitemia, ± severe anemia/hypoglycemia/AKI): 'IV artesunate' (superior to quinine) + supportive (จัดการ hypoglycemia, seizures, fluid). Uncomplicated malaria → oral ACT. เช็ค G6PD ก่อน primaquine (vivax). พบในไทยแถบชายแดน/ป่า"}, {"topic": "High anion gap acidosis", "q": "A patient has a high anion gap metabolic acidosis. Which mnemonic-based cause list should be considered?", "choices": ["Causes of respiratory alkalosis only", "Only gastrointestinal bicarbonate loss", "Exclusively renal tubular acidosis", "Causes of metabolic alkalosis", "MUDPILES / GOLDMARK"], "ans": 4, "exp": "High anion gap metabolic acidosis: MUDPILES — Methanol, Uremia, DKA/alcoholic/starvation ketoacidosis, Propylene glycol/Paraldehyde, Isoniazid/Iron, Lactic acidosis, Ethylene glycol, Salicylates (updated: GOLDMARK — Glycols, Oxoproline, L-lactate, D-lactate, Methanol, Aspirin, Renal failure, Ketoacidosis). คำนวณ anion gap + osmolar gap ช่วยแยกสาเหตุ"}, {"topic": "Acute abdomen approach", "q": "A patient presents with severe abdominal pain and generalized rigidity with rebound tenderness (peritonitis). What is the appropriate initial approach?", "choices": ["Resuscitate, keep NPO, imaging, and urgent surgical consultation", "Give a strong laxative to relieve the obstruction", "Discharge with oral analgesia and follow-up", "Oral feeding to test the tolerance", "Reassurance since abdominal pain is usually benign"], "ans": 0, "exp": "Peritonitis (rigidity + rebound) = surgical abdomen → resuscitate (IV fluid), NPO, NG ถ้าจำเป็น, analgesia, investigations (CBC, lipase, lactate, upright CXR/erect abdomen สำหรับ free air, CT), broad-spectrum antibiotics ถ้าสงสัย perforation/sepsis + 'urgent surgical consult'. หาสาเหตุ (perforation, ischemia, appendicitis, obstruction)"}, {"topic": "Caustic ingestion", "q": "A child swallows a strong alkaline drain cleaner. What is the appropriate management?", "choices": ["Induce vomiting immediately to remove the caustic", "Do NOT induce vomiting or neutralize", "Give an acid to neutralize the alkali", "Perform gastric lavage to wash out the stomach", "Give large volumes of milk then discharge"], "ans": 1, "exp": "Caustic (alkali) ingestion → liquefactive necrosis (deep, esophageal injury/perforation, late stricture). 'ห้าม induce vomiting' (re-expose), 'ห้าม neutralize' (exothermic), ห้าม gastric lavage/charcoal. ประเมิน airway (edema → intubate เร็ว), NPO, IV fluid, และ endoscopy เพื่อ grade injury. เฝ้าระวัง stricture ระยะยาว"}, {"topic": "Hydrocarbon ingestion", "q": "A child ingests kerosene and starts coughing. What is the main risk and management principle?", "choices": ["Systemic poisoning; induce vomiting immediately", "Corrosive burns; neutralize with an acid", "Aspiration pneumonitis", "Iron overload; give deferoxamine", "Cholinergic crisis; give atropine"], "ans": 2, "exp": "Hydrocarbon (kerosene/petroleum) ingestion: main risk = 'aspiration pneumonitis' (low viscosity, volatile). 'ห้าม induce vomiting/gastric lavage' (เพิ่ม aspiration). รักษา supportive (O2, respiratory support, observe for chemical pneumonitis on CXR). Systemic toxicity เกิดกับ hydrocarbon บางชนิด (CHAMP: camphor, halogenated, aromatic, metals, pesticides)"}, {"topic": "Botulism (food-borne)", "q": "Adults develop symmetric descending flaccid paralysis, diplopia, ptosis, dysphagia, and dry mouth after eating home-canned food, without fever or sensory loss. What is the diagnosis?", "choices": ["Guillain-Barre syndrome", "Myasthenia gravis", "Tick paralysis", "Food-borne botulism", "Organophosphate poisoning"], "ans": 3, "exp": "Food-borne botulism (Clostridium botulinum toxin, home-canned/preserved food): 'descending' symmetric flaccid paralysis (cranial nerves ก่อน — diplopia, ptosis, bulbar), autonomic (dry mouth, ileus), 'ไม่มีไข้/ไม่เสีย sensory'. รักษา: antitoxin เร็ว + respiratory/supportive care. ต่างจาก GBS (ascending) และ organophosphate (cholinergic 'wet')"}, {"topic": "Amatoxin mushroom poisoning", "q": "A patient develops severe gastroenteritis 6-12 hours after eating wild mushrooms, seems to improve, then develops fulminant hepatic failure. What toxin is responsible?", "choices": ["Muscarine causing cholinergic effects", "Psilocybin causing hallucinations", "Coprine causing a disulfiram reaction", "Ibotenic acid causing delirium", "Amatoxin (Amanita species)"], "ans": 4, "exp": "Amatoxin (Amanita phalloides/'death cap'): 'delayed' GI symptoms (6-24 ชม.) → apparent recovery → 'fulminant hepatic failure' (วันที่ 2-4). รักษา supportive + NAC/silibinin + consider transplant. Delayed onset = ominous (hepatotoxic/nephrotoxic). Early-onset (<6 ชม.) mushroom toxins มักไม่รุนแรงเท่า (muscarinic, GI-irritant)"}, {"topic": "Stevens-Johnson syndrome / TEN", "q": "A patient on a new drug (e.g., allopurinol, anticonvulsant, sulfonamide) develops fever, painful mucosal erosions, and widespread skin blistering with a positive Nikolsky sign. What is the management?", "choices": ["Stop the culprit drug and give supportive burn-unit-type care", "Continue the drug and add an antihistamine", "Apply topical antibiotics alone and discharge", "Immediate systemic thrombolysis", "High-dose vitamin C as the definitive therapy"], "ans": 0, "exp": "Stevens-Johnson syndrome / TEN (drug reaction — allopurinol, anticonvulsants, sulfonamides, NSAIDs): fever + painful 'mucosal' erosions (≥2 sites) + epidermal detachment (Nikolsky+). SJS <10% BSA, TEN >30%. รักษา: 'หยุด culprit drug ทันที' + supportive 'burn-unit' care (fluid, wound, eye, nutrition) + specialized center. High mortality (SCORTEN). ± IVIG/ciclosporin"}, {"topic": "Toxic shock syndrome", "q": "A patient develops high fever, hypotension, a diffuse sunburn-like erythroderma, vomiting, and multi-organ involvement, later with desquamation of palms/soles. What is the mechanism?", "choices": ["IgE-mediated anaphylactic reaction", "Superantigen toxin", "A simple self-limited viral exanthem", "Autoimmune small-vessel vasculitis", "Inherited complement deficiency"], "ans": 1, "exp": "Toxic shock syndrome: superantigen (staph TSST-1 หรือ strep exotoxin) → massive cytokine release → fever + hypotension + diffuse macular erythroderma + multi-organ dysfunction → desquamation (palms/soles) ภายหลัง. รักษา: source control (remove tampon/drain infection), fluids, antibiotics (clindamycin ลด toxin + beta-lactam) ± IVIG"}, {"topic": "Meningococcemia", "q": "An adolescent rapidly develops high fever, hypotension, and a spreading non-blanching petechial/purpuric rash. What is the priority?", "choices": ["Await blood cultures before any antibiotics", "Oral antibiotics with outpatient follow-up", "Immediate parenteral antibiotics and resuscitation", "Antihistamines for the spreading rash", "Topical steroids to the skin lesions"], "ans": 2, "exp": "Meningococcemia (Neisseria meningitidis): fulminant sepsis + non-blanching petechial/purpuric rash + shock (purpura fulminans, Waterhouse-Friderichsen). Priority = 'parenteral antibiotics (ceftriaxone) ทันที' + aggressive resuscitation — 'ไม่รอ' culture. ให้ chemoprophylaxis close contacts. ป้องกันด้วย vaccine"}, {"topic": "Acute dystonia", "q": "A young patient given an antiemetic (metoclopramide) or antipsychotic develops an acute involuntary sustained muscle contraction (neck twisting, tongue protrusion, oculogyric crisis). What is the treatment?", "choices": ["More of the same dopamine-blocking drug", "Naloxone to reverse the reaction", "Dantrolene as the specific antidote", "Anticholinergic or antihistamine", "Benzodiazepine as the only effective therapy"], "ans": 3, "exp": "Acute dystonic reaction (dopamine-blocking drugs — metoclopramide, antipsychotics): sudden sustained muscle spasm (torticollis, tongue, oculogyric crisis, laryngospasm rarely). รักษาด้วย 'anticholinergic (benztropine)' หรือ 'antihistamine (diphenhydramine)' — ตอบสนองเร็ว. หยุด/หลีกเลี่ยงยาต้นเหตุ. ต่างจาก tardive dyskinesia (late) และ akathisia (restlessness)"}, {"topic": "Malignant spinal cord compression", "q": "A cancer patient develops progressive back pain, bilateral leg weakness, a sensory level, and urinary retention. What is the emergency management?", "choices": ["Simple analgesia and outpatient physiotherapy", "Bed rest alone with reassessment in a week", "Immediate chemotherapy as the only measure", "Lumbar puncture to relieve the pressure", "Urgent MRI and high-dose corticosteroids"], "ans": 4, "exp": "Malignant spinal cord compression (oncologic emergency): back pain + bilateral weakness + sensory level + sphincter dysfunction (retention/incontinence). → 'urgent MRI whole spine' + 'high-dose corticosteroids (dexamethasone)' ทันที + definitive (radiotherapy หรือ surgical decompression). Delay → permanent paralysis. Cauda equina (saddle anesthesia) ก็ต้อง emergency decompression"}, {"topic": "Superior vena cava syndrome", "q": "A patient with a mediastinal malignancy develops facial and upper-limb swelling, distended neck/chest veins, and dyspnea worse when lying down. What is the diagnosis?", "choices": ["Superior vena cava obstruction", "Bilateral deep vein thrombosis of the arms", "Acute heart failure with pulmonary edema", "Cardiac tamponade with pulsus paradoxus", "Anaphylaxis with facial angioedema"], "ans": 0, "exp": "SVC syndrome (มัก malignancy — lung cancer/lymphoma): obstruction ของ SVC → facial/upper-limb/neck swelling, distended veins, plethora, dyspnea (แย่เมื่อนอนราบ/ก้ม). วินิจฉัยด้วย CT. รักษา: จัดการ underlying (radiotherapy/chemo), ± stent; ยกศีรษะสูง, steroid ในบางกรณี. Emergency ถ้า airway/cerebral edema"}, {"topic": "Ovarian torsion", "q": "A woman has sudden severe unilateral pelvic pain with nausea and an adnexal mass; Doppler ultrasound shows reduced ovarian blood flow. What is the management?", "choices": ["Oral analgesia and outpatient gynecology follow-up", "Emergency surgery to salvage the ovary", "Antibiotics for presumed pelvic infection", "Observation because it resolves spontaneously", "Immediate total hysterectomy"], "ans": 1, "exp": "Ovarian torsion: sudden severe unilateral pelvic pain + nausea/vomiting + adnexal mass; Doppler อาจเห็น reduced/absent flow (แต่ flow ปกติไม่ตัดออก). เป็น 'surgical emergency' → laparoscopy + 'detorsion' (salvage ovary, ยิ่งเร็วยิ่งดี) ± cystectomy. Differential ของ acute pelvic pain (ectopic, appendicitis, cyst rupture, PID)"}, {"topic": "Hyperemesis gravidarum", "q": "A pregnant woman in the first trimester has intractable vomiting with weight loss, ketonuria, and dehydration. What is the management?", "choices": ["Encourage large meals to replace the losses", "Withhold all fluids to rest the stomach", "IV fluids, antiemetics, thiamine, and correction of electrolytes", "Immediate termination of pregnancy", "High-dose corticosteroids as first-line for all"], "ans": 2, "exp": "Hyperemesis gravidarum: intractable vomiting + weight loss (>5%) + ketonuria + dehydration + electrolyte disturbance. รักษา: 'IV fluid rehydration', antiemetics (pyridoxine-doxylamine, ondansetron/metoclopramide), 'thiamine' (ป้องกัน Wernicke), แก้ electrolyte (hypokalemia). ตัด molar/multiple pregnancy, thyroid. ส่วนใหญ่ดีขึ้นหลัง trimester แรก"}, {"topic": "Placental abruption", "q": "A woman at 34 weeks has sudden painful vaginal bleeding with a tense, tender uterus and fetal distress after trauma. What is the diagnosis?", "choices": ["Placenta previa", "Uterine rupture", "Vasa previa", "Placental abruption", "Normal bloody show of labor"], "ans": 3, "exp": "Placental abruption (premature separation): 'painful' vaginal bleeding + tense/tender uterus + fetal distress ± concealed hemorrhage/DIC; risk trauma/HT/cocaine. → resuscitate + monitor fetus + delivery (emergency C/S ถ้า fetal/maternal compromise). ต่างจาก placenta previa ('painless' bleeding, 'ห้าม PV' → US)"}, {"topic": "Uterine rupture", "q": "A woman in labor with a previous cesarean scar has sudden severe abdominal pain, loss of uterine contractions, fetal bradycardia, and a rising presenting part. What is the diagnosis?", "choices": ["Placental abruption", "Cord prolapse", "Amniotic fluid embolism", "Precipitate labor", "Uterine rupture"], "ans": 4, "exp": "Uterine rupture (risk: previous C/S scar, obstructed labor, oxytocin): sudden severe pain + 'cessation of contractions' + fetal bradycardia/loss + 'rising/receding presenting part' + maternal shock. เป็น catastrophic emergency → immediate resuscitation + 'emergency laparotomy/cesarean' + repair/hysterectomy. Life-threatening ทั้งแม่และทารก"}, {"topic": "Amniotic fluid embolism", "q": "During or just after delivery, a woman suddenly develops cardiovascular collapse, hypoxia, and profuse bleeding from DIC. What is the most likely diagnosis?", "choices": ["Amniotic fluid embolism", "Pulmonary thromboembolism", "Eclampsia", "Septic shock", "Simple vasovagal syncope"], "ans": 0, "exp": "Amniotic fluid embolism (rare, catastrophic, peripartum): sudden 'cardiovascular collapse + hypoxia + DIC/hemorrhage' + altered consciousness. Diagnosis of exclusion, clinical. รักษา: aggressive resuscitation/ACLS, respiratory + circulatory support, aggressive management of DIC (blood products), delivery. High mortality"}, {"topic": "Central vs peripheral vertigo", "q": "A patient with acute vertigo has direction-changing nystagmus, inability to walk, and other neurologic signs. What does this suggest?", "choices": ["Benign paroxysmal positional vertigo needing repositioning", "A central cause requiring urgent evaluation", "A simple viral labyrinthitis needing only reassurance", "Meniere disease requiring diuretics", "A psychogenic cause needing no workup"], "ans": 1, "exp": "Vertigo: red flags for 'central' cause (cerebellar stroke) = direction-changing/vertical nystagmus, severe gait ataxia (ล้ม/เดินไม่ได้), other neuro signs, negative head-impulse test (HINTS exam central pattern), sudden onset + vascular risk. → urgent neuroimaging (MRI). Peripheral (BPPV/vestibular neuritis): unidirectional nystagmus, can walk, HINTS peripheral"}, {"topic": "Sudden sensorineural hearing loss", "q": "A patient has sudden unilateral hearing loss over hours to days without an obvious cause, confirmed as sensorineural. Why is this important?", "choices": ["It always resolves and needs no treatment", "It is only a cosmetic concern", "It is an emergency; early corticosteroids may improve recovery", "It is managed with antibiotics as first-line", "It requires no urgency or specialist referral"], "ans": 2, "exp": "Sudden sensorineural hearing loss (SSNHL): sudden unilateral hearing loss (sensorineural, ตัด conductive/cerumen ด้วย tuning fork/exam). เป็น 'otologic emergency' — early 'corticosteroids' (systemic ± intratympanic) + urgent ENT referral/audiogram อาจช่วยการฟื้นตัว. ตัด acoustic neuroma (MRI). Time-sensitive"}, {"topic": "Ludwig angina", "q": "A patient with a dental infection develops bilateral submandibular swelling, a raised/protruding tongue, drooling, and difficulty breathing. What is the priority?", "choices": ["Oral antibiotics with next-day dental follow-up", "Reassurance and warm compresses", "Antihistamines for the facial swelling", "Airway management plus IV antibiotics and drainage", "Observation until the swelling resolves"], "ans": 3, "exp": "Ludwig angina (rapidly spreading cellulitis ของ submandibular/sublingual space, มักจาก dental infection): bilateral submandibular swelling, tongue elevation/protrusion, drooling, trismus → 'airway compromise' (life-threatening). Priority = 'secure airway (early, difficult)' + IV broad-spectrum antibiotics + surgical drainage. Airway มาก่อน"}, {"topic": "Deep vein thrombosis", "q": "A patient has unilateral leg swelling, calf pain, and warmth after prolonged immobilization. What is the appropriate approach?", "choices": ["Immediate systemic thrombolysis for all DVTs", "Massage the calf vigorously to relieve the clot", "Reassurance and discharge without any testing", "Antibiotics for presumed cellulitis as first-line", "Assess pretest probability, D-dimer/ultrasound"], "ans": 4, "exp": "Deep vein thrombosis (unilateral leg swelling/pain/warmth, risk immobilization/surgery/malignancy): assess 'Wells score' → D-dimer (low probability) หรือ 'compression ultrasound' (confirm) → 'anticoagulation' (DOAC/LMWH). หลีกเลี่ยงการนวด/massage. Thrombolysis เฉพาะ limb-threatening (phlegmasia). เฝ้าระวัง PE"}, {"topic": "Acute confusional state (delirium)", "q": "An elderly hospitalized patient develops acute fluctuating confusion with inattention over hours. What is the priority?", "choices": ["Identify and treat the underlying organic cause", "Sedate heavily and defer any evaluation", "Assume dementia and take no further action", "Physical restraints as the first-line management", "Discharge home to reduce the confusion"], "ans": 0, "exp": "Delirium (acute, fluctuating, inattention, altered consciousness) เป็น 'organic' → หา/แก้สาเหตุ: infection (UTI/pneumonia/sepsis), drugs (anticholinergic, opioid, benzo, withdrawal), metabolic (glucose, Na, hypoxia, uremia), pain, retention/constipation. จัดการ non-pharmacologic (reorientation, sleep, mobilize); ยาเฉพาะเมื่อจำเป็น. ต่างจาก dementia (chronic)"}, {"topic": "Acute glaucoma treatment", "q": "A patient with acute angle-closure glaucoma needs urgent intraocular pressure reduction. Which is an appropriate emergency measure?", "choices": ["Warm compresses and simple analgesia only", "Topical and systemic pressure-lowering agents", "Immediate enucleation of the affected eye", "Topical corticosteroids as the sole therapy", "Dilating drops to open the drainage angle"], "ans": 1, "exp": "Acute angle-closure glaucoma: ลด IOP ด่วน — topical (timolol, apraclonidine, pilocarpine) + systemic (acetazolamide, ± IV mannitol) + analgesia/antiemetic → definitive 'laser peripheral iridotomy'. 'ห้าม' mydriatic/dilating drops (ทำให้แย่ลง). Emergency — delay → optic nerve damage/vision loss"}, {"topic": "Retinal detachment", "q": "A patient describes sudden floaters, flashes of light, and a 'curtain' descending over part of the vision. What is the diagnosis and urgency?", "choices": ["Migraine aura; reassurance and analgesia", "Simple vitreous floaters; routine follow-up", "Retinal detachment; urgent ophthalmology referral", "Acute conjunctivitis; topical antibiotics", "Refractive error; new glasses prescription"], "ans": 2, "exp": "Retinal detachment: 'floaters + flashes (photopsia) + curtain/shadow' over visual field, painless vision loss. เป็น emergency → 'urgent ophthalmology referral' for surgical repair (esp. if macula still attached — 'macula-on'). Sudden monocular symptoms ต้อง evaluate เร็ว"}, {"topic": "Acute mastoiditis", "q": "A child with recent acute otitis media develops fever, postauricular swelling/redness, tenderness, and a protruding auricle. What is the management?", "choices": ["Oral antibiotics with outpatient follow-up", "Topical ear drops alone", "Reassurance because it resolves spontaneously", "Admit for IV antibiotics and imaging, with possible surgical drainage", "Antihistamines for the swelling"], "ans": 3, "exp": "Acute mastoiditis (complication ของ AOM): fever + postauricular swelling/erythema/tenderness + protruding auricle (หูกาง). → 'admit + IV antibiotics' + imaging (CT) + ENT; myringotomy/mastoidectomy ในบางราย. เสี่ยงลาม intracranial (abscess, sinus thrombosis). ต่างจาก otitis externa"}, {"topic": "Spontaneous bacterial peritonitis", "q": "A patient with cirrhosis and ascites develops fever, abdominal pain, and worsening encephalopathy. Ascitic fluid shows a neutrophil count above 250/µL. What is the diagnosis and treatment?", "choices": ["Secondary peritonitis; immediate laparotomy for all", "Simple ascites; increase the diuretic dose only", "Hepatic encephalopathy alone; lactulose only", "Tuberculous peritonitis; anti-TB drugs empirically", "Spontaneous bacterial peritonitis"], "ans": 4, "exp": "Spontaneous bacterial peritonitis (SBP): cirrhosis + ascites + fever/abdominal pain/worsening encephalopathy; ascitic 'PMN ≥250/µL'. รักษา: 'cefotaxime' (third-gen cephalosporin) + 'IV albumin' (ลด hepatorenal syndrome/mortality). Secondary prophylaxis + primary ในกลุ่มเสี่ยง. เป็น complication ที่พบบ่อยและ serious ของ cirrhosis"}, {"topic": "Acute cholecystitis", "q": "A patient has right upper quadrant pain, fever, and a positive Murphy sign; ultrasound shows gallbladder wall thickening and stones. What is the management?", "choices": ["IV antibiotics, analgesia, and early laparoscopic cholecystectomy", "Oral antibiotics with discharge home", "Immediate ERCP as the definitive treatment", "Observation with a low-fat diet only", "Long-term ursodeoxycholic acid alone"], "ans": 0, "exp": "Acute cholecystitis (RUQ pain + fever + Murphy sign + US: wall thickening/stone/pericholecystic fluid): รักษา IV fluid + antibiotics + analgesia + 'early laparoscopic cholecystectomy' (ภายในไม่กี่วัน). ต่างจาก ascending cholangitis (Charcot triad → biliary drainage/ERCP). Acalculous cholecystitis พบในผู้ป่วยวิกฤต"}, {"topic": "Bowel obstruction", "q": "A patient with prior abdominal surgery has colicky abdominal pain, distension, vomiting, and failure to pass flatus; radiograph shows dilated loops with air-fluid levels. What is the initial management?", "choices": ["Oral laxatives and encouraging oral intake", "NPO, nasogastric decompression, IV fluids, and monitoring", "Immediate laparotomy for every case", "Discharge with outpatient follow-up", "High-fiber diet to relieve the obstruction"], "ans": 1, "exp": "Small bowel obstruction (adhesion จาก prior surgery พบบ่อยสุด): colicky pain, distension, vomiting, ไม่ผายลม, air-fluid levels. Initial: 'NPO + NG decompression + IV fluid + electrolyte correction' + monitoring ('drip and suck'). Surgery ถ้า strangulation/ischemia (fever, tachycardia, peritonitis, lactate สูง)/complete/ไม่ดีขึ้น"}, {"topic": "Diverticulitis", "q": "An older patient has left lower quadrant pain, fever, and altered bowel habits; CT shows sigmoid diverticulitis without abscess or perforation. What is the management of uncomplicated disease?", "choices": ["Immediate emergency colectomy for all", "Colonoscopy during the acute inflammatory phase", "Antibiotics, bowel rest, and analgesia", "High-fiber diet acutely with no other treatment", "Long-term corticosteroids as the mainstay"], "ans": 2, "exp": "Acute uncomplicated diverticulitis (LLQ pain + fever, CT confirms, no abscess/perforation/obstruction): bowel rest, analgesia, ± antibiotics (selected — บางแนวทางไม่ให้ใน mild uncomplicated). Complicated (abscess → drainage; perforation/peritonitis → surgery). Colonoscopy ทำ 'หลัง' acute phase (~6 สัปดาห์) เพื่อตัด malignancy"}, {"topic": "Excited delirium / hyperthermia", "q": "A severely agitated patient with stimulant use has extreme agitation, hyperthermia, and metabolic acidosis at risk of sudden death. What are key management priorities?", "choices": ["Physical restraint alone without any medication", "Beta-blocker monotherapy for the tachycardia", "Withhold fluids to avoid overload", "Sedation, aggressive cooling, and IV fluids with monitoring", "Immediate discharge once restrained"], "ans": 3, "exp": "Severe agitation/'excited delirium' (มัก stimulant): extreme agitation + hyperthermia + acidosis + rhabdomyolysis → เสี่ยง sudden cardiac arrest. Priority: 'sedation (benzodiazepines ± ketamine)' + 'active cooling' + IV fluids + monitor/treat hyperkalemia/rhabdo/acidosis. หลีกเลี่ยง prolonged restraint (worsens acidosis). (ดูแลด้วยความปลอดภัย)"}, {"topic": "Hypertensive encephalopathy", "q": "A patient has very high blood pressure with headache, confusion, seizures, and papilledema, without focal deficit. What is the appropriate blood-pressure management?", "choices": ["Rapid normalization of blood pressure within minutes", "Sublingual nifedipine to drop the pressure fast", "No treatment since the patient is chronically hypertensive", "Oral medication with discharge and follow-up", "Controlled IV reduction, not abrupt normalization"], "ans": 4, "exp": "Hypertensive emergency (severe HT + acute end-organ damage — encephalopathy): 'controlled' IV reduction ด้วย titratable agent (labetalol, nicardipine, nitroprusside) ~10-25% ในชั่วโมงแรก แล้วค่อยๆ ลด (เร็วเกิน → ischemia). หลีกเลี่ยง sublingual nifedipine. ข้อยกเว้นเป้าเฉพาะ: aortic dissection (เร็ว/ต่ำ), acute stroke (เกณฑ์ต่างกัน)"}, {"topic": "Cauda equina syndrome", "q": "A patient with acute low back pain develops saddle anesthesia, bilateral leg weakness, and new urinary retention with overflow incontinence. What is the management?", "choices": ["Urgent MRI and emergency surgical decompression", "Bed rest and analgesia with outpatient follow-up", "Physiotherapy and reassurance", "Epidural steroid injection as first-line", "Lumbar traction and observation for a week"], "ans": 0, "exp": "Cauda equina syndrome (red flag ของ back pain): 'saddle anesthesia' + bilateral leg weakness/sciatica + 'bladder/bowel dysfunction' (retention → overflow incontinence, ↓anal tone) — มักจาก large central disc herniation/tumor. → 'urgent MRI' + 'emergency surgical decompression' (ยิ่งเร็วยิ่งดี, ป้องกัน permanent deficit). เป็น surgical emergency"}, {"topic": "Acute severe asthma - child", "q": "A child with a severe asthma attack has marked respiratory distress, is unable to speak, and has decreasing air entry ('silent chest') with drowsiness. What does this indicate?", "choices": ["Mild asthma that can be discharged after one nebulizer", "Life-threatening asthma requiring aggressive treatment and possible intubation", "A simple viral wheeze needing no treatment", "Improvement because the wheeze has stopped", "Bronchiolitis requiring only supportive care"], "ans": 1, "exp": "'Silent chest' + drowsiness/exhaustion + inability to speak = 'life-threatening' asthma (air movement น้อยมากจน wheeze หาย — ไม่ใช่ดีขึ้น). → aggressive: continuous nebulized SABA + ipratropium + systemic steroid + O2 + IV magnesium ± IV salbutamol/aminophylline, เตรียม 'intubation/ICU'. Deteriorating mental status = impending respiratory arrest"}, {"topic": "Epididymo-orchitis vs torsion", "q": "A young man has gradual-onset scrotal pain with fever, dysuria, an intact cremasteric reflex, and relief on elevating the testis (positive Prehn sign). What is the likely diagnosis?", "choices": ["Testicular torsion", "Testicular rupture", "Epididymo-orchitis", "Inguinal hernia", "Varicocele"], "ans": 2, "exp": "Epididymo-orchitis: 'gradual' onset scrotal pain + fever/dysuria (infection — STI ในหนุ่ม, coliform ในสูงอายุ) + 'cremasteric reflex intact' + relief on elevation (Prehn+). รักษาด้วย antibiotics. ต้องแยกจาก 'testicular torsion' (sudden, absent cremasteric, high-riding, no relief on elevation — surgical emergency); ถ้าสงสัย torsion → explore/ultrasound"}, {"topic": "Acute stroke - thrombolysis contraindication", "q": "A patient with acute ischemic stroke within the time window is being considered for IV thrombolysis. Which is an absolute contraindication?", "choices": ["Blood pressure of 150/90 mmHg", "Age over 60 years", "A blood glucose of 120 mg/dL", "Recent intracranial hemorrhage or active internal bleeding", "Mild well-controlled hypertension on treatment"], "ans": 3, "exp": "IV thrombolysis (alteplase/tenecteplase) contraindications: 'intracranial hemorrhage (current/history), active internal bleeding, recent major surgery/head trauma/stroke, bleeding diathesis, BP >185/110 ที่ควบคุมไม่ได้, glucose ผิดปกติมาก (hypoglycemia mimics), CT แสดง large infarct/hemorrhage'. ต้องคัดกรองก่อนให้. Reperfusion เร็วสำคัญแต่ต้องปลอดภัย"}, {"topic": "Acute chest pain risk", "q": "A patient with chest pain has a normal ECG and initial troponin. What is the appropriate approach to exclude acute coronary syndrome?", "choices": ["Immediately discharge based on the single normal troponin", "Give thrombolysis empirically to all chest pain patients", "Perform emergency coronary bypass surgery", "Ignore the pain since the first ECG was normal", "Risk-stratify with serial troponin before disposition"], "ans": 4, "exp": "Undifferentiated chest pain: ประเมิน ACS ด้วย 'risk stratification' (HEART score) + 'serial troponin' (high-sensitivity troponin protocols) + serial ECG ก่อนตัดสิน disposition. Single normal troponin/ECG 'ไม่' ตัด ACS ทันที (โดยเฉพาะมาเร็ว). Low-risk → early discharge/outpatient; intermediate-high → admit/further testing. ตัด life-threats อื่น (dissection, PE, pneumothorax)"}]}, {"id": "for-1", "title": "นิติเวชศาสตร์ ชุดที่ 1 — Thanatology/Injuries/Pathology", "subject": "forensic", "questions": [{"topic": "Postmortem - livor mortis", "q": "A body found supine shows reddish-purple discoloration over the back and buttocks that blanches on pressure when examined a few hours after death. What is this finding?", "choices": ["Livor mortis", "Antemortem bruising from trauma", "Early putrefactive discoloration", "Rigor mortis of the skin", "A contact burn from the ground"], "ans": 0, "exp": "Livor mortis (hypostasis/lividity): เลือดตกตามแรงโน้มถ่วงในหลอดเลือด → reddish-purple ในบริเวณที่อยู่ต่ำ (แต่ 'contact/pressure areas ซีด' — เลือดถูกกด). 'Blanchable' ช่วงแรก แล้ว 'fixed' (~6-12 ชม.). ตำแหน่ง lividity บอก body position; ช่วยประเมินเวลาตายและว่ามีการเคลื่อนย้ายศพหรือไม่"}, {"topic": "Livor mortis color clues", "q": "The cherry-red (bright pink) color of livor mortis in a deceased person suggests which cause of death?", "choices": ["Massive external hemorrhage", "Carbon monoxide poisoning", "Mechanical asphyxia by hanging", "Blunt force head trauma", "Electrocution injury"], "ans": 1, "exp": "สีของ livor mortis เป็นเบาะแส: 'cherry-red/bright pink' → carbon monoxide (carboxyhemoglobin) หรือ cyanide, หรือ cold/refrigeration. Chocolate-brown → methemoglobinemia. Normal = reddish-purple. Green → putrefaction. ช่วยชี้แนะสาเหตุการตาย"}, {"topic": "Rigor mortis", "q": "Regarding rigor mortis, which statement is correct about its typical time course in a temperate setting?", "choices": ["It appears immediately at the moment of death", "It never resolves once it has developed", "It begins 2-6 hours after death, is complete ~12 hours, and passes off ~24-36 hours", "It develops only in the lower limbs", "It is unaffected by ambient temperature"], "ans": 2, "exp": "Rigor mortis (กล้ามเนื้อแข็งจาก ATP depletion → actin-myosin lock): เริ่ม ~2-6 ชม.หลังตาย (เล็ก → ใหญ่, มัก face/jaw ก่อน), complete ~12 ชม., คงอยู่ ~12 ชม., แล้วคลาย ~24-36 ชม. (จาก autolysis/putrefaction). เร่งใน heat/exertion (cadaveric spasm ต่างกัน). ใช้ประเมินเวลาตายร่วมกับปัจจัยอื่น"}, {"topic": "Algor mortis", "q": "Which postmortem change refers to the cooling of the body after death and is used to estimate the time of death?", "choices": ["Livor mortis", "Rigor mortis", "Putrefaction", "Algor mortis", "Mummification"], "ans": 3, "exp": "Algor mortis = การเย็นลงของร่างกายหลังตาย (body cools toward ambient temperature). ใช้ประเมินเวลาตาย (เช่น Henssge nomogram) แต่ได้รับผลจากหลายปัจจัย (ambient temp, body mass, clothing, environment). Livor = lividity, rigor = stiffness, putrefaction = decomposition"}, {"topic": "Estimating time of death", "q": "Which combination of findings is most useful for estimating the time since death in the early postmortem period?", "choices": ["Only the external appearance of the wounds", "The stated time from a single witness alone", "The color of the clothing worn", "The blood group of the deceased", "Body temperature, rigor mortis, and livor mortis together"], "ans": 4, "exp": "Early postmortem interval ประเมินจาก 'algor (temperature) + rigor + livor mortis' ร่วมกัน (แต่ละอย่างมี error) + stomach contents, vitreous potassium, environment. Later: putrefaction/decomposition, entomology (insect). ไม่มีวิธีเดียวที่แม่นยำ — ใช้หลายปัจจัยประกอบ"}, {"topic": "Antemortem vs postmortem wound", "q": "During autopsy, which feature indicates that a wound was inflicted before death (antemortem)?", "choices": ["Vital reaction — hemorrhage into tissues and signs of inflammation/healing", "Absence of any bleeding into the tissue", "Clean-cut edges without any tissue reaction", "The wound being covered by livor mortis only", "The wound following the skin cleavage lines"], "ans": 0, "exp": "Antemortem wound แสดง 'vital reaction' — bleeding/hemorrhage เข้าเนื้อเยื่อ (มี circulation), inflammation, ± healing/infection. Postmortem wound มัก 'ไม่มี vital reaction' (no/minimal bleeding, gaping ต่าง, edges ต่าง). สำคัญในการแยกว่าบาดแผลเกิดก่อนหรือหลังตาย"}, {"topic": "Sharp force - incised wound", "q": "A wound is longer on the skin surface than it is deep, with clean-cut regular edges, sharp/pointed ends, no tissue bridging, and it gapes. What type of wound is this?", "choices": ["Laceration from blunt force", "Incised wound", "Stab (penetrating) wound", "Abrasion from friction", "Contusion from impact"], "ans": 1, "exp": "Incised wound (sharp cutting edge เช่นมีด/แก้ว): 'ยาวกว่าลึก', clean/regular edges, pointed ends, 'no tissue bridging', gapes. ต่างจาก 'stab wound' (ลึกกว่ายาว), และ 'laceration' (blunt force — irregular edges, 'tissue bridging', abrasion/contusion รอบๆ). Defense wounds มัก incised ที่มือ/แขน"}, {"topic": "Stab wound", "q": "A penetrating wound is deeper than it is long on the surface, indicating the minimum length of the weapon. What type of wound is this?", "choices": ["Incised wound", "Laceration", "Stab wound", "Abrasion", "Contusion"], "ans": 2, "exp": "Stab (penetrating) wound: 'ลึกกว่ายาว' (depth > surface length). Depth บอก 'minimum' length ของอาวุธ (แต่ระวัง compression ของ tissue). ลักษณะ wound margin/shape อาจบอกชนิดอาวุธ (single vs double-edged). Direction/depth สำคัญทาง forensic"}, {"topic": "Laceration", "q": "A wound over a bony prominence from blunt impact has irregular, ragged, abraded/contused margins with intact tissue strands ('bridging') across the depths. What is this?", "choices": ["Incised wound from a knife", "Clean surgical wound", "Puncture wound from a needle", "Laceration (blunt force tear of the skin)", "Thermal burn blister"], "ans": 3, "exp": "Laceration = การฉีกขาดของผิวหนังจาก 'blunt force' (มักเหนือ bony prominence): irregular/ragged margins, abrasion/contusion รอบๆ, 'tissue bridging' (เส้นเนื้อเยื่อข้ามก้นแผล — vessel/nerve ไม่ขาด). ต่างจาก incised wound (sharp, clean, no bridging). อย่าใช้คำ 'laceration' กับ incised wound"}, {"topic": "Abrasion (direction)", "q": "A graze (abrasion) shows heaped-up epidermis at one end. What does this indicate?", "choices": ["The exact time of injury to the minute", "The type of weapon used", "The blood group of the assailant", "That the injury was definitely fatal", "The direction of the force"], "ans": 4, "exp": "Abrasion (graze/scratch): epidermis ถูกถลอก; 'heaped-up epidermis' อยู่ปลายด้านที่แรงสิ้นสุด → บอก 'direction of force'. Patterned abrasion (เช่น tire mark, ligature) อาจบอกวัตถุ. Abrasion เป็น antemortem/perimortem marker และช่วย reconstruct เหตุการณ์"}, {"topic": "Contusion (bruise) aging", "q": "The color change of a bruise over time (red/purple → blue → green → yellow) is used cautiously to estimate what?", "choices": ["The approximate age of the injury", "The exact weapon that caused it", "The blood alcohol level at injury", "The identity of the assailant", "The precise time of death"], "ans": 0, "exp": "Contusion (bruise): color evolution (red-purple → blue → green → yellow-brown) จาก hemoglobin breakdown ใช้ประเมิน 'age of injury' อย่าง 'คร่าวๆ/ระวัง' (แปรผันตามตำแหน่ง/ความลึก/บุคคล — ไม่แม่นยำ). 'Yellow' บ่งบอกว่าเก่ากว่า ~18-24 ชม. Bruise ที่ต่าง ages สำคัญใน suspected abuse"}, {"topic": "Firearm - entrance wound", "q": "A gunshot entrance wound typically has which features compared with the exit wound?", "choices": ["Larger and more irregular than the exit wound", "Round/oval with an abrasion collar", "Everted ragged margins without any abrasion", "Always star-shaped regardless of range", "Identical in every way to the exit wound"], "ans": 1, "exp": "Gunshot 'entrance' wound: round/oval + 'abrasion collar' (marginal abrasion จากกระสุนถู) + inverted margins; มัก 'เล็กและ regular' กว่า exit. 'Exit' wound: irregular, everted (ปลิ้นออก), no abrasion collar, มัก 'ใหญ่กว่า' (ยกเว้น shored exit). ลักษณะเปลี่ยนตาม range"}, {"topic": "Firearm - range of fire", "q": "A gunshot wound with soot/blackening and stippling (tattooing) of gunpowder on the surrounding skin indicates what firing range?", "choices": ["Distant range beyond several meters", "That the shot was self-inflicted", "Close/intermediate range", "That the weapon was a shotgun only", "That the victim was already deceased"], "ans": 2, "exp": "Range of fire จาก gunshot: 'contact' (muzzle imprint, soot in wound, seared/stellate); 'close/intermediate' (soot blackening + 'stippling/tattooing' จาก gunpowder — powder tattooing เป็น antemortem vital sign); 'distant' (เฉพาะ entrance + abrasion collar, no soot/stippling). ช่วยประเมินระยะยิงและ manner (suicide vs homicide)"}, {"topic": "Defense wounds", "q": "Incised wounds on the palms, fingers, and forearms of a stabbing victim most likely represent what?", "choices": ["Self-inflicted hesitation marks", "Postmortem artifacts from the autopsy", "Accidental injuries from a fall", "Defense wounds sustained while warding off the attack", "Occupational injuries unrelated to the death"], "ans": 3, "exp": "Defense wounds: incised/stab wounds ที่ 'ฝ่ามือ นิ้ว แขน' (ยกป้องกัน) → บ่งชี้ว่าเหยื่อ 'ต่อสู้/ป้องกันตัว' ระหว่างถูกทำร้าย → สนับสนุน homicide. ต่างจาก 'hesitation marks' (self-inflicted, superficial parallel cuts ใกล้ fatal wound ใน suicide)"}, {"topic": "Asphyxia - hanging vs strangulation", "q": "In a hanging death, the ligature mark on the neck typically shows which pattern?", "choices": ["A horizontal, continuous mark low on the neck", "Multiple crisscrossing horizontal marks", "No mark at all in any hanging", "A circular mark only around the mouth", "An inverted-V, non-continuous mark high on the neck above the thyroid"], "ans": 4, "exp": "Hanging: ligature mark เป็น 'oblique/inverted-V', 'non-continuous' (จางที่จุดแขวน), อยู่ 'สูงบนคอ' (เหนือ thyroid cartilage), เฉียงขึ้นไปหาปม. ต่างจาก 'ligature strangulation' (horizontal, continuous, low on neck) และ 'manual strangulation' (bruises/abrasions, fingernail marks, ไม่มี ligature mark ต่อเนื่อง)"}, {"topic": "Petechial hemorrhages", "q": "Pinpoint hemorrhages (petechiae) in the conjunctivae, face, and eyelids of a deceased person are a classic sign of what?", "choices": ["Asphyxia from raised venous pressure", "Carbon monoxide poisoning", "Blunt abdominal trauma", "Drowning in fresh water", "Electrocution injury"], "ans": 0, "exp": "Petechial hemorrhages (Tardieu spots) ที่ conjunctiva/face/eyelids จาก 'raised venous pressure + hypoxia' ในการอุดกั้นทางเดินหายใจ/หลอดเลือดคอ — เป็น classic sign ของ 'asphyxia' (strangulation, hanging, smothering, traumatic asphyxia). ไม่จำเพาะ 100% แต่สนับสนุน mechanical asphyxia"}, {"topic": "Drowning findings", "q": "Which autopsy finding supports antemortem drowning (the person was alive when submerged)?", "choices": ["Absence of any water in the respiratory tract", "Fine white froth in the airways and water/diatoms in distal organs", "Livor mortis over the back only", "Rigor mortis in the upper limbs", "A cherry-red discoloration of the skin"], "ans": 1, "exp": "Antemortem drowning: 'fine white/blood-tinged froth' ใน airway (จากการหายใจน้ำ + surfactant), water aspiration, hyperinflated lungs (emphysema aquosum), และในบางกรณี 'diatoms' ใน distal organs (bone marrow — บ่งชี้ circulation ตอนจมน้ำ). Drowning วินิจฉัยยาก (มัก diagnosis of exclusion) — ต้องตัดสาเหตุอื่น"}, {"topic": "Burn - antemortem vs postmortem", "q": "How can a forensic pathologist tell that a burn victim was alive at the time of a fire?", "choices": ["The presence of charring of the skin alone", "Contraction of the burned muscles (pugilistic attitude)", "Soot in the airways and elevated carboxyhemoglobin", "The body being found near the fire", "The absence of any blisters on the skin"], "ans": 2, "exp": "การอยู่รอด (alive) ขณะไฟไหม้ ยืนยันด้วยหลักฐานการ 'หายใจ' ควัน: 'soot ใน airway/trachea' + 'elevated carboxyhemoglobin' (CO จากการหายใจ) + thermal airway injury. 'Pugilistic attitude' (ท่านักมวยจาก muscle contraction จากความร้อน) และ 'heat hematoma' เกิดได้แม้ตายแล้ว — ไม่ยืนยัน antemortem"}, {"topic": "Cadaveric spasm", "q": "Immediately at the moment of death, a drowning victim is found tightly clutching weeds/grass in the hand. What is this instantaneous stiffening called?", "choices": ["Ordinary rigor mortis", "Postmortem clenching artifact", "Heat stiffening", "Cadaveric spasm", "Cold stiffening"], "ans": 3, "exp": "Cadaveric spasm (instantaneous rigor): กล้ามเนื้อที่ทำงานหนัก/emotional tension 'ทันที' ก่อนตาย แข็งค้าง 'ทันทีที่ตาย' (เช่น จับอาวุธ, กำหญ้าในคนจมน้ำ, จับปืนใน suicide). ต่างจาก rigor mortis ปกติ (เกิดหลังตายหลายชั่วโมง). มี medicolegal significance (บ่งชี้กิจกรรมขณะตาย)"}, {"topic": "Manner of death", "q": "Which of the following is a category of 'manner of death' as classified in forensic practice?", "choices": ["Myocardial infarction", "Cardiac arrest", "Multi-organ failure", "Respiratory failure", "Homicide (others: natural, accident, suicide, undetermined)"], "ans": 4, "exp": "'Manner of death' (ลักษณะการตาย) = natural, accident, suicide, homicide, undetermined. ต่างจาก 'cause of death' (สาเหตุ เช่น myocardial infarction, hemorrhage) และ 'mechanism' (เช่น cardiac arrest, exsanguination). Manner สำคัญทางกฎหมาย/สืบสวน"}, {"topic": "Postmortem interval - vitreous", "q": "Which biochemical measurement in the vitreous humor of the eye rises predictably after death and can help estimate the postmortem interval?", "choices": ["Vitreous potassium", "Vitreous glucose", "Vitreous sodium", "Vitreous calcium", "Vitreous bilirubin"], "ans": 0, "exp": "Vitreous 'potassium' เพิ่มขึ้นค่อนข้าง predictable หลังตาย (จาก cell breakdown) → ใช้ประเมิน postmortem interval (ร่วมกับปัจจัยอื่น, มี error). Vitreous ทน putrefaction ได้ดีกว่า blood. Vitreous glucose/urea ก็ใช้ประเมินบางภาวะ (เช่น diabetic ketoacidosis)"}, {"topic": "Exhumation / decomposition", "q": "The dry, preserved state of a body with leathery skin found in a hot, dry environment is called what?", "choices": ["Adipocere formation", "Mummification", "Skeletonization", "Putrefaction", "Maceration"], "ans": 1, "exp": "Mummification: การเก็บรักษาศพในสภาพ 'แห้ง' (hot/dry/ventilated environment) → skin แห้ง leathery, dehydration แทนที่ putrefaction. 'Adipocere' (grave wax): สภาพ 'ชื้น/ไม่มีอากาศ' → fat เปลี่ยนเป็น waxy substance. Maceration = การเปื่อยของทารกที่ตายในครรภ์ (sterile). ทั้งหมดช่วยประเมิน PMI/สภาพแวดล้อม"}, {"topic": "Traumatic asphyxia", "q": "A worker crushed under a heavy load has a deeply congested, purple face with florid petechiae and subconjunctival hemorrhage but a normal-colored body below. What is this?", "choices": ["Carbon monoxide poisoning", "Anaphylactic reaction", "Traumatic asphyxia", "Superior vena cava obstruction from tumor", "Facial burns from a fire"], "ans": 2, "exp": "Traumatic asphyxia: chest/abdomen ถูกกดทับหนัก → เลือดดำย้อนขึ้นหน้า/คอ (raised venous pressure) → 'deeply congested purple face', florid petechiae, subconjunctival hemorrhage, ขอบเขตชัดที่คอ (masque ecchymotique) โดยลำตัวส่วนล่างสีปกติ. บ่งชี้ mechanism การตายจากการกดทับ"}, {"topic": "Fracture pattern - dating", "q": "In a suspected child abuse case, which radiographic finding suggests fractures of different ages (repeated injury)?", "choices": ["A single acute fracture with no callus", "Normal bones with no fractures", "A congenital bone deformity", "Fractures with varying degrees of callus/healing on skeletal survey", "Only soft-tissue swelling without fracture"], "ans": 3, "exp": "Fractures ที่มี 'varying stages of healing' (callus ต่าง ages) บน skeletal survey บ่งชี้ 'repeated injury over time' → สนับสนุน non-accidental injury (child abuse). Specific patterns: metaphyseal corner/bucket-handle fractures, posterior rib fractures, fractures ในทารกที่ยังเดินไม่ได้. ต้องแยก osteogenesis imperfecta. (หัวข้อละเอียดอ่อน)"}, {"topic": "Environmental asphyxia - CO", "q": "A man is found dead in a sealed car with a charcoal stove inside; livor mortis is bright cherry-red. What is the cause of death?", "choices": ["Cyanide toxicity", "Methane asphyxiation", "Hydrogen sulfide toxicity", "Simple environmental hypoxia", "Carbon monoxide poisoning"], "ans": 4, "exp": "Sealed space + burning stove + 'cherry-red' livor = 'carbon monoxide (CO) poisoning' — CO จับ hemoglobin (carboxyhemoglobin สีแดงสด) → tissue hypoxia. ยืนยันด้วย carboxyhemoglobin level ที่สูง. เป็น classic forensic scenario (accidental/suicidal). H2S ให้ greenish, cyanide อาจ pink"}, {"topic": "Smothering", "q": "The deliberate obstruction of the external airways (nose and mouth) causing asphyxia is termed what?", "choices": ["Smothering", "Throttling (manual strangulation)", "Choking (internal airway obstruction)", "Ligature strangulation", "Hanging"], "ans": 0, "exp": "Asphyxia terms: 'smothering' = ปิด external airways (จมูก+ปาก) เช่น หมอน/มือ; 'choking' = obstruction 'ภายใน' airway (foreign body/food); 'throttling' = manual strangulation (มือบีบคอ); 'ligature strangulation' = เชือกรัดคอ (แรงจากภายนอก ไม่ใช่ body weight); 'hanging' = body weight บน ligature. แยกกลไกสำคัญทาง forensic"}, {"topic": "Manual strangulation signs", "q": "In manual strangulation (throttling), which autopsy findings are characteristic?", "choices": ["A continuous horizontal ligature mark only", "Fingernail abrasions/bruises on the neck and fractured hyoid/thyroid cartilage", "An oblique inverted-V mark high on the neck", "No neck findings whatsoever", "Bright cherry-red discoloration of the neck"], "ans": 1, "exp": "Manual strangulation (throttling): 'fingernail marks/abrasions + bruises' บนคอ (จากมือ/นิ้ว), internal bruising ของ neck muscles, และ 'fracture ของ hyoid bone/thyroid cartilage' (โดยเฉพาะผู้สูงอายุ), petechiae. ไม่มี continuous ligature mark. บ่งชี้ homicidal asphyxia"}, {"topic": "Shotgun wound", "q": "A shotgun wound fired from a distance produces a wide scatter of individual pellet marks around a central defect. What does the spread of pellets help estimate?", "choices": ["The exact identity of the shooter", "The time of death precisely", "The range of firing", "The victim's blood alcohol level", "The manner of death with certainty"], "ans": 2, "exp": "Shotgun: ที่ระยะใกล้ pellets ยังรวมกัน (single defect); ยิ่งไกล pellets 'กระจาย' มากขึ้น → 'spread/pattern ของ pellets ช่วยประเมิน range of fire'. Contact wound: soot, muzzle imprint, large defect. Wad อาจพบในแผล. ช่วย reconstruct ระยะและทิศทาง"}, {"topic": "Suicide vs homicide - sharp", "q": "In an incised-wound death, which features favor suicide rather than homicide?", "choices": ["Multiple deep wounds on the back", "Prominent defense wounds on the hands", "Wounds through the clothing in inaccessible areas", "Hesitation marks, wounds in accessible sites, and clothing moved aside", "Signs of a violent struggle at the scene"], "ans": 3, "exp": "Suicidal sharp-force death features: 'hesitation marks' (superficial tentative cuts ข้างๆ fatal wound), wounds ในตำแหน่งที่ 'เอื้อมถึงเอง' (wrist, neck, precordium), clothing มัก 'เลื่อนออก' (ไม่ตัดผ่านเสื้อ), no defense wounds/struggle. ต่างจาก homicide (defense wounds, wounds ที่ back/inaccessible, through clothing, struggle)"}, {"topic": "Postmortem identification - primary", "q": "Which methods are considered 'primary' (most reliable) for positive identification of human remains?", "choices": ["Clothing and personal effects found on the body", "Approximate height and body build", "Visual recognition by a distressed relative", "Tattoos and scars alone", "Fingerprints, dental comparison, and DNA analysis"], "ans": 4, "exp": "Primary identifiers (scientific, most reliable): 'fingerprints, dental records comparison, และ DNA'. Secondary/supportive: personal effects, clothing, tattoos/scars, medical findings, visual ID (unreliable ในสภาพ decomposed/trauma). ใน mass disaster ใช้ primary methods เป็นหลัก"}, {"topic": "Age estimation - teeth", "q": "In estimating the age of a child's remains, which dental feature is particularly useful?", "choices": ["Tooth eruption sequence and dental development stage", "The color of the tooth enamel only", "The number of dental fillings present", "The presence of orthodontic braces", "The overall size of the jaw alone"], "ans": 0, "exp": "Age estimation ในเด็ก: 'tooth eruption/dental development' (deciduous → permanent, calcification stages) แม่นยำ; ประกอบกับ 'epiphyseal (growth plate) fusion' ของกระดูก และ ossification centers. ในผู้ใหญ่ใช้ dental attrition, cranial suture closure, pubic symphysis, sternal rib end. เด็ก dentition/bone growth ให้ความแม่นยำสูง"}, {"topic": "Sex determination - skeleton", "q": "Which part of the skeleton is most reliable for determining sex of adult remains?", "choices": ["The single finger phalanx", "The pelvis", "The hyoid bone", "A single rib", "The nasal bone alone"], "ans": 1, "exp": "การพิจารณาเพศจากโครงกระดูก: 'pelvis' เชื่อถือได้ที่สุด (female pelvis กว้าง, subpubic angle >90°, greater sciatic notch กว้าง, oval inlet). รองลงมา skull (male: prominent brow ridge, mastoid ใหญ่, square chin). Long bone size/robustness ช่วยเสริม. Pelvis + skull ให้ความแม่นยำสูงสุด"}, {"topic": "Sudden natural death", "q": "A middle-aged man collapses and dies suddenly; autopsy shows severe coronary atherosclerosis with an acute thrombus. What is the most common cause of sudden natural death in adults?", "choices": ["Ruptured berry aneurysm", "Massive pulmonary embolism", "Coronary artery disease", "Epilepsy-related death", "Acute pancreatitis"], "ans": 2, "exp": "สาเหตุที่พบบ่อยที่สุดของ 'sudden natural death' ในผู้ใหญ่ = 'ischemic heart disease/coronary artery disease' (acute MI/arrhythmia จาก coronary atherosclerosis/thrombus). สาเหตุอื่น: ruptured aneurysm (aortic/berry → SAH), massive PE, cardiomyopathy, epilepsy (SUDEP). Autopsy สำคัญในการหา cause of natural death"}, {"topic": "SUNDS / Brugada (Thai)", "q": "A young previously healthy Thai/Southeast Asian man dies suddenly during sleep ('Lai Tai'); autopsy shows a structurally normal heart. Which channelopathy is associated?", "choices": ["Hypertrophic cardiomyopathy", "Rheumatic heart disease", "Coronary atherosclerosis", "Brugada syndrome", "Aortic dissection"], "ans": 3, "exp": "Sudden unexplained nocturnal death syndrome (SUNDS, 'Lai Tai') ในชายเอเชียตะวันออกเฉียงใต้/ไทย สัมพันธ์กับ 'Brugada syndrome' (SCN5A sodium channelopathy) → VF ในหัวใจที่ 'structurally normal' (autopsy negative). สำคัญทาง forensic/family screening (ECG, genetic). Molecular autopsy อาจช่วยวินิจฉัย"}, {"topic": "Postmortem toxicology sampling", "q": "For postmortem toxicology in a suspected poisoning, which specimen is often preferred because it is relatively protected from postmortem redistribution?", "choices": ["Central cardiac blood only", "Cavity blood pooled in the chest", "Superficial skin swabs", "Hair from the day of death only", "Femoral blood"], "ans": 4, "exp": "Postmortem toxicology: 'femoral (peripheral) blood' ถูกเลือกเพราะได้รับผลจาก 'postmortem redistribution' น้อยกว่า central/cardiac blood (ยาบางชนิดกระจายจากอวัยวะกลับเข้า central blood หลังตาย → ค่าสูงเทียม). เก็บหลาย specimen (blood, urine, vitreous, gastric, liver, hair) เพื่อ interpretation. Chain of custody สำคัญ"}, {"topic": "Corrosive poisoning postmortem", "q": "At autopsy, a person who ingested a strong acid has blackened, leathery corrosion of the mouth, esophagus, and stomach. What does this indicate?", "choices": ["Corrosive poisoning", "Carbon monoxide poisoning", "Cyanide poisoning", "Organophosphate poisoning", "Arsenic poisoning"], "ans": 0, "exp": "Corrosive poisoning: acid → 'coagulative necrosis' (blackened/leathery, hard eschar) ของ mouth/esophagus/stomach; alkali → liquefactive (soft, edematous, deeper). Pattern บ่งชี้ชนิด. ต้องเก็บ specimen เพื่อ identify สาร. ประเมิน manner (suicide/accident/homicide)"}, {"topic": "Arsenic poisoning - forensic", "q": "In chronic arsenic poisoning, which tissue is useful for detecting exposure over time (because arsenic is deposited there)?", "choices": ["Cerebrospinal fluid only", "Hair and nails", "Superficial epidermis", "Tear fluid", "Exhaled breath"], "ans": 1, "exp": "Chronic arsenic (และ heavy metals): สะสมใน 'hair และ nails' (keratin) → segmental analysis บอก timeline การได้รับ (โบราณเรียก 'poison of kings'). อาการ: GI, peripheral neuropathy, Mees lines (transverse white lines บนเล็บ), skin pigmentation/hyperkeratosis. Forensic hair analysis สำคัญใน chronic poisoning"}, {"topic": "Firearm - rifling / ballistics", "q": "The unique striations (marks) imparted to a bullet by the rifling of a gun barrel allow forensic examiners to do what?", "choices": ["Determine the exact time of the shooting", "Identify the shooter's fingerprints on the bullet", "Match a fired bullet to a specific firearm", "Measure the victim's blood alcohol level", "Establish the manner of death conclusively"], "ans": 2, "exp": "Rifling ของ gun barrel สร้าง 'unique striations' บนกระสุน (และ firing pin/breech marks บนปลอกกระสุน) → forensic ballistics เปรียบเทียบ 'match กระสุน/ปลอกกับอาวุธเฉพาะกระบอก' (individual characteristics). ช่วยเชื่อมโยงอาวุธกับที่เกิดเหตุ. Class characteristics บอกชนิด/ยี่ห้อ"}, {"topic": "Postmortem animal / insect activity", "q": "Superficial skin defects with dry, yellow-brown margins and no vital reaction found on exposed areas of a body outdoors are most likely due to what?", "choices": ["Antemortem incised wounds from an attack", "Antemortem abrasions from a struggle", "Chemical (acid) burns before death", "Postmortem animal or insect predation", "Electrical burns from contact"], "ans": 3, "exp": "Postmortem predation (insects — ants/roaches, หรือ animals): superficial defects, 'no vital reaction' (no bleeding/inflammation), dry margins, มักที่ exposed/moist areas (eyes, mouth, wounds). ต้องแยกจาก antemortem injury (มี vital reaction). Insect (forensic entomology) ยังช่วยประเมิน PMI"}, {"topic": "Entomology - PMI", "q": "Forensic entomology estimates the postmortem interval primarily by studying what?", "choices": ["The color of the deceased's clothing", "The blood group of the deceased", "The presence of dental fillings", "The type of soil at the scene only", "The developmental stage and succession of insects on the body"], "ans": 4, "exp": "Forensic entomology: ใช้ 'developmental stage ของแมลง' (blowfly egg → larva/maggot → pupa → adult) และ 'succession' ของชนิดแมลง บนศพ → ประเมิน 'minimum PMI' (โดยเฉพาะศพที่ตายนานเกินกว่าจะใช้ rigor/livor). ต้องคำนึงถึง temperature/environment. มีประโยชน์ในศพเน่า/outdoor"}, {"topic": "Heat / cold death - undressing", "q": "A hypothermia victim is sometimes found partially undressed in a paradoxical manner. What is this phenomenon called?", "choices": ["Paradoxical undressing", "Cadaveric spasm", "Pugilistic attitude", "Traumatic asphyxia", "Postmortem caloricity"], "ans": 0, "exp": "'Paradoxical undressing': ในภาวะ hypothermia รุนแรง ผู้ป่วยอาจรู้สึกร้อน (จาก peripheral vasodilation ช่วงท้าย) → ถอดเสื้อผ้า — พบในศพ hypothermia (อาจถูกเข้าใจผิดว่าเป็น sexual assault). Wischnewsky spots (gastric mucosal hemorrhage) เป็นอีก finding ของ hypothermia death"}, {"topic": "Fall from height", "q": "A person who falls from a great height and lands feet-first may have which characteristic injury pattern?", "choices": ["Isolated superficial facial abrasions only", "Calcaneal fractures with axial spinal and internal injuries", "A single small entry wound like a gunshot", "Ligature marks around the neck", "Cherry-red discoloration of the skin"], "ans": 1, "exp": "Fall from height (feet-first landing): 'calcaneal (heel) fractures' + axial force transmission → lower limb, pelvis, spine (compression fractures), และ internal organ injury (aortic transection, visceral) จาก deceleration. Injury pattern ช่วย reconstruct mechanism/ตำแหน่ง landing. ประเมิน manner (accident/suicide/homicide)"}, {"topic": "Pedestrian vs vehicle injury", "q": "In a pedestrian struck by a car, a bruise/laceration on the lower leg at bumper height ('bumper injury') helps determine what?", "choices": ["The exact speed of the vehicle to the km/h", "The blood alcohol level of the driver", "The point of primary impact and the vehicle/pedestrian position", "The identity of the driver", "The time of death precisely"], "ans": 2, "exp": "Pedestrian-vehicle: 'primary impact' (bumper injury ที่ leg — height บอกชนิดรถ/posture), 'secondary impact' (ถูกเหวี่ยงขึ้น bonnet/windscreen), 'tertiary' (ตกกระแทกพื้น), และ run-over (tire marks, crush). Injury pattern reconstruct เหตุการณ์/posture. Bumper injury height ช่วยประเมินตำแหน่ง"}, {"topic": "Custodial / restraint death", "q": "In a death occurring during restraint or custody, which mechanism should be considered along with a thorough independent autopsy?", "choices": ["Only natural causes should be considered", "The death should not be investigated", "Simple fainting as the sole cause", "Positional/restraint asphyxia and excited delirium", "A minor allergic reaction only"], "ans": 3, "exp": "Custodial/restraint death: ต้อง independent/thorough forensic autopsy + investigation (medicolegal sensitivity). พิจารณา 'positional/restraint asphyxia' (prone restraint จำกัดการหายใจ), excited delirium (มัก stimulant), trauma, natural disease, และ neck compression. Manner ต้องพิจารณาอย่างเป็นกลาง. (หัวข้อละเอียดอ่อน)"}, {"topic": "Vitreous / decomposition order", "q": "In the sequence of decomposition, which early external sign of putrefaction typically appears first?", "choices": ["Complete skeletonization of the body", "Adipocere formation throughout", "Full mummification of the limbs", "Bright cherry-red lividity", "Greenish discoloration of the right lower abdomen"], "ans": 4, "exp": "Putrefaction: สัญญาณภายนอกแรกๆ = 'greenish discoloration ที่ right iliac fossa/lower abdomen' (จาก bacteria ใน cecum + hemoglobin → sulfhemoglobin) → marbling (venous pattern), bloating (gas), skin slippage → skeletonization. ลำดับช่วยประเมิน PMI (แปรตาม environment/temperature)"}, {"topic": "Electrocution mark", "q": "At autopsy, a firm, pale, raised skin lesion with a central depression and blistered/collar-like margin at the contact point suggests what?", "choices": ["An electrical burn / electric mark", "A gunshot entrance wound", "An incised wound", "A chemical acid burn", "A postmortem insect bite"], "ans": 0, "exp": "Electric mark (Joule burn): ที่จุดสัมผัสไฟฟ้า — firm, pale/gray, raised margin + central depression (crater), ± metallization. บ่งชี้การสัมผัสกระแสไฟฟ้า (antemortem). High-voltage/lightning อาจมี arborescent (Lichtenberg) figure/extensive burn. ช่วยยืนยัน electrocution เป็นสาเหตุ"}, {"topic": "Coup / contrecoup injury", "q": "A person falls backward and strikes the occiput; the brain shows contusion at the site of impact and also on the opposite (frontal) side. What are these called?", "choices": ["Diffuse axonal injury only", "Coup and contrecoup injuries", "Epidural hematoma from arterial tear", "Subarachnoid hemorrhage from aneurysm", "A simple scalp contusion without brain injury"], "ans": 1, "exp": "Coup = brain contusion ที่ 'จุดกระแทก'; contrecoup = contusion ที่ 'ด้านตรงข้าม' (จาก brain เคลื่อนภายในกะโหลก, พบเด่นเมื่อ 'moving head' กระแทกวัตถุนิ่ง เช่นล้มหลังศีรษะ). ช่วย reconstruct mechanism (fall vs blow). Contrecoup มัก frontal/temporal poles"}, {"topic": "Skull fracture patterns", "q": "A large heavy object dropped on a stationary head produces a fracture radiating from the impact point. A different, ring-like fracture around the foramen magnum after a fall from height on the feet/buttocks is called what?", "choices": ["Depressed comminuted vault fracture", "Linear fracture of the temporal bone", "Ring fracture of the skull base", "Diastatic suture fracture", "Hinge fracture of the mandible"], "ans": 2, "exp": "Ring fracture: fracture รอบ foramen magnum — เกิดจากแรงตามแนวแกน (fall from height ลงเท้า/ก้น → spine ดัน skull base) หรือ blow ที่ vertex. Skull fractures อื่น: linear, depressed (localized blow), comminuted, hinge (base), diastatic (แยกตาม suture ในเด็ก). Pattern ช่วยประเมิน mechanism/force"}, {"topic": "Drowning - diatom test", "q": "In a suspected drowning, finding diatoms (microscopic algae) in the bone marrow of long bones supports what?", "choices": ["The exact time the body entered the water", "The identity of the drowned person", "That death was definitely a homicide", "That the person was alive and circulating blood when submerged", "The species of fish in the water"], "ans": 3, "exp": "Diatom test: diatoms (algae ในน้ำ) ที่พบใน 'distal organs/bone marrow' (ต้องผ่าน pulmonary circulation) สนับสนุนว่า 'ยังมีชีวิต + circulation ตอนจมน้ำ' (antemortem drowning) และ match diatoms กับแหล่งน้ำ. มีข้อจำกัด/ถกเถียง (contamination) — ใช้ประกอบหลักฐานอื่น (drowning เป็น diagnosis of exclusion)"}, {"topic": "Washerwoman hands", "q": "A body recovered from water shows wrinkled, sodden, bleached skin of the palms and soles. What does this indicate?", "choices": ["Antemortem chemical burns to the hands", "A specific poison exposure before death", "Electrocution through the hands", "That the person was definitely murdered", "Immersion of the body in water"], "ans": 4, "exp": "'Washerwoman's hands/feet': ผิวหนังฝ่ามือ/ฝ่าเท้าเปื่อยยับ ซีด บวมน้ำ จากการแช่น้ำ → บ่งชี้ 'immersion' และช่วยประเมินระยะเวลาที่อยู่ในน้ำ (ไม่ใช่ว่าจมน้ำตายเสมอ — ศพที่ถูกทิ้งลงน้ำหลังตายก็มีได้). ประเมินร่วมกับ findings อื่นว่าเป็น drowning หรือไม่"}, {"topic": "Infanticide - live birth", "q": "In examining a dead newborn to determine whether it was born alive, which finding indicates the baby breathed after birth?", "choices": ["Aerated lungs that had established respiration", "The presence of vernix on the skin", "The length of the umbilical cord", "The color of the newborn's hair", "The weight of the placenta"], "ans": 0, "exp": "การพิสูจน์ 'live birth' (สำคัญใน infanticide): สัญญาณว่าเด็ก 'หายใจ' หลังคลอด — lungs ที่ aerated (hydrostatic/floatation test: ปอดที่หายใจแล้วลอยน้ำ — ต้องระวัง putrefaction/resuscitation ทำให้ผลคลาดเคลื่อน), diaphragm level, air ใน GI, changes อื่น. ต้องแยก stillborn (มัก macerated ถ้าตายในครรภ์นาน)"}, {"topic": "Stillbirth - maceration", "q": "A fetus that died in utero and was retained for days before delivery shows skin slippage, reddish-brown discoloration, and softening. What is this sterile decomposition called?", "choices": ["Putrefaction", "Maceration", "Mummification", "Adipocere formation", "Cadaveric spasm"], "ans": 1, "exp": "Maceration = 'sterile' autolytic decomposition ของ fetus ที่ตายในครรภ์และค้างอยู่ (ไม่มี bacteria — aseptic): skin slippage, reddish-brown discoloration, softening, overlapping skull bones (Spalding sign). บ่งชี้ 'intrauterine death' (dead born) ก่อนคลอด → แยกจาก live birth ในคดี infanticide"}, {"topic": "Cyanide poisoning - smell", "q": "At autopsy, a characteristic bitter almond smell and bright pink lividity in a person who died rapidly after ingestion suggests which poison?", "choices": ["Arsenic", "Organophosphate", "Cyanide", "Paraquat", "Carbon monoxide"], "ans": 2, "exp": "Cyanide poisoning: 'bitter almond' smell (บางคนดมไม่ได้ genetically), rapid death, bright pink/red lividity (จาก high venous O2 — cells ใช้ O2 ไม่ได้). Blocks cellular respiration. Confirm ด้วย toxicology. เก็บ specimen ในภาชนะปิดสนิท (volatile). CO ก็ให้ cherry-red แต่ไม่มีกลิ่น almond"}, {"topic": "Datura / plant poisoning", "q": "A person who ingested Datura (jimsonweed) seeds presents with an anticholinergic picture. Which finding fits?", "choices": ["Pinpoint pupils and excessive salivation", "Bright cherry-red skin and coma", "Descending flaccid paralysis without fever", "Dilated pupils, dry skin, delirium, and tachycardia", "Severe metabolic acidosis with high osmolar gap"], "ans": 3, "exp": "Datura (jimsonweed, มี atropine/scopolamine): 'anticholinergic' toxidrome — 'dilated pupils (mydriasis), dry skin, delirium/hallucination, tachycardia', urinary retention, hyperthermia ('mad as a hatter...'). พบใน accidental/intentional ingestion ในไทย/เอเชีย. รักษา supportive + benzodiazepine; physostigmine ในบางกรณี"}, {"topic": "Snakebite - fang marks", "q": "In a suspected snakebite death, examination of the wound may show what characteristic finding?", "choices": ["A round entrance wound with an abrasion collar", "An oblique ligature mark on the neck", "Bright cherry-red discoloration", "Stellate soot-blackened wound edges", "Paired puncture marks with local swelling"], "ans": 4, "exp": "Snakebite: 'paired puncture (fang) marks' + local swelling/necrosis (viper) หรือ minimal local + systemic (neurotoxic — cobra/krait). Forensic: identify fang marks, envenomation effects (hematotoxic bleeding/coagulopathy, neurotoxic paralysis), venom detection. ประเมิน manner (accidental มัก)"}, {"topic": "Alcohol - postmortem production", "q": "In interpreting postmortem blood alcohol, why must caution be used with decomposed bodies?", "choices": ["Microbial fermentation can produce alcohol after death", "Alcohol always disappears completely after death", "Postmortem alcohol is impossible to measure", "Decomposition never affects alcohol levels", "Alcohol converts to cyanide after death"], "ans": 0, "exp": "Postmortem blood alcohol: 'microbial fermentation' (โดยเฉพาะ decomposed bodies) สามารถ 'สร้าง ethanol' หลังตาย → false 'elevated' level. Interpretation ต้องระวัง — ใช้ vitreous/urine, ตรวจ other alcohols (propanol) เป็น marker ของ postmortem production, และคำนึง decomposition. Antemortem interpretation ต้องรอบคอบ"}, {"topic": "Postmortem clot", "q": "At autopsy, a yellowish 'chicken-fat' clot with underlying dark red 'currant-jelly' clot in the heart chambers indicates what?", "choices": ["An antemortem thrombus causing the death", "A postmortem clot", "A pulmonary embolus that killed the patient", "Evidence of poisoning", "An artifact of embalming"], "ans": 1, "exp": "Postmortem clot: 'chicken-fat' (yellow, serum/plasma layer) เหนือ 'currant-jelly' (dark red, RBC settle) — เกิดหลังตาย, ผิวเรียบ, ไม่ติดผนัง. ต่างจาก 'antemortem thrombus' (dry, granular, laminated 'lines of Zahn', ติดผนัง) ที่อาจเป็นสาเหตุการตาย (PE/MI). แยกกันสำคัญ"}, {"topic": "Firearm - contact wound", "q": "A gunshot wound with a stellate (star-shaped) tear, muzzle imprint, and soot inside the wound track indicates what firing distance?", "choices": ["Distant range beyond several meters", "Intermediate range only", "Contact range", "That the gun was never fired at the victim", "A shotgun fired from a distance"], "ans": 2, "exp": "Contact (hard-contact) gunshot wound: gas เข้าใต้ผิว → 'stellate tearing' (โดยเฉพาะเหนือกระดูก เช่น skull), 'muzzle imprint' (รอยปากกระบอก), soot 'ภายใน' wound track, seared margins. บ่งชี้ระยะสัมผัส — สำคัญในการประเมิน manner (suicide มัก contact ที่ temple/mouth)"}, {"topic": "Grievous injury concept", "q": "In forensic/legal terms, an injury that endangers life, causes permanent disfigurement, or fracture/dislocation is generally classified as what (versus 'simple hurt')?", "choices": ["A trivial abrasion", "A postmortem artifact", "A natural disease process", "Grievous hurt", "A self-limited bruise"], "ans": 3, "exp": "การจำแนกบาดแผลทางกฎหมาย: 'grievous hurt' (บาดเจ็บสาหัส) = อันตรายถึงชีวิต, permanent disfigurement/loss of function, fracture/dislocation, prolonged incapacity — ตามที่กฎหมายกำหนด; ต่างจาก 'simple hurt' (บาดเจ็บเล็กน้อย). แพทย์ระบุลักษณะ/ความรุนแรงเพื่อ medicolegal report (การจัดประเภทตามกฎหมายเป็นของศาล)"}, {"topic": "Sexual assault - evidence", "q": "In examining a sexual assault survivor, which evidence collection is important within the appropriate time window?", "choices": ["Only a verbal history without any examination", "Immediate discharge without any evidence collection", "Collecting evidence only if the survivor insists loudly", "Destroying clothing to protect privacy", "Swabs for spermatozoa/DNA, documentation of injuries, with chain of custody"], "ans": 4, "exp": "Sexual assault examination (ด้วยความยินยอม, sensitive, non-judgmental): เก็บ evidence ตาม time window — swabs (spermatozoa, seminal fluid/'acid phosphatase', DNA), document injuries (genital/extragenital), clothing, + medical care (STI/HIV prophylaxis, emergency contraception, mental health support) + 'chain of custody'. Negative sperm ไม่ตัด assault (condom, azoospermia, delay). (หัวข้อละเอียดอ่อน — ดูแลด้วยความเห็นใจ)"}, {"topic": "Sexual assault - acid phosphatase", "q": "In sexual assault forensics, a negative test for spermatozoa and acid phosphatase 3 days after the event means what?", "choices": ["It does not exclude assault", "It definitively proves no sexual contact occurred", "It proves the survivor is not telling the truth", "It confirms the assailant's identity", "It establishes the exact time of the assault"], "ans": 0, "exp": "Seminal markers (spermatozoa, 'acid phosphatase', PSA) เสื่อมสลายตามเวลา (sperm ตรวจได้ ~ไม่กี่วัน, acid phosphatase สั้นกว่า) → 'negative ไม่ตัด' sexual assault (delay, condom, no ejaculation, azoospermia, washing). ต้องประเมินองค์รวม (history, injuries, DNA). อย่าตีความ negative = ไม่มีเหตุ. (sensitive topic)"}, {"topic": "Bite mark", "q": "A patterned injury on a victim's skin showing paired opposing arches of tooth marks may allow comparison for what?", "choices": ["Determining the exact time of death", "Comparison with a suspect's dentition", "Measuring the blood alcohol level", "Identifying the victim's blood group", "Establishing the cause of natural death"], "ans": 1, "exp": "Bite mark: patterned injury (paired arches ของรอยฟัน) → อาจเปรียบเทียบกับ dentition ของผู้ต้องสงสัย + swab สำหรับ salivary DNA. อย่างไรก็ตาม bite mark analysis มีข้อจำกัด/ความน่าเชื่อถือถูกตั้งคำถาม (skin distortion) — DNA จาก saliva reliable กว่า. ใช้ประกอบหลักฐาน"}, {"topic": "Fingerprint patterns", "q": "Fingerprint identification relies on the uniqueness and permanence of ridge patterns. What are the three basic pattern types?", "choices": ["Lines, dots, and circles", "Squares, triangles, and stars", "Loops, whorls, and arches", "Waves, spirals, and grids", "Bands, rings, and crosses"], "ans": 2, "exp": "Fingerprint (dermatoglyphics): pattern พื้นฐาน 3 แบบ = 'loops, whorls, arches' (+ minutiae/ridge details ที่ unique). Uniqueness + permanence → primary identification. ใช้ระบุตัวบุคคล/ที่เกิดเหตุ (latent prints). ยังไม่เปลี่ยนตลอดชีวิต"}, {"topic": "Stature estimation", "q": "Forensic anthropologists estimate a deceased person's height from skeletal remains primarily using what?", "choices": ["The circumference of the skull only", "The number of teeth present", "The width of the pelvis alone", "Regression formulae based on long bone lengths", "The length of the fingernails"], "ans": 3, "exp": "Stature (height) estimation: ใช้ 'regression formulae' จากความยาว 'long bones' (femur เชื่อถือได้สุด, ตามด้วย tibia/humerus) — population-specific. ส่วนหนึ่งของ biological profile (age, sex, stature, ancestry) ในการ identify skeletal remains"}, {"topic": "Dowry / bride burning", "q": "A young married woman dies of extensive burns at home; forensic evaluation must carefully consider which possibility besides accident?", "choices": ["Only accidental kitchen fire in every case", "Natural disease causing the burns", "A postmortem artifact of decomposition", "That burns are never medicolegally significant", "Homicidal or suicidal burning"], "ans": 4, "exp": "การเสียชีวิตจากไฟไหม้ในหญิงสาว (โดยเฉพาะบริบท domestic/dowry violence — สำคัญในเอเชียใต้) ต้องประเมินอย่างรอบคอบว่าเป็น 'accident, suicide, หรือ homicide' (bride burning): pattern ของ burns, accelerant, scene, antemortem injury, dying declaration. Manner ต้องพิจารณาเป็นกลาง. (หัวข้อละเอียดอ่อน)"}, {"topic": "Drug abuse - needle marks", "q": "At autopsy of a suspected intravenous drug user, which finding supports chronic injection drug use?", "choices": ["Needle track marks and scarring over veins", "Bright cherry-red lividity", "Paired fang puncture marks", "A stellate contact gunshot wound", "Washerwoman changes of the hands"], "ans": 0, "exp": "Chronic IV drug use: 'needle track marks/scarring' over accessible veins (antecubital, groin, neck), thrombosed veins, skin abscesses, ± foreign body granulomas ในปอด/ตับ. Forensic: toxicology (drug level), body packing (ห่อยา), overdose evaluation. ช่วยประเมิน cause/manner (accidental overdose พบบ่อย)"}, {"topic": "Starvation / neglect death", "q": "A dependent elderly or child found emaciated with pressure sores and dehydration raises concern for what, requiring investigation?", "choices": ["Only natural aging with no concern", "Neglect (with forensic and social evaluation)", "A normal finding requiring no action", "A self-limited condition needing no report", "An artifact of postmortem change only"], "ans": 1, "exp": "Emaciation + pressure sores + dehydration ในผู้พึ่งพิง (เด็ก/ผู้สูงอายุ/ผู้พิการ) → นึกถึง 'neglect/abuse' → ต้องประเมิน forensic + social, document, และรายงานตามกฎหมาย (mandatory reporting ในบางบริบท). ต้องแยก underlying disease (malignancy, malabsorption). (หัวข้อละเอียดอ่อน — ดูแลรอบคอบ)"}, {"topic": "Firearm suicide site", "q": "In firearm suicide, the entrance wound is most commonly located in which accessible 'site of election'?", "choices": ["The middle of the upper back", "The back of the head at the occiput", "Temple, mouth, or precordium", "The sole of the foot", "The palm of the non-dominant hand"], "ans": 2, "exp": "Firearm suicide 'sites of election' (accessible, มัก contact wound): 'temple (มัก non-dominant side... จริงๆ dominant side), mouth, precordium (chest over heart), submental'. + hesitation/soot/contact features, weapon ในมือ (cadaveric spasm), single wound. Wounds ที่ back/occiput/inaccessible ชี้ homicide. (หัวข้อละเอียดอ่อน)"}, {"topic": "Medicolegal autopsy indication", "q": "Which death requires a medicolegal (forensic) autopsy rather than only a clinical one?", "choices": ["An expected death from a documented terminal illness", "A death after a long hospital stay with a clear diagnosis", "Any death where the family requests no autopsy", "Sudden, unexpected, or unnatural death", "A death certified by the treating physician as natural"], "ans": 3, "exp": "Medicolegal (forensic) autopsy จำเป็นใน: 'sudden/unexpected/unnatural death' — accident, suicide, homicide, poisoning, death in custody/anesthesia, unidentified body, suspicious circumstances, maternal/operative death. ทำโดยคำสั่ง (พนักงานสอบสวน/ศาล) — ไม่ต้องขอ family consent (ต่างจาก clinical autopsy). ในไทยตาม พ.ร.บ.ชันสูตรพลิกศพ"}, {"topic": "Locard's principle", "q": "The forensic principle that 'every contact leaves a trace' (transfer of trace evidence between people/objects) is known as what?", "choices": ["Beck's triad", "Wilson-Jungner criteria", "The Daubert standard", "Virchow's triad", "Locard's exchange principle"], "ans": 4, "exp": "Locard's exchange principle: 'every contact leaves a trace' — เมื่อบุคคล/วัตถุสัมผัสกัน มีการ transfer ของ trace evidence (fiber, hair, DNA, soil, gunshot residue) ทั้งสองทาง → เป็นพื้นฐานของ forensic trace evidence/crime scene investigation. ช่วยเชื่อมโยงผู้ต้องสงสัย-เหยื่อ-สถานที่"}, {"topic": "Gunshot residue", "q": "To determine whether a person recently fired a gun, forensic examiners test the hands for what?", "choices": ["Gunshot residue", "Diatoms from the water", "Acid phosphatase from semen", "Carboxyhemoglobin levels", "Vitreous potassium concentration"], "ans": 0, "exp": "Gunshot residue (GSR): primer particles ('lead, barium, antimony') ถูก deposit บนมือ/เสื้อผ้าของผู้ยิง (และรอบ entrance wound). ตรวจด้วย SEM-EDX → บ่งชี้ว่าบุคคล 'ยิงปืน/อยู่ใกล้' (ระวัง secondary transfer/contamination). ช่วยแยก shooter และประเมิน range (residue รอบแผล)"}, {"topic": "Air embolism", "q": "A diver who ascends too rapidly, or a patient with a large open neck vein, can develop sudden collapse from what?", "choices": ["Fat embolism from a fracture", "Air embolism", "Amniotic fluid embolism", "Septic pulmonary emboli", "A postmortem clot"], "ans": 1, "exp": "Air/gas embolism: อากาศเข้า venous (open neck vein, central line, barotrauma) หรือ arterial (diving barotrauma) → obstruct circulation → sudden collapse/arrest. Diving: rapid ascent → arterial gas embolism/pneumothorax. รักษา: left-lateral/Trendelenburg (venous), 100% O2, hyperbaric. Forensic: หา air ใน right heart (autopsy under water)"}, {"topic": "Fat embolism", "q": "A young patient with long-bone (femur) fractures develops dyspnea, confusion, and a petechial rash 1-2 days later. What is the diagnosis?", "choices": ["Pulmonary thromboembolism", "Air embolism", "Fat embolism syndrome", "Anaphylaxis", "Acute myocardial infarction"], "ans": 2, "exp": "Fat embolism syndrome (1-3 วันหลัง long-bone/pelvic fracture): classic triad = 'respiratory distress (hypoxia) + neurologic (confusion) + petechial rash' (โดยเฉพาะ conjunctiva/axilla/chest). รักษา supportive (O2/ventilation), early fracture fixation ป้องกัน. Forensic: fat globules ในปอด/สมอง (special stain). ต่างจาก PE (thrombus)"}, {"topic": "Sudden death - epilepsy", "q": "A person with known epilepsy is found dead in bed with no anatomical cause at autopsy. What is this recognized entity?", "choices": ["Sudden cardiac death from coronary disease", "Death from status epilepticus witnessed", "Death from an overdose of medication", "Sudden unexpected death in epilepsy", "Death from an undetected stroke"], "ans": 3, "exp": "SUDEP (sudden unexpected death in epilepsy): ผู้ป่วย epilepsy เสียชีวิตกะทันหันโดย 'ไม่พบสาเหตุทาง anatomical/toxicological' ที่ autopsy (มัก nocturnal, unwitnessed) — เชื่อว่าเกี่ยวกับ postictal cardiorespiratory dysfunction. เป็น diagnosis of exclusion. Poor seizure control เพิ่มความเสี่ยง"}, {"topic": "Anaphylaxis death - tryptase", "q": "In a suspected fatal anaphylaxis, which postmortem laboratory test supports the diagnosis?", "choices": ["Elevated vitreous potassium", "Elevated carboxyhemoglobin", "Presence of diatoms in marrow", "Elevated postmortem blood alcohol", "Elevated serum mast cell tryptase"], "ans": 4, "exp": "Fatal anaphylaxis: 'elevated serum mast cell tryptase' (released จาก mast cells) สนับสนุนการวินิจฉัย (เก็บ postmortem blood, ระวัง interpretation). + history of exposure, laryngeal/pulmonary edema, specific IgE. Autopsy findings อาจ subtle → tryptase + clinical context สำคัญ"}, {"topic": "Hangman's fracture", "q": "In judicial hanging with a long drop, a characteristic fracture of the C2 vertebra occurs. What is it called?", "choices": ["Hangman's fracture", "Jefferson fracture of C1", "Odontoid peg fracture", "Clay-shoveler fracture", "Chance fracture of the lumbar spine"], "ans": 0, "exp": "Hangman's fracture = bilateral pedicle/pars fracture ของ C2 (axis) จาก hyperextension + distraction — classic ใน 'judicial hanging (long drop)'. ใน typical suicidal hanging (short drop) มัก 'asphyxia' เป็นกลไกตาย (ligature mark, petechiae) โดยไม่มี cervical fracture. Jefferson = C1 burst"}, {"topic": "Chop wound", "q": "A wound with features of both incised and lacerated wounds (deep, gaping, with underlying bone cuts) inflicted by a heavy sharp weapon (axe, machete) is called what?", "choices": ["Simple incised wound", "Chop wound", "Puncture wound", "Abrasion", "Contusion"], "ans": 1, "exp": "Chop wound: จากอาวุธ 'หนัก + มีคม' (axe, machete, ใบพัด) → รวมลักษณะ incised (edges ค่อนข้างเรียบ) + laceration (deep, gaping, underlying bone/cartilage cuts, marginal abrasion/contusion). บ่งชี้ heavy sharp force. พบใน homicide/accident (เครื่องจักร)"}, {"topic": "Postmortem artifact - resuscitation", "q": "At autopsy of a patient who received CPR, rib fractures and sternal bruising are found. How should these be interpreted?", "choices": ["Definitive evidence of a homicidal assault", "Proof that the patient was strangled", "Likely resuscitation artifacts, distinguished from antemortem assault injuries", "Signs of a fall from a great height", "Evidence of a firearm injury"], "ans": 2, "exp": "Resuscitation artifacts: CPR → rib/sternal fractures, chest bruising, gastric/liver injury, intubation trauma; central line/defibrillation marks. ต้อง 'แยกจาก antemortem assault injury' (ประวัติ resuscitation, distribution, vital reaction). อย่าตีความผิดเป็น homicide. Documentation ของ resuscitation สำคัญ"}, {"topic": "Ancestry from skull", "q": "In building a biological profile from skeletal remains, ancestry (population affinity) is estimated primarily from features of which structure?", "choices": ["The femur length only", "The number of ribs", "The finger phalanges", "The skull (craniofacial features)", "The sternum shape alone"], "ans": 3, "exp": "Ancestry/population affinity ประเมินจาก 'craniofacial features ของ skull' (nasal aperture, orbital shape, facial projection, dental morphology) — ร่วมกับ metric analysis. เป็นส่วนหนึ่งของ biological profile (age, sex, stature, ancestry) ในการ identify skeletal remains. ยังคงมีข้อจำกัด/ควรระวังการตีความ"}, {"topic": "mtDNA / STR", "q": "When only degraded skeletal remains are available and maternal-line comparison is needed, which DNA analysis is useful?", "choices": ["Nuclear STR analysis of fresh blood only", "Y-chromosome analysis for maternal lineage", "Blood group ABO typing alone", "Fingerprint pattern comparison", "Mitochondrial DNA analysis"], "ans": 4, "exp": "DNA forensics: 'nuclear STR' (short tandem repeats) เป็นมาตรฐาน (individual identification, ต้องการ DNA คุณภาพดี). ในตัวอย่างเก่า/degraded (bone, hair shaft) → 'mitochondrial DNA' (มี copy มาก, ทนกว่า, 'maternally inherited' → เปรียบเทียบ maternal relatives). Y-STR สำหรับ paternal lineage/male fraction"}, {"topic": "Disaster victim identification", "q": "In a mass fatality incident, the internationally recognized framework for identifying victims relies primarily on which comparisons?", "choices": ["Primary identifiers: fingerprints, dental, and DNA", "Only visual recognition by relatives", "Clothing and jewelry as the sole method", "Approximate height and weight only", "The location where each body was found"], "ans": 0, "exp": "Disaster Victim Identification (DVI, Interpol framework): เปรียบเทียบ 'antemortem vs postmortem data' โดยใช้ 'primary identifiers (fingerprints, dental, DNA)' เป็นหลัก + secondary (medical, property, tattoos). Phases: scene, postmortem, antemortem, reconciliation, debriefing. Visual ID ไม่น่าเชื่อถือในภัยพิบัติ"}, {"topic": "Stomach contents", "q": "At autopsy, the state of digestion of the stomach contents is sometimes used, with caution, to help estimate what?", "choices": ["The exact identity of the deceased", "The time interval between the last meal and death", "The blood group of the deceased", "The manner of death conclusively", "The type of weapon used"], "ans": 1, "exp": "Stomach contents + degree of digestion + gastric emptying (~นาที-ชั่วโมงหลังมื้ออาหาร) ใช้ประเมิน 'เวลาระหว่างมื้อสุดท้ายกับการตาย' อย่าง 'ระวัง' (แปรผันมาก — ชนิดอาหาร, stress, illness, individual). ใช้ประกอบการประเมิน time of death ร่วมกับปัจจัยอื่น. Type of food อาจบ่งบอกมื้อ"}, {"topic": "Autoerotic death", "q": "A person is found dead with evidence of self-applied asphyxial apparatus and no suicide note or third-party involvement. What is this likely manner?", "choices": ["Homicide by strangulation", "Natural death from a cardiac cause", "Accidental death", "Suicidal hanging with intent", "Postmortem artifact"], "ans": 2, "exp": "Autoerotic asphyxia: การใช้ self-applied asphyxial mechanism เพื่อ enhance sexual arousal → หากพลาดเป็น 'accidental death' (มัก escape mechanism, no suicide intent/note, specific paraphernalia, private setting). ต้องแยกจาก suicide/homicide อย่างรอบคอบ. (หัวข้อละเอียดอ่อน — ประเมินเป็นกลาง)"}, {"topic": "Postmortem lividity fixation", "q": "In a body examined 12 hours after death, the livor mortis no longer blanches on pressure and does not shift with repositioning. What does 'fixed' lividity indicate?", "choices": ["The exact minute of death", "That death was a homicide", "The blood alcohol level at death", "The body has not been moved after lividity became fixed", "That the person drowned"], "ans": 3, "exp": "Livor mortis 'fixation' (~6-12 ชม.): เลือดออกนอกหลอดเลือด/แข็งตัว → 'ไม่ blanch, ไม่ shift' เมื่อพลิกตัว. ถ้าพบ lividity ในตำแหน่งที่ไม่ตรงกับ body position ปัจจุบัน → บ่งชี้ 'การเคลื่อนย้ายศพ' หลังตาย. ช่วยประเมิน PMI และ scene reconstruction"}, {"topic": "Firearm - backspatter", "q": "In a close-range gunshot to the head, blood/tissue may be projected back toward the weapon and shooter. What is this called?", "choices": ["Forward spatter", "Arterial spurting", "Passive dripping", "Transfer stain", "Backspatter"], "ans": 4, "exp": "Backspatter: blood/tissue ที่ถูก 'ดีดกลับ' ไปทางอาวุธ/ผู้ยิง ใน close-range gunshot (โดยเฉพาะศีรษะ) → อาจพบบนมือ/อาวุธของผู้ยิง (bloodstain pattern analysis). ต่างจาก 'forward spatter' (ออกทาง exit ไปทิศกระสุน). ช่วยประเมินระยะ/ตำแหน่งผู้ยิง"}, {"topic": "Aconite / oleander (cardiac)", "q": "A person who ingested a plant (e.g., oleander/aconite) dies with cardiac arrhythmia; these plants act like which drug class?", "choices": ["Cardiac glycosides / sodium channel effects causing arrhythmia", "Anticholinergic agents causing dry delirium", "Cholinesterase inhibitors causing wet crisis", "Corrosive acids causing GI burns", "Opioids causing respiratory depression"], "ans": 0, "exp": "พืชพิษต่อหัวใจ: 'oleander' (ยี่โถ, cardiac glycosides คล้าย digoxin → hyperkalemia, arrhythmia — treat like digoxin toxicity, Fab); 'aconite' (โหรา, sodium channel activator → arrhythmia, paresthesia). พบใน accidental/intentional poisoning ในเอเชีย/ไทย. Forensic: history, plant identification, toxicology"}, {"topic": "Heat stroke death", "q": "A person dies during a heat wave with a very high core temperature and no other cause. Autopsy may be nonspecific. What is the cause and manner?", "choices": ["Hypothermia; always homicidal", "Hyperthermia", "Carbon monoxide poisoning; always suicidal", "Drowning; always accidental", "Cyanide poisoning; always natural"], "ans": 1, "exp": "Heat stroke death: very high core temperature + CNS dysfunction; autopsy findings มัก 'nonspecific' → ต้องอาศัย 'circumstantial evidence' (environment/heat wave, activity, temperature at scene) + rule out other causes. Manner มัก accidental (elderly, exertional, infants in cars). Hyperthermia เป็น cause ที่ต้องประเมินบริบท"}, {"topic": "Time since death - factors", "q": "Which factor most significantly affects the rate of body cooling (algor mortis) and thus estimates of time since death?", "choices": ["The blood group of the deceased", "The color of the deceased's eyes", "Ambient temperature", "The number of teeth present", "The deceased's occupation"], "ans": 2, "exp": "Algor mortis (cooling) rate ได้รับผลจาก 'ambient temperature' (มากสุด) + body mass/surface area, clothing/covering, environment (air/water — น้ำเย็นเร็วกว่า), position. ทำให้การประเมิน time of death จาก temperature มี error → ใช้ร่วมกับ rigor/livor/other. ไม่มีวิธีเดียวแม่นยำ"}, {"topic": "Traumatic tattooing vs powder tattoo", "q": "Foreign material (dirt, gunpowder) driven into and retained in the skin around a wound, that cannot be wiped away, is called what?", "choices": ["Livor mortis discoloration", "A simple surface abrasion", "Postmortem lividity", "Traumatic tattooing", "A thermal burn eschar"], "ans": 3, "exp": "Traumatic tattooing: particulate (dirt, gunpowder — 'stippling/powder tattooing' รอบ gunshot ระยะใกล้, หรือ debris จากอุบัติเหตุ) ฝังในผิวหนัง 'เช็ดไม่ออก' (permanent). Powder tattooing เป็น 'vital sign' (antemortem) และช่วยประเมิน range of fire. ต่างจาก soot ที่เช็ดออกได้"}, {"topic": "Exhumation", "q": "Exhumation (disinterment) of a buried body may be ordered for which forensic purpose?", "choices": ["To reuse the burial plot for another person", "Only for religious ceremony reasons", "To simply relocate the grave", "It is never permitted under any circumstance", "Re-examination for cause/manner of death, toxicology, or identity in a legal case"], "ans": 4, "exp": "Exhumation: การขุดศพขึ้นมาตรวจซ้ำ (โดยคำสั่งกฎหมาย/ศาล) เพื่อ forensic purposes — re-examine cause/manner of death, toxicology (poisoning สงสัยภายหลัง), identification, หรือ new evidence in ongoing case. ต้องมี legal authorization + documentation + identification. เก็บ samples (tissue, hair, nails) สำหรับ analysis"}, {"topic": "Sudden death - ruptured aneurysm", "q": "A person collapses with sudden death; autopsy reveals blood in the subarachnoid space from a ruptured berry aneurysm. What is the cause of death?", "choices": ["Subarachnoid hemorrhage from a ruptured cerebral aneurysm", "Traumatic epidural hematoma", "Ischemic stroke from thrombosis", "Hypertensive intracerebral hemorrhage", "Meningitis with cerebral edema"], "ans": 0, "exp": "Ruptured 'berry (saccular) aneurysm' (มักที่ circle of Willis) → subarachnoid hemorrhage → sudden severe headache/collapse/death. เป็นสาเหตุ sudden natural death (ต้องแยกจาก traumatic SAH). Autopsy พบ blood ใน subarachnoid space + aneurysm. Risk: HT, smoking, polycystic kidney disease"}, {"topic": "Bloodstain pattern", "q": "At a scene, elongated blood drops with directional tails and a pattern of many small spots may allow analysts to infer what?", "choices": ["The exact time of the assault to the minute", "The direction, force, and mechanism of the bloodshed event", "The blood group of the assailant only", "The identity of the victim conclusively", "The natural disease of the deceased"], "ans": 1, "exp": "Bloodstain pattern analysis: shape/size/distribution ของ bloodstains บอก 'direction (tail ชี้ทิศ), angle of impact, force/mechanism' (passive drip, medium/high-velocity spatter, cast-off, arterial, transfer, void). ช่วย reconstruct เหตุการณ์/ตำแหน่ง. ใช้ประกอบหลักฐาน (มีข้อจำกัด/ต้องผู้เชี่ยวชาญ)"}, {"topic": "Postmortem caloricity", "q": "In rare situations (e.g., some infections, poisonings), the body temperature transiently rises after death instead of falling. What is this called?", "choices": ["Algor mortis", "Paradoxical undressing", "Postmortem caloricity", "Cadaveric spasm", "Cold stiffening"], "ans": 2, "exp": "Postmortem caloricity: body temperature 'สูงขึ้นชั่วคราวหลังตาย' (แทนที่จะเย็นลง) — พบใน septicemia/severe infection, บาง poisoning (strychnine), heat stroke, pontine hemorrhage (ต่อ metabolism/bacterial activity). ทำให้การประเมิน time of death จาก temperature ผิดพลาดได้ → ต้องคำนึงถึงบริบท"}, {"topic": "Perimortem vs postmortem fracture", "q": "In skeletal remains, a fracture with sharp edges and a 'green-bone' plastic response (bending) suggests the injury occurred when?", "choices": ["Long after death, when the bone was dry", "Only during the excavation of remains", "During embalming of the body", "Around the time of death, when bone was still fresh/moist", "It cannot be determined at all"], "ans": 3, "exp": "Perimortem fracture (ขณะ/ใกล้เวลาตาย, bone ยัง 'fresh/moist' มี collagen): plastic response — สม? edges, bending, radiating fractures, adherent fragments. Postmortem (dry bone): sharp right-angle edges, different color at fracture, no plastic deformation. ช่วยแยกว่า trauma เกิดใกล้ตายหรือ postmortem (excavation artifact)"}, {"topic": "Judicial vs suicidal hanging", "q": "In typical suicidal hanging (short drop), what is the usual mechanism of death?", "choices": ["Complete transection of the spinal cord", "Massive hemorrhage from a neck vessel", "Cardiac tamponade from the ligature", "Immediate decapitation in every case", "Asphyxia and/or cerebral vascular occlusion, not cervical fracture"], "ans": 4, "exp": "Suicidal hanging (short drop): mechanism มัก 'venous/arterial occlusion + airway compression → cerebral hypoxia/asphyxia' — cervical fracture 'ไม่ค่อยพบ' (ต่างจาก judicial long-drop ที่มี hangman's fracture C2). Findings: oblique ligature mark สูงบนคอ, petechiae. ประเมิน manner (มัก suicide). (หัวข้อละเอียดอ่อน)"}, {"topic": "Trace evidence - fiber/hair", "q": "Fibers and hairs recovered from a victim or scene are examples of what kind of evidence, consistent with Locard's principle?", "choices": ["Trace evidence linking people, objects, and locations", "Primary identification evidence like DNA", "Evidence of the exact time of death", "Proof of the manner of death alone", "Evidence unrelated to the investigation"], "ans": 0, "exp": "Trace/transfer evidence (fibers, hair, glass, soil, paint, GSR) — ตาม Locard's principle การสัมผัสทิ้งร่องรอย → เชื่อมโยง suspect-victim-scene. Hair อาจให้ mtDNA (root → nuclear DNA). Collection/preservation + chain of custody สำคัญ. เป็น corroborative evidence"}, {"topic": "Abusive head trauma", "q": "A 3-month-old presents with coma, seizures, subdural hematomas of different ages, and retinal hemorrhages, without a history of significant trauma. What must be strongly suspected?", "choices": ["A simple benign external hydrocephalus", "Abusive head trauma", "Bacterial meningitis with effusion", "An inherited bleeding disorder alone", "A normal variant requiring no evaluation"], "ans": 1, "exp": "Abusive head trauma (shaken baby syndrome): triad = 'subdural hematoma (มัก different ages) + retinal hemorrhages + encephalopathy' โดยไม่มีประวัติ trauma ที่สมเหตุผล. ต้องประเมินครบ (imaging, ophthalmology, skeletal survey, coagulation เพื่อแยก) + child protection + report. เป็นสาเหตุ death/disability สำคัญจาก abuse. (หัวข้อละเอียดอ่อน)"}, {"topic": "Skeletal age - epiphyseal fusion", "q": "In estimating the age of young-adult skeletal remains, forensic anthropologists rely heavily on which developmental feature?", "choices": ["The color of the bone surface", "The presence of dental fillings", "The pattern and timing of epiphyseal fusion", "The overall weight of the skeleton", "The type of soil where it was buried"], "ans": 2, "exp": "Age estimation ใน young adults: 'epiphyseal (growth plate) fusion' timing (แต่ละกระดูก fuse ที่อายุจำเพาะ — เช่น medial clavicle fuse ช้าสุด ~25-30 ปี) + dental development ในเด็ก. ในผู้สูงอายุใช้ degenerative changes (pubic symphysis, sternal rib, cranial sutures, osteoarthritis). Population-specific"}, {"topic": "Poisoning - strychnine", "q": "A person who ingested strychnine develops severe generalized muscle spasms/convulsions with an arched back (opisthotonos) while remaining conscious. What is the mechanism?", "choices": ["Acetylcholinesterase inhibition causing cholinergic crisis", "Sodium channel blockade slowing conduction", "Opioid receptor agonism depressing respiration", "Glycine antagonism causing unchecked motor neuron excitation", "Cardiac glycoside effect causing arrhythmia"], "ans": 3, "exp": "Strychnine poisoning: antagonize 'glycine' (inhibitory neurotransmitter ที่ spinal cord) → unchecked motor excitation → severe generalized spasms/convulsions, opisthotonos, risus sardonicus 'while conscious' (คล้าย tetanus). รักษา supportive: benzodiazepine/paralysis + ventilation, minimize stimuli. อาจ postmortem caloricity. Forensic: history + toxicology"}, {"topic": "Heavy metal - mercury/lead", "q": "In suspected chronic heavy-metal poisoning as a cause of death, which specimens are especially useful for detecting long-term exposure?", "choices": ["Only a single fresh blood sample", "Exhaled breath at the time of death", "Tear fluid from the eyes", "Superficial skin swabs only", "Hair, nails, and bone"], "ans": 4, "exp": "Chronic heavy-metal (lead, mercury, arsenic) poisoning: สะสมใน 'hair, nails (keratin), และ bone' (lead) → segmental analysis บอก timeline exposure. Blood/urine สะท้อน recent exposure. อาการ: neuropathy, GI, cognitive/behavioral (lead ในเด็ก), Mees lines. Forensic: multiple specimens + occupational/environmental history"}]}, {"id": "for-2", "title": "นิติเวชศาสตร์ ชุดที่ 2 — Death Certification/Ethics/Law", "subject": "forensic", "questions": [{"topic": "Cause of death - structure", "q": "On a death certificate, Part I is written in a causal sequence. Which is the correct concept for the 'underlying cause of death'?", "choices": ["The disease/injury that initiated the chain of events leading to death", "The final mechanism such as cardiac arrest or respiratory failure", "Any unrelated condition present at the time of death", "The mode of dying such as coma", "The immediate terminal event only"], "ans": 0, "exp": "Death certificate Part I: เขียนเป็น causal sequence — immediate cause (บนสุด) ← intermediate ← 'underlying cause' (ล่างสุด = โรค/การบาดเจ็บที่ 'เริ่มต้น' ห่วงโซ่นำไปสู่การตาย). Part II = contributing conditions. 'ห้าม' เขียน mechanism/mode (cardiac arrest, respiratory failure, coma) เป็น underlying cause"}, {"topic": "Cause vs mechanism vs manner", "q": "A patient dies of septic shock from pneumonia complicating a stroke. Which is the underlying cause of death?", "choices": ["Septic shock (the mechanism)", "The stroke (the initiating condition)", "Pneumonia (the intermediate cause)", "Cardiac arrest (the mode of dying)", "Multi-organ failure (a terminal event)"], "ans": 1, "exp": "Underlying cause = โรคที่ 'เริ่มต้น' ห่วงโซ่ = 'stroke' (→ นำสู่ pneumonia → septic shock → death). Immediate = septic shock; intermediate = pneumonia. Mechanism (cardiac arrest/organ failure) ไม่ใช่ underlying cause. Underlying cause สำคัญต่อสถิติสาธารณสุข (coded ตาม ICD)"}, {"topic": "Death certificate - avoid mechanism", "q": "Which of the following should NOT be written as the sole cause of death on a certificate?", "choices": ["'Acute myocardial infarction'", "'Ruptured berry aneurysm'", "'Cardiac arrest' or 'respiratory failure' alone", "'Metastatic lung carcinoma'", "'Bacterial meningitis'"], "ans": 2, "exp": "'Cardiac arrest' / 'respiratory failure' / 'cardiopulmonary failure' เป็น 'mechanism/mode of dying' ไม่ใช่ cause of death — 'ห้ามเขียนเป็นสาเหตุเดี่ยว' (ทุกคนตายด้วย cardiac arrest ในที่สุด). ต้องระบุ 'โรค/สาเหตุที่แท้จริง' (MI, aneurysm, cancer, meningitis). ระบุ causal chain ให้ครบ"}, {"topic": "When to report to police", "q": "Which death must be reported to the police / undergo medicolegal investigation rather than routine certification by the attending physician?", "choices": ["An expected death from documented terminal cancer", "A death after a prolonged illness with a clear diagnosis", "A hospice death with a signed care plan", "Unnatural or unexpected death", "A natural death witnessed by the treating doctor"], "ans": 3, "exp": "Death ที่ต้องแจ้ง/สอบสวน (medicolegal): 'unnatural/unexpected' — accident, suicide, homicide, poisoning, death in custody/police action, operative/anesthetic death, maternal death, unidentified body, suspicious circumstances. → ชันสูตรพลิกศพร่วมพนักงานสอบสวน. Natural expected death (terminal illness) แพทย์ผู้ดูแลออกใบมรณบัตรได้"}, {"topic": "Medical certificate - honesty", "q": "A patient asks a physician to write a sick-leave certificate for days the patient was not actually ill. What is the appropriate response?", "choices": ["Write it to maintain a good doctor-patient relationship", "Write it if the patient pays an extra fee", "Write it but postdate it to avoid detection", "Write it because the patient requested it", "Decline; medical certificates must be truthful and accurate"], "ans": 4, "exp": "Medical certificate ต้อง 'truthful/accurate' ตามข้อเท็จจริงทางการแพทย์ — ปฏิเสธการออกใบรับรองเท็จ (false certificate) เป็นการผิดจริยธรรม/กฎหมาย และอาจถูกลงโทษทางวิชาชีพ. หลักความซื่อสัตย์ (integrity/honesty) ในการออกเอกสารรับรอง"}, {"topic": "Four ethical principles", "q": "Respecting a competent patient's right to refuse a recommended treatment reflects which ethical principle?", "choices": ["Autonomy", "Beneficence", "Non-maleficence", "Justice", "Confidentiality"], "ans": 0, "exp": "หลักจริยธรรม 4 ประการ: 'Autonomy' (เคารพสิทธิผู้ป่วยในการตัดสินใจ รวมการปฏิเสธการรักษาถ้ามี capacity), Beneficence (ทำเพื่อประโยชน์ผู้ป่วย), Non-maleficence (ไม่ทำอันตราย 'primum non nocere'), Justice (ความเป็นธรรม/จัดสรรทรัพยากร). ผู้ป่วย competent มีสิทธิปฏิเสธแม้แพทย์ไม่เห็นด้วย"}, {"topic": "Beneficence vs non-maleficence", "q": "Weighing the benefits of a treatment against its risks/harms to the patient primarily balances which two principles?", "choices": ["Autonomy and justice", "Beneficence and non-maleficence", "Confidentiality and consent", "Veracity and fidelity", "Justice and autonomy"], "ans": 1, "exp": "การชั่งน้ำหนัก 'benefit vs risk/harm' ของการรักษา = balance 'beneficence' (ทำประโยชน์) กับ 'non-maleficence' (ไม่ทำอันตราย). ทุกการรักษ่ามี risk — เลือกเมื่อ benefit > harm และสอดคล้อง autonomy ของผู้ป่วย. Justice = การกระจายทรัพยากร/ความเป็นธรรมในสังคม"}, {"topic": "Informed consent elements", "q": "Valid informed consent for a procedure requires which key elements?", "choices": ["Only the patient's signature on a form", "The physician's decision alone without discussion", "Capacity, adequate disclosure, understanding, and voluntariness", "A family member's approval regardless of the patient", "Payment of the procedure fee in advance"], "ans": 2, "exp": "Valid informed consent: (1) 'capacity/competence' (สามารถเข้าใจ+ตัดสินใจ), (2) 'disclosure' (ข้อมูลเพียงพอ — nature, risks, benefits, alternatives, ผลของการไม่รักษา), (3) 'understanding', (4) 'voluntariness' (ไม่มีการบังคับ). ลายเซ็นเป็นหลักฐานแต่ไม่พอถ้าขาดองค์ประกอบเหล่านี้"}, {"topic": "Decision-making capacity", "q": "Which best describes assessing a patient's capacity to make a specific medical decision?", "choices": ["Whether the patient agrees with the doctor's recommendation", "The patient's age being over a fixed number only", "A psychiatric diagnosis automatically removing capacity", "Ability to understand, retain, weigh information, and communicate a choice", "The family's opinion about the patient's judgment"], "ans": 3, "exp": "Decision-making capacity (task-specific, not global): ผู้ป่วยสามารถ 'understand' ข้อมูล, 'retain', 'weigh/reason' (ชั่งน้ำหนัก), และ 'communicate a choice'. การไม่เห็นด้วยกับแพทย์ 'ไม่ได้' แปลว่าไม่มี capacity. Mental illness ไม่ได้ตัด capacity อัตโนมัติ. ประเมินเฉพาะการตัดสินใจนั้นๆ"}, {"topic": "Confidentiality limits", "q": "In which situation may patient confidentiality be justifiably breached?", "choices": ["Whenever a family member asks about the patient", "To share interesting cases casually with friends", "For the physician's personal curiosity", "Confidentiality can never be breached for any reason", "When required by law or to prevent serious harm to others"], "ans": 4, "exp": "Confidentiality สำคัญแต่ 'ไม่สัมบูรณ์' — อาจเปิดเผยได้เมื่อ: 'required by law' (notifiable disease, court order, gunshot/abuse reporting), 'prevent serious harm to others' (เช่น เตือนผู้ที่จะถูกทำร้าย, infectious disease control), หรือผู้ป่วยยินยอม. เปิดเผยเท่าที่จำเป็น. ไม่เปิดเผยเพื่อความอยากรู้/สังคม"}, {"topic": "Emergency treatment consent", "q": "An unconscious patient with life-threatening bleeding needs immediate surgery, and no family is available. What is the appropriate action?", "choices": ["Proceed under implied/emergency consent to save life", "Wait indefinitely until a relative can be contacted", "Do nothing without a signed consent form", "Discharge the patient to avoid liability", "Obtain a court order before any treatment"], "ans": 0, "exp": "ในภาวะฉุกเฉินที่คุกคามชีวิต + ผู้ป่วยตัดสินใจไม่ได้ (unconscious) + ไม่มีผู้แทนโดยชอบ → รักษาช่วยชีวิตได้ภายใต้ 'implied/emergency consent' (doctrine of necessity, ตาม 'reasonable person' standard, ทำเท่าที่จำเป็นเพื่อ stabilize). ไม่ต้องรอ consent/court order. ถ้ามี advance directive/known refusal ที่ชัดต้องเคารพ"}, {"topic": "Minor consent / confidentiality", "q": "A 16-year-old seeks confidential care for a sensitive health issue. What is generally the appropriate approach?", "choices": ["Always inform the parents of everything without exception", "Provide confidential care within legal limits while encouraging family involvement", "Refuse to treat any minor without a parent present", "Report the minor to authorities routinely", "Never involve the family under any circumstances"], "ans": 1, "exp": "Adolescent care: ให้ 'confidential care' สำหรับ sensitive issues (sexual/reproductive health, mental health, substance use) ช่วยการเข้าถึงบริการ, ภายใน 'legal framework' (mature minor/emancipated, กฎหมายท้องถิ่น) + ส่งเสริมการมีส่วนร่วมของครอบครัว. ข้อยกเว้น: safety concern (abuse, suicidal/homicidal) ต้อง break confidentiality"}, {"topic": "Truth-telling / breaking bad news", "q": "A patient asks directly about their serious diagnosis. The family requests the doctor withhold it. What principle guides disclosure?", "choices": ["Always defer to the family's request to withhold", "Never disclose serious diagnoses to any patient", "The patient's right to know, respecting their wishes", "Disclose only if the patient pays for counseling", "Withhold information to avoid upsetting the patient"], "ans": 2, "exp": "Truth-telling (veracity) + autonomy: ผู้ป่วยที่ competent 'มีสิทธิรู้' ข้อมูลของตนเอง — respect การถามโดยตรง (แจ้งด้วยความเห็นใจ, sensitive, ตามความพร้อม/ความต้องการรับรู้ของผู้ป่วย). 'Therapeutic privilege' (withhold) ใช้ได้จำกัดมาก. Family ไม่มีสิทธิ override ผู้ป่วยที่ competent (แต่คำนึงบริบทวัฒนธรรม/ค่อยๆ สื่อสาร)"}, {"topic": "Confidentiality after death", "q": "After a patient dies, the duty of confidentiality regarding their medical information generally does what?", "choices": ["Ends immediately with no further obligation", "Allows sharing with anyone who asks", "Applies only if the family requests it", "Continues to apply", "Is transferred entirely to the media"], "ans": 3, "exp": "Duty of confidentiality 'ยังคงอยู่' หลังผู้ป่วยเสียชีวิต — เปิดเผยได้เฉพาะเหตุอันชอบ (legal requirement, death certification, benefit claims, ผู้มีสิทธิตามกฎหมาย). ไม่เปิดเผยตามอำเภอใจ/ต่อสาธารณะ/สื่อ. เคารพความเป็นส่วนตัวของผู้เสียชีวิตและครอบครัว"}, {"topic": "Brain death criteria", "q": "Which set of findings is required to diagnose brain death?", "choices": ["A flat ECG for several minutes", "Absent spinal reflexes only", "A single doctor's clinical impression alone", "Deep coma that may still be reversible", "Irreversible coma, absent brainstem reflexes, and apnea"], "ans": 4, "exp": "Brain death (death by neurologic criteria): 'irreversible coma จากสาเหตุที่ทราบ' + 'absent brainstem reflexes' (pupillary, corneal, oculocephalic/vestibular, gag/cough) + 'apnea test positive' — โดยต้องตัด confounders (hypothermia, drugs/intoxication, severe metabolic/electrolyte, neuromuscular blockade). ต้องประเมินตามเกณฑ์/ผู้ประเมินตามที่กำหนด (แพทยสภา). = legal death"}, {"topic": "Organ donation - brain death", "q": "Deceased organ donation for transplantation typically requires which determination and consent?", "choices": ["Confirmed brain death with appropriate consent/authorization", "The recipient's family choosing the donor", "The surgeon deciding without any consent", "Only the hospital administrator's approval", "Donation from any patient regardless of death status"], "ans": 0, "exp": "Deceased organ donation: ต้องมีการยืนยัน 'brain death' (หรือ circulatory/DCD) ตามเกณฑ์ + 'consent/authorization' (ผู้บริจาคแสดงเจตนาไว้ล่วงหน้า หรือครอบครัว/ผู้มีสิทธิ ตามกฎหมาย/ศูนย์รับบริจาคอวัยวะ สภากาชาดไทย). 'Dead donor rule' (บริจาคหลังตายเท่านั้นสำหรับ vital organs). แยกทีมวินิจฉัยตาย ออกจากทีม transplant (conflict of interest)"}, {"topic": "DNR / end-of-life", "q": "A competent patient with terminal illness requests a 'Do Not Resuscitate' order. What is the appropriate approach?", "choices": ["Override the patient because resuscitation is always required", "Respect the patient's informed wishes and document the DNR order", "Require the family to overrule the patient's decision", "Ignore the request and provide full resuscitation", "Only honor it if the physician personally agrees"], "ans": 1, "exp": "DNR/advance care planning: ผู้ป่วยที่ competent มีสิทธิ 'ปฏิเสธ CPR/การรักษาที่ยืดชีวิต' (autonomy) — respect + document + สื่อสารกับทีม/ครอบครัว. Advance directive/living will (พ.ร.บ.สุขภาพแห่งชาติ มาตรา 12 ในไทย รับรองสิทธิปฏิเสธการรักษาในวาระสุดท้าย). ไม่ใช่ euthanasia; เป็นการเคารพเจตนาและ palliative care"}, {"topic": "Negligence elements", "q": "For a claim of medical negligence to succeed, which elements must generally be established?", "choices": ["Only that the patient had a bad outcome", "That the doctor charged a high fee", "Duty, breach of standard of care, causation, and damages", "That the patient was dissatisfied", "That a complication occurred despite proper care"], "ans": 2, "exp": "Medical negligence (4 องค์ประกอบ): 'Duty' (มีหน้าที่ดูแล) + 'breach' (ทำต่ำกว่า standard of care — reasonable physician) + 'causation' (การกระทำเป็นเหตุของความเสียหาย) + 'damages/harm'. Bad outcome/complication เพียงอย่างเดียว 'ไม่ใช่' negligence ถ้าให้การดูแลตามมาตรฐาน. ต้องครบทุกองค์ประกอบ"}, {"topic": "Standard of care", "q": "The 'standard of care' against which a physician's conduct is judged is generally based on what?", "choices": ["The best possible outcome in every case", "The most expensive treatment available", "The patient's personal expectations only", "What a reasonably competent physician would do in similar circumstances", "A guarantee of a perfect result"], "ans": 3, "exp": "Standard of care = สิ่งที่ 'reasonably competent physician' ในสาขา/บริบทเดียวกันจะทำ (ตาม accepted practice/guidelines/evidence). ไม่ใช่การรับประกันผลลัพธ์ที่สมบูรณ์แบบหรือ best outcome เสมอ. การประเมินอิงมาตรฐานวิชาชีพ ณ เวลานั้น (ไม่ใช่ hindsight). Bolam/Bolitho principles"}, {"topic": "Medical council role", "q": "In Thailand, which body regulates the medical profession, issues/revokes licenses, and handles professional ethics complaints?", "choices": ["The Ministry of Commerce", "The local police department", "The hospital's marketing department", "The pharmaceutical industry association", "The Medical Council of Thailand"], "ans": 4, "exp": "แพทยสภา (Medical Council of Thailand) ตาม 'พ.ร.บ.วิชาชีพเวชกรรม พ.ศ.2525': ควบคุมมาตรฐานวิชาชีพ, ออก/เพิกถอนใบอนุญาต, พิจารณาข้อร้องเรียนด้านจริยธรรม/มาตรฐานวิชาชีพ, ออกข้อบังคับ/แนวทาง. บทลงโทษ: ว่ากล่าวตักเตือน, ภาคทัณฑ์, พักใช้/เพิกถอนใบอนุญาต. เป็น regulator ของแพทย์"}, {"topic": "Confidentiality vs mandatory reporting", "q": "A physician treats a gunshot wound. Local law requires reporting such injuries. What should the physician do?", "choices": ["Report as legally required while providing medical care", "Withhold the report to protect confidentiality absolutely", "Report only if the patient consents", "Refuse to treat until police arrive", "Ignore the injury and discharge the patient"], "ans": 0, "exp": "Mandatory reporting (เช่น gunshot/stab wounds, suspected child/elder abuse, notifiable infectious diseases, บางกรณีตามกฎหมาย) เป็น 'legal exception' ต่อ confidentiality — 'report ตามกฎหมาย' + ให้การรักษาต่อเนื่อง. Duty to the law/public safety override confidentiality ในกรณีเหล่านี้ (เปิดเผยเท่าที่จำเป็น)"}, {"topic": "Dying declaration", "q": "A statement made by a person who believes death is imminent, concerning the cause/circumstances of their impending death, may be admissible in court. What is this called?", "choices": ["An informed consent", "A dying declaration", "An advance directive", "A living will", "A hearsay objection"], "ans": 1, "exp": "Dying declaration: คำให้การของผู้ที่เชื่อว่าตนกำลังจะตาย (settled hopeless expectation of death) เกี่ยวกับสาเหตุ/พฤติการณ์การตายของตน — เป็นข้อยกเว้นของ hearsay rule ยอมรับเป็นพยานหลักฐานในศาลได้ (โดยเฉพาะคดี homicide). แพทย์อาจต้องบันทึก verbatim + สภาพจิต. Medicolegal significance"}, {"topic": "Refusal of blood - Jehovah's Witness", "q": "A competent adult Jehovah's Witness refuses a life-saving blood transfusion on religious grounds. What is the appropriate action?", "choices": ["Transfuse anyway because it will save the patient's life", "Transfuse secretly to avoid the patient's objection", "Respect the refusal and provide alternative care", "Refuse to provide any further treatment", "Obtain a court order to force the transfusion"], "ans": 2, "exp": "ผู้ป่วยผู้ใหญ่ที่ 'competent' มีสิทธิ 'ปฏิเสธ' blood transfusion (autonomy) แม้จะช่วยชีวิต — ต้องเคารพ + ให้ทางเลือก (blood-conservation, alternatives) + document. บังคับ/ให้แอบเป็นการละเมิด. (ในเด็ก/ผู้ไร้ความสามารถ อาจต้องขอศาลเพื่อประโยชน์สูงสุดของเด็ก — best interests)"}, {"topic": "Surrogate decision-making", "q": "For a patient who lacks capacity and has no advance directive, medical decisions should be based on what?", "choices": ["Whatever is cheapest for the hospital", "The physician's personal preference alone", "The wishes of whoever arrives first", "The patient's best interests", "Always the most aggressive treatment possible"], "ans": 3, "exp": "ผู้ป่วยที่ 'lacks capacity' + ไม่มี advance directive → ตัดสินใจตาม 'best interests' (พิจารณา benefit/harm, quality of life) + 'substituted judgment' (สิ่งที่ผู้ป่วยน่าจะเลือกจาก known values/prior wishes) โดย surrogate/ผู้แทนโดยชอบตามกฎหมาย/ครอบครัว. ไม่ใช่ตาม cost หรือความชอบของแพทย์"}, {"topic": "Disclosure of medical error", "q": "A physician makes an error that harms a patient. What does professional ethics require?", "choices": ["Concealing the error to avoid a lawsuit", "Blaming the nursing staff for the mistake", "Altering the medical records to hide it", "Ignoring it if the patient is unaware", "Honest disclosure of the error to the patient and appropriate remediation"], "ans": 4, "exp": "จริยธรรมวิชาชีพต้องการ 'honest disclosure' ของ medical error ที่ทำให้เกิด harm ต่อผู้ป่วย (open disclosure) + ขอโทษ/แก้ไข/ป้องกันซ้ำ + document ตามจริง (ห้ามแก้ไขเวชระเบียนเพื่อปกปิด). Honesty/veracity + non-maleficence. การปกปิด/แก้ไขบันทึกเป็นการผิดจริยธรรมและกฎหมาย"}, {"topic": "Conflict of interest - industry", "q": "A pharmaceutical company offers a physician lavish gifts to prescribe its drug. What is the ethical concern?", "choices": ["Conflict of interest that may bias clinical judgment", "There is no concern; gifts are always acceptable", "It improves patient care automatically", "It is only a concern if discovered", "It is required for good medical practice"], "ans": 0, "exp": "การรับ gifts/incentives จากอุตสาหกรรมยาสร้าง 'conflict of interest' — อาจ bias การสั่งจ่ายยา/การตัดสินใจ ขัดกับผลประโยชน์ผู้ป่วย (fiduciary duty). ควรหลีกเลี่ยง/เปิดเผย conflict + ตัดสินใจตาม evidence/ประโยชน์ผู้ป่วย. มีข้อบังคับ/แนวทางจำกัดการรับของกำนัล"}, {"topic": "Duty to warn (third party)", "q": "A psychiatric patient makes a credible, specific threat to seriously harm an identifiable person. What may the physician's duty include?", "choices": ["Absolute confidentiality with no exceptions", "A duty to protect/warn the potential victim", "Ignoring the threat entirely", "Immediately discharging the patient", "Publicizing the threat to the media"], "ans": 1, "exp": "เมื่อผู้ป่วยแสดง 'credible/specific threat' ต่อบุคคลที่ระบุตัวได้ → แพทย์อาจมี 'duty to protect/warn' (Tarasoff principle) — เตือนเหยื่อที่คาดว่าจะถูกทำร้าย/แจ้งเจ้าหน้าที่ (breach confidentiality เท่าที่จำเป็น เพื่อป้องกัน serious harm to others). Balance confidentiality vs public safety"}, {"topic": "Notifiable disease reporting", "q": "A physician diagnoses a case of a notifiable communicable disease (e.g., measles, cholera, TB). What is the obligation?", "choices": ["Keep it confidential and report nothing", "Report only if the patient agrees", "Report to public health authorities as required by law", "Wait until an outbreak is declared", "Report only fatal cases"], "ans": 2, "exp": "โรคติดต่อที่ต้องแจ้ง (notifiable diseases — measles, cholera, TB, dengue, diphtheria, COVID ฯลฯ) → แพทย์/สถานพยาบาลต้อง 'รายงานต่อเจ้าหน้าที่สาธารณสุข' ตาม 'พ.ร.บ.โรคติดต่อ พ.ศ.2558' เพื่อ surveillance + outbreak control (สอบสวนโรค, contact tracing). เป็น legal duty (exception ต่อ confidentiality)"}, {"topic": "Quarantine / isolation authority", "q": "During a communicable disease outbreak, the legal authority to impose isolation/quarantine measures generally rests with whom?", "choices": ["The individual physician's discretion alone", "The patient's family", "The hospital's finance department", "Public health authorities", "The pharmaceutical industry"], "ans": 3, "exp": "อำนาจในการ 'isolation/quarantine' และมาตรการควบคุมโรค (เช่น restrict movement, close venues) ในภาวะระบาด อยู่กับ 'เจ้าพนักงานควบคุมโรคติดต่อ/หน่วยงานสาธารณสุข' ตาม พ.ร.บ.โรคติดต่อ (balance สิทธิส่วนบุคคล vs public health). แพทย์รายงาน/ให้ข้อมูล; มาตรการบังคับเป็นของ authority"}, {"topic": "Involuntary psychiatric admission", "q": "Under mental health law, involuntary admission of a patient is generally justified when the patient has a mental illness and what additional criterion?", "choices": ["Simply disagrees with the treating psychiatrist", "Refuses to pay the hospital bill", "Has any psychiatric diagnosis at all", "The family finds them inconvenient", "Poses a serious risk of harm to self or others"], "ans": 4, "exp": "Involuntary (compulsory) psychiatric admission (ตาม พ.ร.บ.สุขภาพจิต): ต้องมี 'mental disorder' + 'serious risk of harm to self/others' หรือไม่สามารถดูแลตนเองจนเป็นอันตราย + จำเป็นต้องรักษาในสถานพยาบาล. ต้องมีขั้นตอน/ผู้ประเมินตามกฎหมาย + review. การไม่เห็นด้วย/ไม่จ่ายเงิน ไม่ใช่เกณฑ์. Balance autonomy vs safety"}, {"topic": "Abortion law (Thailand)", "q": "Regarding termination of pregnancy in Thailand under current law, which statement is generally correct?", "choices": ["It is permitted under specified legal conditions", "It is absolutely prohibited under all circumstances", "It requires no medical involvement at all", "It is decided solely by the woman's employer", "It is legal only after the third trimester"], "ans": 0, "exp": "กฎหมายไทยเรื่องการยุติการตั้งครรภ์ได้รับการแก้ไข (ประมวลกฎหมายอาญา ม.301-305, ฉบับแก้ไข พ.ศ.2564) — อนุญาตภายใต้เงื่อนไขที่กำหนด (เช่น อายุครรภ์ ≤12 สัปดาห์โดยความยินยอม, หรือมีข้อบ่งชี้ทางการแพทย์/สุขภาพกาย-จิต, การตั้งครรภ์จากความผิดทางเพศ, ความผิดปกติของทารก ตามหลักเกณฑ์) โดยแพทย์ตามข้อบังคับแพทยสภา. *ควรตรวจสอบรายละเอียด/ฉบับล่าสุดของกฎหมายเสมอ"}, {"topic": "Age of consent - medical", "q": "Regarding a minor's ability to consent to their own medical treatment, which concept describes a minor mature enough to understand and decide?", "choices": ["Emancipation by employment only", "Mature minor / Gillick competence", "Automatic capacity at any age", "Parental veto in all situations", "Consent is impossible for anyone under 18"], "ans": 1, "exp": "'Mature minor / Gillick competence': ผู้เยาว์ที่มีวุฒิภาวะพอเข้าใจ nature/consequences ของการรักษา อาจให้ consent ได้เองในบางบริบท (แม้ยังไม่บรรลุนิติภาวะ) — ขึ้นกับกฎหมาย/สถานการณ์ (โดยเฉพาะ sensitive/reproductive health). พิจารณา capacity เฉพาะการตัดสินใจนั้น. กฎหมายไทยมีเกณฑ์ความยินยอมของผู้เยาว์/ผู้แทน"}, {"topic": "Sexual assault - exam consent", "q": "Before performing a forensic medical examination of a sexual assault survivor, what is essential?", "choices": ["Proceeding immediately without any consent", "Consent only from the police", "Informed consent from the survivor, with a supportive, non-judgmental approach", "Examining only if the survivor is calm and composed", "Skipping documentation to protect privacy"], "ans": 2, "exp": "Forensic examination ของ sexual assault survivor: ต้องได้ 'informed consent' จากผู้เสียหาย (autonomy/dignity) + approach ที่ supportive, non-judgmental, private + medical care (STI/HIV prophylaxis, emergency contraception, mental health/psychosocial support) + careful documentation + evidence + chain of custody. (หัวข้อละเอียดอ่อน — ดูแลด้วยความเห็นใจ)"}, {"topic": "Child abuse mandatory report", "q": "A physician suspects child physical abuse based on inconsistent history and injuries. What is the obligation?", "choices": ["Confront the parents and take no other action", "Keep it confidential to preserve the family relationship", "Report only if the abuse is witnessed directly", "Report to child protection authorities and ensure the child's safety", "Discharge the child and hope for the best"], "ans": 3, "exp": "Suspected child abuse (red flags: injury ไม่เข้ากับ history/development, delayed presentation, bruises/fractures หลาย ages) → แพทย์มีหน้าที่ 'report ต่อหน่วยงานคุ้มครองเด็ก' + ดูแลความปลอดภัยของเด็ก + document + medical evaluation (skeletal survey ฯลฯ). Mandatory reporting override confidentiality (พ.ร.บ.คุ้มครองเด็ก). ไม่ต้องพิสูจน์แน่นอนก่อน report — 'reasonable suspicion' พอ"}, {"topic": "Futility / withdrawing treatment", "q": "In a patient where continued aggressive treatment is medically futile, what is an ethically appropriate consideration?", "choices": ["Continuing all aggressive treatment indefinitely regardless of benefit", "Immediately performing euthanasia", "Withdrawing care without any discussion", "Basing decisions solely on cost", "Shifting to comfort/palliative care after discussion with patient/family"], "ans": 4, "exp": "เมื่อการรักษาเชิงรุก 'medically futile' (ไม่ให้ประโยชน์ตามเป้าหมายที่สมเหตุผล) → พิจารณาปรับสู่ 'comfort/palliative care' หลังการสื่อสารกับผู้ป่วย/ครอบครัว (shared decision-making, respect values). Withholding/withdrawing life-sustaining treatment ที่ไม่ให้ประโยชน์ต่างจาก euthanasia (ซึ่งเป็นการทำให้ตายโดยเจตนา — ผิดกฎหมายในไทย)"}, {"topic": "Euthanasia vs palliative care", "q": "Which statement correctly distinguishes palliative care from euthanasia?", "choices": ["Palliative care relieves suffering", "They are identical and both are legal", "Palliative care intentionally hastens death", "Euthanasia is a routine part of hospice care", "Both require the physician to cause death"], "ans": 0, "exp": "Palliative care = บรรเทาความทุกข์ทรมาน/อาการ (pain, symptoms) โดยไม่ได้มีเจตนาเร่งการตาย (แม้ยาบางอย่างอาจมี 'double effect' — เจตนาหลักคือบรรเทาอาการ). 'Euthanasia' (การทำให้ตายโดยเจตนา) และ physician-assisted suicide 'ผิดกฎหมายในไทย'. การปฏิเสธ/ถอนการรักษาที่ยืดชีวิต (patient's right) ต่างจาก euthanasia"}, {"topic": "Confidentiality - HIV partner", "q": "An HIV-positive patient refuses to inform their sexual partner who is at ongoing risk. What may the physician ethically do after counseling fails?", "choices": ["Do nothing, as confidentiality is absolute", "Consider disclosure to the at-risk partner to prevent serious harm", "Publicly announce the patient's status", "Refuse to treat the patient further", "Inform the patient's employer instead"], "ans": 1, "exp": "HIV disclosure: encourage/counsel ผู้ป่วยให้แจ้ง partner + safe practices ก่อน. ถ้าปฏิเสธและ partner ยังมี 'ongoing serious risk' → อาจพิจารณา 'disclosure to at-risk partner' เพื่อป้องกัน serious harm (duty to protect, ตาม guidelines/law, เปิดเผยเท่าที่จำเป็น). Balance confidentiality vs third-party harm. (sensitive — ทำตามแนวทาง/กฎหมาย)"}, {"topic": "Good Samaritan / duty in emergency", "q": "A physician encounters an emergency outside the hospital. Which principle generally applies to providing aid?", "choices": ["Never help outside of a hospital setting", "Only help if guaranteed payment", "Provide reasonable help within one's competence", "Only help patients one already knows", "Avoid helping to prevent any liability"], "ans": 2, "exp": "การช่วยเหลือฉุกเฉินนอกสถานพยาบาล: จริยธรรมวิชาชีพสนับสนุนให้ช่วยเหลือตามความสามารถ/สถานการณ์ (beneficence). 'Good Samaritan' principle คุ้มครองผู้ช่วยเหลือด้วยเจตนาดีในภาวะฉุกเฉิน (ตามกฎหมาย/บริบท). ควรช่วยเท่าที่ทำได้อย่างสมเหตุผล + ส่งต่อระบบการแพทย์ฉุกเฉิน"}, {"topic": "Medical records ownership/access", "q": "Regarding medical records, which statement is generally correct?", "choices": ["Patients can never see their own records", "Records can be discarded immediately after a visit", "Anyone can access a patient's records freely", "The physical record belongs to the provider, but the patient has a right to access their information", "Records have no legal or medicolegal value"], "ans": 3, "exp": "เวชระเบียน: 'physical record' เป็นของสถานพยาบาล/ผู้ให้บริการ แต่ 'ข้อมูล' เป็นของผู้ป่วย — ผู้ป่วยมีสิทธิเข้าถึง/ขอสำเนาข้อมูลของตน (patient rights, PDPA). ต้องเก็บรักษาตามระยะเวลาที่กำหนด, เป็นความลับ, และเป็นหลักฐาน medicolegal สำคัญ (documentation ที่ดี = การป้องกันตนเอง). ห้ามแก้ไขย้อนหลังเพื่อปกปิด"}, {"topic": "Expert witness duty", "q": "When a physician serves as an expert witness in court, to whom is the primary duty owed?", "choices": ["To the side that pays the fee", "To the patient regardless of facts", "To the medical profession's reputation only", "To secure a conviction or acquittal", "To the court — providing objective, unbiased expert opinion"], "ans": 4, "exp": "Expert witness: หน้าที่หลักคือต่อ 'ศาล' — ให้ความเห็นที่ 'objective/unbiased' ตามหลักวิชาการและข้อเท็จจริง (ไม่ใช่ advocate ให้ฝ่ายที่ว่าจ้าง). ต้องอยู่ในขอบเขตความเชี่ยวชาญ, เปิดเผยข้อจำกัด/uncertainty. Integrity สำคัญ (Daubert/relevant standards สำหรับ admissibility ของ expert testimony)"}, {"topic": "Medicolegal case documentation", "q": "For a patient who is a medicolegal case (e.g., assault, road accident), what is important in documentation?", "choices": ["Accurate, contemporaneous, detailed records of injuries and history, preserving evidence", "Minimal documentation to save time", "Documenting opinions about who is at fault", "Altering records to help the patient's legal case", "Discarding clothing and evidence immediately"], "ans": 0, "exp": "Medicolegal case (MLC — assault, RTA, poisoning, sexual assault, burns, custody): documentation ต้อง 'accurate, contemporaneous, detailed' — describe injuries (type, size, location, age), history (verbatim ที่เกี่ยวข้อง), ไม่ตีความ fault/manner (นั่นเป็นของศาล), preserve evidence + chain of custody, notify authorities ตามกฎหมาย. Objective + factual"}, {"topic": "Chain of custody", "q": "In handling forensic evidence (e.g., blood samples, retrieved bullets), why is 'chain of custody' important?", "choices": ["To speed up laboratory testing only", "To document who handled the evidence, ensuring its integrity and admissibility in court", "To reduce the cost of the investigation", "To identify the treating physician", "It has no legal relevance"], "ans": 1, "exp": "Chain of custody: การบันทึกลำดับผู้ครอบครอง/ส่งต่อหลักฐาน (ใคร-เมื่อไหร่-อย่างไร) ตั้งแต่เก็บจนถึงศาล — เพื่อรับประกัน 'integrity' (ไม่ถูกปลอมแปลง/ปนเปื้อน/สับเปลี่ยน) และ 'admissibility' ในศาล. หลักฐาน (samples, bullets, clothing) ต้อง label, seal, sign, document ทุกขั้น. สำคัญมากทาง forensic"}, {"topic": "Fitness to drive/work certificate", "q": "A physician is asked to certify fitness to drive for a patient with poorly controlled epilepsy/seizures. What is appropriate?", "choices": ["Certify fit to please the patient", "Refuse to have any involvement", "Provide an honest assessment considering public safety, per regulations", "Certify based only on the patient's wishes", "Ignore the seizures entirely"], "ans": 2, "exp": "Fitness-to-drive/work certification: แพทย์ต้องประเมิน 'honestly' ตามข้อเท็จจริงทางการแพทย์และ 'ข้อกำหนด/กฎระเบียบ' โดยคำนึงถึง 'public safety' (เช่น uncontrolled epilepsy, severe visual impairment มีข้อจำกัดในการขับขี่). Balance patient's interest vs safety of others. ออกใบรับรองตามจริง (ไม่เอาใจผู้ป่วยจนละเลยความปลอดภัย)"}, {"topic": "Research ethics - consent", "q": "Enrolling a patient in a clinical research study requires what, beyond routine clinical consent?", "choices": ["Only the researcher's decision to enroll", "Consent that cannot be withdrawn once given", "No consent if the study is beneficial", "Voluntary informed consent with ethics committee approval", "The sponsor's approval instead of the patient's"], "ans": 3, "exp": "Research on human subjects (ตาม Declaration of Helsinki): ต้อง 'voluntary informed consent' + 'ethics committee/IRB approval' + สิทธิถอนตัวได้ตลอดเวลาโดยไม่กระทบการรักษา + risk-benefit favorable + protect vulnerable groups. แยกจาก clinical care. Autonomy + protection ของ participant สำคัญสูงสุด"}, {"topic": "Professional boundaries", "q": "A physician develops a romantic/sexual relationship with a current patient. What is the ethical assessment?", "choices": ["It is acceptable if both consent", "It is fine as long as it is kept private", "It improves the therapeutic relationship", "It is only wrong if the patient complains", "It is a serious boundary violation and professional misconduct"], "ans": 4, "exp": "ความสัมพันธ์ทางเพศ/โรแมนติกกับผู้ป่วยปัจจุบันเป็น 'boundary violation' ที่ร้ายแรง — เป็น professional misconduct (power imbalance, exploit trust, กระทบ judgment/care) แม้ 'consent'. ผิดจริยธรรมวิชาชีพ (แพทยสภา) และอาจถูกลงโทษ. ต้องรักษา professional boundaries เสมอ"}, {"topic": "Vicarious liability", "q": "A hospital may be held legally responsible for the negligent act of its employee (e.g., a nurse) committed in the course of employment. What is this doctrine called?", "choices": ["Vicarious liability", "Res ipsa loquitur", "Contributory negligence", "Informed consent", "Double effect"], "ans": 0, "exp": "Vicarious liability (respondeat superior): นายจ้าง/โรงพยาบาลรับผิดต่อการกระทำประมาทของลูกจ้างที่ทำในขอบเขตหน้าที่การงาน. ต่างจาก 'res ipsa loquitur' (สิ่งที่พูดแทนตัวเอง — ความประมาทชัดในตัว เช่น ลืมเครื่องมือในตัวผู้ป่วย) และ 'contributory negligence' (ผู้ป่วยมีส่วนประมาทเอง)"}, {"topic": "Res ipsa loquitur", "q": "A surgical instrument is left inside a patient's abdomen after surgery. Which legal doctrine allows negligence to be inferred without specific proof?", "choices": ["Vicarious liability", "Res ipsa loquitur", "Contributory negligence", "Volenti non fit injuria", "The doctrine of double effect"], "ans": 1, "exp": "Res ipsa loquitur: ในบางกรณีความประมาท 'ชัดเจนในตัวเอง' (เช่น retained surgical instrument, ผ่าตัดผิดข้าง/ผิดคน) → infer negligence ได้โดยไม่ต้องพิสูจน์ breach เฉพาะเจาะจง (เหตุการณ์ปกติไม่เกิดถ้าไม่ประมาท + อยู่ในความควบคุมของแพทย์). ผู้ถูกฟ้องต้องพิสูจน์ว่าไม่ประมาท"}, {"topic": "Contributory negligence", "q": "A patient ignores clear medical advice and stops prescribed medication, worsening their condition. In a lawsuit, this may be relevant as what?", "choices": ["Vicarious liability of the hospital", "Res ipsa loquitur against the doctor", "Contributory negligence by the patient", "Breach of confidentiality", "Lack of informed consent"], "ans": 2, "exp": "Contributory negligence: ผู้ป่วยมีส่วน 'ประมาทเอง' (เช่น ไม่ทำตามคำแนะนำ, หยุดยา, ไม่มาตามนัด) ที่ทำให้เกิด/เพิ่มความเสียหาย → อาจลดความรับผิด/ค่าเสียหายของแพทย์ (ขึ้นกับหลักกฎหมาย). ต่างจาก vicarious liability (นายจ้างรับผิดแทนลูกจ้าง)"}, {"topic": "Data protection (PDPA)", "q": "Under personal data protection law, patient health data is sensitive. What is required for processing/sharing it?", "choices": ["It can be shared freely with anyone", "No protection applies to health data", "Only the hospital's marketing needs to approve", "A lawful basis/consent and appropriate safeguards for the data", "Data can be sold to third parties without limit"], "ans": 3, "exp": "Health data เป็น 'sensitive personal data' → การเก็บ/ใช้/เปิดเผยต้องมี 'lawful basis/consent' + safeguards (security, purpose limitation, data minimization) ตาม พ.ร.บ.คุ้มครองข้อมูลส่วนบุคคล (PDPA). ห้ามเปิดเผย/ขายโดยไม่มีฐานทางกฎหมาย. เชื่อมโยงกับ confidentiality"}, {"topic": "Confidentiality - court order", "q": "A court issues a valid order (subpoena) for a patient's medical records relevant to a legal case. What should the physician do?", "choices": ["Refuse absolutely to protect confidentiality", "Destroy the records to avoid disclosure", "Disclose everything to the media as well", "Ignore the order without consequence", "Comply with the lawful court order, disclosing what is legally required"], "ans": 4, "exp": "เมื่อมี 'valid court order/subpoena' → แพทย์ต้อง comply (legal exception ต่อ confidentiality) โดยเปิดเผย 'เท่าที่กฎหมายกำหนด/เกี่ยวข้อง'. เป็นหน้าที่ตามกฎหมาย. (ต่างจากการเปิดเผยตามอำเภอใจ). ควรเปิดเผยเฉพาะส่วนที่ relevant ไม่เกินความจำเป็น"}, {"topic": "Impaired colleague", "q": "A physician notices a colleague appears impaired by substance use while on duty, endangering patients. What is the ethical obligation?", "choices": ["Take action to protect patients and support the colleague", "Ignore it to protect the colleague's reputation", "Confront the colleague publicly in front of patients", "Do nothing unless a patient is harmed first", "Cover for the colleague to avoid conflict"], "ans": 0, "exp": "Impaired physician (substance/illness ที่กระทบการดูแลผู้ป่วย): มี 'duty to protect patients' — report ตาม protocol/แพทยสภา/หน่วยงาน (patient safety มาก่อน) + สนับสนุนให้ colleague ได้รับการช่วยเหลือ/บำบัด. ไม่ปกปิด (เสี่ยงผู้ป่วย). Balance ความเป็นเพื่อนร่วมงานกับความปลอดภัยผู้ป่วย"}, {"topic": "Chaperone", "q": "When performing an intimate examination (e.g., pelvic, breast, genital), what is good practice?", "choices": ["Never use a chaperone to save time", "Offer/provide a chaperone and obtain consent, explaining the examination", "Proceed without explanation to reduce anxiety", "Only examine if no one else is present", "Skip consent for intimate examinations"], "ans": 1, "exp": "Intimate examination (pelvic, breast, genital, rectal): ควร 'offer/provide chaperone' + explain + obtain consent + maintain dignity/privacy + document. Chaperone ปกป้องทั้งผู้ป่วยและแพทย์ (misunderstanding/allegation). Respect autonomy + professionalism. (sensitive)"}, {"topic": "Pandemic resource allocation", "q": "During a pandemic with limited ventilators, allocating them based on maximizing benefit (e.g., likelihood of survival) primarily invokes which principle?", "choices": ["Autonomy of the sickest patient", "Confidentiality of medical records", "Distributive justice", "Non-maleficence toward one individual only", "The physician's personal preference"], "ans": 2, "exp": "การจัดสรรทรัพยากรจำกัด (ventilators, ICU beds, vaccines) ในภาวะวิกฤต = หลัก 'distributive justice' (จัดสรรอย่างเป็นธรรม, มัก maximize benefit/lives saved, ใช้เกณฑ์ objective/transparent, ไม่เลือกปฏิบัติ). Balance individual autonomy vs population/utilitarian ในภาวะ scarcity. ต้องมี framework/policy ที่ยุติธรรม"}, {"topic": "Conscientious objection", "q": "A physician has a moral objection to performing a legal procedure a patient requests. What is generally required?", "choices": ["Refuse and prevent the patient from getting the procedure", "Perform it against personal conscience always", "Abandon the patient entirely", "Refer the patient to another provider without abandoning or obstructing care", "Report the patient to authorities"], "ans": 3, "exp": "Conscientious objection: แพทย์อาจปฏิเสธการทำหัตถการที่ขัด conscience (ในกรอบที่กฎหมายอนุญาต) 'แต่' ต้องไม่ abandon/obstruct ผู้ป่วย → ต้อง 'refer' ไปยังผู้ให้บริการอื่นที่ทำได้ + ให้ข้อมูล + ไม่ตัดสิน. Balance conscience ของแพทย์กับ autonomy/access ของผู้ป่วย. Emergency ต้องช่วยชีวิตก่อน"}, {"topic": "Advance directive (Thailand)", "q": "Under Thai law (National Health Act section 12), a person may make a written declaration to do what?", "choices": ["Request active euthanasia by the physician", "Force doctors to provide any treatment they want", "Transfer their medical decisions to a stranger", "Waive all rights to medical care", "Refuse life-sustaining treatment intended only to prolong dying in the terminal stage"], "ans": 4, "exp": "พ.ร.บ.สุขภาพแห่งชาติ พ.ศ.2550 มาตรา 12: รับรองสิทธิทำ 'living will/advance directive' — แสดงเจตนา 'ปฏิเสธการรักษาที่เพียงยืดการตายในวาระสุดท้าย' (ไม่ให้ทรมาน). เป็นการเคารพ autonomy + palliative care. 'ไม่ใช่' euthanasia (การทำให้ตายโดยเจตนา ยังผิดกฎหมาย). แพทย์ต้องเคารพเจตนาที่ทำไว้"}, {"topic": "Withholding vs withdrawing", "q": "Ethically and legally, withholding a life-sustaining treatment (not starting it) versus withdrawing it (stopping it) are generally regarded how?", "choices": ["As ethically equivalent when justified by the patient's wishes/best interests", "Withdrawing is always illegal, withholding is always legal", "Both are equivalent to euthanasia", "Withholding requires a court order but withdrawing does not", "Neither is ever permissible"], "ans": 0, "exp": "Withholding (ไม่เริ่ม) และ withdrawing (หยุด) life-sustaining treatment ถือว่า 'ethically equivalent' เมื่อมีเหตุผลรองรับ (patient's wishes/best interests, futility) — ทั้งคู่ต่างจาก euthanasia (เจตนาทำให้ตาย). เป็นการยอมให้ underlying disease ดำเนินไปตามธรรมชาติ + palliative care. Decision ควร shared + documented"}, {"topic": "Circulatory determination of death", "q": "Besides brain death, death may be determined by circulatory criteria. What does this require?", "choices": ["A single low blood pressure reading", "Irreversible cessation of circulatory and respiratory function", "Absence of movement for one minute", "The family's agreement that death occurred", "A flat EEG only"], "ans": 1, "exp": "Determination of death: (1) 'circulatory/cardiopulmonary criteria' = irreversible cessation ของ circulation + respiration (ยืนยันด้วย absent pulse/heart sounds/respiration, asystole, ช่วง observation), หรือ (2) 'neurologic criteria' (brain death). ทั้งคู่ = legal death. Circulatory death เป็นพื้นฐานของ donation after circulatory death (DCD)"}, {"topic": "Cremation / burial certificate", "q": "Before a body can be cremated or buried, what document is generally required?", "choices": ["A verbal statement from any bystander", "The deceased's own written permission", "A properly completed death certificate", "A hospital marketing form", "No documentation is needed"], "ans": 2, "exp": "ก่อนฌาปนกิจ/ฝังศพ ต้องมี 'death certificate (ใบมรณบัตร)' ที่สมบูรณ์ (ระบุ cause of death, certified โดยแพทย์/ผู้มีอำนาจ) + จดทะเบียนการตาย. ในกรณี unnatural/medicolegal death ต้องผ่านการชันสูตร/อนุญาตก่อน. เอกสารนี้จำเป็นทางกฎหมาย/สถิติ/การจัดการศพ"}, {"topic": "Autopsy consent (clinical)", "q": "For a clinical (non-medicolegal) autopsy to investigate the cause of a natural death, what is required?", "choices": ["No consent is ever needed for any autopsy", "Only the pathologist's decision", "The insurance company's approval", "Consent from the next of kin / legally authorized person", "A court order in every case"], "ans": 3, "exp": "Clinical (hospital) autopsy สำหรับ natural death (เพื่อหา cause/education/quality) ต้อง 'consent จาก next of kin/ผู้มีสิทธิตามกฎหมาย'. ต่างจาก 'medicolegal (forensic) autopsy' (unnatural/suspicious death) ที่ทำโดยคำสั่งกฎหมาย 'ไม่ต้อง' ขอ consent ครอบครัว. เคารพความประสงค์/ศาสนาของครอบครัว"}, {"topic": "Photography / teaching consent", "q": "Using a patient's clinical photographs for teaching or publication requires what?", "choices": ["No consent since it is educational", "Only the department head's approval", "Consent from another patient", "Publishing first and asking later", "Specific informed consent from the patient"], "ans": 4, "exp": "การใช้ภาพถ่าย/ข้อมูลผู้ป่วยเพื่อการเรียนการสอน/publication ต้องมี 'specific informed consent' จากผู้ป่วย + anonymization/ปกปิดตัวตนเท่าที่ทำได้ + ใช้ตามวัตถุประสงค์ที่ยินยอม. เคารพ privacy/autonomy. การเผยแพร่โดยไม่ยินยอม = ละเมิด confidentiality/PDPA"}, {"topic": "Social media / privacy", "q": "A physician wants to post an interesting patient case on social media. What is the ethical requirement?", "choices": ["Do not post identifiable patient information without consent", "Posting is fine if the patient is not tagged", "Any case can be shared for education freely", "Only avoid posting if a colleague objects", "Patient privacy does not apply online"], "ans": 0, "exp": "Social media: 'ห้าม' โพสต์ข้อมูล/ภาพที่ระบุตัวผู้ป่วยได้โดยไม่ได้รับ consent — รักษา confidentiality/professionalism ออนไลน์เช่นเดียวกับในคลินิก (แม้ 'ลบชื่อ' ก็อาจ identifiable จากรายละเอียด). ระวัง defamation, boundaries. Digital professionalism สำคัญ"}, {"topic": "Gifts from patients", "q": "A grateful patient offers a physician a very expensive personal gift. What is the appropriate consideration?", "choices": ["Always accept any gift regardless of value", "Politely decline large gifts that could create obligation or bias", "Demand gifts as part of the service", "Accept only cash gifts", "Accept gifts in exchange for better care"], "ans": 1, "exp": "Gifts จากผู้ป่วย: 'small tokens of gratitude' มักรับได้; แต่ 'large/expensive gifts' ควรปฏิเสธอย่างสุภาพ (อาจสร้าง sense of obligation, bias, boundary issue, inequity ในการดูแล). ไม่รับ gift แลกกับการดูแลที่ดีกว่า (fairness/justice). ใช้ดุลยพินิจตามบริบท/ข้อบังคับ"}, {"topic": "Vulnerable populations", "q": "When obtaining consent from a vulnerable person (e.g., prisoner, cognitively impaired, subordinate), what extra care is needed?", "choices": ["Skip consent because they are vulnerable", "Obtain consent from the institution only", "Ensure the consent is truly voluntary and free from coercion", "Assume they cannot consent at all", "Proceed faster to reduce their burden"], "ans": 2, "exp": "Vulnerable populations (prisoners, cognitively impaired, children, subordinates, economically disadvantaged): ต้องระวังเป็นพิเศษว่า consent 'voluntary จริง ปราศจาก coercion/undue influence' + protect จาก exploitation (โดยเฉพาะใน research). ประเมิน capacity อย่างเหมาะสม + ใช้ surrogate/safeguards เมื่อจำเป็น. Justice + protection"}, {"topic": "Refusal by parents (child)", "q": "Parents refuse a clearly life-saving treatment (e.g., blood transfusion) for their young child on religious grounds. What may be appropriate?", "choices": ["Automatically follow the parents' refusal", "Discharge the child without treatment", "Transfuse secretly without any process", "Seek legal/court authorization to act in the child's best interests", "Refuse to be involved in the case"], "ans": 3, "exp": "เมื่อพ่อแม่ปฏิเสธการรักษาที่ 'life-saving' สำหรับเด็ก (ผู้ไร้ความสามารถตัดสินใจเอง) → parental autonomy 'ไม่ absolute' — แพทย์อาจต้องขอ 'court authorization/child protection' เพื่อรักษาตาม 'best interests ของเด็ก'. ในภาวะฉุกเฉินคุกคามชีวิต อาจรักษาช่วยชีวิตได้ตาม necessity. Child's welfare มาก่อน (ต่างจากผู้ใหญ่ที่ปฏิเสธเองได้)"}, {"topic": "Telemedicine", "q": "In providing telemedicine, which principle still applies?", "choices": ["Confidentiality does not apply online", "Consent is unnecessary in telemedicine", "Documentation can be skipped", "Standard of care is lower for telemedicine", "Standard of care, consent, confidentiality, and appropriate documentation still apply"], "ans": 4, "exp": "Telemedicine: หลักการทางการแพทย์/จริยธรรมยังคงใช้ — standard of care (เหมาะสมกับ modality, รู้ข้อจำกัด, refer ถ้าจำเป็น), informed consent (รวมข้อจำกัดของ telemedicine), confidentiality/data security, documentation, licensing/ระเบียบ. ไม่ใช่มาตรฐานที่ต่ำกว่า. ตามข้อบังคับแพทยสภาเรื่อง telemedicine"}, {"topic": "Criminal responsibility - insanity", "q": "In forensic psychiatry, an accused who, due to a mental disorder, did not know the nature or wrongfulness of the act may raise which defense?", "choices": ["Insanity defense", "Contributory negligence", "Res ipsa loquitur", "Dying declaration", "Vicarious liability"], "ans": 0, "exp": "Insanity defense (McNaughton rules): จำเลยที่เนื่องจาก 'mental disorder' ไม่รู้ 'nature/quality' ของการกระทำ หรือไม่รู้ว่าเป็น 'wrong' อาจไม่ต้องรับผิดทางอาญาเต็มที่ (ตามกฎหมาย — ประเทศไทยมีบทบัญญัติเรื่องผู้กระทำผิดที่มีจิตบกพร่อง/วิกลจริต ป.อาญา ม.65). Forensic psychiatrist ประเมิน mental state ณ เวลากระทำ + fitness to stand trial"}, {"topic": "Blood alcohol - legal", "q": "A driver involved in a crash is examined for suspected intoxication. Regarding blood alcohol testing, what is important medicolegally?", "choices": ["Any staff can draw and label the sample informally", "Proper consent/legal authority, correct technique, and chain of custody of the sample", "Results need no documentation", "Alcohol swab should be used to clean the site", "The sample can be stored without preservative indefinitely"], "ans": 1, "exp": "Blood alcohol (medicolegal — drunk driving): ต้องมี legal authority/consent ตามกฎหมาย, 'ไม่ใช้ alcohol swab' ทำความสะอาด (ใช้ non-alcoholic เช่น povidone — กัน contamination), เก็บใน tube ที่มี preservative/anticoagulant (sodium fluoride ป้องกัน fermentation), label + 'chain of custody', documentation. ค่าตามกฎหมายไทย (เช่น ≥50 mg% ทั่วไป). Interpretation ตามกฎหมาย"}, {"topic": "Examination of assault victim", "q": "When documenting injuries of an assault victim for medicolegal purposes, the physician should do what?", "choices": ["State conclusively who caused the injuries", "Only note the most severe injury", "Objectively describe each injury without assigning blame", "Give an opinion on the legal verdict", "Estimate the exact time to the minute always"], "ans": 2, "exp": "การตรวจ/บันทึกผู้ถูกทำร้าย (medicolegal): 'objective description' ของแต่ละบาดแผล — type (abrasion/contusion/laceration/incised), size, site, characteristics, approximate age — พร้อม diagram/photo (ด้วย consent), history verbatim ที่เกี่ยวข้อง. 'ไม่' ระบุว่าใครทำ/fault/verdict (เป็นของศาล). ประเมินความรุนแรง (simple/grievous) ตามข้อเท็จจริง"}, {"topic": "Virginity / 'two-finger' test", "q": "A court or family requests a 'virginity test' (e.g., two-finger test) on a woman. What is the correct stance?", "choices": ["It accurately proves whether intercourse occurred", "It should be done whenever requested", "It is a reliable forensic examination", "It is unscientific and unethical and should not be performed", "It is required in all sexual assault cases"], "ans": 3, "exp": "'Virginity testing' / 'two-finger test' เป็นการตรวจที่ 'unscientific' (hymen ไม่ได้บ่งชี้ virginity/intercourse อย่างน่าเชื่อถือ) และ 'unethical' (ละเมิดศักดิ์ศรี/สิทธิ) — WHO และองค์กรสากลแนะนำให้ 'ยกเลิก'. ไม่ควรทำ. Forensic exam ของ sexual assault มุ่ง documenting injuries/evidence ด้วย consent อย่างเคารพ"}, {"topic": "Age of consent / statutory rape", "q": "Regarding sexual offences, why is the concept of 'age of consent' important medicolegally?", "choices": ["It determines the age to obtain a driver's license", "It sets the age for voting", "It has no medicolegal relevance", "It only applies to marriage", "Sexual activity with a person below the legal age may be an offence regardless of apparent consent"], "ans": 4, "exp": "'Age of consent': กฎหมายกำหนดอายุขั้นต่ำที่บุคคลให้ความยินยอมทางเพศได้ — การมีเพศสัมพันธ์กับผู้ที่อายุต่ำกว่าเกณฑ์อาจเป็น 'ความผิด (statutory)' 'แม้จะดูเหมือนยินยอม' (เด็กถือว่าให้ consent ไม่ได้ตามกฎหมาย). แพทย์ที่ตรวจต้องตระหนักถึง mandatory reporting/child protection. (กฎหมายไทยมีบทบัญญัติเฉพาะ)"}, {"topic": "Paternity testing", "q": "In a disputed paternity case, which test provides the most definitive evidence?", "choices": ["DNA analysis", "ABO blood group comparison alone", "Physical resemblance assessment", "The mother's statement only", "Fingerprint pattern comparison"], "ans": 0, "exp": "Disputed paternity: 'DNA analysis' (STR markers) ให้หลักฐานที่ definitive ที่สุด (exclude ได้แน่นอน, include ด้วย probability สูงมาก). ABO/blood group เดิมใช้ 'exclude' ได้บางกรณีแต่ไม่ยืนยัน. DNA เป็นมาตรฐานปัจจุบัน (ต้อง consent + chain of custody สำหรับ legal use)"}, {"topic": "Torture documentation", "q": "In documenting alleged torture or ill-treatment, physicians should follow which internationally recognized standard?", "choices": ["The Parkland formula", "The Istanbul Protocol", "The Glasgow Coma Scale", "The Bethesda system", "The Ranson criteria"], "ans": 1, "exp": "Istanbul Protocol: มาตรฐานสากลสำหรับ 'การตรวจและบันทึกหลักฐาน torture/ill-treatment' อย่างมีประสิทธิภาพ — objective documentation ของ physical/psychological findings, consistency กับที่กล่าวอ้าง, ด้วยหลัก human rights/ethics. เป็น medicolegal/human rights standard. (หัวข้อละเอียดอ่อน)"}, {"topic": "Duty to treat in emergency", "q": "A patient arrives at the emergency department in a life-threatening condition but cannot pay. What is the physician's/hospital's duty?", "choices": ["Refuse care until payment is secured", "Transfer the unstable patient immediately to save costs", "Provide necessary emergency stabilizing care regardless of ability to pay", "Provide care only to insured patients", "Discharge the patient to another facility first"], "ans": 2, "exp": "Emergency care: มี 'duty to provide necessary stabilizing treatment' ในภาวะฉุกเฉินคุกคามชีวิต 'ไม่ว่าจะจ่ายได้หรือไม่' (beneficence/non-maleficence + กฎหมาย/สิทธิผู้ป่วยฉุกเฉิน 'UCEP' ในไทย — เจ็บป่วยฉุกเฉินวิกฤตรักษาทุกที่). การปฏิเสธ/transfer ผู้ป่วย unstable เพราะเงินเป็นการผิดจริยธรรม/กฎหมาย. Abandonment ต้องหลีกเลี่ยง"}, {"topic": "Occupational disease", "q": "A worker is diagnosed with an occupational disease (e.g., silicosis, lead poisoning). What is an appropriate action?", "choices": ["Keep it confidential from everyone", "Ignore the occupational link", "Blame the worker for the condition", "Report/notify as required and address workplace exposure", "Advise the worker to quit without any report"], "ans": 3, "exp": "Occupational disease (silicosis, lead/heavy metal poisoning, occupational asthma, noise-induced hearing loss): แพทย์ควร 'report/notify' ตามกฎหมาย (occupational disease surveillance) + จัดการ workplace exposure (ป้องกันคนงานอื่น) + compensation (กองทุนเงินทดแทน) + fitness for work. Prevention ที่แหล่งกำเนิด. เชื่อมโยง public/occupational health"}, {"topic": "Screening - sensitivity", "q": "A screening test's ability to correctly identify those WITH the disease (true positive rate) is called what?", "choices": ["Specificity", "Positive predictive value", "Negative predictive value", "Prevalence", "Sensitivity"], "ans": 4, "exp": "Sensitivity = TP/(TP+FN) = ความสามารถตรวจพบ 'ผู้ที่เป็นโรคจริง' (true positive rate); test ที่ sensitive สูง ใช้ 'rule out' (SnNout — negative ช่วยตัดโรค). Specificity = TN/(TN+FP) = ตรวจ 'ผู้ไม่เป็นโรค' ถูก; specific สูงใช้ 'rule in' (SpPin). Screening ต้องการ sensitivity สูง"}, {"topic": "Predictive value & prevalence", "q": "How does disease prevalence affect the positive predictive value (PPV) of a test?", "choices": ["Lower prevalence lowers the PPV", "Prevalence has no effect on PPV", "Higher prevalence lowers the PPV", "PPV equals sensitivity regardless of prevalence", "Prevalence only affects specificity"], "ans": 0, "exp": "PPV = TP/(TP+FP) 'ขึ้นกับ prevalence': ในประชากรที่ prevalence 'ต่ำ' → PPV 'ต่ำ' (false positives มากเทียบ true positives — แม้ test ดี). NPV สูงขึ้นเมื่อ prevalence ต่ำ. Sensitivity/specificity เป็น 'คุณสมบัติของ test' (ไม่ขึ้น prevalence). สำคัญในการแปลผล screening ในประชากรทั่วไป"}, {"topic": "Study design hierarchy", "q": "Which study design provides the strongest evidence for a causal effect of a treatment?", "choices": ["Case report", "Randomized controlled trial", "Cross-sectional survey", "Case-control study", "Expert opinion"], "ans": 1, "exp": "ลำดับความแข็งแรงของหลักฐาน (สำหรับ therapy/causation): 'RCT' (randomization ลด confounding) > cohort > case-control > cross-sectional > case series/report > expert opinion. Systematic review/meta-analysis ของ RCTs อยู่บนสุด. RCT ควบคุม bias/confounding ได้ดีที่สุดสำหรับ intervention"}, {"topic": "Case-control study", "q": "To study risk factors for a rare disease efficiently by comparing those with and without the disease looking backward at exposures, which design is best?", "choices": ["Randomized controlled trial", "Prospective cohort study", "Case-control study", "Cross-sectional study", "Ecological study"], "ans": 2, "exp": "Case-control study: เปรียบเทียบ 'cases (มีโรค)' กับ 'controls (ไม่มีโรค)' โดยมองย้อนหลังถึง 'exposure' — เหมาะกับ 'rare disease' และ long latency, ประหยัด/เร็ว. วัด 'odds ratio'. ข้อจำกัด: recall/selection bias, ไม่คำนวณ incidence โดยตรง. Cohort เหมาะ rare exposure/วัด incidence/RR"}, {"topic": "Relative risk vs odds ratio", "q": "In a prospective cohort study, which measure of association is directly calculated?", "choices": ["Odds ratio only", "Prevalence ratio only", "Number needed to harm only", "Relative risk", "Attributable fraction only"], "ans": 3, "exp": "Cohort study (follow forward จาก exposure → outcome) คำนวณ 'incidence' ได้ → วัด 'relative risk (risk ratio)' โดยตรง. Case-control (backward) วัด 'odds ratio' (approximate RR เมื่อโรค rare). RR/OR บอกความสัมพันธ์ระหว่าง exposure กับ outcome (>1 เพิ่มเสี่ยง, <1 protective)"}, {"topic": "Confounding", "q": "A study finds coffee drinking associated with lung cancer, but coffee drinkers also smoke more. Smoking is acting as what?", "choices": ["The direct cause being studied", "A random measurement error", "The outcome variable", "An effect modifier only, never a confounder", "A confounder"], "ans": 4, "exp": "Confounder = ปัจจัยที่สัมพันธ์กับทั้ง 'exposure' (coffee) และ 'outcome' (lung cancer) และไม่ใช่ intermediate ในเส้นทาง — ทำให้เกิด spurious association (smoking เป็นตัวจริง). จัดการด้วย randomization, restriction, matching, stratification, multivariable adjustment. ต่างจาก 'effect modification' (ผลต่างกันตาม subgroup)"}, {"topic": "Number needed to treat", "q": "A treatment reduces the absolute risk of an event from 20% to 10%. What is the number needed to treat (NNT)?", "choices": ["10", "2", "5", "20", "100"], "ans": 0, "exp": "Absolute risk reduction (ARR) = 20% − 10% = 10% = 0.10. NNT = 1/ARR = 1/0.10 = '10' (ต้องรักษา 10 คนเพื่อป้องกัน 1 event). NNT ต่ำ = treatment มีประสิทธิภาพ/คุ้มค่ามาก. ต่างจาก relative risk reduction (RRR = 50% ในตัวอย่างนี้) ที่อาจดูใหญ่แต่ absolute effect ขึ้นกับ baseline risk"}, {"topic": "Incidence vs prevalence", "q": "The number of NEW cases of a disease occurring in a population over a time period is called what?", "choices": ["Prevalence", "Incidence", "Attack rate over lifetime", "Case fatality rate", "Mortality rate"], "ans": 1, "exp": "Incidence = จำนวน 'ผู้ป่วยรายใหม่' ต่อประชากรเสี่ยงในช่วงเวลาหนึ่ง (วัด risk/rate ของการเกิดโรค). Prevalence = จำนวน 'ผู้ป่วยทั้งหมด (เก่า+ใหม่)' ณ จุดเวลา (วัด burden). Prevalence ≈ incidence × duration. Incidence เหมาะศึกษา etiology/risk; prevalence เหมาะวางแผนทรัพยากร"}, {"topic": "Screening criteria", "q": "According to Wilson-Jungner criteria, a condition suitable for screening should have which feature?", "choices": ["No available treatment for the condition", "A test that is very expensive and invasive", "An important health problem with a detectable early stage and effective treatment", "A disease with no recognizable latent phase", "A condition that is extremely rare and untreatable"], "ans": 2, "exp": "Wilson-Jungner screening criteria: โรคเป็น 'important health problem', มี 'recognizable latent/early stage', มี 'accepted effective treatment' (early treatment ดีกว่า), มี suitable test (accurate, acceptable, ไม่แพงเกิน), natural history เข้าใจ, cost-effective, continuous process. ตัวอย่าง: cervical cancer, PKU, hypothyroid newborn screening"}, {"topic": "Lead-time bias", "q": "A screening test appears to improve survival simply because the disease is detected earlier without actually delaying death. What bias is this?", "choices": ["Recall bias", "Selection bias", "Confounding", "Lead-time bias", "Publication bias"], "ans": 3, "exp": "Lead-time bias: screening 'ตรวจพบโรคเร็วขึ้น' → survival time (นับจากวินิจฉัย) 'ดูยาวขึ้น' 'แม้ไม่ได้เลื่อนการตายจริง' (แค่วินิจฉัยเร็วขึ้น). ทำให้ overestimate ประโยชน์ของ screening. Length-time bias = screening จับ slow-progressing (indolent) disease มากกว่า. ต้องประเมินด้วย mortality ใน RCT"}, {"topic": "Outbreak investigation", "q": "In investigating a foodborne outbreak, calculating the attack rate among those who ate vs did not eat a specific food helps do what?", "choices": ["Determine the exact pathogen without any testing", "Establish the treatment protocol", "Prove causation with absolute certainty", "Replace the need for laboratory confirmation", "Identify the likely source/vehicle of the outbreak"], "ans": 4, "exp": "Outbreak investigation: คำนวณ 'attack rate' (ผู้ป่วย/ผู้สัมผัส) ในกลุ่มที่กิน vs ไม่กินอาหารแต่ละอย่าง → เปรียบเทียบ (relative risk) เพื่อ 'identify vehicle/source'. ขั้นตอน: ยืนยัน outbreak, case definition, descriptive epidemiology (time-place-person, epidemic curve), hypothesis, analytic study, control measures. ± lab confirmation"}, {"topic": "Epidemic curve", "q": "A histogram of the number of cases by time of onset during an outbreak (epidemic curve) can suggest what?", "choices": ["The pattern of spread and possible incubation period", "The exact identity of the index case", "The treatment cost of the outbreak", "The genetic sequence of the pathogen", "The individual immunity of each case"], "ans": 0, "exp": "Epidemic curve (cases by onset time): shape บอก 'pattern of transmission' — 'point-source' (single peak, tight — สัมผัสร่วมครั้งเดียว เช่น งานเลี้ยง), 'continuous common source' (plateau), 'propagated/person-to-person' (successive peaks ห่างกันตาม incubation period). ช่วยประเมิน source, incubation, และ intervention"}, {"topic": "Herd immunity", "q": "Why does high vaccination coverage protect even unvaccinated individuals in a community?", "choices": ["Vaccines transfer directly between people", "Herd immunity reduces transmission, indirectly protecting the susceptible", "Unvaccinated people cannot get the disease anyway", "It only protects the vaccinated individuals", "It eliminates the pathogen from the environment instantly"], "ans": 1, "exp": "Herd (community) immunity: เมื่อสัดส่วนคนมีภูมิ (จาก vaccination) สูงพอ (เกิน herd immunity threshold ที่ขึ้นกับ R0) → การแพร่เชื้อลดลง → 'ปกป้องผู้ที่ไม่มีภูมิทางอ้อม' (ทารก, immunocompromised, ผู้ที่ vaccine ไม่ได้ผล). สนับสนุนการฉีดวัคซีนในวงกว้าง. โรคที่ติดง่าย (measles) ต้อง coverage สูงมาก (~95%)"}, {"topic": "Prevention levels", "q": "Giving a vaccine to prevent a disease from ever occurring is which level of prevention?", "choices": ["Secondary prevention", "Tertiary prevention", "Primary prevention", "Quaternary prevention", "Rehabilitation"], "ans": 2, "exp": "Levels of prevention: 'Primary' = ป้องกันไม่ให้เกิดโรค (vaccination, health promotion, ลด risk factor). 'Secondary' = early detection/treatment (screening — Pap smear, mammogram). 'Tertiary' = ลด complication/disability ในผู้ป่วย (rehabilitation, จัดการโรคเรื้อรัง). Vaccine = primary prevention"}, {"topic": "Sensitivity vs specificity trade-off", "q": "For a screening test to be used in a healthy population, high sensitivity is usually prioritized. Why?", "choices": ["To minimize the number of tests performed", "Because specificity does not matter for screening", "To ensure everyone tests positive", "To minimize false negatives, with confirmatory testing for positives", "Because it makes the test cheaper"], "ans": 3, "exp": "Screening ในประชากรสุขภาพดี มักต้องการ 'sensitivity สูง' (จับ true cases ให้ครบ, 'ลด false negatives' — ไม่พลาดคนป่วย) แล้วยืนยัน positive ด้วย 'confirmatory test ที่ specific สูง' (ลด false positives/harm จาก overdiagnosis). Trade-off sensitivity ↔ specificity ตาม cut-off. เลือกตามวัตถุประสงค์"}, {"topic": "Bias - selection", "q": "In a study, if the way participants are chosen makes the sample unrepresentative of the target population, what type of error is introduced?", "choices": ["Confounding", "Random error only", "Lead-time bias", "Effect modification", "Selection bias"], "ans": 4, "exp": "Selection bias: การเลือก participants (หรือ loss to follow-up) ที่ทำให้ sample 'ไม่ representative' ของ target population → distort ผล (เช่น Berkson bias, healthy worker effect, non-response). ต่างจาก 'confounding' (ตัวแปรที่สัมพันธ์ทั้ง exposure/outcome) และ 'information/measurement bias' (recall, misclassification). จัดการด้วย proper sampling/design"}, {"topic": "Mortality vs case fatality", "q": "The proportion of people diagnosed with a disease who die from it (over a period) is called what?", "choices": ["Case fatality rate", "Crude mortality rate", "Incidence rate", "Prevalence", "Attack rate"], "ans": 0, "exp": "Case fatality rate (CFR) = ผู้เสียชีวิตจากโรค / ผู้ป่วยที่เป็นโรคนั้น (วัดความรุนแรงของโรค). ต่างจาก 'mortality rate' (ผู้เสียชีวิต / ประชากรทั้งหมด — วัด burden ในประชากร). CFR สูง = โรครุนแรง (เช่น rabies ~100%, Ebola สูง)"}, {"topic": "Randomization purpose", "q": "In a clinical trial, the main purpose of randomly allocating participants to treatment groups is to do what?", "choices": ["Guarantee a positive result for the drug", "Balance known and unknown confounders between groups", "Reduce the sample size needed to one", "Eliminate the need for a control group", "Ensure everyone receives the active treatment"], "ans": 1, "exp": "Randomization (RCT): แจกผู้ป่วยเข้ากลุ่มโดยสุ่ม → 'balance confounders ทั้งที่รู้และไม่รู้' ระหว่างกลุ่ม (ลด confounding, selection bias) → ผลต่างจึงน่าจะมาจาก intervention. เสริมด้วย 'blinding' (ลด performance/detection bias) และ 'allocation concealment'. เป็นจุดแข็งของ RCT ต่อ causation"}, {"topic": "Blinding", "q": "In a trial, keeping the participants and assessors unaware of the treatment assignment ('double-blind') primarily reduces what?", "choices": ["Selection bias at enrollment", "Confounding by indication", "Performance and detection bias", "Lead-time bias in screening", "Random sampling error"], "ans": 2, "exp": "Blinding (masking): 'double-blind' (participants + assessors/outcome evaluators ไม่รู้ allocation) → ลด 'performance bias' (พฤติกรรม/co-intervention ต่างกัน) และ 'detection/observer bias' (การวัด outcome ลำเอียง), รวมถึง placebo effect. Randomization ลด selection/confounding; blinding ลด bias หลัง randomization"}, {"topic": "Sentinel event / patient safety", "q": "A 'sentinel event' in patient safety (e.g., wrong-site surgery, retained instrument) should prompt what response?", "choices": ["Blaming and punishing the individual only", "Concealing the event from any review", "Ignoring it if no lawsuit results", "Root cause analysis and system improvement to prevent recurrence", "Discharging the involved staff immediately"], "ans": 3, "exp": "Sentinel event (unexpected serious harm — wrong-site/patient surgery, retained instrument, medication death): ควรทำ 'root cause analysis' + 'system improvement' (patient safety culture — 'just culture' ไม่ใช่ blame individual เป็นหลัก, มองระบบ). Disclosure ต่อผู้ป่วย + report/learn. Prevention เชิงระบบ (checklists, protocols) ลดความผิดพลาด"}, {"topic": "Notification timeframe", "q": "For a dangerous communicable disease requiring urgent control (e.g., cholera, in some systems), notification to authorities should be done when?", "choices": ["Only at the end of the month with routine statistics", "Only after the patient recovers", "Only if more than ten cases occur", "Notification is optional for dangerous diseases", "Immediately/urgently as specified by the communicable disease regulations"], "ans": 4, "exp": "โรคติดต่ออันตราย/ที่ต้องเฝ้าระวังบางชนิด (ตาม พ.ร.บ.โรคติดต่อ — เช่น cholera, plague, dangerous emerging diseases) ต้อง 'แจ้งโดยด่วน' ตามกรอบเวลาที่กำหนด (บางโรคภายในชั่วโมง/วัน) เพื่อการควบคุมทันท่วงที (สอบสวน, isolation, contact tracing). โรคเฝ้าระวังทั่วไปรายงานตามระบบปกติ. Timeliness สำคัญต่อ outbreak control"}, {"topic": "Fitness for work / return", "q": "A worker recovering from an illness asks about returning to a physically demanding job. The physician's role includes what?", "choices": ["Assessing capacity and advising on safe return/accommodations honestly", "Certifying fit regardless of the actual condition", "Refusing any involvement in work matters", "Keeping the worker off indefinitely without assessment", "Deciding based only on the employer's wishes"], "ans": 0, "exp": "Fitness for work/return-to-work: แพทย์ประเมิน 'capacity' ตามภาวะสุขภาพจริง + advise 'safe return' (restrictions/accommodations, graded return) อย่างซื่อสัตย์ — balance ประโยชน์ของ worker (การกลับไปทำงานมีผลดีต่อสุขภาพ) กับ safety (ตนเองและผู้อื่น). ไม่ certify ตามใจนายจ้าง/worker โดยละเลยข้อเท็จจริง"}, {"topic": "Community health - primary care", "q": "A core principle of primary health care (as in the Alma-Ata declaration) emphasizes what?", "choices": ["Only high-technology hospital-based specialist care", "Accessible, equitable, community-based essential health care with prevention and participation", "Care available only to those who can pay", "Treatment of disease with no role for prevention", "Centralized care with no community involvement"], "ans": 1, "exp": "Primary health care (Alma-Ata 1978, 'Health for All'): เน้น 'accessible, equitable, community-based essential care' + health promotion/prevention + community participation + intersectoral collaboration + appropriate technology. เป็นพื้นฐานของระบบสุขภาพ (เช่น health promoting hospital, อสม., universal coverage ในไทย). Justice/equity สำคัญ"}, {"topic": "Informed refusal", "q": "A competent patient refuses a recommended test/treatment after being informed of the risks. What should the physician do?", "choices": ["Force the treatment against the patient's will", "Refuse to see the patient again", "Document the informed refusal, including that risks were explained", "Not document anything about the refusal", "Discharge the patient without any record"], "ans": 2, "exp": "Informed refusal: ผู้ป่วยที่ competent มีสิทธิปฏิเสธ (autonomy) 'หลังได้รับข้อมูล' ความเสี่ยงของการไม่รักษา → แพทย์ควร 'document informed refusal' (ได้อธิบาย risks/consequences, ผู้ป่วยเข้าใจ, ตัดสินใจเอง) — ป้องกันตนเองทางกฎหมาย + เคารพสิทธิ. ยังคงให้การดูแล/ทางเลือกอื่น (ไม่ abandon)"}, {"topic": "Consent for medical students", "q": "A medical student wishes to perform an intimate examination on a patient for learning. What is required?", "choices": ["No consent because it is for education", "Consent from the supervising doctor only", "Proceeding without informing the patient", "The patient's informed consent, knowing a student is involved", "Consent only if the patient is unconscious"], "ans": 3, "exp": "การให้นักศึกษาแพทย์ตรวจ/ทำหัตถการ (โดยเฉพาะ intimate examination) ต้องได้ 'informed consent' จากผู้ป่วยโดยรู้ว่าเป็นนักศึกษา + สมัครใจ (ปฏิเสธได้โดยไม่กระทบการดูแล) + supervision + chaperone. เคารพ autonomy/dignity. การตรวจโดยไม่แจ้ง/ไม่ยินยอม (เช่น pelvic exam ในผู้ป่วยที่ดมยาสลบเพื่อสอน) เป็นการผิดจริยธรรม"}, {"topic": "Whistleblowing / patient safety", "q": "A physician discovers systematic unsafe practices in their institution that endanger patients, and internal reporting has failed. What is ethically supported?", "choices": ["Staying silent to protect the institution's reputation", "Leaking confidential patient data to the media", "Ignoring it since it is not one's direct responsibility", "Retaliating against those responsible personally", "Raising the concern appropriately to protect patients through proper channels"], "ans": 4, "exp": "Whistleblowing: เมื่อพบ 'systematic unsafe practices' ที่เป็นอันตรายต่อผู้ป่วยและช่องทางภายในล้มเหลว → มี ethical support ในการ 'raise concern' ผ่านช่องทางที่เหมาะสม (regulator, authority) เพื่อ protect patients (patient welfare > institutional reputation). ทำอย่างมี integrity, ไม่ละเมิด confidentiality ผู้ป่วยโดยไม่จำเป็น, factual"}]}];
